-- Seed file for CuriosityUntamed badges + requirements.
-- One-shot import: deletes existing rows in the 3 badge tables and
-- re-populates them. Safe to re-run.
--
-- Run on production:  sqlite3 /path/to/data/family.db < server/scripts/seed-badges.sql

BEGIN TRANSACTION;
DELETE FROM badge_optional_requirements;
DELETE FROM badge_level_requirements;
DELETE FROM badges;
COMMIT;
