INSERT INTO badges VALUES(1,'7 Wonders of the Ancient World','7-wonders-of-the-ancient-world-badge','Discover the World','Meghan Wilson','7-wonders-of-the-ancient-world-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/7-wonders-of-the-ancient-world-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Thousands of years ago, people built incredible structures that amazed the ancient world—from a towering lighthouse to a massive stone statue. These seven legendary monuments show what humans could create with determination and skill, and some still stand today.',NULL);
INSERT INTO badges VALUES(2,'911 Emergency','911-emergency-badge','Discover Health & Safety','Jessica Williams',NULL,0,NULL,'https://curiosityuntamed.com/badges/911-emergency-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','When something dangerous happens, 911 dispatchers are the first people who help. They answer calls, ask the right questions, and send police, firefighters, or ambulances to save the day—so knowing when and how to reach them could make a real difference.','🚨');
INSERT INTO badges VALUES(3,'9/11 Memorial','911-memorial-badge','Discover Character','Suzanne Vicoryosmanson','911-memorial-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/911-memorial-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5}',1,'2026-05-20 16:10:36','On September 11, 2001, terrorists attacked the World Trade Center in New York City and other sites, changing America forever. This badge honors the people we lost that day and explores how communities remember and support each other through difficult times.',NULL);
INSERT INTO badges VALUES(4,'ABCs','abc-badge','Discover Knowledge','Adele Nolan','abc-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/abc-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The alphabet is your building block for reading and writing everything. Master the ABCs forwards and backwards, write your name, and even create wild sentences where every word starts with the next letter.',NULL);
INSERT INTO badges VALUES(5,'About Me','about-me-badge','Discover the Home','Kerry Cordy','about-me-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/about-me-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','You''re the expert on you—your favorite things, what you''re great at, and how you''re growing. This booklet captures who you are right now, from your hand size to your dreams, so you can look back later and see how much you''ve changed.',NULL);
INSERT INTO badges VALUES(6,'Accessories','accessories-badge','Discover the Home','Doreen Olson','accessories-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/accessories-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Belts, hats, scarves, shoes—these everyday items protect us and express our style, but they''re also smart choices about quality, cost, and care. Explore how accessories started as practical needs and became the finishing touches that make an outfit feel complete.',NULL);
INSERT INTO badges VALUES(7,'Accountablilty','accountability-badge','Discover Character','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/accountability-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Being accountable means doing what you say you''ll do and taking care of what''s yours. It''s about showing up, following through, and learning how your choices lead to real results—good and bad.','✋');
INSERT INTO badges VALUES(8,'Advanced Aviation','advanced-aviation-badge','Discover Science & Technology','','advanced-aviation-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/advanced-aviation-badge/','{"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','From understanding how planes stay in the air to exploring advanced flight systems, aviation reveals the physics and engineering behind human flight. Discover the technology that powers everything from commercial jets to experimental aircraft.',NULL);
INSERT INTO badges VALUES(9,'Advanced Baking','advanced-baking-badge','Discover the Home','Doreen Olson','advanced-baking-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/advanced-baking-badge/','{"level3":4,"level4":5}',1,'2026-05-20 16:10:36','Baking gets more interesting when you master tricky techniques like laminated dough, precise temperatures, and flavors that actually complement each other. Go beyond basic cookies to create impressive pastries, breads, and desserts that look and taste professional.',NULL);
INSERT INTO badges VALUES(10,'Advanced Cooking','advanced-cooking-badge','Discover the Home','','advanced-cooking-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/advanced-cooking-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cooking goes beyond following recipes—it''s about understanding flavors, nutrition, and techniques that turn basic ingredients into meals your family loves. Master knife skills, learn why breakfast matters, and discover how small choices make food healthier and tastier.',NULL);
INSERT INTO badges VALUES(11,'Advanced Knitting','advanced-knitting-badge','Discover Art','Sylvia Duke','advanced-knitting-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/advanced-knitting-badge/','{"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Intricate stitches, colorful yarns, and projects that go beyond basic scarves—advanced knitting lets you create sweaters, socks, hats with tricky patterns, and textured designs that look like real art.',NULL);
INSERT INTO badges VALUES(12,'Advanced Photography','advanced-photography-badge','Discover Art','Sophia Sepulveda','advanced-photography-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/advanced-photography-badge/','{"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Photography goes way beyond pointing and clicking—it''s about mastering light, composition, and timing to tell stories with your camera. Advanced photographers know how to frame the perfect shot, control exposure, and edit their work to create stunning images.',NULL);
INSERT INTO badges VALUES(13,'Advanced Quilting','advanced-quilting-badge','Discover the Home','Doreen Olson','advanced-quilting-badge.jpg',0,'Projects used to complete your Quilting badge may not be used for the Advanced Quilting badge.  New projects must be made.  If necessary, make a second or third quilting project to finish your requirements.','https://curiosityuntamed.com/badges/advanced-quilting-badge/','{"preschool":2,"level1":3,"level2":4,"level3":5,"level4":6,"level5":8}',1,'2026-05-20 16:10:36','Quilting takes scraps of fabric and transforms them into cozy blankets and wall hangings through careful cutting, piecing, and stitching. Master the advanced techniques that make intricate patterns come alive.',NULL);
INSERT INTO badges VALUES(14,'Advanced Sewing','advanced-sewing-badge','Discover the Home','Sylvia Duke','advanced-sewing-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/advanced-sewing-badge/','{"level1":2,"level2":2,"level3":2,"level4":4}',1,'2026-05-20 16:10:36','Sewing becomes a real superpower when you can read patterns, work a sewing machine confidently, and create projects that actually fit and look polished. From sturdy tote bags to fitted garments, you''ll make things people actually want to use.',NULL);
INSERT INTO badges VALUES(15,'Aerospace','aerospace-badge','Discover Science & Technology','Katie Cordy','aerospace-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/aerospace-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Aerospace is all about flight—from airplanes soaring through Earth''s sky to rockets blasting into space and beyond. Explore the amazing machines humans have built to fly, discover what NASA does to push the boundaries of space exploration, and trace the incredible history of how we learned to leave the ground.',NULL);
INSERT INTO badges VALUES(16,'Alien Life','alien-life-badge','Discover Science & Technology','Ramon Gomez',NULL,0,NULL,'https://curiosityuntamed.com/badges/alien-life-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','What if life exists on distant planets, and what would those alien creatures actually look like? Imagine new worlds with strange environments and the beings that might call them home, then explore the mind-bending question: with billions of galaxies out there, why haven''t we found aliens yet?','👽');
INSERT INTO badges VALUES(17,'Alpaca','alpaca-badge','Discover Agriculture','Kerry Cordy','alpaca-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/alpaca-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Alpacas are fluffy, gentle animals from South America that produce some of the softest fiber in the world. Explore what it takes to raise them, where their wool goes, and maybe even visit a herd in person.',NULL);
INSERT INTO badges VALUES(18,'Air Force','aerospace-badge-2','Discover Knowledge','Kerry Cordy','aerospace-badge-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/aerospace-badge-2/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Air Force defends the skies with fighter jets, transport planes, and reconnaissance aircraft that soar around the world. Explore the history of aviation in the military, meet the different types of planes and their missions, and discover what keeps our air operations running.',NULL);
INSERT INTO badges VALUES(19,'Airplanes','airplane-badge','Discover Science & Technology','','airplane-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/airplane-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Airplanes carry people and cargo across the sky by using wings, engines, and clever design. Explore how different planes look and work, from small bush planes to giant jumbo jets, and trace how flight has changed over the last hundred years.',NULL);
INSERT INTO badges VALUES(20,'Amateur Radio','amateur-radio-badge','Discover Science & Technology','Kelley Klor','amateur-radio-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/amateur-radio-badge/','{"preschool":1,"level1":2,"level2":2,"level3":3,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Amateur radio lets people talk to each other across towns, countries, or even the whole world using special equipment and radio waves. Amateur radio operators get their own call signs, tune into frequencies where others are listening, and create a community that''s been connecting people for over a century.',NULL);
INSERT INTO badges VALUES(21,'Amelia Earhart','amelia-earhart-badge','Discover Knowledge','Megan Lundquist','amelia-earhart-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/amelia-earhart-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Amelia Earhart was a fearless pilot who pushed the limits of what was possible in the sky, breaking records and inspiring millions before her mysterious disappearance. Explore her daring flights, her record-breaking achievements, and the questions that still surround her legendary final journey.',NULL);
INSERT INTO badges VALUES(22,'American Documents','american-documents-badge','Discover Knowledge','','american-documents-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/american-documents-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','America''s most important papers—like the Declaration of Independence and Constitution—shaped the country''s laws, freedoms, and history. Discover what these powerful documents say, why they mattered so much, and how they changed the nation.',NULL);
INSERT INTO badges VALUES(23,'American Girl Dolls','american-girlr-doll-badge','Discover Knowledge','','american-girlr-doll-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/american-girlr-doll-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','American Girl dolls each have their own story set in a different time period in American history, from colonial days to modern times. Explore these characters, read their adventures, and discover how the dolls let you step into their worlds and learn about the past.',NULL);
INSERT INTO badges VALUES(24,'American Heritage','american-heritage-badge','Discover Knowledge','Sylvia Duke','american-heritage-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/american-heritage-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','America''s story is built on big ideas like freedom, unity, and individual rights—values that shaped the Declaration of Independence, Constitution, and Bill of Rights. Explore what makes America unique, how citizens and government work together, and why "E Pluribus Unum" (out of many, one) still matters today.',NULL);
INSERT INTO badges VALUES(25,'American Revolution','american-revolution-badge','Discover Knowledge','','american-revolution-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/american-revolution-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','America''s independence didn''t happen overnight—it took a war, brave soldiers, and bold ideas about freedom. Explore the colonies, the battles, and the key moments that led thirteen states to declare they were free from British rule.',NULL);
INSERT INTO badges VALUES(26,'Amish','amish-badge','Discover the World','Cheryl Ousley',NULL,0,NULL,'https://curiosityuntamed.com/badges/amish-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Amish live simply without electricity, relying on horse-drawn buggies, hand-crafted goods, and close-knit communities. Step into their world for a day—no devices, no packaged food—and discover why some people choose tradition over modern conveniences.','🐴');
INSERT INTO badges VALUES(27,'Amphibians','animal-kingdom-amphibians','Discover the Outdoors','Kerry Cordy','animal-kingdom-amphibians.jpg',0,'A separate badge can be earned for each of the following categories: Mammals, reptiles, amphibians, marine life, insects and birds.','https://curiosityuntamed.com/badges/animal-kingdom-amphibians/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Amphibians start life in water with gills and tails, then transform into land animals with lungs and legs—frogs, salamanders, and newts are masters of this double life. Spot them in your own backyard or nearby wetlands, learn what makes them tick, and discover how they survive in two very different worlds.',NULL);
INSERT INTO badges VALUES(28,'Amusement and Theme Parks (Specific)','14881-2','Discover the World','','14881-2.jpg',1,NULL,'https://curiosityuntamed.com/badges/14881-2/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Theme parks are engineering marvels where rides spin, splash, and soar while thousands of people have fun together. Explore the history, layout, and magic behind a real amusement park near you.',NULL);
INSERT INTO badges VALUES(29,'Animals (Specific)','animals-specific-badge','Discover the Outdoors','Erin Bradley','animals-specific-badge.jpg',1,'This badge can be earned multiple times, once for each animal studied. Adapt these general requirements to the animal you are learning about. On the bottom of the page are links to the different badges created for specific animals, such as the Horse badge, the Hamster Badge, and the Cats badge.','https://curiosityuntamed.com/badges/animals-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pick an animal you''re curious about and become an expert on it. You''ll learn what it looks like, where it lives, what it eats, how it grows from baby to adult, and what other creatures depend on it to survive.',NULL);
INSERT INTO badges VALUES(30,'Animals Around the World','2130-2','Discover the World','Kerry Cordy','2130-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/2130-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every continent has its own wild creatures—from African lions and Australian kangaroos to Asian tigers and rainforest poison frogs. Explore the amazing animals that call different parts of the world home and discover what makes them special.',NULL);
INSERT INTO badges VALUES(31,'Animal Migration','animal-migration-badge','Discover Science & Technology','Ashley Bergum',NULL,0,NULL,'https://curiosityuntamed.com/badges/animal-migration-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every year, millions of animals pack up and travel thousands of miles to find food, escape cold weather, or raise their babies in safer places. Explore why some creatures make these epic journeys while others stay put, and discover the invisible instincts that guide them across oceans and continents.','🦅');
INSERT INTO badges VALUES(32,'Animal Rescue','animal-rescue-badge','Discover Character','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/animal-rescue-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Animals in shelters need help finding safe, loving homes. You''ll discover why rescue matters, meet different animals who need care, and learn what it takes to handle and help them thrive.','🐾');
INSERT INTO badges VALUES(33,'Animal Tracking','animal-tracking','Discover the Outdoors','Margaret Chind','animal-tracking.jpg',0,NULL,'https://curiosityuntamed.com/badges/animal-tracking/','{"preschool":1,"level2":3,"level3":4,"level4":5,"level5":6}',1,'2026-05-20 16:10:36','Animals leave clues wherever they go—paw prints in mud, hoof marks in snow, scratches on bark. Learn to spot and identify these tracks to discover which creatures share your neighborhood and what they''re doing there.',NULL);
INSERT INTO badges VALUES(34,'Animation','animation-badge','Discover Art','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/animation-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Animation brings drawings and objects to life through a series of images played in quick succession, making them move and tell stories. From classic cartoons to modern CGI, you''ll explore different animation styles and create your own flipbook magic.','🎬');
INSERT INTO badges VALUES(35,'Anne of Green Gables','anne-of-green-gables-badge','Discover Knowledge','Sarah Bruekherr',NULL,0,NULL,'https://curiosityuntamed.com/badges/anne-of-green-gables-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Anne Shirley arrives at Green Gables with wild red hair, a vivid imagination, and endless chatter that wins over the whole town of Avonlea. Follow her adventures on Prince Edward Island as she makes friends, gets into scrapes, and grows from a talkative orphan into a thoughtful young woman.','🍎');
INSERT INTO badges VALUES(36,'Anti-Bullying','861-2','Discover Character','Kerry Cordy','861-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/861-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Bullying hurts, and it comes in many forms—from mean words in person to hurtful messages online that spread fast. Learn how to stand up for yourself and others, spot when someone needs help, and build friendships based on kindness instead of putting people down.',NULL);
INSERT INTO badges VALUES(37,'Antiques','antiques-badge','Discover Knowledge','Charlotte Duke','antiques-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/antiques-badge/','{"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Old objects tell amazing stories about how people lived, what they valued, and how the world has changed. Spotting a real antique, understanding its history, and appreciating its craftsmanship is like being a detective with artifacts.',NULL);
INSERT INTO badges VALUES(38,'Appalachian Trail','appalachian-trail-badge','Discover the Outdoors','Amy Chartier','appalachian-trail-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/appalachian-trail-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Appalachian Trail stretches over 2,000 miles from Georgia to Maine, passing through 14 states and some of America''s most stunning mountain landscapes. Hikers tackle it in different ways—some walk the whole thing in one epic journey, others explore sections over years, and many enjoy single-day adventures on its well-marked paths.',NULL);
INSERT INTO badges VALUES(39,'Apples','apples-badge','Discover Agriculture','Kerry Cordy','apples-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/apples-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Apples come in dozens of varieties—some are sweet, some tart, some crisp, some soft—and each one has its own flavor and story. From seed to tree to fruit, discover why apples have been grown around the world for thousands of years, and meet the real person behind the Johnny Appleseed legend.',NULL);
INSERT INTO badges VALUES(40,'Aquarium','aquarium-badge','Discover the World','','aquarium-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/aquarium-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fish tanks create tiny underwater worlds where colorful creatures swim, hide, and hunt just like in the ocean. Explore what lives in aquariums and discover why these glass homes need the right water, plants, and care to keep animals healthy and happy.',NULL);
INSERT INTO badges VALUES(41,'Archaeology','archaeology-badge','Discover the World','Amy Chartier','archaeology-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/archaeology-badge/','{"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Archaeologists carefully dig up the past—old tools, pottery, buildings, and bones—to understand how people lived thousands of years ago. It''s like detective work underground, where every artifact tells a story and protecting the site matters as much as finding treasure.',NULL);
INSERT INTO badges VALUES(42,'Archery','archery-badge','Discover the Outdoors','Kerry Cordy','archery-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/archery-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Archery is about aiming, releasing, and watching your arrow fly straight toward a target. You''ll learn the safety rules that keep everyone protected on the range, practice your stance and aim, and discover how archers compete at tournaments.',NULL);
INSERT INTO badges VALUES(43,'Architecture','architecture-badge','Discover Knowledge','Doreen Olson','architecture-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/architecture-badge/','{"preschool":1,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Buildings are more than just walls and roofs—they''re art shaped by the people, places, and tools available when they''re built. Architects dream up these structures and use math and science to turn sketches into real homes, bridges, and monuments that last for centuries.',NULL);
INSERT INTO badges VALUES(44,'Army','army','Discover Knowledge','Kerry Cordy','army.jpg',0,NULL,'https://curiosityuntamed.com/badges/army/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Army is one branch of the U.S. military with a long history of protecting our country on land. Discover what soldiers do, how the Army got started, and the different ways people serve—from active duty to the National Guard.',NULL);
INSERT INTO badges VALUES(45,'Art','art-badge','Discover Art','Doreen Olson','art-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/art-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Art is everywhere—in colors that pop, lines that guide your eye, and textures that invite you to touch. Create your own masterpieces using paint, pencils, clay, and more while discovering what makes a piece truly stand out.',NULL);
INSERT INTO badges VALUES(46,'Art History','art-history-badge','Discover Art','Doreen Olson','art-history-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/art-history-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Art has looked wildly different across thousands of years—from cave paintings to Renaissance masterpieces to wild modern experiments. Explore the styles, artists, and stories behind the world''s most famous artworks and see how people''s ideas about beauty and creativity have transformed over time.',NULL);
INSERT INTO badges VALUES(47,'Art in Nature','art-in-nature','Area of Discovery','Kerry Cordy','art-in-nature.png',0,NULL,'https://curiosityuntamed.com/badges/art-in-nature/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":6}',1,'2026-05-20 16:10:36','Nature is full of colors, shapes, and textures waiting to become art. Grab your sketchbook, camera, or found materials like leaves and rocks, then head outside to create something beautiful inspired by what you discover.',NULL);
INSERT INTO badges VALUES(48,'Art (Specific)','art-specific-badge','Discover Art','Jill Brady',NULL,1,'This badge can be earned for any form of art you choose. Examples include mosaics, sculpture, mixed media, video clips, embroidery, underwater basket weaving, chainmail, etc.  Many specific badges also exist for forms of artwork, such as painting, so be sure to double check for those options as well.','https://curiosityuntamed.com/badges/art-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Art comes in endless forms—painting, sculpture, photography, digital art, and so much more. You''ll explore what makes your chosen type special, create your own piece, discover the tools and materials artists use, and uncover the history behind it all.','🎨');
INSERT INTO badges VALUES(49,'Artificial Intelligence (AI)','artificial-intelligence-badge','Discover Science & Technology','Ramon Gomez',NULL,0,NULL,'https://curiosityuntamed.com/badges/artificial-intelligence-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Artificial intelligence powers everything from voice assistants that answer questions to programs that learn from examples and get smarter over time. Explore how AI does things humans can''t (like processing millions of data points instantly) and why some jobs still need the human touch.','🤖');
INSERT INTO badges VALUES(50,'Artist Trading Cards','artisit-trading-cards-badge','Discover Art','Stephanie Pearce','artisit-trading-cards-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/artisit-trading-cards-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Tiny postcards filled with your own art become treasures to swap with friends. Create designs, trade your cards, and start a collection that shows off all the different styles and ideas artists come up with.',NULL);
INSERT INTO badges VALUES(51,'Astronomy','astronomy-badge-2','Discover Science & Technology','Kerry Cordy','astronomy-badge-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/astronomy-badge-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Astronomy is the study of everything beyond Earth—stars, planets, galaxies, and more scattered across the universe. You''ll learn what''s actually out there, how to safely spot them in the night sky, and the names and stories of the worlds in our solar system.',NULL);
INSERT INTO badges VALUES(52,'Attentiveness','attentiveness-badge','Discover Character','Kamilla Sepulveda','attentiveness-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/attentiveness-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Paying attention sounds simple, but it''s a superpower that takes practice. When you''re truly attentive—using your eyes, ears, and mind all at once—you catch details others miss, follow instructions better, and show people you care about what they''re saying.',NULL);
INSERT INTO badges VALUES(53,'Aurora Borealis','aurora-borealis-badge','Discover Science & Technology','Sarah Bruekherr',NULL,0,NULL,'https://curiosityuntamed.com/badges/aurora-borealis-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Aurora Borealis is a shimmering light show in the night sky, painting the air with greens, purples, and reds when the sun''s energy dances with Earth''s atmosphere. Uncover the science behind this natural wonder and the stories cultures have told about it for centuries.','🌌');
INSERT INTO badges VALUES(54,'Autism Awareness','863-2','Discover Character','','863-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/863-2/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Autism is a difference in how people''s brains are wired, affecting how they communicate, learn, and experience the world around them. Understanding autism means recognizing that autistic people have unique strengths and challenges—and that the world works better when we''re patient and thoughtful about how different brains work.',NULL);
INSERT INTO badges VALUES(55,'Automotive Maintenance','automotive-maintenance','Discover the Home','Chana Barak','automotive-maintenance.jpg',0,NULL,'https://curiosityuntamed.com/badges/automotive-maintenance/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cars need regular checkups just like people do—checking the oil, testing lights, and making sure everything works keeps you safe on the road. Find out what to look for under the hood and how to spot problems before they become dangerous.',NULL);
INSERT INTO badges VALUES(56,'Aviation','aviation-badge-2','Discover Science & Technology','','aviation-badge-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/aviation-badge-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Airplanes come in all shapes and sizes—from tiny propeller planes to massive jets—and each one flies because of special parts working together. Fold paper planes, tinker with flaps and wings to change how they fly, and discover the forces that keep aircraft soaring through the sky.',NULL);
INSERT INTO badges VALUES(57,'Babies','babies-badge','Discover the Home','Lauren Greenfield','babies-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/babies-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Babies grow from tiny cells into whole humans in just nine months, then keep changing fast after birth—learning to smile, grab, roll over, and talk. Discover how newborns develop, what they need to thrive, and the stories behind the names we give them.',NULL);
INSERT INTO badges VALUES(58,'Baby Animals','baby-animals-badge','Discover Science & Technology','Annalise Wolf',NULL,0,NULL,'https://curiosityuntamed.com/badges/baby-animals-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',0,'2026-05-20 16:10:36','Baby animals start out tiny, helpless, and totally dependent on their parents—but they grow up fast. Explore how different creatures are born, what they eat, and how they learn to survive in the wild.','🐣');
INSERT INTO badges VALUES(59,'Backpacking','backpacking-badge','Discover the Outdoors','Chana Barak','backpacking-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/backpacking-badge/','{"preschool":1,"level1":2,"level2":3,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Backpacking is camping with everything you need strapped to your back—tent, sleeping bag, food, and all. You''ll learn to pick trails, pack smart, stay safe in the wilderness, and spend nights under the stars miles from civilization.',NULL);
INSERT INTO badges VALUES(60,'Backyard Buddies','backyard-buddies-badge','Discover the Outdoors','Crystal Marcum','backyard-buddies-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/backyard-buddies-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your backyard is alive with creatures hunting, hiding, and surviving right outside your door. Discover who your wild neighbors are, how they find food through the seasons, and simple ways to help them thrive without turning them into dependents.',NULL);
INSERT INTO badges VALUES(61,'Backyard Camping','backyard-camper','Discover the Outdoors','Kerry Cordy','backyard-camper.jpg',0,NULL,'https://curiosityuntamed.com/badges/backyard-camper/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Sleeping under the stars in your own backyard opens up a whole new world—you''ll spot constellations, listen for night creatures, and learn to pack your gear like a real camper. One night outside changes how you see the sky forever.',NULL);
INSERT INTO badges VALUES(62,'Badge Writing','the-badge-writing-badge','Discover Knowledge','Kimberly Bogers','the-badge-writing-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/the-badge-writing-badge/','{"level1":1,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','You become a badge designer, researching a topic you''re curious about and creating achievement requirements for other kids to follow. Talk to experts, dig into books and websites, design fun activities and challenges, then write it all up for approval—and maybe inspire the next learner to explore something amazing.',NULL);
INSERT INTO badges VALUES(63,'Baking','1130-2','Discover the Home','Kerry Cordy','1130-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/1130-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Baking transforms simple ingredients like flour, sugar, and eggs into cakes, cookies, and bread through heat and chemistry. Master kitchen safety, learn baker''s lingo, and create delicious treats from scratch or mixes to discover what tastes best.',NULL);
INSERT INTO badges VALUES(64,'Balloon Art','balloon-art-badge','Discover Art','Emily Goldenberg','balloon-art-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/balloon-art-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Colorful balloons twisted into swords, dogs, and flowers turn simple air into art you can hold and give away. Round balloons and long skinny ones create totally different shapes, so there''s lots to explore with just your hands and a pump.',NULL);
INSERT INTO badges VALUES(65,'Bandanas','bandanas-badge','Discover Art','Katie Lundquist','bandanas-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/bandanas-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Bandanas are colorful squares of fabric with a wild history—from India to the Wild West to fashion runways. Tie one on your head, wear it as a scarf, or use it as a pocket square and discover why this simple piece of cloth has been cool for centuries.',NULL);
INSERT INTO badges VALUES(66,'Banking','banking-badge','Discover the Home','Cindy Lillemo',NULL,0,NULL,'https://curiosityuntamed.com/badges/banking-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Banks are places where people keep their money safe and borrow it when they need it. Find out how tellers, ATMs, and safety deposit boxes work, and learn what happens when you deposit, withdraw, debit, or credit your account.','🏦');
INSERT INTO badges VALUES(67,'Barbie','barbie-badge','Discover Knowledge','Doreen Olson','barbie-badge.png',0,NULL,'https://curiosityuntamed.com/badges/barbie-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Barbie has been a cultural icon for over 60 years, evolving from the original 1959 doll into hundreds of versions representing different careers, cultures, and stories. Design your own outfits, explore how she''s changed through the decades, and discover why this doll has inspired generations of kids to imagine endless possibilities.',NULL);
INSERT INTO badges VALUES(68,'Batman','batman-badge','Discover Knowledge','Julie Ringrose','batman-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/batman-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Batman is Gotham''s masked detective who uses his brilliant mind, martial arts skills, and high-tech gadgets to fight crime and protect his city. Explore the Dark Knight''s origin story, his greatest villains, and what makes him one of the most iconic superheroes of all time.',NULL);
INSERT INTO badges VALUES(69,'Battery Power','battery-power-badge','Discover Science & Technology','',NULL,0,NULL,'https://curiosityuntamed.com/badges/battery-power-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Batteries are tiny power plants that store energy and feed it to your flashlight, toys, and remote controls. Figure out how to load them the right way, stay safe around them, and unlock the invisible forces that make things go.','🔋');
INSERT INTO badges VALUES(70,'Battle Strategy','battle-strategy-badge','Discover the World','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/battle-strategy-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Battles throughout history have been won and lost based on clever thinking, not just brute force. Explore how generals use terrain, surprise tactics, and smart planning to outwit their opponents—from ancient times to modern warfare.','♟️');
INSERT INTO badges VALUES(71,'BBQ','bbq-badge','Discover the Home','Katie Lundquist','bbq-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/bbq-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',0,'2026-05-20 16:10:36','Smoke, sizzle, and flavor—barbecuing is part cooking technique and part outdoor art. From tending the fire to perfecting rubs and sauces, you''ll learn what makes backyard meals unforgettable.',NULL);
INSERT INTO badges VALUES(72,'Beach Fun','beach-fun-badge','Discover the Outdoors','Suzanne Vicoryosmanson','beach-fun-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/beach-fun-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The beach is an amazing place to swim, build sandcastles, and explore tide pools—but staying safe means knowing the rules, understanding water flags and depth markers, and never swimming without a buddy. Smart beach-goers wear sunscreen, watch for hidden hazards, and respect the ocean''s power.',NULL);
INSERT INTO badges VALUES(73,'Beading','beading-badge','Discover Art','Kerry Cordy','beading-badge.png',0,NULL,'https://curiosityuntamed.com/badges/beading-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":9}',1,'2026-05-20 16:10:36','Tiny beads made from glass, stone, wood, clay, and more can be strung together into bracelets, necklaces, and decorations. String your own jewelry and even craft beads from scratch to create something uniquely yours.',NULL);
INSERT INTO badges VALUES(74,'Beekeeping','beekeeping-badge','Discover Agriculture','Kerry Cordy','beekeeping-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/beekeeping-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Bees are tiny pollinators that make honey, build wax combs, and live in busy colonies of thousands. Get to know how hives work, how beekeepers care for them safely, and the amazing process that turns flower nectar into the honey on your toast.',NULL);
INSERT INTO badges VALUES(75,'Bible Knowledge','bible-knowledge-badge','Discover Character','Doreen Olson','bible-knowledge-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/bible-knowledge-badge/','{"preschool":2,"level1":2,"level2":5,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Bible is one of the world''s oldest and most influential books, split into the Old and New Testaments with dozens of smaller books inside. Explore its history, learn how it was written and preserved over thousands of years, and discover the stories and characters that shaped countless lives.',NULL);
INSERT INTO badges VALUES(76,'Bible Memory','bible-memory-badge','Discover Character','Doreen Olson','bible-memory-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/bible-memory-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Memorizing Bible verses builds your mind like exercise builds your muscles, giving you wisdom and encouragement you can pull from anywhere. Words that have guided people for thousands of years become part of your own story.',NULL);
INSERT INTO badges VALUES(77,'Bicycling','bicycling-badge','Discover Health & Safety','Kerry Cordy','bicycling-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/bicycling-badge/','{"preschool":1,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Bicycles are two-wheeled machines powered by your own pedaling—faster than walking, more fun than sitting still, and way cooler once you can ride without training wheels. Master the basics of balance and steering, learn the rules of the road, and discover how to keep your bike running smoothly with simple repairs and maintenance.',NULL);
INSERT INTO badges VALUES(78,'Big Sister/Big Brother','big-brotherbig-sister-badge','Discover the Home','Savannah Crowell','big-brotherbig-sister-badge.png',0,NULL,'https://curiosityuntamed.com/badges/big-brotherbig-sister-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Being the older sibling means you''re like a guide, cheerleader, and teacher all rolled into one. Share your favorite games, stories, and skills with your little brother or sister—and watch them light up when you help them discover something new.',NULL);
INSERT INTO badges VALUES(79,'Bigfoot','bigfoot-badge','Discover Knowledge','Stacie Stout','bigfoot-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/bigfoot-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Is Bigfoot real, or just a legend? Explore the mysterious footprints, blurry photos, and eyewitness stories that have fascinated people for decades. Dig into the science behind cryptozoology and decide what you believe.',NULL);
INSERT INTO badges VALUES(80,'Biology','biology-badge-2','Discover Science & Technology','Kerry Cordy','biology-badge-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/biology-badge-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Biology is the study of all living things—plants, animals, insects, and more—and how they''re connected. You''ll explore life cycles, sort creatures into groups by their traits, and discover the system scientists use to organize every living thing on Earth.',NULL);
INSERT INTO badges VALUES(81,'Bioluminescence','bioluminescence-badge','Discover Science & Technology','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/bioluminescence-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Some creatures glow in the dark without electricity—fireflies flash in summer yards, deep-sea jellyfish pulse with light, and certain fungi shimmer in forests. Discover why animals create their own light and how they use it to hunt, hide, or find a mate.','🌟');
INSERT INTO badges VALUES(82,'Biomes','biomes-badge','Discover Science & Technology','Katie Lundquist','biomes-badge.jpg',1,'This badge can be earned multiple times for different biomes such as savannah, desert, riparian, etc.','https://curiosityuntamed.com/badges/biomes-badge/','{"preschool":3,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Earth''s different regions each have their own climate, plants, and animals—from frozen tundras to tropical rainforests to vast deserts. Explore what makes each biome unique and how creatures adapt to survive where they live.',NULL);
INSERT INTO badges VALUES(83,'Bird-watching','bird-watching-badge','Discover the Outdoors','Charlotte Duke','bird-watching-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/bird-watching-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Birds are everywhere if you know how to spot them—cardinals, blue jays, sparrows, and dozens more. Grab binoculars, keep a notebook, and learn to recognize them by their colors, shapes, and the songs they sing.',NULL);
INSERT INTO badges VALUES(84,'Birthdays','birthday-badge','Discover Knowledge','Sophia Sepulveda','birthday-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/birthday-badge/','{"level5":7}',1,'2026-05-20 16:10:36','Birthdays mark the day you came into the world—a reason to celebrate you! From cake and candles to traditions around the globe, birthdays bring people together to show someone they matter.',NULL);
INSERT INTO badges VALUES(85,'Board Games','board-games-badge','Discover Knowledge','Karla Freeman','board-games-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/board-games-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Board games are a blast—from quick word games to intense strategy battles to hilarious party showdowns. Dive into different game types, learn the rules, and discover what makes a good game night great, from picking who goes first to deciding whether letting someone win is ever okay.',NULL);
INSERT INTO badges VALUES(86,'Boating Safety','boating-safety-badge','Discover Health & Safety','Nadine Goodwin','boating-safety-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/boating-safety-badge/','{"preschool":1,"level2":3,"level3":4,"level4":5,"level5":7}',0,'2026-05-20 16:10:36','Being safe on the water means knowing how to swim, wear a life jacket, and spot hazards before they become problems. Every boat trip is an adventure when you''re prepared.',NULL);
INSERT INTO badges VALUES(87,'Body Part (Specific)','body-part-specific','Discover Health & Safety','Crystal Morris',NULL,1,NULL,'https://curiosityuntamed.com/badges/body-part-specific/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your body is made of amazing parts that all work together, and this badge dives deep into one specific piece—where it sits, what it does, and how to keep it healthy. You''ll discover how your chosen body part fits into bigger systems and even run experiments that show it in action.','🫀');
INSERT INTO badges VALUES(88,'Bookbinding','book-binding-badge','Discover Art','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/book-binding-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Thread, glue, staples, and ribbons hold books together in surprisingly different ways—and you can make your own. Turn folded paper into a decorated book, then discover how bookbinders have been crafting pages for thousands of years.','📖');
INSERT INTO badges VALUES(89,'Book Club','book-club-badge','Discover Knowledge','Sarah Hershberger','book-club-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/book-club-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Getting together with friends to read the same book and talk about it is way more fun than reading alone. You''ll discover new stories, hear what other people think, and learn what makes a great book worth discussing.',NULL);
INSERT INTO badges VALUES(90,'Books (Specific)','books-badge-specific','Discover Knowledge','Kerry Cordy','books-badge-specific.jpg',1,'This badge is designed to be adapted to earn a specific badge for any book you wish to read and can be earned as many times as you want.','https://curiosityuntamed.com/badges/books-badge-specific/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A single book can teach you new words, show you different worlds, and inspire your imagination in unexpected ways. Dive deep into a story you love, discover what characters can teach you, and create something that shows what the book meant to you.',NULL);
INSERT INTO badges VALUES(91,'Book Writing','badge-writing-badge','Discover Knowledge','Christina Helmbold',NULL,0,NULL,'https://curiosityuntamed.com/badges/badge-writing-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":6}',1,'2026-05-20 16:10:36','Stories come in many shapes—picture books with big bright pages, chapter books with deeper adventures, and everything in between. You''ll discover what makes authors tick, create your own characters and heroes, and write a short story of your own using the building blocks that make tales unforgettable.','📖');
INSERT INTO badges VALUES(92,'Botany','botany-badge','Discover Science & Technology','Francine Geissler','botany-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/botany-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Plants are everywhere—in gardens, forests, and even between sidewalk cracks—and botany is the science of understanding how they grow, reproduce, and fit into the natural world. You''ll start seeds, explore how scientists organize living things, and discover the hidden structures that make plants work.',NULL);
INSERT INTO badges VALUES(93,'Bouldering','bouldering-badge','Discover Health & Safety','Kerry Cordy','bouldering-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/bouldering-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Bouldering is rock climbing on shorter walls where you solve puzzles with your body, using handholds and footwork to reach the top. You''ll learn the safety gear, techniques, and smart thinking needed to climb smart—protecting yourself and others around you.',NULL);
INSERT INTO badges VALUES(94,'Bowling','bowling','Discover Health & Safety','Heidi Fairbrother',NULL,0,NULL,'https://curiosityuntamed.com/badges/bowling/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Bowling is a game where you roll a heavy ball down a lane to knock over pins, and it''s got its own rules to keep everyone safe and having fun. Master the basics like strikes and spares, learn proper lane etiquette, and discover why bumpers are game-changers for beginners.','🎳');
INSERT INTO badges VALUES(95,'Braille','braille-badge','Discover Knowledge','Sara Rauta','braille-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/braille-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Braille is a raised-dot writing system that lets blind and visually impaired people read with their fingertips. Discover how Louis Braille invented this clever code, learn the dots that make up letters and numbers, and unlock a whole new way of reading and writing.',NULL);
INSERT INTO badges VALUES(96,'Bread','bread-badge','Discover the Home','Amy Chartier','bread-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/bread-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Bread comes in hundreds of flavors and textures—crusty sourdough, soft brioche, chewy bagels, and more. Mix flour, water, yeast, and salt, and watch tiny living organisms transform your dough into something warm and delicious that fills your home with amazing smells.',NULL);
INSERT INTO badges VALUES(97,'Breyer Horses','breyer-horse-badge','Discover Knowledge','Katie Cordy','breyer-horse-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/breyer-horse-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Breyer horses are detailed plastic model horses that collectors have loved for decades, each one sculpted to look realistic and painted with beautiful markings. Discover the different sizes and scales Breyer makes, learn how to keep your models looking their best, and explore what makes each horse unique.',NULL);
INSERT INTO badges VALUES(98,'British Crown Jewels','british-crown-jewels-badge','Discover Knowledge','Charlotte Duke','british-crown-jewels-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/british-crown-jewels-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Crown Jewels are glittering treasures locked in the Tower of London—crowns, scepters, and orbs used by British monarchs for centuries. These royal objects tell stories of power, tradition, and the history of a kingdom.',NULL);
INSERT INTO badges VALUES(99,'British Monarchy','british-monarchy-badge','Discover Knowledge','Charlotte Duke','british-monarchy-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/british-monarchy-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Britain''s monarchy is one of the world''s oldest, with a king or queen ruling from a throne and a long line of heirs waiting their turn. Explore the royal family tree, learn how power actually works in a constitutional monarchy, and discover the people and traditions that keep this ancient institution going.',NULL);
INSERT INTO badges VALUES(100,'Bubbles','bubble-badge-2','Discover Science & Technology','Kerry Cordy','bubble-badge-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/bubble-badge-2/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Bubbles are thin layers of soapy water that trap air inside, creating shimmering spheres that float and pop in surprisingly cool ways. Explore the science of surface tension, discover why some bubble recipes last longer than others, and master the art of blowing perfect bubbles.',NULL);
INSERT INTO badges VALUES(101,'Budgeting','budgeting-badge','Discover the Home','Kerry Cordy','budgeting-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/budgeting-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Money has to stretch across food, clothes, fun, and everything else your family needs. Learn where your dollars go, how to split what you earn between spending and saving, and how to make smart choices when you can''t have it all.',NULL);
INSERT INTO badges VALUES(102,'Buffalo','buffalo-badge','Discover Agriculture','Adele Nolan','buffalo-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/buffalo-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Buffalo once roamed North America''s plains by the millions, feeding Native Americans and shaping entire ecosystems. Discover why these massive animals nearly vanished and how they''re making a comeback today.',NULL);
INSERT INTO badges VALUES(103,'Business Math','business-math-badge','Discover Science & Technology','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/business-math-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Running a store means handling money, making change, and figuring out what things cost. You''ll practice buying and selling, count real coins and bills, and learn how sales tax sneaks onto your total at checkout.','💰');
INSERT INTO badges VALUES(104,'Cabbage Patch Kids','learn-about-cabbage-patch-kids-badge','Discover Knowledge','Dawn Durbin','learn-about-cabbage-patch-kids-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/learn-about-cabbage-patch-kids-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','These plush dolls with yarn hair and adoption certificates became a massive craze in the 1980s and are still beloved today. Explore the quirky history behind their cabbage patch origin story, how they''ve evolved, and why collecting them became such a big deal.',NULL);
INSERT INTO badges VALUES(105,'Cake Decorating','cake-decorating-badge','Discover the Home','Kerry Cordy','cake-decorating-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/cake-decorating-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cakes are edible canvases, and a decorator''s tools turn frosting into flowers, swirls, and fancy designs. Learn piping techniques, master different icing types, and turn a plain cake into a showstopper for any celebration.',NULL);
INSERT INTO badges VALUES(106,'California Missions','california-missions-badge','Discover the World','Jessica Price','california-missions-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/california-missions-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Spanish missionaries built a chain of 21 missions across California starting in the 1700s, each one a unique adobe compound with its own story, layout, and history. Visiting these historic sites reveals how different communities adapted to the land and how California''s past shaped what it is today.',NULL);
INSERT INTO badges VALUES(107,'Calligraphy','calligraphy-badge','Discover Art','Doreen Olson','calligraphy-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/calligraphy-badge/','{"preschool":1,"level1":2,"level2":2,"level3":3,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Beautiful handwriting becomes art when you slow down and use special pens to make thick and thin strokes that dance across the page. Master the elegant letterforms, perfect spacing, and flowing lines that turn words into something people want to frame.',NULL);
INSERT INTO badges VALUES(108,'Camping','camping-badge','Discover the Outdoors','Kerry Cordy','camping-badge.jpg',0,'Children are not allowed to build, tend, or cook on any open fire until they have received their Fire Safety badge.  Children are also not allowed to have a pocketknife at camp unless they have earned the Pocketknife badge.','https://curiosityuntamed.com/badges/camping-badge/','{"preschool":2,"level1":2,"level2":3,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Sleeping under the stars beats any bedroom—if you know how to set up safely and leave nature untouched. Learn tent skills, first aid for the outdoors, and how to camp responsibly so the next adventurers find the campsite just as perfect as you did.',NULL);
INSERT INTO badges VALUES(109,'Canadian History','canadian-history-badge','Discover the World','Sarah Bruekherr','canadian-history-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/canadian-history-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Canada''s story starts long before it was called Canada—with Indigenous peoples who thrived across the land with their own languages, homes, and ways of living. Explore how First Nations, Inuit, and Métis communities shaped the continent, then follow the waves of European exploration, Britain''s influence, and the bold vision of the Fathers of Confederation who built a nation.',NULL);
INSERT INTO badges VALUES(110,'Candle Making','candle-making-badge','Discover Art','Kerry Cordy','candle-making-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/candle-making-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Melting wax, pouring it into molds, and watching it cool into a glowing candle is oddly satisfying. Discover why candles burn the way they do, pick the right wicks and wax for different styles, and create your own from votives to pillars.',NULL);
INSERT INTO badges VALUES(111,'Candy Making','candy-making-badge','Discover the Home','Kerry Cordy','candy-making-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/candy-making-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Candy making transforms simple ingredients into sweet treats you can actually eat. Roll, dip, and shape chocolates and lollipops while learning the tricks that keep melted chocolate smooth and shiny instead of grainy and clumpy.',NULL);
INSERT INTO badges VALUES(112,'Canoeing','canoeing-badge','Discover the Outdoors','Kerry Cordy','canoeing-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/canoeing-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A canoe glides quietly through water with just a paddle and your strength. Master launching, steering, and paddling skills while learning water safety and discovering how to handle this classic boat on lakes, rivers, and calm waterways.',NULL);
INSERT INTO badges VALUES(113,'Car Racing','car-racing-2','Discover Science & Technology','Kerry Cordy','car-racing-2.jpg',0,'This badge may be earned multiple times, once for each type of racing you learn about. Examples may include Indy Car Racing, NASCAR, Formula One, Sprint Car Racing, Drag Racing, Go-karts, Rally Car Racing, Sport Car Racing, Off Road Racing, Midgets, etc.','https://curiosityuntamed.com/badges/car-racing-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Race cars zoom around tracks at incredible speeds, and different types—from Formula 1 to drag racing to stock cars—each have their own rules, designs, and history. Explore what makes your favorite racing style unique and where the biggest races happen around the world.',NULL);
INSERT INTO badges VALUES(114,'Card Making','card-making-badge','Discover Art','','card-making-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/card-making-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Turning blank cardstock into personalized greetings is an art form all its own. Mix stamps, markers, collage, and clever folds to create cards that make people smile when they open their mailbox.',NULL);
INSERT INTO badges VALUES(115,'Cardboard','cardboard-badge','Discover Science & Technology','',NULL,0,NULL,'https://curiosityuntamed.com/badges/cardboard-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cardboard is way stronger than it looks—especially the wavy stuff inside that makes it stiff and lightweight. Turn scraps into masks, houses, towers, and creatures, then discover how mills turn trees into the boxes that deliver everything.','📦');
INSERT INTO badges VALUES(116,'Care Bears','care-bears-badge','Discover Knowledge','Adele Nolan',NULL,0,NULL,'https://curiosityuntamed.com/badges/care-bears-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','These colorful bears from the 1980s live in a magical cloud kingdom and use their belly badges to spread happiness and kindness. They teach friends that caring, courage, and good feelings are superpowers worth sharing.','🌈');
INSERT INTO badges VALUES(117,'Career Exploration','career-exploration-badge','Discover Knowledge','Kelly Araneda','career-exploration-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/career-exploration-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Communities need all kinds of workers—from bakers and builders to teachers and firefighters. Explore the jobs around you, meet people doing them, and discover what kind of work might excite you someday.',NULL);
INSERT INTO badges VALUES(118,'Carrots','carrots-badge','Discover Agriculture','Sadira Chidester','carrots-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/carrots-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Carrots grow underground in cool seasons and turn up in kitchens around the world, especially from the US and China. Taste them raw, roasted, or steamed to discover why these crunchy orange roots are packed with vitamins and have been feeding people for centuries.',NULL);
INSERT INTO badges VALUES(119,'Cars Throughout History','cars-throughout-history-badge','Discover Science & Technology','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/cars-throughout-history-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cars have changed dramatically over a century—from boxy Model Ts to sleek electric vehicles. Explore how engineers keep reinventing the wheel, why trucks and SUVs exist, and what made each era''s cars special.','🚗');
INSERT INTO badges VALUES(120,'Cartography','cartography-badge','Discover the World','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/cartography-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Maps show our world in flat pictures, using symbols and grids to mark where things are. You''ll learn how cartographers turn real places into guides, then create your own maps from your bedroom to imaginary lands.','🗺️');
INSERT INTO badges VALUES(121,'Cartoons','cartoon-badge','Discover Art','','cartoon-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/cartoon-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cartoons come in wildly different styles—from the classic slapstick of Looney Tunes to the smooth computer animation of Pixar to the bold lines of anime. You''ll explore what makes each one unique, create your own character with personality and world, and discover how voice actors bring drawings to life.',NULL);
INSERT INTO badges VALUES(122,'Castles','castles-badge','Discover the World','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/castles-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Castles are fortified strongholds built centuries ago with towers, moats, and drawbridges to protect kingdoms and their rulers. Explore how these massive stone structures were designed for defense, discover famous castles from around the world, and learn the purpose of every battlement and arrow loop.','🏰');
INSERT INTO badges VALUES(123,'Cats','cats-badge','Discover the Home','Sharon Konnick','cats-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/cats-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cats are fascinating companions with their own language of meows, purrs, and tail flicks. Discover what makes different breeds unique, how to handle them gently, and what keeps them healthy and happy.',NULL);
INSERT INTO badges VALUES(124,'Ceramics','ceramics-badge','Discover Art','','ceramics-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/ceramics-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Ceramics are clay creations that harden into dishes, sculptures, tiles, and so much more—you probably use or see them every single day. Learn where ceramics hide in your home, try hand-building techniques like pinching and coiling, and discover why this ancient craft is everywhere around you.',NULL);
INSERT INTO badges VALUES(125,'Ceramic Painting','ceramics-painting-badge','Discover Art','',NULL,0,NULL,'https://curiosityuntamed.com/badges/ceramics-painting-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Turn plain white pottery into colorful art by painting ceramic pieces with brushes, sponges, and stencils. Whether you''re decorating a tiny figurine or a dish, you''ll discover how different techniques and colors can bring ceramic art to life.','🎨');
INSERT INTO badges VALUES(126,'Chalk','chalk-badge','Discover Art','Suzanne Vicory','chalk-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/chalk-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Chalk is a soft, dusty material that''s been around for centuries—from cave art to blackboards to sidewalk masterpieces. Mix colors, blend them with your fingers, and discover why artists love this forgiving medium that lets you create and start over whenever you want.',NULL);
INSERT INTO badges VALUES(127,'Character (specific)','character-specific-badge','Discover Art','Kerry Cordy',NULL,1,NULL,'https://curiosityuntamed.com/badges/character-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pick any character that captures your imagination—from books, movies, games, or even someone you dream up yourself—and dive into who they really are. You''ll create a profile, design something from their world, and discover how characters become part of our favorite stories and real lives.','🎭');
INSERT INTO badges VALUES(128,'Charity','charity-badge','Discover Character','Kerry Cordy','charity-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/charity-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Charity means noticing when someone needs help and actually doing something about it. It''s about giving your time, stuff, or kindness—and discovering how good it feels to make someone''s day better.',NULL);
INSERT INTO badges VALUES(129,'Charity (Specific)','charity-specific-badge','Discover Character','Kerry Cordy','charity-specific-badge.jpg',1,'This badge may be earned multiple times. Once for each charity you wish to learn about and support.','https://curiosityuntamed.com/badges/charity-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Giving your time, money, or energy to help others is one of the most rewarding things you can do. Discover what causes matter most to you and find ways to make a real difference in your community.',NULL);
INSERT INTO badges VALUES(130,'Charles Dickens','charles-dickens-badge','Discover Knowledge','Charlotte Duke','charles-dickens-badge.jpg',0,'This badge is to encourage everyone to enjoy Charles Dickens’ works, so please feel free to read picture books, children’s versions, abridged versions or complete books according to your reading comfort level, or listen to audio books.','https://curiosityuntamed.com/badges/charles-dickens-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Charles Dickens wrote thrilling stories about life in Victorian England—tales filled with memorable characters like Scrooge, Pip, and Oliver Twist. Dive into his world and discover why his books have captured readers'' hearts for nearly 200 years.',NULL);
INSERT INTO badges VALUES(131,'Cheerleading','cheerleading-badge','Discover Health & Safety','Sarah Bruekherr',NULL,0,NULL,'https://curiosityuntamed.com/badges/cheerleading-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cheerleaders pump up crowds at games with synchronized moves, catchy chants, and high-flying jumps that take serious strength and teamwork. Master the sharp arm positions and explosive jumps that make cheerleading such an energetic sport.','📣');
INSERT INTO badges VALUES(132,'Cheese','cheese-badge','Discover Agriculture','Kerry Cordy','cheese-badge.png',0,NULL,'https://curiosityuntamed.com/badges/cheese-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":6}',1,'2026-05-20 16:10:36','Cheese comes from milk that''s transformed into hundreds of varieties—soft, hard, stinky, mild—each with its own flavor and texture. Taste your way through different types, discover where they come from, and find out why people have been making cheese for thousands of years.',NULL);
INSERT INTO badges VALUES(133,'Cheese Making','cheese-making-badge','Discover the Home','Renee Austin','cheese-making-badge.png',0,NULL,'https://curiosityuntamed.com/badges/cheese-making-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cheese starts as milk and transforms through simple chemistry into hundreds of varieties—creamy, crumbly, sharp, and mild. Make your own farmer cheese and mascarpone while tasting your way through the amazing flavors hiding in your kitchen.',NULL);
INSERT INTO badges VALUES(134,'Chef','chef-badge','Discover the Home','Doreen Olson','chef-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/chef-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A chef transforms ingredients into delicious meals through skill, creativity, and tons of practice. Discover what chefs wear and why each piece matters, explore how the right setting makes food taste even better, and learn about famous chefs who''ve changed how the world eats.',NULL);
INSERT INTO badges VALUES(135,'Chemistry','chemistry-badge-2','Discover Science & Technology','Kerry Cordy','chemistry-badge-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/chemistry-badge-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Everything around you is made of stuff that mixes, bubbles, melts, and transforms—and chemistry is the detective work of figuring out why. Watch colors swirl, liquids thicken, and gases fizz as you explore what happens when things meet and change.',NULL);
INSERT INTO badges VALUES(136,'Chess','chess-badge','Discover Knowledge','','chess-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/chess-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Chess is a game where each piece moves in its own special way, and you have to think several moves ahead to capture your opponent''s king. Master the pieces, set up the board, and play real games to discover why this ancient strategy game has captivated players for centuries.',NULL);
INSERT INTO badges VALUES(137,'Child Care','child-care-badge','Discover the Home','Kerry Cordy','child-care-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/child-care-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Babies and young kids need extra care—they can''t tell you what''s wrong, and little things like small toys or uncovered outlets become big dangers. This badge teaches you how to hold a baby safely, spot hazards before they happen, and help care for younger children with confidence.',NULL);
INSERT INTO badges VALUES(138,'Childhood Cancer Awareness','childhood-cancer-awareness-badge','Discover Health & Safety','','childhood-cancer-awareness-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/childhood-cancer-awareness-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cancer is a disease where cells in the body grow in unhealthy ways, and kids can get it too—though childhood cancers are different from adult cancers in important ways. Understanding what cancer is, how doctors treat it, and how to support kids facing this challenge makes a real difference.',NULL);
INSERT INTO badges VALUES(139,'Chocolate','chocolate-badge','Discover Knowledge','Abby Olson','chocolate-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/chocolate-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Chocolate comes from cacao beans grown on trees in tropical countries around the world. Taste different types, explore where they''re grown, and discover why chocolate made from scratch tastes different from the instant mix.',NULL);
INSERT INTO badges VALUES(140,'Christian Missionaries','christian-missionaries-badge','Discover Character','Elizabeth Simmons','christian-missionaries-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/christian-missionaries-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','People who dedicate their lives to sharing their faith travel to different countries and communities, teaching, helping the sick, building schools, and serving those in need. They live out their beliefs through action and compassion.',NULL);
INSERT INTO badges VALUES(141,'Christmas Around the World','christmas-around-the-world-badge','Discover the World','Mollie Comer','christmas-around-the-world-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/christmas-around-the-world-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Christmas looks different in every corner of the globe—some places celebrate with snow and sleighs, others with beaches and bonfires. Explore how families around the world decorate, feast, and give gifts in their own special ways.',NULL);
INSERT INTO badges VALUES(142,'Christmas Carols','christmas-carols-badge','Discover Knowledge','Katie Lundquist','christmas-carols-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/christmas-carols-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Christmas carols are songs that spread joy and tradition during the holiday season, from classic melodies like "Silent Night" to fun, singalong favorites. Explore the stories behind these beloved tunes and discover why people have sung them for centuries.',NULL);
INSERT INTO badges VALUES(143,'Christmas Ornament','christmas-ornaments-badge','Discover Art','Doreen Olson','christmas-ornaments-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/christmas-ornaments-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Handmade ornaments turn your creativity into something beautiful that hangs on the tree year after year. Whether you''re painting, sculpting, or assembling, you''ll create keepsakes that tell your family''s story.',NULL);
INSERT INTO badges VALUES(144,'Chronicles of Narnia','narnia-badge','Discover Knowledge','Ella Shapery','narnia-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/narnia-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','C.S. Lewis created a magical world hidden behind a wardrobe where talking animals, mythical creatures, and human kids battle darkness and discover courage. Step into Narnia and follow the unforgettable adventures of the Pevensies as they uncover what makes them heroes.',NULL);
INSERT INTO badges VALUES(145,'Circus','circus-badge','Discover Knowledge','Katie Lundquist','circus-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/circus-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The circus is a wild world of acrobats, animal trainers, clowns, and daring stunts that has thrilled audiences for centuries. Explore what makes circuses magical, from death-defying tricks to the history behind the big top.',NULL);
INSERT INTO badges VALUES(146,'Citizenship','citizenship-badge','Discover Character','Kerry Cordy','citizenship-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/citizenship-badge/','{"preschool":1,"level1":2,"level2":3,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Being a good citizen means helping others, following rules, and respecting your community. It''s about understanding your rights and responsibilities—from knowing the Pledge of Allegiance to learning why your vote matters and who leads your country.',NULL);
INSERT INTO badges VALUES(147,'Civil War','civil-war','Discover the World','Kerry Cordy','civil-war.jpg',0,NULL,'https://curiosityuntamed.com/badges/civil-war/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Civil War tore America apart from 1861 to 1865 as the Northern and Southern states fought over slavery, states'' rights, and the future of the country. Explore the causes, key battles, and turning points that shaped the nation and led to the end of slavery.',NULL);
INSERT INTO badges VALUES(148,'Classical Literature','classical-literature-badge','Discover Knowledge','Doreen Olson','classical-literature-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/classical-literature-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Stories written hundreds of years ago still captivate readers today—think epic adventures, timeless love stories, and unforgettable characters that shaped how we tell stories now. Dive into the classics and discover why certain books and authors have remained beloved across generations.',NULL);
INSERT INTO badges VALUES(149,'Clean Language','clean-language','Discover Character','Cassi Jensen','clean-language.jpg',0,NULL,'https://curiosityuntamed.com/badges/clean-language/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Words matter—how you speak affects how people feel and what they think of you. Clean language shows respect, builds trust, and keeps conversations kind and honest, even when things get tough.',NULL);
INSERT INTO badges VALUES(150,'Cleaning','cleaning-badge','Discover the Home','Doreen Olson','cleaning-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/cleaning-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A clean space feels better, works better, and makes everyone happier. Master the skills to tackle dust, dishes, laundry, and clutter—and discover why keeping your home fresh is a superpower.',NULL);
INSERT INTO badges VALUES(151,'Clothing Repair','clothing-repair','Discover the Home','Doreen Olson','clothing-repair.jpg',0,NULL,'https://curiosityuntamed.com/badges/clothing-repair/','{"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A loose button or torn seam doesn''t have to mean goodbye to your favorite shirt—you can fix it yourself with needle and thread. Master hand-sewing and machine repairs, then get creative solving the tricky problems that pop up when nothing matches quite right.',NULL);
INSERT INTO badges VALUES(152,'Coast Guard','coast-guard-badge','Discover Knowledge','Rigel Chidester','coast-guard-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/coast-guard-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Coast Guard protects America''s coasts and waterways, rescuing people in danger and stopping illegal activities at sea. Find out how these brave sailors got started, what their motto means, and the different ships they use to do their job.',NULL);
INSERT INTO badges VALUES(153,'Codes and Ciphers (Cryptology)','codes-and-ciphers-cryptology-badge','Discover Science & Technology','Ramon Gomez',NULL,0,NULL,'https://curiosityuntamed.com/badges/codes-and-ciphers-cryptology-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Secret messages have been hidden for thousands of years using clever tricks and patterns. Learn how spies, soldiers, and friends send coded messages that only the right person can crack—then create your own codes to share secret notes with others.','🔐');
INSERT INTO badges VALUES(154,'Coding with Scratch','coding-with-scratch','Discover Science & Technology','Heidi Cole','coding-with-scratch.jpg',0,NULL,'https://curiosityuntamed.com/badges/coding-with-scratch/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Scratch lets you drag colorful blocks together to make sprites dance, sing, and move on screen—no typing required. You''ll create your own animated band and discover how programmers bring ideas to life.',NULL);
INSERT INTO badges VALUES(155,'Coin Collecting','coin-collecting-badge','Discover the World','Kerry Cordy','coin-collecting-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/coin-collecting-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Coins tell the story of countries, rulers, and history all in your pocket. Start collecting different coins from around the world, hunt for rare varieties, and discover why some are worth more than others and what materials have been used to make them shine.',NULL);
INSERT INTO badges VALUES(156,'Cold War','cold-war-badge','Discover the World','Jennifer Milakovic','cold-war-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/cold-war-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','After World War II ended, the United States and Soviet Union became rivals without ever fighting directly—instead they competed through spies, weapons, and space races in what became the Cold War. Discover why two superpowers couldn''t get along, which nations picked sides, and how this tense standoff shaped the modern world.',NULL);
INSERT INTO badges VALUES(157,'Collage','collage-badge','Discover Art','Doreen Olson','collage-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/collage-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Collage is the art of cutting and gluing pieces—photos, paper, fabric, anything really—into one wild new creation. You''ll explore famous collage artists and make your own designs using nature and imagination.',NULL);
INSERT INTO badges VALUES(158,'Collecting','collecting-badge','Discover Knowledge','Kerry Cordy','collecting-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/collecting-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Collecting turns everyday objects into a treasure hunt—whether you''re after rocks, trading cards, or vintage bottle caps, each piece tells a story about where it came from and why it matters. Build a collection that''s uniquely yours, display it proudly, and become an expert on what makes your items special.',NULL);
INSERT INTO badges VALUES(159,'College (specific)','college-speci%ef%ac%81c-badge','Discover the World','Jen Milakovic Nelson',NULL,1,NULL,'https://curiosityuntamed.com/badges/college-speci%ef%ac%81c-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pick a college that interests you and become a campus expert—learn its colors, spot its mascot, and explore the grounds in person or online to see where students study, eat, and hang out. It''s your chance to imagine yourself there someday.','🎓');
INSERT INTO badges VALUES(160,'Colonial Williamsburg','colonial-williamsburg-badge','Discover the World','Wendy Conte','colonial-williamsburg-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/colonial-williamsburg-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Step back in time to Colonial Williamsburg, where you''ll explore what daily life looked like for people in America''s past. Walk through historic buildings, watch craftspeople work, and discover how colonists dressed, ate, and built their communities.',NULL);
INSERT INTO badges VALUES(161,'Color','color-badge','Discover Art','Kerry Cordy','color-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/color-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Colors mix and blend in surprising ways—red and yellow make orange, blue and yellow make green. Explore how artists use crayons, paints, pastels, and pencils to create new shades, tints, and tones on paper.',NULL);
INSERT INTO badges VALUES(162,'Coloring','coloring-badge','Discover Art','Samara Brandt','coloring-badge.png',0,NULL,'https://curiosityuntamed.com/badges/coloring-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Colors bring pictures to life, whether you''re using crayons, markers, or colored pencils. Learn the best ways to hold your tools and fill pages with vibrant shades, staying inside the lines and exploring different mediums along the way.',NULL);
INSERT INTO badges VALUES(163,'Comic Books','comic-book-badge','Discover Knowledge','Lisa Garner','comic-book-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/comic-book-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":6}',1,'2026-05-20 16:10:36','Comic books tell stories through pictures and words working together—speech bubbles show what characters say, and action lines make scenes feel fast and exciting. Dive into different comics to see how artists and writers create worlds you can''t wait to flip through.',NULL);
INSERT INTO badges VALUES(164,'Communications','2517-2','Discover Science & Technology','','2517-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/2517-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','People share ideas through phones, emails, letters, texts, and tons of other ways—and each one has its own story. Explore how humans stay connected across distances and time, and discover which brilliant minds invented the tools we use every day.',NULL);
INSERT INTO badges VALUES(165,'Community Safety','community-safety-badge','Discover Health & Safety','Kerry Cordy','community-safety-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/community-safety-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your community is designed with invisible helpers—crosswalks, street lights, and safety rules—that work together to keep everyone protected. Explore how these systems work, spot them in action around town, and figure out how to spread the safety message to your neighbors.',NULL);
INSERT INTO badges VALUES(166,'Company Towns','company-towns-badge','Discover the World','Carrie Ouellette','company-towns-badge.jpg',0,'Apply these badge requirements to any “town” that functions around a single specific industry. This badge can be earned for specific types of company towns IF all requirements focus on the same specific type of industry. Examples of specific types would include: Coal Mining Mill (steel/paper/saw/grain/textile) Logging Glass production So much more! Be sure to document which specific industry and company town you based your learning on and think about whether those findings would necessarily be true, or at least similar, for towns with the same industry nationwide or were perhaps unique to the town you chose to study.','https://curiosityuntamed.com/badges/company-towns-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Company towns were special villages built and run entirely by big businesses for their workers and families. These unique communities shaped how people lived, worked, and played all in one place controlled by a single company.',NULL);
INSERT INTO badges VALUES(167,'Compassion','compassion-badge','Discover Character','Sylvia Duke','compassion-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/compassion-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Compassion is the superpower of understanding how someone else feels and actually caring enough to help. It''s what turns someone''s bad day around and makes the world a little kinder.',NULL);
INSERT INTO badges VALUES(168,'Competitive Card Games','competitive-card-games-badge','Discover the World','',NULL,0,NULL,'https://curiosityuntamed.com/badges/competitive-card-games-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Card games have been around for centuries, and people everywhere play them to compete, strategize, and have fun. Master the rules of a real competitive game, practice your skills with friends and family, and discover what it takes to be a gracious winner and loser.','🃏');
INSERT INTO badges VALUES(169,'Composers','composers-badge','Discover Art','',NULL,0,NULL,'https://curiosityuntamed.com/badges/composers-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Composers are the creative minds behind the music you hear—they write the notes, melodies, and harmonies that make songs memorable. Explore the lives and sounds of different composers across history and discover what makes their music special to you.','🎵');
INSERT INTO badges VALUES(170,'Compost','compost-badge','Discover Agriculture','','compost-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/compost-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Kitchen scraps and yard waste don''t have to go in the trash—they can become dark, crumbly soil that helps gardens grow. Watch nature''s recyclers break down food and leaves into black gold while learning how decomposers, heat, and time transform waste into something alive and useful.',NULL);
INSERT INTO badges VALUES(171,'Computers','computer-badge-2','Discover Science & Technology','','computer-badge-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/computer-badge-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Computers are powerful machines that process information and help us create, learn, and connect—but they''re very different from a phone or TV. Explore how computers work, stay safe while using them, and discover how this incredible technology has transformed nearly everything around you over the past several decades.',NULL);
INSERT INTO badges VALUES(172,'Confidence','confidence-badge','Discover Character','Charlotte Duke','confidence-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/confidence-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Confidence is that inner voice that tells you to try something new, speak up in a group, or keep going when things get tough. It grows stronger every time you face a challenge and discover what you''re actually capable of.',NULL);
INSERT INTO badges VALUES(173,'Conservation','conservation-badge','Discover Character','Kerry Cordy','conservation-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/conservation-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":4}',1,'2026-05-20 16:10:36','Conservation means taking care of Earth by using less water, electricity, and heat at home. You''ll discover simple habits that help your family waste less and save money while protecting the planet together.',NULL);
INSERT INTO badges VALUES(174,'Cookies','cookies-badge','Discover the Home','Jen Milakovic','cookies-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/cookies-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cookies come in endless shapes and flavors—from chewy chocolate chip drops to delicate spritz swirls to no-bake peanut butter bites. Explore what makes each style unique, discover your favorites, and find out what happens in the kitchen when you mix, roll, and bake them just right.',NULL);
INSERT INTO badges VALUES(175,'Cooking','cooking-badge','Discover the Home','Kerry Cordy','cooking-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/cooking-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cooking is about creating delicious meals and snacks while staying safe in the kitchen. You''ll learn how to use tools, measure ingredients, follow recipes, and handle hot pans and sharp knives with a grown-up''s guidance—turning raw ingredients into something amazing to eat.',NULL);
INSERT INTO badges VALUES(176,'Cooking Demo','cooking-demonstration-badge','Discover the Home','Doreen Olson','cooking-demonstration-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/cooking-demonstration-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Watching someone cook is different from reading a recipe—you see the tricks, the timing, and what actually works. Show off your own cooking skills by demonstrating a dish or technique to others, and you''ll discover how to teach kitchen magic to someone else.',NULL);
INSERT INTO badges VALUES(177,'Cooking for Special Diets','cooking-for-special-diets-badge','Discover Health & Safety','Doreen Olson','cooking-for-special-diets-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/cooking-for-special-diets-badge/','{"level5":7}',1,'2026-05-20 16:10:36','Cooking tastes amazing when you know how to make meals for allergies, intolerances, and dietary choices like vegetarian or gluten-free. Feed people you care about while keeping them healthy and happy.',NULL);
INSERT INTO badges VALUES(178,'Coral Reefs','coral-reefs-badge','Discover the Outdoors','Sarah Bruekherr',NULL,0,NULL,'https://curiosityuntamed.com/badges/coral-reefs-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Coral reefs are underwater neighborhoods built by tiny animals called polyps that create colorful structures housing thousands of fish and creatures. Explore the different types of reefs around the world and discover how to protect them when you swim, snorkel, or dive.','🪸');
INSERT INTO badges VALUES(179,'Costume Making','costume-making-badge','Discover Art','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/costume-making-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Transform scraps, old clothes, and everyday stuff into amazing costumes that''ll blow people away. You''ll master the tools and tricks to turn cardboard boxes into armor, sheets into capes, and thrift store finds into anything your imagination dreams up.','🧵');
INSERT INTO badges VALUES(180,'Costumes Around the World','costumes-around-the-world','Discover the World','Abby Olson','costumes-around-the-world.jpg',0,NULL,'https://curiosityuntamed.com/badges/costumes-around-the-world/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every culture wraps itself in cloth, colors, and symbols that tell stories about where people live, what they do, and what matters to them. Explore costumes from around the globe and through history to see how clothing protects, celebrates, and transforms the people who wear it.',NULL);
INSERT INTO badges VALUES(181,'Costume Design','costume-design-badge','Discover Art','Doreen Olson','costume-design-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/costume-design-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Costumes tell stories without words—they show who a character is, where they come from, and even when they live. Design outfits that transform actors into pirates, royalty, time travelers, or anyone else you can imagine by using color, fabric, and historical details.',NULL);
INSERT INTO badges VALUES(182,'County/State Fair','county-state-fair-badge','Discover the World','Amanda Piccarillo','county-state-fair-badge.jpg',0,'This badge can be earned multiple times.  A specialized badge can be earned for each specific fair you study.','https://curiosityuntamed.com/badges/county-state-fair-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":6}',1,'2026-05-20 16:10:36','County and state fairs are bustling celebrations where farmers show off prize-winning pumpkins, kids exhibit their best baking and art, and livestock competitions draw huge crowds. These yearly traditions started over 200 years ago to help farmers share ideas and have grown into the colorful, quirky festivals with rides, games, and blue ribbons that still happen everywhere today.',NULL);
INSERT INTO badges VALUES(183,'Courage','courage-badge','Discover Character','Suzanne Vicoryosmanson','courage-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/courage-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Courage isn''t about being fearless—it''s about doing hard things even when you''re nervous or scared. Find out what real courage looks like in your own life and discover how to keep going when things feel tough.',NULL);
INSERT INTO badges VALUES(184,'Cowgirl/Cowboy','cowgirl-badge','Discover Agriculture','Kerry Cordy','cowgirl-badge.jpg',0,'You may complete this badge studying either cowboys, cowgirls, or both. Warning: Searching the term “cowboy” or “cowgirl” on the internet can bring up some unsavory websites. Please make sure that any online research is done with adult supervision.','https://curiosityuntamed.com/badges/cowgirl-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cowboys and cowgirls work on ranches herding cattle, mending fences, and riding across big open land—skills that look different today than they did in the 1800s. Meet the real people who shaped this tough, adventurous way of life.',NULL);
INSERT INTO badges VALUES(185,'Crafts','crafts-badge','Discover Art','Kerry Cordy','crafts-badge.jpg',0,'Make sure an adult is present to help on projects that require heat or sharp objects.','https://curiosityuntamed.com/badges/crafts-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Crafts are all about turning materials like paper, wood, paint, and glue into something totally yours. You''ll make cards, build wooden projects, and discover decoupage—the cool technique of gluing colorful paper pieces onto objects to create beautiful designs.',NULL);
INSERT INTO badges VALUES(186,'Crepes','crepes-badge','Discover the Home','Lily Seeley','crepes-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/crepes-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Crepes are thin, delicate pancakes that can be sweet or savory, and they''re a fun French treat to make and eat. You''ll discover what makes them special, taste a few different kinds, and help cook up a batch in the kitchen.',NULL);
INSERT INTO badges VALUES(187,'Criminal Forensics','criminal-forensics-badge','Discover Knowledge','Amy Ivy','criminal-forensics-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/criminal-forensics-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fingerprints, fibers, and evidence tell the story of what happened at a crime scene. Detectives use forensic science to find clues, match patterns, and solve mysteries that seem impossible at first.',NULL);
INSERT INTO badges VALUES(188,'Crochet','crochet-badge-2','Discover the Home','Doreen Olson','crochet-badge-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/crochet-badge-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Crochet turns a single strand of yarn into cozy blankets, scarves, and stuffed creations using just a hook and your hands. You''ll learn the basic stitches and techniques to loop yarn into something soft and useful that you made yourself.',NULL);
INSERT INTO badges VALUES(189,'Cross Stitch','cross-stitch-badge','Discover Art','Kerry Cordy','cross-stitch-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/cross-stitch-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Thread and needle meet fabric in a craft where tiny X-shaped stitches build colorful patterns and pictures. Turn cloth into decorated bookmarks, towels, and keepsakes with patience and precise, satisfying stitches.',NULL);
INSERT INTO badges VALUES(190,'Cruise Badge','cruise-badge','Discover the World','Susie Rodriguez','cruise-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/cruise-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Massive floating cities with thousands of people, multiple restaurants, theaters, and pools—cruise ships are like nothing else. Explore the different cruise lines that sail the world, discover how ships evolved over time, and uncover the stories behind this amazing way to travel.',NULL);
INSERT INTO badges VALUES(191,'Cryptids','cryptids-badge','Discover Knowledge','Sarah Bruekherr',NULL,0,NULL,'https://curiosityuntamed.com/badges/cryptids-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cryptids are mysterious creatures that people claim to see but scientists haven''t proven exist—like Bigfoot, the Loch Ness Monster, and the Yeti. You''ll explore famous cryptid stories, discover why some animals were once thought impossible, and decide for yourself whether these elusive beings are real, imaginary, or hiding somewhere in between.','👣');
INSERT INTO badges VALUES(192,'Culture by Country','cultures-by-country-badges','Discover the World','Tracy Price','cultures-by-country-badges.jpg',0,'This badge can be used to earn multiple individual badges. You can earn a culture badge for any country in the world.','https://curiosityuntamed.com/badges/cultures-by-country-badges/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every country has its own way of doing things—different foods, music, languages, and traditions that make it special. Pick one place in the world and dive in: taste what people eat there, hear their music, find it on a map, and learn to say hello in their language.',NULL);
INSERT INTO badges VALUES(193,'Dairying','dairying-badge','Discover Agriculture','Kerry Cordy','dairying-badge.jpg',0,'This badge can be earned for either dairy cows or dairy goats.','https://curiosityuntamed.com/badges/dairying-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Dairy farms turn milk from cows and goats into the cheese, yogurt, and butter we eat. Explore what it takes to care for these animals, recognize different breeds, and understand the tools and spaces that keep a dairy running smoothly.',NULL);
INSERT INTO badges VALUES(194,'Decoupage','decoupage-badge','Discover Art','Kerry Cordy','decoupage-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/decoupage-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Decoupage is the art of cutting out colorful paper pictures and gluing them onto objects to create beautiful, personalized designs. You''ll discover how the right brushes, glues, and techniques can transform anything from boxes to furniture into one-of-a-kind masterpieces.',NULL);
INSERT INTO badges VALUES(195,'Dental Hygiene','dental-hygiene','Discover Health & Safety','Debbie Weaver','dental-hygiene.jpg',0,NULL,'https://curiosityuntamed.com/badges/dental-hygiene/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your teeth are always working—chewing, smiling, talking—so they need real care to stay strong and healthy. Learn the best ways to brush and floss, what cavities really are, and how to keep your smile in great shape for life.',NULL);
INSERT INTO badges VALUES(196,'Digital Movie Making','digital-movie-maker','Discover Art','','digital-movie-maker.png',0,'You will need a video camera or cell phone capable of video recording to complete this badge.','https://curiosityuntamed.com/badges/digital-movie-maker/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Movies start with an idea, a camera, and people willing to act it out. You''ll learn how to frame shots, keep the camera steady, and use editing software to turn raw footage into a story that actually works.',NULL);
INSERT INTO badges VALUES(197,'Diligence','diligence-badge','Discover Character','Kerry Cordy','diligence-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/diligence-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Diligence is about showing up and doing the work, even when it''s boring or hard. Sticking with something until it''s done well—whether it''s homework, a project, or helping someone—builds real strength of character.',NULL);
INSERT INTO badges VALUES(198,'Diners','diners-badge','Discover the World','The Lundquists',NULL,0,NULL,'https://curiosityuntamed.com/badges/diners-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Diners are casual American restaurants where you can grab breakfast all day, milk shakes, and comfort food classics. Explore the culture, history, and charm of these neighborhood gathering spots.','🍔');
INSERT INTO badges VALUES(199,'Dinosaurs','dinosaurs','Discover Knowledge','Adele Nolan','dinosaurs.jpg',0,NULL,'https://curiosityuntamed.com/badges/dinosaurs/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Dinosaurs roamed Earth millions of years ago in shapes and sizes you wouldn''t believe—some were massive meat-eaters, others munched plants all day long. Discover what these ancient reptiles looked like, why they disappeared, and how we know they ever existed.',NULL);
INSERT INTO badges VALUES(200,'Dips','dips-badge','Discover the Home','Katie Lundquist',NULL,0,NULL,'https://curiosityuntamed.com/badges/dips-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Dips are the perfect party food that transforms simple ingredients into something creamy, tangy, or spicy. Mix up classics like guacamole and salsa, or try something unexpected—your snacks will never be the same.','🥑');
INSERT INTO badges VALUES(201,'Diseases and Genetic Disorders (Specific)','diseases-specific-badge','Discover Health & Safety','Kerry Cordy','diseases-specific-badge.jpg',1,'This badge is designed to be adapted to learn about and bring awareness to any specific disease or genetic disorder. It can be earned multiple times, once for each disease studied.  Some members have submitted specific requirements for various diseases/disorders. Links to these requirements can be found at the bottom of this page. You may use either the general requirements listed below, the specific requirements listed in the link, or a combination of the two to earn your badge.','https://curiosityuntamed.com/badges/diseases-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Some diseases and genetic disorders change how a body works, and understanding them helps us support people who live with them. Pick one to investigate—learn its symptoms, find its awareness symbol, build a model showing what happens inside the body, and discover how doctors treat it.',NULL);
INSERT INTO badges VALUES(202,'Disney','disney','Discover Knowledge','Adele Nolan','disney.jpg',0,NULL,'https://curiosityuntamed.com/badges/disney/','{"preschool":1,"level1":2,"level2":3,"level3":3,"level4":4,"level5":7}',1,'2026-05-20 16:10:36','Walt Disney created a magical empire of animated movies, unforgettable characters, and storytelling that''s enchanted families for generations. Explore the films and characters that made Disney a household name, and discover the dreamer behind it all.',NULL);
INSERT INTO badges VALUES(203,'Disneybounding','disneybounding-badge','Discover Art','','disneybounding-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/disneybounding-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Disneybounding is the art of creating outfits inspired by your favorite Disney characters using everyday clothes. Mix colors, patterns, and accessories to show which character you love without wearing an actual costume.',NULL);
INSERT INTO badges VALUES(204,'Disney Animal Kingdom','14887-2','Discover the World','Joanna Durando','14887-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/14887-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',0,'2026-05-20 16:10:36','Disney''s Animal Kingdom is a theme park where real animals roam across habitats inspired by Africa, Asia, and exotic islands. You''ll explore how the park blends thrilling attractions with genuine wildlife conservation and education.',NULL);
INSERT INTO badges VALUES(205,'Disney California Adventure','disney-california-adventure-badge','Discover the World','Sara Rauta','disney-california-adventure-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/disney-california-adventure-badge/','{"preschool":1,"level1":1,"level2":1,"level3":1,"level4":1,"level5":1}',1,'2026-05-20 16:10:36','Disney California Adventure is a theme park celebrating the Golden State with eight unique lands, thrilling rides based on your favorite movies, and magical snacks you can taste and recreate. Explore every corner, find your favorite attractions, and discover the stories behind the park''s design.',NULL);
INSERT INTO badges VALUES(206,'Disney Epcot','disney-epcot-badge','Discover the World','Joanna Durando','disney-epcot-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/disney-epcot-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',0,'2026-05-20 16:10:36','Epcot is a theme park where you can travel around the world without leaving Florida, exploring eleven different country pavilions with their own food, music, and culture. From tasting treats in France to learning about traditions in Japan, it''s like taking a passport-free trip around the globe in one day.',NULL);
INSERT INTO badges VALUES(207,'Disney Hollywood Studios','14896-2','Discover the World','Joanna Durando','14896-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/14896-2/','{"preschool":1,"level1":1,"level2":1,"level3":1,"level4":1,"level5":1}',0,'2026-05-20 16:10:36','Disney''s Hollywood Studios is a theme park where movie magic comes to life through thrilling rides, spectacular shows, and behind-the-scenes glimpses of filmmaking. Explore the attractions and entertainment that celebrate the golden age of Hollywood and modern Disney storytelling.',NULL);
INSERT INTO badges VALUES(208,'Disney Magic Kingdom','14900-2','Discover the World','Joanna Durando','14900-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/14900-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',0,'2026-05-20 16:10:36','The Magic Kingdom is where fairy tales come to life through incredible attractions, enchanted castles, and characters that step right off the screen. Explore the magic behind one of the world''s most famous theme parks and discover what makes it so special.',NULL);
INSERT INTO badges VALUES(209,'Disneyland','disneyland-badge','Discover the World','Sara Rauta','disneyland-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/disneyland-badge/','{"preschool":1,"level1":1,"level2":1,"level3":1,"level4":1,"level5":1}',1,'2026-05-20 16:10:36','Disneyland is a magical theme park divided into nine different lands, each with its own character and attractions. You''ll meet classic Disney characters, ride thrilling attractions, taste iconic treats, and discover the history and creativity behind Walt Disney''s original vision.',NULL);
INSERT INTO badges VALUES(210,'Disney Princesses (Specific)','disney-princesses-badge','Discover Knowledge','','disney-princesses-badge.jpg',1,'A specific badge may be earned for each Disney princess.','https://curiosityuntamed.com/badges/disney-princesses-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Disney Princesses have led epic adventures across magical kingdoms, each with their own unique gifts and strengths. Explore the stories of your favorite heroines, uncover what makes them brave or clever, and discover how their special powers—or the magic around them—change their worlds.',NULL);
INSERT INTO badges VALUES(211,'Disney World Outside the Parks','disney-world-outside-the-parks-badge','Discover the World','',NULL,0,NULL,'https://curiosityuntamed.com/badges/disney-world-outside-the-parks-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',0,'2026-05-20 16:10:36','Orlando has way more to explore beyond the theme parks—shopping districts, nature trails, wildlife encounters, and local restaurants that locals love. Discover the magic hiding in the rest of Central Florida.','🦁');
INSERT INTO badges VALUES(212,'Doctor Who','doctor-who-badge','Discover Knowledge','Kimberlynn Swafford','doctor-who-badge.jpg',0,'Doctor Who is considered a cult TV series and although it is not offensive by today’s standards, it may contain materials that can be scary for young children. Parental supervision and permission are required for Preschool – Level 2 for this badge.','https://curiosityuntamed.com/badges/doctor-who-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Doctor is a time traveler who zips through space and time in the T.A.R.D.I.S., a ship that looks like a blue police box. Explore one of the longest-running sci-fi shows ever, meet the aliens and companions who travel with the Doctor, and uncover the mysteries of time travel itself.',NULL);
INSERT INTO badges VALUES(213,'Dogs','dogs-badge','Discover the Home','Adele Nolan','dogs-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/dogs-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Dogs have been human companions for thousands of years, and they come in hundreds of breeds—from tiny chihuahuas to giant Great Danes. Learn what makes dogs tick: their body parts, how they grow from puppies to adults, different breeds around the world, and how to interact with them safely and kindly.',NULL);
INSERT INTO badges VALUES(214,'Dog Training','dog-training-badge','Discover the Home','Francine Geissler','dog-training-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/dog-training-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Dogs are eager to learn, and teaching them commands like sit, stay, or come strengthens your bond while keeping them safe and happy. Master the patience and timing it takes to train a pup, and discover why consistency and rewards turn a wiggly puppy into a well-behaved companion.',NULL);
INSERT INTO badges VALUES(215,'Dolls','doll-badge','Discover Knowledge','Doreen Olson','doll-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/doll-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Dolls come in countless styles—from baby dolls and fashion dolls to cultural treasures and handmade creations—each with its own story. Explore doll history, craft accessories, and discover how these companions have entertained kids around the world for centuries.',NULL);
INSERT INTO badges VALUES(216,'Donuts','donuts-badge','Discover the Home','Shelley Frausto','donuts-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/donuts-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":4,"level5":6}',1,'2026-05-20 16:10:36','Donuts are sweet, circular treats with a hole in the middle and endless flavor possibilities—from classic glazes to colorful sprinkles and fillings. Making them at home means mastering dough, frying techniques, and the art of toppings that taste as good as they look.',NULL);
INSERT INTO badges VALUES(217,'Dr. Seuss','dr-seuss-badge','Discover Knowledge','Lauren Greenfield','dr-seuss-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/dr-seuss-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Dr. Seuss wrote wild, rhyming stories full of invented creatures, impossible worlds, and characters who learn big lessons. His bouncy words and silly drawings have made kids giggle and think for over 70 years.',NULL);
INSERT INTO badges VALUES(218,'Drama','drama-badge','Discover Art','Kerry Cordy','drama-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/drama-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Drama is about people telling stories through acting, emotions, and movement. You''ll discover how actors bring characters to life, spot the difference between main roles and extras, and learn how your voice and body can completely change what a character feels.',NULL);
INSERT INTO badges VALUES(219,'Drawing','drawing-badge','Discover Art','Kerry Cordy','drawing-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/drawing-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Drawing lets you capture anything you imagine—a favorite pet, a wild landscape, or something totally made up—using just pencils, ink, or charcoal. The more you draw the same thing over and over, the steadier your hand gets and the better you understand what you''re really seeing.',NULL);
INSERT INTO badges VALUES(220,'Drinks','drinks-badge','Discover the Home','','drinks-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/drinks-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Drinks come in endless varieties—from herbal teas and smoothies to hot chocolate and sparkling water—each with its own flavor and story. Explore what''s out there, taste new things, and discover which ones become your favorites.',NULL);
INSERT INTO badges VALUES(221,'Drivers Training','drivers-training-badge','Discover Health & Safety','Doreen Olson','drivers-training-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/drivers-training-badge/','{"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Getting behind the wheel means learning the rules of the road, understanding how your car works, and developing the focus and judgment to drive safely. It''s about becoming a responsible driver who can handle different conditions and keep everyone on the road safe.',NULL);
INSERT INTO badges VALUES(222,'Drones','drone-badge','Discover Science & Technology','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/drone-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Drones are flying machines controlled from the ground that come in dozens of shapes and sizes, from tiny quadcopters to large fixed-wing aircraft. Discover what makes them different from planes and helicopters, explore the pilots who fly them for fun or work, and learn why drones are becoming tools for everything from photography to firefighting.','🛸');
INSERT INTO badges VALUES(223,'Drug Awareness','drug-awareness-badge','Discover Health & Safety','',NULL,0,NULL,'https://curiosityuntamed.com/badges/drug-awareness-badge/','{}',0,'2026-05-20 16:10:36','Your body is a complex system, and some substances can change how it works—sometimes helping, sometimes harming. Understanding drugs, how they affect you, and how to make smart choices keeps you healthy and safe.','🧠');
INSERT INTO badges VALUES(224,'Ducks','ducks-badge','Discover Agriculture','Kerry Cordy','ducks-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/ducks-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Ducks are waterfowl that waddle on land, paddle in water, and come in surprising varieties—from colorful wood ducks to quiet dabbling ducks. Meet real duck keepers, learn what makes males and females different, and discover how to call ducks like their own language.',NULL);
INSERT INTO badges VALUES(225,'Duct Tape','duct-tape-badge','Discover Knowledge','Hannah Lundquist','duct-tape-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/duct-tape-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','That sticky, silver tape in your garage holds everything together—literally. Duct tape started as a military supply and became the go-to fix for everything from torn backpacks to broken furniture, so find out what makes it stick better than regular tape and how it''s actually made.',NULL);
INSERT INTO badges VALUES(226,'Earth Day','earth-day-badge','Discover the World','Wanda Rupright','earth-day-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/earth-day-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Earth Day celebrates our planet and the people working to protect it. Explore why this global holiday matters, discover what your community does to help the environment, and get creative by turning trash into treasure.',NULL);
INSERT INTO badges VALUES(227,'Ecology','ecology-badge','Discover Science & Technology','Debbie Weaver','ecology-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/ecology-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Ecology is all about how living things interact with each other and their environment—from tiny insects in the soil to the biggest animals and plants. It''s the science of connection, showing you how forests, oceans, and ecosystems stay balanced and alive.',NULL);
INSERT INTO badges VALUES(228,'Edible Art','edible-art-badge','Discover Art','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/edible-art-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Food is art you can actually eat. Turn fruits, cookies, candy, and vegetables into colorful creatures, fancy cakes, and wild sculptures that taste as good as they look.','🍰');
INSERT INTO badges VALUES(229,'Egg Art','egg-art-badge','Discover Art','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/egg-art-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Eggshells are blank canvases waiting for color, patterns, and creativity. Turn hollow eggs into decorated masterpieces, painted portraits, or carved designs that show off your artistic imagination.','🥚');
INSERT INTO badges VALUES(230,'Eggs','egg-badge','Discover the Home','Amy Chartier','egg-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/egg-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Eggs come in all shapes, sizes, and colors—from tiny quail eggs to giant ostrich eggs—and they''re laid by birds, reptiles, fish, and insects all over the world. Learn to crack, separate, and cook them like a pro while discovering why this humble ingredient is so important in kitchens everywhere.',NULL);
INSERT INTO badges VALUES(231,'Elastic','elastics-badge','Discover Science & Technology','Charlotte Duke','elastics-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/elastics-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Elastic materials snap back to their original shape after stretching, squishing, or twisting—like rubber bands, bouncy balls, and springs. Explore what makes things stretchy and how that springy power is useful all around you.',NULL);
INSERT INTO badges VALUES(232,'Elections','elections-and-voting-badge','Discover Knowledge','Kerry Cordy','elections-and-voting-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/elections-and-voting-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Voting is how people choose their leaders and decide on rules that affect their town, state, and country. From presidents to sheriffs to school board members, elections shape the laws and services you live with every day.',NULL);
INSERT INTO badges VALUES(233,'Electricity','electricity-badge-2','Discover Science & Technology','Kerry Cordy','electricity-badge-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/electricity-badge-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Electricity powers everything around you, from your phone to your home. Discover how it''s generated, how to use it safely, and the invisible circuits that make modern life work.',NULL);
INSERT INTO badges VALUES(234,'Embrace Neurodiversity','embrace-neurodiversity-badge','Discover Character','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/embrace-neurodiversity-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Everyone''s brain works in its own unique way—some people think in pictures, others hyperfocus intensely, and some process the world differently than expected. Understanding neurodiversity means appreciating how those differences make people special and learning how to be a better friend to people whose brains just work differently than yours.','🧩');
INSERT INTO badges VALUES(235,'Embroidery','embroidery-badge','Discover Art','Charlotte Duke','embroidery-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/embroidery-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Thread and needle transform plain fabric into colorful designs with just a few basic stitches. Running stitch, backstitch, cross-stitch, chain stitch—each one creates different textures and patterns that you can combine into flowers, borders, and pictures that last.',NULL);
INSERT INTO badges VALUES(236,'Emergency Preparedness','emergency-preparedness-badge','Discover Health & Safety','Kerry Cordy','emergency-preparedness-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/emergency-preparedness-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','When disasters strike, staying calm and knowing what to do can save lives—yours and others''. Learn how to prepare your family, handle emergencies in the moment, and recover safely afterward by understanding the real dangers where you live.',NULL);
INSERT INTO badges VALUES(237,'Emergency Services (Specific)','emergency-services-badge','Discover Health & Safety','Katie Lundquist','emergency-services-badge.jpg',1,NULL,'https://curiosityuntamed.com/badges/emergency-services-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level5":7}',1,'2026-05-20 16:10:36','Fire fighters, police officers, paramedics, and search and rescue teams are ready to help when emergencies happen. Find out what these real heroes do, visit their station, and learn how to call for help when you need it.',NULL);
INSERT INTO badges VALUES(238,'Endangered Species','endangered-species-badge','Discover the Outdoors','Melissa Oyler','endangered-species-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/endangered-species-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Some animals are running out of time because their homes are disappearing or they''re hunted too much. Meet the creatures fighting to survive and find out what people are doing to bring them back from the brink.',NULL);
INSERT INTO badges VALUES(239,'Engineering','engineering-badge','Discover Science & Technology','Ramon Gomez',NULL,0,NULL,'https://curiosityuntamed.com/badges/engineering-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Engineering is about solving problems and building things that work—from bridges and robots to apps and medical devices. Explore how shapes and structures stay strong, discover what different engineers actually do, and design your own creation from start to finish.','🏗️');
INSERT INTO badges VALUES(240,'Entrepreneur','entrepreneur-badge','Discover Knowledge','Kerry Cordy','entrepreneur-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/entrepreneur-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','An entrepreneur spots a problem and builds a business to solve it—whether that''s selling lemonade, crafting items, or offering services like leaf raking. You''ll learn how money flows in (revenue) and out (expenses), what profit really means, and how to turn an idea into something real.',NULL);
INSERT INTO badges VALUES(241,'Escape Rooms','escape-room-badge','Discover Knowledge','Emily Foster',NULL,0,NULL,'https://curiosityuntamed.com/badges/escape-room-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Escape rooms lock you in with puzzles, hidden clues, and riddles you have to solve together to get out before time runs out. It''s like being inside a mystery where teamwork, logic, and quick thinking are your best tools.','🔐');
INSERT INTO badges VALUES(242,'Etiquette','etiquette-badge','Discover Character','Kerry Cordy','etiquette-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/etiquette-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Good manners and respect make every interaction smoother, whether you''re at the dinner table, playing a game, or meeting someone new. Master the thoughtful habits that show others you care—from listening without interrupting to thanking people genuinely, respecting differences, and being kind whether you win or lose.',NULL);
INSERT INTO badges VALUES(243,'Event Planning','event-planning-badge','Discover the Home','','event-planning-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/event-planning-badge/','{"preschool":0,"level1":0,"level2":0,"level3":0,"level4":0,"level5":0}',1,'2026-05-20 16:10:36','Throwing a party, ceremony, or fundraiser takes more than just showing up—you''ll juggle dates, budgets, themes, food, and finding the perfect spot to gather everyone. Plan an event from start to finish and discover how all the behind-the-scenes details come together to make something memorable.',NULL);
INSERT INTO badges VALUES(244,'Eyes','eyes-badge','Discover Science & Technology','Deborah Header',NULL,0,NULL,'https://curiosityuntamed.com/badges/eyes-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your eyes are amazing cameras that catch light and send pictures to your brain, but they need care to work their best. Explore how different animals see the world differently, what makes glasses work, and the science of light bending through lenses.','👁️');
INSERT INTO badges VALUES(245,'Fabric Wrapping','fabric-wrapping','Discover the Home','','fabric-wrapping.jpg',0,NULL,'https://curiosityuntamed.com/badges/fabric-wrapping/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Wrapping cloth is an ancient, reusable way to package gifts and carry things without plastic or paper waste. Learn how different folding techniques work across cultures, from Japanese furoshiki to other creative wrapping styles that turn fabric into function.',NULL);
INSERT INTO badges VALUES(246,'Face Painting','face-painting-badge','Discover Art','Kathleen Edwards','face-painting-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/face-painting-badge/','{"preschool":1,"level1":2,"level2":3,"level3":3,"level4":4,"level5":7}',1,'2026-05-20 16:10:36','Your face is a blank canvas waiting for color, glitter, and wild designs. Transform yourself into a glamorous character, a fierce animal, a silly clown, or anything your imagination dreams up—and discover the paints, styles, and tricks that make it all possible.',NULL);
INSERT INTO badges VALUES(247,'Fairies','fairy-badge','Discover Knowledge','Kerry Cordy','fairy-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/fairy-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fairies flutter through countless stories, movies, and poems—from tiny wing-tipped helpers to magical troublemakers. Explore the fairy tales you love, meet the enchanting characters who live in them, and then dream up your very own fairy with a unique personality and magical home.',NULL);
INSERT INTO badges VALUES(248,'Fairy Garden','fairy-garden-badge','Discover Knowledge','Chana Barak','fairy-garden-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/fairy-garden-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A fairy garden is a tiny magical world you create with miniature plants, paths, and little structures—perfect for tucking into a corner, a container, or even around a tree. Design and build your own enchanted space where fairies might rest, explore, and play.',NULL);
INSERT INTO badges VALUES(249,'Fairy Tales','fairy-tale-badge','Discover Knowledge','Kerry Cordy','fairy-tale-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/fairy-tale-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fairy tales are classic stories filled with magic, adventure, and good triumphing over evil. Dive into different versions of beloved tales, discover how stories change across cultures and time, and create your own twisted version set in today''s world.',NULL);
INSERT INTO badges VALUES(250,'Faith/Faithfulness','faith-badge','Discover Character','Kerry Cordy','faith-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/faith-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Faithfulness means showing up for people and promises, even when it''s hard or nobody''s watching. It''s about being reliable, honest, and sticking with what matters most to you.',NULL);
INSERT INTO badges VALUES(251,'Family','family-badge','Discover the Home','Kerry Cordy','family-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/family-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your family is unique—with its own story, roles, and connections stretching back through time. Explore who your relatives are, what makes your family tick, and why every family deserves respect.',NULL);
INSERT INTO badges VALUES(252,'Fantasy','the-fantasy-badge','Discover Knowledge','Tabitha Simicsak','the-fantasy-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/the-fantasy-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fantasy worlds are filled with magical creatures and epic adventures that don''t exist in real life—think dragons, unicorns, and trolls. Dive into stories where anything is possible and explore the imaginative beings that populate these enchanted realms.',NULL);
INSERT INTO badges VALUES(253,'Farm Animals (Specific)','farm-animals-badge','Discover Agriculture','Kerry Cordy','farm-animals-badge.jpg',1,'This badge can be earned as a general Farm Animals badge, or can be adapted to earn an individual badge on any specific farm animal. Examples include pigs, sheep, goats, cattle, chickens, etc. For the purpose of this badge, farm animals include any animal raised for what it produces; meat, milk, eggs, fur, wool, etc. Horses and  poultry have their own specific requirements.','https://curiosityuntamed.com/badges/farm-animals-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Farm animals are raised for food, wool, milk, and companionship—each one has special needs and cool names for males, females, and babies. Get up close with creatures like cows, chickens, goats, and alpacas to discover what they eat, how they live, and why farmers depend on them.',NULL);
INSERT INTO badges VALUES(254,'Farmer','farmer-badge','Discover Agriculture','Kerry Cordy','farmer-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/farmer-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Farms grow food and raise animals in so many different ways—from small family plots to massive operations with thousands of acres. Explore what farmers actually do, how they prepare soil and care for crops, and discover the big differences between a backyard garden and a corporate farm.',NULL);
INSERT INTO badges VALUES(255,'Farm Equipment','farm-equipment-badge','Discover Agriculture','Kerry Cordy','farm-equipment-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/farm-equipment-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Farms need big powerful machines to plant seeds, harvest crops, and care for animals—from tractors and tillers to sprayers and milking equipment. Safety matters most when working around these machines, so you''ll learn what gear to wear, how to stay alert, and which equipment does what.',NULL);
INSERT INTO badges VALUES(256,'Fashion Design','fashion-design-badge','Discover Art','Doreen Olson','fashion-design-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/fashion-design-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":4,"level5":7}',1,'2026-05-20 16:10:36','Clothes tell a story about who we are, and fashion designers decide what that story looks like—from the fabrics they pick to where they place a bright color or bold pattern. Sketch your own designs, explore textures like denim and velvet, and discover how a simple shirt becomes something special.',NULL);
INSERT INTO badges VALUES(257,'Fashion History','fashion-history-badge','Discover Knowledge','',NULL,0,NULL,'https://curiosityuntamed.com/badges/fashion-history-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Clothes tell the story of history—from fancy Victorian dresses to roaring twenties flapper styles to today''s sneakers and hoodies. Travel through different time periods and discover how people dressed, why their fashions changed, and what vintage, retro, and antique really mean.','👗');
INSERT INTO badges VALUES(258,'Fast Food','fast-food-badge','Discover Health & Safety','',NULL,0,NULL,'https://curiosityuntamed.com/badges/fast-food-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fast food is everywhere, but what makes it "fast"—and what''s really inside those meals? You''ll check out what''s in popular fast food items, figure out which ones fit into a healthy diet, and see how restaurants make food so quickly compared to cooking at home.','🍔');
INSERT INTO badges VALUES(259,'Felt','felt-badge','Discover Knowledge','','felt-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/felt-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Felt is a fabric made by matting wool fibers together—no knitting or weaving needed. You can cut, glue, and stitch it into colorful toys, decorations, and wearables with surprisingly simple techniques.',NULL);
INSERT INTO badges VALUES(260,'Feral Horses','feral-horses-badge','Discover the Outdoors','Claudia RichardsonPreschool',NULL,0,NULL,'https://curiosityuntamed.com/badges/feral-horses-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Wild horses roam free across plains and deserts, living in herds with their own social rules and survival strategies. These majestic animals have adapted to life without human care, and their behavior tells the story of how horses thrive in the wild.','🐴');
INSERT INTO badges VALUES(261,'Fidgets','fidgets-badge','Discover Science & Technology','Amanda Piccirillo','fidgets-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/fidgets-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fidgets are little tools and toys that keep your hands busy while your brain focuses. Whether it''s spinners, popits, or stress balls, they''re designed to channel wiggles into something satisfying.',NULL);
INSERT INTO badges VALUES(262,'Fire Building','fire-building-badge','Discover the Outdoors','Kerry Cordy','fire-building-badge.jpg',0,'The Fire Safety badge must be earned in order for a member to build, tend, extinguish, or cook over an open flame. Members need to earn the Fire Building badge before being allowed to start a fire. This badge must be earned again every time a member graduates to a new level in order to review the information. Due to the advanced nature of this badge, it is not offered to Preschool and Level 1 members.','https://curiosityuntamed.com/badges/fire-building-badge/','{"level2":0,"level3":0,"level4":0,"level5":0}',1,'2026-05-20 16:10:36','A good fire starts with understanding tinder, kindling, and fuel—the three materials that work together to create a safe, lasting flame. Master fire safety rules, learn to strike matches and use lighters, and build teepee, log cabin, and trench fires for different outdoor situations.',NULL);
INSERT INTO badges VALUES(263,'Firearms','firearms-specific-badge','Discover the Outdoors','','firearms-specific-badge.jpg',1,NULL,'https://curiosityuntamed.com/badges/firearms-specific-badge/','{"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Firearms are powerful tools that demand serious respect and knowledge to handle safely. You''ll learn the rules that protect you and others, understand how different guns and ammunition work, and discover why responsible ownership means following local laws and never treating firearms like they''re shown in movies or games.',NULL);
INSERT INTO badges VALUES(264,'Fire Safety','fire-safety','Discover Health & Safety','Kerry Cordy','fire-safety.jpg',0,'It is recommended that this badge be earned before a member is allowed to build, tend, extinguish, or cook over an open flame. All requirements must be completed for each level. This badge should be earned again every time a member graduates to a new level in order to review the information.','https://curiosityuntamed.com/badges/fire-safety/','{"preschool":0,"level1":0,"level2":0,"level3":0,"level4":0,"level5":0}',1,'2026-05-20 16:10:36','Fire is powerful and useful, but it demands respect and smart choices. Master the essentials—from how to react if your clothes catch fire to how to safely roast food over flames—so you can enjoy campfires and outdoor cooking without worry.',NULL);
INSERT INTO badges VALUES(265,'First Aid','first-aid-badge','Discover Health & Safety','Kerry Cordy','first-aid-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/first-aid-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','You learn how to help when someone gets hurt—from treating small cuts and bug bites to knowing when to call 911. Being ready with the right skills and supplies means you can stay calm and actually make a difference when it counts.',NULL);
INSERT INTO badges VALUES(266,'First Ladies','first-ladies-badge','Discover Knowledge','Megan Lundquist','first-ladies-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/first-ladies-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every First Lady has her own story—from hosting state dinners to championing causes close to her heart. Discover the women who shaped American history from the White House and what made each one memorable.',NULL);
INSERT INTO badges VALUES(267,'Fishing (Specific)','fishing-badge','Discover the Outdoors','Kerry Cordy','fishing-badge.jpg',1,'These requirements can be used to earn a variety of individual badges such as bass fishing, fly fishing, deep sea fishing, salt water fishing, or fresh water fishing.','https://curiosityuntamed.com/badges/fishing-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fishing is the perfect excuse to spend quiet time by the water while you learn to cast a line, tie knots that hold, and maybe catch dinner. Whether you''re at a lake, river, or pond, you''ll discover patience, technique, and the thrill of what''s beneath the surface.',NULL);
INSERT INTO badges VALUES(268,'Fitness Games (Specific)','fitness-games','Discover Health & Safety','Kerry Cordy','fitness-games.jpg',1,'This badge can be customized for any fitness game you learn about.  Example games are listed after the optional requirements below. If you are looking for sports, please visit the Sports (Specific) badge.','https://curiosityuntamed.com/badges/fitness-games/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Whether it''s tag, basketball, or dance-based games, you''ll discover how fun physical activity keeps your body strong and healthy. You''ll learn the rules, stay safe while playing, and find out which muscles and fitness skills—like speed, balance, or endurance—each game builds up.',NULL);
INSERT INTO badges VALUES(269,'Five Senses','five-senses-badge','Discover Knowledge','','five-senses-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/five-senses-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your eyes, ears, nose, tongue, and skin are always collecting information about the world around you. Explore how each sense works, why they matter for keeping you safe, and discover inspiring stories of people who learned to thrive without one or more of them.',NULL);
INSERT INTO badges VALUES(270,'Flat Stanley','flat-stanley-badge','Discover the World','Kerry Cordy','flat-stanley-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/flat-stanley-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A paper boy who travels the world in envelopes and has the wildest adventures—all because he''s perfectly flat. Follow Stanley''s journey through different countries and cultures as he solves mysteries and makes friends wherever he goes.',NULL);
INSERT INTO badges VALUES(271,'Flexibility','flexibility-badge','Discover Character','Elizabeth Simmons',NULL,0,NULL,'https://curiosityuntamed.com/badges/flexibility-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Flexibility is being able to roll with changes, try new approaches when something doesn''t work, and bounce back when things get tough. It''s the superpower of staying calm and creative no matter what comes your way.','🌊');
INSERT INTO badges VALUES(272,'Flower Arranging','flower-arranging-badge','Discover Art','Kerry Cordy','flower-arranging-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/flower-arranging-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fresh flowers don''t last long, but you can make them look beautiful while they do—and give them a second life when they fade. Learn how to arrange blooms, keep them fresh longer, and transform petals into dried decorations, pressed cards, or even edible garnishes.',NULL);
INSERT INTO badges VALUES(273,'Flower Gardening','flower-gardening-badge','Discover Agriculture','Kerry Cordy','flower-gardening-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/flower-gardening-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Growing flowers from tiny seeds into colorful blooms teaches patience, care, and the rhythms of nature. You''ll learn what soil, water, and sunlight your flowers crave, spot the weeds trying to muscle in, and discover how to keep pests and diseases from ruining your garden.',NULL);
INSERT INTO badges VALUES(274,'Food Around the World','food-around-the-world','Discover the World','Kerry Cordy','food-around-the-world.jpg',0,NULL,'https://curiosityuntamed.com/badges/food-around-the-world/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every country has its own favorite flavors, spices, and ways of cooking. Travel the globe through your taste buds by trying dishes from different cultures, comparing how the same food tastes totally different around the world, and cooking something new in your own kitchen.',NULL);
INSERT INTO badges VALUES(275,'Food Presentation','food-presentation-badge','Discover the Home','Kerry Cordy','food-presentation-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/food-presentation-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A beautifully plated meal is more fun to eat and makes people feel special at the table. Master the tricks chefs use—picking the right plate size, mixing colors and textures, and adding tasty garnishes—to turn ordinary food into something that looks as good as it tastes.',NULL);
INSERT INTO badges VALUES(276,'Food Preservation','food-preservation-badge','Discover the Home','Doreen Olson','food-preservation-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/food-preservation-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Food doesn''t have to spoil—people have used freezing, pickling, canning, smoking, and fermenting for thousands of years to keep meals fresh longer. Try different preservation methods yourself and discover why some foods taste even better preserved than fresh.',NULL);
INSERT INTO badges VALUES(277,'Foods','foods-badge','Discover Agriculture','Kerry Cordy','foods-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/foods-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every meal on your plate is a journey from farms around the world—grain fields, animal pastures, and vegetable gardens all working together to feed you. Discover where your favorite foods come from, how farmers grow and raise them, and how they travel from farm to your fork.',NULL);
INSERT INTO badges VALUES(278,'Food Safety','food-safety-badge','Discover Health & Safety','Charlotte Duke','food-safety-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/food-safety-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Clean hands, cold fridges, and knowing when food has gone bad keeps everyone healthy at the dinner table. Master the basics of food safety and discover how we''ve kept meals safe throughout history.',NULL);
INSERT INTO badges VALUES(279,'Food (Specific)','food-specific-badge','Discover Agriculture','Crystal Morris',NULL,1,NULL,'https://curiosityuntamed.com/badges/food-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pick one food—maybe an apple, carrot, or piece of chicken—and become an expert on it. You''ll taste it, trace where it comes from, discover how long it takes to grow, and map out the journey from farm to your plate.','🥕');
INSERT INTO badges VALUES(280,'Foraging','foraging-badge','Discover the Outdoors','Kelli Messick','foraging-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/foraging-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Finding wild food in forests, fields, and gardens means knowing which plants are safe to eat and which ones to avoid. It''s like a treasure hunt where nature provides snacks, and you learn the skills to spot them safely.',NULL);
INSERT INTO badges VALUES(281,'Formal Wear','formal-wear','Discover Knowledge','',NULL,0,NULL,'https://curiosityuntamed.com/badges/formal-wear/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fancy clothes like tuxedos, wedding dresses, and ball gowns show up at big celebrations and special events. Discover what makes formal wear so elegant and how people care for these treasured outfits.','🎩');
INSERT INTO badges VALUES(282,'French and Indian War','french-and-indian-war-badge','Discover the World','','french-and-indian-war-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/french-and-indian-war-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','This war shaped North America by pitting the French, British, and Native American tribes against each other over land and power in the 1750s. Explore the maps, tribes, and alliances that changed which European nation controlled huge chunks of the continent.',NULL);
INSERT INTO badges VALUES(283,'French Revolution','french-revolution-badge','Discover the World','',NULL,0,NULL,'https://curiosityuntamed.com/badges/french-revolution-badge/','{"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','France in the late 1700s was hungry, angry, and ready for change. Discover what sparked a revolution, how ordinary people challenged their king, and why this explosive moment in history still matters today.','🇫🇷');
INSERT INTO badges VALUES(284,'Friendship','friendship-badge','Discover Character','','friendship-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/friendship-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Real friendships are built on trust, kindness, and showing up for people you care about. Explore what makes a good friend and how to be one, even when things get tricky.',NULL);
INSERT INTO badges VALUES(285,'Frogs','frog-badge','Discover the Outdoors','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/frog-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Frogs are amphibians that leap, croak, and transform through wild life cycles—from tiny eggs to tadpoles to hopping adults. Each species sounds different and looks different too, so discover what makes frogs such successful hoppers across ponds and forests everywhere.','🐸');
INSERT INTO badges VALUES(286,'Fruit (specific)','fruit-specific-badge','Discover Agriculture','Kerry Cordy',NULL,1,NULL,'https://curiosityuntamed.com/badges/fruit-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pick a fruit and become an expert on it—from spotting a ripe one at the market to understanding where it grows and how long it lasts. You''ll explore what makes your fruit special, taste the difference between ripe and unripe, and discover the whole journey from tree or vine to your kitchen.','🍎');
INSERT INTO badges VALUES(287,'Fun at the Pool','fun-at-the-pool-badge','Discover the Outdoors','Sylvia Duke','fun-at-the-pool-badge.jpg',0,'This badge is designed for swimmers and non-swimmers to enjoy time at the swimming pool.  If you are a non-swimmer you may complete all the requirements wearing a flotation device approved by your parent/guardian.','https://curiosityuntamed.com/badges/fun-at-the-pool-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The pool is a place to splash, swim, and have fun with friends while staying safe in the water. Whether you''re learning to float, playing games, or perfecting your strokes, there''s always something new to discover.',NULL);
INSERT INTO badges VALUES(288,'Fun with Science','fun-with-science-badge','Discover Science & Technology','Katie Lundquist','fun-with-science-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/fun-with-science-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Science is all about asking questions and testing ideas to find real answers. You''ll explore how light bends, rainbows form, and discover the step-by-step method scientists use to figure out how the world actually works.',NULL);
INSERT INTO badges VALUES(289,'Fund Raising','fund-raising-badge','Discover Knowledge','Sylvia Duke','fund-raising-badge.jpg',0,'This badge is designed to learn about fundraising for groups.','https://curiosityuntamed.com/badges/fund-raising-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Raising money for a cause you care about teaches you how to get creative, ask for support, and make a real difference. Whether you''re organizing a bake sale, a car wash, or a donation drive, you''ll discover what it takes to turn your ideas into action.',NULL);
INSERT INTO badges VALUES(290,'Fuse/Perler Beads','fuse-beads-badge','Discover Art','Tyler Russell','fuse-beads-badge.jpg',0,'Fuse beads are also known as Perler beads, Hama beads, and Nabbi beads.','https://curiosityuntamed.com/badges/fuse-beads-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Tiny colorful beads melt together under heat to create solid designs, pixel art, and decorations you can wear or display. It''s like painting with beads—arrange them on a pegboard, iron them flat, and watch separate pieces fuse into one.',NULL);
INSERT INTO badges VALUES(291,'Games','games-badge','Discover Knowledge','Diana Havir','games-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/games-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level5":7}',1,'2026-05-20 16:10:36','Games are everywhere—from board games and card games to word games and video games—and each type challenges your brain in different ways. Learn what makes a good sport, explore all kinds of games, and discover which ones become your new favorites.',NULL);
INSERT INTO badges VALUES(292,'Gardening','gardening-badge','Discover Agriculture','Kerry Cordy','gardening-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/gardening-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Growing food from tiny seeds teaches patience and care as you watch plants sprout, grow leaves, and finally produce vegetables or fruits you can eat. You''ll learn what soil, water, and sun each plant needs, spot weeds and pests, and discover organic ways to keep your garden thriving.',NULL);
INSERT INTO badges VALUES(293,'Garnish','garnish-badge','Discover Art','Kerry Cordy','garnish-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/garnish-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A garnish is the finishing touch that makes food look fancy and taste better—a sprinkle of herbs, a twist of citrus, or a colorful vegetable curl. Learn which flavors and textures pair perfectly with dishes, and master the tools that transform simple ingredients into edible art.',NULL);
INSERT INTO badges VALUES(294,'Gemstones','gemstones','Discover the Outdoors','Kerry Cordy',NULL,0,'Gemstones are also known as precious or semi-precious stones.','https://curiosityuntamed.com/badges/gemstones/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Gemstones are beautiful crystals that form deep underground and sparkle with color once they''re polished and cut. Discover where rubies, sapphires, and emeralds come from, spot them in jewelry around you, and learn to identify the real gems hiding in plain sight.','💎');
INSERT INTO badges VALUES(295,'Genealogy','genealogy-badge','Discover the Home','','genealogy-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/genealogy-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your family has a story that stretches back through time, with relatives you might never have met but who shaped who you are today. Trace your family tree, discover the meaning behind your name, and collect the stories and records that connect you to generations past and present.',NULL);
INSERT INTO badges VALUES(296,'Generosity','generosity-badge','Discover Character','Suzanne Vicoryosmanson','generosity-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/generosity-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Generosity is about sharing what you have—time, kindness, stuff, or skills—without keeping score. It feels good to give, but you''ll also learn when saying yes might not be the smart choice, and how real generosity means being thoughtful, not just a pushover.',NULL);
INSERT INTO badges VALUES(297,'Genetics','genetics','Discover Science & Technology','Kerry Cordy','genetics.jpg',0,NULL,'https://curiosityuntamed.com/badges/genetics/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your genes are instructions passed down from your parents that shape everything from your eye color to your height. Trace traits through your family tree, explore how plants differ even when they''re the same kind, and discover why some traits show up while others hide—just like Gregor Mendel figured out with his famous pea experiments.',NULL);
INSERT INTO badges VALUES(298,'Gentleness','gentleness-badge','Discover Character','Kerry Cordy','gentleness-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/gentleness-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Gentleness means treating people, animals, and things with care and kindness—using a soft voice, a light touch, and a patient heart. It''s a strength that makes the world feel safer for everyone around you.',NULL);
INSERT INTO badges VALUES(299,'Geo-caching','geoching-badge','Discover the Outdoors','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/geoching-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Geocaching is like a treasure hunt using GPS coordinates—you follow your device to hidden containers left by other adventurers all over the world, sign the logbook, and maybe swap trinkets. It''s real-world exploration that combines navigation skills, outdoor awareness, and the thrill of discovery.','🗺️');
INSERT INTO badges VALUES(300,'Geology','geology-badge','Discover Science & Technology','Kerry Cordy','geology-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/geology-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Rocks are nature''s record books, storing clues about Earth''s history in their layers, crystals, and colors. Geologists read these stone stories to understand how mountains formed, where dinosaurs walked, and what your own backyard looked like millions of years ago.',NULL);
INSERT INTO badges VALUES(301,'Ghost Towns','ghost-towns-badge','Discover the World','',NULL,0,NULL,'https://curiosityuntamed.com/badges/ghost-towns-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Abandoned towns left behind by history are frozen in time, with empty buildings that tell stories of why people moved away. Explore real ghost towns around the world, discover what caused them to vanish, and create your own imaginary one.','👻');
INSERT INTO badges VALUES(302,'Gift Giving','gift-giving-badge','Discover the Home','Doreen Olson','gift-giving-badge.png',0,NULL,'https://curiosityuntamed.com/badges/gift-giving-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Giving gifts is about showing people you care through thoughtful presents picked just for them. From birthdays to holidays, you''ll discover why different people deserve different gifts and what makes a present truly special.',NULL);
INSERT INTO badges VALUES(303,'Gift Wrapping','gift-wrapping-badge','Discover Art','',NULL,0,NULL,'https://curiosityuntamed.com/badges/gift-wrapping-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Turning a present into a work of art starts with the right fold, tape, and ribbon. Master the techniques that make any gift look thoughtfully wrapped and ready to give.','🎁');
INSERT INTO badges VALUES(304,'Gingerbread','gingerbread-badge','Discover Art','Elisabeth Samel','gingerbread-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/gingerbread-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Gingerbread is a spicy, sweet treat made from ginger root—a bumpy underground plant that grows in tropical places around the world. Build edible houses, taste different gingerbread creations, and discover how this ancient spice became a holiday favorite.',NULL);
INSERT INTO badges VALUES(305,'Glass Art','glass-art-badge','Discover Art','Kerry Cordy','glass-art-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/glass-art-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Glass is way older and cooler than you might think—artisans have been shaping it into beautiful windows, sculptures, and decorative pieces for thousands of years. Explore the colorful world of stained glass, delicate figurines, and artistic glassware while learning how to handle and care for these fragile treasures.',NULL);
INSERT INTO badges VALUES(306,'Glitz & Glam','glitz-glam-badge','Discover Health & Safety','Ellen Smith','glitz-glam-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/glitz-glam-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Looking good doesn''t have to mean damaging your skin or hair—glitz and glam is really about understanding what products actually do and using them safely. From makeup basics to skincare routines, you''ll figure out what works for you and how to keep yourself healthy while having fun with style.',NULL);
INSERT INTO badges VALUES(307,'Gods and Goddesses (Specific)','gods-goddesses-specific-badge','Discover Knowledge','Kerry Cordy',NULL,1,NULL,'https://curiosityuntamed.com/badges/gods-goddesses-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every culture tells stories about powerful beings with special gifts and symbols. Pick a god or goddess from any mythology—whether Norse, Greek, Egyptian, or beyond—and dive into their world through tales, powers, and the meaning they held for ancient people.','🦅');
INSERT INTO badges VALUES(308,'Gold Rush','gold-rush-badge','Discover Knowledge','Kerry Cordy','gold-rush-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/gold-rush-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Thousands of people rushed west in the 1800s hoping to strike it rich by finding gold in rivers and streams. Discover what life was like during this wild time, how people searched for gold, and how this adventure shaped the American West.',NULL);
INSERT INTO badges VALUES(309,'Good Grooming','good-grooming-badge','Discover Health & Safety','Kerry Cordy','good-grooming-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/good-grooming-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Taking care of your hair and looking neat isn''t just about looking good—it''s part of staying healthy and feeling confident. From brushing out tangles to washing and conditioning like a pro, you''ll master the basics of grooming that make a real difference.',NULL);
INSERT INTO badges VALUES(310,'Goodness','goodness-badge','Discover Character','Kerry Cordy','goodness-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/goodness-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Goodness is the choice to be kind, honest, and fair even when nobody''s watching. It''s about helping others, keeping your promises, and treating people the way you''d want to be treated.',NULL);
INSERT INTO badges VALUES(311,'Grains','grains-badge','Discover Agriculture','Kerry Cordy','grains-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/grains-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Wheat, rice, oats, and corn feed billions of people around the world—and they all start as seeds. Explore the different grains that fill your pantry, taste what whole grains are really like, and discover why these plants matter so much to humanity.',NULL);
INSERT INTO badges VALUES(312,'Grammar','grammar-badge','Discover Knowledge','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/grammar-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Words have jobs—nouns are things and people, verbs are actions, and punctuation marks tell your reader when to pause or stop. Master these building blocks and you''ll write sentences that are clear, correct, and actually say what you mean.','📝');
INSERT INTO badges VALUES(313,'Grandparents','grandparents-badge','Discover the Home','Doreen Olson','grandparents-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/grandparents-badge/','{"preschool":3,"level1":4,"level2":5,"level3":6,"level4":7,"level5":9}',0,'2026-05-20 16:10:36','Grandparents are the storytellers and wisdom-keepers in families, full of memories about how things used to be. Getting to know them better means hearing amazing stories and learning what makes them special.',NULL);
INSERT INTO badges VALUES(314,'Greek Elements','greek-elements-badge','Discover Science & Technology','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/greek-elements-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Ancient Greek philosophers believed everything in nature comes from four elements: earth, water, fire, and air. Explore how these elements show up in your everyday life—from the meals you cook to the energy that powers your home.','🔥');
INSERT INTO badges VALUES(315,'Greeting Cards','greeting-cards-badge','Discover Art','Doreen Olson',NULL,0,NULL,'https://curiosityuntamed.com/badges/greeting-cards-badge/','{"preschool":1,"level1":4,"level2":5,"level3":6,"level4":7,"level5":7}',1,'2026-05-20 16:10:36','A handmade greeting card is a personal message wrapped in creativity—you design, decorate, and deliver something that makes someone smile. Mix colors, stickers, ribbons, and fabrics to craft cards for birthdays, thank-yous, holidays, and more.','💌');
INSERT INTO badges VALUES(316,'Grieving','grieving-badge','Discover Character','','grieving-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/grieving-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Grief is a big feeling that comes when we lose someone or something we care about, and it''s completely normal to feel sad, angry, or confused. Understanding how to honor those memories and take care of ourselves during hard times helps us stay strong and connect with others who understand.',NULL);
INSERT INTO badges VALUES(317,'Guinea Pigs','guinea-pig-badge','Discover the Home','Madison Brown, Troop #160','guinea-pig-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/guinea-pig-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":6}',1,'2026-05-20 16:10:36','Guinea pigs are fluffy, squeaky companions that come in different sizes, colors, and fur types. Learn how to handle them gently, keep them healthy and happy with the right food and clean home, and figure out what it really costs to care for one.',NULL);
INSERT INTO badges VALUES(318,'Gymnastics','gymnastics-badge','Discover Health & Safety','Kerry Cordy','gymnastics-badge.jpg',0,'There are two main forms of gymnastics, artistic and rhythmic. These badge requirements can be used to earn either of the two badges.  If you plan to earn both, try to pick different optional requirements for each when possible. Disclaimer: Gymnastics can be dangerous and should be supervised by an experienced adult. Please learn and follow all safety rules.','https://curiosityuntamed.com/badges/gymnastics-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Gymnastics builds strength, balance, and flexibility through controlled movements on equipment like beams, bars, and mats. You''ll master stretches and safety skills, work with spotters, and progress through exercises that challenge your body in amazing ways.',NULL);
INSERT INTO badges VALUES(319,'Haiku','haiku-badge','Discover Art','Sarah Bruekher',NULL,0,NULL,'https://curiosityuntamed.com/badges/haiku-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Haiku is the art of saying something big in just seventeen syllables—three short lines that capture a feeling, a moment, or a tiny slice of nature. Write your own and see how much poetry you can pack into so few words.','🍃');
INSERT INTO badges VALUES(320,'Hair Care','hair-care-badge','Discover Health & Safety','Doreen Olson','hair-care-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/hair-care-badge/','{"level5":7}',1,'2026-05-20 16:10:36','Your hair is unique to you, and keeping it healthy takes the right routine and products. From washing and conditioning to styling and treating different hair types, you''ll master the basics of caring for your crowning glory.',NULL);
INSERT INTO badges VALUES(321,'Hair Donation','locks-of-love','Discover Character','Kerry Cordy','locks-of-love.png',0,NULL,'https://curiosityuntamed.com/badges/locks-of-love/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Growing your hair long and donating it to people who need it is a generous way to make a real difference. Your locks become wigs, extensions, or hair for research that helps others feel confident and whole.',NULL);
INSERT INTO badges VALUES(322,'Hair Styles','hair-styles-badge','Discover Health & Safety','','hair-styles-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/hair-styles-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your hair is a blank canvas for creativity—braid it, twist it, curl it, or style it into something totally new. Explore everything from French braids to buns, learn how to care for your locks properly, and discover how hairstyles have changed throughout history.',NULL);
INSERT INTO badges VALUES(323,'Hair Styling','hair-styling-badge','Discover the Home','Kerry Cordy','hair-styling-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/hair-styling-badge/','{"preschool":1,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your hair needs the same care as the rest of your body—washing, conditioning, and brushing keep it healthy and strong. Master the basics like ponytails and braids, and discover why taking care of your hair matters for how you feel about yourself.',NULL);
INSERT INTO badges VALUES(324,'Hamsters','hamster-badge','Discover the Home','Megan Bond','hamster-badge.png',0,NULL,'https://curiosityuntamed.com/badges/hamster-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Hamsters are tiny furry pets with big personalities—fluffy, curious, and surprisingly fun to watch. Find out what different hamster species are like, how to handle them safely, what they need to stay happy and healthy, and what it really costs to be a hamster owner.',NULL);
INSERT INTO badges VALUES(325,'Hank the Cow Dog','learn-about-hank-the-cowdog-badge','Discover Knowledge','Charlotte Duke','learn-about-hank-the-cowdog-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/learn-about-hank-the-cowdog-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Hank is a lovable cowdog protecting a Texas ranch, getting into funny trouble with his sidekick Drover and a cast of colorful characters. Follow Hank''s adventures across the Texas Panhandle and discover why he''s been a reader favorite for decades.',NULL);
INSERT INTO badges VALUES(326,'Harry Potter','harry-potter-badge','Discover Knowledge','Sara Rauta','harry-potter-badge.jpg',0,'There are some darker themes explored in the Harry Potter series. Some parents may not find it appropriate for children. Parents of Preschool, Level 1 and Level 2 should be advised.','https://curiosityuntamed.com/badges/harry-potter-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Harry Potter is a young wizard who discovers he''s famous, attends a magical school called Hogwarts, and battles dark forces alongside his best friends Ron and Hermione. Dive into J.K. Rowling''s world through books and films to see how the story comes to life on screen.',NULL);
INSERT INTO badges VALUES(327,'Hats','hats-badge','Discover Knowledge','',NULL,0,NULL,'https://curiosityuntamed.com/badges/hats-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Hats sit on your head for style, protection, or just fun—and there are way more kinds than you''d think. Explore everything from cowboy hats and berets to turbans and top hats, and discover which ones suit you best.','🎩');
INSERT INTO badges VALUES(328,'Headphones','headphones-badge','Discover Science & Technology','Sarah Lundquist','headphones-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/headphones-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Headphones turn electrical signals into sound waves that travel straight to your ears, letting you hear music, podcasts, and games in your own private bubble. Explore how speakers vibrate, what different audio tech does, and why sound quality matters.',NULL);
INSERT INTO badges VALUES(329,'Health and Fitness','health-and-fitness','Discover Health & Safety','Kerry Cordy','health-and-fitness.jpg',0,NULL,'https://curiosityuntamed.com/badges/health-and-fitness/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your body is an amazing machine that works better when you move it and fuel it right. Find out how exercise, healthy eating, and everyday activities keep you strong, energized, and ready for anything.',NULL);
INSERT INTO badges VALUES(330,'Heart Health','heart-health','Discover Health & Safety','Carrie Ouellette','heart-health.jpg',0,NULL,'https://curiosityuntamed.com/badges/heart-health/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your heart is a powerful muscle that pumps blood around your body all day and night, keeping you alive and energized. Feel your own heartbeat, discover what makes it speed up or slow down, and learn why this fist-sized organ is your body''s hardest worker.',NULL);
INSERT INTO badges VALUES(331,'Heat Wave','heat-wave-badge','Discover Science & Technology','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/heat-wave-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Heat waves are stretches of dangerously hot weather that last for days, making the air feel even hotter when humidity kicks in. Learn how to spot dangerous heat, dress smart, stay hydrated, and use simple tricks to keep your body cool when the temperature soars.','🌡️');
INSERT INTO badges VALUES(332,'Heraldry','heraldry-badge','Discover the World','Christina Hunt','heraldry-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/heraldry-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every family, school, and country has its own special symbol or shield called a coat of arms—a colorful picture that tells their story through hidden meanings in animals, shapes, and colors. Design your own coat of arms and discover what symbols and colors meant to people throughout history.',NULL);
INSERT INTO badges VALUES(333,'Herbal Teas','herbal-teas-badge','Discover Agriculture','Doreen Olson','herbal-teas-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/herbal-teas-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Herbal teas come in dozens of flavors—some spicy and bold, others sour, calm, or earthy—and each one starts with leaves, flowers, or roots steeped in hot water. You''ll taste different kinds, learn the tools of tea-making, and discover how to brew and serve them safely.',NULL);
INSERT INTO badges VALUES(334,'Herbs','herbs-badge','Discover Agriculture','Kerry Cordy','herbs-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/herbs-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Herbs are fresh plants that add amazing flavors to food—think basil in pizza, mint in lemonade, or oregano in pasta. Grow them, spot them by their leaves and smell, and discover how many everyday foods taste better because of them.',NULL);
INSERT INTO badges VALUES(335,'Hiking','hiking-badge','Discover the Outdoors','Kerry Cordy','hiking-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/hiking-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Hiking means exploring trails, forests, and natural landscapes on foot while staying safe and respecting nature. You''ll learn to read maps, spot dangerous plants, follow Leave No Trace rules, and log your outdoor adventures with friends and family.',NULL);
INSERT INTO badges VALUES(336,'Hindenburg','hindenburg-badge','Discover Knowledge','Megan Lundquist','hindenburg-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/hindenburg-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Hindenburg was a massive German airship filled with hydrogen that caught fire while landing in New Jersey in 1937, killing 35 of the 97 people on board. Explore the story of this famous disaster, the airships that came before it, and how quickly the giant zeppelin was destroyed.',NULL);
INSERT INTO badges VALUES(337,'Historic Era (Specific)','historic-era-badge','Discover the World','Suzanne Vicoryosmanson',NULL,1,'This badge can be earned multiple times, once for each historic era you choose to study. Examples might include the 1940’s, Ancient Egypt, the Victorian period, the Renaissance, or the Elizabethan period. New ideas?  Check out our 1980’s Unit Study','https://curiosityuntamed.com/badges/historic-era-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Travel back in time to explore a pivotal moment in history—the people, events, and ideas that shaped our world. You''ll uncover the stories behind how things came to be the way they are today.','🏛️');
INSERT INTO badges VALUES(338,'Historical Event (specific)','historical-events-specific-badge','Discover the World','Kerry Cordy','historical-events-specific-badge.jpg',1,'Choose any historical event to learn more about.  This badge can be earned multiple times, once for each event you learn about.','https://curiosityuntamed.com/badges/historical-events-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','History is full of moments that shaped the world we live in today. Pick an event that fascinates you, dig into the story, and figure out what it teaches us about making better choices in the future.',NULL);
INSERT INTO badges VALUES(339,'Historic Sites (Specific)','historic-sites-specific-badge','Discover the Wrold','Abigail Pawlowski Troop',NULL,1,NULL,'https://curiosityuntamed.com/badges/historic-sites-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":4,"level5":5}',1,'2026-05-20 16:10:36','Every place has a story—whether it''s an ancient castle, a famous battlefield, or a landmark that changed history. Pick a site that fascinates you, explore it in person or online, and uncover the secrets behind why it still matters today.','🏛️');
INSERT INTO badges VALUES(340,'History by Country (Specific)','history-by-county-badges','Discover the World','Doreen Olson','history-by-county-badges.jpg',1,'This badge can be earned multiple times at each level, once for each individual country.','https://curiosityuntamed.com/badges/history-by-county-badges/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every country has a unique story shaped by the people, events, and changes that happened there over time. Pick one country to explore deeply—discover how its language, borders, and culture came to be, then share what you''ve learned through a timeline filled with the moments that made it what it is today.',NULL);
INSERT INTO badges VALUES(341,'History of Medicine','history-of-medicine-badge','Discover Science & Technology','Charlotte Duke','history-of-medicine-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/history-of-medicine-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Medicine has changed hugely over time—from ancient doctors who didn''t know about germs to modern doctors with powerful tools and knowledge. Explore how people discovered ways to heal, meet the different kinds of health helpers we have today, and see why keeping people healthy is such important work.',NULL);
INSERT INTO badges VALUES(342,'Holidays (General)','holidays-badge-general','Discover the World','',NULL,0,NULL,'https://curiosityuntamed.com/badges/holidays-badge-general/','{}',0,'2026-05-20 16:10:36','Holidays around the world celebrate everything from harvests and new years to historical events and family traditions. Explore how different cultures mark special days with their own customs, foods, decorations, and stories.','🎉');
INSERT INTO badges VALUES(343,'Holistic Wellness','holistic-wellness-badge','Discover Health & Safety','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/holistic-wellness-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Holistic wellness means taking care of your whole self—body, mind, emotions, spirit, and relationships—not just one part. You''ll explore simple daily practices like mindful eating and breathing that help you feel better in all these areas.','🧘');
INSERT INTO badges VALUES(344,'Home Construction','home-construction','Discover the Home','Kerry Cordy','home-construction.jpg',0,NULL,'https://curiosityuntamed.com/badges/home-construction/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every house starts as an empty lot and a stack of plans. Watch the layers go up—framing, wiring, plumbing—and learn how builders read blueprints to know exactly where everything goes. Then design your own dream house and figure out what makes a good building spot.',NULL);
INSERT INTO badges VALUES(345,'Home Decorating','home-decorating-badge','Discover Art','Doreen Olson','home-decorating-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/home-decorating-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your room is a blank canvas waiting for your style. Learn how color, shape, texture, and line come together to make a space feel cozy, bold, or calm—then try decorating with those ideas in mind.',NULL);
INSERT INTO badges VALUES(346,'Home Fire Safety','home-fire-safety-badge','Discover Health & Safety','Suzanne Vicoryosmanson','home-fire-safety-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/home-fire-safety-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fires spread fast, so knowing what to do before one happens keeps your family safe. You''ll learn Stop, Drop, and Roll, create an escape plan, practice drills, and check that your home has working smoke detectors ready to warn you.',NULL);
INSERT INTO badges VALUES(347,'Home Maintenance','home-maintenance-badge','Discover the Home','Kerry Cordy','home-maintenance-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/home-maintenance-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every home needs care to stay safe and running smoothly. Learn how to handle basic fixes like changing lightbulbs, gather the right tools for the job, and know the important emergency shut-offs that keep your household protected.',NULL);
INSERT INTO badges VALUES(348,'Home Maker','home-maker-badge','Discover the Home','Sylvia Duke','home-maker-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/home-maker-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A home-maker keeps a household running smoothly—managing meals, laundry, cleaning, schedules, and a thousand other tasks that make a home comfortable. Meet someone who does this work and discover what it really takes to care for a family and a home.',NULL);
INSERT INTO badges VALUES(349,'Home Nurse','home-nurse-badge','Discover the Home','Doreen Olson','home-nurse-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/home-nurse-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Taking care of someone who''s sick or struggling with daily tasks is a real way to show you care. From keeping them company to helping with meals, bandages, or just making their day brighter, you''ll learn what it means to be someone''s helper when they need it most.',NULL);
INSERT INTO badges VALUES(350,'Home Renovation','home-renovation-badge','Discover the Home','Doreen Olson','home-renovation-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/home-renovation-badge/','{"level5":7}',1,'2026-05-20 16:10:36','Fixing up a home means understanding everything from fresh paint and new flooring to working plumbing and solid walls. You''ll explore the skills and tools that turn a house into a place people love to live in.',NULL);
INSERT INTO badges VALUES(351,'Home Safety','home-safety','Discover Health & Safety','Suzanne Vicoryosmanson','home-safety.jpg',0,NULL,'https://curiosityuntamed.com/badges/home-safety/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your home should be a safe place to play and grow. Learn which areas and items to avoid, create an emergency plan with important phone numbers, build a first aid kit, and hunt through your house to spot hazards like sharp objects, chemicals, and tripping dangers—then help fix them.',NULL);
INSERT INTO badges VALUES(352,'Home Spa','home-spa','Discover the Home','','home-spa.jpg',0,NULL,'https://curiosityuntamed.com/badges/home-spa/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',0,'2026-05-20 16:10:36','Create your own relaxation station with DIY treatments like face masks, bath soaks, and hand massages. It''s self-care you can make at home using simple ingredients.',NULL);
INSERT INTO badges VALUES(353,'Homeschool Pride','homeschool-pride-badge','Discover the Home','Frontier Girls Troop','homeschool-pride-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/homeschool-pride-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your homeschool is one of a kind, so why not give it an identity? Create a name, colors, and mascot that represent who you are, write a motto or chant that gets everyone pumped up, and build traditions that make your learning feel special.',NULL);
INSERT INTO badges VALUES(354,'Hometown Stay-cation','hometown-stay-cation-badge','Discover the Home','Katie Lundquist','hometown-stay-cation-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/hometown-stay-cation-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your town has hidden gems waiting to be explored—parks you''ve never noticed, local restaurants worth trying, and community spots that make your place special. A stay-cation is your chance to play tourist right where you live.',NULL);
INSERT INTO badges VALUES(355,'Honesty','honesty-badge','Discover Character','Kerry Cordy','honesty-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/honesty-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Being honest means telling the truth even when it''s hard, admitting your mistakes, and being someone people can trust. It''s the foundation of real friendships and a clear conscience.',NULL);
INSERT INTO badges VALUES(356,'Honey','honey-badge','Discover Agriculture','Shelley Frausto','honey-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/honey-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Honey starts as flower nectar that honeybees collect, store in their special stomach, and transform into the golden sweetener we love. Explore where different types of bees make honey, what goes into each jar, and why some regions are famous for their unique honey flavors.',NULL);
INSERT INTO badges VALUES(357,'Honor','honor-badge','Discover Character','Doreen Olson','honor-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/honor-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Honor is about showing deep respect to people and things that matter—like your family, heroes, or even a flag. It means standing up for what''s right, keeping your word, and treating others with real dignity, even when it''s hard.',NULL);
INSERT INTO badges VALUES(358,'Horses','horses-badge','Discover Agriculture','Kerry Cordy','horses-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/horses-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Horses are powerful, intelligent animals that need daily care, proper nutrition, and safe handling. Get up close at a stable to learn what it takes to keep them healthy, how to approach them confidently, and spot all their beautiful coat colors.',NULL);
INSERT INTO badges VALUES(359,'Horse Lover','horse-lover-badge','Discover Knowledge','Beth Henderson','horse-lover-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/horse-lover-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Horses are powerful, intelligent animals that bond deeply with people who care for them. Discover what makes these graceful creatures tick, from their behaviors and body language to how they''re trained and kept healthy.',NULL);
INSERT INTO badges VALUES(360,'Horse Racing','horse-racing-badge','Discover the Outdoors','Beth Henderson','horse-racing-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/horse-racing-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Thoroughbreds thundering down the track, jockeys leaning low, and crowds cheering at every finish line—horse racing is a sport where speed, strategy, and animal athleticism come together. Find out what makes these races thrilling and how horses and riders train to compete at the highest level.',NULL);
INSERT INTO badges VALUES(361,'Horse Riding','horse-riding-badge','Discover the Outdoors','Kerry Cordy','horse-riding-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/horse-riding-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Horses are powerful and beautiful animals that need respect, care, and proper handling. From grooming and saddling to safely mounting up and learning how to guide them at different speeds, you''ll discover what it takes to be a confident rider.',NULL);
INSERT INTO badges VALUES(362,'Horse Training','horse-training-badge','Discover Agriculture','Mackenzie Speers','horse-training-badge.png',0,'This badge is focused on ground training. There is no one right way to train a horse, as many methods can be used.','https://curiosityuntamed.com/badges/horse-training-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',0,'2026-05-20 16:10:36','Horses are intelligent partners that respond to patience, clear signals, and trust. Working with them teaches you how to communicate, stay calm under pressure, and build a real relationship with an animal that weighs half a ton.',NULL);
INSERT INTO badges VALUES(363,'Host/Hostess','hosthostess-badge','Discover the Home','Kerry Cordy','hosthostess-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/hosthostess-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Being a great host or hostess means making your guests feel welcome and comfortable from the moment they arrive. Master the art of polite conversation, proper table manners, and thoughtful party planning—skills that turn ordinary gatherings into memorable occasions where everyone feels valued.',NULL);
INSERT INTO badges VALUES(364,'Hot Air Balloons','hot-air-balloon-badge','Discover Knowledge','Suzanne Vicorysmanson','hot-air-balloon-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/hot-air-balloon-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Hot air balloons rise into the sky by heating the air inside a giant envelope until it''s lighter than the air outside. Explore how these colorful giants float, trace their history back to the first flights, and design your own sky-bound adventure.',NULL);
INSERT INTO badges VALUES(365,'Hot Chocolate','hot-chocolate-badge','Discover the Home','','hot-chocolate-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/hot-chocolate-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Hot chocolate is pure comfort in a mug—made from cocoa powder, milk or water, and sweetness stirred together. Explore what makes different versions taste different, from instant packets to homemade recipes, and discover your favorite way to enjoy this cozy winter drink.',NULL);
INSERT INTO badges VALUES(366,'Household Machines (Specific or General)','household-machines-general-or-specific-badge','Discover Science & Technology','',NULL,1,NULL,'https://curiosityuntamed.com/badges/household-machines-general-or-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Household machines do amazing work every day—washing clothes, cleaning dishes, mowing grass, or blending smoothies. Pick one and discover what makes it tick: how motors spin, how heat or water does the job, and what safety rules keep everyone safe around it.','⚙️');
INSERT INTO badges VALUES(367,'Houseplants','houseplants-badge','Discover Science & Technology','',NULL,0,NULL,'https://curiosityuntamed.com/badges/houseplants-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Houseplants turn indoor spaces green and alive, and they''re surprisingly good at cleaning the air you breathe. Grow your own by learning what different plants need, visiting a nursery, and discovering how people have kept plants indoors for centuries.','🌱');
INSERT INTO badges VALUES(368,'Hula-Hoop','hula-hoop-badge','Discover Health & Safety','Kelley Klor','hula-hoop-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/hula-hoop-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Spinning a hula hoop around your waist takes rhythm, balance, and practice—but once you get it going, it''s hard to stop. Discover what your body can do, explore wild world records, and master moves that keep this classic toy twirling.',NULL);
INSERT INTO badges VALUES(369,'Human Body','human-body-badge','Discover Science & Technology','Suzanne Vicoryosmanson','human-body-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/human-body-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your body is an amazing machine made of bones, muscles, organs, and systems all working together to keep you moving, thinking, and growing. Discover what your heart pumps, what your brain controls, and how all the different parts of you do their jobs.',NULL);
INSERT INTO badges VALUES(370,'Hunting','hunting-badge','Discover the Outdoors','Kerry Cordy','hunting-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/hunting-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Hunting provides food and helps manage wildlife populations when done responsibly. Learn about safety, ethics, local laws, and seasons so you can hunt humanely and legally in your area.',NULL);
INSERT INTO badges VALUES(371,'Hygiene','hygiene-badge','Discover Health & Safety','Kerry Cordy','hygiene-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/hygiene-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Staying clean keeps you healthy and shows respect for the people around you. Good hygiene means regular baths, brushing and flossing your teeth, wearing fresh clothes, and understanding why these habits matter for your body and your friendships.',NULL);
INSERT INTO badges VALUES(372,'Ice Cream','ice-cream-badge','Discover Knowledge','Suzanne Vicoryosmanson','ice-cream-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/ice-cream-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Ice cream is frozen dessert magic that dates back centuries and comes in countless flavors and styles. Make your own using simple methods, taste the differences between ice cream and frozen yogurt, and discover why salt and ice work together to turn cream into something cold and delicious.',NULL);
INSERT INTO badges VALUES(373,'Icebergs and Sea Ice','icebergs-and-sea-ice-badge','Discover Science & Technology','Sarah Brueker',NULL,0,NULL,'https://curiosityuntamed.com/badges/icebergs-and-sea-ice-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Massive chunks of ice float in polar oceans, and some are taller than skyscrapers. Find out where icebergs come from, why sea ice is different, and how these frozen giants shape the world''s coldest waters.','🧊');
INSERT INTO badges VALUES(374,'Ice Sculptures','ice-sculpture-badge','Discover Art','',NULL,0,NULL,'https://curiosityuntamed.com/badges/ice-sculpture-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Ice sculptures are frozen art that can take the shape of animals, castles, or wild designs—and you can make your own. Carve, freeze, and decorate ice creations using simple tools and tricks that real sculptors use.','🧊');
INSERT INTO badges VALUES(375,'Iditarod','iditarod-badge','Discover Knowledge','','iditarod-badge.png',0,NULL,'https://curiosityuntamed.com/badges/iditarod-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Iditarod is Alaska''s most famous dog sled race, covering over 1,000 miles of frozen wilderness with teams of hardworking huskies. It honors the heroic mushers and sled dogs who delivered lifesaving medicine to remote communities, and celebrates the incredible bond between racer and pack.',NULL);
INSERT INTO badges VALUES(376,'Indoor Forts','indoor-forts-badge','Discover the Home','Renee Austin & Latitude Learning Center',NULL,0,NULL,'https://curiosityuntamed.com/badges/indoor-forts-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Transform your living room into an awesome hideout using pillows, blankets, chairs, and cardboard boxes. You''ll figure out what materials work best for building, decorating your creation, and making the perfect cozy space that''s all yours.','🏰');
INSERT INTO badges VALUES(377,'Insects (General)','animal-kingdom-insects','Discover the Outdoors','Kerry Cordy','animal-kingdom-insects.jpg',0,'A separate badge  can be earned for each of the following categories: Mammals, reptiles, amphibians, marine life, insects, and birds.','https://curiosityuntamed.com/badges/animal-kingdom-insects/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Insects are six-legged creatures with hard outer shells that live almost everywhere on Earth—from rainforests to deserts to your own backyard. Spot them, identify different species, and uncover what makes each one uniquely suited to survive.',NULL);
INSERT INTO badges VALUES(378,'Insects (Specific)','insects-specific','Discover the Outdoors','Kerry Cordy','insects-specific.jpg',1,'These requirements can be used to earn an individual badge for any specific insect including the Butterfly badge, the Ant badge, the Praying Mantis badge, and any other insect of your choice. Need ideas?  Check out our Ladybugs Unit Study','https://curiosityuntamed.com/badges/insects-specific/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pick one insect and become an expert on it—from its tiny body parts to its life story and favorite foods. You''ll discover where it lives in the world and what role it plays in nature, whether helpful or harmful.',NULL);
INSERT INTO badges VALUES(379,'Instrumental Music by Genre (Specific)','instrumental-music-by-genre-badge','Discover Art','Charlotte Duke','instrumental-music-by-genre-badge.jpg',1,'This badge may be earned multiple times for any genre of instrumental music you choose such as classical, rap, polka, swing, etc.','https://curiosityuntamed.com/badges/instrumental-music-by-genre-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every music style has its own sound, feel, and story—whether it''s jazzy improvisation, dramatic classical symphonies, or energetic rock. Pick a genre that speaks to you, listen deeply to how the instruments tell different stories, and discover why musicians and fans love it.',NULL);
INSERT INTO badges VALUES(380,'Internet','internet','Discover Science & Technology','Katie Cordy','internet.jpg',0,NULL,'https://curiosityuntamed.com/badges/internet/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The internet connects billions of people and endless information, but it''s good to know how to navigate it safely and smartly. Learn how browsers work, spot trustworthy websites, and organize your favorite places to visit online.',NULL);
INSERT INTO badges VALUES(381,'Internet Safety','internet-safety-badge','Discover Science & Technology','Cassi Jensen','internet-safety-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/internet-safety-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The internet is amazing, but it has hidden dangers like strangers, scams, and mean behavior. This badge covers how to protect your personal info, spot sketchy links and ads, stay kind online, and know when to ask a trusted adult for help.',NULL);
INSERT INTO badges VALUES(382,'Inventions','inventions-badge','Discover Science & Technology','Charlotte Duke','inventions-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/inventions-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every tool, gadget, and machine around you started as someone''s bright idea. Meet the inventors who changed the world—from the telephone to the light bulb—and discover how curiosity and problem-solving turn "what if?" into "what''s next?',NULL);
INSERT INTO badges VALUES(383,'Jane Austin','jane-austen-badge','Discover Knowledge','Doreen Olson','jane-austen-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/jane-austen-badge/','{"level5":7}',1,'2026-05-20 16:10:36','Jane Austen wrote witty novels about love, family, and society in England long ago, full of characters you''ll recognize in real life. Her stories are clever, funny, and surprisingly modern about what matters to people.',NULL);
INSERT INTO badges VALUES(384,'Jelly Belly','jelly-belly-badge','Discover Knowledge','','jelly-belly-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/jelly-belly-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Jelly Belly candies are tiny flavor-packed treats that come in wild varieties—from realistic fruit flavors to surprising ones like buttered popcorn and licorice. Discover what makes these little beans so fun to collect, sort, and taste-test.',NULL);
INSERT INTO badges VALUES(385,'Jewelry Making','jewelry-making-badge','Discover Art','Kerry Cordy','jewelry-making-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/jewelry-making-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Turn beads, cords, and clasps into wearable art you designed yourself. From ancient treasures to modern styles, jewelry making combines creativity with craftsmanship in something you can actually wear.',NULL);
INSERT INTO badges VALUES(386,'Jigsaw Puzzles','jigsaw-puzzles-badge','Discover Knowledge','Charlotte Duke','jigsaw-puzzles-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/jigsaw-puzzles-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Jigsaw puzzles challenge your brain to spot patterns, match colors and shapes, and piece together a complete picture from hundreds of scattered parts. It''s a satisfying puzzle that rewards patience and sharp eyes.',NULL);
INSERT INTO badges VALUES(387,'Journaling','journaling-badge','Discover Character','Kerry Cordy','journaling-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/journaling-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A journal is your private space to write down what happened each day, how you felt, and what you''re thinking about. Over time, your journal becomes a record of who you are and how you''ve grown.',NULL);
INSERT INTO badges VALUES(388,'Joy','joy-badge','Discover Character','Kerry Cordy','joy-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/joy-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Joy is that spark of happiness that bubbles up when you''re doing something you love, helping someone, or sharing a laugh with friends. It''s about noticing the good moments and letting them brighten your day.',NULL);
INSERT INTO badges VALUES(389,'Juicing','juicing-badge','Discover Health & Safety','','juicing-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/juicing-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fresh juice straight from real fruit and vegetables tastes way better than the bottled kind, and you get to control exactly what goes in. Learn which produce works best, how to prep and juice safely, and create your own flavor combinations.',NULL);
INSERT INTO badges VALUES(390,'Jump Rope','jump-rope-badge','Discover Health & Safety','Kerry Cordy','jump-rope-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/jump-rope-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Jump rope turns a simple cord into a full-body workout that builds strength, coordination, and rhythm. Master the basics and you''ll be bouncing, jogging, and jumping your way to a healthier heart and stronger legs.',NULL);
INSERT INTO badges VALUES(391,'Junior Ranger','junior-ranger-badge','Discover the Outdoors','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/junior-ranger-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Park rangers are the friendly experts who protect wild places and help visitors explore them safely. Junior Rangers get to work alongside rangers, go on adventures, and discover why national parks and historic sites matter so much.','🌲');
INSERT INTO badges VALUES(392,'Kayak','kayak-badge','Discover the Outdoors','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/kayak-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A kayak is a narrow boat you paddle yourself, sitting low in the water with your legs stretched out in front. Learn water safety, paddling strokes, and how to balance your gear so you can explore rivers and lakes on your own power.','🛶');
INSERT INTO badges VALUES(393,'Keyboarding','keyboarding-typing-badge','Discover Science & Technology','Arabella Fuhrman','keyboarding-typing-badge.png',0,NULL,'https://curiosityuntamed.com/badges/keyboarding-typing-badge/','{"preschool":1,"level1":1,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your fingers have their own special home keys on the keyboard, and when you learn where they live, your hands can fly across the keys without looking down. Typing fast and accurately is a superpower for getting your ideas onto the screen or page.',NULL);
INSERT INTO badges VALUES(394,'Kindness','kindness-badge','Discover Character','Kerry Cordy','kindness-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/kindness-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Kindness is noticing when someone needs help and actually doing something about it—whether that''s listening, sharing, or standing up for someone. Small acts of caring create ripples that make the world a little bit better.',NULL);
INSERT INTO badges VALUES(395,'Kindness Rock Project','kindness-rocks','Discover Character','Suzanne Vicoryosmanson','kindness-rocks.jpg',0,NULL,'https://curiosityuntamed.com/badges/kindness-rocks/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','You paint rocks with cheerful messages and hide them around town for strangers to find and keep. It''s a small act that can brighten someone''s whole day without them ever knowing who helped.',NULL);
INSERT INTO badges VALUES(396,'Kites','kites-badge','Discover the Outdoors','Diana Havir','kites-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/kites-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Kites dance and dive through the sky on just wind and string. Build one, learn to launch it, and master the art of keeping it airborne while you feel the pull of the breeze in your hands.',NULL);
INSERT INTO badges VALUES(397,'Knights','knights-badge','Discover Knowledge','Kacie Perman','knights-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/knights-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Knights were armored warriors who served kings and nobles during the Middle Ages, following codes of honor, bravery, and loyalty. Explore their castles, weapons, training, and the real stories behind the legends.',NULL);
INSERT INTO badges VALUES(398,'Knitting','knitting-badge','Discover Art','Sylvia Duke','knitting-badge.jpg',0,'This badge is designed to help non-knitters learn how to knit.  It is also to allow those who already know how to knit to improve their skills.  Please choose optional requirements that are complementary to your skill level.','https://curiosityuntamed.com/badges/knitting-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Two needles and yarn transform into cozy scarves, blankets, and sweaters—one loop at a time. Master the rhythmic basics of casting on, knitting, and binding off to create something warm and wearable with your own two hands.',NULL);
INSERT INTO badges VALUES(399,'Knots','knots','Discover Knowledge','Kerry Cordy','knots.jpg',0,NULL,'https://curiosityuntamed.com/badges/knots/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A knot is a rope trick that holds things together—from tying your shoes to securing a boat to a dock. Master a few essential knots and you''ll be ready for camping, sailing, climbing, or just keeping stuff bundled up.',NULL);
INSERT INTO badges VALUES(400,'Korean Knots (Maedeup)','korean-knots-maedeup-badge','Discover the World','Beatrice Rennie-Bower',NULL,0,NULL,'https://curiosityuntamed.com/badges/korean-knots-maedeup-badge/','{"preschool":1,"level1":2,"level2":2,"level3":2,"level4":2,"level5":2}',1,'2026-05-20 16:10:36','Korean knots, called maedeup, are colorful twisted cords that dangle from clothing and accessories like tiny works of art. These intricate knots have decorated Korean fashion for centuries, and making them is a meditative craft that turns simple string into beautiful patterns.','🪢');
INSERT INTO badges VALUES(401,'Lace','lace-badge','Discover Art','Suzanne Vicoryosmanson','lace-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/lace-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Lace is delicate fabric full of holes and patterns, made by looping and knotting threads in beautiful designs. Explore different styles from around the world and through history, then create your own collection to see how each one is totally unique.',NULL);
INSERT INTO badges VALUES(402,'Land Surveying','land-surveying-badge','Discover the Outdoors','Judy Costello','land-surveying-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/land-surveying-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Surveyors are the mapmakers of the real world—they measure land, set boundaries, and figure out exactly where things belong. Using compass directions, angles, and clever techniques, they turn wild terrain into precise plans that builders and owners rely on.',NULL);
INSERT INTO badges VALUES(403,'Landscaping','landscaping-badge','Discover the Home','Amy Chartier','landscaping-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/landscaping-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Yards and gardens don''t just happen—they''re designed and cared for by people who know which plants thrive in sun or shade, when to plant them, and how to keep them healthy. Turn your outdoor space into something beautiful by growing flowers and learning what makes plants happy in your specific corner of the world.',NULL);
INSERT INTO badges VALUES(404,'LARPing','role-playing-reenactments-larping-badge','Discover Art','Margaret Hinterlang','role-playing-reenactments-larping-badge.jpg',1,NULL,'https://curiosityuntamed.com/badges/role-playing-reenactments-larping-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Step into a character you invent and bring them to life through costume, personality, and storytelling. Whether you''re a medieval knight, a space explorer, or a character from your favorite book, you''ll design who they are, what they wear, and how they fit into a world of adventure.',NULL);
INSERT INTO badges VALUES(405,'Latch Hook','latch-hook-badge','Discover the Home','Ema Greaver','latch-hook-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/latch-hook-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Latch hooking pulls loops of yarn through a canvas grid to create textured pictures and patterns. You''ll use a special hook and learn which yarn works best for rugs, pillows, and wall hangings—then watch your own colorful creation come to life.',NULL);
INSERT INTO badges VALUES(406,'Latte Art','latte-art-badge','Discover Art','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/latte-art-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Latte art transforms a cup of coffee into a tiny canvas, where baristas create ferns, hearts, rosettas, and wild designs using steamed milk, syrups, stencils, and foam. Design your own café-worthy patterns and discover all the creative techniques that turn your drink into edible art.','☕');
INSERT INTO badges VALUES(407,'Laundry','laundry-badge-2','Discover the Home','Charlotte Duke','laundry-badge-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/laundry-badge-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Clothes get dirty, and someone has to wash them—that''s you! Learn how to sort colors from whites, load the washer and dryer safely, fold like a pro, and discover why your family does so much laundry each week.',NULL);
INSERT INTO badges VALUES(408,'Laura Ingalls','laura-ingalls-wilder','Discover Knowledge','Charlotte Duke','laura-ingalls-wilder.jpg',0,NULL,'https://curiosityuntamed.com/badges/laura-ingalls-wilder/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Laura Ingalls Wilder grew up moving across the frontier in covered wagons, living in log cabins, and surviving harsh winters on the prairie. Her true stories became beloved books that show what pioneer life was really like for families building homes in the American wilderness.',NULL);
INSERT INTO badges VALUES(409,'Leather Working','leather-working-badge','Discover Art','Kerry Cordy','leather-working-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/leather-working-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Leather is tough, beautiful material that''s been crafted for thousands of years. You''ll discover what different leathers feel like, learn safe techniques, and create your own wearable piece like a pouch or case.',NULL);
INSERT INTO badges VALUES(410,'Leave No Trace','leave-no-trace','Discover the Outdoors','Kerry Cordy','leave-no-trace.png',0,NULL,'https://curiosityuntamed.com/badges/leave-no-trace/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The outdoors are amazing to explore, but they''re also fragile. These principles teach you how to hike, camp, and play outside while protecting nature for everyone else—leaving places as wild and beautiful as you found them.',NULL);
INSERT INTO badges VALUES(411,'Legends (specific)','legends-specific-badge','Discover Knowledge','Charlotte Henderson','legends-specific-badge.jpg',1,NULL,'https://curiosityuntamed.com/badges/legends-specific-badge/','{"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Legends mix real history with amazing stories that grow bigger with each retelling. Figure out which parts actually happened, how legends differ from myths and folktales, and why people keep telling the ones that matter most.',NULL);
INSERT INTO badges VALUES(412,'Lego','lego-badge','Discover Knowledge','Kerry Cordy','lego-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/lego-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Colorful plastic bricks snap together to build anything you imagine—houses, cars, creatures, and wild inventions. Discover how builders stack them strong, why each piece matters, and how a Danish toy maker created a building system that''s entertained kids for generations.',NULL);
INSERT INTO badges VALUES(413,'Letterboxing','letterboxing-badge','Discover the Outdoors','Tracy Price','letterboxing-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/letterboxing-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Letterboxing is a real-world treasure hunt where hidden boxes contain stamps, ink pads, and guest books waiting in parks and forests. You''ll navigate outdoor clues, discover scenic spots, and leave your own artistic stamp mark as proof you found each one.',NULL);
INSERT INTO badges VALUES(414,'Letter Writing','letter-writing-badge','Discover Art','Charlotte Duke','letter-writing-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/letter-writing-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Putting pen to paper and sending a letter through the mail is a lost art worth bringing back. You''ll discover the joy of writing to real people, explore how mail actually travels, and maybe even start a lasting friendship through the mailbox.',NULL);
INSERT INTO badges VALUES(415,'Library','library-badge','Discover Knowledge','Kerry Cordy','library-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/library-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A library is way more than just books—it''s a treasure hunt where librarians help you find exactly what you''re looking for, plus movies, maker spaces, clubs, and programs you might never expect to discover. Your library card opens the door to endless stories, knowledge, and community.',NULL);
INSERT INTO badges VALUES(416,'Light and Shadow','light-and-shadow','Discover Science & Technology','Heidi Fairbrother','light-and-shadow.png',0,NULL,'https://curiosityuntamed.com/badges/light-and-shadow/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Shadows are just blocked light, and they change size depending on how close the light is and which direction it comes from. Play with flashlights, sunlight, and see-through materials to discover how light bends, bounces, and disappears.',NULL);
INSERT INTO badges VALUES(417,'Lip Balm','lip-balm-badge','Discover Science & Technology','Makayla Russell','lip-balm-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/lip-balm-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Lip balm keeps your lips soft and protected, but it''s way more than just a waxy stick—it''s a mix of oils, waxes, and flavorings that companies have been perfecting for over a hundred years. You''ll discover why your lips need moisture, taste-test different brands and flavors, and learn how lip balm stacks up against glosses and lipsticks.',NULL);
INSERT INTO badges VALUES(418,'Liquid Nitrogen','liquid-nitrogen-badge','Discover Science & Technology','Karen Harwick','liquid-nitrogen-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/liquid-nitrogen-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Liquid nitrogen is so cold it freezes things instantly and creates dramatic clouds of vapor. Watch everyday materials transform in seconds and explore the science behind extreme cold.',NULL);
INSERT INTO badges VALUES(419,'Literary Heroines','literary-heroines-badge','Discover Character','Suzanne Vicoryosmanson','literary-heroines-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/literary-heroines-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Girls throughout history and stories have shown real courage, cleverness, and heart to overcome challenges and help others. Explore what makes someone truly heroic and discover how you can show those same brave qualities in your own life.',NULL);
INSERT INTO badges VALUES(420,'Listening','listening-badge','Discover Character','','listening-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/listening-badge/','{"preschool":1,"level1":2,"level2":3}',1,'2026-05-20 16:10:36','Real listening means giving someone your full attention—whether they''re reading you a story, sharing memories, or just talking. Discover what you hear when the world gets quiet, and learn why paying attention is one of the kindest things you can do for another person.',NULL);
INSERT INTO badges VALUES(421,'Little House','little-house-on-the-prairie-badge','Discover Knowledge','Kerry Cordy','little-house-on-the-prairie-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/little-house-on-the-prairie-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Step into the frontier world of Laura Ingalls Wilder, where families built homes from logs, grew their own food, and faced harsh winters together. Her stories capture the grit, creativity, and close family bonds that shaped American pioneer life.',NULL);
INSERT INTO badges VALUES(422,'Little Women','little-women-badge','Discover Knowledge','Suzanne Vicoryos','little-women-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/little-women-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Louisa May Alcott''s story of the March sisters follows four very different girls growing up during the Civil War, each with their own dreams and challenges. Their bonds as sisters, their creativity, and their courage through hardship still inspire readers today.',NULL);
INSERT INTO badges VALUES(423,'Locovore','local-motion-badge','Discover the World','Amy Chartier',NULL,0,NULL,'https://curiosityuntamed.com/badges/local-motion-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Eating local means exploring the food and products right in your own backyard—farms, bakeries, and shops nearby that feed your community. You''ll discover what grows in your region, meet the people who make it, and figure out why some folks choose to eat and buy close to home.','🌾');
INSERT INTO badges VALUES(424,'Louis L’Amour','louis-lamour-badge','Discover Knowledge','','louis-lamour-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/louis-lamour-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Louis L''Amour wrote some of the most thrilling Wild West stories ever told, packed with tough cowboys, frontier adventures, and shootouts that keep you turning pages. His characters felt real, his landscapes stretched across the American frontier, and his tales of survival and honor still grab readers today.',NULL);
INSERT INTO badges VALUES(425,'Love','love-badge','Discover Character','Kerry Cordy','love-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/love-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Love is the feeling that makes you want to care for someone, show up when they need you, and celebrate the things that make them special. It shows up in big gestures and everyday kindness.',NULL);
INSERT INTO badges VALUES(426,'Love Languages','love-languages-badge','Discover Character','',NULL,0,NULL,'https://curiosityuntamed.com/badges/love-languages-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Everyone shows love in different ways—some people light up when you say something nice, others feel loved through a hug or help with a chore. Discover the five love languages and figure out how you and the people around you like to give and receive care.','💝');
INSERT INTO badges VALUES(427,'Lunar Science','lunar-science-moon-badge','Discover Science & Technology','Elaine Pelizzari',NULL,0,NULL,'https://curiosityuntamed.com/badges/lunar-science-moon-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The moon lights up our night sky and pulls on Earth''s oceans, but what exactly is it and why does it change shape every night? Explore the lunar phases, safely observe the moon and stars, and discover how this ancient celestial neighbor affects our whole planet.','🌙');
INSERT INTO badges VALUES(428,'Magic Tricks','magic-tricks-badge','Discover Knowledge','Becky Wright','magic-tricks-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/magic-tricks-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Magic tricks use clever sleight of hand, misdirection, and props to create impossible-looking moments that leave audiences amazed and wondering "how''d you do that?" Master card tricks, rope illusions, puzzles, and more while discovering what separates magicians from illusionists.',NULL);
INSERT INTO badges VALUES(429,'Magnetism','magnetism','Discover Science & Technology','Kerry Cordy','magnetism.jpg',0,NULL,'https://curiosityuntamed.com/badges/magnetism/','{"preschool":1,"level1":2,"level2":3,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Magnets are mysterious forces that push and pull without even touching. Experiment with different strengths, flip them to watch them repel each other, turn ordinary metal into a magnet yourself, and navigate with a homemade compass.',NULL);
INSERT INTO badges VALUES(430,'Mail Art','mail-art-badge','Discover Art','Jen Milakovic','mail-art-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/mail-art-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Mail art transforms envelopes and postcards into miniature canvases with drawings, collages, stamps, and wild designs. Create colorful pieces that bring joy to whoever opens the mailbox.',NULL);
INSERT INTO badges VALUES(431,'Main Dishes','main-dishes-badge','Discover the Home','Doreen Olson','main-dishes-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/main-dishes-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A main dish is the star of the meal—the hearty, filling centerpiece that brings everyone to the table. Discover what goes into making them, from proteins and produce to different cooking styles around the world, and cook a few yourself to feed your family.',NULL);
INSERT INTO badges VALUES(432,'Make Up','make-up-badge','Discover Health & Safety','Doreen Olson',NULL,0,NULL,'https://curiosityuntamed.com/badges/make-up-badge/','{"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Makeup is a form of self-expression that goes way beyond just looking pretty—it''s about color theory, blending techniques, and understanding skin tones. Explore how to apply products safely, take care of your skin, and use makeup creatively to highlight your features or just have fun.','💄');
INSERT INTO badges VALUES(433,'Mammals','animal-kingdom-mammals','Discover the Outdoors','Kerry Cordy','animal-kingdom-mammals.jpg',0,'A separate badge  can be earned for each of the following categories: Mammals, reptiles, amphibians, marine life, insects, and birds.','https://curiosityuntamed.com/badges/animal-kingdom-mammals/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Mammals are animals with fur or hair, backbones, and mothers that make milk for their babies—and humans are mammals too. Spot them in your neighborhood or beyond, learn what makes each species unique, and discover how they survive, eat, and communicate in the wild.',NULL);
INSERT INTO badges VALUES(434,'Manga','manga-badge','Discover Art','Finian Stroup',NULL,0,NULL,'https://curiosityuntamed.com/badges/manga-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Manga is the Japanese art of storytelling through comics, with dramatic eyes, action-packed scenes, and styles for every age and interest. Dive into the history, distinctive art techniques, and thrilling worlds that make manga beloved by millions around the globe.','🖼️');
INSERT INTO badges VALUES(435,'Man made Wonders (Specific)','manmade-wonders-badge-specific','Discover Science & Technology','Doreen Olson','manmade-wonders-badge-specific.jpg',1,'This badge is designed to focus on individual structure types such as bridges, dams, tunnels, skyscrapers, cathedrals, or stadiums.  A separate badge may be earned for each type of structure studied. Need ideas?  Check out Skyscrapers Unit Study','https://curiosityuntamed.com/badges/manmade-wonders-badge-specific/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Humans have built some incredible structures—from towering skyscrapers to elegant bridges—and each one solves a puzzle: how to make something stand strong, look amazing, and actually work. Pick a type of structure that fascinates you, study real examples, build your own mini version, and discover how engineers keep improving their designs.',NULL);
INSERT INTO badges VALUES(436,'Maple Syrup','maple-syrup-badge','Discover the Outdoors','Josie Rickerson','maple-syrup-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/maple-syrup-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Maple syrup comes from tree sap that''s boiled down into golden sweetness, and it takes a whole season to make. Discover which maple trees give the best sap, when to tap them, and how this natural treasure goes from forest to your pancakes.',NULL);
INSERT INTO badges VALUES(437,'Marbles','marbles','Discover Knowledge','Brenda Talbott','marbles.jpg',0,NULL,'https://curiosityuntamed.com/badges/marbles/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Marbles are colorful glass spheres with swirling patterns that have been around for centuries, each type with its own nickname and look. Roll them in classic games like ringtaw and lagging, then discover how these tiny treasures were handmade long ago and manufactured today.',NULL);
INSERT INTO badges VALUES(438,'March 4th (Forth!)','march-4th-forth-badge','Discover Knowledge','','march-4th-forth-badge.png',0,NULL,'https://curiosityuntamed.com/badges/march-4th-forth-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','March 4th is Frontier Girls'' day of connection—a chance to celebrate the spirit of pioneers and reach out to sisters in troops across the country. You''ll discover why this date matters, make new friends through letters and swaps, and share something special that represents your home region.',NULL);
INSERT INTO badges VALUES(439,'Marine Craft','marine-craft-badge','Discover Science & Technology','Charlotte Duke','marine-craft-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/marine-craft-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Ships have sailed the oceans for thousands of years, from tiny wooden sailing boats to giant modern cruise ships and cargo carriers. Explore how ships are built, what makes them float, and the amazing jobs different vessels do across the world''s oceans.',NULL);
INSERT INTO badges VALUES(440,'Marine Life','animal-badge-marine-life','Discover the Outdoors','Kerry Cordy','animal-badge-marine-life.jpg',0,'A separate badge  can be earned for each of the following categories: Mammals, reptiles, amphibians, marine biology, insects, and birds.','https://curiosityuntamed.com/badges/animal-badge-marine-life/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Ocean, river, and coastal creatures come in wild varieties—from tiny seahorses to massive whales. Pick a marine animal group that fascinates you, learn what makes them tick, and become an expert at spotting the different species around you.',NULL);
INSERT INTO badges VALUES(441,'Marines','marines-badge','Discover Knowledge','Kerry Cordy','marines-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/marines-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Marines are tough soldiers who fight on land, sea, and air—and they''ve been protecting America since 1775. Learn what makes them special, how they train, and the incredible ways they''ve served throughout history.',NULL);
INSERT INTO badges VALUES(442,'Marshmallows','marshmallow-badge','Discover the Home','','marshmallow-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/marshmallow-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fluffy marshmallows start as a sweet mixture whipped full of air, then dusted with powdered sugar to keep them from sticking. Roast them over a fire, layer them into s''mores, or experiment with homemade versions to discover why this puffy treat has been a campfire favorite for over a century.',NULL);
INSERT INTO badges VALUES(443,'Mary Poppins','mary-poppins-tm-badge','Discover Knowledge','Arabella Fuhrman','mary-poppins-tm-badge.jpg',0,'This badge focuses on the Mary Poppins book series by P.L. Travers. The Movies (Specific) badge is recommended for those who would like to learn more about the Mary Poppins movies.','https://curiosityuntamed.com/badges/mary-poppins-tm-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A magical nanny who slides up banisters, carries an endless carpet bag, and turns chores into adventures. Mary Poppins shows that a spoonful of sugar really does help the medicine go down, and that practically perfect people can be found anywhere.',NULL);
INSERT INTO badges VALUES(444,'Massage','massage-badge','Discover Health & Safety','Doreen Olson','massage-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/massage-badge/','{"preschool":1,"level1":4,"level2":5,"level3":6,"level4":7,"level5":7}',1,'2026-05-20 16:10:36','Massage is a hands-on way to help someone relax and feel better, using gentle strokes and pressure on feet, hands, and legs. You''ll learn real techniques that make people feel cared for and more comfortable.',NULL);
INSERT INTO badges VALUES(445,'Math','mathematics-badge','Discover Science & Technology','Kerry Cordy','mathematics-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/mathematics-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Numbers and measurement are everywhere—from counting your toys to figuring out how tall you''ve grown. This badge explores the math hiding in your everyday world, turning everyday objects and your own body into fun things to count, compare, and measure.',NULL);
INSERT INTO badges VALUES(446,'May Baskets','may-baskets-badge','Discover the World','Amy Chartier','may-baskets-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/may-baskets-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','May baskets are springtime gifts filled with flowers, treats, and surprises that celebrate the arrival of May. Discover this cheerful tradition, craft colorful baskets by hand, and spread joy by delivering them to people who''ll love the thoughtful surprise.',NULL);
INSERT INTO badges VALUES(447,'Meal Traditions','meal-traditions-badge','Discover the World','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/meal-traditions-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every family has meals that matter—maybe a recipe passed down for generations or a weekly dinner that brings everyone together. Discover what makes your own traditions special, then explore how people around the world eat differently, from the utensils they use to the manners that matter most at their tables.','🍽️');
INSERT INTO badges VALUES(448,'Meat Animals','meat-animals-badge','Discover Agriculture','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/meat-animals-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Meat comes from different animals like cows, pigs, chickens, and fish—and each kind tastes unique. Discover where your food comes from, learn how farmers raise these animals with proper care and housing, and explore the full journey from farm to table.','🐄');
INSERT INTO badges VALUES(449,'Microscopes','microscope-badge','Discover Science & Technology','Doreen Olson','microscope-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/microscope-badge/','{"level5":7}',1,'2026-05-20 16:10:36','Microscopes unlock the invisible world hiding in a drop of water or speck of dust. Peer at tiny creatures, plant cells, and crystal patterns that are impossible to see with your bare eyes.',NULL);
INSERT INTO badges VALUES(450,'Microsoft Office','microsoft-office-badge','Discover Knowledge','','microsoft-office-badge.jpg',0,'This badge is designed to learn about all-inclusive office software, Microsoft Office, Office 365, Google Drive, etc.','https://curiosityuntamed.com/badges/microsoft-office-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Microsoft Office is a power-packed suite of tools that help you organize, create, and share ideas. Whether you''re writing documents, building spreadsheets, or designing presentations, these programs are built to make your work faster and easier.',NULL);
INSERT INTO badges VALUES(451,'Military Family','military-family','Discover the Home','MaryEllen King','military-family.jpg',0,NULL,'https://curiosityuntamed.com/badges/military-family/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Military families have unique stories shaped by service, sacrifice, and strength across the five branches. Connect with the veterans and active-duty members in your life to understand their missions, the bonds they share, and what it really means to support those who serve.',NULL);
INSERT INTO badges VALUES(452,'Mind Puzzles','mind-puzzles-badge','Discover Health & Safety','','mind-puzzles-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/mind-puzzles-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Mind puzzles are brain games like crosswords, sudoku, and logic mazes that challenge you to think differently and solve problems. They''re a fun way to keep your mind sharp while having patience and enjoying the "aha!" moment when a tricky puzzle clicks into place.',NULL);
INSERT INTO badges VALUES(453,'Minecraft','minecraft','Discover Knowledge','Giovanni Sepulveda Jr','minecraft.png',0,'To complete this badge, you must have access to Minecraft.','https://curiosityuntamed.com/badges/minecraft/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Minecraft is a sandbox world where you mine resources, build structures, and survive against creatures. Whether you''re creating a dream castle or exploring underground caves, there''s always something new to discover and build.',NULL);
INSERT INTO badges VALUES(454,'Miniatures','miniatures','Discover Art','Kerry Cordy','miniatures.jpg',0,NULL,'https://curiosityuntamed.com/badges/miniatures/','{"level1":2,"level2":3,"level3":4,"level4":5}',1,'2026-05-20 16:10:36','Tiny worlds fit in your hands when you craft miniatures—teeny furniture, food, flowers, and more at perfect scale. Explore what people have been making small for centuries and discover why tiny things feel so magical.',NULL);
INSERT INTO badges VALUES(455,'Mini Golf','mini-golf-badge','Discover Health & Safety','','mini-golf-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/mini-golf-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Mini golf is a fun game where you putt a ball through creative courses with obstacles, ramps, and tricky angles. It''s a great way to practice patience, aim, and strategy while enjoying time outdoors or indoors with friends and family.',NULL);
INSERT INTO badges VALUES(456,'Modesty','modesty-badge','Discover Character','Kerry Cordy','modesty-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/modesty-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Modesty is about being humble and not bragging, even when you''ve done something awesome. It means letting your actions speak for themselves and making others feel good instead of showing off.',NULL);
INSERT INTO badges VALUES(457,'Money','money-badge','Discover the Home','Cindy Lillemo',NULL,0,NULL,'https://curiosityuntamed.com/badges/money-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Money is the tool people use to buy things, save for the future, and trade value with each other. You''ll get to know every coin and bill, discover the clever security tricks that keep money safe from fakes, and play games that show how money actually moves around in real life.','💰');
INSERT INTO badges VALUES(458,'Morse Code','morse-code-badge','Discover the Home','Amy Chartier','morse-code-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/morse-code-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Morse code is a secret language of dots and dashes that turn letters into signals you can tap, flash, or beep. Once you crack the code, you can send hidden messages to friends using nothing but sound and light.',NULL);
INSERT INTO badges VALUES(459,'Mosaics','mosaics','Discover Art','Kerry Cordy','mosaics.jpg',0,NULL,'https://curiosityuntamed.com/badges/mosaics/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Mosaics turn broken tiles, glass, and colorful pieces into stunning pictures and patterns when you arrange them just right. Watch something beautiful come together one small piece at a time.',NULL);
INSERT INTO badges VALUES(460,'Movies (Specific)','movies-specific','Discover Art','','movies-specific.png',1,'This badge can be earned as a general Movies badge or be adapted to earn a specific badge for each movie you wish to learn about.','https://curiosityuntamed.com/badges/movies-specific/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Movies tell stories on screen that can make you laugh, think, or feel surprised. Pick one you love, share what you think about it, create something inspired by what you watched, and explore how different countries decide which movies are right for different ages.',NULL);
INSERT INTO badges VALUES(461,'Mummies','mummies-badge','Discover Knowledge','Crystal Morris',NULL,0,NULL,'https://curiosityuntamed.com/badges/mummies-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Ancient Egyptians figured out how to preserve dead bodies so they''d last thousands of years—and we can still learn from them today. Mummies show us what people ate, what diseases they had, and how they lived, making them like time capsules that help archaeologists solve history''s mysteries.','🪦');
INSERT INTO badges VALUES(462,'Museums','museum-badge','Discover the World','Karen Britton','museum-badge.jpg',1,'This badge can be earned multiple times for whichever museums you have visited.','https://curiosityuntamed.com/badges/museum-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Museums are treasure houses where you can walk through history, art, nature, and science all under one roof. From ancient mummies to dinosaur skeletons to paintings that took years to create, there''s always something amazing to explore and learn.',NULL);
INSERT INTO badges VALUES(463,'Mushrooms','mushrooms-badge','Discover the Outdoors','Seri Fields',NULL,0,NULL,'https://curiosityuntamed.com/badges/mushrooms-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Mushrooms are fungi that pop up in forests, yards, and dead logs—and they''re totally different from plants and animals. You''ll hunt for them outside, learn their secret parts, and discover why these mysterious organisms matter to the whole forest.','🍄');
INSERT INTO badges VALUES(464,'Music','music-badge','Discover Art','Charlotte Duke','music-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/music-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Music is everywhere—in your favorite songs, movies, celebrations, and even when you''re just hanging out. Explore different styles like rock, classical, jazz, and rap to find what moves you, discover the instruments that create those sounds, and understand why music matters so much to people all around the world.',NULL);
INSERT INTO badges VALUES(465,'Music Appreciation','music-appreciation-badge','Discover Art','Kerry Cordy','music-appreciation-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/music-appreciation-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Music surrounds you everywhere—from classical symphonies to hip-hop beats to jazz improvisation. Dive into different genres and learn to spot the unique sounds of instruments like violins, drums, and saxophones as you discover what makes each style special.',NULL);
INSERT INTO badges VALUES(466,'Music Boxes','music-boxes-badge','Discover Knowledge','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/music-boxes-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Music boxes are mechanical machines that play tinkling melodies when you wind them up—no batteries needed. Discover how tiny pins on a spinning cylinder pluck metal teeth to create beautiful songs, and explore the different designs that have delighted people for hundreds of years.','🎵');
INSERT INTO badges VALUES(467,'Music Group Fan (Specific)','music-group-fan-badge','Discover Art','Charlotte Duke','music-group-fan-badge.jpg',1,'This badge can be earned multiple times for each band/music group you like to listen to.','https://curiosityuntamed.com/badges/music-group-fan-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Music groups create unforgettable sounds with their unique style and story—from how they got their name to the faces behind the voices. Dive deep into your favorite band by learning their songs, members, and history like a true fan.',NULL);
INSERT INTO badges VALUES(468,'Music History','music-history-badge','Discover Art','Abby Olson','music-history-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/music-history-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Music has come a long way from ancient drums and pipes to pianos and guitars. Explore how instruments evolved, meet famous composers from different eras, and discover what made each musical period sound totally unique.',NULL);
INSERT INTO badges VALUES(469,'Musical Instrument (Specific)','musical-instrument-specific-badge','Discover Art','Doreen Olson','musical-instrument-specific-badge.jpg',1,'This badge can be earned multiple times using a different instrument each time. Any instrument can be learned about.','https://curiosityuntamed.com/badges/musical-instrument-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Playing an instrument means mastering the basics—how to hold it, keep it in tune, and make it sound good. You''ll learn to read music, play real songs, and discover that practice and patience turn those first squeaky notes into something worth sharing.',NULL);
INSERT INTO badges VALUES(470,'My Community','my-community-badge','Discover the World','Charlotte Duke','my-community-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/my-community-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your community has a story—from the first settlers who arrived to the neighborhoods and people you see today. Dig into your town''s history, map out where you live, and discover the interesting events and families that shaped the place you call home.',NULL);
INSERT INTO badges VALUES(471,'My Little Pony Friendship is Magic','my-little-pony-friendship-is-magic-badge','Discover the Home','Megan Bond','my-little-pony-friendship-is-magic-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/my-little-pony-friendship-is-magic-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Equestria''s six pony friends—Twilight Sparkle, Rainbow Dash, Pinkie Pie, Applejack, Rarity, and Fluttershy—each have special talents shown by their cutie marks. Follow their adventures as they discover that friendship, honesty, kindness, laughter, generosity, and loyalty are the most magical powers of all.',NULL);
INSERT INTO badges VALUES(472,'My Troop','my-troop','Discover Character','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/my-troop/','{}',0,'2026-05-20 16:10:36','Your troop is a group of people working together toward shared goals, learning from each other, and building friendships that last. Being part of a troop means finding your place in a community that supports and celebrates you.','🤝');
INSERT INTO badges VALUES(473,'Mythological Creatures','mythological-creatures','Discover Knowledge','Amanda Piccirillo','mythological-creatures.jpg',1,'This badge can be earned multiple times for each type of mythological creature.','https://curiosityuntamed.com/badges/mythological-creatures/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Dragons breathe fire, phoenixes rise from ashes, and unicorns gallop through enchanted forests—each mythological creature has its own wild powers, weaknesses, and stories. Explore the legends behind these incredible beings and discover where they roamed in the imaginations of ancient cultures.',NULL);
INSERT INTO badges VALUES(474,'Mythology','mythology-badge','Discover Knowledge','Kerry Cordy','mythology-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/mythology-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Ancient myths are epic tales from cultures around the world that explain natural mysteries, teach lessons, and celebrate gods and heroes. Dive into stories from Greek gods on Mount Olympus, then explore the unique myths of other cultures like the Celts, Native Americans, or Japanese to see how different people told their biggest stories.',NULL);
INSERT INTO badges VALUES(475,'Mythology (Specific)','mythology-specific-badge','Discover the World','Kerry Cordy',NULL,1,NULL,'https://curiosityuntamed.com/badges/mythology-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every culture tells epic stories about gods, monsters, and heroes who shape their world. Pick one mythology that calls to you—Greek, Egyptian, Norse, or beyond—and dive into the wild adventures, legendary creatures, and divine powers that made these ancient stories unforgettable.','🐉');
INSERT INTO badges VALUES(476,'Nail Art','nail-art-badge','Discover Art','Kelly Araneda','nail-art-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/nail-art-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your fingernails become a tiny canvas for creativity—painting designs, patterns, and pictures that show off your personal style. A fun way to express yourself with color, brushes, and imagination.',NULL);
INSERT INTO badges VALUES(477,'Napkin Folding','napking-folding-badge','Discover Art','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/napking-folding-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pretty napkins can turn an ordinary table into something special, and folding them into fancy shapes is easier than you''d think. Master a few simple folds and you''ll be ready to impress at any dinner.','🍽️');
INSERT INTO badges VALUES(478,'National Landmarks (Specific)','national-landmarks','Discover the World','Suzanne Vicoryosmanson','national-landmarks.jpg',1,NULL,'https://curiosityuntamed.com/badges/national-landmarks/','{}',0,'2026-05-20 16:10:36','Iconic buildings, monuments, and natural wonders dot the globe, each with its own incredible story. Explore what makes these landmarks famous and why people travel from around the world to see them.',NULL);
INSERT INTO badges VALUES(479,'National Monuments/Memorials (Specific)','national-monumentmemorial-specific-badge','Discover the World','Karen Britton','national-monumentmemorial-specific-badge.jpg',1,'This badge can be earned multiple times for different monuments or memorials.','https://curiosityuntamed.com/badges/national-monumentmemorial-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','America''s monuments and memorials stand as reminders of important people, events, and ideals that shaped the nation. These landmarks tell powerful stories through their architecture, location, and the history they preserve.',NULL);
INSERT INTO badges VALUES(480,'Native American Art','native-american-art-badge','Discover Art','Linda Ruley','native-american-art-badge.jpg',0,'This badge may be earned as a single generic badge or earned multiple times for specific tribes or regions (such as the American Southwest).','https://curiosityuntamed.com/badges/native-american-art-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Native American artists create stunning pieces using traditional techniques like beadwork, pottery, weaving, and carving that tell stories about their cultures and histories. Each tribe has its own distinct styles, patterns, and materials that have been passed down through generations.',NULL);
INSERT INTO badges VALUES(481,'Natural Disasters (Specific)','natural-disasters-badge','Discover the Outdoors','Kerry Cordy','natural-disasters-badge.jpg',1,'This badge can be earned multiple times, once for each different type of natural disaster you study. Possible badges are earthquakes, hurricanes, tornadoes, tsunamis, wild fires, floods, drought, land slides, thunder storms, etc.','https://curiosityuntamed.com/badges/natural-disasters-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Earthquakes, tornadoes, hurricanes, and floods are powerful forces of nature that impact communities around the world. Understand what causes these disasters, how to stay safe when they strike, and how your family can prepare before one happens.',NULL);
INSERT INTO badges VALUES(482,'Natural Food Coloring','natural-food-coloring-badge','Discover the Home','','natural-food-coloring-badge.png',0,NULL,'https://curiosityuntamed.com/badges/natural-food-coloring-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Plants, spices, and pantry staples can turn into vibrant dyes—no chemicals needed. Squeeze color from beets and blueberries, experiment with turmeric and spinach, and discover which natural ingredients stain the brightest on fabric and food.',NULL);
INSERT INTO badges VALUES(483,'Natural Wonders (General)','natural-wonders-badge','Discover the Outdoors','Doreen Olson','natural-wonders-badge.jpg',0,'This badge is meant to give a general understanding of several different types of natural wonders.  If you wish to specialize in a specific natural wonder, such as waterfalls or volcanoes, please see the Natural Wonders (Specific) badge.  The “General” version is perfect for family trips across a large area with stops at famous sites.','https://curiosityuntamed.com/badges/natural-wonders-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Natural wonders are the planet''s most breathtaking places—towering mountains, massive waterfalls, ancient canyons, and more. Explore what makes these spots extraordinary, find them on a map, and learn how to visit them respectfully and safely.',NULL);
INSERT INTO badges VALUES(484,'Navy','navy-badge','Discover Knowledge','Kerry Cordy','navy-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/navy-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Navy protects our coasts and keeps shipping lanes safe across the world''s oceans. Explore how sailors and ships work together, the Navy''s long history, and why this branch of the military matters to our country.',NULL);
INSERT INTO badges VALUES(485,'Neon Lights','neon-lights-badge','Discover Science & Technology','',NULL,0,NULL,'https://curiosityuntamed.com/badges/neon-lights-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Neon lights glow with brilliant colors in signs, art, and decorations—and the science behind them is just as cool. Explore how gases light up when electricity passes through them and create those eye-catching neon effects.','💡');
INSERT INTO badges VALUES(486,'Neuroscience','neuroscience-badge','Discover Science & Technology','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/neuroscience-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your brain is the command center running your thoughts, feelings, memories, and every move you make. Peek inside this incredible organ to discover how its different parts work together and what you can do to keep it sharp and healthy.','🧠');
INSERT INTO badges VALUES(487,'NERF Guns','nerf-guns-badge','Discover the Outdoors','','nerf-guns-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/nerf-guns-badge/','{"preschool":0,"level1":1,"level2":1,"level3":2,"level4":2,"level5":7}',1,'2026-05-20 16:10:36','NERF guns are foam blasters that fire soft darts safely across backyards and fields. Master the rules that keep everyone protected, learn how these guns actually work, and practice real shooting techniques to hit your targets with accuracy.',NULL);
INSERT INTO badges VALUES(488,'Newspapers','newspapers-badge','Discover Knowledge','Charlotte Duke','newspapers-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/newspapers-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Newspapers gather stories, sports scores, ads, and photos all in one place so people can stay informed about their community and the world. Find out how reporters dig up news, explore different sections, and see what goes on behind the scenes at a newspaper office or website.',NULL);
INSERT INTO badges VALUES(489,'Norse Studies','norse-studies-badge','Discover the World','Sandra Hanson',NULL,0,NULL,'https://curiosityuntamed.com/badges/norse-studies-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Norse were bold seafarers and warriors from Scandinavia over a thousand years ago who explored, traded, and settled across Europe. Discover how they lived in villages, what they wore, the games they played, and the epic events that shaped their legendary history.','⚔️');
INSERT INTO badges VALUES(490,'Nursing History','nursing-history-badge','Discover Knowledge','Charlotte Duke','nursing-history-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/nursing-history-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','From battlefield tents to modern hospitals, nurses have been healing the sick and injured throughout history. Explore how nursing evolved from a calling into a skilled profession that saves lives every day.',NULL);
INSERT INTO badges VALUES(491,'Nutcracker Ballet','the-nutcracker-ballet-badge','Discover Art','Tammy Elliot','the-nutcracker-ballet-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/the-nutcracker-ballet-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Nutcracker is a magical holiday ballet full of dancing dolls, enchanted forests, and a hero who shrinks into a dreamworld. Discover the real stories behind the music and characters, and explore how nutcrackers became symbols of protection and good luck across different cultures.',NULL);
INSERT INTO badges VALUES(492,'Nutrition','nutrition-badge','Discover Health & Safety','Doreen Olson','nutrition-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/nutrition-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your body runs on fuel from food, and different foods give you different things you need—like energy, strong bones, and healthy muscles. Learn what makes a meal nutritious, how to spot healthy choices, and what all those numbers on food packages actually mean.',NULL);
INSERT INTO badges VALUES(493,'Nuts','nuts-badge','Discover Agriculture','Doreen Olson','nuts-badge.jpg',0,'This badge is about the cultivation of tree nuts.  It does not cover other “nuts” such as peanuts, soy “nuts,” chufa nuts, or seeds. Need ideas?  Check out our Nuts Unity Study','https://curiosityuntamed.com/badges/nuts-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Nuts grow inside hard shells and come in wild varieties—from peanuts and almonds to walnuts and pecans. Crack them open, taste the differences, and discover why these crunchy snacks have been feeding people for thousands of years.',NULL);
INSERT INTO badges VALUES(494,'Obstacle Course','obstacle-course-badge','Discover the Outdoors','Amanda Barnette','obstacle-course-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/obstacle-course-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Obstacle courses challenge your speed, strength, and problem-solving as you jump, climb, crawl, and dash through creative barriers. Build your own course with everyday stuff, test yourself against it, and discover what your body can do.',NULL);
INSERT INTO badges VALUES(495,'Occupation/Career (Specific)','occupation-career-specific-badge','Discover Knowledge','Amanda Barnette','occupation-career-specific-badge.jpg',1,'This badge may be repeated multiple times for different occupations.','https://curiosityuntamed.com/badges/occupation-career-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every job is different—some people work outside, others in offices, hospitals, or studios. Pick an occupation that interests you and explore what the work is really like, where it happens, and whether it might be something you''d love to do someday.',NULL);
INSERT INTO badges VALUES(496,'Ocean','ocean-badge-2','Discover the Outdoors','Marie Dichoso-Beavers','ocean-badge-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/ocean-badge-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Oceans cover most of our planet and teem with incredible life—from tiny creatures in coral reefs to giant whales in the deep. Explore salty waters, discover the animals that call different ocean habitats home, and learn how to visit beaches and coastlines while protecting them for the future.',NULL);
INSERT INTO badges VALUES(497,'Ocean Conservation','ocean-conservation-badge','Discover the Outdoors','',NULL,0,NULL,'https://curiosityuntamed.com/badges/ocean-conservation-badge/','{"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Our oceans cover most of the planet and give us food, oxygen, and even medicine—but they''re getting buried in trash. Find out why keeping oceans healthy matters for all of us and discover simple ways you can help protect them from your own home.','🌊');
INSERT INTO badges VALUES(498,'Office Worker','office-worker-badge','Discover Knowledge','Doreen Olson','office-worker-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/office-worker-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','An office is a busy place where people answer phones, organize files, and keep everything running smoothly. Find out what office workers really do and try on the professional skills that keep a workplace humming.',NULL);
INSERT INTO badges VALUES(499,'Orienteering','orienteering-badge','Discover the Outdoors','Kerry Cordy','orienteering-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/orienteering-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Navigation with a map and compass turns you into a explorer who can find their way anywhere outdoors. Whether you''re hiking through forests, crossing open fields, or navigating unfamiliar terrain, these tools help you stay on course and discover where you''re really going.',NULL);
INSERT INTO badges VALUES(500,'Olympics','olympics-badge','Discover Knowledge','Lynda Borden','olympics-badge.jpg',0,'This badge is designed to be earned during an Olympic year. You will need to adjust the requirements accordingly if you are trying to earn it in an off year.','https://curiosityuntamed.com/badges/olympics-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Olympics bring together the world''s best athletes every few years to compete in amazing sports—from gymnastics and swimming to ice skating and track and field. Explore the history of these global games, track your favorite athletes, and discover what those iconic rings and symbols really mean.',NULL);
INSERT INTO badges VALUES(501,'Organic Foods','organic-foods-badge','Discover Agriculture','Kerry Cordy','organic-foods-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/organic-foods-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Organic food grows without artificial chemicals or pesticides, relying on natural soil and farming methods instead. Taste the difference yourself, explore why farmers choose this path, and discover how growing food this way helps the land stay healthy for the future.',NULL);
INSERT INTO badges VALUES(502,'Origami','origami-badge','Discover Art','Kerry Cordy','origami-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/origami-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Folding paper into birds, frogs, and flowers turns a flat square into something that can stand, fly, or hop. A patient hobby with surprising results that started centuries ago in Japan.',NULL);
INSERT INTO badges VALUES(503,'Our Flag','flag-badge','Discover Knowledge','Kerry Cordy','flag-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/flag-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The American flag is packed with meaning—from the 13 stripes honoring the original colonies to the stars representing each state. Explore how the flag has changed over time, what the Pledge of Allegiance really says, and why people stand with their hand over their heart when it passes by.',NULL);
INSERT INTO badges VALUES(504,'Outdoor Cooking','outdoor-cooking','Discover the Outdoors','Kerry Cordy','outdoor-cooking.jpg',0,NULL,'https://curiosityuntamed.com/badges/outdoor-cooking/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cooking outside over a fire or camp stove tastes better and feels like an adventure. Plan the menu, prep the food safely, handle hot steam and flames carefully, and master the cleanup so the campsite is left perfect.',NULL);
INSERT INTO badges VALUES(505,'Outdoor Exploration','outdoor-exploration-badge','Discover the Outdoors','Elizabeth Simmons',NULL,0,NULL,'https://curiosityuntamed.com/badges/outdoor-exploration-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Nature''s waiting in your backyard, local park, or hiking trail with bugs to spot, plants to identify, and surprises around every corner. Get outside and see what you can find.','🏕️');
INSERT INTO badges VALUES(506,'Outdoor Safety','outdoor-safety-2','Discover Health & Safety','Kerry Cordy','outdoor-safety-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/outdoor-safety-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Being outside is amazing, but knowing how to stay safe makes it even better. From sun protection and bug awareness to water safety and weather smarts, you''ll be ready for whatever adventure comes your way.',NULL);
INSERT INTO badges VALUES(507,'Painting','painting-badge','Discover Art','Nikita Linn','painting-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/painting-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Painting is the art of creating pictures with color and brushstrokes, whether realistic landscapes, bold abstracts, or creative portraits. You''ll explore different paints and techniques, from traditional brushes to unexpected tools like sponges and cotton balls.',NULL);
INSERT INTO badges VALUES(508,'Paleontology','paleontology-badge','Discover Science & Technology','Kerry Cordy','paleontology-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/paleontology-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Dinosaurs roamed the earth millions of years ago, leaving behind fossils that tell us their stories. Paleontologists dig up these clues to discover what ancient creatures looked like, how they lived, and what happened to them.',NULL);
INSERT INTO badges VALUES(509,'Pancakes','pancakes-badge','Discover the Home','Frontier Girls Troop',NULL,0,NULL,'https://curiosityuntamed.com/badges/pancakes-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fluffy pancakes are a breakfast favorite that starts with simple batter and turns golden on the griddle. Mix up a batch, pick your favorite toppings, and discover why people have been flipping pancakes for thousands of years.','🥞');
INSERT INTO badges VALUES(510,'Pancetta','pancetta-badge','Discover the Home','Finian Stroup',NULL,0,NULL,'https://curiosityuntamed.com/badges/pancetta-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pancetta is Italian cured pork belly that''s smoky, salty, and full of flavor. This ingredient transforms breakfast, pasta, and salads into something special when you know how to slice it, cook it, and use it in your kitchen.','🥓');
INSERT INTO badges VALUES(511,'Paper Crafting','paper-crafting-badge','Discover Art','Doreen Olson','paper-crafting-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/paper-crafting-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Paper transforms into anything you imagine—colorful collages, delicate decorations, folded structures, and mixed-media art. Scissors, glue, and creativity are all you need to turn flat sheets into dimensional masterpieces.',NULL);
INSERT INTO badges VALUES(512,'Paper Dolls','paper-doll-badge','Discover Art','','paper-doll-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/paper-doll-badge/','{"preschool":3,"level1":4,"level2":5,"level3":6,"level4":7,"level5":7}',1,'2026-05-20 16:10:36','Paper dolls are flat friends you design, decorate, and dress with outfits you create from cardstock and markers. Cut, color, and swap their clothes for endless imaginative play and storytelling.',NULL);
INSERT INTO badges VALUES(513,'Parades','parade-badge','Discover Knowledge','Emma Lager','parade-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/parade-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Parades bring whole communities together with marching bands, floats, and celebration. Find out what makes your town''s parades special, join in the fun yourself, and discover the stories and purposes behind the big events happening near you.',NULL);
INSERT INTO badges VALUES(514,'Parshah','parshah-specific-badge','Discover Knowledge','Chana Barak',NULL,1,'The term parshah (plural: parashiyot) refers to the sections of the Torah read each week during services. The division of the text into parashiyot for the biblical books is independent of chapter and verse numbers. The division of parashiyot found in modern-day Torah scrolls of all Jewish communities is based upon the systematic list provided by Maimonides. This badge can be earned multiple times for each parshah.','https://curiosityuntamed.com/badges/parshah-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The weekly Torah portion connects you to thousands of years of Jewish tradition and learning. Each parshah reveals stories, laws, and wisdom that have sparked discussion and debate across generations.','📖');
INSERT INTO badges VALUES(515,'Patchwork','patchwork-badge','Discover Art','Sylvia Duke',NULL,0,NULL,'https://curiosityuntamed.com/badges/patchwork-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Patchwork is the art of cutting fabric into shapes that fit together perfectly, then sewing them into colorful patterns and useful things like mats, pillows, or bags. You''ll discover which fabrics work best, how shapes tessellate together without gaps, and create your own patchwork design from start to finish.','🧵');
INSERT INTO badges VALUES(516,'Patience','patience-badge','Discover Character','Kerry Cordy','patience-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/patience-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Patience is the quiet strength that lets you wait calmly for good things to happen, finish hard tasks without rushing, and handle frustrating moments without getting angry. It''s a superpower that makes everything—from learning something new to helping a friend—go so much smoother.',NULL);
INSERT INTO badges VALUES(517,'Patriotism','patriotism-badge','Discover Character','Kerry Cordy','patriotism-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/patriotism-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Patriotism means loving your country and showing respect for its symbols, history, and people. It''s about understanding what your nation stands for and finding ways to contribute to your community and country.',NULL);
INSERT INTO badges VALUES(518,'Pattern Making','pattern-making-badge','Discover the Home','Kerry Cordy','pattern-making-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/pattern-making-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Patterns are the blueprints that turn fabric into clothes that fit just right. Learn to measure, trace, and draft your own patterns so you can create custom vests, shirts, and more for yourself, dolls, or even pets.',NULL);
INSERT INTO badges VALUES(519,'Peace','peace-badge','Discover Character','Kerry Cordy','peace-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/peace-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Peace is about finding calm within yourself and helping others feel safe and understood. It''s a skill that starts with listening, kindness, and choosing words that bring people together instead of tearing them apart.',NULL);
INSERT INTO badges VALUES(520,'Peanut Butter','peanut-butter-badge','Discover Knowledge','','peanut-butter-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/peanut-butter-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Peanut butter starts as humble peanuts that get roasted, ground, and mixed into a creamy or chunky spread. This versatile food has a wild history, surprising nutrition facts, and endless ways to use it beyond sandwiches.',NULL);
INSERT INTO badges VALUES(521,'Pears','pears-badge','Discover Agriculture','Heidi Cole','pears-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/pears-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pears are sweet, juicy fruits that grow on trees and come in dozens of varieties—some crispy, some soft, some green, some golden. You''ll taste different kinds, learn how pear trees grow from tiny seeds into fruit-producing giants, and discover what makes organic pears different from the rest.',NULL);
INSERT INTO badges VALUES(522,'Penpal','pen-pals-badge-2','Discover the World','Adele Nolan','pen-pals-badge-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/pen-pals-badge-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Writing letters to someone across the world is like sending a little piece of yourself through the mail. You''ll make a new friend, learn about their life and culture, and get to read their handwriting on real paper.',NULL);
INSERT INTO badges VALUES(523,'Performance','performance-badge','Discover Art','Doreen Olson','performance-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/performance-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Performance is any time you share something you''ve created or practiced in front of an audience—whether that''s singing a song, acting out a scene, giving a speech, or putting on a puppet show. Getting on stage (or in front of your family) teaches you confidence, how to handle nervousness, and what it feels like to entertain people.',NULL);
INSERT INTO badges VALUES(524,'Perseverance','perseverance-badge','Discover Characte','',NULL,0,NULL,'https://curiosityuntamed.com/badges/perseverance-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Perseverance is the quiet strength that keeps you going when things get tough instead of throwing in the towel. It''s the difference between quitting at the first stumble and discovering what you''re actually capable of when you stick with something.','🏔️');
INSERT INTO badges VALUES(525,'Pets','pets-badge','Discover the Home','Kerry Cordy','pets-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/pets-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pets are animals that live with families and depend on their humans for food, water, shelter, and care. Whether it''s a dog, cat, hamster, or fish, being a pet owner means learning responsibility, safety, and how to show an animal love every single day.',NULL);
INSERT INTO badges VALUES(526,'Phobias','phobia-badge','Discover Health & Safety','Beth Vicory',NULL,0,NULL,'https://curiosityuntamed.com/badges/phobia-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A phobia is a fear so strong it can freeze you up, but unlike everyday worries, it doesn''t go away on its own. Explore what makes phobias tick, discover some surprisingly weird ones like fear of beards or cheese, and learn how to recognize when fear crosses the line from normal to phobia.','😨');
INSERT INTO badges VALUES(527,'Photography','photography-badge','Discover Art','Sophia Sepulveda','photography-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/photography-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A photograph freezes a moment in time, and learning to take good ones means understanding how your camera works and what makes a picture worth looking at. You''ll explore angles, lighting, and composition while building your eye for the shots that tell a story.',NULL);
INSERT INTO badges VALUES(528,'Physics','physics','Discover Science & Technology','Kerry Cordy','physics.jpg',0,NULL,'https://curiosityuntamed.com/badges/physics/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Everything moves because of forces—pushes and pulls that make things go, stop, and change direction. Explore how friction slows things down, gravity pulls everything toward Earth, and air resistance shapes the world around you by building marble runs, sliding experiments, and paper planes.',NULL);
INSERT INTO badges VALUES(529,'Pies','pies-badge','Discover the Home','Kerry Cordy','pies-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/pies-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pies come in endless flavors—from sweet fruit and creamy custard to savory chicken and breakfast quiches. You''ll explore what makes each type different, taste your way through several varieties, and discover why pie has been a beloved dish for centuries.',NULL);
INSERT INTO badges VALUES(530,'Pinewood Derby','pinewood-derby-badge','Discover Science & Technology','Charlotte Duke','pinewood-derby-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/pinewood-derby-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A pinewood derby is a racing competition where you design and build a wooden car from scratch, then send it zooming down a track to see whose engineering skills are fastest. It''s about creativity, physics, and the thrill of watching your handiwork compete.',NULL);
INSERT INTO badges VALUES(531,'Pioneers','pioneer-badge','Discover Knowledge','Katie Lundquist','pioneer-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/pioneer-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pioneers moved westward across America, building homes in wild landscapes and learning to survive with resourcefulness and courage. Their stories show how ordinary people faced extraordinary challenges and helped shape a new frontier.',NULL);
INSERT INTO badges VALUES(532,'Pipe Cleaners','pipe-cleaners-badge','Discover Art','','pipe-cleaners-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/pipe-cleaners-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pipe cleaners started as practical tools for cleaning pipes, but now they''re colorful craft supplies that bend into wild shapes and sculptures. These fuzzy wires come in dozens of colors, metallics, and extra-fluffy styles—perfect for making animals, decorations, and 3D art that actually stands up.',NULL);
INSERT INTO badges VALUES(533,'Pirates','pirate-badge','Discover Knowledge','Suzanne Vicoryosmanson','pirate-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/pirate-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pirates were sailors who attacked ships at sea to steal treasure and goods, operating from hidden ports across the globe. Explore the real stories of famous pirates like Blackbeard and Ching Shih, discover the places where pirate crews hid out, and uncover what life was actually like on the ocean hundreds of years ago.',NULL);
INSERT INTO badges VALUES(534,'Pizza','pizza-badge','Discover the Home','Kerry Cordy','pizza-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/pizza-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pizza starts with simple dough, sauce, and cheese—then gets creative with toppings, techniques, and flavors from around the world. Make your own pie from scratch and discover why this dish is loved everywhere.',NULL);
INSERT INTO badges VALUES(535,'Planets','planets-badge','Discover Science & Technology','Charlotte Duke','planets-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/planets-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Eight planets orbit our sun, each one totally different—some are rocky and small, others are giant balls of gas, and a few icy dwarfs hang out at the edge. Explore what makes each planet unique, how moons and asteroids fit into the mix, and the wild discoveries humans have made by looking up at the night sky.',NULL);
INSERT INTO badges VALUES(536,'Playwright','playwright-badge','Discover Art','Charlotte Duke','playwright-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/playwright-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A playwright writes stories that come alive on stage with actors, dialogue, and drama. You''ll craft scenes and scripts where characters speak, move, and tell a tale that an audience can actually watch and enjoy.',NULL);
INSERT INTO badges VALUES(537,'Plants (specific)','plant-specific-badge','Discover the Outdoors','Charlotte Henderson',NULL,1,NULL,'https://curiosityuntamed.com/badges/plant-specific-badge/','{"level5":7}',1,'2026-05-20 16:10:36','Plants are everywhere—in gardens, forests, parks, and even cracks in sidewalks. They grow from seeds, drink water through roots, and turn sunlight into food, all while giving us oxygen to breathe.','🌱');
INSERT INTO badges VALUES(538,'Plant Based Foods','plant-based-food-badge','Discover Agriculture','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/plant-based-food-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Plants give us fruits, vegetables, grains, nuts, and beans that can make complete, delicious meals without any meat or dairy. Explore what''s growing at farmers markets and grocery stores to discover how many tasty plant-based foods fuel healthy bodies and help the planet.','🥕');
INSERT INTO badges VALUES(539,'Plush Toys','plush-toys','Discover Knowledge','','plush-toys.jpg',0,NULL,'https://curiosityuntamed.com/badges/plush-toys/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Stuffed animals are more than just cuddly friends—they''re handmade creations with personality, stitching, and stories. From choosing fabrics to stuffing and sewing, discover what goes into making these soft companions that people love to keep forever.',NULL);
INSERT INTO badges VALUES(540,'Pocket Knife','pocket-knife-badge','Discover the Outdoors','Kerry Cordy','pocket-knife-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/pocket-knife-badge/','{"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A good pocket knife is a trusted tool for camping, whittling, and fixing things outdoors. Learn what each blade and tool does, how to handle them safely, and keep your knife sharp and ready for adventure.',NULL);
INSERT INTO badges VALUES(541,'Pocket Knife Safety','pocket-knife-safety-badge','Discover Health & Safety','Kerry Cordy','pocket-knife-safety-badge.jpg',0,'It is required that this badge be earned before a pocket knife can be brought to campouts or other group activities where knives might be appropriate.  This badge must be earned before the Pocket Knife badge can be earned. Due to the advanced nature of this badge, it is not available to Preschool.','https://curiosityuntamed.com/badges/pocket-knife-safety-badge/','{"level1":0,"level2":0,"level3":0,"level4":0,"level5":0}',1,'2026-05-20 16:10:36','A pocket knife is a handy tool when you know how to use it right. Master opening and closing safely, creating a proper safety circle around yourself, passing it hand-to-hand without accidents, and keeping your blade sharp and clean.',NULL);
INSERT INTO badges VALUES(542,'Poetry','poetry-badge','Discover Knowledge','Doreen Olson','poetry-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/poetry-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Poems use clever language and rhythm to share feelings, stories, and ideas in ways that stick with you. Whether they rhyme, tell a tale, or paint a picture with words, you''ll read different kinds and write your own.',NULL);
INSERT INTO badges VALUES(543,'Poetry Memorization','poetry-memorization-badge','Discover Art','',NULL,0,NULL,'https://curiosityuntamed.com/badges/poetry-memorization-badge/','{"preschool":1,"level1":2,"level2":3,"level3":3,"level4":4,"level5":7}',1,'2026-05-20 16:10:36','Words have rhythm, rhyme, and power—and memorizing poems lets you carry them in your mind forever. You''ll discover why certain lines stick with you and how poets choose each word with care.','📖');
INSERT INTO badges VALUES(544,'Poisonous Plants','poisonous-plants-badge','Discover the Outdoors','Savannah Crowell','poisonous-plants-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/poisonous-plants-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Some plants have nasty surprises—toxins in their leaves, berries, or sap that can make you sick or cause painful rashes. Learning to spot them keeps you safe on hikes and in your own backyard, and it''s pretty fascinating to know which ones to avoid and why.',NULL);
INSERT INTO badges VALUES(545,'Pokemon','learn-about-pokemon-badge','Discover Knowledge','Amanda Piccirillo','learn-about-pokemon-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/learn-about-pokemon-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pokemon are creatures with special powers that trainers catch, train, and battle each other. Dive into this huge world to discover how the games started, meet dozens of different Pokemon by sight, and explore the tools trainers use to catch them.',NULL);
INSERT INTO badges VALUES(546,'Pollinators','pollinators-badge','Discover Agriculture','Christina Hunt',NULL,0,NULL,'https://curiosityuntamed.com/badges/pollinators-badge/','{"preschool":1,"level1":2,"level2":3,"level3":3,"level4":4,"level5":5}',0,'2026-05-20 16:10:36','Bees, butterflies, and hummingbirds are nature''s delivery service, moving pollen from flower to flower so plants can make seeds and fruit. Without them, we''d lose most of the colorful flowers and tasty foods we love.','🐝');
INSERT INTO badges VALUES(547,'Polymer Clay','polymer-clay-badge','Discover Art','Elizabeth Simmons','polymer-clay-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/polymer-clay-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Polymer clay is a colorful, moldable material that hardens when you bake it in your oven, letting you sculpt tiny figurines, jewelry, and decorations that actually last. Master the techniques to condition and shape it safely, then finish your creations with varnish to make them shine and protect them from damage.',NULL);
INSERT INTO badges VALUES(548,'Popcorn','popcorn-badge','Discover Agriculture','Sophia and Kamilla Sepulveda, Troop #112','popcorn-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/popcorn-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Popcorn starts as a special type of corn kernel with moisture trapped inside—when heated, that moisture turns to steam and explodes the kernel into a fluffy white puff. Discover how corn grows from seed to harvest, explore different popping methods from stovetop to microwave, and taste your way through homemade and store-bought varieties.',NULL);
INSERT INTO badges VALUES(549,'Postcards','postcard-badge','Discover the World','Kerry Cordy','postcard-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/postcard-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Postcards are little windows into far-off places—smaller than letters, packed with pictures and messages, and cheaper to mail. Collect them, design your own, and send greetings the old-fashioned way to people you care about.',NULL);
INSERT INTO badges VALUES(550,'Prayer','prayer-badge','Discover Character','Doreen Olson','prayer-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/prayer-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Prayer is talking to God about what matters most to you—saying thanks, asking for help, and sharing your hopes. People around the world find it gives them peace, strength, and a chance to think deeply about what''s really important.',NULL);
INSERT INTO badges VALUES(551,'Princess','princess-badge','Discover Knowledge','','princess-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/princess-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Princesses are royalty with their own stories, powers, and adventures—some you know from movies, others from fairy tales and history. Discover how different versions of the same princess can be totally different, and meet real and fictional princesses from around the world.',NULL);
INSERT INTO badges VALUES(552,'Psychology','psychology-badge','Discover Health & Safety','','psychology-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/psychology-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Psychology is the science of how minds work and why people feel and act the way they do. Explore emotions, stress, and what makes people tick—then discover real ways to help yourself and others feel better.',NULL);
INSERT INTO badges VALUES(553,'Public Speaking','public-speaking-badge','Discover Art','','public-speaking-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/public-speaking-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Standing in front of people and sharing your ideas or favorite topic takes courage and practice. Whether you''re talking about something you love or explaining how something works, you''ll discover tricks for staying calm and letting your voice be heard.',NULL);
INSERT INTO badges VALUES(554,'Public Transportation','public-transportation-badge','Discover the World','Sylvia Duke',NULL,0,NULL,'https://curiosityuntamed.com/badges/public-transportation-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Buses, trains, subways, and ferries get people where they need to go—and you can hop aboard to explore your community. Learn the rules for safe traveling, discover what types of transport run near you, and find out what quiet activities make the journey fun.','🚌');
INSERT INTO badges VALUES(555,'Pumpkin Patches','pumpkin-patch-badge','Discover Agriculture','',NULL,0,NULL,'https://curiosityuntamed.com/badges/pumpkin-patch-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pumpkin patches are harvest destinations where families pick orange gourds straight from the field, meet farm animals, and enjoy seasonal activities. Explore how pumpkins grow from tiny seeds to giant jack-o-lantern-ready fruits, and discover what makes each patch unique.','🎃');
INSERT INTO badges VALUES(556,'Pumpkins','pumpkin-badge','Discover Agriculture','Shelley Frausto','pumpkin-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/pumpkin-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pumpkins grow on vines and transform from tiny flowers into giant orange gourds perfect for carving, cooking, and pie. Discover the different varieties, how they grow from seed to harvest, and all the delicious ways to eat them.',NULL);
INSERT INTO badges VALUES(557,'Pumpkin Spice','pumpkin-spice-badge','Discover the Home','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/pumpkin-spice-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pumpkin spice is a cozy blend of cinnamon, nutmeg, cloves, and ginger that shows up in everything from lattes to pie. Mix your own batch, taste it in treats and drinks, and see if you can pick out each warming spice when you smell and taste them together.','🎃');
INSERT INTO badges VALUES(558,'Puppetry','puppetry-badge','Discover Art','Elizabeth Simmons','puppetry-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/puppetry-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Puppets are characters that come alive in your hands—whether they''re made from socks, sticks, shadows, or strings. Bring stories to the stage and make audiences laugh, gasp, and cheer.',NULL);
INSERT INTO badges VALUES(559,'Purse','purse-badge','Discover the Home','Shelley Frausto','purse-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/purse-badge/','{"preschool":1,"level1":2,"level2":3,"level3":1,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A purse holds all the stuff you need to carry with you—money, keys, your phone, snacks. Throughout history, people have used pouches and bags to keep their treasures safe, and today you can find purses in endless colors, materials, and styles that say something about who you are.',NULL);
INSERT INTO badges VALUES(560,'Pyramids','pyramids-badge','Discover the World','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/pyramids-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pyramids are massive structures with triangular sides that meet at a point, built by ancient civilizations and modern architects alike. Explore famous pyramids across the globe, discover the three ancient styles, and build your own miniature version using whatever materials you have on hand.','🔺');
INSERT INTO badges VALUES(561,'Pyrography','pyrography-badge','Discover Art','Sylvia Duke',NULL,0,NULL,'https://curiosityuntamed.com/badges/pyrography-badge/','{"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Fire and wood meet art when you use a heated tool to burn detailed designs right into wooden surfaces. It''s a craft that turns sketches into permanent, beautiful marks that look like they were carved by hand.','🔥');
INSERT INTO badges VALUES(562,'Quilting','quilting-badge','Discover the Home','Adele Nolan','quilting-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/quilting-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Quilts are blankets made from colorful fabric pieces sewn together in patterns, then layered and stitched to create something cozy and beautiful. Learn the tools and techniques that turn scraps into heirlooms, and make your own quilted project to keep or gift.',NULL);
INSERT INTO badges VALUES(563,'Quotes and Speeches','quotes-and-speeches-badge','Discover Knowledge','',NULL,0,NULL,'https://curiosityuntamed.com/badges/quotes-and-speeches-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Famous quotes and speeches are powerful words that stick with people for years—sometimes even centuries. Explore what makes certain words memorable, act out their meanings, and discover why we still repeat what great leaders and thinkers said long ago.','🎤');
INSERT INTO badges VALUES(564,'Rabbits','rabbit-badge','Discover Agriculture','Kerry Cordy','rabbit-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/rabbit-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Rabbits are fluffy hoppers with long ears and powerful back legs that need gentle handling and good care. Learn what they eat, where they live, how to spot health problems, and what makes their bodies so perfectly built for bouncing.',NULL);
INSERT INTO badges VALUES(565,'Railroads','railroad-badge','Discover Science & Technology','Suzanne Vicoryosmanson','railroad-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/railroad-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Trains carry people and cargo across entire continents, moving thousands of tons at incredible speeds on steel tracks. Explore how railroads shaped America, the difference between speeding passenger cars and heavy freight haulers, and the safety rules that keep everyone protected at crossings and stations.',NULL);
INSERT INTO badges VALUES(566,'Rainbow Loom','learn-about-rainbow-loom','Discover Art','Sarah Lundquist','learn-about-rainbow-loom.jpg',0,NULL,'https://curiosityuntamed.com/badges/learn-about-rainbow-loom/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',0,'2026-05-20 16:10:36','Tiny rubber bands snap onto a plastic loom to create colorful bracelets, rings, and charms in endless patterns. Your fingers become the tools as you weave, loop, and pull to make wearable art you can gift to friends.',NULL);
INSERT INTO badges VALUES(567,'Rain Gutter Regatta','rain-gutter-regatta-badge','Discover Science & Technology','Jennifer Foraker','rain-gutter-regatta-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/rain-gutter-regatta-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Tiny model boats race down flowing water in rain gutters, competing to see whose design crosses the finish line fastest. Build a boat, learn the rules, and watch (or join) the splash-filled competition.',NULL);
INSERT INTO badges VALUES(568,'Reading','reading-badge','Discover Knowledge','Kerry Cordy','reading-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/reading-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Stories open up new worlds, funny characters, and amazing facts whether you''re reading them yourself or listening to someone read aloud. You''ll discover what happens in books, understand why characters do what they do, and explore all kinds of stories—from silly poems to real-life adventures.',NULL);
INSERT INTO badges VALUES(569,'Recycling','recycling-badge','Discover Knowledge','Kerry Cordy','recycling-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/recycling-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your trash doesn''t just disappear—it goes somewhere, and you can help decide where. Recycling turns old stuff into new stuff, saves space in landfills, and keeps our planet healthier, one sorted item at a time.',NULL);
INSERT INTO badges VALUES(570,'Relationship Skills','relationship-skills-badge','Discover Health & Safety','Adele Nolan',NULL,0,NULL,'https://curiosityuntamed.com/badges/relationship-skills-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Good relationships start with listening, sharing your feelings, and treating others with respect. These skills help you make real friends, work well with teammates, and handle disagreements in ways that actually work.','🤝');
INSERT INTO badges VALUES(571,'Remote Control (RC) Vehicle (Specific)','remote-control-rc-vehicle-badge-specific','Discover Science & Technology','Kerry Cordy','remote-control-rc-vehicle-badge-specific.jpg',1,'This badge can be earned multiple times, once for each type of RC vehicle you learn about such as RC Boats, RC Cars, RC Airplanes or RC Drones Disclaimer: Remote control vehicles can be dangerous and should be supervised by an experienced adult. Please learn and follow all safety rules.','https://curiosityuntamed.com/badges/remote-control-rc-vehicle-badge-specific/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Remote control vehicles let you command a car, boat, or plane from a distance using radio signals and a handheld controller. Discover how these machines work, where you can safely operate them, and whether you''re racing competitively or just having fun in your backyard.',NULL);
INSERT INTO badges VALUES(572,'Renewable Energy','renewable-energy-badge','Discover Science & Technology','Suzanne Vicoryosmanson','renewable-energy-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/renewable-energy-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Energy from the sun, wind, water, and earth keeps powering up our world without running out. Explore how these natural forces get turned into electricity and heat for homes, cars, and cities everywhere.',NULL);
INSERT INTO badges VALUES(573,'Reptiles','animal-kingdom-reptiles','Discover the Outdoors','Kerry Cordy','animal-kingdom-reptiles.jpg',0,'A separate badge  can be earned for each of the following categories: Mammals, reptiles, amphibians, marine biology, insects, and birds.','https://curiosityuntamed.com/badges/animal-kingdom-reptiles/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Reptiles are cold-blooded creatures with scales and backbones, from tiny lizards to massive pythons. Hunt for species in your area, learn what makes them tick, and discover how they survive in their own wild ways.',NULL);
INSERT INTO badges VALUES(574,'Resourcefulness','resourcefulness-badge','Discover Character','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/resourcefulness-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Finding creative solutions when things don''t go as planned is what resourcefulness is all about. It''s about thinking on your feet, making do with what you have, and discovering that problems often have more than one answer.','💡');
INSERT INTO badges VALUES(575,'Respect','respect-badge','Discover Character','Charlotte Duke','respect-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/respect-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Respect means treating people, animals, and the world around you with kindness and consideration. It''s the foundation of getting along with others and making a difference wherever you go.',NULL);
INSERT INTO badges VALUES(576,'Responsibility','responsibility-badge','Discover Character','Kerry Cordy','responsibility-badge.png',0,NULL,'https://curiosityuntamed.com/badges/responsibility-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Responsibility is doing what you''re supposed to do—without being reminded, without complaining, and doing it right. It shows up in chores, homework, and promises you make, and it''s something everyone can get better at with practice and honesty about where they struggle.',NULL);
INSERT INTO badges VALUES(577,'Restaurants (general)','restaurants-general-badge','Discover Knowledge','Sarah Hershberger','restaurants-general-badge.jpg',0,'This badge focuses on restaurants in a general sense, such as how restaurants work. To learn about a specific restaurant, please go to the Restaurant (Specific) badge.','https://curiosityuntamed.com/badges/restaurants-general-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Restaurants are places where chefs cook food and servers bring it to your table, but behind the scenes there''s so much more—from managing menus to designing the perfect atmosphere. Explore what makes restaurants tick, from cozy family spots to fancy chains, and dream up your own restaurant idea from the menu all the way down to the decor.',NULL);
INSERT INTO badges VALUES(578,'Restaurant (specific)','restaurant-specific-badge','Discover Knowledge','Sarah Hershberger','restaurant-specific-badge.jpg',1,'This badge can be earned multiple times for each different restaurant studied. For a general restaurant badge, please go to the Restaurants (General) badge.','https://curiosityuntamed.com/badges/restaurant-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every restaurant has a story—from how it got its name to the kitchen magic that makes your favorite dish. Explore a real restaurant you love, discover what makes it special, and learn what goes on behind the scenes to get food from their kitchen to your table.',NULL);
INSERT INTO badges VALUES(579,'Rice','rice-badge','Discover Agriculture','Cyndie Lyons',NULL,0,NULL,'https://curiosityuntamed.com/badges/rice-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Rice feeds billions of people around the world and comes in dozens of varieties, from fluffy jasmine to creamy Arborio to nutty wild rice. Cook up savory and sweet dishes while discovering why different recipes call for different kinds of rice, and explore where the world''s rice comes from.','🍚');
INSERT INTO badges VALUES(580,'Road Trip','road-trip-badge','Discover the Outdoors','Doreen Olson','road-trip-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/road-trip-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Planning a road trip means figuring out where you''re going, how long it takes to get there, and what to pack—plus mastering car games and mess-free meals for the drive. You''ll navigate both with GPS and paper maps to discover which way works best for you.',NULL);
INSERT INTO badges VALUES(581,'Robotics','robotics-badge','Discover Science & Technology','Stephanie Love Reed','robotics-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/robotics-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Robots are machines that do work for us—from factory arms building cars to vacuums cleaning floors to rovers exploring Mars. Discover what makes them move, how people invented them, and why robots are becoming part of everyday life.',NULL);
INSERT INTO badges VALUES(582,'Rock Climbing','rock-climbing-badge','Discover the Outdoors','Abby Olson','rock-climbing-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/rock-climbing-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Rock climbing challenges your strength, balance, and problem-solving as you scale walls and boulders with proper safety gear and a trusted partner. You''ll learn how climbers, belayers, and spotters work together as a team, communicate with hand signals, and handle emergencies to stay safe while pursuing this thrilling sport.',NULL);
INSERT INTO badges VALUES(583,'Rockets','rockets','Discover Science & Technology','Jeff Lubin','rockets.jpg',0,NULL,'https://curiosityuntamed.com/badges/rockets/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Rockets blast objects into space by burning fuel so fast it pushes them upward. From ancient fireworks to modern spacecraft, these powerful machines have changed how we explore the world above us.',NULL);
INSERT INTO badges VALUES(584,'Rocks and Minerals','rocks-and-minerals','Discover the Outdoors','Kerry Cordy','rocks-and-minerals.jpg',0,NULL,'https://curiosityuntamed.com/badges/rocks-and-minerals/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Rocks are way older than anything else you''ll find outside—some are billions of years old. Hunt for your own specimens, sort them by color and shape, and discover how different rocks form from fire, layers of sediment, or intense heat and pressure deep underground.',NULL);
INSERT INTO badges VALUES(585,'Rodeo','rodeo-badge','Discover the Outdoors','Charlotte Duke','rodeo-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/rodeo-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Cowboys and cowgirls compete in wild rodeo events like bronc riding, roping, and barrel racing on horses and bulls. Dive into rodeo history, the gear riders use, and what makes each event its own kind of challenge.',NULL);
INSERT INTO badges VALUES(586,'Roller Coasters','roller-coaster-badge','Discover Science & Technology','Kerry Cordy','roller-coaster-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/roller-coaster-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Roller coasters loop, twist, and drop to thrill riders using science like gravity, speed, and momentum. Explore famous coasters around the world, discover how they''ve changed over time, and understand what makes each one its own wild ride.',NULL);
INSERT INTO badges VALUES(587,'Route 66','route-66-2-2','Discover the World','Suzanne Vicoryosmanson','route-66-2-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/route-66-2-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Route 66 is the legendary highway that connected Chicago to Los Angeles and became the symbol of American road trips and adventure. Follow this historic route across eight states, discover the towns and landmarks along the way, and explore why this "Mother Road" still captures people''s imaginations today.',NULL);
INSERT INTO badges VALUES(588,'Rubik’s Cube','learn-about-rubiks-cube','Discover Knowledge','Sarah Carpenter','learn-about-rubiks-cube.jpg',0,'This is an advanced badge due to the challenging puzzle nature of the Rubik’s Cube. It is not recommended for Preschool-Level 1.','https://curiosityuntamed.com/badges/learn-about-rubiks-cube/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A scrambled cube with a million possible combinations—and you''ve got the skills to solve it. This twist-and-turn puzzle teaches patience, pattern recognition, and the satisfaction of getting all six sides to match.',NULL);
INSERT INTO badges VALUES(589,'Sailing','sailing-badge','Discover the Outdoors','Lily Jorrick','sailing-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/sailing-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Harness the wind and water to glide across the ocean or lake in a sailboat. You''ll learn how sails catch the breeze, balance a boat, and navigate using the sun and stars.',NULL);
INSERT INTO badges VALUES(590,'Saints (specific)','saints-badge','Discover Character','Amanda Piccirillo',NULL,1,'This badge can be earned multiple times, once for each saint studied.','https://curiosityuntamed.com/badges/saints-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Saints are real people from history who lived extraordinary lives of faith and kindness, and were officially recognized by the church for miracles or amazing works. Pick one saint to get to know—learn their full story, from childhood to their greatest accomplishments, and discover what made them special enough to be remembered centuries later.','✨');
INSERT INTO badges VALUES(591,'Save the Bees','save-the-bees-badge','Discover Agriculture','Finian Stroup',NULL,0,NULL,'https://curiosityuntamed.com/badges/save-the-bees-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Bees are nature''s hardest workers, pollinating crops and flowers while making honey. Help protect these vital insects by learning what they need to thrive and how you can create a bee-friendly world.','🐝');
INSERT INTO badges VALUES(592,'Salads','salads-badge','Discover the Home','Doreen Olson','salads-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/salads-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A great salad is way more than just leaves in a bowl—it''s about mixing colors, textures, and flavors to make something you actually want to eat. From simple green salads to fruit combinations and cooked vegetable mixes, you''ll discover how the right knife skills and a little creativity turn fresh ingredients into something delicious.',NULL);
INSERT INTO badges VALUES(593,'Salem Witch Trials','salem-witch-trials-badge','Discover Knowledge','Jen Milakovic','salem-witch-trials-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/salem-witch-trials-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','In 1692 Salem, Massachusetts, fear and accusations spiraled into tragedy when dozens of people were arrested and executed for witchcraft based on flimsy evidence and hysteria. This dark chapter shows how quickly communities can turn against their own when panic takes over.',NULL);
INSERT INTO badges VALUES(594,'Sandwiches','sandwiches-badge','Discover the Home','Doreen Olson','sandwiches-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/sandwiches-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Sandwiches are the ultimate handheld meal—layers of bread, fillings, and toppings that can be anything from classic peanut butter and jelly to creative combinations with meats, cheeses, and veggies. Master the basics of assembly, cleanup, and making sandwiches that taste exactly how people want them.',NULL);
INSERT INTO badges VALUES(595,'cavenger Hunt','scavenger-hunt-badge','Discover Knowledge','Jacinta Gary',NULL,0,NULL,'https://curiosityuntamed.com/badges/scavenger-hunt-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Scavenger hunts send you searching for clues and hidden items, mixing puzzle-solving with adventure. You''ll explore why people love them, where they came from, and get to design your own hunt to challenge others.','🔍');
INSERT INTO badges VALUES(596,'School Pride','school-pride-badge','Discover Character','Suzanne Vicoryosmanson','school-pride-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/school-pride-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your school is full of people, traditions, and moments worth celebrating. School pride means showing up for your community, supporting your classmates, and helping make your school a place everyone''s excited to be part of.',NULL);
INSERT INTO badges VALUES(597,'Learn About Scooby Doo','learn-about-scooby-doo','Discover Knowledge','Chealsey Walberg',NULL,0,NULL,'https://curiosityuntamed.com/badges/learn-about-scooby-doo/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":6}',1,'2026-05-20 16:10:36','Scooby Doo is a lovable Great Dane who solves mysteries alongside his best friend Shaggy and the rest of Mystery Inc. Follow along as the gang uncovers spooky secrets, unmasks villains, and proves that there''s always a logical explanation behind the scariest situations.','🐕');
INSERT INTO badges VALUES(598,'Scrabble','scrabble-badge','Discover Knowledge','Charlotte Duke','scrabble-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/scrabble-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Scrabble is a word game where players build interlocking words on a grid to rack up points. Every letter has a different value, so finding the perfect spot for that high-scoring Z could win you the game.',NULL);
INSERT INTO badges VALUES(599,'Scrapbooking','scrapbooking-badge','Discover Art','Kerry Cordy','scrapbooking-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/scrapbooking-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Scrapbooks turn your favorite photos and memories into beautiful keepsakes by combining pictures with decorative papers, stickers, and handwritten stories. Learn how to arrange, crop, and embellish your pages so friends and family can treasure them for years to come.',NULL);
INSERT INTO badges VALUES(600,'Sculpture','15116-2','Discover Art','Elizabeth Simmons','15116-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/15116-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Sculpture is art you can walk around and see from every side—carved from wood, shaped from clay, twisted from wire, or made from whatever materials an artist dreams up. You''ll try different sculpting styles and materials to discover what it feels like to turn something flat into something solid and real.',NULL);
INSERT INTO badges VALUES(601,'Seashells','seashells-badge','Discover the Outdoors','Kerry Cordy','seashells-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/seashells-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Seashells are the colorful homes left behind by ocean creatures like clams, snails, and sea urchins. Discover what these shells are made of, why they grow in spirals or hinges, and how to find and care for them without harming the beach ecosystem.',NULL);
INSERT INTO badges VALUES(602,'Sea World','sea-world-badge','Discover the Outdoors','Tina Swenson','sea-world-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/sea-world-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',0,'2026-05-20 16:10:36','The ocean is home to incredible creatures—from tiny seahorses and colorful fish to massive whales and playful dolphins. Explore the salty waters and meet the animals that make the sea their home.',NULL);
INSERT INTO badges VALUES(603,'Seasons (Specific)','season-specific-badge','Discover Science & Technology','Marie Dichoso-Beavers','season-specific-badge.jpg',1,'This badge can be earned once for each season, fall, winter, spring and summer. Need ideas?  Check out our Summer Unit Study','https://curiosityuntamed.com/badges/season-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pick your favorite season and become an expert on it. Track the weather, discover what the tilt of Earth has to do with hot summers and cold winters, and learn why your season looks, feels, and dresses the way it does.',NULL);
INSERT INTO badges VALUES(604,'Seeds','seeds-badge','Discover Agriculture','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/seeds-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every seed holds a tiny plant waiting to burst into life—all it needs is water, warmth, and time. Plant your own and run experiments to discover what makes seeds sprout, then peek inside to see the secret blueprint hidden in each one.','🌱');
INSERT INTO badges VALUES(605,'Self Control','self-control-badge','Discover Character','Kerry Cordy','self-control-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/self-control-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Self-control is the power to pause before you act, manage your feelings when things get frustrating, and stick with hard tasks even when you want to quit. It''s a superpower that makes everything else easier.',NULL);
INSERT INTO badges VALUES(606,'Self Defense & Personal Safety','self-defense-personal-safety-badge','Discover Health & Safety','Sarah Bruekherr','self-defense-personal-safety-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/self-defense-personal-safety-badge/','{"preschool":1,"level1":1,"level2":1,"level3":1,"level4":1,"level5":1}',1,'2026-05-20 16:10:36','Knowing your name, address, and who to trust keeps you safe when you need help most. You''ll learn how to spot safe adults, use 911 wisely, and get back to your family if things go wrong.',NULL);
INSERT INTO badges VALUES(607,'Senior Citizens','senior-citizens-badge','Discover Character','Kerry Cordy','senior-citizens-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/senior-citizens-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Older people have amazing stories, skills, and wisdom earned through decades of living. Building friendships across generations helps you see the world through different eyes and discover what makes life meaningful.',NULL);
INSERT INTO badges VALUES(608,'Seven Teachings','the-seven-teachings','Discover Character','Julie Ringrose','the-seven-teachings.jpg',0,NULL,'https://curiosityuntamed.com/badges/the-seven-teachings/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Seven Teachings are cherished wisdom from Indigenous cultures that guide how to live well with others and the earth. These timeless lessons about respect, honesty, humility, and courage help shape who you become.',NULL);
INSERT INTO badges VALUES(609,'Sewing','sewing','Discover the Home','Kerry Cordy','sewing.jpg',0,NULL,'https://curiosityuntamed.com/badges/sewing/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Threading a needle and stitching fabric together opens up a whole world of making—from stuffed animals and pillows to mending your favorite clothes. Whether you sew by hand with needle and thread or use a machine, you''ll discover how a few simple tools and materials can transform scraps into something useful and fun.',NULL);
INSERT INTO badges VALUES(610,'Shadow Art','shadow-art-badge','Discover Art','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/shadow-art-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Light and shadows are natural artists—position objects between a light source and a surface to reveal hidden shapes and silhouettes. Create puppet shows, experiment with transparent materials, and discover how the same item casts completely different shadows depending on its angle and the light''s direction.','🌑');
INSERT INTO badges VALUES(611,'Shark Tank','learn-about-shark-tank-badge','Discover Knowledge','Kerry Cordy','learn-about-shark-tank-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/learn-about-shark-tank-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Shark Tank is a real TV show where entrepreneurs pitch their business ideas to a panel of wealthy investors hoping to get funding and advice. Dive into episodes, figure out what makes a good product pitch, and imagine what brilliant idea you''d bring to the tank yourself.',NULL);
INSERT INTO badges VALUES(612,'Shells for Stacey','shells-for-stacey','Discover Character','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/shells-for-stacey/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Shells for Stacey is a kindness project where you paint rocks and hide them for strangers to find and keep—spreading joy while learning to respect nature. You''ll discover why this matters, explore how to hide shells responsibly, and understand the causes the project supports.','🪨');
INSERT INTO badges VALUES(613,'Shelter in Place','shelter-in-place-self-isolation-badge','Discover Health & Safety','Kerry Cordy','shelter-in-place-self-isolation-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/shelter-in-place-self-isolation-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','When an emergency happens, sometimes the safest place to be is right where you are. Find out how to seal rooms, stay calm, and know what supplies to keep nearby when you need to shelter in place.',NULL);
INSERT INTO badges VALUES(614,'Shirley Temple','shirley-temple-badge','Discover Knowledge','Suzanne Vicoryosmanson','shirley-temple-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/shirley-temple-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Shirley Temple was a superstar child actor in the 1930s who sang, danced, and charmed audiences in Hollywood movies. She lived an incredible life beyond films too—from diplomat to author to TV host—showing that one talented person can do many amazing things.',NULL);
INSERT INTO badges VALUES(615,'Shoes','shoes-badge','Discover the Home','Kerry Cordy','shoes-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/shoes-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Shoes protect your feet and take you everywhere—from muddy puddles to fancy parties to hiking trails. Explore how shoes are made, discover why different shoes exist for different jobs and weather, and uncover how footwear has changed throughout history.',NULL);
INSERT INTO badges VALUES(616,'Short Flags','short-flags-badge','Discover Health & Safety','Doreen Olson','short-flags-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/short-flags-badge/','{"preschool":1,"level1":0,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Short flags are colorful props that spin, swirl, and dance in your hands when you learn the right moves. Master the spins and tricks while staying safe, and discover how flag groups around the world put on amazing performances together.',NULL);
INSERT INTO badges VALUES(617,'Sign Language','sign-language-badge','Discover Knowledge','Diana Havir','sign-language-badge.png',0,NULL,'https://curiosityuntamed.com/badges/sign-language-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Sign language is a complete visual language where hands, fingers, and expressions do all the talking—perfect for Deaf and hard of hearing people, and anyone who wants to communicate in a new way. Start with the alphabet and numbers, then build your signing vocabulary across foods, animals, feelings, and everyday life.',NULL);
INSERT INTO badges VALUES(618,'Simple Machines','simple-machines-badge','Discover Science & Technology','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/simple-machines-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Hidden in everyday tools and gadgets are six simple machines that make hard work easier—levers, pulleys, wheels, screws, wedges, and inclined planes. Spot them around your home and community, then figure out the clever tricks each one uses to lift, cut, or move things with less effort.','⚙️');
INSERT INTO badges VALUES(619,'Singing','singing-badge','Discover Art','Kerry Cordy','singing-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/singing-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your voice is an instrument that can be trained and strengthened just like any other. Explore different musical styles, discover how your body helps you sing better, and learn that everyone can develop their voice through practice and fun.',NULL);
INSERT INTO badges VALUES(620,'Sleep','sleep-badge','Discover Health & Safety','Micaela Katanic','sleep-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/sleep-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your body needs sleep to grow, learn, and feel good—but what happens when you don''t get enough? Explore why rest matters, create a bedtime routine that actually works for you, and discover what helps (and hurts) your sleep.',NULL);
INSERT INTO badges VALUES(621,'Slime','slime-badge','Discover Science & Technology','','slime-badge.jpg',0,'Slime recipes vary and some may be toxic. Only make homemade slime under the supervision of an adult and make sure to research safe recipes and chemical combinations.','https://curiosityuntamed.com/badges/slime-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Slime is gooey, stretchy, and weirdly satisfying to squish and pull apart. Mix up a batch with simple ingredients, experiment with different recipes and colors, and discover why this goopy stuff behaves like both a liquid and a solid.',NULL);
INSERT INTO badges VALUES(622,'Sling Shot','sling-shot-badge','Discover the Outdoors','Allison Thomas','sling-shot-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/sling-shot-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A slingshot is a simple but powerful tool that takes aim, steady hands, and respect for safety rules. Master the stance, technique, and care needed to hit your targets accurately on an approved range.',NULL);
INSERT INTO badges VALUES(623,'Slumber Party','slumber-party','Discover the Home','Doreen Olson','slumber-party.jpg',0,NULL,'https://curiosityuntamed.com/badges/slumber-party/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A slumber party is all about having fun with people you like while staying cozy and comfortable. You''ll discover what makes the perfect pajama party setup, plan activities to keep everyone entertained, and learn sleep facts that might surprise you.',NULL);
INSERT INTO badges VALUES(624,'S’Mores','smores-badge','Discover the Outdoors','','smores-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/smores-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Melted chocolate, toasted marshmallows, and graham crackers come together for the perfect campfire treat. The best part is making them yourself over a crackling fire, watching the marshmallow turn golden and gooey.',NULL);
INSERT INTO badges VALUES(625,'Snow','snow-badge','Discover the Outdoors','Doreen Olson','snow-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/snow-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Snow starts as water vapor in the sky that freezes into crystals, each one shaped differently as it falls. Explore why snow only forms in cold places, peek at real snowflakes up close, and discover how water transforms between solid, liquid, and gas.',NULL);
INSERT INTO badges VALUES(626,'Soap Making','soap-making-badge','Discover the Home','Kerry Cordy','soap-making-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/soap-making-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Soap starts as a mix of oils and lye that transforms into something you can use to wash your hands. Mix, pour, mold, color, and scent your way to homemade bars that make great gifts.',NULL);
INSERT INTO badges VALUES(627,'Solar Eclipse','solar-eclipse-badge','Discover Science & Technology','Sylvia Duke',NULL,0,NULL,'https://curiosityuntamed.com/badges/solar-eclipse-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','When the Moon slides in front of the Sun, day turns to twilight in the middle of the afternoon—it''s one of nature''s most dramatic shows. You''ll discover how this cosmic alignment happens, build a safe viewer to watch it, and learn why you can never peek directly at the Sun without serious damage to your eyes.','🌑');
INSERT INTO badges VALUES(628,'Song Writing','song-writing-badge','Discover Art','Kimberly Bogers','song-writing-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/song-writing-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Songs stick in your head because someone wrote words and melodies that mean something. You''ll explore what makes songs work, then write and perform your own to share with people you care about.',NULL);
INSERT INTO badges VALUES(629,'Soups','soups-badge','Discover the Home','Doreen Olson','soups-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/soups-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Soup is comfort food that starts with a simple base and transforms into endless possibilities—from creamy tomato to spicy chicken broth to chunky vegetable stew. Making soup from scratch teaches you how flavors blend together while feeding people you care about.',NULL);
INSERT INTO badges VALUES(630,'Space Derby','space-derby-badge','Discover Science & Technology','Emma McKenney','space-derby-badge.png',0,NULL,'https://curiosityuntamed.com/badges/space-derby-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Model rockets zoom across the sky in thrilling races where builders compete to see whose design flies fastest and straightest. Watch real Space Derbies in action, learn the parts that make rockets soar, and discover what it takes to be a good competitor.',NULL);
INSERT INTO badges VALUES(631,'Space Exploration','space-exploration-badge','Discover Science & Technology','Ramon Gomez',NULL,0,NULL,'https://curiosityuntamed.com/badges/space-exploration-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Rockets blast off toward the moon and stars, carrying astronauts and scientists on incredible adventures beyond Earth. Explore the amazing machines that make space travel possible and the brave explorers who''ve changed what we know about the universe.','🚀');
INSERT INTO badges VALUES(632,'Special Needs (specific)','special-needs-badge','Discover Knowledge','Katie Cordy','special-needs-badge.png',1,NULL,'https://curiosityuntamed.com/badges/special-needs-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Understanding how people''s brains and bodies work differently helps us be kinder classmates and friends. Everyone has unique strengths—discovering what makes each person special makes the world more inclusive and awesome.',NULL);
INSERT INTO badges VALUES(633,'Spelling','spelling-badge','Discover Knowledge','Doreen Olson','spelling-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/spelling-badge/','{"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',0,'2026-05-20 16:10:36','Words are built from letters in a specific order, and getting the spelling right makes your writing clear and readable. Master tricky words, patterns, and rules so your ideas shine through perfectly on the page.',NULL);
INSERT INTO badges VALUES(634,'Spies','spy-badge-2','Discover Knowledge','Kristine Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/spy-badge-2/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Spies gather secrets and send hidden messages to protect their countries and allies. Master the sneaky skills of real intelligence agents—move silently, crack codes, and discover how famous spies changed history.','🕵️');
INSERT INTO badges VALUES(635,'Spinning Badge','spinning-badge','Discover the Home','Suzanne Vicoryosmanson','spinning-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/spinning-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Spinning wheel or spindle turns fluffy clouds of wool into strong thread you can use for knitting, weaving, or sewing. It''s an ancient skill that lets you make something useful from raw fiber, one twist at a time.',NULL);
INSERT INTO badges VALUES(636,'Sports (Specific)','sports-badge','Discover Health & Safety','Kerry CordyNOTE','sports-badge.jpg',1,'A separate badge may be earned for any sport. Some examples may include soccer, badminton, volleyball, softball, basketball, golf, cheer leading, skating, or skiing, with more examples at the end of this badge. This list is not all inclusive and we can make a badge for any sport you choose. Disclaimer: Sports can lead to injury. Please learn and follow all safety rules for your chosen sport.','https://curiosityuntamed.com/badges/sports-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every sport has its own rules, gear, and moves to master. Pick your sport and dive in—learn how to play it right, dress for it safely, drill the skills that matter, and take care of your equipment so it lasts.',NULL);
INSERT INTO badges VALUES(637,'Sports Team Fan (Specific)','sports-team-fan-badge','Discover Knowledge','','sports-team-fan-badge.jpg',1,NULL,'https://curiosityuntamed.com/badges/sports-team-fan-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every team has its own story—from the colors and mascot that represent them to the stadium where fans cheer the loudest. Dive into your favorite team''s past and present to discover what makes them legendary, where they came from, and the championships they''ve won.',NULL);
INSERT INTO badges VALUES(638,'Sportsmanship','sportsmanship-badge','Discover Character','Kerry Cordy','sportsmanship-badge.png',0,NULL,'https://curiosityuntamed.com/badges/sportsmanship-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Winning and losing are both part of playing, but how you handle each one shows real character. Good sportsmanship means playing fair, respecting the rules, treating opponents with respect, and accepting the outcome—whether you win or lose—with grace.',NULL);
INSERT INTO badges VALUES(639,'Stamp Collecting','stamp-collecting','Discover the World','Doreen Olson','stamp-collecting.jpg',0,NULL,'https://curiosityuntamed.com/badges/stamp-collecting/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Stamps are tiny windows into countries around the world, each one showing different leaders, animals, landmarks, and stories. Collect them, learn where they''re from, and discover how mail traveled before the internet existed.',NULL);
INSERT INTO badges VALUES(640,'Star Wars','star-wars-badge','Discover Knowledge','','star-wars-badge.png',0,NULL,'https://curiosityuntamed.com/badges/star-wars-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A galaxy far, far away holds epic battles, unlikely heroes, and the eternal struggle between light and dark. Dive into the Star Wars universe through stories and characters, then map out how this legendary saga unfolded across decades of adventures.',NULL);
INSERT INTO badges VALUES(641,'State Flags','state-flags-badge','Discover the World','','state-flags-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/state-flags-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every state has its own flag with colors, symbols, and stories that tell you something special about that place. From stars and stripes to bears and landmarks, these flags are like visual signatures of America.',NULL);
INSERT INTO badges VALUES(642,'State Parks (Specific)','state-park-specific-badge','Discover the Outdoors','Sylvia Duke',NULL,1,NULL,'https://curiosityuntamed.com/badges/state-park-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','State parks protect amazing natural places and give people spaces to explore, hike, and camp. Pick one park to investigate—get to know what makes it special, from famous rock formations to trails and visitor spots, and discover why your state decided to save it.','🏞️');
INSERT INTO badges VALUES(643,'Steven Universe','steven-universe-badge','Discover Knowledge','Sarah Bruekherr','steven-universe-badge.jpg',0,'Some episodes of Steven Universe can contain frightening situations or animated violence, so parents might want to be careful about younger or more sensitive children working on this badge. Here’s a review for parents about the content in the show, and what ages it’s good for. https://www.commonsensemedia.org/tv-reviews/steven-universe','https://curiosityuntamed.com/badges/steven-universe-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Steven Universe follows a half-human, half-Gem boy and his magical guardians as they protect Earth from cosmic threats while learning what it means to be a family. Dive into their adventures, get to know the colorful characters, and discover how music and friendship save the day.',NULL);
INSERT INTO badges VALUES(644,'Stitchery (Specific)','stitchery-badge','Discover Art','','stitchery-badge.jpg',1,NULL,'https://curiosityuntamed.com/badges/stitchery-badge/','{}',0,'2026-05-20 16:10:36','Needle and thread transform fabric into art, one stitch at a time. Whether you''re sewing seams, adding embroidery, or mending something special, you''ll discover how patience and precision create something beautiful and lasting.',NULL);
INSERT INTO badges VALUES(645,'Stop Motion Animation','stop-motion-animation-badge','Discover Art','Frontier Girls Troop','stop-motion-animation-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/stop-motion-animation-badge/','{"preschool":1,"level1":1,"level2":2,"level3":3,"level4":4,"level5":6}',1,'2026-05-20 16:10:36','Stop motion brings tiny objects to life one frame at a time—a toy moves a little bit, you snap a photo, it moves again, snap again. When you play all those photos fast, it looks like the toy is actually moving and telling a story.',NULL);
INSERT INTO badges VALUES(646,'Story Movement','story-movement-badge','Discover Art','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/story-movement-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your body can tell a story just as well as words. When you move to match what''s happening in a tale—or how it makes you feel—you discover that speed, size, and smoothness of movement all change the meaning, and your face and gestures become a whole new language.','💃');
INSERT INTO badges VALUES(647,'Strawberry Shortcake','strawberry-shortcake-badge','Discover Knowledge','','strawberry-shortcake-badge.png',0,NULL,'https://curiosityuntamed.com/badges/strawberry-shortcake-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Strawberry Shortcake and her friends live in a magical world where kindness, friendship, and teamwork solve problems and bring everyone together. Follow their adventures and discover what makes a good friend and neighbor.',NULL);
INSERT INTO badges VALUES(648,'Street Art','street-art-badge','Discover Art','Sarah Bruekherr',NULL,0,NULL,'https://curiosityuntamed.com/badges/street-art-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Street art transforms public spaces into open-air galleries where anyone walking by can enjoy bold designs, murals, and creative messages. You''ll explore what makes street art legal and beautiful, learn the difference between art and vandalism, and create your own sketchbook of ideas inspired by what you discover.','🎨');
INSERT INTO badges VALUES(649,'Stretching','stretching-badge','Discover Health & Safety','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/stretching-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your muscles get tight from sitting, sports, and everyday life—stretching keeps them loose, flexible, and ready to move. Build a routine that feels good and watch your body become more limber and relaxed over time.','🧘');
INSERT INTO badges VALUES(650,'Super Mario','super-mario-badge','Discover Knowledge','Quinton Geissler','super-mario-badge.png',0,NULL,'https://curiosityuntamed.com/badges/super-mario-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Super Mario has been jumping through video game worlds for decades, battling Bowser, rescuing Princess Peach, and collecting coins across countless platforms and games. Explore the heroes and villains of the Mushroom Kingdom, trace how this iconic franchise grew from arcade classic to global phenomenon, and create your own Mario adventure.',NULL);
INSERT INTO badges VALUES(651,'S.W.A.P.S.','s-w-a-p-s-badge','Discover Art','Adele Nolan','s-w-a-p-s-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/s-w-a-p-s-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Tiny treasures you can trade, collect, and swap with friends—S.W.A.T.S. are small handmade crafts that fit in your pocket. Make beaded pins, painted rocks, or origami creations and start your own trading circle.',NULL);
INSERT INTO badges VALUES(652,'Sweet Treats','sweet-treats-badge','Discover the Home','Hailey Ensor','sweet-treats-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/sweet-treats-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Baking is a mix of science and creativity—the right pan conducts heat differently, a mixer whips air into batter, and following a recipe turns simple ingredients into something delicious. Whip up cakes, cookies, and treats while discovering why bakers make the choices they do.',NULL);
INSERT INTO badges VALUES(653,'Swimming','swimming-badge','Discover Health & Safety','Kerry Cordy','swimming-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/swimming-badge/','{"preschool":1,"level1":1,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Water is fun and powerful, and knowing how to move through it safely is a skill that could save your life or someone else''s. Master floating, different strokes, and rescue techniques so you can enjoy the water with confidence.',NULL);
INSERT INTO badges VALUES(654,'Table Setting','table-setting-badge','Discover the Home','Doreen Olson','table-setting-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/table-setting-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A properly set table is like a welcoming message to your dinner guests—each fork, knife, spoon, and napkin has its place and purpose. Master the etiquette of simple family dinners, fancy formal feasts, and everything in between, then create your own beautiful table settings for occasions you choose.',NULL);
INSERT INTO badges VALUES(655,'Take the Lead','take-the-lead-badge','Discover Character','Kerry Cordy','take-the-lead-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/take-the-lead-badge/','{"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Real leaders listen more than they talk, keep their promises, give credit where it''s due, and help their team succeed together. Whether you''re leading a sports team, a school project, or a group effort, you''ll learn how to inspire people, solve problems fairly, and get things done.',NULL);
INSERT INTO badges VALUES(656,'Tall Flags','tall-flags-badge','Discover Health & Safety','Doreen Olson','tall-flags-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/tall-flags-badge/','{"level1":3,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Tall flags are colorful banners on poles that dancers and performers spin, toss, and wave together in synchronized routines. Master the safe handling techniques, learn classic moves, and discover how tall flags groups perform at events around the world.',NULL);
INSERT INTO badges VALUES(657,'Tea Time','tea-time-badge','Discover the Home','','tea-time-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/tea-time-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Tea is a warm drink enjoyed by people all over the world, and sharing it with others is a cozy tradition. Steep different types of tea, master the proper way to pour and sip, and discover what snacks taste best alongside your favorite blend.',NULL);
INSERT INTO badges VALUES(658,'Teaching','teaching-badge','Discover Knowledge','Doreen Olson','teaching-badge.png',0,NULL,'https://curiosityuntamed.com/badges/teaching-badge/','{"preschool":3,"level1":4,"level2":5,"level3":6,"level4":7,"level5":9}',1,'2026-05-20 16:10:36','Helping someone learn something new is its own kind of magic. Whether you''re explaining a tricky math problem, showing a friend how to draw, or teaching a pet a trick, you''re building skills that make you a better communicator and a more patient person.',NULL);
INSERT INTO badges VALUES(659,'Teal Pumpkin','teal-pumpkin-badge','Discover Character','Danielle Collins',NULL,0,NULL,'https://curiosityuntamed.com/badges/teal-pumpkin-badge/','{"level5":7}',1,'2026-05-20 16:10:36','The Teal Pumpkin Project makes Halloween inclusive for kids with allergies, sensory sensitivities, and other needs by offering non-food trick-or-treat alternatives like toys, stickers, and puzzles. It''s about showing kindness and creativity when celebrating together.','🎃');
INSERT INTO badges VALUES(660,'Teamwork','teamwork-badge','Discover Character','Kerry Cordy','teamwork-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/teamwork-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Teams are everywhere—sports, school projects, family chores, and video games—and they work best when people trust each other, communicate clearly, and respect different ideas. Explore what makes a good teammate, how groups solve problems together, and why working with others often gets better results than going solo.',NULL);
INSERT INTO badges VALUES(661,'Teddy Bears','teddy-bears-badge','Discover Knowledge','Kara Simmons','teddy-bears-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/teddy-bears-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Teddy bears have been cuddly companions for over a century, starting with a president''s hunting trip and a clever toy maker''s idea. Explore the history of these beloved stuffed animals, famous bears through time, and what makes them so special to kids everywhere.',NULL);
INSERT INTO badges VALUES(662,'Ten Commandments','ten-commandments-badge','Discover Character','Kerry Cordy','ten-commandments-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/ten-commandments-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','These ten rules from ancient times teach us how to love God and treat people right. They''re the foundation of how millions of people try to live good lives, and exploring them helps you understand what it really means to be a good person.',NULL);
INSERT INTO badges VALUES(663,'Textile Design','textile-design-badge','Discover Art','Kerry Cordy','textile-design-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/textile-design-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Textiles are fabrics and patterns that wrap around us—on clothes, blankets, pillows, and curtains. Create your own designs and discover what makes some patterns pop while others fall flat.',NULL);
INSERT INTO badges VALUES(664,'Thankfulness','thankfulness-badge','Discover Character','Katie Lundquist, Troop 159','thankfulness-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/thankfulness-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Gratitude is noticing the good things in your life—big and small—and feeling genuinely glad about them. Spend a month writing down what makes you happy each day and discover how thankfulness changes the way you see the world.',NULL);
INSERT INTO badges VALUES(665,'Tie Dye','tie-dye-badge','Discover Art','Kerry Cordy','tie-dye-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/tie-dye-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Swirling colors bloom across white fabric when you fold, tie, and dip it in dye—creating one-of-a-kind patterns no two people make the same way. From colorful coffee filter butterflies to custom tie-dyed shirts, you''ll master this messy, magical art form from setup to cleanup.',NULL);
INSERT INTO badges VALUES(666,'Time Capsule','time-capsule-badge','Discover Knowledge','Norah Flens',NULL,0,NULL,'https://curiosityuntamed.com/badges/time-capsule-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A time capsule is a buried treasure of today that tells tomorrow''s people who you are right now. Pack your favorite things, write messages, and seal them away to surprise someone years from now.','⏰');
INSERT INTO badges VALUES(667,'Timekeeping Through the Ages','timekeeping-through-the-ages-badge','Discover Science & Technology','',NULL,0,NULL,'https://curiosityuntamed.com/badges/timekeeping-through-the-ages-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Humans have figured out surprisingly clever ways to measure time—from ancient sundials and water clocks to the digital watches in our pockets today. Explore how people tracked hours and minutes throughout history, build your own timekeeper, and discover how something as invisible as time actually shapes everything we do.','⏳');
INSERT INTO badges VALUES(668,'Titanic','titanic-badge','Discover Knowledge','Belinda Crowe','titanic-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/titanic-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Titanic was a massive luxury ship that sank in 1912 after hitting an iceberg in the Atlantic Ocean, killing over 1,500 people. Explore how a ship thought to be unsinkable actually went down, where it was built, and the incredible stories of passengers and survival.',NULL);
INSERT INTO badges VALUES(669,'Torah Study','torah-study-badge','Discover Character','','torah-study-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/torah-study-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Torah is the foundational text of Judaism, containing stories of ancestors, laws, and wisdom that have guided Jewish life for thousands of years. Dive into these ancient writings and discover what they teach about living with integrity, justice, and purpose.',NULL);
INSERT INTO badges VALUES(670,'el Art','towel-art-badge','Discover the Home','Jessica Williams',NULL,0,NULL,'https://curiosityuntamed.com/badges/towel-art-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Towel folding transforms everyday bathroom linens into clever animals and decorations that make people smile. Master the folds to create everything from dolphins to elephants, then discover how this playful art started.','🐬');
INSERT INTO badges VALUES(671,'Toy History','toy-history-badge','Discover Knowledge','Ben Erstein',NULL,0,NULL,'https://curiosityuntamed.com/badges/toy-history-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Toys have changed wildly over the past hundred years—from handmade dolls and wooden trains to action figures and video games. Explore what made your parents and grandparents smile as kids, then create your own plaything and map out how toys evolved decade by decade.','🧸');
INSERT INTO badges VALUES(672,'Trademarked Toys (specific)','trademarked-toys-badge','Discover Knowledge','','trademarked-toys-badge.jpg',1,NULL,'https://curiosityuntamed.com/badges/trademarked-toys-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Some toys become so popular they get their own special name and logo that nobody else can copy—that''s a trademark. Pick your favorite toy, explore what makes it unique, and discover how playing with it actually teaches you real skills like creativity, problem-solving, or caring for something.',NULL);
INSERT INTO badges VALUES(673,'Trampolining','trampoline-badge','Discover Health & Safety','Eleanor Gunby','trampoline-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/trampoline-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Bouncing high into the air takes strength, balance, and style—but staying safe is what matters most. Learn the rules, master moves like tucks and twists, and string together a routine that shows off your skills.',NULL);
INSERT INTO badges VALUES(674,'Trade Routes','trade-routes-badge','Discover the World','',NULL,0,NULL,'https://curiosityuntamed.com/badges/trade-routes-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Throughout history, merchants loaded ships, camels, and wagons with silk, spices, and treasures to trade across deserts, oceans, and mountains. Explore how goods travel around the world today and discover the ancient routes that connected distant civilizations.','🛤️');
INSERT INTO badges VALUES(675,'Transportation','transportation-badge','Discover the World','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/transportation-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','People move around the world in cars, trains, planes, boats, and bicycles—each one built for different jobs and places. Explore how these vehicles get us where we need to go, discover what makes each one special, and see how transportation works differently across the globe.','🚂');
INSERT INTO badges VALUES(676,'Trash Collection','trash-collection-badge','Discover the World','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/trash-collection-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Trash might seem gross, but someone has to haul it away—and there''s way more to it than you think. Discover where your garbage goes, how to sort recycling and compost, and what happens to towns when collection stops working.','♻️');
INSERT INTO badges VALUES(677,'Travel','travel-2','Discover the World','Kerry Cordy','travel-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/travel-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every trip is an adventure waiting to happen, and the real skill is getting ready for it. You''ll pack smart, stay organized, and learn how to keep your group together while exploring somewhere brand new.',NULL);
INSERT INTO badges VALUES(678,'Travel Safety','travel-safety-badge','Discover Health & Safety','',NULL,0,NULL,'https://curiosityuntamed.com/badges/travel-safety-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Whether you''re headed to the airport, hopping on a bus, or taking a road trip, traveling safely means staying close to trusted adults, packing smart for the journey, and knowing the rules of the road—and sky. You''ll learn what to do if you get separated, how to pack for different weather, and why staying calm and quiet matters when you''re on the move.','✈️');
INSERT INTO badges VALUES(679,'Trees','trees-badge','Discover the Outdoors','Abby Olson','trees-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/trees-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Trees are the tallest living things on Earth, with roots that drink up water and branches that reach toward the sky. They give us oxygen, shade, food, and homes for countless animals—and each type has its own shape, bark, and leaves to discover.',NULL);
INSERT INTO badges VALUES(680,'T-Shirts','the-t-shirt-badge','Discover Art','Joy Staunton','the-t-shirt-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/the-t-shirt-badge/','{"preschool":3,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',0,'2026-05-20 16:10:36','T-shirts are blank canvases just waiting for your ideas—whether you''re tie-dying, screen printing, painting, or using markers to make designs that are totally you. Turn a plain shirt into wearable art that shows off your style and creativity.',NULL);
INSERT INTO badges VALUES(681,'United Nations','united-nations-badge','Discover the World','Sarah Bruekherr','united-nations-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/united-nations-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The United Nations brings together countries from around the world to solve problems, keep peace, and help people in need. Explore how this global organization works, who represents your country there, and the big moments that shaped it since 1945.',NULL);
INSERT INTO badges VALUES(682,'United States of America','united-states-badge','Discover Knowledge','Kerry Cordy','united-states-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/united-states-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The United States is a huge country made of 50 states, each with its own capital city and story. Get to know the map, the symbols that represent America, and the history that shaped the nation.',NULL);
INSERT INTO badges VALUES(683,'Upcycle','upcycle-badge','Discover Science & Technology','Stacey Helm','upcycle-badge.png',0,NULL,'https://curiosityuntamed.com/badges/upcycle-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Turning trash into treasure means finding new life for things you''d normally throw away—like turning old jeans into a bag or plastic bottles into planters. It''s better for the planet and way more creative than recycling.',NULL);
INSERT INTO badges VALUES(684,'Urban Exploration','abandoned-urban-exploration','Discover the World','','abandoned-urban-exploration.jpg',0,'THIS BADGE MAY ONLY BE EARNED EXPLORING AREAS OPEN TO THE PUBLIC AND DEEMED SAFE FOR THE PUBLIC TO ENTER.','https://curiosityuntamed.com/badges/abandoned-urban-exploration/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Abandoned buildings and forgotten spaces tell stories about the past—why they were built, how people used them, and what happened next. Explore public urban sites safely with your group, pack smart for adventure, and discover the history hiding in plain sight.',NULL);
INSERT INTO badges VALUES(685,'U.S. Constitution','u-s-constitution','Discover Knowledge','Kerry Cordy','u-s-constitution.jpg',0,NULL,'https://curiosityuntamed.com/badges/u-s-constitution/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Constitution is the rulebook for how America''s government works, written way back in 1787 to protect people''s freedoms and keep things fair. Discover the three branches of government, the rights and freedoms it guarantees, and the real people who lead our country today.',NULL);
INSERT INTO badges VALUES(686,'U.S. Geography','u-s-geography-badge','Discover the World','Laura Duck','u-s-geography-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/u-s-geography-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The United States is a massive country with 50 states, each with their own shape, location, and character. Explore where you live on the map, find the places that border your state, and discover the natural wonders—from the deepest canyons to the tallest mountains—that make America so diverse.',NULL);
INSERT INTO badges VALUES(687,'U.S. Government','u-s-government-badge','Discover Knowledge','Doreen Olson and Kerry Cordy','u-s-government-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/u-s-government-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Government is how a country, state, city, and town decide on rules, keep everyone safe, and settle disagreements. Explore the three branches that make laws, enforce them, and judge if rules were broken—from your local city hall all the way to Washington DC.',NULL);
INSERT INTO badges VALUES(688,'U.S. History','u-s-history-badge','Discover Knowledge','Kerry Cordy','u-s-history-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/u-s-history-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','America has iconic symbols like the Statue of Liberty and Liberty Bell that tell stories of freedom and independence. Discover why colonists came here, how they broke away from England, and what makes the United States unique among nations.',NULL);
INSERT INTO badges VALUES(689,'U.S. Presidents','u-s-presidents','Discover Knowledge','Doreen Olson','u-s-presidents.jpg',0,NULL,'https://curiosityuntamed.com/badges/u-s-presidents/','{"level1":2,"level2":3,"level3":4,"level4":5}',1,'2026-05-20 16:10:36','The president is the leader of the United States, and each one has shaped the country in different ways. Discover who they were, what they accomplished, and why this role matters so much to our nation''s story.',NULL);
INSERT INTO badges VALUES(690,'Vacation','vacation-badge','Discover the World','Heather Wilson',NULL,0,NULL,'https://curiosityuntamed.com/badges/vacation-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A vacation is a break from your regular routine where you explore new places, relax, and try new things. Plan a trip somewhere you''ve always wanted to go, keep track of your adventure with a daily journal, and dig up fascinating facts about your destination to share.','🧳');
INSERT INTO badges VALUES(691,'Vegetables','vegetable-badge','Discover Agriculture','Doreen Olson','vegetable-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/vegetable-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Vegetables are way more than something green on your plate—they''re packed with vitamins and minerals your body needs to grow strong. Plant one from seed, taste new ones you''ve never tried, and discover what superpowers are hiding inside carrots, broccoli, peppers, and beyond.',NULL);
INSERT INTO badges VALUES(692,'Vegetables (specific)','vegetable-specific-badge','Discover Agriculture','Kerry Cordy',NULL,1,NULL,'https://curiosityuntamed.com/badges/vegetable-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pick a vegetable and become its expert—learn where it grows, how to pick the best one at the store, and what it tastes like raw and cooked different ways. You''ll discover how the same vegetable can taste totally different depending on how you prepare it.','🥕');
INSERT INTO badges VALUES(693,'Vegetarian','vegetarian-badge','Discover Health & Safety','Meghan Wilson',NULL,0,NULL,'https://curiosityuntamed.com/badges/vegetarian-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Vegetarians skip meat but find protein and nutrition in beans, nuts, eggs, dairy, and veggies instead. Explore plant-based eating, try meatless meals, and discover how this choice affects your body and the planet.','🥬');
INSERT INTO badges VALUES(694,'Veterans','veterans-badge','Discover Character','Suzanne Vicoryosmanson','veterans-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/veterans-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Veterans are people who served in the military and made sacrifices for our country. Honor their courage by learning their stories, recognizing the vets around you, and celebrating what they''ve done.',NULL);
INSERT INTO badges VALUES(695,'Veterinarian','veterinarian-badge','Discover Agriculture','','veterinarian-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/veterinarian-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Veterinarians are doctors who care for sick and injured animals, from pets to farm animals to wildlife. They use special tools, perform check-ups and surgeries, and help keep animals healthy and happy.',NULL);
INSERT INTO badges VALUES(696,'Vietnam War','vietnam-war-badge','Discover Knowledge','Megan Lundquist (Eagle, Troop 159)','vietnam-war-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/vietnam-war-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','The Vietnam War was a long, complicated conflict in Southeast Asia that divided a country and involved the United States in ways that changed American history. Understand where it happened, why different nations got involved, and how this war shaped the world we live in today.',NULL);
INSERT INTO badges VALUES(697,'Vikings','viking-badge','Discover Knowledge','','viking-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/viking-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Vikings were fierce Norse explorers and warriors who sailed from Scandinavia over a thousand years ago, raiding and settling lands across Europe. Discover who they were, where they came from, and the incredible journeys that made them legendary.',NULL);
INSERT INTO badges VALUES(698,'Villains','villains-badge','Discover Knowledge','Wendy Conte','villains-badge.png',0,NULL,'https://curiosityuntamed.com/badges/villains-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every great villain has a story—what made them evil, what powers they wield, and who stands against them. Pick a villain from movies, books, or comics and dig into their past to understand what turned them into a bad guy.',NULL);
INSERT INTO badges VALUES(699,'Vocal Music by Genre','vocal-music-by-genre-badge','Discover Knowledge','','vocal-music-by-genre-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/vocal-music-by-genre-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every genre of music has its own sound, style, and story—from country to opera to hip-hop. Pick one that speaks to you, explore its roots, and learn to sing some of its greatest hits.',NULL);
INSERT INTO badges VALUES(700,'Volunteer','volunteering','Discover Character','Doreen Olson','volunteering.jpg',0,NULL,'https://curiosityuntamed.com/badges/volunteering/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Volunteers are people who give their time and energy to help others without expecting payment—whether that''s serving food at a shelter, cleaning up a park, or visiting someone who''s lonely. Find out what volunteers do in your community and jump in to help yourself.',NULL);
INSERT INTO badges VALUES(701,'Water','water-badge','Discover Science & Technology','Zoee Swafford','water-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/water-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Water is everywhere—in the clouds, the ground, and every living thing on Earth. Explore where water comes from, how it changes form, and why keeping it clean matters for people, plants, and animals.',NULL);
INSERT INTO badges VALUES(702,'Water Games','water-games-badge','Discover Health & Safety','','water-games-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/water-games-badge/','{"preschool":0,"level1":1,"level2":2,"level3":3,"level4":4,"level5":6}',1,'2026-05-20 16:10:36','Making a splash is way more fun when you know water safety tricks. Whether you''re at a pool, beach, or lake, learning to float, swim strong, and watch out for danger keeps you safe while having the best time.',NULL);
INSERT INTO badges VALUES(703,'Water Safety','water-safety-badge','Discover Health & Safety','Sylvia Duke','water-safety-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/water-safety-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Water is amazing for swimming, boating, and fun—but it demands respect and know-how. Learn what keeps you safe around water, from wearing the right gear to understanding when danger is lurking.',NULL);
INSERT INTO badges VALUES(704,'Watersheds','watershed-badge','Discover the Outdoors','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/watershed-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','All water flows downhill toward rivers and streams, carving invisible boundaries across the land called watersheds. Every raindrop, creek, and lake is part of one—and understanding how water moves through these natural systems shows why they matter for plants, animals, and people.','💧');
INSERT INTO badges VALUES(705,'Watercolor','watercolor-badge','Discover Art','Tina Swenson','watercolor-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/watercolor-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Watercolor paint flows and blends on wet paper in ways you can''t predict, creating soft clouds, glowing skies, and dreamy landscapes. Mix colors directly on your paper, layer transparent washes, and discover how different techniques turn simple brushstrokes into beautiful artwork.',NULL);
INSERT INTO badges VALUES(706,'Weapons (Specific)','weapon-specific-badge','Discover Knowledge','Crystal Morris',NULL,1,NULL,'https://curiosityuntamed.com/badges/weapon-specific-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every weapon has a story—from ancient swords to modern firearms. Pick one to explore and learn how it works, what makes it dangerous, who used it and why, and how safety rules keep people protected.','⚔️');
INSERT INTO badges VALUES(707,'Weather','weather-badge','Discover the Outdoors','Kerry Cordy','weather-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/weather-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Storms, blizzards, and wild weather shape where you live and how you need to stay safe. Track the sky for a week, understand what dangerous weather looks like in your area, and help your family plan exactly what to do when the weather turns serious.',NULL);
INSERT INTO badges VALUES(708,'Weaving','weaving-badge','Discover Art','','weaving-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/weaving-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5}',0,'2026-05-20 16:10:36','Thread and loom work together to create fabric from scratch—stripes, patterns, and textures all built by your own hands. It''s a craft that goes back thousands of years and lets you make scarves, wall hangings, or decorative pieces.',NULL);
INSERT INTO badges VALUES(709,'Weddings','wedding-badge','Discover the Home','',NULL,0,NULL,'https://curiosityuntamed.com/badges/wedding-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":4,"level5":7}',1,'2026-05-20 16:10:36','Weddings are celebrations where two people commit to each other, surrounded by family and friends. From the processional walk down the aisle to the reception party afterward, each part of a wedding has special meaning and its own traditions.','💍');
INSERT INTO badges VALUES(710,'Welding','welding','Discover Knowledge','Kerry Cordy','welding.jpg',0,NULL,'https://curiosityuntamed.com/badges/welding/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Welding joins pieces of metal together by melting them at super-hot temperatures—it''s how cars, bridges, and sculptures get built. You''ll discover what metals work best, how to stay safe around intense heat and sparks, and why this skill is so crucial to building the world around you.',NULL);
INSERT INTO badges VALUES(711,'Wilderness Survival','wilderness-survival-badge','Discover the Outdoors','Kerry Cordy','wilderness-survival-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/wilderness-survival-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Staying calm and thinking clearly can save your life when you''re lost in the wilderness. Learn how to signal for help, avoid danger, and use smart survival tricks like staying put and using mirrors to catch rescuers'' attention.',NULL);
INSERT INTO badges VALUES(712,'Wildflowers','wildflowers-badge','Discover the Outdoors','','wildflowers-badge.jpg',0,'All requirements should follow Leave No Trace principles.  Do not collect wildflowers unless they are from your own yard!','https://curiosityuntamed.com/badges/wildflowers-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Wildflowers pop up in fields, roadsides, and gardens without anyone planting them, painting the landscape with unexpected color. Spot the ones growing near you, learn their names and secret parts, and discover why some people dedicate their whole lives to finding and protecting these wild beauties.',NULL);
INSERT INTO badges VALUES(713,'Will Rogers','will-rogers-badge','Discover Knowledge','Suzanne Vicoryosmanson','will-rogers-badge.png',0,NULL,'https://curiosityuntamed.com/badges/will-rogers-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Will Rogers was an Oklahoma cowboy who became one of America''s most beloved entertainers, performing rope tricks, acting in movies, and writing jokes that poked fun at politicians and everyday life. His homespun wisdom and quick wit made him a star who could make people laugh while making them think.',NULL);
INSERT INTO badges VALUES(714,'Williams Syndrome','williams-syndrome-badge','Discover Health & Safety','','williams-syndrome-badge.png',0,NULL,'https://curiosityuntamed.com/badges/williams-syndrome-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Williams syndrome is a rare genetic condition that affects how the body develops, from the heart to the face to the way people learn and interact. Understanding this condition helps you appreciate how human bodies vary and why some people need extra support and care.',NULL);
INSERT INTO badges VALUES(715,'Winter Survival','winter-survival-badge','Discover Health & Safety','',NULL,0,NULL,'https://curiosityuntamed.com/badges/winter-survival-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Staying safe and warm when winter hits means knowing how to layer clothes, preparing supplies for emergencies, and understanding how both animals and people adapt to the cold. Build a survival kit for your car and learn why everything in it matters when you''re stuck in snow or ice.','❄️');
INSERT INTO badges VALUES(716,'Wizard of Oz','wizard-of-oz-badge','Discover Knowledge','Marcella Fischer','wizard-of-oz-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/wizard-of-oz-badge/','{"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Dorothy, the Scarecrow, the Tin Man, and the Cowardly Lion take a wild adventure down the yellow brick road to meet the mysterious Wizard. This beloved story is full of magic, friendship, and the idea that you might already have what you''re searching for.',NULL);
INSERT INTO badges VALUES(717,'Wolves','wolves-badge','Discover the Outdoors','Megan Bond','wolves-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/wolves-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Wolves are wild hunters that live and work together in tight family groups, with each member playing an important role. Discover why they howl, how they hunt as a team, and what makes these powerful predators so different from the dogs we know.',NULL);
INSERT INTO badges VALUES(718,'Women in History','women-in-history-badge','Discover Knowledge','John Carter','women-in-history-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/women-in-history-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Throughout history, women and girls have made bold moves that changed the world—from flying planes to discovering elements to leading armies. Meet the trailblazers who broke barriers, took risks, and left their mark on how we live today.',NULL);
INSERT INTO badges VALUES(719,'Women in Science','women-in-science','Discover Knowledge','Katie Lundquist','women-in-science.jpg',0,NULL,'https://curiosityuntamed.com/badges/women-in-science/','{"preschool":3,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Women have made incredible discoveries in medicine, physics, chemistry, and biology—from vaccines to radioactivity to DNA. Meet the brilliant minds who shaped our world and changed what science can be.',NULL);
INSERT INTO badges VALUES(720,'Women’s Suffrage','womens-suffrage-badge','Discover Character','Kerry Cordy','womens-suffrage-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/womens-suffrage-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Women fought hard for decades to win the right to vote, marching, speaking out, and never giving up even when they faced ridicule and arrest. Their courage changed history and shows what persistence and principle can accomplish.',NULL);
INSERT INTO badges VALUES(721,'Woodworking','woodworking-badge','Discover Art','','woodworking-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/woodworking-badge/','{"preschool":0,"level1":1,"level2":2,"level3":3,"level4":4,"level5":7}',1,'2026-05-20 16:10:36','Woodworking is the craft of shaping wood into useful and beautiful things—from furniture to boxes to decorative pieces. You''ll learn what makes different woods special, discover the tools that turn lumber into finished projects, and create something real with your own hands.',NULL);
INSERT INTO badges VALUES(722,'Words','words-badge','Discover Knowledge','','words-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/words-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Words are the building blocks you use to tell stories, ask questions, and share your ideas with the world. Discover what makes words work—from nouns and verbs to finding meanings in a dictionary—and watch how the right words can paint pictures in someone''s mind.',NULL);
INSERT INTO badges VALUES(723,'World Currencies','world-currencies-badge','Discover the World','','world-currencies-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/world-currencies-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every country has its own money with different names, colors, and faces on them. Explore why currencies matter, how exchange rates work, and what makes each one unique around the globe.',NULL);
INSERT INTO badges VALUES(724,'World Dance','world-dance-3','Discover Art','Kerry Cordy','world-dance-3.jpg',0,NULL,'https://curiosityuntamed.com/badges/world-dance-3/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every country has its own way of moving, celebrating, and telling stories through dance—from the twirling flamenco of Spain to the energetic hula of Hawaii to the graceful Bollywood moves of India. Explore dances from around the world, learn some moves yourself, and discover how dance connects people to their heritage and brings communities together.',NULL);
INSERT INTO badges VALUES(725,'World Flags','world-flags-badge','Discover the World','','world-flags-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/world-flags-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Every country has its own flag with colors and symbols that tell its story—from stripes and stars to unique patterns and designs. Explore what makes flags special and how they represent the people and history behind them.',NULL);
INSERT INTO badges VALUES(726,'World Geography','world-geography-badge','Discover the World','Kerry Cordy','world-geography-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/world-geography-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Earth is divided into seven continents and four oceans, each with its own countries, mountains, and rivers. Explore maps to find where you live, locate the biggest landmasses and waterways, and discover the countries that make up different continents.',NULL);
INSERT INTO badges VALUES(727,'World Geography (Specific)','world-geography-specific','Discover the World','Sylvia Duke','world-geography-specific.jpg',1,NULL,'https://curiosityuntamed.com/badges/world-geography-specific/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pick a place on the map and become a real expert on it. You''ll find out where it sits on the globe, what kids there play and eat, how much things cost, and the wild history that shaped the region into what it is today.',NULL);
INSERT INTO badges VALUES(728,'World Landmarks','world-landmarks-2','Discover the World','Suzanne Vicoryosmanson','world-landmarks-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/world-landmarks-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','From the Great Wall of China to the Statue of Liberty, these incredible structures tell stories of human creativity and ambition across the globe. Explore what makes them iconic and why people from everywhere travel to see them in person.',NULL);
INSERT INTO badges VALUES(729,'World Peace','world-peace-2','Discover the World','Kerry Cordy','world-peace-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/world-peace-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Peace symbols like the dove, olive branch, and peace sign show up in art across cultures and centuries. Explore what these symbols mean, create your own peace artwork, and discover how understanding people different from you is the real work of building a peaceful world.',NULL);
INSERT INTO badges VALUES(730,'World Religions','world-religion-badge','Discover the World','Kerry Cordy',NULL,0,NULL,'https://curiosityuntamed.com/badges/world-religion-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Billions of people around the world follow different religions, each with their own beliefs, practices, and values. Discover what makes religions unique, find the surprising similarities they share—like treating others kindly—and learn what neighbors near and far actually believe.','🌍');
INSERT INTO badges VALUES(731,'Worms','worm-badge','Discover Agriculture','Kerry Cordy','worm-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/worm-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Worms come in many shapes and sizes—earthworms, caterpillars, grubs, and more—and they''re some of nature''s hardest workers. Dig into soil and gardens to discover why these wiggling creatures matter so much for healthy plants and earth.',NULL);
INSERT INTO badges VALUES(732,'Writing','writing-badge','Discover Knowledge','Kerry Cordy','writing-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/writing-badge/','{"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Words are the building blocks of stories, journals, poems, and everything you read. Learn the grammar tools that make sentences work, then practice putting your own thoughts and ideas onto the page.',NULL);
INSERT INTO badges VALUES(733,'WWI','wwi-badge','Discover the World','Kristin Smith',NULL,0,NULL,'https://curiosityuntamed.com/badges/wwi-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5}',1,'2026-05-20 16:10:36','World War I was a massive conflict that pulled in countries from Europe, Asia, Africa, and beyond, making it truly "world-wide." Discover why millions of people fought, which countries were on opposing sides, and how this war changed the course of history.','🪖');
INSERT INTO badges VALUES(734,'WWII','wwii-badge','Discover the World','Kerry Cordy','wwii-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/wwii-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','World War II shaped the entire globe from 1939 to 1945, involving nations across Europe, Asia, and the Pacific in the largest conflict in history. Explore why it started, which countries fought on each side, and the key events that changed the world forever.',NULL);
INSERT INTO badges VALUES(735,'Yoga','yoga-badge','Discover Health & Safety','Kerry Cordy','yoga-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/yoga-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Yoga is an ancient practice that combines stretching, breathing, and balance to strengthen your body and calm your mind. You''ll learn classic poses and sequences, discover how yoga started thousands of years ago, and feel how it can help you stay flexible, focused, and peaceful.',NULL);
INSERT INTO badges VALUES(736,'Yo-yo','yo-yo-badge','Discover Knowledge','Gracyn Stroman','yo-yo-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/yo-yo-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A yo-yo is a spinning disc on a string that goes up and down in your hand—and if you practice, it can walk the dog, go around the world, and do tricks that look like magic. Master the basics and you''ll have a pocket-sized skill that''s been amazing people for thousands of years.',NULL);
INSERT INTO badges VALUES(737,'Yurt','7086-2','Discover the Outdoors','Chana Barak','7086-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/7086-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','A yurt is a round tent home used for thousands of years by nomadic people across Central Asia. These clever shelters stay warm in winter, cool in summer, and can be packed up and moved whenever adventure calls.',NULL);
INSERT INTO badges VALUES(738,'Zero Waste','zero-waste-badge','Discover the World','','zero-waste-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/zero-waste-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Trash doesn''t just disappear—it piles up in landfills for years. See where your waste goes, swap disposables for reusable gear you actually carry with you, and hunt down smarter alternatives to the stuff you throw away every day.',NULL);
INSERT INTO badges VALUES(739,'Zine','zine-badge','Discover Art','Sarah Bruekherr',NULL,0,NULL,'https://curiosityuntamed.com/badges/zine-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Zines are handmade mini-books stuffed with comics, artwork, writing, and wild ideas that people create and share with others who love the same things. Fold one from a single sheet of paper and discover how to become a zinester—someone who tells their own stories their own way.','📰');
INSERT INTO badges VALUES(740,'Ziplining','ziplining-badge','Discover the Outdoors','Kerry Cordy','ziplining-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/ziplining-badge/','{"preschool":0,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Zipping through the air on a cable is an adrenaline rush like no other. Whether you''re soaring across a backyard or gliding through a forest canopy, you''ll learn how ziplines work, what gear keeps you safe, and how to ride like a pro.',NULL);
INSERT INTO badges VALUES(741,'Zoos','zoo-badge-2','Discover Knowledge','Katie Cordy','zoo-badge-2.jpg',0,NULL,'https://curiosityuntamed.com/badges/zoo-badge-2/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Zoos are incredible places where you can see animals from all over the world—from lions and penguins to rare creatures you might never encounter otherwise. Explore what makes zoos work, how they care for different animals, and why they matter for both the animals and the people who visit them.',NULL);
INSERT INTO badges VALUES(742,'Map Reading','map-reading-badge','Discover the World','Kerry Cordy','map-reading-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/map-reading-badge/','{"level1":2,"level2":3,"level3":4,"level4":5}',1,'2026-05-20 16:10:36','Maps are visual languages that turn places into pictures—using symbols, colors, and lines to show everything from hiking trails to city streets to stadium seats. Master reading them and you''ll navigate anywhere, create your own, and understand how the whole world fits on paper.',NULL);
INSERT INTO badges VALUES(743,'Story Telling','storytelling-badge','Discover Art','Doreen Olson','storytelling-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/storytelling-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Stories stick with us because they''re how humans share what matters most—adventures, lessons, laughs, and memories that get passed down through generations. Become a storyteller yourself and discover why the same tale can be told a hundred different ways and still feel magical.',NULL);
INSERT INTO badges VALUES(744,'Video Games','video-game-badge','Discover Knowledge','',NULL,0,NULL,'https://curiosityuntamed.com/badges/video-game-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Video games run on systems with controllers, consoles, and discs that all work together to create the worlds you play in. You''ll discover how to care for your gear, understand game ratings that match your age, and balance gaming with the rest of your life.','🎮');
INSERT INTO badges VALUES(745,'Waffles','waffle-badge','Discover the Home','Brooke Robinson and Jennifer Robinson from Troop 447 in Charlotte, NC)','waffle-badge.jpg',0,NULL,'https://curiosityuntamed.com/badges/waffle-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Waffles are crispy on the outside, fluffy on the inside, and perfect for breakfast, lunch, or dessert. Mix up batches with different toppings and flavors—from chocolate chips and berries to savory cheese and herbs—and discover your new favorite way to eat them.',NULL);
INSERT INTO badges VALUES(746,'College Prep','14931-2','Discover Knowledge','Makayla Russell, Butterfly Troop #159','14931-2.png',0,'This badge is designed for Eagles only','https://curiosityuntamed.com/badges/14931-2/','{"level5":5}',1,'2026-05-20 16:10:36','Getting ready for college means exploring what schools offer, understanding how applications work, and figuring out which path fits your goals. It''s about taking charge of your future, one step at a time.',NULL);
INSERT INTO badges VALUES(747,'Holiday (Specific)','holiday-badge-specific','Discover the World','Marie Dichoso-Beavers','holiday-badge-specific.jpg',1,'This badge can be earned numerous times at each level, once for each holiday.','https://curiosityuntamed.com/badges/holiday-badge-specific/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Pick a holiday that fascinates you, then dig into its history, traditions, and how people celebrate it around the globe. Cook some authentic holiday food and discover how the same celebration can look totally different depending on where you are in the world.',NULL);
INSERT INTO badges VALUES(748,'Superhero (Specific)','superheros-badge-specific','Discover Knowledge','Danae Havir and Hannah Stafford','superheros-badge-specific.jpg',1,NULL,'https://curiosityuntamed.com/badges/superheros-badge-specific/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Your favorite superhero has a secret identity, special powers, and epic battles with villains. Dive deep into who they are, what makes them super, and what challenges they face—from their hidden lives to their greatest enemies.',NULL);
INSERT INTO badges VALUES(749,'Corn Mazes','corn-maze-badge','Discover Agriculture','Jill Brady',NULL,0,NULL,'https://curiosityuntamed.com/badges/corn-maze-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":6}',1,'2026-05-20 16:10:36','A corn maze is a giant puzzle carved right into a cornfield, and the challenge is finding your way from the entrance to the exit without getting lost. You''ll explore how people design these mazes, figure out clever tricks for navigating them, and learn the respectful way to wander through without damaging the crops.','🌽');
INSERT INTO badges VALUES(750,'Famous Animals (specific)','famous-animal-specific-badge','','Mimi Nankivell (Troop 193)','famous-animal-specific-badge.jpg',1,NULL,'https://curiosityuntamed.com/badges/famous-animal-specific-badge/','{"preschool":2,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Some animals become famous for doing amazing things—like a dog who saved lives in the mountains or a chimpanzee who learned sign language. Dig into the real story of one incredible animal, from what made them special to who cared for them and what their species is all about.',NULL);
INSERT INTO badges VALUES(751,'Internet Memes','internet-meme-badge','Discover Knowledge','',NULL,0,NULL,'https://curiosityuntamed.com/badges/internet-meme-badge/','{"preschool":1,"level1":2,"level2":3,"level3":4,"level4":5,"level5":7}',1,'2026-05-20 16:10:36','Internet memes are jokes, images, and videos that spread across the web and get remixed by millions of people. They''re how the internet communicates, laughs, and creates inside jokes—from dancing cats to endless variations on a single silly idea.','😹');
INSERT INTO badge_level_requirements VALUES(1,1,'preschool',0,'Learn what the Seven Wonders of the Ancient World are.');
INSERT INTO badge_level_requirements VALUES(2,1,'preschool',1,'Find coloring pages of the Seven Wonders and color them. Some coloring pages can be found at Super Coloring (third party website).');
INSERT INTO badge_level_requirements VALUES(3,1,'level1',2,'Who created the list of the Seven Wonders and why?');
INSERT INTO badge_level_requirements VALUES(4,1,'level2',3,'Create a timeline that shows the years each of the Wonders was constructed.');
INSERT INTO badge_level_requirements VALUES(5,1,'level3',4,'Choose one of the Ancient Wonders of the World and find out how historians think it was created.  What technology and tools did they have to work with?');
INSERT INTO badge_level_requirements VALUES(6,1,'level4',5,'Research other structures from the ancient world and choose one you think the Ancient Greeks should have included it as the Eighth Wonder and be able to explain why.');
INSERT INTO badge_level_requirements VALUES(7,2,'preschool',0,'Know what 911 emergency is.');
INSERT INTO badge_level_requirements VALUES(8,2,'preschool',1,'Know when and how to call 911. Know how to call using a regular phone and a cell phone.');
INSERT INTO badge_level_requirements VALUES(9,2,'level1',2,'Know your address and be able to give information to a 911 dispatcher if needed.');
INSERT INTO badge_level_requirements VALUES(10,2,'level2',3,'Take tour of a 911 dispatch center either in person or virtually, or interview a 911 dispatcher.');
INSERT INTO badge_level_requirements VALUES(11,2,'level3',4,'Research the history of 911 and find out where the home of 911 is and who made the first call.');
INSERT INTO badge_level_requirements VALUES(12,2,'level4',5,'Do Level 3requirements 1& 2');
INSERT INTO badge_level_requirements VALUES(13,2,'level4',6,'Find out what kind of schooling and training is required to be a 911 dispatcher.');
INSERT INTO badge_level_requirements VALUES(14,2,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your newfound knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(15,3,'preschool',0,'Understand what 9/11 means. What occurred in America on this day in 2001? Look at pictures of whatthe World Trade Center looked like before it was destroyed.');
INSERT INTO badge_level_requirements VALUES(16,3,'level1',1,'Participate in Patriot Day on 9/11.  On this day, the  American Flag should be flown at half staff at individual American homes, at the White House, and on all U.S. government buildings and establishments, home and abroad. Americans should also observe a moment of silence beginning at 8:46 A.M (EDT), the time the first plane struck the North Tower of the World Trade Center on September 11, 2001.');
INSERT INTO badge_level_requirements VALUES(17,3,'level2',2,'Attend a memorial service for 9/11.');
INSERT INTO badge_level_requirements VALUES(18,3,'level3',3,'Design a memorial or monument for 9/11.');
INSERT INTO badge_level_requirements VALUES(19,3,'level4',4,'Explain the long term effects of 9/11 and recognize the ongoing efforts of our armed services in some way. Level 5 – Adults: Do 9 requirements including the two starred*');
INSERT INTO badge_level_requirements VALUES(20,3,'level4',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(21,4,'preschool',0,'Learn the alphabet and say it without any mistakes.');
INSERT INTO badge_level_requirements VALUES(22,4,'preschool',1,'Learn to write your name.');
INSERT INTO badge_level_requirements VALUES(23,4,'level1',2,'Write a story using each letter of the alphabet as the beginning letter of each word. (For example: A Blue Cat Danced Eight Funny ….)');
INSERT INTO badge_level_requirements VALUES(24,4,'level2',3,'Learn the alphabet backwards and say it without any mistakes.');
INSERT INTO badge_level_requirements VALUES(25,4,'level3',4,'Sign or say the alphabet using phonics (the sounds of the letters) only.');
INSERT INTO badge_level_requirements VALUES(26,4,'level4',5,'Research the history of the alphabet.');
INSERT INTO badge_level_requirements VALUES(27,4,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(28,5,'preschool',0,'Create an informational booklet about yourself. At each level you earn this badge, you will have a new booklet and can compare the information, such as how you have grown and what you were interested in. My self-portrait (self drawn picture) My hands (draw outlines of each hand) My feet (what size your feet are) Measurements (I am  ___  in. tall. My waist measures  __  in. My left arm is  __  in. long.  I weigh  __  lbs. My longest hair is  __  in. long. My nose is  __  in. long) I am really good at __________. When I grow up I want to be _______. My favorite food is _______. My favorite activity is _______. My best friend is ________. My favorite color is _______. My favorite song is _______. My favorite movie is ________. My favorite TV show is _______. My favorite book is ________.');
INSERT INTO badge_level_requirements VALUES(29,5,'level1',1,'Find out what your name means and what its origin is.  Why did your parents give you this name?');
INSERT INTO badge_level_requirements VALUES(30,5,'level2',2,'Discuss with an adult what character traits you think make up a good person. Do you have each of these traits? How can you become an even better person?');
INSERT INTO badge_level_requirements VALUES(31,5,'level3',3,'Create a booklet of family traditions. This could include everything from how you spend the holidays to the recipe for the pot roast you make every Sunday for dinner. Include pictures or illustrations.');
INSERT INTO badge_level_requirements VALUES(32,5,'level4',4,'What career do you think you want as an adult and why? Research what type of education you will need. How will you get this education? How much will it cost? Are there scholarships, loans, or other methods of helping to finance the education you will need? How much money can you expect to earn? Where would you need to move in order to work in this career?');
INSERT INTO badge_level_requirements VALUES(33,5,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements;');
INSERT INTO badge_level_requirements VALUES(34,6,'preschool',0,'What are accessories? Find pictures of accessories in catalogs or magazines. Which do you like best?');
INSERT INTO badge_level_requirements VALUES(35,6,'level1',1,'Accessories started as needed, functional items. Try to figure out why people first used the following accessories and how often they are still used that way today: belts, purses, and hats.');
INSERT INTO badge_level_requirements VALUES(36,6,'level1',2,'Out of the list in Level 1 requirement 1, which one(s) will you need to purchase/find in the near future? What ways can you save money when you buy them? How can you take care of them so they last longer? Will choosing a particular brand or style of that item make a difference in how long you will be able to use it or how sturdy it is? For at least one item, such as shoes or belts, find two or three choices and list the reasons why one might be better than the other. Find at least two places you can buy the item.');
INSERT INTO badge_level_requirements VALUES(37,6,'level2',3,'Add these accessories to your list: scarves, shoes, and gloves.');
INSERT INTO badge_level_requirements VALUES(38,6,'level2',4,'Choose an element of design (color, line, shape, texture, etc.) and then find five different accessory examples that illustrate that element. For example, if you were to choose “form” for the element of design, you could find five different hats that illustrate different forms: sombreros, pillbox hats, a long knit stocking hat, baseball caps, and the cone-shaped dunce caps.');
INSERT INTO badge_level_requirements VALUES(39,6,'level3',5,'Add these accessories to your list: watches, jewelry, glasses and umbrellas.');
INSERT INTO badge_level_requirements VALUES(40,6,'level3',6,'Look through a catalog, a store, or a website with good photos and see if you can learn to identify accessories that are classics and accessories that are fads. Why might a person want classics instead of fads? What is the difference?');
INSERT INTO badge_level_requirements VALUES(41,6,'level4',7,'Choose 3 elements of design with 5 examples of each.');
INSERT INTO badge_level_requirements VALUES(42,6,'level4',8,'Find two examples of styles of accessories that were in fashion sometime at least 30 years ago and were again in the last 5 years. Find two styles of accessories that have continued to be used over a period of 25 years without much change.');
INSERT INTO badge_level_requirements VALUES(43,6,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.  You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(44,7,'preschool',0,'Learn what it means to be accountable. Talk about taking care of your own things or helping with a small task.');
INSERT INTO badge_level_requirements VALUES(45,7,'preschool',1,'Follow through on a simple promise or task, like cleaning up after a snack or putting away supplies.');
INSERT INTO badge_level_requirements VALUES(46,7,'level1',2,'Keep track of one daily responsibility (like brushing your teeth or feeding a pet) for one week using a sticker chart or checklist.  How difficult was it to remember to do it?  Did you do it every day and on time?  If not, discuss what prevented you from being accountable.');
INSERT INTO badge_level_requirements VALUES(47,7,'level2',3,'Learn about consequences—natural and logical—and how they relate to accountability and the choices you make.');
INSERT INTO badge_level_requirements VALUES(48,7,'level3',4,'Track a personal goal or habit (such as homework, chores, or fitness) for at least one month. Reflect on how well you followed through.  Where can you improve?  What strategies can you employ to help you stay accountable?');
INSERT INTO badge_level_requirements VALUES(49,7,'level4',5,'Learn about the history and importance of accountability in leadership, government, or business. Give one example of someone famous who was held accountable (or failed to be).');
INSERT INTO badge_level_requirements VALUES(50,7,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(53,9,'level3',0,'Earn the baking badge at the Level 3 Level.  Be able to explain what the following are:  yeast breads, quick breads, flat breads, and sourdough. Read an article or book or watch a documentary about how grains are made into flour.');
INSERT INTO badge_level_requirements VALUES(54,9,'level3',1,'Learn about rising agents.  What would bread & desserts be like without rising agents?  Make a baked good that relies totally on eggs to rise.  Make a baked good that relies on a reaction between acid and base to rise.  Make a baked good that uses no rising agent whatsoever.  Make a baked good that relies on a type of yeast and gluten for rising.');
INSERT INTO badge_level_requirements VALUES(55,9,'level4',2,'Earn the baking badge at Level 4.');
INSERT INTO badge_level_requirements VALUES(56,9,'level4',3,'Read about the differences in various grain flours.  Which ones have the most gluten?  Which ones are gluten-free?  With what flours other than grain flours do people bake with?  Choose a simple recipe such as biscuits, pie crust, plain pancakes or shortbread.  Make it out of three different flours (if you don’t have a good source for alternative flours you may use whole wheat and white flours as two separate flours) and compare the results.  Share your results with your friends or family. Level 5 – Adult:  Do 9 requirements including the 2 starred*');
INSERT INTO badge_level_requirements VALUES(57,9,'level4',4,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(58,10,'preschool',0,'Earn the Cooking badge at Preschool level.');
INSERT INTO badge_level_requirements VALUES(59,10,'preschool',1,'Help to cook one meal with a parent or guardian’s supervision and help.');
INSERT INTO badge_level_requirements VALUES(60,10,'level1',2,'Earn the Cooking badge at Level 1.');
INSERT INTO badge_level_requirements VALUES(61,10,'level1',3,'Know which is the most important meal of the day.  How can you make yours more nutritious?');
INSERT INTO badge_level_requirements VALUES(62,10,'level2',4,'Earn the Cooking badge at Level 2.');
INSERT INTO badge_level_requirements VALUES(63,10,'level2',5,'Learn how to make a meal nutritionally complete, with a good proportion of protein, carbohydrates, fruits and vegetables. Find a food pyramid and be able to understand it.');
INSERT INTO badge_level_requirements VALUES(64,10,'level3',6,'Earn the Cooking badge at Level 3.');
INSERT INTO badge_level_requirements VALUES(65,10,'level3',7,'Be in charge of cooking a full day’s worth of meals.  Make sure each meal is nutritionally complete.');
INSERT INTO badge_level_requirements VALUES(66,10,'level4',8,'Earn the Cooking badge at the Level 4.');
INSERT INTO badge_level_requirements VALUES(67,10,'level4',9,'Be in charge of cooking a full week’s worth of meals. Make sure each meal is nutritionally complete.');
INSERT INTO badge_level_requirements VALUES(68,10,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(75,14,'level1',0,'Earn the Sewing Badge at your level. Be able to identify at least five parts of a sewing machine.');
INSERT INTO badge_level_requirements VALUES(76,14,'level1',1,'Using hand sewing, make a small pillow, bean bag, stuffed toy, sachet or similar project that’s a little more difficult than what you made for the Sewing Badge.');
INSERT INTO badge_level_requirements VALUES(77,14,'level2',2,'Learn how to lay a pattern with the length or grain of a fabric and how to lay a pattern diagonally. Be able to explain to someone else the different terms & symbols printed on patterns.   Learn why it is advantageous to measure things twice before cutting your fabric.  Use a sewing machine to make a simple item such as a tote bag, draw-string bag, vest, or apron. If you did this for the Sewing badge, then sew a second item that’s a little more difficult than the one done for the other badge.');
INSERT INTO badge_level_requirements VALUES(78,14,'level3',3,'With adult supervision, use an iron. Discuss what are appropriate temperatures for certain fabrics. Press five simple things such as a handkerchief, a tea towel, a pillowcase, etc. Why is learning to iron important in sewing?  Why is use of the iron considered as important as a sewing machine when sewing?If you did this for the Sewing Badge, then iron five more items. They need to be made from at least three different kinds of fiber (silk, polyester, cotton, rayon, wool, etc.). At least one should need steam and one should not need steam.');
INSERT INTO badge_level_requirements VALUES(79,14,'level4',4,'Choose a pattern and make a garment.  This can be for yourself, a family member or friend.  It may be for an adult or a child.  Make sure all your seams and hems are neatened.Owls:  Do 9 requirements including the two starred.');
INSERT INTO badge_level_requirements VALUES(80,14,'level4',5,'Do Eagle requirements 1 & 2');
INSERT INTO badge_level_requirements VALUES(81,14,'level4',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(82,15,'preschool',0,'Learn what aerospace means and why it is important.');
INSERT INTO badge_level_requirements VALUES(83,15,'preschool',1,'Look at pictures of different aerospace air crafts.');
INSERT INTO badge_level_requirements VALUES(84,15,'level1',2,'Find out what NASA is and what they do. If possible, with a parent’s permission, visit the NASA website for kids.');
INSERT INTO badge_level_requirements VALUES(85,15,'level2',3,'Create a timeline of the major aerospace events throughout history. Include at least 10 events.');
INSERT INTO badge_level_requirements VALUES(86,15,'level3',4,'Learn about the International Space Station. What is it? When was it originally put in place? Which countries participate in the project? Write a brief essay, or discuss with an adult whether or not you think having an international space station, rather than one used by only one country, is important.');
INSERT INTO badge_level_requirements VALUES(87,15,'level4',5,'Learn about at least 3 companies involved in the aerospace industry. Who are they? What do they produce or study? How large are they? Where are they located?');
INSERT INTO badge_level_requirements VALUES(88,15,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(89,16,'preschool',0,'Look at pictures of planets and constellations and learn their names.');
INSERT INTO badge_level_requirements VALUES(90,16,'preschool',1,'Draw a picture of a new planet (one that hasn’t been discovered yet). Does anything live there? What do they look like and how do they live?');
INSERT INTO badge_level_requirements VALUES(91,16,'level1',2,'Tell a short story about an encounter with an alien species. Who met them? What did they do?  Or  read a book about an alien encounter.');
INSERT INTO badge_level_requirements VALUES(92,16,'level2',3,'Discuss the scale of the universe and the Fermi Paradox.  Do you think there are aliens out there?');
INSERT INTO badge_level_requirements VALUES(93,16,'level3',4,'Identify different theories that explain the Fermi Paradox. Discuss which you think are most likely.');
INSERT INTO badge_level_requirements VALUES(94,16,'level4',5,'Discuss the Drake Equation and its components. Run through a guided calculation of the equation using your own estimates.');
INSERT INTO badge_level_requirements VALUES(95,16,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(96,17,'preschool',0,'What is an alpaca?  Where do they come from (Find it on a map)? What are they used for?');
INSERT INTO badge_level_requirements VALUES(97,17,'level1',1,'Learn about the basic care involved in owning an alpaca. What do they eat?  How should they be sheltered?  What type of fencing should be used?');
INSERT INTO badge_level_requirements VALUES(98,17,'level1',2,'Find out at least three things that are made from alpaca fibers. If possible, find someone who owns something made of alpaca and see what the fibers feel like.');
INSERT INTO badge_level_requirements VALUES(99,17,'level2',3,'Complete Level 1 requirements 1 & 2.  Add the following information to your knowledge about alpacas: How much pasture do they need? How often do they need to be shorn?');
INSERT INTO badge_level_requirements VALUES(100,17,'level2',4,'Visit an alpaca farm in person, if possible, or online with the permission of a parent.');
INSERT INTO badge_level_requirements VALUES(101,17,'level3',5,'Complete Level 2 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(102,17,'level3',6,'What are the costs involved with owning an alpaca?  What is their current market value? Where would  you purchase their food and how much would it cost each month? What could you expect in vet bills? Would you shear them yourself or hire someone? Create a 1 year budget  outlining the costs of caring for one or more alpacas.');
INSERT INTO badge_level_requirements VALUES(103,17,'level4',7,'Complete Level 3 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(104,17,'level4',8,'What associations are available to alpaca owners and breeders in your area? What would be the benefit of joining one of these associations? If no association is available in your area, what national associations are there?');
INSERT INTO badge_level_requirements VALUES(105,17,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(106,18,'preschool',0,'Understand what the Air Force is and what their role is in the military.');
INSERT INTO badge_level_requirements VALUES(107,18,'level1',1,'Learn the history of the Air Force and how it began as well as its mission today.');
INSERT INTO badge_level_requirements VALUES(108,18,'level2',2,'Learn to identify at least 5 different types of aircraft used by the Air Force and what their purpose is.');
INSERT INTO badge_level_requirements VALUES(109,18,'level3',3,'Discuss the contributions the U.S. Air Force as made to our society or write an essay about these contributions.');
INSERT INTO badge_level_requirements VALUES(110,18,'level4',4,'Visit an Air Force recruiter. Find out how to enlist in the Air Force or be commissioned as an Air Force officer. What jobs are available? What training is provided? How long must you enlist for? What are the benefits of joining the military? What are the drawbacks How does your education and background affect your salary in the Air Force?');
INSERT INTO badge_level_requirements VALUES(111,18,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(112,19,'preschool',0,'Learn what an airplane is. Look at pictures of different airplanes. Which is your favorite?');
INSERT INTO badge_level_requirements VALUES(113,19,'level1',1,'Learn to identify at least three different airplanes.');
INSERT INTO badge_level_requirements VALUES(114,19,'level2',2,'but learn to identify at least four different airplanes.');
INSERT INTO badge_level_requirements VALUES(115,19,'level2',3,'Make a timeline of airplane history. You must have at least 10 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(116,19,'level3',4,'but be able to identify at least seven different airplanes from different time periods, and have at least 15 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(117,19,'level3',5,'Read a biography of a famous person connected with aviation history, such as Charles Lindbergh, the Wright Brothers, or Anthony Fokker (If you earned this badge at an earlier level you must read a biography of a different person).');
INSERT INTO badge_level_requirements VALUES(118,19,'level4',6,'Be able to identify at least ten airplanes from different time periods, and have at least 20 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(119,19,'level4',7,'Learn about Bernoulli’s principle (lift), and Newton’s first law of motion (inertia). How do airplanes use these laws?');
INSERT INTO badge_level_requirements VALUES(120,19,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(121,20,'preschool',0,'Describe ways people communicate with each other when they are not together. Learn what amateur radio is and describe how people can use radios to talk to one another.');
INSERT INTO badge_level_requirements VALUES(122,20,'preschool',1,'How is broadcast radio different from amateur radio? Turn on the radio in your home or car, and listen to amateur radio communications on the internet (with permission from a parent) to tell the difference.');
INSERT INTO badge_level_requirements VALUES(123,20,'level1',2,'Complete Preschool requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(124,20,'level1',3,'What is a call sign?” How do amateur radio operators use call signs?');
INSERT INTO badge_level_requirements VALUES(125,20,'level2',4,'Complete Level 1 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(126,20,'level2',5,'Identify and describe the components needed to communicate with others as a ham (antenna, power supply, microphone, speaker and transceiver). Describe what radio waves are.');
INSERT INTO badge_level_requirements VALUES(127,20,'level2',6,'What is the ARRL? What does FCC stand for? What do these two organizations have to do with getting an amateur radio license? Describe the three levels of licensing and the required examinations.');
INSERT INTO badge_level_requirements VALUES(128,20,'level3',7,'Complete Level 2 requirements 1, 2 & 3.');
INSERT INTO badge_level_requirements VALUES(129,20,'level3',8,'Research how ham radio has been useful in the event of emergencies and write an essay.');
INSERT INTO badge_level_requirements VALUES(130,20,'level3',9,'Study an amateur radio licensing book (purchase, or get one from the library) for six hours and take two practice exams. Practice exams may be from the book or from the ARRL website; study time does not have to be done at once; there are also practice test apps you can use for Android. Record your results and look for score improvement. Score 1: _________ Score 2: _________');
INSERT INTO badge_level_requirements VALUES(131,20,'level4',10,'Complete Level 3 requirements 1, 2 & 3.');
INSERT INTO badge_level_requirements VALUES(132,20,'level4',11,'Study an amateur radio licensing book (purchase, or get one from the library) for ten hours and take three practice exams. Practice exams may be from the book or from the ARRL website; study time does not have to be done at once; there are also practice test apps you can use for Android. Record your results and look for score improvement. Score 1: _________ Score 2: _________ Score 3: _________');
INSERT INTO badge_level_requirements VALUES(133,20,'level5',12,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(134,21,'preschool',0,'Learn who Amelia Earhart is and what she is known for.');
INSERT INTO badge_level_requirements VALUES(135,21,'level1',1,'Know what records Amelia Earhart held.');
INSERT INTO badge_level_requirements VALUES(136,21,'level2',2,'Trace the routes of Amelia Earhart’s most famous flights on a map.');
INSERT INTO badge_level_requirements VALUES(137,21,'level3',3,'Discover at least three theories about her disappearance. Study one and make a brief presentation (report, display, photo essay, newspaper article) on whether or not you agree with that theory. Make sure to explain your reasons why or why not.');
INSERT INTO badge_level_requirements VALUES(138,21,'level4',4,'Create a timeline of the history of flight. Especially highlight the role of women pilots. Include at least 15 items.');
INSERT INTO badge_level_requirements VALUES(139,21,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(140,22,'preschool',0,'Learn what a document is. Why can documents be important?  Be able to name at least 1 important document from American history.');
INSERT INTO badge_level_requirements VALUES(141,22,'level1',1,'Be able to name at least 3 different important documents from America’s past.');
INSERT INTO badge_level_requirements VALUES(142,22,'level1',2,'Choose one document from American history, such as the Declaration of Independence, and be able to tell why it is so important.');
INSERT INTO badge_level_requirements VALUES(143,22,'level2',3,'Be able to name at least 5 different important documents in American history and tell why each is important.');
INSERT INTO badge_level_requirements VALUES(144,22,'level2',4,'Make a timeline of important American documents, and documents which America has signed, such as the Versailles Treaty. Be sure you include the Constitution; Emancipation Proclamation; the Declaration of Independence; the Bill of Rights; the Mayflower Compact; the Declaration of Causes; the Gettysburg Address; and the Articles of Confederation. You must have at least 15 documents on your timeline.');
INSERT INTO badge_level_requirements VALUES(145,22,'level3',5,'Have at least 20 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(146,22,'level3',6,'Find out who wrote each of the documents on your timeline. Choose one writer and learn about his life. Learn the history of at least one of the documents you have listed.');
INSERT INTO badge_level_requirements VALUES(147,22,'level4',7,'Have at least 25 items on your timeline, and learn the history of at least three of the documents listed.');
INSERT INTO badge_level_requirements VALUES(148,22,'level4',8,'Learn how our judicial system works. Find examples of documents from other countries, such as the Magna Carta from England, that express the basic ideas on which our system of laws is based.');
INSERT INTO badge_level_requirements VALUES(149,22,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(150,23,'preschool',0,'How many different American Girl historical dolls are there? What are their names? What doll looks most like you? Which doll is your favorite and why?');
INSERT INTO badge_level_requirements VALUES(151,23,'level1',1,'Choose one of the American Girl Dolls and read at least one of her stories. If you do not own one of the books, borrow one from a friend or check one out from the library. Are there featured items in the story that are sold as accessories for the doll?');
INSERT INTO badge_level_requirements VALUES(152,23,'level2',2,'Learn the history of American Girl dolls. What company originally owned them? When were they sold? When were the modern American Girl dolls released? Why do you think the company added so many customizable dolls?');
INSERT INTO badge_level_requirements VALUES(153,23,'level3',3,'Learn more about the American Girl’s charitable efforts that support important causes, and encourage girls to give back to their communities.');
INSERT INTO badge_level_requirements VALUES(154,23,'level4',4,'Compare the American Girl Dolls to other brands of 18″ dolls (for example Madame Alexander, Carpatina, Springfield, and Gotz dolls). What is the difference in price, quality and do the other brands have books and accessories? If a parent will allow, go online to Ebay and see what the price differences are compared to the retail price.');
INSERT INTO badge_level_requirements VALUES(155,23,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(156,24,'preschool',0,'What does “American Heritage” mean? Learn what the term involves and think about the ways in which the United States of America has become American rather than being English, French, Spanish or German. Think about the motto of the United States “E Pluribus Unum” and what it means. How can we preserve America’s Heritage? According to the Heritage Foundation: “Unlike countries governed by the sword under dictatorship or state-controlled systems, America was formed and built on the ideas and ideals of individual rights and the four key themes of Freedom, Unity, Progress, and Responsibility — themes that originate in our Declaration of Independence, U. S. Constitution, and other primary documents and in philosophical ideas and ideals commonly grounded in the study of Western Civilization and Judeo-Christian values.” (Source: http://www.americanheritage.org/the_problem.html)');
INSERT INTO badge_level_requirements VALUES(157,24,'preschool',1,'Citizenship & Government: What sort of government does the United States of America have? Learn what the Declaration of Independence, the Constitution and the Bill of Rights are. What are the basic rights of American citizens? What are the basic obligations? How can you be a good American citizen?');
INSERT INTO badge_level_requirements VALUES(158,24,'level1',2,'What does “American Heritage” mean? Learn what the term involves and think about the ways in which the United States of America has become American rather than being English, French, Spanish or German. Think about the motto of the United States “E Pluribus Unum” and what it means. How can we preserve America’s Heritage? According to the Heritage Foundation: “Unlike countries governed by the sword under dictatorship or state-controlled systems, America was formed and built on the ideas and ideals of individual rights and the four key themes of Freedom, Unity, Progress, and Responsibility — themes that originate in our Declaration of Independence, U. S. Constitution, and other primary documents and in philosophical ideas and ideals commonly grounded in the study of Western Civilization and Judeo-Christian values.” (Source: http://www.americanheritage.org/the_problem.html)');
