INSERT INTO badge_level_requirements VALUES(528,73,'preschool',0,'Learn what a bead is. Look at different types of beads and discuss the differences. What are they made of? How do the colors differ? How do the shapes differ? What about size? How big are the holes?');
INSERT INTO badge_level_requirements VALUES(529,73,'preschool',1,'Make a piece of beaded jewelry.');
INSERT INTO badge_level_requirements VALUES(530,73,'level1',2,'Be able to identify at least 6 types of beads such as glass, plastic, stone, crystal, dough; as well as natural materials such as stone, wood, seeds, or shells.');
INSERT INTO badge_level_requirements VALUES(531,73,'level1',3,'Make your own beads. These can be made of paper, dough, pine nuts, wood, etc.');
INSERT INTO badge_level_requirements VALUES(532,73,'level2',4,'Find out what crimp beads are and how they are used.');
INSERT INTO badge_level_requirements VALUES(533,73,'level2',5,'Learn about the history of beads. What were they made of? How were they used?');
INSERT INTO badge_level_requirements VALUES(534,73,'level3',6,'Learn about the different types of string used: fishing line, stretch cord, thread, etc. When should each be used?');
INSERT INTO badge_level_requirements VALUES(535,73,'level4',7,'Learn to identify and use at least three beading tools such as: Beading loom Beading needle Needle nose pliers Wire cutters Beading awl Bead scoop Thread burner Needle threader Bead mat Beeswax');
INSERT INTO badge_level_requirements VALUES(536,73,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(537,74,'preschool',0,'What do honey bees look like?  Find some pictures of honey bees or go to a place that has honey bees that you can look at.');
INSERT INTO badge_level_requirements VALUES(538,74,'preschool',1,'Know how to keep from being stung by a bee and what to do for a bee sting.  Know what gear is necessary in beekeeping.');
INSERT INTO badge_level_requirements VALUES(539,74,'level1',2,'Know what constitutes a colony of bees and how they live.');
INSERT INTO badge_level_requirements VALUES(540,74,'level2',3,'Read a book or pamphlet on the bee, and tell your club about it. Know how nectar is gathered, stored, and how the honeycomb is built.');
INSERT INTO badge_level_requirements VALUES(541,74,'level3',4,'Know the diseases of bees and some of the things that destroy colonies. How can you help sick bees?');
INSERT INTO badge_level_requirements VALUES(542,74,'level4',5,'Know the life cycle of a bee and the parts of their hive. Be able to recognize and describe each of the following: Queen Drone Worker Egg Larva Pupa Honey Wax Pollen Brood nest Comb Queen cells Bee glue');
INSERT INTO badge_level_requirements VALUES(543,74,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(544,75,'preschool',0,'Understand what the Bible is. Understand the difference between the Old and New Testament.');
INSERT INTO badge_level_requirements VALUES(545,75,'level1',1,'Memorize the names of the books of the Old Testament.');
INSERT INTO badge_level_requirements VALUES(546,75,'level2',2,'Also memorize the names of the books of the New Testament.');
INSERT INTO badge_level_requirements VALUES(547,75,'level2',3,'Learn about the history of the Bible through books, films, online, or in a museum or class setting. Make sure you know how old scholars think the first books are and when people started printing Bibles.');
INSERT INTO badge_level_requirements VALUES(548,75,'level3',4,'Learn about the different Bible translations such as NKJV, NIV, ESV, etc. How are they different? Select three verses from the Bible and write them down from three different translations.');
INSERT INTO badge_level_requirements VALUES(549,75,'level4',5,'Memorize at least 10 verses of the Bible. Write them on a piece of paper and recite them to your family or troop.');
INSERT INTO badge_level_requirements VALUES(550,75,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(553,77,'preschool',0,'Learn what a bicycle is. How is it different from a tricycle? Be able to identify wheels, handlebars, pedals, and the chain. Have your bicycle inspected for safety.');
INSERT INTO badge_level_requirements VALUES(554,77,'preschool',1,'Know the basic safety rules for riding your bike. Learn to ride a bicycle with training wheels – be able to start, stop, and turn in both directions. Level 1: Do four requirements including the the two starred *');
INSERT INTO badge_level_requirements VALUES(555,77,'preschool',2,'Learn to ride a bicycle without training wheels – be able to start, stop, and turn in both directions.');
INSERT INTO badge_level_requirements VALUES(556,77,'level2',3,'Find out the rules of the road for bicyclers. Make sure you know who has the right of way; where you are allowed to ride and in which directions. Know all the hand signals needed for riding on public roads and trails.');
INSERT INTO badge_level_requirements VALUES(557,77,'level2',4,'Define and identify the following parts of a bicycle: Rim Air valve Seat post Chain Sprockets Brakes Brake pads Inner tube Gears Learn how to make basic bicycle repairs (including changing a tire) and how to keep your bicycle clean, rust free, lubricated, and properly adjusted.');
INSERT INTO badge_level_requirements VALUES(558,77,'level3',5,'Plan an all-day bicycle trip. Map out where you are going. Consider safety issues. Be sure to carry a first aid kit, emergency tool kit, and food and water.');
INSERT INTO badge_level_requirements VALUES(559,77,'level4',6,'Be able to teach a younger person how to change a bicycle tire.');
INSERT INTO badge_level_requirements VALUES(560,77,'level4',7,'Avoiding main highways, take two rides of 10 miles each. You must make a report of the rides taken. List dates, routes traveled, and interesting things seen. Make sure you bring a first aid kit, emergency tool kit, food, water, and a cell phone if possible.');
INSERT INTO badge_level_requirements VALUES(561,77,'level5',8,'Take two rides of 15 miles each.');
INSERT INTO badge_level_requirements VALUES(562,77,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(563,78,'preschool',0,'Give your little sibling something from when you were little, such as a toy, blanket, clothing, etc.');
INSERT INTO badge_level_requirements VALUES(564,78,'preschool',1,'Play a game with your sibling, such as a board game, dolls or hide-and-seek.');
INSERT INTO badge_level_requirements VALUES(565,78,'level1',2,'Tell or read a story to your sibling.');
INSERT INTO badge_level_requirements VALUES(566,78,'level2',3,'Teach your sibling something that you know how to do but they have never done before. This could include baking cookies, riding a bike, or playing a sport.');
INSERT INTO badge_level_requirements VALUES(567,78,'level3',4,'Do a craft project with your sibling, such as making a scrapbook together or sewing an item of clothing.');
INSERT INTO badge_level_requirements VALUES(568,78,'level4',5,'Together with your sibling, make a family tree. It should extend at least three generations.');
INSERT INTO badge_level_requirements VALUES(569,78,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(572,80,'preschool',0,'Know what biology is the study of.');
INSERT INTO badge_level_requirements VALUES(573,80,'preschool',1,'Learn about the life cycle of a frog. If possible and with a parent’s permission, visit a pond or creek where tadpoles and frogs can be seen in person. If you can’t see them in person, look at pictures in book or online with a parent.');
INSERT INTO badge_level_requirements VALUES(574,80,'level1',2,'Understand the difference between a reptile, amphibian, mammal, insect, fish, and bird. What are the characteristics of each?');
INSERT INTO badge_level_requirements VALUES(575,80,'level2',3,'Memorize the seven classifications: Kingdom Phylum/Division Class Order Family Genus Species. Be able to explain why they are important. Why are the classifications Life and Domain not widely used yet?');
INSERT INTO badge_level_requirements VALUES(576,80,'level3',4,'Be able to explain how the process of photosynthesis works.');
INSERT INTO badge_level_requirements VALUES(577,80,'level4',5,'Identify the following parts of the cell structure and be able to explain what role they play in the cell. Create a 3D model of a specific cell type: Cell wall Cell membrane Cytoplasm Ribosomes Organelles Nucleus Mitochondria Golgi apparatus Endoplasmic reticulum Microtublules Lysosomes Vacuoles.');
INSERT INTO badge_level_requirements VALUES(578,80,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(579,81,'preschool',0,'Watch a video or look at pictures of glowing animals or plants like fireflies, jellyfish, or glowing fungi.');
INSERT INTO badge_level_requirements VALUES(580,81,'preschool',1,'Do a glow-in-the-dark craft or experiment with glow sticks in a dark room.');
INSERT INTO badge_level_requirements VALUES(581,81,'level1',2,'Identify at least five different bioluminescent organisms and where they live (e.g., fireflies, anglerfish, comb jellies, fungi, and krill).');
INSERT INTO badge_level_requirements VALUES(582,81,'level2',3,'Learn how bioluminescence is used by animals (for example: to attract mates, defend against predators, or lure prey)');
INSERT INTO badge_level_requirements VALUES(583,81,'level3',4,'Learn about the history of how humans discovered and studied bioluminescence, from early firefly observations to deep-sea exploration.');
INSERT INTO badge_level_requirements VALUES(584,81,'level4',5,'Learn how bioluminescence works at the chemical level. Create a diagram showing how the reaction between luciferin and luciferase produces light.');
INSERT INTO badge_level_requirements VALUES(585,81,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(588,83,'preschool',0,'Learn what bird-watching is. Be able to identify three different species of birds.');
INSERT INTO badge_level_requirements VALUES(589,83,'preschool',1,'For a week make a list of the birds you see in your yard. What are the most common?');
INSERT INTO badge_level_requirements VALUES(590,83,'level1',2,'Be able to identify five different species of birds.');
INSERT INTO badge_level_requirements VALUES(591,83,'level1',3,'Birds “communicate” by songs and calls. Learn to identify three different birds by their songs or calls.');
INSERT INTO badge_level_requirements VALUES(592,83,'level2',4,'Be able to identify seven different species of birds.');
INSERT INTO badge_level_requirements VALUES(593,83,'level2',5,'Learn how to use a bird identification book for your area. Understand what migration, range, in the wild, endangered and habitat mean. In the book, find five birds that you see in your area.');
INSERT INTO badge_level_requirements VALUES(594,83,'level3',6,'Be able to identify nine different species of birds.');
INSERT INTO badge_level_requirements VALUES(595,83,'level3',7,'How does a bird fly? What part do the tail, wings and head play in how it flies? Learn about the skeletal structure of birds. How is this different from animals? Observe different kinds of birds in flight. How do they differ in how they fly? Why do you think this is?');
INSERT INTO badge_level_requirements VALUES(596,83,'level4',8,'Be able to identify twelve different species of birds.');
INSERT INTO badge_level_requirements VALUES(597,83,'level4',9,'Go bird-watching for a day, either at a local park, national park, forest, sanctuary, or anywhere else where you can spot different types of birds. Find and identify at least ten types of birds in their natural habitat.');
INSERT INTO badge_level_requirements VALUES(598,83,'level5',10,'Be able to identify fifteen different species of birds.');
INSERT INTO badge_level_requirements VALUES(599,83,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(601,85,'preschool',0,'Learn two board games that are new to you. The games should all be of a different type. Choose from: Strategy Party Word Puzzle Role playing game (RPG) Knowledge Trivia Chance Mazes Educational Cooperative play Sports/racing or others not listed');
INSERT INTO badge_level_requirements VALUES(602,85,'preschool',1,'Teach a favorite board game to an adult.');
INSERT INTO badge_level_requirements VALUES(603,85,'level1',2,'Learn three new board games.');
INSERT INTO badge_level_requirements VALUES(604,85,'level1',3,'Discuss with a parent or leader who should put away the game and why: the loser, the winner, or everyone who played? What is proper board game etiquette before, during, and after play? How do you decide who goes first?');
INSERT INTO badge_level_requirements VALUES(605,85,'level2',4,'Learn four new board games. Discuss with a parent or leader whether you think it is a good idea to let a little kid win a board game. Why or why not?');
INSERT INTO badge_level_requirements VALUES(606,85,'level2',5,'Learn the different types of board games and what their names mean. List an example of each type: Strategy Party Word Puzzle Role playing game (RPG) Knowledge Trivia Chance Mazes Educational Cooperative play Sports/racing or others not listed');
INSERT INTO badge_level_requirements VALUES(607,85,'level3',6,'Learn five new board games.');
INSERT INTO badge_level_requirements VALUES(608,85,'level3',7,'Create your own board game centered on a topic of interest to you.');
INSERT INTO badge_level_requirements VALUES(609,85,'level4',8,'Learn six new board games.');
INSERT INTO badge_level_requirements VALUES(610,85,'level4',9,'Learn the history board games and learn to play a board game from another culture or early civilization. Examples may include Chess, Checkers, Parcheesi, Mancala, Backgammon or another board game of your choice.');
INSERT INTO badge_level_requirements VALUES(611,85,'level5',10,'Learn seven new board games.');
INSERT INTO badge_level_requirements VALUES(612,85,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(613,87,'preschool',0,'Where is your body part located in the body? What does it look like?');
INSERT INTO badge_level_requirements VALUES(614,87,'preschool',1,'What is the purpose of your body part?  What does it do? (Preschool kids should have a general idea of what their body part does while older kids should understand in more detail.)');
INSERT INTO badge_level_requirements VALUES(615,87,'level1',2,'Can you do anything to help take better care of your specific body part? For example, reduce screen time for eyes or eat a high fiber diet for your colon.');
INSERT INTO badge_level_requirements VALUES(616,87,'level2',3,'What body system does your body part belong to and why?  What part does it play in that system?  How does your body part work?  Do a science experiment that has something to do with your body part such as simulating how it works.');
INSERT INTO badge_level_requirements VALUES(617,87,'level3',4,'Learn about common disorders and diseases associated with your body part and how they affect your body part.');
INSERT INTO badge_level_requirements VALUES(618,87,'level4',5,'What type of doctor specializes in your body part? What type of education did they need? What does a typical day look like? What do they like about their job?');
INSERT INTO badge_level_requirements VALUES(619,88,'preschool',0,'Learn what bookbinding is. It is the way in which the pages of the book and its covers are held together. Books may be held together with thread, glue, staples, ribbons, etc. Look at a variety of books that are bound using at least three different methods.');
INSERT INTO badge_level_requirements VALUES(620,88,'preschool',1,'Make a simple “book” by folding paper and stapling or tying it together. Decorate your cover.');
INSERT INTO badge_level_requirements VALUES(621,88,'level1',2,'Learn five vocabulary words related to bookbinding such as spine, folio, signature, endpaper, and binding.');
INSERT INTO badge_level_requirements VALUES(622,88,'level2',3,'Learn about the history of bookbinding, including early methods such as scrolls, codices, and hand-sewn books.');
INSERT INTO badge_level_requirements VALUES(623,88,'level3',4,'Create a book using a stitched binding method such as pamphlet stitch or Japanese stab binding.');
INSERT INTO badge_level_requirements VALUES(624,88,'level4',5,'Be able to identify at least seven different book binding methods.');
INSERT INTO badge_level_requirements VALUES(625,88,'level4',6,'Learn about at least three different types of bookbinding (e.g., perfect binding, case binding, coptic stitch). Try one new technique.');
INSERT INTO badge_level_requirements VALUES(626,88,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(627,89,'preschool',0,'Know what a book club is.');
INSERT INTO badge_level_requirements VALUES(628,89,'preschool',1,'Create a book club, or join one,  with one or more friends.  Choose a book that you and your friends would like to read and read it.  Talk to your friends about they did or did not like about the book.');
INSERT INTO badge_level_requirements VALUES(629,89,'level1',2,'Complete Preschool requirements 1 and 2.   Read at least two books with your club.');
INSERT INTO badge_level_requirements VALUES(630,89,'level1',3,'Know and have good book club etiquette for example be respectful of others opinions. Try to pick books you think everyone will enjoy reading.');
INSERT INTO badge_level_requirements VALUES(631,89,'level2',4,'Complete Level 1 requirements 1 and 2. What are the pros and cons of being in a book club versus reading alone?');
INSERT INTO badge_level_requirements VALUES(632,89,'level2',5,'What are the pros and cons of being in a book club versus reading alone?');
INSERT INTO badge_level_requirements VALUES(633,89,'level3',6,'Complete Level 2 requirements 1 and 2. What is the history of book clubs?');
INSERT INTO badge_level_requirements VALUES(634,89,'level3',7,'Learn about different types of book clubs.');
INSERT INTO badge_level_requirements VALUES(635,89,'level4',8,'Complete Level 3 requirements 1 and 2.');
INSERT INTO badge_level_requirements VALUES(636,89,'level4',9,'Explore the history and evolution of book clubs.');
INSERT INTO badge_level_requirements VALUES(637,89,'level5',10,'Complete Level 4 requirements 1 and 2.');
INSERT INTO badge_level_requirements VALUES(638,89,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional requirements.');
INSERT INTO badge_level_requirements VALUES(639,90,'preschool',0,'Choose a book to read and learn about. Read it yourself or have it read to you. Every time you come across a word you are not familiar with, write it down and learn the definition. At the end of the book count all your new vocabulary words and see how many you learned. Do you still remember what they all mean?');
INSERT INTO badge_level_requirements VALUES(640,90,'preschool',1,'Find at least three lessons, skills, or new ideas that can be learned from your book and discuss them with an adult.');
INSERT INTO badge_level_requirements VALUES(641,90,'level1',2,'Create a costume or art project that represents your book.');
INSERT INTO badge_level_requirements VALUES(642,90,'level2',3,'Write a short story about one or more of the characters in your book.');
INSERT INTO badge_level_requirements VALUES(643,90,'level3',4,'Learn about the time period or location of your book. How do things like fashion, technology, transportation, and home life differ from yours?');
INSERT INTO badge_level_requirements VALUES(644,90,'level4',5,'Read a short biography about the author and make a list of other books they have written.');
INSERT INTO badge_level_requirements VALUES(645,90,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(646,91,'preschool',0,'Learn three different types of books. For example, picture books, children books, and chapter books. How are they similar? What makes the different?');
INSERT INTO badge_level_requirements VALUES(647,91,'preschool',1,'Learn what an author is.');
INSERT INTO badge_level_requirements VALUES(648,91,'level1',2,'and also define a hero in your own words. What makes a hero? How do they add to the story? Is the main character always a hero?');
INSERT INTO badge_level_requirements VALUES(649,91,'level1',3,'Write a short story.');
INSERT INTO badge_level_requirements VALUES(650,91,'level2',4,'Learn what the following words mean and how they impact a story. protagonist antagonist mentor plot climax genre tone point of view');
INSERT INTO badge_level_requirements VALUES(651,91,'level3',5,'What are chapters for in books? How do they effect the book/story? Do you think it has more to do than just layout? Why or why not? What are 3 ways chapters are used in books? Will you name or number them? Do all books have chapters? What kind of books do and don’t?');
INSERT INTO badge_level_requirements VALUES(652,91,'level3',6,'Write a book at least 10 chapters long. When you are done, look back at the use of chapters. How and when did you use them? What for? breaks? drama? suspense?');
INSERT INTO badge_level_requirements VALUES(653,91,'level4',7,'Your book must be at least 15 chapters.');
INSERT INTO badge_level_requirements VALUES(654,91,'level4',8,'What is an editor? What do they do and how can you find one to edit your book?  For now, self edit and revise your book.  Clean up plot holes, fix grammar errors, etc.  Then have one or more people read your book and provide critiques.  A first draft is always going to need editing, so be open to critiques that you may or may not like. Based on those critiques, revise and edit your book at lease one more time.  Do you notice an improvement over your first draft?  Is your book ready for publication yet, or do you think it still needs revision?');
INSERT INTO badge_level_requirements VALUES(655,91,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(656,92,'preschool',0,'What is botany? Learn about what in your area would fall under the study of botany.');
INSERT INTO badge_level_requirements VALUES(657,92,'preschool',1,'Start a plant from a seed and help care for it.');
INSERT INTO badge_level_requirements VALUES(658,92,'level1',2,'Learn about taxonomy. A fun way to do this is to do a ‘shoe taxonomy’: Gather one of every shoe in your house or from each person in your group and place into a  pile. Pick four kingdoms, two phyla for each kingdom, two classes for each phyla, two orders for each class. Study all the shoes.  What big differences separate the shoes?  The largest differences can be used to separate the shoes into your kingdoms.  Some examples: Is it a special occasion shoe?  Is it an everyday shoe?  How do you put it on? Once you have decided how they are separated, divide your shoes into those groups. What is different about each shoe in each kingdom? Continue separating the shoes like this until you get down to a class for each shoe.');
INSERT INTO badge_level_requirements VALUES(659,92,'level2',3,'If you have enough shoes or other items such buttons or clothing articles, take your taxonomy all the way down to species.');
INSERT INTO badge_level_requirements VALUES(660,92,'level2',4,'Learn about vascular vs non-vascular plants. Take a look around where you live and see how many of each you can find.');
INSERT INTO badge_level_requirements VALUES(661,92,'level3',5,'Learn about angiosperms and gymnosperms. Take a look around where you live and see how many of each you can find.');
INSERT INTO badge_level_requirements VALUES(662,92,'level4',6,'Come up with a garden idea and plan it out. You could do a vegetable garden, flower garden, some sort of landscaping, etc. Determine what types of plants you would like to put in your garden and figure out what each type of plant would require for needs. Some plants like shade while others like sun. Some like sandy soil and others like wet clay soil. Some like acidic while others like it more basic. Find out what type of space requirements each plant has in order to grow up healthy.  Draft a plan on what your garden will look like. Share your plans with your family, friends, group. You might want to include pictures of the plants in your plan so others can visualize it better.');
INSERT INTO badge_level_requirements VALUES(663,92,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(664,93,'preschool',0,'Learn what bouldering is and learn the safety rules involved to keep yourself safe both while climbing as well as when watching from below.');
INSERT INTO badge_level_requirements VALUES(665,93,'preschool',1,'Climb on a small artificial climbing wall.');
INSERT INTO badge_level_requirements VALUES(666,93,'level1',2,'Know the proper clothing and safety gear you should wear and have present when bouldering and come prepared when you climb. How do climbing shoes differ from your normal everyday shoes? What is chalk used for? What is a crash mat?');
INSERT INTO badge_level_requirements VALUES(667,93,'level2',3,'Climb at least three different routes on a rock face or climbing wall.');
INSERT INTO badge_level_requirements VALUES(668,93,'level2',4,'Describe the types of hazards you may encounter when bouldering that could pose a risk to your safety. Explain how you can anticipate, prevent and mitigate the dangers involved in bouldering. Consider things such as the weather, visibility, stability of the climbing surface, other people in the area, animals, etc.');
INSERT INTO badge_level_requirements VALUES(669,93,'level3',5,'Learn and follow Leave No Trace rules for bouldering outdoors.');
INSERT INTO badge_level_requirements VALUES(670,93,'level4',6,'Know first aid for common basic injuries that can occur when bouldering including: Cuts and abrasions Blisters Sprains Fractures Snake bites Insect bites and stings Know how to be prepared to summon aid in case of an emergency.');
INSERT INTO badge_level_requirements VALUES(671,93,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(672,94,'preschool',0,'What is bowling? Play at least one game. If you cannot play a real game of bowling play a digital version.');
INSERT INTO badge_level_requirements VALUES(673,94,'preschool',1,'Learn the safety and etiquette rules of bowling.');
INSERT INTO badge_level_requirements VALUES(674,94,'level1',2,'What are “bumpers”?  What are they used for?  If possible, play a game with bumpers.');
INSERT INTO badge_level_requirements VALUES(675,94,'level2',3,'What do the following terms mean: strike, spare, split, miss, foul.');
INSERT INTO badge_level_requirements VALUES(676,94,'level3',4,'Learn how scoring works in bowling. What is a 300 in bowling?  How do you get a 300?');
INSERT INTO badge_level_requirements VALUES(677,94,'level4',5,'What is the difference between scratch and handicap?');
INSERT INTO badge_level_requirements VALUES(678,95,'preschool',0,'What is braille? Why is it important? Who needs it?');
INSERT INTO badge_level_requirements VALUES(679,95,'preschool',1,'Find out who created braille and why.');
INSERT INTO badge_level_requirements VALUES(680,95,'level1',2,'Learn how braille was created and what it was originally based on. Learn more about Louis Braille’s background and how he created the “braille code.”');
INSERT INTO badge_level_requirements VALUES(681,95,'level2',3,'Learn and be able to write the first ten letters of the braille alphabet. These letters also correspond to numbers 0-9.');
INSERT INTO badge_level_requirements VALUES(682,95,'level3',4,'Also learn the next ten letters in the braille alphabet.');
INSERT INTO badge_level_requirements VALUES(683,95,'level3',5,'Research the various braille tools, how they are used and how they have evolved over the years. These may include: a slate and stylus, a braille typewriter, an electronic Brailler (or eBrailler), braille embosser, etc.');
INSERT INTO badge_level_requirements VALUES(684,95,'level4',6,'Learn the final letters of the braille alphabet and be able to write the entire alphabet on a piece of paper.');
INSERT INTO badge_level_requirements VALUES(685,95,'level4',7,'Read at least one paragraph in braille.');
INSERT INTO badge_level_requirements VALUES(686,95,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(687,96,'preschool',0,'Sample three different breads. What makes a good bread?');
INSERT INTO badge_level_requirements VALUES(688,96,'preschool',1,'How should bread be stored? How long does it last? Compare store bread and a homemade or artisan bread for storage.');
INSERT INTO badge_level_requirements VALUES(689,96,'level1',2,'and 2.');
INSERT INTO badge_level_requirements VALUES(690,96,'level1',3,'What is yeast? Proof yeast? How should yeast be stored? Why should you proof it?');
INSERT INTO badge_level_requirements VALUES(691,96,'level2',4,'Taste five different types of bread');
INSERT INTO badge_level_requirements VALUES(692,96,'level2',5,'Bake a loaf of bread. Learn to knead dough. At what internal temperature is the bread done? How long should it sit before slicing?');
INSERT INTO badge_level_requirements VALUES(693,96,'level3',6,'Bake a loaf of bread with simple ingredients (water, yeast, salt, flour) and a sandwich bread. Which do you prefer?');
INSERT INTO badge_level_requirements VALUES(694,96,'level3',7,'Learn what gluten is and why most bread needs it. What grains have gluten? What other grains than wheat can make bread?');
INSERT INTO badge_level_requirements VALUES(695,96,'level4',8,'Taste seven different types of bread.');
INSERT INTO badge_level_requirements VALUES(696,96,'level4',9,'Learn the history of bread and bread baking.');
INSERT INTO badge_level_requirements VALUES(697,96,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(698,97,'preschool',0,'Know what Breyer horses are and be able to identify the logo of Breyer Animal Creations.');
INSERT INTO badge_level_requirements VALUES(699,97,'preschool',1,'Find out how to properly care for and clean your Breyer models.');
INSERT INTO badge_level_requirements VALUES(700,97,'level1',2,'and 2.');
INSERT INTO badge_level_requirements VALUES(701,97,'level1',3,'What is a scale and how does it refer to Breyer animals? Name the current and past scales Breyer uses along with their brand names (some may have more than one name). Look at one or more horses or animals from each size category. Certain scales Breyer no longer produces, such as Paddock Pals.');
INSERT INTO badge_level_requirements VALUES(702,97,'level2',4,'and 2.');
INSERT INTO badge_level_requirements VALUES(703,97,'level2',5,'What is the difference between a mold and model? How many Traditional molds does Breyer come out with a year through its Premier Collection?');
INSERT INTO badge_level_requirements VALUES(704,97,'level3',6,'and 2. Name at least 4 sculptors that made at least one mold for Breyer.');
INSERT INTO badge_level_requirements VALUES(705,97,'level3',7,'Learn about the different types of Breyers, which include, but are not limited to: Regular Runs Limited Editions Series (such as the Berry Ponies, Wild Animals, or Big Cats) Test Runs Event Models');
INSERT INTO badge_level_requirements VALUES(706,97,'level4',8,'and 2. What is the history of Breyer?');
INSERT INTO badge_level_requirements VALUES(707,97,'level4',9,'Find out how Breyer makes its models. What can Breyers be made of?');
INSERT INTO badge_level_requirements VALUES(708,97,'level5',10,'and 2.');
INSERT INTO badge_level_requirements VALUES(709,97,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(712,99,'preschool',0,'.  Learn what a monarch is, and where Britain is. Know who the present monarch of Great Britain is, and be able to recognize them from a picture.');
INSERT INTO badge_level_requirements VALUES(713,99,'level1',1,'.  Do preschool requirement 1*.');
INSERT INTO badge_level_requirements VALUES(714,99,'level1',2,'.  Know the difference between absolute monarchy and constitutional monarchy. Which does Britain have?');
INSERT INTO badge_level_requirements VALUES(715,99,'level2',3,'.  Do Level 1 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(716,99,'level2',4,'.  Look at a family tree of the British royal family. John of Gaunt was never king, but he plays an important part in the history of the royal family and the succession. Learn who are the next 10 people in line after the current Queen.');
INSERT INTO badge_level_requirements VALUES(717,99,'level3',5,'.  Do Level 2 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(718,99,'level3',6,'.  Learn about the British Royal Family today. What are some of the duties of a monarch in Britain? What are the duties of the younger members of the Royal Family?');
INSERT INTO badge_level_requirements VALUES(719,99,'level4',7,'.  Do Level 3 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(720,99,'level4',8,'.  Make a timeline of all British monarchs from 800 AD onward (Britain has been ruled by monarchs ever since the British people migrated there, but 800 AD is where many historians start.)');
INSERT INTO badge_level_requirements VALUES(721,99,'level5',9,'.  Do Level 4 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(722,99,'level5',10,'.  Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(723,100,'preschool',0,'Learn how to properly blow bubbles using either a purchased or homemade bubble solution.');
INSERT INTO badge_level_requirements VALUES(724,100,'level1',1,'Make your own homemade bubble solution. Mix 3 tablespoons of liquid detergent such as Dawn or Joy with 1 cup of water and 1/2 teaspoon of glycerin (available at most pharmacies).');
INSERT INTO badge_level_requirements VALUES(725,100,'level2',2,'Learn the science behind bubbles. How do they hold their shape? What is surface tension? Why do bubbles float instead of fall? What causes them to pop? What role does glycerin or corn syrup play in the recipe?');
INSERT INTO badge_level_requirements VALUES(726,100,'level3',3,'Learn about a unique way that bubbles are used in our world. Examples may include using bubbles to clean up oil or other spills in our seas, humpback whales using bubbles herd fish, or scientists using bubbles to study black holes.');
INSERT INTO badge_level_requirements VALUES(727,100,'level4',4,'Learn about 3 different famous economic bubbles such as the Housing Bubble of the 2000’s, the Stock Market Bubble of the 1920’s, the Tulip Bubble in the Netherlands in the 1600’s, Japan’s “Bubble Economy” of the 1980’s, or the South Sea Bubble of the 1700’s. Why are these economic situation called bubbles? What was the result when each one “popped”?');
INSERT INTO badge_level_requirements VALUES(728,100,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(729,101,'preschool',0,'Understand wants verses needs. Make a chart with needs on one side and wants on the other. Then for each of the following categories, think of something that would classify as a need and something that would be a want.  For example, food is necessary to life. In the need column you might put “fresh fruits and veggies”, while in the want column you might put “candy bars.” Do this for each of the following categories: Food Clothing Transportation Shelter Entertainment You may also fulfill this requirement by playing a simple game of sorting needs verses wants like the one outlined below. Place two paper bags on the floor; one labeled “NEEDS” and one labeled “WANTS.” On a set of note cards, glue pictures of a variety of items you would purchase including both wants and needs such as fruit, candy bars, plain t-shirts, expensive licensed shirts, etc. Then sort the cards into the proper bag. You can play this game in teams if you wish by creating two sets of the game and seeing which team can sort the wants and needs correctly the fastest. If a card is not sorted correctly discuss why this item was placed there.');
INSERT INTO badge_level_requirements VALUES(730,101,'level1',1,'Learn how to save money. Create three different piggy banks. One marked SPEND, one marked SAVE, and one marked GIVE. Decide how much of your allowance, or other money received, should go into each bank. The money in the SPEND bank you may spend whenever, and however you wish. The money in the SAVE bank is money that is to be saved to large purchases in the future. For example, if you want to buy your own computer or a future car. The GIVE bank is a portion of your money set aside to donate to charity, your church or another good cause. A sample percentage for the three banks would be 50% SPEND, 40% SAVE and 10% GIVE.');
INSERT INTO badge_level_requirements VALUES(731,101,'level2',2,'With your family or troop, plan a small party. Set a budget for food, decorations, invitations, and entertainment. With a parent or adult, learn to make sure all the needs of the party are met while deciding which parts of the party are the most important to you and will receive more money than the others. For example, maybe it is important to you to have fancy invitations delivered through the mail, or maybe you are fine with a quick phone call or email as an invitation. Which costs more? On what do you want to spend the most money and where can you save on the other items?');
INSERT INTO badge_level_requirements VALUES(732,101,'level3',3,'You cannot budget your money if you do not know how much you have. Learn to balance a check book or bank register properly.  Know how to keep track of purchases that have not been deducted from your account yet.');
INSERT INTO badge_level_requirements VALUES(733,101,'level4',4,'Choose a career and find out what the average salary is. Create a monthly household budget using this salary. Research each category below to find out what your average monthly expense would be. Where can you afford to live? How much extra do you have for food and entertainment? How will you get to your job? Taxes Rent/mortgage Utilities (electricity, gas, water, sewer, garbage) Phone Transportation Food Entertainment (TV, Internet, movies, books, etc.) Clothing Household items (furniture, home décor, cleaning supplies, etc.) Insurance (renter’s/house, car, health, etc) Pets Charitable giving');
INSERT INTO badge_level_requirements VALUES(734,101,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(735,102,'preschool',0,'Learn to identify what a buffalo looks like.');
INSERT INTO badge_level_requirements VALUES(736,102,'preschool',1,'Draw a picture or make a craft about the buffalo.');
INSERT INTO badge_level_requirements VALUES(737,102,'level1',2,'When first discovered by the Europeans in North America, what was the buffalo population? Why did the population fall to near extinction? What is the population now?');
INSERT INTO badge_level_requirements VALUES(738,102,'level2',3,'What role did the buffalo play with Native Americans? Find out where buffaloes lived and where they live now.');
INSERT INTO badge_level_requirements VALUES(739,102,'level3',4,'Identify three different types of buffalo. How are they different?');
INSERT INTO badge_level_requirements VALUES(740,102,'level4',5,'Read a book about buffaloes.');
INSERT INTO badge_level_requirements VALUES(741,102,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(742,103,'preschool',0,'Play store using pretend money. Practice buying and selling a few items.');
INSERT INTO badge_level_requirements VALUES(743,103,'preschool',1,'Identify coins and dollar bills. Practice sorting them by size and value.');
INSERT INTO badge_level_requirements VALUES(744,103,'level1',2,'Practice making change using coins and small bills with help from an adult.');
INSERT INTO badge_level_requirements VALUES(745,103,'level2',3,'Learn what sales tax is and how much it is where you live. Learn how to calculate sales tax and total cost on a purchase using a calculator.');
INSERT INTO badge_level_requirements VALUES(746,103,'level3',4,'Explain revenue and expenses.  Discuss what types of expenses a business might have.  Learn to calculate profit by subtracting expenses from income using simple examples.');
INSERT INTO badge_level_requirements VALUES(747,103,'level4',5,'Create a basic business budget including expected income and expenses.');
INSERT INTO badge_level_requirements VALUES(748,103,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(749,104,'preschool',0,'Find out why they are called “Cabbage Patch Kids.”');
INSERT INTO badge_level_requirements VALUES(750,104,'preschool',1,'With a friend or family member, play with your Cabbage Patch Kid(s).');
INSERT INTO badge_level_requirements VALUES(751,104,'level1',2,'Who invented Cabbage Patch Kids and when? Why are they “adopted?”');
INSERT INTO badge_level_requirements VALUES(752,104,'level2',3,'Make a timeline of how Cabbage Patch Kids have changed over the years. Include important events, pricing changes, outfit changes, etc, and make sure your timeline has at least 10 items.');
INSERT INTO badge_level_requirements VALUES(753,104,'level3',4,'Several different companies throughout the years have acquired the rights to Cabbage Patch Kids. What were these companies and who currently owns the rights to Cabbage Patch Kids?');
INSERT INTO badge_level_requirements VALUES(754,104,'level4',5,'Design and make an outfit for your Cabbage Patch Kid.');
INSERT INTO badge_level_requirements VALUES(755,104,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(756,105,'preschool',0,'Learn what cake decorating is. There are many different methods of decorating a cake: piped icing, rolled icing, whipped cream, sprinkled sugar, etc. Look in cook books and see how many different types of cake decoration you can find.');
INSERT INTO badge_level_requirements VALUES(757,105,'preschool',1,'Help make a cake, frost it, and decorate it for a specific event (birthday, holiday, party, etc).');
INSERT INTO badge_level_requirements VALUES(758,105,'level1',2,'Learn how to properly use a cake decorating bag.');
INSERT INTO badge_level_requirements VALUES(759,105,'level1',3,'Learn what at least 3 of the following tips are used for and learn to use one properly: Round – for writing, stems, trim and dots Star – fill-in, rosette border, shell border Drop Flower – daisy type flower, twisted flower Leaf – various leaves Rose – rose, rose bud');
INSERT INTO badge_level_requirements VALUES(760,105,'level2',4,'Learn to prepare the two basic icings: buttercream and royal. What is the difference between the two and what are the pros and cons of each?');
INSERT INTO badge_level_requirements VALUES(761,105,'level3',5,'Color icing using liquid food coloring; then color some using solid food coloring. What is the difference between the two and what are the pros and cons of each?');
INSERT INTO badge_level_requirements VALUES(762,105,'level4',6,'Be able to identify each of the following cake decorating tools and explain what they are used for: Turntable Tapered spatula Pastry bag Pastry tips Decorating comb Short offset spatula Long offset spatula Straight spatula Cake board Stencils Icing smoother Pastry bag couplers Flour sifter.');
