INSERT INTO badge_level_requirements VALUES(776,107,'preschool',0,'Understand what calligraphy is. Look at some examples of calligraphy and discuss it with your troop.');
INSERT INTO badge_level_requirements VALUES(777,107,'preschool',1,'Watch someone do calligraphy, whether it be in person, online or on television, with a parent’s permission.');
INSERT INTO badge_level_requirements VALUES(778,107,'level1',2,'Make sure you know what the following terms mean: Felt-tip calligraphy pen Fountain pen Dip pen Nibs Ink cartridges Opaque Proportion Vertical Horizontal 30- to-45 degree angle.');
INSERT INTO badge_level_requirements VALUES(779,107,'level1',3,'Learn the parts of a letter: strokes, serifs, ascenders, and descenders. Practice the basic strokes for a sans serif alphabet until you can do them correctly. Before you start writing the whole alphabet, learn the importance of correct spacing and letter heights. Write out your name.');
INSERT INTO badge_level_requirements VALUES(780,107,'level2',4,'What are quills, ink wells, India ink, and watercolors?');
INSERT INTO badge_level_requirements VALUES(781,107,'level2',5,'After practicing the sans serif strokes, practice some strokes for a cursive alphabet.');
INSERT INTO badge_level_requirements VALUES(782,107,'level2',6,'Write out a complete sans serif alphabet.');
INSERT INTO badge_level_requirements VALUES(783,107,'level3',7,'Write a complete sans serif alphabet and the Roman alphabet.');
INSERT INTO badge_level_requirements VALUES(784,107,'level3',8,'Write out a complete cursive alphabet.');
INSERT INTO badge_level_requirements VALUES(785,107,'level4',9,'Experiment with five different nibs.');
INSERT INTO badge_level_requirements VALUES(786,107,'level4',10,'Write out a complete cursive alphabet and an ornate alphabet such as Old English.');
INSERT INTO badge_level_requirements VALUES(787,107,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(788,108,'preschool',0,'Learn/understand what it means to go camping! Go on an overnight camp out with your family or troop. Learn the safety rules you need for the place where you will be sleeping out and the safety rules for any equipment you will be using. Make sure you follow the Leave Not Trace rule (Leave no trace that you were ever there. The campsite should be as clean, or cleaner, than when you arrived and nothing should be damaged. Never pick anything that is still alive, including flowers, leaves, grass, etc.)');
INSERT INTO badge_level_requirements VALUES(789,108,'level1',1,'Learn how to treat basic camping injuries including scratches, small cuts, bug bites, and minor burns.');
INSERT INTO badge_level_requirements VALUES(790,108,'level2',2,'Learn how to correctly pitch and take down a tent. With another member or non-adult, demonstrate how to put up and take down your tent. Make sure you also learn to correctly fold it and pack it away.');
INSERT INTO badge_level_requirements VALUES(791,108,'level2',3,'and also include heat exhaustion, sunburn, and blisters. Level 3: Do six requirements including the the two starred *');
INSERT INTO badge_level_requirements VALUES(792,108,'level2',4,'Teach a younger person how to pitch and take down a tent as well.');
INSERT INTO badge_level_requirements VALUES(793,108,'level2',5,'and also include heat stroke, dehydration, snakebite, sprained or broken limbs.');
INSERT INTO badge_level_requirements VALUES(794,108,'level4',6,'Design and pitch a shelter or lean-to using only a tarp and a rope. You may use wood found near your campsite as stakes (no live wood). Discuss what you could make bedding out of using natural items found nearby. Remember the Leave No Trace rule and do not actually create the bedding, simply look around to see what you could use if there was an emergency.');
INSERT INTO badge_level_requirements VALUES(795,108,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(796,109,'preschool',0,'Where is Canada? Learn who the Indigenous people of Canada are. What do they call themselves in their own language? Prior to colonization, how did they live? What did they live in? What did they wear? What did they eat? How did they make things?');
INSERT INTO badge_level_requirements VALUES(797,109,'preschool',1,'When did Europeans first start exploring Canada?');
INSERT INTO badge_level_requirements VALUES(798,109,'level1',2,'What was Canada’s relationship with Britain? What was the Canadian Federation and who were the Fathers of Confederation?');
INSERT INTO badge_level_requirements VALUES(799,109,'level2',3,'Also be able to explain the difference between First Nations, Inuit and Métis people.');
INSERT INTO badge_level_requirements VALUES(800,109,'level2',4,'Make a timeline of at least eight items in Canadian history.');
INSERT INTO badge_level_requirements VALUES(801,109,'level3',5,'Include at least twelve items on your timeline.');
INSERT INTO badge_level_requirements VALUES(802,109,'level3',6,'Learn about at least five wars that Canada has fought in, including the War of 1812 and WWII. What was Canada’s impact on the Second World War?');
INSERT INTO badge_level_requirements VALUES(803,109,'level4',7,'Include at least fifteen items on your timeline.');
INSERT INTO badge_level_requirements VALUES(804,109,'level4',8,'Learn what order various provinces joined Canada in. Who joined last? Why did the various provinces decide to join?');
INSERT INTO badge_level_requirements VALUES(805,109,'level5',9,'Include at least twenty items on your timeline.');
INSERT INTO badge_level_requirements VALUES(806,109,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(807,110,'preschool',0,'Learn what a candle is. How is it different from other items that burn? (Like a campfire, gas stove, etc).');
INSERT INTO badge_level_requirements VALUES(808,110,'preschool',1,'Demonstrate and understand proper safety procedures when working around hot wax and candles. Some safety procedures include: Wear loose clothing. If you are wearing tight clothes and wax splashes you it will be in immediate contact with your skin. Tie back any long hair and secure it to make sure that it does not accidentally end up in hot wax, or a flame. If wax gets on your skin, run it under cold water immediately – then peel off the wax. Never leave the melting container unattended when melting wax. Keep all pot handles pointed away from you so that they are not accidentally bumped. Never pour wax down the drain as it will clog the drain. Never leave a lit candle unattended. Always extinguish candles before they reach the bottom of the wick. Never reach over a lit candle or leave a lit candle where it might get bumped. Never place a lit candle on a shelf or surface that has another shelf directly above it.');
INSERT INTO badge_level_requirements VALUES(809,110,'level1',2,'Be able to identify at least three different types of candles. Make at least one. Examples might include: Votive Tapers Pillars Rolled Cut and Peeled Gel Candles Tea Lights Container Candles Sculpted Candles Birthday Candles Sand Candles Ice Candles Hurricanes Oil Candles Molded Candles.');
INSERT INTO badge_level_requirements VALUES(810,110,'level2',3,'Be able to identify at least four types of candles. Demonstrate proper first aid for minor and major burns.');
INSERT INTO badge_level_requirements VALUES(811,110,'level2',4,'Learn about at least three different types of wick and what type of candle they are used for.');
INSERT INTO badge_level_requirements VALUES(812,110,'level3',5,'Be able to identify at least five types of candles.');
INSERT INTO badge_level_requirements VALUES(813,110,'level3',6,'Learn about the history of candles and how they have been made over the years.');
INSERT INTO badge_level_requirements VALUES(814,110,'level4',7,'Be able to identify at least six types of candles,');
INSERT INTO badge_level_requirements VALUES(815,110,'level4',8,'Learn about the different types of wax used in candles and what type each is good for.');
INSERT INTO badge_level_requirements VALUES(816,110,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(817,111,'preschool',0,'Help make a no-cook candy, such as the Oreo Truffles recipe listed at the bottom of the page.');
INSERT INTO badge_level_requirements VALUES(818,111,'level1',1,'Make lollipop recipe of some type (chocolate, hard candy, truffle on a stick, etc.)  A simple recipe can be found at the bottom of the page.');
INSERT INTO badge_level_requirements VALUES(819,111,'level2',2,'Learn the difference between chocolate and melt-able candy coatings and understand the pros and cons of each. Demonstrate the proper way to melt each, either in a microwave or double boiler. Explain what causes chocolate to seize and how you can avoid it.');
INSERT INTO badge_level_requirements VALUES(820,111,'level3',3,'Understand what each of the following terms mean and at approximately what temperature each occurs: Thread Stage Soft – Ball Stage Firm – Ball Stage Hard – Ball Stage Soft – Crack Stage Hard – Crack Stage');
INSERT INTO badge_level_requirements VALUES(821,111,'level4',4,'Be able to identify and explain how to use of each of the following tools: Dipping spoon and dipping fork Candy thermometer Candy molds Lollipop molds Pastry bag and tips Decorating brushes Double boiler Parchment paper');
INSERT INTO badge_level_requirements VALUES(822,111,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(823,112,'preschool',0,'Know what a canoe is and be able to recognize one when a picture is shown to you. Know the difference between a canoe and a kayak. Learn the safety rules for being in and around a canoe.');
INSERT INTO badge_level_requirements VALUES(824,112,'preschool',1,'Wearing a properly fitted PFD (personal flotation device), take a short ride in a canoe.');
INSERT INTO badge_level_requirements VALUES(825,112,'level1',2,'Learn the basics of paddling and help an adult paddle a canoe.');
INSERT INTO badge_level_requirements VALUES(826,112,'level1',3,'Be able to name and point out the major parts of a canoe and paddle.');
INSERT INTO badge_level_requirements VALUES(827,112,'level2',4,'Learn proper paddling techniques and demonstrate the following solo canoe handling: Launch from a dock or the shore (both if possible) Paddle a canoe straight Turn right Turn left Back up Turn in a circle Stop a canoe');
INSERT INTO badge_level_requirements VALUES(828,112,'level2',5,'Safely land a canoe on shore as well as dock if possible. In both instances, show the proper way to secure a canoe so that it does not drift off.');
INSERT INTO badge_level_requirements VALUES(829,112,'level3',6,'Learn how to right a tipped canoe, re-enter and empty the swamped canoe.');
INSERT INTO badge_level_requirements VALUES(830,112,'level4',7,'Learn how to paddle in tandem with another person. Explain how paddling must adapt in order to steer correctly.');
INSERT INTO badge_level_requirements VALUES(831,112,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(832,113,'preschool',0,'Watch a race in person or on TV of your chosen type of car racing.');
INSERT INTO badge_level_requirements VALUES(833,113,'preschool',1,'Be able to identify your type of race car compared to at least three other race car types.');
INSERT INTO badge_level_requirements VALUES(834,113,'level1',2,'Learn about the history of your type of car racing. When and where did it begin? How have the cars changed?');
INSERT INTO badge_level_requirements VALUES(835,113,'level2',3,'Find out where your type of car racing takes place. Where are the most popular tracks? Locate them on a map. How many races do they have each year?');
INSERT INTO badge_level_requirements VALUES(836,113,'level3',4,'Learn about at least three drivers for your type of car racing. Who do they drive for? What is their current standing? How many races have they won? Recognize their colors and sponsors.');
INSERT INTO badge_level_requirements VALUES(837,113,'level4',5,'Understand how sponsorship works. Know the top 10 sponsors of your type of car racing. Why would a company want to spend so much money to have their name on a race car? How can a company maximize their return for their sponsorship dollars?');
INSERT INTO badge_level_requirements VALUES(838,113,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(841,115,'preschool',0,'Explore different types of cardboard (thin, thick, corrugated). Touch and bend each one.');
INSERT INTO badge_level_requirements VALUES(842,115,'preschool',1,'Make something out of cardboard—like a mask, house, crown, or animal—with adult help.');
INSERT INTO badge_level_requirements VALUES(843,115,'level1',2,'Build something with cardboard that stands up on its own. Try a tower, car, or animal and explain how you made it strong.');
INSERT INTO badge_level_requirements VALUES(844,115,'level2',3,'Learn where cardboard comes from and how it’s made. Visit a recycling center, paper mill, or watch a video about cardboard production.');
INSERT INTO badge_level_requirements VALUES(845,115,'level3',4,'Learn about the history of cardboard. When was it invented? How did it become a common packaging material?');
INSERT INTO badge_level_requirements VALUES(846,115,'level4',5,'Explore how cardboard is used in emergency shelters, sustainable architecture, or humanitarian design. Create a model or presentation of one such use.');
INSERT INTO badge_level_requirements VALUES(847,115,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(850,117,'preschool',0,'Learn what a community is. What type of jobs do people do to help make a community thrive?');
INSERT INTO badge_level_requirements VALUES(851,117,'preschool',1,'Learn about at least three different jobs that make your community work, either by reading about them or by visiting an actual work place.');
INSERT INTO badge_level_requirements VALUES(852,117,'level1',2,'Think about four different jobs you might like to have as a grown up in your community. Read books or watch age-appropriate documentaries with a parent’s permission to learn about  these four different occupations. Ask a parent or caregiver to read the books to you, or read the book on your own. You may also visit people who work in these jobs.');
INSERT INTO badge_level_requirements VALUES(853,117,'level2',3,'and 2, but increase the number of occupations/careers you learn about to 5.');
INSERT INTO badge_level_requirements VALUES(854,117,'level2',4,'Visit at least two places of work that you learned about. For example, visit a police station, a bakery, a veterinarian’s office, or the fire station. Call ahead to make sure your visit is expected and acceptable during business hours. If possible, arrange for someone  to give you a tour and/or answer questions.');
INSERT INTO badge_level_requirements VALUES(855,117,'level3',5,'Visit at least three work places.');
INSERT INTO badge_level_requirements VALUES(856,117,'level3',6,'Find someone who works in at least three of the jobs you learned about. Ask each worker at least four questions about the work they do. For example, you could ask about their training, their responsibilities, the challenges and rewards for choosing this kind of work. Take notes as the answers are given. You may also choose to record the responses and type them out later. Remember to be a good listener and to thank the person for taking time to talk to you. Ask for permission to take a photo of the worker and his work place. When you have finished all your interviews, use the photos and the interview responses to create a photo journal showing what you have learned.');
INSERT INTO badge_level_requirements VALUES(857,117,'level4',7,'Take a free online career placement test. What were your results?');
INSERT INTO badge_level_requirements VALUES(858,117,'level4',8,'Brainstorm a list of careers you’d like to learn about or that you think would be a good fit for you in the future. Narrow your choices to two. Interview a person who works in each of these two careers. Ask at least 5-7 well thought out questions. Be sure to ask how this person got started in this career and why they chose it. Record the answers you get on paper or with an audio recording device so you can write them down later. Be a good listener and share your information with your family, friends, or group. If you prefer, make a video of your interview and learn to edit it before presenting. Research the kind of training and/or education needed for the two careers you chose. Locate two schools for each career that provide this training/education. Compare the costs of these two schools. Are there any prerequisites before starting this training? If so, what are they? Make a list of things you can be doing now to prepare yourself for the training you need to acquire for these 2 occupations. Consider the skills, knowledge, experience and funds you could begin to gather.');
INSERT INTO badge_level_requirements VALUES(859,117,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(860,118,'preschool',0,'Where are carrots most commonly grown? What country grows the most? What US state grows the most? What season are carrots grown in?');
INSERT INTO badge_level_requirements VALUES(861,118,'preschool',1,'Eat carrots three different ways, such as cooked, raw, steamed, etc. What was your favorite way?');
INSERT INTO badge_level_requirements VALUES(862,118,'level1',2,'Make a list of reasons why carrots are good for you. Your list should include at least five things.');
INSERT INTO badge_level_requirements VALUES(863,118,'level2',3,'Draw the growing cycle of a carrot, from the time the seed is planted up until it is pulled from the ground. About how long does it take for a carrot to fully grow?');
INSERT INTO badge_level_requirements VALUES(864,118,'level3',4,'Grow your own carrots. If you can, grow several varieties. Take notes and observe them through the process. Once they’ve grown, taste them. How does their taste compare to supermarket carrots?');
INSERT INTO badge_level_requirements VALUES(865,118,'level4',5,'Make three different recipes that emphasize carrots. Which one was your favorite?');
INSERT INTO badge_level_requirements VALUES(866,118,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(867,119,'preschool',0,'Look at pictures of at least 10 different cars spanning at least 100 years.');
INSERT INTO badge_level_requirements VALUES(868,119,'preschool',1,'Be able to identify the differences between a car, a pick up truck, and a sport utility vehicle.');
INSERT INTO badge_level_requirements VALUES(869,119,'level1',2,'Discuss why there are so many different types of cars.  What are the advantages of one style over another for any given purpose?  Compare a modern car to a vintage car.  What changes have been made over the years?');
INSERT INTO badge_level_requirements VALUES(870,119,'level2',3,'Find out who the “Big Three” car manufacturers were and what their first cars were.');
INSERT INTO badge_level_requirements VALUES(871,119,'level3',4,'Create a timeline that highlights at least 15 important events in the history of the automobile.  Check out our blog post 9 Fun timeline Activities to Make History Come Alive.');
INSERT INTO badge_level_requirements VALUES(872,119,'level4',5,'Discuss the role of the automobile in your community?  Do you live in a rural area where pick up trucks are needed?  Or in the city where small fuel efficient cars are the norm?  Does your community encourage individual car ownership, or use of public transportation?  How have communities changed over time due to the automobile?');
INSERT INTO badge_level_requirements VALUES(873,119,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(874,120,'preschool',0,'Understand what cartography means.  Discuss why maps are important and the different types of maps people use.');
INSERT INTO badge_level_requirements VALUES(875,120,'preschool',1,'Draw a simple map of your bedroom, showing where the bed, toys, and other furniture are located.');
INSERT INTO badge_level_requirements VALUES(876,120,'level1',2,'Learn about common map symbols such as trees, houses, and rivers. Create your own symbols and use them to draw a simple map of an imaginary place.');
INSERT INTO badge_level_requirements VALUES(877,120,'level2',3,'Learn how to read and interpret maps, including using the scale, legend and compass.   How can you locate items on a map using a grid?');
INSERT INTO badge_level_requirements VALUES(878,120,'level3',4,'Study at least 3 different types of maps, such as topographic maps, political maps, and weather maps.  Make a map of your own that shows something of interest to you such as the best fishing spots on a lake, or a topographic map of  your favorite hiking trail to show where it is steep and where it is flat.');
INSERT INTO badge_level_requirements VALUES(879,120,'level4',5,'Learn about the history of cartography and its role in shaping the world.');
INSERT INTO badge_level_requirements VALUES(880,120,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(881,121,'preschool',0,'Watch at least 3 different styles of cartoons and talk to a parent or other adult about what makes them different. Examples might include original Disney cartoons, Pixar animation, Japanese anime, educational cartoons, Looney Tunes, superhero cartoons, etc. How do the styles differ? Which do you prefer and why?');
INSERT INTO badge_level_requirements VALUES(882,121,'level1',1,'Design your own cartoon character. Will it be a person? An animal? What is their personality? What setting would their cartoon take place in? Is it designed for print or TV & movies?');
INSERT INTO badge_level_requirements VALUES(883,121,'level2',2,'What is a voice-over? Find out who does the voices for 3 of your favorite cartoon characters. How is sound added to a cartoon?');
INSERT INTO badge_level_requirements VALUES(884,121,'level3',3,'Make at least ten different sound effects and share them with your family, friends, or troop. A minimum of five of these must be made with something other than your voice. See if your friends can guess what each sound should be. Examples of sounds you might wish to try are a train going down the tracks; a horse galloping; a rocket blasting off; a pile of books crashing to the ground; a trash can getting knocked over; or a duck call. Use your imagination. Find out how some of these sounds are actually created in motion cartoons.');
INSERT INTO badge_level_requirements VALUES(885,121,'level4',4,'Find out how movie and TV cartoons are made. How has technology changed the way cartoons are produced? Do your prefer hand drawn animation or digital?');
INSERT INTO badge_level_requirements VALUES(886,121,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(887,122,'preschool',0,'Learn what a castle is and what makes it different from other types of buildings.');
INSERT INTO badge_level_requirements VALUES(888,122,'preschool',1,'Look at pictures of at least 6 different real castles.');
INSERT INTO badge_level_requirements VALUES(889,122,'level1',2,'What is the difference between a castle, a palace and a fortress?');
INSERT INTO badge_level_requirements VALUES(890,122,'level2',3,'Complete a diagram of a typical castle.  Make sure to include the following items and understand the meaning of each: TowersBattlementsMoatBarbiconPortcullisDrawbridgeBaileyArrow Loops');
INSERT INTO badge_level_requirements VALUES(891,122,'level3',4,'Learn about the history of castles. When did they first start to appear and why? Where have most of the castles in the world been built?');
INSERT INTO badge_level_requirements VALUES(892,122,'level4',5,'Find 10 castles that are still standing today.  Locate them on a map.  Who built each of them and why?  How old are they?');
INSERT INTO badge_level_requirements VALUES(893,122,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(894,123,'preschool',0,'What are male and female cats called? What are baby cats called? What is a group of cats called?');
INSERT INTO badge_level_requirements VALUES(895,123,'preschool',1,'Learn how to properly behave around cats and how to hold them so that neither you nor the cat gets hurt.');
INSERT INTO badge_level_requirements VALUES(896,123,'level1',2,'Be able to identify four different breeds of cats, describing their physical characteristics and personalities.');
INSERT INTO badge_level_requirements VALUES(897,123,'level2',3,'Identify 5 different breeds.');
INSERT INTO badge_level_requirements VALUES(898,123,'level2',4,'Know what type of food cats need. What specific nutrients do they need to be healthy? How much should you feed them, and how often? Compare three different types of cat foods. Which one would you feed your cat based on the ingredients and nutritional information?');
INSERT INTO badge_level_requirements VALUES(899,123,'level3',5,'Identify 6 different breeds.');
INSERT INTO badge_level_requirements VALUES(900,123,'level3',6,'Know at least three feline diseases, listing the symptoms and treatment for each.');
INSERT INTO badge_level_requirements VALUES(901,123,'level4',7,'Identify 7 different breeds.');
INSERT INTO badge_level_requirements VALUES(902,123,'level4',8,'Know how to properly groom a cat. What differences are there in grooming long-haired cats and short-haired cats? What grooming is required for a Sphinx cat?');
INSERT INTO badge_level_requirements VALUES(903,123,'level5',9,'Identify 8 different breeds.');
INSERT INTO badge_level_requirements VALUES(904,123,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(905,124,'preschool',0,'What is a ceramic? Find three different pictures or examples of ceramic. Be able to recognize a piece of ceramic such as pottery.');
INSERT INTO badge_level_requirements VALUES(906,124,'preschool',1,'Does your family own any ceramics? Know your family’s rules when it comes to handling ceramics. Are you allowed to touch or hold them? If you drop a ceramic item and it breaks, don’t touch the pieces, stay where you are and call for an adult to help you.');
INSERT INTO badge_level_requirements VALUES(907,124,'level1',2,'While this badge deals mostly with ceramics called pottery and the things a person would study in a ceramics art class, it is important to know that ceramics are used for a lot of other things. Find ten different things made from ceramics in your house or neighborhood: Dinnerware Glassware Spark plugs Bricks Floor tiles Electronic circuits Cement Porcelain toilets, sinks or bathtubs Windows Light bulbs Lenses Roof tiles Drain pipes Abrasives/grinding materials.');
INSERT INTO badge_level_requirements VALUES(908,124,'level1',3,'Find a book or website (with parent’s permission) that explains the three main techniques used to hand build ceramics (pinch, coil & slab) and if you cannot practice them with actual clay, practice making things using at least two of the methods with some type of play dough.');
INSERT INTO badge_level_requirements VALUES(909,124,'level2',4,'Air dry one of your pieces to see how it turns out. How well did it work? Should you do something different in the future?');
INSERT INTO badge_level_requirements VALUES(910,124,'level2',5,'Learn about the history of ceramics by reading a book, visiting a website (with parental permission) or visiting a museum with a large collection of pottery. If you visit the museum, learning about either the history of pottery in general or a detailed history of pottery in just one culture is fine.');
INSERT INTO badge_level_requirements VALUES(911,124,'level3',6,'Make at least one article out of clay using one of the methods mentioned in Level 1 requirement 2 and have it fired. If your article breaks or you haven’t mastered that particular technique, make a second piece. If you don’t apply a glaze to your piece, then you need to decorate the surface in another fashion.');
INSERT INTO badge_level_requirements VALUES(912,124,'level4',7,'Discuss with someone who uses ceramics in the workplace the importance of those ceramics listed in Level 1 requirement 1.');
INSERT INTO badge_level_requirements VALUES(913,124,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(914,125,'preschool',0,'Paint a ceramic object such as a figurine, tile, or small dish using non-toxic paints.');
