INSERT INTO badge_level_requirements VALUES(918,125,'level3',4,'Learn about glaze and underglaze. Paint a piece that uses at least one of these.');
INSERT INTO badge_level_requirements VALUES(919,125,'level4',5,'Learn about the history of ceramic painting in one culture, such as Chinese porcelain, Greek pottery, or Mexican Talavera tiles.');
