INSERT INTO badge_level_requirements VALUES(922,126,'preschool',1,'Create a piece of art using chalk. Learn how to preserve your creation.');
INSERT INTO badge_level_requirements VALUES(923,126,'level2',2,'Study the history of chalk. Name several uses for chalk besides writing/drawing.');
INSERT INTO badge_level_requirements VALUES(924,126,'level3',3,'Learn how chalk is mined. Where does it come from?');
