INSERT INTO badge_level_requirements VALUES(926,126,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(927,127,'preschool',0,'Choose a favorite character from a book, movie, show, game, real life, or your own imagination. Learn their name and where they come from. Discuss why you chose to learn about this character. What makes them special?');
INSERT INTO badge_level_requirements VALUES(928,127,'preschool',1,'Find out if your character appears on any products for sale such as tshirts, lunch boxes, or toys.  If not, what do you wish they would make with your character on it?');
INSERT INTO badge_level_requirements VALUES(929,127,'level1',2,'Create a character profile page with facts, traits, favorite quotes, and a drawing or image of your chosen character.');
INSERT INTO badge_level_requirements VALUES(930,127,'level2',3,'Create something that shows your character’s world—draw a picture, build it in blocks or Minecraft, or make a diorama, map, or collage.');
INSERT INTO badge_level_requirements VALUES(931,127,'level3',4,'Learn about the history or background of your character. When and how were they created? Who invented or portrayed them? How have they changed over time? If your character is real, what is their life story or timeline?');
INSERT INTO badge_level_requirements VALUES(932,127,'level4',5,'Learn about how characters are protected by copyright or trademark laws. Discuss why it’s important to give credit to creators and follow rules when using characters someone else created. Learn about “fair use” and how using a character for educational or personal projects differs from selling licensed products commercially.');
INSERT INTO badge_level_requirements VALUES(933,127,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(938,130,'preschool',0,'Learn who Charles Dickens was, and when he lived.');
INSERT INTO badge_level_requirements VALUES(939,130,'preschool',1,'Read/have someone read to you a children’s version of one of Dickens’ books. Who is your favorite character?');
INSERT INTO badge_level_requirements VALUES(940,130,'level1',2,'Read/have someone read to you a small book about Charles Dickens’ life. How many books did he he have published in his lifetime?');
INSERT INTO badge_level_requirements VALUES(941,130,'level2',3,'Read one of Dickens books all the way through.');
INSERT INTO badge_level_requirements VALUES(942,130,'level3',4,'If you earned this badge at a lower level, read a new book.');
INSERT INTO badge_level_requirements VALUES(943,130,'level3',5,'Make a timeline of Dickens’ life, and include any noteworthy world events that occurred during that time. You must have at least 25 items on your timeline. Show it to your family, friends, or group.');
INSERT INTO badge_level_requirements VALUES(944,130,'level4',6,'If you earned this badge at a lower level you must read a new book. You must have at least 30 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(945,130,'level4',7,'Make a list of the different ways in which Dickens drew knowledge and experience from his own life to add to his stories. What sort of impact did his stories have on popular thinking of his time?');
INSERT INTO badge_level_requirements VALUES(946,130,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(947,131,'preschool',0,'What is a cheerleader? What role do they play in sports?');
INSERT INTO badge_level_requirements VALUES(948,131,'preschool',1,'Learn basic cheerleading arm movements, like the high V, low V, touchdown, and dagger arm positions.');
INSERT INTO badge_level_requirements VALUES(949,131,'level1',2,'Learn at least three cheer jumps, like the pencil jump, tuck jump, and spread eagle jump.');
INSERT INTO badge_level_requirements VALUES(950,131,'level2',3,'Learn at least three cheerleading chants.');
INSERT INTO badge_level_requirements VALUES(951,131,'level3',4,'Learn the difference between sideline cheerleading and competitive cheerleading, and the different roles cheerleaders play in each sport.');
INSERT INTO badge_level_requirements VALUES(952,131,'level4',5,'Learn a cheerleading dance to music. How do cheerleading dances differ from typical dances?');
INSERT INTO badge_level_requirements VALUES(953,131,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(954,132,'preschool',0,'Find out what cheese is made of.');
INSERT INTO badge_level_requirements VALUES(955,132,'preschool',1,'Try at least 5 different types of cheese.');
INSERT INTO badge_level_requirements VALUES(956,132,'level1',2,'Keep a tally of how much cheese you eat in a week.  How many different types of cheese did you eat?  Make a cheese hardness chart based off the cheeses you have tried.');
INSERT INTO badge_level_requirements VALUES(957,132,'level2',3,'Try at least 8 different types of cheese.');
INSERT INTO badge_level_requirements VALUES(958,132,'level2',4,'Learn about the history of cheese.  When was it invented?  How many different cheeses are there and what regions are they from?  How was cheese used in the past compared to today?');
INSERT INTO badge_level_requirements VALUES(959,132,'level3',5,'Learn about each of the following categories of cheese and try at least one cheese from each category. Blue Hard pasta filata Processed Semi-hard Semi-soft soft and fresh soft-ripened');
INSERT INTO badge_level_requirements VALUES(960,132,'level4',6,'Make three different recipes that involve cheese;  one breakfast, one main dish, and one dessert.');
INSERT INTO badge_level_requirements VALUES(961,132,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new-found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(962,133,'preschool',0,'Taste three different kinds of cheese.');
INSERT INTO badge_level_requirements VALUES(963,133,'preschool',1,'Make a simple farmer cheese.  Learn what the term whey means.');
INSERT INTO badge_level_requirements VALUES(964,133,'level1',2,'– 2. Taste six (total) different kinds of cheese.');
INSERT INTO badge_level_requirements VALUES(965,133,'level1',3,'Make a mascarpone cheese.');
INSERT INTO badge_level_requirements VALUES(966,133,'level2',4,'-2. Taste eight (total) different kinds of cheese.');
INSERT INTO badge_level_requirements VALUES(967,133,'level2',5,'Find examples of at least one cheese in the following different categories, then make a cheese that requires rennet. Blue Hard pasta filata Processed Semi-hard Semi-soft soft and fresh soft-ripened');
INSERT INTO badge_level_requirements VALUES(968,133,'level3',6,'-2. Taste 10 (total) different kinds of cheeses, with at least one from each of the above categories.');
INSERT INTO badge_level_requirements VALUES(969,133,'level3',7,'Make whole-milk Ricotta and cook a dish with it.');
INSERT INTO badge_level_requirements VALUES(970,133,'level4',8,'Make a vegan cheese sauce');
INSERT INTO badge_level_requirements VALUES(971,133,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new-found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(972,134,'preschool',0,'What is a chef? What does a professional chef do?');
INSERT INTO badge_level_requirements VALUES(973,134,'preschool',1,'Learn the standard uniform for a chef. Find pictures of various chefs and be able to identify each part of their uniform and what it is used for. The standard uniform for a chef includes a hat, necktie, double-breasted jacket, apron, trousers and steel-toe (or plastic capped) shoes. A chef’s hat (toque) is tall to allow for the circulation of air above the head and also provides an outlet for heat. The hat assists in the prevention of sweat dripping down the face. Skullcaps are an alternative hat worn by chefs. Neckties were originally worn to allow for the mopping of sweat from the face, but as this is now against health and safety regulations, they are largely decorative. The jacket is usually white to repel heat and double-breasted to prevent serious injuries from burns and scalds. The double breast serves to conceal stains on the jacket as one side can be re-buttoned over the other. An apron is worn to just-below knee-length also to assist in the prevention of burns because of spillage. If hot liquid is spilled onto the apron, it can be quickly removed to minimize burns and scalds. Shoes are hard wearing and with a steel-top cap to prevent injury from falling objects or knives. According to some hygiene regulations, jewelry is not allowed apart from wedding bands. Additionally, bandages should be blue in order to more easily identify any that have fallen into food during preparation. Bandages on the hands are traditionally covered with rubber gloves.');
INSERT INTO badge_level_requirements VALUES(974,134,'level1',2,'How important is the setting of one’s meal to the enjoyment of the meal? Can you remember a time when you ate what was supposed to be a special meal that wasn’t very pleasant because you were too hot, too cold, sitting near an obnoxious person, the music was so loud you couldn’t converse or your table or dishes weren’t clean? Have you ever eaten a meal in the dark? Describe what you think is the perfect setting for a family dinner, a wedding reception, a child’s birthday party, and a quiet dinner out.');
INSERT INTO badge_level_requirements VALUES(975,134,'level2',3,'Learn about three different famous chefs and the types of food they cook. List five different things you learn about each and which meal of theirs you would like to try.');
INSERT INTO badge_level_requirements VALUES(976,134,'level3',4,'Know and be able to identify the following different types of chefs: Chef de cuisine, executive chef and head chef Sous-chef Chef de partie Sauté chef (saucier) Fish chef (poissonnier) Roast chef (rôtisseur) Grill chef (gaillardia) Fry chef (friturier) Vegetable chef (entremetier) Rounds man (tournant) Pantry chef (garde manger) Butcher (boucher) Pastry chef (pâtissier)');
INSERT INTO badge_level_requirements VALUES(977,134,'level4',5,'Find out about famous culinary schools. What does it take to get accepted to one? What must you be able to do to graduate? What culinary associations are there? Why might you wish to join one? Is it better to study in America or go abroad to an international school?');
INSERT INTO badge_level_requirements VALUES(978,134,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(979,135,'preschool',0,'Do a simple kitchen science experiment, such as mixing baking soda and vinegar. Watch what happens!');
INSERT INTO badge_level_requirements VALUES(980,135,'preschool',1,'Sort objects by color, texture, or size, and talk about how things can be grouped by their properties.');
INSERT INTO badge_level_requirements VALUES(981,135,'level1',2,'Mix two or more substances together and observe how they change (e.g., cornstarch and water, salt in warm water). Talk about what you see. Describe the difference between a chemical reaction and a physical change.');
INSERT INTO badge_level_requirements VALUES(982,135,'level2',3,'Learn about solids, liquids, and gases. Try an experiment or activity that shows how something can change between these forms.');
INSERT INTO badge_level_requirements VALUES(983,135,'level3',4,'Study the history of chemistry. Learn about at least one famous chemist and what they discovered.Describe three examples of safety equipment used in a chemistry laboratory and the reason each one is used. Describe what a material safety data sheet (MSDS) is and tell why it is used. Obtain an MSDS for both a paint and an insecticide. Compare and discuss the toxicity, disposal, and safe-handling sections for these two common household products. Discuss the safe storage of chemicals. How does the safe storage of chemicals apply to your home, your school, your community, and the environment?');
INSERT INTO badge_level_requirements VALUES(984,135,'level4',5,'Chemistry can be divided into roughly five different categories: General and analytical chemistry Physical chemistry Inorganic chemistry Organic chemistry Biochemistry. Be able to define each category and describe a career in which each might be used.');
INSERT INTO badge_level_requirements VALUES(985,135,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(986,136,'preschool',0,'Be able to identify all of the chess pieces and be able to demonstrate how each piece moves on a chess board.');
INSERT INTO badge_level_requirements VALUES(987,136,'preschool',1,'Correctly set up a chess board for play.');
INSERT INTO badge_level_requirements VALUES(988,136,'level1',2,'Play a game of chess (know how the games ends i.e. check, checkmate, draw, stalemate).');
INSERT INTO badge_level_requirements VALUES(989,136,'level2',3,'Play five games with someone or with the computer/internet (with parental permission).');
INSERT INTO badge_level_requirements VALUES(990,136,'level3',4,'Write a short report on the history of chess. Who invented it? Where was it invented? How did it evolve over the years?');
INSERT INTO badge_level_requirements VALUES(991,136,'level4',5,'Read about a famous chess player. If possible, look up an interview with them. Write about what you learn and share it with your family, friends, or group.');
INSERT INTO badge_level_requirements VALUES(992,136,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(993,137,'preschool',0,'Learn how to properly hold a baby. Why should you support it’s neck? Why is it important to always have an adult around when you’re holding or watching a baby?  Learn how you should safely behave around babies.');
INSERT INTO badge_level_requirements VALUES(994,137,'level1',1,'Learn how to “childproof” a room. Look for items that small children can choke on, unstable items they may pull down, open electrical plugs, cleaners, medications, or other poisonous items within reach, etc. Point out to an adult possible safety hazards to small children.');
INSERT INTO badge_level_requirements VALUES(995,137,'level1',2,'Help an adult take care of children younger than you for at least an hour. Examples might include helping in a Sunday School class or nursery, a daycare, or caring for younger siblings. You should take on as much responsibility as possible for the children’s entertainment.');
INSERT INTO badge_level_requirements VALUES(996,137,'level2',3,'Help an adult take care of children younger than you for at least 6 hours (time can be broken into one hour increments).');
INSERT INTO badge_level_requirements VALUES(997,137,'level2',4,'Role play making 911 calls. Learn to stay calm, state the problem, the age of the child, the address where you are, and the nearest cross street.');
INSERT INTO badge_level_requirements VALUES(998,137,'level3',5,'Perform at least 6 hours of child care, where you are the sole caretaker of the child/children.');
INSERT INTO badge_level_requirements VALUES(999,137,'level3',6,'Complete the Red Cross babysitter training course or the equivalent.');
INSERT INTO badge_level_requirements VALUES(1000,137,'level4',7,'Perform at least 10 hours of child care, where you are the sole caretaker of the child/children.');
INSERT INTO badge_level_requirements VALUES(1001,137,'level4',8,'What colleges or agencies in your town offer courses for daycare providers? Learn what requirements you need to do to become a professional day-care provider.  What courses do you need to take? Do they require any certification? What are the local requirements for running a daycare out of your home?');
INSERT INTO badge_level_requirements VALUES(1002,137,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
