INSERT INTO badge_level_requirements VALUES(1005,138,'level2',2,'Learn about the three most common types of childhood cancer.');
INSERT INTO badge_level_requirements VALUES(1006,138,'level3',3,'but learn about 4 types of cancer.');
INSERT INTO badge_level_requirements VALUES(1007,138,'level3',4,'Learn about how childhood cancer is diagnosed. Find out how many children are diagnosed with childhood cancer each year.');
INSERT INTO badge_level_requirements VALUES(1008,138,'level4',5,'but learn about 5 types of cancer.');
INSERT INTO badge_level_requirements VALUES(1009,138,'level4',6,'Learn about treatments for childhood cancer, specifically the types you learned about in requirement 1.');
INSERT INTO badge_level_requirements VALUES(1010,138,'level5',7,'but learn about 6 types of cancer.');
INSERT INTO badge_level_requirements VALUES(1011,138,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1012,139,'preschool',0,'Try a piece of unsweetened chocolate, dark chocolate, milk chocolate, and white chocolate. Which do you like best and why?');
