INSERT INTO badge_level_requirements VALUES(1048,144,'level5',10,'Read all of the Narnia books.');
INSERT INTO badge_level_requirements VALUES(1049,144,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1050,145,'preschool',0,'Read a book about the circus.');
