INSERT INTO badge_level_requirements VALUES(1054,145,'level2',4,'Learn about the history of the circus. How are modern circuses different from ancient times?');
INSERT INTO badge_level_requirements VALUES(1055,145,'level3',5,'Learn about three circus acts.');
INSERT INTO badge_level_requirements VALUES(1056,145,'level3',6,'Learn about the history of the circus in America. Who was P.T. Barnum? What role did he play in the American Circus?');
INSERT INTO badge_level_requirements VALUES(1057,145,'level4',7,'Learn about four circus acts.');
INSERT INTO badge_level_requirements VALUES(1058,145,'level4',8,'What concerns are there about animal cruelty and circuses? Have circuses changed the way they operate in response to the criticisms and if so, how?');
INSERT INTO badge_level_requirements VALUES(1059,145,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1060,146,'preschool',0,'Learn what it means to be a good citizen in your home or classroom. Discuss things like helping, sharing, and following rules.');
INSERT INTO badge_level_requirements VALUES(1061,146,'preschool',1,'Be able to recognize the American flag.  Know the proper respect that should be shown to our flag.');
INSERT INTO badge_level_requirements VALUES(1062,146,'level1',2,'Learn the Pledge of Allegiance and what each line means.');
INSERT INTO badge_level_requirements VALUES(1063,146,'level2',3,'Know your rights and duties as an American citizen. Why is voting so important? Know the names of the President, Vice President and the Governor of your state. Level 3: Do six requirements including the the two starred *');
INSERT INTO badge_level_requirements VALUES(1064,146,'level2',4,'In addition, know the name of the Speaker of the House and your local senator and representative.');
INSERT INTO badge_level_requirements VALUES(1065,146,'level2',5,'Learn about taxes. How many different taxes can you list? Think about income tax, sales tax, gas taxes, phone taxes, property tax, etc. Where does the tax money go? Make a list of every service you can think of in your community that is funded by tax dollars (library, road maintenance, public transportation, community centers, etc.).');
INSERT INTO badge_level_requirements VALUES(1066,146,'level4',6,'Learn about at least five important issues that affect your state or local community. These might include things like immigration, education, taxes, infrastructure, agriculture, water rights, legalizing drugs, etc. Where do you stand on these issues? Are any of these issues coming up for a vote? If so, how would you vote and why?');
