INSERT INTO badge_level_requirements VALUES(1153,158,'preschool',0,'What is “collecting”?');
INSERT INTO badge_level_requirements VALUES(1154,158,'preschool',1,'Collect at minimum of 10 items from the same category. These could be anything from rocks, to stuffed animals, to bottle caps.');
INSERT INTO badge_level_requirements VALUES(1155,158,'level1',2,'Make a display of your collection to show to others.');
INSERT INTO badge_level_requirements VALUES(1156,158,'level2',3,'Complete Level 1 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(1157,158,'level2',4,'Learn about the category you collect. Who manufactures your items? What are they made of?  Where are they made? Where can you find them? How much do they usually cost? Are some more valuable than others?');
INSERT INTO badge_level_requirements VALUES(1158,158,'level3',5,'Complete Level 2 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(1159,158,'level3',6,'Many people collect items that are “limited editions.” Below is a list of different ways an item may be limited in its production. Find out if there are limited editions within the category you collect. Do you own any? What is the price difference between a limited item in your category and one of mass production? Limited by announced quantity, with each item numbered. Limited by announced quantity, with items not numbered. Limited by announced firing period, numbered or not numbered. Limited by year of issue, restricting the quantity to the number produced during the year of issue. Limited by an announced time period which may be more or less than one year.');
INSERT INTO badge_level_requirements VALUES(1160,158,'level4',7,'Complete Level 3 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(1161,158,'level4',8,'Find out what the job of an appraiser is all about. What type of appraiser would appraise your collection? What type of education or knowledge would they need?  While there are many appraisers of antiques, someone who specializes in novelty items may be harder to find. How much does an appraiser earn per appraisal?');
