INSERT INTO badge_level_requirements VALUES(1789,244,'preschool',0,'Learn what optometry means and what an optometrist does.  Understand why some people wear glasses.');
INSERT INTO badge_level_requirements VALUES(1790,244,'preschool',1,'Compare the of eyes in different animals.  Why do they look different than ours?  Can they see things we can’t?');
INSERT INTO badge_level_requirements VALUES(1791,244,'level1',2,'Learn how to properly care for your eyes.  Why is it important not to stare at “screens” for too long?  Why should you make sure to have good light when reading or drawing?  What can you eat that will help you retain good eyesight?');
INSERT INTO badge_level_requirements VALUES(1792,244,'level2',3,'Learn what a convex lens and a concave lens are. See how the light passes through each.');
INSERT INTO badge_level_requirements VALUES(1793,244,'level3',4,'Learn the different parts of the eye and what they do.  Understand the following: Ciliary BodyIrisAnterior ChamberPupilRodsConesCorneaLensScleraRetinaMacularVitreousOptic Nerve');
INSERT INTO badge_level_requirements VALUES(1794,244,'level4',5,'Learn about the following common eye disorders and be able to explain each: GlaucomaMacular DegenerationCataractsDiabetic RetinopathyNearsightednessFarsightednessAstigmatismColor Blindness');
INSERT INTO badge_level_requirements VALUES(1795,244,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(1796,245,'preschool',0,'Learn what a wrapping cloth is and what it is used for.  Look at pictures of several samples.');
INSERT INTO badge_level_requirements VALUES(1797,245,'preschool',1,'Wrap something using a wrapping cloth.');
INSERT INTO badge_level_requirements VALUES(1798,245,'level1',2,'Wrap two items in two different wrapping styles.');
INSERT INTO badge_level_requirements VALUES(1799,245,'level1',3,'Learn what furoshiki is and how to pronounce it.');
INSERT INTO badge_level_requirements VALUES(1800,245,'level2',4,'Wrap five items in five different wrapping styles.');
INSERT INTO badge_level_requirements VALUES(1801,245,'level2',5,'Learn about bojagi and how it differs from furoshiki.');
INSERT INTO badge_level_requirements VALUES(1802,245,'level3',6,'Wrap eight items in eight different wrapping styles.');
INSERT INTO badge_level_requirements VALUES(1803,245,'level3',7,'Learn the history of furoshiki and bojagi.  Where did it begin? Why did it decline in popularity? Why is it returning?');
INSERT INTO badge_level_requirements VALUES(1804,245,'level4',8,'Wrap ten items in ten different wrapping styles.');
INSERT INTO badge_level_requirements VALUES(1805,245,'level4',9,'Learn what Chogak bo and subo are, and make a small one of each.');
INSERT INTO badge_level_requirements VALUES(1806,245,'level5',10,'Wrap 12 items in 12 different wrapping styles.');
INSERT INTO badge_level_requirements VALUES(1807,245,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1808,246,'preschool',0,'Discuss what face painting is and reasons why someone would paint their face.');
INSERT INTO badge_level_requirements VALUES(1809,246,'preschool',1,'Have your face painted by someone who knows how to face paint.');
INSERT INTO badge_level_requirements VALUES(1810,246,'level1',2,'and have your face painted in at least two different styles.');
INSERT INTO badge_level_requirements VALUES(1811,246,'level1',3,'Discuss face painting styles., such as glamorous, animal face, clown face, etc.');
INSERT INTO badge_level_requirements VALUES(1812,246,'level2',4,'and know the types of paints that can and can’t be used for face painting.');
INSERT INTO badge_level_requirements VALUES(1813,246,'level2',5,'Learn how face painting has been used in different cultures and across history. Look at pictures of Native Americans, Indians, clowns, hunters, sports figures, etc.');
INSERT INTO badge_level_requirements VALUES(1814,246,'level3',6,'and know how to properly remove face paint.');
INSERT INTO badge_level_requirements VALUES(1815,246,'level3',7,'Learn about how face painting is used in movies or TV. Paint your face or someone else’s face with a simple design using at least three colors.');
INSERT INTO badge_level_requirements VALUES(1816,246,'level4',8,'Paint your face or someone else’s face with a complex design using 5 or more colors.');
INSERT INTO badge_level_requirements VALUES(1817,246,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1818,247,'preschool',0,'Read (or have read to you)  a story about a fairy. Be able to describe a fairy.');
INSERT INTO badge_level_requirements VALUES(1819,247,'level1',1,'Fairies abound in books, movies, poems, plays, and TV. Make a list of at least five different fairies, each from a different story/play/movie and be able to explain who they are and what their purpose is.');
INSERT INTO badge_level_requirements VALUES(1820,247,'level2',2,'Your list should include ten fairies.');
INSERT INTO badge_level_requirements VALUES(1821,247,'level2',3,'Design your own fairy. This can be a drawing or in 3D art. Describe in detail what type of fairy she is. What will you name him or her? What is their personality like? Why are they dressed the way they are? Where does they live?');
INSERT INTO badge_level_requirements VALUES(1822,247,'level3',4,'Your list should include fifteen fairies.');
INSERT INTO badge_level_requirements VALUES(1823,247,'level3',5,'Learn about the stories of at least five types of fairy folk from around the world such as: The English Brownie The Leprechauns of Ireland The Water Sprites of Scandinavia The Tennin of Japan The Menehune of Hawaii The Norse Elves The Arabian Jinn');
INSERT INTO badge_level_requirements VALUES(1824,247,'level4',6,'Research the history of fairy related art. Look at pictures of fairy art from at least three different time periods and three different styles.');
INSERT INTO badge_level_requirements VALUES(1825,247,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirement:');
INSERT INTO badge_level_requirements VALUES(1826,248,'preschool',0,'Learn what a fairy garden is.');
INSERT INTO badge_level_requirements VALUES(1827,248,'preschool',1,'Learn about the different ways fairy gardens can be constructed (ex: on a tree, in a container…).');
INSERT INTO badge_level_requirements VALUES(1828,248,'level1',2,'Design a fairy garden. This can be a list, diagram, collage, or drawing.');
INSERT INTO badge_level_requirements VALUES(1829,248,'level2',3,'Build your own fairy garden. Your fairy garden should include at least one plant, and a structure.');
INSERT INTO badge_level_requirements VALUES(1830,248,'level3',4,'Your fairy garden should also include one piece of furniture.');
INSERT INTO badge_level_requirements VALUES(1831,248,'level3',5,'Learn about small plants that are best for a fairy garden. If possible, visit a nursery to see examples of different plants. Learn about the difference between indoor and outdoor plants.');
INSERT INTO badge_level_requirements VALUES(1832,248,'level4',6,'Your fairy garden should also include a bridge.');
INSERT INTO badge_level_requirements VALUES(1833,248,'level4',7,'Create a unique feature of your choosing for your fairy garden. Examples include creating a picnic area, constructing a mini tent, and making a flag or bunting.');
INSERT INTO badge_level_requirements VALUES(1834,248,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1835,249,'preschool',0,'Read, or have read to you, at least five different fairy tales.');
INSERT INTO badge_level_requirements VALUES(1836,249,'level1',1,'Compare two or more different versions of the same fairy tale. How do the stories differ? Which do you like better?');
INSERT INTO badge_level_requirements VALUES(1837,249,'level2',2,'Rewrite a traditional fairy tale, but set it in modern times.');
INSERT INTO badge_level_requirements VALUES(1838,249,'level3',3,'Learn about the Brothers Grimm and Hans Christian Anderson. Read at least three of the original fairy tales from each. How do their stories differ from the way they are presented today by groups like Disney?');
INSERT INTO badge_level_requirements VALUES(1839,249,'level4',4,'Read at least two fables and two myths. Learn what the difference is between a fable, a myth and a fairy tale. Which do you like better and why?');
INSERT INTO badge_level_requirements VALUES(1840,249,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1843,251,'preschool',0,'Know the first and last names of each member of your family.');
INSERT INTO badge_level_requirements VALUES(1844,251,'preschool',1,'Discuss what role each person in your family plays. What are their responsibilities?');
INSERT INTO badge_level_requirements VALUES(1845,251,'level1',2,'Know the names of your cousins, aunts, uncles, and grandparents.');
INSERT INTO badge_level_requirements VALUES(1846,251,'level1',3,'Where did your ancestors come from and how long has your family been in America?');
INSERT INTO badge_level_requirements VALUES(1847,251,'level2',4,'With a parent, discuss different types of families. Examples might include traditional two parent married families; not married parents; single parents; divorced parents; grandparents raising grandchildren; adoption, etc. What are the pros and cons of each family type? Discuss why you should always be kind to everyone regardless of what type of family they come from.');
INSERT INTO badge_level_requirements VALUES(1848,251,'level3',5,'Based on your family heritage, what health issues might you, or your descendants, have to deal with?');
INSERT INTO badge_level_requirements VALUES(1849,251,'level4',6,'Find out what government or charitable agencies there are in your community that help families. What help do they provide? How can people find out about their services? What education and training is needed to work for one of these agencies?');
INSERT INTO badge_level_requirements VALUES(1850,251,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1851,252,'preschool',0,'What does fantasy mean?');
INSERT INTO badge_level_requirements VALUES(1852,252,'preschool',1,'Be able to identify at least five fantasy creatures. Examples might include a unicorn, kirin, or troll.');
INSERT INTO badge_level_requirements VALUES(1853,252,'level1',2,'Be able to identify at least ten fantasy creatures.');
INSERT INTO badge_level_requirements VALUES(1854,252,'level1',3,'Read or have read to you a fantasy book.');
INSERT INTO badge_level_requirements VALUES(1855,252,'level2',4,'Be able to identify at least fifteen fantasy creatures.');
INSERT INTO badge_level_requirements VALUES(1856,252,'level2',5,'Fantasy occurs in every culture. Its history is rooted in various mythologies, religions and superstitions. Research some of the stories from different cultures around the world that originated one or more of your favorite fantasy creatures. For example, you might read about creatures like leprechauns from Ireland, pegasus from ancient Greece, fairies from Scotland, or elves from Germany.');
INSERT INTO badge_level_requirements VALUES(1857,252,'level3',6,'Be able to identify at least twenty fantasy creatures. Read two fantasy books.');
INSERT INTO badge_level_requirements VALUES(1858,252,'level3',7,'Learn about a fantasy creature of your choice. See how many times in media (books, movies, art, ect.) it’s used. Create a timeline of how that creature has changed over the years and how it might appear differently in other cultures.');
INSERT INTO badge_level_requirements VALUES(1859,252,'level4',8,'Be able to identify at least twenty-five fantasy creatures. Read three fantasy books.');
INSERT INTO badge_level_requirements VALUES(1860,252,'level4',9,'Learn how fantasy is important in today’s world.');
INSERT INTO badge_level_requirements VALUES(1861,252,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1862,253,'preschool',0,'Be able to identify at least five different farm animals. Examples might include: pigs, goats, sheep, cows, chickens, rabbits, ducks, emu, alpacas, etc.  Choose a farm animal and be able to tell what it is raised for (meat, wool, milk, etc.).');
INSERT INTO badge_level_requirements VALUES(1863,253,'preschool',1,'Learn and obey the safety rules for being near farm animals.');
INSERT INTO badge_level_requirements VALUES(1864,253,'level1',2,'Choose a farm animal and know what a male, female, and baby is called.  If there is a name for a neutered male, or group of this animal, know that too.');
INSERT INTO badge_level_requirements VALUES(1865,253,'level2',3,'Make a craft that has something to do with your chosen animal. Examples might include one of the following: A 3D diorama of how your animal should be housed. Make pins of your animal to trade. A poster or booklet about your animal.');
INSERT INTO badge_level_requirements VALUES(1866,253,'level3',4,'Explain how to properly feed, house and care for your animal.');
INSERT INTO badge_level_requirements VALUES(1867,253,'level4',5,'Know the most common diseases for your animal and how to prevent or treat them.');
INSERT INTO badge_level_requirements VALUES(1868,253,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1869,254,'preschool',0,'What is a farm? Know what kind of things you could find on a farm.');
INSERT INTO badge_level_requirements VALUES(1870,254,'preschool',1,'Read a book or watch a movie on farmers or a farm. Was the farm that you saw or was described like what you imagined a farm would be? Why or why not?');
INSERT INTO badge_level_requirements VALUES(1871,254,'level1',2,'Visit and tour a small family farm. What chores do the children in the family have if there are any? How do they prepare the soil, plant or tend their crops or stock. If you are unable to visit an actual farm, watch a video about small farmers, or have an adult help you look up information on the internet.');
INSERT INTO badge_level_requirements VALUES(1872,254,'level1',3,'Compare what you learned about a small family farm to large corporate farms. If you are unable to visit one, you can watch a video about large farms, or have an adult help you look information up at either the library or on the internet.');
INSERT INTO badge_level_requirements VALUES(1873,254,'level2',4,'and 2.');
INSERT INTO badge_level_requirements VALUES(1874,254,'level2',5,'Find out what “organic” means and why these foods are better for you.');
INSERT INTO badge_level_requirements VALUES(1875,254,'level3',6,'and 2.');
INSERT INTO badge_level_requirements VALUES(1876,254,'level3',7,'Find out what fruits or vegetables are grown in your local community.  Visit a farmers market and try at least one new food.');
INSERT INTO badge_level_requirements VALUES(1877,254,'level4',8,'and 2.');
INSERT INTO badge_level_requirements VALUES(1878,254,'level4',9,'Volunteer at least six hours at a local farm.');
INSERT INTO badge_level_requirements VALUES(1879,254,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(1880,255,'preschool',0,'Learn basic farm equipment safety including: Wear seat belts whenever your ride in a truck, tractor, or other large machine. Wear appropriate clothing such as heavy boots with no baggy or loose clothing that might get caught in machinery. Make sure you wear sun protection if necessary. Wear long hair tied back or secured under a hat. If your equipment requires safety goggles or ear plugs, make sure you wear them. Always be aware of uneven ground, other equipment around you, and wandering animals or people. Listen to and obey all adults in authority. Do not operate any machinery until you have been fully trained and approved by an adult. Do not operate any machinery you are not completely comfortable with. Most states require children to be at least 16 years old before operating motorized farm equipment. If you have any questions about what you should or should not do, ask an adult!');
INSERT INTO badge_level_requirements VALUES(1881,255,'preschool',1,'Identify at least three different types of farm equipment. Examples might include a tractor, a milking machine, an ATV, a rototiller, a seeder, a sprayer, a mower, a backhoe, etc.');
INSERT INTO badge_level_requirements VALUES(1882,255,'level1',2,'Be able to identify at least four different types of farm equipment.');
INSERT INTO badge_level_requirements VALUES(1883,255,'level1',3,'Make a list of as many different types of farm equipment as you can think of (at least ten). How might the equipment needed on one type of farm differ from that on another – such as a dairy farm and a vegetable farm, or a cattle farm and a chicken farm?');
INSERT INTO badge_level_requirements VALUES(1884,255,'level2',4,'Be able to identify at least five different types of farm equipment.');
INSERT INTO badge_level_requirements VALUES(1885,255,'level2',5,'Learn about the history of farm equipment. What affects has farm equipment had on the farming industry?');
INSERT INTO badge_level_requirements VALUES(1886,255,'level3',6,'Be able to identify at least six different types of farm equipment.');
INSERT INTO badge_level_requirements VALUES(1887,255,'level3',7,'Choose a piece of farm equipment and create a timeline of its development. What could be done to make this piece of equipment even more useful and efficient? (This requirement may be repeated as an optional requirement)');
INSERT INTO badge_level_requirements VALUES(1888,255,'level4',8,'Be able to identify at least seven different types of farm equipment.');
INSERT INTO badge_level_requirements VALUES(1889,255,'level4',9,'Create a poster, essay, or booklet that compares and contrasts two leading brands of a specific piece of farm equipment such as tractors. Which would you purchase? Why?');
INSERT INTO badge_level_requirements VALUES(1890,255,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1891,256,'preschool',0,'What is fashion design? Look through a clothing catalog and be able to explain what makes various pieces of clothing different.');
INSERT INTO badge_level_requirements VALUES(1892,256,'level1',1,'Find out what ‘focal point’ means. What part of a person’s body is best for showing other people what we’re thinking? Why do parents sometimes ask children to look at them while they are talking? Why might clothing help draw attention to our faces?');
INSERT INTO badge_level_requirements VALUES(1893,256,'level1',2,'Make up your own fashion design by drawing it on a piece of paper. Make three different articles of clothing. These can be all different (a shirt, dress, and jacket) or three of the same type of clothing, but with different designs.');
INSERT INTO badge_level_requirements VALUES(1894,256,'level2',3,'Learn to tell the difference between at least 10 different types of fabric. Examples might include: Lace Calico Gingham Plaids Denim Leather Corduroy Gauze Velvet Tulle Fleece Felt Chiffon Wool Plain-weave solids Get a sample of each of your choices at the fabric store and make a sample board.');
INSERT INTO badge_level_requirements VALUES(1895,256,'level3',4,'Why might a person want to draw attention to a part of the body other than the face?  Why might it not be a good idea to draw attention to other parts of the body? How can you draw attention to two different parts of a garment?');
INSERT INTO badge_level_requirements VALUES(1896,256,'level3',5,'Choose one principle of design and at least one fashion design that illustrates that principle. Be able to explain how the photo or drawing illustrates that principle. The Basic Design Principles are: Balance Emphasis / Focal Point Illusion of Motion Texture Value Scale / Proportion Rhythm Unity Line Shape / Volume Illusion of Space and Color');
INSERT INTO badge_level_requirements VALUES(1897,256,'level4',6,'Choose two principles of design to illustrate.');
INSERT INTO badge_level_requirements VALUES(1898,256,'level4',7,'Make a sketch book of your fashion designs. It should have at least five sketches inside of it.');
INSERT INTO badge_level_requirements VALUES(1899,256,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1900,257,'preschool',0,'.  Learn what fashion is. Look at a book about the history of fashion and clothing. See how different the clothes were from today.');
INSERT INTO badge_level_requirements VALUES(1901,257,'level1',1,'.  Do Preschool requirement 1*.');
INSERT INTO badge_level_requirements VALUES(1902,257,'level1',2,'Pick one time period in history, such as the Middle Ages or the Tudor era, and learn about its fashions.');
INSERT INTO badge_level_requirements VALUES(1903,257,'level2',3,'.  What is the difference between “vintage”, “retro” and “antique” fashions? Be able to explain the differences to somebody else.');
INSERT INTO badge_level_requirements VALUES(1904,257,'level3',4,'.  What does the term “haute couture” mean? What were “fashion houses”, and where were they usually located? Learn about a famous fashion house such as Dior or Worth.');
INSERT INTO badge_level_requirements VALUES(1905,257,'level4',5,'. Make a timeline of the way fashions have changed down through the centuries. You must have at least 20 items on your timeline. How has the invention of synthetic fabrics impacted fashion?');
INSERT INTO badge_level_requirements VALUES(1906,257,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1907,258,'preschool',0,'What does the term “fast food” mean? Identify common fast food items by looking at pictures or menus. Talk about which ones you’ve tried.');
INSERT INTO badge_level_requirements VALUES(1908,258,'preschool',1,'Sort toy or paper food into “everyday” foods and “sometimes” foods. Talk about the difference.');
INSERT INTO badge_level_requirements VALUES(1909,258,'level1',2,'Visit a fast food restaurant and observe how the food is prepared and served. What makes it different than a regular restaurant?');
INSERT INTO badge_level_requirements VALUES(1910,258,'level2',3,'Compare the nutritional value of a fast food meal to a homemade version. Discuss calories, sugar, salt, or fat content.');
INSERT INTO badge_level_requirements VALUES(1911,258,'level3',4,'Research how fast food restaurants market to kids and teens. Look for examples in ads, toys, or packaging.');
INSERT INTO badge_level_requirements VALUES(1912,258,'level4',5,'Learn about food preparation in a fast food kitchen. How are most items cooked?  What comes ready made or frozen and what is usually fresh?  What food preparation and storage guidelines must be followed?');
INSERT INTO badge_level_requirements VALUES(1913,258,'level5',6,'Teach someone what you’ve learned about fast food, such as how to make healthier choices or the history of fast food. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1919,262,'level2',0,'Earn the Fire Safety badge at your level.');
INSERT INTO badge_level_requirements VALUES(1920,262,'level2',1,'Know the three types of fuel used to start a wood fire. Tinder: This can be any thin material that burns quickly when touched with a match. Tinder can consist of natural materials such as dried grass, small twigs, or dry leaves, or it may be man made such as crumpled up newspaper or homemade fire starters. Make sure that what every you choose has enough body to burn long enough to catch the kindling on fire. Dry leaves and grass burn very quickly and will not work well unless tied into tight bundles. Kindling: This is the next sin size and should graduate from twigs just a little bigger than tinder to pieces as thick as your thumb or even a little thicker. Make sure that kindling is dry (it should snap when you break it) or it will not light. Fuel: Fuel is the thick pieces of wood that keep a fire going. They should range from small branches to logs. The amount of fuel needed depends upon how long you wish to keep the fire going. Find out why you should avoid wood that is wet, damp or green, or wood that has vines or ants on it. Be able to discuss why these types of wood are unsafe to burn.');
INSERT INTO badge_level_requirements VALUES(1921,262,'level2',2,'Before building a fire, make sure you have a bucket of water and shovel nearby. You may need to smother the fire with dirt, or stir wet coals when you put it out.  Also make sure that your fire site has been cleared and is safe. Make sure you follow all the safety rules. If you are starting your fire in a fire place or wood burning stove, make sure that the draft in the chimney is open and there is a screen to place over the front to prevent spark from jumping out onto clothing or rugs.  Do not start a fire outside during air-pollution alerts, high winds, or very dry conditions.');
INSERT INTO badge_level_requirements VALUES(1922,262,'level2',3,'Have an adult show you the proper way to  strike both book matches and stick matches. Also have an adult show you how to properly use a lighter designed for lighting candles and fires. Demonstrate what you have learned.');
INSERT INTO badge_level_requirements VALUES(1923,262,'level2',4,'Learn to build each of the following types of fires and what each variety is used for. Teepee: Good for general purpose fires. Log Cabin: Good for cooking. Trench Fire: Good to conserve heat and fuel. Used mostly in hot or windy weather.');
INSERT INTO badge_level_requirements VALUES(1924,262,'level2',5,'Know at least three ways to plan for wet weather fire building.');
INSERT INTO badge_level_requirements VALUES(1925,262,'level2',6,'Learn how to properly tend a fire.');
INSERT INTO badge_level_requirements VALUES(1926,262,'level2',7,'Learn how to properly extinguish a fire.');
INSERT INTO badge_level_requirements VALUES(1927,262,'level3',8,'Earn the Fire Safety badge at your level.');
