INSERT INTO badge_level_requirements VALUES(1951,263,'level1',0,'Never touch a gun without a parent’s permission.  Explain the rules of safe gun handling.  (Click here for NRA rules) Learn all gun safety rules. Explain the need for, use and types of eye and hearing protection. Discuss with a parent, or other adult,  gun use on television and in video games as opposed to gun use in real life. Firearms are often handled carelessly in movies, on TV, and in games. Characters are shot and “killed” and then appear in another movie or TV show.  Understand the difference between media and real life.');
INSERT INTO badge_level_requirements VALUES(1952,263,'level1',1,'Know the types of ammunition for your firearm and their uses.');
INSERT INTO badge_level_requirements VALUES(1953,263,'level2',2,'Also explain the basic laws of gun ownership and use in your state and county.');
INSERT INTO badge_level_requirements VALUES(1954,263,'level2',3,'Explain the parts of your firearm and how to safely load one.');
INSERT INTO badge_level_requirements VALUES(1955,263,'level3',4,'Identify the basic safety rules for cleaning your firearm, and identify the materials needed. Safely clean and reload your firearm.');
INSERT INTO badge_level_requirements VALUES(1956,263,'level4',5,'Discuss what points you would consider in selecting a firearm.');
INSERT INTO badge_level_requirements VALUES(1957,263,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1958,264,'preschool',0,'Learn the Stop, Drop, and Roll technique to put out a fire on your body.');
INSERT INTO badge_level_requirements VALUES(1959,264,'preschool',1,'Know the all safety precautions when dealing with fire, including: Keep all hair tied back away from the face in a way that will not allow it to accidentally fall into the fire. Make sure to wear close fitting clothing with no strings or loose sleeves that may fall into the flame. Always wear closed toed shoes when around a fire. Never play near the fire and always be aware of where other people are so that you will not accidentally knock them into the fire. Never put anything into or onto the fire without an adult’s permission. Always have at least one large bucket of water or sand near every fire. Know what types of fires can be put out with water, and which need sand. Never put a marshmallow or other food directly into the flames. Always cook your food over coals. If your food does catch fire, do not remove it, but ask for an adult’s help. Many people are burned each year by panicking and flinging a burning marshmallow off their stick onto themselves or another person. Always move slowly when around fire. Never leave a fire unattended.');
INSERT INTO badge_level_requirements VALUES(1960,264,'level1',2,'Learn the Stop, Drop, and Roll technique to put out a fire on your body.');
INSERT INTO badge_level_requirements VALUES(1961,264,'level1',3,'Know the all safety precautions when dealing with fire, including: Keep all hair tied back away from the face in a way that will not allow it to accidentally fall into the fire. Make sure to wear close fitting clothing with no strings or loose sleeves that may fall into the flame. Always wear closed toed shoes when around a fire. Never play near the fire and always be aware of where other people are so that you will not accidentally knock them into the fire. Never put anything into or onto the fire without an adult’s permission. Always have at least one large bucket of water or sand near every fire. Know what types of fires can be put out with water, and which need sand. Never put a marshmallow or other food directly into the flames. Always cook your food over coals. If your food does catch fire, do not remove it, but ask for an adult’s help. Many people are burned each year by panicking and flinging a burning marshmallow off their stick onto themselves or another person. Always move slowly when around fire. Never leave a fire unattended.');
INSERT INTO badge_level_requirements VALUES(1962,264,'level2',4,'Complete all Preschool & Level 1 requirements.');
INSERT INTO badge_level_requirements VALUES(1963,264,'level2',5,'Learn to make a safe fire site.');
INSERT INTO badge_level_requirements VALUES(1964,264,'level2',6,'Learn how to properly tend a fire.');
INSERT INTO badge_level_requirements VALUES(1965,264,'level2',7,'Learn how to properly extinguish a fire.');
