INSERT INTO badge_level_requirements VALUES(1976,265,'preschool',0,'Learn why first aid is important. How do you keep yourself safe from being hurt when you go to help someone else? People who are hurt or sick might feel afraid: How could you help them not to be scared?  Learn how to properly care for a small cut or scrape.');
INSERT INTO badge_level_requirements VALUES(1977,265,'preschool',1,'Understand how and when to dial 911 and what questions you should be prepared to answer. Role-play with a parent, leader or other adult how a 911 call might go.');
INSERT INTO badge_level_requirements VALUES(1978,265,'level1',2,'Demonstrate how to treat bug bites and minor burns including sunburn.');
INSERT INTO badge_level_requirements VALUES(1979,265,'level1',3,'Put together or purchase a home first aid kit. Be able to identify each item in the kit, what it is used for, and how to use it properly.  Know which items you should not touch without an adult.');
INSERT INTO badge_level_requirements VALUES(1980,265,'level2',4,'Demonstrate how to treat heat exhausion and blisters.');
INSERT INTO badge_level_requirements VALUES(1981,265,'level2',5,'Understand treatment for more severe cuts.  Demonstrate how to control bleeding using direct pressure and elevation.  Learn when a cut is severe enough to require stitches or a call to 911.');
INSERT INTO badge_level_requirements VALUES(1982,265,'level3',6,'Explain the dangers of using a tourniquet and under what extreme emergencies it may be necessary.');
INSERT INTO badge_level_requirements VALUES(1983,265,'level3',7,'Identify the signs and symptoms of fractures and sprains.  Understand the difference between a simple an compound fracture.  Immobilize a simulated fracture and show how to provide care for a sprained joint.');
INSERT INTO badge_level_requirements VALUES(1984,265,'level4',8,'Explain the steps to assist a choking person.  Demonstrate the Heimlich maneuver on a training dummy or simulate it with an adult.  Explain how to treat choking in an infant or small child and demonstrate on a training dummy or simulate with a child.');
INSERT INTO badge_level_requirements VALUES(1985,265,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1986,266,'preschool',0,'Learn the names of both the first U.S. First Lady and the current U.S. First Lady. Be able to identify them in pictures.');
INSERT INTO badge_level_requirements VALUES(1987,266,'preschool',1,'Read a story or have a story read to you about the life of one of the U.S. First Ladies of America and be able to tell something you learned about her.');
INSERT INTO badge_level_requirements VALUES(1988,266,'level1',2,'Memorize the first ten U.S. First Ladies in order.');
INSERT INTO badge_level_requirements VALUES(1989,266,'level1',3,'Choose five of the First Ladies you memorized in requirement 1. Be able to list a significant fact about or an accomplishment of each one of them.');
INSERT INTO badge_level_requirements VALUES(1990,266,'level2',4,'Memorize fifteen First Ladies and choose seven of them to list a fact about or accomplishment of.');
INSERT INTO badge_level_requirements VALUES(1991,266,'level2',5,'Find out which Presidents did not have a First Lady and who performed those duties in her place. What, if anything, is the Vice President’s wife known as?');
INSERT INTO badge_level_requirements VALUES(1992,266,'level3',6,'Learn about the role of the First Lady, including her duties and responsibilities. Which First Lady do you admire the most and why?');
INSERT INTO badge_level_requirements VALUES(1993,266,'level4',7,'Make a timeline of all American First Ladies.');
INSERT INTO badge_level_requirements VALUES(1994,266,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(1995,267,'preschool',0,'Learn fishing and water safety rules.');
INSERT INTO badge_level_requirements VALUES(1996,267,'preschool',1,'Go fishing.');
INSERT INTO badge_level_requirements VALUES(1997,267,'level1',2,'Learn how to properly cast a line.');
INSERT INTO badge_level_requirements VALUES(1998,267,'level2',3,'Learn to tie a proper knot for keeping your lure or hook on your line.');
INSERT INTO badge_level_requirements VALUES(1999,267,'level3',4,'Learn about your local fishing laws and regulations. Do you need a fishing license? Are the limits to how many fish you can take home? Are there laws regarding barbed or barbless hooks? What about laws regarding what types of boats can be used or what type of bait?');
INSERT INTO badge_level_requirements VALUES(2000,267,'level4',5,'Demonstrate proper first aid for common fishing injuries including: Cuts Scratches Puncture wounds Insect bites Sunburn Dehydration Hypothermia Heat exhaustion Demonstrate how to get a fishhook out of your arm or other body part.');
INSERT INTO badge_level_requirements VALUES(2001,267,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2002,268,'preschool',0,'Learn the safety rules for the game you are playing. For example, if you have to lift something heavy, what is the proper way to lift? If you are running, what type of shoes should you be wearing? Discuss the importance of safety when being physically active.');
INSERT INTO badge_level_requirements VALUES(2003,268,'preschool',1,'Learn the rules of how to play the game itself and show that you can follow directions.  Play the game at least three times.');
INSERT INTO badge_level_requirements VALUES(2004,268,'level1',2,'Learn what part of staying physically fit this game focuses on. Balance? Strength? Cardio? Flexibility?  Coordination? Endurance? Does it combine more than one? Why is this type of physical fitness important?');
INSERT INTO badge_level_requirements VALUES(2005,268,'level2',3,'Learn what muscle groups are worked while playing this game (arms, legs, core, heart, etc.). Can you feel them getting stronger as you play?');
INSERT INTO badge_level_requirements VALUES(2006,268,'level3',4,'Exercise your leadership skills and help teach this game to someone else. If you are playing for the first time and there are children younger than you, help them to understand the rules and how to play.');
INSERT INTO badge_level_requirements VALUES(2007,268,'level4',5,'Come up with your own twist for the game you are playing. How might you add even more physical fitness to it? If it is a strength game, can you incorporate balance? If it focuses on balance, how might you add some flexibility?');
INSERT INTO badge_level_requirements VALUES(2008,268,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2009,269,'preschool',0,'Be able to identify your five senses.');
INSERT INTO badge_level_requirements VALUES(2010,269,'preschool',1,'Identify the body parts that match with each of the five senses, such as sight and eyes.');
INSERT INTO badge_level_requirements VALUES(2011,269,'level1',2,'Do Preschool requirements # 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2012,269,'level1',3,'Discuss why each sense is important.  How does it keep you safe?  What is it called when someone is born without one of the five senses?');
INSERT INTO badge_level_requirements VALUES(2013,269,'level2',4,'Read a biography of someone who was born without or lost one of the five senses. How did they learn to overcome their disability? For example, you could study Helen Keller, Beethoven, Ray Charles, etc.');
INSERT INTO badge_level_requirements VALUES(2014,269,'level3',5,'Choose a body organ attached to one of your senses and diagram the parts of it.  For example:  Hearing / Ear should include the outer ear, ear canal, ear drum, hammer/malleus, anvil/incus, stirrup, Eustachian tube, semicircular canals, cochlea, and nerves.');
INSERT INTO badge_level_requirements VALUES(2015,269,'level4',6,'except choose 2 body organs each attached to one of your senses and diagram the parts of it.');
INSERT INTO badge_level_requirements VALUES(2016,269,'level4',7,'Research the history of American Sign Language and Braille.  Learn to write your name in Braille and learn to sign your name in American Sign Language.');
INSERT INTO badge_level_requirements VALUES(2017,269,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2022,272,'preschool',0,'Learn the proper way to care for cut flowers.');
INSERT INTO badge_level_requirements VALUES(2023,272,'level1',1,'Demonstrate the proper way to cut flowers with an adult’s supervision.');
INSERT INTO badge_level_requirements VALUES(2024,272,'level2',2,'Complete Level 1 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2025,272,'level2',3,'Demonstrate a use for faded flowers rather than simply throwing them away. Ideas might include: Cut them up and add them to a compost pile. Dry flowers and petals for use in sachets, wreaths, and aromatherapy projects. Press flowers for making personalized note cards. If you are using edible flowers, first make sure they are truly edible and free of all chemicals and then with adult supervision add them to salads, cakes, casseroles and soups.');
INSERT INTO badge_level_requirements VALUES(2026,272,'level3',4,'Learn basic flower arrangement shapes (arc, circle, curve, right angle, triangular, crescent, oval, “S”, etc.) and be able to tell which shape would be appropriate for the following occasions: A center piece that can be seen from all sides for a display table. A center piece that can be seen from all sides at a dinner table. A table arrangement that will only be seen from one side. A hanging basket arrangement. A bud vase.');
INSERT INTO badge_level_requirements VALUES(2027,272,'level4',5,'Create at least one arrangement using real flowers, one using silk flowers and one using dried flowers.');
INSERT INTO badge_level_requirements VALUES(2028,272,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2029,273,'preschool',0,'Learn to identify three different flowers that grow well in your area. Plant one from seed, and one from a seedling and care for them for them until they are large enough to use in bouquets and arrangements.');
INSERT INTO badge_level_requirements VALUES(2030,273,'preschool',1,'Learn what type of soil your flowers should be planted in,  how much water and sunlight they should receive and how they should be trimmed.');
INSERT INTO badge_level_requirements VALUES(2031,273,'level1',2,'Recognize three common weeds and know the proper way to weed a garden.');
INSERT INTO badge_level_requirements VALUES(2032,273,'level2',3,'but learn to identify six different flowers, plant three from seed, and three from seedlings.');
INSERT INTO badge_level_requirements VALUES(2033,273,'level2',4,'List three garden pests, insects or diseases, and find two organic solutions for dealing with each.');
INSERT INTO badge_level_requirements VALUES(2034,273,'level3',5,'but learn to identify ten flowers. Plan out a flower garden of at least six different flowers using graph paper. Arrange flowers according height and color to design a pleasing area. Make sure you map out how much space each flower will need. When you are ready, plant your garden and care for it until the flowers are ready to be used in floral arrangements.');
INSERT INTO badge_level_requirements VALUES(2035,273,'level3',6,'Learn what the following garden tools are used for and how to properly clean and care for them: Garden shovel Spade Hoe Weeding hoe Cultivator Pruning shear Hedge shear Lopping shear Rake Trowel Pruning saw');
INSERT INTO badge_level_requirements VALUES(2036,273,'level4',7,'but learn to identify fifteen flowers.');
INSERT INTO badge_level_requirements VALUES(2037,273,'level4',8,'Learn the proper way to cut  and trim flowers to prepare them for use in floral arrangements. Make a floral arrangement for a table centerpiece.');
INSERT INTO badge_level_requirements VALUES(2038,273,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2039,274,'preschool',0,'Try food from at least three different countries.');
INSERT INTO badge_level_requirements VALUES(2040,274,'preschool',1,'Try food that is eaten in several different countries, but may be prepared differently. An example may be to try several different sausages, cheeses, or chocolates.');
INSERT INTO badge_level_requirements VALUES(2041,274,'level1',2,'Try foods from four different countries.');
INSERT INTO badge_level_requirements VALUES(2042,274,'level1',3,'Help to cook a recipe from another country.');
INSERT INTO badge_level_requirements VALUES(2043,274,'level2',4,'Try foods from at least five different countries.');
INSERT INTO badge_level_requirements VALUES(2044,274,'level2',5,'Choose five countries and find out what foods they are known for growing. Locate these countries on a map.');
INSERT INTO badge_level_requirements VALUES(2045,274,'level3',6,'Try foods from at least six different countries and cook two recipes.');
INSERT INTO badge_level_requirements VALUES(2046,274,'level3',7,'Learn about popular spice combinations used in different countries. Try foods that use at least three of the spice combinations you learned about.');
INSERT INTO badge_level_requirements VALUES(2047,274,'level4',8,'Learn about foods that are specific to various world holidays or religions. Choose five holidays to learn about.  Examples might include: Hanukkah – Latkes St. Patrick’s Day – Corned Beef Oktoberfest – Bratwurst Diwali – Gulab Jamun Chinese New Year – Peking Duck');
INSERT INTO badge_level_requirements VALUES(2048,274,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2049,275,'preschool',0,'Explain why attractive food presentation is important.');
INSERT INTO badge_level_requirements VALUES(2050,275,'level1',1,'Learn the following food presentation tips: When serving something that comes in pieces, like chicken nuggets, use an odd number as it is more pleasing to the eye. Do not overcrowd the plate for big meals and use garnishes to fill empty spaces on the plate of smaller meals. Add color to the plate. Bland looking meals are not appetizing. Fried chicken with corn and mashed potatoes are all very similar in color. Add some parsley to the top of the potatoes or some red peppers to the corn. Choose a plate or bowl appropriate to the size of the dish. Make sure your plate has a variety of different textures (crunchy, smooth, meaty, etc.) Have different shapes on the plate. Don’t serve Brussels sprouts with meatballs and small red potatoes. Never crowd food on the rim of the plate. Match your portion size to your plate. If the plate is too big, you make your dish look skimpy, if it is too small it looks crowded. Make sure the color and pattern of your plates complement your food.');
INSERT INTO badge_level_requirements VALUES(2051,275,'level1',2,'Serve a dish that is attractively arranged on the plate, bowl or platter, with proper balance of color, shape, and texture.');
INSERT INTO badge_level_requirements VALUES(2052,275,'level2',3,'Explain why any garnishes used on the plate should be edible and taste good with the meal presented. Learn to make at least four different types of garnish. One that is savory, one that is sweet, one that is crunchy, and one that is a sauce or puree.');
INSERT INTO badge_level_requirements VALUES(2053,275,'level3',4,'Practice at least three different plating techniques from those below. The classic arrangement: main item in front, vegetables, starch items, and garnish at the rear. The main item alone in the center of the plate, sometimes with a sauce or simple garnish. The main item in the center, with vegetables distributed randomly around it, sometimes with a sauce underneath. The main item in the center, with neat piles of vegetables carefully arranged around it in a pattern. A starch or vegetable item heaped in the center; the main item sliced and leaning up against it; additional vegetables, garnish, and/or sauce on the plate around the center items. Main item, vegetable and starch accompaniments, and other garnish stacked neatly one atop the other in the center of the plate. Sauces or additional garnish may be placed around the outside. Vegetable in center of plate, sometimes with sauce; main item (in slices, medallions, small pieces, etc.) arranged around it toward the outside of the plate. Slices of the main item shingled on a bed of vegetables or a purée of vegetables or starch, with, perhaps, additional garnish to one side or around.');
INSERT INTO badge_level_requirements VALUES(2054,275,'level4',5,'Look through at least 25 photos of different food presentations. Be able to identify which plating technique was used. Pay attention to any garnishes. Are they needed? Will they add flavor as well as color to the dish? Discuss the balance of each plate. Is there appropriate color, texture, shape, etc?');
INSERT INTO badge_level_requirements VALUES(2055,275,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2056,276,'preschool',0,'What is food preservation? Why would people want to preserve food?');
INSERT INTO badge_level_requirements VALUES(2057,276,'preschool',1,'Find three different foods that have been preserved. Try them both preserved and fresh. Which way do you like best?');
INSERT INTO badge_level_requirements VALUES(2058,276,'level1',2,'Choose three of methods of food preservation and work with an adult to help process some food with those methods. Some methods include: Freezing Drying Candying Canning Salting Pickling Freeze-drying Vacuum-packing Surrounding a food with inert gas such as nitrogen or CO2 Smoking Refrigerating Fermenting');
INSERT INTO badge_level_requirements VALUES(2059,276,'level2',3,'but choose four methods of food preservation.');
INSERT INTO badge_level_requirements VALUES(2060,276,'level2',4,'Learn the basics of safe food storage: how temperature, moisture, and light affect how long food lasts.  Figure out one advantage and one disadvantage for the methods of preservation mentioned in Level 1.');
INSERT INTO badge_level_requirements VALUES(2061,276,'level3',5,'but choose five methods of preservation.');
INSERT INTO badge_level_requirements VALUES(2062,276,'level3',6,'Learn the history of food preservation. How did people keep food from spoiling before electricity and refrigeration?');
INSERT INTO badge_level_requirements VALUES(2063,276,'level4',7,'but choose six methods of preservation.');
INSERT INTO badge_level_requirements VALUES(2064,276,'level4',8,'Compare the nutritional content of fresh, frozen, and preserved versions of the same food');
INSERT INTO badge_level_requirements VALUES(2065,276,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2066,277,'preschool',0,'Find out where our food comes from. Learn how a farm grows grain, raises animals and grows vegetables.');
INSERT INTO badge_level_requirements VALUES(2067,277,'preschool',1,'Try a new food. Where did it come from? How is it made?');
INSERT INTO badge_level_requirements VALUES(2068,277,'level1',2,'Where does our food come from? Make a chart of your favorite meal. What food had to be produced in order to make the meal? For example, if your favorite meal is spaghetti with meatballs, salad with Italian dressing, and chocolate chip cookies, under the spaghetti you should have beef , wheat, tomatoes, herbs, etc. Under salad you should have lettuce, carrots, cabbage, vegetable oil, vinegar, herbs, garlic, etc. And under cookies you should have sugar, cocoa beans, wheat, milk, etc. How many different farms do you think it took to grow the food just in this one meal?');
INSERT INTO badge_level_requirements VALUES(2069,277,'level2',3,'Where are major food crops grown in the greatest quantity? Create a world map that shows which countries produce enough food for themselves, that have enough to export, or need to import. How does this affect the food situation in our world? How did the invention of each of the following effect the foods people eat: Railroads Transport trucks Refrigerated railroad and truck cars Airplanes Commercial canning Prepackaged frozen foods Dehydrating food Preservatives');
INSERT INTO badge_level_requirements VALUES(2070,277,'level3',4,'What resources are there in your area for people who do not have enough food? Don’t forget government food programs as well. How can you help?');
INSERT INTO badge_level_requirements VALUES(2071,277,'level4',5,'Learn about at least five preservatives used in processed foods. What are the health risks of each?');
INSERT INTO badge_level_requirements VALUES(2072,277,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2073,278,'preschool',0,'Know why it is important to handle food properly and to wash your hands before eating or handling food. Demonstrate the proper way to wash your hands.');
INSERT INTO badge_level_requirements VALUES(2074,278,'level1',1,'Learn what food poisoning is and how it can be avoided. Go through your refrigerator with a parent and throw out any food that is too old, has stayed out of the refrigerator too long, is growing mold, or is otherwise unsafe to eat.');
INSERT INTO badge_level_requirements VALUES(2075,278,'level2',2,'Learn the following food safety rules set forth by the USDA.');
INSERT INTO badge_level_requirements VALUES(2076,278,'level2',3,'Make a timeline of events in the history of food safety, such preserving meats or when refrigeration was invented. You must have at least ten items on your timeline.');
INSERT INTO badge_level_requirements VALUES(2077,278,'level3',4,'Have at least fifteen items on your timeline.');
INSERT INTO badge_level_requirements VALUES(2078,278,'level3',5,'Read a biography of a person involved in the area of food safety, such as Josephine Cochrane, who invented the dishwasher. Be able to list at least two significant details about your chosen person’s life.');
INSERT INTO badge_level_requirements VALUES(2079,278,'level4',6,'Have at least twenty items on your timeline.');
INSERT INTO badge_level_requirements VALUES(2080,278,'level4',7,'Learn how refrigeration works, and how it has changed they way people shop and eat.');
INSERT INTO badge_level_requirements VALUES(2081,278,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2082,279,'preschool',0,'Choose a specific food to study.  What does your food look like in its raw form? Look at your food and describe your food.');
INSERT INTO badge_level_requirements VALUES(2083,279,'preschool',1,'Try a sample your food.  What does it taste like?  Can it be eaten raw or does it need to cooked?');
INSERT INTO badge_level_requirements VALUES(2084,279,'level1',2,'Draw the growing cycle of your food. How long does it take for your food to fully grow (or mature if it is an animal; or replenish if a dairy product; etc.)?');
INSERT INTO badge_level_requirements VALUES(2085,279,'level2',3,'Where is your food most commonly grown? What country grows the most? What US state grows the most? What season does it grow?');
INSERT INTO badge_level_requirements VALUES(2086,279,'level3',4,'Learn how your food should be handled when you bring it home. Should your food be rinsed? If so, how and when?  Does it need to be refrigerated?  Is there anything you can do to help your food last longer? Demonstrate your understanding of how to properly store your food.');
INSERT INTO badge_level_requirements VALUES(2087,279,'level4',5,'Find out what types of vitamins and minerals are in your food. What health benefits do these provide your body?  What is considered a single serving of your food?  What happens if you eat too much of your food?');
INSERT INTO badge_level_requirements VALUES(2088,279,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2089,280,'preschool',0,'What is foraging? Talk about it with an adult. Identity 3 plants.');
INSERT INTO badge_level_requirements VALUES(2090,280,'preschool',1,'Learn all safety rules regarding foraging, including: Be 100% certain of the plant’s identity. Learn a few easy ones at a time. Avoid contaminated areas, such as places within 50 feet of heavy traffic, where heavy metals and other pollutants settle. Always have adult supervision. Never eat an unknown plant.');
INSERT INTO badge_level_requirements VALUES(2091,280,'level1',2,'Identify 5 plants.');
INSERT INTO badge_level_requirements VALUES(2092,280,'level1',3,'Find out why foraging is important, and list several reasons on a piece of paper.');
INSERT INTO badge_level_requirements VALUES(2093,280,'level2',4,'Identify 7 plants.');
INSERT INTO badge_level_requirements VALUES(2094,280,'level2',5,'Look up foraging groups or find someone who is experienced in foraging and interview them. Report what you have learned to your family or club.');
INSERT INTO badge_level_requirements VALUES(2095,280,'level3',6,'Identify 10 plants.');
INSERT INTO badge_level_requirements VALUES(2096,280,'level3',7,'Research the origin history of an edible plant. How can you use it? Where does it come from?');
INSERT INTO badge_level_requirements VALUES(2097,280,'level4',8,'Identify 12 plants.');
INSERT INTO badge_level_requirements VALUES(2098,280,'level4',9,'Read a book or blog about foraging, or watch a movie where foraging is the main storyline. Write a few paragraphs about what you learning and share with your family, friends, or group.');
INSERT INTO badge_level_requirements VALUES(2099,280,'level5',10,'Identify 15 plants.');
INSERT INTO badge_level_requirements VALUES(2100,280,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2101,281,'preschool',0,'. Learn what the term “formal wear” means, and what tuxedos, wedding dresses and ball-gowns are. When would they be worn?');
INSERT INTO badge_level_requirements VALUES(2102,281,'preschool',1,'. Look at  a large variety of pictures of formal wear. Which is your favorite?');
INSERT INTO badge_level_requirements VALUES(2103,281,'level1',2,'. Do Preschool requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2104,281,'level1',3,'.  Learn how to treat formal wear carefully, such as by not touching it without permission or with dirty hands. Ask your parents and/or grandparents if they have any formal wear you can look at.');
INSERT INTO badge_level_requirements VALUES(2105,281,'level2',4,'. Do Level 1 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2106,281,'level2',5,'. What is the difference between a cocktail dress, ball-gown, prom dress and an evening gown?');
INSERT INTO badge_level_requirements VALUES(2107,281,'level3',6,'. Do Level 2 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2108,281,'level3',7,'. Be able to identify the following parts of men’s formal wear: tie, bow tie, cummerbund, pocket square, cuff-links, shirt studs and vest/waistcoat. What is the difference between a tuxedo and a regular suit that would be worn for church or business? What is a tailcoat?');
INSERT INTO badge_level_requirements VALUES(2109,281,'level4',8,'. Do Level 3 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2110,281,'level4',9,'. What does it mean to have a “white tie” event or a “black tie” event? What would be worn at each of these?  What is the best way to store formal wear?');
INSERT INTO badge_level_requirements VALUES(2111,281,'level5',10,'.  Do Level 4 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2112,281,'level5',11,'.  Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2113,282,'preschool',0,'Know what a war is and why the French and Indian War was fought.');
INSERT INTO badge_level_requirements VALUES(2114,282,'preschool',1,'Where was the war fought? Look at a map of the area. What part of North America was claimed by France, England and Spain? How did it change after the war?');
INSERT INTO badge_level_requirements VALUES(2115,282,'level1',2,'Also, know the name of the larger war that the French and Indian War was part of in Europe.');
INSERT INTO badge_level_requirements VALUES(2116,282,'level1',3,'What Native American tribes were involved? Which side did they fight for?');
INSERT INTO badge_level_requirements VALUES(2117,282,'level2',4,'Draw a map for Penguin requirement 2.');
INSERT INTO badge_level_requirements VALUES(2118,282,'level2',5,'Create a timeline of ten major events in the French and Indian War.');
INSERT INTO badge_level_requirements VALUES(2119,282,'level3',6,'Include twenty events in your timeline.');
INSERT INTO badge_level_requirements VALUES(2120,282,'level3',7,'The French and Indian War was a costly one. Who ended up paying for it and what events did that lead to?');
INSERT INTO badge_level_requirements VALUES(2121,282,'level4',8,'Include twenty-five events in your timeline.');
INSERT INTO badge_level_requirements VALUES(2122,282,'level4',9,'There were a number of forts that were key in the war. Write an essay about why were they key. Include them in the drawing of your map.');
INSERT INTO badge_level_requirements VALUES(2123,282,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2124,283,'level2',0,'.  Learn what the French Revolution was and when it occurred. What is the difference between the French Revolution and the Reign of Terror?');
INSERT INTO badge_level_requirements VALUES(2125,283,'level2',1,'.  Learn the causes of the French Revolution.');
INSERT INTO badge_level_requirements VALUES(2126,283,'level3',2,'.  Do Level 2requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2127,283,'level3',3,'.  French government went through many changes during the late 1700s and early 1800s. What and when were the ancien regime, the National Assembly/National Constituent Assembly, the Legislative Assembly, the National Convention, the Directoire, the Consulate, and the Empire? How did they differ from each other?');
INSERT INTO badge_level_requirements VALUES(2128,283,'level4',4,'.  Do Level 3 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2129,283,'level4',5,'.  What was the guillotine? How many people were executed by it? How many people died altogether during the French Revolution and the Reign of Terror? Which class of people had the most deaths during the French Revolution and the Reign of Terror?');
INSERT INTO badge_level_requirements VALUES(2130,283,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2133,285,'preschool',0,'Learn to recognize a frog and how to tell a frog from a toad.');
INSERT INTO badge_level_requirements VALUES(2134,285,'preschool',1,'Listen to the sound of a Pacific Tree Frog, also known as a Pacific Chorus Frog.  This is what most people think a frog sounds like, but each type of frog sounds different.  Listen to at least 6 different types of frogs.  How do they differ?');
INSERT INTO badge_level_requirements VALUES(2135,285,'level1',2,'Learn about the general characteristics of frogs. What makes them amphibians?');
INSERT INTO badge_level_requirements VALUES(2136,285,'level2',3,'Study the life cycle of a frog from egg to adult. Create a diagram showing each stage.');
INSERT INTO badge_level_requirements VALUES(2137,285,'level3',4,'Identify and label the main parts of a frog’s anatomy');
INSERT INTO badge_level_requirements VALUES(2138,285,'level4',5,'Investigate the conservation status of frogs globally. What are the major threats they face?  What frogs are endangered?');
INSERT INTO badge_level_requirements VALUES(2139,285,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2140,286,'preschool',0,'Choose a fruit to study.  Be able to recognize your fruit by sight, taste and smell.');
INSERT INTO badge_level_requirements VALUES(2141,286,'preschool',1,'Learn the life cycle of your fruit.');
INSERT INTO badge_level_requirements VALUES(2142,286,'level1',2,'Do Preschool requirements # 1 & 2. _____*2.*  Find out where your fruit grows and in what type of climate. What is the growing season?');
INSERT INTO badge_level_requirements VALUES(2143,286,'level2',3,'What are the physical characteristics to look for in picking out a good piece of your fruit. Know how to tell when it is ripe. Know the proper way to store your fruit. How long does your fruit last before they begin to rot?');
INSERT INTO badge_level_requirements VALUES(2144,286,'level3',4,'Learn about the botanical classification of you fruit.  Find 3 closely related fruits in the same family.');
INSERT INTO badge_level_requirements VALUES(2145,286,'level4',5,'Find out what vitamins, minerals and phytonutrients are in your fruit.  What do you need these vitamins and minerals for?  How much would you need to eat of your fruit in order to get 100% of the daily recommended amount of one nutrient (choose whichever nutrient you want)?');
INSERT INTO badge_level_requirements VALUES(2146,286,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2149,288,'preschool',0,'What is science?');
INSERT INTO badge_level_requirements VALUES(2150,288,'preschool',1,'What is the scientific method? Why is it important in scientific research and experiments?');
INSERT INTO badge_level_requirements VALUES(2151,288,'level1',2,'What is light? Perform one of the following experiments: Bending Light Experiment Bending Light in the Dark Experiment Rising Coin Experiment');
INSERT INTO badge_level_requirements VALUES(2152,288,'level2',3,'What is a rainbow? How are they formed? Perform one of the following experiments: Making a Rainbow Experiment Indoor Rainbow Experiment for Kids');
INSERT INTO badge_level_requirements VALUES(2153,288,'level3',4,'What is air made of? Does air take up space? Does air have weight? Perform one of the following experiments: All About Air Air Pressure Experiments Suck an Egg into a Bottle Make Fog Cloud in a Bottle');
INSERT INTO badge_level_requirements VALUES(2154,288,'level4',5,'What is water made of? What is the water cycle? Perform one of the following experiments: Make a Mini Water Cycle Water Cycle Experiment Make a 3D Model of the Water Cycle');
INSERT INTO badge_level_requirements VALUES(2155,288,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2158,290,'preschool',0,'Know what fuse beads are and what makes them different from other beads.');
INSERT INTO badge_level_requirements VALUES(2159,290,'preschool',1,'Make a fuse bead mosaic with the beads fused together with the help of an adult.   Learn and obey all safety rules when working with fusible beads.');
INSERT INTO badge_level_requirements VALUES(2160,290,'level1',2,'Do Preschool requirements #1 & #2');
INSERT INTO badge_level_requirements VALUES(2161,290,'level1',3,'Make a fuse bead creation of your choice.');
INSERT INTO badge_level_requirements VALUES(2162,290,'level2',4,'Do Level 1 requirements #1 & #2 and make make at least two fuse bead creations.');
INSERT INTO badge_level_requirements VALUES(2163,290,'level2',5,'Find out the history of fuse beads, otherwise known as Perler Beads.  Who invented them and when?  Where were they invented?');
INSERT INTO badge_level_requirements VALUES(2164,290,'level3',6,'Do Level 2 requirements #1 & #2 and make at least 3 fuse bead creations');
INSERT INTO badge_level_requirements VALUES(2165,290,'level3',7,'Find out at least 6 different brands of fuse beads.  Which get the best reviews and why?');
INSERT INTO badge_level_requirements VALUES(2166,290,'level4',8,'Do Level 3 requirements #1 & #2 and make at least 4 fuse bead creations.');
INSERT INTO badge_level_requirements VALUES(2167,290,'level4',9,'Make a 3D fuse bead creation.');
INSERT INTO badge_level_requirements VALUES(2168,290,'level5',10,'and make at least 5 fuse bead creations.');
INSERT INTO badge_level_requirements VALUES(2169,290,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2170,291,'preschool',0,'What are your three favorite games? Tell a friend or a parent how to play these games and then play the games with them.');
INSERT INTO badge_level_requirements VALUES(2171,291,'preschool',1,'Why is it important to be a good sport? What does it mean to be a sore loser? What does it mean to be an ungracious winner? Remember, no one wants to play games with people who don’t behave nicely. How should you act if you lose a game? How should you act if you win a game? Model good sportsmanship when playing the games required for this badge.');
INSERT INTO badge_level_requirements VALUES(2172,291,'level1',2,'and 2.');
INSERT INTO badge_level_requirements VALUES(2173,291,'level1',3,'Know what the following types of games are. If possible, think of a few games for each category, besides the one listed. Board Games (i.e.: Monopoly) Trivia Games (i.e.: Trivial Pursuit) Dice Games (i.e.: Yahtzee) Word Games (i.e.: Scrabble) Card Games (i.e.: Hearts) Role Playing Games (i.e. Dungeons and Dragons) Group Games (i.e.: Hide and Seek) Individual Games (i.e.: Solitaire) Travel Games (i.e.: License Plate Game) Educational Games (i.e.: The Ladybug Game) Video or Computer Games (i.e.: Nintendo Mario Brothers Games) Play a game from four of the different categories. Junior versions of games may count as long as they are still age appropriate. (Many games fit into more than one category; for example, Solitaire is both an individual game and a card game. Each game played for this badge, however, may only be counted in one category). Which type of game is your favorite?');
INSERT INTO badge_level_requirements VALUES(2174,291,'level2',4,'but play games from five different categories.');
INSERT INTO badge_level_requirements VALUES(2175,291,'level2',5,'Learn to play a game from a different country or culture. Know where the game came from and what it is called. Examples could include Mancala (from Africa), Balli (from India), or Spinning Tops (from China).');
INSERT INTO badge_level_requirements VALUES(2176,291,'level3',6,'but play games from six of the different categories listed on Level 1 requirement 1. Also complete Level 2 requirement 2 and teach this game to your friends or another group.');
INSERT INTO badge_level_requirements VALUES(2177,291,'level3',7,'Plan and host a game night. When choosing games to play, be sure to consider participant’s  ages and abilities (i.e.: you wouldn’t want to choose word games for children who can’t yet read). Level 4: Do seven of the following including the two starred *');
INSERT INTO badge_level_requirements VALUES(2178,291,'level3',8,'but play games from seven of the different categories listed on Level 1 requirement 1 and learn about two games from different countries or cultures to teach to your family, friends, or group. Also complete Level 3 requirement 2.');
INSERT INTO badge_level_requirements VALUES(2179,291,'level3',9,'Make up your own game. What kind of game is it? What is it called? How many people can play? What are the rules? What materials are needed to play? Teach your game to three people. If others seem to enjoy the game, think about presenting the idea to a successful game company for them to consider publishing.');
INSERT INTO badge_level_requirements VALUES(2180,291,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2181,292,'preschool',0,'Plant and raise at least three different vegetables or fruits from seeds and care for them until they are ready to harvest.');
INSERT INTO badge_level_requirements VALUES(2182,292,'preschool',1,'Make plant markers for the plants you have chosen.');
INSERT INTO badge_level_requirements VALUES(2183,292,'level1',2,'and 2. Recognize the difference between your seedlings and weeds and keep your garden weeded as well.');
INSERT INTO badge_level_requirements VALUES(2184,292,'level1',3,'Be able to identify at least three pests, insect or disease, that may damage your garden.  Find at least two organic methods for dealing with each.');
INSERT INTO badge_level_requirements VALUES(2185,292,'level2',4,'but plant and raise at least four different vegetables or fruits from seeds and care for them until they are ready to harvest. Know what type of soil they need, and how much water and sunlight they should have.');
INSERT INTO badge_level_requirements VALUES(2186,292,'level2',5,'Harvest the items in your garden and use them in a recipe.');
INSERT INTO badge_level_requirements VALUES(2187,292,'level3',6,'but plant and raise at least six different vegetables or fruits from seeds or seedlings and care for them until they are ready to harvest. Plan out your garden of at least six different fruits and vegetables using graph paper. Make sure to leave enough room for each plant as they grow as well as walk ways so that you can get to your plants to weed and harvest them.  Be able to identify at least three pests, insect or disease, that may damage your garden. Find at least two organic methods for dealing with each.');
INSERT INTO badge_level_requirements VALUES(2188,292,'level3',7,'Learn what the following garden tools are used for and how to properly clean and care for them: Garden shovel Spade Hoe Weeding hoe Cultivator Pruning shear Hedge shear Lopping shear Rake Trowel Pruning saw');
INSERT INTO badge_level_requirements VALUES(2189,292,'level4',8,'Read a book about gardening and look through a garden catalog. Using what you learned in the book and the catalog, create a budget for creating a dream garden. List the plants that you would plant, the tools you would need, etc. How much would your dream garden cost you?');
INSERT INTO badge_level_requirements VALUES(2190,292,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2191,293,'preschool',0,'What is a garnish? Find at least three pictures of foods with garnishes on them.');
INSERT INTO badge_level_requirements VALUES(2192,293,'preschool',1,'Create a simple garnish, such as adding a sprig of parsley to add color to a plate.');
INSERT INTO badge_level_requirements VALUES(2193,293,'level1',2,'Learn what flavors go well together when combining a garnish with a dish. For example, you would not want to garnish chocolate cake with a radish rose, or a spicy Asian dish with a strawberry.');
INSERT INTO badge_level_requirements VALUES(2194,293,'level1',3,'The purpose of food garnishes is to provide contrast in color, texture, and taste, and to give a finished appearance to the dish. Look through a book about garnishes or look up pictures online with your parent’s permission. Find pictures of sweet garnishes, savory garnishes, and drink garnishes. What dishes might they go well with? Why might you want a crunchy garnish to go with a mushy dish, or a colorful garnish with a white or bland colored dish?');
INSERT INTO badge_level_requirements VALUES(2195,293,'level2',4,'Learn to identify five garnishing tools and use at least three of them with adult supervision. Examples include Serrated knife Paring knife Melon baller Zester Citrus cutter Butter curler Vegetable peeler Fancy cutters (like small cookie cutters) Scissors Twin Curl Cutter Spiral Slicer');
INSERT INTO badge_level_requirements VALUES(2196,293,'level3',5,'Identify at least eight garnishing tools and use at least five.');
INSERT INTO badge_level_requirements VALUES(2197,293,'level3',6,'Learn about careers that involve garnishes such as chefs, pastry chefs, food photographers, fruit carvers, etc. Where can you go to learn to study these techniques?');
INSERT INTO badge_level_requirements VALUES(2198,293,'level4',7,'Identify ten garnishing tools and use at least five.');
INSERT INTO badge_level_requirements VALUES(2199,293,'level4',8,'Prepare a meal for family or friends and use some of the garnishing techniques you have learned.');
INSERT INTO badge_level_requirements VALUES(2200,293,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2201,294,'preschool',0,'What is a gem stone? Where do they come from? Preschoolers need a basic understanding, such as a gemstone is dug out of the ground and that it is not alive and that they are pretty to look at/valuable once they are cut and polished. Look at a simple book on gemstones to see the variety of colors.');
INSERT INTO badge_level_requirements VALUES(2202,294,'preschool',1,'Where do we use gemstones? People often use them in jewelry. Visit a jewelry counter/look through a jewelry collection to see some different gemstones. Which ones do you like best?');
INSERT INTO badge_level_requirements VALUES(2203,294,'level1',2,'Find out what your birthstone is and what it looks like. Does it come in more than one color? For example, sapphires are known to be blue, but they also come in yellow, green, pink, purple and orange.');
INSERT INTO badge_level_requirements VALUES(2204,294,'level1',3,'Learn to identify at least three different gemstones. What is their most distinctive characteristic?');
INSERT INTO badge_level_requirements VALUES(2205,294,'level2',4,'Identify five different stones.');
INSERT INTO badge_level_requirements VALUES(2206,294,'level2',5,'Learn the difference between shape and cut. Learn to identify at least three different gem shapes or cuts.');
INSERT INTO badge_level_requirements VALUES(2207,294,'level3',6,'How much does a carat weigh? What is the difference between carat weight and a gem’s size?');
INSERT INTO badge_level_requirements VALUES(2208,294,'level4',7,'Learn the difference between cut and clarity. Why is each important when valuing a gemstone? What are inclusions? How can they help identify where a stone may have come from?');
INSERT INTO badge_level_requirements VALUES(2209,294,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2210,295,'preschool',0,'What is genealogy? Make a small family tree with at least your siblings, parents, and grandparents.');
INSERT INTO badge_level_requirements VALUES(2211,295,'preschool',1,'Know the names of all of your first cousins, aunts, and uncles.');
INSERT INTO badge_level_requirements VALUES(2212,295,'level1',2,'With your parent’s help, create a simple family tree.  Include as many ancestors as you can. You can simply write it on a piece of paper or get creative and create a poster in the shape of a tree, create a hanging mobile, or use photographs to create a scrapbook version.');
INSERT INTO badge_level_requirements VALUES(2213,295,'level1',3,'Find out what your name means and why your parents chose it.');
INSERT INTO badge_level_requirements VALUES(2214,295,'level2',4,'A family group record (FGR), sometimes called a family group sheet, is a form used to list the vital information for one set of parents and all of their children. Obtain a family group record and fill it out to best of your knowledge for your immediate family. Ask your parents to help you fill in the rest.');
INSERT INTO badge_level_requirements VALUES(2215,295,'level3',5,'A pedigree, or ancestral chart, is a form that lists an individual and several generations of his direct-line ancestors (parents and grandparents). Obtain a pedigree chart and fill it out to the best of your knowledge. Ask your parents and grandparents to help you fill it out further.');
INSERT INTO badge_level_requirements VALUES(2216,295,'level4',6,'Learn about terms used in family history research including: Ancestor Ancestry Ancestral Banns Biography Biographer Canon law Census record Baptism Christening Clan Descendant Cousin First cousin Second cousin First cousin once removed Emigration Genealogy Indenture Illegitimate Lineage Maiden name Progeny');
INSERT INTO badge_level_requirements VALUES(2217,295,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2218,296,'preschool',0,'Talk about what the word generosity means and how you can show it in your own life. How does the dictionary describe generosity?');
INSERT INTO badge_level_requirements VALUES(2219,296,'level1',1,'Demonstrate your understanding of generosity by doing something generous.');
INSERT INTO badge_level_requirements VALUES(2220,296,'level2',2,'Discuss the difference between generosity and being taken advantage of. Discuss how to be generous without being a pushover.');
INSERT INTO badge_level_requirements VALUES(2221,296,'level3',3,'Read about someone known for their generosity.');
INSERT INTO badge_level_requirements VALUES(2222,296,'level4',4,'Set aside 10% of your allowance or money earned to donate to a charity or cause of your choice.');
INSERT INTO badge_level_requirements VALUES(2223,296,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2224,297,'preschool',0,'Learn what genetics are and how they influence what you look like and more.');
INSERT INTO badge_level_requirements VALUES(2225,297,'preschool',1,'Have you ever been told you look like your mom or dad? Find at least three genetic traits that have been passed down in your family for at least three generations (grandparent, parent, child). This might be an eye color, hair type, skin color, nose shape, etc. Maybe your family is known for large feet, or lots of freckles. Genetic diseases like psoriasis may also be passed down. If you cannot do this exercise with your own family, do it with a friend’s.');
INSERT INTO badge_level_requirements VALUES(2226,297,'level1',2,'Compare two plants of the same variety either in your yard or at a park. How are they similar? How are they different? Do you have roses? Are they all the same color? Same size? Discuss how genetics affect how each plant looks (or smells!)');
INSERT INTO badge_level_requirements VALUES(2227,297,'level1',3,'Understand what is meant by dominant and recessive. Who was Gregor Mendel and how did his experiment with peas effect the study of genetics?');
INSERT INTO badge_level_requirements VALUES(2228,297,'level2',4,'Create a Punnett square for two gene types. For example, you could use brown eyes (dominant) and blue eyes (recessive). What would be the results of one brown eyed parent and one blue eyed parent. What if the brown eyed parent had one blue gene?');
INSERT INTO badge_level_requirements VALUES(2229,297,'level3',5,'Create a model of a double helix and label the parts.');
INSERT INTO badge_level_requirements VALUES(2230,297,'level4',6,'Understand and explain the following genetic terms: Phenotype Genotype Hybrid Alleles X chromosome Y chromosome Gene mapping Mutation Heterozygous Homozygous');
INSERT INTO badge_level_requirements VALUES(2231,297,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2234,299,'preschool',0,'Learn what a geocache is and how to find one.');
INSERT INTO badge_level_requirements VALUES(2235,299,'preschool',1,'Help find at least 3 geocaches.');
INSERT INTO badge_level_requirements VALUES(2236,299,'level1',2,'Know what types of hazards you might encounter while looking for a geocache and how to be prepared for them.');
INSERT INTO badge_level_requirements VALUES(2237,299,'level2',3,'Know what G.P.S. stands for. Learn about longitude and latitude and how they relate to a G.P.S. coordinate. Learn how to read a G.P.S. system and follow it to find specific coordinates.');
INSERT INTO badge_level_requirements VALUES(2238,299,'level3',4,'Discuss first aid and prevention for the types of injuries or illnesses that could occur while participating in geocaching activities, including cuts, scrapes, snakebite, insect stings, tick bites, exposure to poisonous plants, heat and cold reactions (sunburn, heatstroke, heat exhaustion, hypothermia), and dehydration.');
INSERT INTO badge_level_requirements VALUES(2239,299,'level4',5,'Learn the motto, “cache it in, trash it out ™”, meaning to pick up trash around the cache site and remove it when you leave. When you geocache, bring a trash bag with you to pick up trash. If you are finding a larger cache, bring an extra trash bag to leave in the cache with the “cache it in, trash it out” motto attached to it. Explain how the Leave No Trace rule applies to geocaching.');
INSERT INTO badge_level_requirements VALUES(2240,299,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2241,300,'preschool',0,'Be able to explain what geology means.');
INSERT INTO badge_level_requirements VALUES(2242,300,'preschool',1,'Make a collection of rocks and sort them in different ways such as color, texture, hardness, or crystals.');
INSERT INTO badge_level_requirements VALUES(2243,300,'level1',2,'Give examples of sedimentary, igneous, and metamorphic rocks.  Explain how each was formed.');
INSERT INTO badge_level_requirements VALUES(2244,300,'level2',3,'Create a chart showing suggested geological eras and periods. Look at the rocks in your area. In which period might they have been created?');
INSERT INTO badge_level_requirements VALUES(2245,300,'level3',4,'How does wind, water and ice, affect the landscape? Understand the four different stream types (straight, meandering, dendritic, trellis) and be able to explain which ones carry the largest sediment and why?');
INSERT INTO badge_level_requirements VALUES(2246,300,'level4',5,'Pick five resources that can be extracted or mined from the earth for commercial use. How is each product discovered and processed? What is it used for?');
INSERT INTO badge_level_requirements VALUES(2247,300,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2248,301,'preschool',0,'Look at pictures of an old town where no one lives anymore. Talk about what buildings you see and what they were used for.  Why does no one live there anymore?');
INSERT INTO badge_level_requirements VALUES(2249,301,'preschool',1,'Build or draw your own tiny ghost town using blocks, craft supplies, or paper and explain what happened to it.');
INSERT INTO badge_level_requirements VALUES(2250,301,'level1',2,'Learn what a ghost town is. Find out what causes towns to be abandoned (like mining towns, drought, or jobs moving away).  Look at pictures of several different ghost towns.  What do they have an in common?');
INSERT INTO badge_level_requirements VALUES(2251,301,'level2',3,'Learn the history behind one ghost town’s rise and fall. What industries or people caused it to grow? What led to its decline? Learn when it was abandoned and what remains there today.');
INSERT INTO badge_level_requirements VALUES(2252,301,'level3',4,'Study how ghost towns are preserved, studied, or protected. Are they tourist sites, archaeological sites, or left alone?');
INSERT INTO badge_level_requirements VALUES(2253,301,'level4',5,'Research how satellite images or aerial photography help scientists locate lost or forgotten towns.');
INSERT INTO badge_level_requirements VALUES(2254,301,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2255,302,'preschool',0,'Learn what a gift is.');
INSERT INTO badge_level_requirements VALUES(2256,302,'preschool',1,'Make a list of three people you would want to give gifts to. What type of gift would you give each person? Why would you give different gifts to certain people?');
INSERT INTO badge_level_requirements VALUES(2257,302,'level1',2,'Your list should include four people.');
INSERT INTO badge_level_requirements VALUES(2258,302,'level1',3,'What types of occasions do people give or receive gifts? List all the occasions you can think of, such as birthdays, Christmas, etc.');
INSERT INTO badge_level_requirements VALUES(2259,302,'level2',4,'Your list should include five people.');
INSERT INTO badge_level_requirements VALUES(2260,302,'level2',5,'How do you handle gifts given to you that you don’t like? What is an appropriate response? Write a couple paragraphs on how you would handle a situation like that.');
INSERT INTO badge_level_requirements VALUES(2261,302,'level3',6,'Your list should include six people.');
INSERT INTO badge_level_requirements VALUES(2262,302,'level3',7,'After receiving a gift, how should you react? What makes a good thank you card?');
INSERT INTO badge_level_requirements VALUES(2263,302,'level4',8,'Your list should include seven people.');
INSERT INTO badge_level_requirements VALUES(2264,302,'level4',9,'What do you feel is the best and most thoughtful gift you’ve ever given? What do you think is an important difference between gifts that are bought and gifts that are handmade?');
INSERT INTO badge_level_requirements VALUES(2265,302,'level5',10,'Your list should include eight people.');
INSERT INTO badge_level_requirements VALUES(2266,302,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2269,304,'preschool',0,'Identify ginger root in a local grocery store, encyclopedia or spice book. Taste at least one type of gingerbread such as gingerbread cookies, gingerbread cake, or ginger snaps.');
INSERT INTO badge_level_requirements VALUES(2270,304,'preschool',1,'Make a gingerbread house using a pint milk carton, covering sides and top with sheets of brown paper sack or graham crackers (break in half). Decorate with white play dough, icing, colored noodles, candies, etc.');
INSERT INTO badge_level_requirements VALUES(2271,304,'level1',2,'Taste two types of gingerbread.');
INSERT INTO badge_level_requirements VALUES(2272,304,'level1',3,'Find out what a rhizome is, how deep they are planted in soil and how the plant grows from the rhizome. Look at an encyclopedia and discover the location where most ginger is grown and harvested. Now locate that on a globe.');
INSERT INTO badge_level_requirements VALUES(2273,304,'level2',4,'Identify ginger root in a local grocery store, encyclopedia or spice book. Taste at least one type of gingerbread such as gingerbread cookies, gingerbread cake, or ginger snaps.');
INSERT INTO badge_level_requirements VALUES(2274,304,'level2',5,'Make a gingerbread house using graham crackers (or a kit), glue icing, and candy.');
INSERT INTO badge_level_requirements VALUES(2275,304,'level3',6,'to include discovering what a rhizome is, how deep they are planted in soil, and how the plant grows from rhizomes. Look at an encyclopedia and discover the location where most ginger is grown and harvested during which two months of the year. Now locate that on a globe.');
INSERT INTO badge_level_requirements VALUES(2276,304,'level3',7,'Construct a gingerbread house from a kit or homemade and add extra candy or figurines if desired.');
INSERT INTO badge_level_requirements VALUES(2277,304,'level4',8,'and 2. To include the construction a gingerbread house from a kit or scratch being sure to extend the decorating around the house by adding paths, trees, people, snowman, etc.');
INSERT INTO badge_level_requirements VALUES(2278,304,'level4',9,'Learn about the history of gingerbread houses. Get parent permission before using internet resources. Be able to explain facts about Gingerbread Fairs, why ginger was used during the 15th century and the type of toppings used on gingerbread. Describe how to store fresh ginger root.');
INSERT INTO badge_level_requirements VALUES(2279,304,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2280,305,'preschool',0,'Find examples of three different types of glass art, such as stained glass, glassware, glass figurines, etc.');
INSERT INTO badge_level_requirements VALUES(2281,305,'preschool',1,'Know your family’s rules for handling glassware, such using two hands to hold it, looking but not touching, always having an adult present when you hold the glass, etc.');
INSERT INTO badge_level_requirements VALUES(2282,305,'level1',2,'Learn how to clean and care for glass and glassware in your home.');
INSERT INTO badge_level_requirements VALUES(2283,305,'level1',3,'Look through catalogs and around your home and community.  Make a list of at least ten different items where glass is used in an artistic way.');
INSERT INTO badge_level_requirements VALUES(2284,305,'level2',4,'Learn about the history of glass making.');
INSERT INTO badge_level_requirements VALUES(2285,305,'level3',5,'Learn how glass is made and colors are produced.');
INSERT INTO badge_level_requirements VALUES(2286,305,'level4',6,'Make something out of glass. This requirement can be repeated up to 3 times.');
INSERT INTO badge_level_requirements VALUES(2287,305,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2290,307,'preschool',0,'Choose a specific god or goddess from any mythology.  Learn one interesting fact about the chosen god or goddess, such as their special powers or symbols.');
INSERT INTO badge_level_requirements VALUES(2291,307,'preschool',1,'Listen to or read a story about your chosen god or goddess.');
INSERT INTO badge_level_requirements VALUES(2292,307,'level1',2,'Learn about the attributes and symbols associated with the chosen god or goddess.');
INSERT INTO badge_level_requirements VALUES(2293,307,'level2',3,'Research the origin and cultural significance of the chosen deity.');
INSERT INTO badge_level_requirements VALUES(2294,307,'level3',4,'Create a timeline showcasing significant events or stories related to the chosen deity.  When did people start believing in this deity?  Do they still have followers today?');
INSERT INTO badge_level_requirements VALUES(2295,307,'level4',5,'Research archaeological evidence related to the worship of the chosen deity.');
INSERT INTO badge_level_requirements VALUES(2296,307,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2297,308,'preschool',0,'Learn about what the Gold Rush was and why it was important.');
INSERT INTO badge_level_requirements VALUES(2298,308,'preschool',1,'Learn to pan for gold.');
INSERT INTO badge_level_requirements VALUES(2299,308,'level1',2,'Learn about when and where the Gold Rush took place. Where does the term “49ers” come from?');
INSERT INTO badge_level_requirements VALUES(2300,308,'level2',3,'Discuss how the Gold Rush affected the development of California and the western states.');
INSERT INTO badge_level_requirements VALUES(2301,308,'level3',4,'Learn about the different types of jobs and business that came west as a result of the gold rush. What types of businesses were needed to support the new boom towns? What were the prices of common goods?');
INSERT INTO badge_level_requirements VALUES(2302,308,'level4',5,'Create a map of the largest gold fields discovered during the Gold Rush.');
INSERT INTO badge_level_requirements VALUES(2303,308,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2304,309,'preschool',0,'Earn the Hygiene Badge at the Preschool Level.');
INSERT INTO badge_level_requirements VALUES(2305,309,'preschool',1,'Learn the proper way to brush your hair and remove all the tangles.');
INSERT INTO badge_level_requirements VALUES(2306,309,'level1',2,'Earn the Hygiene Badge at Level 1.');
INSERT INTO badge_level_requirements VALUES(2307,309,'level1',3,'Learn how to properly wash and condition your hair.');
INSERT INTO badge_level_requirements VALUES(2308,309,'level2',4,'Earn the Hygiene Badge at Level 2.');
INSERT INTO badge_level_requirements VALUES(2309,309,'level2',5,'Learn how to shower or take a bath by yourself. Make sure you know how to properly wash your body, hair, feet, etc.');
INSERT INTO badge_level_requirements VALUES(2310,309,'level3',6,'Earn the Hygiene Badge at Level 3.');
INSERT INTO badge_level_requirements VALUES(2311,309,'level3',7,'Have a knowledgeable person teach you about types of faces and skin. What skin type do you have? Demonstrate proper skin cleansing and protection.');
INSERT INTO badge_level_requirements VALUES(2312,309,'level4',8,'Earn the Hygiene Badge at Level 4.');
INSERT INTO badge_level_requirements VALUES(2313,309,'level4',9,'Know how to properly care for your nails, such as trimming, caring for the nail beds, filing, etc. If you want, paint your nails for fun!');
INSERT INTO badge_level_requirements VALUES(2314,309,'level5',10,'Earn the Hygiene Badge at Level 5.');
INSERT INTO badge_level_requirements VALUES(2315,309,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2318,311,'preschool',0,'Learn to recognize and name at least 4 different grains such as wheat, rice, barley, corn, oats, millet, rye, or sorghum.');
INSERT INTO badge_level_requirements VALUES(2319,311,'preschool',1,'Eat at least 3 different types of whole grains.  Examples might include a sandwich on whole grain bread, a rice dish, whole grain cereal, oatmeal, etc.');
INSERT INTO badge_level_requirements VALUES(2320,311,'level1',2,'Recognize 5 types of grain.');
INSERT INTO badge_level_requirements VALUES(2321,311,'level1',3,'Learn the different parts of a grain including the bran, endosperm, and germ.  What is each part good for as part of your nutrition?');
INSERT INTO badge_level_requirements VALUES(2322,311,'level2',4,'Recognize 6 types of grain and eat 4.');
INSERT INTO badge_level_requirements VALUES(2323,311,'level2',5,'Understand the important role that grains play in the human diet.  Know how fiber, complex carbohydrates, iron, B vitamins, and folic acid effect your body.');
INSERT INTO badge_level_requirements VALUES(2324,311,'level3',6,'Recognize 7 types of grain and eat 5.');
INSERT INTO badge_level_requirements VALUES(2325,311,'level3',7,'Learn about how grains are grown and harvested.  Where are most of the grains in the U.S. produced?  What type of grain is grown?  Find these locations on a map.');
INSERT INTO badge_level_requirements VALUES(2326,311,'level4',8,'Recognize 8 types of grain and eat 6.');
INSERT INTO badge_level_requirements VALUES(2327,311,'level4',9,'Learn about the history of grain and the role it has played in various cultures over time. How has the use of grain expanded over the years to include items such as cakes and popcorn?');
INSERT INTO badge_level_requirements VALUES(2328,311,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2329,312,'preschool',0,'Read a book, or have one read to you, and learn what commas and periods are and why they are there.');
INSERT INTO badge_level_requirements VALUES(2330,312,'preschool',1,'Learn the difference between a noun and verb. Use the book you read to identify nouns and verbs in the story.');
INSERT INTO badge_level_requirements VALUES(2331,312,'level1',2,'Use periods and commas appropriately in a sentence and understand verb tense of past, present and future.');
INSERT INTO badge_level_requirements VALUES(2332,312,'level1',3,'Be able to explain why the first letter of a sentence is always capitalized. Know the difference between common, proper, and possessive nouns and which should be capitalized.');
INSERT INTO badge_level_requirements VALUES(2333,312,'level2',4,'Know and be able to use personal, possessive, and indefinite pronouns (e.g., I, me, my; they, them, their, anyone, everything).');
INSERT INTO badge_level_requirements VALUES(2334,312,'level2',5,'Understand the difference between an adjective and adverb and be able to identify them in a sentence.');
INSERT INTO badge_level_requirements VALUES(2335,312,'level3',6,'Know the 10 most common prefixes and suffixes and what they mean.');
INSERT INTO badge_level_requirements VALUES(2336,312,'level3',7,'Differentiate between simple, compound, and complex sentences.  Create original examples for each sentence type.');
INSERT INTO badge_level_requirements VALUES(2337,312,'level4',8,'Master the use of commas, semicolons, colons, and parentheses.');
INSERT INTO badge_level_requirements VALUES(2338,312,'level4',9,'Know all 8 parts of speech and be able to use each in an example as well as identify them in a piece of writing. (noun, pronoun, verb, adjective, adverb, preposition, conjunction, and interjection)');
INSERT INTO badge_level_requirements VALUES(2339,312,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your newfound knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2340,314,'preschool',0,'Be able to name the four elements of Greek philosphy (Earth, Water, Fire and Air) and have a general understanding of what each of them are.');
INSERT INTO badge_level_requirements VALUES(2341,314,'preschool',1,'Think of things you do at home that involve the four elements.  For example taking a bath uses water, cooking on a gas stove uses fire,  digging in the garden uses earth and blowing up a balloon uses air.  How many different things can you think of for each element?');
INSERT INTO badge_level_requirements VALUES(2342,314,'level1',2,'Help prepare a meal that uses all four elements.  For example soup uses water and vegetables from the earth.  It can be cooked on a gas stove or BBQ that uses fire and can be served with a soda that has air bubbles.');
INSERT INTO badge_level_requirements VALUES(2343,314,'level2',3,'Learn how the four elements can help provide energy to our world.  For example windmills turn air into energy.  Hydroelectric dams convert water to energy.  Burning coal from the earth can also make energy.   What are the pro and cons of each.');
INSERT INTO badge_level_requirements VALUES(2344,314,'level3',4,'Research the ancient beliefs and philosophies surrounding the four elements. Compare them with contemporary scientific understanding.  How many elements do we know of today?');
INSERT INTO badge_level_requirements VALUES(2345,314,'level4',5,'Research the impact of human activities on the balance of Earth, Water, Air, and Fire.  How do things like pollution, control burns, dams, deforestation, etc. effect the elements and our earth as a whole?');
INSERT INTO badge_level_requirements VALUES(2346,314,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2347,315,'preschool',0,'Look at different types of greeting cards (birthday, thank-you, holiday, etc.). Talk about when and why people send them.');
INSERT INTO badge_level_requirements VALUES(2348,315,'preschool',1,'Make a greeting card for someone you care about using crayons, markers, stickers, or other simple supplies.');
INSERT INTO badge_level_requirements VALUES(2349,315,'level1',2,'Make cards for four different occasions.');
INSERT INTO badge_level_requirements VALUES(2350,315,'level1',3,'.  Make greeting cards for two different occasions such as a birthday card anda Thank You card.  Use a minimum of two different types of accessories such as: Ribbons Metal brads Stickers Pieces of fabric Jewelry findings Buttons Pressed flowers');
INSERT INTO badge_level_requirements VALUES(2351,315,'level2',4,'Make cards for five different occasions.');
INSERT INTO badge_level_requirements VALUES(2352,315,'level2',5,'Make greeting cards using a minimum of four different techniques such as: Printing Watercolor Drawing Collage Origami Kirigami Rubber stamping Raising part of the design with pieces of foam to give depth');
INSERT INTO badge_level_requirements VALUES(2353,315,'level3',6,'Make greeting cards using at least four different styles of cards.  Examples might include: Portrait fold Landscape fold Center fold Accordion fold Pop-ups Map fold Pockets');
INSERT INTO badge_level_requirements VALUES(2354,315,'level4',7,'Learn about different papers and tools used in making cards.  Be able to identify by sight or feel at least five different kinds of paper such as cardstock, tissue paper, copy paper, scrapbook paper, vellum, or linen papers.  Discover what tools are available to help make fancy cards.  These might include punches, fancy scissors, machines and more.');
INSERT INTO badge_level_requirements VALUES(2355,315,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2358,317,'preschool',0,'Learn about and list three types of guinea pigs. Which one do you have or would you want as a pet?');
INSERT INTO badge_level_requirements VALUES(2359,317,'preschool',1,'How do you properly interact with a guinea pig? How should you pick it up and hold it? When playing with them, how can you prevent them from escaping into the house or even outside?');
INSERT INTO badge_level_requirements VALUES(2360,317,'level1',2,'Learn how to properly care for a domestic guinea pig. What should you feed a guinea pig? How many times a day should you feed it?  How often should you clean their cage?  What/when should you feed them? If you have other animals, such as a cat or dog, how can you protect the guinea pig from getting hurt?');
INSERT INTO badge_level_requirements VALUES(2361,317,'level2',3,'If you were to go out and get a guinea pig (even if you already own one), write down everything you would need to get for it, such as a cage, feeder, etc. Create a budget and look up prices for each item to figure out how much it would cost to own and take care of a guinea pig.');
INSERT INTO badge_level_requirements VALUES(2362,317,'level3',4,'Learn the history and life-span of the guinea pig. Where were they first discovered? How do they reproduce? How long do they typically live?');
INSERT INTO badge_level_requirements VALUES(2363,317,'level4',5,'Learn about guinea pig anatomy and scientific classification.');
INSERT INTO badge_level_requirements VALUES(2364,317,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2365,318,'preschool',0,'Learn to: Balance properly when standing on one leg – do this with your right and left legs in turn. Stand and walk on tip-toes. Walk sideways (as in dancing in a ring-a-rosies fashion). Point your toes. Stand up straight with your hands on your waist.');
INSERT INTO badge_level_requirements VALUES(2366,318,'preschool',1,'Properly stretching before a gymnastic session will help keep your body limber and flexible, and help you to avoid injury. Learn warm up stretches for each part of your body and learn to do them correctly to avoid pulling or tearing muscles. Understand what a spotter is and why they are important in gymnastics.  Never try any new tricks without an adult spotter present. Be able to explain and follow the safety rules of gymnastics.');
INSERT INTO badge_level_requirements VALUES(2367,318,'level1',2,'Learn all safety rules for gymnastics.');
INSERT INTO badge_level_requirements VALUES(2368,318,'level1',3,'Do at least one of the following: Artistic Gymnastics – do everything below: One balance beam exercise One vault exercise One tumbling exercise One uneven bars exercise Rhythmic Gymnastics – do three of the following: One ribbon exercise One ball exercise One hoop exercise One rope exercise One clubs exercise');
INSERT INTO badge_level_requirements VALUES(2369,318,'level2',4,'Learn at least 3 exercises for each area.');
INSERT INTO badge_level_requirements VALUES(2370,318,'level2',5,'What are the different levels of gymnastics?  How do you advance to each new level?  What competitions are available at each level? What teams can you join? Learn how gymnastic routines are scored.');
INSERT INTO badge_level_requirements VALUES(2371,318,'level3',6,'Learn 5 exercises for each area.');
INSERT INTO badge_level_requirements VALUES(2372,318,'level3',7,'Learn the most common injuries in gymnastics and how to prevent and treat them.');
INSERT INTO badge_level_requirements VALUES(2373,318,'level4',8,'Learn about different types of competitive gymnastics including artistic, rhythmic, sport acrobatics, and trampoline & tumbling.');
INSERT INTO badge_level_requirements VALUES(2374,318,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2375,319,'preschool',0,'Learn what a haiku is.');
INSERT INTO badge_level_requirements VALUES(2376,319,'preschool',1,'Read or have read to you at least two haiku');
INSERT INTO badge_level_requirements VALUES(2377,319,'level1',2,'(Read 4 Haiku instead of 2)');
INSERT INTO badge_level_requirements VALUES(2378,319,'level1',3,'Write your own Haiku.');
INSERT INTO badge_level_requirements VALUES(2379,319,'level2',4,'(Read 6 Haiku and write 2)');
INSERT INTO badge_level_requirements VALUES(2380,319,'level2',5,'Understand the 5-7-5 syllable structure of traditional Haiku and how Haiku in other languages differs from the traditional Japanese Haiku.  Is it ok to break the 5-7-65 structure?  Know the plural of the word Haiku.');
INSERT INTO badge_level_requirements VALUES(2381,319,'level3',6,'(Read 8 Haiku and write 4)');
INSERT INTO badge_level_requirements VALUES(2382,319,'level3',7,'Explain what a kigo and a kireji are.');
INSERT INTO badge_level_requirements VALUES(2383,319,'level4',8,'Learn at least three haiku techniques, such as montage, implied story, and symbolism.');
INSERT INTO badge_level_requirements VALUES(2384,319,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2388,322,'preschool',0,'Learn what hairstyling is.  Look at pictures of different hairstyles, such as: Braids (cowgirl, French, fishbone, etc.) Buns Chignons Ponytails Twists Wraps Quiffs Tucks Draping Rolls Permanent wave Mohawk/Mohican');
INSERT INTO badge_level_requirements VALUES(2389,322,'level1',1,'but try at least two different hairstyles.  Learn about hair care (washing, conditioning, etc.) and how to brush your hair properly.');
INSERT INTO badge_level_requirements VALUES(2390,322,'level1',2,'Learn about and make a list of the different tools and ornaments you can use to get your hair the way you want it, such as: Wraps/elastics/scrunchies Hair/headbands Fashion and French twist combs Gel or cream Barrettes Hairpins Bulldog clips Hair-grips Hair-slides Sticks Curlers Topsytail or Topsytail Jr. Hairspray Bun covers Banana clips Hair ribbons, etc. Don’t forget things like hairbrushes and combs.');
INSERT INTO badge_level_requirements VALUES(2391,322,'level2',3,'Learn about some of the “looks” and cuts that there have been in history, such as Mohawk/Mohican, “Bubble cut”, permanent wave, Afro style, bob, “Goth look”, etc.');
INSERT INTO badge_level_requirements VALUES(2392,322,'level2',4,'Make a timeline of when different hairstyles were popular.  You must have at least 10 different hairstyles on your timeline. Look at books about fashion through the centuries; most of them will say something about the hairstyles of the times.');
INSERT INTO badge_level_requirements VALUES(2393,322,'level3',5,'You must have at least 15 hairstyles on your timeline.');
INSERT INTO badge_level_requirements VALUES(2394,322,'level3',6,'Learn about hairstyles from different cultures.  Tell your family, friends, or group what you learned.');
INSERT INTO badge_level_requirements VALUES(2395,322,'level4',7,'You must have at least 20 hairstyles on your timeline.');
INSERT INTO badge_level_requirements VALUES(2396,322,'level4',8,'Read a biography of a famous hairdresser, such as Vidal Sassoon. If you earned this badge at a different level you must read about a new person.');
INSERT INTO badge_level_requirements VALUES(2397,322,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2398,323,'preschool',0,'Know what the basics are to keeping your hair healthy. Washing with shampoo and conditioner, brushing your hair, and properly drying it. Why is it good to do these things?');
INSERT INTO badge_level_requirements VALUES(2399,323,'preschool',1,'Know how to put hair in a ponytail and how to properly take it out. You can demonstrate this on a doll, another person, or your own hair. Why should you not yank or pull a hair tie out of your hair? Level 1: Do four requirements include the two starred *');
INSERT INTO badge_level_requirements VALUES(2400,323,'preschool',2,'Think of four reasons why it might be important to take good care of your hair. What are the things we do to take care of our hair?  How does washing, conditioning, drying and brushing help keep our hair healthy?');
INSERT INTO badge_level_requirements VALUES(2401,323,'preschool',3,'Learn how to braid. You can demonstrate this on a doll, another person, or your own hair.');
INSERT INTO badge_level_requirements VALUES(2402,323,'level2',4,'Think of reasons why other people would be interested in your hair care. Think of five reasons why you should want to take good care of your hair. Why do people use shampoo and conditioner? What are some of the important nutrients for hair growth?');
INSERT INTO badge_level_requirements VALUES(2403,323,'level2',5,'Demonstrate how to put hair into a ponytail, how to braid hair, and learn about two ways to curl hair using different tools. With the help of a parent or adult, try one. Learn how to straighten hair using a tool and try it with the help of an adult if your hair is already curly.');
INSERT INTO badge_level_requirements VALUES(2404,323,'level3',6,'Discuss the importance of hair care to one’s appearance and health. Find out some of the health conditions that might affect hair growth. Investigate the nutrients that are important for healthy hair. Find out the best ways to comb and brush hair and the best way to use shampoo, conditioner, hair spray, and other hair products.');
INSERT INTO badge_level_requirements VALUES(2405,323,'level3',7,'plus demonstrate either a bun or a French braid.');
INSERT INTO badge_level_requirements VALUES(2406,323,'level4',8,'plus discuss the effect that repeated use of hair dryers, curling irons, bleaches and perms may have on your hair.');
INSERT INTO badge_level_requirements VALUES(2407,323,'level4',9,'plus demonstrate a French twist.');
INSERT INTO badge_level_requirements VALUES(2408,323,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2409,324,'preschool',0,'Learn about and list three types of hamsters. Which one do you have or would you want as a pet?');
INSERT INTO badge_level_requirements VALUES(2410,324,'preschool',1,'How do you properly interact with a hamster? How should you pick it up and hold it? When playing with them, how can you prevent them from escaping into the house or even outside?');
INSERT INTO badge_level_requirements VALUES(2411,324,'level1',2,'Learn how to properly care for a hamster. What should you feed a hamster? How many times a day should you feed it? How often should you clean their cage?  What/when should you feed them? If you have other animals, such as a cat or dog, how can you protect the hamster from getting hurt?');
INSERT INTO badge_level_requirements VALUES(2412,324,'level2',3,'If you were to go out and get a hamster (even if you already own one), write down everything you would need to get for it, such as a cage, feeder, wheel, etc. Create a budget and look up prices for each item to figure out how much it would cost to own and take care of a hamster.');
INSERT INTO badge_level_requirements VALUES(2413,324,'level3',4,'Learn the history and life-span of the hamster. Where were they first discovered? How do they reproduce? How long to they typically live?');
INSERT INTO badge_level_requirements VALUES(2414,324,'level4',5,'Learn how to properly care for a domestic hamster. How often should you clean their cage? When playing with them, how can you prevent them from escaping into the house or even outside? What/when should you feed them? If you have other animals, such as a cat or dog, how can you protect the hamster from getting hurt?');
INSERT INTO badge_level_requirements VALUES(2415,324,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2416,325,'preschool',0,'Learn who Hank the Cowdog is, and read/listen to a Hank the Cowdog book.');
INSERT INTO badge_level_requirements VALUES(2417,325,'level1',1,'If you earned this badge at a different level, choose a new book to read.');
INSERT INTO badge_level_requirements VALUES(2418,325,'level1',2,'Be able to identify five of the principal characters, including High Loper, Sally May, Slim Chance, Drover, and Little Alfred.');
INSERT INTO badge_level_requirements VALUES(2419,325,'level2',3,'Read two Hank books. Be able to identify Pete the Barncat; Miss Beulah the Collie; and Wallace and Junior, the Buzzards.');
INSERT INTO badge_level_requirements VALUES(2420,325,'level2',4,'Look at a map of Texas and find Ochiltree County. John R. Erickson, the author of Hank the Cowdog,  is from Perryton, Tx. Locate Perryton on your map.');
INSERT INTO badge_level_requirements VALUES(2421,325,'level3',5,'Read three different Hank books. Be able to identify Miss Viola; Rip and Snort, the Coyotes; Madame Moonshine; and Eddy the Rac.');
INSERT INTO badge_level_requirements VALUES(2422,325,'level3',6,'Learn about the author, John Erickson. How many books and articles has he written? What awards has he received? Make a timeline of John Erickson’s books, putting them in order of publishing date.');
INSERT INTO badge_level_requirements VALUES(2423,325,'level4',7,'Read four different Hank books. Be able to identify Missy Coyote; Plato; Miss Scamper; and Baby Molly.');
INSERT INTO badge_level_requirements VALUES(2424,325,'level4',8,'Find one of John Erickson’s non-fiction books, such as Cowboys are Partly Human or Panhandle Cowboy, and read it. Which do you like best, Hank the Cowdog or the other book you read?');
INSERT INTO badge_level_requirements VALUES(2425,325,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2426,326,'preschool',0,'Understand who Harry Potter is. Who are his two best friends? What is Hogwarts? Who is the author of the Harry Potter series?');
INSERT INTO badge_level_requirements VALUES(2427,326,'preschool',1,'When you go to Hogwarts, you can choose to take one animal with you. Typically, your options are an owl, a rat, a cat, or a toad. Which animal would you take with you and what would you name it?');
INSERT INTO badge_level_requirements VALUES(2428,326,'level1',2,'Read or have read to you at least one Harry Potter book.');
INSERT INTO badge_level_requirements VALUES(2429,326,'level1',3,'Watch at least one Harry Potter movie and compare it to the book it was based on. What are some differences you notice? Do you think the casting was done well?');
INSERT INTO badge_level_requirements VALUES(2430,326,'level2',4,'Read at least two Harry Potter books.');
INSERT INTO badge_level_requirements VALUES(2431,326,'level2',5,'Write a short biography about J.K. Rowling’s life. How did she come up with the idea for Harry Potter? How did the series change her life? There are a few documentaries about her. Watch one and compare it to the biography you wrote.');
INSERT INTO badge_level_requirements VALUES(2432,326,'level3',6,'Read at least four Harry Potter books.');
INSERT INTO badge_level_requirements VALUES(2433,326,'level3',7,'Learn about the history of the Hogwarts Houses. Who were their founders, and what personality traits did each one favor? Who are the House Ghosts? Name several characters from the book in each house. Also, with a parent’s permission, find a quiz online that will sort you into a Hogwarts House, like the one on Pottermore.');
INSERT INTO badge_level_requirements VALUES(2434,326,'level4',8,'Read the entire Harry Potter series.');
INSERT INTO badge_level_requirements VALUES(2435,326,'level4',9,'Name and learn about at least twenty different spells, charms or curses from the series (For example, Wingardium Leviosa is a charm that allows an object to levitate). Also, design your own spell or charm. What would it be called and what would it do?');
INSERT INTO badge_level_requirements VALUES(2436,326,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2437,327,'preschool',0,'. What are hats? Look at pictures of different hats. Try on at least three different styles of hat. Which is your favorite?');
INSERT INTO badge_level_requirements VALUES(2438,327,'level1',1,'. Do Preschool requirement 1*. Try on at least five different styles of hat.');
INSERT INTO badge_level_requirements VALUES(2439,327,'level1',2,'. Be able to identify at least three different styles of hat: Men: Bowler/Derby Cowboy hat/Stetson Boater Top Hat Fedora Baseball Cap Flat Cap Trilby French Foreign Legion hat Deerstalker Panama Women: Pillbox Hat Sunbonnet Cloche Picture Hat Cocktail Hat Both: Beret Beanie Breton Dunce’s Cap Peaked Cap Toque Turban Sunhat/Bucket hat Cavalier Hat');
INSERT INTO badge_level_requirements VALUES(2440,327,'level2',3,'. Do Level 1 requirements 1 & 2. Try on at least eight different styles of hat, and be able to identify at least five.');
INSERT INTO badge_level_requirements VALUES(2441,327,'level3',4,'. Do Level 2 requirements 1 & 2. Try on at least 10 different styles of hat and be able to identify at least eight.');
INSERT INTO badge_level_requirements VALUES(2442,327,'level3',5,'.  Learn the different parts of a hat: brim, crown, hatband, headband, peak, sideband, and tip.');
INSERT INTO badge_level_requirements VALUES(2443,327,'level4',6,'. Do Level 3 requirements 1 & 2. Try on at least 12 different styles of hat and be able to identify each one.');
INSERT INTO badge_level_requirements VALUES(2444,327,'level4',7,'.  Learn about the history of hats. What were milliners and hatters? Why did hatters frequently go mad? What was a “beaver”? What was a hatpin, and how was it used?');
INSERT INTO badge_level_requirements VALUES(2445,327,'level5',8,'.  Do Level 4 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2446,327,'level5',9,'. Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2449,329,'preschool',0,'Why is exercise important? Go participate in physical activity for 20 minutes a day for a week. You can play tag, play at the playground, do jumping jacks, etc. It doesn’t matter as long as you keep moving.');
INSERT INTO badge_level_requirements VALUES(2450,329,'preschool',1,'Go through your kitchen with a parent and learn which foods are healthy for you and which are not. Learn why eating healthy and limiting sweets is important to your health.');
INSERT INTO badge_level_requirements VALUES(2451,329,'level1',2,'Lifestyle activities are movements you use to accomplish everyday activities. Track five lifestyle activities for one week (examples below) and then try to increase three for the following week. How many times did you take a walk instead of riding in a car last week? How many flights of stairs did you take last week? How many times did you choose to get active instead of watching TV last week? How many times did you park at the far end of the parking lot instead of close to the store last week?');
INSERT INTO badge_level_requirements VALUES(2452,329,'level1',3,'Keep a record of what you eat for one week. Make sure you start with the first thing you eat or drink in the morning and finish with the last thing you eat or drink before bed. Don’t forget snacks. How does how much we eat and drink, and what those are, change our body’s health?');
INSERT INTO badge_level_requirements VALUES(2453,329,'level2',4,'Aerobic activity is movement that raises your heart rate and breathing. It gives you lots of energy and boosts your metabolism so that food is burned up faster and more efficiently. Aerobic exercise also improves the health of your mind and body so that you will be sick less often and deal with stress better. Do at least 20 minutes of aerobic activity at least 5 days a week for 2 weeks. Activities may include fast walking, jogging, tennis, basketball, soccer, jumping rope, bicycling or anything else you can think of that keeps you moving at a fast pace.');
INSERT INTO badge_level_requirements VALUES(2454,329,'level3',5,'Stretching increases flexibility and helps prevent soreness in muscles. It will increase your range of motion and help prevent injuries as well. Learn ten different types of stretches. Make sure you learn the proper way to warm up and use each stretch to prevent damaged muscles. Then, try these stretches out 5 days a week for two weeks.');
INSERT INTO badge_level_requirements VALUES(2455,329,'level4',6,'Strength training builds your muscles by wearing them out and prompting them to grow stronger and more toned. Strength training requires resistance, but can easily be done at home rather than in a gym. Pick a goal, like situps or pushups, and see how you can improve on how many you can do in two weeks.');
INSERT INTO badge_level_requirements VALUES(2456,329,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2457,330,'preschool',0,'Be able to identify the purpose of your heart in your body and where it is located.');
INSERT INTO badge_level_requirements VALUES(2458,330,'preschool',1,'Find 2 different places where you can feel your pulse. How does your pulse relate to your heart beating? Feel your heartbeat after you’ve been resting? What do you think will happen to your heartbeat after your run around?…. Test it out and see if you were right.');
INSERT INTO badge_level_requirements VALUES(2459,330,'level1',2,'Try to count your heart beats for 15 seconds for Preschool requirement #2.');
INSERT INTO badge_level_requirements VALUES(2460,330,'level1',3,'Explain how blood is pumped through the heart and around your body. Why does your knee bleed when you fall down?');
INSERT INTO badge_level_requirements VALUES(2461,330,'level2',4,'Can your body run out of blood if you hurt yourself? What can doctors do to help you if that happens?');
INSERT INTO badge_level_requirements VALUES(2462,330,'level2',5,'Build a model of your heart and use it to explain how your heart works.');
INSERT INTO badge_level_requirements VALUES(2463,330,'level3',6,'How many chambers does your heart have? What is each chamber for? How many valves does your heart have? What can doctors do if a chamber or valve is not working properly?');
INSERT INTO badge_level_requirements VALUES(2464,330,'level4',7,'Diagram the flow of blood through your heart and explain how oxygen is distributed through your body.');
INSERT INTO badge_level_requirements VALUES(2465,330,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2466,331,'preschool',0,'Learn what a heat wave is and why it is different from just a hot day.  Identify the best types of clothes to wear on a hot day (light, loose, and light-colored). Pick out and show an outfit you would wear on a hot day.');
INSERT INTO badge_level_requirements VALUES(2467,331,'preschool',1,'Learn why drinking water is important during hot weather.');
INSERT INTO badge_level_requirements VALUES(2468,331,'level1',2,'Demonstrate at least three different methods to stay cool during a heat wave (e.g., ice packs, cool baths, fans).');
INSERT INTO badge_level_requirements VALUES(2469,331,'level2',3,'Learn what the heat index is and how it is calculated.  Use a heat index chart to determine the perceived temperature for different combinations of heat and humidity.');
INSERT INTO badge_level_requirements VALUES(2470,331,'level3',4,'List the common health problems associated with heat waves (e.g., heat exhaustion, heat stroke).  Explain the symptoms and first aid treatments for these conditions as well as how to avoid them.');
INSERT INTO badge_level_requirements VALUES(2471,331,'level4',5,'Investigate the impact of heat waves on agriculture and food supply.');
INSERT INTO badge_level_requirements VALUES(2472,331,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2473,332,'preschool',0,'In heraldry, a “coat of arms” is the unique picture or shield that represents a person, family, corporation (like a business or school) or even country. Learn about different symbols used in a coat of arms and what they mean. Be able to describe the meaning of at least 1 symbol commonly used.');
INSERT INTO badge_level_requirements VALUES(2474,332,'preschool',1,'Design a simple coat of arms using crayons, markers, paint, or other craft supplies.');
INSERT INTO badge_level_requirements VALUES(2475,332,'level1',2,'Be able to describe the meanings of three different symbols or colors.');
INSERT INTO badge_level_requirements VALUES(2476,332,'level1',3,'Many families from Europe have a family crest or coat of arms. Find out if your family has one. If so, be able to recognize your family’s crest and draw your own version of it. If not, create your own family crest.');
INSERT INTO badge_level_requirements VALUES(2477,332,'level2',4,'Describe the meanings of five commonly used symbols.');
INSERT INTO badge_level_requirements VALUES(2478,332,'level2',5,'Each area on the Coat of Arms has a name. Be able to name at least three parts of a coat of arms.');
INSERT INTO badge_level_requirements VALUES(2479,332,'level3',6,'Be able to name at least five parts of a coat of arms.');
INSERT INTO badge_level_requirements VALUES(2480,332,'level3',7,'Another way a family was identified or used to tell everyone what they were about was with a family motto. Learn about different family motto’s and find out if yours has one. If not, work with your family to come up with one.');
INSERT INTO badge_level_requirements VALUES(2481,332,'level4',8,'and 2. Family motto’s are traditionally written in Latin. Find out what your family motto is in Latin.');
INSERT INTO badge_level_requirements VALUES(2482,332,'level4',9,'A Blazon is a formal description of a coat of arms, flag or similar emblem, from which the reader can reconstruct the appropriate image. In blazoning there are rules, established by ancient custom, which must be observed. One who blazons must know the proper terms of heraldry to accurately describe a crest, coat of arms, etc. Learn the meanings of the following terms: Field, Pale, Fesse, Ordinary, charges, Arms, Crest, Mantle.');
INSERT INTO badge_level_requirements VALUES(2483,332,'level5',10,'and 2. Be able to accurately blazon a coat of arms you have designed.');
INSERT INTO badge_level_requirements VALUES(2484,332,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2485,333,'preschool',0,'Taste an herbal tea in each taste category: spicy or flavorful, sour, neutral, and bitter.');
INSERT INTO badge_level_requirements VALUES(2486,333,'preschool',1,'Be able to identify the following, as well as the difference between the two: tea bags and loose herbs.');
INSERT INTO badge_level_requirements VALUES(2487,333,'level1',2,'Also be able to identify: Tea pot Tea kettle Steeping Boiling Strainer Mug Tea cups');
INSERT INTO badge_level_requirements VALUES(2488,333,'level1',3,'Explain the use of the items listed in requirement 1.');
INSERT INTO badge_level_requirements VALUES(2489,333,'level2',4,'Learn and practice kitchen safety. Learn how to turn on different kinds of burners and ways to be careful while pouring hot water. What can you do to help people not burn their mouths on hot drinks or hands on hot cups?');
INSERT INTO badge_level_requirements VALUES(2490,333,'level3',5,'Learn proper etiquette as it relates to serving someone hot tea and hosting a tea party.');
INSERT INTO badge_level_requirements VALUES(2491,333,'level4',6,'Do Level 3 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2492,333,'level4',7,'Learn about medicinal uses for herb teas. Learn the common health applications for at least three different kinds of herb tea.');
INSERT INTO badge_level_requirements VALUES(2493,333,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2494,334,'preschool',0,'Learn the difference between an herb and a spice.');
INSERT INTO badge_level_requirements VALUES(2495,334,'preschool',1,'Be able to identify at least two herbs by sight, smell, and taste.');
INSERT INTO badge_level_requirements VALUES(2496,334,'level1',2,'Be able to identify at least three herbs.');
INSERT INTO badge_level_requirements VALUES(2497,334,'level1',3,'Look through your kitchen and see how many food items you can find that contain at least one herb. What do you think these items would taste like if they did not use any herbs?');
INSERT INTO badge_level_requirements VALUES(2498,334,'level2',4,'Be able to identify at least four herbs.');
INSERT INTO badge_level_requirements VALUES(2499,334,'level2',5,'Make a recipe that uses at least three herbs.');
INSERT INTO badge_level_requirements VALUES(2500,334,'level3',6,'Be able to identify at least five herbs.');
INSERT INTO badge_level_requirements VALUES(2501,334,'level3',7,'Learn about at least three herbs that are good for medicinal purposes. Understand that herbs can also be dangerous when taken in too large a quantity or when they interact with other drugs. Know the dangers of your three herbs as well as the benefits.');
INSERT INTO badge_level_requirements VALUES(2502,334,'level4',8,'Be able to identify at least six herbs.');
INSERT INTO badge_level_requirements VALUES(2503,334,'level4',9,'Learn the proper way to store herbs so that they do not lose their potency.');
INSERT INTO badge_level_requirements VALUES(2504,334,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2505,335,'preschool',0,'Learn and follow Leave No Trace rules. Learn and follow all safety rules, including: Bring plenty of water and stay hydrated. Do not drink from streams or lakes. Only hike during daylight hours. Never hike alone, stay with a group and have at least 2 adults with you. Wear sturdy, comfortable shoes. Stay on the marked trail. Wear sunscreen Bring a whistle in case you get lost. Whistles are a lot louder than shouting. If you get lost. Stay put and blow your whistle.');
INSERT INTO badge_level_requirements VALUES(2506,335,'preschool',1,'Make a chart and record at least 2 hours of hiking with your family, friends, or group. This does not have to be one continuous hike.');
INSERT INTO badge_level_requirements VALUES(2507,335,'level1',2,'Make a chart and record at least 4 hours of hiking.');
INSERT INTO badge_level_requirements VALUES(2508,335,'level1',3,'Learn to identify the plants in your area that are poisonous, or can cause rashes or injury. Examples might include poison oak, nettles, poison ivy, poison sumac, cactus, or oleanders. Watch for these plants while you hike.');
INSERT INTO badge_level_requirements VALUES(2509,335,'level2',4,'Record at least 5 hours of hiking.');
INSERT INTO badge_level_requirements VALUES(2510,335,'level2',5,'Explain first aid for injuries or illnesses that can occur while hiking, including: Hypothermia Heatstroke Heat exhaustion Frostbite Dehydration Sunburn Sprained ankle Insect stings Tick bites Snakebite Blisters Hyperventilation Altitude sickness');
INSERT INTO badge_level_requirements VALUES(2511,335,'level3',6,'Record at least 6 hours of hiking.');
INSERT INTO badge_level_requirements VALUES(2512,335,'level3',7,'Learn how to read a trail map and use a compass or GPS to keep track of where you are.');
INSERT INTO badge_level_requirements VALUES(2513,335,'level4',8,'Record at least 7 hours of hiking.');
INSERT INTO badge_level_requirements VALUES(2514,335,'level4',9,'Develop a plan for conditioning yourself for a 10mile hike. How can you increase your fitness and stamina for longer hikes? Plan for a 10-mile hike including map routes, clothing and equipment list, and a list of foods for a trail lunch. When you are ready, take a hike of at least 10 miles.');
INSERT INTO badge_level_requirements VALUES(2515,335,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2516,336,'preschool',0,'Find out what the Hindenburg is and what it is known for.');
INSERT INTO badge_level_requirements VALUES(2517,336,'preschool',1,'Find out about different types of airships of that time period. What other names were they known by?');
INSERT INTO badge_level_requirements VALUES(2518,336,'level1',2,'Find out how big the Hindenburg was.');
INSERT INTO badge_level_requirements VALUES(2519,336,'level1',3,'Find out where the Hindenburg was built.');
INSERT INTO badge_level_requirements VALUES(2520,336,'level2',4,'Find out how many passengers were on the ship. How many survived the crash? How many were killed? How long did it take for the ship to be completely destroyed?');
INSERT INTO badge_level_requirements VALUES(2521,336,'level2',5,'Find out what caused the Hindenburg to crash. Is there more than one theory or explanation?');
INSERT INTO badge_level_requirements VALUES(2522,336,'level3',6,'Who was the oldest survivor of the Hindenburg and how old was that person when they died?');
INSERT INTO badge_level_requirements VALUES(2523,336,'level3',7,'What safety features were put in place on the Hindenburg and other airships?');
INSERT INTO badge_level_requirements VALUES(2524,336,'level4',8,'Find out what some of the amenities were on the Hindenburg. Were any of the amenities reserved for passengers only and not available to the crew? How do they compare to amenities on airplanes today?');
INSERT INTO badge_level_requirements VALUES(2525,336,'level4',9,'What was unique about the media coverage of the disaster?');
INSERT INTO badge_level_requirements VALUES(2526,336,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2529,338,'preschool',0,'Choose a historical event and be able to describe what happened.');
INSERT INTO badge_level_requirements VALUES(2530,338,'preschool',1,'Read an age level appropriate book about the event.');
INSERT INTO badge_level_requirements VALUES(2531,338,'level1',2,'If this was a bad event, what can we learn about how not to repeat it?  If it was a good event, what can we learn about how to duplicate it or make it even better the next time?');
INSERT INTO badge_level_requirements VALUES(2532,338,'level2',3,'Learn when and where the event happened.  Find the location on a map.');
INSERT INTO badge_level_requirements VALUES(2533,338,'level3',4,'Make a timeline of items that led up to the event and occurred as a consequence of the event.  Include a minimum of 10 items.');
INSERT INTO badge_level_requirements VALUES(2534,338,'level4',5,'Discuss the long term ramifications of the event.  What portion of the population did it effect?  How did it effect the environment?  Were there long term lasting effects from the event?  If so, how have they effected the ongoing population, environment, etc.?');
INSERT INTO badge_level_requirements VALUES(2535,338,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2536,339,'preschool',0,'Be able to recognize pictures of your chosen historical site.');
INSERT INTO badge_level_requirements VALUES(2537,339,'preschool',1,'Understand why this historical site is important.');
INSERT INTO badge_level_requirements VALUES(2538,339,'level1',2,'Visit your historical site in person if possible. If not, take a virtual tour online with permission from a parent/guardian. If neither is possible, watch a documentary or read a book about your site.');
INSERT INTO badge_level_requirements VALUES(2539,339,'level2',3,'Learn the history of your chosen historical site, along with any interesting facts you can find.  For example, Eastern State Penitentiary was the largest and most expensive public structure ever erected in the United States, and quickly became a model for more than 300 prisons worldwide.');
INSERT INTO badge_level_requirements VALUES(2540,339,'level3',4,'Learn what a Historical Society is and how they help history. Do you have a local Historical Society? What does it take for a location to register with a Historical Society? What are the different requirements for a local Historical Society versus a state or national society?');
INSERT INTO badge_level_requirements VALUES(2541,339,'level4',5,'Identify and describe the geographical and cultural features that influenced the development of the location. Why was it built in this specific location? Why was it designed this way? How did the time in which it was built influence it’s design?');
INSERT INTO badge_level_requirements VALUES(2542,339,'level5',6,'Teach someone about the historical location or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your newfound knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2543,340,'preschool',0,'Discuss with an adult what a country is and why it is important to understand the history of countries other than your own.');
INSERT INTO badge_level_requirements VALUES(2544,340,'preschool',1,'Have an adult help you find your chosen country on a map, also find the country where you live and compare how far away they are.');
INSERT INTO badge_level_requirements VALUES(2545,340,'level1',2,'Locate your country on a map and find out what other names it has had over history. What language do they speak there?  Have they always spoken this language?');
INSERT INTO badge_level_requirements VALUES(2546,340,'level1',3,'Learn 10 important historical events that took place in your country.');
INSERT INTO badge_level_requirements VALUES(2547,340,'level2',4,'Draw a timeline for your country. You must list at least 15 major events or people on the timeline and illustrate at least five of them. Share your timeline with at least two people.');
INSERT INTO badge_level_requirements VALUES(2548,340,'level3',5,'Have at least 25 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(2549,340,'level3',6,'Take a current map of your country and go back through history making a note of where the boundaries have changed through the centuries. Track the history of the five largest cities also. What were their founding dates? Were any of them destroyed and rebuilt? Have any of them shrunk or been overshadowed by another city due to economic changes?');
INSERT INTO badge_level_requirements VALUES(2550,340,'level4',7,'Learn about the history of the people of your country. Where did they come from? How has their religion affected their history? What language do they speak? Earn the Foreign Language badge for their language or write a report about their culture including information on customs, clothing, race, religion, food, and holidays. How have these things changed in each of the last five centuries?');
INSERT INTO badge_level_requirements VALUES(2551,340,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2552,341,'preschool',0,'Know what a doctor is, what the word medicine means, and how doctors and nurses use their knowledge of it to help sick people.');
INSERT INTO badge_level_requirements VALUES(2553,341,'level1',1,'Know the difference between emergency medicine and regular doctor practice.');
INSERT INTO badge_level_requirements VALUES(2554,341,'level2',2,'Learn who Hippocrates was, and what the Hippocratic Oath means. Know that there are different kinds of health professionals and be able to list five examples.');
INSERT INTO badge_level_requirements VALUES(2555,341,'level3',3,'Make a timeline of events in the history of medicine. You must have at least 10 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(2556,341,'level4',4,'You must have at least 20 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(2557,341,'level4',5,'Read a biography of a famous person in one of the medical professions, such as Dr. Albert Schweitzer, or a person connected with the history of medicine, such as Sir Alexander Fleming, who discovered penicillin. If you earn this badge at a different level you must read about a new person.');
INSERT INTO badge_level_requirements VALUES(2558,341,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2559,343,'preschool',0,'Learn what holistic wellness means and the five main areas it covers:  physical health, mental health, emotional health, spiritual health, and social health.');
INSERT INTO badge_level_requirements VALUES(2560,343,'preschool',1,'Learn and use one holistic method for each area to help improve your health.  For example physical: exercise; mental: puzzles; emotional: recognizing emotions and learning the appropriate way to express them; spiritual: practice gratitude; social: schedule time to meet with friends');
INSERT INTO badge_level_requirements VALUES(2561,343,'level1',2,'Mindful Eating: Engage in a week-long mindful eating challenge, pay close attention to your senses, emotions, and hunger cues during meals.  Discuss how what you eat affects your overall health.  How can food help or hurt your body?  How can it change your mental awareness or emotions?');
INSERT INTO badge_level_requirements VALUES(2562,343,'level2',3,'Mindful Breathing: Practice deep breathing exercises to help with stress anxiety.  Learn to use visual aids like imagining you are blowing up balloons or pretending to smell a flower.  Discuss how stopping and using mindful breathing can help control emotions and mental health.');
INSERT INTO badge_level_requirements VALUES(2563,343,'level3',4,'Complete a digital detox: refrain from screens (phones, computers, TV) for a whole day.Quality Sleep:');
INSERT INTO badge_level_requirements VALUES(2564,343,'level4',5,'Read three articles or watch 3 videos (with parent permission) on personal development or self-improvement.  If appropriate, implement what you learned.');
INSERT INTO badge_level_requirements VALUES(2565,343,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2566,344,'preschool',0,'Look at pictures of a home under construction or watch one being built in your area.  What do the inside of the walls look like?  What parts go up first?  Last?');
INSERT INTO badge_level_requirements VALUES(2567,344,'level1',1,'Do Preschool requirement #1.');
INSERT INTO badge_level_requirements VALUES(2568,344,'level1',2,'Demonstrate how to read a basic floor plan.  Be able to find windows, doors, stairs, toilets, closets, the water heater, appliances, bathtubs and showers.  Draw a floor plan of an imaginary house to be built in your area.   Make sure to include at least one kitchen, bathroom,  bedroom and laundry area.  Level 3 and above should draw to scale.');
INSERT INTO badge_level_requirements VALUES(2569,344,'level2',3,'In planning a house, and choosing a site for it, discuss what things should be considered such as distance to town, views, level land, utilities etc.  How does each affect the cost and desirability of the house?');
INSERT INTO badge_level_requirements VALUES(2570,344,'level3',4,'.  Discuss in detail what items should be on a home construction budget.  Make sure to include: All building materials Labor Utility installations Roadways Permits Plumbing Lighting Appliances Finish work');
INSERT INTO badge_level_requirements VALUES(2571,344,'level4',5,'Learn about home construction loans verses a traditional mortgage.  What are the going interest rates at this time?  How much must you have in cash?  How is the construction load paid out?  How can building a home be more or less expensive than buying one in your area?');
INSERT INTO badge_level_requirements VALUES(2572,344,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2573,345,'preschool',0,'Make a decoration for your room.');
INSERT INTO badge_level_requirements VALUES(2574,345,'level1',1,'Do Preschool requirement #1.');
INSERT INTO badge_level_requirements VALUES(2575,345,'level1',2,'Have someone help you understand what color, form (overall shape), line (implied direction or boundary), mass (bulk of an object) and texture (how it looks like it will feel) are. Find at least three different examples of each of these in your home.');
INSERT INTO badge_level_requirements VALUES(2576,345,'level2',3,'Do Level 1 requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(2577,345,'level2',4,'Learn what color, form, line, mass, and texture are. Pick three of these design elements and find photos to illustrate two extremes of those three elements. Example for texture: A photo of a stainless steel chair, very sleek & smooth, versus a fluffy bean bag-type chair.');
INSERT INTO badge_level_requirements VALUES(2578,345,'level3',5,'Do Level 2 requirements #1 & 2. Measure the length and width and height of your living room. Go to a store or stores that sell house paint, wall paper, and floor coverings. Figure out how much it would cost to do each of the following to your living room: Paint the walls Paint the ceiling Wallpaper the walls Put in carpet Put in a tile floor Lay a wood floor. Figure out how many months it would take to save up for each of the projects if you could save $100 per month. Find out what some of the advantages and disadvantages are for different kinds of floor coverings and wall coverings.');
INSERT INTO badge_level_requirements VALUES(2579,345,'level3',6,'Learn how color, form, line, mass, and texture relate to the inside of a home. Pick three of these design elements and find photos to illustrate two extremes of those three elements. One set of photos must be of something other than furniture (floor coverings or light fixtures, etc.) Discuss how the following components of composition relate to choosing furniture and choosing colors and patterns on walls, floors, and ceilings: focal point, scale and proportion, harmony and unity, contrast, and variety.');
INSERT INTO badge_level_requirements VALUES(2580,345,'level4',7,'Do Level 3 requirements #1 & 2. Redesign (on paper or foam core board) your family’s or a friend’s living room. You may “keep” two or three of the current pieces of furniture or accessories. Draw a diagram to scale on graph paper of where everything would go. Make notes in the margin with swatches or paint samples and photos of accessories (or use a second piece of paper). Estimate how much it would cost. Find out what some of the advantages and disadvantages are for different kinds of floor coverings and wall coverings.');
INSERT INTO badge_level_requirements VALUES(2581,345,'level4',8,'Learn how color, form, line, mass, and texture relate to the inside of a home. Pick three of these design elements and find photos to illustrate two extremes of those three elements. Example for texture: A photo of a stainless steel chair, very sleek & smooth, versus a fluffy bean bag-type chair. One set of photos must be of something other than furniture (floor coverings or light fixtures, etc.) Discuss how the following components of composition relate to choosing furniture and choosing colors and patterns on walls, floors, and ceilings: focal point, scale and proportion, harmony and unity, contrast, and variety. Find a photo that is either a good example or poor example of each of these terms.');
INSERT INTO badge_level_requirements VALUES(2582,345,'level5',9,'Do Level 4 requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(2583,345,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional requirements.');
INSERT INTO badge_level_requirements VALUES(2584,346,'preschool',0,'Learn what to do if you catch on fire; Stop. Drop. and Roll.  Demonstrate how to do this.  Learn what items in your house can catch things on fire. Know basic safety when around these items such as keeping paper, clothing, and hair away from them at all times.');
INSERT INTO badge_level_requirements VALUES(2585,346,'level1',1,'Explain why you should never play with matches, lighters or other fire sources.');
INSERT INTO badge_level_requirements VALUES(2586,346,'level1',2,'Create a fire escape plan with your family in case of a house fire and then hold a fire drill for a pretend fire.  Know how to exit a structure that is on fire and how to call 911.');
INSERT INTO badge_level_requirements VALUES(2587,346,'level2',3,'Do Level 1requirements 1 & 2');
INSERT INTO badge_level_requirements VALUES(2588,346,'level2',4,'Make sure your house has a working smoke detector in each area of your house and that the batteries are fresh.');
INSERT INTO badge_level_requirements VALUES(2589,346,'level3',5,'Do a fire safety walk through of your house. Learn and follow basic fire safety rules including: Keep clothes, blankets, curtains, towels, and other items that can easily catch on fire at least three feet from space heaters and away from stove burners. Place space heaters where they will not tip over easily. Have chimneys cleaned and inspected every year by a professional. Always use a metal mesh screen with fireplaces and leave glass doors open while burning a fire. Never leave cooking unattended. Be sure your stove and small appliances are off before going to bed. Check for worn wires and do not run cords under rugs or furniture. Never overload electrical sockets.');
INSERT INTO badge_level_requirements VALUES(2590,346,'level4',6,'Learn about causes of electrical fires.  Demonstrate the proper way  to correctly unplug an electrical appliance, as doing it wrong could result in a spark/ fire.  Explain how overloading electric outlets can cause heat build up and result in fire.  Explain why very old appliances, or those with damaged wiring, can cause a fire.  Learn safety precautions to avoid electrical fires such as: Routinely check your electrical appliances and wiring. Frayed wires can cause fires. Replace all worn, old or damaged appliance cords immediately. Replace any electrical tool if it causes even small electrical shocks, overheats, shorts out, or gives off smoke or sparks. Keep electrical appliances away from wet floors and counters and pay special care to electrical appliances in the bathroom and kitchen. Buy electrical products evaluated by a nationally recognized laboratory. Keep clothes, curtains, and other potentially combustible items at least three feet from all heaters. If an appliance has a three-prong plug, use it only in a three-slot outlet. Never force it to fit into a two- slot outlet or extension cord. Don’t allow children to play with or around electrical appliances like space heaters, irons, and hair dryers. Use safety closures to “child-proof” electrical outlets. Use electrical extension cords wisely and never overload extension cords or wall sockets. Immediately shut off, then professionally replace, light switches that are hot to the touch and lights that flicker.');
INSERT INTO badge_level_requirements VALUES(2591,346,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2592,347,'preschool',0,'Discuss and follow general safety rules regarding home repairs, both when you are doing the repairs as well as when you are simply around someone else doing repairs.');
INSERT INTO badge_level_requirements VALUES(2593,347,'level1',1,'Do Preschool requirement #1.  Replace a light bulb in a fixture or lamp.  Make sure that the switch is turned off or the lamp unplugged before beginning.');
INSERT INTO badge_level_requirements VALUES(2594,347,'level1',2,'Put together a tool kit of tools that every home should have to conduct basic maintenance on their home and belongings.  Explain why each tool was chosen and what jobs it might be used for.');
INSERT INTO badge_level_requirements VALUES(2595,347,'level2',3,'Know how to turn off the water and gas supply for your home and whom to call if there is a problem.');
INSERT INTO badge_level_requirements VALUES(2596,347,'level3',4,'Demonstrate how to safely use the following tools: Wrench Saw Hammer Pliers Screwdriver Tape measure Box cutter');
INSERT INTO badge_level_requirements VALUES(2597,347,'level4',5,'Under adult supervision, demonstrate how to properly and safely sharpen knives using a knife sharpener or whetstone.');
INSERT INTO badge_level_requirements VALUES(2598,347,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2599,348,'preschool',0,'What is a home-maker?  Talk to a home-maker about what they do.');
INSERT INTO badge_level_requirements VALUES(2600,348,'level1',1,'Make a list of all the things a home-maker may do in a day.');
INSERT INTO badge_level_requirements VALUES(2601,348,'level1',2,'Help a home-maker with some of their daily activities.');
INSERT INTO badge_level_requirements VALUES(2602,348,'level2',3,'Include in your list all the things a home-maker may do in a week.');
INSERT INTO badge_level_requirements VALUES(2603,348,'level2',4,'Learn how to do one of the jobs that a home-maker would do in a day and do it.');
INSERT INTO badge_level_requirements VALUES(2604,348,'level3',5,'Include in your list all the things a home-maker may do in a month.');
INSERT INTO badge_level_requirements VALUES(2605,348,'level3',6,'Many home-makers also have home businesses.  Find out which are the most popular kinds of businesses for home-makers.  If possible, talk to a home-maker who also has a home business.');
INSERT INTO badge_level_requirements VALUES(2606,348,'level4',7,'Include in your list all the things a home-maker may do in a year.');
INSERT INTO badge_level_requirements VALUES(2607,348,'level4',8,'Successful home-makers know the value of their time.  Research books, websites (with parental permission), magazines etc which help home-makers plan/set goals, chart progress and achieve weekly, monthly, yearly goals.  Which method(s) do you like best?  Why?');
INSERT INTO badge_level_requirements VALUES(2608,348,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2609,349,'preschool',0,'Being sick can make someone feel very sad and lonely, especially if someone has been sick or unable to move for a long time. Sometimes the thing that can make a sick person’s day is just having company. Go and visit someone who is in a hospital, care facility, or is home-bound and spend at least half an hour with them. You could take a book or some magazines for them to read, flowers for them to look at, or a movie to watch together. Anything that could brighten someone’s day.');
INSERT INTO badge_level_requirements VALUES(2610,349,'level1',1,'Learn to do something (daily chores or a mundane activity) for or with a sick person that’s difficult for them to do by themselves – comb hair, eat a meal, rub a back, help with getting dressed or changed someone’s bedding. Learn how to do some of these tasks and perform them for a half hour.');
INSERT INTO badge_level_requirements VALUES(2611,349,'level1',2,'Learn to help with a sick or incapacitated person’s health needs – extra drinks, changing a bandage,  taking a temperature, getting into a wheelchair, hand washing, etc.  Be sure to get permission from the adult in charge first.  Spend at least a half an hour doing such things after first learning how.');
INSERT INTO badge_level_requirements VALUES(2612,349,'level2',3,'Spend at least one hour helping someone with something they struggle to do by themselves.  Learn to help with a sick or incapacitated person’s health needs – extra drinks, changing a bandage,  taking a temperature, getting into a wheelchair, hand washing, etc.  Be sure to get permission from the adult in charge first.  After learning how, spend at least one hour doing such things.');
INSERT INTO badge_level_requirements VALUES(2613,349,'level2',4,'Earn the First Aid badge at your level and write out a reason why its important to know first aid at home, especially if a person in the family isn’t well.');
INSERT INTO badge_level_requirements VALUES(2614,349,'level3',5,'Spend at least one and a half hours helping someone with something they struggle to do by themselves. Spend at least one and a half hours helping a sick or incapacitated person with their health needs.');
INSERT INTO badge_level_requirements VALUES(2615,349,'level3',6,'Learn about the health condition of a relative or friend. Understand what their limitations may be because of their condition and find at least one way that you could help them be more comfortable.');
INSERT INTO badge_level_requirements VALUES(2616,349,'level4',7,'Spend at least two helping someone with something they struggle to do by themselves. Spend at least two helping a sick or incapacitated person with their health needs.');
INSERT INTO badge_level_requirements VALUES(2617,349,'level4',8,'Learn to do or improve your ability at helping with a sick person’s daily activities.  This can include bathing, fixing hair and nails, preparing foods for a special diet, or cleaning up after an ill person.  Spend two hours on such things after your instruction period is ended. Learn to help with medical health needs of another person – changing bandages & diapers, taking temperatures, blood sugar or blood pressure with more than one type of equipment when applicable;  helping with transfers to chairs, commodes, or beds; sterile or cleaning techniques, etc.  Get permission from the adult in charge for everything you do and spend at least two hours helping with these medical needs.');
INSERT INTO badge_level_requirements VALUES(2618,349,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2620,351,'preschool',0,'Know which cupboards in your house you are not allowed to open and which items you are not allowed to touch as they could harm you.  Explain why young children should not touch knives or other sharp objects, play with matches or lighters, or go near stoves or ovens without a parent or responsible adult.  Understand the danger of sticking objects into the electrical outlets');
INSERT INTO badge_level_requirements VALUES(2621,351,'level1',1,'Do Preschool requirement #1.  Create a first aid kit to keep at home. Make sure everyone knows where it is kept, and be sure to keep it stocked if you use it.');
INSERT INTO badge_level_requirements VALUES(2622,351,'level1',2,'Make a list of important emergency phone numbers and keep it posted in a prominent place at home. Make sure your own address and phone number are listed on it, because sometimes in an emergency, your mind goes blank and you can’t provide this necessary information to Emergency Services providers. Some phone numbers to include are the police, your doctor(s), the fire department, and Poison Control.  Know how to call 911 and practice with an adult answering questions that you might be asked.');
INSERT INTO badge_level_requirements VALUES(2623,351,'level2',3,'Do Level 1 requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(2624,351,'level2',4,'Have a safety scavenger hunt and find as many safety hazards as possible in a single room, then work with your parents/leader to correct each one.  A sample checklist may include: Unused electrical outlets are kept uncovered. Knives and sharp objects are kept in reach of children. Non-slip rugs are not placed where there may be water on the floor. Cleaning supplies and other chemicals are kept in reach of small children. Medications and vitamins are kept in reach of small children. Electrical cords with damage or frays. Overloaded electrical outlets. Electrical cords are tangled and out where people can trip on them.');
INSERT INTO badge_level_requirements VALUES(2625,351,'level3',5,'Do Level 2 requirements # 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2626,351,'level3',6,'Learn what dangerous chemicals are in your home and keep them locked up and away from children. Learn the Poison Control phone number and have it posted in your house.');
INSERT INTO badge_level_requirements VALUES(2627,351,'level4',7,'Do Level 3 requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(2628,351,'level4',8,'To prevent scalding burns from tap water, make sure your hot water heater is set to no more than 120 degrees.');
INSERT INTO badge_level_requirements VALUES(2629,351,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2630,353,'preschool',0,'Create a name, school colors and school mascot for your homeschool group or family. If you homeschool through an organized public or charter school, know the name, colors and mascot for your school.');
INSERT INTO badge_level_requirements VALUES(2631,353,'preschool',1,'Create a song, chant, or motto for you homeschool group or family.');
INSERT INTO badge_level_requirements VALUES(2632,353,'level1',2,'Think of a tradition you can do for the first day of homeschool each year and a way to celebrate the end of the year.');
INSERT INTO badge_level_requirements VALUES(2633,353,'level2',3,'Discuss with your parents why they decided to homeschool.');
INSERT INTO badge_level_requirements VALUES(2634,353,'level3',4,'Research homeschool stereotypes and myths. Create a presentation (written, oral or artistic) that corrects the misinformation that is spreading regarding homeschooling. This can be a serious presentation, comedic, artistic, etc. Be creative. Then, present it to a group of your choice.');
INSERT INTO badge_level_requirements VALUES(2635,353,'level4',5,'Learn about your local homeschool laws. What is required to be able to homeschool in your state, and what subjects must you study? What teaching credentials, if any, are required?');
INSERT INTO badge_level_requirements VALUES(2636,353,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2641,356,'preschool',0,'Where does honey come from?');
INSERT INTO badge_level_requirements VALUES(2642,356,'preschool',1,'What are the ingredients in honey?');
INSERT INTO badge_level_requirements VALUES(2643,356,'level1',2,'Name three different types of bees.');
INSERT INTO badge_level_requirements VALUES(2644,356,'level1',3,'What kind of bees are used to make honey? Where can they be found?');
INSERT INTO badge_level_requirements VALUES(2645,356,'level2',4,'When is honey in season? Can it be made year round? Research a popular honey-producing region.');
INSERT INTO badge_level_requirements VALUES(2646,356,'level3',5,'Try three different types of honey. Compare the color and flavor. Which was your favorite and why?');
INSERT INTO badge_level_requirements VALUES(2647,356,'level4',6,'Learn the process of honey-making, starting with the bee and ending with the packaging process. How long does it take? What are some key steps that take place? What are some safety precautions that can be taken when working around bees?');
INSERT INTO badge_level_requirements VALUES(2648,356,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2649,357,'preschool',0,'Learn the definition of honor and be able to give an example of a way you can honor another person and a way to honor a thing such as a flag or historic site.');
INSERT INTO badge_level_requirements VALUES(2650,357,'preschool',1,'Do something to show honor to your parents or grandparents.');
INSERT INTO badge_level_requirements VALUES(2651,357,'level1',2,'Read a book or article about someone worthy of honor, or the story of how someone went out of their way to pay honor to another person.');
INSERT INTO badge_level_requirements VALUES(2652,357,'level2',3,'Give two examples of how to show honor to both people and things.');
INSERT INTO badge_level_requirements VALUES(2653,357,'level2',4,'Role play situations where you choose to honor another person. Discuss how to honor someone even if they make a mistake.');
INSERT INTO badge_level_requirements VALUES(2654,357,'level3',5,'Give three examples of how to show honor to both people and things.');
INSERT INTO badge_level_requirements VALUES(2655,357,'level3',6,'Discuss how you can treat a stranger or casual acquaintance in ways that communicate their worth regardless of their talents or behavior.');
INSERT INTO badge_level_requirements VALUES(2656,357,'level4',7,'Write an essay, song, story or poem about honor or about a person you want to honor.');
INSERT INTO badge_level_requirements VALUES(2657,357,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2658,358,'preschool',0,'Learn the safety procedures and you should follow whenever you are around horses or working with them including what you should wear.');
INSERT INTO badge_level_requirements VALUES(2659,358,'level1',1,'Visit a stable. Find out from the owner/manager what is involved in the care of a horse. Find out how much and what kind of food a horse needs daily, acceptable treats for horses, everyday care for a stable, and how often a horse needs to be shod and why.');
INSERT INTO badge_level_requirements VALUES(2660,358,'level2',2,'Learn to identify the following horse colors: Roan Bay Palomino Pinto Chestnut Dun Buckskin Pinto Grey, including Fleabitten Appaloosa');
INSERT INTO badge_level_requirements VALUES(2661,358,'level2',3,'Explain how to approach and lead a horse safely from a stall, corral, or field and how to tie the horse securely.');
INSERT INTO badge_level_requirements VALUES(2662,358,'level3',4,'Learn to identify the following markings: Bald face Stripe Blaze Snip Star Sock Stocking');
INSERT INTO badge_level_requirements VALUES(2663,358,'level3',5,'Be able to identify these parts of a horse: Withers Hooves Mane Tail Forelock Barrel Chestnut Muzzle Fetlock Knee Poll Flank Cannon bone Hock');
INSERT INTO badge_level_requirements VALUES(2664,358,'level4',6,'Learn about common horse ailments and diseases, such as colic and thrush. Know the symptoms and how they are treated.');
INSERT INTO badge_level_requirements VALUES(2665,358,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2670,361,'preschool',0,'What are the proper safety precautions you should take when you are around a horse?  How should you approach them?  What is the proper way to feed them a treat?  Always make sure you have the owner’s permission before approaching, feeding, or riding a horse.  Learn what kind of proper clothing, footwear, and headgear should be worn.');
INSERT INTO badge_level_requirements VALUES(2671,361,'level1',1,'Before a horse is ridden, it must be groomed. Why is this necessary? Learn how to properly groom a horse.');
INSERT INTO badge_level_requirements VALUES(2672,361,'level2',2,'Demonstrate the following: How to saddle and bridle a horse. The correct way to mount and dismount. How to turn and stop a horse at both a walk and a trot. What to do if your horse rears, trips, bucks, stops, or bolts.');
INSERT INTO badge_level_requirements VALUES(2673,361,'level3',3,'Learn why learning to ride while being lunged or learning how to ride without stirrups can teach a person to have a better seat. In equine jargon, what does “seat” mean?');
INSERT INTO badge_level_requirements VALUES(2674,361,'level4',4,'Be able to demonstrate the correct posture when riding. Why does having correct posture matter?');
INSERT INTO badge_level_requirements VALUES(2675,361,'level4',5,'Learn about at least ten different riding disciplines, such as reining, dressage, show jumping, horse racing, or trail riding. Which one appeals most to you? What equipment do you and your horse need? What should you wear?');
INSERT INTO badge_level_requirements VALUES(2676,361,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2677,363,'preschool',0,'A hostess/host is always polite and gracious. Learn basic hostess/host manners, such as: Always greet someone warmly when they come over to your house.   Make sure to introduce anyone who doesn’t know each other and mention something they have in common so that they have something to talk about. Say, “Please” and “Thank you” often. It shows respect and appreciation. In addition, if you are thanked, then say “You’re welcome”. Always thank someone for coming to your house. Make sure your house is clean.  A dirty house makes guests uncomfortable. Be a good sport. After playing a game (sports, cards, board game), whether you win or lose, be nice. If you win, do not gloat or show off, but be kind.  If you lose, don’t sulk or get mad, but be a good sport and tell the other person “good game” or speak well of them. Take compliments with the intent they were given. If someone praises you, be gracious and say, “thank you”, and avoid putting yourself down or pointing out flaws. Always let your guest go first, and do not interrupt other people when they are speaking. Always send thank you notes when someone has given you anything or done something particularly kind.');
INSERT INTO badge_level_requirements VALUES(2678,363,'level1',1,'Learn and demonstrate good table manners, such as: Wash hands before eating. Sit up straight at the table with your feet in front of you. Place your napkin in your lap.  Use it only to dab you face. Do not use it to blow your nose.  Excuse yourself and go to the bathroom if you need to do this. Eat with a fork unless the food is meant to be eaten with fingers.  Hold your fork, knife and spoon correctly.  Never hold them in a fist. Do not chew with your mouth open, or take such a big bite that you have difficulty chewing.  Eat slowly and do not gobble your food. Do not speak with your mouth full. Always say please and thank you.  If you do not wish to eat something, simply  say, no thank you. Do not pick anything out of your teeth, it’s gross. If it bothers you that bad,  excuse yourself and go to the restroom to pick. When eating rolls, break off a piece of bread before buttering. Eating a whole piece of bread looks tacky. Don’t reach over someone’s plate for something, ask for the item to be passed to you. A good host/hostess always waits until everyone else is served before eating.');
INSERT INTO badge_level_requirements VALUES(2679,363,'level2',2,'Do Level 1 requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(2680,363,'level2',3,'Host a party or get together for your friends.  Make sure to send out invitations at least 2 weeks in advance.  Information on the invitations may include: What, or who, the party is for Where (include directions if necessary) When (both date and time) Phone number and RSVP information Any special instructions (Is this a costume party? Do they need to bring anything? Is it a swim party?) Anticipate that some people will not RSVP and simply show up.  Plan to have enough food and supplies for a few extra people just in case.  At the end of your party, make sure you send out thank you notes to your friends who attended. Don’t forget to learn proper event etiquette, such as: Greet your guests politely when they arrive and make sure to introduce people who may not know anyone. Offer hospitality equally and generously to all guests. Wear clothing suited to the occasion. Contribute to conversations without dominating them and refrain from insults or prying curiosity. Eat neatly and quietly. Accept gifts or favors with humility and gratitude. Acknowledge gifts or favors with prompt thank you notes. Avoid disturbing others with unnecessary noise.');
INSERT INTO badge_level_requirements VALUES(2681,363,'level3',4,'Do Level 2 requirements # 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2682,363,'level3',5,'Help make some food for at least one guest. Keep in mind: You should make something you think they will like.  If you know someone is allergic to something, or won’t eat it, don’t serve it.  If you are having a large party, make sure that you have something for everyone.  If you know a friend is allergic to wheat, it is okay to still have a birthday cake, but make sure to have a non-wheat alternative such as ice cream available so that everyone can have a treat. Do as much cooking and prep ahead of time as possible.  When your guest(s) arrive you want to be able to spend as much time with them as possible, and not in the kitchen. A good hostess also makes sure that the food is presented in an appealing way. Don’t just dump cookies on plate, arrange them nicely. Make your guest feel like they are special and that you took extra time just for them.');
INSERT INTO badge_level_requirements VALUES(2683,363,'level4',6,'Do Level 3 requirements # 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2684,363,'level4',7,'Guests should be made to feel special, even if they have dropped in unexpectedly.  Make a plan for what to do if someone drops by without notice.  What type of drinks and snacks could you offer?  What type of games or entertainment could you provide?');
INSERT INTO badge_level_requirements VALUES(2685,363,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2686,364,'preschool',0,'Learn to identify the three main parts of a hot air balloon: the burner, the basket and the envelope.');
INSERT INTO badge_level_requirements VALUES(2687,364,'preschool',1,'Design your own hot air balloon.');
INSERT INTO badge_level_requirements VALUES(2688,364,'level1',2,'Learn the origin and history of hot air balloons.');
INSERT INTO badge_level_requirements VALUES(2689,364,'level2',3,'Learn the science behind how a hot air balloon works.');
INSERT INTO badge_level_requirements VALUES(2690,364,'level3',4,'Learn what type of weather must be present for safe flying conditions.  What hazards must a balloonist watch out for?');
INSERT INTO badge_level_requirements VALUES(2691,364,'level4',5,'Learn how to steer a balloon based on altitude and wind currents.');
INSERT INTO badge_level_requirements VALUES(2692,364,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2693,365,'preschool',0,'What is hot chocolate? How is it made? What is it made from?  Try 3 different types of hot chocolate, such as instant powder, from scratch, or flavored.');
INSERT INTO badge_level_requirements VALUES(2694,365,'preschool',1,'Make a hot chocolate with water and one with milk. Which one do you like better? What are the differences? What are the similarities? If you cannot drink milk, use an alternative.');
INSERT INTO badge_level_requirements VALUES(2695,365,'level1',2,'Try 4 different types of hot chocolate.');
INSERT INTO badge_level_requirements VALUES(2696,365,'level1',3,'Help make hot chocolate from scratch without an instant powder.');
INSERT INTO badge_level_requirements VALUES(2697,365,'level2',4,'Try 5 different types of hot chocolate.');
INSERT INTO badge_level_requirements VALUES(2698,365,'level2',5,'Can you drink hot chocolate without sweetener? Compare it to one that is sweetened. What do you like more?');
INSERT INTO badge_level_requirements VALUES(2699,365,'level3',6,'What is the history of hot chocolate? Who made the first hot chocolate? How long has it been around? What was it originally called?');
INSERT INTO badge_level_requirements VALUES(2700,365,'level4',7,'Do some research and see if there a way to make hot chocolate for different diets, such as diabetics, paleo,or  vegetarians. Make one of these variations and compare to everyday hot chocolate. What do you like? Not like? Are there nutritional advantages to these types of hot chocolate?');
INSERT INTO badge_level_requirements VALUES(2701,365,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.  You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2702,366,'preschool',0,'Choose a machine at home to learn about (like the dishwasher, washing machine, or vacuum) and be able to explain what it is used for are used for.');
INSERT INTO badge_level_requirements VALUES(2703,366,'preschool',1,'Help an adult use the household machine (like putting clothes in the washer or dishes in the dishwasher). Observe the before and after such as dirty dishes becoming clean or long grass becoming short after it is mowed.');
INSERT INTO badge_level_requirements VALUES(2704,366,'level1',2,'Learn safety rules for using the machine and for being around it when it is on.');
INSERT INTO badge_level_requirements VALUES(2705,366,'level2',3,'Learn the basic science behind how your chosen machine works—such as how its motor spins, how pressure builds, or how heat is generated and used.');
INSERT INTO badge_level_requirements VALUES(2706,366,'level3',4,'Learn about the history of your household machines—how did people do this task before your machine existed?');
INSERT INTO badge_level_requirements VALUES(2707,366,'level4',5,'Identify the key parts of your machine and what powers them (electricity, gas, water pressure, etc.).  Draw a schematic of how it works.');
INSERT INTO badge_level_requirements VALUES(2708,366,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2709,367,'preschool',0,'Learn what a houseplant is. Visit a plant nursery, store, or home that has indoor plants.');
INSERT INTO badge_level_requirements VALUES(2710,367,'preschool',1,'Choose a small houseplant and help water or care for it with an adult’s help.');
INSERT INTO badge_level_requirements VALUES(2711,367,'level1',2,'Learn what plants need to grow (light, water, soil, and air). Understand that different plants need different light, water and soil.  Know what type of plant you have and what your plant needs.');
INSERT INTO badge_level_requirements VALUES(2712,367,'level2',3,'Learn the history of indoor plants. When did people begin keeping plants indoors? Which cultures made houseplants popular?');
INSERT INTO badge_level_requirements VALUES(2713,367,'level3',4,'Learn how to spot common houseplant pests or diseases and what to do about them.');
INSERT INTO badge_level_requirements VALUES(2714,367,'level4',5,'Interview or shadow someone who works with indoor plants, such as a florist, greenhouse worker, or botanical garden educator.');
INSERT INTO badge_level_requirements VALUES(2715,367,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2716,368,'preschool',0,'Choose a hula hoop that is the correct size for you and learn the basic hula hoop move around your waist.');
INSERT INTO badge_level_requirements VALUES(2717,368,'level1',1,'Practice hula hooping until you can keep it going for 30 seconds or longer.');
INSERT INTO badge_level_requirements VALUES(2718,368,'level2',2,'Use the hula hoop around your arms or legs and keep it going');
INSERT INTO badge_level_requirements VALUES(2719,368,'level2',3,'Find out what the world records are that involve hula hoop such as the longest time, most hoops used, largest hoop, hula running, fastest spin, etc.');
INSERT INTO badge_level_requirements VALUES(2720,368,'level3',4,'Learn about the history of hula hoops.  What cultures use hula hoops?');
INSERT INTO badge_level_requirements VALUES(2721,368,'level4',5,'Learn about different kinds of hula hoops available.  What are the pros and cons of different sizes and materials?');
INSERT INTO badge_level_requirements VALUES(2722,368,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2723,369,'preschool',0,'Be able to identify the parts of your body listed below: Head Eyes Ears Nose Mouth Chin Cheeks Forehead Neck Shoulders Elbows Wrists Fingers Ribs Hips Knees Ankles Heels Toes');
INSERT INTO badge_level_requirements VALUES(2724,369,'level1',1,'Identify on a diagram the major organs of the body and explain what they do including: Brain Heart Lungs Stomach Nerves Intestines Muscles Liver Kidneys');
INSERT INTO badge_level_requirements VALUES(2725,369,'level2',2,'Learn the different types of systems in your body: Circulatory Respiratory Nervous Skeletal Muscular Excretory Digestive Endocrine Immune Be able to explain the main function of each system.');
INSERT INTO badge_level_requirements VALUES(2726,369,'level3',3,'Choose four body systems and diagram the major parts of each and the flow of the system.  Be able to explain what each component of the system does.');
INSERT INTO badge_level_requirements VALUES(2727,369,'level4',4,'Diagram the major parts and flow of all nine body systems.');
INSERT INTO badge_level_requirements VALUES(2728,369,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2729,370,'preschool',0,'Learn about hunter and gun safety.');
INSERT INTO badge_level_requirements VALUES(2730,370,'preschool',1,'Learn what animal are hunted for meat, which are hunted for fur, and which are hunted because they are overpopulated.');
INSERT INTO badge_level_requirements VALUES(2731,370,'level1',2,'Learn about hunting ethics, such as: •        Follow all hunting rules and regulations. •        Only hunt what you plan to eat or use. •        Try for a humane kill, never torture an injured animal.');
INSERT INTO badge_level_requirements VALUES(2732,370,'level2',3,'Take a hunter safety course.');
INSERT INTO badge_level_requirements VALUES(2733,370,'level2',4,'Know the hunting laws and seasons for your area and the animals you plan to hunt.  Do you need a permit?  Is there a limit?  Can you only hunt during certain seasons or times of day?');
INSERT INTO badge_level_requirements VALUES(2734,370,'level3',5,'Learn how to track your animal.  What type of signs and tracks should you look for?  Where do they like to bed down, or roost?');
INSERT INTO badge_level_requirements VALUES(2735,370,'level4',6,'Successfully kill an animal, help to properly clean it, and cook at least one recipe from it, or make something from its fur.');
INSERT INTO badge_level_requirements VALUES(2736,370,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2737,371,'preschool',0,'Discuss with a parent or your club leader what good hygiene means. Why is it important? How does having bad hygiene affect others? How does it affect your health?');
INSERT INTO badge_level_requirements VALUES(2738,371,'level1',1,'Take care of your teeth. Learn to brush your teeth properly and then brush them twice every day. Learn how to properly floss your teeth and floss at least once every day. How often should you use fluoride, and for how long?');
INSERT INTO badge_level_requirements VALUES(2739,371,'level1',2,'Wear clean underwear, socks and other clothes each day.');
INSERT INTO badge_level_requirements VALUES(2740,371,'level2',3,'Take a daily bath or shower. Learn when to bathe, what parts of your body you should wash, and what soaps, shampoos, and conditioners you should use.');
INSERT INTO badge_level_requirements VALUES(2741,371,'level3',4,'Find out how to properly care for your skin and treat acne.');
INSERT INTO badge_level_requirements VALUES(2742,371,'level3',5,'Find out what causes body odor. Can things you eat like garlic, onions, and spicy food effect it? What about exercise or hot weather? If you are starting to experience body odor, talk your parent about getting a deodorant to use every day.');
INSERT INTO badge_level_requirements VALUES(2743,371,'level4',6,'Find out what kind of hair you have. Is it dry? Oily? Normal? Is it curly? Straight? Brittle? Does it frizz? Find a shampoo and conditioner for your type of hair and wash your hair at least every 2 days. What kind of styling product should you use for your hair type? What kind of chemicals should you avoid in hair products?');
INSERT INTO badge_level_requirements VALUES(2744,371,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2745,372,'preschool',0,'Try at least three different flavors of ice cream.');
INSERT INTO badge_level_requirements VALUES(2746,372,'preschool',1,'Make some homemade ice cream using one of the following methods: Coffee can rolling or ice cream in a bag Hand crank ice cream machine Electric machine Understand what role salt plays in freezing the cream and why rock salt is better than table salt.');
INSERT INTO badge_level_requirements VALUES(2747,372,'level1',2,'Learn the difference between ice cream, iced milk, frozen yogurt, and soft serve ice cream. Try one of each.');
INSERT INTO badge_level_requirements VALUES(2748,372,'level2',3,'Learn the history of ice cream.  When was ice cream invented? Who invented it? Where?');
INSERT INTO badge_level_requirements VALUES(2749,372,'level3',4,'Be able to explain the scientific process of how the raw ingredients change into ice cream? What kind of chemical or physical reactions take place?');
INSERT INTO badge_level_requirements VALUES(2750,372,'level4',5,'Learn about a major manufacturer of ice cream: Baskin Robbins, Ben & Jerry, Breyer’s, Blue Bunny, etc.  How many flavors do they make?  Where is their base of operations?  How much ice cream do they make each year?  If you live near one of their plants, see if it is possible to get a tour.');
INSERT INTO badge_level_requirements VALUES(2751,372,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2752,373,'preschool',0,'Learn what icebergs and sea ice are by looking at pictures or watching a short video.  If you can visit one in person, that is even better!');
INSERT INTO badge_level_requirements VALUES(2753,373,'preschool',1,'Freeze water in a container into ice and observe how it floats. Try adding a toy or object and see what happens.');
INSERT INTO badge_level_requirements VALUES(2754,373,'level1',2,'Learn the difference between sea ice and icebergs.');
INSERT INTO badge_level_requirements VALUES(2755,373,'level2',3,'Understand the following vocabulary words in regards to icebergs: glacier, ice shelf, growler, bergy bit, ice floe and calving.');
INSERT INTO badge_level_requirements VALUES(2756,373,'level3',4,'Understand the following iceberg characteristics.  Draw a diagram of each: Tabular: A flat, table-like shape. Pinnacled: Having sharp, pointed peaks. Blocky: Having a rectangular or cube-like shape. Dome-shaped: Having a rounded, curved top. Weathered: Having a rough or eroded surface. Tilted: Having a slant or angle. Drydock: A type of iceberg that has a flat, wide base and steep sides.');
INSERT INTO badge_level_requirements VALUES(2757,373,'level4',5,'Learn how scientists study sea ice and icebergs using satellites, buoys, or icebreakers. Share what you find.');
INSERT INTO badge_level_requirements VALUES(2758,373,'level5',6,'Teach someone what you’ve learned about sea ice or icebergs, or lead an activity showing how ice floats or melts. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2759,374,'preschool',0,'Watch a video or look at pictures of ice sculptures. Talk about what they look like and what shapes or animals you see.');
INSERT INTO badge_level_requirements VALUES(2760,374,'preschool',1,'Make a simple ice shape by freezing water in a fun mold or container. Decorate it with food coloring or natural items. Try attaching two pieces using salt.');
INSERT INTO badge_level_requirements VALUES(2761,374,'level1',2,'Try carving a small ice block using safe household tools like salt or warm water with a dropper or a paintbrush.');
INSERT INTO badge_level_requirements VALUES(2762,374,'level2',3,'Learn how professional ice sculptors work. What tools do they use? How do they keep sculptures from melting?');
INSERT INTO badge_level_requirements VALUES(2763,374,'level3',4,'Research the history of ice sculpting. Where and when did it begin? How has the art form changed over time?');
INSERT INTO badge_level_requirements VALUES(2764,374,'level4',5,'Learn about a famous ice sculptor.');
INSERT INTO badge_level_requirements VALUES(2765,374,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2766,375,'preschool',0,'Learn what the Iditarod is and what it commemorates.');
INSERT INTO badge_level_requirements VALUES(2767,375,'preschool',1,'Read or have read to you an age appropriate book about Balto.');
INSERT INTO badge_level_requirements VALUES(2768,375,'level1',2,'Read an age appropriate book about the Iditarod race and tell someone what you’ve learned.');
INSERT INTO badge_level_requirements VALUES(2769,375,'level2',3,'Make a map showing the race route.');
INSERT INTO badge_level_requirements VALUES(2770,375,'level3',4,'Write an essay about what you’ve learned.');
INSERT INTO badge_level_requirements VALUES(2771,375,'level4',5,'Learn about the Jr. Iditarod and present what you’ve learned to your family, friends, or group.');
INSERT INTO badge_level_requirements VALUES(2772,375,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2773,376,'preschool',0,'Make an indoor fort with a parent, adult or much older child, communicating what you would like to do');
INSERT INTO badge_level_requirements VALUES(2774,376,'level1',1,'Do Preschool requirement #1.');
INSERT INTO badge_level_requirements VALUES(2775,376,'level1',2,'Identify what objects from home work best to make an indoor fort.  These can include things like pillows, blankets, sheets, light objects, sofa cushions, chairs, clothespins.  Explain what objects make bad forts like objects that are sharp, heavy or otherwise dangerous.');
INSERT INTO badge_level_requirements VALUES(2776,376,'level2',3,'Do Level 1 requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(2777,376,'level2',4,'Use cardboard to make a fort.  Try to use at least 6 boxes to create a structure with interesting features.  Color your fort using crayons, paint or other materials.');
INSERT INTO badge_level_requirements VALUES(2778,376,'level3',5,'Do Level 2 requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(2779,376,'level3',6,'Watch videos on construction and how structures are made.  Videos on medieval churches can be particularly helpful in understanding how to create space.');
INSERT INTO badge_level_requirements VALUES(2780,376,'level4',7,'Do Level 3 requirements #1 & 2. Using your plan incorporate all previous materials and examples.');
INSERT INTO badge_level_requirements VALUES(2781,376,'level4',8,'Learn about why fort building is very important to child development.  You should examine topics such as social skills, spatial reasoning, ingenuity and trial and error.');
INSERT INTO badge_level_requirements VALUES(2782,376,'level5',9,'Do Level 4 requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(2783,376,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.  You can do this by creating a video to share.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional requirements.');
INSERT INTO badge_level_requirements VALUES(2784,377,'preschool',0,'Learn the definition of this animal group.  What about them classifies them as such?');
INSERT INTO badge_level_requirements VALUES(2785,377,'preschool',1,'Find out as much as you can about the animal group you have chosen in your local environment by reading, observing, and talking to others.  If your chosen animal group does not live in your community, where is the nearest place that they live naturally?');
INSERT INTO badge_level_requirements VALUES(2786,377,'level1',2,'Be able to identify at least 3 species of your animal group.  You may want to look at things like size, shape, color or other distinguishing marks.  Learn about their life cycle, what they eat, how they protect themselves, their calls, and habits.');
INSERT INTO badge_level_requirements VALUES(2787,377,'level2',3,'but identify at least 5 species (If you completed this badge for the same animal group at a different level, you may not use species you have researched in the past.)');
INSERT INTO badge_level_requirements VALUES(2788,377,'level3',4,'If possible, observe your animal category in the wild on at least 3 different occasions.  Take notes on their behavior and compare them to what you have learned.');
INSERT INTO badge_level_requirements VALUES(2789,377,'level3',5,'but identify at least 8 species (If you completed this badge for the same animal group at a different level, you may not use species you have researched in the past.)');
INSERT INTO badge_level_requirements VALUES(2790,377,'level4',6,'If possible, observe your animal category in the wild on at least 5 different occasions.  Take notes on their behavior and compare them to what you have learned.');
INSERT INTO badge_level_requirements VALUES(2791,377,'level4',7,'but identify at least 12 species (If you completed this badge for the same animal group at a different level, you may not use species you have researched in the past.)');
INSERT INTO badge_level_requirements VALUES(2792,377,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.  You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.  If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2793,378,'preschool',0,'Choose an insect and learn to identify them.');
INSERT INTO badge_level_requirements VALUES(2794,378,'preschool',1,'Know the life cycle of your insect and what they eat.');
INSERT INTO badge_level_requirements VALUES(2795,378,'level1',2,'Draw or color a picture of your insect and know the basic anatomy of your insect.');
INSERT INTO badge_level_requirements VALUES(2796,378,'level2',3,'Find out how your insect benefits or hurts the environment.  What places are they native to? Make a map of locations.');
INSERT INTO badge_level_requirements VALUES(2797,378,'level3',4,'Know how many varieties/species there are of your specific insect and how to recognize them.');
INSERT INTO badge_level_requirements VALUES(2798,378,'level4',5,'Learn the scientific name of your insect as well as the Kingdom, Phylum, Class, Order, Family, Genus, Species.');
INSERT INTO badge_level_requirements VALUES(2799,378,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2800,379,'preschool',0,'Listen to a piece of the type of music you chose to learn about. What does it sound like? How does it make you feel?');
INSERT INTO badge_level_requirements VALUES(2801,379,'level1',1,'Listen to three different pieces in your chosen variety.');
INSERT INTO badge_level_requirements VALUES(2802,379,'level1',2,'Find someone else who likes to listen to your type of music and talk to them about it. Ask them what they like about it, who is their favorite composer, what is their favorite piece of music, etc. If you cannot find anyone who likes your type of music, read a book about it.');
INSERT INTO badge_level_requirements VALUES(2803,379,'level2',3,'Listen to five different pieces of music in your style.');
INSERT INTO badge_level_requirements VALUES(2804,379,'level2',4,'Learn about the history of your type of music. Where did it originate?');
INSERT INTO badge_level_requirements VALUES(2805,379,'level3',5,'Listen to seven different pieces of music in your style.');
INSERT INTO badge_level_requirements VALUES(2806,379,'level3',6,'Make a timeline of events in the history of your type of music. Events could include concerts, births of famous musicians, etc. You must have at least 10 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(2807,379,'level4',7,'Listen to at least ten different pieces of music in your style and have 15 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(2808,379,'level4',8,'Read a biography of a person connected with your sort of music and be able to list at least two significant facts about them.');
INSERT INTO badge_level_requirements VALUES(2809,379,'level5',9,'Listen to at least fifteen different pieces of music in your style and have 20 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(2810,379,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2811,380,'preschool',0,'Learn about proper internet safety and discuss these rules with a parent or guardian. Why is it important to remain safe on the internet?');
INSERT INTO badge_level_requirements VALUES(2812,380,'preschool',1,'Learn how to use a basic internet browser. Learn the basic features of the internet. How do you go back or forward between webpages? How do you switch tabs? What is a URL and where is it located?');
INSERT INTO badge_level_requirements VALUES(2813,380,'level1',2,'How can you tell if the knowledge you are researching is true? What are some methods to analyze safe websites versus those who promote falsehoods?');
INSERT INTO badge_level_requirements VALUES(2814,380,'level2',3,'Learn how to save Bookmarks. What is a Bookmark? How can you organize your Bookmarks?');
INSERT INTO badge_level_requirements VALUES(2815,380,'level3',4,'What is a “cookie” or other tracking devices in regards to the internet? What do they do? How are they involved with ads? How can you manage your cookie settings on your browser, and how can you prevent ads and pop-ups?');
INSERT INTO badge_level_requirements VALUES(2816,380,'level4',5,'Learn advanced browser keywords. For instance, how do you only have results from one website appear? How can you ensure the browser will look up your specific words? How can you prevent your browser from showing results with specific words? There are many special commands that can help you narrow down your search.');
INSERT INTO badge_level_requirements VALUES(2817,380,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2818,381,'preschool',0,'Learn about proper internet safety and discuss these rules with a parent or guardian. Why is it important to remain safe on the internet?');
INSERT INTO badge_level_requirements VALUES(2819,381,'preschool',1,'Why is important not to share your personal information on the internet, such as your name, address, or phone number?');
INSERT INTO badge_level_requirements VALUES(2820,381,'level1',2,'Why is it important to be polite and kind online? What is cyberbullying and how can we prevent it or make others more aware of it?');
INSERT INTO badge_level_requirements VALUES(2821,381,'level2',3,'Why should you never click on ads? What about pop-ups? How do you safely prevent and/or avoid these?');
INSERT INTO badge_level_requirements VALUES(2822,381,'level3',4,'Many websites require accounts. Learn proper password safety. What makes a strong password? Why is it important to have a strong password?');
INSERT INTO badge_level_requirements VALUES(2823,381,'level4',5,'What is an online predator? Identify the safety rules for chatting with others online, including on forums and on social media.');
INSERT INTO badge_level_requirements VALUES(2824,381,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2825,382,'preschool',0,'Learn what an invention is, and what an inventor is.  Learn about one inventor and their most famous invention, such as Nikola Tesla, who invented the Tesla coil, or Alexander Graham Bell, who invented the telephone.');
INSERT INTO badge_level_requirements VALUES(2826,382,'level1',1,'Name at least 2 inventors and their most important inventions.');
INSERT INTO badge_level_requirements VALUES(2827,382,'level1',2,'Read a book about a famous inventor such as Samuel Morse, who invented the telegraph.  Find out if they invented other things that are not as well-known.');
INSERT INTO badge_level_requirements VALUES(2828,382,'level2',3,'Name at least 3 inventors.');
INSERT INTO badge_level_requirements VALUES(2829,382,'level2',4,'Make a timeline of famous inventions.  You must have at least 10 items on your timeline.  Show it to your family, friends, or group.');
INSERT INTO badge_level_requirements VALUES(2830,382,'level3',5,'Name at least 4 inventors and have at least 15 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(2831,382,'level3',6,'Learn what a patent is, and what it takes to get one.  Research the history of the U. S. Patent Office, and where the patent records are kept.  Find objects in your home that have patent numbers on them.  Tell your family, friends, or group what you learned.');
INSERT INTO badge_level_requirements VALUES(2832,382,'level4',7,'Name at least 5 inventors and have at least 20 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(2833,382,'level4',8,'Learn about 5 women inventors, such as Jacqueline Cochran or Mary Anderson.  Tell your family or Club what you learned.');
INSERT INTO badge_level_requirements VALUES(2834,382,'level5',9,'Name at least 6 inventors and have at least 25 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(2835,382,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2839,385,'preschool',0,'Make a piece of jewelry using a beading technique.');
INSERT INTO badge_level_requirements VALUES(2840,385,'preschool',1,'Learn about different types of string used in jewelry making such as stretch cord, leather cord, fishing line, beading thread, string, yarn, and satin cord.  Make a piece of jewelry using cord or string of some type.');
INSERT INTO badge_level_requirements VALUES(2841,385,'level1',2,'Learn about different types of clasps and how they open and close. Make a piece of jewelry that requires a clasp.');
INSERT INTO badge_level_requirements VALUES(2842,385,'level2',3,'Learn the history of jewelry and visit a historical jewelry exhibit or look at pictures in a book, or online with permission from a parent.  Learn about at least three famous pieces of jewelry.');
INSERT INTO badge_level_requirements VALUES(2843,385,'level3',4,'Learn about the basic tools necessary for jewelry making.  These tools may differ depending on the jewelry technique you are interested in, but might include wire cutters, needle nose pliers, beading needles or beading looms, rubber jeweler hammer, etc.');
INSERT INTO badge_level_requirements VALUES(2844,385,'level4',5,'Learn about the different gauges and types of wire.  What is each weight usually used for?  What tools do you need to work with wire?');
INSERT INTO badge_level_requirements VALUES(2845,385,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2848,387,'preschool',0,'Make or purchase a journal and personalize it in some way. Add your favorite quote, draw a picture, write a dedication or reason for keeping this journal, etc.');
INSERT INTO badge_level_requirements VALUES(2849,387,'preschool',1,'Keep a daily journal for at least two weeks. Have your parent help you write in it. Draw a picture to go with it.');
INSERT INTO badge_level_requirements VALUES(2850,387,'level1',2,'Keep a daily journal for at least two weeks. Journal entries should be written by yourself with help from a parent when necessary. Draw a picture to with each entry.');
INSERT INTO badge_level_requirements VALUES(2851,387,'level2',3,'Journal entries should be written by yourself. Pictures are optional.');
INSERT INTO badge_level_requirements VALUES(2852,387,'level2',4,'Read excerpts from the journal of a famous person.');
INSERT INTO badge_level_requirements VALUES(2853,387,'level3',5,'Keep your journal for at least one month (It is okay to skip a day now and then, but try to be as consistent as possible).');
INSERT INTO badge_level_requirements VALUES(2854,387,'level3',6,'Read the complete journal of a famous person.');
INSERT INTO badge_level_requirements VALUES(2855,387,'level4',7,'Keep your journal for at least one month (It is okay to skip a day now and then, but try to be as consistent as possible).');
INSERT INTO badge_level_requirements VALUES(2856,387,'level4',8,'Make a list of at least ten famous journals and explain why they play an important role in history.');
INSERT INTO badge_level_requirements VALUES(2857,387,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2860,389,'preschool',0,'Learn basic kitchen safety when washing, cutting, and juicing.');
INSERT INTO badge_level_requirements VALUES(2861,389,'preschool',1,'What are the health benefits of juicing? Know what fruits and vegetables you should not juice.');
INSERT INTO badge_level_requirements VALUES(2862,389,'level1',2,'and 2.');
INSERT INTO badge_level_requirements VALUES(2863,389,'level1',3,'Pick 3 fruits (such as apples, pineapple, lemon) and 3 vegetables (such as carrots, celery, and cucumber) and with the help of an adult, juice them.  Adjust the amount of the fruits or vegetables to your taste preferences.');
INSERT INTO badge_level_requirements VALUES(2864,389,'level2',4,'and 2.');
INSERT INTO badge_level_requirements VALUES(2865,389,'level2',5,'What is the difference between organic and non-organic fruits and vegetables? Which are better for juicing in your opinion?');
INSERT INTO badge_level_requirements VALUES(2866,389,'level3',6,'and 2.');
INSERT INTO badge_level_requirements VALUES(2867,389,'level3',7,'Learn the differences between a manual juicer (hand operated like a citrus juicer), a masticating juicer, (wheatgrass juicer), and a centrifugal juicer ( a general juicer), and the Vitamix. What are the upsides and downsides of each.');
INSERT INTO badge_level_requirements VALUES(2868,389,'level4',8,'and 2.');
INSERT INTO badge_level_requirements VALUES(2869,389,'level4',9,'Research store-bought drinks (pasteurized) vs freshly juiced.  Is the store bought juice as beneficial as the freshly juiced? Why or why not?');
INSERT INTO badge_level_requirements VALUES(2870,389,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional requirements');
INSERT INTO badge_level_requirements VALUES(2871,390,'preschool',0,'Learn what type of ropes are best for jumping and how to make sure yours in the right length.  Learn how to adjust a rope that is too long to fit you.');
INSERT INTO badge_level_requirements VALUES(2872,390,'preschool',1,'Learn how to jump rope with the jogging step (stepping over the rope one foot at a time, as if you’re jogging in place).');
INSERT INTO badge_level_requirements VALUES(2873,390,'level1',2,'Do Preschool requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(2874,390,'level1',3,'Learn to jump rope with a simple single jump motion.');
INSERT INTO badge_level_requirements VALUES(2875,390,'level2',4,'Do Level 1 requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(2876,390,'level2',5,'Be able to jump rope without missing for at least 1 minute.');
INSERT INTO badge_level_requirements VALUES(2877,390,'level3',6,'Learn about the history of jump rope.');
INSERT INTO badge_level_requirements VALUES(2878,390,'level4',7,'Learn at least 3 different jump rope moves such as Double Unders, Criss Cross, or Side Swipe.');
INSERT INTO badge_level_requirements VALUES(2879,390,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2880,391,'preschool',0,'Learn what a Junior Ranger is and who Junior Rangers learn from (park rangers). Talk about why parks and historic places are important.');
INSERT INTO badge_level_requirements VALUES(2881,391,'preschool',1,'Look at pictures of Junior Ranger badges from different parks and talk about what they show (animals, landmarks, symbols).');
INSERT INTO badge_level_requirements VALUES(2882,391,'level1',2,'Learn where Junior Ranger programs are found (national parks, monuments, historic sites, seashores, and more). Find at least two on a map.');
INSERT INTO badge_level_requirements VALUES(2883,391,'level2',3,'Learn what kids usually do to earn a Junior Ranger badge. Name at least three common activity types (such as ranger talks, worksheets, hikes, or service).');
INSERT INTO badge_level_requirements VALUES(2884,391,'level3',4,'Learn the history of the Junior Ranger program. When it began, which government agengy runs it, where it gets its money and why it was created.');
INSERT INTO badge_level_requirements VALUES(2885,391,'level4',5,'Compare Junior Ranger programs at four different parks or agencies. How are the activities, themes, or badges similar and different?');
INSERT INTO badge_level_requirements VALUES(2886,391,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2887,392,'preschool',0,'Be able to identify a kayak.  What makes it different than a canoe?  Watch someone kayak either in person or on a video.');
INSERT INTO badge_level_requirements VALUES(2888,392,'preschool',1,'Learn basic water safety as well as safety rules specifically for being in or around kayaks. Understand why it is important to always wear a life jacket and to always kayak with a buddy. Why should you always have a whistle?');
INSERT INTO badge_level_requirements VALUES(2889,392,'level1',2,'Demonstrate how to properly adjust and wear a PFD.');
INSERT INTO badge_level_requirements VALUES(2890,392,'level1',3,'Demonstrate proper entry and exit technique for a kayak. Learn how a kayak is paddled. Demonstrate proper paddling technique in calm water, including forward stroke, backward stroke, and turning. Understand why a kayak paddle looks different than a canoe paddle.');
INSERT INTO badge_level_requirements VALUES(2891,392,'level2',4,'Demonstrate how to properly secure gear to a kayak using tie-downs and bungee cords.');
INSERT INTO badge_level_requirements VALUES(2892,392,'level3',5,'Demonstrate proper kayak handling technique on land, including how to carry and store a kayak, as well as how to properly load gear into a kayak. Demonstrate how to properly clean and maintain a kayak.');
INSERT INTO badge_level_requirements VALUES(2893,392,'level4',6,'Demonstrate how to properly carry out a capsize drill and re-enter the kayak.');
INSERT INTO badge_level_requirements VALUES(2894,392,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2895,393,'preschool',0,'Learn what a computer keyboard or typewriter is and how it is used.');
INSERT INTO badge_level_requirements VALUES(2896,393,'preschool',1,'With the help of a parent, either open a new page on a word processor (if you are learning computer keyboarding) or load a sheet of paper into a typewriter (if you are learning about a typewriter). Start getting used to the keys, press each key and watch what happens on either the open page in the computer program or on the blank sheet of paper.');
INSERT INTO badge_level_requirements VALUES(2897,393,'level1',2,'Either go online (with a parent’s permission) to find a website with free online typing classes for kids or find a book with typing lessons for kids. Use one of these methods to learn the basics of typing.');
INSERT INTO badge_level_requirements VALUES(2898,393,'level2',3,'Learn about proper positioning of hands and fingers during typing. Which fingers start on which keys? What 3 keys do each finger use when typing? Practice using proper positioning by typing a letter, report or using a typing program.');
INSERT INTO badge_level_requirements VALUES(2899,393,'level3',4,'Either print out or buy a diagram of either a computer keyboard or typewriter keyboard (depending on which one you are learning) and tape it either on the top of the computer monitor or on the wall behind the typewriter. Use it to practice learning where all of the keys are while you are typing instead of looking down at the keys while you are typing.');
INSERT INTO badge_level_requirements VALUES(2900,393,'level4',5,'Learn how to properly clean and maintain a keyboard or typewriter.');
INSERT INTO badge_level_requirements VALUES(2901,393,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2910,398,'preschool',0,'Learn what knitting is.  Look through your clothes and see if you have any knitted garments – some may be knitted by hand and some by machine.  See the differences between them.');
INSERT INTO badge_level_requirements VALUES(2911,398,'preschool',1,'Learn knitting safety and what equipment is needed to knit, such as: Knitting needles (Children should use plastic knitting needles.) Stitch stopper Yarn Stitch counter Tapestry needle Stitch holder Bag to keep your work in.');
INSERT INTO badge_level_requirements VALUES(2912,398,'level1',2,'Complete Preschool requirements  1 & 2.');
INSERT INTO badge_level_requirements VALUES(2913,398,'level1',3,'Know the meaning of the following knitting terms: cast on, knit, cast off/bind off.  Be able to cast on 10 stitches using two needles and knit 20 rows in plain knitting (known as garter stitch) and then cast off/bind off the stitches.   Count the number of stitches at the end of each row to make sure that you have not dropped any.  Attach your square to a piece of card and label it. This can be the beginning of a book of knitting stitches showing your skills.');
INSERT INTO badge_level_requirements VALUES(2914,398,'level2',4,'Complete Level 1 requirements 1 & 2. Cast on 15 stitches using two needles and knit 30 rows in plain knitting (known as garter stitch) and then cast off/bind off the stitches.');
INSERT INTO badge_level_requirements VALUES(2915,398,'level2',5,'Learn how knitting can be repaired when a hole or run is made in a garment.  Learn how to pick up dropped knit stitches.  Learn about the correct way to launder and care for knitted items.');
INSERT INTO badge_level_requirements VALUES(2916,398,'level3',6,'Complete Level 2 requirements 1 & 2. Cast on 20 stitches and knit 40 rows in garter stitch.  Also learn how to increase and decrease the number of stitches in each row and learn the slip stitch.');
INSERT INTO badge_level_requirements VALUES(2917,398,'level3',7,'Learn the purl stitch and cast on 20 stitches and knit 40 rows in stocking stitch (alternating rows of plain and purl).   Learn how to pick up dropped purl stitches.');
INSERT INTO badge_level_requirements VALUES(2918,398,'level4',8,'Complete Level 3 requirements 1 & 2. Cast on 25 stitches and knit 50 rows for the sample squares.');
INSERT INTO badge_level_requirements VALUES(2919,398,'level4',9,'Learn how to sew overcast stitches and blanket stitches with a tapestry needle and knitting yarn so that you can stitch two pieces of knitting together at the seams.  Knit something simple like a coin-purse in plain knitting, joining the seams with overcast stitch or blanket stitch.  Blanket stitch can also be used to decorate the edges of knitted items.');
INSERT INTO badge_level_requirements VALUES(2920,398,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2923,400,'preschool',0,'Learn what a Korean Knot looks like.  Look at several photos or real Korean knot projects.  Which knot is your favorite and why?');
INSERT INTO badge_level_requirements VALUES(2924,400,'preschool',1,'Make a craft containing Korean knots.  The actual knot may be tied by an adult for younger children.');
INSERT INTO badge_level_requirements VALUES(2925,400,'level1',2,'Do Preschool requirements #1 and #2');
INSERT INTO badge_level_requirements VALUES(2926,400,'level1',3,'Define the terms maedeup and norigae.  Be able to identify each.');
INSERT INTO badge_level_requirements VALUES(2927,400,'level2',4,'Do Level 1 requirements #1 and #2');
INSERT INTO badge_level_requirements VALUES(2928,400,'level2',5,'Learn to make at least 2 different Korean knots');
INSERT INTO badge_level_requirements VALUES(2929,400,'level3',6,'Do Level 2 requirements #1 and #2.  Learn to make at least 3 different Korean knots.');
INSERT INTO badge_level_requirements VALUES(2930,400,'level3',7,'Learn about the history of Korean knot making');
INSERT INTO badge_level_requirements VALUES(2931,400,'level4',8,'Do Level 3 requirements #1 and #2');
INSERT INTO badge_level_requirements VALUES(2932,400,'level4',9,'Different Korean knots are used for different purposes.  Choose 3 knots to learn how to tie and use them in the traditional manner. For example the Maehwa knot, a knot in the shape of an apricot blossom, is used for baby clothes and the Norigae while the Dorae knot, the most basic form of the knot or double connection knot, it is used to join, fix or finish a knot.');
INSERT INTO badge_level_requirements VALUES(2933,400,'level5',10,'Do Level 4 requirements #1 and #2');
INSERT INTO badge_level_requirements VALUES(2934,400,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2935,401,'preschool',0,'Know what lace is.  Look at pictures, or real samples, of at least 5 different types of lace.');
INSERT INTO badge_level_requirements VALUES(2936,401,'level1',1,'Learn the history of lace.  How has it changed over time?');
INSERT INTO badge_level_requirements VALUES(2937,401,'level2',2,'Make a lace sample board with scraps of different types of lace');
INSERT INTO badge_level_requirements VALUES(2938,401,'level3',3,'Learn about the different types of lace and be able to identify at least 3 different types by sight.');
INSERT INTO badge_level_requirements VALUES(2939,401,'level4',4,'Discuss how lace went from being an industry to a hobby.');
INSERT INTO badge_level_requirements VALUES(2940,401,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2941,402,'preschool',0,'Learn what surveying is.');
INSERT INTO badge_level_requirements VALUES(2942,402,'preschool',1,'Learn the directions of north, south, east, and west.');
INSERT INTO badge_level_requirements VALUES(2943,402,'level1',2,'Learn the history of surveying.');
INSERT INTO badge_level_requirements VALUES(2944,402,'level2',3,'Identify terminology used in surveying: North Bearing Azimuth Triangulation Side-Stepping');
INSERT INTO badge_level_requirements VALUES(2945,402,'level3',4,'Identify instruments used in surveying: Tripod Clinometers Noman Alidade Bulbul (plumb bob) Bruntan Rods');
INSERT INTO badge_level_requirements VALUES(2946,402,'level4',5,'Help conduct a basic land survey.');
INSERT INTO badge_level_requirements VALUES(2947,402,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2948,403,'preschool',0,'What is a perennial? An annual? What time of year should you plant things in your area?');
INSERT INTO badge_level_requirements VALUES(2949,403,'preschool',1,'Plant an annual in a pot and care for it for at least one month. What is weeding and why is it important?');
INSERT INTO badge_level_requirements VALUES(2950,403,'level1',2,'Plant and arrange at least 3 annuals. What do plantings do for a home?');
INSERT INTO badge_level_requirements VALUES(2951,403,'level1',3,'What are some plants that need sun, shade or partial sun? What do those requirements mean? What are planting zones and which zone do you live in? Why is it important to plant appropriate to your zone?');
INSERT INTO badge_level_requirements VALUES(2952,403,'level2',4,'What is a biennial? A bulb?');
INSERT INTO badge_level_requirements VALUES(2953,403,'level2',5,'What flowers early, mid-season and late in your area? What materials can be used for mulch and what benefits does it provide?');
INSERT INTO badge_level_requirements VALUES(2954,403,'level3',6,'What are common lawn grasses in your area? What is needed for lawn care? What are the benefits and disadvantages of using chemicals on your lawn?');
INSERT INTO badge_level_requirements VALUES(2955,403,'level4',7,'Learn about soil nutrition. Compare manure, compost and synthetic fertilizers.');
INSERT INTO badge_level_requirements VALUES(2956,403,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2957,404,'preschool',0,'Think of a favorite story or movie. If you were a character in that story, what would you wear?  Draw your costume, or find clothing in your home to make a costume for this character.');
INSERT INTO badge_level_requirements VALUES(2958,404,'level1',1,'Imagine how you would fit in the story—who are your friends, where do you live, how do you help the hero of the story?');
INSERT INTO badge_level_requirements VALUES(2959,404,'level1',2,'What kind of role-playing interests you most? Would you want to explore a different time in history, or an imaginary land, or even a comic book world?  Create a “persona” by inventing the character you would play.  Tell where (and when) that character lives,  what that character looks like and wears, what kind of tools that character uses.  Is your character nice or nasty?  Rich or poor? A common person or a powerful person, or a magical person?');
INSERT INTO badge_level_requirements VALUES(2960,404,'level2',3,'Make a character sheet, a written list of the characteristics you invented for your persona as well as what they wear and own and a little bit about their history.');
INSERT INTO badge_level_requirements VALUES(2961,404,'level2',4,'Learn about costumes in your role-playing hobby. Some historical hobbies expect very accurate costumes, others allow more creative expression.  Learn about the kinds of clothes people wore during your time period, including shoes and hats.  If your hobby is fantasy-based, learn what kinds of clothes people wear to participate.  Consider hair styles—to create a believable impression, does your persona need to wear hair styled up, or in a pony tail, or hanging long and loose?  Do you need to change your description of how your persona looks?');
INSERT INTO badge_level_requirements VALUES(2962,404,'level3',5,'Just like an actor, a role-player must be able to remain in character.  What are their mannerisms? How do they speak? You should be able to answer questions and explain things as your persona would. Hold a conversation with someone and remain in character the entire time.');
INSERT INTO badge_level_requirements VALUES(2963,404,'level4',6,'Learn a little about the “culture” in your role playing hobby. If your hobby recreates a historical event or a culture, this requirement may be particularly important. What are the roles played? Are there differences between the roles for men, women, and children? What are the rules of etiquette?');
INSERT INTO badge_level_requirements VALUES(2964,404,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new-found knowledge.  If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(2965,405,'preschool',0,'Be able to name the tools and materials you used latch hooking.');
INSERT INTO badge_level_requirements VALUES(2966,405,'level1',1,'Complete a small latch hook project.');
INSERT INTO badge_level_requirements VALUES(2967,405,'level2',2,'Complete a latch hook project.');
INSERT INTO badge_level_requirements VALUES(2968,405,'level2',3,'What is the best type of yarn to use for different applications? For instance, which is the best type of yarn to use for a rug, a pillow, or wall hanging?');
INSERT INTO badge_level_requirements VALUES(2969,405,'level3',4,'Complete 3 latch hook projects.');
INSERT INTO badge_level_requirements VALUES(2970,405,'level3',5,'Learn the history of latch hook and of rug hooking.');
INSERT INTO badge_level_requirements VALUES(2971,405,'level4',6,'Complete 4 latch hook projects.');
INSERT INTO badge_level_requirements VALUES(2972,405,'level4',7,'Complete a larger latch hook or rug hooking project like a rug or wall hanging.');
INSERT INTO badge_level_requirements VALUES(2973,405,'level5',8,'Complete 5 latch hook projects.');
INSERT INTO badge_level_requirements VALUES(2974,405,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2975,406,'preschool',0,'What is latte art?');
INSERT INTO badge_level_requirements VALUES(2976,406,'preschool',1,'Look at pictures of at least 12 different latte art designs');
INSERT INTO badge_level_requirements VALUES(2977,406,'level1',2,'Look at at least 3 pictures of each of the following latte art styles.  Understand how each is made. Using milk only Using syrups,  Using stencils with powder 3D creations using foam. Using a printer');
INSERT INTO badge_level_requirements VALUES(2978,406,'level2',3,'Design your own latte syrup art.   Either make your own frothed milk in a mason jar to practice with, or practice designs by spreading royal frosting on a plate. Then use chocolate or caramel syrup to draw lines and circles.   If you want thin lines and don’t have writing bottles, you can put the syrup in a small ziplock bag and snip a tiny piece off the corner to squeeze the syrup through.  Using a toothpick, practice dragging the syrup into different designs. You can also use brown pens to draw ideas on paper.');
INSERT INTO badge_level_requirements VALUES(2979,406,'level3',4,'Learn the history of latte art.  Where and when did it originate?  Who is credited with making it popular?');
INSERT INTO badge_level_requirements VALUES(2980,406,'level4',5,'Learn how to properly steam milk to get it to the correct temperature and consistency.    Learn how to properly pour milk foam for latte art including height, flow rate and cup tilt.');
INSERT INTO badge_level_requirements VALUES(2981,406,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2982,407,'preschool',0,'Learn the difference between clean and dirty clothes, and where they go when they are dirty.');
INSERT INTO badge_level_requirements VALUES(2983,407,'preschool',1,'Help your parent with at least one load of laundry. Learn laundry safety, including never climbing into the machines and how to responsibly use clothing detergent. Assist in sorting the load, and folding and putting away your own clothes. If your family does not sort the laundry, then have someone explain to you how other people might sort theirs according to the water temperature.');
INSERT INTO badge_level_requirements VALUES(2984,407,'level1',2,'Assist in loading the laundry into the washing machine and dryer.');
INSERT INTO badge_level_requirements VALUES(2985,407,'level1',3,'Make a chart of how many times a week/month your family does laundry. Mark on it how many loads were done each day. Show it to your parent or guardian and ask them if there are too many loads of laundry each week. If so, how can you help make fewer loads of laundry?');
INSERT INTO badge_level_requirements VALUES(2986,407,'level2',4,'Help with 2 loads of laundry.');
INSERT INTO badge_level_requirements VALUES(2987,407,'level2',5,'Learn about how ironing removes wrinkles from clothes. Learn to iron and/or steam something simple such as a pillowcase safely and properly.');
INSERT INTO badge_level_requirements VALUES(2988,407,'level3',6,'. Do Level 2 requirements 1 & 2. Be fully responsible for at least 1 load.');
INSERT INTO badge_level_requirements VALUES(2989,407,'level3',7,'Learn to remove stains from garments, such as soda, grass, blood, sweat, and grease. Find at least 2 ways to remove each of these stains.');
INSERT INTO badge_level_requirements VALUES(2990,407,'level4',8,'Be in charge of at least 3 loads.');
INSERT INTO badge_level_requirements VALUES(2991,407,'level4',9,'Learn how to interpret wash care symbols for different fabrics, and how to wash special care items such as knitted garments and delicate items.');
INSERT INTO badge_level_requirements VALUES(2992,407,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(2993,408,'preschool',0,'.  Learn who Laura Ingalls Wilder was.  Read or have someone read to you an abridged version of one of the Little House books.');
INSERT INTO badge_level_requirements VALUES(2994,408,'level1',1,'.  Do Preschool requirement 1. You must read or listen to an unabridged book.  If you earned this badge at a different level, read a new book.');
INSERT INTO badge_level_requirements VALUES(2995,408,'level1',2,'.  Look at a map and find the different states in which she lived.');
INSERT INTO badge_level_requirements VALUES(2996,408,'level2',3,'.  Do Level 1 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(2997,408,'level2',4,'.  Create a timeline of Laura Ingalls Wilder’s life.  You must have at least 10 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(2998,408,'level3',5,'.  Do Level 2 requirements 1 & 2.  You must have at least 15 requirements on your timeline.');
INSERT INTO badge_level_requirements VALUES(2999,408,'level3',6,'.  Name all the different family members of Laura’s family. What were their roles in her life? What did they go on to do in their own lives?');
INSERT INTO badge_level_requirements VALUES(3000,408,'level4',7,'.  Do Level 3 requirements 1 & 2.  You must have at least 20 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3001,408,'level4',8,'.  Read Little Town in the Green Groves by Cynthia Rinaldi.  This is the part of Laura’s story that she could not bring herself to write about.  OR read some of Laura’s other writing, such as West from Home or On the Way Home. If you earned his badge at a previous level you must read a different book.');
INSERT INTO badge_level_requirements VALUES(3002,408,'level5',9,'. Do Level 4 requirements 1 & 2. You must have at least 25 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3003,408,'level5',10,'. Write an essay on Laura Ingalls Wilder’s life.');
INSERT INTO badge_level_requirements VALUES(3004,409,'preschool',0,'Touch at least three different types of leather.  Describe what they feel like. What type do you like the best?  Why?');
INSERT INTO badge_level_requirements VALUES(3005,409,'preschool',1,'Learn all leather making safety rules.');
INSERT INTO badge_level_requirements VALUES(3006,409,'level1',2,'Make a simple leather article such as a small purse, hair clip, or eyeglass case.');
INSERT INTO badge_level_requirements VALUES(3007,409,'level2',3,'Learn to identify at least three different types of leather and know what animal they came from and what type of things are made from them.  Understand the difference between tooling and non-tooling leather.');
INSERT INTO badge_level_requirements VALUES(3008,409,'level3',4,'Make a simple leather article and tool it, using your own design.  Finish the edges carefully.');
INSERT INTO badge_level_requirements VALUES(3009,409,'level4',5,'Learn to identify and properly use at least five of the following:tracer or scriber skiving knife leather modeler revolving punch snap setter leather needle awl leather stamps drive punch slip punch');
INSERT INTO badge_level_requirements VALUES(3010,409,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3011,410,'preschool',0,'Learn the basic principles of Leave No Trace.');
INSERT INTO badge_level_requirements VALUES(3012,410,'level1',1,'Show that you understand the Leave No Trace principles by taking a hike or participating in a campout and following all Leave No Trace principles.');
INSERT INTO badge_level_requirements VALUES(3013,410,'level2',2,'Recite and explain in your own words the principles of Leave No Trace, and discuss how an ethical guideline differs from a rule.');
INSERT INTO badge_level_requirements VALUES(3014,410,'level3',3,'Adopt a section of hiking trail, park, or street (older kids only for streets) to keep clean for a minimum of 3 months.');
INSERT INTO badge_level_requirements VALUES(3015,410,'level4',4,'Choose a section of trail and remove any obvious barriers (i.e. fallen limbs, displaced rocks) so hikers won’t be tempted to walk around and widen the trail.');
INSERT INTO badge_level_requirements VALUES(3016,410,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.  If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3017,411,'level1',0,'Understand which parts of your legend are true and which are made up or exaggerated.');
INSERT INTO badge_level_requirements VALUES(3018,411,'level2',1,'Understand the difference between a folktale, a legend, and a myth.  What makes yours a legend?');
INSERT INTO badge_level_requirements VALUES(3019,411,'level3',2,'Know where your chosen legend comes from.  Learn about at least one place connected with your chosen legend.');
INSERT INTO badge_level_requirements VALUES(3020,411,'level4',3,'Why do you think your legend came into being?  Was it to bring people together, to communicate historical events, to explain natural phenomena, to teach people how to behave, to explain how the world works?  Make up your own legend to fulfill the same purpose.');
INSERT INTO badge_level_requirements VALUES(3021,411,'level5',4,'Teach someone how to do a skill from this badge or teach some knLevel 5edge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your newfound knLevel 5edge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3022,412,'preschool',0,'Look through your Lego bricks and see how many different kinds of pieces you have.  Think of different ways in which each piece could be used.  For example: an 8-brick can be used to build a wall, become the body of a dog/cat, be the seat for a bench/chair or be the base/chassis for a small vehicle.');
INSERT INTO badge_level_requirements VALUES(3023,412,'preschool',1,'Learn how to build a wall by overlapping the bricks – the way a brick-layer would build a brick wall.  This makes a stronger wall than building the bricks up in unconnected columns.  Try building walls both ways and see which is easier to knock down.');
INSERT INTO badge_level_requirements VALUES(3024,412,'level1',2,'Find out who invented Lego, where and when.');
INSERT INTO badge_level_requirements VALUES(3025,412,'level1',3,'Create one of each of the following using at least 6 different types of Lego pieces: A structure A vehicle An animal');
INSERT INTO badge_level_requirements VALUES(3026,412,'level2',4,'At least one of your creations should have moving parts.');
INSERT INTO badge_level_requirements VALUES(3027,412,'level2',5,'Make a timeline of Lego history that includes at least 10 events.');
INSERT INTO badge_level_requirements VALUES(3028,412,'level3',6,'Include 20 events in your timeline.');
INSERT INTO badge_level_requirements VALUES(3029,412,'level3',7,'Learn about a Lego Artist such as Nathan Sawaya or Sean Kennedy. Look at examples of their work either online (with a parent’s permission) or in person. Create your own Lego art in the style of the artist you have chosen.');
INSERT INTO badge_level_requirements VALUES(3030,412,'level4',8,'Include 25 events in your timeline.');
INSERT INTO badge_level_requirements VALUES(3031,412,'level4',9,'Choose 6 of the following topics and describe how Lego might be used to learn about them: Chemistry Art Physics Biology History Architecture Math Engineering');
INSERT INTO badge_level_requirements VALUES(3032,412,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3035,414,'preschool',0,'Learn what a letter is. What is the difference between a letter, an email, and a postcard? Write a letter to someone and mail it.');
INSERT INTO badge_level_requirements VALUES(3036,414,'level1',1,'Write at least two letters and mail them.');
INSERT INTO badge_level_requirements VALUES(3037,414,'level1',2,'Learn what the word “correspondence” means. Maintain a correspondence with someone for at least one month.');
INSERT INTO badge_level_requirements VALUES(3038,414,'level2',3,'Write letters to at least three people.');
INSERT INTO badge_level_requirements VALUES(3039,414,'level2',4,'Make a timeline of the history of the U. S. Postal Service. You must have at least 10 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3040,414,'level3',5,'You must have at least 15 items on your timeline. Write letters to at least four people.');
INSERT INTO badge_level_requirements VALUES(3041,414,'level3',6,'Read a biography of someone known for their extensive letter writing, such as Abigail Adams or George Washington. If you earn this badge at a different level, you must read about a different person.');
INSERT INTO badge_level_requirements VALUES(3042,414,'level4',7,'Write letters to at least five people, and have at least 20 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3043,414,'level4',8,'Learn the difference between a business letter and a personal letter. Learn how to write a business letter.');
INSERT INTO badge_level_requirements VALUES(3044,414,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3045,415,'preschool',0,'Learn proper library etiquette.');
INSERT INTO badge_level_requirements VALUES(3046,415,'preschool',1,'Get a library card and check out at least 3 books.');
INSERT INTO badge_level_requirements VALUES(3047,415,'level1',2,'Learn how to find books you are looking for in the library by asking a librarian or using a computer or app. Know the main divisions of your library, such as Children’s, Young Adult, Adult Fiction, and Non-Fiction. What do each of the sections contain?');
INSERT INTO badge_level_requirements VALUES(3048,415,'level2',3,'Learn about the different programs and clubs your library has. It is becoming more often that libraries have more than just books, such as movie nights, Maker Spaces with 3D printers, and more. Do any of these interest you?');
INSERT INTO badge_level_requirements VALUES(3049,415,'level3',4,'Learn what other materials your library supplies. For instance, does your library have access to audiobooks? DvDs? Many libraries also have a wealth of online resources, from free ebooks to movies to magazines and scholarly articles. You may need to ask a librarian or visit your library’s website (with parental permission) to see the full list of materials and resources your library offers.');
INSERT INTO badge_level_requirements VALUES(3050,415,'level4',5,'Learn the difference between the Dewey Decimal System and the Library of Congress Classification. How can you find what book you are looking for with either system? Which system are public libraries likely to use? Academic libraries, like those in elementary schools or colleges?');
INSERT INTO badge_level_requirements VALUES(3051,415,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3052,416,'preschool',0,'Learn what a shadow is and how to make one.');
INSERT INTO badge_level_requirements VALUES(3053,416,'preschool',1,'Learn how the distance between the light and the object will change the size of the shadow.');
INSERT INTO badge_level_requirements VALUES(3054,416,'level1',2,'Learn how the sun’s position in the sky effects the size of shadows. Even the moon can create shadows when it reflects light from the sun.');
INSERT INTO badge_level_requirements VALUES(3055,416,'level2',3,'How do different materials affect lights/shadows?  Experiment with shining light through different objects.');
INSERT INTO badge_level_requirements VALUES(3056,416,'level3',4,'Learn to create at least 5 different shadow puppets');
INSERT INTO badge_level_requirements VALUES(3057,416,'level4',5,'Learn about transparent, translucent and opaque.  Know the difference between each.');
INSERT INTO badge_level_requirements VALUES(3058,416,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3059,417,'preschool',0,'What is lip balm and why to people use it?  Why should you never eat lip balm or lick too much of it?');
INSERT INTO badge_level_requirements VALUES(3060,417,'preschool',1,'Try 2 different flavors of lip balm.  Which do you like better?  Try lip balm from two different companies.  Which did you like better?');
INSERT INTO badge_level_requirements VALUES(3061,417,'level1',2,'What is the difference between lip balm, lip gloss, and lipstick?');
INSERT INTO badge_level_requirements VALUES(3062,417,'level2',3,'Learn the history lip balm. How made it? Why?');
INSERT INTO badge_level_requirements VALUES(3063,417,'level3',4,'What the ingredients are in most lip balms?  What do the ingredients do?  Which are for flavor or smell and which help moisturize or protect your lips? What ingredients should you avoid?  What ingredients should you look for?');
INSERT INTO badge_level_requirements VALUES(3064,417,'level4',5,'Learn about oral herpes (cold sores) and why you should not share your lip balm with others.');
INSERT INTO badge_level_requirements VALUES(3065,417,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3068,419,'preschool',0,'Read (with help, if need be) a story where the main character is a heroine.  Discuss what is a heroine, and what makes someone heroic.');
INSERT INTO badge_level_requirements VALUES(3069,419,'preschool',1,'Discuss ways you can be heroic in your own life.');
INSERT INTO badge_level_requirements VALUES(3070,419,'level1',2,'Read (with help, if need be) at least 3 different character’s stories and determine what traits each character displays that make her a heroine.  Find examples to support character values found in Quest.');
INSERT INTO badge_level_requirements VALUES(3071,419,'level2',3,'Read at least 5 stories.');
INSERT INTO badge_level_requirements VALUES(3072,419,'level2',4,'Even heroes have flaws. Discuss a flaw from each character. What did/can they do to overcome that flaw? How does recognizing flaws in a person’s character help to become a better person?');
INSERT INTO badge_level_requirements VALUES(3073,419,'level3',5,'Learn about the setting of the book. Where a person lives can often play a big part in their character development. What types of physical circumstances contribute to the heroic makeup of these girls?');
INSERT INTO badge_level_requirements VALUES(3074,419,'level4',6,'Write a book report on one of the books you read and focus on the character’s heroic qualities.');
INSERT INTO badge_level_requirements VALUES(3075,419,'level5',7,'Teach someone knowledge about this badge to someone.  You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3076,420,'preschool',0,'Have someone read aloud to you for 20 minutes each day for 2 weeks. If no one is available to read to you, you may listen to audio books appropriate for your age. Some people find it hard to sit and listen if they are doing nothing with their hands. If you are one of those people, try to do a quiet activity whilst you are being read to, such as knitting, crochet, needlework. Often when the hands are busy with a repetitive activity, then the brain can concentrate better on the listening. Make sure you do not distract other people from listening by your quiet activity.');
INSERT INTO badge_level_requirements VALUES(3077,420,'preschool',1,'Sit quietly in your home for at least one minute. What do you hear?');
INSERT INTO badge_level_requirements VALUES(3078,420,'level1',2,'Sit quietly in your house for at least two minutes.');
INSERT INTO badge_level_requirements VALUES(3079,420,'level1',3,'Visit an older person like a grandparent or family friend and ask them to tell you stories of their childhood or youth. Listen respectfully and attentively while they talk.');
INSERT INTO badge_level_requirements VALUES(3080,420,'level2',4,'Do Level 1 requirements #1 & 2. Sit quietly in your house for at least five minutes.');
INSERT INTO badge_level_requirements VALUES(3081,420,'level2',5,'Before education was available to most people, much more information was passed on orally (by word of mouth). Often this was done in the form of various mnemonics. What is a mnemonic? Find 5 mnemoics that teach information, such as how to remember the months of the year, the bones of the body, the American Presidents, etc. Level 3: Do six requirements, including the 2 starred *');
INSERT INTO badge_level_requirements VALUES(3082,420,'level2',6,'Find 3 famous speeches, both in audio and text form. Listen to the speech first and write down what you remember. Listen again and see how much you gained on a second listening. Finally read the speech. How much of the speech did you remember by listening? Level 4: Do seven requirements, including the two starred *');
INSERT INTO badge_level_requirements VALUES(3083,420,'level2',7,'Learn to take good notes from an audio presentation. Some information is important to write down and some is not necessary. Learn two different methods of note taking, such as diagramming a subject or linear note-taking. Level 5: Do 9, including the two starred *');
INSERT INTO badge_level_requirements VALUES(3084,420,'level2',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3089,423,'preschool',0,'Visit a local (non-chain) restaurant or bakery. What was your favorite food item offered there?');
INSERT INTO badge_level_requirements VALUES(3090,423,'preschool',1,'Make a list of foods that are grown in your state. What other products come from your area?');
INSERT INTO badge_level_requirements VALUES(3091,423,'level1',2,'Make a list of 5 locally-owned businesses and what you can buy there. What are the advantages/disadvantages of buying local?');
INSERT INTO badge_level_requirements VALUES(3092,423,'level2',3,'Find a local alternative to 3 items or foods in your home (you don’t have to actually buy them). Make a list of when different foods are in season for your area.');
INSERT INTO badge_level_requirements VALUES(3093,423,'level3',4,'Find where 10 foods in your home were grown.');
INSERT INTO badge_level_requirements VALUES(3094,423,'level3',5,'Find on a map or globe where every item of clothing you are wearing was made (including shoes). Is any of it made in our country? Are there domestic clothing manufacturers?');
INSERT INTO badge_level_requirements VALUES(3095,423,'level4',6,'Ask a local business person how buying local affects them. Compare prices at a local store and a chain store. Which is more expensive? Why? Does one have better quality?');
INSERT INTO badge_level_requirements VALUES(3096,423,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3101,426,'preschool',0,'Talk about ways people show they care—like giving hugs, helping each other, saying kind words, or making special gifts.');
INSERT INTO badge_level_requirements VALUES(3102,426,'preschool',1,'Do something nice for someone in your family using one of these ways to show you care.  Why did you choose that way to show your love?');
INSERT INTO badge_level_requirements VALUES(3103,426,'level1',2,'Learn the five love languages: Words of Affirmation, Acts of Service, Giving/Receiving Gifts, Quality Time, and Physical Touch. Match each with a way you’ve shown or received love.  Which language do you respond to best?');
INSERT INTO badge_level_requirements VALUES(3104,426,'level2',3,'Try showing love in each of the five love languages. Keep track of how people respond and which felt easiest for you.');
INSERT INTO badge_level_requirements VALUES(3105,426,'level3',4,'Learn about the history of the love languages. Who created the idea, and why has it become popular?');
INSERT INTO badge_level_requirements VALUES(3106,426,'level4',5,'Compare how love languages are expressed in different types of relationships—family, friends, romantic, professional. How do expectations or boundaries change in each?');
INSERT INTO badge_level_requirements VALUES(3107,426,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(3108,427,'preschool',0,'What is the moon? Why is the moon important? Look at pictures of the Moon and observe the actual moon.');
INSERT INTO badge_level_requirements VALUES(3109,427,'preschool',1,'Learn what safety precautions to take when making observations at night. What is the proper clothing for observing at night when it is cold? When it is warm? How can you safely observe the sun, objects near the sun, and the moon? Why is it dangerous if you do it incorrectly?');
INSERT INTO badge_level_requirements VALUES(3110,427,'level1',2,'Complete Preschool requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(3111,427,'level1',3,'Learn what causes the moon phases and be able to identify the following: New Moon, Waxing Crescent Moon, First Quarter Moon, Waxing Gibbous Moon, Full Moon, Waning Gibbous Moon, Third Quarter Moon, and Waning Crescent Moon.');
INSERT INTO badge_level_requirements VALUES(3112,427,'level2',4,'Complete Level 1 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(3113,427,'level2',5,'Research and be able to answer the following questions: How big is the moon? How far is it from Earth to the moon? How old is the moon? How do we think the moon was formed? What is a lunar eclipse? How does a lunar eclipse differ from a solar eclipse? When will there be a visible lunar eclipse in your area?');
INSERT INTO badge_level_requirements VALUES(3114,427,'level3',6,'Research and be able to answer the following questions: What is the surface of the moon like? How many craters are in the moon? Why does the moon have big rocks? How many moons are there altogether in our solar system? How hot and cold does it get on the moon?');
INSERT INTO badge_level_requirements VALUES(3115,427,'level4',7,'Learn about moon geography. Be able to identify and define the following: craters, valleys, water bodies, mountains and highlands, islands, catena, wrinkle ridges, cape and headlands, rilles, escarpments, crust, mantle & core, and composition of the Lunar “atmosphere”, soil and rocks.');
INSERT INTO badge_level_requirements VALUES(3116,427,'level5',8,'Teach someone what you have learned by completing this badge. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3117,428,'preschool',0,'Learn and perform a magic trick.');
INSERT INTO badge_level_requirements VALUES(3118,428,'level1',1,'Learn and perform at least 2 different magic tricks.');
INSERT INTO badge_level_requirements VALUES(3119,428,'level1',2,'Understand the difference between a magician and an illusionist.');
INSERT INTO badge_level_requirements VALUES(3120,428,'level2',3,'Learn and perform at least 3 different magic tricks.  These should be different types of tricks such as card tricks, rope tricks, puzzle tricks, etc.');
INSERT INTO badge_level_requirements VALUES(3121,428,'level2',4,'Learn about a famous magician.  When and where did/do they live?  What type of tricks are they famous for?');
INSERT INTO badge_level_requirements VALUES(3122,428,'level3',5,'Learn and perform at least 4 different magic tricks.');
INSERT INTO badge_level_requirements VALUES(3123,428,'level3',6,'Learn about the history of magic tricks.  Create a timeline of at least 10 events in the history of illusion.');
INSERT INTO badge_level_requirements VALUES(3124,428,'level4',7,'Learn and perform at least 5 different magic tricks.');
INSERT INTO badge_level_requirements VALUES(3125,428,'level4',8,'Teach someone else how to do a magic trick.');
INSERT INTO badge_level_requirements VALUES(3126,428,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3127,429,'preschool',0,'What is magnetism? Learn magnet safety rules, including never swallowing magnets.');
INSERT INTO badge_level_requirements VALUES(3128,429,'preschool',1,'Find two magnets of different strengths and stick them to various things around the house. Which magnet stuck to things better? What things did neither magnet stick to?');
INSERT INTO badge_level_requirements VALUES(3129,429,'level1',2,'Find out what happens when you bring 2 magnets close together.  How can you make them attract (come together) or repel (push away from each other)?  Why do these reactions occur?');
INSERT INTO badge_level_requirements VALUES(3130,429,'level1',3,'Make a simple magnet by magnetizing something metal (such as a needle or paper clip).  Stroke it with a strong magnet, in the same direction, about 30-40 times.  Test your magnet to see how strong it is.  Can it pick up a paper clip?  A heavy bolt?');
INSERT INTO badge_level_requirements VALUES(3131,429,'level2',4,'Learn the history of compasses and make your own simple compass. Level 3:  Do six requirements inducing the two starred *');
INSERT INTO badge_level_requirements VALUES(3132,429,'level2',5,'Read about electromagnets and make your own.');
INSERT INTO badge_level_requirements VALUES(3133,429,'level4',6,'Make a simple electromagnetic pin motor.');
INSERT INTO badge_level_requirements VALUES(3134,429,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3137,431,'preschool',0,'What is a main dish? Why is meat often used in main dishes? Learn about five animals that are typically eaten in a main dish and the name of those meats. Alternatively, learn five meat alternatives, such as tofu, and what meats they can replace.');
INSERT INTO badge_level_requirements VALUES(3138,431,'preschool',1,'Help make two main dishes and share them with at least one person.');
INSERT INTO badge_level_requirements VALUES(3139,431,'level1',2,'Learn about ten common items of produce, such as mushrooms, potatoes, and carrots, that are often used in main dishes. Are these generally served cooked, grilled, or raw? What kind of main dishes do they often appear in, such as Italian, Vietnamese, or Mexican dishes? Winter or summer?');
INSERT INTO badge_level_requirements VALUES(3140,431,'level2',3,'Make the majority of the main dishes yourself.');
INSERT INTO badge_level_requirements VALUES(3141,431,'level2',4,'Find out the differences between vegetarians, vegans,  meat-eaters and omnivores.  Learn about complete and complementary proteins.');
INSERT INTO badge_level_requirements VALUES(3142,431,'level3',5,'Make 3 main dishes and do it without adult help (though supervision is recommended).');
INSERT INTO badge_level_requirements VALUES(3143,431,'level3',6,'Go to the seafood counter of a grocery store (if available).  Be able to identify scallops, mussels, lobsters, crab (or crab meat), and shrimp.  Learn about what type of fish is most readily available in your area.');
INSERT INTO badge_level_requirements VALUES(3144,431,'level4',7,'Learn how to package main dish leftovers for refrigeration and for freezing.');
INSERT INTO badge_level_requirements VALUES(3145,431,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3146,432,'level4',0,'Investigate the tools used to apply makeup. What is the purpose of these tools? How does lighting affect how makeup can appear?');
INSERT INTO badge_level_requirements VALUES(3147,432,'level4',1,'From what kinds of weather conditions do people protect themselves cosmetically? Could they protect themselves in another fashion? How do you know from a label that a particular cosmetic will work? Practice applying protective makeup.');
INSERT INTO badge_level_requirements VALUES(3148,432,'level5',2,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3149,433,'preschool',0,'Learn the definition of this animal group.  What about them classifies them as such?');
INSERT INTO badge_level_requirements VALUES(3150,433,'preschool',1,'Find out as much as you can about the animal group you have chosen in your local environment by reading, observing, and talking to others.  If your chosen animal group does not live in your community, where is the nearest place that they live naturally?');
INSERT INTO badge_level_requirements VALUES(3151,433,'level1',2,'Be able to identify at least 3 species of your animal group.  You may want to look at things like size, shape, color or other distinguishing marks.  Learn about their life cycle, what they eat, how they protect themselves, their calls, and habits.');
INSERT INTO badge_level_requirements VALUES(3152,433,'level2',3,'but identify at least 5 species (If you completed this badge for the same animal group at a different level, you may not use species you have researched in the past.)');
INSERT INTO badge_level_requirements VALUES(3153,433,'level3',4,'If possible, observe your animal category in the wild on at least 3 different occasions.  Take notes on their behavior and compare them to what you have learned.');
INSERT INTO badge_level_requirements VALUES(3154,433,'level3',5,'but identify at least 8 species (If you completed this badge for the same animal group at a different level, you may not use species you have researched in the past.)');
INSERT INTO badge_level_requirements VALUES(3155,433,'level4',6,'If possible, observe your animal category in the wild on at least 5 different occasions.  Take notes on their behavior and compare them to what you have learned.');
INSERT INTO badge_level_requirements VALUES(3156,433,'level4',7,'but identify at least 12 species (If you completed this badge for the same animal group at a different level, you may not use species you have researched in the past.)');
INSERT INTO badge_level_requirements VALUES(3157,433,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3158,434,'preschool',0,'What is manga?  What are the different types of manga and what audience are they meant for?  Earn this badge by learning about an appropriate style of manga for your age.');
INSERT INTO badge_level_requirements VALUES(3159,434,'preschool',1,'Read an age appropriate manga book.');
INSERT INTO badge_level_requirements VALUES(3160,434,'level1',2,'Where did manga originate? Find it on a map.');
INSERT INTO badge_level_requirements VALUES(3161,434,'level2',3,'What are the three key elements of manga art?  How does this style differ from other comics and illustrations?');
INSERT INTO badge_level_requirements VALUES(3162,434,'level3',4,'What is the difference between anime and manga. Why are they frequently used together? Watch an age appropriate anime.');
INSERT INTO badge_level_requirements VALUES(3163,434,'level4',5,'Learn about the history of manga. How did early Japanese art influence modern manga?');
INSERT INTO badge_level_requirements VALUES(3164,434,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3165,435,'preschool',0,'What is a man-made wonder? How is it different from a natural wonder?  What are examples of manmade wonders?');
INSERT INTO badge_level_requirements VALUES(3166,435,'preschool',1,'Choose a specific category of man-made structures. Find at least three pictures of that type of structure. Show them to someone and tell them what makes these structures special.');
INSERT INTO badge_level_requirements VALUES(3167,435,'level1',2,'Experiment with making your own mini structure.  How can you make it stronger and more stable?  How can you make the design more appealing while retaining the function?  For example, if you make a toothpick bridge, try adjusting the number of toothpicks used.  Adjust how they are arranged or what you use to glue them together and see what makes a better bridge.  Make at least three different versions of your structure with this experiment.');
INSERT INTO badge_level_requirements VALUES(3168,435,'level1',3,'Learn about a man-made structure that is famous in your category.  It can be famous for being the biggest, tallest, widest, etc. or because it was designed by a famous architect or designer.  Where is it?  Locate it on a map.');
INSERT INTO badge_level_requirements VALUES(3169,435,'level2',4,'Learn the history of these types of structures and how they have improved over the years.');
INSERT INTO badge_level_requirements VALUES(3170,435,'level3',5,'Choose a specific category of man-made structures.  Find a construction project in your category that is being built or has been completed in the last 10 years.  Visit the site or view pictures of the project through books or the internet (with a parent’s permission).');
INSERT INTO badge_level_requirements VALUES(3171,435,'level4',6,'Research the design ideas that go into your structure type such as earthquake proof, green technology, cantilevers, etc.');
INSERT INTO badge_level_requirements VALUES(3172,435,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3173,436,'preschool',0,'Identify three different types of maple trees by their leaves.');
INSERT INTO badge_level_requirements VALUES(3174,436,'preschool',1,'Name the ingredients in pure maple syrup. How is maple syrup made?');
INSERT INTO badge_level_requirements VALUES(3175,436,'level1',2,'Identify three different varieties of trees (maple plus two others) that can be used for maple syrup.');
INSERT INTO badge_level_requirements VALUES(3176,436,'level2',3,'Explain what time of year the sap is collected from trees and why.');
INSERT INTO badge_level_requirements VALUES(3177,436,'level3',4,'Describe which regions of North America are best for harvesting maple syrup and why.');
INSERT INTO badge_level_requirements VALUES(3178,436,'level4',5,'Describe the difference between the different grades of syrup.');
INSERT INTO badge_level_requirements VALUES(3179,436,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Option Requirements');
INSERT INTO badge_level_requirements VALUES(3180,437,'preschool',0,'Look at a variety of marbles and notice their colors, swirls, shape.  What are they made of?  Learn some of their nicknames, and how to recognize these patterns, such as: – Cat’s eye – Alley – Aggie – Commie');
INSERT INTO badge_level_requirements VALUES(3181,437,'preschool',1,'Find a safe place to play with your marbles, and learn how to pick marbles to play with that don’t pose a choking hazard to you. Learn safety rules regarding playing with marbles such as not putting them in your mouth, not throwing them and putting them away as soon as you are done playing with them.');
INSERT INTO badge_level_requirements VALUES(3182,437,'level1',2,'Learn how to play, and then play two marble games, such as: – Lagging (used to select the first player in another game) – Ringtaw');
INSERT INTO badge_level_requirements VALUES(3183,437,'level2',3,'Learn how marbles used to be made and how they are made now.  Where do marbles get their name?');
INSERT INTO badge_level_requirements VALUES(3184,437,'level3',4,'What cultures are responsible for bringing the game of marbles to the world?  What other materials are used in some countries instead of glass marbles?  Try playing a game of marbles with one of these materials.');
INSERT INTO badge_level_requirements VALUES(3185,437,'level4',5,'Research the historical and cultural significance of marbles in different societies.  How have they evolved over time?');
INSERT INTO badge_level_requirements VALUES(3186,437,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3187,438,'preschool',0,'Know what the March 4th holiday is and why Frontier Girls celebrate it.');
INSERT INTO badge_level_requirements VALUES(3188,438,'level1',1,'What is the importance of the March 4th date?');
INSERT INTO badge_level_requirements VALUES(3189,438,'level1',2,'Learn about a troop or Pioneer in another state via letters, emails, cards, or even a video conference.');
INSERT INTO badge_level_requirements VALUES(3190,438,'level2',3,'.Do Level 1 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(3191,438,'level2',4,'Participate  in a swap exchange with Frontier Girl sisters in another area or state.  Make sure your swap represents the part of the country you are from. For more information on SWAPS and their history, with the permission of an adult visit: http://www.makingfriends.com/pro_swaphistory.htm');
INSERT INTO badge_level_requirements VALUES(3192,438,'level3',5,'Create a map of the United States that represents where our Frontier Girls members are located.');
INSERT INTO badge_level_requirements VALUES(3193,438,'level4',6,'March Forth! And take action by participating in a community service project on March 4th that demonstrates a character trait that Frontier Girls promotes.');
INSERT INTO badge_level_requirements VALUES(3194,438,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3195,439,'preschool',0,'Learn what a ship is. Look at pictures of different ships. Which one is your favorite?');
INSERT INTO badge_level_requirements VALUES(3196,439,'level1',1,'Look at a picture of a modern ship, a steamship, and an old-fashioned sailing ship.  What are the main differences between them?');
INSERT INTO badge_level_requirements VALUES(3197,439,'level2',2,'There are many different kinds of ships, such as oil tankers, cruise liners, aircraft carriers, etc.  Pick two different kinds and learn about them. Tell your family, friends, or group what you learned.');
INSERT INTO badge_level_requirements VALUES(3198,439,'level3',3,'Learn about at least four different kinds of ships.');
INSERT INTO badge_level_requirements VALUES(3199,439,'level3',4,'Make a timeline of the history of shipbuilding.  You must have at least 10 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3200,439,'level4',5,'Have at least 15 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3201,439,'level4',6,'Read a biography of a famous person connected with the history of ships, such as Captain James Cook, Admiral Chester Nimitz, or Horatio Nelson. If you earn this badge again at a different level you must read about a different person.');
INSERT INTO badge_level_requirements VALUES(3202,439,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3203,440,'preschool',0,'Learn the definition of this animal group.  What about them classifies them as such?');
INSERT INTO badge_level_requirements VALUES(3204,440,'preschool',1,'Find out as much as you can about the animal group you have chosen in your local environment by reading, observing, and talking to others.  If your chosen animal group does not live in your community, where is the nearest place that they live naturally?');
INSERT INTO badge_level_requirements VALUES(3205,440,'level1',2,'Be able to identify at least 3 species of your animal group.  You may want to look at things like size, shape, color or other distinguishing marks.  Learn about their life cycle, what they eat, how they protect themselves, their calls, and habits.');
