INSERT INTO badge_level_requirements VALUES(3207,440,'level3',4,'If possible, observe your animal category in the wild on at least 3 different occasions.  Take notes on their behavior and compare them to what you have learned.');
INSERT INTO badge_level_requirements VALUES(3208,440,'level3',5,'but identify at least 8 species (If you completed this badge for the same animal group at a different level, you may not use species you have researched in the past.)');
INSERT INTO badge_level_requirements VALUES(3209,440,'level4',6,'If possible, observe your animal category in the wild on at least 5 different occasions.  Take notes on their behavior and compare them to what you have learned.');
