INSERT INTO badge_level_requirements VALUES(3212,441,'preschool',0,'Understand what the Marines are and what their role is in the military.');
INSERT INTO badge_level_requirements VALUES(3213,441,'level1',1,'Learn the history of the Marines and how they began as well as their mission today.');
INSERT INTO badge_level_requirements VALUES(3214,441,'level2',2,'Discuss the contributions the Marines have made to our country or write an essay about these contributions.');
INSERT INTO badge_level_requirements VALUES(3215,441,'level3',3,'What is the Crucible? What does it consist of? Who must endure it? How long does it last? When was it designed and why?');
INSERT INTO badge_level_requirements VALUES(3216,441,'level4',4,'Visit an Marine recruiter. Find out how to enlist in the Marines or be commissioned as an Marine officer. What jobs are available? What training is provided? How long must you enlist for? What are the benefits of joining the military? What are the drawbacks? How does your education and background affect your salary in the Marines?');
INSERT INTO badge_level_requirements VALUES(3217,441,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3222,444,'preschool',0,'Learn a minimum of two different strokes used when massaging the hands or feet.');
INSERT INTO badge_level_requirements VALUES(3223,444,'preschool',1,'Give someone a foot massage.');
INSERT INTO badge_level_requirements VALUES(3224,444,'level1',2,'Perform at least three hand or foot massages each at least two minutes in length.');
INSERT INTO badge_level_requirements VALUES(3225,444,'level1',3,'Learn a minimum of two different or new strokes or types of pressure used massaging the knees and lower legs.');
INSERT INTO badge_level_requirements VALUES(3226,444,'level2',4,'Perform at least three massages that include the lower legs and are at least two minutes in length.');
INSERT INTO badge_level_requirements VALUES(3227,444,'level2',5,'Learn a minimum of two different or new strokes or types of pressure used massaging the neck and shoulders.');
INSERT INTO badge_level_requirements VALUES(3228,444,'level3',6,'.  Do Level 2 requirements 1 & 2. Perform at least three massages that include the neck and shoulders and are at least two minutes in length.');
INSERT INTO badge_level_requirements VALUES(3229,444,'level3',7,'Learn a minimum of two different or new strokes or types of pressure used massaging the back. Perform at least five massages that include the back and are at least five minutes in length.');
INSERT INTO badge_level_requirements VALUES(3230,444,'level4',8,'Learn the basic muscle groups of each part of the body you have learned to massage.  What are the main muscles in each area?');
INSERT INTO badge_level_requirements VALUES(3231,444,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3232,445,'preschool',0,'Learn to count to 10');
INSERT INTO badge_level_requirements VALUES(3233,445,'preschool',1,'Be able to recognize the numbers 1-10');
INSERT INTO badge_level_requirements VALUES(3234,445,'level1',2,'and 2.');
INSERT INTO badge_level_requirements VALUES(3235,445,'level1',3,'Measure yourself in 5 different ways.   How tall are you?  How much do you weigh?  What size clothing do you where?  How fast can your run?  How long is your stride?  These are just a few examples of the ways you can measure yourself.  Be creative and come up with your own “you” things to measure.');
INSERT INTO badge_level_requirements VALUES(3236,445,'level2',4,'. Do Level 1 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(3237,445,'level2',5,'Play at least 6 games that use math. Make a chart to show which games help people practice which skills. Determine which game covers the most math. Which one is the most fun?');
INSERT INTO badge_level_requirements VALUES(3238,445,'level3',6,'Make “kaleidoscope” designs with a compass (and ruler). Color them with beautiful colors. Give some away as small posters or the front of stationery.   Use the compass to make a variety of sizes from small (about 2” diameter) to large (as wide as your compass can go)');
INSERT INTO badge_level_requirements VALUES(3239,445,'level4',7,'Research careers that require a strong math background.  Examples may be engineers, financial advisors, accountants, or construction.  Find out what type of math classes are required for these careers. If possible, shadow someone with a math oriented career for a day.');
INSERT INTO badge_level_requirements VALUES(3240,445,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3241,446,'preschool',0,'What is May Day? What is a May basket?');
INSERT INTO badge_level_requirements VALUES(3242,446,'preschool',1,'What do you put in a May basket? Make a May basket and deliver it.');
INSERT INTO badge_level_requirements VALUES(3243,446,'level1',2,'Make and deliver at least two May baskets.');
INSERT INTO badge_level_requirements VALUES(3244,446,'level2',3,'Make and deliver at least three May baskets.');
INSERT INTO badge_level_requirements VALUES(3245,446,'level2',4,'Learn the history behind May baskets. How are they traditionally delivered?');
INSERT INTO badge_level_requirements VALUES(3246,446,'level3',5,'Make and deliver at least four May baskets.');
INSERT INTO badge_level_requirements VALUES(3247,446,'level3',6,'What are some other traditions to celebrate May Day?');
INSERT INTO badge_level_requirements VALUES(3248,446,'level4',7,'Make and deliver at least five May baskets.');
INSERT INTO badge_level_requirements VALUES(3249,446,'level4',8,'Deliver May baskets at the nursing home, hospital or to shut-ins.');
INSERT INTO badge_level_requirements VALUES(3250,446,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3251,447,'preschool',0,'Help prepare or serve a meal that is special to your family. Talk about who usually cooks it and when.  What makes it special?');
INSERT INTO badge_level_requirements VALUES(3252,447,'preschool',1,'Learn how to politely ask for food, say thank you, and clean up after a meal in your home.');
INSERT INTO badge_level_requirements VALUES(3253,447,'level1',2,'Share a family meal with someone and talk about why it’s meaningful. Is it tied to a holiday, event, or tradition? Or is it simply a traditional way of connecting at the start or end of the day?');
INSERT INTO badge_level_requirements VALUES(3254,447,'level2',3,'Learn about how meals are eaten in other countries. Learn about at least 5 different countries. How many meals per day do they eat? (Spain=5) What utensils do they use? (Japan=chopsticks) Where do they eat, such as a table or the floor? (India=floor)  Are meals quiet or loud? (Korea-quiet) What etiquette do they have? (Burping is polite in China)');
INSERT INTO badge_level_requirements VALUES(3255,447,'level3',4,'Research the history of a meal tradition in your own culture or another culture. When did it begin and why? How has it changed over time?');
INSERT INTO badge_level_requirements VALUES(3256,447,'level4',5,'Compare meal traditions from at least three different cultures or countries. What foods, times of day, utensils, seating, or customs are different?');
INSERT INTO badge_level_requirements VALUES(3257,447,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(3258,448,'preschool',0,'Understand that meat comes from animals and different animals provide different types of meat.');
INSERT INTO badge_level_requirements VALUES(3259,448,'preschool',1,'Know what kind of animal produces the following meats:  beef, pork, chicken, fish, turkey.  Try some of each kind of meat.  Which do you like best?');
INSERT INTO badge_level_requirements VALUES(3260,448,'level1',2,'Be able to identify beef, pork, chicken, fish and turkey by taste.');
INSERT INTO badge_level_requirements VALUES(3261,448,'level1',3,'Learn about the life cycle of a meat animal, from birth or hatching to maturity and eventual processing.');
INSERT INTO badge_level_requirements VALUES(3262,448,'level2',4,'Learn about the proper housing and living conditions required for meat animals, including space, ventilation, and cleanliness.');
INSERT INTO badge_level_requirements VALUES(3263,448,'level3',5,'Understand the nutritional composition of meat, including its protein, fat, and micronutrient content. Learn about meat’s impact on human health and discuss topics such as portion sizes, balanced diets, and dietary guidelines in relation to meat consumpsion.');
INSERT INTO badge_level_requirements VALUES(3264,448,'level4',6,'Understand the concept of animal welfare and the ethical considerations in raising and handling meat animals.  Are there laws in your state about how meat animals are treated?  If so, what are they?');
INSERT INTO badge_level_requirements VALUES(3265,448,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3269,451,'preschool',0,'Read a story or listen to a story about one family member in the military (or a friend of the family).');
INSERT INTO badge_level_requirements VALUES(3270,451,'preschool',1,'Learn about the different military branches that your family (or friend’s family) have been in and what they did in that branch of service, how long they served and what (if any) wars they fought in.');
INSERT INTO badge_level_requirements VALUES(3271,451,'level1',2,'Write to a family member (or friend) who is in the military and tell them how much you appreciate their service.');
INSERT INTO badge_level_requirements VALUES(3272,451,'level1',3,'Learn about all the branches of the military; Air Force, Army, Marines, Navy, and explain the special role of the Coast Guard.');
INSERT INTO badge_level_requirements VALUES(3273,451,'level2',4,'Interview a spouse of a military member. Make a list of at least 15 questions to ask him or her.');
INSERT INTO badge_level_requirements VALUES(3274,451,'level2',5,'Interview a child of a military member. Make a list of at least 10 questions about their life and what it’s like to have a mother or father in the military.');
INSERT INTO badge_level_requirements VALUES(3275,451,'level3',6,'Create an essay on what you’ve learned from your interviews.');
INSERT INTO badge_level_requirements VALUES(3276,451,'level3',7,'Learn about the role of the American Red Cross and what they do for military families.');
INSERT INTO badge_level_requirements VALUES(3277,451,'level4',8,'Learn about Blue Star, Silver Star, & Gold Star families. What are the similarities and differences between the three organizations?');
INSERT INTO badge_level_requirements VALUES(3278,451,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3279,452,'preschool',0,'Learn what mind puzzles are and look at examples of 3 different types, such as crosswords, sudoku, kakuro, hourglass, etc.');
INSERT INTO badge_level_requirements VALUES(3280,452,'preschool',1,'Find someone who likes to work mind puzzles and talk to them.  What is their favorite type of  puzzle, and why?');
INSERT INTO badge_level_requirements VALUES(3281,452,'level1',2,'Learn about a particular type of puzzle and learn to do it.  Do two of these puzzles at your level of difficulty.');
INSERT INTO badge_level_requirements VALUES(3282,452,'level2',3,'Do at least 3 different puzzles. If you earned this badge at an earlier level you must learn about and do a different type of puzzle.');
INSERT INTO badge_level_requirements VALUES(3283,452,'level2',4,'Find 3 examples of mind puzzles and show them to your family or troop.');
INSERT INTO badge_level_requirements VALUES(3284,452,'level3',5,'Do at least 4 different puzzles. If you earned this badge at an earlier level you must learn about and do a different type of puzzle.');
INSERT INTO badge_level_requirements VALUES(3285,452,'level3',6,'Learn about the history of mind puzzles.');
INSERT INTO badge_level_requirements VALUES(3286,452,'level4',7,'Do at least 5 different puzzles. If you earned this badge at an earlier level you must learn about and do a different type of puzzle.');
INSERT INTO badge_level_requirements VALUES(3287,452,'level4',8,'Learn how the different types of puzzles are separated into difficulty levels.');
INSERT INTO badge_level_requirements VALUES(3288,452,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3291,454,'level1',0,'Make at least 3 types of miniatures.  Items might include: Furniture, food, doll house, clothing, flowers, dishes, books, trees, bedding, party décor, or sports equipment');
INSERT INTO badge_level_requirements VALUES(3292,454,'level1',1,'Choose a specific type of miniatures such as doll houses, miniature writing or books, miniature horses or other animals, miniature trains, etc. and learn the history of this type of miniature.  When did people first start to make them?  Where?  Did they originally serve a specific purpose?');
INSERT INTO badge_level_requirements VALUES(3293,454,'level2',2,'Complete Level 1 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(3294,454,'level2',3,'Learn what the following terms mean in relation to miniatures: scale, OOAK, diorama, layout,  polymer clay, artisan quality, acetate, adhesive, armature, balsa');
INSERT INTO badge_level_requirements VALUES(3295,454,'level3',4,'Complete Level 2 requirements 1 &2.');
INSERT INTO badge_level_requirements VALUES(3296,454,'level3',5,'Learn how to make something to scale.    Measure something in your home and try to recreate it using 1:12 scale.  Find miniatures that come in at least 3 different scales.  Which size do you like best?');
INSERT INTO badge_level_requirements VALUES(3297,454,'level4',6,'Complete Level 3 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(3298,454,'level4',7,'Learn about IGMA – the International Guild of Miniature Artisans or NAME – National Association of Miniature Enthusiasts.  Who can join and what are the benefits of membership?  What are the objectives of the Guild?  What other associations are there for miniature enthusiasts?');
INSERT INTO badge_level_requirements VALUES(3303,457,'preschool',0,'What is money and what is it used for?');
INSERT INTO badge_level_requirements VALUES(3304,457,'preschool',1,'Correctly identify all the coins and bills up to a $20 bill and their values.');
INSERT INTO badge_level_requirements VALUES(3305,457,'level1',2,'Learn about the different security features on US currency.  Why are they needed?  How does each feature keep people from creating counterfeit money?');
INSERT INTO badge_level_requirements VALUES(3306,457,'level2',3,'Play a game involving money such as Monopoly, Cashflow, Payday or Exact Change.');
INSERT INTO badge_level_requirements VALUES(3307,457,'level3',4,'Learn about the history of money. What is the difference between bartering and the exchange of money for products or services?');
INSERT INTO badge_level_requirements VALUES(3308,457,'level4',5,'Learn about currencies from around the world. How does the value of the US dollar compare to other currencies? What is an “exchange rate”?');
INSERT INTO badge_level_requirements VALUES(3309,457,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3310,458,'preschool',0,'What is Morse code? What is a cipher?');
INSERT INTO badge_level_requirements VALUES(3311,458,'preschool',1,'What does SOS mean and how do you cipher it in Morse code?');
INSERT INTO badge_level_requirements VALUES(3312,458,'level1',2,'Who invented Morse code and when? What was the first sentence sent?');
INSERT INTO badge_level_requirements VALUES(3313,458,'level1',3,'How can Morse code be used with light and sound? Try it.');
INSERT INTO badge_level_requirements VALUES(3314,458,'level2',4,'Learn your name in Morse code. Write it and say it using sound (dit=dot and dat=dash).');
INSERT INTO badge_level_requirements VALUES(3315,458,'level3',5,'Learn about the telegraph system that sent the first Morse code message.');
INSERT INTO badge_level_requirements VALUES(3316,458,'level4',6,'Make a timeline of at least 10 Morse code events.');
INSERT INTO badge_level_requirements VALUES(3317,458,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3320,460,'preschool',0,'Make a list of your favorite movies, and choose one to watch. Watch it.');
INSERT INTO badge_level_requirements VALUES(3321,460,'preschool',1,'Tell someone about the movie you watched. Did you like it? Why or why not?');
INSERT INTO badge_level_requirements VALUES(3322,460,'level1',2,'Create an art project about your movie. You might draw a picture of your favorite movie character(s), make a diorama of your favorite scene, make a costume from the movie, or an art project of an item from the movie.');
INSERT INTO badge_level_requirements VALUES(3323,460,'level2',3,'Research the movie rating system (G, PG, PG-13, R) and what each means. Find out the rating systems of two other countries.');
INSERT INTO badge_level_requirements VALUES(3324,460,'level3',4,'Write a movie review of a movie you watched. If you are doing a specific movie, make sure your review is of that movie.');
INSERT INTO badge_level_requirements VALUES(3325,460,'level4',5,'Research the history of movie making. Find out what the first movie ever shown in the cinema was. Find out when movies went from silent to sound, and when movies went from black and white to color. If you are doing a specific movie, you can find out when your movie was first made for the big screen, and the history of that movie.');
INSERT INTO badge_level_requirements VALUES(3326,460,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3327,461,'preschool',0,'Learn what mummification is.');
INSERT INTO badge_level_requirements VALUES(3328,461,'preschool',1,'Make a mummy craft');
INSERT INTO badge_level_requirements VALUES(3329,461,'level1',2,'Find out which countries have used mummification in the past or still do.  If they still make mummies, why?');
INSERT INTO badge_level_requirements VALUES(3330,461,'level2',3,'Find out what researchers can learn from a mummy. What can it tell us about the culture and time the person lived in?');
INSERT INTO badge_level_requirements VALUES(3331,461,'level3',4,'Learn about the process of mummification and how it is done.');
INSERT INTO badge_level_requirements VALUES(3332,461,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(3335,463,'preschool',0,'Be able to identify a mushroom. Know that Mushrooms are fungi and their own kingdom and are different than plants or animals.');
INSERT INTO badge_level_requirements VALUES(3336,463,'preschool',1,'Make a playdoh copy of a fruiting form found in the wild (take your playdoh into the woods!)');
INSERT INTO badge_level_requirements VALUES(3337,463,'level1',2,'Do preschool requirement #1');
INSERT INTO badge_level_requirements VALUES(3338,463,'level1',3,'Learn the parts of a mushroom.');
INSERT INTO badge_level_requirements VALUES(3339,463,'level2',4,'Do Level 1 requirement #1 and #2');
INSERT INTO badge_level_requirements VALUES(3340,463,'level2',5,'Learn the lifecycle of a mushroom.');
INSERT INTO badge_level_requirements VALUES(3341,463,'level3',6,'Do Level 2 requirement #1 and #2');
INSERT INTO badge_level_requirements VALUES(3342,463,'level3',7,'Know the phylum breakdowns of fungi, with particular focus on Ascomycetes versus Basidiomycetes.  Choose a fungal phyla for specialization.  Learn how spores are made and dispersed in your phyla – learn how reproduction occurs in your phyla – learn the basic anatomical traits that separate your phyla from the others.  Find a representative of your phyla in the wild or look through photos of mushrooms in your phyla. Make notes on how each fits into your phyla.');
INSERT INTO badge_level_requirements VALUES(3343,463,'level4',8,'Do Level 2 requirement #1 and #2');
INSERT INTO badge_level_requirements VALUES(3344,463,'level4',9,'Pick a genus in your phyla to focus on. Know the geographic range of your genus.  Learn about its toxicity. Is it edible? Is it medicinal? Is it deadly? Is it used for art?  Think about and write about your genus, and any new ideas you have for things that could be made from it.  Either go on a foray or use the internet to find as many images as you can of species in your genus.');
INSERT INTO badge_level_requirements VALUES(3345,463,'level5',10,'Do Level 4 requirements #1 & #2');
INSERT INTO badge_level_requirements VALUES(3346,463,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(3347,464,'preschool',0,'Listen to a different genre of music from what you usually listen to, such as country, rock, classical, rap, etc. Did you like it? Why or why not?');
INSERT INTO badge_level_requirements VALUES(3348,464,'level1',1,'Listen to two different genres of music. Did you like them?  Why or why not? Learn the names of 3 musical instruments and listen to how they sound.');
INSERT INTO badge_level_requirements VALUES(3349,464,'level1',2,'Learn what a composer, an arranger, a conductor, and a musician are.');
INSERT INTO badge_level_requirements VALUES(3350,464,'level2',3,'Listen to three different genres of music and learn the names of at least 5 musical instruments.');
INSERT INTO badge_level_requirements VALUES(3351,464,'level2',4,'Explain why music is an important part of our culture.');
INSERT INTO badge_level_requirements VALUES(3352,464,'level3',5,'Listen to four different genres of music and learn the names of at least 7 musical instruments.');
INSERT INTO badge_level_requirements VALUES(3353,464,'level3',6,'Learn about the history of music. What sort of influence has music had on our history? Create a timeline with at least 10 events for music as a whole, or a specific type of music (such as the history of bluegrass).');
INSERT INTO badge_level_requirements VALUES(3354,464,'level4',7,'Listen to five different genres of music and learn the names of at least 10 different instruments.');
INSERT INTO badge_level_requirements VALUES(3355,464,'level4',8,'Read a biography of a famous person in the music business such as a composer, singer or dancer.  Would you have liked to be them? If you completed this requirement at a lower level you must choose a new person to read about.');
INSERT INTO badge_level_requirements VALUES(3356,464,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3357,465,'preschool',0,'Listen to at least three different genres of music, preferably ones that you have never listened to before.');
INSERT INTO badge_level_requirements VALUES(3358,465,'preschool',1,'Be able to identify at least 3 different musical instruments.');
INSERT INTO badge_level_requirements VALUES(3359,465,'level1',2,'Listen to at least 5 genres of music and identify at least 5 different musical instruments.');
INSERT INTO badge_level_requirements VALUES(3360,465,'level1',3,'Be able to identify the sounds of at least 5 musical instruments.');
INSERT INTO badge_level_requirements VALUES(3361,465,'level2',4,'Be able to identify and describe your 5 musical genre by sound.');
INSERT INTO badge_level_requirements VALUES(3362,465,'level2',5,'Be able to identify by look and sound, 3 different instruments from each of the following categories: Wind Instruments Percussion Instruments String Instruments Brass Instruments');
INSERT INTO badge_level_requirements VALUES(3363,465,'level3',6,'Identify and describe at least 10 musical genres.');
INSERT INTO badge_level_requirements VALUES(3364,465,'level3',7,'Listen to music from at least three other countries. How does their popular or traditional music differ from ours?');
INSERT INTO badge_level_requirements VALUES(3365,465,'level4',8,'Identify and describe at least 15 musical genres.');
INSERT INTO badge_level_requirements VALUES(3366,465,'level4',9,'Learn about the connection between music and the mind. Explain how music affects emotions, memories, and learning abilities. Share your findings either through an essay, booklet, poster, speech or other medium.');
INSERT INTO badge_level_requirements VALUES(3367,465,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3368,466,'preschool',0,'Learn what a music box is and look at pictures of at least 10 different music boxes.');
INSERT INTO badge_level_requirements VALUES(3369,466,'preschool',1,'Listen to at least three different music boxes that each play a different song.  Which is your favorite?  Why?');
INSERT INTO badge_level_requirements VALUES(3370,466,'level1',2,'Learn how a traditional cylinder music box works and how it produces sound.  Demonstrate the ability to identify the different parts of a music box, including the cylinder, comb, and winding mechanism.');
INSERT INTO badge_level_requirements VALUES(3371,466,'level2',3,'Learn about disc music boxes and how they work.  Compare and contrast them to the more common cylinder music boxes.');
INSERT INTO badge_level_requirements VALUES(3372,466,'level3',4,'Demonstrate an understanding of the history of music boxes, including their origins and evolution.');
INSERT INTO badge_level_requirements VALUES(3373,466,'level4',5,'Research the cultural significance of music boxes in different parts of the world.');
INSERT INTO badge_level_requirements VALUES(3374,466,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3375,467,'preschool',0,'What is a band? Be able to explain what a band is to someone.');
INSERT INTO badge_level_requirements VALUES(3376,467,'preschool',1,'Know the name of your band, and what type of music it plays. Learn to sing one of your band’s songs.');
INSERT INTO badge_level_requirements VALUES(3377,467,'level1',2,'*. Be able to sing at least two of their songs. Be able to recognize your band’s logo, if they have one.');
INSERT INTO badge_level_requirements VALUES(3378,467,'level1',3,'Know the names of all the members of your band, and be able to recognize them in a photograph.');
INSERT INTO badge_level_requirements VALUES(3379,467,'level2',4,'Be able to sing at least three of their songs. Know the history of your chosen band’s name.');
INSERT INTO badge_level_requirements VALUES(3380,467,'level2',5,'Learn the history of your band and make a timeline of it. You must have at least 10 items on your timeline. Know when and where your band was founded.');
INSERT INTO badge_level_requirements VALUES(3381,467,'level3',6,'Be able to sing at least four of their songs.');
INSERT INTO badge_level_requirements VALUES(3382,467,'level3',7,'Learn how many albums your band has produced. Be able to name them all.');
INSERT INTO badge_level_requirements VALUES(3383,467,'level4',8,'Be able to sing at least five of their songs.');
INSERT INTO badge_level_requirements VALUES(3384,467,'level4',9,'Know what your bands first number one hit was, and listen to it. Make a list of your favorite songs your band has released and take note of where their first hit appears on your list, if at all.');
INSERT INTO badge_level_requirements VALUES(3385,467,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3386,468,'preschool',0,'Learn about how musical instruments have changed over time.  Look at pictures and learn about at least 3 ancient instruments and their modern counterpart.');
INSERT INTO badge_level_requirements VALUES(3387,468,'preschool',1,'Make an instrument of your own.  It might be a simple drum, a pipe of some type, or even a kazoo.  How do you think people in the past made instruments like yours?');
INSERT INTO badge_level_requirements VALUES(3388,468,'level1',2,'What is a musical period? What are the four main musical periods? Learn the order in which they come and listen to music from each.');
INSERT INTO badge_level_requirements VALUES(3389,468,'level2',3,'From any of the four main musical periods, learn about one composer. Where was he/she from? What period was he/she in? What was he/she famous for?  What instrument did he/she play?');
INSERT INTO badge_level_requirements VALUES(3390,468,'level3',4,'Learn about the instruments from different periods of music. What instruments are prevalent now that either were not popular in an earlier period or were somehow different?  What instruments are there that are now “extinct” or not as widely used as they once were?');
INSERT INTO badge_level_requirements VALUES(3391,468,'level4',5,'Pick four composers (one from each musical period) and learn about them. Were they famous in their day? Where were they from? What instruments or voice types did he/she compose for? When were they born? When did they die?');
INSERT INTO badge_level_requirements VALUES(3392,468,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3393,469,'preschool',0,'Demonstrate the proper way to play your instrument and how to care for it. Know the names of all the parts of your instrument.');
INSERT INTO badge_level_requirements VALUES(3394,469,'preschool',1,'Learn to play a song on your instrument at your current level of ability.');
INSERT INTO badge_level_requirements VALUES(3395,469,'level1',2,'and 2. Learn the clef your instrument is played in and the names of the notes in the clef.');
INSERT INTO badge_level_requirements VALUES(3396,469,'level1',3,'Learn to play a new song on your instrument at your current level of ability. Play the song for another person.');
INSERT INTO badge_level_requirements VALUES(3397,469,'level2',4,'Play two major scales on your instrument.');
INSERT INTO badge_level_requirements VALUES(3398,469,'level2',5,'Learn to play a new song on your instrument at your current level of ability. Play the song for at least two other people.');
INSERT INTO badge_level_requirements VALUES(3399,469,'level3',6,'Play five major scales on your instrument.');
INSERT INTO badge_level_requirements VALUES(3400,469,'level3',7,'Learn to play a new song on your instrument at your current level of ability. Play the song for at least three other people.');
INSERT INTO badge_level_requirements VALUES(3401,469,'level4',8,'Play seven major scales on your instrument and the chromatic scale.');
INSERT INTO badge_level_requirements VALUES(3402,469,'level4',9,'Learn to play a new song on your instrument at your current level of ability. Play the song for at least four other people on at least two different occasions.');
INSERT INTO badge_level_requirements VALUES(3403,469,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(3404,470,'preschool',0,'Learn what a community is. Be able to find your community on a map (if your community is very small, be able to locate the county in which it is on a map).');
INSERT INTO badge_level_requirements VALUES(3405,470,'level1',1,'When was your community founded?  Learn the surnames of the people/families who originally settled your community.');
INSERT INTO badge_level_requirements VALUES(3406,470,'level2',2,'Make a timeline of important dates in your community’s history. You must have at least 10 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3407,470,'level3',3,'You must have at least 15 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3408,470,'level3',4,'Learn the history of your community.  Why was it founded?  What aspects of industry/location/other attraction caused people to settle in that location?  When did your family first move there?');
INSERT INTO badge_level_requirements VALUES(3409,470,'level4',5,'Have at least 20 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3410,470,'level4',6,'Learn who the mayor, aldermen, police chief, fire chief, city council members, and Chamber of Commerce president of your community are.');
INSERT INTO badge_level_requirements VALUES(3411,470,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3412,471,'preschool',0,'Learn the six main My Little Pony: Friendship is Magic characters. Who is your favorite and why?');
INSERT INTO badge_level_requirements VALUES(3413,471,'preschool',1,'Watch at least 3 episodes. Discuss them with your family, friends, or group. What lessons did you learn?');
INSERT INTO badge_level_requirements VALUES(3414,471,'level1',2,'Watch at least 4 episodes.');
INSERT INTO badge_level_requirements VALUES(3415,471,'level1',3,'What is a cutie mark? Learn the cutie marks of the six main My Little Pony characters with the correct color and picture. What character trait does each represent and how are the six traits used in the elements of harmony? How are they different? Explain.');
INSERT INTO badge_level_requirements VALUES(3416,471,'level2',4,'Watch at least 5 episodes.');
INSERT INTO badge_level_requirements VALUES(3417,471,'level2',5,'Learn all about the previous generations My Little Pony shows and movies. Chose a previous generation to watch, and compare it to the current generation. When was the show/movie you watched originally made?');
INSERT INTO badge_level_requirements VALUES(3418,471,'level3',6,'Watch at least 6 episodes.');
INSERT INTO badge_level_requirements VALUES(3419,471,'level3',7,'Look up pictures of all generations of My Little Pony. Create a presentation or write an essay about each generation and how they’re different.');
INSERT INTO badge_level_requirements VALUES(3420,471,'level4',8,'Watch at least 7 episodes.');
INSERT INTO badge_level_requirements VALUES(3421,471,'level4',9,'My Little Pony was made for children, yet the newer television series has caught the attention of teens and young adults. In detail, describe why you think they are attracted to the new series, and why they weren’t as attracted to the original series.');
INSERT INTO badge_level_requirements VALUES(3422,471,'level5',10,'Watch at least 8 episodes.');
INSERT INTO badge_level_requirements VALUES(3423,471,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3424,473,'preschool',0,'Choose a creature and learn about its basic anatomy or traits.');
INSERT INTO badge_level_requirements VALUES(3425,473,'preschool',1,'Read or have read to you a fable, fairy tale, myth, legend, or story featuring your creature.');
INSERT INTO badge_level_requirements VALUES(3426,473,'level1',2,'Learn where this creature lived according to its stories. Locate the areas on a map or globe.');
INSERT INTO badge_level_requirements VALUES(3427,473,'level2',3,'Did your creature have any specific loves or weaknesses? For instance, vampires love blood, but hate garlic. Did they have any particular magical/non-magical strengths, such as the ability to turn into a bat?');
INSERT INTO badge_level_requirements VALUES(3428,473,'level3',4,'When did the original tales for your mythological appear? Is this creature ancient or a more modern myth?');
INSERT INTO badge_level_requirements VALUES(3429,473,'level3',5,'Was this mythological considered “evil” or “good”? Where there specific symbolism or themes that the creature stood for? Why do you think this is?');
INSERT INTO badge_level_requirements VALUES(3430,473,'level4',6,'Are there any modern retellings or other modern books that feature your creature? How did this compare to one of the original tales it came from? Was this true to the original creature, or did the author take liberties? Why do you believe they would have done this?');
INSERT INTO badge_level_requirements VALUES(3431,473,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3432,474,'preschool',0,'A myth is a story with a moral or explanation of why things happen.  Choose a myth and read it or watch it as a movie.');
INSERT INTO badge_level_requirements VALUES(3433,474,'level1',1,'The Greek Gods of Mount Olympus are the most well known characters of mythology.  Learn about at least three of the Olympians.  What were they the gods or goddesses of?  What were they best known for?  Read one of their stories.');
INSERT INTO badge_level_requirements VALUES(3434,474,'level2',2,'While Greek mythology is usually the most well known, many cultures have their own myths. Choose a country or location and learn more about the mythology specific to them.  Examples might include the Celts, Native Americans, or Japanese.');
INSERT INTO badge_level_requirements VALUES(3435,474,'level3',3,'Mythology includes a variety of mythical creatures.  Learn to identify at least six different creatures and learn more about one of them.  Examples might include the kelpie, the chimera, or the kirin.');
INSERT INTO badge_level_requirements VALUES(3436,474,'level4',4,'Write your own myth to explain how or why something happened in the natural world.  You may use existing gods and goddesses from mythology you have studies, or make up your own set of gods and goddesses.');
INSERT INTO badge_level_requirements VALUES(3437,474,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3438,475,'preschool',0,'Pick a culture’s mythology to explore (e.g., Greek, Egyptian, Norse, Hindu, Celtic, Chinese, etc.) and read, or have read to you, at least 3 stories from this mythology.');
INSERT INTO badge_level_requirements VALUES(3439,475,'preschool',1,'Learn about at least three major gods or goddesses from your chosen mythology.');
INSERT INTO badge_level_requirements VALUES(3440,475,'level1',2,'Identify at least three mythical creatures from your chosen culture’s mythology.');
INSERT INTO badge_level_requirements VALUES(3441,475,'level2',3,'Learn about at least three heroes from your chosen mythology and their adventures.');
INSERT INTO badge_level_requirements VALUES(3442,475,'level3',4,'Research symbols or sacred animals connected to the mythology');
INSERT INTO badge_level_requirements VALUES(3443,475,'level4',5,'Make a family tree of the gods and important figures in your chosen mythology.');
INSERT INTO badge_level_requirements VALUES(3444,475,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3447,477,'preschool',0,'Look at pictures of at least 10 different ways napkins can be folded.  Which is your favorite?');
INSERT INTO badge_level_requirements VALUES(3448,477,'preschool',1,'Practice folding a napkin into a basic triangle, rectangle, and square.');
INSERT INTO badge_level_requirements VALUES(3449,477,'level1',2,'Fold a napkin in half lengthwise and crosswise and explain why neat creases matter.  Explain how to use these creases to find the center point of the napkin.');
INSERT INTO badge_level_requirements VALUES(3450,477,'level2',3,'Learn the difference between paper and cloth napkins and the pros and cons of each for folding.');
INSERT INTO badge_level_requirements VALUES(3451,477,'level3',4,'Learn how to properly iron cloth napkins as well as how to use the iron to get neatly pressed folds.');
INSERT INTO badge_level_requirements VALUES(3452,477,'level4',5,'Learn the history of napkin folding art.');
INSERT INTO badge_level_requirements VALUES(3453,477,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3458,481,'preschool',0,'What is a natural disaster? Be able to identify at least three natural disasters from pictures.');
INSERT INTO badge_level_requirements VALUES(3459,481,'preschool',1,'Learn what natural disasters are common in your area. Talk to your parents and find out what you should do if one of these disasters were to happen. How can you remain safe?');
INSERT INTO badge_level_requirements VALUES(3460,481,'level1',2,'Learn what the natural disaster you are studying is and what causes it. Learn what to do to survive during the natural disaster you have chosen. Be careful of myths and make sure you get your information from a reputable source such as the National Oceanic and Atmospheric Administration (NOAA) or Federal Emergency Management Agency (FEMA).');
INSERT INTO badge_level_requirements VALUES(3461,481,'level1',3,'Create a Family Disaster Plan. Find out what types of natural disasters are most common in your community and know how to prepare for each.');
INSERT INTO badge_level_requirements VALUES(3462,481,'level2',4,'Find out where and when the worst of the natural disaster you are studying struck. Find it on a map. Find out where the most recent of the natural disaster you are studying struck. Find it on a map. Locate areas that are prone to your natural disasters and mark them on a map.');
INSERT INTO badge_level_requirements VALUES(3463,481,'level3',5,'Find out how the severity of your natural disaster is measured. For example, hurricanes are rated 1-5 using the Saffir-Simpson scale while earthquakes are rated on a Richtor scale.');
INSERT INTO badge_level_requirements VALUES(3464,481,'level4',6,'Read an account of or watch a documentary about the natural disaster you have chosen, such as Pompeii, the 2019-2020 Australian bushfires, or the 2011 Tōhoku earthquake and tsunami.');
INSERT INTO badge_level_requirements VALUES(3465,481,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3466,482,'preschool',0,'What is artificial food coloring made of? Share your findings with a friend or family member.');
INSERT INTO badge_level_requirements VALUES(3467,482,'preschool',1,'With an adult’s help, use three edible foods to make a natural food dye. Which did you like best?');
INSERT INTO badge_level_requirements VALUES(3468,482,'level1',2,'What food colorings are allowed in the USA and what are they found in?');
INSERT INTO badge_level_requirements VALUES(3469,482,'level2',3,'With a parent’s permission, use your natural dye to dye clothing. Does it work? How can you intensify the colors?');
INSERT INTO badge_level_requirements VALUES(3470,482,'level3',4,'Choose three different ingredients to produce the same color (i.e. beets, strawberries, cherries, etc) and compare color results.');
INSERT INTO badge_level_requirements VALUES(3471,482,'level4',5,'Do a blind taste test with natural dyes vs. artificial dyes. Can you taste a difference?');
INSERT INTO badge_level_requirements VALUES(3472,482,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3473,483,'preschool',0,'What is a natural wonder? Find three pictures of natural wonders and explain to someone why they are special.');
INSERT INTO badge_level_requirements VALUES(3474,483,'level1',1,'Learn about at least three different types of natural wonders.  Find out what the largest, tallest, or oldest example is for each of the natural wonders you learned about, and locate it on a map.');
INSERT INTO badge_level_requirements VALUES(3475,483,'level2',2,'Learn about at least four different types of natural wonders.');
INSERT INTO badge_level_requirements VALUES(3476,483,'level2',3,'How can we be respectful and safe when visiting a natural wonder? Don’t forget to follow Leave No Trace principles.');
INSERT INTO badge_level_requirements VALUES(3477,483,'level3',4,'Learn about at least six different types of natural wonders.');
INSERT INTO badge_level_requirements VALUES(3478,483,'level3',5,'Choose a specific natural wonder site. What is the history of that specific natural wonder, such as Old Faithful in Yellowstone National Park?');
INSERT INTO badge_level_requirements VALUES(3479,483,'level4',6,'Learn about at least seven different types of natural wonders.');
INSERT INTO badge_level_requirements VALUES(3480,483,'level4',7,'What efforts are being made to protect natural wonders? What control do world-wide, federal, state, and local governments and organizations have? What can you do to help?');
INSERT INTO badge_level_requirements VALUES(3481,483,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3482,484,'preschool',0,'Understand what the Navy is and what their role is in the military.');
INSERT INTO badge_level_requirements VALUES(3483,484,'level1',1,'Learn the history of the Navy and how they began as well as their mission today.');
INSERT INTO badge_level_requirements VALUES(3484,484,'level2',2,'Discuss the contributions the Navy has made to our country or create a presentation about these contributions.');
INSERT INTO badge_level_requirements VALUES(3485,484,'level3',3,'Who are most aircraft carriers named after today? What places are submarines named after? Why do you think the Navy chose these people and places to name their ships? How long does a typical Navy ship last before being decommissioned?');
INSERT INTO badge_level_requirements VALUES(3486,484,'level4',4,'Visit a Navy recruiter. Find out how to enlist in the Navy or be commissioned as an Navy officer. What jobs are available? What training is provided? How long must you enlist for? What are the benefits of joining the military? What are the drawbacks? How does your education and background affect your salary in the Navy?');
INSERT INTO badge_level_requirements VALUES(3487,484,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3490,486,'preschool',0,'Know what the brain is and what it does');
INSERT INTO badge_level_requirements VALUES(3491,486,'preschool',1,'Look at photos of brains, or if possible, a real brain.');
INSERT INTO badge_level_requirements VALUES(3492,486,'level1',2,'Learn five tips for keeping your brain healthy, such as proper diet, exercise, sleep, and mindfulness.');
INSERT INTO badge_level_requirements VALUES(3493,486,'level2',3,'Learn the names and functions of five main parts of the brain: cerebrum, cerebellum, brainstem, hippocampus, and amygdala.  Create a diagram or 3D model of a brain.');
INSERT INTO badge_level_requirements VALUES(3494,486,'level3',4,'Understand what a neuron is and how it works.  Draw a diagram or a create a 3D model of a typical neuron and all of its parts.');
INSERT INTO badge_level_requirements VALUES(3495,486,'level4',5,'Research three neurotransmitters (e.g., dopamine, serotonin, acetylcholine) and explain their roles.');
INSERT INTO badge_level_requirements VALUES(3496,486,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3497,487,'preschool',0,'Understand and be able to explain the rules of safe NERF gun handling.  Why should you always wear safety glasses when playing with NERF guns?');
INSERT INTO badge_level_requirements VALUES(3498,487,'preschool',1,'Following all safety rule shoot a NERF gun.  Set up a target and try to hit it.');
INSERT INTO badge_level_requirements VALUES(3499,487,'level1',2,'Explain the parts of your chosen NERF gun.  How do you cock the gun? Where does the bullet leave the gun?  How do you prime your NERF gun for firing? How does a NERF gun work?');
INSERT INTO badge_level_requirements VALUES(3500,487,'level2',3,'Practice the 4 standard rifle firing positions with a NERF rifle ( prone, sitting, standing, kneeling).  Do certain guns lend themselves to certain firing positions?');
INSERT INTO badge_level_requirements VALUES(3501,487,'level3',4,'Research the different types of NERF guns available.  What makes each unique?  Which is best for concealment?  For rapid fire?  For ease of use?  What are the price differences?  What type of bullets do each use?');
INSERT INTO badge_level_requirements VALUES(3502,487,'level4',5,'Learn about NERF and NERF guns.  When was the first NERF gun made? How many darts per minute can the fastest NERF gun shoot? What was the precursor for the NERF gun?  When was the first blaster made? How many NERF darts are manufactured annually? What is NERF an acronym for?');
INSERT INTO badge_level_requirements VALUES(3503,487,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3504,488,'preschool',0,'.  Learn what a newspaper is. Find one and look at it. Which is your favorite section?');
INSERT INTO badge_level_requirements VALUES(3505,488,'level1',1,'.  Do Preschool requirement 1.  Look at a newspaper and find the sports page(s), classified ads page (or half-page) and real estate page(s).  Why do you think each one of these is included in the newspaper?');
INSERT INTO badge_level_requirements VALUES(3506,488,'level1',2,'.  Visit a newspaper office and talk with someone who works there.  Ask them how they got into the business and what they like about it. If you do not have a local newspaper to visit, go online (with your parent’s permission) and look at a newspaper’s website.');
INSERT INTO badge_level_requirements VALUES(3507,488,'level2',3,'.  Do Level 1 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(3508,488,'level2',4,'.  Make a timeline of the history of newspapers.  Have at least 10 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3509,488,'level3',5,'.  Do Level 2 requirements 1 & 2. Have at least 15 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3510,488,'level3',6,'.  Read a biography of a famous person connected with the newspaper business, such as Benjamin Franklin.');
INSERT INTO badge_level_requirements VALUES(3511,488,'level4',7,'.  Do Level 3 requirements 1 & 2. Have at least 20 items on your timeline. If you earned this badge at an earlier level, read about a new person for Level 3 requirement 2.');
INSERT INTO badge_level_requirements VALUES(3512,488,'level4',8,'.  Learn how to write a newspaper article, and write one about a real event or an imaginary one.');
INSERT INTO badge_level_requirements VALUES(3513,488,'level5',9,'.  Do Level 4 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(3514,488,'level5',10,'.  Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3515,489,'preschool',0,'What does Norse mean?  Where did they live and how long ago?');
INSERT INTO badge_level_requirements VALUES(3516,489,'preschool',1,'Look at pictures of Norse people and how they dressed. What did men, women and children wear?');
INSERT INTO badge_level_requirements VALUES(3517,489,'level1',2,'. Do preschool requirements 1 & 2');
INSERT INTO badge_level_requirements VALUES(3518,489,'level1',3,'Describe what life was like in a traditional Norse village.  What didpeople do? Where did they live? What games did they play?  What foods did they eat?');
INSERT INTO badge_level_requirements VALUES(3519,489,'level2',4,'Create a timeline of Norse history.  Include at least 10 events. The timeline must include pictures and a short description of the event.');
INSERT INTO badge_level_requirements VALUES(3520,489,'level3',5,'Create a world map that shows where Norse kingdoms were. What are the modern day names now for these areas?');
INSERT INTO badge_level_requirements VALUES(3521,489,'level4',6,'Learn about at least 10 Norse gods.  Share what you learned either bycreating a Norse god family tree, an information booklet, or a slideshow.');
INSERT INTO badge_level_requirements VALUES(3522,489,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3525,491,'preschool',0,'Read (or have read to you) the story The Nutcracker.');
INSERT INTO badge_level_requirements VALUES(3526,491,'level1',1,'Learn five facts about the history of the Nutcracker Ballet (ex. Who wrote the original story? Who composed the music? Where was it first performed?).');
INSERT INTO badge_level_requirements VALUES(3527,491,'level2',2,'Your list should include ten facts about the history of the Nutcracker Ballet.');
INSERT INTO badge_level_requirements VALUES(3528,491,'level2',3,'Learn the history of Nutcrackers. Where do they come from? What do they symbolize?');
INSERT INTO badge_level_requirements VALUES(3529,491,'level3',4,'Learn what a celesta is and what its significance is to the Nutcracker Ballet.');
INSERT INTO badge_level_requirements VALUES(3530,491,'level4',5,'Watch the Moscow Ballets production of the Great Russian Nutcracker. How is this different than other productions of the Nutcracker Ballet?');
INSERT INTO badge_level_requirements VALUES(3531,491,'level5',6,'Do Level 4requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(3532,491,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason, you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirement:');
INSERT INTO badge_level_requirements VALUES(3533,492,'preschool',0,'What is nutrition? Why is it important?');
INSERT INTO badge_level_requirements VALUES(3534,492,'preschool',1,'What is the difference between a healthy and unhealthy food/meal? Be able to give examples of healthy food versus unhealthy food.');
INSERT INTO badge_level_requirements VALUES(3535,492,'level1',2,'What food groups should you eat each day and how much? What is a “serving”?');
INSERT INTO badge_level_requirements VALUES(3536,492,'level2',3,'Learn how to read a nutritional label.  What are protein, fat, carbohydrates, and calories? What do they do for our body?');
INSERT INTO badge_level_requirements VALUES(3537,492,'level3',4,'Know what fibers and the basic vitamins are. Why are these important?');
INSERT INTO badge_level_requirements VALUES(3538,492,'level3',5,'What are “processed” and “refined” foods? What are the advantages/disadvantages of each? Why should they be avoided?');
INSERT INTO badge_level_requirements VALUES(3539,492,'level4',6,'Plan one week’s worth of nutritious meals for your family (breakfast, lunch, and dinner).  Make sure to provide a balance of calories, fat, fiber, nutrients, etc.  Attempt to make all foods from scratch with no processed ingredients.  Make at least 3 of the meals.');
INSERT INTO badge_level_requirements VALUES(3540,492,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3541,493,'preschool',0,'What is nut? Be able to list three types of nuts.');
INSERT INTO badge_level_requirements VALUES(3542,493,'preschool',1,'Try two different kinds of nuts. How are they different? How are they the same?');
INSERT INTO badge_level_requirements VALUES(3543,493,'level1',2,'Identify three different kinds of nuts by a leaf, an unshelled nut, and the nut meat.');
INSERT INTO badge_level_requirements VALUES(3544,493,'level1',3,'Learn to crack and shell at least 2 different types of nuts.  Use the nuts in cooking or give them to someone as a gift.');
INSERT INTO badge_level_requirements VALUES(3545,493,'level2',4,'Identify 4 kinds of nuts.');
INSERT INTO badge_level_requirements VALUES(3546,493,'level2',5,'Make a trail mix with at least 3 different types of nuts along with other nutritious items such seeds or dried fruit.');
INSERT INTO badge_level_requirements VALUES(3547,493,'level3',6,'Identify 5 different nuts. Be able to point out the general shape of each type of tree.');
INSERT INTO badge_level_requirements VALUES(3548,493,'level3',7,'Get a blank world map.  Label the three highest-producing countries for the nuts you studied in requirement #1. Find out which countries export the most of your chosen nuts.');
INSERT INTO badge_level_requirements VALUES(3549,493,'level4',8,'Identify six kinds of nuts.  Where are nut trees commonly grown?');
INSERT INTO badge_level_requirements VALUES(3550,493,'level4',9,'Tour a nut tree farm or processing plant (a virtual tour is fine too with parent’s permission), or read a book on nut processing.');
INSERT INTO badge_level_requirements VALUES(3551,493,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3552,494,'preschool',0,'What is an obstacle course? How can you be a good sport when going through an obstacle course?');
INSERT INTO badge_level_requirements VALUES(3553,494,'preschool',1,'Know how to properly crawl, hop, climb, and run. What safety rules should be followed when doing an obstacle course?');
INSERT INTO badge_level_requirements VALUES(3554,494,'level1',2,'Make a list of at least 5 different items that could be used for an obstacle course, such as jump ropes, hula hoops, and cones.');
INSERT INTO badge_level_requirements VALUES(3555,494,'level2',3,'Your list should have at least 7 items.');
INSERT INTO badge_level_requirements VALUES(3556,494,'level2',4,'There are many TV shows about obstacle courses. With a parent’s permission, watch at least three episodes of an obstacle course-focused show.');
INSERT INTO badge_level_requirements VALUES(3557,494,'level3',5,'Your list should have at least 9 items.');
INSERT INTO badge_level_requirements VALUES(3558,494,'level3',6,'Learn about military obstacle courses and how they were designed. How are they different than a civilian obstacle course? Are they more difficult?');
INSERT INTO badge_level_requirements VALUES(3559,494,'level4',7,'Your list should have at least 11 items.');
INSERT INTO badge_level_requirements VALUES(3560,494,'level4',8,'Design your own obstacle course. It should include at least 5 items from the list you made. Test it out and then invite your friends, family or group to try it out as well.');
INSERT INTO badge_level_requirements VALUES(3561,494,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3562,495,'preschool',0,'Learn what an occupation is. What kind of occupations do you know about? List several.');
INSERT INTO badge_level_requirements VALUES(3563,495,'preschool',1,'Learn about where people in your chosen occupation work. What kind of environment do they work in?');
INSERT INTO badge_level_requirements VALUES(3564,495,'level1',2,'Read a book about your chosen occupation. What did you learn? List five new things you learned about.');
INSERT INTO badge_level_requirements VALUES(3565,495,'level2',3,'Read two books.');
INSERT INTO badge_level_requirements VALUES(3566,495,'level2',4,'Visit places of work for your occupation. This can be done in person (preferably), or online (with a parent’s permission). Visit at least two or three different places and compare them. Which one did you like better and why?');
INSERT INTO badge_level_requirements VALUES(3567,495,'level3',5,'Create a presentation about your chosen occupation then share it with your family, friends, or group. It must include: Different places that individuals in this occupation can work What kind of degrees, education or certifications are required What potential income levels there are Advantages/disadvantages');
INSERT INTO badge_level_requirements VALUES(3568,495,'level4',6,'Using the information you learned about degree or certification requirements you need for this occupation, research which schools offer these programs. What requirements do you need to get into these schools? Think about skills you have, or what classes or preparations you’ve already made to be able to qualify for this school. How much would it cost to attend one of these schools or get a degree in your chosen career field? Look over an application from one of these schools.');
INSERT INTO badge_level_requirements VALUES(3569,495,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3570,496,'preschool',0,'Learn about ocean water. What makes it different from fresh water? What type of animals live in it?');
INSERT INTO badge_level_requirements VALUES(3571,496,'preschool',1,'Learn about ocean safety.  Learn about the Leave No Trace rules and figure out ways to apply them to visiting an ocean or beach.');
INSERT INTO badge_level_requirements VALUES(3572,496,'level1',2,'Learn all four major oceans and be able to find them on a map.');
INSERT INTO badge_level_requirements VALUES(3573,496,'level2',3,'Learn about ocean habitats.  Know what each of the following are and at least one animal that lives in each: Beaches Tidal pools Coral reefs Estuaries Hydrothermal vents Kelp forests Sea grass beds Deep sea');
INSERT INTO badge_level_requirements VALUES(3574,496,'level3',4,'Learn about currents, tides, and waves.  What causes them?  How can they be predicted? What do the green, yellow, and red colored flags on the beach mean?  What should you do if you are caught in a rip-tide?');
INSERT INTO badge_level_requirements VALUES(3575,496,'level4',5,'Plan a trip to the ocean. Include the area you would like to visit, transportation to and from, hotel accommodations, tours and sites to visit, restaurant, cost, etc. Make an itinerary and present it to your family, friends, or group.');
INSERT INTO badge_level_requirements VALUES(3576,496,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3577,497,'level1',0,'and 2.');
INSERT INTO badge_level_requirements VALUES(3578,497,'level1',1,'Learn the benefits the ocean provides to us. Why is it important we keep our oceans clean and healthy?');
INSERT INTO badge_level_requirements VALUES(3579,497,'level2',2,'Learn about garbage in the ocean such as the Great Pacific Garbage Patch.  Make a list of at least 10 ways you can reduce the amount of trash you throw away.');
INSERT INTO badge_level_requirements VALUES(3580,497,'level3',3,'Learn about ocean acidification and its impacts on marine life.');
INSERT INTO badge_level_requirements VALUES(3581,497,'level4',4,'Learn about ocean governance and the role of international organizations in protecting the ocean.');
INSERT INTO badge_level_requirements VALUES(3582,497,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3583,498,'preschool',0,'Play office. Set up a pretend office and pretend to answer phones and write memos.');
INSERT INTO badge_level_requirements VALUES(3584,498,'preschool',1,'Learn about proper office attire. Put together an appropriate outfit to wear to the office.');
INSERT INTO badge_level_requirements VALUES(3585,498,'level1',2,'Learn phone etiquette. Role play or do the actual tasks of answering the phone, learn how to tactfully say that someone is not available, and learn to take careful messages.');
INSERT INTO badge_level_requirements VALUES(3586,498,'level2',3,'. Do Level 1 requirements 1 & 2. Learn how to place someone on hold and answer call waiting or another phone line. If you have a multi-function phone available, learn how to forward a call. _____*2. Learn various styles and methods of filing, organizing, and sorting. What things are important to keep in a file cabinet? How should they be labeled?');
INSERT INTO badge_level_requirements VALUES(3587,498,'level3',4,'Learn how to work a copy machine. Do a copy machine project including collating and stapling.');
INSERT INTO badge_level_requirements VALUES(3588,498,'level4',5,'Know how to write a professional email. How should you begin and end a professional email? What does a professional subject line look like? What are ways to check your spelling and grammar?');
INSERT INTO badge_level_requirements VALUES(3589,498,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3590,499,'preschool',0,'Understand what orienteering is.');
INSERT INTO badge_level_requirements VALUES(3591,499,'preschool',1,'While holding a compass, be able to tell someone which way is north, south, east and west.');
INSERT INTO badge_level_requirements VALUES(3592,499,'level1',2,'In the field, show how to take a compass bearing and follow it. Explain how a compass works. Know the difference between true north and magnetic north.');
INSERT INTO badge_level_requirements VALUES(3593,499,'level2',3,'Show how to orient a map using a compass.');
INSERT INTO badge_level_requirements VALUES(3594,499,'level3',4,'Participate in at least one orienteering event, or create your own. Be able to show the route you took, how to read the control description sheet, and how you might be able to improve your time between control points.');
INSERT INTO badge_level_requirements VALUES(3595,499,'level4',5,'Set up a cross country orienteering course of at least 500 yards with at least 5 control markers. Prepare the master map and control sheet and be able to explain them to participants.');
INSERT INTO badge_level_requirements VALUES(3596,499,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3597,500,'preschool',0,'What are the Olympics? Find out a few of the sports that are played at the Olympics.  What is your favorite Olympic sport to watch?');
INSERT INTO badge_level_requirements VALUES(3598,500,'preschool',1,'Find out if this year is an Olympic year. If so, when do/did the Olympics start? In what country is/was it located? Find it on a map or globe. If this is not an Olympic year, when is the next Olympic year?  Where will the games be held?  When was the last Olympic year?  Where were those games held?');
INSERT INTO badge_level_requirements VALUES(3599,500,'level1',2,'Learn about the first Olympics, both the ancient and the modern games.');
INSERT INTO badge_level_requirements VALUES(3600,500,'level1',3,'What are the common symbols of the Olympics? What do they symbolize?');
INSERT INTO badge_level_requirements VALUES(3601,500,'level2',4,'Pick an athlete or team and follow their progress throughout the Olympics.');
INSERT INTO badge_level_requirements VALUES(3602,500,'level3',5,'Pick an Olympic sport and learn about its history.');
INSERT INTO badge_level_requirements VALUES(3603,500,'level4',6,'Find out how the Olympic committee decides where the Olympics are held.');
INSERT INTO badge_level_requirements VALUES(3604,500,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3605,501,'preschool',0,'Learn what the term “organic” means.');
INSERT INTO badge_level_requirements VALUES(3606,501,'preschool',1,'Have a taste test with at least 3 different items. Compare both the organic and non-organic version of the same food. Which tastes better? Is there a difference?');
INSERT INTO badge_level_requirements VALUES(3607,501,'level1',2,'Why are organic foods and products considered healthier than non-organic foods and products?');
INSERT INTO badge_level_requirements VALUES(3608,501,'level2',3,'What is sustainable agriculture and how does it relate to organic foods?');
INSERT INTO badge_level_requirements VALUES(3609,501,'level3',4,'What are genetically modified foods organisms (GMO’s)? What are the similarities/differences between GMO and organic food? How does GMO food affect consumers, farmers, and the environment?');
INSERT INTO badge_level_requirements VALUES(3610,501,'level4',5,'Learn about the environmental impact of organic products versus those conventionally grown.');
INSERT INTO badge_level_requirements VALUES(3611,501,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3612,502,'preschool',0,'Learn what origami means.');
INSERT INTO badge_level_requirements VALUES(3613,502,'preschool',1,'Learn to fold a simple origami shape.');
INSERT INTO badge_level_requirements VALUES(3614,502,'level1',2,'Look at several different origami patterns either in a book or online (with the permission of a parent).  What kinds of things can you make with origami?  Make a list.');
INSERT INTO badge_level_requirements VALUES(3615,502,'level2',3,'Learn about the history of origami and where it came from.');
INSERT INTO badge_level_requirements VALUES(3616,502,'level3',4,'Learn about a famous origami artist such as Akria Yoshizawa, Ligia Montoya, or Tomoko Fuse.');
INSERT INTO badge_level_requirements VALUES(3617,502,'level4',5,'Create an origami fold of your own and teach someone else how to do it.');
INSERT INTO badge_level_requirements VALUES(3618,502,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3619,503,'preschool',0,'Learn to recite the Pledge of Allegiance.  Understand how you should stand to show respect for the flag.');
INSERT INTO badge_level_requirements VALUES(3620,503,'preschool',1,'Learn the symbols for the stars, stripes, and colors for the American flag.');
INSERT INTO badge_level_requirements VALUES(3621,503,'level1',2,'What does each sentence of the Pledge of Allegiance mean?');
INSERT INTO badge_level_requirements VALUES(3622,503,'level1',3,'Find out the history of the American flag. Our flag has changed several times over our country’s history. Pick your favorite flag from our past and draw, paint, or make a cut-paper picture of it.  Mount it on a piece of card stock and write underneath the year(s) that it was flown.');
INSERT INTO badge_level_requirements VALUES(3623,503,'level2',4,'Find out the history of our current flag. How long has it been in use?');
INSERT INTO badge_level_requirements VALUES(3624,503,'level2',5,'Learn the Star Spangled Banner. Who wrote it? Why? When? What does it mean? How many verses are there? What did our flag look like at this time?');
INSERT INTO badge_level_requirements VALUES(3625,503,'level3',6,'Learn how to properly fold the flag and demonstrate it for your family, friends, or group.');
INSERT INTO badge_level_requirements VALUES(3626,503,'level3',7,'Learn the rules for proper display and use of the United States flag according to the Federal Flag Code approved by Congress (Public Law 829).');
INSERT INTO badge_level_requirements VALUES(3627,503,'level4',8,'If a new state were added tomorrow, on what date would the new star be officially added to our flag?');
INSERT INTO badge_level_requirements VALUES(3628,503,'level4',9,'Make a diagram of the United States Flag, labeling all parts. Include and be able to define the “hoist”, “peak”, “fly”, staff”, halyard”, and “union”. Be sure to show the correct number of stars and stripes, as well as the order of the stripes.');
INSERT INTO badge_level_requirements VALUES(3629,503,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3630,504,'preschool',0,'Help plan, prepare, and serve an outdoor meal. Help do at least one of the following: plan the menu, make shopping and equipment lists, shop and pack, take care of food at the site, prepare and serve food, or clean up.');
INSERT INTO badge_level_requirements VALUES(3631,504,'preschool',1,'Earn the Fire Safety badge at your level and learn the safety rules for outdoor cooking, including: When roasting marshmallows, or other items on a stick or skewer, always move slowly.  Never put the food directly in the flames or it will catch fire.  Cook it over the coals.  If your food catches fire, bring it up slowly and blow it out or have an adult do it.  Never try to fling off burning food as it may hit someone and burn them.  If you cannot blow out the flame, have an adult help you scrape the food into the fire using an extra stick or skewer. When cooking with foil packets, steam can build up inside the packet.  Make sure an adult removes the packet from the grill (carefully so that the packet does not break and spill hot liquid or food on someone) using tongs or oven mitts.  Poke holes in the foil with a fork to allow steam to escape and let stand for 5 minutes.  Open the packet slowly, keeping your hands and face away from the opening to avoid any excess steam that escapes. When taking the lid off a hot pot, keep your hands and face away to ensure you are not burned by escaping steam. Preschoolers should not use sharp knives.  Older members should follow knife safety and make sure that their knives are always sharp and that they always cut away from themselves.  Never use sharp knives without permission from an adult. Always have a first aid in on hand. Earning the First Aid badge is always a good idea. Make sure to keep hot food hot, and cold food cold to avoid food poisoning. Wash your hands before preparing a meal and make sure your food preparation area is clean. Keep cold foods cold using a cooler and ice.  Keep it cold with fresh ice when necessary. Never keep food in your tent, car, or backpacks where wildlife may be able to get to it. Store food either in a designated food closet, or hang between two trees at least 10’ off the ground. Precook all meats.  Coolers do not keep things at a constant temperature and raw meats can spoil quickly.');
INSERT INTO badge_level_requirements VALUES(3632,504,'level1',2,'Cook at least two meal outdoors.');
INSERT INTO badge_level_requirements VALUES(3633,504,'level1',3,'Demonstrate proper clean up after outdoor cooking including: Put out a fire and remove the ashes, or extinguish the camp stove. Wash, sanitize, and store the dishes. Dispose of the trash and dish water without endangering or damaging the environment');
INSERT INTO badge_level_requirements VALUES(3634,504,'level2',4,'Cook at least three meals outdoors.');
INSERT INTO badge_level_requirements VALUES(3635,504,'level2',5,'Make at least two of the following outdoors: Foil packet meals One pot meals Dessert MRE (meals ready to eat) No cook meal');
INSERT INTO badge_level_requirements VALUES(3636,504,'level3',6,'Cook at least four meals outdoors.');
INSERT INTO badge_level_requirements VALUES(3637,504,'level3',7,'Learn about drinking water safety and purification when participating in outdoor activities.  Purify some water for drinking using one of the following methods: Portable water purification filters:  Pump water through the system and the filter removes all protozoa and bacteria. Chemical Tablets:  Tablets are the easiest and quickest way to purify your water, but they have a limited shelf life, so make sure they are still good when you bring them.  Some protozoa may not be killed by chemical tablets, and they can take longer to work if the water is especially cold or dirty.  Chemical tablets can also affect the taste of the water. Boiling Water:  Bring water to a rolling boil for at least 10 minutes and then let cool before drinking.');
INSERT INTO badge_level_requirements VALUES(3638,504,'level4',8,'Cook at least five meals outdoors.');
INSERT INTO badge_level_requirements VALUES(3639,504,'level4',9,'Demonstrate  how to safely use at least two different cooking methods from the list below: Propane stove Butane stove Gas stove Charcoal Canned Heat Solar energy Campfire');
INSERT INTO badge_level_requirements VALUES(3640,504,'level5',10,'Cook at least six meals outdoors.');
INSERT INTO badge_level_requirements VALUES(3641,504,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3646,507,'preschool',0,'What is painting? Look at different types of paintings such as landscapes, still life, portraits, self-portraits, or abstract.');
INSERT INTO badge_level_requirements VALUES(3647,507,'preschool',1,'Make a finger painting.');
INSERT INTO badge_level_requirements VALUES(3648,507,'level1',2,'Make a painting using items other than a paintbrush. These could include items like cotton balls, Q-tips, sponges, etc. Be creative!');
INSERT INTO badge_level_requirements VALUES(3649,507,'level2',3,'Learn about the different types of paints, such as acrylic, watercolor, oil, etc.');
INSERT INTO badge_level_requirements VALUES(3650,507,'level3',4,'Research different ways to make paint. Make your own paint and learn about how paint was created in the past.');
INSERT INTO badge_level_requirements VALUES(3651,507,'level4',5,'Do Level 3 requirements number 1 & 2.');
INSERT INTO badge_level_requirements VALUES(3652,507,'level4',6,'Make a timeline about famous paintings/painters (i.e. cave drawings, Mona Lisa, etc.). Make sure your timeline includes at least 15 events/dates.');
INSERT INTO badge_level_requirements VALUES(3653,507,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3654,508,'preschool',0,'Learn to identify at least three different prehistoric creatures.');
INSERT INTO badge_level_requirements VALUES(3655,508,'preschool',1,'Learn about what a fossil is.');
INSERT INTO badge_level_requirements VALUES(3656,508,'level1',2,'Be able to answer the following questions: What does the word “Dinosaur” mean? What is a paleontologist? Where can you find fossils?');
INSERT INTO badge_level_requirements VALUES(3657,508,'level2',3,'Learn about the Triassic, Jurassic and the Cretaceous periods and place them on a timeline. Learn about at least one living organism from each period.');
INSERT INTO badge_level_requirements VALUES(3658,508,'level3',4,'Explain and identify the following types of fossils: Mold Fossils (impression fossils) Cast Fossils Trace Fossils (ichnofossils) True Form Fossils Find examples of each either through books, the internet (with parent’s permission), or actual fossils at an exhibit.');
INSERT INTO badge_level_requirements VALUES(3659,508,'level4',5,'Be able to explain what fossil fuels are. How are coal, oil, and natural gas created? How do each of these fossil fuels impact our environment?');
INSERT INTO badge_level_requirements VALUES(3660,508,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3661,509,'preschool',0,'Know what a pancake is and how it differs from other food items like bread or waffles.');
INSERT INTO badge_level_requirements VALUES(3662,509,'preschool',1,'Try a pancake with three different toppings such as butter, syrup, fruit, jam, or whipped cream.  Which did you like best?');
INSERT INTO badge_level_requirements VALUES(3663,509,'level1',2,'Make a batch of basic pancakes with the help of an adult or older sibling.  Learn and obey safety precautions.');
INSERT INTO badge_level_requirements VALUES(3664,509,'level2',3,'Research the history of pancakes. How big was the largest pancake ever created? When is National Pancake Day?');
INSERT INTO badge_level_requirements VALUES(3665,509,'level3',4,'Identify and learn about at least three different types of pancakes from around the world (e.g., crepes, blinis, dosas).  Make a simple version of one of these pancakes.  Discuss how they differ from traditional American Pancakes.');
INSERT INTO badge_level_requirements VALUES(3666,509,'level4',5,'Test different cooking temperatures and observe how they affect pancake texture.');
INSERT INTO badge_level_requirements VALUES(3667,509,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3672,513,'preschool',0,'Watch a parade in person, or on T.V. with your family. Learn which group is always first in every parade, and what is the proper way to watch this group pass.');
INSERT INTO badge_level_requirements VALUES(3673,513,'preschool',1,'Participate in a parade. You may walk, ride in a car, on a float, ride a bike, or even be pulled in a wagon or pushed in a stroller.');
INSERT INTO badge_level_requirements VALUES(3674,513,'level1',2,'Know why your town is having the parade you are participating in.  What is its purpose? How does it benefit the community?  What other parades does your town host throughout the year?');
INSERT INTO badge_level_requirements VALUES(3675,513,'level2',3,'Find out about three parades near you. When are they, what are the requirements to enter, do they have a theme, who is the contact?');
INSERT INTO badge_level_requirements VALUES(3676,513,'level3',4,'Many parades have contests for categories such best float, best large group, best small group, best marching band, etc.  Find out what categories your parade is divided into and how each group is scored.');
INSERT INTO badge_level_requirements VALUES(3677,513,'level4',5,'Design and build a themed float for a parade or decorate a vehicle according to the parade theme.  Know all the rules and regulations that your parade requires to ensure a safe float');
INSERT INTO badge_level_requirements VALUES(3678,513,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3681,515,'preschool',0,'What is patchwork?  Look at real patchwork or pictures of patchwork items.  How is it the same as quilting and how is it different?  What can be made from patchwork?');
INSERT INTO badge_level_requirements VALUES(3682,515,'preschool',1,'Make a patchwork picture.  Shapes that fit together without gaps between them are said to “tessellate”.  Which shapes tessellate easily? (Squares, rectangles, hexagons, triangles etc).  These picture patterns may be made from colored card, wooden shapes or drawn on paper');
INSERT INTO badge_level_requirements VALUES(3683,515,'level1',2,'Identify the basic tools used in patchwork. (Templates, scissors, thread, needles, thimble, pins, paper, squared paper). Learn how to make patchwork templates and use them to sew a simple patchwork project such as a small mat or a lavender bag.');
INSERT INTO badge_level_requirements VALUES(3684,515,'level2',3,'Which fabrics are most suited to patchwork?  Why should you not mix fabrics of different weights together in a design?');
INSERT INTO badge_level_requirements VALUES(3685,515,'level3',4,'Learn about the history of patchwork.  When did it become a recreational art form rather than a home-making skill?');
INSERT INTO badge_level_requirements VALUES(3686,515,'level4',5,'Learn the names of the 14 basic different shapes used in patchwork (hexagon, rectangle, square, diamond, long diamond, pentagon, triangle, irregular pentagon, octagon, clamshell, trapezium, rhomboid, church window, elongated hexagon/coffin).  How are these used in combination?  Look at pictures of patchwork items that use some of these combinations.');
INSERT INTO badge_level_requirements VALUES(3687,515,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3692,518,'preschool',0,'Learn about what a pattern is and how it is used to create clothing and accessories.');
INSERT INTO badge_level_requirements VALUES(3693,518,'preschool',1,'Learn how to trace using a stencil and ruler, and learn how to use a soft measuring tape.');
INSERT INTO badge_level_requirements VALUES(3694,518,'level1',2,'Make a simple pattern for a vest.  This can be for yourself, a doll, a puppet, or even a pet. Understand what a seam allowance is.  How do you allow for one when making your pattern?');
INSERT INTO badge_level_requirements VALUES(3695,518,'level2',3,'Take proper body measurements for someone that includes each of  the following: Shoulders: Measure in a straight line from the outer edge from one shoulder to the other. Bust: Measure around the fullest part of your chest, wrapping the measuring tape around your back, under your arms, and forward to the fullest part of your bust. Natural Waist: Measure around the narrowest part of your torso.  Make sure you are relaxed and not sucking in your breath or slouching. Hips: With you feet together, measure around the widest part of your hips (usually the area where your hip bones are located). Rise:  Starting in front at your natural waist, measure down between your legs and back up to your natural waist on the other side Inseam:  Measure from your crotch to the inside of your ankle. Arms:  Measure from the outside of your shoulder to your wrist.');
INSERT INTO badge_level_requirements VALUES(3696,518,'level3',4,'Make a pattern for a skirt or pair of pants that you can wear.');
INSERT INTO badge_level_requirements VALUES(3697,518,'level4',5,'Make a pattern for a shirt or dress that you can wear.');
INSERT INTO badge_level_requirements VALUES(3698,518,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3703,521,'preschool',0,'Sample and identify at least 2 different types of pears.');
INSERT INTO badge_level_requirements VALUES(3704,521,'preschool',1,'Learn the life cycle of an pear (seed, seedling, tree, flower, fruit, seed….)');
INSERT INTO badge_level_requirements VALUES(3705,521,'level1',2,'Sample and identify at least 3 different types of pear.');
INSERT INTO badge_level_requirements VALUES(3706,521,'level1',3,'Learn how to clean your produce properly. Tell what the difference is between organic and non-organic pears.');
INSERT INTO badge_level_requirements VALUES(3707,521,'level2',4,'Sample and identify at least 4 different types of pears.');
INSERT INTO badge_level_requirements VALUES(3708,521,'level2',5,'Find out where apples are typically grown and in what season. Locate major pear growing regions on a map. Do they specialize in a particular type of pear, or all pears in general?');
INSERT INTO badge_level_requirements VALUES(3709,521,'level3',6,'Sample and identify at least 5 different types of pears.');
INSERT INTO badge_level_requirements VALUES(3710,521,'level3',7,'Find out what types of vitamins and minerals are in pears. How many grams of fiber does a typical pear have? What health benefits do these provide your body?');
INSERT INTO badge_level_requirements VALUES(3711,521,'level4',8,'Sample and identify at least 6 different types of pears.');
INSERT INTO badge_level_requirements VALUES(3712,521,'level4',9,'Make at least 3 recipes using pears. If you choose to use optional requirements that involve recipes, these must be done in addition to the three mentioned in this requirement.');
INSERT INTO badge_level_requirements VALUES(3713,521,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3716,523,'preschool',0,'What is a performance? Find pictures of people performing in three different ways (music, drama, speech, etc.). Attend one performance.');
INSERT INTO badge_level_requirements VALUES(3717,523,'preschool',1,'Perform something for your family. This can be a musical performance, some form of speech, a puppet show, etc.');
INSERT INTO badge_level_requirements VALUES(3718,523,'level1',2,'Complete one performance.');
INSERT INTO badge_level_requirements VALUES(3719,523,'level1',3,'How can performing for an audience help you learn character qualities such as graciousness, teamwork, confidence, etc.? Choose a character quality you would like to improve. Ask your parent(s) and teacher or coach for ways you can practice the character quality you’ve chosen.');
INSERT INTO badge_level_requirements VALUES(3720,523,'level2',4,'Complete two performances.');
INSERT INTO badge_level_requirements VALUES(3721,523,'level2',5,'What is the objective of your performing this art? Is it for diversion/entertainment, inspiration/encouragement, or motivation/education? After you decide why you perform your art, try to think of a way you can accomplish your goal better. How can you continue to improve your performance based off of this goal?');
INSERT INTO badge_level_requirements VALUES(3722,523,'level3',6,'Complete three performances.');
INSERT INTO badge_level_requirements VALUES(3723,523,'level3',7,'Why is it important to accept praise in a gracious manner, no matter how you feel about your performance? Learn how to not boast nor put yourself down when accepting praise. What strategies are out there?');
INSERT INTO badge_level_requirements VALUES(3724,523,'level4',8,'Complete four performances.');
INSERT INTO badge_level_requirements VALUES(3725,523,'level4',9,'Teach a lesson or class in your performing art or take a younger person under your wing and help them with several aspects of their performance, such as pep talks, helping them with their lines, showing them were resources or supplies are, etc.');
INSERT INTO badge_level_requirements VALUES(3726,523,'level5',10,'Complete five performances.');
INSERT INTO badge_level_requirements VALUES(3727,523,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3728,524,'preschool',0,'Discuss what perseverance means.  What does it mean to persevere at something?  How is it similar to patience, endurance, courage and faithfulness?  Why is perseverance important?  When have you had to persevere in your life?');
INSERT INTO badge_level_requirements VALUES(3729,524,'preschool',1,'Listen to or read a story about a character who didn’t give up. Try something that’s hard for you. Don’t give up! Keep trying until you are able to do it.');
INSERT INTO badge_level_requirements VALUES(3730,524,'level1',2,'Choose a skill or activity to practice every day for one week. Record or talk about how you improved with effort.');
INSERT INTO badge_level_requirements VALUES(3731,524,'level2',3,'Reflect on a time you gave up on something. What would you do differently now? What did you learn from the experience?');
INSERT INTO badge_level_requirements VALUES(3732,524,'level3',4,'Learn about the history of someone famous who overcame difficulty through perseverance (e.g., Helen Keller, Thomas Edison, Temple Grandin, or Wilma Rudolph). Share what you learned.');
INSERT INTO badge_level_requirements VALUES(3733,524,'level4',5,'Complete a physical or academic challenge that requires multiple attempts or practice to succeed—such as a puzzle, musical instrament, obstacle course, essay, art project, or science experiment. Reflect on what you learned from failing and trying again.');
INSERT INTO badge_level_requirements VALUES(3734,524,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(3735,525,'preschool',0,'What is a pet? What makes a pet different from a wild animal? Learn three animals that could be wild or a pet.');
INSERT INTO badge_level_requirements VALUES(3736,525,'preschool',1,'Help an adult take care of a pet for a minimum of one week.');
INSERT INTO badge_level_requirements VALUES(3737,525,'level1',2,'Be responsible for the majority of care for a pet for a minimum of a week. You must provide food, water, shelter, grooming, exercise, and love.');
INSERT INTO badge_level_requirements VALUES(3738,525,'level1',3,'What are the most common injuries to humans from owning the type of pet you have chosen? Find out what first aid is necessary to treat those injuries and what can be done to prevent them.');
INSERT INTO badge_level_requirements VALUES(3739,525,'level2',4,'Be responsible for the majority of care for a pet for a minimum of two weeks. You must provide food, water, shelter, grooming, exercise and love.');
INSERT INTO badge_level_requirements VALUES(3740,525,'level2',5,'Calculate what it costs to keep the pet of your choice. This can be either for a current pet, or for one you wish to get. Make sure to find out what kind of food it eats, and how much, any medical needs, any special cage or bedding requirements, toys, special equipment such as a leash, collar, or litter box, any licensing fees, etc. Average out the daily, monthly and yearly cost of owning this type of animal.');
INSERT INTO badge_level_requirements VALUES(3741,525,'level3',6,'Research the most common illnesses and injuries for your pet. How can you prevent them? Learn to recognize the warning signs of common illness and symptoms of common injuries. Show the proper way to administer medication to your pet (if possible). Know where to find your pet’s vet’s information.');
INSERT INTO badge_level_requirements VALUES(3742,525,'level4',7,'Research the possibility of breeding a pet and selling the offspring. Is it responsible for the breed/species? Find out what expenses a person would have in addition to the normal pet expenses. How hard would it be to sell the offspring of a pet you’d like to breed? Where would you advertise?');
INSERT INTO badge_level_requirements VALUES(3743,525,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3744,526,'preschool',0,'Learn a phobia is.  How does it differ form normal fears and anxieties?');
INSERT INTO badge_level_requirements VALUES(3745,526,'preschool',1,'Find out what the most common phobia is.');
INSERT INTO badge_level_requirements VALUES(3746,526,'level1',2,'Learn about at least three uncommon phobias such as pogonophobia (fear of beards) or orturophobia (fear of cheese).');
INSERT INTO badge_level_requirements VALUES(3747,526,'level2',3,'What are symptoms of a phobia?  Research and identify at least 10 common phobias, such as arachnophobia (fear of spiders) or acrophobia (fear of heights).');
INSERT INTO badge_level_requirements VALUES(3748,526,'level3',4,'Learn about and discuss the three main causes of phobias.  Which is usually the most common?');
INSERT INTO badge_level_requirements VALUES(3749,526,'level4',5,'Investigate the historical understanding and treatment of phobias, from ancient times to modern approaches.');
INSERT INTO badge_level_requirements VALUES(3750,526,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3751,527,'preschool',0,'Learn what a photograph is. What can you use to take a photograph (cameras, smart-phones, etc.)? Learn how to take photograph and with parental permission take a photograph.');
INSERT INTO badge_level_requirements VALUES(3752,527,'level1',1,'Find out the name of the parts of the camera you are using. Either draw a picture and label it with those parts and their description, or make a list of those parts with their description.');
INSERT INTO badge_level_requirements VALUES(3753,527,'level1',2,'Describe the elements of a good photograph.');
INSERT INTO badge_level_requirements VALUES(3754,527,'level2',3,'Take a picture of your choice from several different angles such as “Bird’s eye view” and “Worm’s eye view.” Make a collage or other presentation out of these photos either digitally or printed.');
INSERT INTO badge_level_requirements VALUES(3755,527,'level3',4,'Name computer software that can enhance photographs. How does this software work to make changes and what are those changes? If possible, experiment with photo software.');
INSERT INTO badge_level_requirements VALUES(3756,527,'level4',5,'Define the following as it relates to photography: Aperture Brightness Composition Contrast Crop DPI (dots per square inch) Exposure Filters Flash Focal exposure Focus ISO speed Metering Negative space Pixel Red eye Shutter Shutter speed Tripod Zoom');
INSERT INTO badge_level_requirements VALUES(3757,527,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3758,528,'preschool',0,'Understand what the terms force and motion means.  Demonstrate them.  Examples might be to push someone on a swing,  push a toy car across a room, or throwing a ball.  Be able to explain how force and motion affect your demonstration.  What happens if no force is applied? What happens if uneven force is applied on two sides of an object, such as in tug-of-war?  (Younger members should understand the basic concept while older members should be able to explain the terms in detail.)');
INSERT INTO badge_level_requirements VALUES(3759,528,'preschool',1,'Learn what the terms friction and gravity mean. Demonstrate them in action.  For example, you might sled down a hill first on a piece of cardboard and then on a sled.  Why does one move faster than the other? You can try the same experiment on a small play ground slide.  First slide down sitting on a piece of wax paper, then on a piece of rubber, such as a place mat.  Which makes you go faster?  Why? Think of at least three other examples of friction and gravity. (Younger members should understand the basic concept while older members should be able to explain the terms in detail.)');
INSERT INTO badge_level_requirements VALUES(3760,528,'level1',2,'Create a marble run out of objects found in your home such as wrapping paper tubes, funnels, track from toy cars, Legos, etc.  How far can you get a marble to travel?  Can you make a jump and have the marble be caught in a funnel and keep going?  Older members should be able to explain how things like gravity, friction, mass and velocity effect their  marble run.');
INSERT INTO badge_level_requirements VALUES(3761,528,'level2',3,'Learn about air resistance.  What is it?  How does it affect our world?  Drop both a coin and a feather at the same time.  Why do you think one falls faster than the other?  Design a paper plane and fly it.  Why does it stay up in the air for so long?  (Younger members should understand the basic concept while older members should be able to explain the terms in detail.)');
INSERT INTO badge_level_requirements VALUES(3762,528,'level3',4,'Understand and explain Newton’s Three Laws of Motion.');
INSERT INTO badge_level_requirements VALUES(3763,528,'level4',5,'Explain the theory of energy conservation as it applies to physics.  For example, when a car burns gasoline, and moves forward, how is energy conserved?');
INSERT INTO badge_level_requirements VALUES(3764,528,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3765,529,'preschool',0,'Learn basic kitchen safety when baking.');
INSERT INTO badge_level_requirements VALUES(3766,529,'preschool',1,'Taste three different kinds of pie.');
INSERT INTO badge_level_requirements VALUES(3767,529,'level1',2,'Do Preschool requirement # 1 and 2.');
INSERT INTO badge_level_requirements VALUES(3768,529,'level1',3,'Find examples of at least one pie in the following different categories: savory, custard/cream, meat, fruit, breakfast, and nut. Your example can be a real pie or a picture of a pie.  How to they differ in looks and ingredients?');
INSERT INTO badge_level_requirements VALUES(3769,529,'level2',4,'Do Level 1 requirements #1& 2. Taste five different kinds of pie.');
INSERT INTO badge_level_requirements VALUES(3770,529,'level2',5,'Learn about the the history of pies throughout the ages.');
INSERT INTO badge_level_requirements VALUES(3771,529,'level3',6,'Do Level 4 Requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(3772,529,'level3',7,'Learn about types of pies from different countries. Give examples of pies from at least five different countries.');
INSERT INTO badge_level_requirements VALUES(3773,529,'level4',8,'Do Level 3 requirements #1 & 2. Taste seven different kinds of pie.');
INSERT INTO badge_level_requirements VALUES(3774,529,'level4',9,'Bake at least three different types of pies from scratch.  (Pies made for optional requirements must be in addition to these.)');
INSERT INTO badge_level_requirements VALUES(3775,529,'level5',10,'Do Level 4 requirements #1 & 2');
INSERT INTO badge_level_requirements VALUES(3776,529,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.  You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3781,532,'preschool',0,'Understand what a pipe cleaner is, and what they were originally used for.');
INSERT INTO badge_level_requirements VALUES(3782,532,'level1',1,'What color were pipe cleaners when they were first invented? What colors are available now? What other varieties are available now, such as metallic, extra fluffy, etc.?');
INSERT INTO badge_level_requirements VALUES(3783,532,'level2',2,'Learn how pipe cleaners are made.');
INSERT INTO badge_level_requirements VALUES(3784,532,'level3',3,'Research the origins and history of pipe cleaners. Who invented them and when?');
INSERT INTO badge_level_requirements VALUES(3785,532,'level4',4,'Research and find at least five pictures of professional pipe cleaner art and discuss how you think they were made.');
INSERT INTO badge_level_requirements VALUES(3786,532,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirement:');
INSERT INTO badge_level_requirements VALUES(3787,533,'preschool',0,'Be able to explain what a pirate is.');
INSERT INTO badge_level_requirements VALUES(3788,533,'level1',1,'Learn about at least two famous pirates such as Blackbeard, Ching Shih, Mary Reed, Henry Morgan, or Captain Kidd.');
INSERT INTO badge_level_requirements VALUES(3789,533,'level2',2,'Learn about at least 3 famous pirates.');
INSERT INTO badge_level_requirements VALUES(3790,533,'level2',3,'Locate on a map areas that were known for pirate ports.  Examples might include Tortuga, Port Royal, or the Barbary Coast.');
INSERT INTO badge_level_requirements VALUES(3791,533,'level3',4,'Learn about at least 5 famous pirates.');
INSERT INTO badge_level_requirements VALUES(3792,533,'level3',5,'Create a timeline of pirate history. Include at least 25 events or people.');
INSERT INTO badge_level_requirements VALUES(3793,533,'level4',6,'Compare and contrast piracy in its “golden age” with modern piracy.  Where is piracy still practiced today and how does it differ from the piracy of the past?  How are governments dealing with these modern day pirates?');
INSERT INTO badge_level_requirements VALUES(3794,533,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3797,535,'preschool',0,'Learn what a planet is. Know which planet we live on. How is a planet different from a star?');
INSERT INTO badge_level_requirements VALUES(3798,535,'level1',1,'What is the difference between a comet, a moon, and an asteroid?');
INSERT INTO badge_level_requirements VALUES(3799,535,'level1',2,'Be able to name all eight major planets that orbit our sun. Know what the difference is between “Rocky Midgets”, “Gas Giants,” and dwarf planets and where they are located. What is the most well-known dwarf planet?');
INSERT INTO badge_level_requirements VALUES(3800,535,'level2',3,'Make a timeline of events in history relating to planets and their moons, such as when Galileo discovered two of Jupiter’s moons, or when the rings around Saturn were discovered. You must have at least ten items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3801,535,'level3',4,'You must have at least fifteen items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3802,535,'level3',5,'Read a biography of a famous person associated with the planets, such as Galileo Galelei. (If you earn this badge again you must read about a different person.)');
INSERT INTO badge_level_requirements VALUES(3803,535,'level4',6,'You must have at least twenty items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3804,535,'level4',7,'Know how far away from the sun our planet is. What is the “Goldilocks zone”? What is a “light-year”?');
INSERT INTO badge_level_requirements VALUES(3805,535,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3810,538,'preschool',0,'Understand the difference between plant based foods and animal based foods.');
INSERT INTO badge_level_requirements VALUES(3811,538,'preschool',1,'Understand the importance of plant-based foods in a balanced and sustainable diet.');
INSERT INTO badge_level_requirements VALUES(3812,538,'level1',2,'Understand the concept of veganism and vegetarianism and their dietary choices centered around plant-based foods.');
INSERT INTO badge_level_requirements VALUES(3813,538,'level2',3,'Visit a local farmers’ market or organic grocery store to learn about the wide variety of plant-based ingredients available.  If there are none in your area, find out what plant based foods are available at your local grocery store.');
INSERT INTO badge_level_requirements VALUES(3814,538,'level3',4,'Learn about the environmental impact of both plant and animal agriculture and the benefits of plant-based eating for sustainability.');
INSERT INTO badge_level_requirements VALUES(3815,538,'level4',5,'Research and discuss the economic and ethical considerations associated with the plant-based food industry.');
INSERT INTO badge_level_requirements VALUES(3816,538,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3819,540,'level1',0,'Earn the Pocket Knife Safety badge at your level. This must be earned before doing any further requirements for the Pocket Knife badge.');
INSERT INTO badge_level_requirements VALUES(3820,540,'level1',1,'Learn about each of the various tools on your pocket knife.  Know what each does and how to use it properly.');
INSERT INTO badge_level_requirements VALUES(3821,540,'level2',2,'Learn how to properly clean and care for a pocket knife.');
INSERT INTO badge_level_requirements VALUES(3822,540,'level3',3,'Learn about legal issues regarding pocket knives and their use such as where you may or may not carry them.  For example, you may not carry a pocket knife onto an airplane, into most schools, into a court house, etc.');
INSERT INTO badge_level_requirements VALUES(3823,540,'level4',4,'Learn the difference between a jack knife, a pen knife, and a multipurpose knife.  Know the different type of mechanisms for locking the knife in place and closing it again including a lock blade knife, a slip joint knife, a friction folding knife, a push button knife, and a spring assisted knife.');
INSERT INTO badge_level_requirements VALUES(3824,540,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
