INSERT INTO badge_level_requirements VALUES(3855,542,'preschool',0,'What is a poem?');
INSERT INTO badge_level_requirements VALUES(3856,542,'preschool',1,'Read or have read to you two poems.');
INSERT INTO badge_level_requirements VALUES(3857,542,'level1',2,'Read a minimum of four poems.');
INSERT INTO badge_level_requirements VALUES(3858,542,'level1',3,'Write a poem.');
INSERT INTO badge_level_requirements VALUES(3859,542,'level2',4,'Read a minimum of six poems. Read at least two different styles of poetry.');
INSERT INTO badge_level_requirements VALUES(3860,542,'level2',5,'Memorize a poem.');
INSERT INTO badge_level_requirements VALUES(3861,542,'level3',6,'Read a minimum of eight poems. Read at least three different styles of poetry.');
INSERT INTO badge_level_requirements VALUES(3862,542,'level3',7,'Learn about the history of poetry. Make a timeline with at least ten events on it.');
INSERT INTO badge_level_requirements VALUES(3863,542,'level4',8,'Read a minimum of ten poems. Read at least four different styles of poetry.');
INSERT INTO badge_level_requirements VALUES(3864,542,'level4',9,'Learn about at least five different types of poetry, such as sonnet, blank verse, and haiku. Write a poem in one of these styles.');
INSERT INTO badge_level_requirements VALUES(3865,542,'level5',10,'Read a minimum of twelve poems. Read at least five different styles of poetry.');
INSERT INTO badge_level_requirements VALUES(3866,542,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3869,544,'preschool',0,'Learn all safety rules, including not touching or eating unknown plants.');
INSERT INTO badge_level_requirements VALUES(3870,544,'preschool',1,'Learn at least three types of poisonous plants. What poisonous plants live around you?');
INSERT INTO badge_level_requirements VALUES(3871,544,'level1',2,'Be able to identify four different types of poisonous plants.');
INSERT INTO badge_level_requirements VALUES(3872,544,'level1',3,'Learn the history of three types of poisonous plants. What country are they from? What are the effects if you get them on you? Draw a picture of each of the plants.');
INSERT INTO badge_level_requirements VALUES(3873,544,'level2',4,'Be able to identify five different types of poisonous plants.');
INSERT INTO badge_level_requirements VALUES(3874,544,'level2',5,'Read a book or a few articles about poisonous plants. Tell your family, friends, or group what you learned.');
INSERT INTO badge_level_requirements VALUES(3875,544,'level3',6,'Be able to identify six different types of poisonous plants.');
INSERT INTO badge_level_requirements VALUES(3876,544,'level3',7,'Learn about poisonous berries. What types of plants do they grow on? What would happen to you if you ate one? What kinds of treatments are there?');
INSERT INTO badge_level_requirements VALUES(3877,544,'level4',8,'Be able to identify seven different types of poisonous plants.');
INSERT INTO badge_level_requirements VALUES(3878,544,'level4',9,'Research and make a timeline of events in history that involved poisonous plants. Include at least 15 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(3879,544,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3880,545,'preschool',0,'What is Pokemon? When did it start? Identify three important dates in Pokemon history.');
INSERT INTO badge_level_requirements VALUES(3881,545,'preschool',1,'Recognize five different Pokemon by name and type.');
INSERT INTO badge_level_requirements VALUES(3882,545,'level1',2,'Complete Preschool requirements 1 & 2. Identify ten Pokemon by name and type.');
INSERT INTO badge_level_requirements VALUES(3883,545,'level1',3,'What is a Pokeball? What are they used for? Name five different types of Pokeballs.');
INSERT INTO badge_level_requirements VALUES(3884,545,'level2',4,'Complete Level 1 requirements 1 & 2. Identify fifteen Pokemon by name and type.');
INSERT INTO badge_level_requirements VALUES(3885,545,'level2',5,'Who are the main characters in the Pokemon original series? Name three different locations they travel to and three different gyms they visit.');
INSERT INTO badge_level_requirements VALUES(3886,545,'level3',6,'Complete Level 2 requirements 1 & 2. Identify twenty Pokemon by name and type.');
INSERT INTO badge_level_requirements VALUES(3887,545,'level3',7,'How many different types of Pokemon are there (water, grass, poison, etc)? Draw a picture of a new Pokemon. Make sure to give it a name, type, attacks, abilities, evolutions(if any), and its background story.');
INSERT INTO badge_level_requirements VALUES(3888,545,'level4',8,'Complete Level 3 requirements 1 & 2. Identify twenty-five Pokemon by name and type.');
INSERT INTO badge_level_requirements VALUES(3889,545,'level4',9,'Play one of the main series generational handheld game. Who are the main characters? Defeat a gym and earn a badge in game.');
INSERT INTO badge_level_requirements VALUES(3890,545,'level5',10,'Complete Level 4 requirements 1 & 2. Identify thirty Pokemon by name and type.');
INSERT INTO badge_level_requirements VALUES(3891,545,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3892,547,'preschool',0,'What is polymer clay? Learn how to work with it with your hands and simple tools. Learn how to condition, shape, and safely bake it. Polymer clay can be toxic so learn what safety precautions to take when working with polymer clay.');
INSERT INTO badge_level_requirements VALUES(3893,547,'preschool',1,'How do you care for your creation when it is finished? Look at examples of things made from polymer clay.');
INSERT INTO badge_level_requirements VALUES(3894,547,'level1',2,'Learn how polymer clay is made.');
INSERT INTO badge_level_requirements VALUES(3895,547,'level2',3,'What is the difference between polymer clay and at least 2 other moldable clays? What is the purpose of varnish?');
INSERT INTO badge_level_requirements VALUES(3896,547,'level3',4,'Learn some of the history of polymer clay. Watch an experienced person work with polymer clay, either in person or virtually (with parental permission). Look around your house for common items that would make good tools for working with polymer clay. Get permission before using these tools.');
INSERT INTO badge_level_requirements VALUES(3897,547,'level4',5,'Learn about specific tools that are used for polymer clay including conditioning, shaping, and baking. If possible, use some of these tools.');
INSERT INTO badge_level_requirements VALUES(3898,547,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3899,548,'preschool',0,'What type of corn kernels are used for popcorn? What makes it pop? Tell your family, friends, or group what you learned.');
INSERT INTO badge_level_requirements VALUES(3900,548,'preschool',1,'List different methods for popping corn (microwave, stovetop, etc.).');
INSERT INTO badge_level_requirements VALUES(3901,548,'level1',2,'Sample at least three different kinds of popcorn, one of which you make yourself with parent approval.');
INSERT INTO badge_level_requirements VALUES(3902,548,'level1',3,'Learn the stages of a corn plant such as germination, ear development, pollination, harvest and drying. Identify the different parts (roots, stalk, leaves, tassels, ears).');
INSERT INTO badge_level_requirements VALUES(3903,548,'level2',4,'Sample four kinds of popcorn, two of which you make yourself with parent approval.');
INSERT INTO badge_level_requirements VALUES(3904,548,'level2',5,'Define sprouting, silking, milking and denting and explain why it is important that corn plants be grown near other corn plants.');
INSERT INTO badge_level_requirements VALUES(3905,548,'level3',6,'Sample five kinds of popcorn, using at least two different cooking types that you make yourself.');
INSERT INTO badge_level_requirements VALUES(3906,548,'level3',7,'Learn about the nutrition of popcorn. What is the difference in nutritional value when you add flavoring such as butter, caramel, or Parmesan cheese? How about in the different methods of cooking popcorn?');
INSERT INTO badge_level_requirements VALUES(3907,548,'level4',8,'What health claims are made about popcorn? Do these claims seem scientifically-based? What do you think?');
INSERT INTO badge_level_requirements VALUES(3908,548,'level4',9,'Gather the nutritional facts of popped corn (per 1 cup, based on a 2,000 cal. diet) cooked with oil, without oil, with butter, caramel coated, and one other of your choice. Compare them.');
INSERT INTO badge_level_requirements VALUES(3909,548,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3910,549,'preschool',0,'Explain the difference between a postcard and a letter.  Learn what size a postcard can be.  What materials can it be made from?');
INSERT INTO badge_level_requirements VALUES(3911,549,'preschool',1,'Start a collection of at least three postcards.');
INSERT INTO badge_level_requirements VALUES(3912,549,'level1',2,'Learn how to properly write and address a postcard.  Make sure you know what the proper postage is since it differs from a regular letter.');
INSERT INTO badge_level_requirements VALUES(3913,549,'level2',3,'Make your own postcard and send it to a friend or family member.');
INSERT INTO badge_level_requirements VALUES(3914,549,'level3',4,'Learn the history of the postcard.  When were they first used and why?');
INSERT INTO badge_level_requirements VALUES(3915,549,'level4',5,'Do Level 3 requirements # 1 & 2.');
INSERT INTO badge_level_requirements VALUES(3916,549,'level4',6,'Write to all your family and friends around the country and ask them to send you a postcard from where they live.');
INSERT INTO badge_level_requirements VALUES(3917,549,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3918,550,'preschool',0,'What is prayer? Ask some older people what they think prayer is and how important it is in their lives.');
INSERT INTO badge_level_requirements VALUES(3919,550,'preschool',1,'Discuss with someone things you think are good to pray about. Be sure to include things to be thankful for.');
INSERT INTO badge_level_requirements VALUES(3920,550,'level1',2,'Is there any specific order in which you must pray? If not, are there charts which can give you guidelines? With the help of an adult, make a chart describing the order you think you should pray in. (e.g. thanksgiving first, request second, etc.)');
INSERT INTO badge_level_requirements VALUES(3921,550,'level2',3,'Spend some time each day in prayer for a week. Prayer should not be something you keep a clock on, but be sure to spend a decent amount of time. Keep a record of what you pray for and how you see your prayers answered over time.');
INSERT INTO badge_level_requirements VALUES(3922,550,'level3',4,'Read prayers from your book of faith.  Memorize one.');
INSERT INTO badge_level_requirements VALUES(3923,550,'level4',5,'What are some reasons we don’t get the answers we want from prayer? How can we learn to have faith despite hardship? Read about someone such as Joni areckson Tada or Amy  Carmichael who felt they didn’t get what they wanted from prayer, but got something better instead.');
INSERT INTO badge_level_requirements VALUES(3924,550,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3925,551,'preschool',0,'What is a princess?');
INSERT INTO badge_level_requirements VALUES(3926,551,'preschool',1,'Read, or have read to you, stories about three different princesses.');
INSERT INTO badge_level_requirements VALUES(3927,551,'level1',2,'Read about 4 princesses.');
INSERT INTO badge_level_requirements VALUES(3928,551,'level1',3,'Read at least two non-Disney versions of the princesses from requirement 1.  Discuss how the Disney and non-Disney versions differ.');
INSERT INTO badge_level_requirements VALUES(3929,551,'level2',4,'Read about 5 princesses.');
INSERT INTO badge_level_requirements VALUES(3930,551,'level2',5,'Learn about at least 3 real princesses from the past or the present.');
INSERT INTO badge_level_requirements VALUES(3931,551,'level3',6,'Learn about at least 5 real princesses and where they lived.');
INSERT INTO badge_level_requirements VALUES(3932,551,'level4',7,'Learn about at least 7 real princesses and where they lived.');
INSERT INTO badge_level_requirements VALUES(3933,551,'level4',8,'Compare an original princess story to the common day retelling. For instance, Han Christian Andersen’s original The Little Mermaid compared to Disney’s version. How do they differ? Are the endings the same? Are the morals of the story any different?');
INSERT INTO badge_level_requirements VALUES(3934,551,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3935,552,'preschool',0,'What is the basic definition of psychology?');
INSERT INTO badge_level_requirements VALUES(3936,552,'preschool',1,'How can you tell when someone is sad, happy, or angry? How do you feel when you are sad, happy, or angry? If you are sad, what can you do to feel better? How can you help someone else feel better if they are sad?');
INSERT INTO badge_level_requirements VALUES(3937,552,'level1',2,'What kinds of things do psychologists study? Be able to give a brief description of the science of psychology to someone.');
INSERT INTO badge_level_requirements VALUES(3938,552,'level2',3,'Learn about stress. How can it hurt you? What are some things you can do to relieve stress? Talk to at least three different people about their favorite way to relieve stress and try at least one of their ideas yourself.');
INSERT INTO badge_level_requirements VALUES(3939,552,'level3',4,'Learn about the history of psychology as a science. Create a timeline of the advances in psychology and the different theories explored over time. How has the science changed through the years? Have at least ten events on your timeline.');
INSERT INTO badge_level_requirements VALUES(3940,552,'level4',5,'Learn about a person’s IQ and how it is measured. Is this a valid measure of intelligence? Learn about the advantages/disadvantages of the traditional IQ test.');
INSERT INTO badge_level_requirements VALUES(3941,552,'level4',6,'Learn about three famous psychologists throughout history, such as Carl Jung or Ivan Pavlov. Find out why they are famous, what their theories about psychology were, and whether or not their work is still useful today.');
INSERT INTO badge_level_requirements VALUES(3942,552,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead Optional Requirements');
INSERT INTO badge_level_requirements VALUES(3943,553,'preschool',0,'What is public speaking? Listen to someone give a speech.');
INSERT INTO badge_level_requirements VALUES(3944,553,'preschool',1,'When you give a speech, you usually stand up in front of people and talk about a subject that is interesting to you.  Stand up in front of your family, friends, or group and tell them about something you like.');
INSERT INTO badge_level_requirements VALUES(3945,553,'level1',2,'Do Preschool 1 & 2.');
INSERT INTO badge_level_requirements VALUES(3946,553,'level1',3,'Learn at least five tips on how to stay calm and collected in front of an audience.');
INSERT INTO badge_level_requirements VALUES(3947,553,'level2',4,'Complete Level 1  requirements 1 & 2. Your speech should be 3-4 minutes long.');
INSERT INTO badge_level_requirements VALUES(3948,553,'level2',5,'Learn how to project your voice and stand properly in front of an audience. Why is it important to not be too quiet or loud, and not to fiddle with notes or your clothes?');
INSERT INTO badge_level_requirements VALUES(3949,553,'level3',6,'Complete Level 2 requirements 1 & 2. Your speech should be 5-7 minutes long.');
INSERT INTO badge_level_requirements VALUES(3950,553,'level3',7,'Learn how to dress for public speaking. Why is how you dress important? Learn how to interact with props, whether it be a demonstration or a projection screen.');
INSERT INTO badge_level_requirements VALUES(3951,553,'level4',8,'Complete Level 3 requirements 1 & 2. Your speech should be 8-10 minutes long.');
INSERT INTO badge_level_requirements VALUES(3952,553,'level4',9,'Remember that an effective speech conveys your message to the audience.  Speeches need to have some good organization; you must know what you are speaking about and make a plan to communicate your intent to your listeners. Learn how to write to a speech that has a hook, clear message/theme, evidence, and a strong conclusion.');
INSERT INTO badge_level_requirements VALUES(3953,553,'level5',10,'Your speech should be 12-14 minutes long.');
INSERT INTO badge_level_requirements VALUES(3954,553,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3955,554,'preschool',0,'.  Learn what public transport is (bus, train, coach, airplane, ferry boat, taxi cab, subway/underground/metro etc).  Which types of public transport operate in your area?  Ride on public transport of some type.');
INSERT INTO badge_level_requirements VALUES(3956,554,'preschool',1,'.  Learn the safety rules of using public transport.');
INSERT INTO badge_level_requirements VALUES(3957,554,'level1',2,'.  Do Preschool requirements 1* and 2*.');
INSERT INTO badge_level_requirements VALUES(3958,554,'level1',3,'. Work out what you can do to pass the time on public transport.  Any activities must be small enough not to take up too much space, quiet so as not to disturb other passengers and not have small pieces that you could lose (many travel games have magnets to keep all the pieces from falling about).');
INSERT INTO badge_level_requirements VALUES(3959,554,'level2',4,'* and 2*.');
INSERT INTO badge_level_requirements VALUES(3960,554,'level2',5,'. Plan a trip using public transport, work out the costs involved and the time it would take to make the trip.  Is it more expensive to do a one-way trip or a return trip?');
INSERT INTO badge_level_requirements VALUES(3961,554,'level3',6,'.  Do Level 2  1* and 2*.');
INSERT INTO badge_level_requirements VALUES(3962,554,'level3',7,'.  Find out what kind of luggage allowances are available for public transport.  How much is allowed free of charge?  What are the costs involved for extra luggage?  What items are you not allowed to carry on public transport?  Which items must be put in checked-in baggage in the cargo-hold?');
INSERT INTO badge_level_requirements VALUES(3963,554,'level4',8,'.  Do Level 3 1* and 2*.');
INSERT INTO badge_level_requirements VALUES(3964,554,'level4',9,'.  What kind of identification do you need to be able to travel on public transport?  Understand how to make connections between the same type of public transport (eg; bus to bus connection) and between different types (eg; bus to train, bus to airplane, etc.)');
INSERT INTO badge_level_requirements VALUES(3965,554,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3966,555,'preschool',0,'Learn what a pumpkin patch is and visit the one in person.');
INSERT INTO badge_level_requirements VALUES(3967,555,'preschool',1,'Color in a picture of a pumpkin or Jack-o-lantern, or participate in a similar pumpkin craft activity.');
INSERT INTO badge_level_requirements VALUES(3968,555,'level1',2,'Are there animals at the pumpkin patch? Make a list.  Which can you feed? Which can you pet? Which can you ride? Which are just for viewing?  If there aren’t animals, what activities are available, or what what would you encourage the pumpkin patch to consider adding?');
INSERT INTO badge_level_requirements VALUES(3969,555,'level2',3,'Learn about how the patch grows their pumpkins.  Is it on site or are the pumpkins brought in?  How big is the field used to grow the pumpkins? When were they planted?  How many pumpkins are sold at the patch each year?');
INSERT INTO badge_level_requirements VALUES(3970,555,'level3',4,'Be able to read a map of the pumpkin patch, or sketch a simple map if a formal map doesn’t exist.  Use an existing area map to locate the patch within the city or county.');
INSERT INTO badge_level_requirements VALUES(3971,555,'level4',5,'Find out about jobs at the pumpkin patch.  What type of jobs go into creating a pumpkin patch?  Which are seasonal and which are year round? Choose one job that interests you and find out what type of training you would need for this job.  What type of hours would you work?  What type of pay could you expect?  What are the physical requirements for the job, such as lifting or standing? Could accommodations for a specific job be made for persons of different abilities?');
INSERT INTO badge_level_requirements VALUES(3972,555,'level5',6,'Take someone to a pumpkin patch, if available and accessible. You can take kids, your spouse, seniors, anyone, and share your your new found knowledge about the pumpkin patch. If a patch is not available or accessible, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3973,556,'preschool',0,'Identify two types of pumpkins. Learn the life cycle of a pumpkin.');
INSERT INTO badge_level_requirements VALUES(3974,556,'preschool',1,'Eat something made with pumpkin.');
INSERT INTO badge_level_requirements VALUES(3975,556,'level1',2,'Identify three types of pumpkins.');
INSERT INTO badge_level_requirements VALUES(3976,556,'level1',3,'Learn where pumpkins are typically grown and in what season.');
INSERT INTO badge_level_requirements VALUES(3977,556,'level2',4,'Identify four types of pumpkins.');
INSERT INTO badge_level_requirements VALUES(3978,556,'level2',5,'What are the health benefits of pumpkins? Are pumpkins a fruit or vegetable? What is the “three sisters” method of growing pumpkins?');
INSERT INTO badge_level_requirements VALUES(3979,556,'level3',6,'Identify five types of pumpkins.');
INSERT INTO badge_level_requirements VALUES(3980,556,'level3',7,'Make two recipes using pumpkins.');
INSERT INTO badge_level_requirements VALUES(3981,556,'level4',8,'Identify six types of pumpkins.');
INSERT INTO badge_level_requirements VALUES(3982,556,'level4',9,'Find five to eight physical characteristics to look for in picking out a good carving pumpkin. Know how to tell when a pumpkin is ready to harvest. Know the proper way to harvest and store a pumpkin. How long do whole pumpkins last before they begin to rot?');
INSERT INTO badge_level_requirements VALUES(3983,556,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3984,557,'preschool',0,'Smell and taste pumpkin spice');
INSERT INTO badge_level_requirements VALUES(3985,557,'preschool',1,'Eat something made with pumpkin spice such as pumpkin pie, pumpkin muffins, pumpkin pudding, etc.');
INSERT INTO badge_level_requirements VALUES(3986,557,'level1',2,'Drink a pumpkin spice flavored drink such as pumpkin spice tea, a no coffee pumpkin spice latte, pumpkin spice milk, etc.');
INSERT INTO badge_level_requirements VALUES(3987,557,'level2',3,'Learn what spices are usually mixed to create pumpkin spice.  Smell and taste each one individually.  Then smell and taste a pumpkin spice mix.  Can you identify the different components?  Learn to make homemade pumpkin spice blend from scratch.');
INSERT INTO badge_level_requirements VALUES(3988,557,'level3',4,'Research the origin and history of pumpkin spice.');
INSERT INTO badge_level_requirements VALUES(3989,557,'level4',5,'Write a short essay or hold a discussion on the cultural significance of pumpkin spice and its popularity.');
INSERT INTO badge_level_requirements VALUES(3990,557,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(3993,559,'preschool',0,'What is a purse? Learn what a purse is used for.');
INSERT INTO badge_level_requirements VALUES(3994,559,'preschool',1,'What sort of things might you keep in a purse? Make a small collection of items you might want/need to take with you.');
INSERT INTO badge_level_requirements VALUES(3995,559,'level1',2,'Discover what kinds of material can be used to make purses and what colors/accessories you can choose. Draw a picture of the purse you would choose.');
INSERT INTO badge_level_requirements VALUES(3996,559,'level2',3,'What was the original use for a purse, and is it very different from how we use it today? Give some examples of the sorts of people who would use purses in history.');
INSERT INTO badge_level_requirements VALUES(3997,559,'level3',4,'Learn the history of purse design. How has the purse changed over the years?');
INSERT INTO badge_level_requirements VALUES(3998,559,'level4',5,'Learn about a famous purse designer. How are their purses special and how expensive are they to purchase?');
INSERT INTO badge_level_requirements VALUES(3999,559,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4000,560,'preschool',0,'Know what a pyramid is and be able to recognize the shape.');
INSERT INTO badge_level_requirements VALUES(4001,560,'preschool',1,'Look at pictures of at least 6 famous pyramids and learn how they were/are used. Use a mix of ancient and modern designs.');
INSERT INTO badge_level_requirements VALUES(4002,560,'level1',2,'Learn what the three styles of ancient pyramids are:  step, bent, and true.  Find an example of each.');
INSERT INTO badge_level_requirements VALUES(4003,560,'level2',3,'Build a small model of a pyramid.  You might use sugar cubes, LEGO bricks, paper, clay, or toothpicks.');
INSERT INTO badge_level_requirements VALUES(4004,560,'level3',4,'Research the significance of pyramids in three different ancient cultures such as Eygptian, Chinese and Mayan.');
INSERT INTO badge_level_requirements VALUES(4005,560,'level4',5,'Learn about the golden ratio and how it might relate to pyramid design.  What is the significance of the golden ratio?');
INSERT INTO badge_level_requirements VALUES(4006,560,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4007,561,'level1',0,'Identify the basic tools used in pyrographing. (Wood-burning tool, pencils, stencils, paper, tracing paper, ruler, eraser, indelible pens). Learn how to make a simple design by stencilling it onto tracing paper and then transferring it onto wood.   Why is it important to use a soft lead pencil when transferring your design to the wood?');
INSERT INTO badge_level_requirements VALUES(4008,561,'level2',1,'Which woods are most suited to pyrographing?  Why?  What preparation is necessary to make the wood suitable for pyrographing?  With adult help/supervision use a pyrographing tool to burn your design onto wood.');
INSERT INTO badge_level_requirements VALUES(4009,561,'level3',2,'What can you do to make your pyrography designs longer-lasting and more defined?  Use one method to make your design more defined.');
INSERT INTO badge_level_requirements VALUES(4010,561,'level4',3,'Learn about the history of pyrographing.  What does the term “pyrography” actually mean in literal terms?  Look at the works of at least one historical pyrography artist.');
INSERT INTO badge_level_requirements VALUES(4011,561,'level5',4,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4012,562,'preschool',0,'Learn what a quilt is and look at several different types either in person or through pictures.');
INSERT INTO badge_level_requirements VALUES(4013,562,'preschool',1,'Make a quilted pillow or other quilting project (at least 4 squares).  For Preschool and Level 1, this can be a simple cardstock quilt, sewing squares together with string through holes punched along the edges, or a simple tied quilt where the squares are tied to each other.  Level 2 – Level 5 should  complete a hand or machine quilted project that involves actual sewing.');
INSERT INTO badge_level_requirements VALUES(4014,562,'level1',2,'Be able to identify the basic tools used in quilting including: Sewing machine Thread Sewing needles Fabric Pattern Rotary cutter (parents please use the rotary cutter as its very sharp) Cutting mat Backing Batting');
INSERT INTO badge_level_requirements VALUES(4015,562,'level2',3,'Learn the following quilting terms: Backing Batting Bias Blocks Borders Seam allowance Strip piecing Sashing');
INSERT INTO badge_level_requirements VALUES(4016,562,'level3',4,'Choose a quilt pattern.  Measure and cut your fabric (measure twice and cut once!).  Learn how to properly pin your pieces together and then sew your pattern.  Iron and press your seams.  Sew together a quilt front, batting, and quilt back cleanly.');
INSERT INTO badge_level_requirements VALUES(4017,562,'level4',5,'Learn the history of quilting. How are they made differently now?  How were quilts used in the Civil War?');
INSERT INTO badge_level_requirements VALUES(4018,562,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.  If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4019,563,'preschool',0,'Understand what a quote is.  Listen to an adult read or say at least two famous quotes or short parts of speeches. Talk about what the words mean.');
INSERT INTO badge_level_requirements VALUES(4020,563,'preschool',1,'Choose your favorite quote and show examples of what it means by either acting it out or drawing a simple picture');
INSERT INTO badge_level_requirements VALUES(4021,563,'level1',2,'Learn who said your favorite quote or speech and what made that person important.  Why do people remember and quote their words?');
INSERT INTO badge_level_requirements VALUES(4022,563,'level2',3,'Memorize and recite a famous quote or part of a speech. Explain what it means and why it matters.');
INSERT INTO badge_level_requirements VALUES(4023,563,'level3',4,'Learn the history behind a famous speech. What event was it part of? What was its impact?');
INSERT INTO badge_level_requirements VALUES(4024,563,'level4',5,'Analyze how the structure or delivery of a speech affects its message. Compare two speeches or different versions of the same one.');
INSERT INTO badge_level_requirements VALUES(4025,563,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(4026,564,'preschool',0,'What are rabbits? Be able to recognize them from a picture.');
INSERT INTO badge_level_requirements VALUES(4027,564,'preschool',1,'Learn how to properly behave around rabbits and how to hold a rabbit so that neither you, nor the rabbit, gets hurt.');
INSERT INTO badge_level_requirements VALUES(4028,564,'level1',2,'What are male and female rabbits called?  What are the babies called?  What are young rabbits called?  What is a group of rabbits called? Be able to identify at least 5 different points of their anatomy.');
INSERT INTO badge_level_requirements VALUES(4029,564,'level2',3,'Know 8 parts of their anatomy.');
INSERT INTO badge_level_requirements VALUES(4030,564,'level2',4,'Know what type of food a rabbit needs.  How much should a rabbit be fed every day, and how often?  Understand how your rabbit should be housed.  How can you keep it safe from predators?  How is it kept warm in the winter and cool in the summer?  What health concerns are there for rabbits and what are the symptoms?');
INSERT INTO badge_level_requirements VALUES(4031,564,'level3',5,'Know 10 parts of a rabbit’s anatomy and how to tell a male from a female.');
INSERT INTO badge_level_requirements VALUES(4032,564,'level3',6,'Know the difference between the following rabbit types: Small Commercial Commercial Full Arch Semi Arch Cylindrical');
INSERT INTO badge_level_requirements VALUES(4033,564,'level4',7,'Understand rabbit breeding.  Know how to prepare a nest for a doe and when to provide her with it.  Why does the doe need to be taken to the buck’s hutch for breeding?  What is a typical litter size?  How long does a rabbit usually live?  Explain the difference between inbreeding, line breeding, and cross breeding.');
INSERT INTO badge_level_requirements VALUES(4034,564,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4035,565,'preschool',0,'Learn train/ railroad crossing safety rules as well as safety rules when riding trains such as subways and elevated trains.');
INSERT INTO badge_level_requirements VALUES(4036,565,'level1',1,'Learn about the two types of trains: passenger and freight.  Which is used the most today? Why? How do passenger trains differ from freight trains?');
INSERT INTO badge_level_requirements VALUES(4037,565,'level2',2,'Learn the history of railroads in the U.S. and trace the first major railroad routes across our country on a map.  How did the railroad help to expand our nation?');
INSERT INTO badge_level_requirements VALUES(4038,565,'level3',3,'Learn about the people who built the railways across America. What was their life like?');
INSERT INTO badge_level_requirements VALUES(4039,565,'level4',4,'Learn why railroads are still important today, despite the advantages of road travel and air transport.');
INSERT INTO badge_level_requirements VALUES(4040,565,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4041,567,'preschool',0,'What are rain gutter regatta races? Discuss rules and regulations for rain gutter regatta races.');
INSERT INTO badge_level_requirements VALUES(4042,567,'preschool',1,'Watch or participate in a rain gutter regatta race.');
INSERT INTO badge_level_requirements VALUES(4043,567,'level2',2,'Identify parts of the model boat including hull, metal keel, mast, sail, etc.');
INSERT INTO badge_level_requirements VALUES(4044,567,'level3',3,'Assist in setting up equipment and score board items for the race.');
INSERT INTO badge_level_requirements VALUES(4045,567,'level5',4,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4046,568,'preschool',0,'Read (or have read to you) a short book every day for a week.');
INSERT INTO badge_level_requirements VALUES(4047,568,'preschool',1,'Be able to explain what parts of the story are shown in the illustrations.');
INSERT INTO badge_level_requirements VALUES(4048,568,'level1',2,'Read for at least 30 minutes a day for two weeks.');
INSERT INTO badge_level_requirements VALUES(4049,568,'level1',3,'Use Who,  What, Where, When, Why and How to demonstrate your understanding of a story and explain it to someone else.');
INSERT INTO badge_level_requirements VALUES(4050,568,'level2',4,'Read for at least 1 hour every day for 2 weeks.  Read at least one of each of the following types of books: Fiction Nonfiction Poems Folktales Plays');
INSERT INTO badge_level_requirements VALUES(4051,568,'level2',5,'Understand and be able to explain the terms prologue, chapter, eiplogue, scene, verse and stanza in regards to books, plays and poetry.');
INSERT INTO badge_level_requirements VALUES(4052,568,'level3',6,'Choose a book to read and keep a vocabulary journal as you read it.  Write down any word you don’t know the meaning of as you read.  Try to guess what the word means by using context clues in the book and the way the word is used.  Then look up each word and write down the true meaning in your journal.');
INSERT INTO badge_level_requirements VALUES(4053,568,'level4',7,'Do Level 1=3 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(4054,568,'level4',8,'Read the foundational documents of the United States including The Declaration of Independence, the Preamble to the Constitution, the Bill of Rights, and Lincoln’s Second Inaugural Address.  Be able to explain the ideas presented in each document and their historical and present day significance.');
INSERT INTO badge_level_requirements VALUES(4055,568,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4056,569,'preschool',0,'Discuss with an adult what happens to trash after you throw it away. Then discuss what happens to items that are recycled.');
INSERT INTO badge_level_requirements VALUES(4057,569,'preschool',1,'Choose something that you currently throw away and come up with a new idea on how to reuse it safely.');
INSERT INTO badge_level_requirements VALUES(4058,569,'level1',2,'Participate in a recycling project such as a bottle or paper drive.');
INSERT INTO badge_level_requirements VALUES(4059,569,'level2',3,'Make a list of ways recycling can be a part of our daily lives, such as wash out plastic bags, take sacks and bags with you to the grocery store, place foil with cans to recycle,  start a compost pile for fruit and vegetable peelings and yard clippings. Come up with at least 20 different ways to recycle.');
INSERT INTO badge_level_requirements VALUES(4060,569,'level3',4,'Find two items at the store, in your home, etc. One should display poor packaging and one should display good packaging. Discuss why each is good and bad. How could they be better? Write a letter to a manufacturer suggesting or requesting better packaging. Voice your concerns about the packaging.');
INSERT INTO badge_level_requirements VALUES(4061,569,'level4',5,'Help organize a recycling program such as a paper or can drive. Donate the money earned to a local charity.');
INSERT INTO badge_level_requirements VALUES(4062,569,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4065,571,'preschool',0,'Learn what it means to operate a vehicle via remote control.  Know what a “pit” area is and what it is used for.');
INSERT INTO badge_level_requirements VALUES(4066,571,'preschool',1,'Choose an RC vehicle to learn about.  Find out what it is called and how to recognize it.  Understand how to stay safe around RC vehicles of this type both as a spectator as well as a driver or pit helper.');
INSERT INTO badge_level_requirements VALUES(4067,571,'level1',2,'Learn the basic parts of your RC vehicle and how it moves (e.g., wheels, propellers, rudders, motors, radio signals).  Learn to how the controller works for your RC vehicle.   How many channels does your controller have?  What do they control?');
INSERT INTO badge_level_requirements VALUES(4068,571,'level2',3,'Learn where you are allowed to run your RC vehicle.  What type of safety considerations and laws do you have to take into account when choosing a location?  Are there local clubs that provide an area to practice and compete or is your RC vehicle usually just used for recreation?');
INSERT INTO badge_level_requirements VALUES(4069,571,'level3',4,'Learn about the history of RC vehicles. When were they first invented? How have they changed over time?');
INSERT INTO badge_level_requirements VALUES(4070,571,'level4',5,'Learn about competitions available for your RC vehicle.  What associations run them?  Where and how often?  Are there local, regional, state, and national levels of competition? What is the cost of joining a local club?  If there are no competitions, are there recreational clubs where you can meet with other similar RC enthusiasts?');
INSERT INTO badge_level_requirements VALUES(4071,571,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4072,572,'preschool',0,'Learn what renewable or alternative energy is.');
INSERT INTO badge_level_requirements VALUES(4073,572,'level2',1,'Understand what each of the following renewable energy sources are: Solar Energy Wind Energy Geothermal Energy Bioenergy Hydropower Ocean Energy Hydrogen and Fuel Cells');
INSERT INTO badge_level_requirements VALUES(4074,572,'level2',2,'Learn how a windmill works and what they were used for in ancient times.  Learn how that is now being parlayed into electrical and mechanical energy in wind farms across the country.');
INSERT INTO badge_level_requirements VALUES(4075,572,'level3',3,'Understand what it means to live off-grid.');
INSERT INTO badge_level_requirements VALUES(4076,572,'level4',4,'Learn about plug-in hybrid automobiles that use both traditional gas and electric modes of power.  Research a hybrid car that doesn’t need to be plugged in. If possible, take a test ride in one and observe the on-screen demonstration of how the car charges while driving.');
INSERT INTO badge_level_requirements VALUES(4077,572,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead');
INSERT INTO badge_level_requirements VALUES(4078,573,'preschool',0,'Learn the definition of this animal group.  What about them classifies them as such?');
INSERT INTO badge_level_requirements VALUES(4079,573,'preschool',1,'Find out as much as you can about the animal group you have chosen in your local environment by reading, observing, and talking to others.  If your chosen animal group does not live in your community, where is the nearest place that they live naturally?');
INSERT INTO badge_level_requirements VALUES(4080,573,'level1',2,'Be able to identify at least 3 species of your animal group.  You may want to look at things like size, shape, color or other distinguishing marks.  Learn about their life cycle, what they eat, how they protect themselves, their calls, and habits.');
INSERT INTO badge_level_requirements VALUES(4081,573,'level2',3,'but identify at least 5 species (If you completed this badge for the same animal group at a different level, you may not use species you have researched in the past.)');
INSERT INTO badge_level_requirements VALUES(4082,573,'level3',4,'If possible, observe your animal category in the wild on at least 3 different occasions.  Take notes on their behavior and compare them to what you have learned.');
INSERT INTO badge_level_requirements VALUES(4083,573,'level3',5,'but identify at least 8 species (If you completed this badge for the same animal group at a different level, you may not use species you have researched in the past.)');
INSERT INTO badge_level_requirements VALUES(4084,573,'level4',6,'If possible, observe your animal category in the wild on at least 5 different occasions.  Take notes on their behavior and compare them to what you have learned.');
INSERT INTO badge_level_requirements VALUES(4085,573,'level4',7,'but identify at least 12 species (If you completed this badge for the same animal group at a different level, you may not use species you have researched in the past.)');
INSERT INTO badge_level_requirements VALUES(4086,573,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4091,576,'preschool',0,'What is responsibility? In what areas are you responsible? In what areas do you need work?');
INSERT INTO badge_level_requirements VALUES(4092,576,'preschool',1,'Commit to doing a new daily chore around the house for a minimum of 1 week. Do not rely on your parent to remind you, but show that you can be responsible to get it done, and get it done right, without complaints and on time.');
INSERT INTO badge_level_requirements VALUES(4093,576,'level1',2,'Choose an area in your life where you need work on being responsible. Maybe you need to be more responsible in keeping your room clean, getting your homework done on time, or completing your chores. Make a chart with the words “Responsible” and “Irresponsible” on each side. At the end of each day put a check on your chart as to whether you were responsible or not in the area of your choice. Do this for two weeks so that you can see improvement as you try to be more responsible.');
INSERT INTO badge_level_requirements VALUES(4094,576,'level1',3,'Commit to doing a new daily chore around the house for a minimum of 1 month. Do not rely on your parent to remind you, but show that you can be responsible to get it done, and get it done right, without complaints and on time.');
INSERT INTO badge_level_requirements VALUES(4095,576,'level2',4,'Choose two areas you need to work on and keep your chart for 3 weeks.');
INSERT INTO badge_level_requirements VALUES(4096,576,'level2',5,'Commit to doing a new chore around the house for a minimum of 2 months. Do not rely on your parent to remind you, but show that you can be responsible to get it done, and get it done right, without complaints and on time.');
INSERT INTO badge_level_requirements VALUES(4097,576,'level3',6,'Choose three areas you need to work on and keep your chart for 4 weeks.');
INSERT INTO badge_level_requirements VALUES(4098,576,'level3',7,'Commit to doing a new chore around the house for a minimum of 3 months. Do not rely on your parent to remind you, but show that you can be responsible to get it done, and get it done right, without complaints and on time.');
INSERT INTO badge_level_requirements VALUES(4099,576,'level4',8,'Choose four areas you need to work on and keep your chart for 6 weeks.');
INSERT INTO badge_level_requirements VALUES(4100,576,'level4',9,'Commit to doing a new chore around the house for a minimum of 4 months. Do not rely on your parent to remind you, but show that you can be responsible to get it done, and get it done right , without complaints and on time.');
INSERT INTO badge_level_requirements VALUES(4101,576,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4102,577,'preschool',0,'Make a list of your favorite restaurants and eat food from one of them.');
INSERT INTO badge_level_requirements VALUES(4103,577,'preschool',1,'Tell someone about your favorite restaurant and why it is your favorite.');
INSERT INTO badge_level_requirements VALUES(4104,577,'level1',2,'Come up with an idea for a restaurant of your own. Tell someone about what kind of food you would serve, the restaurant’s name, the restaurant’s logo, and anything else you create, such as the decor theme.');
INSERT INTO badge_level_requirements VALUES(4105,577,'level2',3,'Learn the differences between chain, franchise, and independent restaurants. What are the advantages/disadvantages to each? If you were to open a restaurant, which one would you choose?');
INSERT INTO badge_level_requirements VALUES(4106,577,'level3',4,'Learn how the fast food industry started. Write a short essay or create a presentation about it. How did fast food change the restaurant industry?');
INSERT INTO badge_level_requirements VALUES(4107,577,'level4',5,'Learn about the Michelin Guide and how the Michelin Stars work. Why are the Michelin Stars so highly valued?');
INSERT INTO badge_level_requirements VALUES(4108,577,'level5',6,'Teach someone knowledge about this badge. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4109,578,'preschool',0,'What is your favorite food from your restaurant? Why is it your favorite? Tell someone about it.');
INSERT INTO badge_level_requirements VALUES(4110,578,'preschool',1,'Eat a meal from your chosen restaurant. How should you behave in a restaurant?');
INSERT INTO badge_level_requirements VALUES(4111,578,'level1',2,'Learn if your restaurant does dine-in, take-out, deliver, etc. What are some of the advantages and disadvantages of each?');
INSERT INTO badge_level_requirements VALUES(4112,578,'level2',3,'Learn the history behind your restaurant. When was it opened? How did they pick their name? Why do they serve the type of food they do? Who owns it now? Tell your family, friends, or group what you learned.');
INSERT INTO badge_level_requirements VALUES(4113,578,'level3',4,'Learn the differences between chain, franchise, and independent restaurants. Which is your chosen restaurant? What are some advantages and disadvantages to each? Tell your family, friends, or group what you learned.');
INSERT INTO badge_level_requirements VALUES(4114,578,'level4',5,'Try to cook one of the dishes your chosen restaurant serves. Do you like your version better or worse?');
INSERT INTO badge_level_requirements VALUES(4115,578,'level5',6,'Teach someone knowledge about this badge. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4116,579,'preschool',0,'Know what rice is and how it is cooked.  Is it safe to eat raw?  Why not?');
INSERT INTO badge_level_requirements VALUES(4117,579,'preschool',1,'Try at least 4 different types of rice such as basmati, jasmine, wild rice, and Arborio.');
INSERT INTO badge_level_requirements VALUES(4118,579,'level1',2,'Help to cook at least 3 different rice recipes.  At least one should be savory and one should be sweet.  Discuss why the recipe may call for a specific type of rice.  What is the difference between a whole grain rice like brown rice and a processed white rice?');
INSERT INTO badge_level_requirements VALUES(4119,579,'level2',3,'Learn about the origin of rice and create a map highlighting the top rice-producing countries in the world.');
INSERT INTO badge_level_requirements VALUES(4120,579,'level3',4,'Learn how to cook rice.  Research the nutritional value of rice and how it fits into a balanced diet.  Compare the cooking times and water ratios for different types of rice.');
INSERT INTO badge_level_requirements VALUES(4121,579,'level4',5,'Research the environmental impact of rice farming and ways to make it sustainable.');
INSERT INTO badge_level_requirements VALUES(4122,579,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4123,580,'preschool',0,'Decide on your destination and find it on a map. Learn how long it will take to drive there and back.');
INSERT INTO badge_level_requirements VALUES(4124,580,'preschool',1,'Learn three games that can be played in the car on a road trip.');
INSERT INTO badge_level_requirements VALUES(4125,580,'level1',2,'Plan, prepare, and serve a meal to be eaten with a minimum of mess while a car is moving.');
INSERT INTO badge_level_requirements VALUES(4126,580,'level2',3,'Learn how to use a map app/GPS device and a printed map. Drive to a destination you’ve never been before by listening to the audio directions from an app or GPS device. Then, drive back home using a printed map. Which method do you prefer?');
INSERT INTO badge_level_requirements VALUES(4127,580,'level3',4,'Map out your trip. Figure out how many hours you will be driving in a day and when you should stop for the night. Create an itinerary and check list. Suggestions include: Snacks you will need – water, fruit, nuts, chips, etc. Will you need a cooler? How much gas will cost. Compare prices for hotels or campsites. Learn where any attractions you wish to see along the way are located. Will you play games to pass the time? Read? Tell stories? Plan some fun activities to do along the way. Make sure to pack books, coloring paper, tablets, etc to keep occupied. Check all luggage and make sure you have everything you need. Toiletries, enough clothing, any electronic devices and their chargers, money, a map, etc.');
INSERT INTO badge_level_requirements VALUES(4128,580,'level4',5,'Do the driving for at least one day of the trip. If you do not have your license yet, assist the driver for the entirety of the trip. This includes: pumping gas at the gas station, following the map or GPS device, going the correct speed limit, paying attention the road, making sure the headlights are on at night, etc.');
INSERT INTO badge_level_requirements VALUES(4129,580,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional requirement:');
INSERT INTO badge_level_requirements VALUES(4130,581,'preschool',0,'Discuss what a robot is. Do you have any in your home?');
INSERT INTO badge_level_requirements VALUES(4131,581,'preschool',1,'Discuss how robots move, such as programmed into a computer, motion sensors, gears, motors, etc.');
INSERT INTO badge_level_requirements VALUES(4132,581,'level1',2,'What do we use robots for?');
INSERT INTO badge_level_requirements VALUES(4133,581,'level2',3,'Discuss the history of robots and the field of robotics. Make a timeline with at least 10 important events in the evolution and creation of robotics.');
INSERT INTO badge_level_requirements VALUES(4134,581,'level3',4,'Design a robot you would like to build. Write a story about what your robot does and how it would make your life easier or different. Use Lego’s, a computer program, or anything else you find in your household to build a prototype of you robot.');
INSERT INTO badge_level_requirements VALUES(4135,581,'level4',5,'Learn about three of the five major fields of robotics and their importance to robotic development. Find pictures or videos to help you learn. The five fields are: Human-robot interface Mobility Manipulation Programming Sensors');
INSERT INTO badge_level_requirements VALUES(4136,581,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4137,582,'preschool',0,'Discuss why it is important to always rock climb with an adult. What kind of injuries can occur during rock climbing? Learn to dress appropriately for rock climbing. Should you wear a helmet? What kind of footwear should you wear? How about gloves? Learn all safety rules. Why is it important to follow these rules?');
INSERT INTO badge_level_requirements VALUES(4138,582,'preschool',1,'Go rock climbing on an artificial rock climbing wall or  boulder with the help of an adult. Learn the Leave No Trace principles and explain what they mean.');
INSERT INTO badge_level_requirements VALUES(4139,582,'level1',2,'Find out what role each person plays in climbing and what their responsibilities are: Climbers Rappellers Belayers Boulderers and their spotters');
INSERT INTO badge_level_requirements VALUES(4140,582,'level2',3,'Explain the importance of using verbal signals when climbing.   Demonstrate the verbal signals of each of the following: Climbers Rappellers Belayers Boulderers and their spotters');
INSERT INTO badge_level_requirements VALUES(4141,582,'level2',4,'Learn what you should do in case of an emergency on the wall. Learn first aid for injuries or illnesses that could occur during climbing activities, including heat and cold reactions, dehydration, stopped breathing, abrasions, sprains, rope burns, blisters, snakebites, fractures, and insect bites or stings. Know how to summon help to the climbing area in case of an emergency.');
INSERT INTO badge_level_requirements VALUES(4142,582,'level3',5,'Show the correct way to directly tie into a belay rope. Climb at least three different routes on a rock face or climbing wall, demonstrating good technique and using verbal signals with a belayer.');
INSERT INTO badge_level_requirements VALUES(4143,582,'level3',6,'Describe the kinds of rope acceptable for use in climbing and rappelling.  Show how to examine a rope for signs of wear or damage.   Discuss ways to prevent a rope from being damaged. Explain when and how a rope should be retired. Properly coil a rope. Learn the following knots used for rock climbing, belaying, and repelling. What are they used for? Figure eight on a bight Figure eight follow-through Water knot Double fisherman’s knot (grapevine knot) Safety knot');
INSERT INTO badge_level_requirements VALUES(4144,582,'level4',7,'Learn how to evaluate the safety of a particular area. Consider the weather, visibility, condition of climbing surface, as well as any of environmental hazards.  Learn to properly store your gear, harness, ropes, helmets.  Climb a rock face using at least three different routes.');
INSERT INTO badge_level_requirements VALUES(4145,582,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4146,583,'preschool',0,'What is a rocket? Be able to identify a rocket from a photograph.');
INSERT INTO badge_level_requirements VALUES(4147,583,'level1',1,'Discover the intention behind the first rockets and be able to tell their primary use today.');
INSERT INTO badge_level_requirements VALUES(4148,583,'level2',2,'What were two recent events involving rockets? Discuss them with an adult.');
INSERT INTO badge_level_requirements VALUES(4149,583,'level3',3,'Discuss at least three positive things and three negative things rockets have contributed to our world.');
INSERT INTO badge_level_requirements VALUES(4150,583,'level4',4,'Visit a hobby shop and view different parts available for rocket building. What are the primary tools you need to build a rocket? What different kinds of engines, models, and features are available? Build your own rocket and show your model to your family, friends, or group.');
INSERT INTO badge_level_requirements VALUES(4151,583,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4152,584,'preschool',0,'Go outside and find three different rocks. Answer the following questions: Where did you find each one? What color is it? Are there any patterns in your rock such as stripes or flecks? Is it heavy or light? Does it break easily?');
INSERT INTO badge_level_requirements VALUES(4153,584,'preschool',1,'Collect at least 20 small rocks and sort them by color, shape, or size.');
INSERT INTO badge_level_requirements VALUES(4154,584,'level1',2,'Draw the different layers of the earth.');
INSERT INTO badge_level_requirements VALUES(4155,584,'level2',3,'Find out the names of at least three of your rocks.');
INSERT INTO badge_level_requirements VALUES(4156,584,'level2',4,'Understand the difference between igneous, sedimentary, and metamorphic rocks and how each are formed.');
INSERT INTO badge_level_requirements VALUES(4157,584,'level3',5,'Know the names of at least 5 rocks you have collected. For each of the 5 rocks you identified, answer the following questions: Where did it come from? What is the name of your specimen? What color is it? Do we make use of it? If so, how? Is it igneous, sedimentary, or metamorphic? Is it hard or soft? Is it heavy or light as compared to aluminum or lead? Does it contain visible minerals? If so, what?');
INSERT INTO badge_level_requirements VALUES(4158,584,'level3',6,'Understand the difference between a rock and a mineral. Make a list of at least 50 minerals and learn about at least 5 of them.');
INSERT INTO badge_level_requirements VALUES(4159,584,'level4',7,'Learn about the history of minerals such as gold, silver, and copper and how they have effected various cultures.');
INSERT INTO badge_level_requirements VALUES(4160,584,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4161,585,'preschool',0,'Learn what a rodeo is. What kinds of animals are used in rodeos?');
INSERT INTO badge_level_requirements VALUES(4162,585,'level1',1,'Which is your favorite animal in the rodeo?');
INSERT INTO badge_level_requirements VALUES(4163,585,'level1',2,'Learn about the different events featured in a rodeo and how rodeos first began. What is the purpose of each event?');
INSERT INTO badge_level_requirements VALUES(4164,585,'level2',3,'Make a list of items that are used by cowboys/cowgirls during a rodeo, such as saddles, bridles, lassos, chaps, spurs, etc.');
INSERT INTO badge_level_requirements VALUES(4165,585,'level2',4,'Make a timeline of rodeo history. You must have at least 10 dates on your timeline.');
INSERT INTO badge_level_requirements VALUES(4166,585,'level3',5,'You must have at least 15 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(4167,585,'level3',6,'Read a biography of a famous rodeo rider or clown.');
INSERT INTO badge_level_requirements VALUES(4168,585,'level4',7,'You must have at least 20 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(4169,585,'level4',8,'Research a famous rodeo in history. Tell your family, friends, or group what you learned.');
INSERT INTO badge_level_requirements VALUES(4170,585,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4171,586,'preschool',0,'What is a roller coaster? Be able to recognize one from a picture.');
INSERT INTO badge_level_requirements VALUES(4172,586,'level1',1,'Find pictures of six different roller coasters. Where are they located? Find them on a map. What makes each one unique?');
INSERT INTO badge_level_requirements VALUES(4173,586,'level2',2,'Learn the history of roller coasters.');
INSERT INTO badge_level_requirements VALUES(4174,586,'level3',3,'Find out what effect a roller coaster has on your body. Why do you feel like your stomach is rising when you fall? What is a G Force? What is inertia?');
INSERT INTO badge_level_requirements VALUES(4175,586,'level4',4,'Explain the role that potential energy and kinetic energy play in the operation of a roller coaster? What is Newton’s First Law of Motion, and how does it relate to roller coasters?');
INSERT INTO badge_level_requirements VALUES(4176,586,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4177,587,'preschool',0,'Understand what Route 66 is and why it is an important road.');
INSERT INTO badge_level_requirements VALUES(4178,587,'preschool',1,'Visit a museum or exhibit relating to Route 66 either in person or online with the permission of a parent.');
INSERT INTO badge_level_requirements VALUES(4179,587,'level1',2,'Trace Route 66 on a map from its starting point to its finish. Which states does it cross?');
INSERT INTO badge_level_requirements VALUES(4180,587,'level2',3,'Learn the history of Route 66. Create a timeline with at least 10 events.');
INSERT INTO badge_level_requirements VALUES(4181,587,'level3',4,'Be able to explain why Route 66 died. What was the result for many towns along the route?');
INSERT INTO badge_level_requirements VALUES(4182,587,'level4',5,'Learn why was this route is popular among tourists and truck drivers.');
INSERT INTO badge_level_requirements VALUES(4183,587,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4188,590,'preschool',0,'Know what saints are.  Learn the full name of your chosen saint and what they are known for. Look at a picture of your person. Learn a miracle or a good work that led to their canonization.');
INSERT INTO badge_level_requirements VALUES(4189,590,'level1',1,'Understand the difference between a biography and an autobiography. Know where your person was born and raised, when they were born and when they died. Know their feast day and canonization day.');
INSERT INTO badge_level_requirements VALUES(4190,590,'level1',2,'If your chosen saint created something such as an invention or artwork, view pictures of they did and be able to identify what they are. If they are famous for something they said, or wrote, listen to their speech or read their book.  Whatever they are known for, be able to identify their specific work. If possible, find pictures or information on prototypes or earlier works as well.');
INSERT INTO badge_level_requirements VALUES(4191,590,'level2',3,'Create a timeline of childhood events, turning points, special events, and accomplishments in your saint’s life. Include at least 10 items in your timeline and be able to explain why each is important.');
INSERT INTO badge_level_requirements VALUES(4192,590,'level3',4,'Read a biography or autobiography about your chosen saint’s life.');
INSERT INTO badge_level_requirements VALUES(4193,590,'level4',5,'Write an essay about your chosen saint and how their accomplishments affect the world today.');
INSERT INTO badge_level_requirements VALUES(4194,590,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4197,592,'preschool',0,'Make a green salad by tearing larger leaves or washing & draining small leaves. This can be a one-person salad or a larger one. Garnish the salad with at least one food of a contrasting color.');
INSERT INTO badge_level_requirements VALUES(4198,592,'level1',1,'Make sure you also have at least two different textures or tastes (bland and salty, sweet and sour) in your green salad.');
INSERT INTO badge_level_requirements VALUES(4199,592,'level1',2,'Discuss knife safety. Make a vegetable salad that includes some cooked vegetables easy to cut.');
INSERT INTO badge_level_requirements VALUES(4200,592,'level2',3,'Learn how to cut a wedge of iceberg lettuce and enhance its presentation. Make a fruit salad without adding any sugar to the fruit.');
INSERT INTO badge_level_requirements VALUES(4201,592,'level3',4,'Make a main dish salad that includes a full serving of meat (or complimentary proteins for vegetarians).');
INSERT INTO badge_level_requirements VALUES(4202,592,'level4',5,'Discuss how to store and keep cold various kinds of salads. What are the hazards of not having your salad cold enough? Can you think of any salads that can be served warm? What are the disadvantages and advantages of different kinds of storage containers?');
INSERT INTO badge_level_requirements VALUES(4203,592,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4204,593,'preschool',0,'Know what the Salem Witch Trials were.');
INSERT INTO badge_level_requirements VALUES(4205,593,'level1',1,'Read about people involved in the Salem Witch Trials.');
INSERT INTO badge_level_requirements VALUES(4206,593,'level2',2,'Know when and where the Salem Witch Trials took place. Know who the first person accused was, who accused her and why.');
INSERT INTO badge_level_requirements VALUES(4207,593,'level2',3,'Create a timeline of 10 events leading up to and during the Salem Witch Trials.');
INSERT INTO badge_level_requirements VALUES(4208,593,'level3',4,'Be able to locate Salem on a map. Have 15 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(4209,593,'level3',5,'Learn about different theories about what caused the Salem Witch Trials. Which do you think best explains it?');
INSERT INTO badge_level_requirements VALUES(4210,593,'level4',6,'Have 20 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(4211,593,'level4',7,'Learn about different tests that were used to prove someone was a witch. Do you think these tests were fair?');
INSERT INTO badge_level_requirements VALUES(4212,593,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4213,594,'preschool',0,'Try two different sandwiches with different fillings. Which one did you like better? Why?');
INSERT INTO badge_level_requirements VALUES(4214,594,'preschool',1,'Help someone make a sandwich. You can help by placing cheese or meat on the bread, spreading the filling on the bread, or putting the two pieces of bread together.');
INSERT INTO badge_level_requirements VALUES(4215,594,'level1',2,'Learn to make peanut butter and jelly sandwiches without getting the outside of the sandwich messy. Learn to clean up afterwards. What are some ways to keep crumbs out of your peanut butter and jelly? Why does your family store bread, peanut butter, and jelly the way they do?');
INSERT INTO badge_level_requirements VALUES(4216,594,'level1',3,'Try a kind of sandwich you’ve never had before. You don’t need to make it yourself.');
INSERT INTO badge_level_requirements VALUES(4217,594,'level2',4,'Learn to make meat and cheese sandwiches with pre-sliced meat and cheese. Learn to adjust condiments and their amounts to please different tastes. What are some fruits and vegetables that are tasty additions to sandwiches?');
INSERT INTO badge_level_requirements VALUES(4218,594,'level2',5,'Learn the history of sandwiches. Create a timeline with at least 10 events.');
INSERT INTO badge_level_requirements VALUES(4219,594,'level3',6,'Learn to make 3 different spreadable sandwich fillings.');
INSERT INTO badge_level_requirements VALUES(4220,594,'level3',7,'Learn to make fancy sandwiches in different shapes, double and triple decker sandwiches for tea parties, and sandwiches decorated with cream cheese “icing” or garnishes.');
INSERT INTO badge_level_requirements VALUES(4221,594,'level4',8,'Make the bread for a sandwich. This can be brioche, English muffins, biscuits, or crackers and well as sliced sandwich bread. Discuss the pros and cons, including nutritional, of several types of bread as relating to sandwiches. Take a filling and make it into sandwiches using more than one type of bread. Compare your results.');
INSERT INTO badge_level_requirements VALUES(4222,594,'level4',9,'Help make sandwiches for a large group of people. Make at least twenty sandwiches. This can be in an assembly line. Learn to slice neatly in more than one way roast meat, cheese, and bread.');
INSERT INTO badge_level_requirements VALUES(4223,594,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4224,595,'preschool',0,'What are scavenger hunts?  What is the difference between a scavenger hunt and a treasure hunt?');
INSERT INTO badge_level_requirements VALUES(4225,595,'preschool',1,'Participate in a scavenger hunt with your family, friends, or group in addition to your optional requirements.');
INSERT INTO badge_level_requirements VALUES(4226,595,'level1',2,'Research the benefits of scavenger hunts and list the ways they can exercise both your mind and body.');
INSERT INTO badge_level_requirements VALUES(4227,595,'level2',3,'Where did scavenger hunts originate and when did they become popular?');
INSERT INTO badge_level_requirements VALUES(4228,595,'level2',4,'Create and organize a scavenger hunt of at least 15 items for others to complete.');
INSERT INTO badge_level_requirements VALUES(4229,595,'level3',5,'Complete a neighborhood scavenger hunt that you find online (with a parent’s permission) or one that someone created for you.');
INSERT INTO badge_level_requirements VALUES(4230,595,'level4',6,'Create a scavenger hunt for visitors to your community to discover the wonders of your town/city. You can even give your scavenger hunt to your city to use for tourism.');
INSERT INTO badge_level_requirements VALUES(4231,595,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4234,597,'preschool',0,'Read a Scooby Doo book. Who is Scooby Doo? What kind of animal is he?');
INSERT INTO badge_level_requirements VALUES(4235,597,'preschool',1,'Watch a Scooby Doo movie or television episode. What was your favorite part?');
INSERT INTO badge_level_requirements VALUES(4236,597,'level1',2,'(read 2 Scooby doo books)');
INSERT INTO badge_level_requirements VALUES(4237,597,'level1',3,'Learn the names of the Mystery Inc. members. How did they begin? Where did they find Scooby Doo?');
INSERT INTO badge_level_requirements VALUES(4238,597,'level2',4,'Watch one of the Scooby Doo movies. Who was the villain, and what was the motive behind what they were doing? Did they have accomplices or were they working alone?');
INSERT INTO badge_level_requirements VALUES(4239,597,'level3',5,'Write your own Scooby Doo story. In what part of the world will Mystery Inc be? Include some history about the area in that Mystery Inc. is visiting. What type of foods would Shaggy and Scooby Doo eat in this region of the world?');
INSERT INTO badge_level_requirements VALUES(4240,597,'level4',6,'Make a timeline of Scooby Doo illustrations over time. How many times has the dog''s illustration changed over the years and in which ways? How many people have played the voice of Scooby Doo over the course of the dog''s character years?');
INSERT INTO badge_level_requirements VALUES(4241,597,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your newfound knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4244,599,'preschool',0,'Learn what a scrapbook is. What can a scrapbook contain? Look through a scrapbook and see how many different sorts of things have been used to make the pages more interesting.');
INSERT INTO badge_level_requirements VALUES(4245,599,'preschool',1,'With help, create a scrapbook page using at least two photographs and various other decorative papers etc to make it attractive. Don’t forget to write a brief description about your photographs so that someone else looking at your page will know who is in the pictures, where they were taken and when (the writing can be done by person who is helping you if you need help).');
INSERT INTO badge_level_requirements VALUES(4246,599,'level1',2,'Do Preschool 1 & 2. Create a scrapbook page. This can be as a gift for someone or as a remembrance for yourself. Use at least two different papers and 2 different embellishments.');
INSERT INTO badge_level_requirements VALUES(4247,599,'level1',3,'Cropping pictures means to cut out a portion of the picture that you do not want in your scrapbook. Sometimes the picture is simply too big for the page, other times there may be too much background, or maybe you just want to capture someone’s face. Practice cropping pictures using at least 3 of the following methods. Trim a picture to a smaller square or rectangle using a paper cutter or carefully with scissors. Use patterned scissors to add a decorative edge to your photo. Cut out a person or object. Trim away unnecessary background. Use a stencil to trace and cut your picture into a shape such as a heart, circle, etc. Use a large punch to punch out a portion of your picture Use the computer to digitally crop a picture into a smaller rectangle or square. Use a computer to crop your picture into a shape such as a heart, circle, etc. Use a computer to cut out a person or object. Use a computer to crop unnecessary background.');
INSERT INTO badge_level_requirements VALUES(4248,599,'level2',4,'Be able to explain what the following scrapbook terms mean: Photo Safe Archival Quality Layout Journaling Embellishment Texture Acid Free');
INSERT INTO badge_level_requirements VALUES(4249,599,'level3',5,'Learn how to protect your photos. Find out why the following items should never be used in scrapbooking: Paper containing acid and or lignin or paper that is not pH balanced or buffered Recycled Papers Using a liquid adhesive on your photos Photo corner, plastic overlays & pocket pages containing PVC (Poly Vinyl Chloride) Mixing too many adhesive products in your albums Ballpoint pen and felt tip pen inks Adhesives that become brittle with age causing your items to pop off the page (paper cement, rubber cement, glue sticks)');
INSERT INTO badge_level_requirements VALUES(4250,599,'level4',6,'Learn how to apply the basics of good design to your scrapbook layouts, such as line, shape, color, texture, direction, value, and size.');
INSERT INTO badge_level_requirements VALUES(4251,599,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4252,600,'preschool',0,'What is sculpture? Look at different types of sculpture such as carvings, clay, wire, kinetic, abstract, and mixed media.');
INSERT INTO badge_level_requirements VALUES(4253,600,'preschool',1,'Make a sculpture from play dough or other media.');
INSERT INTO badge_level_requirements VALUES(4254,600,'level1',2,'Go on a sculpture hunt. How many pieces of sculpture can you find in your house? Around your town?');
INSERT INTO badge_level_requirements VALUES(4255,600,'level2',3,'Learn about the different types of clay, such as polymer, plasticine, air-dry, baked, salt dough, etc. Make at least two sculptures, each using a different type of clay.  Which did you like better?  Why?');
INSERT INTO badge_level_requirements VALUES(4256,600,'level3',4,'Research the steps to making fired ceramics from clay. If possible tour a clay studio in person or online to see the steps. If possible make a sculpture and have it fired.');
INSERT INTO badge_level_requirements VALUES(4257,600,'level4',5,'Do Level 3 requirements number 1 & 2.');
INSERT INTO badge_level_requirements VALUES(4258,600,'level4',6,'Make a timeline about famous sculptors. Make sure your timeline includes at least 15 events/dates.');
INSERT INTO badge_level_requirements VALUES(4259,600,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4260,601,'preschool',0,'Look through someone’s seashell collection and learn what type of animals lived in the shells.');
INSERT INTO badge_level_requirements VALUES(4261,601,'preschool',1,'Learn safety procedures and laws for seashell collecting.');
INSERT INTO badge_level_requirements VALUES(4262,601,'level1',2,'Learn how to properly clean seashells.');
INSERT INTO badge_level_requirements VALUES(4263,601,'level2',3,'Find out what seashells are made of and how they grow.  Learn why they grow in different shapes.  Why would one animal grow a spiral shell while another grows a hinged shell like a clam?');
INSERT INTO badge_level_requirements VALUES(4264,601,'level3',4,'Check out the rules concerning shell collecting in the areas you might like to collect shells in.  Some places don’t allow collecting or allow it only during certain times of year.  Some require permits. The local park service is a good place to start looking for information.');
INSERT INTO badge_level_requirements VALUES(4265,601,'level4',5,'Know how to identify a mollusk and each of the major mollusk families.');
INSERT INTO badge_level_requirements VALUES(4266,601,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4267,603,'preschool',0,'What type of weather can you expect during your chosen season? What type of clothing is appropriate?');
INSERT INTO badge_level_requirements VALUES(4268,603,'preschool',1,'What colors are associated with your season?');
INSERT INTO badge_level_requirements VALUES(4269,603,'level1',2,'Know when your season officially begins and ends. What causes the seasons? What is happening with the Sun and the Earth during the season you chose?');
INSERT INTO badge_level_requirements VALUES(4270,603,'level2',3,'Keep a weather log for at least one week. Every day record the following information: • Temperature • Cloud type • Wind speed and direction • Rain fall/Snow fall Is this typical weather for this time of year?');
INSERT INTO badge_level_requirements VALUES(4271,603,'level3',4,'Know how your season affects your community. Does it affect tourism? Agriculture? Transportation?');
INSERT INTO badge_level_requirements VALUES(4272,603,'level4',5,'Learn about a seasonal job in your community. This might be a holiday retail position, a seasonal agricultural position, or even a summer lifeguard. How old do you have to be to apply for this position? What experience do you have to have? What does it pay? How long do you work?');
INSERT INTO badge_level_requirements VALUES(4273,603,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4274,604,'preschool',0,'Learn what a seed is and where it comes from.');
INSERT INTO badge_level_requirements VALUES(4275,604,'preschool',1,'Plant a seed and help care for it as it grows.');
INSERT INTO badge_level_requirements VALUES(4276,604,'level1',2,'Learn what seeds need to grow. Try placing seeds in different environments (light vs. dark, wet vs. dry) and observe what happens.');
INSERT INTO badge_level_requirements VALUES(4277,604,'level2',3,'Learn about the parts of a seed (such as seed coat, embryo, and cotyledon). Open a dried bean or soaked seed and identify its parts.');
INSERT INTO badge_level_requirements VALUES(4278,604,'level3',4,'Learn about the history of seed use by humans. Explore how seeds have been saved, traded, or modified across time and cultures.  Learn what a seed bank is.');
INSERT INTO badge_level_requirements VALUES(4279,604,'level4',5,'Research seed dispersal methods (wind, water, animals, etc.) and create a model or demonstration of at least two ways seeds travel.');
INSERT INTO badge_level_requirements VALUES(4280,604,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(4283,606,'preschool',0,'Learn your full name and be able to tell it to someone. Know the phone number of your parent or guardian.');
INSERT INTO badge_level_requirements VALUES(4284,606,'preschool',1,'Know how to find a safe person who can help you get back to your parents or caregiver if you get lost. Go over some safety tips on how to identify a safe person, such as police officers, store clerks, safety guards, etc.');
INSERT INTO badge_level_requirements VALUES(4285,606,'level1',2,'You must also know the full name of your parents or guardians, and the phone number of one member of your extended family, such as an aunt, uncle, grandparent, or adult sibling. Also learn your home address.');
INSERT INTO badge_level_requirements VALUES(4286,606,'level1',3,'Why shouldn’t you talk to strangers? Is it ever okay to go somewhere with a stranger?');
INSERT INTO badge_level_requirements VALUES(4287,606,'level2',4,'Know how to call 911 and when it is appropriate to do so.');
INSERT INTO badge_level_requirements VALUES(4288,606,'level2',5,'Learn how to stomp on someone’s foot to get away if they try to grab you from behind. Practice yelling for help. Sometimes, when children have been abducted, bystanders have thought they were arguing with their parents or throwing a fit. What can you yell so people know this isn’t the case and you are in trouble? Practice scenarios such as this.');
INSERT INTO badge_level_requirements VALUES(4289,606,'level3',6,'Learn three self-defense moves, including the one from Level 2 requirement 2.');
INSERT INTO badge_level_requirements VALUES(4290,606,'level3',7,'Learn what to do if you think someone is following you. What can you do in a situation like this? How can you tell whether a neighborhood is safe to walk alone in? Why shouldn’t you wear headphones or earbuds while out alone? Also, learn what to do if you think you hear prowlers outside, or if you think there is someone in your home or the home where you’re babysitting. Under what situations should you investigate further? How would you escape or get help?');
INSERT INTO badge_level_requirements VALUES(4291,606,'level4',8,'Learn safety rules for moving out on your own, including: Change the locks – you don’t know who might have had a key before you moved in. Get a lock for your bedroom door. Make sure you have a phone in your room. Have something in your room that you could use to defend yourself in an emergency, such as a baseball bat or heavy object. Do not give a copy of your key to someone unless you absolutely trust them. Even if they give your key back to you, anyone can have a copy made in just a few minutes. Be cautious. Make sure your daily routine is not too predictable – try leaving and coming back home at different times, and use different routes to go places.');
INSERT INTO badge_level_requirements VALUES(4292,606,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4297,609,'preschool',0,'Learn the difference between sewing by hand and using a sewing machine. Watch a parent, adult, or older sibling or group member demonstrate both. Which is faster?  Be able to identify a needle, thread, thimble, scissors and fabric. Learn basic stitching using a lacing card.  You can use either a shoelace or yarn and blunt yarn needle as your needle and thread.');
INSERT INTO badge_level_requirements VALUES(4298,609,'preschool',1,'Learn basic safety when sewing.  Why should you be careful not to drop needles and pins on the floor?  Is it safe to play with needles or a sewing machine without an adult’s supervision?  Why or why not? How should you care for someone who has accidentally stuck his or her finger with a needle?');
INSERT INTO badge_level_requirements VALUES(4299,609,'level1',2,'Also, identify and describe the uses of these sewing tools: Scissors Measuring tape Pinking shears Pins Needles Seam ripper Pin cushion Thimble Also identify these sewing materials and describe how they would be used: Fabric (both knit and woven) Thread Velcro Felt Stuffing Patterns Accessories such as buttons, snaps, zippers, hooks, and eyes.');
INSERT INTO badge_level_requirements VALUES(4300,609,'level1',3,'Using hand sewing make a small pillow, bean bag, sachet, or stuffed toy. Using old clothes such as t-shirts or jeans can be a great source of material for these projects.');
INSERT INTO badge_level_requirements VALUES(4301,609,'level2',4,'Identify parts of a sewing machine and demonstrate the following: Winding thread onto a bobbin and inserting it into its holder. Threading the machine. Putting the presser foot up and down, and telling when it should be in each position. Stitching a straight line. Stitching a curved line. Stitching a right angle corner. Laying a pattern on some fabric and cutting out the project.');
INSERT INTO badge_level_requirements VALUES(4302,609,'level3',5,'Demonstrate the following kinds of hand sewing stitches, and explain when each would be used: Basting Whip stitch Blind hem Sewing on a button, snap, or hook and eye.');
INSERT INTO badge_level_requirements VALUES(4303,609,'level4',6,'Be able to define the following sewing terms: Clean finishing Back tack Darts Give Nap Notches Basting Test seam Top stitching Appliqué Bar tack Batting Bias Bias tape Bodice Blanket stitch Casing Drape Embellish Fusible Gather Hem Inseam Interfacing Notions Pleat Seam allowance Selvage');
INSERT INTO badge_level_requirements VALUES(4304,609,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4305,610,'preschool',0,'Using a flashlight, hold up various items in front of a white piece of paper to see what shape their shadow is.  How does the shadow change if you spin the object a different direction?');
INSERT INTO badge_level_requirements VALUES(4306,610,'preschool',1,'Make a shadow puppet show using your hands or paper cutouts.');
INSERT INTO badge_level_requirements VALUES(4307,610,'level1',2,'Explore how thin paper or fabric changes the look of shadows when placed in front of a light source.');
INSERT INTO badge_level_requirements VALUES(4308,610,'level2',3,'Learn five vocabulary words related to shadow art such as silhouette, contrast, backlight, projection, and light source, two-dimensional, or transparency.');
INSERT INTO badge_level_requirements VALUES(4309,610,'level3',4,'Learn about the history of shadow puppetry and shadow art in at least one culture (such as Indonesian Wayang Kulit, Chinese shadow plays, or early European shadow theaters).');
INSERT INTO badge_level_requirements VALUES(4310,610,'level4',5,'Create a shadow art performance or installation. You may create a short play using puppets or hands, design a scene with dramatic shadows, choreograph a dance that relies on shadows or display an art piece that relies on shadow to complete the image.');
INSERT INTO badge_level_requirements VALUES(4311,610,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(4312,611,'preschool',0,'Find out what the show Shark Tank is about and watch an episode.');
INSERT INTO badge_level_requirements VALUES(4313,611,'preschool',1,'Understand the concept of buying and selling things.');
INSERT INTO badge_level_requirements VALUES(4314,611,'level1',2,'Watch at least 3 different episodes of Shark Tank. What was your favorite product and why? If you wanted to go on the show, what would you sell?');
INSERT INTO badge_level_requirements VALUES(4315,611,'level2',3,'Create a timeline for the Shark Tank TV show that begins with the other international shows it was based on. Include at least 10 items.');
INSERT INTO badge_level_requirements VALUES(4316,611,'level3',4,'Research each of the six main Sharks. Who are they? How did they become wealthy investors? What is their specialty?');
INSERT INTO badge_level_requirements VALUES(4317,611,'level4',5,'Understand the following business terms: entrepreneur, patent, patent pending, utility patent, equity, valuation, gross sales, net sales, royalty, revenue, overhead, profit and line of credit.');
INSERT INTO badge_level_requirements VALUES(4318,611,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4319,612,'preschool',0,'Learn about the goals and objectives of the Shells for Stacey project and why it was started.');
INSERT INTO badge_level_requirements VALUES(4320,612,'preschool',1,'Paint and and hide a shell for someone to find.');
INSERT INTO badge_level_requirements VALUES(4321,612,'level1',2,'There are many places you are not allowed to leave painted shells, like National Parks.  Learn the principles of Leave No Trace and discuss how you can hide shells and still respect nature and our environment.  If you plan to hide a shell on private property, make sure to get permission first. Discuss places you can legally leave shells and go hide one or more.');
INSERT INTO badge_level_requirements VALUES(4322,612,'level2',3,'Learn about what Down Syndrome and  Alzheimer’s is and how they effect behavior and memory.');
INSERT INTO badge_level_requirements VALUES(4323,612,'level3',4,'Learn about the genetic link between Down syndrome and Alzheimer’s.  Which chromosome affects both Down Syndrome and Alzheimer’s and what does it do?');
INSERT INTO badge_level_requirements VALUES(4324,612,'level4',5,'Learn about the impact of Down Syndrome and Alzheimer’s on individuals, families, and communities.');
INSERT INTO badge_level_requirements VALUES(4325,612,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4328,614,'preschool',0,'Learn who Shirley Temple was.');
INSERT INTO badge_level_requirements VALUES(4329,614,'preschool',1,'List two things that Shirley Temple was famous for.');
INSERT INTO badge_level_requirements VALUES(4330,614,'level1',2,'Watch at least two of her movies.');
INSERT INTO badge_level_requirements VALUES(4331,614,'level2',3,'List the 5 “professions” Shirley held during her lifetime.');
INSERT INTO badge_level_requirements VALUES(4332,614,'level3',4,'Learn about the background of one of her movies. When did it come out, how much were the production costs, and what did the film net?');
INSERT INTO badge_level_requirements VALUES(4333,614,'level4',5,'Discuss why Shirley was so popular in America.');
INSERT INTO badge_level_requirements VALUES(4334,614,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4335,615,'preschool',0,'Why do we wear shoes?  Look at real shoes or pictures of shoes and explain what the various shoes might be used for.  What type of weather might they be good for?  Be able to identify at least 5 types of shoes.  Some shoe examples are listed below: High Heels Athletic Shoes Sandals Flip Flops Rubber Boots Snow Boots Flat Dress Shoes Cowboy Boots Riding Boots Loafers Work Boots Slippers');
INSERT INTO badge_level_requirements VALUES(4336,615,'level1',1,'Learn how shoes are made. What is the name of a person who made shoes?');
INSERT INTO badge_level_requirements VALUES(4337,615,'level2',2,'Identify at least 10 different types of shoes.');
INSERT INTO badge_level_requirements VALUES(4338,615,'level2',3,'Learn about the history of shoes.  When did mankind first start wearing them?  How have they evolved?');
INSERT INTO badge_level_requirements VALUES(4339,615,'level3',4,'Choose one type of shoes and create a picture timeline to show how the style has changed over the years.');
INSERT INTO badge_level_requirements VALUES(4340,615,'level4',5,'Learn about good foot health.  How do what shoes you wear affect your feet?  Learn how to choose appropriate shoes for your feet based on your size, arch, pronation, etc.');
INSERT INTO badge_level_requirements VALUES(4341,615,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4342,616,'preschool',0,'Be able to explain all safety rules when using short flags, including: Always be aware of where your flags are and the space around you. Keep a minimum of arm lengths between you and anyone else at all times when twirling short flags. Never toss your flags around other people or objects until you have mastered the trick.');
INSERT INTO badge_level_requirements VALUES(4343,616,'preschool',1,'Learn to perform at least three non-spinning moves with your flag.');
INSERT INTO badge_level_requirements VALUES(4344,616,'level1',2,'Learn to perform at least three spinning moves with your flag.');
INSERT INTO badge_level_requirements VALUES(4345,616,'level2',3,'What is the history of short flags groups?  Where did they originate?  How many groups are there now?  What are the differences and similarities between baton twirling and short flags?');
INSERT INTO badge_level_requirements VALUES(4346,616,'level3',4,'To what health issues should short flags troops pay attention?  What about nutrition & hydration?  Know what to do about bruises, blisters, sunburn, heat rash, heat exhaustion, and hypothermia.');
INSERT INTO badge_level_requirements VALUES(4347,616,'level4',5,'Do any short flags camps exist?  How much do they cost?  Is there any other way to get concentrated training?  What major competitions are available for short flags?');
INSERT INTO badge_level_requirements VALUES(4348,616,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4349,617,'preschool',0,'Learn what the purpose of sign language is and who uses sign language. As an experiment, watch a few minutes of an unfamiliar television program with the volume turned down to about 1 or 2. How easy is it to understand what the people on TV are saying? This is what listening to people talking can be like for deaf people. Sign language is a visual language that people “listen to” with their eyes instead of their ears.');
INSERT INTO badge_level_requirements VALUES(4350,617,'preschool',1,'With a parent, try to find a video at the library or online of a favorite children’s story presented in sign language and watch it. Learn to spell your first name using the American Sign Language manual alphabet.');
INSERT INTO badge_level_requirements VALUES(4351,617,'level1',2,'Learn the entire alphabet and numbers 1-10 in sign language.');
INSERT INTO badge_level_requirements VALUES(4352,617,'level1',3,'Learn 5 signs for each of the following categories: Foods (fruits, vegetables, hamburger, hot dog, pizza, salad, etc.) Animals (cat, dog, mouse, bird, horse, cow, chicken, sheep, etc) Relationships (family, friend, mother, father, sister, brother, aunt, uncle, etc.) Verbs (run, jump, sing, walk, buy, drive, help, etc) Colors (red, orange, yellow, green, blue, purple, black, brown, white, etc)');
INSERT INTO badge_level_requirements VALUES(4353,617,'level2',4,'Learn 7 signs from each category, including the additional categories listed below. Also learn to sign numbers up to 100. School subjects (English, science, math, reading, etc.) School supplies (pen, pencil, paper, notebook, scissors, crayons, etc.) Types of transportation (bus, car, train, airplane, bicycle, boat, skates, etc.) Emotions (happy, sad, scared, silly, angry, etc.)');
INSERT INTO badge_level_requirements VALUES(4354,617,'level2',5,'Learn to sign the following question words: who, what, when, where, why, how.');
INSERT INTO badge_level_requirements VALUES(4355,617,'level3',6,'Complete Level 2 requirements 1 & 2. Learn 10 signs from each category, including the additional categories listed below. Learn the difference between signing nouns and verbs that look similar (ie: chair vs. sit; food vs. eat; car vs. drive). Also learn to sign numbers up to 1,000 (does not have to be consecutively. Learn to sign 1-100, then how to sign 200, 300, 400, etc.) Common types of jobs (police officer, firefighter, postal worker, doctor, nurse, teacher, etc) Furniture  (chair, sofa, table, desk, bed, dresser, etc) Rooms (living room, kitchen, bedroom, bathroom, office, etc) Common household equipment (camera, computer, television, washer, dryer, oven, etc.)');
INSERT INTO badge_level_requirements VALUES(4356,617,'level3',7,'Learn the proper etiquette when using a sign language interpreter. Who should you look at when conversing? If the setting is formal, such as an interview, what are possible seating arrangements that will show consideration to the deaf individual while not hindering the interpreter’s work? In a large gathering (such as a church service or school assembly) where are possible places an interpreter can be positioned to interpret for several deaf individuals while not being intrusive or distracting to the hearing people? Consider a service project making posters or brochures to educate people about interpreter etiquette.');
INSERT INTO badge_level_requirements VALUES(4357,617,'level4',8,'Complete Level 3 requirements 1 & 2. Learn 15 signs from each category. Think of 15 additional words that relate to your life or the career you want to go into someday that you don’t already know how to sign. Learn to sign those words. Also learn to sign numbers up to 1 million (1-9 thousand, 10-90 thousand, 100-900 thousand, 1 million).');
INSERT INTO badge_level_requirements VALUES(4358,617,'level4',9,'Learn the difference between ASL and signed English. Be able to explain what “facial grammar” is. How is facial grammar different when asking questions beginning with when, where, why, how, what, or who versus a yes/no question? Present a short story in both signed English and in ASL in front of a group of 5 or more people.');
INSERT INTO badge_level_requirements VALUES(4359,617,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4360,618,'preschool',0,'Understand what a simple machine is.');
INSERT INTO badge_level_requirements VALUES(4361,618,'preschool',1,'Be able to identify all six types of simple machines; screw, inclined plane, wedge, lever, wheel and axle, and pulley.');
INSERT INTO badge_level_requirements VALUES(4362,618,'level1',2,'Identify the six types of simple machines and find at least one example of each in your home or community.');
INSERT INTO badge_level_requirements VALUES(4363,618,'level2',3,'Be able to explain how each of the six simple machines makes work easier.');
INSERT INTO badge_level_requirements VALUES(4364,618,'level3',4,'Research a compound machine (like a can opener or a bicycle) that uses multiple simple machines. Draw a diagram labeling the simple machines involved.');
INSERT INTO badge_level_requirements VALUES(4365,618,'level4',5,'Research how simple machines were used in historical structures (like the Egyptian pyramids or medieval catapults).');
INSERT INTO badge_level_requirements VALUES(4366,618,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4367,619,'preschool',0,'Learn to follow a tune.');
INSERT INTO badge_level_requirements VALUES(4368,619,'preschool',1,'Learn a new song from a musical genre (pop, folk, rock and roll, jazz, spiritual, etc.) you are unfamiliar with.');
INSERT INTO badge_level_requirements VALUES(4369,619,'level1',2,'Learn how posture affects singing and learn one singing exercise and one breathing exercise.');
INSERT INTO badge_level_requirements VALUES(4370,619,'level1',3,'Learn at least one new song from four different musical genres, for four songs total.');
INSERT INTO badge_level_requirements VALUES(4371,619,'level2',4,'If you earned this badge before be sure to learn new songs for Level 1 requirement 2.');
INSERT INTO badge_level_requirements VALUES(4372,619,'level2',5,'Learn two new breathing and singing exercises in Level 1 requirement 1. Show that you are familiar with musical grammar and punctuation.  Show that you know or can do the following: Sing a major scale. Be able to tell, upon hearing a few bars played, whether they are in a major or minor key. Learn to recognize most of the intervals (a third, a fifth, a seventh) in the octave above middle C when they are played or sung. Draw the symbols for the different types of notes and rests.  Explain their values.');
INSERT INTO badge_level_requirements VALUES(4373,619,'level3',6,'Explain the following time signatures, and write a measure for each signature, using both notes and rests for each: 2/2 2/4 4/4 ¾');
INSERT INTO badge_level_requirements VALUES(4374,619,'level3',7,'Learn at least one new song from seven different musical genres, for a total for seven new songs.');
INSERT INTO badge_level_requirements VALUES(4375,619,'level4',8,'Sing a simple piece of music from sight, explain all the signs and terms in it, and beat its rhythm.');
INSERT INTO badge_level_requirements VALUES(4376,619,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4377,620,'preschool',0,'Why is sleep necessary?  What are the benefits of sleep? How long can you survive without sleep?');
INSERT INTO badge_level_requirements VALUES(4378,620,'preschool',1,'Learn why bedtime routines are important.  Create a bedtime routine to help you go to sleep.  This may mean reading a story, singing a song, having a specific stuffed animal or comfort item with you.  Use the same bedtime routine for at least a week.');
INSERT INTO badge_level_requirements VALUES(4379,620,'level1',2,'How many hours should the average child sleep per night? Is it possible to oversleep?');
INSERT INTO badge_level_requirements VALUES(4380,620,'level2',3,'What are some things that affect sleep? Name two negative and two positive things that affect sleep.');
INSERT INTO badge_level_requirements VALUES(4381,620,'level3',4,'Name three negative and three positive things that affect sleep.');
INSERT INTO badge_level_requirements VALUES(4382,620,'level3',5,'Name three indicators that someone is not getting enough sleep.');
INSERT INTO badge_level_requirements VALUES(4383,620,'level4',6,'Name four negative and four positive things that affect sleep.');
INSERT INTO badge_level_requirements VALUES(4384,620,'level4',7,'What are some diseases that are associated with sleep? Choose one and learn about it.  What causes it?  What are the symptoms?  What is the treatment?  What complications can arise from it?');
INSERT INTO badge_level_requirements VALUES(4385,620,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4386,621,'preschool',0,'Hold some slime.  What does it feel like?  How does it move?');
INSERT INTO badge_level_requirements VALUES(4387,621,'preschool',1,'With an adult, make some slime.');
INSERT INTO badge_level_requirements VALUES(4388,621,'level1',2,'Find 2 recipes for slime and make them with an adult.');
INSERT INTO badge_level_requirements VALUES(4389,621,'level1',3,'Experiment with paint or food coloring in slime to make it change colors.');
INSERT INTO badge_level_requirements VALUES(4390,621,'level2',4,'Find 3 recipes for slime and make them with an adult.');
INSERT INTO badge_level_requirements VALUES(4391,621,'level2',5,'Research pros and cons of using Borax in slime. Make one slime recipe that does not include Borax.');
INSERT INTO badge_level_requirements VALUES(4392,621,'level3',6,'Find 5 recipes for slime.');
INSERT INTO badge_level_requirements VALUES(4393,621,'level3',7,'Research the history of slime. Why has it become so popular?');
INSERT INTO badge_level_requirements VALUES(4394,621,'level4',8,'Find 6 recipes for slime.');
INSERT INTO badge_level_requirements VALUES(4395,621,'level4',9,'Learn about the chemical reactions in the slime making process.');
INSERT INTO badge_level_requirements VALUES(4396,621,'level5',10,'Find 7 recipes for slime.');
INSERT INTO badge_level_requirements VALUES(4397,621,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4398,622,'preschool',0,'Learn the general safety rules for slingshots including: Only use slingshots with adult supervision Only use slingshots on an approved range where no one will walk into your way Where to stand while others are shooting Where to point your slingshot Always wear eye protection Inspect all equipment before using Never aim at people or animals Never shoot into the air or at something you cannot see');
INSERT INTO badge_level_requirements VALUES(4399,622,'preschool',1,'Demonstrate good slingshot shooting techniques including: Stance Hold Loading Draw Aim Release');
INSERT INTO badge_level_requirements VALUES(4400,622,'level1',2,'Explain how to properly store and care for slingshot equipment including slingshots, ammunition, and targets.');
INSERT INTO badge_level_requirements VALUES(4401,622,'level2',3,'Make a basic slingshot out of household items. How well did it work? What do you think you could do next time to make it better?');
INSERT INTO badge_level_requirements VALUES(4402,622,'level3',4,'Learn about the history of slingshots. When were the first slingshots developed? Where?');
INSERT INTO badge_level_requirements VALUES(4403,622,'level4',5,'Draw and label the parts of a slingshot.');
INSERT INTO badge_level_requirements VALUES(4404,622,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4405,623,'preschool',0,'Have a pajama party with your family and/or friends.  Put on your nightclothes at least an hour earlier than usual and stay up an hour later than usual. This does not need to be an actual overnight slumber party, unless you wish.');
INSERT INTO badge_level_requirements VALUES(4406,623,'preschool',1,'Discuss what makes a bed comfortable and make a bed on the floor.');
INSERT INTO badge_level_requirements VALUES(4407,623,'level1',2,'Figure out a minimum of three fun activities you could offer a slumber party guest.');
INSERT INTO badge_level_requirements VALUES(4408,623,'level2',3,'Have your slumber party last overnight.');
INSERT INTO badge_level_requirements VALUES(4409,623,'level2',4,'Figure out how many hours a person usually sleeps in one night and in a whole week.  Is there another activity that takes as many hours a week?  What are the things your family does to get ready for bed at night?  Think of at least three ways to make these things more fun and do one.');
INSERT INTO badge_level_requirements VALUES(4410,623,'level3',5,'Attend or host a slumber party for a group of your choice.');
INSERT INTO badge_level_requirements VALUES(4411,623,'level3',6,'Make a list of relaxing activities that are fun as sometimes people get too hyper at slumber parties.  Figure out which of the things on your list are best for different age groups.');
INSERT INTO badge_level_requirements VALUES(4412,623,'level4',7,'What are some things that can go wrong during a night & what can you do to be prepared so they don’t turn into disasters?');
INSERT INTO badge_level_requirements VALUES(4413,623,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4416,625,'preschool',0,'What is snow made of? Why does it snow more where it is colder instead of where it’s warmer?');
INSERT INTO badge_level_requirements VALUES(4417,625,'preschool',1,'Find three pictures of places covered in snow. Look at close-up photographs of real snowflakes.');
INSERT INTO badge_level_requirements VALUES(4418,625,'level1',2,'Draw your own snowflake.');
INSERT INTO badge_level_requirements VALUES(4419,625,'level1',3,'Have someone explain to you what the states of matter are. In which state of matter is snow? How cold does it have to be in order for snow to fall?');
INSERT INTO badge_level_requirements VALUES(4420,625,'level2',4,'Be able to explain to someone else what the three states of matter are. Give examples of ways that people use water in each state. At what temperatures do each of the states start and end? What are the various weather terms related to each state? What is the difference between snowflakes and ice?');
INSERT INTO badge_level_requirements VALUES(4421,625,'level2',5,'Find out how much snow on average your town gets each year. What mountains around you need enough snow to provide runoff for your creeks and rivers?');
INSERT INTO badge_level_requirements VALUES(4422,625,'level4',6,'Learn the safety precautions in regards to snow and winter weather. Learn the symptoms and remedies of hypothermia. What types of extra undergarments and wraps work best in the snow? Learn what to do if you are caught in a blizzard.');
INSERT INTO badge_level_requirements VALUES(4423,625,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4424,626,'preschool',0,'Learn proper safety precautions when working with soap making such as working with hot liquids and blenders.');
INSERT INTO badge_level_requirements VALUES(4425,626,'preschool',1,'Help to make at least one type of soap.');
INSERT INTO badge_level_requirements VALUES(4426,626,'level1',2,'Find 5 different items that can be used as a mold for soap.');
INSERT INTO badge_level_requirements VALUES(4427,626,'level2',3,'Make at least two types of soap.');
INSERT INTO badge_level_requirements VALUES(4428,626,'level2',4,'Find out about safe methods to color and scent your soap.');
INSERT INTO badge_level_requirements VALUES(4429,626,'level3',5,'Make at least three types of soap.');
INSERT INTO badge_level_requirements VALUES(4430,626,'level3',6,'Learn about the history of soap. How was it made in the past?');
INSERT INTO badge_level_requirements VALUES(4431,626,'level4',7,'Know the difference between melt and pour soaps, and cold process soaps.');
INSERT INTO badge_level_requirements VALUES(4432,626,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4433,627,'preschool',0,'Learn what a solar eclipse is and how the Sun, Moon, and Earth line up to produce a solar eclipse.  Demonstrate an eclipse using a flashlight, globe, and a small sphere on a string.');
INSERT INTO badge_level_requirements VALUES(4434,627,'preschool',1,'Research the proper way to look at the eclipse to avoid eye damage.  Understand why you must never look at the sun, even in an eclipse.');
INSERT INTO badge_level_requirements VALUES(4435,627,'level1',2,'Learn the following vocabulary words: Total eclipse Totality Duration Corona');
INSERT INTO badge_level_requirements VALUES(4436,627,'level1',3,'Build a pinhole viewer.');
INSERT INTO badge_level_requirements VALUES(4437,627,'level2',4,'Add the following vocabulary words: New moon Partial eclipse Annular eclipse Eclipse magnitude');
INSERT INTO badge_level_requirements VALUES(4438,627,'level2',5,'Research the specifications for safe solar eclipse viewing glasses. Make sure you buy the right kind for you and your family to use.');
INSERT INTO badge_level_requirements VALUES(4439,627,'level3',6,'Add the following vocabulary words: Annularity Diamond ring Eclipse magnitude Sunspots Sunspot cycle Shadow bands');
INSERT INTO badge_level_requirements VALUES(4440,627,'level3',7,'Understand the difference between a solar eclipse and a lunar eclipse.  Demonstrate a lunar eclipse using a flashlight, globe, and a small sphere on a string.');
INSERT INTO badge_level_requirements VALUES(4441,627,'level4',8,'Add the following vocabulary words: Baily’s Beads Chromosphere Eclipse obscuration Penumbra Photosphere Prominence Umbra');
INSERT INTO badge_level_requirements VALUES(4442,627,'level4',9,'Watch videos of total solar eclipses and read various observations.');
INSERT INTO badge_level_requirements VALUES(4443,627,'level5',10,'Add the following vocabulary words: Antumbra First contact (C1) Second contact (C2) Third contact (C3) Fourth (last) contact (C4) Hybrid eclipse Saros Umbraphile');
INSERT INTO badge_level_requirements VALUES(4444,627,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4445,628,'preschool',0,'What is one of your favorite songs? What is it about? Who wrote it? Why do you like the song?');
INSERT INTO badge_level_requirements VALUES(4446,628,'level1',1,'Pick one of your favorite songs and find out these things Why was this song written? What is the song about? What type of song is it? Country? Classical? Rock? Pop? Hip-Hop? Gospel?');
INSERT INTO badge_level_requirements VALUES(4447,628,'level1',2,'Write a song, and perform it for your family, friends, or group. It has to be at least 1 verse and 1 chorus long.');
INSERT INTO badge_level_requirements VALUES(4448,628,'level2',3,'Write a song, and perform it for your family, friends, or group. It has to have at least 2 verses and 1 chorus.');
INSERT INTO badge_level_requirements VALUES(4449,628,'level3',4,'Write a song, and perform it for your family, friends, or group. It has to have at least 3 verses and 1 chorus.');
INSERT INTO badge_level_requirements VALUES(4450,628,'level4',5,'Write a song, and perform it for your family, friends, or group.  It has to have at least 3 verses, 1 chorus and a bridge.');
INSERT INTO badge_level_requirements VALUES(4451,628,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4452,629,'preschool',0,'Understand what soup is and try a new kind of soup you’ve never had before.');
INSERT INTO badge_level_requirements VALUES(4453,629,'level1',1,'Help make a soup for at least four people.');
INSERT INTO badge_level_requirements VALUES(4454,629,'level2',2,'Make or help make a soup from scratch that’s also available in a can.  Which do you prefer and why?  Is there a difference nutritionally?');
INSERT INTO badge_level_requirements VALUES(4455,629,'level3',3,'Make a hot soup and a cold soup.  One of them needs to be totally from scratch (not even canned broth).  Try a new kind of soup you’ve never had before.');
INSERT INTO badge_level_requirements VALUES(4456,629,'level3',4,'Learn how to make stocks and broths.  What are consommé and bouillon?  How can you increase the nutrition of a stock or broth?  What are they used for besides soup?  Find out how people make a jellied consommé or bouillon.');
INSERT INTO badge_level_requirements VALUES(4457,629,'level4',5,'.  Make four of the following: Cream soup Pureed vegetable soup Clear soup Cold soup Dessert (fruit) soup');
INSERT INTO badge_level_requirements VALUES(4458,629,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4459,630,'preschool',0,'Know what a Space Derby is.');
INSERT INTO badge_level_requirements VALUES(4460,630,'preschool',1,'Learn the safety rules for attending  a Space Derby and watch one in person.');
INSERT INTO badge_level_requirements VALUES(4461,630,'level1',2,'Discuss rules and regulations for the race.  Talk about sportsmanship and why it is important during a race. With a parent, guardian, or leader, role-play examples of good vs. bad sportsmanship.');
INSERT INTO badge_level_requirements VALUES(4462,630,'level2',3,'Be able to identify all parts of the model rocket including hull, metal keel, mast, sail, etc.');
INSERT INTO badge_level_requirements VALUES(4463,630,'level3',4,'Discuss the ethics involved in purchasing a ready made rocket or having an adult build yours for you.  Why would this be considered cheating?  What is the point of the race?  What is it trying to teach youth?');
INSERT INTO badge_level_requirements VALUES(4464,630,'level4',5,'Visit a craft/hobby shop that sells supplies for space derby rockets.  Look through the selections of paints, decals, tools, weights, and accessories.  Set a reasonable budget for a rocket and plan a list of supplies that will fill your needs and still stay in budget.');
INSERT INTO badge_level_requirements VALUES(4465,630,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4466,631,'preschool',0,'Look at pictures of rockets and ships that go to space. Discuss the different parts of a rocket and their functions.');
INSERT INTO badge_level_requirements VALUES(4467,631,'preschool',1,'Read a storybook or watch a video about space exploration and engage in a discussion about the moon, stars, and astronauts.');
INSERT INTO badge_level_requirements VALUES(4468,631,'level1',2,'Learn about the life, work, and contributions to our understanding of space of an astronaut, engineer, or scientist.');
INSERT INTO badge_level_requirements VALUES(4469,631,'level2',3,'Discuss the history of space exploration, focusing on important milestones such as the first moon landing and other significant space missions.');
INSERT INTO badge_level_requirements VALUES(4470,631,'level3',4,'Explore advancements in space technology by researching a specific space probe or satellite. Discuss its purpose, achievements, and how it has contributed to our understanding of space.');
INSERT INTO badge_level_requirements VALUES(4471,631,'level4',5,'Learn about the life, work, and contributions to our understanding of space of four more astronauts, engineers, or scientists.');
INSERT INTO badge_level_requirements VALUES(4472,631,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4475,634,'preschool',0,'What is a spy? What do they do and why?');
INSERT INTO badge_level_requirements VALUES(4476,634,'preschool',1,'Practice moving quietly and staying unnoticed. Try walking across a noisy surface without making sound, hiding in plain sight, or sneaking past someone without being detected. Learn tips like wearing soft shoes, watching where you step, and using shadows or cover.');
INSERT INTO badge_level_requirements VALUES(4477,634,'level1',2,'Create your own secret code and write a message to friend.');
INSERT INTO badge_level_requirements VALUES(4478,634,'level2',3,'Complete Level 1 requirement; 1 &2');
INSERT INTO badge_level_requirements VALUES(4479,634,'level2',4,'Learn about three real spies from history. At least one should be a man and one should be a woman. Share what they did and why they were important.');
INSERT INTO badge_level_requirements VALUES(4480,634,'level3',5,'Complete Level 2 requirements 1 & 2');
INSERT INTO badge_level_requirements VALUES(4481,634,'level3',6,'Find out what Intelink is and how it is used to gather and share information within thegovernment.');
INSERT INTO badge_level_requirements VALUES(4482,634,'level4',7,'Complete Level 3 requirements 1&2 b');
INSERT INTO badge_level_requirements VALUES(4483,634,'level4',8,'Learn how modern spying works in the real world (intelligence agencies, surveillance, cybersecurity). Compare ethical vs. unethical uses of espionage.');
INSERT INTO badge_level_requirements VALUES(4484,634,'level5',9,'Complete Level 4 requirements 1 & 2');
INSERT INTO badge_level_requirements VALUES(4485,634,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4486,635,'preschool',0,'Learn how to card wool or cotton. Why do you do this and how important is it?');
INSERT INTO badge_level_requirements VALUES(4487,635,'preschool',1,'Find out what a spinning wheel looks like and what it does.');
INSERT INTO badge_level_requirements VALUES(4488,635,'level1',2,'Learn about at least 3 different types of spinning wheels and spindles.');
INSERT INTO badge_level_requirements VALUES(4489,635,'level2',3,'Card enough material to spin 3 yards of thread.');
INSERT INTO badge_level_requirements VALUES(4490,635,'level3',4,'Learn to use a simple spinning method, such as a drop spindle.');
INSERT INTO badge_level_requirements VALUES(4491,635,'level4',5,'Spin your own thread to weave, crochet or knit an item for yourself or a gift.');
INSERT INTO badge_level_requirements VALUES(4492,635,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4493,636,'preschool',0,'Learn three basic rules for how to play your sport. Learn at least one good drill that can be used to practice a skill needed in your sport and try it out.');
INSERT INTO badge_level_requirements VALUES(4494,636,'preschool',1,'How should you dress when you play this sport? What kind of shoes should you wear?');
INSERT INTO badge_level_requirements VALUES(4495,636,'level1',2,'Learn the rules of your sport and be able to explain them to others. Find at least 3 good drills that can be used to practice skills needed in your sport and try them out.');
INSERT INTO badge_level_requirements VALUES(4496,636,'level1',3,'. Know how to properly select the equipment and attire for your sport as well as how to properly care and store your equipment.');
INSERT INTO badge_level_requirements VALUES(4497,636,'level2',4,'Learn the rules of your sport and be able to explain them to others. Find at least 5 good drills that can be used to practice skills needed in your sport and master them. Know how to properly select the equipment and attire for your sport as well as how to properly care and store your equipment.');
INSERT INTO badge_level_requirements VALUES(4498,636,'level2',5,'. Know the safety rules for your sport and learn the first aid necessary to treat the most common injuries. What type of competitions and tournaments are connected to your sport? Is this a sport you can compete in locally? In what countries is your sport most popular?');
INSERT INTO badge_level_requirements VALUES(4499,636,'level3',6,'Learn the rules of your sport and be able to explain them to others. Find at least 7 good drills that can be used to practice skills needed in your sport and master them. Know how to properly select the equipment and attire for your sport as well as how to properly care and store your equipment. Know the safety rules for your sport and learn the first aid necessary to treat the most common injuries. What type of competitions and tournaments are connected to your sport? Is this a sport you can compete in locally? In what countries is your sport most popular?');
INSERT INTO badge_level_requirements VALUES(4500,636,'level3',7,'Take part in some form of competition of your sport on at least 3 different occasions; or, if unable to participate 3 times in your sport where you live, participate in some form of competition of your sport at least once, then read 3 news or magazine articles or an age-appropriate book about your sport.');
INSERT INTO badge_level_requirements VALUES(4501,636,'level4',8,'Learn the rules of your sport and be able to explain them to others. Find at least 10 good drills that can be used to practice skills needed in your sport and master them. Know how to properly select the equipment and attire for your sport as well as how to properly care and store your equipment. Know the safety rules for your sport and learn the first aid necessary to treat the most common injuries. What type of competitions and tournaments are connected to your sport? Is this a sport you can compete in locally? In what countries is your sport most popular? Take part in some form of competition of your sport on at least 3 different occasions; or, if unable to participate 3 times in your sport where you live, participate in some form of competition of your sport at least once, then read 3 news or magazine articles or an age-appropriate book about your sport.');
INSERT INTO badge_level_requirements VALUES(4502,636,'level4',9,'Find out about at least one professional athlete in your sport. Who is she? Where is she from? What makes her an outstanding athlete? Write a brief article of your findings to share with your family, friends, or group.');
INSERT INTO badge_level_requirements VALUES(4503,636,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4504,637,'preschool',0,'Learn what sport your team plays, their colors and  what their mascot is.');
INSERT INTO badge_level_requirements VALUES(4505,637,'preschool',1,'Be able to recognize your team logo.');
INSERT INTO badge_level_requirements VALUES(4506,637,'level1',2,'as well as learn the history behind your team’s name and their home playing ground (stadium/arena/field,etc.).');
INSERT INTO badge_level_requirements VALUES(4507,637,'level1',3,'Learn when your team was founded, and where your team was located before their current city (i.e., the Brooklyn Dodgers became the Los Angeles Dodgers).');
INSERT INTO badge_level_requirements VALUES(4508,637,'level2',4,'Find out what and how many national sport titles your team has won. (i.e. the Arizona Diamondbacks won the World Series in 2001.)');
INSERT INTO badge_level_requirements VALUES(4509,637,'level3',5,'Know about a legendary player from your team. Why is she/he remembered? What qualities did/does this player exhibit that make him/her remarkable? Name at least 2 character traits that correlate to Quest Clubs values.');
INSERT INTO badge_level_requirements VALUES(4510,637,'level4',6,'Know the names and positions of at least 8 players on your team. Also know at least 4 facts about each player.');
INSERT INTO badge_level_requirements VALUES(4511,637,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4512,638,'preschool',0,'Be able to explain what good sportsmanship is.  Discuss what it means to be a sore loser.  How should you behave if you lose a game or competition?  What does it mean to be a poor winner?  How should you behave if you win a game or competition?  Play a game or participate in a competition or contest and demonstrate that you understand what it means to be a good loser or a graceful winner.');
INSERT INTO badge_level_requirements VALUES(4513,638,'level1',1,'Role play a situation where someone is a poor loser or a poor winner.  Then role play how that person should have behaved to be a gracious winner or loser.');
INSERT INTO badge_level_requirements VALUES(4514,638,'level1',2,'Discuss what it means to be fair and honest when competing.  Why is winning by cheating wrong?  Who does it hurt?  Why is it still wrong even if you don’t get caught?  Discuss how you feel when you win by being fair and how you would feel if you knew you won because some part of the competition wasn’t fair.');
INSERT INTO badge_level_requirements VALUES(4515,638,'level2',3,'Participate in a game or competition.  Before beginning, make sure you understand all the rules, procedures and policies.  Even if you do not agree with all the rules, understand that if you are to participate, you need to accept the rules as they stand and abide by the results.  Find out who you can appeal to if you feel the rules are unfair and what the procedures are for possibly getting the rules changed.  Role play a situation where you think rules are unfair and demonstrate how you would handle the situation.');
INSERT INTO badge_level_requirements VALUES(4516,638,'level3',4,'Discuss how personal accountability plays a part in good sportsmanship.  Think about a recent situation when you lost a game or competition.  Did you do your very best?  If you lost a competition because you did not study hard enough, practice long enough, or put in a full effort you should recognize that fact and accept it, not blame other people or circumstances for your loss.  Do not make excuses for your own lack of effort.  Choose a game or other competition that you would like to do better in.  Make a plan to improve your results by increasing your study time, focus on practicing areas where you are weak, etc.  Then compete again and compare your results.  Did the extra effort help?  Where can you still improve?  Learn to take pride in your own accomplishments even when you do not necessarily win the event.');
INSERT INTO badge_level_requirements VALUES(4517,638,'level4',5,'at your current level.');
INSERT INTO badge_level_requirements VALUES(4518,638,'level4',6,'Participate in a game or competition and evaluate both your behavior and the behavior of both the other participants as well as the audience.  Answer “Yes” or “No” to each of the following questions for yourself, your competitors, the audience, and the parents of the players (if applicable).  Discuss your results Did you/they demonstrate sportsmanship before, during, and after the event? Did you/they maintain a high standard of personal behavior that reflected well on your/their family, club, or team? Did you/they behave honestly and fairly? Did you/they show courtesy and kindness to others? Did you/they gracefully accept the results?');
INSERT INTO badge_level_requirements VALUES(4519,638,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4520,639,'preschool',0,'Begin a collection of stamps and collect at least 10 different stamps (20 for Level 1, 50 for Level 2, 75 for Level 3, and 100 for Level 4 and 5)');
INSERT INTO badge_level_requirements VALUES(4521,639,'preschool',1,'Discuss with an adult what stamps are used for and how you can get them.');
INSERT INTO badge_level_requirements VALUES(4522,639,'level1',2,'Demonstrate how to properly soak stamps and mount them.');
INSERT INTO badge_level_requirements VALUES(4523,639,'level2',3,'Collect at least one stamp from a minimum of 3 different countries (not including the USA.)  If you write to the Ambassadors of other countries located here in the U.S., they will usually be happy to send you canceled stamps from the mail they receive from their home countries.');
INSERT INTO badge_level_requirements VALUES(4524,639,'level3',4,'Collect at least one stamp from a minimum of 10 different countries (not including the USA.)  If you write to the Ambassadors of other countries located here in the U.S., they will usually be happy to send you canceled stamps from the mail they receive from their home countries.');
INSERT INTO badge_level_requirements VALUES(4525,639,'level4',5,'Show at least ONE example of each of the following: Perforated and imperforate stamps Mint and used stamps Sheet, booklet, and coil stamps Numbers on plate block, booklet, coil, or marginal markings Overprint and surcharge Metered mail Definitive, commemorative, semi postal, and airmail stamps Cancellation and postmark First day cover Postal stationery (aerogramme, stamped envelope, and postal card)');
INSERT INTO badge_level_requirements VALUES(4526,639,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4527,640,'preschool',0,'Read a book based in the Star Wars world.  Learn the basics of the Star Wars stories and who at least 5 of the main characters are.');
INSERT INTO badge_level_requirements VALUES(4528,640,'level1',1,'Do preschool requirements #1 & #2');
INSERT INTO badge_level_requirements VALUES(4529,640,'level2',2,'Do Level 1 requirements #1 & #2');
INSERT INTO badge_level_requirements VALUES(4530,640,'level2',3,'Create a timeline of the history of Star Wars that includes at least 15 items.');
INSERT INTO badge_level_requirements VALUES(4531,640,'level3',4,'Know how many Star Wars movies there currently are, who plays the main characters and directed the movies.');
INSERT INTO badge_level_requirements VALUES(4532,640,'level4',5,'Write an essay on what you feel is the cultural impact of the Star Wars series.');
INSERT INTO badge_level_requirements VALUES(4533,640,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.  If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4536,642,'preschool',0,'Learn what a state park is and why we have them.');
INSERT INTO badge_level_requirements VALUES(4537,642,'preschool',1,'Visit your state park if possible (Be sure to follow all Leave No Trace principles) or look at pictures of it in books or online if not.');
INSERT INTO badge_level_requirements VALUES(4538,642,'level1',2,'Be able to identify well-known features found in your chosen state park. (i.e. Old Faithful in Yellowstone or El Capitan in Yosemite).  If your park does not have any well-known geological features, what attractions, amenities and recreational opportunities does it offer?');
INSERT INTO badge_level_requirements VALUES(4539,642,'level2',3,'Understand why and when your chosen park was set aside as a state park. Locate your park on a map.');
INSERT INTO badge_level_requirements VALUES(4540,642,'level3',4,'Research the Indigenous peoples originally connected to the land and how they used it.');
INSERT INTO badge_level_requirements VALUES(4541,642,'level4',5,'Research the types of habitats or ecosystems within the park.  What animals live here?  What plants and trees help to support them?');
INSERT INTO badge_level_requirements VALUES(4542,642,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4543,643,'preschool',0,'Learn who the main Crystal Gems (Steven, Garnet, Amethyst and Pearl) are. Who is your favorite and why?');
INSERT INTO badge_level_requirements VALUES(4544,643,'preschool',1,'Watch at least three episodes. Discuss them with your family or troop. What did you learn?');
INSERT INTO badge_level_requirements VALUES(4545,643,'level1',2,'Watch at least 4 episodes. Explain who Rose Quartz, Lapis Lazuli and Peridot are.');
INSERT INTO badge_level_requirements VALUES(4546,643,'level1',3,'Steven Universe has songs in many episodes. Choose on of these songs and learn how to sing it, or how to play it on a musical instrument.');
INSERT INTO badge_level_requirements VALUES(4547,643,'level2',4,'Watch at least five episodes. Explain who Greg Universe and Connie Maheswaran are.');
INSERT INTO badge_level_requirements VALUES(4548,643,'level2',5,'Make a timeline of the history of Steven Universe. Who created it? How long has it been airing? Have at least 10 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(4549,643,'level3',6,'Watch at least six episodes. Explain who Ruby and Sapphire are.');
INSERT INTO badge_level_requirements VALUES(4550,643,'level3',7,'Look up pictures of each of the Crystal Gems (Steven, Garnet, Amethyst and Pearl) and one other major character (Rose Quartz, Lapis, Greg, Connie, Ruby or Sapphire). Write a detailed report on all four Crystal Gems and one other character.');
INSERT INTO badge_level_requirements VALUES(4551,643,'level4',8,'Watch at least ten episodes.');
INSERT INTO badge_level_requirements VALUES(4552,643,'level4',9,'Learn about how Steven Universe is made. What steps does an episode go through as it moves from a plot idea to a completed episode? Who provides the voices of the characters? What is the average salary for people working on Steven Universe? Does a voice actor make more than an animator? What kind of training would you need to work on the show?');
INSERT INTO badge_level_requirements VALUES(4553,643,'level5',10,'Watch the entire first season.');
INSERT INTO badge_level_requirements VALUES(4554,643,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4556,646,'preschool',0,'Have someone read a short story out loud and move your body to act out what happens in the story.');
INSERT INTO badge_level_requirements VALUES(4557,646,'preschool',1,'Have someone read the same story, but this time move your body in any way the story makes you feel.  If the wind is blowing and the trees are swaying, what does you body want to do?  If it is raining,  would you feel like dancing in the rain?  Let your body lead your movements.');
INSERT INTO badge_level_requirements VALUES(4558,646,'level1',2,'Choose three different body movements such as raising your arms.  Do each movement three different ways.  How does the movement convey different meaning when done fast verses slow?  Or jerky versus fluid?  How does this affect your story telling when moving to a story?');
INSERT INTO badge_level_requirements VALUES(4559,646,'level2',3,'Convey a range of emotions (joy, sadness, surprise, etc.) through facial expressions and body language.  Discuss how facial expressions added to body language can change the mood of a movement.');
INSERT INTO badge_level_requirements VALUES(4560,646,'level3',4,'Showcase different walking styles and gaits each portraying a distinct character or personality.');
INSERT INTO badge_level_requirements VALUES(4561,646,'level4',5,'Learn about the history of storytelling.  What role has story movement played in telling a good story?');
INSERT INTO badge_level_requirements VALUES(4562,646,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4563,647,'preschool',0,'Learn the main Strawberry Shortcake characters. Who is your favorite and why?');
INSERT INTO badge_level_requirements VALUES(4564,647,'preschool',1,'Watch at least 3 episodes. Discuss them with your troop or family. What lessons did you learn?');
INSERT INTO badge_level_requirements VALUES(4565,647,'level1',2,'Watch at least 4 episodes.');
INSERT INTO badge_level_requirements VALUES(4566,647,'level1',3,'Learn 3 character traits (kindness to others, friendliness, etc) that Strawberry Shortcake episodes teach. Explain.');
INSERT INTO badge_level_requirements VALUES(4567,647,'level2',4,'Watch at least 5 episodes.');
INSERT INTO badge_level_requirements VALUES(4568,647,'level2',5,'Make a timeline of Strawberry Shortcake’s history. Include at least 10 items.');
INSERT INTO badge_level_requirements VALUES(4569,647,'level3',6,'Watch at least 6 episodes.');
INSERT INTO badge_level_requirements VALUES(4570,647,'level3',7,'Look up pictures of all Strawberry Shortcake characters. Write a detailed report about each character, and how they’re different.');
INSERT INTO badge_level_requirements VALUES(4571,647,'level4',8,'Watch at least 7 episodes.');
INSERT INTO badge_level_requirements VALUES(4572,647,'level4',9,'Identify the villain in Strawberry Shortcake and think of 3 ways where the villain could have made a better choice. What would make that a good choice?');
INSERT INTO badge_level_requirements VALUES(4573,647,'level5',10,'Watch at least 8 episodes.');
INSERT INTO badge_level_requirements VALUES(4574,647,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4575,648,'preschool',0,'Look at a minimum of 10 examples of street art.  Understand that street art is art created in public spaces and is meant for everyone to view.');
INSERT INTO badge_level_requirements VALUES(4576,648,'preschool',1,'Learn the difference between street art and graffiti. Why is it important to respect everyone’s property rights, and the law, when creating street art?');
INSERT INTO badge_level_requirements VALUES(4577,648,'level1',2,'Learn what “tagging” is and explain the potential consequences of painting somewhere without permission.');
INSERT INTO badge_level_requirements VALUES(4578,648,'level2',3,'Learn what a “blackbook” is in regards to street art.  Make your own blackbook  with at least 3 of your own art ideas.');
INSERT INTO badge_level_requirements VALUES(4579,648,'level3',4,'Learn the history of street art, and its connection to subcultures as well as key movements and influences.');
INSERT INTO badge_level_requirements VALUES(4580,648,'level4',5,'Explore the process, in your town or city, of getting permission to paint somewhere public. If a building owner gives you permission, do you need anything else, like a permit?');
INSERT INTO badge_level_requirements VALUES(4581,648,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4582,649,'preschool',0,'Understand why stretching is important for your health.   Learn how to stretch safely and avoid overstretching or causing injury.');
INSERT INTO badge_level_requirements VALUES(4583,649,'preschool',1,'Create a daily stretching routine for yourself, including at least 5 stretches.  Complete this routine everyday for at least a week.');
INSERT INTO badge_level_requirements VALUES(4584,649,'level1',2,'Learn at least two stretches for each of the following body parts: Neck Shoulders Wrists Back Hips Thighs Calves Ankles');
INSERT INTO badge_level_requirements VALUES(4585,649,'level2',3,'Create a personal stretching routine and follow it for two weeks, tracking improvements in flexibility and noting any changes in overall well-being.');
INSERT INTO badge_level_requirements VALUES(4586,649,'level3',4,'Research the different types of stretching, such as dynamic, static, and ballistic stretching.  How do they differ? In which circumstances are each type of stretching usually used?  What safety issues must you consider with each type of stretch?');
INSERT INTO badge_level_requirements VALUES(4587,649,'level4',5,'Identify and label major muscle groups in the human body.');
INSERT INTO badge_level_requirements VALUES(4588,649,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4589,650,'preschool',0,'Learn about the major characters of Super Mario.  Who are the “good” guys and who are the “bad” guys?');
INSERT INTO badge_level_requirements VALUES(4590,650,'preschool',1,'Write a timeline of Super Mario’s history. It should have at least 3 items on it. (Ex. Who created it? When did it first come out? How many games are there and what platforms are they for? What kind of other merchandise is there?');
INSERT INTO badge_level_requirements VALUES(4591,650,'level1',2,'Your timeline should have 5 items.');
INSERT INTO badge_level_requirements VALUES(4592,650,'level1',3,'Write a short Super Mario story, such as an adventure the characters could go on.');
INSERT INTO badge_level_requirements VALUES(4593,650,'level2',4,'Your timeline should have 7 items.');
INSERT INTO badge_level_requirements VALUES(4594,650,'level2',5,'Play at least two different Mario games, such as Mario Kart or Mario Party. Discuss which game is your favorite with a parent or friend.');
INSERT INTO badge_level_requirements VALUES(4595,650,'level3',6,'Your timeline should have 10 items.');
INSERT INTO badge_level_requirements VALUES(4596,650,'level3',7,'Create a Mario fangame with any program (The Games Factory, Game Maker, etc).');
INSERT INTO badge_level_requirements VALUES(4597,650,'level4',8,'Your timelines should have 12 items.');
INSERT INTO badge_level_requirements VALUES(4598,650,'level4',9,'Write a one page report on your favorite Super Mario character. Why are they your favorite? What is your favorite power-up they have?');
INSERT INTO badge_level_requirements VALUES(4599,650,'level5',10,'Your timelines should have 12 items.');
INSERT INTO badge_level_requirements VALUES(4600,650,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4603,652,'preschool',0,'Learn why we use different pans for different types of cakes, cookies, brownies, etc.');
INSERT INTO badge_level_requirements VALUES(4604,652,'preschool',1,'With an adult’s help, make a cake or cake mix.');
INSERT INTO badge_level_requirements VALUES(4605,652,'level1',2,'Learn what different types of beaters and mixers are used for.');
INSERT INTO badge_level_requirements VALUES(4606,652,'level2',3,'Make a family recipe. If you don’t have one, try a new one.');
INSERT INTO badge_level_requirements VALUES(4607,652,'level3',4,'Make 2 sheet cakes with fondant and spreadable icing. Which one do you like best?');
INSERT INTO badge_level_requirements VALUES(4608,652,'level4',5,'Make icing decorations with a piping bag. Put a layer of fondant on first to stabilize.');
INSERT INTO badge_level_requirements VALUES(4609,652,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4610,653,'preschool',0,'Learn the basic water safety rules listed in Level 1 #1.');
INSERT INTO badge_level_requirements VALUES(4611,653,'preschool',1,'Demonstrate that you know how to float and doggie paddle.');
INSERT INTO badge_level_requirements VALUES(4612,653,'level1',2,'Demonstrate that you can swim at least 10 feet using at least one swimming stroke (Doggie Paddle, Freestyle or crawl, Backstroke, Breast Stroke, Side Stroke).  Tread water or float on your back for 1 minute');
INSERT INTO badge_level_requirements VALUES(4613,653,'level2',3,'Do Level 1 requirement #1 and #2 , but be able to swim at least 50 feet using at least 2 different strokes.');
INSERT INTO badge_level_requirements VALUES(4614,653,'level2',4,'Demonstrate non-swimming water rescue methods by reaching your arm or leg, by reaching with a suitable object, and by throwing lines and objects. Explain why swimming rescues should not be attempted when a reaching or throwing rescue is possible, and explain why and how a rescue swimmer should avoid contact with the victim.');
INSERT INTO badge_level_requirements VALUES(4615,653,'level3',5,'Do Level 2 requirement #1 and #2, but be able to swim at least 100 feet using at least 3 different strokes. If a direct contact rescue is necessary, demonstrate the proper way to “tow” your victim using the hair or under the chin, so that you maintain as little contact as possible.');
INSERT INTO badge_level_requirements VALUES(4616,653,'level3',6,'Show that you know first aid for injuries or illnesses that could occur while swimming, including hypothermia, dehydration, heat reactions, muscle cramps, stings and bites, cuts and scrapes, spinal injuries, and hyperventilation.');
INSERT INTO badge_level_requirements VALUES(4617,653,'level4',7,'Do Level 3 requirements #1 and #2');
INSERT INTO badge_level_requirements VALUES(4618,653,'level4',8,'Demonstrate survival skills by jumping into deep water wearing clothes (shoes, socks, bathing suit, long pants, and long-sleeved shirt). Show that you can remove your shoes and socks. Then remove and inflate your pants, and show that you can float using the pants for support. Swim for 5 minutes using your pants for support and demonstrate how to re-inflate your pants while using them for support. To float using pants, first tie the legs together (leaving an opening for your head) and button and zip the waistband.  Then use of of the following two methods to inflate your pants. Splash Method Hold the waistband open underwater with one hand. While treading water, splash water and air toward the waistband opening with a downward motion of the hand. Stop the stroke at the opening. Forcing a current of water and air bubbles into the trousers straightens the pant legs. The water passes through leaving air trapped at the ends. Gather and hold the waistband together. Slip your head between the trouser legs, and place the knot behind your neck. Lie back and float. Sling Method Hold the waistband open with both hands behind your head. Then sling the trousers over your head, scooping in the air that is trapped when the open end of the trousers (the waistband) hits the water. Now position yourself between the pant legs and stay afloat.');
INSERT INTO badge_level_requirements VALUES(4619,653,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4620,654,'preschool',0,'Learn how to properly set a simple table for a family dinner. Show where the fork, spoon, knife, napkin, plate, and glass should be placed for each person. Make sure the blade of the knife faces in toward the plate and that the napkin is neatly folded.');
INSERT INTO badge_level_requirements VALUES(4621,654,'level1',1,'Learn what the following mean: buffet, formal, informal, place setting, and casual. Know the difference between soup spoons and teaspoons, salad and dinner forks, soup and fruit/dessert bowls, salad and dinner plates, mugs and tea cups, glasses and goblets, dinner and luncheon napkins & table cloths, placemats and table runners.');
INSERT INTO badge_level_requirements VALUES(4622,654,'level2',2,'Learn the following terms: stemware, stoneware, china, disposables, linen, damask, smorgasbord, cornucopia, brunch, teacart, doily, and sideboard.');
INSERT INTO badge_level_requirements VALUES(4623,654,'level2',3,'Do 2 complete table settings: table covering, centerpiece & place settings. If you do not have the items necessary to make the settings you want, you may go to a department store for ideas and then draw a detailed, colored picture of what you’d like. Your settings need to be from different categories: formal (wedding?), holiday (Thanksgiving?), special occasion (graduation?), business event (buffet or banquet?), children’s party or outdoors, etc.');
INSERT INTO badge_level_requirements VALUES(4624,654,'level3',4,'Learn the following terms: fruit spoon, dessert fork, oyster fork, salt cellar, butter knife, bread plate, charger, finger bowl, chafing-dish, condiments, casserole, relish, & cold cuts.');
INSERT INTO badge_level_requirements VALUES(4625,654,'level4',5,'Discuss the advantages and disadvantages of paper, plastic, glass, enamel, pottery, and china dishes. Discuss the occasions for which a person would need the various items listed in the vocabulary lists. Discuss the impact of various colors & plate designs on a table setting');
INSERT INTO badge_level_requirements VALUES(4626,654,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4627,655,'level1',0,'.  Develop the following leadership qualities and show them in your everyday life. a)        Listen to others without interrupting. b)        When you start something, see it through to the end, even if it is difficult. c)        Learn from your mistakes and do not blame others for your own failings. d)        Don’t take all the credit for a job well done, make sure that everyone who helped out is recognized. e)        Don’t always demand to have things your way, learn to compromise. f)        Finish things on time.');
INSERT INTO badge_level_requirements VALUES(4628,655,'level1',1,'Role play different leadership situations.  Examples may include the following: a)        Resolve a conflict between two team members b)        Motivate a team member whose enthusiasm is lacking c)        Set goals with your team and delegate jobs d)        Deal with a team member who is constantly late e)        Praise a team member for a job well done');
INSERT INTO badge_level_requirements VALUES(4629,655,'level2',2,'Hold a leadership position.  This may be captain of a sports team, a team leader on a school project, a leadership position within your club, leading a Make a Difference project, or even holding a position in student government.  Identify the following: a)        What are the goals for your team and how do you intend to reach them? b)        What are the strengths and weaknesses of the individuals on your team and how can you use them to the best advantage? c)        How do you plan to track your progress toward your goals? d)        How can you motivate your team to their best performance? e)        How do you plan to resolve conflicts that may arise? f)        How do you plan to communicate with your team and inform them of important information?');
INSERT INTO badge_level_requirements VALUES(4630,655,'level3',3,'Having the courage to stand up for what you believe in is a trait of an ethical leader.  Make a list of your core values. Next to each one, list at least one way in which you live this value in your everyday life and how you might use it in a leadership position.  Next, read at least 3 articles regarding ethics in business, politics, education, or other areas that require a person to show leadership qualities. Were these people acting ethically?  Why or why not?');
INSERT INTO badge_level_requirements VALUES(4631,655,'level4',4,'Read a biography about a famous leader.  What made this person an effective leader?  Make a list of character traits that a good leader should have.');
INSERT INTO badge_level_requirements VALUES(4632,655,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4633,656,'level1',0,'Be able to explain all safety rules when using a tall flag. Always be aware of where your flag is and the space around you. Keep a minimum of one flag pole length between you and anyone else at all times when twirling a tall flag. Never toss your flag around other people or objects until you have mastered the trick.');
INSERT INTO badge_level_requirements VALUES(4634,656,'level1',1,'Learn to perform at least three no-spinning moves with your flag.');
INSERT INTO badge_level_requirements VALUES(4635,656,'level2',2,'What is the history of tall flags groups?  Where did they originate?  How many groups are there now?  What are the differences and similarities between baton twirling and tall flags?  What are the differences and similarities between being part of a color guard and a tall flags group?');
INSERT INTO badge_level_requirements VALUES(4636,656,'level2',3,'Learn to perform at least three spinning moves with your flag.');
INSERT INTO badge_level_requirements VALUES(4637,656,'level3',4,'Do Level 2 #1 and #2.');
INSERT INTO badge_level_requirements VALUES(4638,656,'level3',5,'To what health issues should tall flags troops pay attention?  What about nutrition & hydration?  Know what to do about bruises, blisters, sunburn, heat rash, heat exhaustion, and hypothermia.');
INSERT INTO badge_level_requirements VALUES(4639,656,'level4',6,'Do Level 3 #1 & #2.');
INSERT INTO badge_level_requirements VALUES(4640,656,'level4',7,'Do any tall flags camps exist?  How much do they cost?  Is there any other way to get concentrated training?  What major competitions are available for tall flags?');
INSERT INTO badge_level_requirements VALUES(4641,656,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4642,657,'preschool',0,'Try 3 different types of tea. Which one do you like best?');
INSERT INTO badge_level_requirements VALUES(4643,657,'preschool',1,'Attend or host a tea party. Who should pour the first cup of tea?');
INSERT INTO badge_level_requirements VALUES(4644,657,'level1',2,'and 2.');
INSERT INTO badge_level_requirements VALUES(4645,657,'level1',3,'Learn basic manners for having tea. How long should tea steep? Should you squeeze the bag? What should you do with the tea bag when you take it out of your cup? How should you hold a tea cup?');
INSERT INTO badge_level_requirements VALUES(4646,657,'level2',4,'Make a food that goes along with tea and serve it at your tea party.');
INSERT INTO badge_level_requirements VALUES(4647,657,'level2',5,'What is the purpose of having tea? What are some countries where tea is traditional? Where was tea discovered? What is traditional tea time in England? Learn to use a tea ball.');
INSERT INTO badge_level_requirements VALUES(4648,657,'level3',6,'Learn about the health benefits of tea. Make your own tea from leaves, flowers, or spices.');
INSERT INTO badge_level_requirements VALUES(4649,657,'level4',7,'Talk to someone who has tea on a regular basis or has had tea in another country about their experience. Learn about the history of tea.');
INSERT INTO badge_level_requirements VALUES(4650,657,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4654,660,'preschool',0,'Discuss with a parent or leader what teamwork means. Why is it important? Where and when might you use it?');
INSERT INTO badge_level_requirements VALUES(4655,660,'preschool',1,'Discuss different decision making strategies within a group. How do you resolve conflict on a team? How can you compromise? Is there are leader? Does everyone have a specific job or do you work on everything together? What are the advantages of each approach? Discuss how the following terms affect teamwork: Trust, cooperation, respect, support, communication, perseverance, sportsmanship, patience, and sharing.');
INSERT INTO badge_level_requirements VALUES(4656,660,'level1',2,'Discuss with a parent or leader what teamwork means. Why is it important? Where and when might you use it? Come up with your own definition of the word “team.” You may wish to use the word as an acronym such as “Together Everyone Achieves More.” What other definitions can you come up with?');
INSERT INTO badge_level_requirements VALUES(4657,660,'level1',3,'Discuss different decision making strategies within a group. How do you resolve conflict on a team? How can you compromise? Is there are leader? Does everyone have a specific job or do you work on everything together? What are the advantages of each approach? Discuss how the following terms affect teamwork: Trust, cooperation, respect, support, communication, perseverance, sportsmanship, patience, and sharing.');
