INSERT INTO badge_level_requirements VALUES(4667,662,'preschool',0,'Learn the 10 commandments.');
INSERT INTO badge_level_requirements VALUES(4668,662,'preschool',1,'The first 4 commandments tell us to love God more than anything else. The next 6 commandments are to help us love others. Take a few minutes to thank God for loving us and ask Him to help us love others.');
INSERT INTO badge_level_requirements VALUES(4669,662,'level1',2,'Discuss with an adult how you can apply the 10 commandments to your own life.');
INSERT INTO badge_level_requirements VALUES(4670,662,'level2',3,'Learn the story of Moses and how the 10 commandments were given to the Jewish people. Know where to find the 10 commandments in the Bible or Torah.');
INSERT INTO badge_level_requirements VALUES(4671,662,'level3',4,'Print each of the 10 commandments on a piece of paper. Then arrange the papers from the commandment that you think is the most important down to the one you feel is the least important. Discuss with an adult why you arranged them the way you did.');
INSERT INTO badge_level_requirements VALUES(4672,662,'level4',5,'Learn about the role the 10 commandments has played in modern law.');
INSERT INTO badge_level_requirements VALUES(4673,662,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4674,663,'preschool',0,'What is a textile? Look at three different pictures of varied textile designs. Which did you like best? Why?');
INSERT INTO badge_level_requirements VALUES(4675,663,'preschool',1,'Make your own textile design. This can be with colored pencils, markers, paint, rubber stamps, etc.');
INSERT INTO badge_level_requirements VALUES(4676,663,'level1',2,'Find at least 10 samples of good textile design in either clothing or home furnishings.  How can you tell the difference between good design and bad?');
INSERT INTO badge_level_requirements VALUES(4677,663,'level1',3,'Learn at least 5 new vocabulary words that have to do with textile design');
INSERT INTO badge_level_requirements VALUES(4678,663,'level2',4,'Do Level 1 requirements # 1 & 2.  Learn at least 10 vocabulary words from the textile industry.');
INSERT INTO badge_level_requirements VALUES(4679,663,'level2',5,'Create an abstract design and show how it can be repeated to create an over-all pattern.   You can use rubber stamps, computer programs, block prints, etc. to create your design.');
INSERT INTO badge_level_requirements VALUES(4680,663,'level3',6,'Do Level 2 requirements # 1 & 2.');
INSERT INTO badge_level_requirements VALUES(4681,663,'level3',7,'Learn about two modern textile designers and make a collage of pictures of their work.');
INSERT INTO badge_level_requirements VALUES(4682,663,'level4',8,'Do Level 3 requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(4683,663,'level4',9,'Learn how computers have affected the textile design industry.   What computer programs are now available specifically for the textile design industry?');
INSERT INTO badge_level_requirements VALUES(4684,663,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
