INSERT INTO badge_level_requirements VALUES(4697,665,'preschool',0,'Show how to properly prepare a work area to avoid staining things you want to keep clean.');
INSERT INTO badge_level_requirements VALUES(4698,665,'preschool',1,'Create a craft using a tie dye technique with an adult’s help. For example, you can tie dye coffee filters and make them into butterfly wings by pinching them in a cloths pin used as the body of the butterfly. You can also glue on google eyes and pipe cleaner antennas if you like. You can use simple food dyes dissolved in water to dye the coffee filters.');
INSERT INTO badge_level_requirements VALUES(4699,665,'level1',2,'With the help of an adult, tie-dye an article of clothing.');
INSERT INTO badge_level_requirements VALUES(4700,665,'level2',3,'Show how to properly clean all supplies and your work area.');
INSERT INTO badge_level_requirements VALUES(4701,665,'level3',4,'When making your tie dyed article, learn to create a pattern such as stripes, circles or spirals.');
INSERT INTO badge_level_requirements VALUES(4702,665,'level3',5,'Know what types of dyes can be used and how to set the dye.');
INSERT INTO badge_level_requirements VALUES(4703,665,'level4',6,'Learn about the history of tie dye. When and where was it first used? How have the techniques and styles changed? When did it first become popular in modern American culture?');
INSERT INTO badge_level_requirements VALUES(4704,665,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4705,666,'preschool',0,'Learn what a time capsule is and why they are created.');
INSERT INTO badge_level_requirements VALUES(4706,666,'preschool',1,'Make a list of what you would put in a time capsule to communicate to people in the future what they should know about you.');
INSERT INTO badge_level_requirements VALUES(4707,666,'level1',2,'* and 2*.');
INSERT INTO badge_level_requirements VALUES(4708,666,'level1',3,'. Make and hide a time capsule. Don’t forget to pick and record an “open on” date.');
INSERT INTO badge_level_requirements VALUES(4709,666,'level2',4,'* and 2*.');
INSERT INTO badge_level_requirements VALUES(4710,666,'level2',5,'. Research famous time capsules. What is the oldest time capsule found? What is the largest? Where were they found?');
INSERT INTO badge_level_requirements VALUES(4711,666,'level3',6,'. Do Level 2 requirements 1* and 2*.');
INSERT INTO badge_level_requirements VALUES(4712,666,'level3',7,'. Make a list of types of organizations that might choose to make a time capsule and discuss why it would be a good idea? Consider government, service, clubs and business organizations.  Find out if there is an organization near you that plans to dig up a time capsule.  For example, Chico State University in California buries a time capsule for each graduating class and digs it up 50 years later.');
INSERT INTO badge_level_requirements VALUES(4713,666,'level4',8,'. Do Level 3 requirements 1* and 2*.');
INSERT INTO badge_level_requirements VALUES(4714,666,'level4',9,'. Learn why it may be better to include printed materials instead of relying of digital storage of information. Discuss how you could communicate to people in the future how information is recorded and stored today.');
INSERT INTO badge_level_requirements VALUES(4715,666,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4716,667,'preschool',0,'Learn what time is and how a clock or a watch help us track it.');
INSERT INTO badge_level_requirements VALUES(4717,667,'preschool',1,'Look at pictures of different timekeeping devices throughout history.');
INSERT INTO badge_level_requirements VALUES(4718,667,'level1',2,'Use a stopwatch or timer to count how long it takes to do everyday tasks like brushing your teeth, tying your shoes, or walking across a room.');
INSERT INTO badge_level_requirements VALUES(4719,667,'level2',3,'Explore at least three ways people used to measure time in ancient times (such as sundials, water clocks, or candle clocks). Try making one and track its accuracy over several hours and record what you learn.');
INSERT INTO badge_level_requirements VALUES(4720,667,'level3',4,'Study the history of timekeeping. Learn how timekeeping developed from early civilizations through the invention of mechanical clocks and into atomic time. Create a timeline with at least 10 different timekeeping devices or advancements. Check out our blog post 9 Fun timeline Activities to Make History Come Alive.');
INSERT INTO badge_level_requirements VALUES(4721,667,'level4',5,'Explore how time is measured and kept today, including the use of atomic clocks, satellites, daylight savings, time zones, and the role of organizations like NIST or GPS systems.');
INSERT INTO badge_level_requirements VALUES(4722,667,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(4723,668,'preschool',0,'Find out what the Titanic is and what it is known for.');
INSERT INTO badge_level_requirements VALUES(4724,668,'preschool',1,'Find out what caused the Titanic to sink. What happened to the side of the ship that caused the “unsinkable” ship to actually sink?');
INSERT INTO badge_level_requirements VALUES(4725,668,'level1',2,'Find out how big the Titanic was.');
INSERT INTO badge_level_requirements VALUES(4726,668,'level1',3,'Find out where the Titanic was built.');
INSERT INTO badge_level_requirements VALUES(4727,668,'level2',4,'Find out how many passengers were on the ship. How many survived the sinking? How many were killed? How long did it take for the ship to sink?');
INSERT INTO badge_level_requirements VALUES(4728,668,'level2',5,'Name some of the famous people who were on board and whether or not they survived the sinking. If they survived, find out something they did with their life after this experience.');
INSERT INTO badge_level_requirements VALUES(4729,668,'level3',6,'Who was the oldest survivor of the Titanic and how old was that person when they died?');
INSERT INTO badge_level_requirements VALUES(4730,668,'level3',7,'How many lifeboats were on the Titanic at the time it went down? Why were there so few lifeboats on the ship? Find out what percentage of first, second and third class passengers survived the sinking.');
INSERT INTO badge_level_requirements VALUES(4731,668,'level4',8,'Find out what some of the amenities were on the Titanic. Were any of the amenities reserved for first class passengers only? How do they compare to amenities on ships today?');
INSERT INTO badge_level_requirements VALUES(4732,668,'level4',9,'Name some artifacts that were recovered from the Titanic. How were they recovered? Research one process used to preserve these artifacts.');
INSERT INTO badge_level_requirements VALUES(4733,668,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4736,670,'preschool',0,'Learn what towel art is and what it is used for.');
INSERT INTO badge_level_requirements VALUES(4737,670,'preschool',1,'What is the art of towel folding called?');
INSERT INTO badge_level_requirements VALUES(4738,670,'level1',2,'Fold 1 land animal and 1 sea animal');
INSERT INTO badge_level_requirements VALUES(4739,670,'level2',3,'Fold 2 land animals and 2 sea animals');
INSERT INTO badge_level_requirements VALUES(4740,670,'level2',4,'Learn the history of towel folding.');
INSERT INTO badge_level_requirements VALUES(4741,670,'level3',5,'Fold 3 land animals and 3 sea animals');
INSERT INTO badge_level_requirements VALUES(4742,670,'level3',6,'Look online and see how many different ways there is to fold a sea turtle and an elephant. Find something that has more than one way to fold and fold the same thing in 2 different ways. See what the easiest /fastest way is. Is it the one that looks the best of the two.');
INSERT INTO badge_level_requirements VALUES(4743,670,'level4',7,'Do a fold that is not an animal ex. snowman');
INSERT INTO badge_level_requirements VALUES(4744,670,'level4',8,'Learn about jobs that relate to towel folding.');
INSERT INTO badge_level_requirements VALUES(4745,670,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4746,671,'preschool',0,'What toys did your parents play with as children?');
INSERT INTO badge_level_requirements VALUES(4747,671,'preschool',1,'What toys did your grandparents play with as children?');
INSERT INTO badge_level_requirements VALUES(4748,671,'level1',2,'For centuries people have made their own toys.  Make a toy of your own such as a simple yarn doll or toilet paper tube car.');
INSERT INTO badge_level_requirements VALUES(4749,671,'level2',3,'Create a 100 year timeline of toys. Include at least one toy that was popular in each decade.');
INSERT INTO badge_level_requirements VALUES(4750,671,'level3',4,'Choose a toy from at least 50 years ago and find out who the inventor was.  How did they come up with the idea?  Is their toy still available today?  Has it changed since it was originally invented?');
INSERT INTO badge_level_requirements VALUES(4751,671,'level4',5,'Choose a historical era and learn about the toys available at that time.  Which toys were mass produced and sold?  Which were usually homemade?  If possible, make a toy from your chosen era.');
INSERT INTO badge_level_requirements VALUES(4752,671,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4753,672,'preschool',0,'What is a trademark? Explain to someone in simple terms what the word means and what it means when a toy is trademarked.');
INSERT INTO badge_level_requirements VALUES(4754,672,'preschool',1,'Explain why this toy is special to you. Be able to recognize other versions of your toy from the same toy line. For example, if you own a pet from The Littlest Pet Shop, be able to recognize other pets from the same toy line.');
INSERT INTO badge_level_requirements VALUES(4755,672,'level1',2,'and 2.');
INSERT INTO badge_level_requirements VALUES(4756,672,'level1',3,'What area of discovery does your toy fit under and why? (e.g. Legos – Discover science and technology; Etch A Sketch – Discover art, etc.). Learn the name of the company that created your toy. Show how playing with your toy helps you learn important life skills (e.g. littlest pet shop – pet care; cabbage patch kids – child care; Legos – creativity and science/technology; Bionicles – engineering).');
INSERT INTO badge_level_requirements VALUES(4757,672,'level2',4,'and 2.');
INSERT INTO badge_level_requirements VALUES(4758,672,'level2',5,'When was your toy first invented? Make a timeline of its history including the development of the toy’s beginning, who created it and why, and how it has changed over the years. If your toy is a recent invention, research what caused the company to create this line of toys, and where they might have gotten inspiration for their particular models. Create a timeline of the toy’s possible “ancestry” (toys that may have inspired its creation) and how it influenced the making of your toy.');
INSERT INTO badge_level_requirements VALUES(4759,672,'level3',6,'and 2.');
INSERT INTO badge_level_requirements VALUES(4760,672,'level3',7,'What factors have contributed to the popularity of your toy? (E.g. Cabbage patch kids was the first doll to come with adoption papers and have the idea of a personable child, not just a doll). Learn about the company’s process in marketing/publicity of new toys. What comes with your toy when you purchase it? How has the popularity of your toy changed the toy industry?');
INSERT INTO badge_level_requirements VALUES(4761,672,'level4',8,'and 2.');
INSERT INTO badge_level_requirements VALUES(4762,672,'level4',9,'Research jobs available with the company that manufactures your chosen toy. What opportunities are available for things like scholarships, awards and competitions? Does your toy have a use in movie production, literature, pop culture, or sports?');
INSERT INTO badge_level_requirements VALUES(4763,672,'level5',10,'and 2.');
INSERT INTO badge_level_requirements VALUES(4764,672,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(4765,673,'preschool',0,'Demonstrate knowledge about safety rules on and around a trampoline. Great website for trampoline safety rules: http://www.trampolinesafety.com/safety-rules-a-trampoline-without-a-safety-enclosure');
INSERT INTO badge_level_requirements VALUES(4766,673,'preschool',1,'Learn why stretching is important. Learn some basic stretches and how to do them properly.');
INSERT INTO badge_level_requirements VALUES(4767,673,'level1',2,'and 2.  Be able to perform three jumps from the basic skills list below and put them together in a routine of 10 moves. Straight Jump – A vertical jump with the body held straight and arms in a straight line above the body at take-off. Tuck Jump – From a straight jump start, the knees are pulled up to the chest and the hands must at least briefly grasp the legs between the knees and ankle. Pike Jump – Again from a straight jump start, the legs are straight, held together and lifted parallel to the trampoline and the arms and body reach forwards towards the pointed toes. Straddle Jump – Similar to the pike jump except that the legs are spread sideways approximately 90° apart and the arms reach forward towards the pointed toes. Seat Drop or Seat Landing – Landing in a seated position with the legs straight. The hands support the body on either side and very slightly behind the posterior, palms down with fingers pointed towards the pointed toes. Seat Landing Half Twist to Seat Landing or Swivel Hips – Performing a seat landing, bounce up to a straight position (without landing) and then perform a half twist and land in the second seat landing facing in the opposite direction. Half Twist and Full Twist – While in a straight jump position rotating the body until facing the opposite direction for a half twist or a complete 360° rotation for a full twist. Front Drop or Front Landing – Landing horizontally on the bed, face down, with the arms bent to form a diamond shape with the hands overlapping slightly in front of the face. The legs should be bent slightly at the knee but otherwise held in tension for a good landing. Back Drop or Back Landing – Landing on the bed on the back. The legs are bent up at about 90° on landing with legs held straight and the head is held in line with the body flat on the bed (to avoid whiplash injury).');
INSERT INTO badge_level_requirements VALUES(4768,673,'level1',3,'Know how to dress when practicing, also know what the safety rules are and be able to apply them.');
INSERT INTO badge_level_requirements VALUES(4769,673,'level2',4,'and 2. Create a routine using all ten skills from the basic skills list.');
INSERT INTO badge_level_requirements VALUES(4770,673,'level2',5,'Watch one competition, either on television or in person.');
INSERT INTO badge_level_requirements VALUES(4771,673,'level3',6,'and 2, but be able to complete two different ten skill routines.');
INSERT INTO badge_level_requirements VALUES(4772,673,'level3',7,'Learn how trampolinists are judged');
INSERT INTO badge_level_requirements VALUES(4773,673,'level4',8,'and 2.');
INSERT INTO badge_level_requirements VALUES(4774,673,'level4',9,'Be knowledgeable in trampoline vocabulary, know at least 20 different terms');
INSERT INTO badge_level_requirements VALUES(4775,673,'level5',10,'Do Eagle requirements 1 & 2');
INSERT INTO badge_level_requirements VALUES(4776,673,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(4777,674,'preschool',0,'Learn what the word “trade” means by practicing a simple trade—swap a toy or snack with a friend or sibling. Understand that you can trade money for items or services.');
INSERT INTO badge_level_requirements VALUES(4778,674,'preschool',1,'Learn how products travel from one place to another such as via plane, ship, train and truck.  Be able to identify each type of transportation and whether it travels by air, water, or land.');
INSERT INTO badge_level_requirements VALUES(4779,674,'level1',2,'Look at a map or globe and find where something in your home came from (such as fruit, clothing, or a toy). Was it made nearby or far away?  Find out how it got all the way to you.  Did it go by air, sea or land?  Or a combination?');
INSERT INTO badge_level_requirements VALUES(4780,674,'level2',3,'Learn about three famous trade routes such as the Silk Road, Spice Route, or Trans-Saharan Caravan Route. Find out what was traded and between which regions. When were these routes used and what mode of transportation was used?');
INSERT INTO badge_level_requirements VALUES(4781,674,'level3',4,'Study how geography affects trade routes. Use a map to trace one historical or modern trade route and identify any rivers, mountains, deserts, or oceans that shaped the path.');
INSERT INTO badge_level_requirements VALUES(4782,674,'level4',5,'Make a map showing global trade hubs today—major ports, airports, and logistics centers');
INSERT INTO badge_level_requirements VALUES(4783,674,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(4784,675,'preschool',0,'Learn to identify at least five different types of transportation (car, bus, bicycle, airplane, boat, train, etc.) and the terrain they are used for.');
INSERT INTO badge_level_requirements VALUES(4785,675,'preschool',1,'Discuss which modes of transporation are usually used to transport people and which are usually used to transport goods and why.  Which do both?');
INSERT INTO badge_level_requirements VALUES(4786,675,'level1',2,'Listen to sounds of different vehicles (e.g., car horn, train whistle, airplane engine, police siren, ship horn) and try to match the sound to the correct vehicle.');
INSERT INTO badge_level_requirements VALUES(4787,675,'level2',3,'Compare transportation systems in two different countries. Discuss similarities and differences in the modes used and their efficiency.');
INSERT INTO badge_level_requirements VALUES(4788,675,'level3',4,'Learn about the history and evolution of transportation, focusing on significant milestones and advancements.  Create a timeline with at least 10 transporation related events.');
INSERT INTO badge_level_requirements VALUES(4789,675,'level4',5,'Research a historical figure who made significant contributions to the development of transportation.');
INSERT INTO badge_level_requirements VALUES(4790,675,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4791,676,'preschool',0,'Understand what trash/garbage is and why it is important to have someone pick it up and dispose of it.  What would happen if no one ever came to pick up trash?');
INSERT INTO badge_level_requirements VALUES(4792,676,'preschool',1,'Learn to sort your trash into items to be thrown away, items to be recycled and items that can be composted such as yard waste and food scraps.');
INSERT INTO badge_level_requirements VALUES(4793,676,'level1',2,'How many different types of trash pick up are available in your town?  For example you might have pick ups for household trash, recycling, yard waste, compost, office paper etc.  Which of these services is required by your county and which are optional? In what other ways can you dispose of trash safely and cleanly if trash collection is not offered in your area?');
INSERT INTO badge_level_requirements VALUES(4794,676,'level2',3,'Learn about the impact of improper trash disposal on the environment, wildlife.');
INSERT INTO badge_level_requirements VALUES(4795,676,'level3',4,'Learn about the history of trash collection.');
INSERT INTO badge_level_requirements VALUES(4796,676,'level4',5,'Find out how truck routes and scheduling are made.  How many trucks are needed to serve your community?');
INSERT INTO badge_level_requirements VALUES(4797,676,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4798,677,'preschool',0,'Go on a trip with your family to somewhere you have never been before. Discuss how your group is going to stay together and what to do if you are separated from your group.');
INSERT INTO badge_level_requirements VALUES(4799,677,'preschool',1,'Help with the packing for a trip. What kinds of clothing will you need where you are going?  What about toiletries?  Things to stay busy?');
INSERT INTO badge_level_requirements VALUES(4800,677,'level1',2,'but go on an overnight trip.');
INSERT INTO badge_level_requirements VALUES(4801,677,'level1',3,'Show that you know how to pack your own bag for an overnight trip.   What kinds of clothing will you need where you are going?  What about toiletries?  Things to stay busy?  Show that you can fold your own clothes and fit everything you need into one bag.  Know how heavy of a bag you can handle on your own without hurting yourself.');
INSERT INTO badge_level_requirements VALUES(4802,677,'level2',4,'– your trip should be at least 2 nights.');
INSERT INTO badge_level_requirements VALUES(4803,677,'level2',5,'Demonstrate your knowledge of proper behavior on trains, buses, planes, or cars so that you are courteous to fellow travelers and leave no trace of litter or vandalism in restrooms, waiting rooms, etc.');
INSERT INTO badge_level_requirements VALUES(4804,677,'level3',6,'Plan a real or imaginary trip at least 300 miles from your home.  Include detailed plans and budgets for the following items: Mode of transportation (include all necessary transportation including rental cars, etc. if necessary.) Routes Meals Lodging Activities Baggage Timetables');
INSERT INTO badge_level_requirements VALUES(4805,677,'level4',7,'– If you earned this badge at Level 3, you must plan a trip to a different location.');
INSERT INTO badge_level_requirements VALUES(4806,677,'level4',8,'Understand the different rate structures for a specific mode of transportation such as a plane or train.  How does the passenger’s age effect the price?  What about advance purchase verses last minute purchases or the quality of your seating?');
INSERT INTO badge_level_requirements VALUES(4807,677,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4808,678,'preschool',0,'Learn how to stay close to a parent or adult when traveling. Practice holding hands in a parking lot or airport. (If you are an older level redoing this requirement, understand the need to keep track of smaller children.)');
INSERT INTO badge_level_requirements VALUES(4809,678,'preschool',1,'Pack a travel bag with items you need to stay safe and comfortable on a real or pretend trip. What weather do you need to plan for?  What type of shoes will you need?  What will keep you occupied so you stay calm?  What snacks do you need so you don’t get hungry?');
INSERT INTO badge_level_requirements VALUES(4810,678,'level1',2,'Learn your full name and address as well as your parent or guardian’s full name. Practice how to ask for help if you get lost while traveling.');
INSERT INTO badge_level_requirements VALUES(4811,678,'level2',3,'Learn and practice basic travel rules for cars, buses, planes, trains and ships. Know when to sit still, use a seatbelt, or listen for safety announcements. Understand how loud or argumentative behavior can be distracting for drivers or travel personnel like flight attendants, which can become a safety issue.');
INSERT INTO badge_level_requirements VALUES(4812,678,'level3',4,'Learn about the history of travel safety laws such as seatbelt rules, speed limits, or airport security. How and why did they come to be?  Make a timeline of at least 15 different travel safety rules.');
INSERT INTO badge_level_requirements VALUES(4813,678,'level4',5,'Choose four different types of travel (such as car, bus, airplane, train, or ship) and compare and contrast their safety risks, emergency procedures, and required safety gear.');
INSERT INTO badge_level_requirements VALUES(4814,678,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(4817,681,'preschool',0,'Understand what the United Nations is. What is its goal? What does it do?');
INSERT INTO badge_level_requirements VALUES(4818,681,'preschool',1,'Find out the name of your country’s ambassador to the United Nations.');
INSERT INTO badge_level_requirements VALUES(4819,681,'level1',2,'When was the United Nations formed? Make a brief timeline with at least five important events.');
INSERT INTO badge_level_requirements VALUES(4820,681,'level2',3,'Learn the meaning of the following terms in relation to the U.N.: Delegate Resolution Amendment Caucus Bloc');
INSERT INTO badge_level_requirements VALUES(4821,681,'level3',4,'The United Nations consists of several departments and associated organizations. Learn the differences between the U.N. General Assembly, the U.N. Secretariat, the U.N. Security Council, and the U.N. Economic and Social Council. Be able to explain what each one does.');
INSERT INTO badge_level_requirements VALUES(4822,681,'level4',5,'Learn about the International Court of Justice, the judicial branch of the United Nations. What is its role? How does it differ from the International Criminal Court?');
INSERT INTO badge_level_requirements VALUES(4823,681,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4824,682,'preschool',0,'Create a map of the United States.  This can be done by putting together a puzzle, drawing a map, using a computer program, etc.');
INSERT INTO badge_level_requirements VALUES(4825,682,'preschool',1,'Earn the History of the U.S. badge at your current level.');
INSERT INTO badge_level_requirements VALUES(4826,682,'level1',2,'Do Preschool requirements # 1 & 2.');
INSERT INTO badge_level_requirements VALUES(4827,682,'level1',3,'Learn to recognize at least six symbols of the United States of America and find out about their origin and meaning.');
INSERT INTO badge_level_requirements VALUES(4828,682,'level2',4,'Make sure that your map includes all state capitals.');
INSERT INTO badge_level_requirements VALUES(4829,682,'level2',5,'Name the four freedoms guaranteed to United States citizens under the constitution.');
INSERT INTO badge_level_requirements VALUES(4830,682,'level3',6,'Add national parks to your map.');
INSERT INTO badge_level_requirements VALUES(4831,682,'level3',7,'Learn how a person not born in the United States can become a citizen.');
INSERT INTO badge_level_requirements VALUES(4832,682,'level4',8,'Do Level 3 requirement #1 & #2.');
INSERT INTO badge_level_requirements VALUES(4833,682,'level4',9,'Find out what type of questions are on the test that must be passed to become a naturalized citizen.  Could you pass it?  Talk to someone who has taken the test if possible.');
INSERT INTO badge_level_requirements VALUES(4834,682,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4835,683,'preschool',0,'Learn what upcycling means and look at different examples.  What are some benefits to upcycling (for the planet and for our families)?');
INSERT INTO badge_level_requirements VALUES(4836,683,'preschool',1,'Upcycle something that you or your family would normally throw away or recycle.');
INSERT INTO badge_level_requirements VALUES(4837,683,'level1',2,'Look through your house and identify 5 things that you could upcycle instead of throwing away. What could you make from them?');
INSERT INTO badge_level_requirements VALUES(4838,683,'level2',3,'Discuss the similarities and differences between recycling, upcycling, reducing, and reusing.  Create a poster to teach others about how these practices help our environment and our budgets.');
INSERT INTO badge_level_requirements VALUES(4839,683,'level4',4,'Learn about how some people make a living by selling what they upcycle.  What type of items seem to sell the best?');
INSERT INTO badge_level_requirements VALUES(4840,683,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4841,684,'preschool',0,'What is abandoned (urban) exploration? Look at photos of local abandoned areas OPEN TO THE PUBLIC that your leaders have prepared.  What’s interesting about the photos?');
INSERT INTO badge_level_requirements VALUES(4842,684,'level1',1,'and 2.');
INSERT INTO badge_level_requirements VALUES(4843,684,'level1',2,'What should you do if you get separated from your group while exploring? Safety in abandoned (urban) exploration is key.  What are some things we can do to stay safe while exploring?  Even if the space is public, should you enter a building that you aren’t specifically allowed (by site facilitator)  to enter?  Why or why not?');
INSERT INTO badge_level_requirements VALUES(4844,684,'level2',3,'Participate in the “going on an adventure” game.  In this game, scouts will have a hiking pack they must fill with any items needed to go on an urban exploration.  Items ( some needed and some not- some even silly for entertainment value) will be placed in the center of the table.  Each scout will choose an item, fill the pack with it and explain why they chose it ( i.e. why it could be useful for abandoned (urban) exploration)');
INSERT INTO badge_level_requirements VALUES(4845,684,'level3',4,'Visit an abandoned site open to the public and explore.');
INSERT INTO badge_level_requirements VALUES(4846,684,'level4',5,'Choose from a local list of PUBLIC abandoned places within driving distance to visit.  Research your site and try and convince your club or family on why they should visit your chosen site.  Information to include: Directions Location Distance to home Hours of visitation What ruins exist and why they are interesting General history of the area Any other information of interest Pictures Find at least one other area of interest near (park, small hiking trail, rest stop, etc). Use your creativity when presenting the information!  Make a brochure, give an oral presentation, make a posterboard (visual) presentation, or even make a commercial!  It’s up to you how you present, however you must answer questions from the group when you are done presenting. Be prepared to do so!  If you don’t know the answer, be prepared to look it up!');
INSERT INTO badge_level_requirements VALUES(4847,684,'level5',6,'Present any experiences you have had in urban ( abandoned) exploration.  Who were you with?  What were you exploring? How long ago did you go? Where was the site? Why did you choose to explore? How did you stay safe while exploring? Or * do 2 additional requirements.');
INSERT INTO badge_level_requirements VALUES(4848,685,'preschool',0,'Learn the three branches of government and the roles of each. (Note: At the Preschool Level, kids should understand the basic concepts of rules and who is in charge, but are not required to remember the vocabulary.  Level 1 and above should know the names of all three branches and what they do).  Know the names of the President and Vice President and be able to recognize them. Executive – President – Enforces laws Legislative – Makes the laws Judicial – Interprets the laws');
INSERT INTO badge_level_requirements VALUES(4849,685,'preschool',1,'Learn the 3 freedoms guaranteed in the constitution.  (Note: Higher levels should be able to tell you what these are, but Preschoolers should simply learn the ideas of what these mean). Freedom of Speech Freedom of Religion Freedom of Peaceful Assembly');
INSERT INTO badge_level_requirements VALUES(4850,685,'level1',2,'Know the names of the two parts of Congress.');
INSERT INTO badge_level_requirements VALUES(4851,685,'level1',3,'Learn when the constitution was created and why.');
INSERT INTO badge_level_requirements VALUES(4852,685,'level2',4,'Know who the Speaker of the House is. What is their role?');
INSERT INTO badge_level_requirements VALUES(4853,685,'level2',5,'Be able to explain what the constitution is and all its parts. What is an “amendment” and how many are there?  What are they for? What is the Bill of Rights?');
INSERT INTO badge_level_requirements VALUES(4854,685,'level3',6,'Pick a current event or issue and explain why you think it is, or is not, constitutional.  For example, we are guaranteed freedom of speech in the first amendment, but does that mean you should be allowed to yell, “Fire!” in the middle of a movie theater?  We are guaranteed freedom of religion without the government telling us what we should believe.  Does this mean people should not be allowed to pray at school?');
INSERT INTO badge_level_requirements VALUES(4855,685,'level4',7,'How many Supreme Court Justices are there? Who are they and how do they normally rule?');
INSERT INTO badge_level_requirements VALUES(4856,685,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4857,686,'preschool',0,'Find the United States on a world map or globe. Identify the two countries and the two oceans that flank the U.S.');
INSERT INTO badge_level_requirements VALUES(4858,686,'preschool',1,'Find your state on the map. Know your state capital. Find your hometown on a state map.');
INSERT INTO badge_level_requirements VALUES(4859,686,'level1',2,'Identify each of the states that border your own.');
INSERT INTO badge_level_requirements VALUES(4860,686,'level1',3,'Know and find the U.S. capital (Washington, D.C.) on a map. For what does D.C. stand?');
INSERT INTO badge_level_requirements VALUES(4861,686,'level2',4,'On a map, identify the longest river, biggest lake, tallest mountain, deepest canyon and largest desert in the United States.');
INSERT INTO badge_level_requirements VALUES(4862,686,'level3',5,'Identify all 50 states on a blank map of the U.S. and know the capital of each.');
INSERT INTO badge_level_requirements VALUES(4863,686,'level4',6,'Know what a U.S. Territory is and how it differs from a state.  Find out how many there are, their names and where they are located.  Find each of them on a map.');
INSERT INTO badge_level_requirements VALUES(4864,686,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4865,687,'preschool',0,'Understand the 3 jobs our government has (making laws, enforcing laws, and deciding when someone has broken a law).  Find Washington DC on a map.  Understand that this is where our national government works.  Look at pictures of the White House, the Capitol Building and the Supreme Court.');
INSERT INTO badge_level_requirements VALUES(4866,687,'preschool',1,'Learn where some of your city or town’s government offices (i.e.: city hall, police station, etc.) are located.  Arrange a visit with one if possible.  Find out which services are run by your city council e.g.; fire dept, police, library, animal control etc.');
INSERT INTO badge_level_requirements VALUES(4867,687,'level1',2,'Do Preschool 1 & 2.  What are the three branches of government? What are the main jobs of each branch?');
INSERT INTO badge_level_requirements VALUES(4868,687,'level1',3,'What are the four most common levels of government? Which ones are considered “local government?”  Look up on a map where each level has jurisdiction (city, county, state, federal).');
INSERT INTO badge_level_requirements VALUES(4869,687,'level2',4,'Do Level 1 #1. Learn the names of the people currently presiding (learn what that word means) over the U.S. House of Representatives and the Senate. What are the names of their positions? Learn the names, ages, and home states of our president and the chief justice of the Supreme Court. What are the main buildings in Washington DC where each works?');
INSERT INTO badge_level_requirements VALUES(4870,687,'level2',5,'Do Level 1 #2. Where does each level of government get its operating money? Who are the authorities over each level (to whom are they accountable)?');
INSERT INTO badge_level_requirements VALUES(4871,687,'level3',6,'Do Level 2 #1. What are the terms of office for all the people mentioned in Level 2 #1? How do they get their jobs? Are all of them elected all the time?');
INSERT INTO badge_level_requirements VALUES(4872,687,'level3',7,'Do Level 2 #2. What are recalls? What is impeachment? What is the difference between getting fired, resigning, and getting recalled?');
INSERT INTO badge_level_requirements VALUES(4873,687,'level4',8,'Do Level 3 #1. What is the typical professional background for the people mentioned in Level 2 #1?');
INSERT INTO badge_level_requirements VALUES(4874,687,'level4',9,'Do Level 3 #2. Learn the meaning of monarchy, constitutional monarchy, oligarchy, theocracy, democracy, and a republic.');
INSERT INTO badge_level_requirements VALUES(4875,687,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4876,688,'preschool',0,'Learn the names of three symbols of the United States of America and be able to identify them in pictures. Examples may include the Liberty Bell, Statue of Liberty, Great Seal of the United States, Uncle Sam, etc.');
INSERT INTO badge_level_requirements VALUES(4877,688,'preschool',1,'Learn why the Pilgrims wanted to come to America and the name of the ship they sailed on to get here.');
INSERT INTO badge_level_requirements VALUES(4878,688,'level1',2,'Learn about at least five symbols of the United States of America and a bit of history behind each.');
INSERT INTO badge_level_requirements VALUES(4879,688,'level1',3,'Learn about how the United States became a nation. Understand why the first colonists came to America and why we rebelled against England. Understand how America differs from any other country in the world.');
INSERT INTO badge_level_requirements VALUES(4880,688,'level2',4,'but learn about at least seven symbols.');
INSERT INTO badge_level_requirements VALUES(4881,688,'level2',5,'Understand who our “founding fathers” were and how they continue to impact our country today. Know what the following documents are: Declaration of Independence, Bill of Rights, and U.S. Constitution.');
INSERT INTO badge_level_requirements VALUES(4882,688,'level3',6,'Learn about at least ten symbols.');
INSERT INTO badge_level_requirements VALUES(4883,688,'level3',7,'Learn the history of the U.S. flag, the national anthem, the U.S. motto, the Great Seal of the United States, and the Pledge of Allegiance.');
INSERT INTO badge_level_requirements VALUES(4884,688,'level4',8,'Make a timeline of at least 50 events in U.S. history.');
INSERT INTO badge_level_requirements VALUES(4885,688,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(4886,689,'level1',0,'Memorize the names of either the first ten or the most recent ten US presidents in order.');
INSERT INTO badge_level_requirements VALUES(4887,689,'level1',1,'. Be able to list a significant fact about or an accomplishment of five of the presidents whose names you learned for #1.');
INSERT INTO badge_level_requirements VALUES(4888,689,'level2',2,'Memorize 15 presidents and be able to tell a significant fact about or an accomplishment for each of them.');
INSERT INTO badge_level_requirements VALUES(4889,689,'level2',3,'Why do we have a president?  What is a president''s job?  What are the qualifications for being president?  What oath must a president take when they are sworn in?');
INSERT INTO badge_level_requirements VALUES(4890,689,'level4',4,'Read at least three biographies of three different presidents.  What did you learn that you didn''t know before?');
INSERT INTO badge_level_requirements VALUES(4891,690,'preschool',0,'What is a vacation and why do people need them?');
INSERT INTO badge_level_requirements VALUES(4892,690,'preschool',1,'If you could take a vacation anywhere, where would it be and why?');
INSERT INTO badge_level_requirements VALUES(4893,690,'level1',2,'Take a vacation and keep a vacation journal with words or drawings.  The journal should have one entry every day explaining what you did on your vacation that day.');
INSERT INTO badge_level_requirements VALUES(4894,690,'level2',3,'Learn 5 interesting facts about your vacation destination (like the population, how many people vacation there each year, if any famous people live there or were born there, if there are any museums or historical sites there, if the place has any rare wildlife, etc).  Tell someone the most interesting fact you find.');
INSERT INTO badge_level_requirements VALUES(4895,690,'level3',4,'What kind of clothing, accessories, and supplies do you need for your vacation?  Make a packing list.  Pay attention to the climate of the place you will be vacationing when making choices.  Will you need sunscreen,  winter boots,  sports equipment, a tent, something else?');
INSERT INTO badge_level_requirements VALUES(4896,690,'level4',5,'Vacations don’t have to be expensive.  Choose a dollar amount you think you could save within a few years.  Where could you go on that amount of money?  Research how to find cheap flights like red eyes or travel deals like those offered through websites like Travel Zoo.  What lodging could you use?  Can you stay with a friend or relative?  A hostel?  An Airbnb?  What activities could you do for free?  How can you budget food rather than eat in restaurants every day?');
INSERT INTO badge_level_requirements VALUES(4897,690,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
