INSERT INTO badge_level_requirements VALUES(5032,707,'preschool',0,'Learn about the severe weather events that can affect your home town.  These may include hurricanes, tornadoes, blizzards, thunderstorms, ice storms, or high winds.');
INSERT INTO badge_level_requirements VALUES(5033,707,'preschool',1,'Be able to explain what to do to stay safe in each of the conditions you learned about in requirement # 1.');
INSERT INTO badge_level_requirements VALUES(5034,707,'level1',2,'Make a disaster plan with your family and put together a survival kit that includes items such as first aid, flashlights,  radio, canned or dried food, and bottled water.');
INSERT INTO badge_level_requirements VALUES(5035,707,'level2',3,'Keep a weather log for at least one week.  Every day record the following information: •        Temperature •        Cloud types •        Wind speed and direction •        Rain fall');
INSERT INTO badge_level_requirements VALUES(5036,707,'level3',4,'Find at least 6 weather-related stories in newspapers, magazines, or the internet about recent storms or natural disasters.  What meteorological events do the articles mention?  Do particular areas of the world seem to be more affected by bad weather than others?  Which areas are they and can you think why this might be true?');
INSERT INTO badge_level_requirements VALUES(5037,707,'level4',5,'Be able to explain how each of the following instruments are used: •        Thermometer •        Barometer •        Psychrometer •        Rain gauge •        Wind vane •        Anemometer •        Weather maps •        Weather balloons •        Hygrometer •        Weather satellite');
INSERT INTO badge_level_requirements VALUES(5038,707,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5039,709,'preschool',0,'.  Learn what a wedding is, and what happens at one. Learn proper etiquette at a wedding.');
INSERT INTO badge_level_requirements VALUES(5040,709,'level1',1,'.  Do Preschool requirement 1*.');
INSERT INTO badge_level_requirements VALUES(5041,709,'level1',2,'.  Learn the different parts of a wedding: Processional, Invocation, Reading, Vows, Exchange of Rings, Recessional, and Reception.');
INSERT INTO badge_level_requirements VALUES(5042,709,'level2',3,'.  Do Level 1 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(5043,709,'level2',4,'.  Understand the difference between a religious wedding ceremony and a civil service.');
INSERT INTO badge_level_requirements VALUES(5044,709,'level3',5,'.  Do Level 2 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(5045,709,'level3',6,'.  Learn what the “wedding party” is, who it includes, and their respective positions and responsibilities: GroomBrideFather of the BrideFather of the GroomMother of the BrideMother of the GroomMatron/Maid of HonourBest ManBridesmaid(s)Groomsman/menRing BearerFlower Girl');
INSERT INTO badge_level_requirements VALUES(5046,709,'level4',7,'.  Do Level 3 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(5047,709,'level4',8,'. Learn how to correctly word a wedding invitation. What are “response cards”?');
INSERT INTO badge_level_requirements VALUES(5048,709,'level4',9,'.  Discuss with your parents what marriage means. Look at samples of different wedding vows. Why are the vows important? Do you and your parents believe that the bride should promise to submit to and obey her husband? What does this mean?');
INSERT INTO badge_level_requirements VALUES(5049,709,'level5',10,'.  Do Level 4 requirements 1, 2 & 3.');
INSERT INTO badge_level_requirements VALUES(5050,709,'level5',11,'.  Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5051,710,'preschool',0,'Learn the appropriate safety rules when around someone who is welding.');
INSERT INTO badge_level_requirements VALUES(5052,710,'preschool',1,'What is welding? What is it used for? Find three pictures of items that have been welded.');
INSERT INTO badge_level_requirements VALUES(5053,710,'level1',2,'and 2. Learn the appropriate safety rules when welding.  These should include how to check your equipment for safety, make sure your work space is safe, ventilated, and uncluttered, and knowing what type of clothing and shoes you should wear, including safety goggles and a hood.  Make sure you know any safety rules for working with specific tools or metal types.');
INSERT INTO badge_level_requirements VALUES(5054,710,'level1',3,'Be able to identify at least three of the nine basic metals: carbon steel, cast iron, stainless steel, copper, brass, lead, aluminum, magnesium, and pot metal/white metal.  Which is the easiest metal to work with when welding?');
INSERT INTO badge_level_requirements VALUES(5055,710,'level2',4,'Identify at least 5 of the nine basic metals used in welding and a common use for each.');
INSERT INTO badge_level_requirements VALUES(5056,710,'level2',5,'What is the definition of welding and how does it differ from other types of metal work?');
INSERT INTO badge_level_requirements VALUES(5057,710,'level3',6,'but learn all nine basic metals and what each is commonly used for.');
INSERT INTO badge_level_requirements VALUES(5058,710,'level3',7,'Know how to treat the most common welding injuries including burns and eye injuries.');
INSERT INTO badge_level_requirements VALUES(5059,710,'level4',8,'Take a field trip to visit a welder at his/her shop.  If you cannot actually visit a welder, watch welding videos online or a documentary on welding.');
INSERT INTO badge_level_requirements VALUES(5060,710,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5061,711,'preschool',0,'Talk about ways you can avoid panic and keep a positive attitude when you are lost.  Why is this so important?');
INSERT INTO badge_level_requirements VALUES(5062,711,'preschool',1,'Show five different ways to attract attention when lost.  ”Hug a tree” is one way of saying stay put when you discover you are lost.  Why is this important?');
INSERT INTO badge_level_requirements VALUES(5063,711,'level1',2,'Do Preschool Requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(5064,711,'level1',3,'Learn how to recognize dangerous plants and animals in your area, such as poison oak or rattlesnakes,  and what to do if you encounter them.');
INSERT INTO badge_level_requirements VALUES(5065,711,'level2',4,'Do Level 1 requirements #1 & 2.  Demonstrate how to use a signal mirror. Describe five ground-to-air signals and be able to explain what they mean.');
INSERT INTO badge_level_requirements VALUES(5066,711,'level2',5,'Be able to recite from memory the seven priorities for survival in a back country or wilderness location. What is the importance of each?  Explain how to protect yourself from insects, reptiles, and bears.');
INSERT INTO badge_level_requirements VALUES(5067,711,'level3',6,'Do Level 2 requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(5068,711,'level3',7,'Show that you know first aid for, and how to prevent injuries or illnesses that could occur in back country settings, including hypothermia, heat reactions, frostbite, dehydration, blisters, insect stings, tick bites, and snake bites.  Explain what the proper clothing to wear in your area would be for an overnight camp out in extremely hot weather and in extremely cold weather.');
INSERT INTO badge_level_requirements VALUES(5069,711,'level4',8,'Do Level 3 requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(5070,711,'level4',9,'Using three different methods (other than matches), build and light three fires. Know how to start a fire in the wind or in wet weather.');
INSERT INTO badge_level_requirements VALUES(5071,711,'level5',10,'Do Level 4 requirements #1 & 2');
INSERT INTO badge_level_requirements VALUES(5072,711,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5073,712,'preschool',0,'Learn the difference between wildflowers and cultivated flowers. Why might a gardener choose one over the other?');
INSERT INTO badge_level_requirements VALUES(5074,712,'level1',1,'Find at least three different wildflowers in your neighborhood and learn their names.');
INSERT INTO badge_level_requirements VALUES(5075,712,'level2',2,'but find and learn the names of at least five wildflowers. Learn the different parts of a flower including the pistal, style, ovary, stamen, anther, filament, stem, leaf, petals, and sepal.');
INSERT INTO badge_level_requirements VALUES(5076,712,'level2',3,'Learn about a famous person connected with wildflowers, such as Benny Simpson, who was a Texas Parks and wildlife plant identifier and collected/identified many hundreds of plants.');
INSERT INTO badge_level_requirements VALUES(5077,712,'level3',4,'Find and learn the names of at least seven wildflowers.');
INSERT INTO badge_level_requirements VALUES(5078,712,'level3',5,'Learn the Latin names of at least three of the flowers from requirement 1.');
INSERT INTO badge_level_requirements VALUES(5079,712,'level4',6,'Find and learn the names of at least nine wildflowers.');
INSERT INTO badge_level_requirements VALUES(5080,712,'level4',7,'Learn the family names of at least five flowers, including the ones you learned about for Level 3 requirement 2.');
INSERT INTO badge_level_requirements VALUES(5081,712,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5082,713,'preschool',0,'Learn who Will Rogers was.');
INSERT INTO badge_level_requirements VALUES(5083,713,'preschool',1,'List two things that made Will Rogers unique. What was his special talent?');
INSERT INTO badge_level_requirements VALUES(5084,713,'level1',2,'List the 5 “professions” Will held during his lifetime.');
INSERT INTO badge_level_requirements VALUES(5085,713,'level2',3,'Learn a few of the witticisms Will Rogers was famous for.');
INSERT INTO badge_level_requirements VALUES(5086,713,'level3',4,'Read at least two of the columns by Will Rogers.');
INSERT INTO badge_level_requirements VALUES(5087,713,'level4',5,'Discuss why Will was respected by so many people, even though he poked fun at so many.');
INSERT INTO badge_level_requirements VALUES(5088,713,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5091,715,'preschool',0,'Learn what clothes to wear in cold weather. Practice dressing in warm layers with help from an adult.  Why is layering important?');
INSERT INTO badge_level_requirements VALUES(5092,715,'preschool',1,'Explore how animals survive winter—learn about hibernation, fur insulation, and migration—and draw comparisons to human survival gear and actions.');
INSERT INTO badge_level_requirements VALUES(5093,715,'level1',2,'Create a checklist of supplies and actions your family would need in a winter power outage.');
INSERT INTO badge_level_requirements VALUES(5094,715,'level2',3,'Make a winter survival kit to keep in your car during the winter.  Items that can be included are things like a first aid kit, tire chains, flares, matches, water & snacks, flashlight, blanket, tow rope, ice scraper, kitty litter or sand, a shovel, and warm clothes.  Be able to explain why each item is important in case of an emergency.');
INSERT INTO badge_level_requirements VALUES(5095,715,'level3',4,'Study the history of winter survival techniques used by explorers, Indigenous peoples, or mountain rescue teams. How did they adapt to their environments?');
INSERT INTO badge_level_requirements VALUES(5096,715,'level4',5,'Learn how to build a temporary winter shelter such as a snow cave, lean-to, or emergency bivvy. If possible, build a model or real version.');
INSERT INTO badge_level_requirements VALUES(5097,715,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(5100,717,'preschool',0,'What is a group of wolves called? What are the different “ranks” among wolves?');
INSERT INTO badge_level_requirements VALUES(5101,717,'preschool',1,'Why does a wolf howl?');
INSERT INTO badge_level_requirements VALUES(5102,717,'level1',2,'Draw a detailed picture of a wolf and label the different body parts that are different from humans.');
INSERT INTO badge_level_requirements VALUES(5103,717,'level2',3,'Learn about a wolf’s diet. What type of animals do they prey on? How do they hunt?');
INSERT INTO badge_level_requirements VALUES(5104,717,'level3',4,'Watch a documentary about wolves and take notes on what you learn.');
INSERT INTO badge_level_requirements VALUES(5105,717,'level4',5,'List twenty different wolf breeds. Learn one fact about each breed.');
INSERT INTO badge_level_requirements VALUES(5106,717,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(5107,718,'preschool',0,'. Learn about a woman or girl that helped to make or change history, such as Amelia Bloomer, Amelia Earhart, or Sacagawea. What did they do and how did it change things?');
INSERT INTO badge_level_requirements VALUES(5108,718,'level1',1,'. Do Preschool requirement 1, but learn about 2 women or girls.');
INSERT INTO badge_level_requirements VALUES(5109,718,'level1',2,'. Find a well-known woman and locate her home country on a map. If possible, find her hometown as well.');
INSERT INTO badge_level_requirements VALUES(5110,718,'level2',3,'. Do Level 1 requirements 1 & 2, but learn about 3 different women or girls.');
INSERT INTO badge_level_requirements VALUES(5111,718,'level2',4,'. Make a timeline of events in history when women or girls, such as Joan of Arc, Marie Curie, or those mentioned in Preschool 1, have helped to change history. You must have at least 10 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(5112,718,'level3',5,'. Do Level 2 requirements 1 & 2, but learn about 4 different women or girls and have 15 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(5113,718,'level3',6,'. Find on a map at least 3 places connected with each of the girls/women you learned about for requirement 1.');
INSERT INTO badge_level_requirements VALUES(5114,718,'level4',7,'. Do Level 3 requirements 1 & 2, but learn about 5 different women or girls and have at least 20 items on your timeline.');
INSERT INTO badge_level_requirements VALUES(5115,718,'level4',8,'. Find and learn about six Famous First women, such as Margaret Thatcher (first woman Prime Minister of Britain), Sandra Day O’Connor (first woman Supreme Court Justice), Frances Perkins (first U. S. woman to hold a cabinet post), etc.');
INSERT INTO badge_level_requirements VALUES(5116,718,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5121,721,'preschool',0,'What is woodworking? What are some things that woodworkers would make? Find three pictures of something a woodworker made. These can be anything from bookshelves to jewelry boxes.');
INSERT INTO badge_level_requirements VALUES(5122,721,'preschool',1,'Look at three different types of wood i.e: oak, pine, cherry. Be able to identify a knot in a piece of wood.');
INSERT INTO badge_level_requirements VALUES(5123,721,'preschool',2,'With the help of an adult, make a simple wood project.');
INSERT INTO badge_level_requirements VALUES(5124,721,'level1',3,'Find ten things in your house made from wood. Learn what hardwood and softwood are. How can you tell them apart? What are lumber, plywood, and molding?');
INSERT INTO badge_level_requirements VALUES(5125,721,'level1',4,'Be able to identify the following tools: hand saw, combination square, C-clamp, sawhorse, claw hammer, plane, file, hand drill, nails, screws, and sandpaper. Practice pounding five nails into wood. Leave one sticking up just a little and then remove it using the back of your hammer. When should a person wear safety goggles near woodworking?');
INSERT INTO badge_level_requirements VALUES(5126,721,'level1',5,'Make something out of wood. For safety reasons, have an adult cut your wood for you or buy a kit with pre-cut pieces. You may do the gluing, sanding, nailing, and/or screwing.');
INSERT INTO badge_level_requirements VALUES(5127,721,'level2',6,'Do Level 1 #1. Be able to name three types of softwood and three types of hardwood. How is a knot formed in wood? What is the grain of wood? Can you explain which direction to cut wood for more strength?');
INSERT INTO badge_level_requirements VALUES(5128,721,'level2',7,'If this is your first time doing this badge, do Level 1 #2 plus be able to identify the following: vise, awl (or punch), nail set, putty knife, mallet, and chisel. If your family doesn’t own all of them, go look at them in a store. You also need to be able to identify an electric drill, table or circular saw, and jigsaw. Why could sweeping up one’s sawdust be a safety issue?');
INSERT INTO badge_level_requirements VALUES(5129,721,'level2',8,'Make something out of wood pieces that an adult has already cut. Your project needs to use either nails or screws and one of the following procedures: sanding, painting, varnishing, gluing or wood burning (with adult permission and help).');
INSERT INTO badge_level_requirements VALUES(5130,721,'level3',9,'Do Level 2 #1. What are burls? How do furniture makers make new pieces of furniture look like they are antiques? Find out what paneling and hardboard are.');
INSERT INTO badge_level_requirements VALUES(5131,721,'level3',10,'Do Level 2 #2. Practice on scrap lumber (unless you know it will be included in your project for #3) the following: drilling at least five holes, pounding in ten nails, screwing in five screws, and chiseling a groove at least three inches in length.');
INSERT INTO badge_level_requirements VALUES(5132,721,'level3',11,'Make a wood project using at least one piece you have cut (with adult supervision). If you use any electric tools, go over the safety rules beforehand and review first aid needed for cuts, abrasions, and bruises. Why should you wear a dust mask when working with electric tools?');
INSERT INTO badge_level_requirements VALUES(5133,721,'level4',12,'If you did not earn this badge at Level 3, do Level 3 #1. If you did do it at Level 3, go to a lumberyard and familiarize yourself with the most common types of wood, their uses, and common sizes of boards. Learn the names of eight trees used for lumber or woodcrafting. Be able to identify those trees by their leaves, needles, or bark and familiarize yourself with the appearance of the cut wood. Ask someone at the lumberyard about grades of lumber—what can be used in building a house versus a fence?');
INSERT INTO badge_level_requirements VALUES(5134,721,'level4',13,'Do Level 3 #2 and practice cutting a board in half.');
INSERT INTO badge_level_requirements VALUES(5135,721,'level4',14,'Do Level 3 #3, but cut all pieces for the project yourself.');
INSERT INTO badge_level_requirements VALUES(5136,721,'level5',15,'Do Eagle requirements 1 & 2 & 3');
INSERT INTO badge_level_requirements VALUES(5137,721,'level5',16,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5138,722,'preschool',0,'. What are words? How can we use words to communicate? Words help us to express how we feel; what we see; what we are doing; what we are thinking about. Words help us to learn about the world in which we live. Learn a new word. What does it mean?');
INSERT INTO badge_level_requirements VALUES(5139,722,'level1',1,'. Do Preschool requirement 1*. Learn 5 new words, and what they mean.');
INSERT INTO badge_level_requirements VALUES(5140,722,'level1',2,'. Learn what the following types of words are: verbs, adjectives and nouns.');
INSERT INTO badge_level_requirements VALUES(5141,722,'level2',3,'. Do Level 1 requirements 1 & 2. Learn 10 new words and their meanings. Know what the following types of words are: adverbs; contractions; pronouns.');
INSERT INTO badge_level_requirements VALUES(5142,722,'level2',4,'. Learn how to use a dictionary to look up words. Learn how to put words in alphabetical order to the second letter of the words.');
INSERT INTO badge_level_requirements VALUES(5143,722,'level3',5,'. Do Level 2 requirements 1 & 2. Learn 15 new words, and teach them to someone else. Know what the following types of words are: homonyms; synonyms; antonyms; prepositions; conjunctions.');
INSERT INTO badge_level_requirements VALUES(5144,722,'level3',6,'. Learn how to use a thesaurus and a rhyming dictionary. Learn how to put words in alphabetical order to the third letter of the words.');
INSERT INTO badge_level_requirements VALUES(5145,722,'level4',7,'. Do Level 3 requirements 1 & 2. Learn 20 new words and teach them to someone else. Know what the following types of words are: gerunds; spoonerisms; malapropisms; and homophones, and know what it means when a verb is transitive or intransitive. Learn how to put words in alphabetical order to their final letters.');
INSERT INTO badge_level_requirements VALUES(5146,722,'level4',8,'. Learn how and when foreign languages including Latin, Greek, Sanskrit, French, German, Spanish, and Italian, became part of the English language. Be able to interpret the pronunciation and etymology guides correctly.');
INSERT INTO badge_level_requirements VALUES(5147,722,'level5',9,'.  Do Level 4 requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(5148,722,'level5',10,'. Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5151,724,'preschool',0,'Watch three different types of dances from another country or culture. What makes these dances different than ones you have seen before?');
INSERT INTO badge_level_requirements VALUES(5152,724,'level1',1,'Learn a dance from another country or culture. A few examples include: A maypole dance from England The Hula from Hawaii & the Polynesian Islands The Cha Cha, Rumba, Tango, or Merengue from Latin America A Bollywood dance from India A Native American Powwow dance The Flamenco from Spain The Hora from Israel The Kazatzka from Russia The Viennese Waltz from Austria.');
INSERT INTO badge_level_requirements VALUES(5153,724,'level2',2,'but learn 2 dance types.');
INSERT INTO badge_level_requirements VALUES(5154,724,'level2',3,'Dance has always been more than just performance art. It has been an integral part of each country’s culture. Make a list of different events or festivals that incorporates dance. For example weddings, storytelling, or prayer.');
INSERT INTO badge_level_requirements VALUES(5155,724,'level3',4,'except learn 3 different dances.');
INSERT INTO badge_level_requirements VALUES(5156,724,'level3',5,'Create a timeline of dances from around the world. What is the most ancient dance you can find? What about the most recent?');
INSERT INTO badge_level_requirements VALUES(5157,724,'level4',6,'except learn 4 different dances.');
INSERT INTO badge_level_requirements VALUES(5158,724,'level4',7,'Research the history of dance and write an essay, create a booklet, or create some type of display to share with others what you have learned.');
INSERT INTO badge_level_requirements VALUES(5159,724,'level5',8,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5162,726,'preschool',0,'Learn what continents, rivers and mountains are.  Learn which continent we live on.');
INSERT INTO badge_level_requirements VALUES(5163,726,'preschool',1,'Learn what an ocean is and which oceans border the continent on which we live.');
INSERT INTO badge_level_requirements VALUES(5164,726,'level1',2,'Do Preschool 1 & 2.  Learn and be able to identify on a map all seven continents: North America, South America, Europe, Asia, Australia, Africa and Antarctica.');
INSERT INTO badge_level_requirements VALUES(5165,726,'level1',3,'Learn and be able to identify on a map all 4 oceans: Pacific, Atlantic, Indian and Arctic. (Some maps also list the Southern Ocean).');
INSERT INTO badge_level_requirements VALUES(5166,726,'level2',4,'Choose South America, Africa, Europe or Asia and learn all the countries on your continent. Learn where the Mediterranean Sea, the Black Sea, the Red Sea, and the Caspian Sea are located.');
INSERT INTO badge_level_requirements VALUES(5167,726,'level3',5,'If you earned this badge at Level 2, choose a different continent to study.');
INSERT INTO badge_level_requirements VALUES(5168,726,'level3',6,'Learn where the Arabian Sea, South China Sea, Sea of Japan, and the Bering Sea are located.');
INSERT INTO badge_level_requirements VALUES(5169,726,'level4',7,'If you earned this badge at either Level 2 or Level 3, choose a new continent to study.');
INSERT INTO badge_level_requirements VALUES(5170,726,'level4',8,'Learn where Polynesia, the Caribbean Islands, the Bahamas, Fiji Islands, Micronesia, the Hawaiian Islands, and French Polynesia are located.');
INSERT INTO badge_level_requirements VALUES(5171,726,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5172,727,'preschool',0,'Learn where your chosen geographic area is. Which continent is it on?  Find it on a map');
INSERT INTO badge_level_requirements VALUES(5173,727,'preschool',1,'How do people spend their free time?  What do they do for entertainment?  What toys do the children have?  Learn a game from your chosen area or play with a toy from that area.');
INSERT INTO badge_level_requirements VALUES(5174,727,'level1',2,'Learn about the food of your chosen area.  What do most people eat?  How much do groceries cost compared with where you live?  Where does the food come from? Is it locally grown or imported?  Try a recipe from your area.');
INSERT INTO badge_level_requirements VALUES(5175,727,'level2',3,'Learn about the history of your chosen area. When was it first inhabited? By whom? Create a timeline of settlement of your area with at least 10 items (15 for Level 3 and 4, 20 for Level 5). How do the different historic factors affect and continue to shape the region?');
INSERT INTO badge_level_requirements VALUES(5176,727,'level3',4,'Find out which time zone your chosen location is in. How many hours different is it from where you live? How many hours different from Greenwich Mean Time (GMT) is it?');
INSERT INTO badge_level_requirements VALUES(5177,727,'level4',5,'Learn about traditional occupations for your area. Are these occupations still major economic activities today? How have the commercial/industrial activities of the area changed through its history? What jobs do most people do today? How do the different industrial factors affect and continue to shape the region?');
INSERT INTO badge_level_requirements VALUES(5178,727,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5181,729,'preschool',0,'Learn at least 3 symbols for peace that are used in artwork.');
INSERT INTO badge_level_requirements VALUES(5182,729,'preschool',1,'What would world peace look like? Discuss with an adult or with your club.');
INSERT INTO badge_level_requirements VALUES(5183,729,'level1',2,'Learn the history of each peace symbol and where it came from.');
INSERT INTO badge_level_requirements VALUES(5184,729,'level1',3,'Create a piece of artwork expressing world peace. This could be a drawing, painting, sculpture, collage, piece of jewelry, quilt, or anything else you can think of.');
INSERT INTO badge_level_requirements VALUES(5185,729,'level2',4,'Learn what bigotry is and what prejudiced means. Is there bigotry in your own community? What are your own fears and prejudices about people who are different from you? Try to find things you have in common instead of focusing on your differences. If possible, meet someone from another country or religion and invite them to share their culture with you.');
INSERT INTO badge_level_requirements VALUES(5186,729,'level3',5,'Choose an issue that affects world peace such as weapons of mass destruction, over-population, religious tensions, or world hunger and read articles or listen to someone speak about your issue. Find out different points of view and then share your opinions with your club or family.');
INSERT INTO badge_level_requirements VALUES(5187,729,'level4',6,'Write a letter to the president of the United States, or to your congressman/woman asking specific questions about world peace issues. If you have ideas for them, feel free to share them as well. Include a return address so that they can write you back.');
INSERT INTO badge_level_requirements VALUES(5188,729,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5189,730,'preschool',0,'Understand what a religion is.  Know what religion, if any, your family practices.  Understand that other families, especially in other parts of the world, may have different beliefs and follow a different religion.');
INSERT INTO badge_level_requirements VALUES(5190,730,'preschool',1,'The golden rule, “Love your neighbor as yourself” is present in almost every religion around the world.  Learn what the golden rule means and how you can live this rule in your own life. If your family is religious, learn this rule from your book of faith.');
INSERT INTO badge_level_requirements VALUES(5191,730,'level1',2,'Talk to someone who practices a different religion than your family.  What do you have in common?  What are your differences?  If you can’t find someone to talk to, choose a religion different from yours to learn about.  What do they have in common with your own beliefs?  What are their differences?');
INSERT INTO badge_level_requirements VALUES(5192,730,'level2',3,'Learn about at least three different religions other than your own.');
INSERT INTO badge_level_requirements VALUES(5193,730,'level3',4,'Choose 6 different world religions and find out the following: Where in the world is this religion mainly practiced? Is it monotheistic, polytheistic, or nontheistic? Origins of the religion.  Where and when was it founded?    What are the major beliefs or emphases of this religion? What are the scriptures or holy texts/books of this religion? Who are the key figures of this religion? What are the major values or rules for human behavior? What are the key holidays/holy days/religious observances What is unique about this religion relative to other religions? What is similar about the religion relative to other religions?');
INSERT INTO badge_level_requirements VALUES(5194,730,'level4',5,'Intolerance and persecution of other religions has led to conflict, bloodshed and war over the centuries.  Learn about at least 6 different major religious persecutions or conflicts.  Examples include the Crusades, the Inquisition, the Holocaust, or the Palestine/Israel Conflict.  How does religious beliefs play a role in these events?');
INSERT INTO badge_level_requirements VALUES(5195,730,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5196,731,'preschool',0,'What are worms? What do they look like? Many different animals are considered worms. Find out what several of them look like. (For example: Earthworms, caterpillars, roundworms, flatworms, grubs, maggots, and, historically, carnivorous reptiles/serpents/dragons)');
INSERT INTO badge_level_requirements VALUES(5197,731,'preschool',1,'Find out where earthworms live. Where is the best place to find them? Go on a worm hunt and see if you can dig some up. Be careful when you dig so that you do not harm any worms that you find. Looking for worms just after a heavy rain is easy as many of the worms will come to the surface.');
INSERT INTO badge_level_requirements VALUES(5198,731,'level1',2,'Do Preschool requirements # 1 & 2.');
INSERT INTO badge_level_requirements VALUES(5199,731,'level1',3,'Find out why worms are important to the environment. Why are worms important for healthy plants? What type of worms can harm plants?');
INSERT INTO badge_level_requirements VALUES(5200,731,'level2',4,'Do Level 1 requirements # 1 & 2.');
INSERT INTO badge_level_requirements VALUES(5201,731,'level2',5,'Learn the basic body parts of an earthworm. Identify the pharynx, esophagus, crop, gizzard, intestine, bloodstream, and anus, and know what each does. Worms have no lungs. How do they breathe? Be able to identify the differences between a flat worm, round worm, and segmented worm.');
INSERT INTO badge_level_requirements VALUES(5202,731,'level3',6,'Do Level 2 requirements # 1 & 2.');
INSERT INTO badge_level_requirements VALUES(5203,731,'level3',7,'Some worms are parasites and can harm humans and animals. Find out about at least three of the following worms and how they can bring harm. What can you do to prevent these types of worms from getting into your system and how do you treat them if they do? • Heart Worm • Hook Worm • Pinworm • Ringworm • Screw Worms • Tapeworm • Thread Worms • Whipworm');
INSERT INTO badge_level_requirements VALUES(5204,731,'level4',8,'Do Level 3 requirements # 1 & 2.');
INSERT INTO badge_level_requirements VALUES(5205,731,'level4',9,'Find out about careers that deal with worms. Examples might include silk worm farming, earthworm farming, worm picker, ecologist, etc.');
INSERT INTO badge_level_requirements VALUES(5206,731,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5207,732,'level1',0,'In order to write effectively you need to know some basic grammar. Learn what a noun, verb, adjective, and adverb are. Go around your house and find 5 nouns, then describe them with as many adjectives as you can think of. For example you may see a table (noun) and describe it with the adjectives brown, hard, flat, and long. Now come up with 5 action verbs that you can do and think of as many adverbs as you can to describe how they are done. For example you could choose eating (verb) and describe different ways to do it (adverbs) such as quickly, slowly, or sloppily.');
INSERT INTO badge_level_requirements VALUES(5208,732,'level1',1,'Keep a daily journal of what you do each day for at least 2 weeks. Make sure to use lots of good adjectives and adverbs.');
INSERT INTO badge_level_requirements VALUES(5209,732,'level2',2,'Also understand conjunctions such as “and,” “or,” and “but,” as well as common contractions such as “its,” “don’t,” “hasn’t,” etc.');
INSERT INTO badge_level_requirements VALUES(5210,732,'level2',3,'Learn about prewriting (graphic organizers, brain storming, etc.), drafting (1st draft), revising, editing and publishing (final draft.) Use these skills in all of the writing that you do for this badge.');
INSERT INTO badge_level_requirements VALUES(5211,732,'level3',4,'Write one example of each of the following writing styles. Descriptive writing that creates a clear and vivid picture of a person, place or thing. Expository nonfiction writing that explains an event, concept or idea using facts and examples. Narrative writing about an event in a personal way. Persuasive writing that encourages an audience to share the writer’s beliefs, opinions or point of view.');
INSERT INTO badge_level_requirements VALUES(5212,732,'level4',5,'Find out how a writer’s manuscript in turned into a published book and how to submit articles for newspapers or magazines.');
INSERT INTO badge_level_requirements VALUES(5213,732,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5214,733,'preschool',0,'Know what a war is.');
INSERT INTO badge_level_requirements VALUES(5215,733,'preschool',1,'Know why this war was called a “World War”.');
INSERT INTO badge_level_requirements VALUES(5216,733,'level1',2,'Do Penguin 1 & 2. Know when the war started and why; know when the U.S. entered the war and why; and what year the war ended.');
INSERT INTO badge_level_requirements VALUES(5217,733,'level1',3,'Know the major countries involved in the war and who fought on which side.  Find these countries on a map.');
INSERT INTO badge_level_requirements VALUES(5218,733,'level2',4,'Do Otter requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(5219,733,'level2',5,'Know the major countries involved in the war. Know the two alliances and which countries were in each alliance. Find these countries on a map.');
INSERT INTO badge_level_requirements VALUES(5220,733,'level3',6,'Do Dolphin requirements 1 & 2.  Include at least 25 events in your timeline.');
INSERT INTO badge_level_requirements VALUES(5221,733,'level3',7,'Read a biography about someone who lived during WWI.  Examples might include Kaiser Wilhelm II, Woodrow Wilson, Tsar Nicholas II, Paul von Hindenburg, John J. Pershing, Baron Manfred Von Richthofen (AKA “The Red Baron”), Nurse Edith Cavell, Mata Hari');
INSERT INTO badge_level_requirements VALUES(5222,733,'level4',8,'Do Butterfly requirements 1 & 2.  Include at least 40 events in your timeline.');
INSERT INTO badge_level_requirements VALUES(5223,733,'level4',9,'Learn about trench warfare and what it was like fighting in a trench. Know the new weapons and technology that were used. Create a Pro’s vs. Con’s chart about trench warfare. Owl:  Do 9 requirements including the 2 starred');
INSERT INTO badge_level_requirements VALUES(5224,733,'level4',10,'Do Eagle requirements 1 & 2');
INSERT INTO badge_level_requirements VALUES(5225,733,'level4',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5226,734,'preschool',0,'Know what a war is.');
INSERT INTO badge_level_requirements VALUES(5227,734,'preschool',1,'Know why this war was called a “World War”.');
INSERT INTO badge_level_requirements VALUES(5228,734,'level1',2,'Do Preschool 1 & 2. Know the main reason for the war.');
INSERT INTO badge_level_requirements VALUES(5229,734,'level1',3,'Know the major countries involved in the war and who fought on which side.  Find these countries on a map.');
INSERT INTO badge_level_requirements VALUES(5230,734,'level2',4,'Know when the war started and why; know when the U.S. entered the war and why; and what year the war ended.  Create a timeline with at least 15 events from WWII.');
INSERT INTO badge_level_requirements VALUES(5231,734,'level3',5,'Include at least 25 events in your timeline.');
INSERT INTO badge_level_requirements VALUES(5232,734,'level3',6,'Read a biography about someone who lived during WWII.  Examples might include Anne Frank, Winston Churchill, Adolf Hitler, Harry Truman, etc. –');
INSERT INTO badge_level_requirements VALUES(5233,734,'level4',7,'Include at least 40 events in your timeline.');
INSERT INTO badge_level_requirements VALUES(5234,734,'level4',8,'Learn about the Holocaust.  Be able to name and locate at least 3 of the concentration camps.  What were living conditions like?  How were people killed?  What could happen to Germans who protected Jews or other people who had been classified as having “asocial” behavior?');
INSERT INTO badge_level_requirements VALUES(5235,734,'level5',9,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5236,735,'preschool',0,'Learn at least one basic yoga sequence.');
INSERT INTO badge_level_requirements VALUES(5237,735,'preschool',1,'Know what type of clothing best when doing yoga and dress appropriately.');
INSERT INTO badge_level_requirements VALUES(5238,735,'level1',2,'Learn 2 yoga sequences.  For each yoga posture you learn, know what the posture is supposed to do for your mind and body.');
INSERT INTO badge_level_requirements VALUES(5239,735,'level1',3,'Learn the history of yoga.  Where and when did it originate?  How is yoga linked to spirituality?');
INSERT INTO badge_level_requirements VALUES(5240,735,'level2',4,'Learn 3 yoga sequences.');
INSERT INTO badge_level_requirements VALUES(5241,735,'level2',5,'In the west, the most common form of yoga is Hatha Yoga.  Be able to explain and demonstrate the use of asanas (yoga postures), pranayama (yoga breathing), mudra (body gestures), and shatkama (internal cleansing).  What is each used for and how do they work together?');
INSERT INTO badge_level_requirements VALUES(5242,735,'level3',6,'Learn 4 yoga sequences.');
INSERT INTO badge_level_requirements VALUES(5243,735,'level3',7,'Be able to identify and explain the use common yoga props such as a yoga mat, yoga block, yoga strap, and a bolster.');
INSERT INTO badge_level_requirements VALUES(5244,735,'level4',8,'Learn 5 yoga sequences.');
INSERT INTO badge_level_requirements VALUES(5245,735,'level4',9,'Understand and be able to explain Patanjali’s eight-fold path of yoga.');
INSERT INTO badge_level_requirements VALUES(5246,735,'level5',10,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5250,738,'preschool',0,'Visit a dump/land fill. Learn about what happens to trash there.  If you cannot visit one in person, watch a virtual field trip online with a parent.');
INSERT INTO badge_level_requirements VALUES(5251,738,'preschool',1,'Earn the recycling badge at your level.');
INSERT INTO badge_level_requirements VALUES(5252,738,'level1',2,'and 2.  Get a reusable water bottle and use it for one week.  Remember to fill it up!');
INSERT INTO badge_level_requirements VALUES(5253,738,'level1',3,'Create a zero waste kit . Go to a store, thrift store (or shop from your house) and buy a nice bag, a container for holding restaurant leftovers, utensils, a reusable shopping bag, and a water bottle and/or thermos . Also (not at the thrift store) buy a reusable straw. Put them all in the bag you bought and put this in your car so you don’t forget to use it instead of disposable items.');
INSERT INTO badge_level_requirements VALUES(5254,738,'level2',4,'Make a list of 10 things that are disposable. Then for each disposable item, think of something that is reusable that you could use instead. Track all the things you throw away for a day. Look at the list and for each item try to find a way that you could avoided throwing it away.  Could you recycle it?  Could you have used a reusable version of the same item?  Could you have purchased a similar item with little or no packaging?');
INSERT INTO badge_level_requirements VALUES(5255,738,'level3',5,'Bring your own reusable shopping bags when shopping for one month.');
INSERT INTO badge_level_requirements VALUES(5256,738,'level4',6,'Research how much plastic, glass, cardboard, and aluminum is thrown away every year.  In comparison, how much is recycled?  Find out which countries are the top 3 for producing waste.');
INSERT INTO badge_level_requirements VALUES(5257,738,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5258,739,'preschool',0,'Learn what a zine is.');
INSERT INTO badge_level_requirements VALUES(5259,739,'preschool',1,'Read through at least three zines on a topic or topics that interest you.');
INSERT INTO badge_level_requirements VALUES(5260,739,'level1',2,'Learn how to fold and make a simple eight-page zine with one piece of paper, a pair of scissors, and writing or drawing utensils.');
INSERT INTO badge_level_requirements VALUES(5261,739,'level2',3,'Learn what the following zine jargon means: Zine: A handmade book.  Fanzine: A special book made by fans who love something a lot, like a favorite show or game. Perzine: A personal book where someone shares their thoughts and feelings. Layout: Arranging pictures and words in a book to make it look nice. Zinester: Someone who makes and shares their own books. Zine Scene: A group of people who love making and sharing books, like at events and festivals. Print Run: The number of copies made of a special book. Zine Fest: A fun event where people who make books come together to share, trade, and sell them. Page Spread: Two pages in a book that go together and look nice. Mini Zine: A tiny book made from just one piece of paper. Distribution: Sharing books with others by trading, selling, or giving them away.');
INSERT INTO badge_level_requirements VALUES(5262,739,'level3',4,'Learn about the history of self-publishing, and how self-publishing puts power back in the hands of writers and creatives.');
INSERT INTO badge_level_requirements VALUES(5263,739,'level4',5,'Make at least five zines on topics important to you.');
INSERT INTO badge_level_requirements VALUES(5264,739,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach children, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5265,740,'preschool',0,'Learn what a zipline is.');
INSERT INTO badge_level_requirements VALUES(5266,740,'preschool',1,'Learn proper safety precautions for using backyard ziplines including the safety of both the rider and those nearby.  Know what type of safety equipment you should wear such as sturdy closed toed shoes, a helmet and gloves.');
INSERT INTO badge_level_requirements VALUES(5267,740,'level1',2,'Do Preschool requirements #1 & 2.');
INSERT INTO badge_level_requirements VALUES(5268,740,'level1',3,'Learn about different types of ziplines from simple backyard ziplines to professional ones.  Find pictures of at least 3 different types of zipline.');
INSERT INTO badge_level_requirements VALUES(5269,740,'level2',4,'Ride a zipline that is designed for your age and weight.  Make sure to follow all safety instructions, wear all safety gear, and only ride under the supervision of a qualified adult.  If you are riding a professional zipline, be able to tell what each piece of safety equipment is for, know how it should fit, and be able to explain the type of braking method involved.');
INSERT INTO badge_level_requirements VALUES(5270,740,'level3',5,'Learn about the origin of ziplines and the Tyrolean traverse.  Find at least 3 ways pulley systems similar to ziplines are used for things other than entertainment.');
INSERT INTO badge_level_requirements VALUES(5271,740,'level4',6,'Discuss the science and engineering behind ziplining.  How does the length of the line, the steepness, and the weight of the person affect the speed?  How strong do the anchor points have to be?  How do you make sure a zipline is designed with an end point that will stop the person without injury?');
INSERT INTO badge_level_requirements VALUES(5272,740,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5273,741,'preschool',0,'What is a zoo? What is the difference between a wildlife zoo and a petting zoo?');
INSERT INTO badge_level_requirements VALUES(5274,741,'preschool',1,'Visit a zoo either in person or online with permission from a parent or guardian.');
INSERT INTO badge_level_requirements VALUES(5275,741,'level1',2,'Learn the history of zoos. When was the first zoo created?');
INSERT INTO badge_level_requirements VALUES(5276,741,'level2',3,'Pick an animal you can find in a zoo. Make a poster or write an essay explaining three or more of the following: Where is this animal found in its native habitat? Is it endangered, and if so, why? How much space does it require in captivity to thrive? Is this animal typically social (needing others of its kind) or should they be kept alone? How much does it cost to take care of this animal for a year? What does it eat, and how does the diet in captivity differ from the diet in the wild? How can you own or interact with this animal? What are the dangers of the animal (poison, bites, rabies, ect.)?');
INSERT INTO badge_level_requirements VALUES(5277,741,'level3',4,'Do you agree that animals should be kept in zoos and shown to the public? Make a poster or write an essay on your beliefs. Show or read to your club or a parent, family member, or guardian.');
INSERT INTO badge_level_requirements VALUES(5278,741,'level4',5,'Animals are often traded between circuses, carnivals, and zoos. What are the advantages and disadvantages of this practice? Should an animal be allowed to be traded indefinitely, or only a certain number of times? What is your opinion? Share it with your club or a parent, family member, or guardian.');
INSERT INTO badge_level_requirements VALUES(5279,741,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5280,742,'level1',0,'Look at least 3 different types of maps such as globe, a street map, a map of hiking trails, a topographical map, a map of a stadium or auditorium, a demographic map, etc.  Understand what the map represents.');
INSERT INTO badge_level_requirements VALUES(5281,742,'level1',1,'Learn what an atlas is and look through one.');
INSERT INTO badge_level_requirements VALUES(5282,742,'level2',2,'Do Level 1 requirements #1 & 2, but look at 5 different types of maps.');
INSERT INTO badge_level_requirements VALUES(5283,742,'level2',3,'Learn what a key or legend is on a map.  Make a map of your home or yard with a key to show what each symbol stands for.');
INSERT INTO badge_level_requirements VALUES(5284,742,'level3',4,'Learn to read a street map and give specific directions to someone driving to get from one place to another.');
INSERT INTO badge_level_requirements VALUES(5285,742,'level4',5,'Plan a road trip and use a map to write down exact instructions as to how you plan to get to each location you plan to visit.  Use the scale to estimate the distance and how long it will take you to get from point to point.   If you need to measure the distance of a curving road, use a string to follow the road and then straighten it out to measure it on the scale.  At the end of your trip, compare your estimations and directions to your actual trip.');
INSERT INTO badge_level_requirements VALUES(5286,743,'preschool',0,'Tell a story that you learned to someone else. Be sure to get all the facts right and in the correct order.');
INSERT INTO badge_level_requirements VALUES(5287,743,'preschool',1,'Listen to someone tell at least three stories. What is your favorite story told by a parent, guardian, teacher or grandparent? Why is it your favorite?');
INSERT INTO badge_level_requirements VALUES(5288,743,'level1',2,'Tell a story you learned from a book, article, or movie.');
INSERT INTO badge_level_requirements VALUES(5289,743,'level2',3,'What are three reasons people tell stories? What are the different ways a story can be told? Can you think of a story that has been told in more than one way?');
INSERT INTO badge_level_requirements VALUES(5290,743,'level3',4,'Give five examples of well-known stories that have been handed down from generation to generation. What are some occupations or former occupations of story-tellers?');
INSERT INTO badge_level_requirements VALUES(5291,743,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5292,744,'preschool',0,'Learn what a video game system does and all of its parts (console, controllers, discs, etc.)');
INSERT INTO badge_level_requirements VALUES(5293,744,'preschool',1,'Learn how to handle the disc and insert it correctly into the console. Learn why it is important to handle discs carefully and put them into their cases when you are done with them.');
INSERT INTO badge_level_requirements VALUES(5294,744,'level1',2,'Explain why it is important to have a rating system for video games. Check your video games to be sure they are right for your age.');
INSERT INTO badge_level_requirements VALUES(5295,744,'level1',3,'With an adult, create a schedule for you to do things that includes your chores, homework, and video gaming. Do your best to follow this schedule. This schedule could include video gaming time or video gaming could be used as a reward for chores and homework completion.');
INSERT INTO badge_level_requirements VALUES(5296,744,'level2',4,'Learn about the different video game ratings. What do they mean? Why do they matter?');
INSERT INTO badge_level_requirements VALUES(5297,744,'level3',5,'Discuss with an adult the health effects of playing video games for extended periods of time. Include the effects on your brain, eyes, and body. Find ways to counteract those effects.');
INSERT INTO badge_level_requirements VALUES(5298,744,'level4',6,'Write an essay about the history of video games. When was the first one available? How many different brands and models of video game systems are there now? Share this essay with your Club.');
INSERT INTO badge_level_requirements VALUES(5299,744,'level5',7,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5300,745,'preschool',0,'Know what a waffle is and how it is made.');
INSERT INTO badge_level_requirements VALUES(5301,745,'preschool',1,'Help make and eat a waffle. Try at least (2- Preschool), (3 -Level 1), (4- Level 2), (5 -Level 3), (6- Level 4), (7- Level 5) different sweet or savory recipes or toppings.');
INSERT INTO badge_level_requirements VALUES(5302,745,'level1',2,'Know what a waffle is and how it is made.');
INSERT INTO badge_level_requirements VALUES(5303,745,'level1',3,'Help make and eat a waffle. Try at least (2- Preschool), (3 -Level 1), (4- Level 2), (5 -Level 3), (6- Level 4), (7- Level 5) different sweet or savory recipes or toppings.');
INSERT INTO badge_level_requirements VALUES(5304,745,'level2',4,'Know what a waffle is and how it is made.');
INSERT INTO badge_level_requirements VALUES(5305,745,'level2',5,'Help make and eat a waffle. Try at least (2- Preschool), (3 -Level 1), (4- Level 2), (5 -Level 3), (6- Level 4), (7- Level 5) different sweet or savory recipes or toppings.');
INSERT INTO badge_level_requirements VALUES(5306,745,'level3',6,'Know what a waffle is and how it is made.');
INSERT INTO badge_level_requirements VALUES(5307,745,'level3',7,'Help make and eat a waffle. Try at least (2- Preschool), (3 -Level 1), (4- Level 2), (5 -Level 3), (6- Level 4), (7- Level 5) different sweet or savory recipes or toppings.');
INSERT INTO badge_level_requirements VALUES(5308,745,'level4',8,'Know what a waffle is and how it is made.');
INSERT INTO badge_level_requirements VALUES(5309,745,'level4',9,'Help make and eat a waffle. Try at least (2- Preschool), (3 -Level 1), (4- Level 2), (5 -Level 3), (6- Level 4), (7- Level 5) different sweet or savory recipes or toppings.');
INSERT INTO badge_level_requirements VALUES(5310,745,'level5',10,'Know what a waffle is and how it is made.');
INSERT INTO badge_level_requirements VALUES(5311,745,'level5',11,'Help make and eat a waffle. Try at least (2- Preschool), (3 -Level 1), (4- Level 2), (5 -Level 3), (6- Level 4), (7- Level 5) different sweet or savory recipes or toppings.');
INSERT INTO badge_level_requirements VALUES(5314,747,'preschool',0,'Decide on a holiday you would like to study. Find out about the history of the holiday you''ve chosen. Where is it celebrated in the world, and when? If it is not celebrated in any other country, find out about a similar holiday in another country. For example, we celebrate Independence Day on July 4th, a holiday unique to America. However, various countries have their own Independence Day, unique to each country.');
INSERT INTO badge_level_requirements VALUES(5315,747,'preschool',1,'What is/are the traditional food(s) eaten on your chosen holiday? Help prepare the food. Do different countries eat different types of food on the same holiday? If a relevant recipe cannot be found, what food might work well for a celebration of this holiday?');
INSERT INTO badge_level_requirements VALUES(5316,747,'level1',2,'Decide on a holiday you would like to study. Find out about the history of the holiday you''ve chosen. Where is it celebrated in the world, and when? If it is not celebrated in any other country, find out about a similar holiday in another country. For example, we celebrate Independence Day on July 4th, a holiday unique to America. However, various countries have their own Independence Day, unique to each country.');
