INSERT INTO badge_level_requirements VALUES(5325,747,'level5',11,'What is/are the traditional food(s) eaten on your chosen holiday? Help prepare the food. Do different countries eat different types of food on the same holiday? If a relevant recipe cannot be found, what food might work well for a celebration of this holiday?');
INSERT INTO badge_level_requirements VALUES(5326,748,'preschool',0,'What is a superhero? Choose your favorite superhero to focus on as you complete this badge and be able to recognize them both in hero form as well as their alter identity if they have one. (For example: Superman is Clark Kent; Spiderman is Peter Parker; etc.) How are they the same and how are they different? Do they want people to know that they''re a superhero?');
INSERT INTO badge_level_requirements VALUES(5327,748,'preschool',1,'What special powers or gadgets does your superhero have? How do they become a superhero when danger strikes? Be able to identify 1 of the main villains that your superhero battles.');
INSERT INTO badge_level_requirements VALUES(5328,748,'level1',2,'Do Penguin requirements 1 & 2. Be able to identify 2 of the main villains that your superhero battles.');
INSERT INTO badge_level_requirements VALUES(5329,748,'level1',3,'What is your super hero''s weakness?');
INSERT INTO badge_level_requirements VALUES(5330,748,'level2',4,'Do Otter requirements 1 & 2. Be able to identify 3 of the main villains that your superhero battles.');
INSERT INTO badge_level_requirements VALUES(5331,748,'level2',5,'Does your superhero have an origin story? What is it?');
INSERT INTO badge_level_requirements VALUES(5332,748,'level3',6,'Do Dolphin requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(5333,748,'level3',7,'What does your superhero do when not saving the world? What is his/her civilian job/life?');
INSERT INTO badge_level_requirements VALUES(5334,748,'level4',8,'Do Butterfly requirements 1 & 2. Be able to identify 5 of the main villains that your superhero battles.');
INSERT INTO badge_level_requirements VALUES(5335,748,'level4',9,'Research how your superhero has changed from his/her earliest years to the present day. What changes have been made to the personality, costume, abilities, affiliations, and story of your character? Create a timeline with pictures to show your findings.');
INSERT INTO badge_level_requirements VALUES(5336,748,'level5',10,'Do Eagle requirements 1 & 2.');
INSERT INTO badge_level_requirements VALUES(5337,748,'level5',11,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5338,749,'preschool',0,'Learn what a corn maze is.');
INSERT INTO badge_level_requirements VALUES(5339,749,'preschool',1,'Visit a corn maze, explore some of it with an adult.  If a maze is not available or accessible, a maze can be explored virtually or with video of maze navigation.  The video can be a point-of-view video, or documentary-style.');
INSERT INTO badge_level_requirements VALUES(5340,749,'level1',2,'Learn Maze etiquette:  Stay on the paths, even when people have started to make small unofficial paths.  No running.  No screaming.  Don''t hurt or pick the corn!  No fires. Don''t litter. Use the bathroom before entering the maze, just in case.');
INSERT INTO badge_level_requirements VALUES(5341,749,'level2',3,'What are some strategies for navigating a maze?  Try using them.');
INSERT INTO badge_level_requirements VALUES(5342,749,'level3',4,'What other types of mazes, or crops, can be used to create walk-through mazes?  Have you visited any of these other types?  How are they different from corn mazes?');
INSERT INTO badge_level_requirements VALUES(5343,749,'level4',5,'Learn about the math or economics behind corn mazes.  How much does it cost a farmer to create a corn maze?  Is it a profitable enterprise?  What types of entertainment can a farmer add to their property to create more interest in their corn maze attraction?');
INSERT INTO badge_level_requirements VALUES(5344,749,'level5',6,'Take someone to explore a corn maze, or help with a maze design.  Share your knowledge about mazes with them. If for some reason you cannot teach what you have learned to someone else or physically access a corn maze, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5345,750,'preschool',0,'Choose a famous animal and find out what your animal did that made them famous?  Find pictures or information on your animal doing what they are known for.  Look at a picture or statue of your animal and know what they looked like.');
INSERT INTO badge_level_requirements VALUES(5346,750,'level1',1,'Who is the famous animal''s owner (if they had one) and what did they do for a living?  If known, when and where was your chosen animal born, and when they died.  (If they are still living, how old are they?)');
INSERT INTO badge_level_requirements VALUES(5347,750,'level2',2,'What breed/species of animal is your chosen animal?  Research and learn about that breed.');
INSERT INTO badge_level_requirements VALUES(5348,750,'level3',3,'Was your chosen animal given any honors or awards?  If so, what were they and what did your animal do to earn them?  Has your animal been featured in books, TV shows, or films?  If so, which ones?');
INSERT INTO badge_level_requirements VALUES(5349,750,'level4',4,'What is the legacy of your chosen animal?  How has it influenced the breed or species?  How has it influenced the role of animals in society?  Is there a museum, memorial, statue, or organization dedicated to your animal?  If so, where is it?');
INSERT INTO badge_level_requirements VALUES(5350,750,'level5',5,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.  You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new-found knowledge.  If for some reason you cannot teach what you have learned to someone else, you may choose and additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5351,751,'preschool',0,'Understand what Internet memes are.');
INSERT INTO badge_level_requirements VALUES(5352,751,'preschool',1,'Learn what an If/Then meme is.');
INSERT INTO badge_level_requirements VALUES(5353,751,'level1',2,'Many memes are made for adults only or can be cruel.  Explain why it is important to use a search engine with an adult and use good search terms so that you only find kind, clean memes.  Learn how to safely find memes.');
INSERT INTO badge_level_requirements VALUES(5354,751,'level2',3,'Learn about 5 famous, safe memes.  Know what a GIF is and how it is used.  Learn how to create your own GIF.');
INSERT INTO badge_level_requirements VALUES(5355,751,'level3',4,'Learn about different types of memes.  How did print memes evolve into internet memes?');
INSERT INTO badge_level_requirements VALUES(5356,751,'level4',5,'Learn about the history of memes.  How did print memes evolve into internet memes? Understand that memes began as widespread jokes and can be found in Roman, Greek, Persian, Chinese, Indian and Native American cultures.');
INSERT INTO badge_level_requirements VALUES(5357,751,'level5',6,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.  You may create a video to be shared on the internet. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5358,8,'preschool',0,'Earn the Aviation Badge at your level.');
INSERT INTO badge_level_requirements VALUES(5359,8,'preschool',1,'Learn about the Federal Aviation Administration (FAA). What does it do? Which government department administers it?');
INSERT INTO badge_level_requirements VALUES(5360,11,'preschool',0,'Earn the Knitting Badge at your level.  Learn to read a knitting pattern.  You should be familiar with the following most common abbreviations: begcmcontdecgarter stinckk2togkwisem1ppssopwiseremrepsl stst sttbltogrepeat from *(  )');
INSERT INTO badge_level_requirements VALUES(5361,11,'preschool',1,'Before knitting a garment it is important to understand what tension is and how to check the tension of your knitting with that for the pattern.  Learn what tension is and how it can affect your knitting.  Learn how to knit a tension square before starting your item.  Learn why it is important to use the correct weight yarn for your item.');
INSERT INTO badge_level_requirements VALUES(5362,12,'preschool',0,'Earn the Photography Badge at your level.');
INSERT INTO badge_level_requirements VALUES(5363,12,'preschool',1,'Describe lighting in a picture.  How does light affect your picture? Where should you position your source of light? What part of the camera controls the lighting?  What camera settings and equipment would you use to increase or decrease the amount of light needed for your picture? What is soft lighting and when do you use it?  Now show a series of pictures taken in different light sources and show them to your family or troop leader.  Describe why you chose the lighting you did.');
INSERT INTO badge_level_requirements VALUES(5364,13,'preschool',0,'Earn the Quilting Badge. Since quilting tends to be a time-consuming craft, this requirement may be retroactive to a previous age group for one year. Make at least 80% of a quilt all by yourself. Younger kids may make a lap quilt or crib-size quilt, but Level 3-5 should make at least a twin size quilt (or two smaller ones).');
INSERT INTO badge_level_requirements VALUES(5365,13,'preschool',1,'Practice choosing fabrics for a quilt. They do not need to be sewn into your quilt.  Choose two sets of at least three fabrics in a monochromatic color scheme; two sets of at least three fabrics in a complementary color scheme; and two sets of at least three fabrics in an analogous color scheme.');
INSERT INTO badge_level_requirements VALUES(5366,37,'preschool',0,'Learn what an antique is, and how things become antiques (think age, rarity, etc.) What is the difference between antique items and vintage items?  Ask your parents or other family members if they have any antiques that they can show you.');
INSERT INTO badge_level_requirements VALUES(5367,37,'preschool',1,'Read a biography of someone who is known for their collections of antiques, or who is an appraiser of antiques OR read a book about someone whose creations are now classed as antiques, such as Josiah Wedgewood (if you earned this badge at a previous level, read about a different person). Tell your family, friends, club, or troop what you learned.');
INSERT INTO badge_level_requirements VALUES(5368,50,'preschool',0,'What is an Artist Trading Card (ATC), and what are the rules for swapping cards? Make and swap at least 3 ATC’s. Most adults who trade ATC’s put their contact information on the back of the card (address or email). Discuss why it is safer for kids not to use full contact information. Information you should include on the back of your card: Title of the artwork, date created, first name only for kids, and a general location (like Georgia), not a specific address.');
INSERT INTO badge_level_requirements VALUES(5369,50,'preschool',1,'Learn about various ways to protect your ATC collection: card pockets, card collector sheets, card boxes, etc. Decide on the best way to keep your own collection safe.');
INSERT INTO badge_level_requirements VALUES(5370,68,'preschool',0,'What is the secret identity of the first Batman? What happened during his childhood that inspired him to be a detective and crime fighter?');
INSERT INTO badge_level_requirements VALUES(5371,68,'preschool',1,'What is the name of Batman’s younger sidekick? A number of characters have played this role. Find out how one of them ended up working with Batman. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(5372,76,'preschool',0,'Memorize the following amount of verses: Preschool– 3 verses Level 1 – 5 verses Level 2 – 8 verses Level 3 – 10 verses Level 4 – 12 verses Level 5 – 14 verses Be able to recite these verses to an adult or troop leader within two or three sittings.');
INSERT INTO badge_level_requirements VALUES(5373,76,'preschool',1,'Discuss with a parent what these verses mean to you and how they should affect your life.');
INSERT INTO badge_level_requirements VALUES(5374,79,'preschool',0,'Is Bigfoot real or a fantasy? What exactly is he? Explain.');
INSERT INTO badge_level_requirements VALUES(5375,79,'preschool',1,'Is Bigfoot only in the United States? What are some other names for Bigfoot?');
INSERT INTO badge_level_requirements VALUES(5376,82,'preschool',0,'Learn what a biome is.');
INSERT INTO badge_level_requirements VALUES(5377,82,'preschool',1,'Find where your chosen biome is located.  Is it found in more than one area?  Color and label a map.');
INSERT INTO badge_level_requirements VALUES(5378,84,'preschool',0,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5379,98,'preschool',0,'.  Learn what the British Crown Jewels are. Look at a picture of the British Crown Jewels and be able to identify at least three of them. Which is the oldest of the Crown Jewels in existence today?');
INSERT INTO badge_level_requirements VALUES(5380,98,'preschool',1,'. Watch a video recording of a coronation of a British monarch and pay attention to the Crown Jewels used. How were they used?');
INSERT INTO badge_level_requirements VALUES(5381,114,'preschool',0,'Learn about different tools and supplies that are used in card making, including: Card stock and other paper Stickers Punch-outs Rulers Scissors Pens Pencils Markers Stencils');
INSERT INTO badge_level_requirements VALUES(5382,114,'preschool',1,'Learn about at least three different formats of cards, such as window cards, pop-up cards, etc. Tell your family, friends, or group what you learned');
INSERT INTO badge_level_requirements VALUES(5383,116,'preschool',0,'Research the history of Care Bears. Make a timeline with at least 10 items (Preschool & Level 1 include 5 items). Who created them? When did the TV show first air? How have the characters changed since they were first released?');
INSERT INTO badge_level_requirements VALUES(5384,116,'preschool',1,'Discuss the main Care Bears’ names. Know their tummy badges with the correct color and picture. What character trait does each represent? Who are the evil bears? What can you learn from both the good and bad bears?');
INSERT INTO badge_level_requirements VALUES(5385,128,'preschool',0,'Earn at least one Servant’s Heart at your level.');
INSERT INTO badge_level_requirements VALUES(5386,128,'preschool',1,'Sort through the toys in your room and choose some that are still in good condition to donate to a charitable organization. Help your family sort through their belongings such as clothes and household items to add to your donation.');
INSERT INTO badge_level_requirements VALUES(5387,129,'preschool',0,'Choose a charity you wish to support and learn what they are about. Who do they help and why? Are they local, national, or worldwide?');
INSERT INTO badge_level_requirements VALUES(5388,129,'preschool',1,'Participate in a service project to collect items or money to support your chosen charity. This may be collecting cans for a food bank, raising money for research, etc.');
INSERT INTO badge_level_requirements VALUES(5389,140,'preschool',0,'What do people mean when they say missions or missionary?');
INSERT INTO badge_level_requirements VALUES(5390,140,'preschool',1,'What does Matthew 28:18-20 have to do with missions? What else does the Bible say about missions?');
INSERT INTO badge_level_requirements VALUES(5391,142,'preschool',0,'Learn the difference between a carol and a Christmas song. Learn at least three different carols.');
INSERT INTO badge_level_requirements VALUES(5392,142,'preschool',1,'After learning about the different carols, go caroling! This can be in your neighborhood, at a nursing home, fire or police station – anywhere you can give the gift of song to others.');
INSERT INTO badge_level_requirements VALUES(5393,143,'preschool',0,'Learn the history and cultural variations of Christmas ornaments.');
INSERT INTO badge_level_requirements VALUES(5394,143,'preschool',1,'Make at least three different Christmas ornaments using a different method listed below for each. Levels 1 – 2: Make four. Levels 3 – 5: Make six. Paper Clay or dough Felt Fabric other than felt Natural items such as twigs, straw, pine cones, nut shells, etc. Beads Plastic or Styrofoam Metal Paint or glitter Ribbon or lace Sequins or jewels Dye Decoupage Embroider, cross stitch,  crochet, tat or knit Edible materials');
INSERT INTO badge_level_requirements VALUES(5395,150,'preschool',0,'How does good housekeeping help to maintain a home? Which chores should be done daily, weekly, monthly and yearly? How important is a clean home? With which chores can you help? Which can you do all by yourself, including putting away the equipment? If you can’t do a chore by yourself, how can you help someone else work on it? Preschool: Which chores can you help with? Find a daily chore you can help with and do it faithfully for one week. Find a weekly chore you can help with and help with it for two consecutive weeks. Level 1: Which chores can you help with? Find a daily chore you can do by yourself and do it faithfully for one week. Find a weekly chore you can do by yourself or with very little help. Do the weekly chore four consecutive weeks. Level 2: Find a daily chore and do it every day for two weeks. Do a weekly chore two weeks in a row and a monthly chore two months in a row. Level 3: Choose a daily chore to do every day for three weeks, a weekly chore to do three consecutive weeks, a monthly chore to do two consecutive months, and one yearly chore. What is your favorite method of keeping track of which chores are completed? Levels 4 & 5: Choose a daily chore and be responsible for it for three consecutive weeks. Take care of a weekly chore for four consecutive weeks, a monthly chore for two consecutive months and do one yearly chore. What is your favorite method of keeping track of which chores are completed? Ask someone who has recently bought a house if cleanliness had anything to do with their choice of a new home or interview a real estate agent to find out how important cleanliness is in the sale of a home. You can also interview a fireman to find out if cleanliness makes his job easier.');
INSERT INTO badge_level_requirements VALUES(5396,150,'preschool',1,'Basic home-making chores. You may repeat this requirement for each item demonstrated. Preschool & Level 1: Do the required skill with help. Levels 2 – 3: Demonstrate the skill and then do that chore on three separate occasions, trying to be more thorough each time. Levels 4 – 5: Demonstrate ability to do the skill and then teach someone else how to do the chore. Check up a day or so later and make sure your student is still doing the chore correctly. Demonstrate: The proper way to make a bed. The proper way to vacuum a room. The proper way to sweep a floor and use a dust pan. Sweep at least two rooms. The proper way to mop a floor. How to clean mirrors and windows. Clean at least one of each.');
INSERT INTO badge_level_requirements VALUES(5397,160,'preschool',0,'Learn the history of Colonial Williamsburg. What is the mission of the Colonial Williamsburg Foundation?');
INSERT INTO badge_level_requirements VALUES(5398,160,'preschool',1,'Visit and explore Duke of Gloucester Street. Talk with at least one “resident” about his or her life in colonial times. If you cannot visit in person, research what you can about Gloucester Street online with a parent’s permission.');
INSERT INTO badge_level_requirements VALUES(5399,166,'preschool',0,'Understand why your industry became the central feature of towns and during what time period this would have happened. Locate an example of this type of town on a map.');
INSERT INTO badge_level_requirements VALUES(5400,166,'preschool',1,'Be able to identify well-known features found in your chosen type of town (i.e. what features were the same as other towns and which were unique).');
INSERT INTO badge_level_requirements VALUES(5401,167,'preschool',0,'Discuss with an adult what compassion means to you. How is it similar to sympathy, empathy, mercy, and kindness? What does it mean to be compassionate? Why is compassion important?');
INSERT INTO badge_level_requirements VALUES(5402,167,'preschool',1,'For two weeks, write down all the ways that you have been compassionate. Do you tend to judge people harshly for their actions, or do you try to see things from their point of view? Do you help people who are in difficult situations, or do you feel that they should fend for themselves if they have got themselves into a mess? How can you learn to be more compassionate?');
INSERT INTO badge_level_requirements VALUES(5403,172,'preschool',0,'What is confidence? Discuss with a parent or club leader what confidence is.');
INSERT INTO badge_level_requirements VALUES(5404,172,'preschool',1,'Practice being confident for two weeks: on a piece of paper, write down each time you are confident you can do something, such as chores or homework, and each time you feel you will certainly fail. Which happens more often? Do you find you succeed more when you feel confident?');
INSERT INTO badge_level_requirements VALUES(5405,177,'preschool',0,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5406,197,'preschool',0,'Read (or have a story read to you) about someone from history who was diligent. Some examples might include Thomas Edison, Albert Einstein, or Marie Curie. In what ways do they show the character trait diligence? What can you learn from their experiences?');
INSERT INTO badge_level_requirements VALUES(5407,197,'preschool',1,'“I have not failed. I’ve just found 10,000 ways that won’t work.” – Thomas Edison. Thomas Edison showed diligence when he and his team developed the affordable and practical light bulb by testing over 6,000 types of light bulbs. Create your own diligence reminder by drawing 5 light bulbs on pieces of paper and cutting them out. On each one list something you can do to show diligence. Examples might include: Completing homework on time Keeping promises Working without being watched over Cleaning your room without being asked Making your bed, not complaining about chores Post these reminders around your house to remind you to be diligent.');
INSERT INTO badge_level_requirements VALUES(5408,198,'preschool',0,'Learn what a diner is. What makes it different than other restaurants?  Do you have any in your hometown? Is it still operating? Visit if you can.');
INSERT INTO badge_level_requirements VALUES(5409,198,'preschool',1,'Learn the history of diners. Where did they start? When were they most popular? Why did their popularity decline?');
INSERT INTO badge_level_requirements VALUES(5410,200,'preschool',0,'What is a dip? Make a list of the different types of dip. Preschool and Level 1: List 3 types of dip. Levels 2-3: List 5 types. Levels 4-5: List 7 types.');
INSERT INTO badge_level_requirements VALUES(5411,200,'preschool',1,'What kinds of things can you eat with dip? List several and what dip would be appropriate for which types of food.');
INSERT INTO badge_level_requirements VALUES(5412,203,'preschool',0,'Understand what Disneybounding is. Why has it become a popular trend? How does it differ from cosplaying?');
INSERT INTO badge_level_requirements VALUES(5413,203,'preschool',1,'Create your own Disneybounding costume from items in your wardrobe or from around the house.');
INSERT INTO badge_level_requirements VALUES(5414,216,'preschool',0,'List ten different types of donuts. What is your favorite type? Try at least three of the donuts on your list.');
INSERT INTO badge_level_requirements VALUES(5415,216,'preschool',1,'Learn about the history of the donut. Where did it originate? Write a brief timeline.');
INSERT INTO badge_level_requirements VALUES(5416,216,'preschool',2,'Levels 4 & 5: Bake your own donuts from scratch.');
INSERT INTO badge_level_requirements VALUES(5417,217,'preschool',0,'What was Dr. Seuss’ real name? What was the first book he ever published and what year was it released? How many books did he have published in his lifetime? When was he born and when did he die?');
INSERT INTO badge_level_requirements VALUES(5418,217,'preschool',1,'Do these reading requirements based on your level: Preschool: Read 3 Dr. Seuss books Level 1: Read 4 Dr. Seuss books Level 2: Read 5 Dr. Seuss books Level 3: Read 6 Dr. Seuss books Level 4: Read 7 Dr. Seuss books Level 5: Read 9 Dr. Seuss books Optional Requirements');
INSERT INTO badge_level_requirements VALUES(5419,221,'preschool',0,'Take whatever driver’s training course is recommended by your state, even if it is only a master check list given to your parents.');
INSERT INTO badge_level_requirements VALUES(5420,221,'preschool',1,'After completion of the official driver’s training, practice driving for another fifteen hours with at least two different types of conditions: Paved/unpaved roads Clear/stormy weather No extra/several extra passengers Numerous stops per hour/open road trip Caravanning/going at your own pace City/country driving.');
INSERT INTO badge_level_requirements VALUES(5421,229,'preschool',0,'Learn how to blow out and clean an egg to get it ready for artwork. With an adult’s help, use a sharp pointed knife to poke a small hole in both the top and bottom of your egg. The pointed end of a drawing compass, a darning needle, or an Exacto knife works well too. Use a toothpick to poke inside the hole and stir up the egg inside. It is easier to blow if the yolk has been broken. Room temperature eggs are also easier than cold eggs straight from the refrigerator. Hold the egg over a bowl and carefully blow into the top hole. You will need to blow hard, but be careful not to crush your egg on accident. The white and yolk should squirt out into the bowl below. Once you have blown out your egg, drop a small about of liquid soap inside and run water through it. Plug the bottom and top hole with your fingers and shake the soapy water around. Drain your egg (you may need to blow some of the water and soap out). Let the egg dry on a paper towel. Wait until the egg has completely dried, and put a few drops of glue over the holes to protect the egg from cracking. Now you are ready for art!');
INSERT INTO badge_level_requirements VALUES(5422,229,'preschool',1,'Learn to enhance the décor of a simple dyed egg. Preschool-Level 1: Learn at least one technique. Level 2: Learn two techniques.  Level 3: Learn three techniques. Level 4: Learn four techniques. Level 5: Learn five techniques. Examples might include: Wax resist dying. Using wax crayons, draw on the egg prior to dying. The dye will not stick to the wax. White or clear crayons or wax works the best and give a batik effect. Use stickers or tape to create a relief image on your egg. Make sure the sticker is small and has no wrinkles when it is applied. Any dye that gets underneath will ruin your design. Small stripes of masking tape can also be used to make stripes and other designs. Layer dyed colored to create stripes, or other simple patterns. First place your egg in the lightest color. Next place just a portion of the egg in the next darkest color and hold until it reaches the color you wish. To make a rainbow egg, dye half the egg yellow and half light green. Then place the yellow half in orange dye until you only have a stripe of yellow still showing, hold until the orange color sets. Repeat with red. Then flip your egg over and place the green end in the blue dye.  Follow the instructions above for blue and then purple.  When you are finished, you should have a striped rainbow egg. Using stickers or paint to decorate an egg after it has already been dyed. Leaf applications. Soak the (clean) eggs for 30 minutes in lukewarm water. Wet a small leaf with a little water and stick it on the egg. You can apply several leaves to create patterns or use a single one. Carefully wrap the egg in a nylon stocking. Make sure it holds the leaves tightly in place. Then tie the nylon at the top of the egg with some thread.  Immerse the egg in your chosen dye. When it is done, remove the nylon and the leaves and admire the beautiful batiked pattern. Gluing on embellishments such as jewels, ribbon, sequins, feathers, or silk flowers.');
INSERT INTO badge_level_requirements VALUES(5423,231,'preschool',0,'Learn what the word elastic means, and what elastic itself is. How is it used in everyday life? Look around your home and find at least five different things that have elastic in them. Finding five pairs of trousers doesn’t count!');
INSERT INTO badge_level_requirements VALUES(5424,231,'preschool',1,'Read a book, watch a video, or go online (with your parent’s permission) to find out how elastic is made. Tell your family, friends, or group what you learned.');
INSERT INTO badge_level_requirements VALUES(5425,238,'preschool',0,'Learn what endangered means.');
INSERT INTO badge_level_requirements VALUES(5426,238,'preschool',1,'Choose an animal from the endangered species list and learn where it lives, what it likes to eat, & why it’s endangered.');
INSERT INTO badge_level_requirements VALUES(5427,250,'preschool',0,'Discuss with a parent or other adult what faith means. What do people mean when they say that they have a faith in someone or something? What does it mean to be faithful?');
INSERT INTO badge_level_requirements VALUES(5428,250,'preschool',1,'For two weeks write down all the ways that you have been faithful. Do you pray every day? Did you have faith that something would turn out all right? Were you a faithful friend when someone needed you? Were you faithful in carrying out your daily responsibilities? How can you strengthen your faith and help it to grow?');
INSERT INTO badge_level_requirements VALUES(5429,259,'preschool',0,'What is felt naturally made of? Where do you get the materials? How is it made?');
INSERT INTO badge_level_requirements VALUES(5430,259,'preschool',1,'What can you make with felt? Make a list of everything you can think of that uses felt. Make at least one project using felt.');
INSERT INTO badge_level_requirements VALUES(5431,260,'preschool',0,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your newfound knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5432,261,'preschool',0,'What is a fidget?  Why were they invented?  What medical conditions can they be used for?');
INSERT INTO badge_level_requirements VALUES(5433,261,'preschool',1,'Identify and explore types of fidgets. Preschoolers: Identify two. Level 1: Identify three. Level 2: Identify four. Level 3: Identify five. Level 4: Identify six. Level 5: Identify seven. Optional requirements');
INSERT INTO badge_level_requirements VALUES(5434,270,'preschool',0,'Read the original story of Flat Stanley by Jeff Brown. Learn about the author and why he wrote the story. Discuss why you think his story caught on in such a unique way, inspiring others to use Flat Stanley to connect with people around the world.');
INSERT INTO badge_level_requirements VALUES(5435,270,'preschool',1,'Find someone in another state, or even better, another country, and send a Flat Stanley to them. Ask them to send it back with a picture of your Flat Stanley with them and a letter about its adventures.');
INSERT INTO badge_level_requirements VALUES(5436,271,'preschool',0,'Discuss with a parent or other adult what flexibility means as a character trait. Discuss how self control is related to flexibility. Emphasize the importance of not suppressing your feelings when plans change, but handling feelings appropriately while situations are changing.');
INSERT INTO badge_level_requirements VALUES(5437,271,'preschool',1,'Keep track for two weeks of how many times flexibility for a situation is needed in you and in those around you. Examples: We were ready to go out the door and the baby needed a diaper change at the last minute. A friend had to cancel a playdate. We were ready to cook dinner but were surprised to be missing an important ingredient. The weather changed and blocked our plans. The floor was just mopped and milk has been spilled on it again.  In each situation you record, how did you react?  Were you able to adapt or did it make you angry, stressed, or frustrated?');
INSERT INTO badge_level_requirements VALUES(5438,284,'preschool',0,'List qualities of a good friend such as honesty, understanding, loyalty, etc. Discuss these with a family member or group leader, then ask them if they can think of more to add to the list.');
INSERT INTO badge_level_requirements VALUES(5439,284,'preschool',1,'Explore ways to resolve conflicts without arguments and come up with ideas on how to compromise. Write these ideas down, and discuss these with a family member or your group.');
INSERT INTO badge_level_requirements VALUES(5440,287,'preschool',0,'Know basic water safety rules and obey all pool rules.');
INSERT INTO badge_level_requirements VALUES(5441,287,'preschool',1,'Work on the swimming/water rescue requirements of your level Life Skills for at least half an hour. If you have completed your requirements already, then help other members of your club or family to complete theirs.');
INSERT INTO badge_level_requirements VALUES(5442,289,'preschool',0,'. What is fund raising? What will you be raising funds for? What will your group do with the money that you earn? Be a good friend or neighbor by thinking of ways to help others through your fundraiser sales. Set aside a portion of the profits to buy some of your sales-product and donate it to others in need, buy supplies for use in your group service projects, or use the proceeds to help our soldiers.');
INSERT INTO badge_level_requirements VALUES(5443,289,'preschool',1,'. Learn the safety rules when selling your fundraiser. Talk about safety rules when you go door to door, when you sell at booths, when you sell to family and friends, etc. Always be polite and courteous, especially if people decline to support you. Remember to thank people for their support of your group. Remember that when you are fundraising, you aren’t just representing yourself, but rather your whole group.');
INSERT INTO badge_level_requirements VALUES(5444,298,'preschool',0,'Discuss with a parent or other adult what gentleness means. How can you be gentle with your touch? With your words? With your actions?');
INSERT INTO badge_level_requirements VALUES(5445,298,'preschool',1,'Make a list of everyone in your family (including any pets). Now think about the ways in which you behave towards them. For each member of your family, write down one way in which you are not gentle, and then write down a way to change that behavior to gentleness. For example, if you yell at your brother a lot, then you may wish to write down, “speak in a calm voice.” Or maybe you are getting bigger and find that your “squeeze hugs” are starting to hurt your mother. You might write down “hug gently.” Think of as many ways as possible to act in a gentle fashion to each member of your family.');
INSERT INTO badge_level_requirements VALUES(5446,303,'preschool',0,'. Learn what it means to wrap a gift or present. Learn how to wrap one (Preschool and Level 1), two (Level 2 & 3), three (Level 4 & 5) presents of different sizes and shapes.');
INSERT INTO badge_level_requirements VALUES(5447,303,'preschool',1,'. Go to a store and look at the gift wrapping supplies. How many different items can you find for wrapping presents? Be sure to include things like money wallets. For extra fun, choose a category, such as wrapping paper or ribbon, and count how many different patterns and varieties you can find.');
INSERT INTO badge_level_requirements VALUES(5448,306,'preschool',0,'Discuss why proper skin care is important for your age level.');
INSERT INTO badge_level_requirements VALUES(5449,306,'preschool',1,'Discuss different ways to protect your skin during different times of year.');
INSERT INTO badge_level_requirements VALUES(5450,310,'preschool',0,'Being good is not necessarily about making easy choices. There are so many messages out there telling us “if it feels good, it must be good.” And this is simply not the case. Search through the media for advertising messages, both good and bad. Create a chart and list the good messages on one side, and the bad on the other. Discuss with a parent or other adult why you listed them the way you did. Which message do you see more of in today’s media, good messages or bad? Examples may come from commercials, TV shows, music, advertising, radio or magazines.');
INSERT INTO badge_level_requirements VALUES(5451,310,'preschool',1,'Pay attention to your behavior for two weeks. At the end of each day, write down any behavior that was especially good (helping Mom with dishes with no complaints) and behavior where you may need some improvement (yelling at your brother). Each day, try to have more good things on your list and less bad.');
INSERT INTO badge_level_requirements VALUES(5452,316,'preschool',0,'Experience the death of someone in your immediate or extended family, friend, pet or loss due to divorce or move.');
INSERT INTO badge_level_requirements VALUES(5453,316,'preschool',1,'Talk with parents, other family members, or someone close to you about your feelings regarding your loss and the impact they have on your life.');
INSERT INTO badge_level_requirements VALUES(5454,320,'preschool',0,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(5455,321,'preschool',0,'Research the different non-profits that accept donated hair to turn into wigs for those who cannot afford them. What happens to hair they cannot use? How do they spend their money? What are the reviews of those who have interacted with them? Read their Frequently Asked Questions page.');
INSERT INTO badge_level_requirements VALUES(5456,321,'preschool',1,'Donate at least 10” of your hair to the non-profit of your choice.');
INSERT INTO badge_level_requirements VALUES(5457,328,'preschool',0,'Learn how to use headphones safely, including: Never turn the volume up too loud. Never use headphones while driving or riding a bike. Never use headphones on playground equipment or other places where they could get caught.');
INSERT INTO badge_level_requirements VALUES(5458,328,'preschool',1,'Learn when the first headphones were created and by whom.  Learn about at least 6 different types of headphones. Which is your favorite? Why? Optional Requirement:');
INSERT INTO badge_level_requirements VALUES(5459,337,'preschool',0,'Learn about the clothing of your chosen era. What did average people wear? What were popular trends of the time?');
INSERT INTO badge_level_requirements VALUES(5460,337,'preschool',1,'Learn about events that this era is known for in history. Preschool-Level 1: Learn at least five. Levels 2-4: Learn at least 10. Level 5: Learn at least fifteen.');
INSERT INTO badge_level_requirements VALUES(5461,350,'preschool',0,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5462,354,'preschool',0,'Plan an itinerary and budget for your family to visit the local sites that interest you.  Don’t forget to plan for gas, admissions, and meals.');
INSERT INTO badge_level_requirements VALUES(5463,354,'preschool',1,'Find out at least 3 things your hometown is known for.  Maybe it is an amusement park, or skyscrapers, or a historical battlefield.  Visit at least one.');
INSERT INTO badge_level_requirements VALUES(5464,355,'preschool',0,'Read about a famous person who was known for their honesty.');
INSERT INTO badge_level_requirements VALUES(5465,355,'preschool',1,'Put honesty into action.  Do at least 10 of the activities below or come up with your own: Thank someone in your family for being honest. Tell your parents about a mistake you’ve made. Tell the truth when you’ve done something wrong. Compliment a friend for being honest. Express your real feelings without anger, without blaming others, without exaggerating, and without hurting the feelings of someone else. Turn in something that is lost and encourage others to do the same. When someone wants to copy your work, politely explain that it isn’t right and that it’s best to do your own work. Admit a mistake or error in judgment you have made and apologize to anyone it might have affected. Do your schoolwork honestly. Be truthful with your friends and thank them for being truthful with you. When you ask someone to be honest with you, don’t get angry with them if their honesty isn’t what you wanted to hear. Tell the truth if you have not done something you were supposed to, or did not do it well, such as chores.');
INSERT INTO badge_level_requirements VALUES(5466,359,'preschool',0,'Earn the Horses badge at your level.');
INSERT INTO badge_level_requirements VALUES(5467,359,'preschool',1,'Learn about 6 different horse breeds from around the world.  Know what each type of horse is generally used for.');
INSERT INTO badge_level_requirements VALUES(5468,360,'preschool',0,'Know the names of three major races, where they are held, and when.');
INSERT INTO badge_level_requirements VALUES(5469,360,'preschool',1,'Who founded horse racing as a sport?');
INSERT INTO badge_level_requirements VALUES(5470,383,'preschool',0,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5471,384,'preschool',0,'Visit the Jelly Belly Factory or take a virtual tour.');
INSERT INTO badge_level_requirements VALUES(5472,384,'preschool',1,'Learn how Jelly Bellies are made and packaged. Tell your family, friends, or group the process.');
INSERT INTO badge_level_requirements VALUES(5473,386,'preschool',0,'Know what a jigsaw puzzle is.  Be able to put together at least a 25-piece puzzle (Preschool), 100-piece puzzle (Level 1), 350-piece puzzle (Level 2), 500-piece puzzle (Level 3), a 1000-piece puzzle (Level 4), and a 1,500-piece puzzle.');
INSERT INTO badge_level_requirements VALUES(5474,386,'preschool',1,'Learn about the history of jigsaw puzzles. When and where were they first made?');
INSERT INTO badge_level_requirements VALUES(5475,388,'preschool',0,'How would you define joy? For two weeks, keep a Joy Journal. In it put every little thing that you find joy in each day. Entries may be as simple as seeing a beautiful bird outside your window, the smell of chocolate chip cookies, or a really good book. (Preschool and Level 1 can keep a picture journal if they prefer.)');
INSERT INTO badge_level_requirements VALUES(5476,388,'preschool',1,'Try to make someone smile every day for two weeks. Make it challenging and try to pick people who really look like they need someone to brighten their day. Help your mom clean the kitchen without being asked, tell the clerk at the grocery store that you like their shirt, play a game with your little brother even if you may not feel like it. Note in your journal how you gave joy to someone else every day for two weeks.');
INSERT INTO badge_level_requirements VALUES(5477,394,'preschool',0,'Discuss the following with a parent or adult: What is your definition of kindness? Have you ever felt disappointed or cheated because you did something nice for another person, but he or she did not return the favor? If you expect to get something back, are you then performing a kind act or are you really trading favors for favors? Has anyone ever done something for you anonymously, without expecting something in return? How is kindness similar to character traits like love, joy, and gentleness? How is it different?');
INSERT INTO badge_level_requirements VALUES(5478,394,'preschool',1,'Perform at least one random act of kindness per day for two weeks and expect nothing in return.');
INSERT INTO badge_level_requirements VALUES(5479,395,'preschool',0,'Learn what Kindness Rocks Project is and how it got started.  Paint and either hide or give away at least one rock.');
INSERT INTO badge_level_requirements VALUES(5480,395,'preschool',1,'Learn the do’s and don’ts of hiding painted rocks. Some do’s and don’ts include: Do: Make sure your rock is nice and clean before painting. Only paint happy things, and art that will brighten someone’s day! Make sure you seal your rock so your paint doesn’t wash away. Acrylic paint is the easiest and cheapest option, but while it is non-toxic it isn’t very good for the environment. Don’t: Trespass when hiding your rocks. Put your rock in a lawn, or large body of grass. It can get ran over by a lawn mower causing sparks and fires. Don’t leave your rock in national parks, or any park or place that has Leave No trace Rules, and other regulations regarding the protection of nature and its natural beauty. Don’t leave your rock at businesses or other private property without permission.');
INSERT INTO badge_level_requirements VALUES(5481,396,'preschool',0,'Research people from history who made discoveries or scientific advancements using kites. Describe their use of kites in detail. How did their studies or developments impact the world? Preschool: Research 3 people. Level 1: Research 4 people. Level 2: Research 5 people. Level 3: Research 6 people. Level 4: Research 7 people. Level 5: Research 8 people.');
INSERT INTO badge_level_requirements VALUES(5482,396,'preschool',1,'Learn and follow all kite safety rules. Why is it important to be safe with a kite?');
INSERT INTO badge_level_requirements VALUES(5483,397,'preschool',0,'Learn who knights were, what they did, and when they lived.');
INSERT INTO badge_level_requirements VALUES(5484,397,'preschool',1,'Learn about the kind of clothing and weapons knights utilized.');
INSERT INTO badge_level_requirements VALUES(5485,399,'preschool',0,'Learn about different types of rope and string and which works best for different types of knots. Look at things like fiber used, weight, elasticity, strength,  how easily it slides, how resistant it is to water, and whether or not it floats.');
INSERT INTO badge_level_requirements VALUES(5486,399,'preschool',1,'Learn how to properly maintain your rope. If you are Level 2 or above, learn how to repair any fraying ends using a whip stitch for natural fibers or have an adult help you melt the ends on a synthetic rope.');
INSERT INTO badge_level_requirements VALUES(5487,413,'preschool',0,'Learn the basic rules for letterboxing and the safety rules you should follow including proper attire. Know what types of hazards you might encounter while looking for a letterbox and how to be prepared for them.');
INSERT INTO badge_level_requirements VALUES(5488,413,'preschool',1,'Help find at least 3 letterboxes.');
INSERT INTO badge_level_requirements VALUES(5489,418,'preschool',0,'Learn what liquid nitrogen is. Learn about the three states of matter (solid, liquid and gas). What state of matter is liquid nitrogen at room temperature? How is nitrogen transformed from one state of matter to another?');
INSERT INTO badge_level_requirements VALUES(5490,418,'preschool',1,'Learn how liquid nitrogen is handled safely. What is some safety equipment that is used when handling it?');
INSERT INTO badge_level_requirements VALUES(5491,421,'preschool',0,'Read, or have read to you, at least one of the books from the Little House series by Laura Ingalls Wilder. Levels 2-3: Read two books. Level 4-5: Read four books.');
INSERT INTO badge_level_requirements VALUES(5492,421,'preschool',1,'Learn about the real Laura Ingalls Wilder. Who was she? When did she live? Why is she notable?');
INSERT INTO badge_level_requirements VALUES(5493,422,'preschool',0,'Read, or have read to you, at least one of the books from the Little Women series by Louisa May Alcott.  Levels 3-5: Read at least 3 books.');
INSERT INTO badge_level_requirements VALUES(5494,422,'preschool',1,'Learn about the author, Louisa May Alcott. Who was she? When and where did she live?');
INSERT INTO badge_level_requirements VALUES(5495,424,'preschool',0,'Learn who Louis L’Amour was and when he lived. Know what a western novel is, and what “western” means.');
INSERT INTO badge_level_requirements VALUES(5496,424,'preschool',1,'Read at least one of Louis L’Amour’s books. Read a new book if you are earning this badge a different level.');
INSERT INTO badge_level_requirements VALUES(5497,425,'preschool',0,'Loving yourself is just as important as loving others. Make a list of everything you love about yourself. Challenge yourself to not put anything on the list that has to do with what you look like because that is not who you are, but rather what people see. Do you have a great sense of humor? Can you sing beautifully or draw with precision? Do you show kindness to others? Focus on those thing you love about yourself and find a way to share them with others.');
INSERT INTO badge_level_requirements VALUES(5498,425,'preschool',1,'Discuss how you can show love to others. Ideas may include showing kindness, sharing, helping with chores, letting someone else go first, etc. See how big a list you can come up with. What areas can you improve in your own life? Maybe you can let your sibling choose the television show or let your friend decide what game to play. You could offer to help your parent with a chore without being asked or play a game with your grandparents.');
INSERT INTO badge_level_requirements VALUES(5499,430,'preschool',0,'Understand what mail art is. Look at some examples of mail art and discuss it with your family, friends, or group.');
INSERT INTO badge_level_requirements VALUES(5500,430,'preschool',1,'Make and send a piece of mail art.');
INSERT INTO badge_level_requirements VALUES(5501,442,'preschool',0,'What is a marshmallow made of? What other names is it known by?');
INSERT INTO badge_level_requirements VALUES(5502,442,'preschool',1,'Use marshmallows in a recipe.');
INSERT INTO badge_level_requirements VALUES(5503,443,'preschool',0,'Read, or have read to you, the books from the Mary Poppins book series by P. L Travers. Preschool-Level 1: Read at least one book. Levels 2-3: Read at least two books. Level 4: Read at least three books. Level 5: Read all eight books.');
INSERT INTO badge_level_requirements VALUES(5504,443,'preschool',1,'Either make a timeline of P.L. Travers’ life or earn the Biographies badge at your level for P. L. Travers.');
INSERT INTO badge_level_requirements VALUES(5505,449,'preschool',0,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5506,450,'preschool',0,'Know the main components of your program and what each function’s purpose is.');
INSERT INTO badge_level_requirements VALUES(5507,450,'preschool',1,'With help, if necessary, make a presentation about a subject of your choice. Share it with your family, friends, or group.');
INSERT INTO badge_level_requirements VALUES(5508,453,'preschool',0,'Learn the history of Minecraft and who designed it.  How has it evolved over time? How many versions are there? How is Minecraft used in education?');
INSERT INTO badge_level_requirements VALUES(5509,453,'preschool',1,'Build a two story house using wood or stone, and include glass windows, a bed, a furnace, a crafting table, and double chest.  Memorize the basic crafting recipes for the tools and armor.');
INSERT INTO badge_level_requirements VALUES(5510,455,'preschool',0,'Play mini-golf. Preschool-Level 1: Play one time. Levels 2-3: Play two times on different courses if possible. Levels 4-5: Play three times on different courses if possible. Learn how to choose the correct putter for your size.  Level 1 and Up: Learn how to keep score.');
INSERT INTO badge_level_requirements VALUES(5511,455,'preschool',1,'Learn the history of miniature golfing. What other names does it go by?');
INSERT INTO badge_level_requirements VALUES(5512,456,'preschool',0,'What is modesty? Why is it important? What is the difference between modesty and putting yourself down? How can you be modest and confident of yourself and your self worth at the same time?');
INSERT INTO badge_level_requirements VALUES(5513,456,'preschool',1,'Learn to show modesty toward others.  Don’t be selfish and don’t live to make a good impression on others.  Instead, be humble, thinking of others as equally valuable as yourself.  Find an opportunity with a friend or family member to draw praise and attention to them rather than yourself. For the next week, every time you find yourself seeking praise or attention, find something to praise in someone else instead.');
INSERT INTO badge_level_requirements VALUES(5514,459,'preschool',0,'Learn about the history of mosaics. Look at examples of ancient mosaics such as those from Rome or the Aztecs, either at an exhibit, in a book, or online with permission from a parent.');
INSERT INTO badge_level_requirements VALUES(5515,459,'preschool',1,'Create a craft using a mosaic technique.');
INSERT INTO badge_level_requirements VALUES(5516,462,'preschool',0,'Be able to identify what can be found in your museum.');
INSERT INTO badge_level_requirements VALUES(5517,462,'preschool',1,'Understand why and when your chosen museum was built. Locate it on a map.');
INSERT INTO badge_level_requirements VALUES(5518,476,'preschool',0,'Learn how to keep your nails healthy and well groomed, including proper nutrition and personal hygiene.  Level 2 and above should be able to handle nail clippers and files safely.');
INSERT INTO badge_level_requirements VALUES(5519,476,'preschool',1,'Learn how to safely use nail polish and polish remover.  Never paint your nails without a parent’s permission.');
INSERT INTO badge_level_requirements VALUES(5520,479,'preschool',0,'Be able to identify your chosen monument or memorial by a picture.');
INSERT INTO badge_level_requirements VALUES(5521,479,'preschool',1,'Understand why and when your chosen monument/memorial was built.  Locate it on a map.');
INSERT INTO badge_level_requirements VALUES(5522,480,'preschool',0,'Choose a specific tribe or region to learn about. What was their trademark style? How can it be recognized when compared to other Native American artwork?');
INSERT INTO badge_level_requirements VALUES(5523,480,'preschool',1,'Explain how one type of artwork (pottery, baskets, rugs, jewelry, etc.)  is made and name the materials needed.');
INSERT INTO badge_level_requirements VALUES(5524,485,'preschool',0,'.  Know what neon lights are, and where they are frequently found.  Read a book, watch a video or go online (with your parent’s permission) to find out how neon lights are made. What makes the lights different colors?');
INSERT INTO badge_level_requirements VALUES(5525,485,'preschool',1,'.  Learn about the history of neon lights, and when and where they were first used.');
INSERT INTO badge_level_requirements VALUES(5526,490,'preschool',0,'.  Learn what nursing is and how it has changed over the centuries.  How is working in a hospital different from working on a battlefield?');
INSERT INTO badge_level_requirements VALUES(5527,490,'preschool',1,'.  Read a biography of a famous nurse, such as Clara Barton, Mary Seacole, or Florence Nightingale.  Be able to list at least two significant facts about the person you read about. If you earned this badge at a higher level you must read about a new person.');
INSERT INTO badge_level_requirements VALUES(5528,505,'preschool',0,'Before heading outdoors, learn safety rules for the area you plan to explore to keep you from getting injured or lost.');
INSERT INTO badge_level_requirements VALUES(5529,505,'preschool',1,'Learn the rules of Leave No Trace.');
INSERT INTO badge_level_requirements VALUES(5530,506,'preschool',0,'Learn about drinking water safety and purification when participating in outdoor activities.  Purify some water for drinking using on of your learned methods.');
INSERT INTO badge_level_requirements VALUES(5531,506,'preschool',1,'Know basic water safety rules for being in and around water and demonstrate them when participating in water activities.');
INSERT INTO badge_level_requirements VALUES(5532,510,'preschool',0,'What is pancetta?  How is it made?');
INSERT INTO badge_level_requirements VALUES(5533,510,'preschool',1,'Know the animal that produces the meat pancetta is made from.  What other meats come from this animal?');
INSERT INTO badge_level_requirements VALUES(5534,511,'preschool',0,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5535,512,'preschool',0,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5536,514,'preschool',0,'Choose a parshah and read it or have it read to you. Younger levels may have an abridged version read to them.');
INSERT INTO badge_level_requirements VALUES(5537,514,'preschool',1,'Discuss your parshah with a family member or other knowledgeable adult. What insights can they give you? What did it mean to you?');
INSERT INTO badge_level_requirements VALUES(5538,516,'preschool',0,'Think of times in your life when patience has been very difficult for you; maybe it is has been staring at a bunch of birthday gifts and being unable to open them until the end of the party, or maybe it has been the anticipation of a friend or relative coming to visit. For each item on your list, discuss with a parent what your actions were. Were you able to be patient, or did you annoy everyone with constant complaining or energy? How might you have improved your behavior in each of these circumstances?');
INSERT INTO badge_level_requirements VALUES(5539,516,'preschool',1,'Do at least three activities that require patience such as baking bread and waiting for it to rise; planting a seed and waiting for it to sprout; or raising a caterpillar into a butterfly. Why is patience important?');
INSERT INTO badge_level_requirements VALUES(5540,517,'preschool',0,'What does patriotism mean? Explain why it is important to be patriotic. Discuss ways you can show your patriotism.');
INSERT INTO badge_level_requirements VALUES(5541,517,'preschool',1,'Participate in a service project that supports our military or veterans. You may choose to write letters or make cards of thanks, send care packages, do a performance of some kind for your local veterans, be creative!');
INSERT INTO badge_level_requirements VALUES(5542,519,'preschool',0,'Everyone gets into arguments sometimes, but a peaceful person should not lose their temper and should help to resolve the argument as quickly and fairly as possible. Learn several methods on how to manage anger and resolve conflict. The next time you get into an argument with a sibling, friend, or parent, try putting these steps into practice.');
INSERT INTO badge_level_requirements VALUES(5543,519,'preschool',1,'Spend one hour alone with nature (½ hour for Preschool-Level 2). Find a quiet place in a park, on the beach, in a forest, or even your backyard, and simply be alone with your thoughts. Sitting in peaceful silence can sometimes be very hard in our loud and chaotic culture. Learn to take time out each day to appreciate the beauty around you. You may write, draw, sing, meditate, pray, or simply sit. Think about the blessings in your life and concentrate on calming your mind and finding ways to be content with your life.');
INSERT INTO badge_level_requirements VALUES(5544,520,'preschool',0,'Find where peanuts are grown.  To what family of plants do they belong?  What other names are they known by?  How are they harvested?  Draw and label the parts of a peanut plant.');
INSERT INTO badge_level_requirements VALUES(5545,520,'preschool',1,'Learn how peanut butter is made.  What is the best kind of peanut for making peanut butter?  How many peanuts go into each jar?');
INSERT INTO badge_level_requirements VALUES(5546,522,'preschool',0,'Research the history of Pen Pals. How did they become popular?');
INSERT INTO badge_level_requirements VALUES(5547,522,'preschool',1,'Learn proper pen pal safety.  Then find a pen pal and exchange at least 3 letters or emails.');
INSERT INTO badge_level_requirements VALUES(5548,530,'preschool',0,'.  Design and build your own Pinewood Derby car from a kit, including any gluing, painting or measuring, and race it.  (Adult supervision is required for Preschool, Level 1 and Level 2.)');
INSERT INTO badge_level_requirements VALUES(5549,530,'preschool',1,'.  Discuss rules and regulations for the race.  Talk about sportsmanship and why it is important during a race. With a parent, guardian or group leader, role-play examples of good vs. bad sportsmanship.');
INSERT INTO badge_level_requirements VALUES(5550,531,'preschool',0,'Read at least one age appropriate book about pioneer life.');
INSERT INTO badge_level_requirements VALUES(5551,531,'preschool',1,'Who were Lewis and Clark, Davy Crockett, Daniel Boone and Kit Carson?  Learn about the Oregon Trail, the Santa Fe Trail, the Mormon Trail and the California Trail.');
INSERT INTO badge_level_requirements VALUES(5552,534,'preschool',0,'Make a dinner or appetizer pizza.');
INSERT INTO badge_level_requirements VALUES(5553,534,'preschool',1,'Learn about the history of pizza and how it differs in other countries.');
INSERT INTO badge_level_requirements VALUES(5554,536,'preschool',0,'Write a short skit, puppet show, or play and read it for your family, friends, or group.');
INSERT INTO badge_level_requirements VALUES(5555,536,'preschool',1,'Read a book about the life of a famous playwright, such as William Shakespeare. (If you did this requirement at a lower level, choose a different person to learn about.) Level 3, 4, and 5 must read one of the plays written by their chosen person.');
INSERT INTO badge_level_requirements VALUES(5556,537,'preschool',0,'Do Level 4 requirements # 1 & 2.');
INSERT INTO badge_level_requirements VALUES(5557,537,'preschool',1,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5558,539,'preschool',0,'Find out what the ‘first” stuffed toy was and what country it was from.');
INSERT INTO badge_level_requirements VALUES(5559,539,'preschool',1,'Lean about the history of stuffed toys.  What materials were used to stuff the original stuffed toys and what materials are used now?  Look at pictures of stuffed and plush toys over history.');
INSERT INTO badge_level_requirements VALUES(5560,543,'preschool',0,'. Memorize a poem of at least two verses (Level 1: 3; Level 2: 5; Level 3: 7; Level 4 and Level 5: 10) and recite it to someone else.');
INSERT INTO badge_level_requirements VALUES(5561,543,'preschool',1,'. Learn about the benefits of memorizing poetry, such as improved language skills, memory and vocabulary.  Do you notice a difference the more poetry you memorize?');
INSERT INTO badge_level_requirements VALUES(5562,558,'preschool',0,'What is puppetry? Learn about different types of puppets from the list below or others. You should be familiar with the type of puppet, not necessarily how to use or construct it. Preschool: 3 types. Level 1: 5 types. Level 2: 7 types. Level 3: 10 types. Level 4: 15 types. Level 5: 20 types. Animatronics Blacklight Bunraku Caricature (portrait) puppets Costume (body) puppets Finger puppets Found puppets Glove puppets Hand puppets Karagozis Marionettes Marottes Mouth puppets Muppets Parade (Carnival) puppets Rod puppets Shadow puppets Shoulder puppets Sock puppets Water puppetry Wayang Golek Wayang Kulit');
INSERT INTO badge_level_requirements VALUES(5563,558,'preschool',1,'Make different types of puppets and spend some time using them. Give each puppet you made a name, voice, and personality. Preschool -Level 1: Make at least 2 types. Level 2: Make at least 3 types. Levels 3-5: Make at least 4 types.');
INSERT INTO badge_level_requirements VALUES(5564,570,'preschool',0,'Discuss what makes up a relationship  What types of relationships are there? (friends, family, co- workers, etc.).  How do they differ?  Explain what makes a healthy relationship.');
INSERT INTO badge_level_requirements VALUES(5565,570,'preschool',1,'For one week, keep a list of inappropriate relationship behavior demonstrated in the books your read and the movies and TV shows that you watch.  At the end of the week, review your list.  Could the author or director have still told the story if they had their characters behave in a more modest or appropriate manner?  If not, was the story still worth telling?  Think about what you read and watch and whether or not you need to make changes in your own behavior. (Preschool and Level 1 may discuss relationships in their books and shows with parents as they occur rather than keeping a written list.)');
INSERT INTO badge_level_requirements VALUES(5566,574,'preschool',0,'Resourcefulness starts with making wise use of your own time, talents, energy, and mind.  Keep a journal for a week to show how you spend your time.  At the end of the week, sit down with your parents and evaluate what you learned.  Do you schedule enough time for your homework to make sure you can do quality work without being rushed?  Are you involved in too many after school activities?  Do you get enough sleep at night?  Do you spend most of your time in front of the TV and computer, or do you get outside and exercise?  Do you eat healthy meals or mostly junk food?  Find at least 3 areas you think you can improve and work on them for the next two weeks.  (Preschool and Level 1 may keep a picture journal if they wish.)');
INSERT INTO badge_level_requirements VALUES(5567,574,'preschool',1,'Being resourceful also means using the materials around you efficiently. Repair, reuse, or recycle three things that you would normally throw away.  Decorated juice cans make great pencil holders, two liter bottles can be turned into bird feeders, an old tire can become a swing, and old crayons can be melted to make candles.  What can you come up with?');
INSERT INTO badge_level_requirements VALUES(5568,575,'preschool',0,'What is respect? Why is it important? Discuss with your family, friends, or group how you can show respect to others, such as parents, teachers, older siblings, friends, group leaders, etc.');
INSERT INTO badge_level_requirements VALUES(5569,575,'preschool',1,'Practice being respectful of others for two weeks. Make a chart and mark on it when you were respectful of others and when you weren’t. Which should happen more often?');
INSERT INTO badge_level_requirements VALUES(5570,588,'preschool',0,'Learn to solve a 3x3x3 Rubik’s cube using the basic solve method.');
INSERT INTO badge_level_requirements VALUES(5571,588,'preschool',1,'Learn who created Rubik’s cubes, where and when.');
INSERT INTO badge_level_requirements VALUES(5572,589,'preschool',0,'Learn the proper terminology for all the main parts of a sloop-rigged sailboat (mast, sails, bow, stern, hull, rudder, keel, boom, lines, halyards, sheets, etc.).');
INSERT INTO badge_level_requirements VALUES(5573,589,'preschool',1,'Learn and follow all safety rules. Have an experienced sailor give you a lesson, then go sailing with an experienced adult on at least three different occasions (for at least one hour total).');
INSERT INTO badge_level_requirements VALUES(5574,591,'preschool',0,'Learn about what a pollinator is.  Be able to describe the process of pollination and how it benefits both us and nature.');
INSERT INTO badge_level_requirements VALUES(5575,591,'preschool',1,'Learn about the plight of the honeybee.  What are some of the main causes of deaths to honey bees?  How are humans harming honey bees?');
INSERT INTO badge_level_requirements VALUES(5576,596,'preschool',0,'Know the name of your school, your school mascot and colors. If your school has a song or chant, learn it.');
INSERT INTO badge_level_requirements VALUES(5577,596,'preschool',1,'Know the name(s) of your teacher(s) and know at least one each: Principal/vice principal Office Manager/Attendance Clerk Custodians Cafeteria Workers Health Aid, Counselor, Psychologist, etc. Specialty Teachers (special education, speech art, computers, resource, librarian, etc.) Bus Driver Title IX Coordinator, Homeless Liaison, etc.');
INSERT INTO badge_level_requirements VALUES(5578,598,'preschool',0,'Learn what Scrabble is and how to play it.  Level 1 and Up: Play a game of Scrabble with someone. Level 2 and Up: Keep score.');
INSERT INTO badge_level_requirements VALUES(5579,598,'preschool',1,'Learn about the history of the Scrabble game.  Who invented it?  Read, or have read to you, a biography of the inventor.');
INSERT INTO badge_level_requirements VALUES(5580,605,'preschool',0,'Someone with self control: Completes their assignments Stays on task Shows patience Ignores peer pressure Chooses productive rather than destructive activities Controls their tempers Make a list of ten ways you can exhibit these characteristics in your daily life.');
INSERT INTO badge_level_requirements VALUES(5581,605,'preschool',1,'Discuss the following questions with a parent or other adult. How can I demonstrate self control when I am tired or irritated? What are some positive activities that I can do to replace bad habits? How does my choice in friends affect my actions? Who are trustworthy people I can talk to if I need help or advice?');
INSERT INTO badge_level_requirements VALUES(5582,607,'preschool',0,'Find out at what age someone is usually considered a senior citizen.  What is the age difference between what many businesses and agencies consider to be senior citizens and the age you need to be to collect government benefits such as social security and medicare.  Talk with a senior citizen for at least 15 minutes.');
INSERT INTO badge_level_requirements VALUES(5583,607,'preschool',1,'Interview a senior citizen and find out about their lives.  Some questions you may ask them include: Where did they grow up? How much education do they have? What did they do as an adult? What is their favorite childhood memory?');
INSERT INTO badge_level_requirements VALUES(5584,608,'preschool',0,'Learn the seven teachings. Be able to explain what each one means and how you use them in your own life.');
INSERT INTO badge_level_requirements VALUES(5585,608,'preschool',1,'Know the brief story of the Seven Teachings.');
INSERT INTO badge_level_requirements VALUES(5586,613,'preschool',0,'Understand what it means to Shelter in Place and how it can keep you and others safe in an emergency.');
INSERT INTO badge_level_requirements VALUES(5587,613,'preschool',1,'Know the local rules for your Shelter in Place or Stay at Home order.  What you are allowed to do?  What are you not allowed to do?  What is the difference between obeying the letter of the law verses the intent of the law?  Why is it important that you take the restrictions seriously?  Who do you put at risk if you don’t? Optional Requirements');
INSERT INTO badge_level_requirements VALUES(5588,624,'preschool',0,'Research the history of s’mores. How big was the largest s’more ever created? When is National S’Mores Day?');
INSERT INTO badge_level_requirements VALUES(5589,624,'preschool',1,'Make basic s’mores (2 graham crackers with a piece of chocolate and a toasted marshmallow between them). Learn and obey safety precautions.');
INSERT INTO badge_level_requirements VALUES(5590,632,'preschool',0,'Why is it important to include everyone, no matter their physical or mental abilities?');
INSERT INTO badge_level_requirements VALUES(5591,632,'preschool',1,'Choose a specific area of disability to study, such as cerebral palsy or autism. Learn about its defining characteristics.');
INSERT INTO badge_level_requirements VALUES(5592,641,'preschool',0,'.  Learn to identify 3 (Preschool), 5 (Level 1 and 2), 8 (Level 3 and 4) 10 (Level 5) flags from other states.');
INSERT INTO badge_level_requirements VALUES(5593,641,'preschool',1,'.  Research the history of at least one of the flags you chose for requirement 1*.');
INSERT INTO badge_level_requirements VALUES(5594,645,'preschool',0,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5595,651,'preschool',0,'What is SWAPS? Why do people join SWAPS events? Help set up or participate in a SWAPS.  Discuss if you are going to swap within your group or with others as individuals or as a group.');
INSERT INTO badge_level_requirements VALUES(5596,651,'preschool',1,'Decide on the theme for your SWAPS, holiday, food, badge, state swap, just for fun, to celebrate a holiday, to help in earning in a badge, etc.  Keep in mind that SWAPS should represent the person giving it in some way.  Make a SWAPS.  Make sure all pins have a message about the pin and /or your group number or name.');
INSERT INTO badge_level_requirements VALUES(5597,658,'preschool',0,'In order to teach others effectively you must understand the three most common learning styles. The three most common learning styles are visual (when one learns by seeing with their eyes), auditory (when one learns by simply listening with the ears), and kinesthetic (when one learns by doing). Which way do you think you learn best? Which way do those around you learn best?');
INSERT INTO badge_level_requirements VALUES(5598,658,'preschool',1,'In order to teach others well it’s important to teach using all three learning styles. Explain your subject (for auditory learners), demonstrate your subject (for visual learners), guide your students in doing your subject (for kinesthetic learners). Pick the subject in which you’d like to teach others. (Perhaps teach how to play a game or how to plant a seed.)');
INSERT INTO badge_level_requirements VALUES(5599,659,'preschool',0,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone. You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge. If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(5600,661,'preschool',0,'Learn about how the first teddy bear was created. Make sure you know about both companies who created the bears and the story that inspired the toy.');
INSERT INTO badge_level_requirements VALUES(5601,661,'preschool',1,'Gather your teddy bears and a friend’s and look at them to compare their features. What is your favorite thing about each one?');
INSERT INTO badge_level_requirements VALUES(5602,669,'preschool',0,'Learn the names of the Five Books of the Torah and (Level 2 and above) the 54 parshiyot (individual sections read weekly.)');
INSERT INTO badge_level_requirements VALUES(5603,669,'preschool',1,'Read or hear the parsha for two weeks (Preschool and Level 1 may read or have read to them abridged versions.) Tell some else what the parsha said.');
INSERT INTO badge_level_requirements VALUES(5604,679,'preschool',0,'Do Level 4 *1 and *2');
INSERT INTO badge_level_requirements VALUES(5605,679,'preschool',1,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5606,702,'preschool',0,'Learn to play a game in each of the following categories: Contest game (hold your breath the longest, swim the fastest, float the longest, etc.) Tag game (Marco Polo, sharks and minnows, colors, etc) Sport game (water polo, diving, snorkeling, surfing, canoeing, etc) Race game (freestyle race, pool noodle riding, raft racing, etc) Adapted game (water baseball, basketball, capture the flag, etc) Obstacle course games (string together slip-n-slides, mini pools, water balloons on strings to break, etc) Cooperative game (non-competitive games, working towards a common goal, etc)');
INSERT INTO badge_level_requirements VALUES(5607,702,'preschool',1,'Earn the Water Safety badge at your level.');
INSERT INTO badge_level_requirements VALUES(5608,702,'preschool',2,'Create your own game to play in the water. What type of game is it? How many people can play? Is there an age or ability limit? What items do you need to play? Teach someone else to play the game.');
INSERT INTO badge_level_requirements VALUES(5609,714,'preschool',0,'Learn about Williams Syndrome. What is Williams Syndrome? What causes it?');
INSERT INTO badge_level_requirements VALUES(5610,714,'preschool',1,'Discuss the common features of people with Williams Syndrome.');
INSERT INTO badge_level_requirements VALUES(5611,716,'preschool',0,'Watch the classic 1939 film The Wizard of Oz.');
INSERT INTO badge_level_requirements VALUES(5612,716,'preschool',1,'Read or have read to you the first book in the Wizard of Oz series written by L. Frank Baum.');
INSERT INTO badge_level_requirements VALUES(5613,719,'preschool',0,'What is science?');
INSERT INTO badge_level_requirements VALUES(5614,719,'preschool',1,'Study the lives and work of 2 prominent women scientists (Level 2 – 3, Level 3 – 4, and Level 4 & Level 5 – 5). Try to choose from women in different areas of scientific study.');
INSERT INTO badge_level_requirements VALUES(5615,720,'preschool',0,'What does Women’s Suffrage mean?  Understand what voting means and why it is important that both men and women get to vote.');
INSERT INTO badge_level_requirements VALUES(5616,720,'preschool',1,'Read a book or story about Women’s Suffrage. Optional Requirements');
INSERT INTO badge_level_requirements VALUES(5617,723,'preschool',0,'.  Learn what the word “currency” means. Look at pictures of currencies used in other countries (at least 3) and learn what they are called.   How are they different from the U. S. Dollar? How are they similar?  Level 3 and up must learn about how the value of currency differs around the world and how that value affects a country’s economy.');
INSERT INTO badge_level_requirements VALUES(5618,723,'preschool',1,'.  Read a book, watch a video, or go online (with your parent’s permission) to find out how coins and banknotes are made. What sorts of metals are coins in the U. S. made from? Tell your family or Club what you learned.');
INSERT INTO badge_level_requirements VALUES(5619,725,'preschool',0,'.  Learn to identify 3 (Preschool), 5 (Level 1 and 2), 10 (Level 3 and 4) 15 (Level 5) flags from other countries.');
INSERT INTO badge_level_requirements VALUES(5620,725,'preschool',1,'.  Research the history of at least three of the flags you chose for requirement 1*.  Why was this design chosen?  What does it represent?');
INSERT INTO badge_level_requirements VALUES(5621,728,'preschool',0,'Find at least one world landmark on each continent and locate it on a map.  Be able to identify the landmark from a picture.');
INSERT INTO badge_level_requirements VALUES(5622,728,'preschool',1,'Learn the history of each of the landmarks found in requirement #1.  Is it man-made? If so, why was it built?');
INSERT INTO badge_level_requirements VALUES(5623,736,'preschool',0,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.   You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.   If for some reason you cannot teach what you have learned to someone else, you may choose an additional 2 optional requirements instead.');
INSERT INTO badge_level_requirements VALUES(5624,737,'preschool',0,'Learn what a yurt is, how it is built, and what makes it unique from other structures.');
INSERT INTO badge_level_requirements VALUES(5625,737,'preschool',1,'Locate at least one yurt in your state. Visit a yurt if possible.');
INSERT INTO badge_level_requirements VALUES(5626,746,'preschool',0,'Know the difference between associates, bachelors, masters and PhD, understand which is needed for your future occupation and the time commitment and cost of each.');
INSERT INTO badge_level_requirements VALUES(5627,746,'preschool',1,'Research the amount of money your degree will take to earn and create a financial plan for your education to help keep you out of debt.  Understand how school choice can affect how much debt you will incur.  Have a plan in place to pay off any debt as quickly as possible.');
INSERT INTO badge_optional_requirements VALUES(1,1,3,'Use Minecraft, Legos, a 3D puzzle or other building materials or computer programs to build a Wonder of your choosing.');
INSERT INTO badge_optional_requirements VALUES(2,1,4,'Watch a movie or documentary about one or all of the Wonders.');
INSERT INTO badge_optional_requirements VALUES(3,1,5,'Learn about the  New7Wonders Foundation list of  Wonders of the World.');
INSERT INTO badge_optional_requirements VALUES(4,1,6,'Find the locations of each wonder on the map. You could also add the New7Wonders, and the Seven Wonders of the Natural World. Where is the one closest to your home? Which one is the farthest away? What continent has the most?');
INSERT INTO badge_optional_requirements VALUES(5,1,7,'Create a pop-up book featuring the Seven Wonders or illustrate a book of your own.');
INSERT INTO badge_optional_requirements VALUES(6,1,8,'If you were in charge of creating a new list of Wonders of the World, which would you choose?  Be able to support your choices.');
INSERT INTO badge_optional_requirements VALUES(7,1,9,'There is also a list of Seven Wonders of the Natural World. Learn about the Wonders on this list.');
INSERT INTO badge_optional_requirements VALUES(8,1,10,'Visit the site of a wonder from any of the three lists mentioned here.');
INSERT INTO badge_optional_requirements VALUES(9,1,11,'Of all the Wonders of the Ancient World, only one remains mostly intact. Choose one that no longer stands and learn what happened to it. What stands in its place, now?');
INSERT INTO badge_optional_requirements VALUES(10,2,3,'Know what the difference between a 911 dispatcher and a 911 operator is.');
INSERT INTO badge_optional_requirements VALUES(11,2,4,'Go to the 911 festival in Haleyville, AL.  Or host your own mini festival to honor your local first responders.');
INSERT INTO badge_optional_requirements VALUES(12,2,5,'Visit a training facility for 911 emergency service.');
INSERT INTO badge_optional_requirements VALUES(13,2,6,'Help your community respond to or recover from an emergency.');
INSERT INTO badge_optional_requirements VALUES(14,2,7,'Visit a museum or exhibit regarding 911 emergency services. The home of 911 has a wall dedicated to the fist 911 call.');
INSERT INTO badge_optional_requirements VALUES(15,2,8,'Help with a community service event such as the 911 festival that honors first responders. Set up a booth or make fliers to hand out inviting others to join your troop or club.');
INSERT INTO badge_optional_requirements VALUES(16,2,9,'Interview a 911 dispatcher and ask why he/she chose this field, their most rewarding moment, most difficult situation etc.');
INSERT INTO badge_optional_requirements VALUES(17,2,10,'Find out how to become a 911 dispatcher and how much a 911 dispatcher makes in your area.');
INSERT INTO badge_optional_requirements VALUES(18,2,11,'Write an essay about how 911 emergency services has helped you or someone you have loved in the past.');
INSERT INTO badge_optional_requirements VALUES(19,2,12,'Find out where the funding for 911 dispatchers come from (taxes, grants, donations, etc.)?');
INSERT INTO badge_optional_requirements VALUES(20,2,13,'Read a book about 911 or one where 911 plays a big part.');
INSERT INTO badge_optional_requirements VALUES(21,2,14,'Create a poster or fliers to teach others about 911 emergency service, what they do.');
INSERT INTO badge_optional_requirements VALUES(22,2,15,'With your parent’s permission, watch a documentary or a movie about 911 emergency services.');
INSERT INTO badge_optional_requirements VALUES(23,2,16,'Earn your emergency preparedness badge at your level.');
INSERT INTO badge_optional_requirements VALUES(24,2,17,'Earn your emergency services badge at your level for any of the services called by 911 (police, fire department, ambulance, etc.)');
INSERT INTO badge_optional_requirements VALUES(25,2,18,'Earn the First Aid Badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(26,3,3,'Participate in a 9/11 memorial ceremony.');
INSERT INTO badge_optional_requirements VALUES(27,3,4,'Do a community service project related to 9/11 that does not include attending or participating in a memorial service or supporting our troops. This might include supporting charities the help the victims of 9/11 or doing cleanup at a 9/11 memorial or monument.');
INSERT INTO badge_optional_requirements VALUES(28,3,5,'Visit Ground Zero, the Pentagon or the Pennsylvania field where the planes crashed.');
INSERT INTO badge_optional_requirements VALUES(29,3,6,'Visit a monument for 9/11.');
INSERT INTO badge_optional_requirements VALUES(30,3,7,'Create a piece of art that shows how you feel about 9/11.');
INSERT INTO badge_optional_requirements VALUES(31,3,8,'Write a poem for 9/11 Patriot Day.');
INSERT INTO badge_optional_requirements VALUES(32,3,9,'Write a report or give an oral presentation to your troop or family about 9/11 means to you.');
INSERT INTO badge_optional_requirements VALUES(33,3,10,'Learn about the 9/11 memorial in New York.  What controversies came up during its design andconstruction?  Who designed it?  How long did it take to complete?');
INSERT INTO badge_optional_requirements VALUES(34,3,11,'Find out how 9/11 changed airport security.');
INSERT INTO badge_optional_requirements VALUES(35,3,12,'Find out what role dogs played in the aftermath of 9/11. Third Party Resources: 9/11 Memorial and Museum website: https://www.911memorial.org/teach-learn');
INSERT INTO badge_optional_requirements VALUES(36,4,3,'Create a small book (4×6) for the alphabet. Have one letter on each page, and then add a word that corresponds with that letter. For example, for the letter A you might write the word Apple and then decorate the page with apples. Here are some page examples you might use when creating your book: Food, Shoes, Holidays, Colors, Movies, etc.');
INSERT INTO badge_optional_requirements VALUES(37,4,4,'Create an alphabet scrapbook. Each picture must be associated with a letter of the alphabet, such as “A is for Adventurous” with a picture of you climbing a tree, “B is for Bountiful” with a picture of your family at Thanksgiving dinner, “C is for Color” with a picture of you coloring, etc.');
INSERT INTO badge_optional_requirements VALUES(38,4,5,'Create words on the fridge using magnet letters.  Try to use as many letters as you can without running out.');
INSERT INTO badge_optional_requirements VALUES(39,4,6,'Put together an alphabet puzzle.');
INSERT INTO badge_optional_requirements VALUES(40,4,7,'Teach the alphabet to someone younger than yourself.');
INSERT INTO badge_optional_requirements VALUES(41,4,8,'Create a 3D art project that involves letters.');
INSERT INTO badge_optional_requirements VALUES(42,4,9,'Choose 5 different words and use them to create acronyms.');
INSERT INTO badge_optional_requirements VALUES(43,4,10,'Play an ABC computer game.');
INSERT INTO badge_optional_requirements VALUES(44,4,11,'Play an alphabet game such as: Choose a subject. Take turns with your friends going through the alphabet saying words from that subject.  (Ex: The subject is Food. Apples, Bread, Chocolate, Donuts, etc…) Choose a subject, such as food, and take turns with your friends naming a food that start with whatever letter the last food ended with. (Ex:  Apple, Eggplant, Toast, etc….)');
INSERT INTO badge_optional_requirements VALUES(45,4,12,'Write an alliteration, a sentence where each word starts with the same letter.');
INSERT INTO badge_optional_requirements VALUES(46,4,13,'Create a picture using only letters.');
INSERT INTO badge_optional_requirements VALUES(47,4,14,'Go on an Alphabet scavenger hunt around your town. See if you can find all 26 letters on the street signs, license plates, store signs, etc. that you pass.');
INSERT INTO badge_optional_requirements VALUES(48,4,15,'Make a secret code and then write a message with it. Have someone decode it.');
INSERT INTO badge_optional_requirements VALUES(49,4,16,'Buy a giant letter from the craft store (such as the first letter of your name). Mod Podge pictures onto the letter and then display it somewhere in your home.');
INSERT INTO badge_optional_requirements VALUES(50,4,17,'Research the alphabet of a different culture/language. How is it different from ours? Do they have more or less letters than we do? Write the alphabet on a piece of paper and try saying it. Third Party Resources: WikiHow’s How to Learn the Alphabet Backwards: https://www.wikihow.com/Learn-the-Alphabet-Backwards WriteShop’s Make an ABC Book: https://writeshop.com/making-an-alphabet-book/ Hands On As We Grow’s 50 Alphabet Activities for Kids: https://handsonaswegrow.com/50-alphabet-activities/  Kidz Phonics: https://www.kizphonics.com/');
INSERT INTO badge_optional_requirements VALUES(51,6,3,'Pick a simple outfit such as a blouse and skirt, or t-shirt and pants. How many ways can you change the look of the outfit by changing accessories? Make a sketch of each option, or take pictures of you accessorizing each outfit differently.');
INSERT INTO badge_optional_requirements VALUES(52,6,4,'Learn how to make or decorate an accessory of your choice. You may dye or embroider a scarf, attach beads to a belt, sew lace or a crocheted flower on gloves, etc.');
INSERT INTO badge_optional_requirements VALUES(53,6,5,'Take a tour of a museum that has historic accessories on display or through a factory that makes some type of accessory or a specialty store that has examples of one type of accessory.');
INSERT INTO badge_optional_requirements VALUES(54,6,6,'Find photos of people carrying or wearing accessories that really stand out.  Be able to tell whether it is the shape, the color, or size, etc. that makes the items stand out.  Do you like all of them?  Are any of them classics or fads?  Are they an appropriate match for the outfit they are with? Preschool – Level 1: Find photos of 5 people. Levels 2 & 3: Find photos of 6 people. Level 4: Find photos of 7 people. Level 5: Find photos of 9 people.');
INSERT INTO badge_optional_requirements VALUES(55,6,7,'Choose a type of accessory and learn the names of different styles of that item.  For example, for hats there are cowboy, fedora, cloche, baseball caps, knit caps, etc. Make a poster display of the different styles. This requirement may be repeated with different accessories such as jewelry, scarves, handbags, shoes, etc.');
INSERT INTO badge_optional_requirements VALUES(56,6,8,'Play a game of choosing accessories.  Pick an outfit out of your closet and have a contest with someone else to see who can find the best accessories to go with it.  You can choose a time limit if you want. You may also choose the type of activity or time of year the outfit will be used if you want. You may draw the accessories, find photos in catalogs, or locate items online (with permission). You may choose a photo or borrow an outfit from a friend or parent, etc.');
INSERT INTO badge_optional_requirements VALUES(57,6,9,'Visit a store or look through a catalog and make a list of at least 6 different types of hair accessories. How can accessories in your hair add or detract from an outfit?');
INSERT INTO badge_optional_requirements VALUES(58,6,10,'Find a favorite book and draw at least five pictures of the main character in different activities with different accessories.');
INSERT INTO badge_optional_requirements VALUES(59,6,11,'In today’s day of technological gadgets, what accessories are available to hold them? Find at least 5 different accessories for items such as cell phones, iPods and laptop computers.  How can these items be both fashionable and functional?');
INSERT INTO badge_optional_requirements VALUES(60,6,12,'Choose some of your accessories in good repair to donate to a charity or give to a needy friend OR you can make some accessories for the same purpose.');
INSERT INTO badge_optional_requirements VALUES(61,6,13,'Find two books or documentaries on famous people that talk a lot about that person’s style, clothing or accessories. Evaluate the famous person’s choice of accessories.  Were they good choices?  Do you agree with the authors?  Which books or movies did you prefer and why?');
INSERT INTO badge_optional_requirements VALUES(62,6,14,'Help make, buy, design or decorate some special accessories for a friend who is going on a special trip or needs some special accessories for a drama production.');
INSERT INTO badge_optional_requirements VALUES(63,6,15,'Discuss the accessory needs of a person with some type of special challenge.  What kinds of materials can people with severe allergies use in their accessories?  What type of purse would you want to carry if you had only one arm, etc.?  Is there an accessory that people with disabilities use more than other folks? Where do people with disabilities go to find things that fit/work for them?');
INSERT INTO badge_optional_requirements VALUES(64,8,3,'Earn the Airplanes Badge at your level.');
INSERT INTO badge_optional_requirements VALUES(65,8,4,'Learn about commercial airliners. Which types of airplanes are used for trans-continental flights? Which are used for inter-continental flights? What are their capacities? How much does it cost to operate each?');
INSERT INTO badge_optional_requirements VALUES(66,8,5,'Study a well-documented airliner crash. What are the most common types of errors that cause crashes: pilot error, technical malfunction, weather conditions or a combination?');
INSERT INTO badge_optional_requirements VALUES(67,8,6,'Investigate freight haulage by aircraft. What types of planes are used for freight? What are the costs involved in maintaining an air freight business?');
INSERT INTO badge_optional_requirements VALUES(68,8,7,'What types of training and licenses are required for commercial pilots, flight instructors, and flight examiners? What type of medical tests?');
INSERT INTO badge_optional_requirements VALUES(69,8,8,'Learn about civilian (non-military) uses of helicopters. What are they used for? What training is required for a helicopter pilot license?');
INSERT INTO badge_optional_requirements VALUES(70,8,9,'Find out about other civilian (non-military) uses of air craft besides passenger and freight carriage. What other industries/businesses use aircraft such as the oil industry or medical industry? What training and pay scale can be expected for a pilot in these industries?');
INSERT INTO badge_optional_requirements VALUES(71,8,10,'Learn why thunderstorms are so dangerous for aircraft. What is a micro-burst? What effect would it have on an airplane flying into it? What action should be taken by a pilot who does fly into a micro-burst?');
INSERT INTO badge_optional_requirements VALUES(72,8,11,'Read a biography of a famous pilot or other aviation specialist.');
INSERT INTO badge_optional_requirements VALUES(73,8,12,'Learn about the ground-crew that supports pilots. What specific jobs are there? Choose one and learn about the training, pay and certification involved in becoming qualified for the job. (This requirement may be repeated for each different job studied).');
INSERT INTO badge_optional_requirements VALUES(74,8,13,'Learn about an experimental aircraft. What makes it different from current aircraft? What are its capabilities? What particular advantage(s) is it expected to have?');
INSERT INTO badge_optional_requirements VALUES(75,8,14,'Learn about different types of fuel for different aircraft engines. What identifying signs (symbols/icons/letters/numbers) are on the containers of fuel to show the difference?');
INSERT INTO badge_optional_requirements VALUES(76,8,15,'Learn about the Civil Air Patrol. What is its function?');
INSERT INTO badge_optional_requirements VALUES(77,8,16,'Learn about the National Transportation Safety Board (NTSB). What does it do?');
INSERT INTO badge_optional_requirements VALUES(78,9,3,'Practice baking pastry products.  Bake at least two of the following: turnovers, dessert pies, baklava or something else made with phyllo dough, as well as breakfast pastries, pot pies, quiche with crust, tarts, or something using puff pastry.');
INSERT INTO badge_optional_requirements VALUES(79,9,4,'Research a career as a baker. What type of salary could you expect? What sort of education do you need? What are some of the highs and lows and various costs of starting your own bakery? What is the difference between owning your own bakery and working for an established one?');
INSERT INTO badge_optional_requirements VALUES(80,9,5,'Broaden your experience with pies and pie crusts.  Choose three of the following to bake: a pie crust made of graham crackers, pie crust made with other cookie crumbs, a regular two-crusted pie, a custard pie, a cream pie, a pie with a fancy border on the crust, or a pie with a design either cut into the top crust or stuck on the top with extra layers of crust.');
INSERT INTO badge_optional_requirements VALUES(81,9,6,'Make two types of cake batter twice each.  Make a regular cake and cupcakes out of both types of batter.  How did you need to adjust things so that you get the best product when you changed the size?');
INSERT INTO badge_optional_requirements VALUES(82,9,7,'Bake two types of cake such as a torte, a jellyroll, a layer cake with at least three layers, a cake that has a ‘trench’ cut into it for a filling, a bundt cake, or a sheet cake that is made into a shape such as a house or heart.');
INSERT INTO badge_optional_requirements VALUES(83,9,8,'Learn about the different categories of cookies such as bar, drop, pressed, molded, etc.  Choose a flavor such as vanilla, chocolate, or lemon, and make at least two different types of cookies of the same flavor.  Which do you like better and why?');
INSERT INTO badge_optional_requirements VALUES(84,9,9,'Choose a baked doughnut, biscuit, or yeast bread recipe and bake it in at least two forms or shapes.  For example, you can make doughnuts in the traditional circle, a rectangle, or take a strip and twist it into a pretzel-type shape.  Yeast breads can be made into many shapes for rolls and they can be braided, twisted, long & thin, or big & round.');
INSERT INTO badge_optional_requirements VALUES(85,9,10,'Learn about the various different types of cake such as pound, chiffon, angel food, fruit cake, etc.  Bake two that you haven’t tried before.');
INSERT INTO badge_optional_requirements VALUES(86,9,11,'Take a simple recipe such as plain pancakes or biscuits and (1) use the recipe the way it is written, (2) double the liquid, the salt, or the fat, and (3) halve the liquid, salt, or fat.  It would be wise to only make half a recipe for the second or third option so as to not waste ingredients should you not like your results.  Figure out something to do with any finished product that you really don’t like—bread crumbs for a casserole, cubes for bread pudding or croutons.');
INSERT INTO badge_optional_requirements VALUES(87,9,12,'Research the various ethnic flat breads such as pita, tortillas, naan, chapatti and lavish.  Try making two of them.');
INSERT INTO badge_optional_requirements VALUES(88,9,13,'Make a poster with a world map and pictures on countries showing where special breads or baked goods originated.  Level 3: Use at least ten pictures. Level 4: Use at least 15 pictures. Level 5 :Use at least 20 pictures.');
INSERT INTO badge_optional_requirements VALUES(89,9,14,'Bake at least two baked goods for a bake sale supporting your group or a non-profit organization.');
INSERT INTO badge_optional_requirements VALUES(90,9,15,'Bake two special recipes for someone on a special diet such as diabetic, egg-free, or gluten-free.');
INSERT INTO badge_optional_requirements VALUES(91,9,16,'Baked goods are most commonly used as a side dish such as rolls or for a dessert.  Prepare two different main dishes that are partly baked goods such as pot pie, meat turnovers, empanadas, burritos, or stew with dumplings that you have not made before.');
INSERT INTO badge_optional_requirements VALUES(92,9,17,'Visit the workplace of any portion of the process of bread-making from marketing & planting the seed to packing baked goods and selling them.');
INSERT INTO badge_optional_requirements VALUES(93,9,18,'Research the least expensive places to buy flour, oil, and sweeteners in your community.  Does the quality vary?  What are the best ways to store your baking ingredients?  How do you store various baked goods?  Which ones can be frozen?');
INSERT INTO badge_optional_requirements VALUES(94,9,19,'Compare at least three different types of ovens for energy efficiency, price, and satisfactory baking: toaster oven, gas oven, electric oven, convection, wood stove ovens, microwave, camping, and solar ovens.');
INSERT INTO badge_optional_requirements VALUES(95,10,3,'Earn the Chef badge at your level.');
INSERT INTO badge_optional_requirements VALUES(96,10,4,'Earn the Foods badge at your level.');
INSERT INTO badge_optional_requirements VALUES(97,10,5,'Choose two different types of meat (beef, poultry, lamb/mutton, goat, etc) and learn how to cook each one.  Which did you like best?');
INSERT INTO badge_optional_requirements VALUES(98,10,6,'Earn the Baking badge at your level.');
INSERT INTO badge_optional_requirements VALUES(99,10,7,'Learn how to create a full meal from scratch with no prepackaged or boxed foods.');
INSERT INTO badge_optional_requirements VALUES(100,10,8,'Earn the Nutrition badge at your level.');
INSERT INTO badge_optional_requirements VALUES(101,10,9,'Learn about foods from another culture. Choose a country and learn how to make at least one food from it, such as enchiladas from Mexico, kolaches from Czechoslovakia (Czech Republic), Yorkshire puddings from England, or oat cakes from Scotland.');
INSERT INTO badge_optional_requirements VALUES(102,10,10,'Learn how to make desserts such as crumbles, cakes, meringues, mousses, pies, etc. Make one and serve it to your family or troop.');
INSERT INTO badge_optional_requirements VALUES(103,10,11,'Earn the Cake Decorating badge at your level.');
INSERT INTO badge_optional_requirements VALUES(104,10,12,'Learn about careers in the cooking business, such as a chef, a caterer, a waitress, etc.  What kind of training/education is required?  What are working hours typically like and what hourly pay-rate/salary can you expect? Level 3 – 5 only: if possible, shadow someone for a day who works in the cooking business for a living.');
INSERT INTO badge_optional_requirements VALUES(105,10,13,'People who live in different parts of the United States have different local foods. For instance, in the Southern states (such as Georgia and Alabama), people would eat a lot of sweet potatoes, peanuts, and chicken. People in New England would eat a lot of corn, squash, and beans.  Choose a part of the U.S. other than where you live, learn about the kinds of food they eat and learn how to cook at least one dish from that area. If you do not live in the U.S., modify this requirement to suit your country and/or region.');
INSERT INTO badge_optional_requirements VALUES(106,10,14,'Different foods are appropriate for different occasions. For instance, foods that would normally be served at a barbecue are not the same foods one would serve at a wedding reception.  What sorts of foods would you serve at the following events: a wedding reception, a garden party/tea party, a barbecue, a quiet dinner at home, a bridal/baby shower, a birthday party, or a formal banquet?');
INSERT INTO badge_optional_requirements VALUES(107,10,15,'Learn what sorts of drinks should be served at different occasions. When would you serve the following: red wine, white wine, champagne, water, fruit juices, hot tea, coffee, iced tea, soft drinks/sodas, or milkshakes/smoothies?');
INSERT INTO badge_optional_requirements VALUES(108,10,16,'Create your own recipe book.  Include any recipes you have tried and liked while earning this badge.  Show it to your family, friends, club, or troop. You must have at least 12 different recipes in your recipe book, including at least one for each of the following foods: breads, main dishes, salads, soups, drinks (such as smoothies), cookies, and desserts.');
INSERT INTO badge_optional_requirements VALUES(109,10,17,'Visit your local supermarket and look at the different vegetables and fruits. Choose at least one that you have not tried before and try it.  Many vegetables can or should be cooked before eating.  Try one way of cooking a vegetable that you have not eaten before, such as steaming, sautéing, stir-frying, roasting, etc.');
INSERT INTO badge_optional_requirements VALUES(110,10,18,'Learn how to cook food for an allergy diet, such as gluten-free, dairy-free, nut-free, low-sodium, GAPS, or Failsafe.');
INSERT INTO badge_optional_requirements VALUES(111,11,3,'Learn two new ways of casting on stitches (Examples: long tail cast-on, two-needle cast on; stranded cast-on; provisional cast-on).  What are the different kinds of casting on most suited for?');
INSERT INTO badge_optional_requirements VALUES(112,11,4,'Learn how to read a knitting chart.  Knit an item using a knitting chart pattern.');
INSERT INTO badge_optional_requirements VALUES(113,11,5,'Learn how to do picture knitting.  It requires special techniques to knit a picture in different colored yarns.  Knit something which has a picture in it.  This does not have to be a complicated pattern: there are simple geometric designs that you can try!');
INSERT INTO badge_optional_requirements VALUES(114,11,6,'Learn how to knit using the ridged technique.  Knit an item, such as a tea-cosy or toilet-roll cover, using this technique.');
INSERT INTO badge_optional_requirements VALUES(115,11,7,'Learn how to knit “short rows” of knitting.  Knit an item that uses “short rows.”  A ruffled scarf would be a simple article.');
INSERT INTO badge_optional_requirements VALUES(116,11,8,'There are many, many different knitting techniques, such as modular knitting, knitting from the top down, circular knitting, seamless knitting, patchwork knitting, heirloom knitting, etc.  Visit a hobby/craft shop and look at books on the various techniques available.  With parental permission you may go online and look at knitting books and visit knitting sites and look at patterns.  Some sites offer free patterns.  Choose a technique you have never done before and knit an article using that technique.  You may repeat this requirement for each new technique you learn.');
INSERT INTO badge_optional_requirements VALUES(117,11,9,'Knitting items in different historical fashion styles is also popular. Jane Austen Knits is a magazine devoted to knitting in the Regency style of fashion.  There are books with knitting inspired by Medieval patterns, Tudor patterns, Anne of Green Gables novels, and Victorian themes.  Choose a time period that you are interested in and find a knitting pattern for a piece of clothing or accessory item that would be appropriate for that time and knit the item.');
INSERT INTO badge_optional_requirements VALUES(118,11,10,'Knitting for pets is becoming more popular and there are many patterns available.  Knit an item of clothing for a pet.');
INSERT INTO badge_optional_requirements VALUES(119,11,11,'Make or add to your book of sample squares of different knitting stitch patterns. Learn five new knitting stitch patterns and make a sample square of each pattern.  Examples of stitch patterns would be Wickerwork pattern; Grain of Wheat pattern; Rick-rack Rib; Tulip pattern; Basket stitch, and many more!  Attach each square to a piece of card and label each pattern.');
INSERT INTO badge_optional_requirements VALUES(120,11,12,'Learn how to knit cable patterns.  Knit a tension-square with a cable pattern in it. Attach your square to a piece of card and label the pattern.  Research the history of Aran/Fishermen’s Sweaters.   Find the meanings of three of the stitch patterns used in them. Wikipedia’s Aran Sweater page  (http://en.wikipedia.org/wiki/Aran_sweater) is a good place to start.');
INSERT INTO badge_optional_requirements VALUES(121,11,13,'Learn about the development of Knitters Gilds.  Why were these necessary and how did they help to preserve the art of knitting?  Are Gilds/Guilds still in existence today?');
INSERT INTO badge_optional_requirements VALUES(122,11,14,'Knit an item of clothing for yourself such as: a cardigan, shrug, vest, sweater, shawl, cowl, or capelet.  If you did this for the Knitting Badge, you must make a different item for this badge.');
INSERT INTO badge_optional_requirements VALUES(123,11,15,'Knit a layette for a baby.  This should include a hat, booties, and/or cardigan/matinee jacket.');
INSERT INTO badge_optional_requirements VALUES(124,11,16,'Research the history of knitted lace.  Learn how to knit one lace pattern.  You may either knit a length of lace and stitch it to a garment or pillow or knit a lace pattern scarf.');
INSERT INTO badge_optional_requirements VALUES(125,11,17,'Learn how to knit socks.  Learn which types of yarn are most suitable.  Find a simple pattern and knit a pair of socks.');
INSERT INTO badge_optional_requirements VALUES(126,11,18,'Learn what Entrelac knitting is and knit an item using this method.');
INSERT INTO badge_optional_requirements VALUES(127,11,19,'Learn to knit “in the round”.  Round knitting is popular for hats.  Knit an item made in the round.');
INSERT INTO badge_optional_requirements VALUES(128,11,20,'Learn about knitting from another culture.  Fair Isle, Norwegian, Faroe, Flemish, Tyrolean, Eriskay, Bolivian, Icelandic, Yugoslavian knitting are different examples.  Learn the special techniques particular to the culture you are studying and knit a piece in that style.  You may repeat this requirement for each different style of knitting studied.');
INSERT INTO badge_optional_requirements VALUES(129,12,3,'What are the different ways to store pictures both digitally and in print? What digital formats can they be saved in and when would you choose to use each one? How do you download them? For printed pictures, what can you print them on? Answer these questions by writing a short “instruction manual”.');
INSERT INTO badge_optional_requirements VALUES(130,12,4,'Take a series of group photos with your family, friends, club, or troop. Make a list of the steps needed to take an effective group picture. Choose several backgrounds and props. Once the pictures are completed in either digital or printed format compare them and write a short explanation on why you chose each background and what you hoped it would accomplish. Explain why it did or didn’t work.');
INSERT INTO badge_optional_requirements VALUES(131,12,5,'Make a stop action animation video using photographs.');
INSERT INTO badge_optional_requirements VALUES(132,12,6,'Prepare an exhibit and display your photography with permission in a local nursing home, group home, library, or other public location for at least one week. Include a short bio of yourself and who your inspiration is. Plan a time to be present to answer questions.');
INSERT INTO badge_optional_requirements VALUES(133,12,7,'Volunteer to take photos at a community event or function.');
INSERT INTO badge_optional_requirements VALUES(134,12,8,'Find the instruction manual for the camera you are using. Explore all the different settings available and either: make a collage using each setting, write a brief report or make a chart comparing them.');
INSERT INTO badge_optional_requirements VALUES(135,12,9,'Attend a class on photography, (minimum of 2 hours). Take notes. Share what you learned.');
INSERT INTO badge_optional_requirements VALUES(136,12,10,'Experiment with the following: Sepia, Black and White, Color. Make a presentation using a combination of 2 or 3 of these with the same photo or same subject.');
INSERT INTO badge_optional_requirements VALUES(137,12,11,'Choose a photography career and write a report on it. What types of pictures do they focus on? What is the typical salary range? Collect samples from your career choice and/or interview someone in that field.');
INSERT INTO badge_optional_requirements VALUES(138,12,12,'Visit a museum or art gallery and view a photography exhibit. Choose your favorite and learn about the artist and their work.  Describe the elements used that make their work appealing to you.  Try to imitate the artist’s work in a photograph you take. Show a family member or friend.');
INSERT INTO badge_optional_requirements VALUES(139,12,13,'Research different types of cameras. Make a chart comparing them.');
INSERT INTO badge_optional_requirements VALUES(140,12,14,'Take several landscape or cityscape pictures of your favorite places during different times of the day. Make a picture postcard and mail it off to a friend or family member. If possible, you can take under water pictures for a seascape.');
INSERT INTO badge_optional_requirements VALUES(141,13,3,'Save up and pay for any parts of your quilt that your family doesn’t already own.');
INSERT INTO badge_optional_requirements VALUES(142,13,4,'Include in your quilt at least one square that has hand appliqués.');
INSERT INTO badge_optional_requirements VALUES(143,13,5,'Include in your quilt at least two squares that have machine appliqués.');
INSERT INTO badge_optional_requirements VALUES(144,13,6,'Include in your quilt at least one square that has hand embroidery.');
INSERT INTO badge_optional_requirements VALUES(145,13,7,'Include in your quilt at least two squares that have machine embroidery.');
INSERT INTO badge_optional_requirements VALUES(146,13,8,'Include in your quilt at least one square that has fabric paint or dye.');
INSERT INTO badge_optional_requirements VALUES(147,13,9,'Include in your quilt at least six squares with two geometric shapes per square.');
INSERT INTO badge_optional_requirements VALUES(148,13,10,'Include in your quilt at least two squares with non-geometric shapes.');
INSERT INTO badge_optional_requirements VALUES(149,13,11,'Give a quilt you make as a gift or donate it to a charity.');
INSERT INTO badge_optional_requirements VALUES(150,13,12,'Keep a journal while completing a quilt. Record lessons you’ve learned, both practical and in character development.');
INSERT INTO badge_optional_requirements VALUES(151,13,13,'Take photos of your quilt and use them to decorate some stationery, bookmarks, or business cards.');
INSERT INTO badge_optional_requirements VALUES(152,13,14,'Complete projects using two of the three methods of quilting: hand quilting, machine quilting, and tying.');
INSERT INTO badge_optional_requirements VALUES(153,13,15,'Tour a quilting workshop and watch a professional use a large industrial sewing machine to quilt.');
INSERT INTO badge_optional_requirements VALUES(154,14,3,'Demonstrate your ability to convert metric measurements to inches & yards and vice versa.');
INSERT INTO badge_optional_requirements VALUES(155,14,4,'Use a sewing machine or serger to sew items as part of a community service project such as making burp cloths for new mothers.');
INSERT INTO badge_optional_requirements VALUES(156,14,5,'Learn and demonstrate at least three seam finishes (e.g., French seam, serging, pinking).');
INSERT INTO badge_optional_requirements VALUES(157,14,6,'Sew another garment for yourself.');
INSERT INTO badge_optional_requirements VALUES(158,14,7,'Learn and demonstrate how to sew zippers, buttonholes, and darts.');
INSERT INTO badge_optional_requirements VALUES(159,14,8,'Learn to alter or tailor a garment for better fit, such as hemming, taking in seams, or adding darts.');
INSERT INTO badge_optional_requirements VALUES(160,14,9,'Learn to sew on at least four different types of fasteners such as buttons (with either a loop or a buttonhole), a hook and eye, a snap, a frog, velcro, D rings, toggles or ties.');
INSERT INTO badge_optional_requirements VALUES(161,14,10,'Measure for and make any home décor item including curtains, pillows, table runners, etc.');
INSERT INTO badge_optional_requirements VALUES(162,14,11,'Learn the difference between woven and knit fabrics and how they affect sewing.');
INSERT INTO badge_optional_requirements VALUES(163,14,12,'Learn to use a serger and use it to make at least 3 different items.  These can be for home decor, apparel, baby items, accessories, etc.');
INSERT INTO badge_optional_requirements VALUES(164,14,13,'Find a machine you can use to try out a variety of different stitches. Try at least five different stitches you have never used before.  Include at least one decorative stitch and use it in a sewing project.');
INSERT INTO badge_optional_requirements VALUES(165,14,14,'Find out when companies started printing the types of patterns we buy in stores today.');
INSERT INTO badge_optional_requirements VALUES(166,14,15,'Learn three advanced sewing techniques such as trapunto, appliqué, pleating, or using piping in a seam.');
INSERT INTO badge_optional_requirements VALUES(167,14,16,'Sew a garment with a thin fabric overlay (lace, tulle, organza) for part of the pattern.');
INSERT INTO badge_optional_requirements VALUES(168,14,17,'Make a type of home décor item that you’ve never made before. Explain to your parent or leader how you would go about making a home décor item that just had a written plan rather than pattern pieces to cut out.');
INSERT INTO badge_optional_requirements VALUES(169,14,18,'Earn either the Embroidery badge your current level.');
INSERT INTO badge_optional_requirements VALUES(170,14,19,'Earn the Patchwork Badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(171,14,20,'Earn either the Textiles, or Quilting Badge at your level.');
INSERT INTO badge_optional_requirements VALUES(172,14,21,'Design and sew an original item that includes at least two advanced techniques (e.g., pleating, lining, invisible zipper).');
INSERT INTO badge_optional_requirements VALUES(173,14,22,'Earn the Garment Repair Badge at your current level .');
INSERT INTO badge_optional_requirements VALUES(174,14,23,'Create a sewing journal or portfolio documenting your completed projects and techniques used.');
INSERT INTO badge_optional_requirements VALUES(175,14,24,'Watch a professional tailor or seamstress work, and interview them about their job.');
INSERT INTO badge_optional_requirements VALUES(176,14,25,'Learn and use pattern grading to adjust sizes on a commercial pattern.');
INSERT INTO badge_optional_requirements VALUES(177,14,26,'Complete a project using quilting, smocking, or embroidery as a decorative technique.');
INSERT INTO badge_optional_requirements VALUES(178,14,27,'Learn to use digital tools for sewing such as design software or embroidery machines.');
INSERT INTO badge_optional_requirements VALUES(179,14,28,'Learn how to read and adjust sewing machine tension and troubleshoot common machine issues.');
INSERT INTO badge_optional_requirements VALUES(180,14,29,'Practice eco-friendly sewing by repurposing old clothes or using fabric scraps creatively.');
INSERT INTO badge_optional_requirements VALUES(181,15,3,'Visit an aerospace museum or exhibit.');
INSERT INTO badge_optional_requirements VALUES(182,15,4,'Read a biography of someone involved in aerospace such as an astronaut or aerospace engineer.');
INSERT INTO badge_optional_requirements VALUES(183,15,5,'Watch a documentary regarding aerospace.');
INSERT INTO badge_optional_requirements VALUES(184,15,6,'Find at least 5 everyday products we use today that were invented as part of the aerospace movement.');
INSERT INTO badge_optional_requirements VALUES(185,15,7,'Learn about careers in aerospace such as aerospace engineering, astronauts, or research and development. What education would you need for one of these jobs? What could you expect to be paid? Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(186,15,8,'Make a poster or booklet showing the variety of different aerospace aircraft and what each is used for.');
INSERT INTO badge_optional_requirements VALUES(187,15,9,'Design your own aerospace aircraft. What important components will your craft need to survive passage through the atmosphere?');
INSERT INTO badge_optional_requirements VALUES(188,15,10,'Learn about the different ways the US government supports our national aerospace industries?');
INSERT INTO badge_optional_requirements VALUES(189,15,11,'Read a book or magazine about aerospace.');
INSERT INTO badge_optional_requirements VALUES(190,15,12,'Learn about how travel through space affects the human body (radiation, weight loss, disorientation, etc.) and your mental capabilities (stress, homesickness, small confined spaces, etc.) What special food and equipment is necessary to make sure astronauts stay healthy both physically and emotionally in space? Third Party Resources: Aerospace Guide’s Space for Kids: http://www.aerospaceguide.net/space_kids.html NASA: nasa.gov');
INSERT INTO badge_optional_requirements VALUES(191,16,3,'Go on a field trip to a local observatory, planetarium, or space center.');
INSERT INTO badge_optional_requirements VALUES(192,16,4,'Make a craft or art project about alien life.');
INSERT INTO badge_optional_requirements VALUES(193,16,5,'Watch a movie or read a book about alien life.');
INSERT INTO badge_optional_requirements VALUES(194,16,6,'Learn about the Search for Extraterrestrial Intelligence (SETI), and the tools they use.');
INSERT INTO badge_optional_requirements VALUES(195,16,7,'Learn about the theory of panspermia, and what role extremophiles would play.');
INSERT INTO badge_optional_requirements VALUES(196,16,8,'Analyze literary works, films, or artworks featuring extraterrestrial beings and discuss the portrayal of aliens.');
INSERT INTO badge_optional_requirements VALUES(197,16,9,'Explore hypothetical scenarios and ethical dilemmas related to communication and interaction with alien species.');
INSERT INTO badge_optional_requirements VALUES(198,16,10,'Explore the major milestones in astronomy and space exploration throughout history, and how these advancements have shaped our understanding of the universe and the search for extraterrestrial life.');
INSERT INTO badge_optional_requirements VALUES(199,16,11,'Discuss current technological limitations and potential future advancements in space travel.');
INSERT INTO badge_optional_requirements VALUES(200,16,12,'Research and analyze notable historical UFO sightings and encounters, such as the Roswell incident, and discuss potential explanations for these phenomena.');
INSERT INTO badge_optional_requirements VALUES(201,16,13,'Learn about the Kardashev Scale and its classification of civilizations based on energy usage. Discuss the implications.');
INSERT INTO badge_optional_requirements VALUES(202,16,14,'Explore current and planned space exploration missions, such as the James Webb Space Telescope and Mars exploration.');
INSERT INTO badge_optional_requirements VALUES(203,16,15,'Discuss the factors that contribute to habitability of exoplanets.');
INSERT INTO badge_optional_requirements VALUES(204,16,16,'Explore different possible methods of interstellar communications.');
INSERT INTO badge_optional_requirements VALUES(205,16,17,'Learn about the Great Filter. Discuss whether you believe the Great Filter is behind or in front of us.');
INSERT INTO badge_optional_requirements VALUES(206,16,18,'Discuss spectroscopy and its application in analyzing exoplanet atmospheres, including biosignatures.');
INSERT INTO badge_optional_requirements VALUES(207,16,19,'Learn about stellar evolution, and what effect it might have on the planets nearby.');
INSERT INTO badge_optional_requirements VALUES(208,17,3,'Alpacas are known to “spit” at people. Find out why.');
INSERT INTO badge_optional_requirements VALUES(209,17,4,'Alpacas and llamas are frequently confused. Find out how to tell the difference between these two animals. How many types of alpaca are there?  How many natural colors do they come in?');
INSERT INTO badge_optional_requirements VALUES(210,17,5,'What are the most common predators of alpacas and how can you best protect them?');
INSERT INTO badge_optional_requirements VALUES(211,17,6,'Attend an alpaca show or shearing demonstration.');
INSERT INTO badge_optional_requirements VALUES(212,17,7,'How can owning alpacas be turned into a profitable business?  What type of income can you expect per animal?');
INSERT INTO badge_optional_requirements VALUES(213,17,8,'Volunteer to help at an alpaca farm for at least 4 hours.');
INSERT INTO badge_optional_requirements VALUES(214,17,9,'Interview someone who owns a profitable alpaca farm.  Find out what they recommend for someone who wishes to get started in the alpaca business.');
INSERT INTO badge_optional_requirements VALUES(215,17,10,'There are numerous business strategy options when deciding to breed alpacas. Find out the benefits and drawbacks of each of these strategies: Purchasing one or more females (bred or open) and one male (a breeding pair) is a common strategy for beginning alpaca owners. Purchasing one or more females (bred or open) and obtaining the services of outside herd sires is another common strategy. The purchase of a premier herd sire to generate income from breeding commissions is another approach. Others start out purchasing pet quality animals to “get their feet wet” in alpaca husbandry before deciding to turn their hobby into a business.');
INSERT INTO badge_optional_requirements VALUES(216,18,3,'Listen to and learn the Air Force Song (otherwise known as The Wild Blue Yonder)');
INSERT INTO badge_optional_requirements VALUES(217,18,4,'Visit an Air and Space or Aircraft museum. Identify those crafts that have been used by the Air Force.');
INSERT INTO badge_optional_requirements VALUES(218,18,5,'Tour an Air Force base and find out what jobs they do there.');
INSERT INTO badge_optional_requirements VALUES(219,18,6,'Attend and Air Force show or a local Air Force Days.');
INSERT INTO badge_optional_requirements VALUES(220,18,7,'Tour and Air Force Museum');
INSERT INTO badge_optional_requirements VALUES(221,18,8,'Interview a member of the Air Force. What is their role? What has their experience been like? What is the best and worst part of their job? Where have they traveled?');
INSERT INTO badge_optional_requirements VALUES(222,18,9,'Make a map of the 10 Air Force bases nearest you. Which is the closest? What is their mission? What groups are stationed there?');
INSERT INTO badge_optional_requirements VALUES(223,18,10,'Participate in a community service project for the Air Force. For example, you could send cards or care packages to Air Force members overseas; do yardwork or babysitting for an Air Force family with a member serving away from home; serve dinner at your local VFW post and listen to stories from veteran Air Force men and women; volunteer at your local veteran cemetery such as placing flags or wreaths on the graves for memorial day; etc.');
INSERT INTO badge_optional_requirements VALUES(224,18,11,'Learn how to read a 24 hour clock as well as use the military phonetic alphabet. Practice translating time from a 12 hour clock to 24 hour and back again. Translate license plates using the phonetic alphabet.');
INSERT INTO badge_optional_requirements VALUES(225,18,12,'Attend an Air Force ceremony or event such as a Tattoo, Change of Command Ceremony, Plane Dedication, Parade, or performance of the Air Force Honor Guard.');
INSERT INTO badge_optional_requirements VALUES(226,18,13,'Who were the Tuskeegee Airmen and why were they such an important part of American History and the Air Force?');
INSERT INTO badge_optional_requirements VALUES(227,19,3,'Write an essay about the history of airplanes. How did the invention of the airplane affect world events?');
INSERT INTO badge_optional_requirements VALUES(228,19,4,'Learn about a famous man or woman connected with aviation history, such as Jacqueline Cochran or Amelia Earhart.');
INSERT INTO badge_optional_requirements VALUES(229,19,5,'Pick a famous airplane, such as the U-2, the SR 71 Blackbird, or the Sopwith Camel, and learn its history. When was it first produced, and how many of them were made? Is this aircraft still in use?');
INSERT INTO badge_optional_requirements VALUES(230,19,6,'Research careers in the aviation business, such as designers, mechanics, ground crew, pilots, stewardesses, air traffic control personnel, etc. Levels 3-5 only: If possible, shadow someone for a day who works in the aviation business. What education do you need to be a part of this career? What might your salary be?');
INSERT INTO badge_optional_requirements VALUES(231,19,7,'Learn about the job of being a test pilot for new planes. Read about a famous test pilot, such as Chuck Yeager. Tell your family, friends, club, or troop what you learned.');
INSERT INTO badge_optional_requirements VALUES(232,19,8,'Choose a time period, such as World War I, and learn about the airplanes that were in use during it. Preschool must be able to identify one airplane from your chosen time period; Level 1 and 2, three; Level 3 and 4, five; and Level 5, six.');
INSERT INTO badge_optional_requirements VALUES(233,19,9,'Read a biography of a famous flying ace from wartime, such as Jimmy Doolittle, Butch O’Hare, or Eddie Rickenbacker. Tell your family, friends, club, or troop what you learned. If you earned this requirement at a previous level you must read about a new person.');
INSERT INTO badge_optional_requirements VALUES(234,19,10,'Learn about the different forms of safety equipment that are in use for pilots in the Air Force, such as ejector seats and parachutes. Tell your family, friends, club, or troop what you learned.');
INSERT INTO badge_optional_requirements VALUES(235,19,11,'Make a list of jobs that airplanes do, such as helping to fight wildfires, carrying troops, transporting tourists, etc.');
INSERT INTO badge_optional_requirements VALUES(236,19,12,'Watch a documentary or a movie about airplanes, such as an episode of Wings. Tell your family, friends, club, or troop about it.');
INSERT INTO badge_optional_requirements VALUES(237,19,13,'Learn about the history of the Presidential plane, Air Force One. (National Geographic did a film all about Air Force One.) Tell your family, friends, club, or troop.');
INSERT INTO badge_optional_requirements VALUES(238,19,14,'Read an aviation fiction book, such as Linda Carlson’s Ocean Flight or one of the Biggles books.');
INSERT INTO badge_optional_requirements VALUES(239,19,15,'Look at a Cross-Sections book about airplanes. Be able to identify the parts of an airplane: find the pilot’s seat, the co-pilot’s seat (if the airplane you chose includes a co-pilot in its crew), wings, tail fin, ailerons, elevators, and instrument board.');
INSERT INTO badge_optional_requirements VALUES(240,19,16,'Visit an air show or a flight museum. Tell your family, friends, club, or troop about it or write a short story about your trip.');
INSERT INTO badge_optional_requirements VALUES(241,19,17,'Plan a pretend trip by airplane to another location. Use the internet (with your parent’s permission) to find the costs of tickets, the route the plane will take, etc. What documents (passports, visas etc) do you need? Do you need special vaccinations?');
INSERT INTO badge_optional_requirements VALUES(242,19,18,'Look at a map that includes airports and locate at least 5. Which is the nearest to your town? With your parent’s permission, go online to YouTube and look at the map that shows the busiest air traffic centers.');
INSERT INTO badge_optional_requirements VALUES(243,19,19,'Learn about early attempts to create a flying machine and why they did or didn’t work. Tell your family, friends, club, or troop what you learned.');
INSERT INTO badge_optional_requirements VALUES(244,19,20,'Find out how an aircraft carrier operates and how take-off and landing are different for a carrier-based aircraft versus a land-based airplane.');
INSERT INTO badge_optional_requirements VALUES(245,19,21,'Practice flying an airplane on a flight simulator for at least 15 minutes.');
INSERT INTO badge_optional_requirements VALUES(246,19,22,'Learn about the different instruments on an airplane’s instrument panel, such as altimeter, compass, artificial horizon, etc, and what they are used for. How do they help a pilot?');
INSERT INTO badge_optional_requirements VALUES(247,19,23,'Build a model airplane. Preschool – Level 2 may make a simple balsa-wood plane, but Levels 3 – 5 need to make a complex model from a plastic or wooden kit. Third Party Resources: Popular Mechanics’ 30 Most Important Airplanes of All Time: https://www.popularmechanics.com/flight/g2142/the-30-most-important-airplanes-of-all-time/ Wright Brothers Aeroplane Company’s History of the Airplane: http://www.wright-brothers.org/History_Wing/History_of_the_Airplane/History_of_the_Airplane_Intro/History_of_the_Airplane_Intro.htm Air and Space’s 10 Great Pilots: https://www.airspacemag.com/history-of-flight/10-great-pilots-4026745/?no-ist');
INSERT INTO badge_optional_requirements VALUES(248,20,3,'Study an amateur radio study guide and take a practice test.');
INSERT INTO badge_optional_requirements VALUES(249,20,4,'Earn the Physics badge.');
INSERT INTO badge_optional_requirements VALUES(250,20,5,'Research amateur radio clubs in your area and attend an event.');
INSERT INTO badge_optional_requirements VALUES(251,20,6,'Find a licensed ham radio operator in your area and interview them (visit a ham radio store, interview a family member or family friend, e-mail a club member, etc).');
INSERT INTO badge_optional_requirements VALUES(252,20,7,'Find a licensed ham radio operator and listen to conversations they have on air.');
INSERT INTO badge_optional_requirements VALUES(253,20,8,'Draw a chart of the electromagnetic spectrum covering 100 kilohertz (kHz) to 1000 megahertz (MHz). Label the MF, HF, VHF, UHF and microwave portions of the spectrum on your diagram.');
INSERT INTO badge_optional_requirements VALUES(254,20,9,'Become a member of ARRL.');
INSERT INTO badge_optional_requirements VALUES(255,20,10,'Become a member of YLRL.');
INSERT INTO badge_optional_requirements VALUES(256,20,11,'Research scholarships available for male or female amateur radio operators.');
INSERT INTO badge_optional_requirements VALUES(257,20,12,'Attend an amateur radio conference in your area.');
INSERT INTO badge_optional_requirements VALUES(258,20,13,'Complete an online course through ARRL.');
INSERT INTO badge_optional_requirements VALUES(259,20,14,'Learn your name in Morse Code.');
INSERT INTO badge_optional_requirements VALUES(260,20,15,'Learn and write the phonetic alphabet.');
INSERT INTO badge_optional_requirements VALUES(261,20,16,'Learn about the history of radio and compare how and why it was original used how and why it is used today.');
INSERT INTO badge_optional_requirements VALUES(262,20,17,'Earn a General Class License.');
INSERT INTO badge_optional_requirements VALUES(263,20,18,'Earn an Extra Class License.');
INSERT INTO badge_optional_requirements VALUES(264,20,19,'Earn a Technician Class License (License Number: ___________________). Third Party Resources: YLRL: http://www.ylrl.org/ ARRL: http://www.arrl.org AmateurRadio.com: http://www.amateurradio.com/ Hamstudy.org: https://hamstudy.org/ Rocky Mountain Ham Radio: https://www.rmham.org/ ARRL’s Amateur Radio Emergency Service® (ARES): http://www.arrl.org/ares eHam.net’s Ham Exams: http://www.eham.net/exams/');
INSERT INTO badge_optional_requirements VALUES(265,21,3,'Find out what Amelia did before she became a pilot.');
INSERT INTO badge_optional_requirements VALUES(266,21,4,'Find out what groups or associations she belonged to.');
INSERT INTO badge_optional_requirements VALUES(267,21,5,'Read a book about Amelia Earhart.');
INSERT INTO badge_optional_requirements VALUES(268,21,6,'Who was with her on her last flight? What was his job?');
INSERT INTO badge_optional_requirements VALUES(269,21,7,'How old was Amelia when she got her pilot’s license? What kind of training was involved? What are the regulations today for getting a pilot’s license?');
INSERT INTO badge_optional_requirements VALUES(270,21,8,'Visit an aircraft museum online or in person.');
INSERT INTO badge_optional_requirements VALUES(271,21,9,'Take a flight on an airplane. See if there is a Young Eagles chapter or a Civil Air Patrol in your area.');
INSERT INTO badge_optional_requirements VALUES(272,21,10,'What were the names of the planes Amelia flew in? What would you name your own plane? What kind of planes did she fly?');
INSERT INTO badge_optional_requirements VALUES(273,21,11,'Learn about the dynamics of flight: lift, drag, thrust, weight, roll, pitch, yaw. Learn which parts of the plane control each.');
INSERT INTO badge_optional_requirements VALUES(274,21,12,'What was the standard uniform of the day for pilots? Why were these clothes chosen?');
INSERT INTO badge_optional_requirements VALUES(275,21,13,'Learn to make 3 types of paper airplanes.');
INSERT INTO badge_optional_requirements VALUES(276,22,3,'Earn the U. S. Constitution badge at your level.');
INSERT INTO badge_optional_requirements VALUES(277,22,4,'Read the full versions of at least 3 documents from U. S. history. Tell your family, friends, club, or troop what you read and why each is important.');
INSERT INTO badge_optional_requirements VALUES(278,22,5,'Learn about 5 different treaties which America has signed with peoples of other nations, such as the American Indians. Read at least one treaty and decide whether or not each side has kept their side of the bargain.');
INSERT INTO badge_optional_requirements VALUES(279,22,6,'Visit Washington D.C. and look at the original copy of the Declaration of Independence.');
INSERT INTO badge_optional_requirements VALUES(280,22,7,'Read a biography of Woodrow Wilson. Be able to explain what his “brain-child,” the League of Nations, was and how it affected world history and politics.');
INSERT INTO badge_optional_requirements VALUES(281,22,8,'Read the United Nations charter and make a list of the aims set forth in it. Decide if the UN has lived up to and fulfilled these aims.');
INSERT INTO badge_optional_requirements VALUES(282,22,9,'Find and read the constitutions of at least three other countries and compare them with the U. S. Constitution.  How are they alike?  How are they different?');
INSERT INTO badge_optional_requirements VALUES(283,22,10,'Make a scrapbook page, poster or collage showing how the Constitution, or another American document, sets forth and explains how the United States government is constructed and works. Show it to your family, friends, club, or troop.');
INSERT INTO badge_optional_requirements VALUES(284,22,11,'Read about the Armistice that was signed to end WWI.  Decide whether the terms imposed on Germany were fair, and if not, why?');
INSERT INTO badge_optional_requirements VALUES(285,22,12,'Learn about the different ways in which documents have been made over the centuries.  Long ago, people paid scribes to write important documents.  Find out what sort of tools were used at different times in history; for instance, in ancient lands scribes would use clay or wax tablets and styluses to write with. Later, people used quill pens and ink; then the printing press was invented.');
INSERT INTO badge_optional_requirements VALUES(286,22,13,'Find out what sort of training is required to become a writer of legal documents and international treaties.  What sort of background do these people have?  What sort of pay and work hours?');
INSERT INTO badge_optional_requirements VALUES(287,23,3,'Visit an American Girl Doll Store (look online for a store nearest you) or, browse the catalog or look on their website at www.americangirl.com. Observe the clothing styles of each doll and it’s era. Observe the many different sports outfits and accessories that are offered. What are your favorites?');
INSERT INTO badge_optional_requirements VALUES(288,23,4,'Watch an American Girl movie (Example: Samantha: An American Girl Holiday, Felicity: An American Girl Adventure, Kit Kittredge: An American Girl, Molly: An American Girl on the Home Front, Chrissa Stands Strong). What lesson(s) did you learn from the story?');
INSERT INTO badge_optional_requirements VALUES(289,23,5,'Hold a party, and invite your friends to bring their American Girl Dolls and accessories (or similar size 18″ dolls). The party may include cupcakes, craft making, karaoke, an autograph book (to have friends sign theirs and their doll’s name).  You can take photos of guests with their dolls and create a scrapbook page for each attendee, or make favors for guests to take home. You will need to provide real food for the guests (finger food, pizza, health snacks, etc).  You may also make “pretend food” (with play dough or construction paper cutouts) for the dolls to “eat”.');
INSERT INTO badge_optional_requirements VALUES(290,23,6,'Put on an American Girl play. You can make up your own skit or play.  Or, there are American Girl Theater Kits available online (for instance, on Amazon) for you and your friends to perform. Titles such as “Hairum Scarum” a comedy, “Check Under The Bed”, “What a World” a musical, and there are also Theater Kits about the characters Felicity, Kit, Kirsten, Molly, Addy, and Samantha.');
INSERT INTO badge_optional_requirements VALUES(291,23,7,'Make a Frontier Girls Vest for your doll. (Print out the Vest Pattern at the end of this badge.  Red felt was used.)  Or, you can hand or machine sew an outfit, or crochet a scarf or hat for your American Girl Doll.  (You can use a Simplicity or a McCalls Pattern, search online for free patterns, or design your own).');
INSERT INTO badge_optional_requirements VALUES(292,23,8,'Create a piece of furniture, bedding, jewelry, or dishes for your doll.  Use your imagination!  You can also visit a Michael’s store or Barnes & Noble to see all the craft and activity sets that are available under the American Girl Doll brand.  Titles like: Doll Jewelry, Doll Crafts, Doll Purses, Doll School or Doll Tees.  You may purchase one or get ideas from these kits to imitate them at home.');
INSERT INTO badge_optional_requirements VALUES(293,23,9,'Create a house or a room for your doll.  You can use a large cardboard box or construct one from wood, or create an area in your closet or bedroom.  If cardboard or wood is used, you may paint, glue fabric, or use scrapbooking paper for the walls, add a window with curtains and add furniture and accessories.');
INSERT INTO badge_optional_requirements VALUES(294,23,10,'Try several hair styles on your doll.  You may create a hat, use a scarf, barrettes, clips, elastic bands, feathers,” bling” items, weave ribbon into braids, etc…. use your imagination!  (Some ideas include a sophisticated look, an everyday look, outdoor braids or ponytail, an elegant formal look…)');
INSERT INTO badge_optional_requirements VALUES(295,23,11,'Photograph your American Girl Doll collection and make an album.');
INSERT INTO badge_optional_requirements VALUES(296,23,12,'Read about the authors of the American Girl books on the American Girl website under “About Our Authors.”');
INSERT INTO badge_optional_requirements VALUES(297,23,13,'Find copies of the discontinued American Girl Magazine to read.');
INSERT INTO badge_optional_requirements VALUES(298,23,14,'Earn the Doll Badge.');
INSERT INTO badge_optional_requirements VALUES(299,23,15,'With the permission of a parent, view the “Fast Facts” found on the American Girl website under the “Our Company” category.  These “fast facts” cover interesting trivia such as how many American Girl books and how many dolls have been sold since the beginning, in 1986.  Also view the Frequently Asked Questions page to see how the company answers them.');
INSERT INTO badge_optional_requirements VALUES(300,23,16,'Help a younger Frontier Girl earn this badge, by assisting her in a few of the following:  Making clothes, furniture, jewelry for her doll, performing a skit or play, reading an American Girl book to her, looking at the website or catalog with them, helping put together a party, sharing your American Girl Doll or similar doll with her, etc.');
INSERT INTO badge_optional_requirements VALUES(301,23,17,'When was the first American Girl Doll made?  What is her name and from what Historical Era (Year) was she from? Has the American Girl Doll changed over the years? What clothes and extras did she come with?');
INSERT INTO badge_optional_requirements VALUES(302,23,18,'Go online to the American Girl website to explore the story and play their newest Girl of the Year games and activities. (You may need a parent’s permission.)');
INSERT INTO badge_optional_requirements VALUES(303,23,19,'Choose an American Girl and write a short essay on why she is your favorite. Which one of her books did you enjoy best? What do you love most about the time period she lives in? If you could go back to her time, what would you want to do? Third Party Resources American Girl: www.americangirl.com Quest Club Resources: Vest Pattern: https://questclubs.com/wp-content/uploads/2020/06/vest-pattern.pdf');
INSERT INTO badge_optional_requirements VALUES(304,24,3,'History & Flag: Make a timeline of the most important events in American History. How many different flags have flown over the land of the United States? Choose your favorite one and make a colored picture of it. Learn the terminology for the different parts of a flag.');
INSERT INTO badge_optional_requirements VALUES(305,24,4,'Geography: Learn where America is located on a globe. Look at a map of America and find: The major population centers, Washington D.C. and the Statue of Liberty. The major highways, railway lines and international airports. Major waterways used to transport goods (e.g. Mississippi river, Erie Canal). Also look at a physical map of America to find out the various different types of Terrain (mountains, prairies, forests, deserts). Land use (agriculture, industry) and where industrial raw materials (coal, iron, copper etc) are located.');
INSERT INTO badge_optional_requirements VALUES(306,24,5,'Art: Learn about famous American Artists. Which artist’s works do you like the best? Make your own painting, sculpture, etc in the same style, or color a reproduction of one of his/her pieces.');
INSERT INTO badge_optional_requirements VALUES(307,24,6,'Music: What sorts of music is America famous for? Listen to various types. Which do you like best? Why?');
INSERT INTO badge_optional_requirements VALUES(308,24,7,'Technology: What technological advances have been made by American inventors and designers? Learn about one of them.');
INSERT INTO badge_optional_requirements VALUES(309,24,8,'Fashion: Learn about the fashions from one of the following eras of American History: Colonial Period Revolutionary Period Nineteenth Century 1920s & 1930s 1940s & 1950s 1960s & 1970s This requirement may be repeated for different eras.');
INSERT INTO badge_optional_requirements VALUES(310,24,9,'Craft: Learn about handicrafts from the past that were popular in America (knitting, crochet, basket-weaving, whittling, stenciling, wood-working, etc). Are these crafts still done today? Find one that you like and learn how to do it. Show your family, friends, club, or troop what you have learned and made.');
INSERT INTO badge_optional_requirements VALUES(311,24,10,'Industry: Which industries has America been famous for? Learn about one of America’s industries. Is this industry still competitive on the world market?');
INSERT INTO badge_optional_requirements VALUES(312,24,11,'Games: Learn about some of the games and pastimes that Americans used to do and learn one of them. Play it with your family, friends, club, or troop.');
INSERT INTO badge_optional_requirements VALUES(313,24,12,'Biography: There have been many famous Americans! Learn about one famous American or group of Americans. You may study a film star, a politician, industrialist, soldier, etc. Find out what their impact was on America and its heritage. This requirement may be repeated for each famous American studied.');
INSERT INTO badge_optional_requirements VALUES(314,24,13,'Social Studies: America was known as a “melting pot.” What does this mean? How has ethnic diversity made America unique? Learn about one specific ethnic group: where they originated; where they settled; what impact they had on American culture and whether this ethnic group is still ethnically different today, or whether it melted into the American mix. This requirement may be repeated for different ethnic groups.');
INSERT INTO badge_optional_requirements VALUES(315,24,14,'Food: Making food was an important part of housekeeping in America’s past, as prepared foods were not readily available as they are today. Learn what a typical cook would have to make to feed their family in previous centuries. Find an old recipe and make the dish. This could be making your great-grandma’s from-scratch brownies, making jam, or making butter from cream!');
INSERT INTO badge_optional_requirements VALUES(316,24,15,'Dance: What different forms of dance is America famous for? Either watch a video, go to a live dance or learn the dance steps of a particular form of American dancing.');
INSERT INTO badge_optional_requirements VALUES(317,25,3,'Watch a documentary on the Revolutionary War.');
INSERT INTO badge_optional_requirements VALUES(318,25,4,'Visit a Revolutionary War re-enactment.');
INSERT INTO badge_optional_requirements VALUES(319,25,5,'Visit a location from an important event or battle that took place during the Revolutionary War.');
INSERT INTO badge_optional_requirements VALUES(320,25,6,'Learn about the uniforms worn on both sides during the war.  Make a tricorn hat, flag, or colonial-style clothing item to wear during a presentation or reenactment.');
INSERT INTO badge_optional_requirements VALUES(321,25,7,'Learn about the song “Yankee Doodle” and how it was used in the Revolutionary War. What other songs were there during the war?');
INSERT INTO badge_optional_requirements VALUES(322,25,8,'Learn about 3 important Americans. At least 1 should be a woman that played an important part in the Revolutionary War. Examples might include: George Washington Benjamin Franklin Paul Revere Henry Knox Thomas Paine Thomas Jefferson Baron Friedrich von Steuben Patrick Ferguson Abigail Adams Esther Reed Martha Washington Deborah Sampson Sybil Ludington Martha Bratton Prudence Wright Emily Geiger');
INSERT INTO badge_optional_requirements VALUES(323,25,9,'Study how music, fife and drum corps, or revolutionary songs were used for communication and morale.  Learn at least one song from that era.');
INSERT INTO badge_optional_requirements VALUES(324,25,10,'Study how messages were sent during the war (Paul Revere’s ride, lanterns, secret codes). Try creating your own code.');
INSERT INTO badge_optional_requirements VALUES(325,25,11,'What diseases were common among the soldiers and why?');
INSERT INTO badge_optional_requirements VALUES(326,25,12,'Who were the American soldiers? What were some of the things they had to overcome?');
INSERT INTO badge_optional_requirements VALUES(327,25,13,'What was winter camp life like for the American soldiers?');
INSERT INTO badge_optional_requirements VALUES(328,25,14,'Learn what “buck and ball” was and how it was used during the American Revolution. Create a simple diagram or model to show how it differed from regular musket ammunition.');
INSERT INTO badge_optional_requirements VALUES(329,25,15,'Learn about Bushnell’s Turtle.');
INSERT INTO badge_optional_requirements VALUES(330,25,16,'Take part in a Independence Day celebration.');
INSERT INTO badge_optional_requirements VALUES(331,25,17,'Learn about the Boston Massacre.');
INSERT INTO badge_optional_requirements VALUES(332,25,18,'What other peoples got involved? What side were they on?');
INSERT INTO badge_optional_requirements VALUES(333,25,19,'What are the Federalist Papers?  Read a summary and discuss how what they support differ from the Articles of Confederation. Third Party Resources: Historical Flags of Our Ancestors’ Flags of the Revolutionary War: http://www.loeser.us/flags/revolution.html');
INSERT INTO badge_optional_requirements VALUES(334,26,3,'Made homemade bread.');
INSERT INTO badge_optional_requirements VALUES(335,26,4,'Visit an Amish town such as Shipshewana, Indiana.  Remember do not take pictures as it is against their faith.');
INSERT INTO badge_optional_requirements VALUES(336,26,5,'Interview an Amish community member to understand their beliefs and values.');
INSERT INTO badge_optional_requirements VALUES(337,26,6,'Create an Amish outfit using traditional patterns.');
INSERT INTO badge_optional_requirements VALUES(338,26,7,'Craft a simple Amish-style quilt or woodworking project.');
INSERT INTO badge_optional_requirements VALUES(339,26,8,'Prepare a traditional Amish recipe.');
INSERT INTO badge_optional_requirements VALUES(340,26,9,'Experience a traditional horse and buggy ride.');
INSERT INTO badge_optional_requirements VALUES(341,26,10,'Craft an Amish-style doll using traditional materials.');
INSERT INTO badge_optional_requirements VALUES(342,26,11,'Learn a traditional Amish game such as croquet, horseshoes or Dutch Blitz.');
INSERT INTO badge_optional_requirements VALUES(343,26,12,'Create a miniture model of a simple Amish barn design.');
INSERT INTO badge_optional_requirements VALUES(344,26,13,'Learn about Amish wedding tradtions.');
INSERT INTO badge_optional_requirements VALUES(345,26,14,'What is the Ordnung?  What is its goal?');
INSERT INTO badge_optional_requirements VALUES(346,26,15,'Explore traditional Amish remedies and healthcare practices.');
INSERT INTO badge_optional_requirements VALUES(347,26,16,'. Research the rumspringa tradition in the Amish culture');
INSERT INTO badge_optional_requirements VALUES(348,26,17,'Volunteer in a community service project within an Amish community.');
INSERT INTO badge_optional_requirements VALUES(349,26,18,'Visit an Amish market.');
INSERT INTO badge_optional_requirements VALUES(350,26,19,'Learn about how the Amish enjoy music?  Why don’t they play musical instruments?');
INSERT INTO badge_optional_requirements VALUES(351,26,20,'Read a book or short story written by an Amish author.');
INSERT INTO badge_optional_requirements VALUES(352,26,21,'Research the Amish education system and compare it to mainstream education.');
INSERT INTO badge_optional_requirements VALUES(353,26,22,'Learn a few basic phrases in Pennsylvania German (Pennsylvania Dutch), the language spoken by the Amish.');
INSERT INTO badge_optional_requirements VALUES(354,26,23,'Discuss the importance of family in the Amish community.  Who is the head of the household?  How many children do families usually have?  How many families usually make up each Amish community?');
INSERT INTO badge_optional_requirements VALUES(355,26,24,'Start your own vegetable garden or help raise an animal for meat.');
INSERT INTO badge_optional_requirements VALUES(356,26,25,'Visit a local farm or petting zoo to see animals like the ones the Amish care for. Talk about the importance of animals on an Amish farm.');
INSERT INTO badge_optional_requirements VALUES(357,27,3,'Visit a zoo, pet shop, or other place where you can see your category of animal being fed and cared for. Level 2: Also interview the caretakers and find out what they like/dislike about their job. Level 3: Do Level 2 of this requirement and also find out what type of education or special training is necessary to work in this position. Level 4 & Level 5: Do requirement 11.');
INSERT INTO badge_optional_requirements VALUES(358,27,4,'Make something to attract, protect, or observe your category of animal.');
INSERT INTO badge_optional_requirements VALUES(359,27,5,'Make a chart, poster, booklet, or other exhibit to teach others what you have learned while earning this badge.');
INSERT INTO badge_optional_requirements VALUES(360,27,6,'Make a list of animals from your category that might make good pets.  What special equipment would you need to take care of them?  What types of foods do they eat?  Is this a pet that you would like to have?  Why or why not?');
INSERT INTO badge_optional_requirements VALUES(361,27,7,'Design and carry out a service project that will benefit your animal group.  This may be planting trees or flowers for birds or insects, raising money for organizations that protect endangered species, gathering a volunteer crew to help out at a local animal shelter, etc.');
INSERT INTO badge_optional_requirements VALUES(362,27,8,'Research any state and federal laws that protect your animal category.  What animals in your category are on the endangered species list?  What specific protection do they receive?  How would the extinction of this animal affect mankind?  (If you researched this group at an earlier level, make sure all your data is up to date.)');
INSERT INTO badge_optional_requirements VALUES(363,27,9,'What local or national organizations are there that study or protect animals in your category?  What do they do?  Make a poster showing how you can help to protect an animal from your category. Level 4 & Level 5: Volunteer at least 4 hours to working with one of these organizations.');
INSERT INTO badge_optional_requirements VALUES(364,27,10,'If your animal category is present naturally in your local community, find out which animals are beneficial to humans, which are nuisances, and which are harmful.  Explain how people interact with each of these animals.');
INSERT INTO badge_optional_requirements VALUES(365,27,11,'Level 4 & Level 5 Only: Shadow an animal caretaker for a day at a zoo, pet shop, or other place where you can see your category of animal being fed and cared for.  What careers are there in working with these types of animals?  What education or special training would you need?');
INSERT INTO badge_optional_requirements VALUES(366,28,3,'Learn the history of when and where amusement parks started.');
INSERT INTO badge_optional_requirements VALUES(367,28,4,'If your park has characters or mascots, know who they are.  If there are more than 10, know at least 10 of them.  Take a picture with one or more if possible. Why do these characters represent of the park?');
INSERT INTO badge_optional_requirements VALUES(368,28,5,'Go on at least 5 different types of rides such as roller coasters, water rides, spinners,  dark rides, height rides or carousels for example at your park.');
INSERT INTO badge_optional_requirements VALUES(369,28,6,'If your park has a train or monorail system, what type is it? Steam?  Electric?  Know the history behind the train at your park and take a ride on it.');
INSERT INTO badge_optional_requirements VALUES(370,28,7,'See a show or some sort of live entertainment at your park.');
INSERT INTO badge_optional_requirements VALUES(371,28,8,'Play a carnival game, pan for crystals or gem stones, participate in a show, or do another non ride activity');
INSERT INTO badge_optional_requirements VALUES(372,28,9,'Try a specialty food or drink item of that park.');
INSERT INTO badge_optional_requirements VALUES(373,28,10,'Understand height restrictions and how they effect your safety.  On each ride you go on, understand the safety harnesses and how they are designed to keep you safe.');
INSERT INTO badge_optional_requirements VALUES(374,28,11,'Find out if your park participates in badge, patch, or pin trading.  If so, bring some to swap with someone.');
INSERT INTO badge_optional_requirements VALUES(375,28,12,'If your park is divided into themed areas, learn what each one is and what the special attractions for each area are.');
INSERT INTO badge_optional_requirements VALUES(376,28,13,'Find out how much it costs to enter the park.  Is the park a pay one price to enter admission or is it free admission that uses tickets to pay per ride?  Are discounts available for groups? Season passes? Coupons or promotions?');
INSERT INTO badge_optional_requirements VALUES(377,28,14,'Watch a documentary about your park.');
INSERT INTO badge_optional_requirements VALUES(378,28,15,'Design a ride for your park.  Be able to explain why this ride fits the atmosphere of the park, what ages it is for, and how you would restrain people in the ride to keep them safe.  Draw a picture or make a 3D model of your ride.');
INSERT INTO badge_optional_requirements VALUES(379,28,16,'Take a behind the scene tour of part of your park.');
INSERT INTO badge_optional_requirements VALUES(380,28,17,'Participate in a service project that involves your park in some way.  This could be supporting a charity affiliated with it, volunteering to help take a group of younger kids or disabled kids to the park, raising money to buy tickets to the park for a local community group, etc.');
INSERT INTO badge_optional_requirements VALUES(381,28,18,'Using a smart phone or pedometer to track your steps around the park for the day.  Determine how far you walked, how many steps equal a mile, convert miles to kilometers, and calculate your average miles per hour.');
INSERT INTO badge_optional_requirements VALUES(382,29,3,'Read a book about your animal.');
INSERT INTO badge_optional_requirements VALUES(383,29,4,'Learn how your animal protects itself.');
INSERT INTO badge_optional_requirements VALUES(384,29,5,'Draw a picture or make a craft of your animal or take a picture of your animal.');
INSERT INTO badge_optional_requirements VALUES(385,29,6,'Learn the scientific classification and name of your animal.  Is it a reptile, amphibian, mammal, bird, fish, insect?  Is it a vertebrate?  An invertebrate?');
INSERT INTO badge_optional_requirements VALUES(386,29,7,'Create a habitat or feeder for your animal.');
INSERT INTO badge_optional_requirements VALUES(387,29,8,'Find out if people eat your animal. If so, find out how they cook or prepare it and try some, if possible.');
INSERT INTO badge_optional_requirements VALUES(388,29,9,'Visit somewhere you can see or interact with your animal');
INSERT INTO badge_optional_requirements VALUES(389,29,10,'Give a presentation about the animal or make a display about your animal.');
INSERT INTO badge_optional_requirements VALUES(390,29,11,'Learn how to safely interact with this animal   If you come across one in the wild, what should you do?');
INSERT INTO badge_optional_requirements VALUES(391,29,12,'Participate in a community service project that helps your animal in some way.  Examples might be to help plant trees, raise awareness for endangered species, or raise money for an animal foundation.');
INSERT INTO badge_optional_requirements VALUES(392,29,13,'What careers are there that deals with this animal?  Research one.  What education is needed?  Where would you have to live?  What hours might you work?  How much might you be paid?');
INSERT INTO badge_optional_requirements VALUES(393,29,14,'If your animal can be kept as a pet, learn about how you could care for it. What would you feed it? If your animal cannot be kept as a pet, learn about how it takes care of itself in the wild. What does it eat? How does it find its food?');
INSERT INTO badge_optional_requirements VALUES(394,29,15,'Learn about special organizations that help injured wild animals and raise them back to health. How do they find such animals, and what do they do to help them?');
INSERT INTO badge_optional_requirements VALUES(395,30,3,'Visit a zoo that has animals from around the world. If you can’t visit one in person, visit one online with the permission of your parents.');
INSERT INTO badge_optional_requirements VALUES(396,30,4,'Interact with an animal that is not an everyday house pet. For example, you could: Take a ride on an animal from another country such as a camel or an elephant Swim with dolphins Touch a boa constrictor Take a walk with a porcupine Hold a koala');
INSERT INTO badge_optional_requirements VALUES(397,30,5,'Participate in a service project that involves our world’s animals. Examples might include: Volunteer at a wildlife rescue Raise money to help save an endangered species Make flyers to educate people on and endangered species Help paint no dumping signs around drains to help save our fish and water wildlife Raise money to help a family in another country buy a goat, chicken, or rabbit');
INSERT INTO badge_optional_requirements VALUES(398,30,6,'Find at least 5 animals that are eaten in other parts of the world that are not eaten in the U.S. What are they? Where are they found? How are they prepared? If possible, try some.');
INSERT INTO badge_optional_requirements VALUES(399,30,7,'Find at least 5 animals from around the world that are used for their fur. If possible, visit a store or  exhibit where you can touch and compare furs from around the world.');
INSERT INTO badge_optional_requirements VALUES(400,30,8,'Create a map of where endangered species can be found. Include at least 20 different animals. Why are they endangered?');
INSERT INTO badge_optional_requirements VALUES(401,30,9,'Play a game that involves animals around the world such as Zoo Tycoon 2 or Zooreaka!');
INSERT INTO badge_optional_requirements VALUES(402,30,10,'Learn about careers regarding animals around the world. Examples might include a wildlife conservationist, photographer, veterinarian, or zookeeper, animal rescue worker, etc. What education and training do you need? What salary can you expect? What hours could you expect to work? Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(403,30,11,'With the permission of your parents watch a live action cam online that shows an animal from somewhere in the world. It might be trained on an eagle’s nest, a zoo exhibit, the African wildlife, etc. Watch the cam off and on for at least a week. Share what you saw.');
INSERT INTO badge_optional_requirements VALUES(404,30,12,'Learn about animal rights and how animals around the world are being harmed and abused by humans such as dolphins being trapped in fishing nets, circus animals being mistreated, overpopulation of dogs and cats, poaching rhinos for their horn, etc. Choose one specific form of abuse and find out what you can do to help stop it. What organizations are there that are trying help? How can people get involved?');
INSERT INTO badge_optional_requirements VALUES(405,31,3,'Read a book about animal migration.');
INSERT INTO badge_optional_requirements VALUES(406,31,4,'Watch a video that outlines the migration journey of one or several of your chosenanimals.');
INSERT INTO badge_optional_requirements VALUES(407,31,5,'Research some of the “most epic” animal migrations that take place each year (forexample, the longest non-stop bird flight). What are some of the records these animals hold?');
INSERT INTO badge_optional_requirements VALUES(408,31,6,'Choose one of your animals and map the path of their migration route.');
INSERT INTO badge_optional_requirements VALUES(409,31,7,'Learn about some of the impacts that humans have on animal migration. Are they goodor bad? Is there anything the general population can do to help migrating animals?');
INSERT INTO badge_optional_requirements VALUES(410,31,8,'Give a presentation or create a poster about the migration journey of one of your chosen animals.');
INSERT INTO badge_optional_requirements VALUES(411,31,9,'Scientists’ understanding of migration has changed significantly over time and they areconstantly learning new things about migrating animals. What are some of the early theories that werepresented about where migrating animals went before migration was understood better?');
INSERT INTO badge_optional_requirements VALUES(412,31,10,'Did humans of the past ever migrate like animals do today? What was their reason formigrating? Do humans migrate today? What are some reasons that humans might migrate now?');
INSERT INTO badge_optional_requirements VALUES(413,31,11,'Research some of the technology used by scientists to track animal migration. What typeof data do scientists record? How has this technology changed over time?');
INSERT INTO badge_optional_requirements VALUES(414,31,12,'Learn about any special organizations that help keep migrating animals safe. Whichanimals do they assist? How are they making an impact?');
INSERT INTO badge_optional_requirements VALUES(415,31,13,'Interview a local expert or visit a wildlife conservation center to learn about migration conservation efforts.');
INSERT INTO badge_optional_requirements VALUES(416,31,14,'Identify and describe some of the challenges or dangers faced by migrating animals.');
INSERT INTO badge_optional_requirements VALUES(417,31,15,'Observe and document the behavior of migratory birds or animals in your area during migration season.');
INSERT INTO badge_optional_requirements VALUES(418,31,16,'Take part in a citizen science project focused on tracking or monitoring migratory species.');
INSERT INTO badge_optional_requirements VALUES(419,31,17,'Learn about a career that involves animal migration such as a a wildlife photographer or a marine biologist.  What type of education do you need?  What type of pay could you expect?  What type of hours and travel might be expected?');
INSERT INTO badge_optional_requirements VALUES(420,31,18,'Create a field guide of local migratory species found in your area, including their habitats and behaviors.');
INSERT INTO badge_optional_requirements VALUES(421,31,19,'Learn to identify different bird calls and mimic at least three migratory bird songs.');
INSERT INTO badge_optional_requirements VALUES(422,31,20,'Participate in a community cleanup activity in a migratory bird nesting area or along a migratory route.');
INSERT INTO badge_optional_requirements VALUES(423,31,21,'Research and identify three plants that rely on migratory animals for pollination or seed dispersal.');
INSERT INTO badge_optional_requirements VALUES(424,31,22,'Design and construct a “migration obstacle course” with different challenges mimicking the hazards faced by migrating animals.');
INSERT INTO badge_optional_requirements VALUES(425,31,23,'Create a migration themed board game.');
INSERT INTO badge_optional_requirements VALUES(426,31,24,'Create migratory animal-themed crafts, such as origami birds or butterfly mobiles.');
INSERT INTO badge_optional_requirements VALUES(427,32,3,'Volunteer at a local animal shelter.');
INSERT INTO badge_optional_requirements VALUES(428,32,4,'Attend a pet adoption event and find out about the adoption process.');
INSERT INTO badge_optional_requirements VALUES(429,32,5,'Research the different types of animal abuse and neglect, including signs and prevention methods.');
INSERT INTO badge_optional_requirements VALUES(430,32,6,'Learn about the laws and regulations surrounding animal welfare and rescue in your area.');
INSERT INTO badge_optional_requirements VALUES(431,32,7,'Learn about different types of traps and their use in animal rescue.');
INSERT INTO badge_optional_requirements VALUES(432,32,8,'Participate in a community service project focused on pet rescue and welfare.');
INSERT INTO badge_optional_requirements VALUES(433,32,9,'Learn how to properly transport animals for rescue or adoption.');
INSERT INTO badge_optional_requirements VALUES(434,32,10,'Participate in a fundraiser for an animal shelter or rescue organization.');
INSERT INTO badge_optional_requirements VALUES(435,32,11,'Learn how to recognize and report animal cruelty to the proper authorities.');
INSERT INTO badge_optional_requirements VALUES(436,32,12,'Research the benefits of spaying and neutering pets, including reducing pet overpopulation and health benefits.');
INSERT INTO badge_optional_requirements VALUES(437,32,13,'Shadow a veterinarian or animal rescue worker for a day.');
INSERT INTO badge_optional_requirements VALUES(438,32,14,'Learn about the process of rehabilitating abused or neglected pets and how to provide them with proper care.');
INSERT INTO badge_optional_requirements VALUES(439,32,15,'Participate in a pet adoption drive and assist with promoting and advertising adoptable pets.');
INSERT INTO badge_optional_requirements VALUES(440,32,16,'Learn about the importance of microchipping pets and how it assists in their rescue and return.');
INSERT INTO badge_optional_requirements VALUES(441,32,17,'Volunteer to foster a pet in need of a temporary home.');
INSERT INTO badge_optional_requirements VALUES(442,32,18,'Research the impact of pet rescue on communities and society.');
INSERT INTO badge_optional_requirements VALUES(443,32,19,'Participate in a trap-neuter-release program for feral cats.');
INSERT INTO badge_optional_requirements VALUES(444,32,20,'Research the impact of animal rescue on the environment.');
INSERT INTO badge_optional_requirements VALUES(445,32,21,'Learn about the process of adopting a pet and how to properly care for them in your home.');
INSERT INTO badge_optional_requirements VALUES(446,32,22,'Participate in a pet obedience or training class to improve the adoptability of pets in shelters.');
INSERT INTO badge_optional_requirements VALUES(447,32,23,'Adopt a pet from a shelter or rescue organization and provide them with a loving forever home.');
INSERT INTO badge_optional_requirements VALUES(448,32,24,'Learn about different types of animal carriers and their use in rescue.');
INSERT INTO badge_optional_requirements VALUES(449,32,25,'Understand the importance of quarantine and isolation when dealing with sick animals.');
INSERT INTO badge_optional_requirements VALUES(450,33,3,'Recognize signs of nesting or denning sites and explain how they can be located through tracking.');
INSERT INTO badge_optional_requirements VALUES(451,33,4,'Animals can leave behind more than just their tracks. Learn how to recognize the different types of animal scat, and how animal fur and scat can be a part of seed dispersal.');
INSERT INTO badge_optional_requirements VALUES(452,33,5,'Make a weekend (or three day/night) long activity of taking a series of photographs of tracks to trace where animals are most prevalent.');
INSERT INTO badge_optional_requirements VALUES(453,33,6,'Research and discuss litter and the effect that it plays on domestic wildlife creatures.');
INSERT INTO badge_optional_requirements VALUES(454,33,7,'Read an age-appropriate book about animals (appropriate to your climate and habitat – such as woodland creatures etc.). Be able to recognize the tracks of the animals you read about.');
INSERT INTO badge_optional_requirements VALUES(455,33,8,'Visit a nature museum and study the taxidermy animals and discuss the prints they might make if they were to visit your yard.');
INSERT INTO badge_optional_requirements VALUES(456,33,9,'Study and explain how humans affect animal habitats and where/how animals travel.');
INSERT INTO badge_optional_requirements VALUES(457,33,10,'Sketch an animal track and compare it to illustrations in a photographic encyclopedia or online (from a reputable source).');
INSERT INTO badge_optional_requirements VALUES(458,33,11,'Watch an appropriate documentary, non-fiction film or short on animal habitats.');
INSERT INTO badge_optional_requirements VALUES(459,33,12,'Learn about careers that involve animal tracking. What education do you need for this occupation? What is the pay and work schedule you can expect? Level 3 and up only: If possible, shadow someone with this job for a day.');
INSERT INTO badge_optional_requirements VALUES(460,33,13,'Learn about the importance of animal tracking in Native American culture.');
INSERT INTO badge_optional_requirements VALUES(461,33,14,'Visit a national park (appropriate to your tracking environment) and learn what information they have to share on your local animal habitats. Share your new knowledge.');
INSERT INTO badge_optional_requirements VALUES(462,33,15,'Plan and participate in a 30-minute to one-hour observation session that includes using binoculars or night vision.');
INSERT INTO badge_optional_requirements VALUES(463,33,16,'Visit the library and research at least one animal of whose tracks you found. Learn about their habitat environment, food preferences, and a unique fact. Share this information or write a one-page minimum informational set of paragraphs.');
INSERT INTO badge_optional_requirements VALUES(464,33,17,'Go backyard camping and watch for animals, and then check for tracks after you have seen them leave a full 15-30 minutes before.');
INSERT INTO badge_optional_requirements VALUES(465,33,18,'Organize a service project to promote conservation of wildlife habitats.');
INSERT INTO badge_optional_requirements VALUES(466,33,19,'Take a photos of animal tracks and create an informational poster for identifying them.');
INSERT INTO badge_optional_requirements VALUES(467,33,20,'Explain how weather conditions can affect the visibility and preservation of tracks.');
INSERT INTO badge_optional_requirements VALUES(468,33,21,'Identify signs of animal territorial markings and explain their significance.');
INSERT INTO badge_optional_requirements VALUES(469,33,22,'Explain how tracking skills can be used in search and rescue operations.');
INSERT INTO badge_optional_requirements VALUES(470,33,23,'Participate in a wildlife conservation project and describe how tracking knowledge contributes to conservation efforts.');
INSERT INTO badge_optional_requirements VALUES(471,33,24,'Keep a tracking journal with sketches of all the tracks you see.');
INSERT INTO badge_optional_requirements VALUES(472,34,3,'Earn the Cartoons badge at your level.');
INSERT INTO badge_optional_requirements VALUES(473,34,4,'Learn about 3 different major animation studios such as Disney, Nickelodeon or Dreamworks.  Do they have a specific style that is recognizable?  Does the animation style differ depending on the demographics of the intended audience?');
INSERT INTO badge_optional_requirements VALUES(474,34,5,'Learn how to create a short stop-motion animation.');
INSERT INTO badge_optional_requirements VALUES(475,34,6,'Describe the role of sound in animation and how it enhances the viewing experience.  Make at least ten different sound effects using things other than your voice. Examples of sounds you might wish to try are a crackling fire; rain; popping bubbles; or footsteps. Use your imagination. Find out how some of these sounds are usually created in modern animation.');
INSERT INTO badge_optional_requirements VALUES(476,34,7,'Learn how to use digital animation software and create a short digital animation.');
INSERT INTO badge_optional_requirements VALUES(477,34,8,'Research and discuss impact of animation on popular culture.');
INSERT INTO badge_optional_requirements VALUES(478,34,9,'Learn about the different roles in an animation production team, such as animator, storyboard artist, and sound designer.  Choose one and find out what education is needed, what the expected salary is, and where you might find jobs in this industry.');
INSERT INTO badge_optional_requirements VALUES(479,34,10,'Learn about the technology behind computer-generated animation and how it has evolved over time.');
INSERT INTO badge_optional_requirements VALUES(480,34,11,'Learn how animated visual effects are used in the movies such as explosions or flying dragons.  What is a green screen and how does it help blend the animation with reality?');
INSERT INTO badge_optional_requirements VALUES(481,34,12,'Learn how technology uses motion capture to turn real people into animated characters.');
INSERT INTO badge_optional_requirements VALUES(482,34,13,'Create a short animated music video using a song of your choice.');
INSERT INTO badge_optional_requirements VALUES(483,34,14,'Watch a documentary about the animation industry such as The Pixar Story.');
INSERT INTO badge_optional_requirements VALUES(484,34,15,'Attend an animation festival or screening.');
INSERT INTO badge_optional_requirements VALUES(485,34,16,'Learn about how animation is utilized in medical and scientific fields to visualize processes, procedures, and phenomena that are difficult to observe or understand through traditional methods. It is used in areas such as anatomy education, surgical simulations, and molecular modeling.  Watch at least one age appropriate medical animation.');
INSERT INTO badge_optional_requirements VALUES(486,34,17,'Animation is used in educational materials, such as e-learning modules, interactive simulations, and educational videos.  Find an animation that helps explain something you are currently learning about.');
INSERT INTO badge_optional_requirements VALUES(487,34,18,'Animation is used by architects and designers to create virtual walkthroughs, flyovers, and renderings of architectural designs and construction projects.  Take an animated virtual tour through a building, or other architechtural project.');
INSERT INTO badge_optional_requirements VALUES(488,34,19,'Learn how animation is used in engineering and manufacturing industries for product design, assembly instructions, and process simulations. It allows engineers and manufacturers to visualize how products work, identify potential issues, and optimize workflows.  Watch an animation that explains how to use to make something.');
INSERT INTO badge_optional_requirements VALUES(489,34,20,'Animated simlulators are used to train pilots, emergency response teams and more.  Participate in an animated simulation.');
INSERT INTO badge_optional_requirements VALUES(490,34,21,'Both virtual reality (VR) and augmented reality (AR) use animation to create immersive environments and interactive interfaces.  What is the difference between VR and AR?  What purposes do they serve?  How are they usually used?');
INSERT INTO badge_optional_requirements VALUES(491,34,22,'Learn what animation software is currently used most by the gaming community.  Find out if they have a student or free version.  What is the cost of a commercial license to use the software?  How long does it typically take to learn?  Are the free tutorials online?');
INSERT INTO badge_optional_requirements VALUES(492,34,23,'Create an animated PSA about something important you would like to educate your local community about.');
INSERT INTO badge_optional_requirements VALUES(493,34,24,'Learn about 3D modeling and use 3D modeling software to create a 3D model of something.');
INSERT INTO badge_optional_requirements VALUES(494,35,3,'Many different foods are mentioned in the Anne of Green Gables books. Try cooking some of them. There are recipes online, and an official Anne of Green Gables cookbook which could help you.');
INSERT INTO badge_optional_requirements VALUES(495,35,4,'Explore the setting of Prince Edward Island, Canada, where the series takes place. What landscapes and landmarks are significant to the story.');
INSERT INTO badge_optional_requirements VALUES(496,35,5,'Watch at least two adaptations of Anne of Green Gables—for example, the films from the 1980s, the recent film series, the cartoon, or the Anne with an E television series. How are the adaptations similar? How do they differ? Why do you think the creators made the decisions they did about which parts of the books to emphasize?');
INSERT INTO badge_optional_requirements VALUES(497,35,6,'Read another book or story by Lucy Maud Montgomery set in the Avonlea universe, like the Story Girl books.');
INSERT INTO badge_optional_requirements VALUES(498,35,7,'Make an Anne of Green Gables costume.');
INSERT INTO badge_optional_requirements VALUES(499,35,8,'Learn about Lucy Maud Montgomery’s life. Read a biography of her.');
INSERT INTO badge_optional_requirements VALUES(500,35,9,'Anne becomes a teacher when she grows up. Learn about teachers in real life, and how their training is similar to or different from Anne’s training in the books.  What training did teachers need in the  late 1800’s compared to what they need now?');
INSERT INTO badge_optional_requirements VALUES(501,35,10,'Learn about the different attractions in P.E.I. themed around Anne of Green Gables, and the Anne tourism industry.');
INSERT INTO badge_optional_requirements VALUES(502,35,11,'Compile a list of memorable quotes from the series and explain why they resonate with you.');
INSERT INTO badge_optional_requirements VALUES(503,35,12,'Design a book cover for one of the Anne of Green Gables books that captures its essence and appeal.');
INSERT INTO badge_optional_requirements VALUES(504,35,13,'Create a character analysis chart that explores the personalities, relationships, and growth of key characters in the Anne of Green Gables series.');
INSERT INTO badge_optional_requirements VALUES(505,35,14,'Develop a scavenger hunt based on the Anne of Green Gables series, with clues and riddles related to the books and their characters.');
INSERT INTO badge_optional_requirements VALUES(506,35,15,'Write a short story or fan fiction set in the world of Anne Shirley, showcasing your creativity and understanding of the characters.');
INSERT INTO badge_optional_requirements VALUES(507,35,16,'Research the impact of the Anne of Green Gables series on popular culture. Create a timeline or infographic showcasing the series’ influence and adaptations over the years.');
INSERT INTO badge_optional_requirements VALUES(508,35,17,'Explore the themes of friendship and community in the series. Volunteer for a local organization or participate in a community event, reflecting the spirit of the Anne of Green Gables books.');
INSERT INTO badge_optional_requirements VALUES(509,35,18,'Create a map of Avonlea, the fictional village in the Anne of Green Gables series, depicting key locations mentioned in the books.');
INSERT INTO badge_optional_requirements VALUES(510,35,19,'Participate in a dramatic reading or performance of a scene from one of the Anne of Green Gables books, bringing the characters and dialogue to life.');
INSERT INTO badge_optional_requirements VALUES(511,36,3,'Read a book that addresses bullying.');
INSERT INTO badge_optional_requirements VALUES(512,36,4,'Write an essay, poem, or song about anti-bullying');
INSERT INTO badge_optional_requirements VALUES(513,36,5,'Make a list of what resources are available to you and your family if you are the victim of bullying.');
INSERT INTO badge_optional_requirements VALUES(514,36,6,'Gather some friends and make posters about anti-bullying. Ask your school if you can post them on campus, or place them around your community.');
INSERT INTO badge_optional_requirements VALUES(515,36,7,'Cliques, and excluding others, are another form of bullying. Make an effort to include others in your conversations and activities. Examples might include asking someone new to join you and your friends for lunch; when someone asks if they can play a game with you and friends, tell them yes.”');
INSERT INTO badge_optional_requirements VALUES(516,36,8,'Earn a character badge that will help you stand up to bullying such as the Courage badge, Perseverance badge, or Confidence badge.');
INSERT INTO badge_optional_requirements VALUES(517,36,9,'Earn a character badge that will help prevent you from bullying others such as the Kindness badge, Respect badge, or Self Control badge.');
INSERT INTO badge_optional_requirements VALUES(518,36,10,'Participate in a service project that has to do with bullying. Examples might include organizing an anti-bullying rally at your school; creating a website with activities to promote anti-bullying; or performing skits or songs regarding anti-bullying for schools, or youth groups.');
INSERT INTO badge_optional_requirements VALUES(519,36,11,'Research careers that have to do with anti-bullying. Examples might include teachers, counselors, authors, psychologists, movie production, etc. How does this career address anti-bullying? What type of education would you need to have this career? What type of salary could you expect? What hours might you have to work? Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(520,36,12,'Help teach younger kids how to deal with bullying.');
INSERT INTO badge_optional_requirements VALUES(521,36,13,'Learn good manners such as please and thank you. Discuss how being polite can help avoid bullying. (Penguins and Otters optional)');
INSERT INTO badge_optional_requirements VALUES(522,36,14,'Discuss why hitting, biting, shoving, etc. is considered bullying. Practice other, non-violent, ways of dealing with anger and frustration. (Penguins and Otters optional) Third Party Resources: The following resources were compiled by Kelby Pierce, Troop 42359, Girl Scouts of Western Washington. Websites: Stopbullying.gov: www.stopbullying.gov Pacer’s National Bullying Prevention Center: www.pacer.org/bullying A Platform for Good: www.cyberbully.org Netsmartz: www.netsmartz.org i-SAFE Ventures: www.isafe.org Stop Bullying Now: www.stopbullyingnow.com Teaching Tolerance: www.teachingtolerance.org Wired Safety: www.wiredsafety.org Phone Numbers: Childhelp National Child Abuse Helpline: 1-800-4CHILD National Suicide Prevention Helpline: 1-800-273-talk');
INSERT INTO badge_optional_requirements VALUES(523,37,3,'Learn about careers in the antiques business, such as an appraiser or an auctioneer.  What kind of training/education is required?  What are working hours typically like and what hourly pay-rate/salary can you expect?  Level 3-5 only: If possible, shadow someone for a day who works in the antiques business.');
INSERT INTO badge_optional_requirements VALUES(524,37,4,'Visit an antiques shop or a museum which includes antiques in its display.  Did you like the antiques you saw?  Which ones did you like best?  Do you feel that everything in the display was really an antique?');
INSERT INTO badge_optional_requirements VALUES(525,37,5,'Watch a documentary or a movie about antiques, or watch at least two episodes of a TV show about antiques, such as Antiques Roadshow or Flog It!');
INSERT INTO badge_optional_requirements VALUES(526,37,6,'Pick one famous antique, such as Wedgewood china or Hummel figures, and learn how, where and when it was made.  Find out what makes this item so special.  Tell your family, friends, club, or troop what you learned. ­­');
INSERT INTO badge_optional_requirements VALUES(527,37,7,'Spend at least one hour helping an older person to dust and arrange their antiques.');
INSERT INTO badge_optional_requirements VALUES(528,37,8,'Make a timeline of when some famous antiques, such as Chippendale chairs or Wedgewood china, were produced.  You must have at least 10 items on your timeline.');
INSERT INTO badge_optional_requirements VALUES(529,37,9,'Read a book about antiques, and tell your family, friends, club, or troop what you learned.');
INSERT INTO badge_optional_requirements VALUES(530,37,10,'Read a book, watch a video, or go online (with your parent’s permission) to find out about three collections of antiques that are famous for their size, contents, or rarity. Tell your family, friends, club, or troop what you learned.');
INSERT INTO badge_optional_requirements VALUES(531,37,11,'Devote at least 6 hours of community service to a museum or other organization that deals with antiques.');
INSERT INTO badge_optional_requirements VALUES(532,37,12,'Find a type of antique that interests you. Spend some time researching it. How much would it cost to start collecting these items? Does the item you want to collect hold monetary value, or is it just sentimental? If this antique is extremely fragile or rare, how would you store or display it?');
INSERT INTO badge_optional_requirements VALUES(533,38,3,'Hike on a section of the Appalachian Trail.');
INSERT INTO badge_optional_requirements VALUES(534,38,4,'Learn about trail magic. Do some, if possible.');
INSERT INTO badge_optional_requirements VALUES(535,38,5,'Plan the food you would need for 3 days of backpacking.');
INSERT INTO badge_optional_requirements VALUES(536,38,6,'Earn the backpacking badge at your level.');
INSERT INTO badge_optional_requirements VALUES(537,38,7,'Learn about the first thru hiker, Earl Shaffer.');
INSERT INTO badge_optional_requirements VALUES(538,38,8,'Do work on a local trail.');
INSERT INTO badge_optional_requirements VALUES(539,38,9,'Learn about the Pacific Crest and Continental Divide Trails. Why are these a part of the triple crown of hiking?');
INSERT INTO badge_optional_requirements VALUES(540,38,10,'Interview a thru hiker about their experience.');
INSERT INTO badge_optional_requirements VALUES(541,38,11,'Learn trail lingo: what is a nobo, sobo, zero day, slack pack, and mail drop? What do thru-hikers do on town stops?');
INSERT INTO badge_optional_requirements VALUES(542,38,12,'What is a trail name? Think up one for yourself. Why did you choose this?');
INSERT INTO badge_optional_requirements VALUES(543,38,13,'Look at a picture of or visit an A.T. shelter. How far apart are they generally? How do you sleep in one?');
INSERT INTO badge_optional_requirements VALUES(544,38,14,'Learn about the International Appalachian Trail. Where does it go?');
INSERT INTO badge_optional_requirements VALUES(545,38,15,'What dangerous plants and animals might an A.T. hiker encounter? What other challenges?');
INSERT INTO badge_optional_requirements VALUES(546,38,16,'How do hikers get water? Learn to purify water one way.');
INSERT INTO badge_optional_requirements VALUES(547,38,17,'Thru hikers are known for their appetites. How much food do thru hikers consume? What is the 1/2 gallon challenge? What are some other eating related challenges for hikers along the trail?');
INSERT INTO badge_optional_requirements VALUES(548,38,18,'Learn about other long distance trails around the world.');
INSERT INTO badge_optional_requirements VALUES(549,38,19,'What are the speed hiking records for the A.T.? Where these people wearing a pack? What is the average miles per day for a thru-hiker?');
INSERT INTO badge_optional_requirements VALUES(550,38,20,'Play the Appalachian Trail game.');
INSERT INTO badge_optional_requirements VALUES(551,38,21,'Read a story about a thru-hiker (Grandma Gatewood, Bill Irwin, many others).');
INSERT INTO badge_optional_requirements VALUES(552,39,3,'Read at least three myths or stories where an apple plays an important role. Examples might include Snow White, Adam and Eve, the Golden Apple of Greek mythology, or The Giving Tree by Shel Silverstein.');
INSERT INTO badge_optional_requirements VALUES(553,39,4,'Visit an apple orchard and pick your own. You can also visit a fruit stand, or grocery store, and price out different types of apples.');
INSERT INTO badge_optional_requirements VALUES(554,39,5,'Make a hot apple recipe such as baked apples, apple muffins, apple butter, apple galettes, or apple pie.');
INSERT INTO badge_optional_requirements VALUES(555,39,6,'Make a cold apple recipe such as Waldorf salad, fruit salad, or apples with peanut butter.');
INSERT INTO badge_optional_requirements VALUES(556,39,7,'Make an apple drink such as hot apple cider or an apple smoothie.');
INSERT INTO badge_optional_requirements VALUES(557,39,8,'Make an apple craft such as apple prints, apple candle holders, or shrunken apple heads.');
INSERT INTO badge_optional_requirements VALUES(558,39,9,'Participate in a community service project that has something to do with apples. Examples might include donating apples or apple recipe items to a shelter, shut-ins, food bank, etc., or holding an apple bake sale or craft sale to donate money to a local charity.');
INSERT INTO badge_optional_requirements VALUES(559,39,10,'Find out what careers involve apples – examples might include: Farmer, Produce Manager, Fruit Stand Owner, or Chef. What education is needed for this job? What type of pay could you expect? What type of hours might you need to work? Where might you need to live?');
INSERT INTO badge_optional_requirements VALUES(560,39,11,'Visit your county fair and see what apple items were entered. How is the judging conducted? Enter an apple recipe or project yourself if you can.');
INSERT INTO badge_optional_requirements VALUES(561,39,12,'Learn a song or poem about apples.');
INSERT INTO badge_optional_requirements VALUES(562,39,13,'Teach younger children something about apples.');
INSERT INTO badge_optional_requirements VALUES(563,39,14,'Play an apple game.');
INSERT INTO badge_optional_requirements VALUES(564,39,15,'Dehydrate apples. Try different recipes such as dipping the apples in maple syrup first, or in cinnamon and sugar.');
INSERT INTO badge_optional_requirements VALUES(565,39,16,'Learn how to juice apples and try the fresh juice.');
INSERT INTO badge_optional_requirements VALUES(566,39,17,'Find out how to keep an apple from turning brown. Why does it work? What makes the apple turn brown in the first place?');
INSERT INTO badge_optional_requirements VALUES(567,39,18,'Find out about apple world records, such as the heaviest apple or the most people apple bobbing at once. What other un-verified records can you find such as the longest apple peel or the tallest apple tower? You may be to find some answers at Guinness World Records: http://www.guinnessworldrecords.com (third party website).');
INSERT INTO badge_optional_requirements VALUES(568,40,3,'Earn a Marine Life badge to correlate with your visit to the aquarium.');
INSERT INTO badge_optional_requirements VALUES(569,40,4,'Participate in a community service project related to this badge.');
INSERT INTO badge_optional_requirements VALUES(570,40,5,'Volunteer at an aquarium.');
INSERT INTO badge_optional_requirements VALUES(571,40,6,'Learn about careers available in aquariums, or related to the marine biology field. What type of education or training do you need?');
INSERT INTO badge_optional_requirements VALUES(572,40,7,'Shadow an aquarium employee for the day.');
INSERT INTO badge_optional_requirements VALUES(573,40,8,'Make a craft related your aquarium visit.');
INSERT INTO badge_optional_requirements VALUES(574,40,9,'Choose one of the creatures you saw in the aquarium and learn about it. Find out it’s scientific name, where it is native to, lifespan, hope it reproduces, etc.');
INSERT INTO badge_optional_requirements VALUES(575,40,10,'Learn about the management of an aquarium, going all the way up to the board of directors.');
INSERT INTO badge_optional_requirements VALUES(576,40,11,'Make a scrapbook or photo album of your aquarium visit.');
INSERT INTO badge_optional_requirements VALUES(577,40,12,'What is one of the most well or popular aquariums in the world? Research it and find out what it makes it so well known.');
INSERT INTO badge_optional_requirements VALUES(578,40,13,'Is your chosen aquarium involved in any conservation initiatives? If so, what are they? Third Party Resources: Tropical Fish Hobbyist Magazine’s Aquarium Care Basics: https://www.tfhmagazine.com/articles/aquarium-basics LiveAquaria’s Aquariums as a Teaching Tool: https://www.liveaquaria.com/PIC/article.cfm?aid=230');
INSERT INTO badge_optional_requirements VALUES(579,41,3,'Look at archaeological finds in a museum.');
INSERT INTO badge_optional_requirements VALUES(580,41,4,'Read a book about archaeology.');
INSERT INTO badge_optional_requirements VALUES(581,41,5,'How are excavations documented? How are artifacts handled after discovery?');
INSERT INTO badge_optional_requirements VALUES(582,41,6,'Learn how long it takes for various items to break down: wool, leather, plastic spoon, plastic bottle, tin can, cardboard, glass, clay pot.');
INSERT INTO badge_optional_requirements VALUES(583,41,7,'What is the Rosetta Stone and how was it discovered? Why is it important?');
INSERT INTO badge_optional_requirements VALUES(584,41,8,'Collect 10 random items and pretend they were discovered at a dig. What could an archaeologist assume was true about the people who left these finds?');
INSERT INTO badge_optional_requirements VALUES(585,41,9,'Paint an old clay pot and then place it in a paper bag. Tap the pot with a hammer so it breaks into pieces. Then, glue it back together in a way that makes sense. Do this with multiple pots for an extra challenge!');
INSERT INTO badge_optional_requirements VALUES(586,41,10,'Where are some current archaeological digs and what are a few recent finds?');
INSERT INTO badge_optional_requirements VALUES(587,41,11,'Learn about the discovery of King Tut’s tomb in Egypt. What was learned from it and why was it important?');
INSERT INTO badge_optional_requirements VALUES(588,41,12,'Learn about archaeological finds from native people in North America.');
INSERT INTO badge_optional_requirements VALUES(589,41,13,'Pick an interesting archaeological site and learn about it (Pompeii, Machu Picchu, Qin Shi Huang’s tomb, etc). This can be repeated for additional requirements.');
INSERT INTO badge_optional_requirements VALUES(590,41,14,'Read Motel of Mysteries by David Macauley or a similar book that shows how archaeologists can misinterpret what they find.');
INSERT INTO badge_optional_requirements VALUES(591,41,15,'Learn about careers in archaeology.  What education is needed?  Where might you work?  What are the hours and work day like?');
INSERT INTO badge_optional_requirements VALUES(592,42,3,'Make a basic bow and arrow out of household items. How well did it work? What do you think you could do next time to make it better?');
INSERT INTO badge_optional_requirements VALUES(593,42,4,'Take a field trip to an archery store. Find out what different equipment is available and the price differences of each.');
INSERT INTO badge_optional_requirements VALUES(594,42,5,'Participate in a community service project that involves archery of some type. You might put on a benefit archery competition; help clean or repair equipment for use at a camp or other youth organization; sell refreshments at an archery competition to raise money for charity, etc.');
INSERT INTO badge_optional_requirements VALUES(595,42,6,'Learn about the history of archery. When were the first bow and arrow developed? Where? How has the role of the archery changed over time?');
INSERT INTO badge_optional_requirements VALUES(596,42,7,'Learn about at least three different types of bows. What are the pros and cons of each.');
INSERT INTO badge_optional_requirements VALUES(597,42,8,'Learn about at least 3 different types of arrows. What are the pros and cons of each.');
INSERT INTO badge_optional_requirements VALUES(598,42,9,'Explain the differences between field, target and 3D archery.');
INSERT INTO badge_optional_requirements VALUES(599,42,10,'Locate and mark with dental floss, crimp-on, or other method, the nocking point on the bowstring of the bow you are using.');
INSERT INTO badge_optional_requirements VALUES(600,42,11,'Demonstrate stringing and un-stringing a bow or know three methods of stringing a bow.');
INSERT INTO badge_optional_requirements VALUES(601,42,12,'Explain how to determine the proper arrow length to use.');
INSERT INTO badge_optional_requirements VALUES(602,42,13,'Find out how big a standard archery target is, and how score is kept.');
INSERT INTO badge_optional_requirements VALUES(603,42,14,'Make an arrow from a bare shaft.');
INSERT INTO badge_optional_requirements VALUES(604,42,15,'Explain what “weight” means as applied to bows.');
INSERT INTO badge_optional_requirements VALUES(605,42,16,'Learn these different archery terms. For Preschool learn 5; Level 1 learn 6; Level 2 learn 7; Level 3 learn 8; Level 4 learn 10; and Level 5 learn the entire list below: Anchor point Fletching Nock Points Cresting Blunts Compound bow Cross bow Draw length Long bow Loop Quiver Release Finger tab Cast Draw weight Spine');
INSERT INTO badge_optional_requirements VALUES(606,42,17,'Learn about Comanche Indian archery technique.  How does it differ from modern technique?');
INSERT INTO badge_optional_requirements VALUES(607,42,18,'Watch a trick shooter, like Lars Andersen, shoot arrows.  How does his technique differ from accepted practice?');
INSERT INTO badge_optional_requirements VALUES(608,42,19,'What is barebow archery?  How does it differ from other types of competition archery?');
INSERT INTO badge_optional_requirements VALUES(609,42,20,'Learn how cresting is put onto arrows.  Watch someone put cresting onto an arrow, or with parental permission, watch an online video of cresting being done.');
INSERT INTO badge_optional_requirements VALUES(610,43,3,'Learn the definitions of architectural terms and find photos or draw pictures to illustrate the terms. Use your illustrations to give a report to your club, explain the definitions to someone outside your family or to make a poster for your family’s wall. (6 terms for Level 1, 8 terms for Level 2, 10 terms for Level 3, 12 terms for Level 4, and 14 terms for Level 5)');
INSERT INTO badge_optional_requirements VALUES(611,43,4,'Draw a floor plan of your bedroom.');
INSERT INTO badge_optional_requirements VALUES(612,43,5,'Design your dream home. What would it look like? What kind of rooms would it need to have? Draw a floor plan and illustrate what the outside would look like.');
INSERT INTO badge_optional_requirements VALUES(613,43,6,'Read the biography of a famous architect or the story of how a famous building was built.');
INSERT INTO badge_optional_requirements VALUES(614,43,7,'Make plans for an imaginary trip to a faraway city. List the famous buildings you could see and estimate how long it would take to tour at least two of them. Find out if the buildings you’ve chosen are close together or whether you would have to see them on two separate days.');
INSERT INTO badge_optional_requirements VALUES(615,43,8,'Read some of David Macaulay’s books or watch movies based on his books. Share something you learn with a friend or relative and also do a report for your club. What makes his books more interesting than some of the others about architecture? Can you find any similar books that you like better?');
INSERT INTO badge_optional_requirements VALUES(616,43,9,'Watch a documentary about a famous architect.');
INSERT INTO badge_optional_requirements VALUES(617,43,10,'Take an architectural tour of a city near your home (population over 25,000). Find examples of at least four different styles of home and two different styles of office or public buildings. Identify as many parts of the buildings as possible and find out which are the oldest homes and the oldest public buildings. Can you find out anything about any of the architects that built the bigger buildings? If you are repeating this badge, the city you visit should have a population of 50,000 or more. If you are far away from a city that big, you can combine two cities whose populations equal 50,000.');
INSERT INTO badge_optional_requirements VALUES(618,43,11,'Using blocks or sugar cubes create your own building. Level 2 & Up: Using blocks, sugar cubes, or a pre-made kit, make (1) a replica of a famous building or (2) design your own buildings to illustrate a dome, more than one type of arch, columns, an entablature, a buttress, and a pediment. (Level 3: add vaults & towers; Level 4 and Level 5: no pre-made kits allowed and either illustrate fourteen architectural terms, or seven terms in two different styles (example: Roman vs. Egyptian))');
INSERT INTO badge_optional_requirements VALUES(619,43,12,'Find a company or government agency that’s planning to build a building. Draw your own idea of what the building should look like. Take into consideration what materials will make it last a long time and the type of work that will be done in it. Do they need big windows for lots of light? Do they need convenient parking right near the front door? How can you make it accessible to a wide variety of people?');
INSERT INTO badge_optional_requirements VALUES(620,43,13,'Read biographies of two famous architects. Write a short report on the book you prefer (Level 4 should read 3 biographies and Level 5 should read 4). If you are repeating this badge, choose different architects this time. Write out the best features of each of the books and tell your family, friends, club, or troop about at least one of them OR read another book about one of the same architects and write out a comparison of the two books.');
INSERT INTO badge_optional_requirements VALUES(621,43,14,'Plan an imaginary architectural tour of a country that includes two cities and as many buildings as you think you could see in two weeks. Would these buildings come from several different time periods? If you had to shorten your visit to one week, which structures would you consider most important? Do the buildings you want to see have regular tours? How much do they cost? Write out the results of your research & planning. If you are repeating this badge, your destinations must be different than any used previously. Find illustrations or photos of the buildings you want to see & include them in your plans.');
INSERT INTO badge_optional_requirements VALUES(622,43,15,'Find someone who is planning to build a house or building & find out what features they want in the building. Draw a floor plan that you think might work. Have an adult look at the plan and give you constructive criticism. See if you can compare your plans with the plans that the owner has drawn up. Is there something important that you forgot? What did they do differently that you really liked?');
INSERT INTO badge_optional_requirements VALUES(623,43,16,'Draw floor plans to scale of at least two rooms in your house or a building near you. If you need to include more rooms to total at least 400 square feet, do so. On a separate paper, list what you think are the best features of the rooms or else list the changes you would have made had you been the architect.');
INSERT INTO badge_optional_requirements VALUES(624,43,17,'Virtually visit towns and cities around the world using a program such as Google Earth, with a parent’s permission. Compare the architecture as you “wander” around. For Preschool, virtually visit four different countries on minimum three different continents. Level 1, visit six different countries on minimum three different continents. Level 2, visit eight different countries on minimum four different continents. Level 3, visit ten different countries on minimum five different continents. Level 4, visit twelve different countries on minimum six different continents. Level 5, visit fourteen different countries on all seven continents (Antarctica will count as a country and a continent. General Bernardo O’Higgins Base is an example place to visit).');
INSERT INTO badge_optional_requirements VALUES(625,44,3,'Listen to and learn the Army song (otherwise known as “The Caisson Song”) and learn it.');
INSERT INTO badge_optional_requirements VALUES(626,44,4,'Be able to identify at least 5 different Army vehicles and explain their purpose.');
INSERT INTO badge_optional_requirements VALUES(627,44,5,'Tour an Army base and find out what jobs they do there.');
INSERT INTO badge_optional_requirements VALUES(628,44,6,'What is the USO? How do they help the Army? What can you do to help the USO?');
INSERT INTO badge_optional_requirements VALUES(629,44,7,'Tour an Army Museum.');
INSERT INTO badge_optional_requirements VALUES(630,44,8,'Interview a member of the Army. What is their role? What has their experience been like? What is the best and worst part of their job? Where have they traveled?');
INSERT INTO badge_optional_requirements VALUES(631,44,9,'Make a map of the 10 Army bases nearest you. Which is the closest? What is their mission? What groups are stationed there?');
INSERT INTO badge_optional_requirements VALUES(632,44,10,'Participate in a community service project for the Army. For example, you could send cards or care packages to Army members overseas; do yard work or babysitting for an Army family with a member serving away from home; serve dinner at your local VFW post and listen to stories from veteran Army men and women; volunteer at your local veteran cemetery such as placing flags or wreaths on the graves for memorial day; etc.');
INSERT INTO badge_optional_requirements VALUES(633,44,11,'Learn how to read a 24 hour clock as well as use the military phonetic alphabet. Practice translating time from a 12 hour clock to 24 hour and back again. Translate license plates using the phonetic alphabet.');
INSERT INTO badge_optional_requirements VALUES(634,44,12,'Visit an Army monument, memorial, or cemetery.');
INSERT INTO badge_optional_requirements VALUES(635,45,3,'Compare 5 pieces of art of the same general medium that are done in 5 different styles.  For example, if you choose painting you might compare paintings that are impressionistic, expressionistic, realistic, modern, and cubist.  If you choose ink, you might compare line drawings, pointillist, etching,  sketches, and cartoons.');
INSERT INTO badge_optional_requirements VALUES(636,45,4,'Enter an art contest or sell some of your art.');
INSERT INTO badge_optional_requirements VALUES(637,45,5,'Attend a juried art show or tour a museum with an art wing.');
INSERT INTO badge_optional_requirements VALUES(638,45,6,'Watch an artist work or give a demonstration.');
INSERT INTO badge_optional_requirements VALUES(639,45,7,'Send a piece of your art to someone who could use some cheer (faraway relative, sick person, or a soldier).');
INSERT INTO badge_optional_requirements VALUES(640,45,8,'What are the theories behind art therapy? Research the profession.');
INSERT INTO badge_optional_requirements VALUES(641,45,9,'Do something to help an artist (such as clean his studio or wash his paint rags), an art organization, or help your parents take care of your family’s art—dust picture frames for a week, or move mementos to acid-free paper.');
INSERT INTO badge_optional_requirements VALUES(642,45,10,'Earn the Art History badge.');
INSERT INTO badge_optional_requirements VALUES(643,45,11,'Attend an art workshop or help put one together for younger girls.');
INSERT INTO badge_optional_requirements VALUES(644,45,12,'How do health, the economy, personality, and scientific advances affect artists?  Give examples of each.');
INSERT INTO badge_optional_requirements VALUES(645,45,13,'Learn 3 new techniques in the art form of your choice.  This requirement may be repeated. Third Party Resources: Project ARTiculate’s Elements & Principles of Art: http://www.projectarticulate.org/principles.php Totally History’s Famous Artists: http://totallyhistory.com/art-history/famous-artists/');
INSERT INTO badge_optional_requirements VALUES(646,46,3,'Visit an art museum or art gallery. Identify which eras of art are represented.');
INSERT INTO badge_optional_requirements VALUES(647,46,4,'Interview the curator or restoration specialist of a museum or art collection. What are some of the things that have changed in preserving artifacts? Level 3 – 5 only: If possible, shadow the curator or restoration specialist for a day.');
INSERT INTO badge_optional_requirements VALUES(648,46,5,'Explore how technological and scientific advances have influenced art. What has changed in coloring materials, welding, and glue in the last five hundred years? How about sealants, varnishes, sanders, air brushes?');
INSERT INTO badge_optional_requirements VALUES(649,46,6,'Read a biography of a famous artist.');
INSERT INTO badge_optional_requirements VALUES(650,46,7,'Read or carefully look through a well-illustrated book that follows a type of art (sculpture, furniture, ceramics, architecture, painting, etc.) through the eras of art.');
INSERT INTO badge_optional_requirements VALUES(651,46,8,'Earn the Art Badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(652,46,9,'Choose a subject such as a pine tree or an animal and paint or draw it two different ways to suggest two different eras of art history.');
INSERT INTO badge_optional_requirements VALUES(653,46,10,'Attend an art show or read a book with a theme of one subject matter in art such as farming, fish, flowers, or children. The show or book needs to present the subject matter in more than one style.');
INSERT INTO badge_optional_requirements VALUES(654,46,11,'Investigate the history of art materials and tools. What were used to make cave paintings? When do historians think the first pen, pencil, and oil-based paint were made? From what were the first pigments taken? When did people start making synthetic fiber paintbrushes? See if you can find a documentary (even a short clip) on a factory that makes some type of art material.');
INSERT INTO badge_optional_requirements VALUES(655,46,12,'Find a poem or song inspired by a piece of visual art, or vice versa and share it with your family, friends, club, or troop. Levels 3 – 5 only:');
INSERT INTO badge_optional_requirements VALUES(656,46,13,'Help some younger children (minimum 2) learn their ten or fifteen famous works of art so they can earn this badge.');
INSERT INTO badge_optional_requirements VALUES(657,46,14,'Donate some time or money to an organization that restores or preserves art of any type (architecture, quilts, etc.).');
INSERT INTO badge_optional_requirements VALUES(658,47,3,'Make a piece of jewelry or other accessory out of something you find in nature.');
INSERT INTO badge_optional_requirements VALUES(659,47,4,'Make a fairy house or fairy garden');
INSERT INTO badge_optional_requirements VALUES(660,47,5,'Learn about careers that involve art in nature.  Examples might be a wildlife photographer, a landscape artist, a woodworker, etc.  Find out how to train for one of these careers, what the average pay is and where jobs may be found.');
INSERT INTO badge_optional_requirements VALUES(661,47,6,'Create a piece of sand art such as a sand castle or sand drawing');
INSERT INTO badge_optional_requirements VALUES(662,47,7,'Create some leaf animals such as these.');
INSERT INTO badge_optional_requirements VALUES(663,47,8,'Paint a rock');
INSERT INTO badge_optional_requirements VALUES(664,47,9,'Learn to make a God’s Eye from sticks you find on the ground.');
INSERT INTO badge_optional_requirements VALUES(665,47,10,'Learn what macro photography is and find a book or website to view with professional macro photography of nature.  How does this type of photography capture nature in a way we don’t normally see?');
INSERT INTO badge_optional_requirements VALUES(666,47,11,'Create an animal sculpture out of rocks and seashells.');
INSERT INTO badge_optional_requirements VALUES(667,47,12,'Press flowers or leaves and use to create cards or bookmarks');
INSERT INTO badge_optional_requirements VALUES(668,47,13,'Participate in a service project that involves nature in art.  This could be anything from creating and selling craft items to raise money for your favorite charity to providing a free kids craft activity at a local fair or event.');
INSERT INTO badge_optional_requirements VALUES(669,47,14,'Make prints using leaves and other natural items by dipping them in paint or ink and then pressing to paper.');
INSERT INTO badge_optional_requirements VALUES(670,47,15,'Create “water shadows” by laying out various leaves and sticks on the sidewalk or in the dirt and then spraying the area with a spritz bottle.  Remove the items to see the design the “shadows” made.');
INSERT INTO badge_optional_requirements VALUES(671,47,16,'Make leaf or flower rubbings with crayons.');
INSERT INTO badge_optional_requirements VALUES(672,47,17,'Simulate nature fall leaves by making wax paper and crayon leaves.');
INSERT INTO badge_optional_requirements VALUES(673,48,3,'Where can your art be viewed in person? Find both a nearby location and a distant location, such as in another country.  Identify those places on a map.');
INSERT INTO badge_optional_requirements VALUES(674,48,4,'What senses are used to experience your specific art? Has the art been adapted so it can be experienced by people of different abilities?');
INSERT INTO badge_optional_requirements VALUES(675,48,5,'Participate in a community service project that involves your specific art.');
INSERT INTO badge_optional_requirements VALUES(676,48,6,'Can you identify the 7 Principles of Art in your specific art?  (Balance, Emphasis, Movement, Proportion, Rhythm, Unity, and Variety).');
INSERT INTO badge_optional_requirements VALUES(677,48,7,'Are there specific cultures that make your specific art?  Learn about the role the art played in the culture.  Was the art usually created by certain people in the culture, or created by everyone? Was it used in religion, politics, or family identity? Etc.');
INSERT INTO badge_optional_requirements VALUES(678,48,8,'Is there any controversy surrounding your art?  Did it get taken by another culture for display? Do some people/belief systems object to its creation or display?');
INSERT INTO badge_optional_requirements VALUES(679,48,9,'With parent’s permission, watch an age-appropriate movie where your specific art is the primary focus. When it’s over, review it.');
INSERT INTO badge_optional_requirements VALUES(680,48,10,'Attend a class for your specific art.');
INSERT INTO badge_optional_requirements VALUES(681,48,11,'Make a photo collage or album of your specific art.');
INSERT INTO badge_optional_requirements VALUES(682,48,12,'Learn more about a artist  in your specific art. If possible, read their biography or watch a documentary about them.');
INSERT INTO badge_optional_requirements VALUES(683,48,13,'Go to a place where your art is displayed, such as a museum, craft fair, or other similar location or event.  If a location cannot be visited in person, you can take a virtual tour of the location online, or learn about the location and the art that can be found there from books or media.');
INSERT INTO badge_optional_requirements VALUES(684,48,14,'Does your specific art currently employ anyone, such art creators for direct sale, teachers, recreating the art for use in movies or media, historians?  What training is needed for these careers?  What salaries could someone potentially earn in this career, especially average salaries, not just the salary of the highest earners?');
INSERT INTO badge_optional_requirements VALUES(685,48,15,'Use your specific art form to create at least 3 different pieces of art.');
INSERT INTO badge_optional_requirements VALUES(686,48,16,'Learn at least 10 vocabulary words that relate to your specific art form.');
INSERT INTO badge_optional_requirements VALUES(687,49,3,'Explore how AI is portrayed in movies, TV shows, and literature. Analyze the accuracy of these representations and discuss their impact on public perception of AI.');
INSERT INTO badge_optional_requirements VALUES(688,49,4,'Investigate the uses of AI for inclusive applications that help people with disabilities such as the blind or deaf.');
INSERT INTO badge_optional_requirements VALUES(689,49,5,'Discuss how AI can contribute to environmental sustainability efforts. Explore applications such as optimizing energy usage, reducing waste, or improving climate change predictions.');
INSERT INTO badge_optional_requirements VALUES(690,49,6,'Explore AI applications in creative fields like art, music, and storytelling. Create AI-generated content. What is the quality? How can you tell it was generated by AI?');
INSERT INTO badge_optional_requirements VALUES(691,49,7,'Explore how AI impacts various sectors, such as healthcare, transportation, and entertainment.');
INSERT INTO badge_optional_requirements VALUES(692,49,8,'Examine the broader social implications of AI, including job automation, the future of work, and society as a whole.');
INSERT INTO badge_optional_requirements VALUES(693,49,9,'Understand how AI can help solve problems and make existing tasks more efficient.');
INSERT INTO badge_optional_requirements VALUES(694,49,10,'Discuss model development, and the difference between supervised and unsupervised learning. Define reinforcement learning.');
INSERT INTO badge_optional_requirements VALUES(695,49,11,'Discuss the importance of data in AI systems and the ethical considerations surrounding data collection and usage.');
INSERT INTO badge_optional_requirements VALUES(696,49,12,'Talk with a professional or researcher in an AI-related field.');
INSERT INTO badge_optional_requirements VALUES(697,49,13,'Take a field trip or virtual tour of an AI research lab or company working on AI projects.');
INSERT INTO badge_optional_requirements VALUES(698,49,14,'Read recent news articles about AI.');
INSERT INTO badge_optional_requirements VALUES(699,49,15,'Brainstorm some examples of different machine learning apps that do each of these: decide, recommend, predict');
INSERT INTO badge_optional_requirements VALUES(700,49,16,'Experiment with natural language processing and large language models');
INSERT INTO badge_optional_requirements VALUES(701,49,17,'Create an entire AI application by gathering data, training a model, and writing a front-end application.');
INSERT INTO badge_optional_requirements VALUES(702,49,18,'Explore the intersection of AI and robotics. Discuss how AI enables robots to perceive and interact with their environment, and how robotics benefits from AI algorithms for decision-making and learning.');
INSERT INTO badge_optional_requirements VALUES(703,49,19,'Investigate the field of computer vision and its role in AI. Create a presentation or infographic explaining how computer vision is used in areas like facial recognition, object detection, and autonomous vehicles.');
INSERT INTO badge_optional_requirements VALUES(704,49,20,'Participate in an AI-related community service project, such as teaching AI concepts to students or assisting in the development of AI-based solutions for a local organization.');
INSERT INTO badge_optional_requirements VALUES(705,49,21,'Attend a conference, workshop, or webinar on AI and write a summary of key takeaways and new insights gained.');
INSERT INTO badge_optional_requirements VALUES(706,49,22,'Learn about the term “AI slop”, and understand the dangers of this type of content. What threats does it pose? How can you avoid creating and consuming it, and what can be done about it?');
INSERT INTO badge_optional_requirements VALUES(707,50,3,'ATC’s supposedly began in Switzerland. Find this country on a map and learn a bit about the history of ATC’s there.');
INSERT INTO badge_optional_requirements VALUES(708,50,4,'Find a way to preserve and remember your artwork before you trade it away. You could take a digital photo of each card, make a color copy, or create 2 of the same card – one to keep and one to trade.');
INSERT INTO badge_optional_requirements VALUES(709,50,5,'Make 3 additional cards using 3 different artistic techniques: colored pencils, watercolor, marker, pen and ink, stamping, collage, etc. This requirement may be repeated if different techniques are used each time.');
INSERT INTO badge_optional_requirements VALUES(710,50,6,'LTC’s (letter-boxing trading cards) are a variation of ATC’s. Learn about this special type of trading card. View some examples online, if possible.');
INSERT INTO badge_optional_requirements VALUES(711,50,7,'Organize an ATC demonstration, display, and swap for other community members. Have art supplies and blank cards on hand so they can create and swap their own.');
INSERT INTO badge_optional_requirements VALUES(712,50,8,'Arrange to make and swap cards with another person.');
INSERT INTO badge_optional_requirements VALUES(713,50,9,'Collect ATC’s from 10 different states.');
INSERT INTO badge_optional_requirements VALUES(714,50,10,'Collect a total of 30 cards.');
INSERT INTO badge_optional_requirements VALUES(715,50,11,'The official size of an ATC is 2.5 x 3.5 inches. Figure out how to get the most cards out of one standard-size (8.5 x 11 in.) sheet of card stock and cut your own set of blanks.');
INSERT INTO badge_optional_requirements VALUES(716,50,12,'Collect cards from 3 different countries.');
INSERT INTO badge_optional_requirements VALUES(717,50,13,'What is an ACEO (Art Cards, Editions and Originals)? With an adult’s assistance, view examples of ACEO’s online and compare costs. Third Party Resources: Wikipedia’s Artist Trading Cards:  http://en.wikipedia.org/wiki/Artist_trading_cards ATCsforAll’s forums, ongoing swaps, gallery of examples:  www.atcsforall.com Atlas Quest’s Letter-boxing Trading Cards: http://www.atlasquest.com/about/wiki/browse.html?gCatId=39');
INSERT INTO badge_optional_requirements VALUES(718,51,3,'Take a series of photographs or digital images of the movement of the Moon, a planet, an asteroid, meteoroid, or a comet. In your visual display, label each image and include the date and time it was taken. Show all positions on a star chart or map. Show your display at school or at a club meeting. Explain the changes you observed.');
INSERT INTO badge_optional_requirements VALUES(719,51,4,'Be able to identify the Great Bear (alternatively known as the Big Dipper and also the Plough) and the North Star.');
INSERT INTO badge_optional_requirements VALUES(720,51,5,'Read a reading-age-appropriate book about astronomy.');
INSERT INTO badge_optional_requirements VALUES(721,51,6,'Explain the difference between binoculars and a telescope. How do they work and what should each be used for. Learn how to properly handle and care for each. Level 2 and Up: Learn what the different parts of an astronomical telescope are called and how to care for the telescope.');
INSERT INTO badge_optional_requirements VALUES(722,51,7,'Visit a planetarium or observatory. Tell your family or club what you saw.');
INSERT INTO badge_optional_requirements VALUES(723,51,8,'Explain what light pollution is and how air pollution affects astronomy.');
INSERT INTO badge_optional_requirements VALUES(724,51,9,'Sketch the face of the moon and indicate at least five seas and five craters. Label these landmarks. Sketch the phase and the daily position of the Moon at the same hour and place, for a week. Include landmarks on the horizon such as hills, trees, and buildings to help show the position. Explain the changes you observe.');
INSERT INTO badge_optional_requirements VALUES(725,51,10,'Learn about careers that involve astronomy. What education do you need for this career? What is the pay and work schedule you can expect? Level 3-5 only: If possible, shadow someone with this job for a day.');
INSERT INTO badge_optional_requirements VALUES(726,51,11,'Plan and participate in a two-hour observation session that includes using binoculars or a telescope. List the celestial objects you want to observe, and find each on a star chart or in a guidebook.');
INSERT INTO badge_optional_requirements VALUES(727,51,12,'Describe the composition of the sun and the effects of its radiation on Earth’s weather. What are sunspots and what effects can they have on solar radiation. Identify at least one red star, one blue star, and one yellow star (other than the Sun). Explain the meaning of these colors.');
INSERT INTO badge_optional_requirements VALUES(728,51,13,'Identify 8 stars, five of which are of magnitude 1 or brighter.');
INSERT INTO badge_optional_requirements VALUES(729,51,14,'Plan and host a star party for your club or other group such as your class at school. Use binoculars or a telescope to show and explain celestial objects to the group.');
INSERT INTO badge_optional_requirements VALUES(730,51,15,'Compare several types of astronomical telescopes. What are their different features? Costs? Quality? Choose at least 3 instruments that can be used with astronomical telescopes and explain their purpose.');
INSERT INTO badge_optional_requirements VALUES(731,51,16,'Learn how ancient cultures used the stars for navigation, calendars, or storytelling. Share one myth, legend, or cultural belief about a constellation or celestial object.');
INSERT INTO badge_optional_requirements VALUES(732,51,17,'Learn about space exploration missions such as the Mars Rovers, James Webb Space Telescope, or Artemis missions to the Moon. Share something exciting that scientists have discovered recently.');
INSERT INTO badge_optional_requirements VALUES(733,51,18,'Build a simple model or diorama of a famous astronomical object, such as a black hole, comet, or planetary system.');
INSERT INTO badge_optional_requirements VALUES(734,51,19,'Explore how gravity works by doing a simple gravity or orbit demonstration using marbles, a sheet, or online simulations.');
INSERT INTO badge_optional_requirements VALUES(735,51,20,'Learn about the electromagnetic spectrum. What kinds of light do astronomers use besides visible light? How do different types of telescopes help us see the universe?');
INSERT INTO badge_optional_requirements VALUES(736,51,21,'Investigate the concept of time zones and how Earth’s rotation and orbit affect time and seasons.');
INSERT INTO badge_optional_requirements VALUES(737,51,22,'Complete a student project for your grade from the NASA JPL Educational Resources page or a project from a similar space education program. Third Party Resources: KidsAstronomy.com’s Earth and Space Science Resources Astronomical Society of the Pacific’s Hands-On Astronomy Projects');
INSERT INTO badge_optional_requirements VALUES(738,52,3,'Preschool and Level 1 Only: Draw a picture of what attentiveness means to you.');
INSERT INTO badge_optional_requirements VALUES(739,52,4,'Preschool and Level 1 Only: Name a career that requires your full attention and describe what can happen if that person is not paying attention as (s)he should. You can even turn that into a skit to combine with requirement # 5.');
INSERT INTO badge_optional_requirements VALUES(740,52,5,'Write a story or skit where attentiveness plays an important role.');
INSERT INTO badge_optional_requirements VALUES(741,52,6,'What does your book of worship says about Attentiveness? Preschool: Memorize at least one verse about attentiveness. Level 1: Memorize at least two verses about attentiveness. Level 2: Memorize at least three verses about attentiveness. Level 3: Memorize at least four verses about attentiveness. Level 4: Memorize at least five verses about attentiveness. Level 5: Memorize at least six verses about attentiveness.');
INSERT INTO badge_optional_requirements VALUES(742,52,7,'Memorize or write a poem about attentiveness and recite it to your friends or family.');
INSERT INTO badge_optional_requirements VALUES(743,52,8,'Do a report on someone famous, or not so famous that had/has keen attentiveness such as John James Audubon or John Adams.');
INSERT INTO badge_optional_requirements VALUES(744,52,9,'Keep a journal in which you write out the important things you see and hear for one week. One example might be observing your father changing the oil in the car. How was it done? How often does he do it and why? Another example is observing a mother bird and her new hatchlings. What does she do for them? How do they react to her?');
INSERT INTO badge_optional_requirements VALUES(745,52,10,'Divide a piece of paper into two sides. On one side, list words that describe being attentive, such as aware, focused, or observant. On the other side, make a list of words that describe what being attentive is not, such as distracted, inconsiderate, or careless. Come up with solutions to combat the ways in which we can be inattentive such as taking notes during a lecture or sermon. Discuss your ideas with friends or family.');
INSERT INTO badge_optional_requirements VALUES(746,52,11,'Write a paper on how animals are attentive. Compare the differences between how we are attentive with one another and our surroundings, and how animals react. Present your findings to friends, family or group.');
INSERT INTO badge_optional_requirements VALUES(747,52,12,'In the next few weeks keep track of when you benefited from being attentive during a lesson, radio show, discussion with a parent, friend, pastor, or anyone, magazine article, something you read in a book, witnessing others’ mistakes, etc. Write down your experiences and share them with your friends or family.');
INSERT INTO badge_optional_requirements VALUES(748,52,13,'Through your attentiveness, find ways in which you can help your community meet its needs. You can combine this with the Servant’s Heart Award and/or the Make a Difference Award by following through with your ideas and putting it into a project to execute. An example might be: a recent flood has occurred in your town and there has been damage to homes and businesses. You notice that the local carpet cleaning store is having to throw out merchandise that can be used in those homes with carpet and upholstery mold.');
INSERT INTO badge_optional_requirements VALUES(749,52,14,'Watch a foreign movie in which you must read subtitles. Write a summary of the main characters and the plot of the story. What did you like about it? Dislike? How was it different from American movies?');
INSERT INTO badge_optional_requirements VALUES(750,52,15,'Attend an opera. Write out a summary of the main characters and the plot of the story. Did you notice any mistakes in costuming, stage props, etc.?');
INSERT INTO badge_optional_requirements VALUES(751,53,3,'Learn who coined the term “Aurora borealis”, and from what myths the name derived.');
INSERT INTO badge_optional_requirements VALUES(752,53,4,'Learn what the “auroral zone” is.  Draw a map showing places where the Northern Lights can be seen.');
INSERT INTO badge_optional_requirements VALUES(753,53,5,'If you live somewhere where the Northern Lights can regularly be seen, go observe them. If you live somewhere where they can be seen on rare occasion, learn when they can be spotted in your area.');
INSERT INTO badge_optional_requirements VALUES(754,53,6,'Create an art project, or write a story,  inspired by an aurora myth from a culture of your choice.');
INSERT INTO badge_optional_requirements VALUES(755,53,7,'If you live somewhere where they can be seen, take photographs of the Aurora borealis. Does it look more vivid to the naked eye, or in photographs? Why?');
INSERT INTO badge_optional_requirements VALUES(756,53,8,'Watch a documentary or educational video about auroras');
INSERT INTO badge_optional_requirements VALUES(757,53,9,'Learn the five main forms of auroras that can be seen from the ground.');
INSERT INTO badge_optional_requirements VALUES(758,53,10,'Learn how aurorae change with time.');
INSERT INTO badge_optional_requirements VALUES(759,53,11,'When is the earliest written record of an Aurora from? What did it say about the phenomenon?');
INSERT INTO badge_optional_requirements VALUES(760,53,12,'Compare world mythologies related to auroras, from at least three distinct cultures, such as Japanese, Scandinavian, Indigenous Australian, Māori, or Inuit cultures. What did and do they believe about aurorae?');
INSERT INTO badge_optional_requirements VALUES(761,53,13,'Find out what other planets, comets, or brown dwarfs have auroras. Look at photographs of extraterrestrial aurorae. How does they differ from aurorae on Earth?');
INSERT INTO badge_optional_requirements VALUES(762,53,13,'Learn correct grammar, capitalization, and pluralization when writing about aurorae.');
INSERT INTO badge_optional_requirements VALUES(763,53,14,'Learn what the Aurora Australis is.  Why is it lesser known than the Aurora Borealis?  Look at pictures of the Aurora Australis lights and compare them to those of the Aurora Borealis.');
INSERT INTO badge_optional_requirements VALUES(764,53,15,'Compose a piece of music or find songs inspired by the northern lights.');
INSERT INTO badge_optional_requirements VALUES(765,53,16,'Find out how animals react to the aurora borealis and its effects on wildlife.');
INSERT INTO badge_optional_requirements VALUES(766,54,3,'Learn about why a puzzle piece is the symbol of autism.');
INSERT INTO badge_optional_requirements VALUES(767,54,4,'Make a craft using a puzzle piece as your theme to represent autism awareness.');
INSERT INTO badge_optional_requirements VALUES(768,54,5,'Read a book about autism or by someone who is autistic.');
INSERT INTO badge_optional_requirements VALUES(769,54,6,'Watch a movie about someone with autism.');
INSERT INTO badge_optional_requirements VALUES(770,54,7,'Spend some time with an autistic child or adult.');
INSERT INTO badge_optional_requirements VALUES(771,54,8,'Participate in a community service project that promotes autism awareness.');
INSERT INTO badge_optional_requirements VALUES(772,54,9,'Learn about Asperger’s Syndrome.  How does it differ from traditional autism?');
INSERT INTO badge_optional_requirements VALUES(773,54,10,'Learn what is meant by an autistic savant.');
INSERT INTO badge_optional_requirements VALUES(774,54,11,'Create a timeline of scientific progress in autism research.');
INSERT INTO badge_optional_requirements VALUES(775,54,12,'Why is autism considered a “social” disorder? What other types of social disorders are there?');
INSERT INTO badge_optional_requirements VALUES(776,55,3,'Learn and demonstrate how to safely connect jumper cables to a car battery.');
INSERT INTO badge_optional_requirements VALUES(777,55,4,'Explain the importance of registering a vehicle and find out the annual registration fee for renewing your family car’s registration.');
INSERT INTO badge_optional_requirements VALUES(778,55,5,'Create a booklet about general auto maintenance.');
INSERT INTO badge_optional_requirements VALUES(779,55,6,'In the vehicle you are working with, check each of the seat belts to be sure they are functioning properly. Be able to explain why seat belts are important.');
INSERT INTO badge_optional_requirements VALUES(780,55,7,'In the vehicle you are working with, make sure the spare tire is in good condition and ready to use. Check that all tools necessary to change a tire are located in the vehicle and are accessible.');
INSERT INTO badge_optional_requirements VALUES(781,55,8,'Familiarize yourself with the owner’s manual if the car you are working with. Be able to find the pages detailing general car maintenance.');
INSERT INTO badge_optional_requirements VALUES(782,55,9,'Create a checklist of car maintenance that you should check or do before beginning a long road trip.');
INSERT INTO badge_optional_requirements VALUES(783,55,10,'Locate the fuse boxes in the vehicle you are working on, determine the size of the fuses. Learn and demonstrate how to replace burned-out fuses.');
INSERT INTO badge_optional_requirements VALUES(784,55,11,'Be able to explain why wheel alignment is important to the life of a vehicle’s tires.');
INSERT INTO badge_optional_requirements VALUES(785,55,12,'Know what kind of gas to put in your vehicle. Demonstrate how to purchase gasoline for your car.');
INSERT INTO badge_optional_requirements VALUES(786,55,13,'Become familiar with the indicator lights on the dash board of the vehicle you are working with. Be able to identify what they mean.');
INSERT INTO badge_optional_requirements VALUES(787,55,14,'Create a poster with reminders for general car maintenance, or choose one item such as oil changes. Hang the poster somewhere it will remind a vehicle owner to maintain their vehicle.');
INSERT INTO badge_optional_requirements VALUES(788,55,15,'Learn and demonstrate how to change a vehicle’s oil.');
INSERT INTO badge_optional_requirements VALUES(789,55,16,'Participate a community service project involving proper car maintenance.');
INSERT INTO badge_optional_requirements VALUES(790,55,17,'Learn about different careers involving car maintenance. How much could you expect to be paid? What hours would you be expected to work? Level 3 and up: Shadow a mechanic or someone else who has a job involving car maintenance.');
INSERT INTO badge_optional_requirements VALUES(791,55,18,'Find out how much it costs to perform simple vehicle maintenance tasks at a professional auto mechanic shop verses doing it yourself. Preschool choose 1 of the following (Level 1 choose 2, Level 2 choose 3, Level 3 choose 4, Level 4 and Level 5 choose all 5): Oil change Air filter replacement Replacing a burnt fuse Replacing a dead battery Replacing windshield wipers');
INSERT INTO badge_optional_requirements VALUES(792,55,19,'How often should you clean your vehicle to keep it in good condition? Properly/thoroughly clean your vehicle inside and out. Explain the importance of keeping your vehicle clean. Know what kind of equipment and cleaning products are safe to use on your vehicle.');
INSERT INTO badge_optional_requirements VALUES(793,55,20,'Learn how to properly polish headlights, and why this is necessary. With adult supervision, polish the headlights on your vehicle.');
INSERT INTO badge_optional_requirements VALUES(794,55,21,'Level 4 & 5 only: Learn the correct (safe) way to check water levels in the battery and top-up as necessary, and check the battery-post connections and clean as necessary.');
INSERT INTO badge_optional_requirements VALUES(795,55,22,'Learn the unique maintenance and safety considerations for alternative fuel vehicles (hybrid, electric, etc.).');
INSERT INTO badge_optional_requirements VALUES(796,55,23,'Learn what maintenance is necessary for a vehicle’s braking system. Help maintain brakes, with adult supervision.');
INSERT INTO badge_optional_requirements VALUES(797,55,24,'Learn which parts of the vehicle require lubrication. Help with a “grease job”.');
INSERT INTO badge_optional_requirements VALUES(798,55,25,'Know how to check the anti-freeze in your vehicle. What does anti-freeze do? How often should you change the coolant fluid? What tool do you use to test anti-freeze? Help change your vehicle’s anti-freeze if necessary.');
INSERT INTO badge_optional_requirements VALUES(799,55,26,'Understand the fundamental components of a car, including the engine, transmission, brakes, and suspension.');
INSERT INTO badge_optional_requirements VALUES(800,55,27,'Memorize and identify essential car parts under the hood and beneath the vehicle.');
INSERT INTO badge_optional_requirements VALUES(801,55,28,'Understand the importance of functional wiper blades and practice inspecting and replacing them.');
INSERT INTO badge_optional_requirements VALUES(802,55,29,'Understand the function of spark plugs and practice inspecting and replacing them.');
INSERT INTO badge_optional_requirements VALUES(803,55,30,'Familiarize yourself with basic car electrical systems, including fuses and bulbs.');
INSERT INTO badge_optional_requirements VALUES(804,55,31,'Understand the role of belts and hoses in the engine and practice inspecting them for wear and tear.');
INSERT INTO badge_optional_requirements VALUES(805,55,32,'Understand the importance of tire rotation and practice rotating tires following the recommended pattern.');
INSERT INTO badge_optional_requirements VALUES(806,55,33,'Learn to check and, if necessary, replace transmission fluid according to the vehicle’s specifications.');
INSERT INTO badge_optional_requirements VALUES(807,55,34,'Familiarize yourself with common car problems and develop the ability to diagnose issues like strange sounds or warning lights.');
INSERT INTO badge_optional_requirements VALUES(808,55,35,'Create and maintain an emergency kit for your vehicle, including essential tools and supplies.');
INSERT INTO badge_optional_requirements VALUES(809,56,3,'Visit one: a Federal Aviation Administration facility control tower, terminal radar control facility, air route traffic control center, or flight service station. Learn what happens here.');
INSERT INTO badge_optional_requirements VALUES(810,56,4,'Take a flight in an aircraft, with your parent’s permission. Note the date, place, type of aircraft, and duration of flight, and report on your impressions of the flight, like a pilot’s log.');
INSERT INTO badge_optional_requirements VALUES(811,56,5,'Create a poster or model of a typical aviation instrument panel and be able to explain the purposes and functions of the various instruments such as attitude indicator, heading indicator, altimeter, airspeed indicator, turn and bank indicator, vertical speed indicator, compass, navigation (GPS and VOR) and communication radios, tachometer, oil pressure gauge, and oil temperature gauge.');
INSERT INTO badge_optional_requirements VALUES(812,56,6,'Demonstrate how the control surfaces of an airplane are used for takeoff, straight climb, level turn, climbing turn, descending turn, straight descent, and landing.');
INSERT INTO badge_optional_requirements VALUES(813,56,7,'Visit an aviation museum or attend an air show.');
INSERT INTO badge_optional_requirements VALUES(814,56,8,'Explain how an airfoil generates lift, how the primary control surfaces (ailerons, elevators, and rudder) affect the airplane’s attitude, and how a propeller produces thrust.');
INSERT INTO badge_optional_requirements VALUES(815,56,9,'Explain the difference between a recreational pilot and private pilot certificate.  What is required for each?');
INSERT INTO badge_optional_requirements VALUES(816,56,10,'Build a model airplane. Explain safety rules for use of glue, paint, rope, plastics, fuel, and battery packs.');
INSERT INTO badge_optional_requirements VALUES(817,56,11,'Fly a model airplane.  Describe safety rules for flying model airplanes.');
INSERT INTO badge_optional_requirements VALUES(818,56,12,'Find out about career opportunities in aviation. Pick one and find out the education, training, and experience required for this profession.');
INSERT INTO badge_optional_requirements VALUES(819,56,13,'Using one of many flight simulator software packages available for computers. “Fly” a course and successfully land your plane.');
INSERT INTO badge_optional_requirements VALUES(820,56,14,'Visit an airport (in person, or online with the permission of an adult). Learn how runways are numbered, and how runways are determined to be “active.”  What types of aircraft land at this airport? What types of jobs do people do here?');
INSERT INTO badge_optional_requirements VALUES(821,57,3,'Look through baby pictures of yourself, your parents, your siblings, or your grandparents. What features are the same and different?');
INSERT INTO badge_optional_requirements VALUES(822,57,4,'Track how a baby grows over one year, with details listed for each month. You can look up this information in a book or online, with a parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(823,57,5,'Learn why the tone of your voice and how you say things to a baby is important.');
INSERT INTO badge_optional_requirements VALUES(824,57,6,'Learn about why some people think listening to classical musical is good for babies. Do you agree with them?');
INSERT INTO badge_optional_requirements VALUES(825,57,7,'Learn how a woman can become pregnant with more than one baby (twins, triplets, etc.) If possible, interview a woman who has twins and find out how it can be more difficult raising two babies than one.');
INSERT INTO badge_optional_requirements VALUES(826,57,8,'Volunteer to help with babies for a day.');
INSERT INTO badge_optional_requirements VALUES(827,57,9,'Collect baby supplies to donate to a charity.');
INSERT INTO badge_optional_requirements VALUES(828,57,10,'Learn about jobs that have something to do with babies such as midwife, pediatrician, obstetrician, labor and delivery nurse, sonographer, day care provider, etc. Third Party Resources: KidsHealth.org: Breastfeeding vs. Formula Feeding Social Security Administration: Popular Baby Names by Decade Governors Highway Safety Association: Child Passenger Safety Laws by State');
INSERT INTO badge_optional_requirements VALUES(829,58,3,'Watch a baby animal hatch or be born, either in person or on a video. Try to watch different types, not all the same (don’t watch all bird species hatch or all mammals being born).');
INSERT INTO badge_optional_requirements VALUES(830,58,4,'Identify at least two different predators that hunt baby animals.');
INSERT INTO badge_optional_requirements VALUES(831,58,5,'Research how often different species of animals reproduce, and how many offspring each can be expected to have in an average lifetime for that species in the wild (2 species for Preschool, 3 for Level 1,  4 for Level 2, 5 for Level 3, 6 for Level 4 and 7 for Level 5).');
INSERT INTO badge_optional_requirements VALUES(832,58,6,'Learn about various adaptations that baby animals have to protect themselves from predators.');
INSERT INTO badge_optional_requirements VALUES(833,58,7,'Choose a species on the endangered species list.  Research how many offspring that species would need to produce and for how many years, in order to bring that species off the endangered list.');
INSERT INTO badge_optional_requirements VALUES(834,58,8,'Identify at least two different reasons why a baby animal might be taken to a rehabilitation center or sanctuary.');
INSERT INTO badge_optional_requirements VALUES(835,58,9,'Research how zoologists and vets care for a baby animal in the wild that has lost its mother.');
INSERT INTO badge_optional_requirements VALUES(836,58,10,'Read a book, or have it read to you about baby animals.');
INSERT INTO badge_optional_requirements VALUES(837,58,11,'Volunteer at a shelter, zoo, or vet clinic and learn about how the professionals in those locations help care for baby animals.');
INSERT INTO badge_optional_requirements VALUES(838,58,12,'Research when in history mankind began caring for orphaned animals in the wild and why.');
INSERT INTO badge_optional_requirements VALUES(839,58,13,'Learn about animal husbandry in the agricultural world. How do farmers and ranchers manage their livestock and the baby animals to keep their operation running, and their own families fed. Interview a farmer or rancher that keeps livestock about how they manage when their baby animals are born and how they raise them or sell them.');
INSERT INTO badge_optional_requirements VALUES(840,58,14,'Look up 3 different careers that work with or assist baby animals. Pick one that you are interested in learning more about. Find out what education, skills, training, and experience are needed to work in this career.');
INSERT INTO badge_optional_requirements VALUES(841,58,15,'Learn about the responsibility of keeping a pet baby animal. Find out the cost of food, housing, and medical care for your baby animal over an average lifespan for that species.');
INSERT INTO badge_optional_requirements VALUES(842,58,16,'Learn what spaying and neutering are. Find out why animal shelters generally require that animals they adopt out be spayed or neutered.');
INSERT INTO badge_optional_requirements VALUES(843,58,17,'Learn about how the reproduction cycle varies for non-domesticated animals in the wild and in captivity. Research 2 different species of animal that are historically unable to reproduce in captivity and what zoologists are doing to help.');
INSERT INTO badge_optional_requirements VALUES(844,58,18,'Pick an animal and visit or look up online, with your parent’s permission, an organization that cares for baby animals in the wild.');
INSERT INTO badge_optional_requirements VALUES(845,58,19,'Learn the names of at least five different baby animal groups, such as a litter, brood, or clutch.');
INSERT INTO badge_optional_requirements VALUES(846,59,3,'Make a list of important things to consider when choosing a campsite.');
INSERT INTO badge_optional_requirements VALUES(847,59,4,'Some trails have historical significance or interesting stories. Learn the history of at least one trail (two for Level 1 and 2, three for Level 3 and up).');
INSERT INTO badge_optional_requirements VALUES(848,59,5,'Earn the Leave No Trace badge at your level.');
INSERT INTO badge_optional_requirements VALUES(849,59,6,'Visit a store with a wide selection of outdoor gear such as REI or Bass Pro Shops. View the items available for backpacking. List ten essential items you found and explain why. List ten items you found that are not essential and explain why you would or would not bring them. If it is not possible to go to a store with a wide selection of outdoor gear, you may visit a store online with your parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(850,59,7,'Earn the Pocket Knife and Pocket Knife Safety badges at your level.');
INSERT INTO badge_optional_requirements VALUES(851,59,8,'Create a field guide for a trail you enjoy hiking. Include wildlife such as trees, wildflowers, and animals you might see along a hike there.');
INSERT INTO badge_optional_requirements VALUES(852,59,9,'Learn how to make beef jerky. With the help of an adult, make some and share it with your family or club.');
INSERT INTO badge_optional_requirements VALUES(853,59,10,'Make trail mix. Why is this a good food for backpacking?');
INSERT INTO badge_optional_requirements VALUES(854,59,11,'Come up with a list of questions and interview someone about their backpacking experience(s).');
INSERT INTO badge_optional_requirements VALUES(855,59,12,'Create a training plan to prepare for a multi-day hike with a pack.');
INSERT INTO badge_optional_requirements VALUES(856,59,13,'Explain how to properly prepare for and deal with changes in weather during a backpacking trip.');
INSERT INTO badge_optional_requirements VALUES(857,59,14,'Explain how to stay found and what to do if you get lost.');
INSERT INTO badge_optional_requirements VALUES(858,59,15,'Participate in or organize a litter cleanup along a trail you enjoy.');
INSERT INTO badge_optional_requirements VALUES(859,60,3,'Make a detailed drawing of a bird or squirrel feeder that you would like to make for some birds or squirrels in your yard or watch an online video about how to construct a feeder.');
INSERT INTO badge_optional_requirements VALUES(860,60,4,'Draw a map of your yard.  Make a key that includes trees, where you could put animal feeders, potential homes for animals, and fixed objects (fences, house, garage…).');
INSERT INTO badge_optional_requirements VALUES(861,60,5,'Visit a store that sells a variety of bird feeders or squirrel feeders.  What do you notice about them? What are some characteristics that they have in common?  What are some characteristics that aid in their effectiveness?  How much does decoration play in the appearance of these feeders?  Does the decoration serve a purpose?');
INSERT INTO badge_optional_requirements VALUES(862,60,6,'Make a bird feeder out of recycled materials.  These could include cardboard rolls, drink cartons, plastic bottles, etc.  Place the bird feeder in your yard.');
INSERT INTO badge_optional_requirements VALUES(863,60,7,'(Must complete #6) Hang it in a place that you can see it.  Collect data on its use for one week.  View it at the same time each day.  Note how much food is gone from the last time you saw it.  Note whether you see any birds on the feeder.  Note whether you see any other animals on the feeder.');
INSERT INTO badge_optional_requirements VALUES(864,60,8,'(Must complete #6 and #7) Make a third bird feeder for your yard out of materials that you choose.  Compare the effectiveness of each.  What makes one more accessible or successful than the others?  Why?  What could you improve to make each one equally successful?');
INSERT INTO badge_optional_requirements VALUES(865,60,9,'Make a squirrel feeder.  Place the feeder in your yard.');
INSERT INTO badge_optional_requirements VALUES(866,60,10,'(Must complete #9)  Collect data on your squirrel feeder for one week.  View it at the same time each day.  Note how much food is gone from the last time you saw it.  Note whether you see any squirrels on the feeder.  Note whether you see any other animals on the feeder.');
INSERT INTO badge_optional_requirements VALUES(867,60,11,'Make a Venn diagram comparing squirrels’ food and birds’ food.  Write a compare and contrast paragraph on the two.');
INSERT INTO badge_optional_requirements VALUES(868,60,12,'Design and build a “squirrel proof” bird feeder.  What attributes make your bird feeder unique? Test it to see if it is successful!');
INSERT INTO badge_optional_requirements VALUES(869,60,13,'Research different types of bird seed.  Draw the bird beak that would be appropriate for at least 7 types of seed.  Explain why seeds are more appropriate for certain birds.');
INSERT INTO badge_optional_requirements VALUES(870,60,14,'Brainstorm what other things animals need to survive in the winter.  Make something for your yard that provides something to animals that is not food.');
INSERT INTO badge_optional_requirements VALUES(871,60,15,'Take photographs of the wild animals in your yard and the things you have created to help them.');
INSERT INTO badge_optional_requirements VALUES(872,60,16,'Write a fictional story about some of the animals’ adventures.  The story should be age appropriate in length.');
INSERT INTO badge_optional_requirements VALUES(873,60,17,'Make a diorama (shoebox scene) of your yard with the animals interacting with the feeders you created.');
INSERT INTO badge_optional_requirements VALUES(874,60,18,'Plant shrubs, flowers, and other plants that can feed hummingbirds, bees, butterflies, and other animals.');
INSERT INTO badge_optional_requirements VALUES(875,61,3,'Participate in a “5 Senses” scavenger hunt. Find three items for each of your senses. Ideas might include: Sense of Feel: Find something squishy Find something rough Find something smooth Sense of Hearing: Listen for a bird call Listen for an insect Listen for water running or a splash Sense of Smell: Smell the air Smell a tree Smell the dirt Sense of Sight: Find something that looks beautiful Find something that looks strange Find something looks gross Sense of Taste (Do not put anything in your mouth that your parent or leader has not approved): Taste something sweet Taste something salty Taste something bland');
INSERT INTO badge_optional_requirements VALUES(876,61,4,'Make a “Sit-Upon” so that you have a cushion to sit on if it is damp outside. Using two pieces of vinyl tablecloth material measuring 18”x18”, have a parent punch holes along the edges every 1”. Use yarn or string to sew your sit-upon together and stuff it with plastic bags from the grocery store to make an outdoor pillow to sit on.');
INSERT INTO badge_optional_requirements VALUES(877,61,5,'Make s’mores. If you do not have a campfire, have a parent show you how to make them over a BBQ or outdoor stove. Make sure to obey all fire safety rules.');
INSERT INTO badge_optional_requirements VALUES(878,61,6,'Put on a shadow puppet show using the side of tent or a sheet strung up between trees.');
INSERT INTO badge_optional_requirements VALUES(879,61,7,'Preschool – Level 3 only: Learn to identify the all the types of trees in your backyard. Do a bark rubbing and leaf rubbing of each and make a tree identification booklet.');
INSERT INTO badge_optional_requirements VALUES(880,61,8,'Bird watch and make an identification booklet with a picture or drawing of each bird you see.');
INSERT INTO badge_optional_requirements VALUES(881,61,9,'Make a bug jar and go on an insect hunt. Using a large mason jar, punch holes in the lid and place a few small leaves and sticks inside. Put any bugs you catch in the jar so that you can observe them. Make sure to let the bugs go when you are finished. Check with your parent or leader before bug hunting – some insects sting!');
INSERT INTO badge_optional_requirements VALUES(882,61,10,'Preschool – Level 2 only: Make a nature collage of things from your backyard, or make a nature bracelet. To make a bracelet, make a circle of duct tape around your wrist with the sticky side facing out. Stick acorn caps, leaves, small twigs or pebbles to the tape to create a bracelet.');
INSERT INTO badge_optional_requirements VALUES(883,61,11,'Participate in a skit or talent show around a campfire. If you do not have a real campfire, make one using a pile of flashlights or lanterns.');
INSERT INTO badge_optional_requirements VALUES(884,61,12,'Level 2 and up: Learn about the Great American Backyard Campout sponsored by the National Wildlife Federation. Why do you think they put this program together? What is so important about getting kids outside?');
INSERT INTO badge_optional_requirements VALUES(885,61,13,'Level 2 and up: Learn to pitch a tent and to take it down and repack it.');
INSERT INTO badge_optional_requirements VALUES(886,61,14,'Level 3 and up: Help organize a backyard campout for younger children.');
INSERT INTO badge_optional_requirements VALUES(887,61,15,'Level 3 and up: Make tin can lanterns. Materials: Tin can, label removed Markers Towel Hammer Nails of different sizes Small screw-in hook 20-inch wood dowel Coat hanger Votive candle Dried spaghetti noodle Instructions: 1. On the outside of the clean, empty can, draw a pattern for the lantern holes. 2. Fill the can with water and freeze it for two days. (The ice keeps the sides from collapsing when you hammer them.) When the water in the can is frozen solid, place the can on its side on top of a towel and use the nail tips to hammer in holes of various sizes according to his design. Be sure to make two holes near the top, on opposite sides, for stringing a handle. 3. Remove any chunks of ice from inside the tin can (a parent’s job, since the hammered-in holes will have sharp edges). 4. Screw the hook into one end of the wood dowel, then string the length of wire through the hook. Wind the ends of the wire through the hanging holes on the can a few times until they are secure. 5. Use a small bit of melted wax or modeling clay to affix the votive candle to the bottom of the can. Tip: The dried spaghetti noodle is a handy way to light the lantern; it burns steadily and lessens the likelihood of scorching fingers. Make sure to blow out the candles before going to bed and obey all fire safety rules. Third Party Resources: Homeschools Share: Free Camping Lapbook National Wildlife Federation: Our Work Great Books for Backyard Camping Cooking on a Stick: Campfire Recipes for Kids by Linda White & Fran Lee Cooking in a Can: More Campfire Recipes for Kids by Kate White and Debra Dixon Sleeping in a Sack: Camping Activities for Kids by Linda White & Fran Lee Trekking on a Trail by Linda White & Fran Lee Wishing on a Star: Constellation Stories and Stargazing Activities for Kids by Fran Lee Fishing in a Brook: Angling Activities for Kids by Fran Lee Backyard Birding for Kids by Fran Lee Kids Camp! Activities for the Backyard or Wilderness by Laurie Carlson');
INSERT INTO badge_optional_requirements VALUES(888,62,3,'Interview your family and friends. Ask them for badge ideas. Does a particular subject come up more often than others? Make a list of the badge ideas you found and ask the kids in your club which one they would like to earn the most. Make a graph of your results and share it with your club leader. (If you are an individual member, do this with family and friends.)');
INSERT INTO badge_optional_requirements VALUES(889,62,4,'Get some friends together, and have a Badge Writing Day. Either come up with ideas to work on together or each kid can work on writing their own badge.');
INSERT INTO badge_optional_requirements VALUES(890,62,5,'Interview a kid or adult who has already written a badge or your club leader for some tips. You may also email Curiosity Untamed through the website or ask for advice through Curiosity Untamed and Quest Clubs Facebook Group');
INSERT INTO badge_optional_requirements VALUES(891,62,6,'When your badge is complete and approved by your parent or club leader, earn it.');
INSERT INTO badge_optional_requirements VALUES(892,62,7,'Have a friend, parent or club member earn your badge and give you feedback on it. Revise as necessary.');
INSERT INTO badge_optional_requirements VALUES(893,62,8,'If your badge includes a recipe or directions for making something, have someone else run through the project start-to-finish to make sure your directions are the clearest and best they can be. If that person has questions, so will others, so make sure to add any clarifications if necessary.');
INSERT INTO badge_optional_requirements VALUES(894,62,9,'Come up with three more badge ideas. Briefly describe why they interest you and how you would go about writing badge requirements for them.');
INSERT INTO badge_optional_requirements VALUES(895,63,3,'Bake cookies such as drop cookies, pan cookies, refrigerator cookies, shaped cookies, etc.');
INSERT INTO badge_optional_requirements VALUES(896,63,4,'Bake any type of bread.');
INSERT INTO badge_optional_requirements VALUES(897,63,5,'Bake a main dish.');
INSERT INTO badge_optional_requirements VALUES(898,63,6,'Bake a cake.');
INSERT INTO badge_optional_requirements VALUES(899,63,7,'Bake brownies.');
INSERT INTO badge_optional_requirements VALUES(900,63,8,'Bake muffins');
INSERT INTO badge_optional_requirements VALUES(901,63,9,'Bake a quick bread.');
INSERT INTO badge_optional_requirements VALUES(902,63,10,'Make a batch of cookies or brownies and give them as a gift to a shut in, your local fire department, police department, food bank, rescue mission, etc.');
INSERT INTO badge_optional_requirements VALUES(903,63,11,'Take a field trip to a local bakery.');
INSERT INTO badge_optional_requirements VALUES(904,63,12,'Choose a baking recipe and find a way to make it healthier.  For example, substitute butter with applesauce, whole milk with 2% or nonfat milk, sour cream with plain yogurt, etc.');
INSERT INTO badge_optional_requirements VALUES(905,63,13,'Research careers in the baking industry.  What education will you need?  What types of jobs are available?  How much to they usually pay?  What hours are expected?  Level 3, 4, and 5 only: Shadow someone who works in the baking industry.');
INSERT INTO badge_optional_requirements VALUES(906,63,14,'Hold a bake sale. Follow all federal, state, and local legislature.');
INSERT INTO badge_optional_requirements VALUES(907,63,15,'Learn about the history of baking.');
INSERT INTO badge_optional_requirements VALUES(908,63,16,'Learn how flour is produced.  If possible grind some flour from whole grains, or visit a flour mill.');
INSERT INTO badge_optional_requirements VALUES(909,63,17,'Learn about different products used in the baking industry to make baked goods easier to make.  e.g. dough conditioners, preservatives, etc.');
INSERT INTO badge_optional_requirements VALUES(910,63,18,'Not all baking is  done with wheat flour.  Bake a recipe using a different flour such as rye, barley, oats, etc.');
INSERT INTO badge_optional_requirements VALUES(911,63,19,'Some people have an intolerance to gluten contained in wheat, rye, and barley. Learn about gluten- free grains, and bake a recipe that uses gluten-free grains, such as rice, millet, buckwheat, etc.');
INSERT INTO badge_optional_requirements VALUES(912,63,20,'Bake a bread from another country, such as scones from England, kolaches from Czech Republic, etc.');
INSERT INTO badge_optional_requirements VALUES(913,63,21,'Earn the Grains Badge at your level.');
INSERT INTO badge_optional_requirements VALUES(914,63,22,'Bake a dessert.');
INSERT INTO badge_optional_requirements VALUES(915,63,23,'Earn the Cooking for Special Diets Badge at your level.');
INSERT INTO badge_optional_requirements VALUES(916,63,24,'Bake crackers.');
INSERT INTO badge_optional_requirements VALUES(917,63,25,'Bake rice.');
INSERT INTO badge_optional_requirements VALUES(918,63,26,'Make Granola.');
INSERT INTO badge_optional_requirements VALUES(919,63,27,'Bake a pie.');
INSERT INTO badge_optional_requirements VALUES(920,63,28,'Bake scones.');
INSERT INTO badge_optional_requirements VALUES(921,63,29,'Understand the role of different leavening agents, such as yeast, baking powder, and baking soda, in baking.');
INSERT INTO badge_optional_requirements VALUES(922,63,30,'Take a tour of a local bakery, and interview a baker.');
INSERT INTO badge_optional_requirements VALUES(923,63,31,'Experiment with incorporating fresh herbs into your baked goods for unique flavors.');
INSERT INTO badge_optional_requirements VALUES(924,63,32,'Learn how to convert measurements in baking recipes.  Be able to cut a recipe in half, double a recipe and convert metric measurements to U.S. standard measurements.');
INSERT INTO badge_optional_requirements VALUES(925,63,33,'Bake a recipe from a different culture.');
INSERT INTO badge_optional_requirements VALUES(926,63,34,'Develop a three-course menu that includes an appetizer, main course, and dessert, all of which involve baking.');
INSERT INTO badge_optional_requirements VALUES(927,63,35,'Experiment with alternative sweeteners, such as honey, maple syrup, or agave nectar, in your baking.  Discuss why measurments may need to be adjusted based on the sweetener you use.');
INSERT INTO badge_optional_requirements VALUES(928,63,36,'Host a baking swap event with your troop or with friends, where everyone brings and shares their favorite baked goods.');
INSERT INTO badge_optional_requirements VALUES(929,63,37,'Keep a journal documenting your baking experiments, including successes, challenges, and lessons learned.');
INSERT INTO badge_optional_requirements VALUES(930,63,38,'Choose a seasonal ingredient and incorporate it into a delicious baked recipe.');
INSERT INTO badge_optional_requirements VALUES(931,63,39,'Create a savory pastry, such as quiche or empanadas.');
INSERT INTO badge_optional_requirements VALUES(932,63,40,'Learn the use for each of the following baking tools: Measuring cups and spoons Wooden spoon Rubber spatula Metal spatula Pastry brush Whisk Rolling pin Fine-mesh sieve (sifter) Wire rack Electric mixer (hand or stand) Parchment paper');
INSERT INTO badge_optional_requirements VALUES(933,63,41,'Name three different items you can bake with each of the following pans: Square baking pan Rectangular baking pan Loaf pan Pie Pan Round cake pan Muffin pan Cookie sheet pan');
INSERT INTO badge_optional_requirements VALUES(934,63,42,'Contribute your baking skills to a community event or fundraiser.');
INSERT INTO badge_optional_requirements VALUES(935,63,43,'Learn about the importance of food presentation in baking and apply it to your creations. Third Party Resources: Snackworks: Top 10 Safety Rules for Kids in the Kitchen Baking Mad: Easy Baking Recipes');
INSERT INTO badge_optional_requirements VALUES(936,64,3,'Learn about how balloons are made.');
INSERT INTO badge_optional_requirements VALUES(937,64,4,'Read a book on balloon art.');
INSERT INTO badge_optional_requirements VALUES(938,64,5,'Watch a how to video or documentary on creating balloon art.');
INSERT INTO badge_optional_requirements VALUES(939,64,6,'Learn how to use multiple balloons in a twisted balloon art piece to create more intricate designs.  Make a piece of twisted balloon art using the techniques you learned.');
INSERT INTO badge_optional_requirements VALUES(940,64,7,'Learn how to make balloon hats.');
INSERT INTO badge_optional_requirements VALUES(941,64,8,'Participate in a community service project involving balloon art.  You might choose to make a balloon display for a charitable event, make balloon animals for children at a charitable event, sell balloon animals to raise money for a charity, etc.');
INSERT INTO badge_optional_requirements VALUES(942,64,9,'Learn to make balloon flowers and give a balloon bouquet to someone who needs cheering up or to whom you would like to show thanks or appreciation.');
INSERT INTO badge_optional_requirements VALUES(943,64,10,'Learn about careers in balloon art.  How do you become a balloon designer or artist?  What is the difference between an artist who twists balloons at parties and an artist who creates elaborate displays?  How much money does each type of artist typically make?');
INSERT INTO badge_optional_requirements VALUES(944,64,11,'Learn different techniques for adding details to balloon art such as drawing on the balloons to add faces, twisting or attaching balloons to sticks, strings, or other bases, or using balloons with pre-printed pictures or designs on them.  Look through pictures of balloon modeling and identify how details were added.');
INSERT INTO badge_optional_requirements VALUES(945,64,12,'Make balloon animals for a party or a club meeting to entertain your friends.');
INSERT INTO badge_optional_requirements VALUES(946,64,13,'Make a large balloon display to decorate for a party or club ceremony.');
INSERT INTO badge_optional_requirements VALUES(947,64,14,'Learn about different balloon organizations and conventions.');
INSERT INTO badge_optional_requirements VALUES(948,64,15,'Compare 3 different brands of balloons.  Do you notice any quality difference?');
INSERT INTO badge_optional_requirements VALUES(949,64,16,'Make three of the following (these must be in addition to any pieces made under the Level 2 requirement): Balloon horse Balloon bear Balloon creation with floppy ears Balloon creation  with wings Balloon hat Balloon flower Balloon dog Balloon giraffe Balloon cat Balloon monkey Balloon swan Any balloon animal or object not already listed');
INSERT INTO badge_optional_requirements VALUES(950,64,17,'Learn about at least 5 different world records in the area of balloon modeling and sculpture.  Examples might include the record for 1 hour balloon modeling (number of completed sculptures in 1 hour), the Sprint: 100 Animals (fastest time for twisting 100 animals), Largest Modeling Balloon Sculpture, etc. Third Party Resources: Balloon HQ: Info on balloon history, conventions, sculpting basics and more Record Holders: Balloon Records');
INSERT INTO badge_optional_requirements VALUES(951,65,3,'Design your own bandana on a 12×12 piece of paper from one of the categories mentioned in Level 3 requirement 2.');
INSERT INTO badge_optional_requirements VALUES(952,65,4,'A bandana can be an indispensable tool on a camp or hike. Make a list of 10 (Preschool and Level 1), 15 (Level 2), 20 (Level 3), 25 (Level 4 and 5) uses for a bandana on a hike, campout or other outdoor activity.');
INSERT INTO badge_optional_requirements VALUES(953,65,5,'Decorate your own bandana with fabric paint, fabric markers, or tie dye.');
INSERT INTO badge_optional_requirements VALUES(954,65,6,'Create an accessory using bandanas (bag, belt, hair band, etc.).');
INSERT INTO badge_optional_requirements VALUES(955,65,7,'Create something for the home with bandanas (tablecloth, lamp shade, etc.).');
INSERT INTO badge_optional_requirements VALUES(956,65,8,'Use a bandana in a new-to-you hairstyle.');
INSERT INTO badge_optional_requirements VALUES(957,65,9,'Use strips of bandanas to make friendship bracelets. Keep one and give one to a friend.');
INSERT INTO badge_optional_requirements VALUES(958,65,10,'Deployed soldiers use bandanas to keep off the dust and to keep warm. Help a soldier by sending a care package with bandanas or donating to a charity like Operation Bandanas.');
INSERT INTO badge_optional_requirements VALUES(959,65,11,'Decorate a bandana for your pet.');
INSERT INTO badge_optional_requirements VALUES(960,65,12,'Research other names for the bandana depending on how it is used. Third Party Resources: Bandanashop.com: History of the Bandana');
INSERT INTO badge_optional_requirements VALUES(961,66,3,'Open a savings account and make a deposit. Level 3 and above: identify your routing number and your account number.');
INSERT INTO badge_optional_requirements VALUES(962,66,4,'What is an “overdraft” fee? What is a “non-sufficient funds” fee? How are these fees different? What is a “bounced check”?');
INSERT INTO badge_optional_requirements VALUES(963,66,5,'What is a “fee and information schedule” and why is it important to review it?');
INSERT INTO badge_optional_requirements VALUES(964,66,6,'What is a bank statement? What information does it contain and why is it important to review it? How much time do you have to report an error if one is made on your account?');
INSERT INTO badge_optional_requirements VALUES(965,66,7,'How is a credit union different from a bank? Make a list of all the banks and credit unions in your town. Choose two and compare the products they offer and the fees they charge.');
INSERT INTO badge_optional_requirements VALUES(966,66,8,'Tour a Federal Reserve Bank or a US Mint.');
INSERT INTO badge_optional_requirements VALUES(967,66,9,'How is a savings account different from a checking account? What is Federal Regulation D?');
INSERT INTO badge_optional_requirements VALUES(968,66,10,'Learn how to write out a check.');
INSERT INTO badge_optional_requirements VALUES(969,66,11,'What is a bank account register?  Learn how to balance your account using a register.');
INSERT INTO badge_optional_requirements VALUES(970,66,12,'Learn how online banking works.  What self service options do you have?');
INSERT INTO badge_optional_requirements VALUES(971,66,13,'Learn about what products and services banks sell such as credit cards, car loans, CDs, etc.  Contact your local bank for a complete list.  Understand what each product or service is.');
INSERT INTO badge_optional_requirements VALUES(972,66,14,'Discuss the pros and cons of putting your money in a bank vs. keeping cash on hand.');
INSERT INTO badge_optional_requirements VALUES(973,66,15,'Understand the difference between a credit card and a debit card.  What are the pros and cons of each?');
INSERT INTO badge_optional_requirements VALUES(974,66,16,'Know what a CD (certificate of deposit) is.  What are the advantages and disadvantages to purchasing CDs?');
INSERT INTO badge_optional_requirements VALUES(975,66,17,'Learn about some careers in the banking industry, such as: teller, banker, service manager, loan officer or branch manager.');
INSERT INTO badge_optional_requirements VALUES(976,66,18,'Learn about identity theft.  How can you help protect your bank information from thieves?  What insurance do you have against banking identity theft?');
INSERT INTO badge_optional_requirements VALUES(977,66,19,'Find out what a money market account is.  How does it differ from a savings or checking account?');
INSERT INTO badge_optional_requirements VALUES(978,66,20,'Earn the Money badge at your level. Resources provided by  Cindy Lillemo.  Not all sources have been checked yet.  Please use at your own risk. Currency Coloring Pages: https://www.uscurrency.gov/sites/default/files/downloadable-materials/files/en/play-money-coloring-sheets-en.pdfPrintable Play Money: https://www.uscurrency.gov/sites/default/files/downloadable-materials/files/en/printable-play-money-en.pdfJack HartmanJack Hartman Money SongJack Hartman Show Me the Moneywww.juniorachievement.orgwww.jausa.ja.org/programs/indexJunior Achievement Home Resources: https://sites.google.com/ja.org/ja-ed-resources/homeJunior Achievement Saving Tips:  (https://drive.google.com/file/d/1KI4utocsRCSgWAZ5z3fO8ZoJvf_fyvX-/view?usp=drivesdk)www.education.com/games/money-mathCurrency Security Features: https://www.uscurrency.gov/sites/default/files/downloadable-materials/files/en/know-your-money-en.pdfHow are coins made?: https://www.govmint.com/coin-authority/post/how-are-coins-made#:~:text=Initially%2C%20coins%20were%20made%20with%20a%20hammer%20and,hydraulic%20presses%20are%20used%20for%20minting%20today%E2%80%99s%20coinage.YouTubeUS Quarter Minting Process: https://www.youtube.com/watch?v=HRpRz2P4l2gField Trip to the Money Factory: https://www.youtube.com/watch?v=-IBHbe-t-X4How to write a check: www.thebalance.com/how-to-write-a-checkFederal Regulation D: https://www.thebalance.com/what-is-regulation-d-5074854What is a register: https://www.thebalance.com/use-check-registers-3152898 Printable Checkbook Registers: https://www.examples.com/business/printable-checkbook-register-examples-pdf.htmlHow to balance your account: https://www.thebalance.com/balance-checking-accounts-step-by-step-guide-315357#:~:text=Five%20Steps%20to%20Balance%20Your%20Checking%20Account%201,Numbers.%20…%205%20Fix%20Mistakes%20and%20Problems.%20Bank vs. credit union: https://keydifferences.com/difference-between-credit-union-and-bank.html#:~:text=The%20significant%20differences%20between%20credit%20union%20and%20bank,operate%20in%20making%20profits.%20…%20More%20items…%20Identity Theft: https://www.usa.gov/identity-theft');
INSERT INTO badge_optional_requirements VALUES(979,67,2,'Investigate Ken’s history. Has his appearance changed over the years? Compare all his clothes and extras with Barbies.');
INSERT INTO badge_optional_requirements VALUES(980,67,3,'Make a list of your favorite Barbie movies, books and friends. Why are they your favorite?');
INSERT INTO badge_optional_requirements VALUES(981,67,4,'Look through at least five (Preschool – Level 2) or ten (Level 3 and Up) toy or children’s catalogs or sales flyers and tally how many other things you can find that have a Barbie theme on them, such as pajamas, notepads, telephones, slippers, etc.');
INSERT INTO badge_optional_requirements VALUES(982,67,5,'Go to a museum or toy fair that has a large Barbie collection. Report to your family, friends, or group what you learned about Barbie & her stuff.');
INSERT INTO badge_optional_requirements VALUES(983,67,6,'Define accessories. Make a list of all Barbie’s accessories that are currently on the market and their prices. What is the total?');
INSERT INTO badge_optional_requirements VALUES(984,67,7,'Save your money and buy a brand-new Barbie or one of her outfits and donate it to a charity for a child’s Christmas present.');
INSERT INTO badge_optional_requirements VALUES(985,67,8,'Act out three different stories with Barbie and friends or write a Barbie poem or song.');
INSERT INTO badge_optional_requirements VALUES(986,67,9,'Hold a Barbie party to work on this badge with some friends.');
INSERT INTO badge_optional_requirements VALUES(987,67,10,'Research the company that creates Barbie. What is the name of it? What kind of things did it make before it started making Barbies? What percentage of their business is from Barbies?');
INSERT INTO badge_optional_requirements VALUES(988,67,11,'Watch one of Barbie’s movies and tell a parent or troop member what you learned.');
INSERT INTO badge_optional_requirements VALUES(989,67,12,'Make some Barbie furniture or dishes.');
INSERT INTO badge_optional_requirements VALUES(990,67,13,'Help a friend clean up her Barbie collection and sort everything, wash things that are dirty, repair rips, and put everything away neatly.');
INSERT INTO badge_optional_requirements VALUES(991,67,14,'Find a website or book that is passionately opposed to “anatomically incorrect”dolls. What are their main points? With which points do you agree? What should such parents consider about Barbie and her substitutes? Write a short essay on your findings or discuss this with an adult.');
INSERT INTO badge_optional_requirements VALUES(992,67,15,'Many people feel that one of the values of baby dolls is that children can practice taking care of babies by playing with their dolls. What would you say to these folks when they say there isn’t the same value for Barbies? Write a short essay on your findings or discuss this with an adult.');
INSERT INTO badge_optional_requirements VALUES(993,67,16,'My Twinn and American Girls dolls have tried to promote character values, ethnic pride or historical awareness with their dolls. Has Barbie promoted any value other than the sense of fashion she is known for? Write a short essay on your findings or discuss this with an adult.');
INSERT INTO badge_optional_requirements VALUES(994,67,17,'Do you agree with people that say that the whole “Barbie culture” overdoes consumer spending and that Barbie clothes don’t last very long? Find someone with the opposite viewpoint and listen to her side.');
INSERT INTO badge_optional_requirements VALUES(995,67,18,'Research limited edition Barbies. What are so special about these particular dolls? Which Barbie is the most rare/sought after?');
INSERT INTO badge_optional_requirements VALUES(996,67,19,'Research artists who re-do or customize Barbies, such as repainting their faces in a more realistic fashion, or who give Barbie new hairstyles. How do the artists customize these Barbies? What do you like/dislike about these customized Barbies?');
INSERT INTO badge_optional_requirements VALUES(997,70,3,'Learn about forts and how they are used to defend people. Build a fort of your own using pillows, blankets, cardboard, snow etc. Explain why your fort is a good place to defend or hide.');
INSERT INTO badge_optional_requirements VALUES(998,70,4,'Learn the purpose of the parade march in strategy and watch videos of parade marches from at least three different countries or eras.  For example the German parade march from World War II, the North Korean parade march, the Russian parade march or the Portuguese parade march.  How do they differ? Which do you think serves the purpose the best?');
INSERT INTO badge_optional_requirements VALUES(999,70,5,'Play a game of capture the flag.  Discuss how each teams strategy led to their victory or defeat.');
INSERT INTO badge_optional_requirements VALUES(1000,70,6,'Define the difference between strategy and tactics. Provide an example of how both were used in a real-world scenario.');
INSERT INTO badge_optional_requirements VALUES(1001,70,7,'Read The Art of War by Sun Tzu. Identify five key principles and explain how they apply to modern strategies.');
INSERT INTO badge_optional_requirements VALUES(1002,70,8,'Understand the role of logistics in warfare. Explain how supply lines and resources can affect strategic decisions.');
INSERT INTO badge_optional_requirements VALUES(1003,70,9,'Research how technology, such as drones or cyber tools, influences battle strategy today. Give an example of modern technological impact.');
INSERT INTO badge_optional_requirements VALUES(1004,70,10,'Learn about strategic retreats. Provide an example of a battle where retreat led to an eventual victory.');
INSERT INTO badge_optional_requirements VALUES(1005,70,11,'Explore the role of diplomacy in strategy. Identify a conflict where diplomacy played a major role in avoiding or concluding warfare.');
INSERT INTO badge_optional_requirements VALUES(1006,70,12,'Study the concept of psychological warfare. Share a historical example where it was effectively used.');
INSERT INTO badge_optional_requirements VALUES(1007,70,13,'Learn about the role of deception in battle strategy. Explain a case where misleading the enemy led to victory.');
INSERT INTO badge_optional_requirements VALUES(1008,70,14,'Study different historical battle formations (e.g., phalanx, cavalry charges). Recreate one on paper or using toy soliders and explain how it worked.');
INSERT INTO badge_optional_requirements VALUES(1009,70,15,'Understand how intelligence gathering (spying, reconnaissance) affects battle plans. Discuss an example where intelligence played a key role.');
INSERT INTO badge_optional_requirements VALUES(1010,70,16,'Study the importance of the chain of command in executing battle strategy. Discuss how a break in communication can lead to failure.');
INSERT INTO badge_optional_requirements VALUES(1011,70,17,'Compare two different leadership styles of military commanders. Explain how their styles impacted their strategic decisions.');
INSERT INTO badge_optional_requirements VALUES(1012,70,18,'Learn about naval strategy and how it differs from land-based warfare. Explore a naval battle to illustrate key differences.');
INSERT INTO badge_optional_requirements VALUES(1013,70,19,'Watch a movie about a famous battle.');
INSERT INTO badge_optional_requirements VALUES(1014,70,20,'Explore the concept of economic warfare. Explain how nations have used economic sanctions or blockades as part of a broader strategy.');
INSERT INTO badge_optional_requirements VALUES(1015,70,21,'Research asymmetric warfare and how smaller forces can outmaneuver larger ones. Discuss a real-world example.');
INSERT INTO badge_optional_requirements VALUES(1016,70,22,'Understand how battle strategies impact civilian populations. Study a conflict where civilian involvement influenced the outcome.');
INSERT INTO badge_optional_requirements VALUES(1017,70,23,'Play a strategy-based board game or simulation (e.g., Risk, Civilization). Discuss your strategic approach and its success.');
INSERT INTO badge_optional_requirements VALUES(1018,70,24,'Why do armies learn drill commands?  How do they contribute to a battle strategy? Learn some basic drill commands and how to do them. Practice with a group if possible. Halt Attention At Ease Right Face Left Face About Face Forward March');
INSERT INTO badge_optional_requirements VALUES(1019,70,25,'Learn about the role of flags in battle throughout time.  Why did many defend a flag until death?');
INSERT INTO badge_optional_requirements VALUES(1020,71,3,'Different regions in the US are known for their different BBQ sauce. What are some of the more famous areas? Which type of sauce and/or meat is each known for?');
INSERT INTO badge_optional_requirements VALUES(1021,71,4,'Make your own homemade BBQ sauce. Compare to store bought. Which tastes better? Which is healthier?');
INSERT INTO badge_optional_requirements VALUES(1022,71,5,'Compare several store bought sauces. You can either compare different flavors from the same brand, or several brands of similar flavors. Which is your favorite?  Do you like them hot?  Sweet?  Vinegary?');
INSERT INTO badge_optional_requirements VALUES(1023,71,6,'What meats are typically used in BBQ? BBQ a meat that you have never tried before.');
INSERT INTO badge_optional_requirements VALUES(1024,71,7,'What is a dry rub? Use a dry rub on a meat before BBQing.');
INSERT INTO badge_optional_requirements VALUES(1025,71,8,'What is a marinade? What is a brine? How are they used in BBQ?  Use either a brine or marinade in a BBQ recipe.');
INSERT INTO badge_optional_requirements VALUES(1026,71,9,'Help serve BBQ for a charity function.');
INSERT INTO badge_optional_requirements VALUES(1027,71,10,'Make and package a dry rub for a fundraiser for your troop or for charity (Make sure to follow all federal/state/local food safety laws).');
INSERT INTO badge_optional_requirements VALUES(1028,71,11,'What sides are typically served with BBQ? Make one from scratch.');
INSERT INTO badge_optional_requirements VALUES(1029,71,12,'What desserts are traditionally served with BBQ? Make one from scratch.');
INSERT INTO badge_optional_requirements VALUES(1030,71,13,'What is BBQ like around the world? How is it different from US BBQ?');
INSERT INTO badge_optional_requirements VALUES(1031,71,14,'Different woods are used to smoke meat for BBQ. What are some of the different kinds and why and where are they used?');
INSERT INTO badge_optional_requirements VALUES(1032,71,15,'Make a BBQ-ed dessert.');
INSERT INTO badge_optional_requirements VALUES(1033,71,16,'Make a BBQ-ed vegetable dish.');
INSERT INTO badge_optional_requirements VALUES(1034,71,17,'Create a BBQ recipe book to share.');
INSERT INTO badge_optional_requirements VALUES(1035,71,18,'Not everyone eats meat. BBQ an alternative, such as portabella mushrooms for a burger, or another plant-based patty.');
INSERT INTO badge_optional_requirements VALUES(1036,72,3,'Play a beach game such as beach volleyball, Frisbee, or beach ball tag.');
INSERT INTO badge_optional_requirements VALUES(1037,72,4,'Make a beach craft such as sand candles or a drift wood mobile.');
INSERT INTO badge_optional_requirements VALUES(1038,72,5,'Learn to do a water sport such as body surfing, skiing, surfing, or wakeboarding.');
INSERT INTO badge_optional_requirements VALUES(1039,72,6,'Build a sand castle using items you find on the beach to decorate it such as shells, twigs, leaves, etc. Also learn to make a dribble castle (let drippy wet sand dribble through your fingers to create peaks).');
INSERT INTO badge_optional_requirements VALUES(1040,72,7,'Collect shells, sea glass, driftwood, or rocks. Learn about what you collected.  What animal lived in the shells? What type of tree did the wood come from?  What type of rocks are they?  What type of glass did you find and where might it have come from?');
INSERT INTO badge_optional_requirements VALUES(1041,72,8,'Hold a wild life scavenger hunt listing as many animals (and insects) that you know live in and around your beach. Just make sure not to touch or interfere with those animals.');
INSERT INTO badge_optional_requirements VALUES(1042,72,9,'Work on the swimming/water rescue requirements of your level Life Skills for at least half an hour. If you have completed your requirements already, then help family members, friends, or your group to complete theirs.');
INSERT INTO badge_optional_requirements VALUES(1043,72,10,'Learn what careers there are that affect Beach Fun.  For example, you might research a life guard, a beach party planner, or a beach front hotel manager.  What education might you need?  What type of salary could you expect?  Where might you have to live?  What hours might you have to work?');
INSERT INTO badge_optional_requirements VALUES(1044,72,11,'Create a sand art mural using sticks to draw with and stones and shells to decorate it.');
INSERT INTO badge_optional_requirements VALUES(1045,72,12,'Participate in a community service project involving beach fun. For example, you might host games for younger children, put on a community hot dog roast, or help clean up your favorite beach.');
INSERT INTO badge_optional_requirements VALUES(1046,72,13,'Fly a kite on the beach.');
INSERT INTO badge_optional_requirements VALUES(1047,72,14,'Learn to snorkel.');
INSERT INTO badge_optional_requirements VALUES(1048,73,3,'Visit a bead store and explore the variety of beads offered.');
INSERT INTO badge_optional_requirements VALUES(1049,73,4,'Decorate an article of clothing using beads (shirt, socks, sweater, etc.).');
INSERT INTO badge_optional_requirements VALUES(1050,73,5,'Decorate a home decor item using beads (lamp shade, window hanging, basket, candle holder, etc.).');
INSERT INTO badge_optional_requirements VALUES(1051,73,6,'Decorate an accessory with beads (purse, belt, headband, key chain, etc.).');
INSERT INTO badge_optional_requirements VALUES(1052,73,7,'Learn how to use a beading loom.');
INSERT INTO badge_optional_requirements VALUES(1053,73,8,'Teach a younger person a beading technique.');
INSERT INTO badge_optional_requirements VALUES(1054,73,9,'Participate in a community service project that involves beading.  You may choose to create illustrated beading instructions that can be copied and used by youth programs; sell some of your creations and donate the money to charity; decorate used clothing to make it new again and donate it, etc.');
INSERT INTO badge_optional_requirements VALUES(1055,73,10,'Learn about careers that involve beads.  Examples might be an archaeologist or historian, art teacher, jeweler, etc.');
INSERT INTO badge_optional_requirements VALUES(1056,73,11,'Learn two different bead stitches such as the brick stitch, herringbone stitch, ladder stitch, right-angle weave, or peyote stitch.');
INSERT INTO badge_optional_requirements VALUES(1057,73,12,'Read a book or magazine about beading');
INSERT INTO badge_optional_requirements VALUES(1058,73,13,'Learn how at least three different types of beads are made.');
INSERT INTO badge_optional_requirements VALUES(1059,73,14,'Make something out of edible beads such as Fruit Loops, Cheerios, licorice, macaroni, etc.');
INSERT INTO badge_optional_requirements VALUES(1060,73,15,'Make 5 pieces of jewelry using beads.');
INSERT INTO badge_optional_requirements VALUES(1061,73,16,'Learn how other peoples of the world used beads as trading items or for decoration. What was wampum? Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(1062,73,17,'Learn to make a simple beaded fringe.');
INSERT INTO badge_optional_requirements VALUES(1063,74,3,'Draw a diagram of a bee and label each of its parts.');
INSERT INTO badge_optional_requirements VALUES(1064,74,4,'Find at least 3 recipes that use honey and make one to share with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(1065,74,5,'Be able to explain why bees are an important part of our environment.  What do you think would happen to many of the foods we eat if there were no bees?  Know the value of having bees wherever plants are grown for food or for pleasure.');
INSERT INTO badge_optional_requirements VALUES(1066,74,6,'Know what part the queen, drones, and workers play in the life of the colony.');
INSERT INTO badge_optional_requirements VALUES(1067,74,7,'Taste at least 3 different types of honey made from the nectar of 3 different flowers.  Which did you like the best and why?');
INSERT INTO badge_optional_requirements VALUES(1068,74,8,'Assist in hiving a swarm, examining a colony, removing the comb, finding the queens, putting foundations in sections, filling and removing supers, and preparing honey in comb and strained for market. Be able to identify different parts of a hive.');
INSERT INTO badge_optional_requirements VALUES(1069,74,9,'Know which flowers afford the best food for bees, and how honey varies in color and flavor according to the flowers.');
INSERT INTO badge_optional_requirements VALUES(1070,74,10,'Know how to fix the hives for the winter months.');
INSERT INTO badge_optional_requirements VALUES(1071,74,11,'Know the effect, if any, of insect sprays on bees.');
INSERT INTO badge_optional_requirements VALUES(1072,74,12,'Know something about the habits of wild bees and how you go about finding a colony of them.');
INSERT INTO badge_optional_requirements VALUES(1073,74,13,'Find out what predators there are to a beehive in your area.  What in the hive does the predator go after and how does the predator get it?  How do you protect a beehive from those predators?  What creatures are just annoying to beekeepers because they can cause damage to the hive or beekeeper and how do you protect against them?');
INSERT INTO badge_optional_requirements VALUES(1074,74,14,'Level 3 and up only: Create a booklet to teach basic beekeeping to younger children.');
INSERT INTO badge_optional_requirements VALUES(1075,74,15,'Level 3 and up only: Know how to introduce a new queen into a hive.');
INSERT INTO badge_optional_requirements VALUES(1076,74,16,'Participate in a community service project involving bees.');
INSERT INTO badge_optional_requirements VALUES(1077,74,17,'Learn about careers involving bee keeping. What are the risks involved? What kind of pay could you expect, and how many hours would you be expected to work? Level 3 and up: Shadow a bee keeper.');
INSERT INTO badge_optional_requirements VALUES(1078,74,18,'Do the “Bee Color Experiment”.  Bees can see ultraviolet light which means they are more attracted to flowers of certain colors. Using this simple experiment, you will be able to see which colored flowers are the most popular with bees in your garden. What you will need: 1 square each of red, orange, yellow, green blue, purple and white paper; 7 plastic bottle tops (preferably white); half a cup of sugar; half a cup of warm water; pencil & paper; a bit of patience! What to do:  Mix the sugar and water until the sugar is fully dissolved.  Cut your colored paper about 4” diameter (roughly).  Place the paper in a line on a flat sunny surface in your garden.  Make sure they are about ½ inch from each other.  Clean the bottle tops and carefully fill with your sugar water mixture.  Place one bottle in the center of each of your paper pieces.  Sit back and watch the bees pay a visit.  Using your pencil & paper, keep a tally of how many bee visits there are to color.  Which colors did they like the most?  Do any other insects, such as butterflies, visit too? Third Party Resources: Mother Earth News: Bee Color Experiment Avas Flowers: The Importance of Honeybees  The Organic Backyard Beekeeper: Beekeeping for Kids Mother Earth News: Bee Color Experiment');
INSERT INTO badge_optional_requirements VALUES(1079,76,3,'Make a poster, painting, or sculpture of what a Bible passage(s) mean to you.');
INSERT INTO badge_optional_requirements VALUES(1080,76,4,'Compose or learn a song that includes a Bible passage.');
INSERT INTO badge_optional_requirements VALUES(1081,76,5,'Write a paper about the historical context of a Bible passage.');
INSERT INTO badge_optional_requirements VALUES(1082,76,6,'Choose a charitable project that shows what you learned from the Bible verses you memorized.');
INSERT INTO badge_optional_requirements VALUES(1083,76,7,'Help a younger person memorize one of the passages you chose to learn.');
INSERT INTO badge_optional_requirements VALUES(1084,76,8,'Locate on a map where one of your Bible verses was written, speaks about, or took place.');
INSERT INTO badge_optional_requirements VALUES(1085,76,9,'Write an essay about how one of these verses could affect you, your community, or the world.');
INSERT INTO badge_optional_requirements VALUES(1086,76,10,'Interview your pastor about his/her favorite Bible verses. Why are they his/her favorite?');
INSERT INTO badge_optional_requirements VALUES(1087,76,11,'Create or learn motions to go along with the verse. You can use the American Sign Language Dictionary to look up signs for the words in your verse.');
INSERT INTO badge_optional_requirements VALUES(1088,76,12,'Look for Bible verses quoted in public places. Where do you see them? Are they only in church buildings or in other public places? Which verses do you find?');
INSERT INTO badge_optional_requirements VALUES(1089,76,13,'Investigate incidents in history where Bible verses where quoted to inspire people to action. Which verses were used? For example, the British used the expression “But if not” when preparing for the Dunkirk evacuation. Why did they use these words? Which Bible verse is being quoted?');
INSERT INTO badge_optional_requirements VALUES(1090,76,14,'Learn a continuous passage of scripture of at least Preschool– 3 verses Level 1 – 5 verses Level 2 – 8 verses Level 3 – 10 verses Level 4 – 12 verses Level 5 – 14 verses How easy is it to memorize a passage of scripture rather than random individual verses? These verses must be different from the ones you memorized for 1* requirement.');
INSERT INTO badge_optional_requirements VALUES(1091,76,15,'Research a particular topic in the Bible and memorize verses about the subject: Preschool– 3 verses Level 1 – 5 verses Level 2 – 8 verses Level 3 – 10 verses Level 4 – 12 verses Level 5 – 14 verses');
INSERT INTO badge_optional_requirements VALUES(1092,76,16,'Read the Ten Commandments from Exodus 20:1-17 and Deuteronomy 5:6-21 and memorize one of the passages.');
INSERT INTO badge_optional_requirements VALUES(1093,76,17,'Read the Beatitudes in Matthew 5:1-18 and memorize the passage.');
INSERT INTO badge_optional_requirements VALUES(1094,76,18,'Memorize a Psalm and then learn a musical version of the Psalm. This requirement may be repeated up to 3 times.');
INSERT INTO badge_optional_requirements VALUES(1095,76,19,'Memorize the names of all the books in the Bible in order.');
INSERT INTO badge_optional_requirements VALUES(1096,76,20,'Memorize a Proverb of your choice.');
INSERT INTO badge_optional_requirements VALUES(1097,76,21,'Memorize a key verse from each of the four Gospels (Matthew, Mark, Luke, John).');
INSERT INTO badge_optional_requirements VALUES(1098,76,22,'Explore the spiritual significance of memorizing scripture.  Research how various religious traditions emphasize the importance of scripture memorization.');
INSERT INTO badge_optional_requirements VALUES(1099,76,23,'Research mnemonic devices and memory techniques that aid in scripture memorization.');
INSERT INTO badge_optional_requirements VALUES(1100,76,24,'Explore how early religious communities passed down teachings through oral traditions, including memorization.');
INSERT INTO badge_optional_requirements VALUES(1101,76,25,'Discuss how memorizing specific verses has impacted people’s lives in times of challenges or decision-making.');
INSERT INTO badge_optional_requirements VALUES(1102,77,3,'What are the 3 basic types of bicycles, and what are they used for? Visit a bicycle shop and learn about the different types of bicycles.. Level 2: Find out what to look for when buying a bicycle. How do you know when a bicycle is the right size for you? Level 3: Find out the costs of the different types of bicycles. Which is the most suitable for your purposes? Level 4: What added extras can be purchased with bicycles? Does the price increase with the number of gears or the type of brakes? Level 5: Evaluate which bicycles would be best for a learner; which sort of brakes are recommended and what size tires.');
INSERT INTO badge_optional_requirements VALUES(1103,77,4,'What types of clothing should you wear when riding a bike? What should you stay away from? What are safe ways to carry your things safely on a bicycle?');
INSERT INTO badge_optional_requirements VALUES(1104,77,5,'Pinpoint bicycle hazards or trouble spots in your community and find a way to tell others about these hazards. Create a list of public bike trails in your community. Make sure to list the hours they are open and any rules that are listed.');
INSERT INTO badge_optional_requirements VALUES(1105,77,6,'On a map, find the safest bicycle route from your home to your school, park, or other location. Do you have city-ordained bike paths available?');
INSERT INTO badge_optional_requirements VALUES(1106,77,7,'Plan a bicycle tour of your community.  Make maps available to your friends, family, and/or club members.');
INSERT INTO badge_optional_requirements VALUES(1107,77,8,'Find out what types of bicycle accidents are the most common. Learn and show that you know first aid for injuries or illnesses that could occur while cycling, including hypothermia, heat reactions, frostbite, dehydration, insect stings, tick bites, snakebites, blisters, and hyperventilation.');
INSERT INTO badge_optional_requirements VALUES(1108,77,9,'Find out what cycling events are available to men and women in the Olympics. How did your country do in these events in the last Olympics? What kind of training is necessary?');
INSERT INTO badge_optional_requirements VALUES(1109,77,10,'Research the history of the bicycle and the role it played in the women’s movement of the late 1800’s. Make a booklet to share the story with your family, friends, or group. Hint: Try looking up information on Annie Londonderry.');
INSERT INTO badge_optional_requirements VALUES(1110,77,11,'Research local bicycle clubs or groups. How many are in your area. What do they do?');
INSERT INTO badge_optional_requirements VALUES(1111,77,12,'Invite a member of your local sheriff’s department to talk to your group about bicycle safety and/or bicycle inspection or licensing.');
INSERT INTO badge_optional_requirements VALUES(1112,77,13,'Describe your state’s traffic laws for bicycles. Compare them with motor-vehicle laws. Know the bicycle-safety guidelines.');
INSERT INTO badge_optional_requirements VALUES(1113,77,14,'Volunteer for at least 5 hours with a local charity that repairs bikes to give away.');
INSERT INTO badge_optional_requirements VALUES(1114,77,15,'Create a bicycle safety booklet for the younger members of your troop.');
INSERT INTO badge_optional_requirements VALUES(1115,77,16,'Hold a bike safety day.  Have participants demonstrate that they can correctly: Start and stop their bike. Use a brake to control their speed. Give correct hand signals. Make eye contact with drivers of trucks, cars and other bicycles to make sure they understand what you intend to do. Watch for cars at intersections, alleys, and driveways. Make left turns while watching for cars and making eye contact.');
INSERT INTO badge_optional_requirements VALUES(1116,77,17,'(Preschool – Level 2 only) Take a bike ride! Preschool: With a parent, in a safe place such as a bicycle path at a park, ride around the path. Level 1: With a parent, take a short bike ride of at least a 1/2 hour. Level 2: Go on a group bike ride of at least 2 hours.  Map out where you are going.  Consider safety issues.  Be sure to carry a first aid kit, emergency tool kit, and food and water.');
INSERT INTO badge_optional_requirements VALUES(1117,77,18,'Participate in a bicycling marathon.');
INSERT INTO badge_optional_requirements VALUES(1118,78,3,'With your sibling, draw a picture of your whole family.');
INSERT INTO badge_optional_requirements VALUES(1119,78,4,'Make a gift for your sibling.');
INSERT INTO badge_optional_requirements VALUES(1120,78,5,'Make a book for your sibling.');
INSERT INTO badge_optional_requirements VALUES(1121,78,6,'Help your sibling with their chores for one week.');
INSERT INTO badge_optional_requirements VALUES(1122,78,7,'Make up a game to play together.');
INSERT INTO badge_optional_requirements VALUES(1123,78,8,'Make your sibling a snack for one week, such as apple slices or crackers and cheese.');
INSERT INTO badge_optional_requirements VALUES(1124,78,9,'Offer to babysit your sibling for a night.');
INSERT INTO badge_optional_requirements VALUES(1125,78,10,'Cook a meal for your sibling, and if possible, let them help you.');
INSERT INTO badge_optional_requirements VALUES(1126,78,11,'Put together an outfit for your sibling to go out and play in.');
INSERT INTO badge_optional_requirements VALUES(1127,78,12,'Help them with their homework for at least two nights.');
INSERT INTO badge_optional_requirements VALUES(1128,78,13,'Make a costume for your sibling and play with them while they wear it.');
INSERT INTO badge_optional_requirements VALUES(1129,78,14,'Earn a badge with your sibling.');
INSERT INTO badge_optional_requirements VALUES(1130,79,3,'What does Bigfoot eat? What makes sense for the environment he would live in? Talk about the different foods he may eat, and if you can, try one of them.');
INSERT INTO badge_optional_requirements VALUES(1131,79,4,'What are some safety rules to have if you want to go looking for Bigfoot?');
INSERT INTO badge_optional_requirements VALUES(1132,79,5,'Make a list of items you would take with you if you were going searching for Bigfoot. Make sure your list has at least five items.');
INSERT INTO badge_optional_requirements VALUES(1133,79,6,'Create an artistic representation of what you think Bigfoot looks like.');
INSERT INTO badge_optional_requirements VALUES(1134,79,7,'Should you look for Bigfoot during the day or night? Explain your reasoning.');
INSERT INTO badge_optional_requirements VALUES(1135,79,8,'Look at pictures of Bigfoot’s foot and compare them to yours. Give your best guess as to how much bigger is his foot than yours.');
INSERT INTO badge_optional_requirements VALUES(1136,79,9,'When was the first sighting of Bigfoot? Where was it? Who sighted him?');
INSERT INTO badge_optional_requirements VALUES(1137,79,10,'If possible, hike in an area where Bigfoot has been spotted.');
INSERT INTO badge_optional_requirements VALUES(1138,79,11,'Visit a museum that has a display about Bigfoot.');
INSERT INTO badge_optional_requirements VALUES(1139,79,12,'Watch a movie, documentary, or TV show that features Bigfoot.');
INSERT INTO badge_optional_requirements VALUES(1140,79,13,'Read a book or article about Bigfoot.');
INSERT INTO badge_optional_requirements VALUES(1141,79,14,'Find at least ten locations where Bigfoot has been spotted and find them on a map.');
INSERT INTO badge_optional_requirements VALUES(1142,80,3,'Earn the Genetics badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(1143,80,4,'Understand the difference between vertebrates and invertebrates. Preschool: Know two organisms in each category. Level 1: Know four organisms. Level 2: Know six organisms. Level 3: Know eight organisms. Level 4: Know ten organisms. Level 5: Know twelve organisms.');
INSERT INTO badge_optional_requirements VALUES(1144,80,5,'Draw a food web. Preschool: Have four plants or animals in your food web. Level 1: Six plants or animals. Level 2: Eight plants or animals. Level 3: Ten plants or animals. Level 4: Twelve plants or animals. Level 5: Fourteen plants or animals.');
INSERT INTO badge_optional_requirements VALUES(1145,80,6,'Dissect an owl pellet and explain what you found.');
INSERT INTO badge_optional_requirements VALUES(1146,80,7,'Learn about mimicry in nature. Why does one organism pretend to look or sound like something they are not? Be able to name at least 6 animals that use mimicry as a survival technique and know the model each is mimicking.');
INSERT INTO badge_optional_requirements VALUES(1147,80,8,'Be able to explain what a biome is. Discuss the characteristics of the following biomes: Deserts Tropical rain forests Savannas Temperate grasslands Temperate forests Tundra Taigas Chaparrals Aquatic communities.');
INSERT INTO badge_optional_requirements VALUES(1148,80,9,'Discuss the role of bacteria in biology. In what ways can bacteria be dangerous? How can they be helpful? How has humanity harnessed the power of bacteria in our society? What do we use them for?');
INSERT INTO badge_optional_requirements VALUES(1149,80,10,'Learn about careers that revolve around biology. Examples might be biologist, geneticist, lab technician, or ecologist. What education and training do you need? What salary can you expect? What type of hours might you need to work, and where might you need to live?');
INSERT INTO badge_optional_requirements VALUES(1150,80,11,'Participate in a community service project that involves biology. Examples might include helping to restore wetlands, building bird houses or other habitats for local animals, or volunteering at a local wildlife rescue facility.');
INSERT INTO badge_optional_requirements VALUES(1151,80,12,'Take a field trip to a lake, forest, river, wetland, etc. Keep a log of the plants and animals you see there. What type of food web do you think is present in this environment?');
INSERT INTO badge_optional_requirements VALUES(1152,82,3,'What types of flora (plants) live in your chosen biome?  Preschool: Draw one, Level 1: Draw two, Level 2: draw three, Level 3: draw four, Level 4: draw five, and Level 5: draw six.');
INSERT INTO badge_optional_requirements VALUES(1153,82,4,'What types of fauna (animals) live in your chosen biome? Preschool: Draw one, Level 1: Draw two, Level 2: draw three, Level 3: draw four, Level 4: draw five, and Level 5: draw six.');
INSERT INTO badge_optional_requirements VALUES(1154,82,5,'Make a 3D diorama of your chosen biome.  Be sure to include examples of both flora and fauna in their natural habitats.');
INSERT INTO badge_optional_requirements VALUES(1155,82,6,'Diagram the food web of your biome.');
INSERT INTO badge_optional_requirements VALUES(1156,82,7,'Learn about the climate of your biome.');
INSERT INTO badge_optional_requirements VALUES(1157,82,8,'Study the people who live in your biome.  Learn about their history, culture, way of life, etc.');
INSERT INTO badge_optional_requirements VALUES(1158,82,9,'Make a recipe popular from one of the cultures that live in your biome.');
INSERT INTO badge_optional_requirements VALUES(1159,82,10,'Make an edible version of your biome.');
INSERT INTO badge_optional_requirements VALUES(1160,82,11,'Learn about environmental and social challenges in your biome.  What can you do to help?');
INSERT INTO badge_optional_requirements VALUES(1161,82,12,'Make a poster or display board of what you’ve learned. Be sure to include your map, drawings and pictures from your research.');
INSERT INTO badge_optional_requirements VALUES(1162,82,13,'Be able to name at least five different kinds of biomes on earth, and briefly describe them.');
INSERT INTO badge_optional_requirements VALUES(1163,82,14,'Teach someone else several facts you have learned about your biome. Be sure to discuss fauna, flora, people, food, and climate.');
INSERT INTO badge_optional_requirements VALUES(1164,83,3,'Choose a bird that is at risk of being endangered, or is endangered. Make a poster, brochure or fliers encouraging others to save this species of bird. Include any necessary information and helpful advice.');
INSERT INTO badge_optional_requirements VALUES(1165,83,4,'What is your state bird? What is the national bird of the United States? Have you ever seen either of them? Where?');
INSERT INTO badge_optional_requirements VALUES(1166,83,5,'Talk to someone who lives in a different state. What species of birds do they see? What is their state bird?');
INSERT INTO badge_optional_requirements VALUES(1167,83,6,'What sort of equipment do bird-watchers use when bird-watching? Examples might include, binoculars, pen and paper, a tape recorder, indexes, etc.');
INSERT INTO badge_optional_requirements VALUES(1168,83,7,'Visit a zoo or aviary and look at the exotic birds. Where are they from? How do they differ from the birds you usually see in your yard?');
INSERT INTO badge_optional_requirements VALUES(1169,83,8,'Research different bird families, such as raptors, thrushes, flycatchers, woodpeckers and sapsuckers, waterbirds, etc. How are they different?');
INSERT INTO badge_optional_requirements VALUES(1170,83,9,'What types of careers involve birds? How much bird-watching is involved? What sort of education would you need, and where might you expect to work?');
INSERT INTO badge_optional_requirements VALUES(1171,83,10,'Identify different locations where bird-watching is popular, such as the Florida Everglades or Slimbridge in the U.K. What sorts of birds live there?');
INSERT INTO badge_optional_requirements VALUES(1172,83,11,'Go on a guided bird-watching tour. Make a log of the birds you see.');
INSERT INTO badge_optional_requirements VALUES(1173,83,12,'Watch a documentary on bird-watching.');
INSERT INTO badge_optional_requirements VALUES(1174,83,13,'Create something to attract birds to your yard, such as a bird feeder or a bird house. Observe for one week what types of birds come to it.');
INSERT INTO badge_optional_requirements VALUES(1175,83,14,'Earn the Birds badge at your level.');
INSERT INTO badge_optional_requirements VALUES(1176,83,15,'Participate in a community service project related to birds, such as helping to clean up a pond or wetland, or volunteering at your local zoo.');
INSERT INTO badge_optional_requirements VALUES(1177,83,16,'Research which plants can attract specific species of birds to your backyard. If possible, plant some to encourage the birds to visit.');
INSERT INTO badge_optional_requirements VALUES(1178,83,17,'Learn what “memory phrases” are. Read the book Bird Talk by Ann Jonas. Learn to identify at least three birds by their memory phrases.');
INSERT INTO badge_optional_requirements VALUES(1179,83,18,'Be able to identify male, female and juvenile birds of at least five different species.');
INSERT INTO badge_optional_requirements VALUES(1180,83,19,'Choose a part of a bird, such as feet or beak, and research how it differs between species. Why is this? How does what the birds eat affect what sort of beak they have?');
INSERT INTO badge_optional_requirements VALUES(1181,83,20,'Choose your favorite bird and make a poster or brochure about it. Be sure to include the following information: How many eggs does it lay? Does it mate for life? What is the population of this bird? What does it eat? Where does it live/what is its range? What sort of nest does it make? Does it need to live in large groups? Does it migrate? Where from and where to?');
INSERT INTO badge_optional_requirements VALUES(1182,83,21,'On a diagram of a bird, identify at least ten different parts. Examples include: Auriculars Back Belly Bill Breast Crown Ear patch Eyebrow Eye line Eye-ring Flank Greater upperwing coverts Lore Malar Mandible Mantle Maxilla Median upperwing coverts Nape Primaries Rump Scapulars Secondaries Side Submalar mark Supercilium Tail feathers Tarsus Tertials Throat Toes Undertail coverts Uppertail coverts Vent.');
INSERT INTO badge_optional_requirements VALUES(1183,84,3,'Research charities that throw birthday parties for the less fortunate. Volunteer with that charity if possible or gather donated party items that can be given to someone unable to afford a party.');
INSERT INTO badge_optional_requirements VALUES(1184,84,4,'Find out how people in other cultures celebrate their birthday. Make a poster on what you find. Preschool: Learn about one culture, Level 1: learn about two, Level 2: learn about three, Level 3: learn about four, Level 4: learn about five, Level 5: learn about six,');
INSERT INTO badge_optional_requirements VALUES(1185,84,5,'Find out the history of birthday cakes, candles, gifts, noise makers, hats, balloons and confetti. When did goodie bags get introduced?');
INSERT INTO badge_optional_requirements VALUES(1186,84,6,'Dedicate and plant a tree for a new baby you know being born.');
INSERT INTO badge_optional_requirements VALUES(1187,84,7,'Throw a birthday party for someone else (If you threw a party for someone else for Level 2 requirement 2, it does not count for this requirement.).');
INSERT INTO badge_optional_requirements VALUES(1188,84,8,'In your faith, is there a traditional birthday celebration of a prominent figure? (ex: Jesus, Buddha) Which religions group(s) do not celebrate birthdays and why?');
INSERT INTO badge_optional_requirements VALUES(1189,84,9,'Come up with ideas for a birthday party on a low budget. Ideas can be using recycled materials, using electronic invitations and thank you’s, timing the party between meals and just serving snacks.');
INSERT INTO badge_optional_requirements VALUES(1190,84,10,'Find out the history of pinatas. List three categories of things you can put in it. Make your own pinata. Find out what is the largest pinata in the world.');
INSERT INTO badge_optional_requirements VALUES(1191,84,11,'Research places other than a home where you can have a birthday party. Preschool: name two, Level 1: name three, Level 2: name four, Level 3: name five, Level 4: name six, Level 5: name seven. What would the cost be? How many people can it hold?');
INSERT INTO badge_optional_requirements VALUES(1192,84,12,'How many different versions of the birthday song can you find? Learn how to sing a new version and use it at your party or teach it to your troop.');
INSERT INTO badge_optional_requirements VALUES(1193,84,13,'List three companies that sell party supplies (online or at a store near you). Cost compare some of the items on your party list. Are there alternatives to buying them new? Come up with an idea to replace one item for free or using something recycled.');
INSERT INTO badge_optional_requirements VALUES(1194,84,14,'Find out your Astrological sign. Do you agree with the description? Do you believe the meaning of the Zodiac signs? Why, or why not?');
INSERT INTO badge_optional_requirements VALUES(1195,84,15,'List birthday party games and teach them to someone. Preschool: list two, Level 1: list three, Level 2: list four, Level 3: list five, Level 4: list six, Level 5: list seven.  Play one of them at your party or with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(1196,84,16,'Find out how royalty celebrate their birthdays. Name at least two royal figures and research their most recent birthday celebration.');
INSERT INTO badge_optional_requirements VALUES(1197,84,17,'Research types of careers involved in throwing a birthday party. (Ex: professional cake decorator, entertainers, planners, caterers). Research one specific career. What is the average salary? Is any specific education required or helpful? If possible, shadow someone in that career or interview someone that has a career in the birthday party industry.');
INSERT INTO badge_optional_requirements VALUES(1198,85,3,'Organize a family or group board game day.');
INSERT INTO badge_optional_requirements VALUES(1199,85,4,'Write instructions for a simple game you enjoy.');
INSERT INTO badge_optional_requirements VALUES(1200,85,5,'List at least 5 tips that would help someone who was learning how to play your favorite board game.');
INSERT INTO badge_optional_requirements VALUES(1201,85,6,'Teach a favorite board game to other children.');
INSERT INTO badge_optional_requirements VALUES(1202,85,7,'Learn the tournament rules for a board game, and then play that board game in a family or group tournament.');
INSERT INTO badge_optional_requirements VALUES(1203,85,8,'Visit a board game tournament (chess or any other board game) and tell your troop about it.');
INSERT INTO badge_optional_requirements VALUES(1204,85,9,'Play a board game that will help you practice your math, spelling, or another skill that helps you in your schoolwork.');
INSERT INTO badge_optional_requirements VALUES(1205,85,10,'Organize a board game drive for a local children’s charity.');
INSERT INTO badge_optional_requirements VALUES(1206,85,11,'List 5 benefits of playing table top games.');
INSERT INTO badge_optional_requirements VALUES(1207,85,12,'Visit a local game store. Take note of whether they have a regularly scheduled board game day, sponsor a board game club or events, scheduled demonstrations of new board games, and if they have a website.');
INSERT INTO badge_optional_requirements VALUES(1208,85,13,'With your family or group, create “on the go” game packets to be distributed in food baskets or military care packages. (Examples: Yahtzee, Farkle, etc)');
INSERT INTO badge_optional_requirements VALUES(1209,85,14,'Discover a board game that would teach about animals and tell your family, friends, or group about it.');
INSERT INTO badge_optional_requirements VALUES(1210,85,15,'Ask your local game store to carry a game they don’t already have.  Be able to explain why this particular game would be popular and would sell in their store.');
INSERT INTO badge_optional_requirements VALUES(1211,85,16,'Explain why it is important to have an age rating on board games.');
INSERT INTO badge_optional_requirements VALUES(1212,85,17,'With your parents, create a plan to buy a board game that is right for your age group. Choose a board game you might like to purchase. Compare the price for this game at three different stores – preferably comparing a local games store, a chain store, and an online board game retailer. Decide what store has the best deal. In your decision, be sure to consider things like the store return policy and shipping costs.');
INSERT INTO badge_optional_requirements VALUES(1213,85,18,'Put together 2 file folder games for a teacher’s classroom, either from materials you find on the internet or ones you create yourself.');
INSERT INTO badge_optional_requirements VALUES(1214,85,19,'Learn how a board game is produced, from idea inception to marketing and report it to  your family, friends, or group. Investigate how large manufacturing companies produce thousands of copies of the same game. Investigate how a small independent person or company might produce a small quantity of games.');
INSERT INTO badge_optional_requirements VALUES(1215,85,20,'Survey at least 8 family members and friends to determine what their favorite type of board game is, such as chance, knowledge, strategy, etc. Make a chart to show the results of your survey.');
INSERT INTO badge_optional_requirements VALUES(1216,85,21,'Look at the parts of a game.  Suggest ways to make the game more eco-friendly in its design and packaging.');
INSERT INTO badge_optional_requirements VALUES(1217,85,22,'Volunteer to help at a local library or school game day event.');
INSERT INTO badge_optional_requirements VALUES(1218,85,23,'Read a biography of George Parker or Milton Bradley or another board game pioneer.');
INSERT INTO badge_optional_requirements VALUES(1219,85,24,'Think of 2 different board games that you enjoy. Write down 3 ways they are the same and 3 ways they are different.');
INSERT INTO badge_optional_requirements VALUES(1220,85,25,'Use a different board game for each answer that you write. Name a game that: Uses dice Has markers Uses money Requires math Involves strategy Has cards Requires a pencil Involves mostly luck.');
INSERT INTO badge_optional_requirements VALUES(1221,85,26,'Design an advertisement for your favorite board game.');
INSERT INTO badge_optional_requirements VALUES(1222,85,27,'Interview a local game store owner, employee, board game designer/developer or game company representative.  Find out why they choose to work in this field and what skills and education are needed.  Find out what they enjoy most about their job.');
INSERT INTO badge_optional_requirements VALUES(1223,85,28,'When you play a board game with 2 dice, you have a higher chance of rolling a 7 than any other number. Explain to a parent or leader why you think this is true. What 2 numbers do you have the lowest chance of rolling? Why?');
INSERT INTO badge_optional_requirements VALUES(1224,85,29,'For Level 4 only –  (A) Find out if your local high school or favorite college has a game club. If so, email them or read their website to see what activities they offer. Report to your troop or family. AND (B) Discuss with your family their views on the appropriateness of gambling games.');
INSERT INTO badge_optional_requirements VALUES(1225,86,3,'Learn the difference between rope & line. Learn how to tie at least (2) knots commonly used in boating.');
INSERT INTO badge_optional_requirements VALUES(1226,86,4,'Learn and demonstrate basic first aid procedures for the following: sunburn, minor cut and blisters.');
INSERT INTO badge_optional_requirements VALUES(1227,86,5,'Attend a boating show or seminar.');
INSERT INTO badge_optional_requirements VALUES(1228,86,6,'Go for a boat ride and follow all rules and safety procedures.');
INSERT INTO badge_optional_requirements VALUES(1229,86,7,'Learn about twisted rope vs. braided rope, understand the advantages and disadvantages of each.');
INSERT INTO badge_optional_requirements VALUES(1230,86,8,'Earn your Water Safety badge at your level.');
INSERT INTO badge_optional_requirements VALUES(1231,86,9,'Earn your First Aid badge at your level.');
INSERT INTO badge_optional_requirements VALUES(1232,86,10,'Earn your Swimming badge at your level.');
INSERT INTO badge_optional_requirements VALUES(1233,86,11,'Create a PSA such as a Powerpoint, radio, or video commercial to explain any local laws/requirements for having a properly outfitted vessel (lifejackets, personal flotation devices, and/or throwable flotation devices).');
INSERT INTO badge_optional_requirements VALUES(1234,86,12,'Demonstrate appropriate visual signals for communicating vessel distress or an emergency situation to a passing boater.');
INSERT INTO badge_optional_requirements VALUES(1235,86,13,'Learn about Marine Patrol or Harbor Patrol. What is their purpose and what do they do to help boaters?');
INSERT INTO badge_optional_requirements VALUES(1236,86,14,'Explain the difference between aerial and hand-held flares. Explain the advantages and disadvantages of both.');
INSERT INTO badge_optional_requirements VALUES(1237,86,15,'Earn your Fire Safety badge at your level.');
INSERT INTO badge_optional_requirements VALUES(1238,86,16,'If you have access to a vessel, inspect the vessel for proper safety equipment according to your state laws.');
INSERT INTO badge_optional_requirements VALUES(1239,86,17,'Attend a boating safety course or class and obtain a license, card or certificate.');
INSERT INTO badge_optional_requirements VALUES(1240,88,3,'Make your own cover boards from recycled materials or cardboard');
INSERT INTO badge_optional_requirements VALUES(1241,88,4,'Decorate your book with a hand-drawn title page or cover design.');
INSERT INTO badge_optional_requirements VALUES(1242,88,5,'Design and make a bookplate.');
INSERT INTO badge_optional_requirements VALUES(1243,88,6,'Tour the mending department of your local library. Learn how they preserve the books and keep them in good repair.');
INSERT INTO badge_optional_requirements VALUES(1244,88,7,'Visit somewhere with examples of well bound books. These may be in a private collection, in a museum, or even your public library.');
INSERT INTO badge_optional_requirements VALUES(1245,88,8,'Visit a professional bookbinder.');
INSERT INTO badge_optional_requirements VALUES(1246,88,9,'Make simple design and tool a leather book cover.');
INSERT INTO badge_optional_requirements VALUES(1247,88,10,'Bind a set of music sheets or magazines.');
INSERT INTO badge_optional_requirements VALUES(1248,88,11,'Make a file by binding together envelopes between strong covers.');
INSERT INTO badge_optional_requirements VALUES(1249,88,12,'Bind a book using the method of your choice that you have not used in previous requirements.');
INSERT INTO badge_optional_requirements VALUES(1250,88,13,'Learn what endpapers are and make some hand decorated endpapers. Try using rubber stamps, finger paint, marbling, stenciling or any other method of your choice.');
INSERT INTO badge_optional_requirements VALUES(1251,88,14,'View a documentary on book binding, or view videos of bookbinding. Several good videos can be found on YouTube if you search “book bindery tour.” Do not use YouTube without parental supervision.');
INSERT INTO badge_optional_requirements VALUES(1252,88,15,'Know the meaning of the following terms: First edition Volume Manuscript Autographed copy Bookplate End paper Signature Parchment Vellum Deckle edge Headbands');
INSERT INTO badge_optional_requirements VALUES(1253,88,16,'Interview or shadow someone who works in bookbinding, book restoration, or publishing');
INSERT INTO badge_optional_requirements VALUES(1254,88,17,'Learn how to fold signatures and assemble them in correct page order');
INSERT INTO badge_optional_requirements VALUES(1255,88,18,'Explore how glue, thread, and tools like bone folders are used in bookbinding');
INSERT INTO badge_optional_requirements VALUES(1256,88,19,'Write and illustrate your own short story or journal and bind it into a finished book');
INSERT INTO badge_optional_requirements VALUES(1257,88,20,'Make a handmade book to give as a gift or donate to a community organization');
INSERT INTO badge_optional_requirements VALUES(1258,88,21,'Research a famous bookbinder, historical or modern, and what they contributed to the craft');
INSERT INTO badge_optional_requirements VALUES(1259,88,22,'Learn how to repair a torn page or damaged spine in a book you already own');
INSERT INTO badge_optional_requirements VALUES(1260,88,23,'Try making a miniature book or zine');
INSERT INTO badge_optional_requirements VALUES(1261,88,24,'Visit a print shop, bookbindery, or museum exhibit featuring handmade books or historical manuscripts');
INSERT INTO badge_optional_requirements VALUES(1262,88,25,'Create a book using eco-friendly or recycled materials');
INSERT INTO badge_optional_requirements VALUES(1263,88,26,'Compare the durability and function of different binding methods');
INSERT INTO badge_optional_requirements VALUES(1264,88,27,'Make a notebook or sketchbook using handbound techniques');
INSERT INTO badge_optional_requirements VALUES(1265,88,28,'Help organize a book-themed art show or handmade book display for your group or library');
INSERT INTO badge_optional_requirements VALUES(1266,88,29,'Learn how embossing, gilding, or marbling are used to decorate book covers');
INSERT INTO badge_optional_requirements VALUES(1267,90,3,'Learn a skill that was represented in your book. This might be a dance, song, game deciphering codes, building something, sewing something, etc.');
INSERT INTO badge_optional_requirements VALUES(1268,90,4,'Hold a book club event to discuss the messages in your book. You can even earn the Book Club badge at your level!');
INSERT INTO badge_optional_requirements VALUES(1269,90,5,'Do a dramatic reading from your book for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(1270,90,6,'Watch a movie that was made from your book and discuss the differences between the movie and the book.');
INSERT INTO badge_optional_requirements VALUES(1271,90,7,'Write a short essay or discuss with others how the main character(s) changes throughout the book. What causes these changes?');
INSERT INTO badge_optional_requirements VALUES(1272,90,8,'Hold a costume party where guests dress as characters from the book and try to serve food similar to that in the book..');
INSERT INTO badge_optional_requirements VALUES(1273,90,9,'Find out if there are any licensed products being sold that use characters and items from your book. Make a list of everything you can find. What scenes/characters seem to be the most popular?');
INSERT INTO badge_optional_requirements VALUES(1274,90,10,'Play or make a game based on your book.');
INSERT INTO badge_optional_requirements VALUES(1275,90,11,'Illustrate a scene from your book.');
INSERT INTO badge_optional_requirements VALUES(1276,90,12,'Learn about getting a book published. What is the difference between going through a publisher and self publishing? What are the advantages to each? How do they differ?');
INSERT INTO badge_optional_requirements VALUES(1277,90,13,'Learn about copyright law. How do you copyright a book you have written? How long is a copyright good for?');
INSERT INTO badge_optional_requirements VALUES(1278,90,14,'Participate in a community service project that involves books in some way. You might choose to hold a book drive, volunteer at your local library, or volunteer to read to young children.');
INSERT INTO badge_optional_requirements VALUES(1279,90,15,'Make some food or drink that is special to your book and try it. Requirements for specific books or book series: Hank the Cowdog Harry Potter Little House on the Prairie Little Women Louis L’Amour Wizard of Oz');
INSERT INTO badge_optional_requirements VALUES(1280,91,3,'Make a cover for your book. What is a book cover designer? What do they do?');
INSERT INTO badge_optional_requirements VALUES(1281,91,4,'Draw a map of where your book takes place and mark important places.');
INSERT INTO badge_optional_requirements VALUES(1282,91,5,'Design a family tree for you main characters.');
INSERT INTO badge_optional_requirements VALUES(1283,91,6,'Look into what it takes to publish your book. What is the difference between self-publishing and going through a publisher? Which one is easier? Which one is better? Which one would get your book out faster?  Which pays you more?');
INSERT INTO badge_optional_requirements VALUES(1284,91,7,'How is your book similar or different to an already published book in your genre? (Your favorite author perhaps.) Did you learn from it? How can reading books help your writing?');
INSERT INTO badge_optional_requirements VALUES(1285,91,8,'Learn what Fan Fiction is and write a Fan Fiction book based on the series of your choice.');
INSERT INTO badge_optional_requirements VALUES(1286,91,9,'How did people write books in the past centuries? Find out the process (and how much patience it took) to write, edit, and print your book before computers. What about before the printing press? How did books get mass-produced then?');
INSERT INTO badge_optional_requirements VALUES(1287,91,10,'Find out how much an average author earns. How can this range vary widely? Why is finding an average wage for an author difficult?');
INSERT INTO badge_optional_requirements VALUES(1288,91,11,'Learn about ways to sell your book if it was published. What would you sell it for? Are there marketing techniques that could help launch your book? How would you go about publishing and launching your book to get it out to the public eye? Use what you learned to make a marketing plan for your book.');
INSERT INTO badge_optional_requirements VALUES(1289,91,12,'How did you pick your genre for you book/short story? How would writing a non-fiction book be different than writing a fiction book? What about a historical fiction book? Sci-Fi? Text book? A guide? How much more research would the author have to do than in a fiction story? Why?');
INSERT INTO badge_optional_requirements VALUES(1290,91,13,'On the cover flap of all kinds of books of all genres, there is an about the author write up. Find and read at least three about the authors in books in the same genre as yours. Write your own about the author for your book or short story. Keep it short and like the ones you read. If you make it too long or detailed, the readers will get bored and not read it.');
INSERT INTO badge_optional_requirements VALUES(1291,91,14,'How do illustrations augment a book? What books have more or less illustrations? Why? Illustrate a page of your book. How does the picture add to your words? Make sure, if the picture was taken away, the reader could still understand what’s going on through the words. A illustration in a chapter book should never take place of words, only aid them. How might this be different in a children’s book?');
INSERT INTO badge_optional_requirements VALUES(1292,91,15,'Participate in a book writing contest or event, such as NaNoWriMo.');
INSERT INTO badge_optional_requirements VALUES(1293,91,16,'Read a biography about an author. How did they become an author? Why did they become an author?');
INSERT INTO badge_optional_requirements VALUES(1294,91,17,'Do you need both a hero and a villain to create a good story? Or can you just have a hero without a villain? Think of a few books (children books are good examples) where there is no villains, just problems the protagonist must overcome. How is this type of story different from a hero versus villain story?  What is a “slice of life” story?');
INSERT INTO badge_optional_requirements VALUES(1295,91,18,'What is a stand alone book, a series, and a trilogy? How would the ends of each book be different? Such as, if you have a stand alone, you will not end with a giant cliff hanger, but if you are writing a series, you probably will (but don’t have too) so the readers will be anxiously awaiting your next book. Think of your feelings when you read a stand alone (or the last book of a series) and the nice wrapped up ending. Now think about your feelings when the book ends a cliff hanger? What is your book’s ending?');
INSERT INTO badge_optional_requirements VALUES(1296,91,19,'Interview an author.');
INSERT INTO badge_optional_requirements VALUES(1297,91,20,'Earn the writing badge at your level.');
INSERT INTO badge_optional_requirements VALUES(1298,91,21,'Earn the books badge at your level.');
INSERT INTO badge_optional_requirements VALUES(1299,91,22,'Publish your book or short story after it has been edited by at least one other person besides yourself. You can send it to a publisher, or you can self-publish.');
INSERT INTO badge_optional_requirements VALUES(1300,92,3,'Learn about seeds. How are they created? How do they germinate? How many different types of seeds can you come up with? Design a seed coat, or testa.');
INSERT INTO badge_optional_requirements VALUES(1301,92,4,'Learn about monocotyledons and dicotyledons. Go out and find as many as you can in your area.');
INSERT INTO badge_optional_requirements VALUES(1302,92,5,'Learn about flowers. Do a flower dissection (cannot be a composite flower. Must have visible stamens and carpel, like a tulip). Create a page by gluing your flower parts on a piece of paper and labeling each part. Parts you should end up with are: sepals & calyx, petals & corolla, stamen, filament, anther, carpel, stigma and ovary.  **Warning: a sharp knife may be needed for some items so please have adult supervision and help.** What is the difference between a simple flower and a composite flower?');
INSERT INTO badge_optional_requirements VALUES(1303,92,6,'Learn about carnivorous plants. If possible, go check some live ones out. Learn how they live/work. What does the plant get out of the animals it catches? How do they catch their prey. The more common plants are Venus flytrap, bladderwort, pitcher plant and sundews. Each have different ways in which they trap prey and how they digest their victims.');
INSERT INTO badge_optional_requirements VALUES(1304,92,7,'Learn about pollination. There are several different ways in which pollination occurs. Find out the different ways. Learn about nectar guides.');
INSERT INTO badge_optional_requirements VALUES(1305,92,8,'What is botanically a fruit and a vegetable? Learn about the different types of each. Examples: leaves, stems, roots, berries, pepos, pomes, hesperidium, grains, legumes, nuts, etc. Take some foods that you eat and try to classify each.');
INSERT INTO badge_optional_requirements VALUES(1306,92,9,'Learn about how seeds are dispersed. Take a look around where you live and see what you can find for seeds and how you think they were dispersed.');
INSERT INTO badge_optional_requirements VALUES(1307,92,10,'Learn about photosynthesis and chlorophyll. What does a plant need in order to survive? Why do some leaves change color?');
INSERT INTO badge_optional_requirements VALUES(1308,92,11,'Learn about leaves. Learn about leaf anatomy, how they are shaped, arranged, venation and margins. Create a leaf classification chart. You can find leaves that have already fallen off the plant or take pictures. Please do not pull leaves off the plant to do this. Why are leaves important to both the plant and to us?');
INSERT INTO badge_optional_requirements VALUES(1309,92,12,'Learn about roots. How do they grow? What do they provide not only for the plant but also the area in which it lives? What different types of roots are there? What is geotropism? Find some roots and try to classify them. Please do not dig up or pull up anything without getting permission to do so first.');
INSERT INTO badge_optional_requirements VALUES(1310,92,13,'Learn about stems. What is phloem and xylem? What is phototropism? Learn about tree rings. Do the celery/carnation experiment (put a piece of celery/carnation in colored water and see how the leaves/petals change color over time. Also notice the small dots at the bottom of the stem, they are the xylem).');
INSERT INTO badge_optional_requirements VALUES(1311,92,14,'Learn how ferns and nonvascular plants reproduce.');
INSERT INTO badge_optional_requirements VALUES(1312,92,15,'Create a Lichenometer. Using a coat hanger, yarn, and trees with lichen on them you can test the quality of your air. Bend your coat hanger into the shape of an oval. Cut several pieces of yarn about 10 inches long and 3 pieces of yarn about 20 inches long. Tie the yarn across the coat hanger to make a series of squares within the oval of your coat hanger. It should look something like a tennis racket when you are done. This is your Lichenometer. Place your meter against a tree and count how many squares are filled by lichen. Only count squares that are completely filled. Take the total number of squares that are completely filled with lichen and divide by the total number of squares on your Lichenometer. Then, multiply by 100. The result would be the percentage your meter was filled with lichen. You can compare different areas around where you live and see where the air quality is better. The more lichen, the better the air quality.');
INSERT INTO badge_optional_requirements VALUES(1313,92,16,'Make and use a botany journal.');
INSERT INTO badge_optional_requirements VALUES(1314,92,17,'Earn at your level one of the badges that has to do with botany, such as trees, flowers or gardening.');
INSERT INTO badge_optional_requirements VALUES(1315,92,18,'Do some sort of community service that involves botany. Examples might be to help with a BioBlitz or volunteer at a greenhouse.');
INSERT INTO badge_optional_requirements VALUES(1316,92,19,'Visit a place that deals with botany such as a greenhouse or botanical gardens. Levels 3 & Up: Create a written report, a scrapbook, poster, or  video presentation to share with your troop that includes what you saw and learned.  Include some identifications on things you learned about elsewhere in this badge. Examples include: angiosperms, gymnosperms or different types of leaves or different types of flowers.');
INSERT INTO badge_optional_requirements VALUES(1317,92,20,'Research careers involving botany. What education is necessary? What pay and work schedule can you expect? If possible, shadow a botanist for a day.');
INSERT INTO badge_optional_requirements VALUES(1318,92,21,'After completing Level 4 requirement 2, plant your planned garden. Were you able to plant it as planned? If not, why? Share your garden with your family, friends, or troop.');
INSERT INTO badge_optional_requirements VALUES(1319,93,3,'Explain how the difficulty of climbs are classified.');
INSERT INTO badge_optional_requirements VALUES(1320,93,4,'Find out what competitions there are for bouldering in both indoor and outdoor settings. Describe at least two different formats for competition.');
INSERT INTO badge_optional_requirements VALUES(1321,93,5,'Learn about the history of bouldering as a sport. How did it evolve?');
INSERT INTO badge_optional_requirements VALUES(1322,93,6,'Read a short biography about a famous climber.');
INSERT INTO badge_optional_requirements VALUES(1323,93,7,'Learn about modern climbing shoes and how they are constructed.');
INSERT INTO badge_optional_requirements VALUES(1324,93,8,'Learn the difference between static and dynamic climbing movements and attempt one of each in a safe manner.');
INSERT INTO badge_optional_requirements VALUES(1325,93,9,'What exercises can you do to help strengthen and prepare you for bouldering? Create an exercise routine and stick to it for one month.');
INSERT INTO badge_optional_requirements VALUES(1326,93,10,'Learn about careers regarding bouldering. This might include jobs like a climbing instructor, shoe manufacturer, website blogger, etc. What skills and education is necessary for one of these jobs?');
INSERT INTO badge_optional_requirements VALUES(1327,93,11,'Participate in a community service project related to bouldering. This could be anything from planting trees to help with erosion to a trail trash pick up to volunteering to help with a completion.');
INSERT INTO badge_optional_requirements VALUES(1328,93,12,'Learn about some of the most famous and/or extreme bouldering locations in the world. If you could climb at one, which one would you choose and why?');
INSERT INTO badge_optional_requirements VALUES(1329,95,3,'Watch a documentary on braille.');
INSERT INTO badge_optional_requirements VALUES(1330,95,4,'Participate in a community service or volunteer project that helps the blind in some way.');
INSERT INTO badge_optional_requirements VALUES(1331,95,5,'Research careers involving braille, such as a braille transcriber. What type of education do you need? What does the job involve?');
INSERT INTO badge_optional_requirements VALUES(1332,95,6,'Observe how many establishments or buildings use braille, such as on bathroom signs, stairwells, or next to entrances. Visit several different buildings and make a list of how many signs you notice that have braille.');
INSERT INTO badge_optional_requirements VALUES(1333,95,7,'Pick one famous person who was blind and either read a biography on them or watch a movie based on their life. How did they overcome their struggles?');
INSERT INTO badge_optional_requirements VALUES(1334,95,8,'Learn about braille music. How is it different from literary braille? Learn at least three braille music symbols and syntax. Also, learn about the life of a famous blind musician.');
INSERT INTO badge_optional_requirements VALUES(1335,95,9,'Transcribe at least one sentence into braille.');
INSERT INTO badge_optional_requirements VALUES(1336,95,10,'Interview someone who is blind, either in person, online or over the phone. How has braille helped improve their life for the better?');
INSERT INTO badge_optional_requirements VALUES(1337,95,11,'What is binary coding and how does it relate to braille?');
INSERT INTO badge_optional_requirements VALUES(1338,96,3,'Learn the history of bread.');
INSERT INTO badge_optional_requirements VALUES(1339,96,4,'Mill flour for baking bread. How should you store whole grain flour? How long does it last as flour? How long does grain last before milling?');
INSERT INTO badge_optional_requirements VALUES(1340,96,5,'Visit a flour mill.');
INSERT INTO badge_optional_requirements VALUES(1341,96,6,'Visit a bakery. How do they bake bread? What types of bread do they sell?');
INSERT INTO badge_optional_requirements VALUES(1342,96,7,'Visit a farm where wheat is grown.');
INSERT INTO badge_optional_requirements VALUES(1343,96,8,'Start and feed a sourdough starter.  Bake a loaf of sourdough bread.');
INSERT INTO badge_optional_requirements VALUES(1344,96,9,'What is quick bread and how does it differ from traditional breads?  Make one type of quick bread.');
INSERT INTO badge_optional_requirements VALUES(1345,96,10,'Bake bread for someone not in your family and deliver it.');
INSERT INTO badge_optional_requirements VALUES(1346,96,11,'Experiment with baking white bread, whole wheat and a blend. How are the breads different? Which do you prefer?');
INSERT INTO badge_optional_requirements VALUES(1347,96,12,'Learn to bake the traditional bread from a different culture (pita, enjeera, naan, etc).');
INSERT INTO badge_optional_requirements VALUES(1348,96,13,'Earn the Grain badge at your level.');
INSERT INTO badge_optional_requirements VALUES(1349,96,14,'Discuss bread as a term for money. What is a “breadwinner”? What is a “bread line”?');
INSERT INTO badge_optional_requirements VALUES(1350,96,15,'Bake a loaf of gluten free bread.');
INSERT INTO badge_optional_requirements VALUES(1351,96,16,'Learn about the ovens used to bake artisan breads. What special techniques do they use to improve bread?');
INSERT INTO badge_optional_requirements VALUES(1352,96,17,'Find out what sort of jobs are in this field  What sort of education do these people have?  What sort of pay and work hours?');
INSERT INTO badge_optional_requirements VALUES(1353,96,18,'Participate in a community service project regarding bread.');
INSERT INTO badge_optional_requirements VALUES(1354,96,19,'Bake a loaf of bread that has nuts, raisins, cheese, chocolate, etc.');
INSERT INTO badge_optional_requirements VALUES(1355,97,3,'Over the years Breyer has made several models and molds based off of horses from literature and real life. Pick one of their many molds and design a model based off of an animal you know OR pick one of their models based off of a real animal (such as Secretariat or Blueberry Wine) or a famous animal in literature (such as Black Beauty or Benji) and write an essay about the animal.');
INSERT INTO badge_optional_requirements VALUES(1356,97,4,'What is Breyerfest and where is it held every year? When did it start? What makes it unique?');
INSERT INTO badge_optional_requirements VALUES(1357,97,5,'What was Just About Horses (JAH)? How did it spread the word about Breyer? Why did Breyer stop printing it? Find a copy to read if possible.');
INSERT INTO badge_optional_requirements VALUES(1358,97,6,'What is the North American Model Horse Show Association (NAMHSA) and why is it important to many serious Breyer collectors?');
INSERT INTO badge_optional_requirements VALUES(1359,97,7,'What is tack? What can it be made of? Make a piece of tack for a Breyer horse (1/8th ribbon is excellent for beginner halters and brides. Making saddles are recommended only for advanced crafters.)');
INSERT INTO badge_optional_requirements VALUES(1360,97,8,'Many collectors take photos of their models with in-scale objects to make the scene look as realistic as possible. Some people send in their photos to be in a model horse photo show. Try taking an in-scale photo with your model horse.');
INSERT INTO badge_optional_requirements VALUES(1361,97,9,'What is customization? Why would artists and collectors want to do this to a model? Find pictures of at least three different Breyer customizations, visit an exhibit, or show that has them available for viewing or for sale.  If you would like to try this, find a guide online and use a “body” quality model. DO NOT use any expensive models! The recommended size for beginners is Breyer’s Mini Whinnies, Stablemate, and Classic sizes due to cheap cost.');
INSERT INTO badge_optional_requirements VALUES(1362,97,10,'What is the difference between Unrealistic and Realistic coloring? What are the four most common Unrealistic colorings on a Breyer?');
INSERT INTO badge_optional_requirements VALUES(1363,97,11,'Participate in Breyer Fun Day, Breyer West, Breyerfest, or another Breyer special event.');
INSERT INTO badge_optional_requirements VALUES(1364,97,12,'Find out what it means to be retired. What does it mean to break a mold? What Breyerfest model specifically had its mold broken?');
INSERT INTO badge_optional_requirements VALUES(1365,97,13,'Collectors use many acronyms to quickly describe their models. Define the following acronyms: RR LE OOAK NIB/MIB OF CM LSQ/PSQ COA');
INSERT INTO badge_optional_requirements VALUES(1366,97,14,'What is Breyer’s Collectors Club? What are the different types of membership? What are the benefits of membership?');
INSERT INTO badge_optional_requirements VALUES(1367,97,15,'How has the type of plastic changed the design of the molds over the years? Compare a Chris Hess mold with a Kathleen Moody mold. What are the differences?');
INSERT INTO badge_optional_requirements VALUES(1368,97,16,'What happens to some Breyers as they age? How can you prevent Vinegar Syndrome, oozing, shrinking, yellowing, and warping?');
INSERT INTO badge_optional_requirements VALUES(1369,97,17,'Research porcelain, china, and resin model horses. What are the pros and cons of these models? Why doesn’t Breyer create models often in these materials?');
INSERT INTO badge_optional_requirements VALUES(1370,97,18,'Research Peter Stone, Hagen Renaker, and other alternative model horse brands, as well as artists who create and cast their own models like Mel Miller or Maggue Bennett. Why is Breyer the most popular, and what are the pros and cons of these alternative brands?');
INSERT INTO badge_optional_requirements VALUES(1371,97,19,'What is the most expensive Breyer ever sold at auction? Why do you think this horse went for so much?');
INSERT INTO badge_optional_requirements VALUES(1372,97,20,'How has the design of Breyer boxes changed over the years?');
INSERT INTO badge_optional_requirements VALUES(1373,97,21,'What is a drastic custom? How do these models differ from other customs?');
INSERT INTO badge_optional_requirements VALUES(1374,98,3,'Earn the Tower of London badge at your level.');
INSERT INTO badge_optional_requirements VALUES(1375,98,4,'Make your own set of Crown Jewels.');
INSERT INTO badge_optional_requirements VALUES(1376,98,5,'Learn about a famous person connected with the Crown Jewels, such as King John, Queen Victoria, or Colonel Blood.');
INSERT INTO badge_optional_requirements VALUES(1377,98,6,'Make a graph of the different stones used in the Crown Jewels. How many rubies, pearls, emeralds, diamonds, sapphires, etc., are there in the Crown Jewels? What is the total value of the Crown Jewels in today’s money?');
INSERT INTO badge_optional_requirements VALUES(1378,98,7,'Learn which gemstones are in the Crown Jewels. Which famous stones are there? Are there any legends about any of the stones?');
INSERT INTO badge_optional_requirements VALUES(1379,98,8,'Look at pictures of the crown jewels of other countries. How are they similar? How do they differ?');
INSERT INTO badge_optional_requirements VALUES(1380,98,9,'The Crown Jewels are kept in the Jewel House in the Tower of London. Visit the Tower of London and pay special attention to the Crown Jewels.');
INSERT INTO badge_optional_requirements VALUES(1381,98,10,'During the English Civil War, many of the Crown Jewels were melted down for the metal contained within them. Learn about the English Civil War. Which is the only Crown Jewel to survive the Civil War? How much did it cost to replace the Crown Jewels for Charles II’s coronation?');
INSERT INTO badge_optional_requirements VALUES(1382,98,11,'Make a poster or scrapbook page that shows what you learned while earning this badge.');
INSERT INTO badge_optional_requirements VALUES(1383,98,12,'Make a timeline of the history of the Crown Jewels. You must have at least 10 items on your timeline.');
INSERT INTO badge_optional_requirements VALUES(1384,98,13,'For many years, the jewels for the coronation would be hired for the occasion, and then the crown would be dismantled afterwards. When was this custom in effect?');
INSERT INTO badge_optional_requirements VALUES(1385,98,14,'Look at the robes that are worn at a coronation. Which is your favorite? How long have these robes been in use?');
INSERT INTO badge_optional_requirements VALUES(1386,98,15,'On what other occasions are the Crown Jewels used, besides coronations?');
INSERT INTO badge_optional_requirements VALUES(1387,98,16,'Which other members of the royal family wear crowns, besides the monarch? Look at pictures of some of their crowns. Which do you like best?');
INSERT INTO badge_optional_requirements VALUES(1388,99,3,'Only a very few other countries in the world today still have monarchies. Learn which countries these are, and be able to find them on a map.');
INSERT INTO badge_optional_requirements VALUES(1389,99,4,'Read a book or watch a documentary about a royal wedding, such as Prince William and Kate Middleton, Princess Anne and Captain Mark Philips, Prince Charles and Lady Diana Spencer, Prince Andrew and Sarah Ferguson, Princess Elizabeth (now Elizabeth II) and Prince Philip, Henry VIII and Anne Boleyn, etc.');
INSERT INTO badge_optional_requirements VALUES(1390,99,5,'Learn about the British monarchy before 800 AD.');
INSERT INTO badge_optional_requirements VALUES(1391,99,6,'Earn the British Crown Jewels badge at your level.');
INSERT INTO badge_optional_requirements VALUES(1392,99,7,'Learn about at least one of the royal palaces, either now (Windsor Castle, Balmoral, Buckingham Palace, Osborne House) or in the past (such as the Savoy Palace, Hatfield, or Woodstock).');
INSERT INTO badge_optional_requirements VALUES(1393,99,8,'Research how the monarchy in Britain has changed over time. What was the “divine right of kings”?');
INSERT INTO badge_optional_requirements VALUES(1394,99,9,'The Wars of the Roses were fought in the 1400’s AD over who would be the next king of England (At that time, the country we know as Britain today was two separate countries: England – which comprised modern-day England and Wales – and Scotland.). Learn about the Wars of the Roses. Who was Warwick the Kingmaker?');
INSERT INTO badge_optional_requirements VALUES(1395,99,10,'Be able to identify British monarchs other than the present one from portraits or pictures. Preschool and Level 1: Be able to identify at least one. Level 2: Be able to identify three. Level 3: Be able to identify five. Levels 4-5: Be able to identify eight.');
INSERT INTO badge_optional_requirements VALUES(1396,99,11,'Learn about the consorts (spouses – usually wives) of at least 3 of the British monarchs (If you choose Henry VIII, you need only learn about his wives, as long as you learn about each one of them.).');
INSERT INTO badge_optional_requirements VALUES(1397,99,12,'Understand the following terms: Abdication Ascension Coronation Dowager queen Heir apparent Regent Queen mother King/queen/prince consort');
INSERT INTO badge_optional_requirements VALUES(1398,99,13,'Learn fun facts about British monarchs. Preschool: Learn one fact. Levels 1-2: Learn three facts. Levels 3-4: Learn five facts. Level 5: Learn eight facts.');
INSERT INTO badge_optional_requirements VALUES(1399,99,14,'Read a biography of a famous British monarch.');
INSERT INTO badge_optional_requirements VALUES(1400,99,15,'The English Civil War was fought between the Royalists on one side, who favored the monarchy under the Stuart king Charles I and the Parliamentary forces. Learn about the English Civil War. What were some of the principal battles?');
INSERT INTO badge_optional_requirements VALUES(1401,99,16,'After the English Civil War, Oliver Cromwell established the Commonwealth. Learn about the Commonwealth.');
INSERT INTO badge_optional_requirements VALUES(1402,99,17,'Choose one of the royal dynasties, or “houses”, of Britain, such as the Tudors, the Stuarts, the Plantagenets, or the Windsors, and learn about them.');
INSERT INTO badge_optional_requirements VALUES(1403,99,18,'Memorize the names and dates of reign of the last 10 rulers of Britain (20 for Levels 4-5).');
INSERT INTO badge_optional_requirements VALUES(1404,99,19,'What was the Jacobite Rebellion? When did it occur? Who were Bonnie Prince Charlie, Sir John Cope and the Duke of Cumberland? What happened at Glencoe?');
INSERT INTO badge_optional_requirements VALUES(1405,99,20,'For centuries, Scotland was a separate country with its own royal family and its own government. Learn about the Scottish royal family. What was the Scottish royal palace called? Does it still exist?');
INSERT INTO badge_optional_requirements VALUES(1406,99,21,'Visit one of the British royal palaces.');
INSERT INTO badge_optional_requirements VALUES(1407,100,3,'Make at least 3 different homemade bubble wands. Use items such as coat hangers or pipe cleaners to create different sizes and shapes or use household items such as funnels, fly swatters, or slotted spoons.');
INSERT INTO badge_optional_requirements VALUES(1408,100,4,'Hold a bubble blowing contest and compete for things like the biggest bubble, the smallest bubble, the bubble that lasts the longest before popping, or the person who can pop the most bubbles.');
INSERT INTO badge_optional_requirements VALUES(1409,100,5,'Create a bubble painting. In a low, wide bowl, mix 1/4 cup dis detergent, 1/4 cup poster paint, and 1/2 cup water. Using a drinking straw, blow bubbles in the mixture until the bowl is filled with bubbles. Gently place some heavy paper (Such as cardstock) over the bubbles to catch their shape on the paper. For younger members, mix food color with bubble solution and blow bubbles directly onto the paper.');
INSERT INTO badge_optional_requirements VALUES(1410,100,6,'Create a bubble bottle. Fill a clear, empty water bottle 1/3 full with water, 1/3 full with liquid dish detergent and a little poster paint or food color. Put on the lid and shake until the bottle is full of bubbles.');
INSERT INTO badge_optional_requirements VALUES(1411,100,7,'Find out what the boiling point of water is. Why does boiling water make bubbles?');
INSERT INTO badge_optional_requirements VALUES(1412,100,8,'Add extra glycerin to your bubble mixture to the make the bubbles stronger and then blow some bubbles onto a paper plate. Quickly, before they pop, place the plate in the freezer. It doesn’t take long before the bubbles turn to ice crystals.');
INSERT INTO badge_optional_requirements VALUES(1413,100,9,'Sit inside a giant bubble. For this project you will need a LOT of bubble solution and it is recommended to add some extra glycerin to make sure your bubbles are strong. Fill a small wading pool with about an inch of bubble solution. Have a child stand in the center (or place a small stool for them to sit on). Carefully bring a hula hoop over their head and dip it in the solution. Very slowly, bring the hoop back up and over their head. As the hoop rises, the child should be completely inside the bubble.');
INSERT INTO badge_optional_requirements VALUES(1414,100,10,'Participate in a community service project that involves bubbles. You might choose to send bubbles to our soldiers overseas (Yes, they play with them too!), hold a bubble party for kids in your community, host a bubble science day to teach others about the science behind bubbles, or sell bubbles to raise money for a local charity.');
INSERT INTO badge_optional_requirements VALUES(1415,100,11,'Learn how a bubble machine works and use one.');
INSERT INTO badge_optional_requirements VALUES(1416,100,12,'Look at examples of how bubbles are used in art. This might be sculptures, photography, paintings, etc. Create a piece of bubble art yourself (you may not use projects you made in other requirements too fulfill this requirement).');
INSERT INTO badge_optional_requirements VALUES(1417,100,13,'Make a list of ways that bubbles are used in different products. Examples might include bubble wrap for packaging or candy bars with air bubbles.');
INSERT INTO badge_optional_requirements VALUES(1418,101,3,'Learn what a coupon is and how it is used. What does the expiration date mean? Find a coupon for something you, or someone in your family, wishes to purchase and use to reduce the price paid. Understand any terms and conditions written on the coupon. Learn how to find online coupons. What is the difference between a printable coupon, an online code, or a coupon that is scanned from a smart phone or tablet?');
INSERT INTO badge_optional_requirements VALUES(1419,101,4,'Learn to comparison shop. Look through weekly advertisements and compare at least 5 items that are sold at different stores. Who has the best deal? Know what price matching is and find out if any of the stores offer it.');
INSERT INTO badge_optional_requirements VALUES(1420,101,5,'Play a game of “The Price is Right.” Cut out pictures from recent advertisements and paste them on the front of a note card with the price listed on the back. Divide into team or play as individuals. Show the note cards one at a time. Each team must guess the price of the item. The team who gets closest to the price without going over gets a point. The team with the most points at the end of the game wins.');
INSERT INTO badge_optional_requirements VALUES(1421,101,6,'Plan a trip with an assigned budget. This could be your dream vacation, or a simple camp-out for your family, friends, or group. Make sure to include the following items: Transportation Lodging Food Entertainment Extra spending money for souvenirs or personal items');
INSERT INTO badge_optional_requirements VALUES(1422,101,7,'Play a game that involves budgeting. Good examples are board games such as Monopoly or computer games such as Lemonade Stand or Zoo Tycoon 2.');
INSERT INTO badge_optional_requirements VALUES(1423,101,8,'Plan a food budget for your family for one week. Have a parent tell you the amount you can spend and plan a week’s worth of menus without going over budget. How far under budget can you get and still have a variety of tasty and healthy meals? Discuss with a parent why sometimes healthier foods are more expensive than junk food.');
INSERT INTO badge_optional_requirements VALUES(1424,101,9,'Budgeting your time can be just as important as budgeting your money. Make a time budget for one week. Make sure to allow time for school, homework, sports or after school activities and recreation. If you budgeted 1 hour for homework, make sure you work hard and get your homework done in that hour. If you daydream or get sidetracked and it takes you two hours, where will the second hour come from? Will you take it from your recreation? Your sleep? Just like money, you only have so many hours in the day and you should use them wisely.');
INSERT INTO badge_optional_requirements VALUES(1425,101,10,'Hold a fundraiser for a local charity or good cause. Make a budget for how much you can spend on supplies and advertising and figure out how much profit you will make on items sold that can go toward your cause. How much will you have to sell just to break even?');
INSERT INTO badge_optional_requirements VALUES(1426,101,11,'Learn about jobs that involve budgeting. Examples might include a financial planner, an entrepreneur, a purchasing agent, or an estate planner. What salary could you expect for one of those jobs? What education would you need?');
INSERT INTO badge_optional_requirements VALUES(1427,101,12,'Understand how a credit card works and how the interest charged needs to be factored into your budget. Find out what the difference would be if you charged a $500 item on a credit card and only paid the minimum amount due each month verses paying it off immediately. How long would it take you to pay off? How much interest would you pay over that time?  What would be the final price paid for your item?');
INSERT INTO badge_optional_requirements VALUES(1428,101,13,'Unfortunately, debt is something many people struggle with. What are the most common types of debt? Learn how you can avoid debt, or, if you cannot, how quickly you can pay off debt and avoid interest if you budget well.');
INSERT INTO badge_optional_requirements VALUES(1429,102,3,'What type of sound do buffaloes make? Find a recording and listen to it.');
INSERT INTO badge_optional_requirements VALUES(1430,102,4,'Watch a documentary about buffalo.');
INSERT INTO badge_optional_requirements VALUES(1431,102,5,'Find at least three recipes that use buffalo meat. Make one if possible.');
INSERT INTO badge_optional_requirements VALUES(1432,102,6,'Learn about three different diseases that affect buffalo.');
INSERT INTO badge_optional_requirements VALUES(1433,102,7,'What are the buffalo’s predators? And how does the buffalo defend themselves?');
INSERT INTO badge_optional_requirements VALUES(1434,102,8,'What are the two “true” buffalo in the world?');
INSERT INTO badge_optional_requirements VALUES(1435,102,9,'Learn about the life cycle of a buffalo. What do their babies look like? How long do they live? How often do they have young?');
INSERT INTO badge_optional_requirements VALUES(1436,102,10,'Go to the zoo, or elsewhere, and visit a buffalo. Make sure to follow all safety rules, as buffalo can be dangerous. Third Party Resources; Smithsonian National Museum of American History Interactive Activities: Tracking the Buffalo, Stories from a Buffalo Hide Painting');
INSERT INTO badge_optional_requirements VALUES(1437,103,3,'Play a board game that involves earning and spending money, such as Monopoly or The Game of Life.');
INSERT INTO badge_optional_requirements VALUES(1438,103,4,'Visit a store and practice comparing unit prices to find the best deal.');
INSERT INTO badge_optional_requirements VALUES(1439,103,5,'Learn what a receipt is and identify the parts: item, quantity, cost, tax, and total.');
INSERT INTO badge_optional_requirements VALUES(1440,103,6,'Learn the difference between fixed and variable expenses.');
INSERT INTO badge_optional_requirements VALUES(1441,103,7,'Design a simple business (like a lemonade stand) and figure out what items you need to buy, how much they cost, and how much you’ll charge.  What will your profit be on each product?');
INSERT INTO badge_optional_requirements VALUES(1442,103,8,'Learn to calculate discounts and sale prices using percentages.');
INSERT INTO badge_optional_requirements VALUES(1443,103,9,'List 5 ways math is used in a business every day.');
INSERT INTO badge_optional_requirements VALUES(1444,103,10,'Learn how taxes and deductions affect your paycheck.  What taxes does your employer pay on your behalf?');
INSERT INTO badge_optional_requirements VALUES(1445,103,11,'Define what inventory carrying costs are and list the main types of expenses included (such as storage costs, insurance, depreciation, and opportunity cost)');
INSERT INTO badge_optional_requirements VALUES(1446,103,12,'Explore how to use a spreadsheet (like Excel or Google Sheets) to track income and expenses.');
INSERT INTO badge_optional_requirements VALUES(1447,103,13,'Learn about supply and demand using a hands-on activity or game.');
INSERT INTO badge_optional_requirements VALUES(1448,103,14,'Interview a small business owner and ask how they use math in their business.');
INSERT INTO badge_optional_requirements VALUES(1449,103,15,'Compare gross sales vs. net sales and why the difference matters.');
INSERT INTO badge_optional_requirements VALUES(1450,103,16,'Learn what a loan is and how repayment works including interest.  What is your total cost vs the amount your received from the loan?');
INSERT INTO badge_optional_requirements VALUES(1451,103,17,'Hold a fundraiser for your group.  Have participants create a small craft or food item (like decorated bookmarks or cookies) to sell.  Price out materials, estimate time, and decide how much to charge to make a profit.');
INSERT INTO badge_optional_requirements VALUES(1452,103,18,'Design a simple profit and loss report for your pretend business summarizing your income and expenses.');
INSERT INTO badge_optional_requirements VALUES(1453,103,19,'Learn what an invoice is and create one for a pretend product or service.');
INSERT INTO badge_optional_requirements VALUES(1454,103,20,'Research common business expenses like rent, utilities, payroll, and materials.  What is the average commercial rent per square foot where you live?');
INSERT INTO badge_optional_requirements VALUES(1455,103,21,'Explore how shipping costs affect product pricing in a business.');
INSERT INTO badge_optional_requirements VALUES(1456,103,22,'Calculate break-even point for a small pretend business: how many items do you need to sell to cover your costs?');
INSERT INTO badge_optional_requirements VALUES(1457,103,23,'Watch a video or tutorial about how entrepreneurs use math every day.');
INSERT INTO badge_optional_requirements VALUES(1458,103,24,'Study how businesses price products to include materials, shipping, storage, time, and profit.');
INSERT INTO badge_optional_requirements VALUES(1459,103,25,'Understand the following business math vocabulary terms: Profit Margin Return on Investment Commission Withdrawal Deposit Interest Unit Price Markup Net Profit Gross Profit Expenses Assets Liabilities');
INSERT INTO badge_optional_requirements VALUES(1460,104,3,'Donate a Cabbage Patch Kid doll or accessories to a charity of your choice.');
INSERT INTO badge_optional_requirements VALUES(1461,104,4,'Organize a picnic or tea party with you, your Cabbage Patch Kids and some friends.');
INSERT INTO badge_optional_requirements VALUES(1462,104,5,'How have Cabbage Patch Kids related to the US Olympic Teams in the past?');
INSERT INTO badge_optional_requirements VALUES(1463,104,6,'Watch a video of the Cabbage Patch Dance and try to recreate it on your own.');
INSERT INTO badge_optional_requirements VALUES(1464,104,7,'Read or have read to you a Cabbage Patch book.');
INSERT INTO badge_optional_requirements VALUES(1465,104,8,'Make your own commercial promoting Cabbage Patch Kids. What would you say to make other kids want to buy them?');
INSERT INTO badge_optional_requirements VALUES(1466,104,9,'Look into careers involving the toy industry, such as doll designers, working for a toy company, etc.');
INSERT INTO badge_optional_requirements VALUES(1467,104,10,'Learn about variations and extensions of Cabbage Patch Kids. When were they released? How are they different than the main Cabbage Patch Kids?');
INSERT INTO badge_optional_requirements VALUES(1468,105,3,'Decorate a cake for a family member, neighbor, or friend.');
INSERT INTO badge_optional_requirements VALUES(1469,105,4,'Look through cake decorating books or magazines and put together a scrapbook of ideas. Preschool: Collect at least 5 cake decorating ideas. Level 1:  Collect at least 8 cake decorating ideas. Level 2: Collect at least 12 cake decorating ideas. Level 3: Collect at least 20 cake decorating ideas. Level 4: Collect at least 25 cake decorating ideas. Level 5: Collect at least 30 cake decorating ideas.');
INSERT INTO badge_optional_requirements VALUES(1470,105,5,'Demonstrate decorating techniques using food instead of frosting. Examples might include daisies made of sliced marshmallows with M&M centers, an American Flag made of strawberries and blueberries, flowers molded out of fruit roll ups, etc. (If you did this requirement to earn the badge at a lower level, then you must choose different techniques): Preschool: Demonstrate at least one technique. Level 1: Demonstrate at least two techniques. Level 2: Demonstrate at least three techniques. Level 3: Demonstrate at least five techniques. Level 4: Demonstrate at least eight techniques. Level 5: Demonstrate at least ten techniques.');
INSERT INTO badge_optional_requirements VALUES(1471,105,6,'Learn the history of cake decorating.');
INSERT INTO badge_optional_requirements VALUES(1472,105,7,'Design your own cake based on a theme. What cake decorating tools would you need? What kind of frosting will work best? What type of coloring? Make your cake.');
INSERT INTO badge_optional_requirements VALUES(1473,105,8,'Watch a how to video on cake decorating or take a class.');
INSERT INTO badge_optional_requirements VALUES(1474,105,9,'Learn how to make fondant and how it can be used to frost or decorate a cake.');
INSERT INTO badge_optional_requirements VALUES(1475,105,10,'Level cakes are much easier to decorate and are necessary if you plan to have a multi-layered cake. Demonstrate the proper way to level and split cakes. Find at least 3 recipes for cake fillings and make one. Make a two layer (or more) cake, leveling it appropriately and using the filling you have chosen.');
INSERT INTO badge_optional_requirements VALUES(1476,105,11,'Mix marshmallow fluff with powdered sugar until you get a mold-able consistency. Work in food coloring to make it the color of your choice (wear rubber gloves for this to this to avoid staining your hands.) Use the dough to mold everything from Easter eggs to teddy bears. Be creative.');
INSERT INTO badge_optional_requirements VALUES(1477,105,12,'Learn to decorate using chocolate. Melt chocolate and pipe it into designs on a piece of wax paper. Once dry, you can peel off the design and you can stick it upright in your cake. You can also melt chocolate and “paint” it on leaves (make sure you use non-poisonous leaves only). Once dry, peel off the leaf and you will be left with a chocolate one. Learn to make chocolate curls. Fudge can be molded into a variety of shapes such as teddy bears and used as well.');
INSERT INTO badge_optional_requirements VALUES(1478,105,13,'Research careers involving cake decorating. What education is necessary? What pay and work schedule can you expect? Level 3 and Up Only: If possible, shadow a cake decorator for a day.');
INSERT INTO badge_optional_requirements VALUES(1479,106,3,'Make a poster about a mission showing what you’ve learned.');
INSERT INTO badge_optional_requirements VALUES(1480,106,4,'Look for the adobe walls on the mission. Find out how they were made. How long did they last? Find out why they do/do not last.');
INSERT INTO badge_optional_requirements VALUES(1481,106,5,'What was happening on the east side of America during that time.');
INSERT INTO badge_optional_requirements VALUES(1482,106,6,'How did the missions affect the Native Americans? Find out what the Native Americans who converted were called.');
INSERT INTO badge_optional_requirements VALUES(1483,106,7,'Make a model of a mission of your choice.');
INSERT INTO badge_optional_requirements VALUES(1484,106,8,'Find out how long Father Serra lived. Read a book about his life.');
INSERT INTO badge_optional_requirements VALUES(1485,106,9,'Find out how many original bells are still around from mission times.');
INSERT INTO badge_optional_requirements VALUES(1486,106,10,'Find out how long the missions lasted. Do you think they were successful?');
INSERT INTO badge_optional_requirements VALUES(1487,106,11,'Make a scrapbook of the missions making a page for each mission showing special facts about it.');
INSERT INTO badge_optional_requirements VALUES(1488,106,12,'Draw a map of “El Camino Real” and mark where the missions are along it.');
INSERT INTO badge_optional_requirements VALUES(1489,106,13,'If you live near a mission find out if there’s a way that you can help it keep running.');
INSERT INTO badge_optional_requirements VALUES(1490,106,14,'Make a timeline of the missions.');
INSERT INTO badge_optional_requirements VALUES(1491,106,15,'Tour one of the missions.');
INSERT INTO badge_optional_requirements VALUES(1492,107,3,'Visit a show or display of calligraphy or read a book that shows creative uses of several different alphabets.');
INSERT INTO badge_optional_requirements VALUES(1493,107,4,'Read a book about the history of calligraphy.');
INSERT INTO badge_optional_requirements VALUES(1494,107,5,'Investigate various writing surfaces. What are papyrus, parchment, vellum, scrolls, watermarks, handmade paper, and rice paper? Go to a store that sells a lot of different kinds of paper and see how many you can find that are nonabsorbent and smooth enough for calligraphy OR earn the Paper Crafting badge for your level. Levels 3 and Up: Also discuss what you would do to incorporate into your project some papers that are too absorbent to be used with calligraphy.');
INSERT INTO badge_optional_requirements VALUES(1495,107,6,'Learn about the work of a famous calligrapher or the calligraphy of the Medieval Era. What are illuminated pages? Manuscripts? Flourishes? Borders? Levels 4-5: Also take one of your alphabets you’ve written and add a border around it or some flourishes using more than one width of nibs.');
INSERT INTO badge_optional_requirements VALUES(1496,107,7,'What is the difference between calligraphy and lettering? Learn a fun alphabet and use it to make a gift or poster.');
INSERT INTO badge_optional_requirements VALUES(1497,107,8,'Using one of the alphabets you learned in Level 2 and 3 requirement 3, make a project such as a greeting card, book plates, invitations or a quote for your wall. Levels 4 – 5: Use one of the alphabets you learned in Level 4 requirement 2.');
INSERT INTO badge_optional_requirements VALUES(1498,107,9,'Play around with fonts on a computer and do at least three calligraphy-style projects on the computer. What are the advantages of doing calligraphy by hand?');
INSERT INTO badge_optional_requirements VALUES(1499,107,10,'Discuss the importance of the direction of the words to a project. Discuss the importance of weight-the thinness or thickness of letters. How can you design a project to emphasize certain words?');
INSERT INTO badge_optional_requirements VALUES(1500,107,11,'Use your calligraphy skills to help a non-profit organization-label place cards for a banquet, write thank you cards, make signs for the rooms at a conference or name cards for panel discussion participants, etc.');
INSERT INTO badge_optional_requirements VALUES(1501,108,3,'Learn how to dress appropriately for the weather. What gear will you need for rain, heat, wind, or overcast weather? Make a packing list for a two day (one night) camp out. What type of items will you need?  Make sure to include proper clothing, sleeping items, cooking equipment, first aid kit, lighting, etc.');
INSERT INTO badge_optional_requirements VALUES(1502,108,4,'Plan a menu for a two day (one night) camp out. What is your budget? Make a grocery list of items needed and their costs. If you go over budget, adjust your menu accordingly. What cooking equipment will you need to pack in order to prepare you menu?');
INSERT INTO badge_optional_requirements VALUES(1503,108,5,'Create a kaper chart for a two day (one night) camp out. How many jobs need to be assigned? How many people are going on your camp out? Can you assign jobs individually, or do you need to divide your group into patrols?');
INSERT INTO badge_optional_requirements VALUES(1504,108,6,'Learn about campground etiquette and make a poster to show others what you have learned.  Why is it important to show respect for others?');
INSERT INTO badge_optional_requirements VALUES(1505,108,7,'Learn how to properly roll and tie a sleeping bag. Make a carry strap to make it easier to carry without unrolling.');
INSERT INTO badge_optional_requirements VALUES(1506,108,8,'What do you look for in a good campsite? How does the lay of the land, water, and weather affect the desirability of a campsite? What amenities should be available? Design your dream campsite and make a map or poster of what it would look like.');
INSERT INTO badge_optional_requirements VALUES(1507,108,9,'Learn how to pack a cooler efficiently. What items need to be kept cool and how can you repackage them to make the most of your space. What are the advantages/disadvantages to using ice blocks verses ice cubes? What other methods can you use to help keep things cold? How can you keep food from getting wet?');
INSERT INTO badge_optional_requirements VALUES(1508,108,10,'Assist with meal preparation on your camp-out. Preschool & Level 1: Assist with at least one meal cooked outdoors. At this level kids do not have to cook, just assist with meal preparation and service. Level 2: Assist in cooking at least 2 meals cooked outdoors. Level 3, 4, & 5: Demonstrate how to cook at least one breakfast, lunch and dinner out of doors.');
INSERT INTO badge_optional_requirements VALUES(1509,108,11,'Demonstrate how to tie 1 (Preschool), 2 (Level 1), 4 (Level 2), 6 (Level 3), 7 (Level 4 & 5) of the following knots and explain when each should be used: Square Knot – for putting together ropes of equal thickness. Used when tying bundles; when fastening a sling bandage or splint; in mending broken strings, ropes or cords; for lengthening rope, mooring, or life saving lines. Sheet Bend – For putting together two ropes of unequal thickness; or for fastening an end to a permanent loop. Sheepshank – For taking up the slack in a rope. Bowline – May be used for a halter or life line. The loop can be made any size and will not jam or give. Hitching Tie – For tying halter ropes or mooring ropes to a post or ring. Archer’s Knot (Timber Hitch) – For stringing a bow or hauling timber Two Half Hitches or Clove Hitch – Both are used for fastening the end of a robe. Use at least 2 of these knots to create something for your camp out.');
INSERT INTO badge_optional_requirements VALUES(1510,108,12,'List the different types of camp lighting. What are the advantages and disadvantages of each?  Which are safest and which are least safe? Which are most and least expensive? Which one do you find easiest to use? Buy or borrow three different flashlights (or lanterns) and compare their performances. How far ahead of you does the light shine? Are they the same brightness? How expensive are they?');
INSERT INTO badge_optional_requirements VALUES(1511,108,13,'Learn some new things about the area of your campground. Be able to identify at least three new birds, trees, plants, or insects.');
INSERT INTO badge_optional_requirements VALUES(1512,108,14,'Make a list of fun camping activities such as games and songs to sing. Play one game with younger kids or teach your friends a new song or game. Are there any games on your list that need safety precautions?');
INSERT INTO badge_optional_requirements VALUES(1513,108,15,'Make up a game to teach younger kids an important camping skill and teach it to the younger members of your club.');
INSERT INTO badge_optional_requirements VALUES(1514,108,16,'Earn a Wild Edibles badge or Survival badge or make a handcraft using plant or mineral material found in the area of your campground. Make sure that whatever you use is allowed by the rules of that campground.');
INSERT INTO badge_optional_requirements VALUES(1515,108,17,'Visit a Cabela’s or Bass Pro Shop showroom. Pay special attention to the animal and natural displays. Find in at least two items you think would be helpful to own while camping.');
INSERT INTO badge_optional_requirements VALUES(1516,108,18,'Learn proper lashing techniques. Demonstrate the differences between diagonal lashing, square lashing, and continuous lashing. When should each be used Levels 3 and Up: Teach the younger kids in your club how to use basic lashing techniques to create a “God’s Eye” Craft. Using two sticks, lash them together with yarn in an X formation. Once lashed, wind the yarn around each stick in a clockwise direction until a diamond forms. When the diamond is the size you want, tie off the yarn using a square knot.');
INSERT INTO badge_optional_requirements VALUES(1517,108,19,'Learn about 3 different types of tents and the advantages/disadvantages of each.  Learn about 3 different types of sleeping bags and what conditions each is designed for.  Explain proper care and storage for sleeping bags and tents.');
INSERT INTO badge_optional_requirements VALUES(1518,108,20,'Research lightweight camp stoves. Explain the safety procedures when using a propane or butane stove and a liquid fuel stove. What are the advantages and disadvantages of each? Cook a sample meal for your club using a lightweight camp stove.');
INSERT INTO badge_optional_requirements VALUES(1519,108,21,'Discuss how the things you did to earn this badge have taught you about personal health and safety, survival, conservation, and good citizenship.');
INSERT INTO badge_optional_requirements VALUES(1520,109,3,'Learn about the Vikings, who were the first Europeans to visit Canada. Who was Lief Erikson?');
INSERT INTO badge_optional_requirements VALUES(1521,109,4,'Learn about the Red River Rebellion (also called the Red River Resistance, Red River Uprising or First Riel Rebellion).');
INSERT INTO badge_optional_requirements VALUES(1522,109,5,'Learn about the history of the Canadian flag.');
INSERT INTO badge_optional_requirements VALUES(1523,109,6,'Learn about the construction of railways in Canada, including the construction of the Canadian Pacific Railway. How were the people building the railways treated?');
INSERT INTO badge_optional_requirements VALUES(1524,109,7,'Around 25% of Canadians speak French as their first language, and a lot of people speak both English and French. There are French-speaking communities all across Canada. Preschool: Learn how to say hello in French. Level 1: Learn at least three words. Level 2: Learn at least five words. Level 3: Learn at least seven words. Level 4: Learn at least ten words. Level 5: Learn at least fifteen words.');
INSERT INTO badge_optional_requirements VALUES(1525,109,8,'Learn about Canada’s participation in World War I.');
INSERT INTO badge_optional_requirements VALUES(1526,109,9,'If you live in Canada, find a historical site near you and visit it.');
INSERT INTO badge_optional_requirements VALUES(1527,109,10,'Choose a Canadian Prime Minister, and learn about their life.');
INSERT INTO badge_optional_requirements VALUES(1528,109,11,'Learn about Loyalists who came to Canada.');
INSERT INTO badge_optional_requirements VALUES(1529,109,12,'Learn about the Acadian people. Who were they? What was the Expulsion of the Acadians?');
INSERT INTO badge_optional_requirements VALUES(1530,109,13,'Learn about Home Children in Canada.');
INSERT INTO badge_optional_requirements VALUES(1531,109,14,'Until 1949, Newfoundland was not a part of Canada. What was it before then? What was it like there? Why did it join Canada?');
INSERT INTO badge_optional_requirements VALUES(1532,109,15,'Learn about the Gold Rush in Canada.');
INSERT INTO badge_optional_requirements VALUES(1533,109,16,'Learn about the Halifax Explosion.');
INSERT INTO badge_optional_requirements VALUES(1534,109,17,'Learn about the 1837 Rebellion.');
INSERT INTO badge_optional_requirements VALUES(1535,109,18,'Learn about the Hudson’s Bay Trading Company. What was it? What was its effect on Aboriginal people? In what form does it exist today?');
INSERT INTO badge_optional_requirements VALUES(1536,109,19,'Learn about the Spanish Flu epidemic and the Polio epidemic and their effects on Canada. How were they similar? How were they different?');
INSERT INTO badge_optional_requirements VALUES(1537,109,20,'Learn about Ukrainian Internment Camps during WWI and Japanese Interment Camps during WWII. How were they similar? How were they different?');
INSERT INTO badge_optional_requirements VALUES(1538,109,21,'Learn about residential schools for Indigenous children. What was their purpose? How were people treated during them? Level 3 and up: Read a survivor’s account of their lives there.');
INSERT INTO badge_optional_requirements VALUES(1539,109,22,'Learn about the Great Depression in Canada.');
INSERT INTO badge_optional_requirements VALUES(1540,109,23,'Learn about the Underground Railroad, and the lives of formerly enslaved people in Canada.');
INSERT INTO badge_optional_requirements VALUES(1541,109,24,'Learn about the North West Resistance.');
INSERT INTO badge_optional_requirements VALUES(1542,109,25,'Learn about Resettlement in Newfoundland.');
INSERT INTO badge_optional_requirements VALUES(1543,109,26,'Learn about War Guests in Canada during WWII.');
INSERT INTO badge_optional_requirements VALUES(1544,109,27,'Learn about the Great Fire of St. John’s.');
INSERT INTO badge_optional_requirements VALUES(1545,109,28,'Choose a group of immigrants to Canada (the Irish or Chinese, for example) and learn about their history. Level 3 and up: Learn about Canada’s stance on Jewish refugees during the Holocaust.');
INSERT INTO badge_optional_requirements VALUES(1546,109,29,'Learn about the Plains of Abraham battle.');
INSERT INTO badge_optional_requirements VALUES(1547,109,30,'Read a book about a part of Canadian history.');
INSERT INTO badge_optional_requirements VALUES(1548,109,31,'Watch a film or documentary about a part of Canadian history.');
INSERT INTO badge_optional_requirements VALUES(1549,110,3,'Make a rolled beeswax candle.');
INSERT INTO badge_optional_requirements VALUES(1550,110,4,'Make an ice candle. Using a small milk carton, open the top all the way so that you have a square opening. Wash and dry the carton. Place a small taper candle in the center of the carton (use sticky wax or bluetack to stick it to the bottom of the carton). Fill the carton with small ice cubes. Have an adult pour hot wax over the ice cubes. When the wax is hard, peel away the milk carton and you should be left with a square candle with interesting holes all through it from the melted ice. Using two different colors of wax in the same candle is quite beautiful using this technique. Make sure to let the candle completely dry for a few days before lighting it.');
INSERT INTO badge_optional_requirements VALUES(1551,110,5,'Learn about the history of candles and how they have been made over the years.');
INSERT INTO badge_optional_requirements VALUES(1552,110,6,'Sell handmade candles as a charity fundraiser or give them as gifts to others.');
INSERT INTO badge_optional_requirements VALUES(1553,110,7,'Make a sand candle. At a beach, or in a sandbox, dig a small hole in the sand. Dig the hole in the shape you want your candle. You can place rocks, or shells around the edges if you wish for extra décor. Tie your wick to a stick long enough to stretch across the hole. Place the stick across the top of your hold and poke the wick down into the sand in the center of the hole. Have an adult pour melted wax into the hole, but do not fill it until it hits the stick. When the wax hardens, remove your candle. Most of the sand will fall away, but some usually sticks here and there. The shells and rocks will stick to the wax.');
INSERT INTO badge_optional_requirements VALUES(1554,110,8,'Make dipped candles. (Not recommended for Preschoolers and younger Level 1’s)');
INSERT INTO badge_optional_requirements VALUES(1555,110,9,'Use tissue paper to decorate a candle. Using patterned tissue paper or paper napkins, cut out a picture and make sure you only have one layer of the paper. You may also draw a picture on tissue paper if you wish. Place the picture on a pillar candle where you want the design and cover with a piece of wax paper. Hold the wax paper tight against the candle and using a heating tool or hair dryer, have an adult melt the wax paper over the picture. Let it cool and gently peel away the wax paper. Your picture should now be attached to the candle with a thin layer of wax over it.');
INSERT INTO badge_optional_requirements VALUES(1556,110,10,'Learn how to color and scent your candles.');
INSERT INTO badge_optional_requirements VALUES(1557,110,11,'Take a field trip to a candle shop or candle exhibit.');
INSERT INTO badge_optional_requirements VALUES(1558,110,12,'Make a container candle.');
INSERT INTO badge_optional_requirements VALUES(1559,110,13,'Make candles to use for a party or ceremony.');
INSERT INTO badge_optional_requirements VALUES(1560,110,14,'Learn about the different types of wax used in candles and what type each is good for.');
INSERT INTO badge_optional_requirements VALUES(1561,110,15,'Levels 3 & Up Only: Find out how to start your own candle making business, or explore careers in the candle industry.');
INSERT INTO badge_optional_requirements VALUES(1562,110,16,'Levels 3 & Up Only:  Teach a candle making technique to others.');
INSERT INTO badge_optional_requirements VALUES(1563,111,3,'Make some candy using candy molds.');
INSERT INTO badge_optional_requirements VALUES(1564,111,4,'Make some caramel.');
INSERT INTO badge_optional_requirements VALUES(1565,111,5,'Make some toffee.');
INSERT INTO badge_optional_requirements VALUES(1566,111,6,'Make some rock candy.');
INSERT INTO badge_optional_requirements VALUES(1567,111,7,'Demonstrate how to properly store candy to avoid changes in texture.');
INSERT INTO badge_optional_requirements VALUES(1568,111,8,'Make a decorative box or other packing along with tags or labels to give your candies as gifts');
INSERT INTO badge_optional_requirements VALUES(1569,111,9,'Participate in a community service project that involves candy making. You might teach younger kids how to make candy, make candy to donate to local fire fighters, or to sell to raise money for your favorite charity.');
INSERT INTO badge_optional_requirements VALUES(1570,111,10,'Learn about careers that involve candy making such as becoming a sugar artist, managing a candy store, or working at a candy plant. What salary could you expect? Where might you have to live? What hours might you expect?');
INSERT INTO badge_optional_requirements VALUES(1571,111,11,'Add flavor and color to your candy using extracts and food coloring.');
INSERT INTO badge_optional_requirements VALUES(1572,111,12,'Make some fudge.');
INSERT INTO badge_optional_requirements VALUES(1573,111,13,'Make a dipped candy.');
INSERT INTO badge_optional_requirements VALUES(1574,111,14,'Make a hard candy.');
INSERT INTO badge_optional_requirements VALUES(1575,111,15,'Make a cream filled candy.');
INSERT INTO badge_optional_requirements VALUES(1576,111,16,'Visit a sugar art show or watch a sugar contest on TV with a parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(1577,111,17,'Take a field trip to a candy shop and learn how at least 2 of the candies are made.');
INSERT INTO badge_optional_requirements VALUES(1578,111,18,'Make some taffy.');
INSERT INTO badge_optional_requirements VALUES(1579,111,19,'Learn to make sugar flowers or other decorative candy items. Oreo Truffles Recipe: Ingredients: 1 bag Oreo cookies 8 ounces cream cheese, softened 8 oz. dark chocolate, melted Directions: Line a baking sheet with aluminum foil and spray it with nonstick cooking spray. Chop 6 Oreo Cookies into 1/2″ chunks and set aside. Using a blender or food processor, finely crush the rest of the cookies. Stir together the cookie crumbs and cream cheese until well mixed. Place the candy in the refrigerator to firm up for about 1 hour. Form the mixture into 1-inch balls by rolling between your hands until they are round. Place the candies on the prepared baking sheet and refrigerate. Melt the chocolate in the microwave using a microwave safe bowl.  Stir every 30 seconds until melted. Allow the chocolate to cool slightly, but do not let it harden. Dip the candy balls in the melted chocolate and place on the foil-lined baking sheet. While the chocolate is still wet, top each with a sliver of cookie. Repeat with remaining truffles, and refrigerate for 1 hour or until chocolate has hardened. Lollipop Recipe: You will need: Cookie sheet and foil Assorted hard candies Meat mallet or small hammer Metal cookie cutter (optional) Lollipop sticks (available at crafts stores) Directions: Preheat the oven to 350 degrees. Line a cookie sheet with foil and spray with non-stick spray. Place the hard candy into a strong plastic bag. Use the meat mallet to crush the candies into small chunks. Pile candy pieces 1/4 to 1/2 inch thick  in four piles on your cookie sheet. Each one will become one lollipop. Be creative by using different colors to create a pattern if you wish. Bake for 6 to 8 minutes or until candies are completely melted. Remove from the oven and quickly attach a stick to the base of each melted lollipop shape. Carefully twist the stick to cover the lollipop end with the melted candy. Cool completely, then peel foil from the back of the lollipop. Wrap in a plastic bag and tie with a ribbon.');
INSERT INTO badge_optional_requirements VALUES(1580,112,3,'Understand how weather changes can affect canoeing. What should you do if a lightning storm develops or high winds begin? Explain the importance of checking the weather before leaving for a canoe trip.');
INSERT INTO badge_optional_requirements VALUES(1581,112,4,'Learn about different types of canoeing such as the following: Touring Outrigger Whitewater Marathons Olympic events Freestyle');
INSERT INTO badge_optional_requirements VALUES(1582,112,5,'Explain how to choose a canoe to fit your needs. What is the difference between a short fat canoe and a long thin one? What is each good for?');
INSERT INTO badge_optional_requirements VALUES(1583,112,6,'Learn about the different materials canoes are made from. What are the pros and cons of each?');
INSERT INTO badge_optional_requirements VALUES(1584,112,7,'Understand the best type of PDF to be worn while canoeing and how to fit one properly.');
INSERT INTO badge_optional_requirements VALUES(1585,112,8,'Explain how to care for and maintain a canoe, paddles and PFD.');
INSERT INTO badge_optional_requirements VALUES(1586,112,9,'Demonstrate how to safely carry and launch a canoe from shore, a dock, or both if possible.');
INSERT INTO badge_optional_requirements VALUES(1587,112,10,'Explain what types of hazards are most commonly encountered when canoeing and what you should do to anticipate, prevent, mitigate, or respond to them.');
INSERT INTO badge_optional_requirements VALUES(1588,112,11,'Earn the Swimming badge at your level.');
INSERT INTO badge_optional_requirements VALUES(1589,112,12,'Earn the Water Safety Badge at your level. What extra water safety measures must be taken when canoeing?');
INSERT INTO badge_optional_requirements VALUES(1590,112,13,'Learn about different paddle types. What is the difference between a straight and bent paddle and when should each be used?');
INSERT INTO badge_optional_requirements VALUES(1591,112,14,'Learn how to correctly size a paddle for someone in both the sitting and kneeling positions.');
INSERT INTO badge_optional_requirements VALUES(1592,112,15,'Demonstrate how to safely pack a canoe to keep it from tipping.  How should you secure your belongings? How can you best pack your equipment to keep it safe in case of a capsize?');
INSERT INTO badge_optional_requirements VALUES(1593,112,16,'Create a packing list for a group camping trip where you would need to canoe to your campsite.  How would you pack the items using the canoes available?  (Assume one canoe for every two members).');
INSERT INTO badge_optional_requirements VALUES(1594,112,17,'Earn the Knots badge at your level and explain which knots are useful in canoeing and why.');
INSERT INTO badge_optional_requirements VALUES(1595,112,18,'Learn and demonstrate the following strokes: Forward stroke Backstroke Draw stroke Pushaway stroke Forward sweep Reverse sweep J-stroke Rudder stroke');
INSERT INTO badge_optional_requirements VALUES(1596,113,3,'Earn the Race Car badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(1597,113,4,'Research careers in car racing. This might include drivers, pit crew, team owners, promoters, etc. What education or training do you need? What salary can you expect? What hours might you have to work? Will you have to travel?');
INSERT INTO badge_optional_requirements VALUES(1598,113,5,'Visit a museum or exhibit about your type of car racing.');
INSERT INTO badge_optional_requirements VALUES(1599,113,6,'Visit the pits at a car race and talk to some of the drivers.');
INSERT INTO badge_optional_requirements VALUES(1600,113,7,'What fan clubs are there for your type of racing? Collect at least 3 pieces of memorabilia for your type of racing.');
INSERT INTO badge_optional_requirements VALUES(1601,113,8,'Learn about what tracks are made of for your type of racing. How are the tracks designs to both increase speed as well as provide safety for the drivers and audience?');
INSERT INTO badge_optional_requirements VALUES(1602,113,9,'Show that you understand audience etiquette and know how to be a considerate fan. Earn a character badge that you can use as a race fan such as Patience (for standing in long lines), Respect (for respecting fans of other drivers) or Sportsmanship (for being a good sport whether your favorite driver wins or loses.)');
INSERT INTO badge_optional_requirements VALUES(1603,113,10,'Make a list of as many licensed goods as you can that you can purchase with your favorite driver’s logo. Items might include t-shirts, key chains, mugs, hats, etc. Can you think of any other products that sell well? Understand what licensing means and why some companies can produce products with your driver’s logo while others cannot.');
INSERT INTO badge_optional_requirements VALUES(1604,113,11,'Learn who the top 10 drivers in your type of racing are. Who holds records for the most wins? The most wrecks? The most points?');
INSERT INTO badge_optional_requirements VALUES(1605,113,12,'Find out what makes your type of car racing different from others. Compare tracks, car styles, engines, point systems, etc.');
INSERT INTO badge_optional_requirements VALUES(1606,114,3,'Learn about scrap booking. Tell your family, friends, or group what you learned. Find examples of scrap booked cards in magazines or online. Make 3 scrap booked cards and give them away.');
INSERT INTO badge_optional_requirements VALUES(1607,114,4,'Learn about rubber stamping. Make 3 rubber stamped cards and give them away.');
INSERT INTO badge_optional_requirements VALUES(1608,114,5,'Learn about embossing. Levels 3 – 5 must learn rubber stamping embossing, as well as metal and paper embossing. Make 3 embossed cards and give them away.');
INSERT INTO badge_optional_requirements VALUES(1609,114,6,'Learn about paper making. Tell your family, friends, or group what you learned. Find examples of handmade paper. Make 3 cards with handmade paper and give them away.');
INSERT INTO badge_optional_requirements VALUES(1610,114,7,'Learn about quilling/twirled paper. Tell your family, friends, or group what you learned. Find examples of quilled cards. Make 3 quilled cards and give them away.');
INSERT INTO badge_optional_requirements VALUES(1611,114,8,'Learn about different jobs in the card making industry, such as a designer. If possible, shadow someone for a day who works in the card making industry.');
INSERT INTO badge_optional_requirements VALUES(1612,114,9,'Read a book or watch a video about card making. Tell your family or club what you learned.');
INSERT INTO badge_optional_requirements VALUES(1613,114,10,'Learn to do calligraphy. Use it to embellish 3 cards and give them away.');
INSERT INTO badge_optional_requirements VALUES(1614,114,11,'Learn to do cross stitch and use it to embellish 3 cards and/or learn how to make hand embroidered/hand stitched cards and make one.');
INSERT INTO badge_optional_requirements VALUES(1615,114,12,'Learn how to do spatter-work with paint, an old toothbrush and a knife (Preschool and Level 1 must have adult supervision when using a knife). Put some leaves, for example, on a piece of paper and then spatter the paint over them.  Remove the leaves.  You will have a leaf print.  Make 3 spatter-worked cards and give them away.');
INSERT INTO badge_optional_requirements VALUES(1616,114,13,'Make cards to give away as a service project. You could send cards to soldiers serving overseas, make cards for seniors in a retirement community, or cards for a sick community member.');
INSERT INTO badge_optional_requirements VALUES(1617,114,14,'Use recycled greeting cards to make new cards.');
INSERT INTO badge_optional_requirements VALUES(1618,114,15,'Make gift tags.');
INSERT INTO badge_optional_requirements VALUES(1619,114,16,'Learn about shaped punches. What are the benefits from the different grips? How can punches be layers to create flowers, animals and other subjects? Make at least one card using punches.');
INSERT INTO badge_optional_requirements VALUES(1620,116,3,'Watch a Care Bears movie (Level 4 & 5 watch two movies) with a parent’s permission. Discuss it with an adult. What lessons did you learn? Talk about three important things you learned.');
INSERT INTO badge_optional_requirements VALUES(1621,116,4,'Watch at least three episodes of the original Care Bear series (Level 4 & 5 watch at least ten). Discuss it with an adult. What lessons did you learn? Compare the old TV series to the new one. How are they different? How are they the similar?');
INSERT INTO badge_optional_requirements VALUES(1622,116,5,'Preschool – Level 2 only: Read 2 Care Bears books.');
INSERT INTO badge_optional_requirements VALUES(1623,116,6,'Make a Care Bear scrapbook. Include at least four pages with either drawings, pictures from the show, magazine cut-outs, character designs, etc.');
INSERT INTO badge_optional_requirements VALUES(1624,116,7,'Design your own tummy badge. Draw a picture of it and and explain why you designed it the way you did and what it means.');
INSERT INTO badge_optional_requirements VALUES(1625,116,8,'Who are your three favorite Care Bears and why? How can you use what they teach in your own life?');
INSERT INTO badge_optional_requirements VALUES(1626,116,9,'Donate a Care Bear toy to charity.');
INSERT INTO badge_optional_requirements VALUES(1627,116,10,'Make and play your own Care Bears themed game. Teach it to your troop or family.');
INSERT INTO badge_optional_requirements VALUES(1628,116,11,'Throw a Care Bears party, watch a Care Bears movie (not including the ones watched for requirement 3), make Care Bears themed snacks, or go on a Care Bears themed scavenger hunt!');
INSERT INTO badge_optional_requirements VALUES(1629,117,3,'Check out 3 books from the library to learn about 3 different careers. Find someone who works in at least one of the jobs you read about. Ask a worker at least one question about the work they do.');
INSERT INTO badge_optional_requirements VALUES(1630,117,4,'Find out if there are any volunteer opportunities in your community that could help you prepare for the careers you are interested in. Learn more about it and how volunteering would prepare you for that specific job field.');
INSERT INTO badge_optional_requirements VALUES(1631,117,5,'Spend at least 4 hours as a job shadow for one of the careers you chose. You will need to contact someone who works in the area of your choice to arrange the details. After completing your job shadow, discuss or write about your experience. Explain any likes, dislikes, difficulties, challenges, and successes you experienced. Is this still a career you’d like to consider for yourself?');
INSERT INTO badge_optional_requirements VALUES(1632,117,6,'Learn about the history of your community.  Who settled your town, what are its major industries, who are the current local government officials?  What are your major work forces?');
INSERT INTO badge_optional_requirements VALUES(1633,117,7,'Use the information from your interviews to write and illustrate your own short book about occupations. Share your book with a parent, sibling, friend, or your group.  Make a cover for your book. Decide how you will bind it.');
INSERT INTO badge_optional_requirements VALUES(1634,117,8,'Make a poster for at least two of the careers you studied explaining why this occupation/career would be a good choice for you or anyone else. Illustrate your poster with any medium you choose.');
INSERT INTO badge_optional_requirements VALUES(1635,117,9,'Contribute to your own community by performing a simple act of service that is related to one of the career paths you wish to explore.');
INSERT INTO badge_optional_requirements VALUES(1636,117,10,'Learn the history of one of the careers you are interested in pursuing. Who are some well-known people who have worked in this occupation? What is the first record of this job having been performed? How has it evolved and changed over the years?');
INSERT INTO badge_optional_requirements VALUES(1637,117,11,'What type of education would you need for one of the careers you are interested in? Find three of the top schools you would need to attend to excel in that career field. How long should you expect to attend school for that career? What type of salary could you receive?');
INSERT INTO badge_optional_requirements VALUES(1638,117,12,'Research your career of choice in other cultures. How is it similar? How is it different? Does this job seem to be more in demand elsewhere or where you live? What are some differences in the education or salary?');
INSERT INTO badge_optional_requirements VALUES(1639,118,3,'Eat a purple carrot. How is it different than an orange carrot?');
INSERT INTO badge_optional_requirements VALUES(1640,118,4,'Make carrot art. This can be drawing a picture of carrots, painting, or using actual carrots in some way. Share your project with your troop or family.');
INSERT INTO badge_optional_requirements VALUES(1641,118,5,'Visit your local farmer’s market and find some carrots. How many varieties can you find? If you can, buy a few. How does their taste compare to supermarket carrots? Also, if possible, interview someone who grows carrots.');
INSERT INTO badge_optional_requirements VALUES(1642,118,6,'Make fresh carrot juice. How does it taste?');
INSERT INTO badge_optional_requirements VALUES(1643,118,7,'What is the most common type of carrot? Write a few paragraphs on what you learn.');
INSERT INTO badge_optional_requirements VALUES(1644,118,8,'What vitamins are most abundant in carrots? What do these vitamins do for you?');
INSERT INTO badge_optional_requirements VALUES(1645,118,9,'Research the history of carrots. Has orange always been the most common color? What other colors have existed? If you can, find carrots that are these different colors. Which color tastes the best?');
INSERT INTO badge_optional_requirements VALUES(1646,118,10,'Research what the most common types of carrots are in your region. What characteristics make them the most popular?');
INSERT INTO badge_optional_requirements VALUES(1647,118,11,'What myth circulated in WWII around carrots? Why did this myth come to be?');
INSERT INTO badge_optional_requirements VALUES(1648,118,12,'Make a recipe that includes carrots.');
INSERT INTO badge_optional_requirements VALUES(1649,119,3,'Visit a car museum.  Learn about the different models, their historical significance, and the evolution of automotive design over time.');
INSERT INTO badge_optional_requirements VALUES(1650,119,4,'Visit a car show or rally and talk to the car owners.');
INSERT INTO badge_optional_requirements VALUES(1651,119,5,'Take a guided tour of an automotive factory. Many automotive manufacturers offer guided tours of their factories. Witness the process of car manufacturing firsthand and gain insights into the technological advancements that have shaped the industry.  If you cannot visit in person, find a virtual tour online.');
INSERT INTO badge_optional_requirements VALUES(1652,119,6,'Help with a car restoration project and get hands-on experience in restoring a vintage or classic car. It’s a great way to learn about the different components, mechanics, and techniques used in older vehicle models.');
INSERT INTO badge_optional_requirements VALUES(1653,119,7,'Watch a documentary or film about automotive history.');
INSERT INTO badge_optional_requirements VALUES(1654,119,8,'Plan a road trip along a famous route associated with automotive history, such as Route 66. Visit landmarks, roadside attractions, and automobile-themed stops along the way.');
INSERT INTO badge_optional_requirements VALUES(1655,119,9,'Attend local car auctions or vintage car auctions to observe the bidding process and witness the sale of classic and historical vehicles. If you can’t visit one in person, watch one on TV or online.');
INSERT INTO badge_optional_requirements VALUES(1656,119,10,'Create a poster that illustrates the different types of early automobiles.');
INSERT INTO badge_optional_requirements VALUES(1657,119,11,'Look through someone’s Hot Wheels car collection and see how many cars you can identify.');
INSERT INTO badge_optional_requirements VALUES(1658,119,12,'Understand the difference between a manual and automatic shifting car.  What are the advantages to each?');
INSERT INTO badge_optional_requirements VALUES(1659,119,13,'Identify and explain the significance of at least five influential car models throughout history.');
INSERT INTO badge_optional_requirements VALUES(1660,119,14,'Learn about the impact of World War II on the automobile industry.');
INSERT INTO badge_optional_requirements VALUES(1661,119,15,'Choose a specific classic car to learn about.  Who designed and manufactured it?  Why was it popular? What type of motor does it have? What does that car sell for today?  See one in person if at all possible.');
INSERT INTO badge_optional_requirements VALUES(1662,119,16,'Learn about different motor types used in automobiles over time.  How much weight can they pull?  What is their fuel efficiency?  How much pollution do they produce?');
INSERT INTO badge_optional_requirements VALUES(1663,119,17,'Learn about the development of hybrid and electric cars.  How do they differ from traditional gas powered cars?  What are the pros and cons of these cars?');
INSERT INTO badge_optional_requirements VALUES(1664,119,18,'Design the car of the future.  What will it look like?  What will power it?  What will it be used for?');
INSERT INTO badge_optional_requirements VALUES(1665,120,3,'Create a map for a favorite storybook. Draw the different places the characters go and how they get there.');
INSERT INTO badge_optional_requirements VALUES(1666,120,4,'Create a simple treasure map. Hide small treasures or treats at different locations marked on the map and let friends follow the map to find them.');
INSERT INTO badge_optional_requirements VALUES(1667,120,5,'Set up an obstacle course in your backyard. Draw a map showing the course and have friends follow the map to navigate through the obstacles.');
INSERT INTO badge_optional_requirements VALUES(1668,120,6,'Learn about the different types of mapping software and their uses.');
INSERT INTO badge_optional_requirements VALUES(1669,120,7,'Learn about the use of maps in environmental conservation and resource management.');
INSERT INTO badge_optional_requirements VALUES(1670,120,8,'Create a map of a historical event or battle, including troop movements and key locations.');
INSERT INTO badge_optional_requirements VALUES(1671,120,9,'Learn about the role of cartography in the military and intelligence gathering.');
INSERT INTO badge_optional_requirements VALUES(1672,120,10,'Learn about the use of cartopgraphy in disaster response and emergency management');
INSERT INTO badge_optional_requirements VALUES(1673,120,11,'Learn about the use of maps in cultural and social studies, including mapping population demographics and migration patterns.');
INSERT INTO badge_optional_requirements VALUES(1674,120,12,'Learn about cartographic design principles, including color theory and layout.');
INSERT INTO badge_optional_requirements VALUES(1675,120,13,'Study the use of maps in journalism and media, including data visualization and infographics.');
INSERT INTO badge_optional_requirements VALUES(1676,120,14,'Create a map of a fantasy world, including magical locations and creatures.');
INSERT INTO badge_optional_requirements VALUES(1677,120,15,'Create a map of a real or fictional theme park, including rides and attractions.');
INSERT INTO badge_optional_requirements VALUES(1678,120,16,'Learn about the use of cartography in agriculture and farming, including soil mapping and irrigation planning.');
INSERT INTO badge_optional_requirements VALUES(1679,120,17,'Study the use of maps in video games.  What do they show?  If you were the cartographer, what would you add to the map to make the game easier to play?');
INSERT INTO badge_optional_requirements VALUES(1680,120,18,'Learn about mining cartography and how maps of mines are made.');
INSERT INTO badge_optional_requirements VALUES(1681,120,19,'Study the use of maps in transportation and logistics, including shipping and delivery routes.  Create a map to show how to get a product from one destination to another.');
INSERT INTO badge_optional_requirements VALUES(1682,120,20,'Learn about the use of maps in marketing and advertising, including location-based targeting.');
INSERT INTO badge_optional_requirements VALUES(1683,120,21,'Learn about the use of maps in sports and recreation, including hiking and biking trails.');
INSERT INTO badge_optional_requirements VALUES(1684,120,22,'At night, look up at the stars and make a celesial map of what you see.');
INSERT INTO badge_optional_requirements VALUES(1685,120,23,'Study the use of cartography in urban planning and city development.');
INSERT INTO badge_optional_requirements VALUES(1686,120,24,'Create a map of your neighborhood or a local park.');
INSERT INTO badge_optional_requirements VALUES(1687,120,25,'Find an old map of your town or city and a current map. Compare the two with discuss how the area has changed over time. Draw yourown version of what tyouthink the area will look like in the future.');
INSERT INTO badge_optional_requirements VALUES(1688,121,3,'What is Japanese anime? How does it differ from American cartoons? Try drawing something in anime style.');
INSERT INTO badge_optional_requirements VALUES(1689,121,4,'Find out how cartoons were used during WWII in educating both the public and the soldiers. Watch one of these cartoons.');
INSERT INTO badge_optional_requirements VALUES(1690,121,5,'Learn about the history of print cartoons. Read at least three different print cartoons. Levels 3 and Up: Read at least three books on different print cartoons.');
INSERT INTO badge_optional_requirements VALUES(1691,121,6,'Learn about the history of TV and Movie cartoons.');
INSERT INTO badge_optional_requirements VALUES(1692,121,7,'Music is a large part of setting the mood for motion cartoons. Watch at least three different cartoons and pay attention to the type of music that they play. What instruments do you hear? How does the music change with each scene? What does the music make you feel? Levels 2 and Up: Also watch a cartoon with the sound turned off. What type of music do you imagine should be in each scene? Cartoons without speaking roles are best for this such as Tom and Jerry cartoons.');
INSERT INTO badge_optional_requirements VALUES(1693,121,8,'Make a flip-book of at least 25 pages. Levels 3 and Up: Make a stop motion cartoon clip of at least 10 seconds or a flip-book of at least 50 pages.');
INSERT INTO badge_optional_requirements VALUES(1694,121,9,'Create a print cartoon and submit it for publication in your local newspaper, school newspaper, or troop newsletter.');
INSERT INTO badge_optional_requirements VALUES(1695,121,10,'Learn about licensing and copyright laws. Why are you not allowed to sell t-shirts or other merchandise with cartoon characters on them without permission?');
INSERT INTO badge_optional_requirements VALUES(1696,121,11,'Learn about different careers in the cartoon industry. What educational requirements are there to work in these fields? What type of pay can you expect?');
INSERT INTO badge_optional_requirements VALUES(1697,121,12,'Research how your favorite cartoon character is/was created. What type of style was used to animate them? Who is their voice actor? If possible, watch a video on how they were animated and brought to life. Then, draw that character to the best of your ability.');
INSERT INTO badge_optional_requirements VALUES(1698,122,3,'Find out how castles were built in medieval times.  Learn about a modern day castle that used authentic medieval methods to build it such as Castello Di Amorosa in California which took 15 years to build and was finished in 2007.');
INSERT INTO badge_optional_requirements VALUES(1699,122,4,'What is a treadwheel crane and what was its role in castle construction.');
INSERT INTO badge_optional_requirements VALUES(1700,122,5,'Learn about the various people who lived in a castle and what their roles were.   Nobles (Lord and Lady)Noble childrenStewardChamberlainMarshalSeneschalChaplainLaundressChambermaidEntertainerSpinnerSoldiersCookPageGong-FarmerGroom');
INSERT INTO badge_optional_requirements VALUES(1701,122,6,'How were toilets (“loos”, “garderobes” or “gongs”) designed in a castle?');
INSERT INTO badge_optional_requirements VALUES(1702,122,7,'Visit a medieval castle and learn its history.  If you can’t visit one in person, take a virtual tour.');
INSERT INTO badge_optional_requirements VALUES(1703,122,8,'Find out what castle is nearest where you live. (This can be a modern castle that is simply designed to look like one from medieval history.)  With a parent’s permission, try Googling “Castle Near Me” with your location on and see what pops up.  If possible, go visit the castle.');
INSERT INTO badge_optional_requirements VALUES(1704,122,8,'Build a sand castle.');
INSERT INTO badge_optional_requirements VALUES(1705,122,9,'Read a book about medieval life in a castle.');
INSERT INTO badge_optional_requirements VALUES(1706,122,10,'What is feudalism and what role did it play in the evolution of castles?');
INSERT INTO badge_optional_requirements VALUES(1707,122,11,'Learn the differences between the following types of castles.  What were the pros and cons of each? Motte and Bailey CastleConcentric CastleShell Keep CastleStone Keep Castle');
INSERT INTO badge_optional_requirements VALUES(1708,122,12,'Create a castle craft.');
INSERT INTO badge_optional_requirements VALUES(1709,122,13,'Learn about how castles were defended.  What role did the catapult and crossbow play?');
INSERT INTO badge_optional_requirements VALUES(1710,122,14,'Learn about castle design and how it differed in different eras, countries and regions.  For example, compare and contrast the Neuschwanstein Castle in Bavaria with Alnwick Castle in the UK.');
INSERT INTO badge_optional_requirements VALUES(1711,122,15,'Build a castle out of something around the house such as blocks, Lego, cardboard tubes or boxes, or sugar cubes. Make sure to include all the main parts of a typical castle. Or draw and design a castle of your own including all major parts.');
INSERT INTO badge_optional_requirements VALUES(1712,122,16,'Make a working model of a drawbridge or portcullis.');
INSERT INTO badge_optional_requirements VALUES(1713,122,17,'How were castles attacked?  What is a siege?  How were weapons such as siege towers, trebuchets, battering rams, and grappling hooks used?');
INSERT INTO badge_optional_requirements VALUES(1714,122,18,'Make a working model of a trebuchet or catapult.');
INSERT INTO badge_optional_requirements VALUES(1715,122,19,'How were moats built and filled?  How would opposing armies get across a moat?');
INSERT INTO badge_optional_requirements VALUES(1716,122,20,'How did castles defend against siege?  What is a murder hole or meurtrière?');
INSERT INTO badge_optional_requirements VALUES(1717,123,3,'What helps a cat see in low light? How does it do this?');
INSERT INTO badge_optional_requirements VALUES(1718,123,4,'Describe 5 different parts of a cat’s anatomy. Draw a picture labeling them.');
INSERT INTO badge_optional_requirements VALUES(1719,123,5,'Why is play important to a cat? What happens when cats do not have opportunities to play?');
INSERT INTO badge_optional_requirements VALUES(1720,123,6,'Why is spaying or neutering important? List at least three potential problems for cats that are not spayed or neutered.');
INSERT INTO badge_optional_requirements VALUES(1721,123,7,'Visit a rescue or animal shelter. Speak with a volunteer there to understand how animals come to end up there.');
INSERT INTO badge_optional_requirements VALUES(1722,123,8,'Take up a collection of supplies such as cat food, litter, toys, blankets, etc. and donate them to a local rescue or shelter.');
INSERT INTO badge_optional_requirements VALUES(1723,123,9,'Spend at least one afternoon volunteering at a local shelter or rescue.');
INSERT INTO badge_optional_requirements VALUES(1724,123,10,'Attend a cat show. Interview a judge about what criteria they use for judging.');
INSERT INTO badge_optional_requirements VALUES(1725,123,11,'Learn about careers that involve cats, such as a veterinarian or cat breeder. What degrees or certifications are necessary for these careers? What type of education would you need?');
INSERT INTO badge_optional_requirements VALUES(1726,123,12,'Create a small booklet about cats, including pictures and descriptions.');
INSERT INTO badge_optional_requirements VALUES(1727,123,13,'Write a song or poem about cats, or create a craft project that involves cats. Share it with your family or club.');
INSERT INTO badge_optional_requirements VALUES(1728,123,14,'Learn about cat breeding. What are some new breeds, and how were they created?');
INSERT INTO badge_optional_requirements VALUES(1729,123,15,'Learn about other types of felines, such as cougars, jaguars, or mountain lions. How are they different than domesticated cats? Research what types of cat breeds could have come from these other feline types.');
INSERT INTO badge_optional_requirements VALUES(1730,123,16,'Find a coloring book of cats. Color at least five pages. Make sure to color the cats the actual colors they might be, such as black, brown or golden.');
INSERT INTO badge_optional_requirements VALUES(1731,123,17,'Learn how cats hunt their prey, be it mice or squirrels. How can this change from breed to breed?');
INSERT INTO badge_optional_requirements VALUES(1732,123,18,'Find at least 3 poems, ballads, or songs about cats and learn one of them.');
INSERT INTO badge_optional_requirements VALUES(1733,123,19,'Research the role cats have played in history. For instance, the ancient Egyptians believed cats were holy, and other nations used tigers to hunt with.');
INSERT INTO badge_optional_requirements VALUES(1734,123,20,'Know the first aid for any injuries that may occur when dealing with a cat, such as scratches and bites, and asthma attacks which may occur if a person is allergic to cats/cat hair.');
INSERT INTO badge_optional_requirements VALUES(1735,123,21,'Watch a documentary or a movie about cats.');
INSERT INTO badge_optional_requirements VALUES(1736,123,22,'Find at least three pictures or works of art about cats and look at them. Which do you like best?');
INSERT INTO badge_optional_requirements VALUES(1737,123,23,'Create a scrapbook page, collage, or poster about cats. Share it with your club or family.');
INSERT INTO badge_optional_requirements VALUES(1738,123,24,'How do cats affect the environment? How can we help both cats and the environment?');
INSERT INTO badge_optional_requirements VALUES(1739,124,3,'Go to a ceramics studio and apply a glaze to a piece of pottery or watch someone else do it. How does the appearance change after going through the kiln?');
INSERT INTO badge_optional_requirements VALUES(1740,124,4,'Learn about kilns. Find a kiln you can look at and try to arrange to be present when a potter takes her wares out of the kiln. Find at least two different types of kilns to visit or look at in photos. What are the most common types of kilns and what types of fuel do they use? You may help load or unload a kiln with the help of an experienced adult. What are the things a person needs to be aware of in loading a kiln? What temperatures are used for different types of pottery? Are some things fired more than once? Also find out how much it costs each time the kiln is used.');
INSERT INTO badge_optional_requirements VALUES(1741,124,5,'Find a book or website (with parent’s permission) that lists helpful tools for potters. Which ones are used for making surface designs in the clay? Find a potter’s wheel to look at and if you cannot watch someone using it, find photos or a movie to watch. Find out the use for each of at least five tools. Practice using some of them on clay or play-dough.');
INSERT INTO badge_optional_requirements VALUES(1742,124,6,'Visit a craft fair, ceramic studio, or museum and count the different shapes of items made of pottery. How many different surface designs can you find? How many different colors of glazes? Try to determine which method was used in making the various pieces. If you are able, check with the potter(s) to see how accurate your guessing is. Ask the artist how long it took to make each piece. If you divide the price of a piece by the number of hours it took to make it, how much is the potter getting per hour?');
INSERT INTO badge_optional_requirements VALUES(1743,124,7,'Learn the definition of ten of these words: Throw Fire Slip Earthenware Stoneware Porcelain Wedging Reducing Kaolin Bentonite Raku Mishima Majolica Sgraffito Crackle');
INSERT INTO badge_optional_requirements VALUES(1744,124,8,'Make at least one article out of clay using a hand building method not used in Level 1 requirement 2 and have it fired. If your article is ruined in some way or you haven’t mastered that particular technique, make a second piece using the same technique. If you don’t apply glaze to the piece, decorate it in another way. This requirement can be repeated a second time so that you have mastered all three hand building techniques.');
INSERT INTO badge_optional_requirements VALUES(1745,124,9,'Spend at least two hours helping an artists’ association with a fundraiser or charitable project that includes something related to ceramics or sell some pieces of your pottery and donate the money.');
INSERT INTO badge_optional_requirements VALUES(1746,124,10,'Make a piece of pottery by any method and make a well-fitting lid for it.');
INSERT INTO badge_optional_requirements VALUES(1747,124,11,'Make a piece of pottery that combines more than one shape, such as a goblet or teapot.');
INSERT INTO badge_optional_requirements VALUES(1748,124,12,'Make a piece of pottery with handles, a pierced design, or with decorations made from added pieces of clay (sprigs). Your chosen variation can be used on pieces that also count for requirement 8 or 10.');
INSERT INTO badge_optional_requirements VALUES(1749,124,13,'After touring a home or business that used several different styles of floor or kitchen tiles, try making a series of coordinated tiles or slabs to be used as stepping stones, trivets, or some other part of home or yard decor.');
INSERT INTO badge_optional_requirements VALUES(1750,124,14,'Try making a piece of hollow molded pottery by pouring slip into a mold, or watch someone else do it. You will need to observe this on more than one occasion in order to see the entire process.');
INSERT INTO badge_optional_requirements VALUES(1751,124,15,'Research one of the following: glaze recipes, the history of pottery on a particular continent, pyrometric cones, or the chemistry of firing.');
INSERT INTO badge_optional_requirements VALUES(1752,124,16,'Try your hand at making a pot by throwing. Find out some things that can go wrong while a piece is being thrown. How can they be prevented? How does a potter combine more than one shape in a piece?');
INSERT INTO badge_optional_requirements VALUES(1753,124,17,'Make a piece of pottery using a wheel. Remove the piece from the wheel yourself. Find out what a bat is and observe someone using one or try throwing an open shape that requires a bat.');
INSERT INTO badge_optional_requirements VALUES(1754,125,3,'Visit a local pottery studio, ceramic artist, or paint-your-own pottery shop and ask questions about how they prepare, glaze, and fire pieces.');
INSERT INTO badge_optional_requirements VALUES(1755,125,4,'Learn the difference between bisque, greenware, and glazed ceramic.');
INSERT INTO badge_optional_requirements VALUES(1756,125,5,'Create a seasonal or holiday-themed ceramic decoration.');
INSERT INTO badge_optional_requirements VALUES(1757,125,6,'Use masking tape or wax resist to create clean lines or patterns.');
INSERT INTO badge_optional_requirements VALUES(1758,125,7,'Experiment with dot painting or pointillism on a ceramic surface.');
INSERT INTO badge_optional_requirements VALUES(1759,125,8,'Watch a demonstration (live or video) of ceramic glazing or kiln firing.');
INSERT INTO badge_optional_requirements VALUES(1760,125,9,'Paint a tile that tells a story or shows a scene.');
INSERT INTO badge_optional_requirements VALUES(1761,125,10,'Use reference images to paint an animal or flower on your ceramic piece.');
INSERT INTO badge_optional_requirements VALUES(1762,125,11,'Learn how colors may change after firing and plan your piece accordingly.');
INSERT INTO badge_optional_requirements VALUES(1763,125,12,'Create a textured ceramic piece using stamps or imprints before painting.');
INSERT INTO badge_optional_requirements VALUES(1764,125,13,'Participate in a group project, like painting tiles for a mural or collaborative art piece.');
INSERT INTO badge_optional_requirements VALUES(1765,125,14,'Try layering different colors and observe how they blend or interact.  How do the colors change once fired?');
INSERT INTO badge_optional_requirements VALUES(1766,125,15,'Interview a ceramic artist about their techniques or career.');
INSERT INTO badge_optional_requirements VALUES(1767,125,16,'Learn about the difference between low-fire and high-fire ceramic painting');
INSERT INTO badge_optional_requirements VALUES(1768,125,17,'Document your process from idea to finished piece with photos or a journal.');
INSERT INTO badge_optional_requirements VALUES(1769,125,18,'Enter your painted ceramics in an art show, fair, or exhibition.');
INSERT INTO badge_optional_requirements VALUES(1770,125,19,'Paint a functional item such as a mug, plate, or soap dish.');
INSERT INTO badge_optional_requirements VALUES(1771,125,20,'Create a gift by painting a personalized ceramic item for someone special.');
INSERT INTO badge_optional_requirements VALUES(1772,125,21,'Study famous ceramic artists or historical pottery styles and try to imitate one.');
INSERT INTO badge_optional_requirements VALUES(1773,125,22,'Try painting on a 3D object with multiple curves or angles to improve your precision.');
INSERT INTO badge_optional_requirements VALUES(1774,125,23,'Learn how to safely clean and store ceramic painting tools.');
INSERT INTO badge_optional_requirements VALUES(1775,125,24,'Use a stencil or stamp to create repeating patterns on your piece.');
INSERT INTO badge_optional_requirements VALUES(1776,125,25,'Learn to sign or mark the bottom of your ceramic pieces with your initials or a symbol.');
INSERT INTO badge_optional_requirements VALUES(1777,125,26,'Keep a sketchbook of designs or ideas for future ceramic painting projects.');
INSERT INTO badge_optional_requirements VALUES(1778,125,27,'Use a ceramic pencil to sketch your design before painting.');
INSERT INTO badge_optional_requirements VALUES(1779,125,28,'Paint a ceramic piece inspired by your favorite book, movie, or story.');
INSERT INTO badge_optional_requirements VALUES(1780,125,29,'Paint a pair of matching items (such as two candle holders or salt & pepper shakers).');
INSERT INTO badge_optional_requirements VALUES(1781,125,30,'Find out what safety steps are needed when working with glazes and kilns.');
INSERT INTO badge_optional_requirements VALUES(1782,126,3,'Read a children’s book that centers around chalk');
INSERT INTO badge_optional_requirements VALUES(1783,126,4,'Name five careers that use chalk as a main or important tool.');
INSERT INTO badge_optional_requirements VALUES(1784,126,5,'What substitutions have been made in traditional chalk uses in modern society?');
INSERT INTO badge_optional_requirements VALUES(1785,126,6,'Attend a chalk art festival.');
INSERT INTO badge_optional_requirements VALUES(1786,126,7,'Participate in a chalk art festival as an artist.');
INSERT INTO badge_optional_requirements VALUES(1787,126,8,'Volunteer at a chalk art festival.');
INSERT INTO badge_optional_requirements VALUES(1788,126,9,'Give chalk to a local children’s charity, family shelter or other program.');
INSERT INTO badge_optional_requirements VALUES(1789,126,10,'Host a mini chalk fest in your neighborhood. Teach the kids chalk etiquette, then see what kind of artworks they create!');
INSERT INTO badge_optional_requirements VALUES(1790,126,11,'Attempt to make your own sidewalk chalk. There are recipes online and in children’s craft books telling you how.');
INSERT INTO badge_optional_requirements VALUES(1791,126,12,'Do a service project that involves chalk in some way.');
INSERT INTO badge_optional_requirements VALUES(1792,126,13,',  Take a class on art pastels.');
INSERT INTO badge_optional_requirements VALUES(1793,126,14,'Create a diorama of a chalk mine or the geographic chalk deposits on Earth.');
INSERT INTO badge_optional_requirements VALUES(1794,128,3,'What does your religious faith say about charity? Find one (Preschool), three (Levels 2 & 3), five (Levels 3 & 4), seven (Level 5), verse(s) in your book of faith that talks about charity and memorize it/them.');
INSERT INTO badge_optional_requirements VALUES(1795,128,4,'Make a list of how you can implement charity in your everyday life. Have at least five ways, and then share them with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(1796,128,5,'Understand and be able to explain the difference between welfare and charity.');
INSERT INTO badge_optional_requirements VALUES(1797,128,6,'If you receive an allowance, set aside at least 10% each week to donate to the charity of your choice. If you do not receive an allowance, earn some money through chores or a fundraiser to donate.');
INSERT INTO badge_optional_requirements VALUES(1798,128,7,'Visit a nursing home or retirement home and spend some time visiting with the residents. If you sing or dance, you could even put on a short show.');
INSERT INTO badge_optional_requirements VALUES(1799,128,8,'Write a report, create a booklet, or design a poster on the life of a saint or other person who was/is known for their charity.');
INSERT INTO badge_optional_requirements VALUES(1800,128,9,'Find at least 3 charities that were started by kids. Read about their stories and why they started their charities.');
INSERT INTO badge_optional_requirements VALUES(1801,128,10,'Find one (Preschool), three (Levels 2 & 3), five (Levels 3 & 4), seven (Level 5), famous quotations about charity and memorize them.');
INSERT INTO badge_optional_requirements VALUES(1802,128,11,'Using the Victorian Language of flowers, make a bouquet that symbolizes what charity means to you. You can find the meanings assigned to the flowers at various websites (with parental permission) or in books and you may cut pictures from magazines or web-pages to create a collage “bouquet.” Make sure you include the name and meaning of each flower that you choose. You may make a scrapbook page using pictures of flowers or make a bouquet using real or artificial flowers.');
INSERT INTO badge_optional_requirements VALUES(1803,128,12,'Write the word CHARITY on a piece of paper and then think of one charitable act that you could do that starts with each letter in the word. For example, for “C” you could put “Caring for others” and for “H” you might put “Helping those in need.”');
INSERT INTO badge_optional_requirements VALUES(1804,129,3,'Volunteer your time to help out your charity in some way. You might serve dinner at your local rescue mission, help with child care at a local walk-a-thon, help repaint a room in a homeless shelter, etc.');
INSERT INTO badge_optional_requirements VALUES(1805,129,4,'Learn about how your charity operates. For example, if they are a local food bank, where do they get their food? How is it stocked? How is it packaged for distribution? How many volunteers does it take to keep operations flowing? How do they pay for their building? etc. If they are a national charity such as a disease research organization, where does the majority of their money come from? What kinds of fund raisers or activities do they do nationwide that groups can participate in? How can research groups apply for grants?');
INSERT INTO badge_optional_requirements VALUES(1806,129,5,'Look at the financial operation of your charity. How much of the money that comes in is spent on operational costs and paid employees and how much goes directly to benefit people or research they support?');
INSERT INTO badge_optional_requirements VALUES(1807,129,6,'Design a poster to help bring awareness regarding your chosen charity and post them around town.');
INSERT INTO badge_optional_requirements VALUES(1808,129,7,'What is a 501(c)3 organization? How does it differ from other non-profit organizations?');
INSERT INTO badge_optional_requirements VALUES(1809,129,8,'Learn about what other charities are also working toward the same goals. Discuss why you chose your specific charity rather than one of their competitors to support.');
INSERT INTO badge_optional_requirements VALUES(1810,129,9,'Learn about non-profit law. What does it take to register as a charity? Who do you have to file with at the federal, state, and local level? What are the costs? What is required to maintain your charitable status?');
INSERT INTO badge_optional_requirements VALUES(1811,129,10,'Find out what free tools are available to charities regarding training volunteers, learning about insurance, accounting, etc. Are there online resources? Are there local classes through the small business center or government offices?');
INSERT INTO badge_optional_requirements VALUES(1812,129,11,'Make a video to bring awareness about your charity and post it online with the permission of a parent.');
INSERT INTO badge_optional_requirements VALUES(1813,131,3,'Learn 3 basic tumbling moves, like how to do a cartwheel, walkover, or forward roll.');
INSERT INTO badge_optional_requirements VALUES(1814,131,4,'Choreograph your own cheerleading dance.');
INSERT INTO badge_optional_requirements VALUES(1815,131,5,'Learn 2 additional cheerleading jumps such as the pike or the herkie.');
INSERT INTO badge_optional_requirements VALUES(1816,131,6,'Learn about cheer uniforms. What are the components that make up a cheer outfit? What about practice wear? Design and sketch your own cheerleading uniform, considering functionality and aesthetics.');
INSERT INTO badge_optional_requirements VALUES(1817,131,7,'Learn how to incorporate pom poms and signs into your cheers. Make your own cheerleading sign.');
INSERT INTO badge_optional_requirements VALUES(1818,131,8,'Learn about basic stunting, like shoulder sits, thigh stands,pyramids or basket tosses. Remember that stunting should only be performed under the supervision of a qualified adult.');
INSERT INTO badge_optional_requirements VALUES(1819,131,9,'Learn the different roles of a cheerleading squad. What is the difference between a base and a flier? How might you decide which role is best for someone?');
INSERT INTO badge_optional_requirements VALUES(1820,131,10,'Research the origins and evolution of cheerleading, including its cultural significance.');
INSERT INTO badge_optional_requirements VALUES(1821,131,11,'Attend a cheer camp.');
INSERT INTO badge_optional_requirements VALUES(1822,131,12,'Choose appropriate music for cheerleading routines and understand how to match movements to the beat.');
INSERT INTO badge_optional_requirements VALUES(1823,131,13,'Practice proper warm-up and stretching techniques used before cheerleading practices and performances.');
INSERT INTO badge_optional_requirements VALUES(1824,131,14,'Practice projecting your voice clearly and confidently for effective cheering.');
INSERT INTO badge_optional_requirements VALUES(1825,131,15,'Understand the basics of stunting safety and proper spotting techniques.');
INSERT INTO badge_optional_requirements VALUES(1826,131,16,'Learn about cheerleading competitions, scoring criteria, and judging panels.');
INSERT INTO badge_optional_requirements VALUES(1827,131,17,'Educate yourself on common cheerleading injuries and how to prevent them.');
INSERT INTO badge_optional_requirements VALUES(1828,132,3,'When is National Cheese Day? Learn the history of this day and how people celebrate it.  There are many cheese related National holidays.  How many can you find?');
INSERT INTO badge_optional_requirements VALUES(1829,132,4,'Make a sweet dish with cheese.');
INSERT INTO badge_optional_requirements VALUES(1830,132,5,'Make a savory dish with at least 4 distinct cheeses.');
INSERT INTO badge_optional_requirements VALUES(1831,132,6,'Participate in a fundraiser or volunteer at a soup kitchen that utilizes cheese (bake cheese-based cookies, participate in a spaghetti dinner).');
INSERT INTO badge_optional_requirements VALUES(1832,132,7,'Make a cheese recipe for three different holidays.  For example, cheese balls for Christmas, cheddar on apple pie for 4th of July, or cheesy mashed potatoes for Thanksgiving');
INSERT INTO badge_optional_requirements VALUES(1833,132,8,'Earn the Cheese Making Badge at your current level');
INSERT INTO badge_optional_requirements VALUES(1834,132,9,'Host an event (taco night, pizza night, chili cook off) where you can showcase different cheeses.');
INSERT INTO badge_optional_requirements VALUES(1835,132,10,'Learn about Vegan cheese.  What is it usually made of?  What recipes does it work best in?');
INSERT INTO badge_optional_requirements VALUES(1836,132,11,'Make macaroni and cheese 3 times.  Each time, make it with a different cheese or combination of cheeses.  Which did you like best and why?');
INSERT INTO badge_optional_requirements VALUES(1837,132,12,'Learn about non-food uses for cheese like beauty and skin care.');
INSERT INTO badge_optional_requirements VALUES(1838,132,13,'Find out what goes into processed cheese.  What percent is usually cheese verses other fillers and artificial ingredients?');
INSERT INTO badge_optional_requirements VALUES(1839,132,14,'Make a cheese recipe from another country.');
INSERT INTO badge_optional_requirements VALUES(1840,132,15,'Learn how cheese is made.  Tour a cheese factory if possible.  If not, take a virtual tour.');
INSERT INTO badge_optional_requirements VALUES(1841,132,16,'Visit a cheese store or look through the cheese department of large grocery store with a gourmet cheese section.  Make a chart of the different cheeses you see.  How many varieties do they offer?  How do the prices differ?  What is the ratio of hard to soft cheeses?  What type of “flavored” cheeses do they have (smoke, herb, etc.?)');
INSERT INTO badge_optional_requirements VALUES(1842,133,3,'Taste and compare your homemade cheeses to the store equivalent. (Farmer’s Cheese is nearest to cottage cheese).  Make a compare and contrast chart including taste, texture, smell and color.');
INSERT INTO badge_optional_requirements VALUES(1843,133,4,'If possible, find a cheese that is produced locally.  Find out why this cheese is best produced locally.  If you can, tour the premises.   If you cannot tour a local factory try to find a virtual tour of a cheese factory online.');
INSERT INTO badge_optional_requirements VALUES(1844,133,5,'Learn about cheese made from non-cow sources such as: Goat Sheep Camel Buffalo Reindeer Moose Yak Vegan How do these cheeses usually differ from traditional cheese made from cow milk?');
INSERT INTO badge_optional_requirements VALUES(1845,133,6,'Research careers in cheesemaking.  What education would you need?  What salary could you expect?  Where might you have to live? Examples might include: Food scientist Cheese Sculptor Creamery Worker Cheese Maker Marketing Manager for a Cheese Company Dairy or Goat farmer');
INSERT INTO badge_optional_requirements VALUES(1846,133,7,'Understand the process for making cheese and how someone would enter the market at both the industrial and small boutique business levels.  How does cheese making differ when made in small kitchen batches verses large cheese factories?');
INSERT INTO badge_optional_requirements VALUES(1847,133,8,'Participate in a fundraiser or volunteer at a soup kitchen that utilizes cheese (bake cheese based cookies, participate in a spaghetti dinner).');
INSERT INTO badge_optional_requirements VALUES(1848,133,9,'Create a cheese brand.  What kind of cheese would you sell? How would you differentiate yourself?  Create a logo and tag line for your brand.  Understand the terms associated with labels like vegan, kosher, and organic.');
INSERT INTO badge_optional_requirements VALUES(1849,133,10,'Understand supply lines and transportation for cheese.');
INSERT INTO badge_optional_requirements VALUES(1850,133,11,'Research how cheeses are shaped. Make homemade cheese into a shape by using an ice cube tray or silicone mold.');
INSERT INTO badge_optional_requirements VALUES(1851,133,12,'Earn the Cheese Badge at your current level');
INSERT INTO badge_optional_requirements VALUES(1852,133,13,'Find out what imitation cheese is made of and how it is produced..');
INSERT INTO badge_optional_requirements VALUES(1853,133,14,'Dividing a batch of farmer’s cheese, experiment with at least 4 different flavors and herbs.');
INSERT INTO badge_optional_requirements VALUES(1854,133,15,'Make two additional vegan cheeses.');
INSERT INTO badge_optional_requirements VALUES(1855,133,16,'Learn how the oldest types of cheese are made.  What is the longest type of “long aged cheese”');
INSERT INTO badge_optional_requirements VALUES(1856,133,17,'Learn about fresh cheeses.  What are the pros and cons of fresh cheeses?');
INSERT INTO badge_optional_requirements VALUES(1857,133,18,'Learn about the history of cheese.  When was it invented?  How many different cheeses are there and what regions are they from?  How was cheese used in the past compared to today?');
INSERT INTO badge_optional_requirements VALUES(1858,133,19,'Find at least five different uses for whey.');
INSERT INTO badge_optional_requirements VALUES(1859,133,20,'Learn how processed cheese is made. What percent is actually cheese verses fillers and artificial ingredients?');
INSERT INTO badge_optional_requirements VALUES(1860,134,3,'With a parent’s permission, watch a TV show  featuring a famous chef, either on the Food Network channel or online. Watch at least three episodes.');
INSERT INTO badge_optional_requirements VALUES(1861,134,4,'What are the essential parts of a special meal? Can you have a meal of all salads if they have the right ingredients? Do fancy meals usually have more or less courses than an everyday meal? Why might a high-protein course be important? Make up a menu that would be very nice, but also healthy. Ask someone for ideas of how to make it even healthier without reducing its eye-appeal and taste. Then make this meal with the help of an adult and serve it to family or friends.');
INSERT INTO badge_optional_requirements VALUES(1862,134,5,'Learn the names of all the common pieces of flatware & linen and the most common dishes used in setting a table for a special occasion. Learn where they should all be placed and how their placement should vary with a sit-down dinner versus a buffet serving. Or, you could earn the Table Setting badge at your level.');
INSERT INTO badge_optional_requirements VALUES(1863,134,6,'Discuss the importance of the appearance of food. What would you think if someone served you a meal of  four different kinds of soup? What if all your pieces of food were cut into unusual shapes? Think of five pairs of food that would lack eye-appeal such as baked cod served with mashed potatoes. What could you do to improve their  appearance? Learn at least 3 different garnish or plating techniques to improve the look of the food. Or, you could earn the Food Presentation badge at your level.');
INSERT INTO badge_optional_requirements VALUES(1864,134,7,'How important is it  to know how to cook food from different countries? What is “comfort food?” Can serving a person’s native foods be a way of honoring that person? Where do you go to find out what people eat in different geographical areas? Where do you find unusual ingredients to use in cooking? Research a country’s food that you have never tasted, and create a sample menu.');
INSERT INTO badge_optional_requirements VALUES(1865,134,8,'Cook the sample menu you created in requirement 7 and serve it to family or friends.');
INSERT INTO badge_optional_requirements VALUES(1866,134,9,'Learn how to describe food so that it sounds appealing. Write out a paragraph describing a meal and ask another person for suggestions on how to make the food sound even better. When is it appropriate to write out a fixed menu to send with an invitation or to place on a table? Think of a more “exciting way” to list a salad, a soup, a main dish, and a dessert other than its common name (does Luscious Lemon Cake sound better than Lemon Cake?).');
INSERT INTO badge_optional_requirements VALUES(1867,134,10,'Make up a menu that combines different tastes and textures for a pleasing variety. Cook this menu with the help of an adult for your family or friends. Questions to think about and discuss: What would  you think of a meal that had a lot of salt in every course or each dish had a lot of sugar in it? What makes a meal or dish ‘heavy’  or ‘light’? What is “cleansing the palate?” How important is it to offer diners a beverage other than water?');
INSERT INTO badge_optional_requirements VALUES(1868,134,11,'What are some special kitchen utensils that a chef or advanced cook might use? Learn five of their names, their uses, and how much they cost.');
INSERT INTO badge_optional_requirements VALUES(1869,134,12,'Help elevate a meal for a charitable organization from ordinary to special OR volunteer at a fundraiser that includes beautifully served food.');
INSERT INTO badge_optional_requirements VALUES(1870,134,13,'Think of at least three dishes that are easy to overcook. Choose what you consider is a complicated or difficult dish and learn how to make it.');
INSERT INTO badge_optional_requirements VALUES(1871,134,14,'Research two famous banquets in history. What made them famous? Did the chefs or cooks  know beforehand that this was going to be a famous banquet? Do we know what was served and how it looked?');
INSERT INTO badge_optional_requirements VALUES(1872,134,15,'Research careers as a chef. What type of salary could you expect? Do you have to start at a lower position and work your way up? How does a chef command a kitchen?');
INSERT INTO badge_optional_requirements VALUES(1873,135,3,'Explain how the end use or purpose of a product affects its chemical formulation. In a clear container, mix a half-cup of water with a tablespoon of oil. Explain why the oil and water do not mix. Find a substance that will help the two combine, and add it to the mixture. Describe what happened, and explain how that substance worked to combine the oil and water.');
INSERT INTO badge_optional_requirements VALUES(1874,135,4,'Visit a laboratory and talk to a practicing chemist. Ask what the chemist does, and what training and education are needed to work as a chemist.');
INSERT INTO badge_optional_requirements VALUES(1875,135,5,'Learn what a molecule is. Make marshmallow molecules. You will need both large and small marshmallows, a bunch of toothpicks and a felt pen. Assign an “atom” to each of the marshmallows. The large marshmallows should be either C, N, or O and the small marshmallows should be H or Cl. Use the following rules for the number of toothpicks that can go into a marshmallow. Carbon ( C ) 4 toothpicks all pointing away from each other. Nitrogen ( N ) 3 toothpicks pointing downward. Oxygen ( O ) 2 toothpicks pointing downward Hydrogen (H) and Chlorine (Cl) 1 toothpick pointing any direction. Now try making the following molecules from your marshmallow atoms: H2O:  This is one oxygen and two hydrogens. NH3:  This is one nitrogen and three hydrogens. CH4:  This is one carbon and four hydrogens. CH3OH:  This is one carbon with three hydrogens and one oxygen.  The oxygen has one hydrogen. Now following the rules of how many toothpicks can go into a particular marshmallow make as many different shapes as you can without breaking the rules.  Bonus if you can find out what each combination makes.');
INSERT INTO badge_optional_requirements VALUES(1876,135,6,'Learn how to recognize chemical reactions by using the following experiment. You will need: Baking soda, lemon juice, balsamic vinegar, sugar (1-2 Tbsp dissolved in ¼ cup water), salt (1-2 Tbsp dissolved in ¼ cup water)  egg whites, several small jars or clear bowls, an eye dropper. Using the items above, mix 2 at time in a small jar and note the reaction.  Look for things like bubble, color change or a precipitate (small particles that form.)  Which items create a chemical reaction when mixed?  Which don’t?');
INSERT INTO badge_optional_requirements VALUES(1877,135,7,'With the help of an adult, create an acid-base indicator. You will need: A head of red cabbage, distilled water, small jars, coffee filters, eye dropper, ammonia, vinegar, and various liquids such as soda pop, milk, and fruit juice. Divide the head of cabbage into several pieces and boil it in 3 cups of distilled water for several minutes. When the water is a deep purple color, remove the cabbage and let the water cool.  This is your acid base indicator. Cut the coffee filters into small strips about 2cm wide by 4cm long. Dip the strips into the cooled cabbage water and allow to dry.  Dip them a second time and allow to dry again.  They should be slightly pink and uniform in color.  This is your acid indicator paper. Label one jar “control acid” and place one Tbsp of vinegar and 5 Tbsp of water into it.  This is your known acid. Label another jar “control base” and place on Tbsp of ammonia and 5 Tbsp of water in the jar.  This is your known base. Place one Tbsp of each of the other solutions you have collected in a jar with 2-5 Tbsp of water. Carefully dip the pH paper you created (your acid base indicator) into the control acid and record the color that it turns. Carefully dip a new pH paper into the control base and record the color that it turns. Now dip a pH paper into each of the solutions you gathered.  Judging by the color change, which are acids and which are bases?');
INSERT INTO badge_optional_requirements VALUES(1878,135,8,'Find a book on edible science experiments and prepare something yummy for which you can explain the chemistry behind the product');
INSERT INTO badge_optional_requirements VALUES(1879,135,9,'Describe how you could separate sand from water, table salt from water, oil from water, and gasoline from motor oil. Name the practical processes that require these kinds of separations.');
INSERT INTO badge_optional_requirements VALUES(1880,135,10,'Name two government agencies that are responsible for tracking the use of chemicals for commercial or industrial use. Pick one agency and briefly describe its responsibilities to the public and the environment.');
INSERT INTO badge_optional_requirements VALUES(1881,135,11,'Learn about famous chemistry discoveries such as the periodic table, polymers, or antibiotics. Create a timeline of key events.');
INSERT INTO badge_optional_requirements VALUES(1882,135,12,'Define pollution. Explain the chemical effects of ozone, global warming, and acid rain. Pick a current environmental problem as an example. Briefly describe what people are doing to resolve this hazard and to increase understanding of the problem.');
INSERT INTO badge_optional_requirements VALUES(1883,135,13,'Visit a county farm agency or similar governmental agency and learn how chemistry is used to meet the needs of agriculture in your county.');
INSERT INTO badge_optional_requirements VALUES(1884,135,14,'Do any two high-school level experiments with lab reports from the following topics: Chemical reactions and their equations Light and matter Distillation Families of organic compounds Acids/bases Combustion Analysis of a common substance (a food or hard water, etc.) Chromatography Spectroscopy Making polymers.');
INSERT INTO badge_optional_requirements VALUES(1885,135,15,'Be able to identify and demonstrate proper use and cleaning of: Bunsen burner Tubing Evaporating dish Test tubes, tongs, and stoppers Erlenmeyer flasks Wire gauze Graduated cylinders Pipettes Thermometers Scales Ring stands and clamps');
INSERT INTO badge_optional_requirements VALUES(1886,135,16,'Memorize at least the first fifty elements on the Periodic Table of elements. Recite them to one other person.');
INSERT INTO badge_optional_requirements VALUES(1887,135,17,'Be able to explain the periodic table. Why are the elements organized the way they are? What is the difference between the atomic number and the atomic weight?');
INSERT INTO badge_optional_requirements VALUES(1888,135,18,'Describe three examples of safety equipment used in a chemistry laboratory and the reason each one is used. Describe what a material safety data sheet (MSDS) is and tell why it is used. Obtain an MSDS for both a paint and an insecticide. Compare and discuss the toxicity, disposal, and safe-handling sections for these two common household products. Discuss the safe storage of chemicals. How does the safe storage of chemicals apply to your home, your school, your community, and the environment?');
INSERT INTO badge_optional_requirements VALUES(1889,135,19,'Interview or shadow someone who works in chemistry—such as a pharmacist, lab technician, environmental scientist, or food chemist');
INSERT INTO badge_optional_requirements VALUES(1890,135,20,'Find out how chemistry is used in a specific industry, such as agriculture, cosmetics, or environmental science.');
INSERT INTO badge_optional_requirements VALUES(1891,135,21,'Participate in a community service project that involves chemistry, such as a water quality testing day or a safe cleaning product workshop.');
INSERT INTO badge_optional_requirements VALUES(1892,135,22,'Learn basic lab safety rules and demonstrate how to safely measure, pour, mix, and clean up materials');
INSERT INTO badge_optional_requirements VALUES(1893,136,3,'Visit or participate in a chess tournament.');
INSERT INTO badge_optional_requirements VALUES(1894,136,4,'Learn how to write chess notation and record a game.');
INSERT INTO badge_optional_requirements VALUES(1895,136,5,'Create your own set of chess pieces. You may use any form of media such as Lego, modelling clay, wood, cardboard etc.  Use this set in a game. How different did the game feel with different pieces? Do you and your opponent prefer the new pieces or the standard pieces?');
INSERT INTO badge_optional_requirements VALUES(1896,136,6,'Play a game with someone in a nursing home or other place where you can share your knowledge with the community.');
INSERT INTO badge_optional_requirements VALUES(1897,136,7,'Learn opening strategies like controlling the center of the board, exposing the king, etc.');
INSERT INTO badge_optional_requirements VALUES(1898,136,8,'Learn about special tactics like fork, skewer and pin.');
INSERT INTO badge_optional_requirements VALUES(1899,136,9,'Learn about the U.S. Chess Federation ratings for chess players.');
INSERT INTO badge_optional_requirements VALUES(1900,136,10,'Explain or demonstrate rules for promotion, en passant, and castling.');
INSERT INTO badge_optional_requirements VALUES(1901,136,11,'Learn how to checkmate using 2 rooks, rook and king, and king and queen.');
INSERT INTO badge_optional_requirements VALUES(1902,136,12,'Research different versions of chess boards. Many popular franchises are releasing their own chess boards, such as Disney, Nintendo, or Star Wars. How might game play be different using one of these unique boards?');
INSERT INTO badge_optional_requirements VALUES(1903,136,13,'With a parent’s permission, participate in an online chess tournament.');
INSERT INTO badge_optional_requirements VALUES(1904,136,14,'Watch a movie or documentary about chess.');
INSERT INTO badge_optional_requirements VALUES(1905,136,15,'Read a book on chess. What did you learn? Did you learn any new strategies?');
INSERT INTO badge_optional_requirements VALUES(1906,136,16,'Compete in a chess tournament.');
INSERT INTO badge_optional_requirements VALUES(1907,137,3,'Level 2 & Under Only: Fix a healthy snack for a child younger than you. Make sure you have an adult’s permission before you begin and be aware of any food restrictions due to age or allergies.');
INSERT INTO badge_optional_requirements VALUES(1908,137,4,'Learn the proper way to hold and carry a baby. Learn how various baby restraints operate including those on a high chair, swing, bouncy seat, and car seat. Also learn how to feed and dress a baby.');
INSERT INTO badge_optional_requirements VALUES(1909,137,5,'Put together a list of games and activities that you might use to entertain a younger child. What types of activities are appropriate for infants verses toddlers?');
INSERT INTO badge_optional_requirements VALUES(1910,137,6,'Put together a “rainy days activity box” to keep young children busy indoor. Include supplies for at least 6 activities. Give the box to a family with small children.');
INSERT INTO badge_optional_requirements VALUES(1911,137,7,'A babysitter needs a lot of information before being left alone with young children. Create a form that can be used by parents to inform their sitters of important information. Your form should include the following: Parents’ Names A phone number where they can be reached or alternate person to call in an emergency. Home address and phone number Nearest cross street Emergency numbers or 911 Doctor’s phone number Any allergies Special care instructions (feedings, bedtime routines, favorite toys, etc.) Permission slip for medical professionals to do what they need to in case they can not reach a parent. Give your form to your parents to use when they need a sitter.');
INSERT INTO badge_optional_requirements VALUES(1912,137,8,'Children are capable of different things at different ages. Create a chart that shows what kids can do at each of the following ages: 0-6 months 6-12 months 12-18 months 18-24 months 2 years 3 years 4 years 5 years');
INSERT INTO badge_optional_requirements VALUES(1913,137,9,'Read to a younger child for at least 1 hour (time can be broken into increments).');
INSERT INTO badge_optional_requirements VALUES(1914,137,10,'Put together a “Restaurant Survival Kit” for a family with small children. Find a small box and place things inside such as crayons, a small notepad, a mini Etch-A-Sketch, small plastic animals, etc. Stay away from things like balls or cars that can roll off the table.');
INSERT INTO badge_optional_requirements VALUES(1915,137,11,'Learn the proper way to change a diaper. How should diapers be disposed of? What are the advantages/disadvantages of cloth diapers verses disposable diapers?');
INSERT INTO badge_optional_requirements VALUES(1916,137,12,'Become familiar with local, state, and federal laws that protect children. Find out what you should do if you suspect child abuse.');
INSERT INTO badge_optional_requirements VALUES(1917,137,13,'Watch at least 5 different children’s TV shows. Write a review of each explaining why you think it is a positive or negative influence on young children. Consider educational value, moral value, creativity, and entertainment.');
INSERT INTO badge_optional_requirements VALUES(1918,137,14,'Create a file of songs, games, finger plays, and stories that young children enjoy. You can even include simple crafts. Keep adding to your file and use these ideas when you babysit.');
INSERT INTO badge_optional_requirements VALUES(1919,137,15,'Compare 2 types of toys today to what children played with 20 years ago, 40 years ago, and 60 years ago. What changes do you see as technology advances?  What type of toys do you think your children will be playing with? Design a toy for the future.');
INSERT INTO badge_optional_requirements VALUES(1920,137,16,'Volunteer to help with the child care at a community event at your local school, church, library, or other site.');
INSERT INTO badge_optional_requirements VALUES(1921,137,17,'Create a recreation guidebook of your town for parents with young children. Include local parks and playgrounds, children’s museums, festivals,  gyms or roller rinks that allow small children (be sure to include age requirements when necessary).');
INSERT INTO badge_optional_requirements VALUES(1922,137,18,'Visit both an institutional daycare and an in-home daycare. What are the differences? Compare the ratio of adults to children, meals served, toys and entertainment available, educational activities, cleanliness, etc. What routines do they follow? Interview at least one worker from each and find out why they chose this form of day-care.');
INSERT INTO badge_optional_requirements VALUES(1923,137,19,'Interview a full-time work outside the home parent, a part-time work outside the home parent, a work-at-home parent, and a full-time stay at home parent.  What child care arrangements do they each have? What roles do their spouse, grandparents, or other family members play in caring for the children? Ask about the advantages and disadvantages of each type of child care.');
INSERT INTO badge_optional_requirements VALUES(1924,137,20,'Level 3 & Up Only: Offer to baby sit for at least 3 hours (Levels 4-5: 6 hours) free of charge to a mother in need.');
INSERT INTO badge_optional_requirements VALUES(1925,137,21,'Level 3 & Up Only: Create a “Babysitting Club” with friends or other girls in your club or troop. Create a brochure to advertise your group’s services and contact information.  Meet regularly to exchange ideas and tips.');
INSERT INTO badge_optional_requirements VALUES(1926,137,22,'Level 3 & Up Only: Develop a client list of people for whom you baby sit. Include the parent’s names, children’s names and ages, address, phone number, and any special information you need to remember such as allergies or medications.  Create a babysitting bag that includes emergency phone numbers, a flashlight, band aids, a little money in case of emergency, and a special book or game for the children to play.');
INSERT INTO badge_optional_requirements VALUES(1927,138,3,'Learn about why a gold ribbon is the symbol of childhood cancer.');
INSERT INTO badge_optional_requirements VALUES(1928,138,4,'Make a craft using a gold ribbon as your theme to represent childhood cancer awareness.');
INSERT INTO badge_optional_requirements VALUES(1929,138,5,'Read a book about cancer.');
INSERT INTO badge_optional_requirements VALUES(1930,138,6,'Watch a movie or documentary about someone with cancer.');
INSERT INTO badge_optional_requirements VALUES(1931,138,7,'Spend some time with a child or adult who is currently receiving treatment for cancer or is a cancer survivor.');
INSERT INTO badge_optional_requirements VALUES(1932,138,8,'Participate in a community service project that promotes childhood cancer awareness, like a walk-a-thon or bake sale.');
INSERT INTO badge_optional_requirements VALUES(1933,138,9,'Learn about a childhood cancer courage and support programs like The Beads of Courage or ACCO’s Hero Beads.');
INSERT INTO badge_optional_requirements VALUES(1934,138,10,'What is the Children’s Miracle Network? When was it founded, and by whom? Who do they help and how? What is the CMN hospital that services your area? Report on what you’ve learned to your family or troop.');
INSERT INTO badge_optional_requirements VALUES(1935,138,11,'Visit a doctor’s office, clinic, hospital, or other health facility that treats childhood cancer patients.');
INSERT INTO badge_optional_requirements VALUES(1936,138,12,'What is meant by “staging” in a cancer diagnosis? How is the staging of a cancer done?');
INSERT INTO badge_optional_requirements VALUES(1937,138,13,'Make a donation of any amount to your choice of childhood cancer related charity.');
INSERT INTO badge_optional_requirements VALUES(1938,138,14,'Learn about careers that involve treating, diagnosing, or are related in any way to childhood cancer, such as a doctor, nurse or technician. What sort of schooling would you need? Where could you expect to work?');
INSERT INTO badge_optional_requirements VALUES(1939,139,3,'Taste a minimum of three gourmet dark chocolates and compare their tastes. Levels 3 & Up: Write a short report on the taste differences.');
INSERT INTO badge_optional_requirements VALUES(1940,139,4,'Play a chocolate game such as Chocolatier or Chocolatier II.');
INSERT INTO badge_optional_requirements VALUES(1941,139,5,'Make at least five chocolate candies in molds.');
INSERT INTO badge_optional_requirements VALUES(1942,139,6,'Learn the history of at least two major chocolate-producing companies. Make a timeline of their histories. It should include a minimum of ten important events.');
INSERT INTO badge_optional_requirements VALUES(1943,139,7,'Bake five chocolate baked goods. Two with melted chocolate and three with cocoa powder.');
INSERT INTO badge_optional_requirements VALUES(1944,139,8,'Write a short report on the health benefits of dark chocolate or cocoa.');
INSERT INTO badge_optional_requirements VALUES(1945,139,9,'What is the average income of a cocoa farmer? Is this a low, average, or high income for his country? What is the average income of an employee in a chocolate factory? What are the top three countries that produce finished chocolate candies?');
INSERT INTO badge_optional_requirements VALUES(1946,139,10,'Learn the definitions of cocoa, cocoa butter, cacao nibs, white chocolate, milk & dark chocolate. Taste any of them you’ve previously never eaten.');
INSERT INTO badge_optional_requirements VALUES(1947,139,11,'Name six non-baked chocolate desserts. Level 1: Make one dessert. Levels 2 & Up: Make two desserts.');
INSERT INTO badge_optional_requirements VALUES(1948,139,12,'Find three main dish recipes that include chocolate as an ingredient.');
INSERT INTO badge_optional_requirements VALUES(1949,139,13,'Use chocolate to make decorations on a fancy dessert or dish. Examples are curls, cutouts, leaves, and molded chocolates.');
INSERT INTO badge_optional_requirements VALUES(1950,139,14,'Find out some of the government standards for keeping chocolate clean as it moves through a factory. Find out the concentration of insect parts that are allowed in chocolate.');
INSERT INTO badge_optional_requirements VALUES(1951,139,15,'Draw a diagram of all the steps in chocolate candy making. Start with the tree all the way to the finished product.');
INSERT INTO badge_optional_requirements VALUES(1952,139,16,'Hold a bake sale that includes only chocolate goods. Follow all federal, state, and local laws. Donate the proceeds to a charity of your choice or to your group.');
INSERT INTO badge_optional_requirements VALUES(1953,139,17,'Research careers that involve chocolate, such as a baker, cocoa farmer, etc. Learn what type of training you would need and what type of salary you could expect.');
INSERT INTO badge_optional_requirements VALUES(1954,139,18,'Visit a chocolate or candy factory, a sweet shop, or bakery. Interview one of the workers about the chocolate making process.');
INSERT INTO badge_optional_requirements VALUES(1955,140,3,'Learn about a missionary from history. Where did he/she serve? What challenges did he/she encounter? Share his/her story with someone.');
INSERT INTO badge_optional_requirements VALUES(1956,140,4,'What jobs are considered missionary jobs? Find as many as you can.');
INSERT INTO badge_optional_requirements VALUES(1957,140,5,'How many societies do not have the Bible in their language? Find out a little about translation work.');
INSERT INTO badge_optional_requirements VALUES(1958,140,6,'What training is needed to be a missionary? Is this training the same for every job in missions?');
INSERT INTO badge_optional_requirements VALUES(1959,140,7,'Discuss with a parent or guardian how you can be a missionary.');
INSERT INTO badge_optional_requirements VALUES(1960,140,8,'Research some opportunities for short term missions. How do they differ from long term missions? Try to find a trip you could go on.');
INSERT INTO badge_optional_requirements VALUES(1961,140,9,'Go on a mission trip. Share your experience with a group, whether it be your family, your friends, your club, or your church.');
INSERT INTO badge_optional_requirements VALUES(1962,140,10,'Do something to support a missionary, such as send money, pray regularly, send encouragement, provide supplies, help them to set up for a presentation, etc.');
INSERT INTO badge_optional_requirements VALUES(1963,140,11,'Talk to a missionary or exchange letters or emails. What does he/she do? Where does he/she serve? What challenges does he/she face? What is family life like for them? Find his/her location on a map.');
INSERT INTO badge_optional_requirements VALUES(1964,140,12,'Research a missions organization. Where do they work? What is the focus of their work? What jobs do their missionaries do? How are their missionaries paid? What is family life like for missionaries in their organization?');
INSERT INTO badge_optional_requirements VALUES(1965,140,13,'Not all missionaries serve in foreign countries. Research some missionaries or projects in your country.');
INSERT INTO badge_optional_requirements VALUES(1966,140,14,'Think of several things you do easily in your town – grocery shopping, haircuts, doctor visits, etc. How do you think you might handle this in a remote area? Do a little research or ask a missionary if you can. Discuss at least five tasks.');
INSERT INTO badge_optional_requirements VALUES(1967,140,15,'Prepare a poster or pamphlet on what you have learned about missions. Share it with your family, friends, or group. Sharing about missions work is one of the best ways to encourage missions.');
INSERT INTO badge_optional_requirements VALUES(1968,141,1,'Make Christmas cards in the style of another country.');
INSERT INTO badge_optional_requirements VALUES(1969,141,2,'Learn a Christmas song in another language.');
INSERT INTO badge_optional_requirements VALUES(1970,141,3,'Design a costume typically worn during the holiday season in another country.');
INSERT INTO badge_optional_requirements VALUES(1971,141,4,'Throw a Christmas party in the tradition of a country of your choosing.');
INSERT INTO badge_optional_requirements VALUES(1972,141,5,'Attend a Christmas production (music, theater, school program, etc).');
INSERT INTO badge_optional_requirements VALUES(1973,141,6,'Make a traditional Christmas dessert from another country.');
INSERT INTO badge_optional_requirements VALUES(1974,141,7,'Go caroling with your group. Make sure to include at least one song that originated from a foreign country.');
INSERT INTO badge_optional_requirements VALUES(1975,141,8,'Create a Christmas craft that is somehow related to a country of your choosing.');
INSERT INTO badge_optional_requirements VALUES(1976,141,9,'Learn about the true meaning of Christmas vs. the commercialized Christmas.');
INSERT INTO badge_optional_requirements VALUES(1977,141,10,'Write a short letter to Santa in a different language.');
INSERT INTO badge_optional_requirements VALUES(1978,141,11,'Read a Christmas story from a country of your choosing.');
INSERT INTO badge_optional_requirements VALUES(1979,141,12,'Watch a foreign movie that is related to Christmas.');
INSERT INTO badge_optional_requirements VALUES(1980,141,13,'Connect with a pen-pal from a different country and ask how they celebrate Christmas.');
INSERT INTO badge_optional_requirements VALUES(1981,141,14,'Watch a documentary about Christmas celebrations in another country.');
INSERT INTO badge_optional_requirements VALUES(1982,141,15,'Create a world map highlighting countries that do not celebrate Christmas and discuss why this is.');
INSERT INTO badge_optional_requirements VALUES(1983,141,16,'Compare how Christmas is celebrated differently in tropical, temperate, and snowy regions.');
INSERT INTO badge_optional_requirements VALUES(1984,141,17,'Research what a Christmas market is and how Christmas markets are celebrated in European countries like Germany or Austria.');
INSERT INTO badge_optional_requirements VALUES(1985,141,18,'Study KFC’s role in Christmas traditions in Japan and explain why it became popular.');
INSERT INTO badge_optional_requirements VALUES(1986,141,19,'Compare how Christian, secular, and cultural Christmas traditions overlap and differ worldwide.');
INSERT INTO badge_optional_requirements VALUES(1987,141,20,'Organize a cultural “Christmas Around the World” event or presentation for your family, club or  community.');
INSERT INTO badge_optional_requirements VALUES(1988,142,3,'Learn the history of Christmas carols. Preschool and Level 1: Learn about two Christmas Carols. Level 2: Learn three. Level 3: Learn four. Level 4: Learn five. Level 5: Learn six.');
INSERT INTO badge_optional_requirements VALUES(1989,142,4,'Learn all of the verses to one carol.');
INSERT INTO badge_optional_requirements VALUES(1990,142,5,'Rewrite a carol in your own words/modern language.');
INSERT INTO badge_optional_requirements VALUES(1991,142,6,'Write your own carol.');
INSERT INTO badge_optional_requirements VALUES(1992,142,7,'Create a book of carols for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(1993,142,8,'Learn to play a carol on the instrument of your choice. Perform it for someone.');
INSERT INTO badge_optional_requirements VALUES(1994,142,9,'Poll your friends & family about their favorite carol. Graph the results and share the information with your family, friends, or group. Is there a correlation between a person’s age and their favorite carol?');
INSERT INTO badge_optional_requirements VALUES(1995,142,10,'Research and listen to a modern carol – no more than fifteen years old.');
INSERT INTO badge_optional_requirements VALUES(1996,142,11,'Listen to two carols from other countries.');
INSERT INTO badge_optional_requirements VALUES(1997,142,12,'Participate in a Christmas program that uses carols.');
INSERT INTO badge_optional_requirements VALUES(1998,142,13,'Attend a Christmas program that uses carols.');
INSERT INTO badge_optional_requirements VALUES(1999,142,14,'Watch a television special that focuses on Christmas carols.');
INSERT INTO badge_optional_requirements VALUES(2000,143,3,'Make a personalized ornament. What are some ways to make an ornament personalized?');
INSERT INTO badge_optional_requirements VALUES(2001,143,4,'Make an ornament with a message such as a nativity scene or an inspirational quote. Single words such as “joy” or “peace” do not count.');
INSERT INTO badge_optional_requirements VALUES(2002,143,5,'Decorate a tree as part of a community service project.');
INSERT INTO badge_optional_requirements VALUES(2003,143,6,'Make an ornament with components that are usually considered trash (up-cycled).');
INSERT INTO badge_optional_requirements VALUES(2004,143,7,'Discuss safety issues with Christmas trees. Know what to do if your Christmas tree catches fire or falls over. Understand why ornaments should be distributed evenly around a tree and not just on the visible side if the tree is in a corner (so that the weight is even and the tree does not tip over). Discuss safety hazards of ornaments such as paper ornaments next to hot lights, glass ornaments that can break, etc.');
INSERT INTO badge_optional_requirements VALUES(2005,143,8,'Visit a museum that displays several dozen antique ornaments or look through several books picturing old ornaments.');
INSERT INTO badge_optional_requirements VALUES(2006,143,9,'Organize and host an ornament exchange party.');
INSERT INTO badge_optional_requirements VALUES(2007,143,10,'Make ornaments that are used at a function of a non-profit organization.');
INSERT INTO badge_optional_requirements VALUES(2008,143,11,'Make a tree topper and a garland for Christmas trees.');
INSERT INTO badge_optional_requirements VALUES(2009,143,12,'Learn how to wrap and cushion an ornament for shipping or mailing. Send an ornament in the mail.');
INSERT INTO badge_optional_requirements VALUES(2010,143,13,'Learn about collectible ornaments. Find at least five companies that produce collectible ornaments and research what at least three discontinued ornaments are now worth.');
INSERT INTO badge_optional_requirements VALUES(2011,143,14,'Visit a Christmas store with at least five different themed trees and discuss what other type of ornaments could be made to match each tree.');
INSERT INTO badge_optional_requirements VALUES(2012,143,15,'Learn how to properly take ornaments off the tree and store them until next Christmas. Make sure they are cushioned and wrapped properly so as not to break. Clean up an entire Christmas tree on your own (or with the help of a parent for Preschool and Level 1).');
INSERT INTO badge_optional_requirements VALUES(2013,143,16,'Make a list of ornaments that cannot ordinarily be made at home, such as blown glass, molten glass, extruded plastic or soldered metal ornaments. How are these ornaments made? Why can’t you make them at home?');
INSERT INTO badge_optional_requirements VALUES(2014,144,3,'Draw a picture of your favorite Narnia character.');
INSERT INTO badge_optional_requirements VALUES(2015,144,4,'Put on a play or a puppet show of a scene out of one of the Narnia books.');
INSERT INTO badge_optional_requirements VALUES(2016,144,5,'Make up a story of your own with some of the characters in the Narnia books.');
INSERT INTO badge_optional_requirements VALUES(2017,144,6,'Try Turkish Delight from The Lion, the Witch, and the Wardrobe. Do you think it was as tasty as Edmund did?');
INSERT INTO badge_optional_requirements VALUES(2018,144,7,'There have been several versions of the Chronicles of Narnia created for television. With parental permission, watch a Narnia movie or show.  Discuss or write about the differences between the movie or show and the book.');
INSERT INTO badge_optional_requirements VALUES(2019,144,8,'Find out the difference between the originally published order of the books and the chronological order of the books.  Which order do you think they should be read in and why?');
INSERT INTO badge_optional_requirements VALUES(2020,144,9,'Earn a Character badge that represents a quality of one of the main characters in the Narnia books such as Courage or Faithfulness.  Who is that character?  How does he or she embody that quality?');
INSERT INTO badge_optional_requirements VALUES(2021,144,10,'Find out when and where the Narnia books were written.  Level 2 and Up: Find out what historical events were happening at that time.');
INSERT INTO badge_optional_requirements VALUES(2022,144,11,'Read and discuss a Narnia book with a book club.');
INSERT INTO badge_optional_requirements VALUES(2023,144,12,'Write a scene out of one of the Narnia books from another character’s point of view.');
INSERT INTO badge_optional_requirements VALUES(2024,144,13,'Write a rough timeline of Narnia’s history based on the books.');
INSERT INTO badge_optional_requirements VALUES(2025,144,14,'Research C.S. Lewis and write a brief biography of his life. How did his life affect his literature? What other notable author did Lewis know?');
INSERT INTO badge_optional_requirements VALUES(2026,144,15,'What are the common religious and non-religious themes in the Chronicles of Narnia?');
INSERT INTO badge_optional_requirements VALUES(2027,144,16,'Find out the religious themes that C.S. Lewis considered each book to cover. Why do you think these were important to him?');
INSERT INTO badge_optional_requirements VALUES(2028,144,17,'Who does Aslan represent?  Who does the White Witch represent?  Discuss with a parent the similarities and differences between the characters and their Biblical parallels.');
INSERT INTO badge_optional_requirements VALUES(2029,144,18,'Find out about one of the people that C.S. Lewis dedicated a Narnia book to.');
INSERT INTO badge_optional_requirements VALUES(2030,145,3,'Learn about the different types of animals used in the circus and their routines. Which is your favorite?');
INSERT INTO badge_optional_requirements VALUES(2031,145,4,'Learn about the history of circus music and listen to some.');
INSERT INTO badge_optional_requirements VALUES(2032,145,5,'What is clown school? Create your own clown act.');
INSERT INTO badge_optional_requirements VALUES(2033,145,6,'Learn about the history of circus trains. Go see one if it comes through your town. Make a model or drawing of a circus train using oatmeal containers and shoe boxes and any other craft material you have.');
INSERT INTO badge_optional_requirements VALUES(2034,145,7,'Learn about the history of circus posters. Design your own poster for a circus or other fun event (camp-out, pinewood derby, field trip, etc). Use plenty of color, action and descriptive words.');
INSERT INTO badge_optional_requirements VALUES(2035,145,8,'Learn to juggle.');
INSERT INTO badge_optional_requirements VALUES(2036,145,9,'Besides performing, what other jobs are available with the circus? What training is required? What salary would you expect?');
INSERT INTO badge_optional_requirements VALUES(2037,145,10,'Participate in a community service project that involves the circus. You might create a mini circus for some younger children to enjoy, raise money to buy and donate tickets to low income families, or help increase awareness for animal rights within circuses.');
INSERT INTO badge_optional_requirements VALUES(2038,145,11,'Visit a circus museum.');
INSERT INTO badge_optional_requirements VALUES(2039,145,12,'With friends and family, create your own circus. Use costumes, face paint and any props you have. Use hula hoops for your rings. Sell tickets, popcorn & peanuts. Get creative and have fun!');
INSERT INTO badge_optional_requirements VALUES(2040,145,13,'Learn about careers in the circus. This could include performers, circus managers, event coordinators, etc. What type of education is necessary for one of these jobs? What type of salary could you expect? What type of travel might you have to do?');
INSERT INTO badge_optional_requirements VALUES(2041,146,3,'Go to the polls with your parent when they vote. Discuss their choices. Levels 3 & Up: Who are the candidates? What bills and propositions are up for vote?');
INSERT INTO badge_optional_requirements VALUES(2042,146,4,'Take a field trip to a police station and fire department. How do these departments impact the local citizens? As a citizen, what can you do to help them?');
INSERT INTO badge_optional_requirements VALUES(2043,146,5,'Visit a local government office and talk to someone involved with the governmental process.');
INSERT INTO badge_optional_requirements VALUES(2044,146,6,'Learn how a bill becomes a law in the United States. Create a flowchart or comic strip to explain it.');
INSERT INTO badge_optional_requirements VALUES(2045,146,7,'Discuss how community service is part of being a good citizen. Participate in a community service project and discuss how it helped you to be a better citizen.');
INSERT INTO badge_optional_requirements VALUES(2046,146,8,'Create a poster or collage about America and why you like being a citizen of our country.');
INSERT INTO badge_optional_requirements VALUES(2047,146,9,'Take a tour of your state capital.');
INSERT INTO badge_optional_requirements VALUES(2048,146,10,'Participate in a parade or other local community event.');
INSERT INTO badge_optional_requirements VALUES(2049,146,11,'Write a letter to your local newspaper or government official about an issue that concerns you. You may send your letter by either email or regular mail.');
INSERT INTO badge_optional_requirements VALUES(2050,146,12,'Visit a courtroom and talk to someone who works there.');
INSERT INTO badge_optional_requirements VALUES(2051,146,13,'Find out how someone becomes a citizen of the United States. If possible, interview someone who has become a naturalized citizen. Why did they want to become a citizen of the United States?');
INSERT INTO badge_optional_requirements VALUES(2052,146,14,'Learn how recycling and conservation helps to protect our environment. How does protecting our environment make us better citizens?');
INSERT INTO badge_optional_requirements VALUES(2053,146,15,'Read the biography of someone you consider a good citizen. Write a brief book report regarding their citizenship.');
INSERT INTO badge_optional_requirements VALUES(2054,146,16,'Make a list of organizations, other than churches and religious groups, in your community that help people. What do they do? How would your community function without them?');
INSERT INTO badge_optional_requirements VALUES(2055,146,17,'Attend a city or town council meeting, or school board meeting. What issues were discussed? Which side did you agree with and why?');
INSERT INTO badge_optional_requirements VALUES(2056,146,18,'Put together a pamphlet of local governmental offices, sites of interest, hospitals, police stations, fire stations, and anything else you think a new citizen in your community might need.  Pass out these pamphlets to local realtors, churches, or other locations that someone new to your community might visit.');
INSERT INTO badge_optional_requirements VALUES(2057,146,19,'Learn about the history of citizenship in the United States. Who could vote in the past, and how has that changed over time?');
INSERT INTO badge_optional_requirements VALUES(2058,146,20,'Compare the rights and responsibilities of citizens in at least two different countries.');
INSERT INTO badge_optional_requirements VALUES(2059,147,3,'Draw or color both Union and Confederate flags.');
INSERT INTO badge_optional_requirements VALUES(2060,147,4,'Learn about the diet of slaves or of the soldiers. What kinds of foods did they eat? Were there a variety of foods? Was the diet healthy?');
INSERT INTO badge_optional_requirements VALUES(2061,147,5,'Watch a documentary on the Civil War.');
INSERT INTO badge_optional_requirements VALUES(2062,147,6,'Visit a Civil War re-enactment.');
INSERT INTO badge_optional_requirements VALUES(2063,147,7,'Visit a location from an important event or battle that took place during the Civil War.');
INSERT INTO badge_optional_requirements VALUES(2064,147,8,'Learn the song, “Follow the Drinking Gourd” and what each verse meant.');
INSERT INTO badge_optional_requirements VALUES(2065,147,9,'Play songs that were popular among the Northern and Southern troops. Compare the songs and how they were different between the North and the South.');
INSERT INTO badge_optional_requirements VALUES(2066,147,10,'Read an age-appropriate book about the Civil War. Share your thoughts with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(2067,147,11,'Level 2 & Up Only: Play a civil war simulation board or video game.');
INSERT INTO badge_optional_requirements VALUES(2068,147,12,'Level 2 & Up Only: Watch Gone with the Wind or another historical fiction movie about the Civil War.');
INSERT INTO badge_optional_requirements VALUES(2069,147,13,'Level 3 & Up Only: Make a recruiting poster for the Union and/or Confederate army. List the reasons men should join the army on the posters.');
INSERT INTO badge_optional_requirements VALUES(2070,148,3,'Go to a play or musical based on a book of classical literature or create your own & help perform it. You can act in the play or direct it.');
INSERT INTO badge_optional_requirements VALUES(2071,148,4,'Draw a series of illustrations for a classical book you’ve read. They need to illustrate parts of the book that are not illustrated in your copy. Preschool – Level 1: Create three pictures. Levels 2 – 3: Create five pictures. Levels 4 – 5: Create seven pictures.');
INSERT INTO badge_optional_requirements VALUES(2072,148,5,'Make a poster promoting the books of one of your favorite authors.');
INSERT INTO badge_optional_requirements VALUES(2073,148,6,'Donate some books of classical literature to a charity that serves children that will use the books, rather than just sell them. They may be second hand books, but make sure they in good shape.');
INSERT INTO badge_optional_requirements VALUES(2074,148,7,'Play a game, read a poem, sing a song, visit a historical site, or prepare a dish mentioned in one of the books you read. Reading the biography of a person referred to in one of the books can also count.');
INSERT INTO badge_optional_requirements VALUES(2075,148,8,'Wear a costume for a day that is based on a character in one of the books you read. Have some historical information prepared that you can give other people who ask about your costume or memorize an interesting paragraph that you can recite for others. Levels 4 & 5: You may make the costume for a younger child to wear to fulfill your requirement.');
INSERT INTO badge_optional_requirements VALUES(2076,148,9,'Attend a party with a literary theme based on an author’s work(s).');
INSERT INTO badge_optional_requirements VALUES(2077,148,10,'Read one of your books to someone to introduce them to an author new to them.');
INSERT INTO badge_optional_requirements VALUES(2078,148,11,'Join a book club that is discussing a classical book and attend at least six meetings.');
INSERT INTO badge_optional_requirements VALUES(2079,148,12,'Read a book to the visually impaired, read to children at a childcare facility, or do a story time at a library for a minimum of two hours.');
INSERT INTO badge_optional_requirements VALUES(2080,148,13,'Design a wall mural or some curtain fabric based on a book series. If you choose curtain fabric, the panels need to be at least 12 wide.');
INSERT INTO badge_optional_requirements VALUES(2081,148,14,'After reading one of your books, read a condensed/abridged version. Did they do a good job condensing the story? What aspects did the condensers do best and which ones did you dislike the most? Why?');
INSERT INTO badge_optional_requirements VALUES(2082,148,15,'If you were to do a major research project on your favorite author, where would you go to find original documents? What would you have to do to gain permission to look at the documents? If your author is no longer living, is there a relative with whom you can talk?');
INSERT INTO badge_optional_requirements VALUES(2083,148,16,'Write a song or poem based on one of the books you read and perform it for an audience.');
INSERT INTO badge_optional_requirements VALUES(2084,148,17,'Volunteer at your local library or host a book drive.');
INSERT INTO badge_optional_requirements VALUES(2085,148,18,'What are the oldest examples of classical literature? What is the difference between an epic, a comedy, and a tragedy?');
INSERT INTO badge_optional_requirements VALUES(2086,149,3,'What are some career options where it is very important to have clean language? Research a few and share your findings with a family or friend. Some suggestions can be a teacher, judge, doctor, waitress, etc.');
INSERT INTO badge_optional_requirements VALUES(2087,149,4,'Find at least 5 verses about clean language in your book of faith. Write them down on a piece of paper.');
INSERT INTO badge_optional_requirements VALUES(2088,149,5,'Do a skit about clean language to perform for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(2089,149,6,'Earn the Modesty badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2090,149,7,'Earn the Respect badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2091,149,8,'Interview an older friend or other member of the community about their view on clean language. Do you agree? Disagree? Level 4 and 5 only: How is it similar or different from the interview you conducted in Level 3 requirement 2?');
INSERT INTO badge_optional_requirements VALUES(2092,149,9,'How has language changed in society over the years? Research language over the decades and evaluate how it has changed. Has it become cleaner or more unclean?');
INSERT INTO badge_optional_requirements VALUES(2093,149,10,'Learn why media uses unclean language and discuss with parents how it makes you feel. What kind of programs on TV are appropriate and which are not based on language?');
INSERT INTO badge_optional_requirements VALUES(2094,150,3,'Dish-washing: Demonstrate how to either wash dishes by hand or rinse them for the dishwasher and load. Levels 3 – 5: Handle your family’s dish-washing for one week.');
INSERT INTO badge_optional_requirements VALUES(2095,150,4,'Household Cleaning Equipment: What equipment and supplies do you need for each of the following household chores: Vacuuming Dusting Sweeping Mopping Scrubbing toilets Scrubbing sinks and tubs Cleaning the oven Washing the dishes Washing the laundry');
INSERT INTO badge_optional_requirements VALUES(2096,150,5,'Window Cleaning: Demonstrate how to clean mirrors and windows. Which works better: a vinegar and water mixture, plain water, or a commercially made product? Which works better: paper towels, newspaper, or a cloth?');
INSERT INTO badge_optional_requirements VALUES(2097,150,6,'Storage: Reorganize a closet or cupboard for maximum convenience and storage. Show how to properly dust books and group them on book shelves for efficient reference and interest.');
INSERT INTO badge_optional_requirements VALUES(2098,150,7,'Linens: What is the best way to store blankets, rugs, linens, and clothing to protect them from moths, insects, and mold?');
INSERT INTO badge_optional_requirements VALUES(2099,150,8,'Household pests: Preschool – Level 2: What are the causes of common household pests and what is the best way to get rid of them? Levels 3 – 5: After reviewing the causes of some common household pests, check out ways to get rid of them. How many ways can you find for getting rid of cockroaches, silverfish, ants, spiders, and termites. Which are the least toxic ways? When should you hire a professional?');
INSERT INTO badge_optional_requirements VALUES(2100,150,9,'Look for ways to neaten up your home and make it more attractive such as rearranging furniture, picking up items laying around, having fresh flowers on the table, tending the house plants, etc.');
INSERT INTO badge_optional_requirements VALUES(2101,150,10,'Laundry: Preschool – Level 1: Help sort laundry into white, lights, darks, and delicates. Help to hang the clothes to dry or load the dryer. Help put away the clean clothes. Level 2 also: Which temperatures should be used for each? How much detergent should you use? Levels 3 – 5: If you don’t know how to care for laundry yet, learn how to sort it and set the washer for the right temperature and time. Read the labels of at least three different agents used in laundering. Be in charge of sorting and washing at least three loads. What is the difference between machine washing and dry cleaning? Why do some clothes say “dry clean only?” Why should you dry some clothes flat? Why shouldn’t you machine dry an item that says “line dry?”');
INSERT INTO badge_optional_requirements VALUES(2102,150,11,'Know the care for floors, curtains, walls, furniture, and rugs. Demonstrate at least two.');
INSERT INTO badge_optional_requirements VALUES(2103,150,12,'Bathroom cleaning: Preschool – Level 2: Help to clean a bathroom in your home and find out what you can do to help keep it clean and tidy. Levels 3 – 5: Clean a bathroom in your home and find out what you can do to help keep it clean and tidy. Be in charge of keeping it clean for a week.');
INSERT INTO badge_optional_requirements VALUES(2104,150,13,'Deep Cleaning or spring cleaning: What is “deep cleaning”? Preschool – Level 2: Help to give a thorough cleaning to one room in your house. Levels 3 – 5: Deep clean one room in your house.');
INSERT INTO badge_optional_requirements VALUES(2105,150,14,'Learn about the history of housecleaning. How has electricity and wall-to-wall carpeting changed housecleaning? Try an ‘older’ method of cleaning something, such as scrubbing a floor with a scrub brush or washing several garments by hand.');
INSERT INTO badge_optional_requirements VALUES(2106,150,15,'Help your own family with keeping track of chores. Offer to mark a calendar or make a system to keep track of weekly, monthly, and yearly chores.');
INSERT INTO badge_optional_requirements VALUES(2107,150,16,'How often should a mattress be turned and why? Which types of mattresses do not need to be turned? If you have a mattress that needs to be turned, help your parents turn it properly.');
INSERT INTO badge_optional_requirements VALUES(2108,150,17,'Participate in a community service project that involves cleaning, such as offering to clean someone’s home, helping the elderly or a shelter with their chores, etc.');
INSERT INTO badge_optional_requirements VALUES(2109,150,18,'Research some health conditions that are influenced by cleanliness such as asthma, mold allergies, or emphysema. What would you do differently if someone at your house had one of these ailments? Is there anything your family should do to help prevent one of these conditions? How important is cleanliness after natural disasters? What diseases can be transmitted and health conditions worsened when there isn’t proper sanitation? What were the health effects of the Hurricane Katrina clean-up? What does a person do to make contaminated water usable?');
INSERT INTO badge_optional_requirements VALUES(2110,150,19,'Clean your refrigerator and freezer and replace the contents in the most efficient arrangement for space saving and storage.');
INSERT INTO badge_optional_requirements VALUES(2111,150,20,'Find out how to remove the following stains: Tea Coffee Ink Rust Paint Grass Fruit Blood');
INSERT INTO badge_optional_requirements VALUES(2112,150,21,'What is the effect of light on a home’s cleanliness and mood? Use a flashlight after your standard cleaning to check some corners and under some furniture. Bring an extra lamp into a room that has just been cleaned. Do you like what the extra light does for the room?');
INSERT INTO badge_optional_requirements VALUES(2113,150,22,'Take a tour of your yard and garage. Is there something you can do to clean up the garage or exterior of your home? Do it. What are some of the reasons for cleaning up the garage or exterior of a home?');
INSERT INTO badge_optional_requirements VALUES(2114,151,3,'Learn to pull snags to the other side of a fabric.');
INSERT INTO badge_optional_requirements VALUES(2115,151,4,'With the help of an adult, learn to apply an iron-on patch. Levels 4 – 5: Apply two patches. One should be reinforcing a knee before it wears through.');
INSERT INTO badge_optional_requirements VALUES(2116,151,5,'Apply an appliqué-type patch by hand. Use the same fabric with which the garment was sewn. When should new fabric not be used on an older garment?');
INSERT INTO badge_optional_requirements VALUES(2117,151,6,'Learn to darn an item. Level 3 and Up: Darn at least two items.');
INSERT INTO badge_optional_requirements VALUES(2118,151,7,'Learn how to fix bleach marks or get rid of paint or ink marks.');
INSERT INTO badge_optional_requirements VALUES(2119,151,8,'Learn to re-attach hooks, eyes, and snaps.');
INSERT INTO badge_optional_requirements VALUES(2120,151,9,'Learn when and how to use safety pins as an emergency repair tool. Level 3 & Up: Also learn how to use fabric glue and fusible interfacing as emergency repair tools.');
INSERT INTO badge_optional_requirements VALUES(2121,151,10,'Add some decoration to a garment to cover up a “boo-boo.”');
INSERT INTO badge_optional_requirements VALUES(2122,151,11,'Learn how to repair a ripped buttonhole.');
INSERT INTO badge_optional_requirements VALUES(2123,151,12,'Replace a ripped hem or lower a hem. Learn how to cover old hem line marks or inset a strip of fabric to make a garment longer.');
INSERT INTO badge_optional_requirements VALUES(2124,151,13,'Finish some seams that are starting to unravel. This can be done by hand (whipping), zigzag on a regular machine, or serging.');
INSERT INTO badge_optional_requirements VALUES(2125,151,14,'Learn how to reweave fabric that has been eaten by a moth.');
INSERT INTO badge_optional_requirements VALUES(2126,151,15,'Learn how to use a zipper-repair kit.');
INSERT INTO badge_optional_requirements VALUES(2127,151,16,'Repair some garments so they can be sold by a charity for cash or used by someone in a shelter or safe home, etc. Or do some mending for a person incapable of doing so.');
INSERT INTO badge_optional_requirements VALUES(2128,152,3,'Learn about the Coast Guard uniform. What are the purposes of the different styles?');
INSERT INTO badge_optional_requirements VALUES(2129,152,4,'Learn about three Coast Guard vehicles that are not water vehicles. What are these used for?');
INSERT INTO badge_optional_requirements VALUES(2130,152,5,'Research Rescue Swimmers. What vehicle do they usually use? What hazards to they face? For example, watch Coast Guard Alaska on the Weather Channel.');
INSERT INTO badge_optional_requirements VALUES(2131,152,6,'Research how to protect against cold water. What kinds of suits are available? What are the benefits/drawbacks of each?');
INSERT INTO badge_optional_requirements VALUES(2132,152,7,'Every Coast Guard vehicle has a red stripe. What is the meaning of this stripe? When was it implemented?');
INSERT INTO badge_optional_requirements VALUES(2133,152,8,'Make a map of at least ten Coast Guard Stations. Which one is closest to you?');
INSERT INTO badge_optional_requirements VALUES(2134,152,9,'How is the speed of a ship or boat calculated? What is a nautical mile?');
INSERT INTO badge_optional_requirements VALUES(2135,152,10,'Learn to tie important sailor knots including Bowline, Carrick Bend and Square. Along with being able to hold, these knots are important because they can be untied easily.');
INSERT INTO badge_optional_requirements VALUES(2136,152,11,'Learn Morse code and send a message to a friend.');
INSERT INTO badge_optional_requirements VALUES(2137,152,12,'What is a buoy? What is their purpose? How are they maintained?');
INSERT INTO badge_optional_requirements VALUES(2138,152,13,'Learn the basics of reading a nautical chart.');
INSERT INTO badge_optional_requirements VALUES(2139,152,14,'Choose a type of cutter and draw a diagram of it. Include important features such as crew quarters, galley and safety equipment locations.');
INSERT INTO badge_optional_requirements VALUES(2140,153,3,'Create a number cipher where each letter of the alphabet is represented by a number (e.g., A=1, B=2, C=3, etc.) and decode a message from a friend.');
INSERT INTO badge_optional_requirements VALUES(2141,153,4,'Understand the difference between a cipher and a code.');
INSERT INTO badge_optional_requirements VALUES(2142,153,5,'Define the terms plaintext, ciphertext, encryption, and decryption.');
INSERT INTO badge_optional_requirements VALUES(2143,153,6,'Be able to identify at least 6 classic ciphers such as the Caesar cipher and the Atbash cipher.');
INSERT INTO badge_optional_requirements VALUES(2144,153,7,'Learn how to count in binary (up to 10) and write your name in 8-bit ASCII.');
INSERT INTO badge_optional_requirements VALUES(2145,153,8,'Describe the role of ciphers in military and diplomatic communications throughout history.');
INSERT INTO badge_optional_requirements VALUES(2146,153,9,'Learn how cryptography has shaped computer science and digital security.');
INSERT INTO badge_optional_requirements VALUES(2147,153,10,'Understand what steganography is and how it hides information in plain sight.');
INSERT INTO badge_optional_requirements VALUES(2148,153,11,'Design a scavenger hunt using coded clues for your friends.');
INSERT INTO badge_optional_requirements VALUES(2149,153,12,'Learn how to write your name in Braille.');
INSERT INTO badge_optional_requirements VALUES(2150,153,13,'Make invisible ink using lemon juice and write a secret message. With the help of an adult, use a hair dryer to heat the page and make the writing visible. Be careful not to burn your paper.');
INSERT INTO badge_optional_requirements VALUES(2151,153,14,'Invent your own secret code or cipher and use it in a message.');
INSERT INTO badge_optional_requirements VALUES(2152,153,15,'Create a secret agent name using a code where each letter of your name corresponds to a different letter of the alphabet.');
INSERT INTO badge_optional_requirements VALUES(2153,153,16,'Make a color code where each color represents a letter. Send a message using colored beads, paint, or markers.');
INSERT INTO badge_optional_requirements VALUES(2154,153,17,'Invent a simple sign language with a friend using gestures for common words or phrases.');
INSERT INTO badge_optional_requirements VALUES(2155,153,18,'Participate in an escape room challenge that uses codes or ciphers.');
INSERT INTO badge_optional_requirements VALUES(2156,153,19,'Hold a relay race where teams must solve a series of coded messages before progressing to the next station. Incorporate a variety of ciphers and decoding techniques.');
INSERT INTO badge_optional_requirements VALUES(2157,153,20,'Collaborate on a real-world application project that involves encryption and decryption. This could include creating a secure messaging app, designing a password manager, or developing a digital treasure hunt using GPS coordinates and coded clues.');
INSERT INTO badge_optional_requirements VALUES(2158,153,21,'Learn about the Enigma machine, who invented it, its importance and how it worked.');
INSERT INTO badge_optional_requirements VALUES(2159,153,22,'What is a brute force attack? What other types of attacks are there against ciphers and codes?');
INSERT INTO badge_optional_requirements VALUES(2160,153,23,'Understand the differences between block and stream ciphers.');
INSERT INTO badge_optional_requirements VALUES(2161,153,24,'Explain why passphrases are stronger than passwords. Explain how to create a secure passphrase.');
INSERT INTO badge_optional_requirements VALUES(2162,153,25,'Learn about Navajo Code Talkers. What made their language so effective during WWII?');
INSERT INTO badge_optional_requirements VALUES(2163,153,26,'Research how emojis can act as modern pictographic codes. Write a sentence using only emojis. Ask someone to interpret it.');
INSERT INTO badge_optional_requirements VALUES(2164,153,27,'Learn about prime numbers and why they are important in modern encryption.');
INSERT INTO badge_optional_requirements VALUES(2165,153,28,'Learn about one-time pad ciphers and explain why they’re theoretically unbreakable.');
INSERT INTO badge_optional_requirements VALUES(2166,153,29,'Make a piece of artwork or jewelry that contains a secret message in code or cipher.');
INSERT INTO badge_optional_requirements VALUES(2167,153,30,'Interview someone who works in cybersecurity or another field involving encryption. Ask them about how codes are used in real life.');
INSERT INTO badge_optional_requirements VALUES(2168,153,31,'Research how protest groups, oppressed communities, or resistance movements have historically used codes or secret messaging.');
INSERT INTO badge_optional_requirements VALUES(2169,154,3,'Understand/define the following terms: Binary Bitmap Block menu Computer logic Condition Event menu Syntax');
INSERT INTO badge_optional_requirements VALUES(2170,154,4,'Explain to a younger child the purpose of the 10 part menu guide, and what types of code you will find in each (motion, looks, sound, etc…).');
INSERT INTO badge_optional_requirements VALUES(2171,154,5,'Create a program using pictures you personally have (not stock images in the program).');
INSERT INTO badge_optional_requirements VALUES(2172,154,6,'In your interactive story, include video sensing buttons that can change the program’s direction.');
INSERT INTO badge_optional_requirements VALUES(2173,154,7,'Create your own Virtual Pet. Capabilities must include feeding, dancing, tickling, bedtime, and noises.');
INSERT INTO badge_optional_requirements VALUES(2174,154,8,'Program a new game that keeps score.');
INSERT INTO badge_optional_requirements VALUES(2175,154,9,'Create a program that can make a sprite appear & disappear or sneak up on other characters for a hide and seek game or story.');
INSERT INTO badge_optional_requirements VALUES(2176,154,10,'Remix is another person’s code that has been shared.  Make it your own in some way.');
INSERT INTO badge_optional_requirements VALUES(2177,154,11,'Share a project with the community or your club, so others may try your code.');
INSERT INTO badge_optional_requirements VALUES(2178,154,12,'Create an interactive art program using clones.');
INSERT INTO badge_optional_requirements VALUES(2179,154,13,'Program a guess the number game.');
INSERT INTO badge_optional_requirements VALUES(2180,154,14,'Create your own sprite with the painting tool.');
INSERT INTO badge_optional_requirements VALUES(2181,155,3,'Read a book or magazine about coin collecting.');
INSERT INTO badge_optional_requirements VALUES(2182,155,4,'Write a review of an interesting article from a coin collecting newspaper, magazine, or book.');
INSERT INTO badge_optional_requirements VALUES(2183,155,5,'Prepare a two to three page display involving coins. Using ingenuity, as well as clippings, drawings, etc., tell a story about the coins. How do they relate to history and geography?');
INSERT INTO badge_optional_requirements VALUES(2184,155,6,'Collect the quarters from all 50 states.');
INSERT INTO badge_optional_requirements VALUES(2185,155,7,'Collect coins from at least 2 countries other than the U.S.');
INSERT INTO badge_optional_requirements VALUES(2186,155,8,'Visit a coin store or pawn shop that deals with coins and see what types of coins they have for sale. How much are they worth now compared to the stated value when they were made?');
INSERT INTO badge_optional_requirements VALUES(2187,155,9,'Find out how coins are made. What metals are used for each of the U.S. coins?  Have these metals always been used or have they changed over time?');
INSERT INTO badge_optional_requirements VALUES(2188,155,10,'Define the following coin collecting terms: Bag mark Blank Clad coinage Commemorative Counterfeit Currency Denomination Error Field Hairlines Legal tender Luster Obsolete Overstrike Obverse Restrike Rim Edge Stike Uncirculated Reeds');
INSERT INTO badge_optional_requirements VALUES(2189,155,11,'Tour the U.S. Mint, the Bureau of Engraving and Printing, or a Federal Reserve Bank, either in person or online with permission from a parent.');
INSERT INTO badge_optional_requirements VALUES(2190,155,12,'Coin collectors collect in a variety of ways. Learn about collecting coins in each of the following ways: By Series Proof Coins Uncirculated Coins Mint Sets Commemorative Coins American Eagle Buillion Coins Foreign Coins Ancient Coins Type Sets Date Collections');
INSERT INTO badge_optional_requirements VALUES(2191,155,13,'Learn how to properly store and display your coins in order to protect their value. How should they be cleaned? How should they be held to protect the surface from the oils of your skin?');
INSERT INTO badge_optional_requirements VALUES(2192,155,14,'Earn the Collecting badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2193,155,15,'Attend a coin show or exhibit.');
INSERT INTO badge_optional_requirements VALUES(2194,155,16,'Give a talk about coin collecting to your troop, club, or class at school or another location.');
INSERT INTO badge_optional_requirements VALUES(2195,155,17,'Participate in a community service project involving coins, such as helping a collector, museum or shop organize and clean their collection of coins.');
INSERT INTO badge_optional_requirements VALUES(2196,156,3,'Visit a historic site related to the Cold War or a museum with a Cold War exhibit.');
INSERT INTO badge_optional_requirements VALUES(2197,156,4,'Read a book or watch a movie about the Cold War.');
INSERT INTO badge_optional_requirements VALUES(2198,156,5,'Learn who Joseph McCarthy was and be able to explain the term McCarthyism.');
INSERT INTO badge_optional_requirements VALUES(2199,156,6,'Learn about the Cuban Missile Crisis');
INSERT INTO badge_optional_requirements VALUES(2200,156,7,'Learn what the Manhattan Project was. Who started it and why? What were the secret cities?');
INSERT INTO badge_optional_requirements VALUES(2201,156,8,'Learn about the Korean War');
INSERT INTO badge_optional_requirements VALUES(2202,156,9,'Learn about the Space Race during the Cold War');
INSERT INTO badge_optional_requirements VALUES(2203,156,10,'Watch the “Duck and Cover” video from the Cold War to learn how kids were taught to prepare for a nuclear bomb. Do you think this plan would be effective? How is it different from drills taught in school today?');
INSERT INTO badge_optional_requirements VALUES(2204,156,11,'Learn about the Berlin Wall and how Germany was divided. What was life like in East Germany vs. West Germany? Many families were separated by the divide and couldn’t see each other for years. How do you think that would make you feel?');
INSERT INTO badge_optional_requirements VALUES(2205,156,12,'Learn about new technology created during the Cold War such as advancements in vehicles and weapons. What technologies carried over to civilian life?');
INSERT INTO badge_optional_requirements VALUES(2206,156,13,'After the Cold War the U.S. and Soviet Russia began dismantling weapon systems. How long did it take them to finish projects?');
INSERT INTO badge_optional_requirements VALUES(2207,157,3,'Make a series of at least two collages that are abstract (Learn what abstract means).');
INSERT INTO badge_optional_requirements VALUES(2208,157,4,'Make at least two collages that “send a message.”');
INSERT INTO badge_optional_requirements VALUES(2209,157,5,'Make collages that use at least 3 different types of material. These can be all in one collage, or as three separate collages.');
INSERT INTO badge_optional_requirements VALUES(2210,157,6,'Make a 3D collage.');
INSERT INTO badge_optional_requirements VALUES(2211,157,7,'Make two collages that are centered around the same theme, but differing in size. The smallest should be 4” x 4” or smaller and the largest should be at least 12” x 14”.');
INSERT INTO badge_optional_requirements VALUES(2212,157,8,'Make a collage that emphasizes one element of art over the others, such as line, color, shape, or texture.');
INSERT INTO badge_optional_requirements VALUES(2213,157,9,'Enter one of your collages in a fair, contest, or show.');
INSERT INTO badge_optional_requirements VALUES(2214,157,10,'Give one of your collages as a gift or part of a gift (such as decorating the gift tag).');
INSERT INTO badge_optional_requirements VALUES(2215,157,11,'Make a collage that celebrates another badge: dried leaves, chocolate candy wrappers, labels of canned food, and scraps of sewing supplies.');
INSERT INTO badge_optional_requirements VALUES(2216,157,12,'Make a photo collage.');
INSERT INTO badge_optional_requirements VALUES(2217,157,13,'Make a collage using your computer.');
INSERT INTO badge_optional_requirements VALUES(2218,157,14,'Make a collage that shows people what you have done over the last couple years. Share it with your family, friends, or another group.');
INSERT INTO badge_optional_requirements VALUES(2219,158,3,'Photograph your collection and create an album to show to others.');
INSERT INTO badge_optional_requirements VALUES(2220,158,4,'Bring something from your collection to show and tell either at school or to a club meeting.');
INSERT INTO badge_optional_requirements VALUES(2221,158,5,'Learn about the history of what you collect. Create either a timeline of the history of your item, or a map of where they are made or found.');
INSERT INTO badge_optional_requirements VALUES(2222,158,6,'Make a graph of your collection showing the quantities of different subcategories within your collection. For example, how many stuffed rabbits do you own in comparison to stuffed bears?');
INSERT INTO badge_optional_requirements VALUES(2223,158,7,'Write down specific memories that go with at least 10 of the items in your collection and share them with someone.');
INSERT INTO badge_optional_requirements VALUES(2224,158,8,'Read a book about what you collect.');
INSERT INTO badge_optional_requirements VALUES(2225,158,9,'Visit a person or museum who collects the same thing you do and learn about their collection. If there are no similar collections near you, find one online with your parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(2226,158,10,'Research the value of your collection and estimate its worth. Where would you sell your collection if you wished to? Who would be your target market?');
INSERT INTO badge_optional_requirements VALUES(2227,158,11,'Set up a “Collector’s Museum” with your friends or another group for a day. Using a place of worship or classroom, invite several friends to bring in their collections to display. Make sure each person includes labels or cards to explain what their collections are all about. Invite friends, family, etc. to come and view the collections.');
INSERT INTO badge_optional_requirements VALUES(2228,158,12,'Volunteer to help someone organize or clean their collection.');
INSERT INTO badge_optional_requirements VALUES(2229,159,3,'Learn the difference between public and private colleges/universities. Which is yours?');
INSERT INTO badge_optional_requirements VALUES(2230,159,4,'Do a service project for your college');
INSERT INTO badge_optional_requirements VALUES(2231,159,5,'Find out what type of scholarships your chosen college offers.');
INSERT INTO badge_optional_requirements VALUES(2232,159,6,'Make a scrapbook or collage of pictures taken during your visit.');
INSERT INTO badge_optional_requirements VALUES(2233,159,7,'Learn about careers working in higher education. For example, professors, deans, admissions, registrars, coaches, advisors, etc.');
INSERT INTO badge_optional_requirements VALUES(2234,159,8,'Find out what degrees the college offers. What is an Associate’s Degree? Bachelor’s? Master’s? Doctorate? What are some majors offered?');
INSERT INTO badge_optional_requirements VALUES(2235,159,9,'Find out what the current tuition is.');
INSERT INTO badge_optional_requirements VALUES(2236,159,10,'What type of architecture was used when the college  was built?');
INSERT INTO badge_optional_requirements VALUES(2237,159,11,'Find out about famous alumni of the college.');
INSERT INTO badge_optional_requirements VALUES(2238,159,12,'Attend an event at the college such as a sporting event, play, or concert.');
INSERT INTO badge_optional_requirements VALUES(2239,159,13,'Draw a map of the college’s campus. Label the different buildings.');
INSERT INTO badge_optional_requirements VALUES(2240,159,14,'Interview a student that attends the college. What do they like and dislike? What did they do to get into the college? What are they studying? What is their typical day like?');
INSERT INTO badge_optional_requirements VALUES(2241,159,15,'Look at the website or catalog of the college.  Find at least 5 classes that you would like to take.');
INSERT INTO badge_optional_requirements VALUES(2242,159,16,'Create a timeline of the college’s history.   Include a minimum of 10 items.');
INSERT INTO badge_optional_requirements VALUES(2243,159,17,'Learn the names of the school board of the college.');
INSERT INTO badge_optional_requirements VALUES(2244,159,18,'Learn the school song.');
INSERT INTO badge_optional_requirements VALUES(2245,159,19,'Learn what clubs and activities the college offers.');
INSERT INTO badge_optional_requirements VALUES(2246,159,20,'Find out what college accreditation means.  Which accreditations are preferred?  Are credits from colleges with accreditations transferable?');
INSERT INTO badge_optional_requirements VALUES(2247,160,3,'Take a carriage ride through Revolutionary City or a ride on an 18th Century ox wagon.');
INSERT INTO badge_optional_requirements VALUES(2248,160,4,'Attend a public audience with a Founding Father.');
INSERT INTO badge_optional_requirements VALUES(2249,160,5,'Explore the Public Hospital of 1773, the DeWitt Wallace Decorative Arts Museum, and the Abby Aldrich Rockefeller Folk Art Museum.');
INSERT INTO badge_optional_requirements VALUES(2250,160,6,'Wear a period costume as you explore Williamsburg (costume’s may be rented at the visitor’s center, or bring your own!)');
INSERT INTO badge_optional_requirements VALUES(2251,160,7,'Learn about some of the buildings in Colonial Williamsburg. Pick three and research their history. When were they built? What is their purpose?');
INSERT INTO badge_optional_requirements VALUES(2252,160,8,'Tour Anderson’s Blacksmith Shop and Public Armory. Take in a period cooking demonstration in the kitchen, if possible.');
INSERT INTO badge_optional_requirements VALUES(2253,160,9,'What was the fashion like in the time of Colonial Williamsburg? Research images of what both women and men wore in that era.');
INSERT INTO badge_optional_requirements VALUES(2254,160,10,'Explore period trades. Attend demonstrations or tours of four different trades (Examples of some trades available include: basketmaker, candlemaker, apothecary, tailor, printing office, and much more). If you cannot attend the demonstrations in person, pick four trades to research online.');
INSERT INTO badge_optional_requirements VALUES(2255,160,11,'Find out more about the lives of slaves during colonial times. If possible, visit Great Hopes Plantation and/or the African American Religious Exhibit.');
INSERT INTO badge_optional_requirements VALUES(2256,160,12,'Explore period homes. Tour three different Williamsburg homes (Examples of some homes available include: Governor’s Palace, James Geddy House, Powell House, and much more). If you cannot tour the homes in person, research online what colonial homes were like in that era. What sort of appliances did they have, if any? What was the style of structure of the homes like?');
INSERT INTO badge_optional_requirements VALUES(2257,160,13,'Participate in a mock trial at the courthouse and visit the Public Gaol.');
INSERT INTO badge_optional_requirements VALUES(2258,160,14,'Explore the Native American Encampment.');
INSERT INTO badge_optional_requirements VALUES(2259,160,15,'Tour the Capitol Building.');
INSERT INTO badge_optional_requirements VALUES(2260,160,16,'See authentic firearms at the Magazine and visit the Military Encampment. If you cannot visit in person, learn about what types of firearms were used in this era.');
INSERT INTO badge_optional_requirements VALUES(2261,160,17,'Take in a performance at the Playbooth Theater.');
INSERT INTO badge_optional_requirements VALUES(2262,160,18,'Visit R. Charleston’s Coffeehouse, Raleigh Tavern, or Wetherburn’s Tavern.');
INSERT INTO badge_optional_requirements VALUES(2263,160,19,'Take in a musical performance at Revolutionary City.');
INSERT INTO badge_optional_requirements VALUES(2264,160,20,'Take part in a reenactment, such as the storming of the Governor’s Palace.');
INSERT INTO badge_optional_requirements VALUES(2265,160,21,'Colonial Williamsburg has many special events and classes happening daily. Take part in one of these events or classes and share your experience with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(2266,160,22,'Dine at one of the eating establishments in Colonial Williamsburg. What similarities do you notice to dining in a modern day restaurant? What differences do you notice? If you cannot complete this requirement in person, research the types of food that were served at restaurants in Colonial Williamsburg.');
INSERT INTO badge_optional_requirements VALUES(2267,160,23,'Create a scrapbook of your visit and/or what you have learned. Make sure it has at least 5 pages. Share your scrapbook with your family or club.');
INSERT INTO badge_optional_requirements VALUES(2268,161,3,'Find a color wheel and learn how to use it. Explore what happens when you mix different colors.');
INSERT INTO badge_optional_requirements VALUES(2269,161,4,'Color a picture using at least 3 different mediums from Level 2 requirement 2. Levels 3 – 5: Understand that subdued evening light and candlelight create a distortion of color. Under these circumstances light colors need more intensity and dark colors less. Distance causes receding (cool) colors to “black out”. Consequently lighter values of color should be employed for greater emphasis. Colors should be lighter where light would shine upon them and gradually darken where light would not reach.');
INSERT INTO badge_optional_requirements VALUES(2270,161,5,'Learn to color digitally. Find a website that lets you color online using the computer and color a picture.');
INSERT INTO badge_optional_requirements VALUES(2271,161,6,'Use food coloring and clear glasses of water to experiment with color mixing (Make sure you have adult supervision as food coloring can stain if it spills.). What happens if you use neon colors? Optional: Use what you have learned to create a colored frosting for use on a cake or cupcakes.');
INSERT INTO badge_optional_requirements VALUES(2272,161,7,'Make a color chart of a single item such as a leaf, flower, seashell, rug, or piece of fabric. What hues are in your object? What shades or tints or each hue?');
INSERT INTO badge_optional_requirements VALUES(2273,161,8,'Learn to colorize a black and white photo using a computer graphic program. If you do not have a black and white photo, input a color photo and change it to black and white before beginning.');
INSERT INTO badge_optional_requirements VALUES(2274,161,9,'Create and color your own font either by using a computer program, or by drawing and coloring it by hand.');
INSERT INTO badge_optional_requirements VALUES(2275,161,10,'Tear off a small rectangle about 1 ½ x 2” from a magazine picture. Using a medium that blends well such as paints, crayons, or pastels, try to duplicate your rectangle on an 8 ½ x 11” piece of cardstock. Pay close attention to the colors and they way they blend rather than worrying about getting any particular shape correct.');
INSERT INTO badge_optional_requirements VALUES(2276,161,11,'Tie dye a t-shirt or other article. Learn at least 2 different tie dye patterns.');
INSERT INTO badge_optional_requirements VALUES(2277,161,12,'Learn to create color schemes using a diad, a triad, and a tetrad. If you could redesign your bedroom, what color scheme would you use?');
INSERT INTO badge_optional_requirements VALUES(2278,161,13,'Learn about the physics of color (wavelength, frequency, etc). Why do you think certain colors stand out more than others? Think about signs and why certain colors were chosen for those signs (For example: McDonald’s uses red and yellow in their signs because they catch your eye quicker than other colors and this is because of their wavelength).');
INSERT INTO badge_optional_requirements VALUES(2279,161,14,'Learn about how computers read colors with HTML and CSS, both with the decimal and the hex code.');
INSERT INTO badge_optional_requirements VALUES(2280,162,3,'Draw or print your own coloring page and then color it in.');
INSERT INTO badge_optional_requirements VALUES(2281,162,4,'Color pictures then take them to a retirement home or care unit for the elderly.');
INSERT INTO badge_optional_requirements VALUES(2282,162,5,'Earn the Color badge at your level');
INSERT INTO badge_optional_requirements VALUES(2283,162,6,'Visit a store either in person or online and look through the different styles of coloring books available.  How many different types can you find?  What ages are they for?  What coloring mediums are they meant for?');
INSERT INTO badge_optional_requirements VALUES(2284,162,7,'Learn about the different types of paper used in coloring books and the types of coloring mediums they support.');
INSERT INTO badge_optional_requirements VALUES(2285,162,8,'Learn how to remove coloring from walls, wood, clothes, etc.');
INSERT INTO badge_optional_requirements VALUES(2286,162,9,'Learn about some of the more advanced coloring mediums and how they are used such as Copic Markers, Oil Pastels, Gel Pens, or Watercolor Pencils.');
INSERT INTO badge_optional_requirements VALUES(2287,162,10,'Color 3 greeting cards to give to other people');
INSERT INTO badge_optional_requirements VALUES(2288,162,11,'Use coloring to help you learn about something in school or that you are interested in.  For example you might download a coloring page of the muscular system of the human body or a dissection of a flower.');
INSERT INTO badge_optional_requirements VALUES(2289,163,1,'How can you tell when a comic book character is speaking aloud vs thinking? What purpose do captions serve in comics?');
INSERT INTO badge_optional_requirements VALUES(2290,163,2,'Create your own comic book on paper or using an app and share it with your family, friends, or group. Preschool: Include at least 4 frames. Level 1: Include at least 6 frames. Levels 2 and 3: Include at least 8 frames. Levels 4 and 5: Include at least 12 frames. Be sure to include a cover and a title.');
INSERT INTO badge_optional_requirements VALUES(2291,163,3,'Visit a comic book store and find at least two examples of each of the following types of comic books: superhero, cartoon, manga*, slice of life, and fantasy. * Parental discretion advised. A lot of manga is aimed at older teens and adults, not kids. However, there are many titles available for kids. Ask for the advice of the sales clerk if you are unsure.');
INSERT INTO badge_optional_requirements VALUES(2292,163,4,'Some people collect comic books. Learn how comics are stored to protect them, and how the value is determined for resale.');
INSERT INTO badge_optional_requirements VALUES(2293,163,5,'Read about a comic book artist. How did he/she get started? What sort of training or skills are necessary to develop a career in comic book illustration?');
INSERT INTO badge_optional_requirements VALUES(2294,163,6,'How are comics printed? What are the steps in the process from idea to publication?');
INSERT INTO badge_optional_requirements VALUES(2295,163,7,'Attend a Free Comic Book Day event.');
INSERT INTO badge_optional_requirements VALUES(2296,163,8,'Make a timeline showing at least 5 major events in comic book history.');
INSERT INTO badge_optional_requirements VALUES(2297,163,9,'Explain what is meant by, “The Golden Age of Comics.” Name some characters from that time period.');
INSERT INTO badge_optional_requirements VALUES(2298,163,10,'Explore different careers in the comic book industry. Be able to explain what the following people do:  Writer Penciller Colorist Letterer Editor Publisher Distributor.');
INSERT INTO badge_optional_requirements VALUES(2299,163,11,'Interview at least 5 different people about their favorite comic books. What are their favorite titles? Favorite artists? Why?');
INSERT INTO badge_optional_requirements VALUES(2300,163,12,'Prepare a presentation for a group telling all about your favorite comic book. You may dress up as the main character and explain the backstory, but be sure to include samples of the comic book and explain why you enjoy it.');
INSERT INTO badge_optional_requirements VALUES(2301,163,13,'Some people feel comic books have traditionally neglected certain groups such as minorities, women, or people with disabilities. Today there is more diversity than ever among comic book characters. Find at least two examples from each group, and explain why it is important for them to be included in the world of comic books.');
INSERT INTO badge_optional_requirements VALUES(2302,163,14,'When a comic has been around for many years, characters often change, including backstories. Give an example of a character who has changed over time.');
INSERT INTO badge_optional_requirements VALUES(2303,163,15,'Explain what is meant by “reboot” and how it differs from “retcon.”');
INSERT INTO badge_optional_requirements VALUES(2304,164,3,'Draw a picture of a form of communication and show it to your family or club.');
INSERT INTO badge_optional_requirements VALUES(2305,164,4,'Choose a form of communication, such as the telephone, and learn how it has changed over the years.');
INSERT INTO badge_optional_requirements VALUES(2306,164,5,'Write a letter to someone and mail it. Learn how the postal service has changed over the years. How did stagecoaches, Pony Express riders, automobiles and airplanes affect it?');
INSERT INTO badge_optional_requirements VALUES(2307,164,6,'Learn about some more unusual forms of communications, such as the talking drums in Africa, or smoke signals in America. Learn three messages in the “language” you learned about.');
INSERT INTO badge_optional_requirements VALUES(2308,164,7,'Earn the Foreign Language badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2309,164,8,'In countries that use or used to use windmills, such as the Netherlands or England, millers could send messages from one windmill to another simply by fixing the sails of their mills in different ways.  Learn three messages in “windmill language.”');
INSERT INTO badge_optional_requirements VALUES(2310,164,9,'Learn Morse code. Ask someone else to write down a short message in Morse code or tap it out on a table or wall. See if you can decode it.');
INSERT INTO badge_optional_requirements VALUES(2311,164,10,'Radio, television, and the printed word, such as newspapers, are all classed as ways of communicating on a large scale. Pick one of these media and learn about its history. Tell your family or club what you learned.');
INSERT INTO badge_optional_requirements VALUES(2312,164,11,'Level 3 & Up Only: Shadow someone for a day who works in the communications business, such as a newspaper printer, or a telegraph operator.');
INSERT INTO badge_optional_requirements VALUES(2313,164,12,'Learn about an occupation having to do with communicating that is no longer as prevalent as it once was, such as a telephone switchboard operator or answering service, town crier or a messenger on foot. What has replaced the occupation you studied?');
INSERT INTO badge_optional_requirements VALUES(2314,164,13,'Make up your own code out of letters, numbers or symbols, or a combination of any of these. Write down a message in your code and then ask a friend to decode it.');
INSERT INTO badge_optional_requirements VALUES(2315,164,14,'Research the ways in which musicians and singers use music to communicate feelings/emotions to other people. For example, a singer might sing certain lines of a song in a quiet, sad voice, thus wringing tears from the audience; or a musician might play a piece of music in a lively way thus making everyone in the room feel happy and want to dance. Think about the films/TV shows you watch: how much does the music influence your emotional responses to the story?');
INSERT INTO badge_optional_requirements VALUES(2316,164,15,'Preschool and Level 1: with help, make a toy “telephone” out of two tin cans and a piece of string. Ask an adult to punch a hole in the end of each can, then thread the string through the holes and tie a knot in each end. With the string taut between you, hold one can up to your ear and ask a friend to talk into the other can. What happens? Levels 2 – 5 must help a younger child with this project in order to fulfill this requirement.');
INSERT INTO badge_optional_requirements VALUES(2317,164,16,'Find pieces of artistic media that include a form of communication, such as a telephone, or a letter, etc, in them. You may find paintings, sculptures, songs, poems etc. See what you can find!');
INSERT INTO badge_optional_requirements VALUES(2318,164,17,'Learn about semaphore, and how and where it is used. Learn three messages in semaphore and “send” them to a friend on the other side of the room.');
INSERT INTO badge_optional_requirements VALUES(2319,164,18,'People who speak via an interpreter, sometimes have problems with communication because their words can be translated incorrectly. This can turn a simple message into something that is very funny, such as when Pepsi advertised in China saying, “Come alive with the great taste of Pepsi!” and the Chinese advertising men translated it as “Drink Pepsi and all your ancestors will come alive!” Find examples of humorous mistranslations and share them with your family or club. Preschool: Find one example. Levels 1 – 2: Find three. Levels 3 – 4: Find five. Level 5: Find seven.');
INSERT INTO badge_optional_requirements VALUES(2320,164,19,'Earn the Listening badge.');
INSERT INTO badge_optional_requirements VALUES(2321,165,3,'Visit your local fire department. What services do they provide to help keep your community safe other than just putting out fires? How can you help? Levels 4 – 5: Volunteer with the local fire department to help teach fire safety. If they don’t have a program in place already, helping them to create a “Learn Not to Burn” program would make a great Make a Difference project.');
INSERT INTO badge_optional_requirements VALUES(2322,165,4,'Visit your local police station. What services do they provide to help keep your community safe? What laws are there that kids need to obey? How can you help? Levels 4 – 5: Work with the local police to organize a bike safety fair, car seat safety clinic, or other safety project. If your local police department does not already have activities like this set up, helping to organize a program from scratch that can be used over and over would make a great Make a Difference project.');
INSERT INTO badge_optional_requirements VALUES(2323,165,5,'Visit at least two public buildings. What measures have been taken to ensure people’s safety?');
INSERT INTO badge_optional_requirements VALUES(2324,165,6,'Collect news stories of accidents and discuss why they happened and how they could have been prevented.');
INSERT INTO badge_optional_requirements VALUES(2325,165,7,'Go to a local park and look for safety hazards. Who should you notify about any problems?');
INSERT INTO badge_optional_requirements VALUES(2326,165,8,'Design a safety campaign for bicycling, trick or treating, gardening, camping, sledding, or any other activity of your choice. What safety rules should people be aware of? How can you educate people? Are there organizations you can work with? Can you put up flyers in areas where they will be seen? Will your local newspaper run a story about how to stay safe during your chosen activity? Be creative.');
INSERT INTO badge_optional_requirements VALUES(2327,165,9,'Help teach the Fire Safety badge to a group of younger kids.');
INSERT INTO badge_optional_requirements VALUES(2328,165,10,'What services do the U.S. Forestry Department provide to help keep your community safe? How do they help in fire fighting efforts, safe hiking trails, etc.?');
INSERT INTO badge_optional_requirements VALUES(2329,165,11,'Learn about environmental safety concerns that affect your community. If your storm drains empty into local creeks or rivers, make sure that nothing toxic gets poured down them. If your community is suffering from drought conditions, how can you help to conserve water? Find a way to volunteer in your community to help keep your environment healthy for everyone.');
INSERT INTO badge_optional_requirements VALUES(2330,165,12,'Levels 4 – 5 Only: Shadow someone for a day that has a career that deals with public safety.');
INSERT INTO badge_optional_requirements VALUES(2331,166,3,'Visit a modern day version of your chosen type of town, a ‘ghost town’, or a reproduction town. Be sure to follow all Leave No Trace principles.');
INSERT INTO badge_optional_requirements VALUES(2332,166,4,'Do a service project while visiting your company town. You could pick up litter, clear trails, clean facilities, or help with a ranger program.');
INSERT INTO badge_optional_requirements VALUES(2333,166,5,'Earn the Leave No Trace badge and understand why following these guidelines is important to this town.');
INSERT INTO badge_optional_requirements VALUES(2334,166,6,'Make up a puzzle or game using facts about your chosen type of company town. Play it with someone.');
INSERT INTO badge_optional_requirements VALUES(2335,166,7,'Make a scrapbook about your visit to one or more company towns (or if you are earning specific categories of company towns, add to your scrapbook for this type of town).');
INSERT INTO badge_optional_requirements VALUES(2336,166,8,'Write a report or make a brochure or poster about the interesting natural features of your chosen type of company town. Be sure to highlight the appropriate time period and critical features.');
INSERT INTO badge_optional_requirements VALUES(2337,166,9,'Learn about a legend or myth that features this type of company town. Retell your story to someone or to a group.');
INSERT INTO badge_optional_requirements VALUES(2338,166,10,'Learn about the people that would have called this company town home. Share what you learn with your family, friends, or group. Think about how a family depended on the company, whether they worked there or just supported the people that work there.');
INSERT INTO badge_optional_requirements VALUES(2339,166,11,'Watch a documentary or travelogue about this type of company town and plan a trip (real or imaginary) to visit the places you liked most in the video.');
INSERT INTO badge_optional_requirements VALUES(2340,166,12,'Watch a show or movie about the specific type of company town of your choice.');
INSERT INTO badge_optional_requirements VALUES(2341,166,13,'Research the history of your type of company town and give a presentation about it.');
INSERT INTO badge_optional_requirements VALUES(2342,166,14,'Earn the Occupation/Career (Specific) badge for the worker who would have been critical to your choice of industry town.');
INSERT INTO badge_optional_requirements VALUES(2343,166,15,'Make a chart comparing and contrasting the lifestyle, features, animals, climate, weather, etc. of a typical company town as compared to your town today.');
INSERT INTO badge_optional_requirements VALUES(2344,166,16,'Were there any animals, machines, or geologic/geographic features that were critical to the industry, and why?');
INSERT INTO badge_optional_requirements VALUES(2345,166,17,'Make a 3 dimensional model of a key feature of your industrial town. If your industrial town involves a railroad, you might want to make your model at the appropriate scale for your train layout.');
INSERT INTO badge_optional_requirements VALUES(2346,166,18,'Learn about at what age a young person would start with the company, what education they needed or typically received, and about a typical day.');
INSERT INTO badge_optional_requirements VALUES(2347,166,19,'Did the company of choice typically have an apprentice program? Was anyone in your family ever employed by a company in the manner you’ve learned about?');
INSERT INTO badge_optional_requirements VALUES(2348,166,20,'Learn about typical housing for company workers in the industry of your choice.');
INSERT INTO badge_optional_requirements VALUES(2349,166,21,'Are there “good” and “bad” company towns? What would make a company town be considered “good”? What would make a company town be considered “bad”? What options would an employee in a bad company have and are those options similar to workers today?');
INSERT INTO badge_optional_requirements VALUES(2350,166,22,'How did safety requirements compare for company towns versus the same industry today?');
INSERT INTO badge_optional_requirements VALUES(2351,167,3,'Create a piece of artwork about what compassion means to you.');
INSERT INTO badge_optional_requirements VALUES(2352,167,4,'Write an essay about what compassion means to you.');
INSERT INTO badge_optional_requirements VALUES(2353,167,5,'Write a story or skit where compassion plays an important role.');
INSERT INTO badge_optional_requirements VALUES(2354,167,6,'Read a biography about someone known for their compassion.');
INSERT INTO badge_optional_requirements VALUES(2355,167,7,'What does your book of worship say about compassion? Preschool: Memorize at least one verse about compassion. Levels 1-2: Memorize three verses. Levels 3-5: Memorize five verses.');
INSERT INTO badge_optional_requirements VALUES(2356,167,8,'Memorize or write a poem about compassion.');
INSERT INTO badge_optional_requirements VALUES(2357,167,9,'Find and memorize famous quotations about compassion. Preschool: Memorize one. Levels 1-2: Memorize three. Levels 3-5: Memorize five.');
INSERT INTO badge_optional_requirements VALUES(2358,167,10,'Read a story where compassion plays a major part. This may be a story about someone who is initially compassionate, or one where a character learns to be compassionate as the story goes on.');
INSERT INTO badge_optional_requirements VALUES(2359,167,11,'Using the Victorian Language of flowers, make a bouquet that symbolizes what compassion means to you. You can find the meanings assigned to the flowers at various websites or in books and you may cut pictures from magazines or webpages to create a “collage bouquet.” Make sure you include the name and meaning of each flower that you choose. You may make a scrapbook page using pictures of flowers or make a bouquet using real or artificial flowers.');
INSERT INTO badge_optional_requirements VALUES(2360,167,12,'Write the word COMPASSION on a piece of paper and then think of one compassionate act that you could do that starts with each letter in the word. For example for you could put “Care for other people” and  you might put “Others see things differently.”');
INSERT INTO badge_optional_requirements VALUES(2361,167,13,'Divide a piece of paper into two sides. On one side, list words that describe being compassionate, such as kind, caring, or understanding. On the other side, make a list of words that describe what being compassionate is not, such as judgmental, selfish, or uncaring. Discuss your list with someone else and see if they have ideas to add to it.');
INSERT INTO badge_optional_requirements VALUES(2362,167,14,'Make a list of times in your life when other people have been compassionate to you. How did you feel when they showed you compassion? How can you learn from their actions?');
INSERT INTO badge_optional_requirements VALUES(2363,167,15,'Role play at least 3 instances where compassion may be necessary.');
INSERT INTO badge_optional_requirements VALUES(2364,167,16,'Interview people with careers that require compassion such as doctors, nurses, and teachers. How does compassion help their work?');
INSERT INTO badge_optional_requirements VALUES(2365,167,17,'Discuss characters in TV/movies/films who are compassionate. Are they portrayed as strong or weak characters? Is compassion a characteristic that is valued by the media? Watch at least one movie or show where the main character is compassionate.');
INSERT INTO badge_optional_requirements VALUES(2366,167,18,'Discuss characters in books/literature who are compassionate. Are they portrayed as strong or weak characters? Do the writers encourage the readers to be compassionate?');
INSERT INTO badge_optional_requirements VALUES(2367,169,3,'Learn about a famous woman composer, such as Clara Schumann, or Cecile Chaminade. Listen to a piece of their music; does it differ from the music written by men during the same time? How?');
INSERT INTO badge_optional_requirements VALUES(2368,169,4,'Earn the Music badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2369,169,5,'Sometimes composers found themselves on the wrong side of public opinion regarding their music. For instance, Johann Strauss Sr.’s Radetzky March later became a political tool against him. Research at least two instances of a composer becoming “tainted” by their own music.');
INSERT INTO badge_optional_requirements VALUES(2370,169,6,'Choose a composer and listen to a famous piece of their music. Now find a piece of their music that is not so well known and listen to it. Which did you like better?');
INSERT INTO badge_optional_requirements VALUES(2371,169,7,'Read a book that deals with at least three composers, such as Lives of the Great Composers, by David Ewen, or any of the Ladybird Lives of the Great Composers books.');
INSERT INTO badge_optional_requirements VALUES(2372,169,8,'Earn the Musical Instrument badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2373,169,9,'Find a piece of music written by your favorite composer and learn to play it on a musical instrument.');
INSERT INTO badge_optional_requirements VALUES(2374,169,10,'Create a poster or scrapbook page showing what you learned while earning this badge.');
INSERT INTO badge_optional_requirements VALUES(2375,169,11,'Earn the Music Appreciation badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2376,169,12,'Choose two composers who lived at least 100 years apart from one another, and listen to at least two pieces of music written by each of them. How were they similar? How did they differ? Which did you like best?');
INSERT INTO badge_optional_requirements VALUES(2377,169,13,'Make a timeline of composers. Level 2 and 3 must have at least 10 composers on their timelines; Level 4 and 5 should have at least 25.');
INSERT INTO badge_optional_requirements VALUES(2378,169,14,'Earn the Music History badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2379,169,15,'Watch a documentary about a composer.');
INSERT INTO badge_optional_requirements VALUES(2380,169,16,'When most people think of “composers”, they generally think of people such as Handel, Beethoven, Mozart or Strauss. Learn about at least two modern composers, such as Andrew Lloyd Webber or Vangelis.');
INSERT INTO badge_optional_requirements VALUES(2381,169,17,'Research careers as a composer. What education do you need? Where would you need to live? What sort of salary could you expect?');
INSERT INTO badge_optional_requirements VALUES(2382,169,18,'Many composers taught students who went on to become well-known composers themselves, for instance, Mozart taught Hummel, Haydn taught Beethoven, etc. How did the style of the teacher affect the style of the student?');
INSERT INTO badge_optional_requirements VALUES(2383,169,19,'Learn to identify what makes one a composer sound different to all the others. Is it the way they use certain parts of an orchestra? Is it a certain character hidden within the music? Try listening to a piece of music and identifying the composer.');
INSERT INTO badge_optional_requirements VALUES(2384,169,20,'Many of the composers knew each other – some were even friends. How did they interact with one another? Learn about three composers who at least knew about each other.');
INSERT INTO badge_optional_requirements VALUES(2385,169,21,'How does film/movie music differ from classical music? How is it similar?');
INSERT INTO badge_optional_requirements VALUES(2386,169,22,'Learn about a piece that was started by one composer and finished by another, for instance, Beethoven’s 10th Symphony was completed by Barry Cooper. How many examples of this happening can you find? Can you tell where one composer ends and another begins?');
INSERT INTO badge_optional_requirements VALUES(2387,169,23,'Compose a piece of music.');
INSERT INTO badge_optional_requirements VALUES(2388,169,24,'Take a field trip to listen to a symphony, orchestra or other live musical production. Resources: The Lives and Times of the Great Composers, by Michael Steen. ISBN: 9781840466799');
INSERT INTO badge_optional_requirements VALUES(2389,170,3,'Learn about different types of soils/dirt. What makes some soil better for growing plants?  Try growing seeds in at least 2  different types of soil both with and without compost.  What are the results?');
INSERT INTO badge_optional_requirements VALUES(2390,170,4,'Find out what makes compost smell? Does it have to smell?');
INSERT INTO badge_optional_requirements VALUES(2391,170,5,'Read a book about composting.');
INSERT INTO badge_optional_requirements VALUES(2392,170,6,'Research jobs or hobbies that use or make compost.');
INSERT INTO badge_optional_requirements VALUES(2393,170,7,'Earn the Worm badge and understand the role worms play in compost.');
INSERT INTO badge_optional_requirements VALUES(2394,170,8,'Why is composting a good thing to do- either at the city level or home level? Why is it good to keep organic foods out of the landfill?');
INSERT INTO badge_optional_requirements VALUES(2395,170,9,'What is the carbon cycle? What is the nitrogen cycle? Why are these important in the compost pile? What is the perfect ratio for a compost pile?');
INSERT INTO badge_optional_requirements VALUES(2396,170,10,'What is the right level of moisture/water for a compost pile? Why does it make a difference?');
INSERT INTO badge_optional_requirements VALUES(2397,170,11,'What are some different ways composting can happen at home/community? Research the different types of home compost bins and name at least 1 difference between them.');
INSERT INTO badge_optional_requirements VALUES(2398,170,12,'Research what kind of composting your community may have. Yard waste pickup? Or food compost? Visit their facility or take an online tour of a similar facility of possible.');
INSERT INTO badge_optional_requirements VALUES(2399,170,13,'Earn the Gardening Badge using compost for some of the plants!');
INSERT INTO badge_optional_requirements VALUES(2400,170,14,'Visit a compost/mulch and soil yard or garden center and learn how they make it.');
INSERT INTO badge_optional_requirements VALUES(2401,172,3,'Learn a song about confidence, assurance or belief, such as I Have Confidence from The Sound of Music.');
INSERT INTO badge_optional_requirements VALUES(2402,172,4,'Look through your book of faith, and find and memorize verses about confidence. Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize seven.');
INSERT INTO badge_optional_requirements VALUES(2403,172,5,'Draw a picture of what confidence means to you. Show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(2404,172,6,'Read a poem about confidence, then try writing your own.');
INSERT INTO badge_optional_requirements VALUES(2405,172,7,'Write an acrostic about confidence: on a piece of paper, write the word ‘CONFIDENCE’ down the side and then write a word or sentence describing confidence next to each letter. For instance, ‘C’ could be “Constantly believing I can”, ‘O’ could be “Optimistically carrying on”, etc.');
INSERT INTO badge_optional_requirements VALUES(2406,172,8,'Read a biography of someone known for their confidence. What can you learn from them?');
INSERT INTO badge_optional_requirements VALUES(2407,172,9,'Find quotations about confidence and learn them. Preschool: Find one quote. Levels 1-2: Find three quotes. Levels 3-4: Find five. Level 5: Find seven.');
INSERT INTO badge_optional_requirements VALUES(2408,172,10,'Create a ‘Confidence Bouquet’ using pictures of flowers that represent confidence in the Victorian Language of Flowers. Make a collage, poster, or scrapbook page of your bouquet and show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(2409,172,11,'Which is better: self-confidence or confidence in God? How are confidence and faith similar?');
INSERT INTO badge_optional_requirements VALUES(2410,172,12,'Participate in a theater class, try out for a part in a local play, or take a public speaking class.');
INSERT INTO badge_optional_requirements VALUES(2411,173,3,'Pay attention to what your family buys during the course of one week. What items could you have done without? Learn the difference between a “want” and a “need.” Find out how much money you could have saved if you had only made purchases that were “needs”.');
INSERT INTO badge_optional_requirements VALUES(2412,173,4,'Discuss how pollution effects land, air and water. How does pollution happen? Participate in a community service project to help clean up our land or waterways.');
INSERT INTO badge_optional_requirements VALUES(2413,173,5,'Earn the Recycling badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(2414,173,6,'Be able to explain what erosion is and name three kinds of soil erosion. What kinds of grasses, trees, or ground cover can be planted to help limit erosion? Tell why soil conservation is important.');
INSERT INTO badge_optional_requirements VALUES(2415,173,7,'Plant a tree in your yard, on the grounds of whoever hosts your group, or in a park or other public place. Be sure to get permission first.');
INSERT INTO badge_optional_requirements VALUES(2416,173,8,'Learn about aquatic ecosystems and wetlands in your area. What role does aquatic ecosystems and wetlands play in supporting the life-cycles of wildlife and humans? What can you do locally to ensure the continuation of your local wetlands and aquatic ecosystems?');
INSERT INTO badge_optional_requirements VALUES(2417,173,9,'Learn about the National Conservation Practices. What areas have detailed plans for conservation? Why do you think these areas are important enough to our planet to deserve special attentions?');
INSERT INTO badge_optional_requirements VALUES(2418,173,10,'What is the importance of conserving our range, grazing and pasture lands? What are these land used for? How can they be conserved?');
INSERT INTO badge_optional_requirements VALUES(2419,173,11,'Learn about careers in conservation. What education might you need for one of these jobs? What kind of  salary could you expect? Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(2420,173,12,'Explain what a watershed is. Find a contour map of your area. Where is the nearest watershed? How big is it? Does it contain smaller watersheds?');
INSERT INTO badge_optional_requirements VALUES(2421,173,13,'Explain what a river basin is. Tell why all people living in a river basin should be concerned about land and water use in the basin.');
INSERT INTO badge_optional_requirements VALUES(2422,173,14,'Take a field trip to somewhere that deals with conservation. Examples might include: An agricultural experiment. A managed forest or a woodlot, range, or pasture. A wildlife refuge or a fish or game management area. A conservation-managed farm or ranch. A managed watershed. A waste-treatment plant. A public drinking water treatment plant. An industry water-use installation. A desalinization plant.');
INSERT INTO badge_optional_requirements VALUES(2423,174,3,'Taste and compare store bought cookies, cookies made from scratch and cookies made from a box/frozen dough.');
INSERT INTO badge_optional_requirements VALUES(2424,174,4,'When is National Cookie Day? Learn the history of this day and how people celebrate it.');
INSERT INTO badge_optional_requirements VALUES(2425,174,5,'Take a field trip to a bakery where they make cookies.');
INSERT INTO badge_optional_requirements VALUES(2426,174,6,'Bake a savory cookie.');
INSERT INTO badge_optional_requirements VALUES(2427,174,7,'Make cookies to give as a gift to a neighbor, elderly person, emergency worker, etc.');
INSERT INTO badge_optional_requirements VALUES(2428,174,8,'Host a bake sale.');
INSERT INTO badge_optional_requirements VALUES(2429,174,9,'Research careers in the baking industry, such as a pastry chef, baker, recipe book writer, etc. What type of education would you need? What kind of salary could you expect to make?');
INSERT INTO badge_optional_requirements VALUES(2430,174,10,'Make a recipe book of your favorite cookie recipes. Include at least 5 recipes.');
INSERT INTO badge_optional_requirements VALUES(2431,174,11,'Design your own cookie cutters by shaping aluminum foil. Design at least three and use them.');
INSERT INTO badge_optional_requirements VALUES(2432,174,12,'Make cookies for a holiday, such as gingerbread cookies around Christmastime or green cookies for St. Patrick’s Day.');
INSERT INTO badge_optional_requirements VALUES(2433,174,13,'Host an event for people to decorate their own cookies. Provide everyone with plain sugar cookies and decorations such as frosting, sprinkles, candies, etc.');
INSERT INTO badge_optional_requirements VALUES(2434,174,14,'Choose a basic cookie recipe and experiment by adding or removing ingredients. What happens if you add more flour? What’s the difference if you add white sugar vs. brown sugar? What happens if you use baking powder vs. baking soda? Etc.');
INSERT INTO badge_optional_requirements VALUES(2435,174,15,'Make a bar cookie.');
INSERT INTO badge_optional_requirements VALUES(2436,174,16,'Make cut-out cookies.');
INSERT INTO badge_optional_requirements VALUES(2437,174,17,'Make cookies with a surprise filling.');
INSERT INTO badge_optional_requirements VALUES(2438,174,18,'Learn how to use a cookie press and make spritz cookies.');
INSERT INTO badge_optional_requirements VALUES(2439,174,19,'Build and decorate a building with cookies, such as a gingerbread house.');
INSERT INTO badge_optional_requirements VALUES(2440,175,3,'Learn to make five garnishes and describe the types of dishes they would go with. Use garnishes on at least two different recipes.');
INSERT INTO badge_optional_requirements VALUES(2441,175,4,'What is the difference between institutional cooking, restaurant cuisine, and home cooked food? Find a recipe that might be used for each.');
INSERT INTO badge_optional_requirements VALUES(2442,175,5,'Research a career that involves cooking. What education and experience do you need? What is the average pay and hours worked? If possible, shadow someone who works with food for a living for at least 4 hours.');
INSERT INTO badge_optional_requirements VALUES(2443,175,6,'Collect recipes for different types of pies and crusts. Prepare one cooked pie and one cold pie.');
INSERT INTO badge_optional_requirements VALUES(2444,175,7,'Prepare a “one pot” meal for your family in the form of a casserole or Crock Pot dish.');
INSERT INTO badge_optional_requirements VALUES(2445,175,8,'Collect recipes for appetizers. Make one hot appetizer and one cold appetizer.');
INSERT INTO badge_optional_requirements VALUES(2446,175,9,'Study model kitchens in stores and magazines. Then draw or make a model of your dream kitchen. Make sure you arrange things in a manner that is convenient to use in order to save on labor.');
INSERT INTO badge_optional_requirements VALUES(2447,175,10,'Learn to crack an egg correctly and make a recipe that requires you to do so.  Level 2 & Up: Learn how to crack an egg one handed with both your left and right hands. Can you crack two eggs at the same time without dropping any shells into your recipe?');
INSERT INTO badge_optional_requirements VALUES(2448,175,11,'Preschool & Level 1 only: Make a sandwich by yourself. Don’t forget to clean up and put everything away when you are done.');
INSERT INTO badge_optional_requirements VALUES(2449,175,12,'Make your own trail mix recipe using things like nuts, dried fruit, dry cereal, seeds, pretzels, etc.');
INSERT INTO badge_optional_requirements VALUES(2450,175,13,'Learn to cook eggs using one of the following methods: boiling, scrambling, frying, poaching, or coddling.');
INSERT INTO badge_optional_requirements VALUES(2451,175,14,'Learn several ways to use leftover meats and vegetables. Make a recipe that includes leftovers.');
INSERT INTO badge_optional_requirements VALUES(2452,175,15,'Make of the following and donate them to shut ins, police, firemen, or another worthy organization: cookies, cupcakes, brownies, muffins, pies, cakes, fudge, or other candy. Preschool-Level 2: Make one. Level 3: Make two. Level 4: Make three. Level 5: Make four.');
INSERT INTO badge_optional_requirements VALUES(2453,175,16,'Collect recipes using milk, such as cream soups, puddings, sauces, or ice cream. Pick two and make them.');
INSERT INTO badge_optional_requirements VALUES(2454,175,17,'Make one recipe where meat or seafood is the main ingredient.');
INSERT INTO badge_optional_requirements VALUES(2455,175,18,'Choose two vegetables you seldom eat or have never tried and cook each two different ways.');
INSERT INTO badge_optional_requirements VALUES(2456,175,19,'Collect recipes for different types of pizza. Learn to make pizza dough from scratch and cook two pizzas of your choice: traditional, vegetarian, dessert, etc.');
INSERT INTO badge_optional_requirements VALUES(2457,175,20,'Collect recipes for different types of salads. Prepare a hearty salad that contains meat, cheese, seafood, or eggs to serve as a main dish. Examples may include chef salad, cobb salad, grilled chicken salad, etc.');
INSERT INTO badge_optional_requirements VALUES(2458,175,21,'Plan a well balanced menu for a whole week for your family.  Include at least three dishes where leftovers may be utilized and cook at least two of the meals.');
INSERT INTO badge_optional_requirements VALUES(2459,175,22,'Prepare two simple dishes from another country.');
INSERT INTO badge_optional_requirements VALUES(2460,175,23,'Create your own cookbook. Include at least ten recipes with detailed instructions and pictures.');
INSERT INTO badge_optional_requirements VALUES(2461,176,3,'Learn the following cooking demo vocabulary and practice the list of presentation tips: Vocabulary: Prep Ad lib Script Scripted Outline Time constraint Product promotion Presentation Tips: Increase audience participation by asking questions like, “Do you like this fruit/vegetable? How do you usually prepare it?” Place a damp cloth under mixing bowls to hold them steady and cut down on noise. Use wooden spoons rather than metal ones to cut down on noise. Tip bowls and pans toward participants so they can see them better. Don’t try to speak over loud machines. Bring items to garnish the product such as lettuce leaves, parsley, etc. If people ask you questions concerning their health problems, refer them to their physician or the dietitian at the clinic, hospital, or doctor’s office that they visit.');
INSERT INTO badge_optional_requirements VALUES(2462,176,4,'Discuss what types of attire, jewelry, and makeup are appropriate for a person demonstrating cooking techniques.');
INSERT INTO badge_optional_requirements VALUES(2463,176,5,'Watch a camera person or crew as they film or photograph a cooking demonstration. What things do they have to keep track of? What equipment do the y need besides the actual camera?');
INSERT INTO badge_optional_requirements VALUES(2464,176,6,'If someone asks you to give a cooking demonstration in a location you’ve never visited, what should you find out before and after agreeing to do the demo?');
INSERT INTO badge_optional_requirements VALUES(2465,176,7,'Do a demo that has a strict time limit. Practice with a timer at least twice before giving your presentation.');
INSERT INTO badge_optional_requirements VALUES(2466,176,8,'Do all the preparations for a demonstration: All the shopping, gathering of equipment Writing your outline Making a list of things to remember such as wearing an apron and tying your hair back, checking for proper seating and lighting, etc.');
INSERT INTO badge_optional_requirements VALUES(2467,176,9,'What makes a good demonstration kitchen? Discuss kitchen layout, the lighting, the seating, cooking supplies, safety features, etc.');
INSERT INTO badge_optional_requirements VALUES(2468,176,10,'Do a demonstration that helps others earn this badge.');
INSERT INTO badge_optional_requirements VALUES(2469,176,11,'When should you provide something in writing for your audience? What kinds of things would an audience want to take home with them? Practice writing directions or a recipe in a methodical manner.');
INSERT INTO badge_optional_requirements VALUES(2470,176,12,'What do you do if something goes wrong during a demo? When should you start over instead of just continuing the demo? When would humor not be appropriate? When should you tell an audience to evacuate a building? Learn how to accept compliments & constructive criticisms gracefully.');
INSERT INTO badge_optional_requirements VALUES(2471,176,13,'Earn three cooking-related badges such as baking, cooking, vegetables, ice cream, etc.');
INSERT INTO badge_optional_requirements VALUES(2472,176,14,'Learn about careers that involve cooking demos. In addition to the chef giving the demo, there are set and kitchen designers, marketing and promotion, camera operators, etc. What might your salary be in one of these positions? Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(2473,176,15,'Learn how famous chefs or bakers have earned their own cooking demonstration shows. What did it take for them to reach that point? How does their content differ from other similar shows? What type of audience are they targeting?');
INSERT INTO badge_optional_requirements VALUES(2474,177,3,'Create a totally new recipe that fits a special diet and be able to justify the use of all ingredients.');
INSERT INTO badge_optional_requirements VALUES(2475,177,4,'Figure out a way to present a meal to entice a sick person (on one of the diets listed below) with poor appetite to eat it.');
INSERT INTO badge_optional_requirements VALUES(2476,177,5,'Cook something for someone on a special diet as a present or favor.');
INSERT INTO badge_optional_requirements VALUES(2477,177,6,'Learn about careers that involve special diets. Examples might include being a personal chef, a nutritionist, or a personal care assistant. For Optional Requirements 7-18: Find out what can and cannot be eaten on the diet and what the benefits of the diet are. Find out the things that are cautions for each diet. Find out what the standard ‘substitutions’ are for the items not used on the diet. Fix one dish that needed to be modified from the “standard recipe” to fit the diet.');
INSERT INTO badge_optional_requirements VALUES(2478,177,7,'Low-glycemic/diabetic');
INSERT INTO badge_optional_requirements VALUES(2479,177,8,'High protein');
INSERT INTO badge_optional_requirements VALUES(2480,177,9,'Low salt');
INSERT INTO badge_optional_requirements VALUES(2481,177,10,'Ketogenic');
INSERT INTO badge_optional_requirements VALUES(2482,177,11,'Gluten-free');
INSERT INTO badge_optional_requirements VALUES(2483,177,12,'Dairy-free');
INSERT INTO badge_optional_requirements VALUES(2484,177,13,'Any other allergy or rotation diet eliminating a class of food');
INSERT INTO badge_optional_requirements VALUES(2485,177,14,'Liquid diet');
INSERT INTO badge_optional_requirements VALUES(2486,177,15,'High-fiber diet');
INSERT INTO badge_optional_requirements VALUES(2487,177,16,'Low oxalate diet (interstitial cystitis diet)');
INSERT INTO badge_optional_requirements VALUES(2488,177,17,'Raw foods');
INSERT INTO badge_optional_requirements VALUES(2489,177,18,'Low salicylates (for hyperactive kids)');
INSERT INTO badge_optional_requirements VALUES(2490,178,3,'Practice different ways you can protect reefs in everyday life, like  Disposing of trash properly and never littering. Coral reefs can be damaged by trash that blows into waterways or the ocean.  Minimizing use of fertilizer on your lawn, where possible. Fertilizer runoff enters waterways and can cause damage to reefs even if you live very far from the coast. Nutrients from excess fertilized increase algae growth, which blocks sunlight from corals. Conserve water. The less water you use, the less runoff and wastewater that will eventually find its way to the ocean.');
INSERT INTO badge_optional_requirements VALUES(2491,178,4,'Know what a drowned reef is.');
INSERT INTO badge_optional_requirements VALUES(2492,178,5,'Earn the ocean conservation badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2493,178,6,'Make a piece of art, like a drawing or a sculpture, depicting coral reefs.');
INSERT INTO badge_optional_requirements VALUES(2494,178,7,'Contact a local representative to ask what your state is doing to protect water quality and coral reefs.');
INSERT INTO badge_optional_requirements VALUES(2495,178,8,'Read a book about coral reefs.');
INSERT INTO badge_optional_requirements VALUES(2496,178,9,'Participate in a beach cleanup. Trash on the beach can make its way into the ocean and harm corals.');
INSERT INTO badge_optional_requirements VALUES(2497,178,10,'Learn to follow Leave No Trace principles with beaches, oceans, and watersheds.');
INSERT INTO badge_optional_requirements VALUES(2498,178,11,'Learn the difference between hard and soft coral.');
INSERT INTO badge_optional_requirements VALUES(2499,178,12,'Draw and label the parts of a coral polyp or create a model or sculpture of a polyp complete with labels.');
INSERT INTO badge_optional_requirements VALUES(2500,178,13,'Locate and mark the major coral reefs around the world.');
INSERT INTO badge_optional_requirements VALUES(2501,178,14,'Explain the role of coral reffs in the larger marine ecosystem.');
INSERT INTO badge_optional_requirements VALUES(2502,178,15,'Research and describe at least three different coral reef conservation organizations and what they do.');
INSERT INTO badge_optional_requirements VALUES(2503,178,16,'Conduct a basic water quality test (e.g., pH, temperature, salinity) in a local body of water.  Compare your results to the ideal conditions for coral reefs.');
INSERT INTO badge_optional_requirements VALUES(2504,178,17,'Create a presentation or pamphlet to educate others on coral reefs.');
INSERT INTO badge_optional_requirements VALUES(2505,178,18,'Learn about deep water corals, who extend to deeper and darker parts of the ocean than shallow corals.');
INSERT INTO badge_optional_requirements VALUES(2506,178,19,'Learn about the Census of Coral Reefs by the Census of Marine Life.');
INSERT INTO badge_optional_requirements VALUES(2507,178,20,'Participate in a swimming, snorkeling or diving activity to observe a coral reef.');
INSERT INTO badge_optional_requirements VALUES(2508,178,21,'Visit a local aquarium that features a coral reef exhibit.  Interview a marine biologist or aquarium staff about coral reef care.');
INSERT INTO badge_optional_requirements VALUES(2509,178,22,'Learn to identify at least five different species of coral.  Create a field guide with drawings or photos of these species.');
INSERT INTO badge_optional_requirements VALUES(2510,178,23,'Learn about the process of coral spawning.  Watch a video or documentary about coral spawning events.');
INSERT INTO badge_optional_requirements VALUES(2511,178,24,'Take photographs of coral reefs, or create a photo slideshow of different coral types.');
INSERT INTO badge_optional_requirements VALUES(2512,178,25,'Design and play a board game or card game that teaches about coral reefs.');
INSERT INTO badge_optional_requirements VALUES(2513,178,26,'Conduct a simulation or experiment to demonstrate the effects of coral bleaching.  Discuss the results and implications for real coral reefs.');
INSERT INTO badge_optional_requirements VALUES(2514,178,27,'Read a book or story set in a coral reef environment.  Discuss the role of the reef in the story and what you learned from it.');
INSERT INTO badge_optional_requirements VALUES(2515,178,28,'Research and list sustainable seafood options that do not harm coral reefs.  Prepare a meal using one of these sustainable options. Learn about how climate change affects ocean acidification and impedes the growth and ability to survive of coral reefs. 25% of the world’s coral reefs have disappeared in the last 30 years!');
INSERT INTO badge_optional_requirements VALUES(2516,180,3,'Learn about special accessories that go with a specific costume. These might be a special hat, piece of jewelry, shoes, scarf, etc. Why are they important to the overall costume? What role to they play?');
INSERT INTO badge_optional_requirements VALUES(2517,180,4,'Investigate different fabrics used for costumes around the world such as lodin or madras. What are they made from and what are they used for?');
INSERT INTO badge_optional_requirements VALUES(2518,180,5,'Read a book on historical costumes or watch a documentary on the subject. From your point of view did they do a good job presenting the material? Why or why not?');
INSERT INTO badge_optional_requirements VALUES(2519,180,6,'Find different decorative elements on fabrics from countries around the world. Embroidered fabrics from Europe, prints from Asia and the Pacific Islands, or shisha (alba) embroidered fabric from India.');
INSERT INTO badge_optional_requirements VALUES(2520,180,7,'Attend an event where people wear authentic cultural clothing, a cultural awareness day, a cinco de mayo celebration, etc…');
INSERT INTO badge_optional_requirements VALUES(2521,180,8,'Make a complete authentic costume of your choice from a country you researched. Full-scale, authentic fabrics and accessories if possible.');
INSERT INTO badge_optional_requirements VALUES(2522,180,9,'Create a game, write a brochure or blog post, or make a poster to help other people learn or understand more about cultural clothing from around the world.');
INSERT INTO badge_optional_requirements VALUES(2523,180,10,'Attend and help with a cultural awareness project/event where ethnic costumes are used. What did this teach you?');
INSERT INTO badge_optional_requirements VALUES(2524,180,11,'Find out what would be the monetary value of some of the costumes you have studied. Did people make their clothing or was it store made? What were some of the materials used? Why would certain articles of clothing be more expensive or rare?');
INSERT INTO badge_optional_requirements VALUES(2525,180,12,'Visit a museum or exhibit about costumes. These could be historical costumes, ethnic costumes, Hollywood costumes, etc.');
INSERT INTO badge_optional_requirements VALUES(2526,180,13,'Talk to someone who has a career in costumes. It could be a designer or a historian. Where do they find out what costumes were like in that particular place or time period? Why is it important to be correct in research?');
INSERT INTO badge_optional_requirements VALUES(2527,180,14,'Learn about careers in the costume business. Everything from costume store owner to designers for movies or television shows. What kind of education would you need to obtain such a job? What kind of salary could you expect?');
INSERT INTO badge_optional_requirements VALUES(2528,180,15,'Participate in a community service project involving ethnic or historic costumes.  Examples might include helping with restorations or sewing costumes for a festival.');
INSERT INTO badge_optional_requirements VALUES(2529,180,16,'Learn about masks worn around the world. What role do they play? How do they differ between countries?');
INSERT INTO badge_optional_requirements VALUES(2530,182,3,'Participate in a flag ceremony, parade or event at your fair.');
INSERT INTO badge_optional_requirements VALUES(2531,182,4,'Enter a project  into the fair such as a pie, some photography or an animal.');
INSERT INTO badge_optional_requirements VALUES(2532,182,5,'Earn one of the Animal badges that you saw at your fair, such as rabbits, cows, horses, chickens, etc.');
INSERT INTO badge_optional_requirements VALUES(2533,182,6,'Enter an exhibit or info board about your Quest Club group.');
INSERT INTO badge_optional_requirements VALUES(2534,182,7,'Be a judge/junior judge at the fair.');
INSERT INTO badge_optional_requirements VALUES(2535,182,8,'Learn how to make a food commonly found at the fair, such as cotton candy, elephant ears, funnel cakes, deep fried Oreo’s, etc).');
INSERT INTO badge_optional_requirements VALUES(2536,182,9,'Meet the fair coordinator,  members of the committee or fair president. What is their job?');
INSERT INTO badge_optional_requirements VALUES(2537,182,10,'Watch a movie or read a book about being at the fair , such as Charlotte’s Web.');
INSERT INTO badge_optional_requirements VALUES(2538,182,12,'Earn your major in Agriculture award');
INSERT INTO badge_optional_requirements VALUES(2539,183,3,'Discuss how standing up for your own beliefs takes courage and why it is important.');
INSERT INTO badge_optional_requirements VALUES(2540,183,4,'What does your book of faith say about courage? Find at least five passages or verses that talk about courage and write them down.');
INSERT INTO badge_optional_requirements VALUES(2541,183,5,'Explore career options that would involve courage, such as a police office or firefighter. How would having courage be important for a job like that? How could you demonstrate it?');
INSERT INTO badge_optional_requirements VALUES(2542,183,6,'Participate in a community service project that involves courage. Examples might be collecting teddy bears for police to give to kids when they are taken from their parents, making cookies or treats for you local fire department, or collecting games for kids in hospitals.');
INSERT INTO badge_optional_requirements VALUES(2543,183,7,'Read a story or novel about a courageous person.');
INSERT INTO badge_optional_requirements VALUES(2544,183,8,'Write a poem, song or essay about what courage means to you.');
INSERT INTO badge_optional_requirements VALUES(2545,183,10,'Create a piece of artwork that represents courage.');
INSERT INTO badge_optional_requirements VALUES(2546,183,11,'Role play different situations where courage may be necessary such as standing up to a bully, public speaking, getting a shot at the doctor’s, etc.');
INSERT INTO badge_optional_requirements VALUES(2547,183,12,'Interview someone in your life who had to exhibit a great deal of courage in a specific situation in their life. Ask them how they overcame their fears and how they felt afterwards.');
INSERT INTO badge_optional_requirements VALUES(2548,184,3,'Find out what types of guns cowboys/girls used. Why were guns important? What were they used for? What is sharp shooting? If possible, watch a sharp shooting competition either in person or on video.');
INSERT INTO badge_optional_requirements VALUES(2549,184,4,'It wasn’t until the advent of Wild West Shows that “cowgirls” came into their own. These women were performers skilled in expert marksmanship, trick roping, and demonstrating riding. Learn about at least one famous Wild West Show and the women they featured.');
INSERT INTO badge_optional_requirements VALUES(2550,184,5,'Watch a movie or television show with cowboys or cowgirls in it, such as a Clint Eastwood or John Wayne movie or a show like Bonanza.');
INSERT INTO badge_optional_requirements VALUES(2551,184,6,'Watch a movie with cowboys or cowgirls in it, such as Calamity Jane or The Dalton Girls.');
INSERT INTO badge_optional_requirements VALUES(2552,184,7,'Take a western horseback riding lesson.');
INSERT INTO badge_optional_requirements VALUES(2553,184,8,'Attend a rodeo with men or women competitors.');
INSERT INTO badge_optional_requirements VALUES(2554,184,9,'Learn how to make a lasso. Be able to throw it and tie it around a fence post or other object.');
INSERT INTO badge_optional_requirements VALUES(2555,184,10,'Watch a documentary or read the biography of a famous cowboy/girl.');
INSERT INTO badge_optional_requirements VALUES(2556,184,11,'Earn one of the firearm badges.');
INSERT INTO badge_optional_requirements VALUES(2557,185,1,'Create something using clay. You can use salt dough, polymer clay, an air dry clay, or pottery clay.');
INSERT INTO badge_optional_requirements VALUES(2558,185,2,'Learn the art of quilling. Quilling or paper filigree is the art of rolling thin strips of paper into different shapes and using the shapes to form designs. Learn to make a variety of quilling shapes and create a picture to frame or a note card to give to someone.');
INSERT INTO badge_optional_requirements VALUES(2559,185,3,'Learn how to rubber stamp. Make sure you know how to properly ink and clean your stamps. Make 6 simple cards to give away. For Butterflies and Eagles, learn advanced rubber stamping techniques such as embossing. Use stamps to embellish something other than paper such as a candle, fabric, or wood.');
INSERT INTO badge_optional_requirements VALUES(2560,185,4,'Learn how to emboss on metal sheets. Do not forget that metal can have sharp edges so be careful. Use your embossed metal on a scrapbook page, a card, or even to decorate a small box.');
INSERT INTO badge_optional_requirements VALUES(2561,185,5,'Make your own picture frame. Use stickers, paint, glitter, whatever you want. Insert one of your favorite pictures when it’s finished.');
INSERT INTO badge_optional_requirements VALUES(2562,185,6,'Create a holiday themed decoration for the holiday of your choice. This could be a wreath for Christmas, a spooky banner for Halloween, etc.');
INSERT INTO badge_optional_requirements VALUES(2563,185,7,'Make a giant poster that represents who you are. Include a picture of yourself in the middle and surround it with things you love, such as your favorite books or movies, pictures of your family, pets, activities you love, etc. Be creative. Share it with your family or troop.');
INSERT INTO badge_optional_requirements VALUES(2564,185,8,'Learn how to papier-mache. This is the method of using paper strips glued together with adhesive and placing them on a structure or shape of your choice. Create one project with this technique.');
INSERT INTO badge_optional_requirements VALUES(2565,185,9,'Learn a craft of your choice that is not listed here. (This requirement may be repeated with new crafts)');
INSERT INTO badge_optional_requirements VALUES(2566,186,1,'Make a list of 10 things you can put into a crepe.');
INSERT INTO badge_optional_requirements VALUES(2567,186,2,'Make a fruit crepe and a crepe with jelly. Which one looks more professional?  Which tastes better?');
INSERT INTO badge_optional_requirements VALUES(2568,186,3,'Make a Crepe Suzette.');
INSERT INTO badge_optional_requirements VALUES(2569,186,4,'Make a lunch or dinner crepe.');
INSERT INTO badge_optional_requirements VALUES(2570,186,5,'Make a breakfast crepe.');
INSERT INTO badge_optional_requirements VALUES(2571,186,6,'Make a dessert crepe.');
INSERT INTO badge_optional_requirements VALUES(2572,186,7,'Have a party with a crepe bar.');
INSERT INTO badge_optional_requirements VALUES(2573,186,8,'Take a field trip to a restaurant that specializes in crepes.');
INSERT INTO badge_optional_requirements VALUES(2574,186,9,'How can you make a crepe for those that are lactose intolerant? Is it easy to find a recipe? Make a crepe without any dairy.');
INSERT INTO badge_optional_requirements VALUES(2575,186,10,'Make a crepe batter with gluten-free flour. How does it taste? How well does it cook?');
INSERT INTO badge_optional_requirements VALUES(2576,186,11,'Make a crepe batter with honey and one with sugar. Did they cook the same? Is one sweeter?');
INSERT INTO badge_optional_requirements VALUES(2577,186,12,'It there a way to make a crepe that is vegan? Find a recipe and see what ingredients they use that are different? Are there other ingredients that can be used like the recipe you found?');
INSERT INTO badge_optional_requirements VALUES(2578,186,13,'Earn the Cooking badge for your level.');
INSERT INTO badge_optional_requirements VALUES(2579,186,14,'Look for menus at restaurants that serve crepes; what do they put on their crepes? How is it different from yours?');
INSERT INTO badge_optional_requirements VALUES(2580,186,15,'Look at the prices that restaurants have customers pay for crepes? Calculate what it cost for you to make yours? What are the differences between what it took to make and what they pay in restaurants?');
INSERT INTO badge_optional_requirements VALUES(2581,186,16,'Make crepes for your church or for a community event.');
INSERT INTO badge_optional_requirements VALUES(2582,186,17,'Have a crepe making contest with a group to see who can make the most unique crepe.');
INSERT INTO badge_optional_requirements VALUES(2583,186,18,'How would you set up crepes for a pot luck compared to a family dinner? How would you keep them fresh and warm without getting soggy or cold?');
INSERT INTO badge_optional_requirements VALUES(2584,188,3,'Teach someone else how to crochet.');
INSERT INTO badge_optional_requirements VALUES(2585,188,4,'Look through someone’s yarn collection or go to a store that sells yarn to feel at least four different types of fiber (bamboo, wool, acrylic, mohair, cotton) and three styles of yarns such as plain, fuzzy, variegated colors, etc.');
INSERT INTO badge_optional_requirements VALUES(2586,188,5,'Make a collage poster or small booklet picturing at least 10 different crocheted items.');
INSERT INTO badge_optional_requirements VALUES(2587,188,6,'Visit a fair or craft day display that displays at least ten different crocheted items.');
INSERT INTO badge_optional_requirements VALUES(2588,188,7,'Find a new or used garment in a store/sale that has some part crocheted. Buy it and either wear it or give it away.');
INSERT INTO badge_optional_requirements VALUES(2589,188,8,'Learn how to care for crocheted items. Learn what the little laundry symbols mean on yarn labels. Why does the temperature of washing water matter? What is blocking? How can you repair a crocheted item that has a hole?');
INSERT INTO badge_optional_requirements VALUES(2590,188,9,'Compare at least three beginning crochet instructional manuals (books, DVD’s, Internet, YouTube, etc). Which were easiest to understand? How could the illustrations or instructions be better?');
INSERT INTO badge_optional_requirements VALUES(2591,188,10,'Make at least three crocheted items to donate to a shelter or other non-profit.');
INSERT INTO badge_optional_requirements VALUES(2592,188,11,'Trace the history of crocheting. Where did it originate? Research to find a museum containing a crochet collection that you’d like to visit.');
INSERT INTO badge_optional_requirements VALUES(2593,188,12,'Come up with three ideas of ways to use leftover yarn. Make a project with yarn leftovers.');
INSERT INTO badge_optional_requirements VALUES(2594,188,13,'Learn how to take a crochet pattern and make the item for a larger person.');
INSERT INTO badge_optional_requirements VALUES(2595,188,14,'Attend a crochet class at a craft store.');
INSERT INTO badge_optional_requirements VALUES(2596,188,15,'Crochet an item to donate to someone in the hospital, such as a hat for a cancer patient who has lost their hair or a blanket.');
INSERT INTO badge_optional_requirements VALUES(2597,188,16,'Crochet a baby item to give away to a newborn baby.');
INSERT INTO badge_optional_requirements VALUES(2598,188,17,'Find a new way to organize and store your yarn collection. This could include buying new bins for organization, building a display on your wall, or simply organizing by color or yarn type. Be creative.');
INSERT INTO badge_optional_requirements VALUES(2599,189,3,'Visit a craft or sewing store and examine the cross stitch supplies. What type of fabrics do they have for cross stitch? What types of  thread, embroidery floss, or yarn? What type of books? What type of hoops?');
INSERT INTO badge_optional_requirements VALUES(2600,189,4,'Learn how to properly secure the edges of your fabric so they don’t fray. When you finish your project, learn how to frame it. Hang it somewhere special.');
INSERT INTO badge_optional_requirements VALUES(2601,189,5,'Visit an exhibit or display of cross stitch pieces.');
INSERT INTO badge_optional_requirements VALUES(2602,189,6,'Learn the history of cross stitch in relation to other embroidery techniques.');
INSERT INTO badge_optional_requirements VALUES(2603,189,7,'Create a cross stitch piece to give to someone else.');
INSERT INTO badge_optional_requirements VALUES(2604,189,8,'Cross stitch a design on a piece of gingham.');
INSERT INTO badge_optional_requirements VALUES(2605,189,9,'Create a traditional sampler using cross stitch.');
INSERT INTO badge_optional_requirements VALUES(2606,189,10,'Create a cross stitch book mark.');
INSERT INTO badge_optional_requirements VALUES(2607,189,11,'Create a cross stitch ornament.');
INSERT INTO badge_optional_requirements VALUES(2608,189,12,'Create a set of note cards with cross stitch patterns on the front.');
INSERT INTO badge_optional_requirements VALUES(2609,189,13,'Learn about different needlecraft organizations and associations such as the Cross Stitch Guild, National Academy of Needle Arts, National Needle Arts Association, or Embroiders Guild of America.');
INSERT INTO badge_optional_requirements VALUES(2610,189,14,'Learn about Aida cloth. What is the difference between 8 count Aida cloth and 16 count? How will the count affect your finished piece? Use Aida cloth, an embroidery hoop, and embroidery floss. Learn how to find the center of your cloth and do an anchor stitch. Learn how to properly cut and unwind embroidery floss without causing knots. Know how many strands you should be using for the size Aida cloth you are using in your project. Make sure to keep an extra 3” border around your design area and seal the edges with masking tape to prevent fraying.');
INSERT INTO badge_optional_requirements VALUES(2611,189,15,'Learn the history of cross stitch. Where did it originate? Who are some artists who are famous for their cross stitch?');
INSERT INTO badge_optional_requirements VALUES(2612,190,3,'Write an essay about the history of cruise ships and how the invention of the cruise ship affected world travel.');
INSERT INTO badge_optional_requirements VALUES(2613,190,4,'Go on a cruise.');
INSERT INTO badge_optional_requirements VALUES(2614,190,5,'Watch an age-appropriate movie, TV show, or documentary about a cruise. Summarize the show and how they presented life on a cruise ship.');
INSERT INTO badge_optional_requirements VALUES(2615,190,6,'Research careers in the cruise business, List 8 different jobs related to cruise ships. Choose one to research and find out how much they are paid, what qualifications are needed, how long the contract is usually for, etc.');
INSERT INTO badge_optional_requirements VALUES(2616,190,7,'Share about a cruise you went on. What cruise line did you go on? Where did you go? What was your room like? What was the food like? What was your favorite thing to do on the ship?  This requirement may be done verbally, in writing, or in an art presentation.');
INSERT INTO badge_optional_requirements VALUES(2617,190,8,'What types of entertainment is available on a cruise ship? List at least 5 things. What do you think you would enjoy the most? Why?  What are the entertainment options between a mega cruise ship and a small cruise ship?');
INSERT INTO badge_optional_requirements VALUES(2618,190,9,'Research 10 different ports a person could start a cruise at. Which one is closest you where you live? How far away is this port? Where can you travel from this port?');
INSERT INTO badge_optional_requirements VALUES(2619,190,10,'Interview someone who works on a cruise ship. How did they get their job? What is their favorite part of their job? What is the hardest part of their job?');
INSERT INTO badge_optional_requirements VALUES(2620,190,11,'What happens if a cruise ship breaks down in the middle of the ocean? How is it fixed? What do they do with the people if it can’t be fixed right away? Do the passengers get a refund?');
INSERT INTO badge_optional_requirements VALUES(2621,190,12,'What happens if some get’s sick or hurt on a cruise ship? How do they get the help they need?');
INSERT INTO badge_optional_requirements VALUES(2622,190,13,'Learn about 3 excursions (things to do at a port) that you find interesting. Tell someone about each one and why you think it would be fun to do.');
INSERT INTO badge_optional_requirements VALUES(2623,190,14,'Make a presentation about a cruise (tell about a cruise line, a trip, a specific ship, etc.) with at least 7 slides in your presentation. Share your presentation with someone.');
INSERT INTO badge_optional_requirements VALUES(2624,190,15,'If you go on a cruise that ports in a country you are not from, tell about that country’s culture. What types of foods were different than your home country’s? What did you notice about the people? Clothing? Shopping areas? Climate? Land? What else would you like to share?');
INSERT INTO badge_optional_requirements VALUES(2625,190,16,'Space on a cruise ship is extremely limited.  Research packing tips for a cruise and learn how to make the most of the small space you will have.');
INSERT INTO badge_optional_requirements VALUES(2626,190,17,'Learn about volunteer opportunities on a cruise line such as Luxe Crystal Cruises ever-expanding You Care, We Care program or Holland America’s Cruise with Purpose.');
INSERT INTO badge_optional_requirements VALUES(2627,190,18,'Find out about charity cruises that raise money for various charities around the world such as Carnival’s Care to Play that support St. Jude Children’s Hospital.');
INSERT INTO badge_optional_requirements VALUES(2628,191,3,'Learn about Phantom Cats otherwise known as Big Alien Cats.');
INSERT INTO badge_optional_requirements VALUES(2629,191,4,'Earn the Bigfoot badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2630,191,5,'Learn about a cryptid in your area. What evidence exists to support it?');
INSERT INTO badge_optional_requirements VALUES(2631,191,6,'Watch a documentary about a cryptid.');
INSERT INTO badge_optional_requirements VALUES(2632,191,7,'Read a book or a scientific article about a cryptid.');
INSERT INTO badge_optional_requirements VALUES(2633,191,8,'Learn what cryptozoology means. Who are cryptozoologists? Do they have any special training?');
INSERT INTO badge_optional_requirements VALUES(2634,191,9,'Create a timeline of sightings of cryptids.');
INSERT INTO badge_optional_requirements VALUES(2635,191,10,'Create a world map with different cryptids identified by where they’re believed to exist.');
INSERT INTO badge_optional_requirements VALUES(2636,191,11,'Many cryptids are spotted out in nature. Learn the safety rules of going out searching for cryptids.');
INSERT INTO badge_optional_requirements VALUES(2637,191,12,'Learn about cryptozoology forums. With a parent’s permission and supervision, read cryptozoology forum posts.');
INSERT INTO badge_optional_requirements VALUES(2638,191,13,'Plan a mock expedition to search for a specific cryptid, including location scouting and equipment preparation.');
INSERT INTO badge_optional_requirements VALUES(2639,191,14,'Study famous cryptid photographs and learn to analyze them for authenticity.');
INSERT INTO badge_optional_requirements VALUES(2640,191,15,'Understand common methods used in hoaxing cryptid evidence and how to spot them.');
INSERT INTO badge_optional_requirements VALUES(2641,191,16,'Learn about the impact of cryptid tourism on local economies and environments.');
INSERT INTO badge_optional_requirements VALUES(2642,191,17,'Analyze how cryptids are portrayed in various forms of media (e.g., movies, TV shows, documentaries).');
INSERT INTO badge_optional_requirements VALUES(2643,191,18,'Understand legal considerations related to cryptid research, such as permits and land access.  Why can’t you just go anywhere you want to look for cryptids?');
INSERT INTO badge_optional_requirements VALUES(2644,191,19,'Prepare a presentation or report on a specific cryptid.');
INSERT INTO badge_optional_requirements VALUES(2645,191,20,'Make a 3D sculpture, model or drawing of a specific cryptid.');
INSERT INTO badge_optional_requirements VALUES(2646,192,3,'Try on or research outfits from your chosen country. Learn when these are worn. Are they everyday clothes or ceremonial?');
INSERT INTO badge_optional_requirements VALUES(2647,192,4,'Learn a traditional craft from your chosen country.');
INSERT INTO badge_optional_requirements VALUES(2648,192,5,'Learn a children’s song, nursery rhyme or traditional song from your chosen country. Learn its significance.');
INSERT INTO badge_optional_requirements VALUES(2649,192,6,'Read a story from your chosen country (in English is fine). What similarities and differences do you see compared to your life? Listen to the words and also look at the pictures.');
INSERT INTO badge_optional_requirements VALUES(2650,192,7,'What is the most common mode of transportation in your chosen country?');
INSERT INTO badge_optional_requirements VALUES(2651,192,8,'Learn about the geography and climate of your chosen country. How does it affect the culture of your chosen country such as what they wear, build with and eat.');
INSERT INTO badge_optional_requirements VALUES(2652,192,9,'What are common toys and games for children in your chosen country? Do you think it would be fun to play with those? Why or why not? If possible, try to play one of them.');
INSERT INTO badge_optional_requirements VALUES(2653,192,10,'Interview someone from your chosen country.  How does living in their country differ from yours?');
INSERT INTO badge_optional_requirements VALUES(2654,192,11,'Make a poster advertising travel to this country highlighting some of the more famous things to do there.');
INSERT INTO badge_optional_requirements VALUES(2655,192,12,'Cook a dish from your chosen country and serve it to your family or troop.');
INSERT INTO badge_optional_requirements VALUES(2656,192,13,'Learn some of the history of your selected country and make a timeline with ten important events.  Be able to explain how these events affected the culture of that country.');
INSERT INTO badge_optional_requirements VALUES(2657,192,14,'Attend or participate in a cultural event, festival, or celebration related to your chosen culture.');
INSERT INTO badge_optional_requirements VALUES(2658,192,15,'Find out what type of alphabet they use in your selected country. Is it familiar to yours or different? If similar, are some letters pronounced differently? Write the entire alphabet.');
INSERT INTO badge_optional_requirements VALUES(2659,192,16,'Be able to recognize the flag of your chosen country and explain the symbolism of the design.');
INSERT INTO badge_optional_requirements VALUES(2660,192,17,'Learn about the history and important holidays of the culture. What do they celebrate and why?');
INSERT INTO badge_optional_requirements VALUES(2661,192,18,'Explore how this culture expresses itself through art, dance, or music. Try learning a traditional dance move or musical rhythm.');
INSERT INTO badge_optional_requirements VALUES(2662,192,19,'Learn about the religion(s) commonly practiced in the culture and how they influence daily life.');
INSERT INTO badge_optional_requirements VALUES(2663,192,20,'Research how colonization, immigration, or war affected the culture and what it looks like today.');
INSERT INTO badge_optional_requirements VALUES(2664,193,3,'Know how butter and cottage cheese are made and approximately how much milk it takes to make a pound of each. Make some of each, if you can.');
INSERT INTO badge_optional_requirements VALUES(2665,193,4,'Visit a dairy and learn how milk is handled before and after pasteurizing and how it is prepared for delivery. If you cannot visit a real dairy, visit one online.');
INSERT INTO badge_optional_requirements VALUES(2666,193,5,'Be able to describe the food values of milk and milk products. Know three recipes using milk products in quantity.');
INSERT INTO badge_optional_requirements VALUES(2667,193,6,'Visit and, if possible, take part in your state or county fair. Visit the dairy cows and/or goats.');
INSERT INTO badge_optional_requirements VALUES(2668,193,7,'Know what is meant by butterfat content and how it is measured. Know how and why milk is pasteurized and how it can be done in the home. Know the difference between the two market kinds of milk, namely, raw and pasteurized, and the usual three grades of each, namely, Certified, Grade A, and Grade B.');
INSERT INTO badge_optional_requirements VALUES(2669,193,8,'What is meant by the term “raw” milk? Learn about the difference between “raw” and pasteurized milk. Which states permit the sale of raw milk? Learn how a dairy may become a “Grade-A Certified Raw Milk Dairy.” Find out if any dairies in your community sell raw milk.');
INSERT INTO badge_optional_requirements VALUES(2670,193,9,'Know the wholesale and retail costs of various grades of milk, including homogenized, in your community, and, if possible, how the prices are set.');
INSERT INTO badge_optional_requirements VALUES(2671,193,10,'Find out how to make milk soap. Make some, if possible.');
INSERT INTO badge_optional_requirements VALUES(2672,193,11,'Using what you have learned, put together a short booklet or poster to teach younger kids about dairy production, or teach younger kids about the health benefits of milk and cook a recipe using milk with them.');
INSERT INTO badge_optional_requirements VALUES(2673,193,12,'Know the sanitary care of milking machines, pails, and other equipment used in milking.');
INSERT INTO badge_optional_requirements VALUES(2674,193,13,'Learn what you can about your state and local laws that govern the sanitation of a dairy barn and the marketing of milk.');
INSERT INTO badge_optional_requirements VALUES(2675,193,14,'Be able to identify and describe the following milk products: Crème fraiche Clotted cream Butter milk Skim milk Condensed milk Evaporated milk Ghee Gelato Custard Dulce de leche Yogurt Sour cream Cottage cheese Kefir');
INSERT INTO badge_optional_requirements VALUES(2676,193,15,'Volunteer at a dairy farm for the day.');
INSERT INTO badge_optional_requirements VALUES(2677,193,16,'Learn about careers involving dairying. What type of training or education do you need?');
INSERT INTO badge_optional_requirements VALUES(2678,194,3,'Use decoupage for community service. For example, you might make a decoupage craft to sell to raise money for a charity, or use decoupage to help create decor when redecorating a room at a homeless shelter.');
INSERT INTO badge_optional_requirements VALUES(2679,194,4,'Teach a decoupage technique to others.');
INSERT INTO badge_optional_requirements VALUES(2680,194,5,'Take a field trip to visit an artist who uses decoupage.');
INSERT INTO badge_optional_requirements VALUES(2681,194,6,'Visit an exhibit of decoupage art.');
INSERT INTO badge_optional_requirements VALUES(2682,194,7,'Create some type of home décor using decoupage. Examples might include a vase, a pencil holder, jewelry box, frame, furniture, or light switch cover.');
INSERT INTO badge_optional_requirements VALUES(2683,194,8,'Use decoupage as part of a mixed media art piece.');
INSERT INTO badge_optional_requirements VALUES(2684,194,9,'Use decoupage to make a recycled craft.');
INSERT INTO badge_optional_requirements VALUES(2685,194,10,'Learn about careers that use decoupage.');
INSERT INTO badge_optional_requirements VALUES(2686,194,11,'Use decoupage to create some holiday or party decor.');
INSERT INTO badge_optional_requirements VALUES(2687,194,12,'Use decoupage to create a piece of jewelry.');
INSERT INTO badge_optional_requirements VALUES(2688,194,13,'Decoupage on eggs. You will need: An egg An Exacto knife or thick needle (please use with parental supervision) A bowl A mixture of water and vinegar White glue A paint brush Patterned tissue paper or a patterned paper napkin Clear, sparkling glitter Two beads Ribbon or colored string. Instructions: Blow out an egg by poking a small hole on each end using the point of an Exacto knife or a thick needle (an adult should help with this part). Use a toothpick to scramble the inside of the egg. Then blow on one end with your egg over a bowl until all the inside has been blown out. Rinse the egg by filling it with water and vinegar and re-blowing it out. Let it dry. Using patterned tissue paper or paper napkins, cut out the designs you wish to put on your egg (if you are using paper napkins, make sure you peel them down to only a single layer of paper). Paint glue on you egg, place the cutouts on top of the glue and paint another layer of glue over the entire egg. Roll it in the clear glitter and let it dry. Finally, pull some ribbon or string through a bead and glue over one hole in the egg to create a hanger. Glue another bead over the other hole, and you are finished!');
INSERT INTO badge_optional_requirements VALUES(2689,195,3,'Find out what the four “detergent foods” are and how they help fight plaque.');
INSERT INTO badge_optional_requirements VALUES(2690,195,4,'Name and identify five tools that are used by a dental hygienist/dentist.');
INSERT INTO badge_optional_requirements VALUES(2691,195,5,'Visit a dental office and interview to a dental hygienist or dentist.');
INSERT INTO badge_optional_requirements VALUES(2692,195,6,'Get an annual dental check-up and cleaning.');
INSERT INTO badge_optional_requirements VALUES(2693,195,7,'Research careers in the dental hygiene field, such as dentist, orthodontist, dental hygienist, oral and maxillofacial surgeon.');
INSERT INTO badge_optional_requirements VALUES(2694,195,8,'Run a dental experiment such as the affect of acid or soda on teeth.');
INSERT INTO badge_optional_requirements VALUES(2695,195,9,'Prepare dental care packages to donate to organizations such as your local homeless shelter, foster care agency, or other program.');
INSERT INTO badge_optional_requirements VALUES(2696,195,10,'Learn about protection for your teeth while playing sports and how to prevent injuries in the mouth.');
INSERT INTO badge_optional_requirements VALUES(2697,195,11,'Learn the types of teeth in your mouth (canines, incisors, premolars, molars, and wisdom teeth).');
INSERT INTO badge_optional_requirements VALUES(2698,195,12,'What types of products or food can stain your teeth? Name at least five. Examples include coffee, tobacco products, etc. Also learn about various ways you can whiten your teeth.');
INSERT INTO badge_optional_requirements VALUES(2699,197,3,'Write the following statements on a piece of paper and post it somewhere in your room where you can see it every morning. For two weeks, read through this list and do your best to follow it. The statements are: “I will finish my projects. I will do a job right. I will follow instructions. I will concentrate on my work. I will not be lazy.”');
INSERT INTO badge_optional_requirements VALUES(2700,197,4,'What does your faith tell you about diligence? Learn three verses from your book of worship regarding diligence. Examples from the Bible might include Deuteronomy 4:9, Joshua 22:5, or Proverbs 10:4.');
INSERT INTO badge_optional_requirements VALUES(2701,197,5,'Demonstrate diligence to God in the following ways: listening to His Word, keeping His commandments, and studying your book of worship.');
INSERT INTO badge_optional_requirements VALUES(2702,197,6,'Demonstrate diligence to your parents by: Rising early in the morning Taking the initiative in helping with chores before you’re asked Going beyond the assignments you are given Helping your brothers and sisters Honoring them and speaking well of them in front of others Do the jobs no one else wants to do');
INSERT INTO badge_optional_requirements VALUES(2703,197,7,'With your parents, complete a lesson on diligence.');
INSERT INTO badge_optional_requirements VALUES(2704,197,8,'Read or listen to a story where diligence plays a key role. Draw a picture of a specific scene from the story where a character showed diligence or write a short report about it.');
INSERT INTO badge_optional_requirements VALUES(2705,197,9,'Make a poster about what diligence means to you.');
INSERT INTO badge_optional_requirements VALUES(2706,197,10,'What dreams and goals do you have for your future? How can you be diligent in accomplishing those goals? What knowledge and skills will you need? What distractions do you see that might keep you from attaining your goal? Create a list of five goals you wish to accomplish. For each goal, list what you will need to be diligent in to accomplish that goal and what distractions or poor character traits (such as laziness) will keep you from them.');
INSERT INTO badge_optional_requirements VALUES(2707,197,11,'Identify a bad habit you have. For one week, be diligent not to do that bad habit. Examples include nail biting, leaving your clothes on the floor, watching too much television, etc.');
INSERT INTO badge_optional_requirements VALUES(2708,197,12,'A diligent job is a job well-done. Learn the correct way to fold pants, shirts and sheets, etc. Fold a weeks worth of laundry as professional as possible.');
INSERT INTO badge_optional_requirements VALUES(2709,199,3,'Find out some of the locations where dinosaur bones have been found. How close to where you live has a find been made? Mark at least six dinosaur finds on a map.');
INSERT INTO badge_optional_requirements VALUES(2710,199,4,'Earn the Paleontology badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2711,199,5,'Learn about the life cycle of a dinosaur.');
INSERT INTO badge_optional_requirements VALUES(2712,199,6,'Complete a craft or art project involving dinosaurs. Examples might include puppets, coloring sheets, decorating plastic eggs to look like dinosaur eggs, face painting, cake decorating, etc.');
INSERT INTO badge_optional_requirements VALUES(2713,199,7,'Create your own dinosaur presentation, book, movie, song, etc. about what you have learned.');
INSERT INTO badge_optional_requirements VALUES(2714,199,8,'Visit a dinosaur museum or exhibit.');
INSERT INTO badge_optional_requirements VALUES(2715,199,9,'Watch a dinosaur movie such as The Land Before Time or The Good Dinosaur for younger members, or Jurassic Park for older members. How realistic/unrealistic are these movies?');
INSERT INTO badge_optional_requirements VALUES(2716,199,10,'Watch a documentary about dinosaurs.');
INSERT INTO badge_optional_requirements VALUES(2717,199,11,'Read a non- fictional book about dinosaurs.');
INSERT INTO badge_optional_requirements VALUES(2718,199,12,'Read a fictional book about dinosaurs.');
INSERT INTO badge_optional_requirements VALUES(2719,199,13,'Learn about careers that involve dinosaurs. Examples might be a paleontologist, museum curator, exhibit designer, etc. What type of education would you need? Would you need to relocate? What type of salary might you receive?');
INSERT INTO badge_optional_requirements VALUES(2720,199,14,'Participate in a dig for fossils.');
INSERT INTO badge_optional_requirements VALUES(2721,199,15,'Play a game that involves dinosaurs. Instead of an Easter egg hunt, you might hold a dinosaur egg hunt, dig for dinosaur bones in a sandbox, pin the teeth on the T-Rex, or even a scavenger hunt through dinosaur books.');
INSERT INTO badge_optional_requirements VALUES(2722,200,4,'Make a sour cream based dip, such as French onion or ranch dip.');
INSERT INTO badge_optional_requirements VALUES(2723,200,5,'Make a dip that requires cooking, such as buffalo chicken dip.');
INSERT INTO badge_optional_requirements VALUES(2724,200,6,'Make a dip for fruit, such as strawberry yogurt dip.');
INSERT INTO badge_optional_requirements VALUES(2725,200,7,'Make a cream cheese based dip, such as raspberry cream cheese.');
INSERT INTO badge_optional_requirements VALUES(2726,200,8,'Make a dip using fresh vegetables, such as guacamole or salsa.');
INSERT INTO badge_optional_requirements VALUES(2727,200,9,'Make a dessert dip, such as s’mores dip.');
INSERT INTO badge_optional_requirements VALUES(2728,200,10,'Make a dip in a Crock Pot or Instant Pot, such as cheesy artichoke dip.');
INSERT INTO badge_optional_requirements VALUES(2729,200,11,'Make a meal of dips. Include at least 4 kinds/courses and make it a balanced meal.');
INSERT INTO badge_optional_requirements VALUES(2730,200,12,'What are alternatives to sour cream and cream cheese for those with lactose intolerance or dairy allergies? Make a dairy free dip. Compare it to the regular version and see what you like best.');
INSERT INTO badge_optional_requirements VALUES(2731,200,13,'Make dry dip mixes to sell at a fundraiser. Make sure to follow all local/state/federal laws.');
INSERT INTO badge_optional_requirements VALUES(2732,200,14,'Make dry dip mixes to give away as gifts.');
INSERT INTO badge_optional_requirements VALUES(2733,200,15,'Make dips to serve at a charity auction or church potluck.');
INSERT INTO badge_optional_requirements VALUES(2734,200,16,'Find creative ways to serve dip, such as in a bread bowl.');
INSERT INTO badge_optional_requirements VALUES(2735,200,17,'Look at the ingredients in a store bought dip and compare to one that is homemade. Which one is healthier?');
INSERT INTO badge_optional_requirements VALUES(2736,200,18,'Try a vegetable or fruit that you’ve never tried before with a dip that you have made.');
INSERT INTO badge_optional_requirements VALUES(2737,200,19,'Make a dip using fresh fruit, such as mango or pineapple.');
INSERT INTO badge_optional_requirements VALUES(2738,200,20,'Make a dip from beans, chickpeas (pulses/legumes), such as hummus.');
INSERT INTO badge_optional_requirements VALUES(2739,201,3,'Are there different variations of this disease/disorder? If so, what are they and how do they differ?');
INSERT INTO badge_optional_requirements VALUES(2740,201,4,'Does diet and nutrition have an effect on this disease/disorder? Why or why not? Are there any diets specifically geared toward this disease/disorder? What is the scientific basis for this diet?');
INSERT INTO badge_optional_requirements VALUES(2741,201,5,'If you have this disease/disorder, keep track of your diet and activities for two weeks. How did it affect how you felt?');
INSERT INTO badge_optional_requirements VALUES(2742,201,6,'Read a book or watch a movie about someone who suffered from this disease/disorder.');
INSERT INTO badge_optional_requirements VALUES(2743,201,7,'Spend some time with someone currently suffering from this disease/disorder and find out how it affects their day to day life.');
INSERT INTO badge_optional_requirements VALUES(2744,201,8,'Visit a doctor’s office, clinic, hospital, or other health facility that treats people with this disease/disorder.');
INSERT INTO badge_optional_requirements VALUES(2745,201,9,'Visit a local health fair.');
INSERT INTO badge_optional_requirements VALUES(2746,201,10,'Make an informational display about your disease/disorder and donate it to a health facility, library or other location to help educate others.');
INSERT INTO badge_optional_requirements VALUES(2747,201,11,'Create a children’s color or activity book that can help teach children afflicted with the disease/disorder about what is happening to their body.');
INSERT INTO badge_optional_requirements VALUES(2748,201,12,'Create a video public service announcement regarding this disease/disorder and post it on the Internet with a parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(2749,201,13,'Find out if there is a specific day dedicated to awareness of your disease/disorder. What groups promote this day and what do they do?');
INSERT INTO badge_optional_requirements VALUES(2750,201,14,'Research a career where you can help people with this specific disease/disorder. What type of education would you need? What would the job responsibilities be? What would the salary be like?');
INSERT INTO badge_optional_requirements VALUES(2751,201,15,'Study the history of your disease/disorder. What is the first recorded case of it? How have treatments for it changed over the years? Make a timeline with at least eight items.');
INSERT INTO badge_optional_requirements VALUES(2752,202,3,'Earn the Disneyland or California Adventure badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2753,202,4,'Find out about the role that Disney played in training films and propaganda during WWII. Watch at least one cartoon from those used. With the permission of a parent, you can visit Youtube and search for Disney WWII.');
INSERT INTO badge_optional_requirements VALUES(2754,202,5,'Save up your money to buy a new Disney doll or toy to give to someone who doesn’t have any or donate gently used Disney toys to your local shelter or thrift store.');
INSERT INTO badge_optional_requirements VALUES(2755,202,6,'Make your own Disney doll or toy either from scratch or from a kit.');
INSERT INTO badge_optional_requirements VALUES(2756,202,7,'Learn about the Disney theme parks. How many are there? What was the very first Disney park and what is the most recent? Find each park on a map and name one significant detail about each.');
INSERT INTO badge_optional_requirements VALUES(2757,202,8,'Who are the Disney Imagineers and what do they do? Name at least five famous Imagineers.');
INSERT INTO badge_optional_requirements VALUES(2758,202,9,'Listen to Radio Disney and find out what movies or shows featured at least five of the songs you hear.');
INSERT INTO badge_optional_requirements VALUES(2759,202,10,'Take a tour of a Disney facility, such as the Walt Disney Family Museum or the Pixar Studio.');
INSERT INTO badge_optional_requirements VALUES(2760,202,11,'Paint, draw, or photograph some friends and their favorite Disney movie or character. Frame the portraits and give them to your friends.');
INSERT INTO badge_optional_requirements VALUES(2761,202,12,'Find a song from Disney or a Disney movie. Learn to play it on your instrument of choice.');
INSERT INTO badge_optional_requirements VALUES(2762,202,13,'Throw a Disney themed party.');
INSERT INTO badge_optional_requirements VALUES(2763,202,14,'Research possible careers with Disney. This could include an animator, theme park worker, voice actor, cruise ship attendant, etc. Pick one and find out what kind of training you would need to be considered for that job. One Day at Disney may inspire jobs you may not have thought of.');
INSERT INTO badge_optional_requirements VALUES(2764,202,15,'Create a ABC brag book with a Disney theme');
INSERT INTO badge_optional_requirements VALUES(2765,202,16,'Pick any Disney movie and take an in-depth look at it. What year was it released and how did it do at the box office? Who were the voice actors? Who were the main animators? What legacy has it left since it was released?');
INSERT INTO badge_optional_requirements VALUES(2766,202,17,'Find out when Mickey Mouse was invented. How did Walt Disney come up with the idea for Mickey and how did Mickey change his life? What was Mickey’s original name going to be? Watch Steam Boat Willie.');
INSERT INTO badge_optional_requirements VALUES(2767,202,18,'Learn about the nature films that Disney has produced and watch at least one.');
INSERT INTO badge_optional_requirements VALUES(2768,202,19,'Learn about the history of the Mickey Mouse Club. Watch an episode if possible. What famous actors and actresses used to star on that show? Name several.');
INSERT INTO badge_optional_requirements VALUES(2769,202,20,'Play at least three Disney themed games.');
INSERT INTO badge_optional_requirements VALUES(2770,202,21,'Attend a Disney play, show or Disney on Ice.');
INSERT INTO badge_optional_requirements VALUES(2771,202,22,'Host a Disney story time for younger kids.');
INSERT INTO badge_optional_requirements VALUES(2772,202,23,'What is the Disney College Program and how could you get accepted into it?');
INSERT INTO badge_optional_requirements VALUES(2773,202,24,'Make a Disney themed snack or dessert, such as Mickey Mouse cupcakes. Or, replicate one of your favorite food products from a Disney theme park, such as the pineapple Dole Whip or churro.');
INSERT INTO badge_optional_requirements VALUES(2774,202,25,'What is “Disneybounding?” Find out and then figure out how to design three Disneybounds from your own wardrobe. If you would like, earn the Disneybounding badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2775,202,26,'Go to a store and make a list of every Disney item you can find. What characters seem to be featured the most? What sorts of products did you find with Disney images?');
INSERT INTO badge_optional_requirements VALUES(2776,202,27,'Disney owns many companies and brands, such as Marvel and ESPN. Learn about the many acquisitions of Disney. Did any of them surprise you? Which one was the newest?');
INSERT INTO badge_optional_requirements VALUES(2777,202,28,'Earn the Disney Princesses badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2778,203,3,'Learn who Leslie Kay is. Understand that she did not create Disneybounding, but she coined the term and popularized the concept.');
INSERT INTO badge_optional_requirements VALUES(2779,203,4,'Understand what a “Rulebreaker” is.');
INSERT INTO badge_optional_requirements VALUES(2780,203,5,'Learn what item of clothing/accessories is considered the “holy Grail” of Disneybounding. How many outfits can you use this item for?');
INSERT INTO badge_optional_requirements VALUES(2781,203,6,'With a parent’s permission, look on Pinterest or another internet site and gather images of Disneybounding outfits.');
INSERT INTO badge_optional_requirements VALUES(2782,203,7,'Create a Disneybounding inspiration scrapbook. Go through magazines and catalogs and cut out pictures of clothing to compile outfits. Or create a Pinterest board or other online scrapbook.');
INSERT INTO badge_optional_requirements VALUES(2783,203,8,'How important are accessories in Disneybounding?');
INSERT INTO badge_optional_requirements VALUES(2784,203,9,'Pick five accessories from your own wardrobe or looking in local shops to use in Disneybound outfits.');
INSERT INTO badge_optional_requirements VALUES(2785,203,10,'Choose five characters to bound as, and create outfits from items in your wardrobe.');
INSERT INTO badge_optional_requirements VALUES(2786,203,11,'Pick one item from your wardrobe and try to build as many bounding outfits around it as possible.');
INSERT INTO badge_optional_requirements VALUES(2787,203,12,'With a parent’s permission, join a group on Facebook such as Disneybounders United! and participate in a “Challenge”');
INSERT INTO badge_optional_requirements VALUES(2788,203,13,'Teach someone what Disneybounding is, and help them create their own Disneybounding outfit.');
INSERT INTO badge_optional_requirements VALUES(2789,203,14,'Create a buddy bound with someone.');
INSERT INTO badge_optional_requirements VALUES(2790,203,15,'Interview an experienced Bounder. Get their opinion on the importance of accessories, color, and style in a Disneybounding outfit. Find out if they invest a lot of money into this hobby, or only “wardrobe bound.”');
INSERT INTO badge_optional_requirements VALUES(2791,203,16,'Create a Rulebreaker outfit.');
INSERT INTO badge_optional_requirements VALUES(2792,203,17,'Balancing work and play can be difficult. Create a Bound that is “work appropriate.” How does it differ from an outfit you would wear to go shopping, visit Disneyland, or just generally hang out with family and friends?');
INSERT INTO badge_optional_requirements VALUES(2793,203,18,'Create bounding outfits for a single character that fit at least three different aspects of life, such as work, swimming, park visits, bedtime.');
INSERT INTO badge_optional_requirements VALUES(2794,203,19,'Can you think of a career that this hobby could lead to? Explore careers related to fashion and Disney.');
INSERT INTO badge_optional_requirements VALUES(2795,203,20,'Take your bound out. Go to the Disney Store or a Disney on Ice, Disney movie, or other Disney event in one of your new outfits.');
INSERT INTO badge_optional_requirements VALUES(2796,203,21,'Visit a Disney park in one of your Disneybounding outfits.');
INSERT INTO badge_optional_requirements VALUES(2797,205,3,'Attend World of Color. Review the experience and share it with your club or family.');
INSERT INTO badge_optional_requirements VALUES(2798,205,4,'Explore Cars Land. Ride Radiator Springs Racers, get a snack from the Cozy Cone Motel, or take a picture in front of the sign.');
INSERT INTO badge_optional_requirements VALUES(2799,205,5,'Buy at least three souvenirs and show them to your friends or other group. Why did you pick these particular souvenirs?');
INSERT INTO badge_optional_requirements VALUES(2800,205,6,'Attend a show at the Hyperion Theater.');
INSERT INTO badge_optional_requirements VALUES(2801,205,7,'Take a picture with at least ten different characters. Also, collect their autographs.');
INSERT INTO badge_optional_requirements VALUES(2802,205,8,'Interview one of the cast members about their experience working at California Adventure. Ask them how long they’ve been an employee, what their favorite ride is, etc. Include at least ten questions.');
INSERT INTO badge_optional_requirements VALUES(2803,205,9,'Have a character dining experience, such as the kind at Ariel’s Grotto. Take a picture with one of the characters you meet. If it is a face character, have a grief interview with them. For example, if you meet Ariel at Ariel’s Grotto, ask her what it’s like to live under the sea or how she enjoys being a human compared to being a mermaid. Have fun with it.');
INSERT INTO badge_optional_requirements VALUES(2804,205,10,'Trade pins with at least five different cast members.');
INSERT INTO badge_optional_requirements VALUES(2805,205,11,'Research a job at Disneyland. What sort of qualifications do you need? What are the different job options (Working on rides, in restaurants, as characters, etc)? What would the hours be like?');
INSERT INTO badge_optional_requirements VALUES(2806,205,12,'Design your own California Adventure ride. Draw a picture of it and what it would do. Would there be any narration? Would it be a dark ride, roller coaster, interactive ride, etc? What would the queue be like?');
INSERT INTO badge_optional_requirements VALUES(2807,205,13,'Some rides have really great queues, such as Tower of Terror or Toy Story Mania. Pay careful attention to one of these queues and note some of your favorite aspects. Snap photos of interesting details you notice. If possible, interview the ride attendant about what they love about the queue.');
INSERT INTO badge_optional_requirements VALUES(2808,205,14,'Take a tour of the parks.');
INSERT INTO badge_optional_requirements VALUES(2809,205,15,'Watch a parade all the way through.');
INSERT INTO badge_optional_requirements VALUES(2810,205,16,'Ride the Red Car Trolley in a full loop. Interview the conductor about what he loves about his job.');
INSERT INTO badge_optional_requirements VALUES(2811,205,17,'Attend the Disney Junior: Live on Stage show.');
INSERT INTO badge_optional_requirements VALUES(2812,205,18,'Do the Redwood Creek Challenge Trail. Make sure to complete the whole trail.');
INSERT INTO badge_optional_requirements VALUES(2813,205,19,'Draw one of your favorite characters at the Animation Academy. Share your drawing with your club or family.');
INSERT INTO badge_optional_requirements VALUES(2814,205,20,'Attend the Mad T Party.');
INSERT INTO badge_optional_requirements VALUES(2815,209,3,'Attend a show in the parks. Review the show and share your review with your family or club.');
INSERT INTO badge_optional_requirements VALUES(2816,209,4,'Watch a fireworks show. How does the music or narration tie in with the show?');
INSERT INTO badge_optional_requirements VALUES(2817,209,5,'Learn about the three Disneyland hotels. When were they built? What is the average cost to stay for a night at each hotel? Walk around the lobby of one of the hotels (the Grand Californian lobby is particularly gorgeous). What perks can guests expect if they stay at one of these hotels?');
INSERT INTO badge_optional_requirements VALUES(2818,209,6,'Learn about Disneyland safety rules and regulations. Why are they important and how does Disneyland reinforce these rules? Write them down and remember them when you visit the park.');
INSERT INTO badge_optional_requirements VALUES(2819,209,7,'Visit Downtown Disney. Explore the different shops and restaurants.');
INSERT INTO badge_optional_requirements VALUES(2820,209,8,'Buy at least three souvenirs and show them to your troop or family. Why did you pick these particular souvenirs?');
INSERT INTO badge_optional_requirements VALUES(2821,209,9,'Ride all of the original Disneyland rides that are still open. Compare them to the most recent rides. How are they different? Which type of ride do you prefer?');
INSERT INTO badge_optional_requirements VALUES(2822,209,10,'Take a picture with at least ten different characters. Also, collect their autographs.');
INSERT INTO badge_optional_requirements VALUES(2823,209,11,'Find and take a photo of at least twenty “Hidden Mickeys.” There are many resources online and in books that point out where you can find them.');
INSERT INTO badge_optional_requirements VALUES(2824,209,12,'Interview one of the cast members about their experience working at Disneyland. Ask them how long they’ve been an employee, what their favorite ride is, etc. Include at least ten questions.');
INSERT INTO badge_optional_requirements VALUES(2825,209,13,'Take a tour of the parks.');
INSERT INTO badge_optional_requirements VALUES(2826,209,14,'Have your silhouette drawn at the Silhouette Studio on Main Street.');
INSERT INTO badge_optional_requirements VALUES(2827,209,15,'Ride the Disneyland railroad or the Lilly Belle train. Make sure to ride it in a full loop around the park.');
INSERT INTO badge_optional_requirements VALUES(2828,209,16,'Earn the Disney badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2829,209,17,'Draw or paint a picture of your favorite ride. Include details and appropriate colors.');
INSERT INTO badge_optional_requirements VALUES(2830,209,18,'Dine at a Disneyland restaurant. Review the menu and rate your experience.');
INSERT INTO badge_optional_requirements VALUES(2831,209,19,'Attend Great Moments with Mr. Lincoln.');
INSERT INTO badge_optional_requirements VALUES(2832,209,20,'Trade pins with at least five different cast members.');
INSERT INTO badge_optional_requirements VALUES(2833,209,21,'Receive a makeover from the Bibbidi Bobbidi Boutique.');
INSERT INTO badge_optional_requirements VALUES(2834,209,22,'Research a job at Disneyland or attending the Disney College Program. What sort of qualifications do you need? What are the different job options? (Working on rides, in restaurants, as characters, etc). What would the hours be like?');
INSERT INTO badge_optional_requirements VALUES(2835,209,23,'Design your own Disneyland ride. Draw a picture of it and what it would do. Would there be any narration? Would it be a dark ride, roller coaster, interactive ride, etc? What would the queue be like?');
INSERT INTO badge_optional_requirements VALUES(2836,209,24,'Some rides have really great queues, such as Indiana Jones or Space Mountain. Pay careful attention to one of these queues and note some of your favorite aspects. Snap photos of interesting details or hidden Mickeys. If possible, interview the ride attendant about what they love about the queue.');
INSERT INTO badge_optional_requirements VALUES(2837,209,25,'Watch a parade all the way through.');
INSERT INTO badge_optional_requirements VALUES(2838,209,26,'Disneybound at Disneyland. If you desire, earn the Disneybounding badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2839,209,27,'Learn about the Disneylands around the world. Where are they? How do they differ from the first Disneyland in California? If you could visit one, which one would you go to? Why?');
INSERT INTO badge_optional_requirements VALUES(2840,210,3,'Create a craft that has to do with your movie. It could be a crown, a sea shell necklace, or something that has to do with your movie.');
INSERT INTO badge_optional_requirements VALUES(2841,210,4,'Learn how you can become a Disney princess at Disneyland or Disney World.');
INSERT INTO badge_optional_requirements VALUES(2842,210,5,'Watch at least 5 of the Disney princess movies.');
INSERT INTO badge_optional_requirements VALUES(2843,210,6,'Write a paper on who you think the next Disney Princess should be. Do you think they should be based on real person in history, a story, or something entirely new.');
INSERT INTO badge_optional_requirements VALUES(2844,210,7,'Make a list of all the Disney Princess merchandise you can find. Is there a product they haven’t come out with that you think they should?');
INSERT INTO badge_optional_requirements VALUES(2845,210,8,'Does your princess have a pet? If so, who is it and are they in the movie or not?');
INSERT INTO badge_optional_requirements VALUES(2846,210,9,'Draw or paint your princess.');
INSERT INTO badge_optional_requirements VALUES(2847,210,10,'Read a Disney Princess book.');
INSERT INTO badge_optional_requirements VALUES(2848,210,11,'Dress up as your princess.');
INSERT INTO badge_optional_requirements VALUES(2849,210,12,'Have a Disney princess themed party.');
INSERT INTO badge_optional_requirements VALUES(2850,210,13,'Buy a Disney princess toy and give it to a child who doesn’t have one.');
INSERT INTO badge_optional_requirements VALUES(2851,210,14,'Complete the Disney badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2852,210,15,'Get a photo with your favorite Disney princess.');
INSERT INTO badge_optional_requirements VALUES(2853,210,16,'Attend a Disney play or show.');
INSERT INTO badge_optional_requirements VALUES(2854,210,17,'Learn about the Disney Princess merchandise lines. What is so important about the limited edition or special edition dolls, tea sets, ornaments, or more? Where are these items sold? Pick an item and learn how much it went for originally, and how much it might be worth now.');
INSERT INTO badge_optional_requirements VALUES(2855,210,18,'Learn how Disney Princesses have been portrayed in other forms of media. What movies, television shows, and video games do they appear in?');
INSERT INTO badge_optional_requirements VALUES(2856,210,19,'Learn about the Disney Princesses roles in the Disney theme parks. Which Disney Princesses have their own rides, castles, events, and more?');
INSERT INTO badge_optional_requirements VALUES(2857,210,20,'Design your own amusement park ride, shop, restaurant, or event (theater show, ice skating show, fireworks show, parade, etc) based off of a Disney Princess.');
INSERT INTO badge_optional_requirements VALUES(2858,212,3,'Learn how many different people have acted the part of Doctor Who over the course of the show’s history. Read a biography of one of these people. (If you earn this badge at a different level, you must read about a different person. An online biography is acceptable.) Understand how Doctor Who regenerates, allowing different actors to take over the part and for the show to continue over a long period of time.');
INSERT INTO badge_optional_requirements VALUES(2859,212,4,'Learn about the theory of time travel and explain what a paradox is. Design your own time machine, both inside and out, and name it.');
INSERT INTO badge_optional_requirements VALUES(2860,212,5,'Learn about space travel. What type of space travel are humans currently capable of? How does this differ from what science fiction has created over the years? Discuss whether or not you think there are intelligent beings in our universe on planets other than earth. Know the planets in our own solar system.');
INSERT INTO badge_optional_requirements VALUES(2861,212,6,'Learn about the companions of Doctor Who. Which Doctor would you want to be a companion to and why? If you were traveling through time and space, what type of companion would you want? Draw and describe your ideal companion.');
INSERT INTO badge_optional_requirements VALUES(2862,212,7,'Find out how K-9 became a companion of Doctor Who and how many models there were during the run of the series.');
INSERT INTO badge_optional_requirements VALUES(2863,212,8,'Try the following 3 foods associated with Doctor Who and be able to identify why they are important to the show. Fish Finger Custard Biscuits Tea');
INSERT INTO badge_optional_requirements VALUES(2864,212,9,'Explain what a Dalek is and why they are dangerous. Be able to recognize one. Be able to name and recognize at least three other beings from the TV show.');
INSERT INTO badge_optional_requirements VALUES(2865,212,10,'Create a Doctor Who craft of some sort.');
INSERT INTO badge_optional_requirements VALUES(2866,212,11,'Write your own episode of Doctor Who.');
INSERT INTO badge_optional_requirements VALUES(2867,212,12,'Explain what at least 3 of the following organizations or groups are: Blue Peter CIA Cybus Industries FBI LINDA Ood Operations Shadow Proclamation The Silver Cloak The Sisters of Plenitude Sybilline Sisterhood The Time Agency Torchwood Institute UNIT');
INSERT INTO badge_optional_requirements VALUES(2868,212,13,'Explain what a sonic screwdriver is and be able to recognize at least three of them from different regenerations. Design your own sonic screwdriver.');
INSERT INTO badge_optional_requirements VALUES(2869,212,14,'Learn about at least 5 of the following items: Deadlock Seal Osterhagen Key Perception Filter Psychic Paper Stormcage Containment Facility Cloister Bell Fast Return Switch Harmonic Filter Roundels Time Rotor Time Vector Generator Anti-Plastic ATMOS Chameleon Arch Eye Drive The Genesis Ark Genetic Manipulation Device Gravity Bubble Hallucinogenic Lipstick Handbot Home Box Immortality Gate Infostamp Key to Time Nanogenese Paradox Machine Reality Bomb Stattenheim Remote Control Teselecta Vortex Manipulator');
INSERT INTO badge_optional_requirements VALUES(2870,212,15,'Much of Doctor Who is based on current scientific knowledge. Be able to explain at least 3 of the following scientific concepts and how they are currently used today. Cyrogenics Cloning Cybernetics Antimatter DNA Robots Satellites');
INSERT INTO badge_optional_requirements VALUES(2871,212,16,'Be able to explain at least 3 of the following time and relativity concepts used in Doctor Who: Blinovitch Limitation Effect Dimensionally Transcendental Temporal Rift Time Energy Time Vortex Time Winds The Untempered Schism');
INSERT INTO badge_optional_requirements VALUES(2872,212,17,'As the Doctor travels through time, he meets some real people from our history. Watch at least three episodes of Doctor Who with real people from history in them and then learn about those people. Examples might include: Cleopatra Agatha Christie Winston Churchill Charles Dickens Vincent van Gogh William Shakespeare Queen Victoria');
INSERT INTO badge_optional_requirements VALUES(2873,212,18,'Learn about at least three locations from Doctor Who such as: Apalapucia Cardiff Barcelona (the planet) The Chess Pits of Vegas 12 The Delirium Archive Demon’s Run The Fields of Trenzalore Gallifrey Krop Tor Lake Silencio Leadworth The Library The Medusa Cascade Messaline Midnight New Earth The Ood-sphere Pompeii Raxacoricofallapatrorius San Helios Sardicktown Shan Shen Skaro Totters Lane');
INSERT INTO badge_optional_requirements VALUES(2874,213,3,'Learn about the history of dog breeding. Choose three dogs and find out what they were specifically bred to do. What health issues has certain breeding produced?');
INSERT INTO badge_optional_requirements VALUES(2875,213,4,'Know what type of food a dog needs. How much should a dog be fed every day, and how often? Explore the benefits of hard and wet food.');
INSERT INTO badge_optional_requirements VALUES(2876,213,5,'Understand how a dog should be housed. How can you keep it safe from predators? How is it kept warm in the winter and cool in the summer?');
INSERT INTO badge_optional_requirements VALUES(2877,213,6,'Visit someone who raises dogs and learn about how they care for them.');
INSERT INTO badge_optional_requirements VALUES(2878,213,7,'Visit your state or county dog shelter; see how dogs come to be there, and volunteer if possible.');
INSERT INTO badge_optional_requirements VALUES(2879,213,8,'Attend a dog show or watch one on television.');
INSERT INTO badge_optional_requirements VALUES(2880,213,9,'Know the difference between the following dog types: Hound Terrier Shepherd Toy Mix');
INSERT INTO badge_optional_requirements VALUES(2881,213,10,'Participate in a service project that deals with dogs, such as volunteering at the animal shelter or walking dogs.');
INSERT INTO badge_optional_requirements VALUES(2882,213,11,'Build a dog feeder, carrying case, dog bed, or other equipment for your dog.');
INSERT INTO badge_optional_requirements VALUES(2883,213,12,'Conduct a demonstration about dogs, or create a small booklet, to share with a group of younger children.');
INSERT INTO badge_optional_requirements VALUES(2884,213,13,'Understand dog breeding. Know how to prepare a nest for a female and when to provide her with it. What is a typical litter size? How long does a dog usually live? Explain the difference between inbreeding, line breeding, and cross breeding.');
INSERT INTO badge_optional_requirements VALUES(2885,213,14,'Learn about careers that involve dogs.');
INSERT INTO badge_optional_requirements VALUES(2886,213,15,'Learn how to register a dog with the American Kennel Club.');
INSERT INTO badge_optional_requirements VALUES(2887,213,16,'Create a craft project or piece of art that involves dogs.');
INSERT INTO badge_optional_requirements VALUES(2888,213,17,'Learn a song or poem about dogs.');
INSERT INTO badge_optional_requirements VALUES(2889,213,18,'Participate in a dog parade.');
INSERT INTO badge_optional_requirements VALUES(2890,213,19,'Earn the Dog Training badge.');
INSERT INTO badge_optional_requirements VALUES(2891,213,20,'Watch a documentary about dogs.');
INSERT INTO badge_optional_requirements VALUES(2892,214,3,'Watch a documentary, online video, or movie on dog training.');
INSERT INTO badge_optional_requirements VALUES(2893,214,4,'Learn about body blocking – what it is, how to do it, when to do it and why.');
INSERT INTO badge_optional_requirements VALUES(2894,214,5,'Research and practice long leashes and short leashes. What type of training should you use it for? Is it effective?');
INSERT INTO badge_optional_requirements VALUES(2895,214,6,'Attend a dog training class with your dog.');
INSERT INTO badge_optional_requirements VALUES(2896,214,7,'Learn about dog crates – how to use them, when and why.');
INSERT INTO badge_optional_requirements VALUES(2897,214,8,'How do the police, FBI, search-and-rescue, or other first responders train their dogs? Do some research on their methods and what type of training a dog has to go through. Visit your local police station and interview one of the officers who works closely with a dog.');
INSERT INTO badge_optional_requirements VALUES(2898,214,9,'Learn about dog training methods in other cultures. How do they differ from American methods? Which methods do you think would be more effective? Pick one culture and try to teach your dog a command or trick that that culture uses.');
INSERT INTO badge_optional_requirements VALUES(2899,214,10,'How can you use hand signals when training your dog? Look up different hand signals and gestures that are effective and what commands you can use them with. Research at least five.');
INSERT INTO badge_optional_requirements VALUES(2900,214,11,'Luring – what is it and how do you use it in training? Teach it to your dog.');
INSERT INTO badge_optional_requirements VALUES(2901,214,12,'Anthropomorphize – What is it? Give some examples of when you or someone else should do it.');
INSERT INTO badge_optional_requirements VALUES(2902,214,13,'Participate in a community service project that involves dog training.');
INSERT INTO badge_optional_requirements VALUES(2903,214,14,'Research careers as a professional dog trainer. What type of education would you need? What types of facilities could you work at? What is the average salary?');
INSERT INTO badge_optional_requirements VALUES(2904,214,15,'Are different breeds of dogs more easily trained then others? Is there a difference between small dogs and larger dogs? Make a list of the top five most “trainable” dog breeds.');
INSERT INTO badge_optional_requirements VALUES(2905,214,16,'Learn about training a dog for protection. Some families will adopt and train a dog for the sole purpose of guarding or protecting their home or children. Research this and make a list of some of the top dogs used for this purpose.');
INSERT INTO badge_optional_requirements VALUES(2906,215,3,'With a parent’s permission, do a major doll cleaning. You can do this for a nursery at a church, a preschool, a friend who is ill, or at your own home. This should include washing all the doll clothes that are dirty, washing off the faces & bodies of any dirty dolls, donating some dolls if you have too many, sorting all doll accessories, and neatly arranging your clean dolls.');
INSERT INTO badge_optional_requirements VALUES(2907,215,4,'Watch a movie or read a well-illustrated book about how dolls are made. You can also tour a doll factory.');
INSERT INTO badge_optional_requirements VALUES(2908,215,5,'Find a song or poem about dolls and memorize it.');
INSERT INTO badge_optional_requirements VALUES(2909,215,6,'Read a book or watch a movie wherein a doll has a central role.');
INSERT INTO badge_optional_requirements VALUES(2910,215,7,'Paint, draw, or photograph some friends and their dolls. Frame the portraits and give them to your friends.');
INSERT INTO badge_optional_requirements VALUES(2911,215,8,'Organize a doll and stuffed animal drive for a shelter that needs them. Keep collecting until you have a minimum of twenty to donate.');
INSERT INTO badge_optional_requirements VALUES(2912,215,9,'Host some kind of doll extravaganza other than a tea party. Party ideas include favors for people to take home, taking several photos of each guest, or making a scrapbook page for each attendee. You will need to provide real food for your friends. Your party could be a class on how to make doll food or doll clothes. Or you could invite an adult friend to share her collection with your friends as part of the occasion.');
INSERT INTO badge_optional_requirements VALUES(2913,215,10,'Collect at least five different books, movies, songs, or poems about dolls. Critique them and share your insights with your club. Include any thoughts you have about how they could have been better.');
INSERT INTO badge_optional_requirements VALUES(2914,215,11,'Write, perform/film, or help perform/film a story about a child and a doll.');
INSERT INTO badge_optional_requirements VALUES(2915,215,12,'Find a less-fortunate young child, a shelter, a hospital, etc. that has dolls but very little or no extra clothes, accessories, doll furniture, etc. Make or adapt at least five items to give her/them.');
INSERT INTO badge_optional_requirements VALUES(2916,215,13,'Shadow for at least four hours a person who runs a doll hospital or makes fancy dolls or doll paraphernalia. You need to observe more than one task being done.');
INSERT INTO badge_optional_requirements VALUES(2917,215,14,'Research the amount of money that could be made from selling someone’s doll collection of at least twenty dolls. This needs to be an actual collection, but it does not matter whether the owner is actually planning to sell or not.');
INSERT INTO badge_optional_requirements VALUES(2918,215,15,'Learn to make Quest Clubs vest or other clothing item for dolls.');
INSERT INTO badge_optional_requirements VALUES(2919,215,16,'Allow a younger child to play with your doll collection on at least two occasions. This could be done as part of a babysitting job or as a reward for the child. Be sure to clean everything up afterwards.');
INSERT INTO badge_optional_requirements VALUES(2920,216,4,'When is National Donut Day? Learn about the history of this day and when it was first celebrated.');
INSERT INTO badge_optional_requirements VALUES(2921,216,5,'Take a tour of a donut bakery.');
INSERT INTO badge_optional_requirements VALUES(2922,216,6,'What is the difference between a cake donut and a jelly donut? Try one of each. Which one do you like best?');
INSERT INTO badge_optional_requirements VALUES(2923,216,7,'Learn about donuts in other countries. Compare donuts from three other countries. How do they differ? How are they similar to donuts found in the U.S.?');
INSERT INTO badge_optional_requirements VALUES(2924,216,8,'What world records have been set involving donuts? Research a few and tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(2925,216,9,'Participate in a community service project involving donuts, such as a fundraiser or bake sale.');
INSERT INTO badge_optional_requirements VALUES(2926,216,10,'Take donuts to someone in need (such as at a hospital or nursing home) or deliver donuts to your local fire station or police department.');
INSERT INTO badge_optional_requirements VALUES(2927,216,11,'What are some careers that involve donuts? Research what type of education you would need and where you could expect to work.');
INSERT INTO badge_optional_requirements VALUES(2928,216,12,'What is the nutritional value of donuts? What would happen to a person if they ate a donut every day? Are there any “healthy” donuts or donut alternatives?');
INSERT INTO badge_optional_requirements VALUES(2929,216,13,'What is the difference between a donut and a spudnut?');
INSERT INTO badge_optional_requirements VALUES(2930,216,14,'Visit a donut shop and sample at least three different types of donuts.');
INSERT INTO badge_optional_requirements VALUES(2931,216,15,'Choose a national donut chain, such as Dunkin’ Donuts or Krispy Kreme, and learn about their history and how their donuts have changed over the years. Visit one of these locations and try a donut.');
INSERT INTO badge_optional_requirements VALUES(2932,218,3,'Make a Mask – Masks have been used for centuries as part of dramas and ceremonies. Make a mask in the style of your choice. Sometimes they are used to create a character such as an animal, other times they are used to conceal someone’s identity such as for a masquerade. Before creating your mask, decide its purpose and be able to explain why you created the mask you did.');
INSERT INTO badge_optional_requirements VALUES(2933,218,4,'Makeup – Use makeup to create a mask or personality.');
INSERT INTO badge_optional_requirements VALUES(2934,218,5,'Attend a play or theatrical performance.');
INSERT INTO badge_optional_requirements VALUES(2935,218,6,'How is drama presented on television? Is drama used in cartoons? Puppets? How can you tell the difference between what is real and pretend?');
INSERT INTO badge_optional_requirements VALUES(2936,218,7,'Mirror Mimic – Acting is all about becoming someone you are not. Find a partner and take turns being their mirror image. Face each other, and whatever they do, you do. Try out different emotions, different ways of walking, etc.');
INSERT INTO badge_optional_requirements VALUES(2937,218,8,'Warm up exercises: Try each of the following exercises to warm up your voice. Why is warming up your voice important? Which parts of your body are involved when you speak? Try these exercises: Breathe deeply through your nose and expand your stomach out as far as you can. Slowly exhale through your mouth, contracting your stomach as you go (If you stick your chest out and suck your stomach in while taking a breath, as most people do, the bottom of your lungs cannot fully expand and you actually hold in less air.). Do the above exercise again, but this time say “Ahhhhhhh” as you exhale. See how long you can hold that sound. Try the same exercise one more time, this time see how loudly you can hold the “Ahhhhh.” Try saying several tongue twisters as quickly as you can. “Red leather, yellow leather”');
INSERT INTO badge_optional_requirements VALUES(2938,218,9,'Mime – Mime is a form of drama where no sound is used at all. Using mime, act out at least three of the following activities. Making your bed. Feeding the dog. Pick up an imaginary object and see if someone can guess what it is. What shape is it? How heavy is it? What does it smell like? What does it feel like? Toasting a marshmallow over a campfire on a cold night.');
INSERT INTO badge_optional_requirements VALUES(2939,218,10,'What is reader’s theater? How does it differ from traditional theater? Pick a story and perform it as a reader’s theater production.');
INSERT INTO badge_optional_requirements VALUES(2940,218,11,'Pretend to have a conversation with someone on the phone. How convincing can you be?');
INSERT INTO badge_optional_requirements VALUES(2941,218,12,'Learn about different types of stages. What is a proscenium arch, a round stage, and a thrust stage? What are the pros and cons of working with each type? What type of performance is each stage type designed for?');
INSERT INTO badge_optional_requirements VALUES(2942,218,13,'Produce a play with your club or family. You should take one of the following positions: Director Producer Stage Designer Costume Designer Makeup Artist. Research each job and volunteer for the one that interests you most.');
INSERT INTO badge_optional_requirements VALUES(2943,218,14,'To put on a good theatrical performance, more than just good actors and actresses are needed. Research the following jobs and be able to explain each of their responsibilities: Stage Director Music Director Lighting Director Set Designer Costume Designer Prop Assistant Makeup Artist Theater Critic If possible, shadow a person in the theater industry for day and see first hand what their responsibilities are.');
INSERT INTO badge_optional_requirements VALUES(2944,218,15,'Costume Design – Design and create a costume for a play or puppet show you will perform.');
INSERT INTO badge_optional_requirements VALUES(2945,218,16,'Monologue – Select a monologue from a favorite play and perform it for an audience without any costume or makeup. Can your audience “see” who you are simply by following you body language and the expressions in your voice.');
INSERT INTO badge_optional_requirements VALUES(2946,218,17,'Volunteer to record books on tape for use through the library, Guild for the Blind, or other organization. Record a minimum of at least 5 children’s books, 3 young reader chapter books, or one adult book. Remember to read with prosody (emotion).');
INSERT INTO badge_optional_requirements VALUES(2947,218,18,'Arrange to perform a reader’s theater piece at your local library or book store.');
INSERT INTO badge_optional_requirements VALUES(2948,218,19,'Perform a puppet show for a group. Puppets can be homemade or store bought, simple finger puppets, marionettes, or even shadow puppets. Don’t forget your stage sets and lighting if needed. You can write your own play, or perform your favorite story or fairy tale. If you have pre-recorded stories, you can use these as the voices and make the puppets act out the story.');
INSERT INTO badge_optional_requirements VALUES(2949,218,20,'Sound Effects – Find a short story (science fiction or thrillers work best) that needs several sound effects.  Figure out what props could be used to make the necessary sounds and then record your story.  Play it for your family or troop.  Your story should have a minimum of 10 sound effects (things such as creaky doors, footsteps, honking horns, rain, etc.).');
INSERT INTO badge_optional_requirements VALUES(2950,218,21,'Create a set design for a play. Learn what symbols are used to identify set pieces and lighting areas and your stage map. If possible, show the design to a play director and get their feedback.');
INSERT INTO badge_optional_requirements VALUES(2951,219,3,'Draw a cartoon person or animal.');
INSERT INTO badge_optional_requirements VALUES(2952,219,4,'Learn about different types of erasers. Test each one. Knead-able erasers White plastic eraser Art Gum erasers');
INSERT INTO badge_optional_requirements VALUES(2953,219,5,'Visit a museum, studio or art gallery to see drawings or view some online with permission from your parents. Which do you like? How do drawing styles differ?');
INSERT INTO badge_optional_requirements VALUES(2954,219,6,'Draw a portrait of yourself.');
INSERT INTO badge_optional_requirements VALUES(2955,219,7,'Take a drawing class.');
INSERT INTO badge_optional_requirements VALUES(2956,219,8,'Learn the difference between line drawing and value drawing. Draw something using each method.');
INSERT INTO badge_optional_requirements VALUES(2957,219,9,'Learn to draw something in a new style.');
INSERT INTO badge_optional_requirements VALUES(2958,219,10,'Look at 3 different optical illusions. Try to create one of your own.');
INSERT INTO badge_optional_requirements VALUES(2959,219,11,'Explain what squirkling is. Draw something using this shading method.');
INSERT INTO badge_optional_requirements VALUES(2960,219,12,'Read about two artists famous for drawing, one from the past and one considered a “modern” artist. What is the difference between their drawing styles?');
INSERT INTO badge_optional_requirements VALUES(2961,219,13,'What careers are there where drawing is a main component? Choose one of these jobs and find out what kind of education or experience you might need to get hired, what you could expect to be paid, and the hours you might be expected to work.');
INSERT INTO badge_optional_requirements VALUES(2962,219,14,'Participate in a community service project involving drawing, such as drawing pictures to send to soldiers overseas.');
INSERT INTO badge_optional_requirements VALUES(2963,219,15,'Try digital drawing. What did you think? Why do some people prefer digital over traditional media?');
INSERT INTO badge_optional_requirements VALUES(2964,220,3,'Find things to add to your drinks as garnishes whose look and flavor enhances the drink.  Examples might include putting peppermint sticks in cocoa, a cherry in a soda, etc. Come up with at least 10 garnish/drink combinations and try at least one.');
INSERT INTO badge_optional_requirements VALUES(2965,220,4,'Make at least one of each type of smoothie with the same flavor profile (such as strawberry): Juice smoothie Yogurt smoothie Ice Cream smoothie/milkshake How do they compare? What are the taste and textural differences?');
INSERT INTO badge_optional_requirements VALUES(2966,220,5,'Blend juices or sodas into three of your own unique flavor combinations. Use a minimum of three different flavors in each of your drinks. An example might include mixing lemonade with 7-Up.');
INSERT INTO badge_optional_requirements VALUES(2967,220,6,'Compare machines that make or blend drinks. For example, if you are interested in smoothies, compare different blenders. What are the differences between inexpensive kitchen models and expensive professional models? Or you could choose coffee makers and look at the differences in traditional machines, Keurig style one cup machines, industrial machines, etc. What are the pros and cons of each?');
INSERT INTO badge_optional_requirements VALUES(2968,220,7,'Participate in a community service project that revolves around drinks. Examples might include having a lemonade stand to raise money for charity, or hosting a smoothie social for local kids or families.');
INSERT INTO badge_optional_requirements VALUES(2969,220,8,'Ice is used in a variety of drinks to keep them cold. Use ice in at least three different ways in a drink (basic ice cubes do not count). You might make snow-cones, slushies, flavored ice cubes, juice ice cubes, cubes with fruit in them, shaped or colored cubes, etc.  You can also use ice cubes made of the same drink as you are drinking to prevent the drink from getting diluted such as making apple juice ice cubes to put in your apple juice.');
INSERT INTO badge_optional_requirements VALUES(2970,220,9,'Research cups that keep drinks hot or cold. What are they made of? What sizes do they come in? Which are best for the environment? Which are the cheapest?');
INSERT INTO badge_optional_requirements VALUES(2971,220,10,'Research unique drink concoctions such as the Horton Drink: lemon lime soda, a scoop of ice, pre-made gelatin cubes in your favorite flavor, and a straw and long spoon for stirring and scooping out the gels. Find at least three unique concoctions and try one or make up one of your own.');
INSERT INTO badge_optional_requirements VALUES(2972,220,11,'Visit an ethnic grocery store and look through the types of drinks they offer. Try at least one.');
INSERT INTO badge_optional_requirements VALUES(2973,220,12,'Learn about different careers that have to do with drinks. Examples might include baristas, fruit tree farmers, taste testers, etc. What type of education might you need for one of these jobs?  What type of pay could you expect? Where might you need to live?');
INSERT INTO badge_optional_requirements VALUES(2974,220,13,'Take a field trip to a specialty drink shop such as Starbucks or Jamba Juice. Interview one of the workers about their job and find out more about the company.');
INSERT INTO badge_optional_requirements VALUES(2975,220,14,'Use a drink in a recipe such as Sunkist orange soda cake or a Diet soda cake.');
INSERT INTO badge_optional_requirements VALUES(2976,221,3,'Pump and pay for your own gasoline.');
INSERT INTO badge_optional_requirements VALUES(2977,221,4,'Make the appointment and take your car in for a repair or maintenance job. Or, learn to fix it yourself.');
INSERT INTO badge_optional_requirements VALUES(2978,221,5,'Go comparison shopping for a new vehicle. Visit at least three dealerships and one website.');
INSERT INTO badge_optional_requirements VALUES(2979,221,6,'Do the driving for a trip that is at least 75 miles long.');
INSERT INTO badge_optional_requirements VALUES(2980,221,7,'Plan a trip with maps and then use GPS while on the trip. Were there many differences between the two routes?');
INSERT INTO badge_optional_requirements VALUES(2981,221,8,'Take a trip where you spend at least one night on the road. Be responsible for making sure that everyone’s luggage gets in the car both at home and after your overnight stay.');
INSERT INTO badge_optional_requirements VALUES(2982,221,9,'Take a trip that includes paying a toll or checking in at a gated community.');
INSERT INTO badge_optional_requirements VALUES(2983,221,10,'Go through five different drive-thru’s, such as fast food, pharmacy, postal service, etc.');
INSERT INTO badge_optional_requirements VALUES(2984,221,11,'Change a tire mostly by yourself.');
INSERT INTO badge_optional_requirements VALUES(2985,221,12,'Compare three different car or driver’s insurance plans.');
INSERT INTO badge_optional_requirements VALUES(2986,221,13,'Interview a tow truck driver and ask him what are the top five things he wishes people would do differently.');
INSERT INTO badge_optional_requirements VALUES(2987,221,14,'Drive at least two miles in each of three different types of cars (vans, compact, pickups, etc.).');
INSERT INTO badge_optional_requirements VALUES(2988,221,15,'Research different driving careers, such as a bus driver, truck driver, tow truck driver, etc.');
INSERT INTO badge_optional_requirements VALUES(2989,221,16,'Drivers are responsible for keeping their vehicles in good condition. Earn the Automotive Maintenance badge at your level.');
INSERT INTO badge_optional_requirements VALUES(2990,221,17,'Take your car for its annual inspection and pay the fee yourself.');
INSERT INTO badge_optional_requirements VALUES(2991,221,18,'Pass your State driving test.');
INSERT INTO badge_optional_requirements VALUES(2992,221,19,'Learn to drive a manual transmission vehicle.');
INSERT INTO badge_optional_requirements VALUES(2993,221,20,'Obtain and familiarize yourself with the latest edition of the local driver’s handbook to understand traffic laws.');
INSERT INTO badge_optional_requirements VALUES(2994,221,21,'Develop proficiency in parallel parking, perpendicular parking, and angle parking.');
INSERT INTO badge_optional_requirements VALUES(2995,221,22,'Develop control over the vehicle by practicing turns, lane changes, and U-turns in a safe and controlled environment.');
INSERT INTO badge_optional_requirements VALUES(2996,221,23,'Research and adhere to local parking regulations, including time limits and restricted zones.');
INSERT INTO badge_optional_requirements VALUES(2997,221,24,'Practice navigating different types of intersections, including controlled and uncontrolled intersections as well as roundabouts.');
INSERT INTO badge_optional_requirements VALUES(2998,221,25,'Understand and minimize blind spots by adjusting mirrors and performing shoulder checks.');
INSERT INTO badge_optional_requirements VALUES(2999,221,26,'Learn and follow pedestrian right-of-way rules and practice yielding to pedestrians.');
INSERT INTO badge_optional_requirements VALUES(3000,221,27,'Learn what to do in case of a breakdown, accident, or other emergencies.');
INSERT INTO badge_optional_requirements VALUES(3001,221,28,'Practice parking on hills and driving on steep inclines and declines.');
INSERT INTO badge_optional_requirements VALUES(3002,222,3,'Create a diagram of the main parts of a drone, including its frame, propellers, motors, battery, and camera.');
INSERT INTO badge_optional_requirements VALUES(3003,222,4,'Research the basic laws and regulations surrounding drone use in the United States, including where and how drones can be flown.  Find out about “no-fly zones” and why certain areas are restricted for drone flights.');
INSERT INTO badge_optional_requirements VALUES(3004,222,5,'Learn to fly a drone. Ensure that you follow all safety rules and local laws regarding where you are allowed to fly. Practice flying a drone in a controlled environment, learning basic maneuvers like takeoff, hovering, and landing.');
INSERT INTO badge_optional_requirements VALUES(3005,222,6,'Watch a drone race or event in person, on TV, or on the Internet with your parent’s permission.  Find out about drone competitions.  What types can you find?');
INSERT INTO badge_optional_requirements VALUES(3006,222,7,'Watch a drone light show in person, on TV or on the Internet with your parent’s permission.  Learn how they a drone light show is made.');
INSERT INTO badge_optional_requirements VALUES(3007,222,7,'Dream up 3 different ways you think drones could be used in the future to make life better for people.  Draw a picture of how one of these drones would do its job.');
INSERT INTO badge_optional_requirements VALUES(3008,222,8,'Research how drones assist in search and rescue operations and learn about two real-life examples.');
INSERT INTO badge_optional_requirements VALUES(3009,222,9,'Learn about the use of drones in filmmaking and list at least three popular films or documentaries where drones were used for filming.');
INSERT INTO badge_optional_requirements VALUES(3010,222,10,'Find out how drones are used in environmental monitoring (e.g., wildlife tracking, anti-poaching, pollution measurement).');
INSERT INTO badge_optional_requirements VALUES(3011,222,11,'Research how drones are used in disaster management (e.g., delivering supplies, assessing damage) and describe two cases where they have been crucial.');
INSERT INTO badge_optional_requirements VALUES(3012,222,12,'Discover how drones are involved in urban planning and smart cities (e.g., mapping, traffic monitoring) and summarize the advantages they bring.');
INSERT INTO badge_optional_requirements VALUES(3013,222,13,'Investigate the role of drones in law enforcement (e.g., crowd surveillance, crime scene investigation) and the ethical considerations involved.');
INSERT INTO badge_optional_requirements VALUES(3014,222,14,'Study how drones are employed in infrastructure inspection (e.g., bridges, power lines, wind turbines) and explain the benefits over traditional methods.');
INSERT INTO badge_optional_requirements VALUES(3015,222,15,'Investigate how drones are used in agriculture and describe at least three specific applications (e.g., crop monitoring, spraying, soil analysis).');
INSERT INTO badge_optional_requirements VALUES(3016,222,16,'Explain the different types of remote control systems used for drone operation, including radio frequency (RF) and digital transmission.  Examine the pros and cons of each.');
INSERT INTO badge_optional_requirements VALUES(3017,222,17,'Understand the various power systems used in drones, including battery types, voltage, capacity, and flight time considerations.');
INSERT INTO badge_optional_requirements VALUES(3018,222,18,'Learn about the importance of cameras and gimbals in drone applications, including aerial photography, videography, and inspection tasks.');
INSERT INTO badge_optional_requirements VALUES(3019,222,19,'Explain the principles of aerodynamics and how they apply to drone flight, including lift, drag, thrust, and weight.');
INSERT INTO badge_optional_requirements VALUES(3020,222,20,'Understand the importance of privacy when using drones and discuss the ethical implications of drone surveillance.');
INSERT INTO badge_optional_requirements VALUES(3021,222,21,'Learn about the process of obtaining a commercial drone license and the requirements for certification.');
INSERT INTO badge_optional_requirements VALUES(3022,222,22,'Build or assemble a simple drone from a kit and learn about the different parts while doing so.');
INSERT INTO badge_optional_requirements VALUES(3023,222,23,'Make a short video using a drone and edit it to showcase a particular feature or landscape.');
INSERT INTO badge_optional_requirements VALUES(3024,222,24,'Create a list of the different types of drone cameras and their uses, such as thermal cameras, high-definition cameras, and multi-spectral cameras.');
INSERT INTO badge_optional_requirements VALUES(3025,222,25,'Investigate career opportunities in the drone industry, including things like piloting, aerial surveying, cinematography, and drone software development.  What certifications and education do you need?  What type of pay can you expect?');
INSERT INTO badge_optional_requirements VALUES(3026,225,3,'Duct tape now comes in a variety of colors and prints. Look at different styles at the store or online (with a parent’s permission) and pick your favorite. Find out which companies produce duct tape in patterns.');
INSERT INTO badge_optional_requirements VALUES(3027,225,4,'Several other types of tape now come in colors and patterns as well. Find sources for patterned packing and masking tapes. Which are your favorites? What makes these tapes different than duct tape and what type of projects might you use them for?');
INSERT INTO badge_optional_requirements VALUES(3028,225,5,'Decorate an item of clothing using duct tape.');
INSERT INTO badge_optional_requirements VALUES(3029,225,6,'Create something useful out of duct tape (wallet, purse, etc.).');
INSERT INTO badge_optional_requirements VALUES(3030,225,7,'Decorate a home decor accessory using duct tape.');
INSERT INTO badge_optional_requirements VALUES(3031,225,8,'Create an item out of duct tape to give as a gift.');
INSERT INTO badge_optional_requirements VALUES(3032,225,9,'Create a piece of jewelry out of duct tape.');
INSERT INTO badge_optional_requirements VALUES(3033,225,10,'Learn about a career that uses duct tape either to fix things, or to create things.');
INSERT INTO badge_optional_requirements VALUES(3034,225,11,'Participate in a community service project that involves duct tape. You might teach younger kids how to make duct tape creations; sell some of your creations and donate the money to a charity; use duct tape to help fix things for people.');
INSERT INTO badge_optional_requirements VALUES(3035,226,3,'Find out what “up-cycled, reduce, and reuse” means. Write a short paragraph on each and how we can use them in our daily lives.');
INSERT INTO badge_optional_requirements VALUES(3036,226,4,'Adopt an area to clean up on a schedule.');
INSERT INTO badge_optional_requirements VALUES(3037,226,5,'Earn the Leave No Trace badge.');
INSERT INTO badge_optional_requirements VALUES(3038,226,6,'Meet at the local litter office and interview the litter officer.');
INSERT INTO badge_optional_requirements VALUES(3039,226,7,'Learn what programs are available in your state that are similar to Earth Day (such as “Keep Ohio Beautiful”).');
INSERT INTO badge_optional_requirements VALUES(3040,226,8,'Learn who cleans three specific areas in your community, such as roadways or parks. Do they get paid or do they volunteer? If you can, interview one of them.');
INSERT INTO badge_optional_requirements VALUES(3041,226,9,'Learn what laws exist in your state or county to prevent litter and pollution.');
INSERT INTO badge_optional_requirements VALUES(3042,226,10,'How does litter effect our environment? How can we reduce or prevent litter? Find at least five ways.');
INSERT INTO badge_optional_requirements VALUES(3043,226,11,'Design a poster for litter prevention.');
INSERT INTO badge_optional_requirements VALUES(3044,226,12,'Choose an area that you notice has a lot of litter. Take before photos of the area, than clean up all the litter. Take after photos to show how different it looks with no more litter or garbage.');
INSERT INTO badge_optional_requirements VALUES(3045,226,13,'Play or teach a game to a group of your choice that promotes litter control and/or environmental protection.');
INSERT INTO badge_optional_requirements VALUES(3046,226,14,'Have a “litter” scavenger hunt or racing game to see who can collect the most litter in a given amount of time.');
INSERT INTO badge_optional_requirements VALUES(3047,226,15,'How can litter harm wildlife? List a few ways it is harmful and how we can make a difference and prevent it.');
INSERT INTO badge_optional_requirements VALUES(3048,229,3,'Dye some eggs different colors. Try both artificial and natural dyes. Natural dyes can be made by boiling things like purple cabbage or onion skins. The more skins you put in the water and the longer you leave the eggs in the dye, the darker your color will be. Artificial dyes can be purchased in a dissolvable pill format or simple food coloring can be used mixed with a ¼ cup of water and a teaspoon of vinegar.');
INSERT INTO badge_optional_requirements VALUES(3049,229,4,'Visit an exhibit of egg art at a museum or art show.');
INSERT INTO badge_optional_requirements VALUES(3050,229,5,'Learn about some of the history of egg art and look at pictures of different egg art techniques.');
INSERT INTO badge_optional_requirements VALUES(3051,229,6,'Decoupage an egg. You will need: 1 egg Tissue paper or a paper napkin with small pictures or flowers on them. Scissors White glue Paint brush Clear glitter String or ribbon Beads, sequins or silk flowers Instructions:  First, cut out small pictures or shapes from your tissue paper (if using paper napkins, make sure to peel them apart into the finest layer you can). Next use the white glue to paint a section of your egg that is slightly bigger than your picture. Place the picture over the glue and smooth down with your paint brush. Brush more glue over the top of the picture. Be careful, the tissue rips easily especially as it gets damp. Paint the entire egg with glue and then roll in clear glitter and let dry. Once dry, use the string or ribbon to create a loop and glue to the top of the egg for a hanger. Use the beads, sequins or small silk flowers to glue over and around the small holes that were used to blow out the egg.');
INSERT INTO badge_optional_requirements VALUES(3052,229,7,'Paint some eggs. If you wish, you can use small gems, beads, sequins or silk flowers to glue onto the egg for added embellishment.');
INSERT INTO badge_optional_requirements VALUES(3053,229,8,'Make some egg ornaments, or other egg artwork to give to someone else. Bowls of brightly colored eggs given to a nursing home for Easter, or egg Christmas ornaments given to your local veterans group to hang on their tree are just a few ideas.');
INSERT INTO badge_optional_requirements VALUES(3054,229,9,'Make egg people with grass hair. You will need: Eggs Potting soil Grass seeds Permanent markers or paints Egg carton or egg cup Instructions: Have an adult cut the tops off several uncooked eggs by gently cracking the shell around the narrow end with the blade of a kitchen knife. The shell should break away clean so you will have deep shells perfect for planting. Save the egg inside to cook with later. Clean the shells with water and vinegar. Let dry overnight. Fill the egg ¾ full with potting soil. Sprinkle grass seeds on the soil and water using a spray bottle every day. After a few days, the grass should grow. Once the grass has sprouted, decorate the eggs with different faces using the pens or paint. You can also use pipe cleaners or other items to make things like glasses or ties to glue to your egg person.');
INSERT INTO badge_optional_requirements VALUES(3055,229,10,'Make egg animals. One example might be a ladybug. Paint ¾ of the egg red. Once it is dry, paint a black line down the center and black dots on either side. Paint the last ¼ of the egg black as well. Glue two google eyes to the face and paint on a smiling mouth and tiny nose.');
INSERT INTO badge_optional_requirements VALUES(3056,229,11,'Make an egg mosaic. Dye several blown eggs a variety of different colors. Once dry, break the eggs and use the shells to create a mosaic by gluing them on to a piece of paper, cardboard, or wood.');
INSERT INTO badge_optional_requirements VALUES(3057,229,12,'Make egg shell flowers. You will need: Eggs Floral Wire or green pipe cleaners Beads (1/4 inch or larger) Glue Paint Instructions:  Carefully crack eggs in half (save egg inside for cooking later). Wash the shells with water and vinegar and let dry overnight. Twist the end of the floral wire into a spiral and glue it to the bottom of the eggs shell. Place the shells upside down and dry overnight. Paint the shells to look like petals by first painting the shell a light color as a base and then painting stripes of color on the flowers by starting at the center of the egg and pulling the brush to the edge. When they are dry, you can glue a bead in the center of the flower if you wish.');
INSERT INTO badge_optional_requirements VALUES(3058,229,13,'Look through a book, or go online with a parent’s permission, and look at a collection of Faberge Eggs. Learn a little bit about this famous artist.');
INSERT INTO badge_optional_requirements VALUES(3059,230,3,'Learn the history of eating eggs. When did chicken eggs become popular for eating?');
INSERT INTO badge_optional_requirements VALUES(3060,230,4,'Identify the colors of eggs laid by three different breeds of chickens. Is one color healthier or better than the others?');
INSERT INTO badge_optional_requirements VALUES(3061,230,5,'Try eggs from another bird species (duck, quail, goose, etc).');
INSERT INTO badge_optional_requirements VALUES(3062,230,6,'Learn to cook (or Preschool and Level 1 taste) eggs three different ways. Which is your favorite?');
INSERT INTO badge_optional_requirements VALUES(3063,230,7,'Visit a farm or local person who raises eggs and see their hens. Do their hens lay eggs all year?');
INSERT INTO badge_optional_requirements VALUES(3064,230,8,'Incubate eggs and hatch them.');
INSERT INTO badge_optional_requirements VALUES(3065,230,9,'Learn to pasteurize an egg in the shell. What are some recipes that call for raw egg? Why might people pasteurize them instead of using them raw?');
INSERT INTO badge_optional_requirements VALUES(3066,230,10,'Are chicken eggs eaten in other cultures? What other types of eggs are eaten and where?');
INSERT INTO badge_optional_requirements VALUES(3067,230,11,'Learn the proper way to boil an egg. What does a greenish ring around the yolk mean? What can you do so the eggs will be easy to peel?');
INSERT INTO badge_optional_requirements VALUES(3068,230,12,'Earn the Egg Art badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3069,230,13,'Learn to use ground flax seed as an egg substitute for baking. Are there any other egg substitutes?');
INSERT INTO badge_optional_requirements VALUES(3070,230,14,'How many eggs does a hen lay in a day? In a year? For how long will a chicken lay eggs? At what age will a hen start laying eggs?');
INSERT INTO badge_optional_requirements VALUES(3071,230,15,'What does it mean to temper an egg and why would you do it?  How is egg used in mayonnaise, eggnog, and meringue? What other recipes use eggs?');
INSERT INTO badge_optional_requirements VALUES(3072,230,16,'How are eggs stored? Are they stored differently in other parts of the world? How are they stored without refrigeration? What are the pros and cons of washing eggs?');
INSERT INTO badge_optional_requirements VALUES(3073,230,17,'Find out what sort of jobs involve eggs. What education do these people have?  What pay and work hours?');
INSERT INTO badge_optional_requirements VALUES(3074,231,3,'Sometimes pieces of elastic lose their stretchiness over time. Learn how to replace an old piece of elastic in something, like a skirt waistband, with a new piece.');
INSERT INTO badge_optional_requirements VALUES(3075,231,4,'Learn about the history of elastic. Make a timeline of events that have happened in the history of elastic.  You must have at least 10 items on your timeline.');
INSERT INTO badge_optional_requirements VALUES(3076,231,5,'Conduct a science experiment that uses elastic.');
INSERT INTO badge_optional_requirements VALUES(3077,231,6,'Read about someone who creates furniture, sculptures, etc. out of rubber bands. Look at pictures of their creations. Do you like the creations? Do you think they would be comfortable to sit on? Are they pretty to look at?');
INSERT INTO badge_optional_requirements VALUES(3078,231,7,'Learn about careers in the elastic business, such as a manufacturer, or a seamstress who uses elastic in clothes. Levels 3 – 5 Only: If possible, shadow someone for a day who works with elastic for a living.');
INSERT INTO badge_optional_requirements VALUES(3079,231,8,'During the 1950’s, men and women wore belts made out of elastic with decorative buckles. Find one of these belts and look at it. Try making your own.');
INSERT INTO badge_optional_requirements VALUES(3080,231,9,'Make a necklace or bracelet out of beads strung on elastic.');
INSERT INTO badge_optional_requirements VALUES(3081,231,10,'Visit a craft store and look at different types of elastic, such as regular elastic that would be used for waistbands, skinny circular elastic that you could string beads on, or elastic with sequins attached. Which is your favorite?');
INSERT INTO badge_optional_requirements VALUES(3082,231,11,'Make a list of uses for elastic in the world today. Think about commercial, industrial, and home uses.');
INSERT INTO badge_optional_requirements VALUES(3083,231,12,'Make something that uses elastic (no jewelry).  You might make a slingshot, use rubber bands to tie-dye a shirt, make a pretend guitar, etc.');
INSERT INTO badge_optional_requirements VALUES(3084,232,3,'Understand the structure and duties of local, state and federal government');
INSERT INTO badge_optional_requirements VALUES(3085,232,4,'Create a want ad for your ideal political candidate. Stress the qualities an officeholder should have: honesty, integrity, hard-working, etc.');
INSERT INTO badge_optional_requirements VALUES(3086,232,5,'Visit a polling location with an adult during an election.');
INSERT INTO badge_optional_requirements VALUES(3087,232,6,'Take a field trip to an official city or county building and/or community service organization. How do elections affect the way they do business?');
INSERT INTO badge_optional_requirements VALUES(3088,232,7,'Visit a museum with an exhibition of election and campaign materials.');
INSERT INTO badge_optional_requirements VALUES(3089,232,8,'With your family or friends, make a list of “laws” you feel would be good for your family or group. Have your friends and family vote on each one. Were there some “laws” people thought were not such a good idea? For example, maybe you wanted a “law” that said you would never have to clean your room, but your parents both voted against it. If such a “law” passed in your family, can you see why even though it was voted in, it may not be the best thing for your family? The same thing can happen in our government elections if people do not think through the consequences of the laws they vote for.  Levels 3 – 5 Only: What propositions are currently on the ballot that people might not think about the long term consequences?');
INSERT INTO badge_optional_requirements VALUES(3090,232,9,'Learn about at least three third party organizations and what they stand for such as: Green Party Independence Party Constitution Party Socialist Party Libertarian Party Reform Party Natural Law Party Peace & Freedom Party Tea Party');
INSERT INTO badge_optional_requirements VALUES(3091,232,10,'View examples of real campaign brochures and then create one for the candidate of your choice. The cover should be eye-catching and simple, showing a picture of the candidate and their name. The inside pages should have information about the candidate that show why they should be elected and a list of their core beliefs and values.');
INSERT INTO badge_optional_requirements VALUES(3092,232,11,'Participate in a mock election with your friends. This can be based on an actual election, or an imaginative one. Each person is responsible for developing a political party with a name, an animal symbol, slogans, buttons, pennants, etc., a candidate, an issues platform and an opening speech for their convention. Next, each person should select a city and venue in which they would hold their convention. What are important considerations in choosing a convention site? Use a United States map, atlases and the Internet (with parent permission) to choose your convention site. Invite friends or family to your mock conventions and then create a polling place with sheets or cardboard boxes as dividers so people can have privacy’ while they vote. Have them place their completed ballots in a ballot box (take a shoebox and make a slit in the top) and then tally the results. Let everyone know who won and then discuss why that candidate probably won and what the other candidates should have done differently.');
INSERT INTO badge_optional_requirements VALUES(3093,232,12,'Understand the differences between a primary elections, caucuses, mid-term elections, general elections, and presidential elections.');
INSERT INTO badge_optional_requirements VALUES(3094,232,13,'What is a national convention? Watch a portion of at least one party’s convention TV.');
INSERT INTO badge_optional_requirements VALUES(3095,232,14,'What is the Electoral College? How does it work and why? Find out what was unique about the 1876 presidential election and the role the Electoral College played.');
INSERT INTO badge_optional_requirements VALUES(3096,232,15,'Create bookmarks that encourage voting and provide reasons why it is important. Distribute the finished bookmarks through local banks, dentist offices, the local League of Women Voters, the local Motor Vehicles bureau, public libraries, etc. You may also choose a different craft project such as buttons, stickers, posters, or badges.');
INSERT INTO badge_optional_requirements VALUES(3097,232,16,'Find out what parts of the constitution and its amendments address voting rights.');
INSERT INTO badge_optional_requirements VALUES(3098,232,17,'Survey at least 20 people about how they plan to vote on upcoming candidates and ballot measures and propositions. Graph your results.');
INSERT INTO badge_optional_requirements VALUES(3099,232,18,'Learn the history of voting rights in America and create a timeline of how they have evolved.');
INSERT INTO badge_optional_requirements VALUES(3100,232,19,'Watch a portion of the election returns and be able to explain the difference between a red and blue state.');
INSERT INTO badge_optional_requirements VALUES(3101,232,20,'Understand the process to getting elected including each of the following steps: qualify, get nominated, political parties, debates, primary elections, votes, swearing in.');
INSERT INTO badge_optional_requirements VALUES(3102,232,21,'Learn about the women’s suffrage movement and women such as Susan B. Anthony, Elizabeth Cady Stanton, Alice Stokes Paul, or Lucy Burns. Create a timeline of their struggle.  What were the arguments and fears of the anti-suffragists?');
INSERT INTO badge_optional_requirements VALUES(3103,232,22,'Visit website of various candidates (with parent’s permission). Compare where they stand on the issues; how easy the site is to navigate; how they present themselves; and the general look of the website. What could they improve? How has the internet affected how politicians market themselves?');
INSERT INTO badge_optional_requirements VALUES(3104,232,23,'Create spreadsheets or a database of population data, state size and congressional representation. Do this for at least 10 different states. Then make one bar graph showing the population of different states, one showing the number of representatives per state in the House of Representatives, and one showing the size (in square miles) of each state. Compare the three graphs to see which look the most similar. Is congressional representation based on population or size? Why does the number of senators differ from the number of representatives?');
INSERT INTO badge_optional_requirements VALUES(3105,232,24,'Have you ever noticed how often certain words come up in political speeches? Listen to several different speeches from at least two different candidates over the course of an election. Find the similarities and differences between them. Analyze the candidate’s word choices. How can their choice of words affect how people perceive them? For example, to contribute to a campaign and to donate to it mean basically the same thing, but they can give an entirely different feeling to a constituent. To contribute means to participate and be part of a bigger picture, to donate simply means to give with no involvement. Which word do you think would be more valuable to a politician?');
INSERT INTO badge_optional_requirements VALUES(3106,232,25,'Call or visit the Supervisor of Elections’ office to obtain the following information: What are the qualifications for voting in your state? How do you register to vote? How is your polling place determined? If you will be out of town during the election, how would you vote? When is the next primary or general election? Is your state an open or closed primary state? Complete a sample voter registration form.');
INSERT INTO badge_optional_requirements VALUES(3107,232,26,'Read a book at your reading level about American government and how it works.  This may be a general overview of American republican democracy, or it may be a book specifically dealing with election and voting issues.');
INSERT INTO badge_optional_requirements VALUES(3108,233,3,'Explain the proper way to rescue a person in contact with an electric wire and why you should never attempt this yourself. Understand basic first aid that can be offered to the person who is unconscious from electric shock. Explain how to treat an electrical burn.');
INSERT INTO badge_optional_requirements VALUES(3109,233,4,'How does your home get its electricity? What type of plant produces the electricity you use? Learn how to read your electric meter or understand what tools are available to you online if your meter is a “smart” meter. What does it cost to provide electricity to your home? How can you conserve energy and reduce your costs?');
INSERT INTO badge_optional_requirements VALUES(3110,233,5,'What is a surge protector and why are the necessary in today’s households? What damage can an electrical surge do to your appliances? What can cause an electric surge? How often should you replace your surge protectors?');
INSERT INTO badge_optional_requirements VALUES(3111,233,6,'Take a field trip to an electric plant or visit a museum or exhibit about electricity.');
INSERT INTO badge_optional_requirements VALUES(3112,233,7,'Explain what to do in an electrical storm. Why should you come indoors, stay away from water and electrical appliances? What can happen in each of these instances?');
INSERT INTO badge_optional_requirements VALUES(3113,233,8,'Explain what to do in the event of an electrical fire. What precautions can you take to avoid such fires?');
INSERT INTO badge_optional_requirements VALUES(3114,233,9,'Explain why a fuse blows or a circuit breaker trips. Where would you find a blown fuse or tripped circuit breaker in your home? Show how to safely reset the circuit breaker. What can you do to make sure your home circuits are not overloaded?');
INSERT INTO badge_optional_requirements VALUES(3115,233,10,'Construct a simple electric magnet and understand how it works.');
INSERT INTO badge_optional_requirements VALUES(3116,233,11,'Participate in a community service project involving electricity. Examples might include creating posters or booklets on electrical safety to share with younger children or showing people how to conserve energy.');
INSERT INTO badge_optional_requirements VALUES(3117,233,12,'Research careers involving electricity such as an electrician, a power plant worker, a solar engineer, or a hydroelectric engineer. What education and training might you need?  What salary could you expect? Where might you need to live? What hours might you have to work?');
INSERT INTO badge_optional_requirements VALUES(3118,233,13,'Create a timeline of events in the history of electricity and mankind. Include at least 20 events or electric inventions.');
INSERT INTO badge_optional_requirements VALUES(3119,233,14,'Draw a simple diagram, showing resistors, capacitors, and transistors or integrated circuits. Using correct symbols, label all parts. Explain the purpose of each part of your diagram.');
INSERT INTO badge_optional_requirements VALUES(3120,233,15,'Keep a log for one week of all the things you use that require electricity. How would you do these things if you had no electricity?  Which are essential to your home, such as for cooking or heating, and which are simply for enjoyment?');
INSERT INTO badge_optional_requirements VALUES(3121,233,16,'Explain static electricity and demonstrate it in some way.');
INSERT INTO badge_optional_requirements VALUES(3122,233,17,'Learn about at least five different battery types such as dry cell, lithium-ion, button cell, alkaline battery, and nickel-cadmium battery. What are the differences between them? What are each normally used for? What are their advantages and disadvantages?');
INSERT INTO badge_optional_requirements VALUES(3123,234,3,'Create an original artwork, poem, or story that highlights the value of different ways of thinking.');
INSERT INTO badge_optional_requirements VALUES(3124,234,4,'Explore how neurodiversity is portrayed in the media—both good and bad examples.');
INSERT INTO badge_optional_requirements VALUES(3125,234,5,'Color a picture of a brain and talk about how people think in many different ways.');
INSERT INTO badge_optional_requirements VALUES(3126,234,6,'Learn about executive functioning and how challenges in this area affect daily life.');
INSERT INTO badge_optional_requirements VALUES(3127,234,7,'Learn a calming strategy (like deep breathing or using a fidget) that some people use to help stay focused or relaxed.');
INSERT INTO badge_optional_requirements VALUES(3128,234,8,'Interview a parent, teacher, or therapist about what they’ve learned from working with neurodivergent children.');
INSERT INTO badge_optional_requirements VALUES(3129,234,9,'Create a quiet zone or sensory-friendly space in your home or meeting space.');
INSERT INTO badge_optional_requirements VALUES(3130,234,10,'Discuss the strengths that come with thinking differently. Give examples.');
INSERT INTO badge_optional_requirements VALUES(3131,234,11,'Explore what sensory processing challenges are and try a simulation or activity that helps you understand them.');
INSERT INTO badge_optional_requirements VALUES(3132,234,12,'Learn what it means to self-regulate. Make your own calming toolkit.');
INSERT INTO badge_optional_requirements VALUES(3133,234,13,'Interview someone who is neurodivergent or watch a video of them sharing their story.');
INSERT INTO badge_optional_requirements VALUES(3134,234,14,'Learn about the history of the neurodiversity movement.');
INSERT INTO badge_optional_requirements VALUES(3135,234,15,'Make a poster, presentation, or short video celebrating neurodiversity.');
INSERT INTO badge_optional_requirements VALUES(3136,234,16,'Participate in an activity that builds empathy, such as using noise-canceling headphones or trying to read with mirrored letters.');
INSERT INTO badge_optional_requirements VALUES(3137,234,17,'Learn what “stimming” is and why some people do it.');
INSERT INTO badge_optional_requirements VALUES(3138,234,18,'Attend or help host a neurodiversity-friendly event or sensory-friendly activity.');
INSERT INTO badge_optional_requirements VALUES(3139,234,19,'Read a book, article, or blog post written by a neurodivergent person and share what you learned.');
INSERT INTO badge_optional_requirements VALUES(3140,234,20,'Learn about the concept of masking and why some neurodivergent individuals feel they need to hide how they truly behave.');
INSERT INTO badge_optional_requirements VALUES(3141,234,21,'Examine your school, group, or organization. How could it be more inclusive for neurodivergent individuals? Make a suggestion for improvement.');
INSERT INTO badge_optional_requirements VALUES(3142,234,22,'Role-play how to be support someone who is being misunderstood or treated unfairly because of neurodiversity.');
INSERT INTO badge_optional_requirements VALUES(3143,234,23,'Discuss the importance of accepting—not just accommodating—people who are different.  What is the difference?');
INSERT INTO badge_optional_requirements VALUES(3144,234,24,'Learn about the difference between person-first and identity-first language. Discuss which is preferred and why.');
INSERT INTO badge_optional_requirements VALUES(3145,234,25,'Write an article, blog post, or social media post to raise awareness about neurodiversity.');
INSERT INTO badge_optional_requirements VALUES(3146,234,26,'Learn how workplace or classroom accommodations help neurodivergent people succeed.');
INSERT INTO badge_optional_requirements VALUES(3147,234,27,'Design a neurodiversity inclusion guide or checklist for events or activities.');
INSERT INTO badge_optional_requirements VALUES(3148,234,28,'Explore current advocacy efforts or laws that support neurodivergent individuals (e.g., IDEA, ADA, IEPs).');
INSERT INTO badge_optional_requirements VALUES(3149,234,29,'Help plan a sensory-friendly field trip or gathering for your group.');
INSERT INTO badge_optional_requirements VALUES(3150,234,30,'Create a visual display (poster, art piece, zine, etc.) to celebrate neurodiverse thinkers.');
INSERT INTO badge_optional_requirements VALUES(3151,234,31,'Identify local organizations or charities that support neurodivergent people and find a way to support their mission.');
INSERT INTO badge_optional_requirements VALUES(3152,234,32,'Volunteer at an event or program for people with disabilities or neurodivergence.');
INSERT INTO badge_optional_requirements VALUES(3153,235,3,'Learn about the wide variety of embroidery works of art. Embroidery can be done with different types of yarn such as silk, cotton or woolen yarn, and each will have a distinctive texture and appearance. Which do you like best? Why?');
INSERT INTO badge_optional_requirements VALUES(3154,235,4,'Look at examples of embroidery on paper or card: these can be very simple or extremely complex! Learn how to sew embroidery designs onto a sewing card. You can make embroidery designs using thread on construction paper or card with holes in it. Make your own design and stitch it on a card.');
INSERT INTO badge_optional_requirements VALUES(3155,235,5,'Design your own embroidery pattern. Preschool-Level 1: Geometric designs are very similar to embroidery. Design your own embroidery patterns on squared paper by making cross-stitch and running stitch designs. Levels 2-5: Create a design to embroider using paper and colored pencils/pens. Then learn how to transfer the design to fabric and stitch the design.');
INSERT INTO badge_optional_requirements VALUES(3156,235,6,'Embroider something, such as a hand towel, a pillow, or a pin-cushion, etc. using at least 6 different stitches and give it to someone.');
INSERT INTO badge_optional_requirements VALUES(3157,235,7,'Enter a piece of your embroidery in your state or county fair.');
INSERT INTO badge_optional_requirements VALUES(3158,235,8,'Visit your state fair or a museum where there are displays of embroidery. Tell your family, friends, or group what you learned. Which piece was your favorite, and why?');
INSERT INTO badge_optional_requirements VALUES(3159,235,9,'Embroider a baby, birthday, or wedding gift to give away.');
INSERT INTO badge_optional_requirements VALUES(3160,235,10,'Embroider a garment for yourself, or someone else, using at least five different stitches.');
INSERT INTO badge_optional_requirements VALUES(3161,235,11,'Learn to do different embroidery stitches and learn when they are used. This requirement may be repeated for each kind of stitch learned. Preschool-Level 1: Learn to do 1 of each kind of stitch. Level 2: Learn 2 of each kind. Levels 3-5: Learn 3 of each kind of stitch. Add these to your booklet of stitches. Laced stitches: Laced running stitch, Pekinese stitch, and whipped running stitch. Outline stitches: Stem stitch, back stitch, and overcast stitch. Flat stitches: Flat stitch, satin stitch and fishbone stitch. Looped stitches: Vandyke stitch or ladder stitch, and cretan or open cretan stitch. Chained stitches: Chain stitch, twisted chain stitch or chequered chain stitch. Couching and filling stitches: Roumanian couching, Bokhara couching, and seeding. Composite stitches: Portuguese border stitch, interlaced band, and striped woven band. Knotted stitches: Bullion stitch, knot stitch edging, and double knot stitch.');
INSERT INTO badge_optional_requirements VALUES(3162,235,12,'Learn what smocking is, and how to do it. Make something, such as a romper/onesie for a baby, with smocking on it.');
INSERT INTO badge_optional_requirements VALUES(3163,235,13,'Learn about different embroidery techniques such as ribbon embroidery, crewel embroidery and needle-weaving. Make a sample piece of one type of embroidery. If you did this at a lower level, choose a different technique.');
INSERT INTO badge_optional_requirements VALUES(3164,235,14,'Have some friends over for an embroidery party or bring your embroidery along and spend some time with an older person who likes to do embroidery too.');
INSERT INTO badge_optional_requirements VALUES(3165,235,15,'Find somebody who likes to do embroidery and talk to them about it. Look at any examples of their work that they can show you. If you cannot find anyone to talk with, then find books about embroidery work. There are books on how to do embroidery and also books with pictures of famous works of embroidery in them. With your parents’ permission you may look at pictures of embroidery on the Internet.');
INSERT INTO badge_optional_requirements VALUES(3166,237,3,'Does the emergency service you chose have a mascot? Learn about them and what they stand for. How is the mascot used to educate people? Draw it, or design one of your own.');
INSERT INTO badge_optional_requirements VALUES(3167,237,4,'Read a biography of a real-life community hero.');
INSERT INTO badge_optional_requirements VALUES(3168,237,5,'Bake and bring cookies or other goodies to the station. Call first to see if they will accept treats.');
INSERT INTO badge_optional_requirements VALUES(3169,237,6,'Visit a training facility for workers in your emergency service.');
INSERT INTO badge_optional_requirements VALUES(3170,237,7,'Visit a museum or exhibit regarding emergency services.');
INSERT INTO badge_optional_requirements VALUES(3171,237,8,'Help with a community service event such as a bicycle registration clinic, car seat safety check, fire safety demonstration, mock disaster, etc.');
INSERT INTO badge_optional_requirements VALUES(3172,237,9,'Interview a service worker. Ask why he/she chose this field, their most rewarding moment, most difficult situation and anything else you wish to learn.');
INSERT INTO badge_optional_requirements VALUES(3173,237,10,'Have a member of the organization come talk to your club about safety.');
INSERT INTO badge_optional_requirements VALUES(3174,237,11,'Research the chain of command and other career opportunities in the service you chose. Who is in charge? What are his/her title and responsibilities? How many people are under his/her authority? What support personnel are needed?');
INSERT INTO badge_optional_requirements VALUES(3175,237,12,'Where does the funding for your chosen emergency service come from (taxes, grants, donations, etc.)?');
INSERT INTO badge_optional_requirements VALUES(3176,237,13,'Make up and play a role-playing game to show what you’ve learned. You may substitute putting on a skit or puppet show to teach younger girls what you have learned for the role-playing game if you choose');
INSERT INTO badge_optional_requirements VALUES(3177,237,14,'Create a poster or flyer to teach others about your emergency service, what they do, how to contact them, etc.');
INSERT INTO badge_optional_requirements VALUES(3178,237,15,'With your parent’s permission, watch a documentary or a movie about one of the emergency services. OR, watch at least two episodes of a TV show about firefighters, paramedics, policemen, etc, such as Emergency, or Adam 12.');
INSERT INTO badge_optional_requirements VALUES(3179,237,16,'Write an essay about how the emergency services help us, and how they have changed over the years.');
INSERT INTO badge_optional_requirements VALUES(3180,237,17,'Learn about emergency rescue services that come into an area after a major disaster.  What sort of equipment do they have that is additional to the local emergency services?  What sort of training do they have that is different from local emergency services?  Who pays for their services?  Who decides when they are dispatched to an area?');
INSERT INTO badge_optional_requirements VALUES(3181,237,18,'Volunteer with your emergency service (Level 3, 4 and 5 only).');
INSERT INTO badge_optional_requirements VALUES(3182,237,19,'Become qualified as an emergency service personnel member (Level 5).');
INSERT INTO badge_optional_requirements VALUES(3183,237,20,'Watch one or more training videos for your emergency service.');
INSERT INTO badge_optional_requirements VALUES(3184,237,21,'Volunteer to clean the local emergency service building or do yard work outside.');
INSERT INTO badge_optional_requirements VALUES(3185,237,22,'Organize a fund-raiser for your local emergency service.');
INSERT INTO badge_optional_requirements VALUES(3186,238,4,'Learn 5 of the 7 categories of species endangerment according to the International Union for Conservation of Nature (IUCN). Levels 2-5: Learn the basic criteria for each category.');
INSERT INTO badge_optional_requirements VALUES(3187,238,5,'Read a book about an endangered species. It does have to be the same species you chose in starred requirement #2.');
INSERT INTO badge_optional_requirements VALUES(3188,238,6,'Create a mobile or other project featuring 10 different endangered species. Be sure to include a drawing or picture of each species along with its common name, scientific name, level of endangerment, and where it’s typically found.');
INSERT INTO badge_optional_requirements VALUES(3189,238,7,'Make a puppet of the animal you chose in starred requirement #2 and use it to create a 3-5 minute skit about the animal, endangered species in general, or habitat conservation. Perform the skit for at least 3 people. The puppet may be made from a brown paper bag, a sock, felt, or any other suitable material.');
INSERT INTO badge_optional_requirements VALUES(3190,238,8,'Learn what a food chain is and draw a picture of the food chain for the animal you chose in starred requirement #2. Then, discuss what might happen to this food chain if the animal you chose becomes extinct.');
INSERT INTO badge_optional_requirements VALUES(3191,238,9,'Habitat destruction is one of the main reasons why many species have become endangered today. Learn two ways animal habitats are being destroyed and make a list of things you can do to help prevent it.');
INSERT INTO badge_optional_requirements VALUES(3192,238,10,'Complete a service project that either helps protect or encourages the growth of an endangered population in your area.');
INSERT INTO badge_optional_requirements VALUES(3193,238,11,'Design and make a t-shirt that promotes awareness of an endangered species in your area. If you also choose to complete a service project for this species (requirement #10) wear your shirt during the project.');
INSERT INTO badge_optional_requirements VALUES(3194,238,12,'Earn the Ecology badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3195,238,13,'Learn which animal species are endangered in your state. Make a chart to show how many of them are mammals, birds, fish, reptiles, or amphibians. Which class of animal is the most threatened where you live?');
INSERT INTO badge_optional_requirements VALUES(3196,238,14,'Learn which plants & insects are endangered in your state. Are any of them a source of food for an animal? Is that animal also endangered?');
INSERT INTO badge_optional_requirements VALUES(3197,238,15,'Learn about a career that works with endangered animals &/or habitat conservation. What education is needed? What is the average salary for this career? What are some of the duties performed by those working in this field? What parts of this job interest you the most? Share what you’ve learned with your troop, class, or family.');
INSERT INTO badge_optional_requirements VALUES(3198,238,16,'Earn the Animals (Specific) badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3199,238,17,'Earn one of the Animal Category badges at your level, such as Insects, Amphibians, Birds, Mammals, Reptiles, and Marine Life.');
INSERT INTO badge_optional_requirements VALUES(3200,239,3,'LEVEL 2 AND ABOVE: Build the birdhouse from your blueprint in requirement #2.');
INSERT INTO badge_optional_requirements VALUES(3201,239,4,'Earn the Man-made Wonders badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(3202,239,5,'Earn the Math badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(3203,239,6,'Talk with an engineer and discuss what they do, the tools they use, how their work is done, and a current project they are working on.');
INSERT INTO badge_optional_requirements VALUES(3204,239,7,'Find a Code of Ethics for engineers and browse through it. What do you think are the most important parts? Why is a Code of Ethics needed?');
INSERT INTO badge_optional_requirements VALUES(3205,239,8,'Learn about the Engineering Process. Discuss the differences and similarities to the Scientific Method.');
INSERT INTO badge_optional_requirements VALUES(3206,239,9,'Select a manufactured item in your home and, under adult supervision, investigate how and why it works, and the engineering types that were involved in its design.');
INSERT INTO badge_optional_requirements VALUES(3207,239,10,'Participate in an engineering fair, science fair, or similar competition requiring you to build or produce something.');
INSERT INTO badge_optional_requirements VALUES(3208,239,11,'Learn about at least 5 different engineer types.  How do they relate to each other? What sorts of solutions or products might they design together?');
INSERT INTO badge_optional_requirements VALUES(3209,239,12,'Think about your daily life and surroundings – Find three things that could be improved by engineering. What type of engineer would be able to improve it?');
INSERT INTO badge_optional_requirements VALUES(3210,239,13,'LEVEL 5 ONLY: Build the solution from your design (this is a great opportunity for a service project).');
INSERT INTO badge_optional_requirements VALUES(3211,239,14,'Earn the biography badge for a famous inventor or engineer.');
INSERT INTO badge_optional_requirements VALUES(3212,239,15,'Choose an engineering category and learn about the various tools that type of engineers uses such as CAD software, laboratory equipment, programming languages, etc.');
INSERT INTO badge_optional_requirements VALUES(3213,239,16,'Learn about safety protocols and regulations relevant to engineering work, including personal protective equipment (PPE), hazard identification, and emergency procedures.');
INSERT INTO badge_optional_requirements VALUES(3214,239,17,'Choose an engineering concept to explain to someone and use at least one communication skill for presenting technical information such as writing a report, creating a presentation, or explaining complex concepts to non-engineers.');
INSERT INTO badge_optional_requirements VALUES(3215,239,18,'Investigate recent engineering innovations and breakthroughs, discussing their impact on society and potential future developments.');
INSERT INTO badge_optional_requirements VALUES(3216,239,19,'Study a case of engineering failure, analyzing the causes and lessons learned to prevent similar incidents in the future.');
INSERT INTO badge_optional_requirements VALUES(3217,239,20,'Understand the importance of patents and intellectual property rights in engineering, including how to protect inventions and respect the intellectual property of others.');
INSERT INTO badge_optional_requirements VALUES(3218,239,21,'Learn about environmental issues related to engineering activities, including pollution, sustainability, and conservation efforts.');
INSERT INTO badge_optional_requirements VALUES(3219,239,22,'Hold a toothpick bridge contest.  Using only a set number of toothpicks and glue, see who can build a bridge that can hold the most weight, or who can build the longest bridge, or the one with the craziest design.');
INSERT INTO badge_optional_requirements VALUES(3220,240,3,'Watch a documentary about a famous entrepreneur.');
INSERT INTO badge_optional_requirements VALUES(3221,240,4,'Visit a locally owned business and talk to the business owner about what being an entrepreneur means to them. What are the benefits? What are the drawbacks?  How much time to do they spend at their business?');
INSERT INTO badge_optional_requirements VALUES(3222,240,5,'Visit a local business and make a list of other business you might own that sell things to the business you are visiting. For example, if you visit an office supply store,  other businesses that may be involved might be some of the following: A paper mill A sign maker Heating and air-conditioning repair Janitorial services Temporary employee agency Office supply wholesaler Retail fixture sales Paint Store or Painter Carpet Store Landscaper (to maintain outside landscaping)');
INSERT INTO badge_optional_requirements VALUES(3223,240,6,'Earn a Character badge that will help you if you wish to become an entrepreneur. Examples might include Diligence, Patience, or Responsibility. Be able to tell why the character trait you chose would be of help to an entrepreneur.');
INSERT INTO badge_optional_requirements VALUES(3224,240,7,'Learn about a successful kid entrepreneur such as: Cameron Johnson – Greeting Cards, Beanie Babies and Online Enterprises Javier Fernández-Han – VERSATILE system Leanna Archer – Hair Inc. Jason O’Neill – Pencil Bugs');
INSERT INTO badge_optional_requirements VALUES(3225,240,8,'Play a video or board game that involves being an entrepreneur. Examples might include Lemonade Stand or Gazillinaire.');
INSERT INTO badge_optional_requirements VALUES(3226,240,9,'Join a Junior Achievement club in your area.');
INSERT INTO badge_optional_requirements VALUES(3227,240,10,'In order for a business to succeed, they have to sell a product or service people actually want, and they have to find a way to let people know they are in business.  This is called marketing. Marketing includes everything from designing your logo and signage, to advertisements, to taking surveys about what people want. Do one of the following: Survey 20 people and ask them what their favorite flavor of ice cream is. Graph your results and be able to explain which flavor you would choose to sell if you were in business and why. Design a name and logo for a business you might run. How does your name and logo reflect your business? Why do some businesses chose to have a slogan? Create a video commercial for a product. How can you convince people to buy your product in less than 30 seconds?');
INSERT INTO badge_optional_requirements VALUES(3228,240,11,'Read the biography of an entrepreneur.');
INSERT INTO badge_optional_requirements VALUES(3229,240,12,'Find out how you might get financing for your business if you do not have the money yourself. How does financing and loans work? Calculate how much a loan of $10,000 would cost you over 5 years at 10% interest per year. Why would a business want to borrow money if it costs them more in the long run?');
INSERT INTO badge_optional_requirements VALUES(3230,240,13,'Learn about insurance. Why does a business need to be insured? What types of insurance might they need? How much might business insurance cost and how would that be factored into your profit or loss?');
INSERT INTO badge_optional_requirements VALUES(3231,240,14,'Learn about employee law. What notices must be hung in your place of business? What type of taxes must you withhold from employee paychecks? What are the discrimination laws?');
INSERT INTO badge_optional_requirements VALUES(3232,240,15,'Take an accounting course.');
INSERT INTO badge_optional_requirements VALUES(3233,242,3,'Learn coughing and sneezing etiquette, such as: Turn away from people when about to cough or sneeze. Always cover your mouth when coughing or sneezing with a disposable tissue. If a tissue is not readily available, then cough into your elbow, not your hand. Throw the tissue away immediately. Wash hands with soap and water or clean hands with alcohol based sanitizers such as wipes or gels.');
INSERT INTO badge_optional_requirements VALUES(3234,242,4,'Have a “fancy dinner” with your family to demonstrate the table manners you have learned.');
INSERT INTO badge_optional_requirements VALUES(3235,242,5,'Learn to sit elegantly, such as: Walk toward the chair or couch and stand directly in front of it. Without looking backwards or down, back up slightly towards the chair, feel the chair gently with your leg. Then, while keeping your back straight, gently sit down onto the front of the chair. Slide back onto the seat a little more, but keep feet on the floor. Keep your knees together and either tuck one foot behind the other or keep your ankles together. Feet can be slightly to the side. To stand up, uncross your ankles, place your feet flat in front of you. Slide forward until you are at the edge of the chair. Keeping your back straight, stand up.');
INSERT INTO badge_optional_requirements VALUES(3236,242,6,'Learn ladylike behavior, such as: Never lower yourself in public or private by getting into a confrontational situation. It’s better to handle everything in a ladylike manner. Take care of your reputation. It is something you can’t get back too easily in life. Learn how to dress for any occasion and maintain proper hygiene. If you do not care about your appearance, why should anyone else? Always respect your elders and people in a position of authority, such as teachers or law enforcement. A lady never: sits with her legs open; belches, lets out gas, or picks her teeth in public; chews with her mouth open; talks with food in her mouth; dresses in a manner that is revealing; behaves rudely, or in an overbearing and loud manner; swears; talks about bathroom issues; puts her elbows on the table while eating; or brushes her hair at the dinner table. A proper lady always: says please and thank you; sits up straight; covers her mouth when coughing or sneezing; blows her nose in private; eats slowly; holds her fork correctly; lets a man open the door; asks to be excused from the dinner table. If you must chew gum, no snapping or blowing bubbles in public, don’t chew with your mouth open, and place it in a proper trash receptacle. Look the other person in the eyes when speaking and listening.');
INSERT INTO badge_optional_requirements VALUES(3237,242,7,'Look up the Federal Flag code and learn proper etiquette when handling or displaying the American Flag.');
INSERT INTO badge_optional_requirements VALUES(3238,242,8,'Host or attend a party to practice your party etiquette.');
INSERT INTO badge_optional_requirements VALUES(3239,242,9,'Learn proper phone etiquette, such as: The correct way to answer a phone is a simple “Hello,” or “Hello, this is Jane.” or “Hello, this is the Smith residence.” When the telephone in the home is answered by someone other than the head of the house and someone says, “May I speak to Mrs. Brown, please?” he or she should say, “Just a moment, please.” If Mrs. Brown is unable to come to the phone, the correct reply is “Mrs. Brown can’t come to the phone now. May I have your name, and she will call you back as soon as possible?” If you must put the telephone down during the conversation, do it gently. The person at the other end may still have the phone close to his ear, and a sudden sharp bang can be hurtful as well as rude. Courtesy is as important in speaking over the phone as in talking to people face to face. Phone calls generally should not be made before 7:00 am in the morning or after 9:00 pm at night. Try to avoid mealtimes. Be aware of time differences when calling someone long distance. After someone answers the phone, the caller should give his or her name before asking for the person desired. When you talk on the telephone, remember your voice quality and express yourself clearly and concisely . The person at the other end of the phone cannot see your facial expressions or gestures and the impression he receives depends on what she hears. The telephone carries your voice at its natural volume and pitch. Try not to shout but speak clearly and distinctly. Make sure of the correct number so as not to risk disturbing strangers. Make sure that your conversations with busy people are as brief as possible. Time your calls so as not to interfere with the work schedule of those you call. Make business calls well before the close of the office hours. After dialing a wrong number simply say, “Sorry, wrong number.” When the number you are calling is not answered quickly, wait long enough for someone to put aside what he or she is doing. It is very annoying to have been disturbed just to pick up the telephone and find the caller has hung up.');
INSERT INTO badge_optional_requirements VALUES(3240,242,10,'Learn audience etiquette, such as: Go easy with perfume and cologne as many people are allergic. Unwrap all candies and cough drops before the curtain goes up, the movie starts, or the concert begins. Make sure cell phones and smart watches are off or on silent mode. Don’t wear jewelry such as bangle bracelets that make noise. Don’t text or take phone calls during a performance. If you must respond, do so in the hallway or elsewhere outside of the venue. The overture is part of the performance. Please cease talking at this point. Do not speak with your neighbor, when you lean your heads together, you block the view of the person behind you. Leaning forward also blocks the view. Do not talk, or hum, or sing along, or beat time with a body part. Force yourself to wait for a pause or intermission before rifling through a purse, backpack, or shopping bag. While the parking lot gets busy and public transportation is tricky, leaving while the show is in progress is discourteous.');
INSERT INTO badge_optional_requirements VALUES(3241,242,11,'Learn the etiquette of slang. There is a time and a place for the use of slang, but in most cases its use is not only inappropriate, but questions your credibility. You want people to view you as intelligent and if you are too lazy to use language properly, why would others assume you are capable of it? Use of slang gives the appearance of informality and suggests a degree of personal familiarity that is inappropriate with elders or in a formal situation. It is quite rude to use slang in front of others who may not be familiar with the terms. It is much like speaking another language and expecting someone to be able to understand you. Only use slang in the company of close friends who understand what the terms mean. Make a list of all the slang words you use every day. Next to each word, write a better word that you could use instead (it must be found in a dictionary!). If possible, come up with several synonyms for each word. For fun, when you are finished, show your list to your parents and see how many of the slang words they knew the meaning of.');
INSERT INTO badge_optional_requirements VALUES(3242,242,12,'Learn about “netiquette,” also known as etiquette on the Internet, such as: Always be polite. You are communicating with a live person, not a computer screen and they have feelings. When you type in all capital letters, it is the equivalent of shouting. Alternating between capital letters and lowercase letters unnecessarily is typically read as mocking and rude. Remember that the person on the other end cannot hear your tone of voice, all they can do is read your words. Make sure that your text does not come off mean, or rude, without intention. Be careful not to use rude or bad language online. Many providers will terminate your account, not to mention, it is simply not nice. Don’t break any laws. When you’re on the net, follow the same rules of behavior that you would in real life. Remember, if it is against the law in the real world, it is against the law in cyberspace. When emailing, be brief whenever possible. No one wants to read through a lot of unnecessary information. If you are replying to an e-mail, try editing out unimportant information and anything that is repeated. Don’t send rude or offensive e-mails or postings. If someone says something rude about you, do not respond, instead, notify a parent, teacher, or other adult. Watch your spelling and grammar. If you will be writing a lot of text, break it up into paragraphs to keep it manageable. Do not use texting abbreviations in an email or other writing. Check you emails regularly so that you can respond in a timely manner. Don’t send confidential information in an email as others may be able to access it. If you write a message while you are upset, wait at least 24 hours before sending it. Once it is gone, you can’t take it back. Never share someone’s email address or other information without their permission. Always fill in the subject line of an email so that people know what to expect Remember that the Internet lasts forever. Even if you think something is deleted, it doesn’t mean it has disappeared.');
INSERT INTO badge_optional_requirements VALUES(3243,242,13,'Learn proper tea etiquette and hold a tea party for the younger children to teach them some etiquette tips.');
INSERT INTO badge_optional_requirements VALUES(3244,242,14,'Learn business etiquette, such as: Always be punctual to work. It is better to arrive slightly early than to run late. Plan time for unexpected occurrences, like traffic or construction. People may feel that if you can’t be trusted not to embarrass yourself in business and social situations, you may lack the self-control necessary to be good at what you do. Etiquette is about presenting yourself with the kind of polish that shows you can be taken seriously. Etiquette is also about being comfortable around people (and making them comfortable around you!). Superiors: The only thing you owe your boss above and beyond what you owe peers and subordinates, such as politeness and consideration, is more information. Unobtrusively be sure he or she knows what you’re doing, is alerted as early as possible to issues that may arise, and is aware of outcomes and milestones. Never surprise your boss. It goes without saying that you should speak well of him or her within and outside the company, and give him or her the benefit of the doubt (Which you would do for anyone, of course!). The Phone: Always return calls. Even if you don’t yet have an answer to the caller’s question, call and explain what you’re doing to get the requested information, or direct them to the appropriate place to get it. When you initiate a call and get a receptionist or secretary, identify yourself and tell them the basic nature of your call. That way, you’ll be sure you’re getting the right person or department and the person you’re trying to reach will be able to pull up the appropriate information and help you more efficiently. When you’re on the receiving end of a phone call, identify yourself and your department. Answer the phone with some enthusiasm or at least warmth, even if you are being interrupted, because the person on the other end doesn’t know that! Personalize the conversation. Many people act in electronic media (including phone, phone mail, and e-mail) the way they act in their cars. They feel since they’re not face-to-face with a person, it is perfectly acceptable to be abrupt, crass, or rude. Make best use of the advantages of these media without falling headfirst into the disadvantages. Interruptions: Always apologize if you must interrupt a conversation, meeting, or someone’s concentration on a task. Quickly state the nature of what you need, and show consideration for the fact that you are interrupting valuable work or progress. Appreciation/Credit : Always pass along credit and compliments to everyone who made a contribution to the effort. Speak well of your coworkers and always point out their accomplishments to any interested party. Appearing to have taken the credit in a superiors’ or customers’ eyes is the surest way to sabotage a relationship with a coworker. Dress/Appearance : It can be insulting to your coworkers or clients to show a lack of concern about your appearance. Being wrinkled, unshaven, smelly or unkempt communicates (intentionally or not) that you don’t care enough about the situation, the people or the company to present yourself respectably. If in doubt, always err on the side of conservative. If you think jeans may be OK for a social event but aren’t sure, opt for a nice pair of slacks or a skirt and blouse. Always err on the side of conservative and dressy. Always practice impeccable grooming (even in a jeans environment!).');
INSERT INTO badge_optional_requirements VALUES(3245,242,15,'Learn etiquette for taking your dog out, such as: Clean up after your dog wherever you go. You do not let doggie poo pile up at home, so don’t do it on hiking trails, in a park, etc. Always have baggies handy to clean up your mess. Never let your dog relieve himself on someone else’s property. Do not let your dog bark at or chase cars, bicyclists, hikers, etc. Keep your dog in sight and under voice control at all times. Obey all leash laws. If you are walking on a trail where horses may be present, remember that every horse can be spooked, and even the best rider can be thrown. It is your responsibility to make sure that you and your dog are not the cause of such an event. For approaching horses, step to the side of the trail or get off it entirely and have your dog in a down-stay. Leash your dog if necessary to enforce the stay. Greet the riders. Even if they tell you their horses are okay with dogs, just tell them you are being extra cautious. Don’t let your dog jerk toward the horses as they pass you. Horses are herd animals that survived in the wild by running quickly away from any sudden unexplained motion that they saw out of the corner of their eye. The reaction is hard-wired into their nervous system, and you don’t want your dog to trigger it. If you are overtaking horses from behind (rare, but it can happen), let them know you are there in a conversational tone of voice, and let the riders know that you have a dog with you. Then let them figure out whether they’ll move aside on the trail or just stop until you are past. Don’t pass them until you get acknowledgment that they are ready for you. Regardless of how the riders handle it, leash your dog before approaching and passing the horses. More unpredictable than horses are bikes. With skill levels ranging from young children wobbling along with their parents to mountain bikers cycling at extreme speeds, you can’t count on any consistent behavior. Do not count on the posted rules of right-of-way (everyone yields to equestrians, cyclists yield to all other trail users). If you and your dog can get off to the side to let cyclists pass, it’s better for everyone. Above all, avoid the “clothesline”, when your leashed dog is sniffing bushes on one side of the trail and you are standing on the other-the rider can crash, your arm and wrist can be severely jerked, and your dog can be pulled right into the middle of the pile of falling bike and rider. Some people are scared to death of dogs. They get the same feelings when approached by a dog that you get hearing a rattlesnake buzz a foot from your leg. You can’t reason with emotional reactions, so just practice “defensive dog driving.” When approaching other people on the trails, keep your dog at heel. If your dog is running ahead of you, recall him. People with a fear of dogs will spook as easily as horses, so either leash your dog or keep him on his best behavior. Even if your dog has passed all obedience training courses, if someone asks you to leash your dog, comply cheerfully. Not all dogs are okay with other dogs. Talk to the owner before letting your dog approach another dog. Be aware that loose dogs may not be friendly to you and your pooch. Never get in the way of a dog fight.');
INSERT INTO badge_optional_requirements VALUES(3246,242,16,'Learn laundry room etiquette in apartments or dormitories, such as: If the laundry room is used by many tenants, then only use one washer at a time. However, if there are plenty of washers and most are not in use, then using 2-3 washers at the same time would be fine as long as there are other available machines. Using a laundry basket makes it easier to transport and transfer clothes. Leave the basket on top or in front of the washer so that if you are late in retrieving your clothes, the next person can remove your clothes and put them in your basket. Be prompt. Keep track of the wash time and return promptly transfer your wet clothes to a dryer. Keep track of the dry time and return promptly retrieve your clothes when they have finished drying. If the wash or dry cycle is finished for another person’s laundry, but the person has not returned, then put their clothes in their basket or on the counter if you need to use their machine. Clean the dryer lint trap when finished.');
INSERT INTO badge_optional_requirements VALUES(3247,242,17,'Learn etiquette for the gym or fitness club, such as: Bring a towel with you and wipe off equipment after use. Use disinfectant if it is available. Share equipment in between sets. Return equipment to its proper place. If listening to music, use headphones in order to not disturb others. Staying hydrated is important, but do not leave your water bottle laying around. Take it with you to the different stations. Turn cell phones off or put them on silent mode. Do not stare at others working out. Do not grunt loudly and avoid clanging of equipment. Wear clean workout clothes and have good personal hygiene. Keep conversations to a minimum, but if you must talk, do so quietly and be polite.');
INSERT INTO badge_optional_requirements VALUES(3248,242,18,'Learn about etiquette from another country. What are some of the main differences about what may be acceptable in the U.S. while insulting to someone of another culture?');
INSERT INTO badge_optional_requirements VALUES(3249,242,19,'Learn about ways that etiquette has effected behavior in different societies or time periods and create a booklet or poster about what you have learned.');
INSERT INTO badge_optional_requirements VALUES(3250,242,20,'Learn the etiquette of writing thank-you notes. Write three thank-you notes.');
INSERT INTO badge_optional_requirements VALUES(3251,242,21,'Learn proper etiquette for walking on roads, sidewalks, and trails. Which direction should you always be facing? Is it proper to ride a bike on a sidewalk?');
INSERT INTO badge_optional_requirements VALUES(3252,245,3,'What were the original furoshiki fabrics made from and what are the traditional measurement of furoshiki?');
INSERT INTO badge_optional_requirements VALUES(3253,245,4,'Make your own furoshiki wraps using repurposed fabrics.');
INSERT INTO badge_optional_requirements VALUES(3254,245,5,'Watch a video demonstrating different wraps.');
INSERT INTO badge_optional_requirements VALUES(3255,245,6,'Earn the Japanese or Korean culture badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3256,245,7,'Make a list of different fabric “gifts” you could repurpose for cloth wrapping, to wrap holiday or birthday gifts. For example, a silk scarf in Mom’s favorite color to wrap her new novel.');
INSERT INTO badge_optional_requirements VALUES(3257,245,8,'Go paperless for your next gift giving occasion. Teach your family how to fabric wrap and skip the wrapping paper this Christmas or on your next birthday.');
INSERT INTO badge_optional_requirements VALUES(3258,245,9,'Make a comparison chart showing the financial benefit of choosing furoshiki over wrapping paper.');
INSERT INTO badge_optional_requirements VALUES(3259,245,10,'Using a piece of plan fabric, decorate it using embroidery, paint, fabric pens etc. to create your own wrapping cloth and wrap something in it.');
INSERT INTO badge_optional_requirements VALUES(3260,245,11,'Earn the Upcycling badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3261,245,12,'Earn the Textile Design badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3262,246,3,'With a parent’s permission, watch an instructional video on how to apply face paint.');
INSERT INTO badge_optional_requirements VALUES(3263,246,4,'Learn about various careers that involve face painting or require your face to be painted for your profession.');
INSERT INTO badge_optional_requirements VALUES(3264,246,5,'Talk to someone who does face painting as a hobby or business and ask why they enjoy what they do.');
INSERT INTO badge_optional_requirements VALUES(3265,246,6,'Learn how to make homemade face paint.');
INSERT INTO badge_optional_requirements VALUES(3266,246,7,'Sketch ten designs you would like to be able to face paint on someone in the future.');
INSERT INTO badge_optional_requirements VALUES(3267,246,8,'Participate in a service project that involves face painting.');
INSERT INTO badge_optional_requirements VALUES(3268,246,9,'Research other materials that can be used for face painting, such as glitter, face paint stickers, etc.');
INSERT INTO badge_optional_requirements VALUES(3269,246,10,'Read a book about face painting.');
INSERT INTO badge_optional_requirements VALUES(3270,246,11,'Practice face painting on a rock or other round paint-able object, such as a balloon or melon.');
INSERT INTO badge_optional_requirements VALUES(3271,246,12,'After you have your face painted, create a costume to match your painted face.');
INSERT INTO badge_optional_requirements VALUES(3272,248,3,'Write a story about the fairies who live in a fairy garden. If you have a fairy garden, write a story about fairies who might live in your fairy garden.');
INSERT INTO badge_optional_requirements VALUES(3273,248,4,'Visit someone who owns a fairy garden. See what they created and learn how they created it.');
INSERT INTO badge_optional_requirements VALUES(3274,248,5,'Read an article about fairy gardens.');
INSERT INTO badge_optional_requirements VALUES(3275,248,6,'With the permission of an adult, view pictures of fairy gardens online using Pinterest or a search engine.');
INSERT INTO badge_optional_requirements VALUES(3276,248,7,'Make a piece of furniture such as a chair, bench, or stool for your fairy garden.');
INSERT INTO badge_optional_requirements VALUES(3277,248,8,'Make a birdhouse for your fairy garden.');
INSERT INTO badge_optional_requirements VALUES(3278,248,9,'Create a fairy garden in a non traditional container such as a basket, drawer, or glass jar.');
INSERT INTO badge_optional_requirements VALUES(3279,248,10,'Create a water feature in your fairy garden. This can be a pond, or you can use blue stones or something else to create the illusion of water.');
INSERT INTO badge_optional_requirements VALUES(3280,248,11,'Earn the Fairy badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3281,248,12,'Earn the Miniatures badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3282,248,13,'Create a fairy garden to give as a gift. Give it to someone to brighten their day.');
INSERT INTO badge_optional_requirements VALUES(3283,248,14,'Create an event where your friends, family, or another group creates their own fairy gardens.');
INSERT INTO badge_optional_requirements VALUES(3284,248,15,'Create a fairy garden with a store or other non-house building.');
INSERT INTO badge_optional_requirements VALUES(3285,248,16,'Create a fairy garden with an area for the fairies’ friends, such as mermaids, unicorns, chipmunks, or more.');
INSERT INTO badge_optional_requirements VALUES(3286,249,3,'Write a fairy tale of your own.');
INSERT INTO badge_optional_requirements VALUES(3287,249,4,'Perform a puppet show, play, or skit about a fairy tale.');
INSERT INTO badge_optional_requirements VALUES(3288,249,5,'Draw an illustration from your favorite fairy tale.');
INSERT INTO badge_optional_requirements VALUES(3289,249,6,'Participate in a community service project that revolves around fairy tales. You might hold a princess/prince party for younger kids, hold a fairy tale drive to collect toys to donate, or spend some time reading fairy tales to younger children at your local library.');
INSERT INTO badge_optional_requirements VALUES(3290,249,7,'Define the concept of a “fairy tale.” What common characteristics are usually found?  Read at least one fairy tale from at least three different countries. Discuss how their stories differ based on the culture they are from.');
INSERT INTO badge_optional_requirements VALUES(3291,249,8,'Watch a Disney or another animated fairy tale meant for children. Read the original story and compare. What changes were made to make the story better suited to small children? (This requirement should be done with older children or under the supervision of parents as some original fairy tales can get quite gruesome.)');
INSERT INTO badge_optional_requirements VALUES(3292,249,9,'Create a craft with a fairy tale theme.');
INSERT INTO badge_optional_requirements VALUES(3293,249,10,'Learn about a career that  involves fairy tales. Examples might include an illustrator, animator, author, party planner, costume designer, etc. What education do they need? What can they expect to get paid?  What hours do they work? Where might you have to live to have this career?');
INSERT INTO badge_optional_requirements VALUES(3294,249,11,'Learn about “fractured fairy tales.” A fractured fairy tale is a story that uses fairy tales you know and then changes the characters, the setting, points of view, or plots to make it humorous.  Read at least three fractured fairy tales and then write one of your own.');
INSERT INTO badge_optional_requirements VALUES(3295,249,12,'Create a costume for your favorite fairy tale character. If possible, dress up as this character for a party or event.');
INSERT INTO badge_optional_requirements VALUES(3296,249,13,'Host a fairy tale party.');
INSERT INTO badge_optional_requirements VALUES(3297,249,14,'Read the biography of a famous fairy tale author such as Hans Christian Anderson, the Brothers Grimm, Charles Perrault, or Alexander Afanasyev.');
INSERT INTO badge_optional_requirements VALUES(3298,250,3,'Draw a picture of what faithfulness means to you.');
INSERT INTO badge_optional_requirements VALUES(3299,250,4,'Write an essay about what faithfulness means to you.');
INSERT INTO badge_optional_requirements VALUES(3300,250,5,'Write a story or skit where faith plays an important role.');
INSERT INTO badge_optional_requirements VALUES(3301,250,6,'Read a biography about someone known for their faith.');
INSERT INTO badge_optional_requirements VALUES(3302,250,7,'What does your book of worship say about faithfulness? Memorize verses about faithfulness. Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(3303,250,8,'Memorize or write a poem about faith.');
INSERT INTO badge_optional_requirements VALUES(3304,250,9,'Find and memorize quotes about faith. Preschool: Memorize one quotes. Levels 1-2: Memorize three quotes. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(3305,250,10,'Walk through a place that helps you strengthen your faith. What items do you see that help you focus on your faith?');
INSERT INTO badge_optional_requirements VALUES(3306,250,11,'Using the Victorian Language of flowers, make a bouquet that symbolizes what faithfulness means to you. You can find the meanings assigned to the flowers at various websites or in books and you may cut pictures from magazines or webpages to create a collage or a bouquet. Make sure you include the name and meaning of each flower that you choose. You may make a scrapbook page using pictures of flowers or make a bouquet using real or artificial flowers. Please do not use the Internet without a parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(3307,250,12,'Write the word FAITHFULNESS on a piece of paper and then think of one faithful act that you could do that starts with each letter in the word. For example, you could put “Feed my pet every day” and you might put “Always be truthful.”');
INSERT INTO badge_optional_requirements VALUES(3308,251,3,'What does your book of faith say about family?');
INSERT INTO badge_optional_requirements VALUES(3309,251,4,'How are family members treated in different parts of the world? Choose at least three different countries with cultures different than ours to research. What role does each family member play in their culture?');
INSERT INTO badge_optional_requirements VALUES(3310,251,5,'Earn the Genealogy badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(3311,251,6,'Earn a Character badge that will help you in your family relationship such as Kindness, Patience, or Responsibility. Be able to explain why this character trait is important in a family.');
INSERT INTO badge_optional_requirements VALUES(3312,251,7,'Create a family scrapbook or family tree.');
INSERT INTO badge_optional_requirements VALUES(3313,251,8,'Make a list of your family traditions. These could be anything from what you eat on Sunday nights to how you celebrate holidays.');
INSERT INTO badge_optional_requirements VALUES(3314,251,9,'Pay attentions to the families you see on TV, in the movies, or in books you read. How are these families the same as yours? How are they different? Do you know anyone with families like these?');
INSERT INTO badge_optional_requirements VALUES(3315,251,10,'Have a family meeting to create a goals chart. Have each member of the family list a goal they want to reach within the next year and put it on the calendar. Then brainstorm all the necessary steps to reach that goal and put those tasks on the calendar as well. Use the calendar to hold each other accountable and help each member reach their goal.');
INSERT INTO badge_optional_requirements VALUES(3316,251,11,'Discuss what chores need to be done around your house and the capabilities of each family member to complete them. Then create a chore chart outlining each family member’s responsibilities for household chores.');
INSERT INTO badge_optional_requirements VALUES(3317,251,12,'Interview at least 10 people (non-related) about what family means to them. Is there something that all answers have in common? What stands out the most to you?');
INSERT INTO badge_optional_requirements VALUES(3318,251,13,'Participate in a community service project that revolves around family. Ideas might include food or clothing drives, suitcase drives for foster kids, serving dinner at a local homeless shelter, decorating a room at a battered women’s shelter, etc.');
INSERT INTO badge_optional_requirements VALUES(3319,251,14,'Create a family memory box. Have each member of your family write down as many happy family memories as they can and put each one on a small slip of paper. Put all the papers in a decorated box and pull one out each day to relive a happy memory.');
INSERT INTO badge_optional_requirements VALUES(3320,251,15,'Talk to seniors in your family or community about what family life used to be like. What household chores needed to be done? What did families do for recreation and fun?');
INSERT INTO badge_optional_requirements VALUES(3321,251,16,'Talk to your parents about your household budget. Find out what expenses your family has each month. How can you help your family reduce expenses to free up money for other things?');
INSERT INTO badge_optional_requirements VALUES(3322,251,17,'Interview at least 6 different parents. Find out what being a parent means to them. How did their lives change when they had kids? What is the hardest part about being a parent? What is the best part?');
INSERT INTO badge_optional_requirements VALUES(3323,252,3,'Draw a picture of your favorite fantasy creatures.');
INSERT INTO badge_optional_requirements VALUES(3324,252,4,'Write a story with one fantasy creature. Level 2 use two fantasy creatures, Level 3 use three, and Level 4 & 5 use four.');
INSERT INTO badge_optional_requirements VALUES(3325,252,5,'Do a craft that has to do with fantasy.');
INSERT INTO badge_optional_requirements VALUES(3326,252,6,'Cook one dish out of a fantasy cookbooks or from an online fantasy recipe.');
INSERT INTO badge_optional_requirements VALUES(3327,252,7,'Visit someone with a fantasy collection.');
INSERT INTO badge_optional_requirements VALUES(3328,252,8,'Watch a fantasy movie and review it. How many different fantasy creatures were in the movie?');
INSERT INTO badge_optional_requirements VALUES(3329,252,9,'(Preschool – Level 2 only) Write a few short paragraphs on what you like about fantasy and what fantasy means to you. (Level 3 – 5) Write an essay on this topic.');
INSERT INTO badge_optional_requirements VALUES(3330,252,10,'Design and make your own fantasy costume.');
INSERT INTO badge_optional_requirements VALUES(3331,252,11,'Participate in a community service project that involved fantasy. Ideas might include reading books to children at your local hospital or library, helping with a fantasy play, or holding a book drive.');
INSERT INTO badge_optional_requirements VALUES(3332,252,12,'(Level 3 – 5 only) Organize a fantasy story day at your local library.');
INSERT INTO badge_optional_requirements VALUES(3333,252,13,'Make a list of careers that use fantasy. Ideas might include artists, graphic designers, authors, actors, directors, or photographers. What type of education might you need for one of these careers?');
INSERT INTO badge_optional_requirements VALUES(3334,252,14,'Create and/or perform a fantasy play.');
INSERT INTO badge_optional_requirements VALUES(3335,253,3,'Visit a farm or ranch where your animal is raised. Be sure to follow all safety rules.');
INSERT INTO badge_optional_requirements VALUES(3336,253,4,'Learn how fur from your animal is sorted and graded.');
INSERT INTO badge_optional_requirements VALUES(3337,253,5,'Raise one of your animals to market weight.');
INSERT INTO badge_optional_requirements VALUES(3338,253,6,'Learn how to card and spin wool or fur into yarn.');
INSERT INTO badge_optional_requirements VALUES(3339,253,7,'Using a sketch of your animal, show where various cuts of meat come from.');
INSERT INTO badge_optional_requirements VALUES(3340,253,8,'Learn about different breeds of your animal and what each is best used for.');
INSERT INTO badge_optional_requirements VALUES(3341,253,9,'Learn about the history of your animal and their use in different cultures.');
INSERT INTO badge_optional_requirements VALUES(3342,253,10,'Learn how your animal is sheared and/or milked and watch it being done either in person or on video.');
INSERT INTO badge_optional_requirements VALUES(3343,253,11,'Read a book about your animal.');
INSERT INTO badge_optional_requirements VALUES(3344,253,12,'Participate in a service project that has something to do with your animal. Ideas include volunteering at the county fair, a local farm, etc.');
INSERT INTO badge_optional_requirements VALUES(3345,253,13,'Make a recipe from something that comes from your animal (meat, milk, eggs, etc.).');
INSERT INTO badge_optional_requirements VALUES(3346,253,14,'Make a craft from something that comes from your animal. Examples might include: A leather purse made from cow leather. Knitting an alpaca scarf. Sewing a wool jacket.');
INSERT INTO badge_optional_requirements VALUES(3347,253,15,'Find out where in the world your animal is raised. Which breeds are found in which countries?');
INSERT INTO badge_optional_requirements VALUES(3348,253,16,'Butterflies and up: Work on a farm where your animal is raised.');
INSERT INTO badge_optional_requirements VALUES(3349,253,17,'Visit a museum/educational facility that specialises in your animal.  Do they focus on raising the animal for food or using its wool/hide/hair?');
INSERT INTO badge_optional_requirements VALUES(3350,255,3,'Visit a farm and learn about the equipment needed to run it. (This requirement can be repeated if you visit different types of farms with different equipment.)');
INSERT INTO badge_optional_requirements VALUES(3351,255,4,'Dream up an invention for a new piece of farm equipment. What would it do? How would it do it? What would the machine look like? How would it be powered and operated?');
INSERT INTO badge_optional_requirements VALUES(3352,255,5,'Create a 3D model of a piece of farm equipment.');
INSERT INTO badge_optional_requirements VALUES(3353,255,6,'Participate in a service project that has something to do with farm equipment such as helping to raise funds to buy equipment for a community garden.');
INSERT INTO badge_optional_requirements VALUES(3354,255,7,'Learn how to use a piece of farm equipment.');
INSERT INTO badge_optional_requirements VALUES(3355,255,8,'Create a poster, website, or booklet to show what you have learned about farm equipment.');
INSERT INTO badge_optional_requirements VALUES(3356,255,9,'Learn how a piece of farm equipment runs. Understand how the motor operates, how the moving parts work, etc.');
INSERT INTO badge_optional_requirements VALUES(3357,255,10,'How much does farm equipment cost? Create a realistic budget for an imaginary farm. How much money would you need to purchase the basic equipment needed to run your type of farm. Which pieces of equipment would be nice to have, but are not necessary and may be eliminated if the budget gets too tight? Third Party Resources: Wikipedia: List of Agricultural Machinery');
INSERT INTO badge_optional_requirements VALUES(3358,256,3,'Choose an imaginary or real special occasion for which you would like to design an outfit for yourself and a special person of your choice. You will be choosing two outfits of the same fabric. Decide whether the occasion will be outdoors, in your house, or in a special building and whether this occasion will be during the winter or summer. Draw pictures of how you’d like the outfits to look or you can take pictures from clothing catalogs or magazines. If you choose the illustrations on the front of a pattern or from another printed source, you will need to change one thing about the outfits. It can be as simple as a different collar. Go to the fabric store (unless you have something at home that you like) and get a swatch of fabric that you would like to use to make the outfits. Explain anything in your illustrations that isn’t obviously the way you want it.');
INSERT INTO badge_optional_requirements VALUES(3359,256,4,'Do the same thing as requirement 3, but design the outfits for yourself and a child.');
INSERT INTO badge_optional_requirements VALUES(3360,256,5,'Read a book, take a virtual tour of a museum, or visit an exhibit of either historical clothing or ethnic garments. The exhibit should have at least ten outfits. Share what you have learned with family or friends.');
INSERT INTO badge_optional_requirements VALUES(3361,256,6,'Same as requirement 5, but the exhibit needs to be about theatrical costumes. The exhibit needs to have at least ten outfits.');
INSERT INTO badge_optional_requirements VALUES(3362,256,7,'Pretend that all your clothing disappeared overnight and someone gave you money to get a new wardrobe. Find pictures in catalogs or take some photos at a department store of five complete outfits for the school/work days in a week and at least one special occasion outfit. If you have a hobby such as ice skating, playing softball, or riding horses, be sure to include an outfit for that. Don’t forget a jacket for winter and swimsuit for summer. See if you can find shoes that are versatile enough to go with all the outfits you’ve chosen for weekdays. Find out what ‘separates’ mean when people are talking about clothes. If some of your outfits are separates, try to choose ones that can be rearranged and matched with other things on your list.');
INSERT INTO badge_optional_requirements VALUES(3363,256,8,'Research fashion design schools in your country. Which school would be your top choice to attend and how much would it cost?');
INSERT INTO badge_optional_requirements VALUES(3364,256,9,'Earn the Accessories badge.');
INSERT INTO badge_optional_requirements VALUES(3365,256,10,'Find illustrations of at least  ten different types of shoe styles and make a poster identifying them. Examples might include: Mary Janes, pumps, tennis shoes, deck shoes, cowgirl/boy boots, hiking shoes, flip flops, or sandals.');
INSERT INTO badge_optional_requirements VALUES(3366,256,11,'Find illustrations of at least ten different types of hat styles and make a poster identifying them. Examples might include: cowboy hat, fedora, pill box, felt hat, visor, sun bonnet, baseball hat, etc.');
INSERT INTO badge_optional_requirements VALUES(3367,256,12,'Design one item from each of the following categories. Make sure that all the items coordinate with one and other: Outerwear: Jacket, coat, or sweater Tops: Shirt or blouse Bottoms: Pants, skirt, kilt, or shorts Shoes Accessories: handbags, belts, hats, watches, etc.');
INSERT INTO badge_optional_requirements VALUES(3368,256,13,'Attend a play or musical or watch a movie that has unusually good costumes. Be able to explain to someone else why the costumes were exceptional.');
INSERT INTO badge_optional_requirements VALUES(3369,256,14,'Attend a fashion show or spend at least two hours window shopping at clothing stores. Choose your favorite outfit for the day and be able to tell how one of the elements of design or one of the principles of design was used in that outfit.');
INSERT INTO badge_optional_requirements VALUES(3370,256,15,'Design a mix-and-match wardrobe for a weekend trip. Draw a minimum of three garments and a maximum of six. They do not need to be the same color or fabric, but they do all need to go well with each other. Design the accessories you think would go well with your outfits, a minimum of five and a maximum of ten.');
INSERT INTO badge_optional_requirements VALUES(3371,256,16,'Design a series of garments (minimum three) that are inspired by ethnic or historical fashions.');
INSERT INTO badge_optional_requirements VALUES(3372,256,17,'Learn some fashion vocabulary. Preschool: Learn two terms. Level 1: Learn four terms. Level 2: Learn six terms. Level 3: Learn eight terms. Level 4: Learn ten terms. Level 5: Learn twelve terms. Boat, jewel, décolleté, scoop, horseshoe, cowl, square, off the shoulder, sweetheart, and keyhole necklines Button-down, middy (sailor), Peter Pan, Chelsea, Bertha, Mandarin, band, crew neck, turtleneck, shawl, bow tie, stock and jabot collars Kimono, dolman, raglan, bishop, bell, cape, shirt, puff, cowl, petal, leg-o’-mutton, Juliette, and two-piece tailored sleeves Straight, A-line, flared, circular, knife pleated, box pleated, gathered, dirndl, gored, and wrap skirts.');
INSERT INTO badge_optional_requirements VALUES(3373,256,18,'Learn about different body styles and how clothing can make you more or less attractive. Are you high waisted? Bow legged? Extremely tall or extremely short? Find out what body style you have and what fashion styles look best on your body.');
INSERT INTO badge_optional_requirements VALUES(3374,256,19,'Read about at least three different famous fashion designers. What are they famous for?  Whose designs do you like the most and why?');
INSERT INTO badge_optional_requirements VALUES(3375,256,20,'Investigate careers in the apparel industry (designers, apparel manufacturing, retail management, fashion advertising, theatrical costumers, etc.). How much do they pay? Interview or shadow someone in the industry if possible.');
INSERT INTO badge_optional_requirements VALUES(3376,256,21,'Watch a fashion design documentary.');
INSERT INTO badge_optional_requirements VALUES(3377,256,22,'Organize a runway fashion show for your family, friends, or other group.');
INSERT INTO badge_optional_requirements VALUES(3378,256,23,'Help host a fashion design workshop or party, preferably for younger children. Make the party educational and fun.');
INSERT INTO badge_optional_requirements VALUES(3379,257,3,'Learn how hairstyles have changed through time. Choose three different hairstyles from the past and try them. Which did you like best? Which was the most comfortable? Did you find you could do them by yourself, or did you need someone to help you?');
INSERT INTO badge_optional_requirements VALUES(3380,257,4,'Talk to a family member about what fashions were like when they were your age. Did they like them? What was their favorite garment? Would they want to wear those fashions again?');
INSERT INTO badge_optional_requirements VALUES(3381,257,5,'Choose an unusual article of dress from the past, such as chopines, ruffs or panniers, and learn how and why it was worn, and when.');
INSERT INTO badge_optional_requirements VALUES(3382,257,6,'Color a small coloring book of fashions from a specific era of history, such as the 1970’s or the Victorian era.');
INSERT INTO badge_optional_requirements VALUES(3383,257,7,'Learn how jewelry has changed over the centuries. OR, earn the Jewelry Through Time badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3384,257,8,'Make an accessory that was worn in the past, such as an Egyptian collar out of string and card. Paint or glue on the ‘jewels’.');
INSERT INTO badge_optional_requirements VALUES(3385,257,9,'Visit a museum that includes exhibits of clothing from another era.');
INSERT INTO badge_optional_requirements VALUES(3386,257,10,'During World Wars I and II fabric was in short supply so it was rationed. This meant that you could only have so much each per time. Find some pictures of the type of clothes that were worn during those time periods. Would you like to have worn them? What was this type of fashion called?');
INSERT INTO badge_optional_requirements VALUES(3387,257,11,'Learn about a famous person who has set fashion trends, such as Princess Diana, Kate Middleton, Audrey Hepburn, Beau Brummel or Marie Antoinette. What trends or fashions did they introduce?');
INSERT INTO badge_optional_requirements VALUES(3388,257,12,'Explore how shoes have changed over the years, OR earn the Shoes badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3389,257,13,'Read a non-fiction book about the history of fashion.');
INSERT INTO badge_optional_requirements VALUES(3390,257,14,'Research careers to do with fashion history, such as a museum curator or a costume designer specializing in period films.');
INSERT INTO badge_optional_requirements VALUES(3391,257,15,'Learn about the history of hats. How have they changed over the centuries? Learn about proper hat etiquette for both men and women. OR earn the Hats badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3392,257,16,'Learn about a famous fashion designer who greatly influenced changes in fashion, such as Coco Chanel, Jean Paul Gaultier or Elsa Schiaparelli.');
INSERT INTO badge_optional_requirements VALUES(3393,257,17,'In the past clothing and fabrics were regulated by a person’s place in society. For instance, in many places during the Middle Ages servants were not allowed to wear clothes like the ones their masters wore. Only royalty could wear purple. In Ancient Rome, women were not allowed to wear togas. Make a list of as many different clothing restrictions like these as you can find.');
INSERT INTO badge_optional_requirements VALUES(3394,257,18,'Learn what at least 20 of the following terms means: Aigrette A-Line Batwing Bell-bottoms Bloomers Bodice Bodysuit Bustier Bustle Cap-sleeves Capsule wardrobe Combinations Dirndl Empire line Fantail Fishtail Frou-frou Girdle Hobble skirt Jumpsuit Neckline Oxford bags Pedal-pushers Pencil skirt Pin-tuck Plus-fours Princess Line Raglan Ra-ra skirt Sarong Sash Skirt Slashing Stays Tabard Tea-gown Train Veil Waspie Wimple');
INSERT INTO badge_optional_requirements VALUES(3395,257,19,'Earn the Formal Wear badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3396,257,20,'Learn about the undergarments were worn beneath historical clothes. Learn to identify a chemise/shift, stockings, combinations, pantaloons, garter, corset, corset cover, camisole, petticoat, bustle cage, crinoline and bust bodice. How has underwear changed over the years? When did the practice of wearing “underwear” as “outerwear” become popular?');
INSERT INTO badge_optional_requirements VALUES(3397,257,21,'Make a costume from history for yourself, a younger child or a doll.');
INSERT INTO badge_optional_requirements VALUES(3398,257,22,'Learn about how sports-wear has changed over the years, for instance, men’s hunting clothes, ladies riding habits, etc. Are there any elements that are still included in today’s sportswear?');
INSERT INTO badge_optional_requirements VALUES(3399,257,23,'Throughout the years, new pigments and dyes have been created and manufactured. When were colors that we nowadays take for granted first used? What were popular or fashionable colors at various points through history?');
INSERT INTO badge_optional_requirements VALUES(3400,257,24,'Pick an era of fashion, and then design a dress that incorporates at least one aspect of that era – for instance, for the 1810s, you might choose an empire waistline, for the 1890s a large crinoline skirt, or a draped bodice from the 1930s.');
INSERT INTO badge_optional_requirements VALUES(3401,257,25,'Up until the late 1700s, menswear was a lot more ornate than women’s, but after 1800 the women started to wear more ornate clothes. What caused the switch?');
INSERT INTO badge_optional_requirements VALUES(3402,257,26,'Men’s clothes have undergone lots of changes over the years. Look at several examples of gentlemen’s attire throughout history. Which era did you like best?');
INSERT INTO badge_optional_requirements VALUES(3403,257,27,'There have been several famous dresses through history. Choose one and learn about how it was constructed. Where and when was it made? Who wore it? Draw a picture of your chosen dress.');
INSERT INTO badge_optional_requirements VALUES(3404,258,3,'Create your own fast food restaurant complete with name, logo and menu including healthy and less healthy options.');
INSERT INTO badge_optional_requirements VALUES(3405,258,4,'Compare fast food menus from at least three different restaurants and see how many healthy options are available.  What could you order at each restaurant that would make a healthy meal?');
INSERT INTO badge_optional_requirements VALUES(3406,258,5,'Watch a documentary or video about the fast food industry and summarize what you learned.');
INSERT INTO badge_optional_requirements VALUES(3407,258,6,'Learn the history of a major fast food chain such as McDonald’s or Taco Bell.');
INSERT INTO badge_optional_requirements VALUES(3408,258,7,'Compare how fast food is packaged and discuss environmental impacts like waste and recycling.');
INSERT INTO badge_optional_requirements VALUES(3409,258,8,'Make a homemade version of your favorite fast food item and compare the taste and ingredients.');
INSERT INTO badge_optional_requirements VALUES(3410,258,9,'Identify preservatives or additives often found in fast food and research what they do.');
INSERT INTO badge_optional_requirements VALUES(3411,258,10,'Interview someone who works in fast food and ask what their job is like.');
INSERT INTO badge_optional_requirements VALUES(3412,258,11,'Calculate how much money you would spend eating out at fast food restaurants daily for one week versus cooking at home.');
INSERT INTO badge_optional_requirements VALUES(3413,258,12,'Research how fast food has influenced food culture in other countries.');
INSERT INTO badge_optional_requirements VALUES(3414,258,13,'Create an advertisment for a fast food restaurant (real or made up) in either print or video.');
INSERT INTO badge_optional_requirements VALUES(3415,258,14,'Learn about the technology used in modern fast food restaurants (ordering kiosks, apps, robots, etc.).');
INSERT INTO badge_optional_requirements VALUES(3416,258,15,'Design a healthier version of a popular fast food meal.');
INSERT INTO badge_optional_requirements VALUES(3417,258,16,'Explore the rise of plant-based options in fast food restaurants. When did restaurants start offering plant based options?  Look at the menus of at least three different fast food restaurants and list their plant based food items. Try one if possible.  Compare the plant based options at McDonalds in America to the plant based options at McDonalds in Germany.  Why do you think there is such a large difference?');
INSERT INTO badge_optional_requirements VALUES(3418,258,17,'Learn the average calories in common fast food meals and how they compare to daily recommended amounts.');
INSERT INTO badge_optional_requirements VALUES(3419,258,18,'Study how portion sizes have changed over the past 50 years in the fast food industry.');
INSERT INTO badge_optional_requirements VALUES(3420,258,19,'Research how fast food affects health when eaten frequently over time.');
INSERT INTO badge_optional_requirements VALUES(3421,258,20,'Create a board game or trivia game about fast food history, facts, and nutrition.');
INSERT INTO badge_optional_requirements VALUES(3422,258,21,'Learn how drive-thrus work and how they’ve changed how people eat.  Where and when was the first drive thru restaurant created?');
INSERT INTO badge_optional_requirements VALUES(3423,258,22,'Visit three different fast food restaurants and compare their kids’ meals.');
INSERT INTO badge_optional_requirements VALUES(3424,258,23,'Track how much money you or your family spends on fast food in one month.');
INSERT INTO badge_optional_requirements VALUES(3425,258,24,'Learn what “ultra-processed food” means and see how much of it is in typical fast food meals.');
INSERT INTO badge_optional_requirements VALUES(3426,258,25,'Learn about the history of fast food and create a timeline of important events.  Check out our blog post 9 Fun timeline Activities to Make History Come Alive.');
INSERT INTO badge_optional_requirements VALUES(3427,258,26,'Analyze the economic impact of a fast food restaurant opening in a small community, considering employment, competition with local businesses, and community health.');
INSERT INTO badge_optional_requirements VALUES(3428,258,27,'Research how fast food restaurants are trying to become more eco-friendly.');
INSERT INTO badge_optional_requirements VALUES(3429,258,28,'Identify the cultural origins of popular fast food items like hamburgers, tacos, or pizza.');
INSERT INTO badge_optional_requirements VALUES(3430,258,29,'Learn about careers in the fast food industry beyond entry-level positions.');
INSERT INTO badge_optional_requirements VALUES(3431,258,30,'Learn how fast food affects energy, mood, and physical performance in the short term.');
INSERT INTO badge_optional_requirements VALUES(3432,259,3,'Read about or watch a video on felt making.');
INSERT INTO badge_optional_requirements VALUES(3433,259,4,'Producers have learned how to make an artificial felt. What are some of the differences between artificial and wool felt?');
INSERT INTO badge_optional_requirements VALUES(3434,259,5,'How is felt used in the automotive industry?');
INSERT INTO badge_optional_requirements VALUES(3435,259,6,'How is it used in making musical instruments?');
INSERT INTO badge_optional_requirements VALUES(3436,259,7,'Hat makers used to be called “Mad Hatters.” Why?');
INSERT INTO badge_optional_requirements VALUES(3437,259,8,'What are different ways to use felt in crafts?');
INSERT INTO badge_optional_requirements VALUES(3438,259,9,'What is a textile? Why does felt differ from fabric?');
INSERT INTO badge_optional_requirements VALUES(3439,259,10,'Make a felt board. Make small cutouts and write a story. Tell your story to some small children.');
INSERT INTO badge_optional_requirements VALUES(3440,259,11,'Many fabrics are woven. Felt is not. Is felt strong enough to use for clothing?');
INSERT INTO badge_optional_requirements VALUES(3441,259,12,'What is the difference between “felting” and “fulling?”');
INSERT INTO badge_optional_requirements VALUES(3442,259,13,'What is the process used for dying felt?');
INSERT INTO badge_optional_requirements VALUES(3443,259,14,'Make a piece of felt using an animal fur.');
INSERT INTO badge_optional_requirements VALUES(3444,259,15,'Learn about the history of felt and the role it has played throughout time.');
INSERT INTO badge_optional_requirements VALUES(3445,259,16,'Learn about needle felting and try this technique.');
INSERT INTO badge_optional_requirements VALUES(3446,260,3,'Watch a movie or documentary about feral horses.');
INSERT INTO badge_optional_requirements VALUES(3447,260,4,'Learn about one founder of Natural Horsemanship (Monti Roberts for example) and how observing feral horses influenced their training methods.');
INSERT INTO badge_optional_requirements VALUES(3448,260,5,'Learn about an organization that studies/helps or manages feral horse populations.');
INSERT INTO badge_optional_requirements VALUES(3449,260,6,'Help a feral horse organization by either volunteering, donating, sponsoring, adopting, becoming a member, spreading awareness, etc.');
INSERT INTO badge_optional_requirements VALUES(3450,260,7,'Do a fundraiser for an organization that helps feral horses.');
INSERT INTO badge_optional_requirements VALUES(3451,260,8,'Visit a place where feral horses live and observe them.');
INSERT INTO badge_optional_requirements VALUES(3452,260,9,'Learn about the history of the American Mustang.');
INSERT INTO badge_optional_requirements VALUES(3453,260,10,'In what other countries do feral horses live? What are they called? Are they threatened?');
INSERT INTO badge_optional_requirements VALUES(3454,260,10,'Learn about equine ethology and how research on feral horses have helped us understand and care for domestic horses.');
INSERT INTO badge_optional_requirements VALUES(3455,260,11,'Mustangs are a symbol of freedom in the USA. Find out how they have influenced art by finding paintings or poems about them. You can even try making your own drawing, painting or writing about them.');
INSERT INTO badge_optional_requirements VALUES(3456,260,12,'Create a list of feral horse breeds found in the United States.  Where did these breeds originate?');
INSERT INTO badge_optional_requirements VALUES(3457,260,13,'What is the Bureau of Land Management (BLM) and what role do they play in the lives of feral horses?');
INSERT INTO badge_optional_requirements VALUES(3458,260,14,'What laws are there regarding feral horses?');
INSERT INTO badge_optional_requirements VALUES(3459,260,15,'What is a “freeze mark” and how is it used for feral horses?');
INSERT INTO badge_optional_requirements VALUES(3460,263,3,'Explain the hunting laws in your state and county, including seasons, limits, and restrictions on any firearm types.');
INSERT INTO badge_optional_requirements VALUES(3461,263,4,'Safely shoot a target.');
INSERT INTO badge_optional_requirements VALUES(3462,263,5,'Explain how hunting is related to the wise use of renewable wildlife resources.');
INSERT INTO badge_optional_requirements VALUES(3463,263,6,'Describe how you should react if a friend visiting your home asked to see you or your family’s firearm(s).');
INSERT INTO badge_optional_requirements VALUES(3464,263,7,'Make a poster about firearm safety. Present it to a group of your choice.');
INSERT INTO badge_optional_requirements VALUES(3465,263,8,'Learn about the history of your firearm.');
INSERT INTO badge_optional_requirements VALUES(3466,263,9,'Visit a gun shop and learn about the different firearms available, their uses, and what types of cases and safes are available to safely store a firearm.');
INSERT INTO badge_optional_requirements VALUES(3467,263,1,'o. Make a list of careers where firearm handling would be part of the job.  If possible, interview someone with one of these jobs or shadow them for a day.');
INSERT INTO badge_optional_requirements VALUES(3468,263,11,'Go to a competition for your type of firearm.');
INSERT INTO badge_optional_requirements VALUES(3469,263,9,'Visit a gun shop and learn about the different firearms available, their uses, and what types of cases and safes are available to safely store a firearm.');
INSERT INTO badge_optional_requirements VALUES(3470,263,1,'o. Make a list of careers where firearm handling would be part of the job.  If possible, interview someone with one of these jobs or shadow them for a day.');
INSERT INTO badge_optional_requirements VALUES(3471,263,11,'Go to a competition for your type of firearm.');
INSERT INTO badge_optional_requirements VALUES(3472,265,3,'Describe what action you would take for someone who shows signs of shock, of a heart attack and of a stroke. What conditions must be present before performing CPR on a person? Obtain certification in CPR (Cardiopulmonary Resuscitation).  What is in AED (automated external defibrillator)? How and when should it be used?');
INSERT INTO badge_optional_requirements VALUES(3473,265,4,'Describe what to do in the following scenarios: One of your friends falls from a tree, blood is gushing from her arm and her lower leg looks broken. A summer hiker is pale, nauseous, complaining of a headache, and their breathing is fast and shallow. A ball hits your friend in the face and his nose begins to bleed. While camping you receive several mosquito bites on your arms and legs.');
INSERT INTO badge_optional_requirements VALUES(3474,265,5,'Identify signs of shock.  Demonstrate appropriate first aid measures for shock.');
INSERT INTO badge_optional_requirements VALUES(3475,265,6,'A bandana can be used for a variety of first aid purposes. Demonstrate how to use a bandana as a sling, to stop bleeding, to cool off an over heated person, or to stabilize a twisted ankle.');
INSERT INTO badge_optional_requirements VALUES(3476,265,7,'Explain when and why an injured person should not be moved. If an injured person must be moved describe how you would decide the best method. Demonstrate (with a “victim” weighing less than you) a chair carry, a two-man carry, and how to improvise a stretcher.');
INSERT INTO badge_optional_requirements VALUES(3477,265,8,'Look into a career where first aid is important. Ideas might include teachers, lifeguards, police, fire fighters, EMT, or day care provider. What first aid training is required for their job? What types of injuries/illnesses are most common in that profession?');
INSERT INTO badge_optional_requirements VALUES(3478,265,9,'Take a first aid certification course.');
INSERT INTO badge_optional_requirements VALUES(3479,265,10,'Take a CPR course.');
INSERT INTO badge_optional_requirements VALUES(3480,265,11,'Take turns with your family, friends, or club members where someone is playing a “victim” (they decide what kind of ailment they are suffering from or what kind of accident they have been in). They can be conscious or unconscious. Assess them and try to figure out what medical attention they may need based on what they describe or what kind of scenario is taking place.');
INSERT INTO badge_optional_requirements VALUES(3481,265,12,'Describe the signs of a concussion.  Explain the importance of seeking medical attention for head injuries.');
INSERT INTO badge_optional_requirements VALUES(3482,265,13,'Identify the signs of heat exhaustion, heatstroke, hypothermia, and frostbite.  Demonstrate appropriate first aid measures for each.');
INSERT INTO badge_optional_requirements VALUES(3483,265,14,'Identify common household poisons.  Demonstrate appropriate first aid for poisoning.  Know the number for the Poison Control Center and why it is important to call them if you think someone has been poisoned.');
INSERT INTO badge_optional_requirements VALUES(3484,265,15,'Identify common insects and spiders that may cause harm.  Demonstrate proper first aid for insect bites and stings.');
INSERT INTO badge_optional_requirements VALUES(3485,265,16,'Understand the legal and ethical responsibilities of a first aider.  Find out of your state has a “good samaritan” law.');
INSERT INTO badge_optional_requirements VALUES(3486,265,17,'Learn the principles of triage in mass casualty situations.  Participate in a simulated mass casualty incident, prioritizing patients for care.');
INSERT INTO badge_optional_requirements VALUES(3487,265,18,'Know the signs and symptoms of a severe allergic reaction such as those from bee stings or peanut allergies.  Understand when and how to use an EpiPen for severe allergic reactions.  Demonstrate the proper administration technique on a training device.');
INSERT INTO badge_optional_requirements VALUES(3488,265,19,'Participate in a full-scale first aid simulation drill.');
INSERT INTO badge_optional_requirements VALUES(3489,266,3,'Attend a parade, political rally, celebration, or other gathering where you get to see a First Lady or former First Lady. If you cannot actually attend an event, watch it on TV or the internet (with a parent’s permission). How many First Ladies are still alive today?');
INSERT INTO badge_optional_requirements VALUES(3490,266,4,'Be able to identify by portrait the First Ladies you learned about in Preschool requirement 1. Preschool and Level 1: Identify two. Levels 2-3: Identify five. Levels 4-5: Identify seven. This requirement can be repeated for each First Lady chosen.');
INSERT INTO badge_optional_requirements VALUES(3491,266,5,'Visit the birthplace, monument or home of a First Lady. This requirement can be repeated. This can be done online or with books if an actual visit cannot be arranged.');
INSERT INTO badge_optional_requirements VALUES(3492,266,6,'Tour the White House.');
INSERT INTO badge_optional_requirements VALUES(3493,266,7,'Write a report about a First Lady and share it with your family, friends, or group. This requirement can be repeated.');
INSERT INTO badge_optional_requirements VALUES(3494,266,8,'Research what the life of a First Lady is like.');
INSERT INTO badge_optional_requirements VALUES(3495,266,9,'Write to the First Lady to thank her or encourage her for something she did.');
INSERT INTO badge_optional_requirements VALUES(3496,266,10,'Learn if any of the First Ladies come from your home state. If so, how many? Learn the names of them all, if any (Preschool and Level 1, learn the name of one). Learn at least two specific facts about each one. If none are from your home state, research a state adjacent to yours or one that you wish to visit.');
INSERT INTO badge_optional_requirements VALUES(3497,266,11,'Research the changing ladies’ fashions throughout the history of the U.S. Presidency. Which First Ladies were known as trendsetters? Which did not follow current fashion trends?');
INSERT INTO badge_optional_requirements VALUES(3498,266,12,'Sketch a picture of your favorite First Lady.');
INSERT INTO badge_optional_requirements VALUES(3499,266,13,'Modern First Ladies choose from famous fashion designers for their Inaugural Ball dress. Research some of the last few First Ladies and their choices. Who did they choose, and why? What happens to the dresses after the Ball?');
INSERT INTO badge_optional_requirements VALUES(3500,266,14,'Find out who the First Lady was the year you were born. Did she accomplish or do anything important that year? Did anything significant happen?');
INSERT INTO badge_optional_requirements VALUES(3501,266,15,'When did the term “First Lady” come into common use? Where and when did it spread to other nations?');
INSERT INTO badge_optional_requirements VALUES(3502,266,16,'Who helps the First Lady in her role? What are some of the positions available?');
INSERT INTO badge_optional_requirements VALUES(3503,266,17,'What is the White House China collection? Who designs it? What is it used for?');
INSERT INTO badge_optional_requirements VALUES(3504,266,18,'Where is the First Ladies National Historic Site? Who operates it? What can be seen there? Visit it online or in person, if possible.');
INSERT INTO badge_optional_requirements VALUES(3505,267,3,'Learn about different poles used in your type of fishing. What is the difference in weight, length and material?');
INSERT INTO badge_optional_requirements VALUES(3506,267,4,'Learn about the different lures used in your style of fishing. Do you use top water baits, flies, live bait, spinner baits, plastic worms, etc. Look through different types of lures used for your style of fishing and learn to identify these lures. Preschool: Identify three. Level 1: Identify four. Level 2: Identify five. Level 3: Identify six. Level 4: Identify seven. Level 5: Identify eight.');
INSERT INTO badge_optional_requirements VALUES(3507,267,5,'Learn about different types of hooks including barbed, non-barbed, and treble. Learn about the difference size, weights, materials, and colors. Why is there such a variety? Why do you use the one you do?');
INSERT INTO badge_optional_requirements VALUES(3508,267,6,'Learn about different types of fishing line. How does the weight and material effect the fishing?');
INSERT INTO badge_optional_requirements VALUES(3509,267,7,'Learn how to effectively use weights and bobbers.');
INSERT INTO badge_optional_requirements VALUES(3510,267,8,'Learn about different ways to go fishing including out of a boat, along a bank, using waders, or a float tube. Choose one method and create a poster or booklet comparing three different choices. For example, you could compare three different fishing boats, or three different locations with good bank fishing.');
INSERT INTO badge_optional_requirements VALUES(3511,267,9,'Learn about the habitat and habits of the type of fish you fish for. What type of cover do they like? What temperature water do they prefer? What do they eat and when (if you are fly fishing, this is especially important)? What water depth are they usually at each time of year? How does weather affect them? The more you know about your fish, the better chance you have of catching one.');
INSERT INTO badge_optional_requirements VALUES(3512,267,10,'Learn about environmental issues in your area that effect fish. How can you help improve your local fisheries?');
INSERT INTO badge_optional_requirements VALUES(3513,267,11,'Participate in a community service project that involves fish. You may choose to help with a coastal cleanup, or even help plant cover in local lakes');
INSERT INTO badge_optional_requirements VALUES(3514,267,12,'Discuss the importance of catch and release and demonstrate how to properly catch and release a fish');
INSERT INTO badge_optional_requirements VALUES(3515,267,13,'Be able to identify the different parts of both your rod and reel and explain proper care and maintenance of your equipment.');
INSERT INTO badge_optional_requirements VALUES(3516,267,14,'Catch a fish, properly clean it, and cook it.');
INSERT INTO badge_optional_requirements VALUES(3517,267,15,'Learn to tie a fly, or make/modify  another type of lure.');
INSERT INTO badge_optional_requirements VALUES(3518,267,16,'Learn what it means to “match the hatch.” Visit a fishing location and look for insects. Look in the air, under the water, and under the rocks (watch out for snakes and biting insects). What type of insects are active right now? Do you have lures to match the current food source.');
INSERT INTO badge_optional_requirements VALUES(3519,267,17,'Explain the principles of Leave No Trace and how it affects fisheries.');
INSERT INTO badge_optional_requirements VALUES(3520,267,18,'Learn about careers that involve fishing. Examples might include professional fisher, working for department of fish and game, owning or working in a tackle shop, or being a fishing guide.');
INSERT INTO badge_optional_requirements VALUES(3521,267,19,'Demonstrate how to attach live bait. Explain why live bait should never be released. Why is live bait not allowed at some fisheries?');
INSERT INTO badge_optional_requirements VALUES(3522,268,3,'Learn the actual names of the muscles in the muscle group this game works. For example if this game works mostly legs, what are the muscles in the legs?');
INSERT INTO badge_optional_requirements VALUES(3523,268,4,'Learn at least three stretches that will help keep muscles limber for this type of game.');
INSERT INTO badge_optional_requirements VALUES(3524,268,5,'Know what type of equipment is needed for this game. Help get the equipment out and help put it away properly.');
INSERT INTO badge_optional_requirements VALUES(3525,268,6,'Design your own game using the equipment you needed for the original game, but that focuses on a different muscle group. For example if the original game focused on arm strength, how could you use the same equipment to strengthen your legs? Make sure to keep safety in mind.');
INSERT INTO badge_optional_requirements VALUES(3526,268,7,'Design your own game using the equipment you needed for the original game, but that focuses on a different type of fitness. For example if the original game was cardio based, how could you use the same equipment to create a strength based game? Make sure to keep safety in mind.');
INSERT INTO badge_optional_requirements VALUES(3527,268,8,'If this is an individual game, find a way to make it a team game. If it is a team game, find a way to turn it into and individual challenge.');
INSERT INTO badge_optional_requirements VALUES(3528,268,9,'Discuss what role sportsmanship has in this game. Is it easy to cheat? Hog the ball?  Say mean things? Why is it important to play fair, take turns, and congratulate someone who did a great job, or encourage someone who might not do so well?');
INSERT INTO badge_optional_requirements VALUES(3529,268,10,'Learn what other sports or activities the skills you learn in this game transfer to. For example, hand-eye coordination, strength, gross motor control, and the ability to track moving objects in the air transfer to sports and activities that involve flying objects, including balls, shuttlecocks, frisbees, ribbons, sticks, batons.');
INSERT INTO badge_optional_requirements VALUES(3530,268,11,'Learn how the exercises you learn in a particular game will help you stay healthy for your day to day activities. For example if the game focuses on cardio, be able to explain why you need a healthy heart and cardio endurance for a healthy lifestyle. If the game focuses on arm strength, when might you need that in everyday activities?');
INSERT INTO badge_optional_requirements VALUES(3531,268,12,'Learn about a career in fitness.');
INSERT INTO badge_optional_requirements VALUES(3532,268,13,'Participate in a community service project that involves fitness games. Example Games: Ship to Shore Equipment Needed: None Instructions: Choose one person to be IT. IT stands at the front of the group and calls out commands that the rest of the kids must do. If a child does the wrong action, or if it is an action that requires them to get into groups and there is a person without a group, then they are “out”.  While “out” kids must walk around the edges of game until either “Ship” or “Shore” are called, then everyone runs to the appropriate side of the playing field and everyone is back in the game.  The faster the commands are changed, the more exercise the kids will get. Some of the actions are: ‘Ship’ all kids run towards the ship (one side of the playing field). ‘Shore’ all kids run towards the shore (the opposite side of the playing field). ‘Man overboard’ 2 person action. One person gets down on hands and knees. The other person puts one foot on the back of the person on the ground and shades their eyes like they are looking into the distance for someone. ‘Crows nest’ 3 person action. 3 kids get together with their backs towards each other and lock arms. ‘Captain’s coming’. Each person must salute. kids can’t move from ‘captains coming’ until IT calls ‘at ease’. If a player moves, they are out. ‘At ease’. All kids put their hands at their sides and can continue when the next action is called. ‘Hit the deck’. All kids lay down on their bellies. ‘Three men in a boat’. 3 kids get together in a line and squat. They must act like they are rowing a boat while they sing “Row Row Row Your Boat”. ‘Octopus’. Kids must lay on their backs with their arms and feet waving in the air. Develops: Listening skills, cardio, strength, endurance, reaction time, and teamwork.  Skills transfer to sports such as soccer, basketball and football that require quick thinking, teamwork, long playing times and listening to the other players. Forts Equipment needed: Chairs Exercise mats Sheets Anything else you have that can be used as a support or cover. Instructions: Put all equipment in one corner of the room.  Have the kids work as a team to create a fort out of the materials on hand.  Now create various routes through and around the fort, adding obstacles to make it more difficult.  Play follow the leader through and around the fort or have races through a particular route and see how fast you can go.  Once you have exhausted the routes for one fort, tear it down and build another. Develops:  Teamwork, logic, strength, and flexibility.  These skills transfer to sports and activities such as weight lifting and rock climbing. Goal! Equipment needed: Large, soft foam ball with a diameter between three and five inches. Instructions: This is a partner game.  Start by having kids sit opposite each other on the floor with their legs spread in a V.   Roll the ball to your partner and get it between their legs for a “goal”.  Gradually get farther apart to increase difficulty.  Once kids have gone as far as they can.  Change to basket goals.  Have one person stand with hands and forearms forming a bowl or “basket” in front of his or her stomach. Toss the ball into the “basket” from about a foot away.  Increase the distance of your toss slightly each round.   What other objects can you use for the goal? To add a strength element, try having partners face each other in the “up” position of a push-up. They are spaced one to two feet apart. Each child tries to maintain the “up” position and score a goal by using one hand to push ball between his or her partner’s hands. A goal is scored each time the ball goes between the other child’s hands. Develops: Hand-eye coordination, strength, gross motor control, and the ability to track moving objects in the air. These skills transfer to sports and activities that involve flying objects, including balls, shuttlecocks, frisbees, and batons. Balloon Burst! Equipment needed: Lots of balloons Slips of paper A pen or pencil Instructions: Blow up balloons and scatter them on the floor.  Choose one person as the score keeper.  Players stand in scatter formation. On “GO”, the object is to break as many balloons as possible, by sitting on them! When a person breaks a balloon, he shouts “I SCORE!” and must put his hand in the air. The score-keeper then runs up to the person whose hand is in the air, and marks a point down on his tally sheet. The player then tries to break another balloon and earn more points. When all balloons are broken, scores are added up and a winner is declared. Variations: Break the balloons by putting them between the knees and squeezing them until they break. Burst balloon by squeezing it between two people. Develops:  Cardio and strength.  Skills transfer to sports and activities such as bicycle riding and soccer. Backyard Trash Equipment needed: Lots of crumpled up balls of newspaper Masking tape or rope. Instructions: Place a strip of masking tape or rope down the center of the playing field. Divide the kids into two teams and put half the newspaper balls on one side and half on the other.  On “Go!” both teams try to throw all their paper into the other teams “backyard.” The game is won when one team briefly has a yard free of trash. Develops: Cardio, strength, endurance, coordination and teamwork. Skills transfer to sports and activities such as running, bicycling, soccer, basketball and more.');
INSERT INTO badge_optional_requirements VALUES(3533,269,3,'Diagram the parts of an organ attached to one of the senses (this must be a different organ than the Levels 3-5 starred requirements.');
INSERT INTO badge_optional_requirements VALUES(3534,269,4,'Earn the Sign Language badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3535,269,5,'Research what causes deafness.');
INSERT INTO badge_optional_requirements VALUES(3536,269,6,'Play a game involving one or more of your senses.');
INSERT INTO badge_optional_requirements VALUES(3537,269,7,'Research what a Cochlea Transplant is and explain it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(3538,269,8,'Watch a movie about someone who was born without or lost one of the five senses. It can be a real person like Helen Keller in the Miracle Worker or a fictional character like Daredevil.');
INSERT INTO badge_optional_requirements VALUES(3539,269,9,'Write a Sense Poem.');
INSERT INTO badge_optional_requirements VALUES(3540,269,10,'Play a 5 Sense guessing game.  Describe an item using only your senses.  For example, it feels smooth, it tastes sweet, it smells minty.');
INSERT INTO badge_optional_requirements VALUES(3541,269,11,'Learn about Louis Braille and the Braille alphabet.');
INSERT INTO badge_optional_requirements VALUES(3542,269,12,'Make a painting of what you see (it can be a still life inside or a landscape outside).');
INSERT INTO badge_optional_requirements VALUES(3543,269,13,'Make a touch book or touch board with a variety of surface textures.');
INSERT INTO badge_optional_requirements VALUES(3544,269,14,'Blindfolded, how many objects can you identify?  Can you tell the difference between a pencil and a pen or a screw and a nail?  Now put on mittens and try again.');
INSERT INTO badge_optional_requirements VALUES(3545,269,15,'Have a blindfolded taste test with your family, friends, or group.  Chart the results.');
INSERT INTO badge_optional_requirements VALUES(3546,269,16,'Draw a tongue and label the locations for salt, bitter, sour and sweet.');
INSERT INTO badge_optional_requirements VALUES(3547,269,17,'Have a blindfolded smell test with your troop.  Make a list of which items were pleasant and which were not.  Were some smells pleasant to some people but not to others (like onions or spices)? Why?');
INSERT INTO badge_optional_requirements VALUES(3548,269,18,'Taste new food items. Preschool: Try two new foods. Level 1: Try three. Level 2: Try four. Level 3: Try five. Level 4: Try six. Level 1: Try seven. Levels 3 -5 must help prepare at least one of the new food items they taste.');
INSERT INTO badge_optional_requirements VALUES(3549,270,3,'Find out how many different Flat Stanley books there are and read  at least three of them.');
INSERT INTO badge_optional_requirements VALUES(3550,270,4,'What is the Flat Stanley Project? How can you participate?');
INSERT INTO badge_optional_requirements VALUES(3551,270,5,'Create your own “Flat Stanley” that looks like you.');
INSERT INTO badge_optional_requirements VALUES(3552,270,6,'Send your Flat Stanley to another Curiosity Untamed group, Quest Club, or Frontier Girls troop and ask them to send it back with a picture of your Flat Stanley at one of their meetings or activities with a letter about its adventures.');
INSERT INTO badge_optional_requirements VALUES(3553,270,7,'What is the Flatter World and how does it help teachers and students?');
INSERT INTO badge_optional_requirements VALUES(3554,270,8,'Learn about the Musical Adventures of Flat Stanley Broadway Jr. production and learn at least one song from it.');
INSERT INTO badge_optional_requirements VALUES(3555,270,9,'Find out how Flat Stanley has changed over the years since his creation in 1964.');
INSERT INTO badge_optional_requirements VALUES(3556,270,10,'Start a stamp collection of stamps from the places your Flat Stanley has visited.');
INSERT INTO badge_optional_requirements VALUES(3557,270,11,'Create a scrapbook of all of your Flat Stanley’s adventures.');
INSERT INTO badge_optional_requirements VALUES(3558,270,12,'Send your Flat Stanley adventuring to a new location and get pictures of it doing the following: Eating a food item specific to the location Visiting a special landmark Participating in home life');
INSERT INTO badge_optional_requirements VALUES(3559,270,13,'With permission from a parent, look at Flat Stanley pictures online and see where other Flat Stanley’s have traveled (even to the President of the United States!).');
INSERT INTO badge_optional_requirements VALUES(3560,270,14,'Send your Flat Stanley to a famous person and see if they will respond.');
INSERT INTO badge_optional_requirements VALUES(3561,270,15,'Read three news articles about Flat Stanley.');
INSERT INTO badge_optional_requirements VALUES(3562,270,16,'What type of curriculum for teachers integrates the concept of Flat Stanley?');
INSERT INTO badge_optional_requirements VALUES(3563,270,17,'With a parent’s permission, research what Flat Stanley Apps are available and what they do.');
INSERT INTO badge_optional_requirements VALUES(3564,270,18,'With a parent’s permission, explore Flat Stanley via social media such as following his adventures on Facebook or Instagram.');
INSERT INTO badge_optional_requirements VALUES(3565,272,3,'Learn to identify different types of flowers. Preschool: Identify five. Level 1: Identify seven.  Level 2: Identify ten.  Level 3: Identify fifteen.  Level 4: Identify twenty.  Level 5: Identify twenty-five.');
INSERT INTO badge_optional_requirements VALUES(3566,272,4,'Make a three bud vase.');
INSERT INTO badge_optional_requirements VALUES(3567,272,5,'Arrange fresh flowers in a vase.');
INSERT INTO badge_optional_requirements VALUES(3568,272,6,'Take a field trip to a florist shop.');
INSERT INTO badge_optional_requirements VALUES(3569,272,7,'Make a center piece for a table display');
INSERT INTO badge_optional_requirements VALUES(3570,272,8,'Make a bouquet and give it to someone.');
INSERT INTO badge_optional_requirements VALUES(3571,272,9,'Make a flower wreath.');
INSERT INTO badge_optional_requirements VALUES(3572,272,10,'Participate in a community service project involving flowers, such as bringing flowers to hospital patients or spending a day working in a flower garden.');
INSERT INTO badge_optional_requirements VALUES(3573,272,11,'Demonstrate how to make at least two different types of bows to decorate your arrangements.');
INSERT INTO badge_optional_requirements VALUES(3574,272,12,'Learn to identify and know the purpose of the following tools and supplies for flower arranging: Floral wire Wire cutters Floral foam Floral picks Floral tape Floral frog Candle cups Water picks Styrofoam forms Floral pins Glue gun Tulle');
INSERT INTO badge_optional_requirements VALUES(3575,272,13,'Make a corsage');
INSERT INTO badge_optional_requirements VALUES(3576,272,14,'Find out what careers there are in the flower industry. What education would be required? What pay could you expect? What hours would you be expected to work?');
INSERT INTO badge_optional_requirements VALUES(3577,272,15,'Volunteer to create flower arrangements for a specific event.');
INSERT INTO badge_optional_requirements VALUES(3578,273,3,'Create a small garden for a nursing home, school, or church.');
INSERT INTO badge_optional_requirements VALUES(3579,273,4,'Find at least three careers that involve the use of flowers. What education would you need for this career? What is the average pay and work schedule? If possible, shadow a person with one of these careers for a day.');
INSERT INTO badge_optional_requirements VALUES(3580,273,5,'Learn to identify flowers by scent. Preschool: Identify three. Level 1: Identify five.  Level 2: Identify eight.  Level 3: Identify ten.  Level 4: Identify twelve.  Level 5: Identify fourteen.');
INSERT INTO badge_optional_requirements VALUES(3581,273,6,'Visit your county extension agent’s office, a local university’s agricultural or horticultural department, or a botanical garden or arboretum. Report what you learned. Preschool-Level 2 may make a poster instead of writing a report.');
INSERT INTO badge_optional_requirements VALUES(3582,273,7,'Identify at least six flowers that are used for medicinal purposes. Can you grow any of these in your own garden?');
INSERT INTO badge_optional_requirements VALUES(3583,273,8,'Demonstrate your knowledge of at least three bulb flowers, three tree flowers, three wild flowers, and three garden flowers. Levels 3-4: Demonstrate your knowledge of six each. Level 5: Demonstrate your knowledge for nine each.');
INSERT INTO badge_optional_requirements VALUES(3584,273,9,'Identify at least six local flowers that are poisonous to people or animals.');
INSERT INTO badge_optional_requirements VALUES(3585,273,10,'Sketch, paint or photograph at least ten different flowers and create a display to show to your club or family.');
INSERT INTO badge_optional_requirements VALUES(3586,273,11,'Know what the terms annual, perennial and biennial mean and be able to identify at least three flowers from each group. Levels 3-4: Demonstrate your knowledge of six each. Level 5: Demonstrate your knowledge for nine each.');
INSERT INTO badge_optional_requirements VALUES(3587,273,12,'Weed someone’s garden for them.');
INSERT INTO badge_optional_requirements VALUES(3588,273,13,'Cut some flowers and make a bouquet  to give as a gift to someone. Help keep it fresh by wrapping the stems in wet paper towels and then in tin foil to keep it from leaking. Tie a pretty bow around them and you have a beautiful fresh bouquet.');
INSERT INTO badge_optional_requirements VALUES(3589,273,14,'Visit your garden after dark for at least a week noting what insects are visiting and which flowers are closed and which are open.');
INSERT INTO badge_optional_requirements VALUES(3590,273,15,'Learn six flowers that are edible, such as pansies and zucchini flowers. Find a recipe using one of these and prepare it to share with your club or family.');
INSERT INTO badge_optional_requirements VALUES(3591,273,16,'Enter a flower you grew into your local fair or other flower competition.');
INSERT INTO badge_optional_requirements VALUES(3592,274,3,'Learn about at least three countries that eat insects. What type do they eat? How are they usually prepared?');
INSERT INTO badge_optional_requirements VALUES(3593,274,4,'Learn about some of the culture in the countries you have tried food from.');
INSERT INTO badge_optional_requirements VALUES(3594,274,5,'Visit an ethnic restaurant and eat an entire meal.');
INSERT INTO badge_optional_requirements VALUES(3595,274,6,'Tour an ethnic restaurant or interview an ethnic chef.');
INSERT INTO badge_optional_requirements VALUES(3596,274,7,'Take a field trip to an ethnic market. How does it differ from the market you shop at?');
INSERT INTO badge_optional_requirements VALUES(3597,274,8,'Learn about at least five different cooking methods used around the world.  Examples might include BBQ, spit cooking, open fire cooking, boiling, pit cooking, bamboo steamers, banana leaf steaming, etc. Use one of these methods to cook a meal.');
INSERT INTO badge_optional_requirements VALUES(3598,274,9,'Learn about at least ten different cooking or eating tools and utensils used around the world. Examples might include: Chopsticks Formal Cutlery Mortar and Pestle Grinding Stone Teapot Clay or Brick Stoves Kabob sticks or skewers Injera (African bread used as a plate and utensil) Bamboo Mat');
INSERT INTO badge_optional_requirements VALUES(3599,274,11,'Learn about careers that involve food from around the world. Examples might include a chef, food critic, produce wholesaler, farmer, freight forwarder, etc.');
INSERT INTO badge_optional_requirements VALUES(3600,274,12,'Find out how foods are shipped to other countries. How do they keep them fresh? What forms of transportation do they use?');
INSERT INTO badge_optional_requirements VALUES(3601,274,13,'Look through cookbooks from at least five different countries. How does the food differ?');
INSERT INTO badge_optional_requirements VALUES(3602,274,14,'Make a list of ten of the strangest foods you can find that people eat around the world.');
INSERT INTO badge_optional_requirements VALUES(3603,274,15,'Watch a TV show or documentary about foods around the world.');
INSERT INTO badge_optional_requirements VALUES(3604,274,16,'Participate in a community service project that has something to do with food around the world. One idea is to sponsor a “Who’s Hungry?” night to teach your community about the lack of food around the world. Invite a group of people to dinner.  When they arrive randomly divide them into groups.  1/5 will receive a large dinner (spaghetti, roll, salad, milk), 3/5 will receive ½ cup of rice and a cup of broth, and the remaining 1/5 will receive a glass of water. This is a general summation of the hungry people in the world and how many actually have enough to eat. Get the statistics for your local community and combine your evening with a food drive for a local food bank.');
INSERT INTO badge_optional_requirements VALUES(3605,274,17,'Find out what the average family spends on food each year in at least five different countries. How do the totals differ? How does America compare?');
INSERT INTO badge_optional_requirements VALUES(3606,274,18,'Learn about traditional foods eaten at different weddings around the world. Pick three countries and compare what types of foods are traditionally served at weddings.');
INSERT INTO badge_optional_requirements VALUES(3607,274,19,'Make your own cookbook filled with recipes from at least ten different cultures.');
INSERT INTO badge_optional_requirements VALUES(3608,275,3,'What out of the ordinary containers can be used to present food in a new and interesting way?  For example some restaurants serve eggs and potatoes in a cast iron frying pan. Veggie sticks can be served in a hollowed out bell pepper. How many different containers can you come up with to serve different dishes?');
INSERT INTO badge_optional_requirements VALUES(3609,275,4,'Prepare and present a cheese platter');
INSERT INTO badge_optional_requirements VALUES(3610,275,5,'Prepare and present a fruit platter.');
INSERT INTO badge_optional_requirements VALUES(3611,275,6,'Prepare and present a vegetable platter.');
INSERT INTO badge_optional_requirements VALUES(3612,275,7,'Prepare and present a molded dish.');
INSERT INTO badge_optional_requirements VALUES(3613,275,8,'Prepare and present a deli tray.');
INSERT INTO badge_optional_requirements VALUES(3614,275,9,'Prepare and present a dessert dish.');
INSERT INTO badge_optional_requirements VALUES(3615,275,10,'Prepare and present a main dish.');
INSERT INTO badge_optional_requirements VALUES(3616,275,11,'Prepare and present an appetizer.');
INSERT INTO badge_optional_requirements VALUES(3617,275,12,'Earn the Garnish Badge.');
INSERT INTO badge_optional_requirements VALUES(3618,275,13,'Visit a restaurant and discuss the presentation of the food you receive.');
INSERT INTO badge_optional_requirements VALUES(3619,275,14,'Participate in a community service project that involves food presentation. This might be a bake sale to raise money for charity, a class to teach others about food presentation, making platters of food for a charity event, etc.');
INSERT INTO badge_optional_requirements VALUES(3620,275,15,'Learn about careers that involve food presentation. Examples might be chefs, banquet managers, hospitality workers, etc. What type of hours might you expect to work? What type of salary could you expect?');
INSERT INTO badge_optional_requirements VALUES(3621,278,3,'Make a list of at least three different types of food poisoning and the foods they are associated with. Learn what botulism is and why it is so dangerous.');
INSERT INTO badge_optional_requirements VALUES(3622,278,4,'Learn about careers in the food safety business, such as an inspector for the USDA, a meat processor, or a person in charge of packaging foods correctly. What kind of training/education is required? What are working hours typically like and what hourly pay-rate/salary can you expect? Ff possible, shadow someone for a day who works for a living in the food safety business.');
INSERT INTO badge_optional_requirements VALUES(3623,278,5,'Earn the Hygiene badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3624,278,6,'Create a booklet or coloring book to teach younger children how to be safe with food and prevent themselves and others from becoming sick from eating improperly cooked or bad food.');
INSERT INTO badge_optional_requirements VALUES(3625,278,7,'Earn the Food Preservation badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3626,278,8,'Know how different meats, such as beef, poultry, mutton/lamb, etc. must be thawed and what temperature each type of meat should be cooked to. Why is it important to thaw meat in the correct manner? Learn the correct safety protocols for handling raw and cooked meats.');
INSERT INTO badge_optional_requirements VALUES(3627,278,9,'Visit a food bank and talk to someone who works there. Ask them how they keep their food stored to prevent bacteria growth and cross-contamination.');
INSERT INTO badge_optional_requirements VALUES(3628,278,10,'Learn why it is so important to have the oven at the correct temperature when cooking foods. Why should you not put foods (meat in particular) in an oven that is still heating?');
INSERT INTO badge_optional_requirements VALUES(3629,278,11,'Learn how different foods should be refrigerated or frozen. Learn which parts of the fridge or freezer are best suited to which foods. Why should meat be stored below other foods? What should you do if one food spills onto another?');
INSERT INTO badge_optional_requirements VALUES(3630,278,12,'Learn what an iceman was, and how his job contributed to food safety in his day.');
INSERT INTO badge_optional_requirements VALUES(3631,279,3,'Grow your food. Take notes and observe them through the process. Once they’ve grown, taste them. How does their taste compare to supermarkets?');
INSERT INTO badge_optional_requirements VALUES(3632,279,4,'Make three different recipes that include your food. Which one was your favorite?');
INSERT INTO badge_optional_requirements VALUES(3633,279,5,'Eat a minimum of three varieties of your food (for example, red, yellow , and green apples). How are they the same? How are they different?');
INSERT INTO badge_optional_requirements VALUES(3634,279,6,'Make art from your food. This can be a drawing, painting or sculpture of your food, or you can actually use your food in some artistic way.');
INSERT INTO badge_optional_requirements VALUES(3635,279,7,'Visit your local farmer’s market and find some of your food. How many varieties can you find? If you can, buy a few. How does their taste compare to those found in a supermarket?');
INSERT INTO badge_optional_requirements VALUES(3636,279,8,'Interview someone who grows your food.');
INSERT INTO badge_optional_requirements VALUES(3637,279,9,'Make fresh juice from your food. How does it taste?');
INSERT INTO badge_optional_requirements VALUES(3638,279,10,'Research the history of your food. Has your food changed over the years? Has the way it is grown or processed changed?');
INSERT INTO badge_optional_requirements VALUES(3639,279,11,'Research what the most common types of your food is in your region. What characteristics make them the most popular?');
INSERT INTO badge_optional_requirements VALUES(3640,279,12,'What myths have circulated about your food in history? Why?');
INSERT INTO badge_optional_requirements VALUES(3641,279,13,'Learn about someone famous associated with your food. What was his/her name? When did he live? Why did he become so well known?');
INSERT INTO badge_optional_requirements VALUES(3642,279,14,'Read a story that includes your food.');
INSERT INTO badge_optional_requirements VALUES(3643,279,15,'Visit a farm where your food is grown and pick your own.');
INSERT INTO badge_optional_requirements VALUES(3644,279,16,'Participate in a community service project that has something to do with your food. Examples might include raising money at a lemonade stand for charity if your food is lemons or helping a local winery pick grapes during crush season.');
INSERT INTO badge_optional_requirements VALUES(3645,279,17,'Find out what careers involve your food– examples might include: Farmer, Produce Manager, Fruit Stand Owner, or Chef. What education is needed for this job? What type of pay could you expect? What type of hours might you need to work? Where might you need to live?');
INSERT INTO badge_optional_requirements VALUES(3646,279,18,'Visit your county fair and see exhibits of your food entered. How is the judging conducted? Enter a recipe or project yourself if you can.');
INSERT INTO badge_optional_requirements VALUES(3647,279,19,'Learn a song or poem about your food such as Goober Peas for peanuts.');
INSERT INTO badge_optional_requirements VALUES(3648,279,20,'Play a game about your food or with your food (ex. Hot potato).');
INSERT INTO badge_optional_requirements VALUES(3649,279,21,'Dehydrate your food. Try it.');
INSERT INTO badge_optional_requirements VALUES(3650,279,22,'Find out about world records about your food, such as the heaviest, longest, smallest, etc.');
INSERT INTO badge_optional_requirements VALUES(3651,279,23,'Research various folklore about your food. Does any of the folklore sound like it could have any truth to it? Discuss your findings with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(3652,279,24,'What is the difference between jam, jelly, and preserves? Make a small batch of jam, jelly, or preserves with your food. If possible, compare it to a store bought item of the same type. Which one do you prefer? What differences are there in the ingredients?');
INSERT INTO badge_optional_requirements VALUES(3653,279,25,'Find at least 10 unusual facts about your food.');
INSERT INTO badge_optional_requirements VALUES(3654,279,26,'Research festivals about your food. What type of activities do they offer? If there is one near you, visit it.');
INSERT INTO badge_optional_requirements VALUES(3655,279,27,'What types of pests or diseases attack your food? What is the most common way to deal with them?  What is the best way for our environment to deal with them that still saves the crop or animal?');
INSERT INTO badge_optional_requirements VALUES(3656,279,28,'How is your food processed?    What is the difference between hand processing and machine processing?');
INSERT INTO badge_optional_requirements VALUES(3657,279,29,'Learn about GMO.  Has your food been modified?');
INSERT INTO badge_optional_requirements VALUES(3658,280,3,'Fix a while food dish and share it with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(3659,280,4,'Have a foraging hunt party with your club, family or friends. Identify edible plants, collect them and make a meal.');
INSERT INTO badge_optional_requirements VALUES(3660,280,5,'Learn a poem or story about foraging.');
INSERT INTO badge_optional_requirements VALUES(3661,280,6,'Write your own poem or story about a plant or several plants that you forage.');
INSERT INTO badge_optional_requirements VALUES(3662,280,7,'Complete the Wilderness Survival badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3663,280,8,'Complete the Cooking badge at your level.');
INSERT INTO badge_optional_requirements VALUES(3664,280,9,'Go on a scavenger hunt. Make a list of plants you are learning to forage for and see who can find all of them first. Or, you can have a time limit and see who can find the most within the time limit. After everyone is done, go over what you all found.');
INSERT INTO badge_optional_requirements VALUES(3665,280,10,'Mix and Match game: Put several leaves from 5 or more plants or trees in a grab bag. Take turns pulling leaves out of the bag and try to match them to the surrounding area or someone holding the same type of leaf.');
INSERT INTO badge_optional_requirements VALUES(3666,280,11,'Create your own game to identify plants to forage.');
INSERT INTO badge_optional_requirements VALUES(3667,280,12,'Plan a foraging camp out. Bring some food just in case, but go foraging for all or part of your meals.');
INSERT INTO badge_optional_requirements VALUES(3668,280,13,'Make a foraging scrap book. Add plants you forage, take pictures, draw, cut out pictures from magazines, add recipes or tips, etc.');
INSERT INTO badge_optional_requirements VALUES(3669,281,3,'With your parent’s permission, go onto YouTube and watch some clips of the “best ever” ball-gown, wedding dress, or tuxedo compilations, or designer wedding dress fashion shows. Which were your favorites?');
INSERT INTO badge_optional_requirements VALUES(3670,281,4,'Learn about the history of wedding dresses. Who was the first person to start the fashion of wearing a white dress for a wedding? What color are wedding dresses in other countries?');
INSERT INTO badge_optional_requirements VALUES(3671,281,5,'Wedding dresses and formal gowns are often made of more expensive fabrics such as silk, satin, tulle, lace or velvet. Go to a fabric store and look and feel the fancy fabrics there. Which ones do you like best?');
INSERT INTO badge_optional_requirements VALUES(3672,281,6,'Design your own formal dress. Learn the following terms and use your knowledge to help you: Princess line, Empire line, mermaid style, ball-gown style, A-line, sheath, trumpet style, tea length, sweetheart neckline, V neckline, halter neck, one-shoulder, square neckline, full length sleeve, 3/4 sleeve, 1/2 sleeve, cap sleeve, strapless and crinoline.');
INSERT INTO badge_optional_requirements VALUES(3673,281,7,'Design your own tuxedo.  Learn the following terms and use your knowledge to help you: Jacket, notch lapel, peak lapel, shawl lapel, bow tie, cuff links, cummerbund, lapel pin, wingtip collar, point collar, spread collar, suspenders, pocket square, pleated pant, straight pant, skinny pant.');
INSERT INTO badge_optional_requirements VALUES(3674,281,8,'Look at pictures of how formal dresses and tuxedos have changed over the years. How does this relate to how fashions for everyday wear have changed?');
INSERT INTO badge_optional_requirements VALUES(3675,281,9,'Color one or more ball gowns in a color book.');
INSERT INTO badge_optional_requirements VALUES(3676,281,10,'Visit an exhibition of formal dresses. If you cannot visit an exhibit in person, you may look at a book or go online (with your parent’s permission). Ideas would include the dresses worn by First Ladies to Inaugural Balls, or the dresses and trains worn by the Rose Queens at the Tyler Rose Festival in Tyler, Texas.');
INSERT INTO badge_optional_requirements VALUES(3677,281,11,'Learn about a famous fashion designer, such as Norman Hartnell, Charles Frederick Worth, David & Elizabeth Emanuel or Vera Wang, and look at pictures of their ball-gowns and wedding dresses.');
INSERT INTO badge_optional_requirements VALUES(3678,281,12,'Research famous formal dresses, for example Lady Diana Spencer’s wedding dress in 1982, Lady Curzon’s Peacock dress in 1902, or Queen Elizabeth II’s coronation dress from 1953.');
INSERT INTO badge_optional_requirements VALUES(3679,281,13,'Watch something that contains lots of shots of formal dresses, such as Disney’s live-action Cinderella or the Oscars. Which is your favorite dress?');
INSERT INTO badge_optional_requirements VALUES(3680,281,14,'Go to a thrift store and look at or, if possible, try on different formal dresses. Which is your favorite? What do they cost? For extra interest, see if you can find out online (with your parent’s permission) how much each dress would have cost new. How much money could you save by buying a second-hand dress?');
INSERT INTO badge_optional_requirements VALUES(3681,281,15,'Learn how formal dress for men has changed over the years. What was “morning dress”? What was “court dress”? What were a frock coat and a cravat? When and where would each of these be worn?');
INSERT INTO badge_optional_requirements VALUES(3682,281,16,'Make a formal dress for a doll or younger child.');
INSERT INTO badge_optional_requirements VALUES(3683,281,17,'Read a nonfiction book about formal dresses.');
INSERT INTO badge_optional_requirements VALUES(3684,281,18,'Pick one aspect of formalwear and look at how it has changed over the past 100 years, such as gentlemen’s suits, ladies’ evening wear, wedding dresses, etc. Is there a particular era you like?');
INSERT INTO badge_optional_requirements VALUES(3685,281,19,'Learn about military formalwear. When would it be worn? What differences are there between different branches of the military?');
INSERT INTO badge_optional_requirements VALUES(3686,281,20,'In some circumstances hats are required as part of formalwear. What is proper hat etiquette? Are there rules for size or style of hat depending on the occasion? How does hat etiquette differ between men and women?');
INSERT INTO badge_optional_requirements VALUES(3687,281,21,'Look at the formal dresses created for Barbie dolls over the years. Which do you like best? Are any of them based on real dresses?');
INSERT INTO badge_optional_requirements VALUES(3688,281,22,'With your parent’s permission, watch an episode of a TV series about wedding dresses or ball-gowns, such as Say Yes to the Dress, I Found the Gown or Bride by Design. (Level 3 and up must watch at least three episodes.)');
INSERT INTO badge_optional_requirements VALUES(3689,281,23,'Take a hand-me-down or thrifted formal dress and alter it to become your own design.  You may add or remove trims, change the cut and shape of the dress, add extra fabric, etc.');
INSERT INTO badge_optional_requirements VALUES(3690,282,3,'Watch a documentary on the French and Indian War.');
INSERT INTO badge_optional_requirements VALUES(3691,282,4,'Visit a French and Indian War re-enactment.');
INSERT INTO badge_optional_requirements VALUES(3692,282,5,'Visit a location from an important event or battle that took place during the French and Indian War.');
INSERT INTO badge_optional_requirements VALUES(3693,282,6,'Learn about one American leader whom gained invaluable experience from the French and Indian war. Examples include George Washington, John Stark and Benjamin Franklin.');
INSERT INTO badge_optional_requirements VALUES(3694,282,7,'What were some of the occupations that could be found in the 18th century? Compare and contrast the jobs to today’s occupations.');
INSERT INTO badge_optional_requirements VALUES(3695,282,8,'Earn a Native American badge at your level for one of the tribes involved in the war.');
INSERT INTO badge_optional_requirements VALUES(3696,282,9,'Learn about cooking in the 18th century. Compare and contrast with cooking today.');
INSERT INTO badge_optional_requirements VALUES(3697,282,10,'Learn about weaponry of the war.');
INSERT INTO badge_optional_requirements VALUES(3698,282,11,'Learn about war tactics of the time period and their effectiveness. How did the colonists learn from these for future use?');
INSERT INTO badge_optional_requirements VALUES(3699,282,12,'Learn about Rogers’ Rangers.');
INSERT INTO badge_optional_requirements VALUES(3700,282,13,'Read a book based on this war, or the biography of an important figure in the war.');
INSERT INTO badge_optional_requirements VALUES(3701,283,3,'Read a fiction book set in the French Revolution time period, such as A Tale of Two Cities, by Charles Dickens; In Search of Honour, by Donna Lynn Hess; or The Scarlet Pimpernel, by Baroness Orczy.');
INSERT INTO badge_optional_requirements VALUES(3702,283,4,'Learn how fashions changed during and immediately after the French Revolution.');
INSERT INTO badge_optional_requirements VALUES(3703,283,5,'Read a biography of someone who lived (or died!) during the French Revolution, such as Marie Antoinette, Louis XVI, Robespierre, Georges Danton, Madame Tussaud, the Princesse de Lamballe, etc.');
INSERT INTO badge_optional_requirements VALUES(3704,283,6,'One of the most famous episodes in the French Revolution was the storming and taking of the Bastille prison by the revolutionists. Learn about the storming of the Bastille. When is Bastille Day?');
INSERT INTO badge_optional_requirements VALUES(3705,283,7,'Make a timeline of events that occurred during and immediately after the French Revolution. You must have at least 10 events on your timeline.');
INSERT INTO badge_optional_requirements VALUES(3706,283,8,'The motto of the revolutionists was Libertie, Equalitie, Fraternitie. Learn what this means.');
INSERT INTO badge_optional_requirements VALUES(3707,283,9,'Learn about some of the symbols of the French revolutions, such as Phrygian caps and the tricolor, and be able to identify at least 5 of them.');
INSERT INTO badge_optional_requirements VALUES(3708,283,10,'Watch a movie set during the French Revolution, such as A Tale of Two Cities, or The Scarlet Pimpernel.');
INSERT INTO badge_optional_requirements VALUES(3709,283,11,'The revolutionists’ anthem was called La Marsellaise. Listen to La Marsellaise.When was it written, and by whom?');
INSERT INTO badge_optional_requirements VALUES(3710,283,12,'In 1793 the government instituted a new calendar, called the French Republican Calendar, to be used in France. What was so dramatically different about this calendar? Is it still in use in France today?');
INSERT INTO badge_optional_requirements VALUES(3711,283,13,'The revolutionists viewed all in the upper class and the aristocracy as being “enemies of the people”. What form of address did they require everyone to use instead of Monsieur or Madame? Why?');
INSERT INTO badge_optional_requirements VALUES(3712,283,14,'Learn about at least one of the French royal palaces, such as the Tuileries, or the Palace of Versailles. When was it built, and by whom?');
INSERT INTO badge_optional_requirements VALUES(3713,283,15,'Learn about the different political parties during the French Revolution. Who were the Jacobins, the Girondins, the Montagnards, and the Feuillants?');
INSERT INTO badge_optional_requirements VALUES(3714,283,16,'What was feudalism? What was the “Declaration of the Rights of Man”? How did this affect how people viewed government?');
INSERT INTO badge_optional_requirements VALUES(3715,284,3,'Learn about and celebrate Friendship Day with your friends. The United States Congress, in 1935, proclaimed the first Sunday of August as National Friendship Day. What countries now celebrate this annual holiday? Who is the United Nations ambassador?');
INSERT INTO badge_optional_requirements VALUES(3716,284,4,'Make a “friendship code” poster with your friends or troop. Come up with things such as “hug a willing friend” and “I will let my friend choose what to play.” Put the poster in a visible place.');
INSERT INTO badge_optional_requirements VALUES(3717,284,5,'Make a new friend. Find out their first name and one thing about them. (Level 2 find out two things, Level 3 find out three things, Level 4 find out four things, and Level 5 find out five things.)');
INSERT INTO badge_optional_requirements VALUES(3718,284,6,'Take funny pictures of each other and make up captions to go with them. (Levels 3 – 5 print this picture out and give it to your friend or send it in an email)');
INSERT INTO badge_optional_requirements VALUES(3719,284,7,'Make your friend a mixed CD of all the songs that define your friendship (or ones that you just happen to mutually like!).');
INSERT INTO badge_optional_requirements VALUES(3720,284,8,'Watch a friend’s pet while they are away or babysit their children.');
INSERT INTO badge_optional_requirements VALUES(3721,284,9,'Set up a play date with your friend and plan to do something they enjoy. Suggestions: meet at the zoo, museum, science center, picnic or hike, bowling or skating, sit and play cards or do a whole puzzle for the afternoon, sew on a quilt, etc.');
INSERT INTO badge_optional_requirements VALUES(3722,284,10,'Make a special friendship book for your best friends. Include photos, quotes and poetry telling your friends how special they are.');
INSERT INTO badge_optional_requirements VALUES(3723,284,11,'Teach your friend how to do something they don’t know how to do.');
INSERT INTO badge_optional_requirements VALUES(3724,284,12,'Learn how to do something new with your friend.');
INSERT INTO badge_optional_requirements VALUES(3725,284,13,'Plan a special event with your best friend or friendship group. Ideas might be a surprise party, congratulations party, birthday party, get well gathering, dinner party, trip to the beach, etc.');
INSERT INTO badge_optional_requirements VALUES(3726,284,14,'Make up or memorize a song about friendship.');
INSERT INTO badge_optional_requirements VALUES(3727,284,15,'Earn a Character badge that might be needed for a good friendship, such as Kindness or Patience. How does this character trait improve a friendship?');
INSERT INTO badge_optional_requirements VALUES(3728,284,16,'Cheer up a friend by writing a letter telling her what she means to you.');
INSERT INTO badge_optional_requirements VALUES(3729,284,17,'Draw a picture of what friendship means to you.');
INSERT INTO badge_optional_requirements VALUES(3730,284,18,'Anonymously do something for your friend.');
INSERT INTO badge_optional_requirements VALUES(3731,284,19,'Make up or memorize a poem or song about friendship.');
INSERT INTO badge_optional_requirements VALUES(3732,284,20,'Weave a friendship bracelet or something similar and exchange with your friend(s).');
INSERT INTO badge_optional_requirements VALUES(3733,284,21,'Find a pen pal and make a long distance friend. Exchange letters for at least three months.');
INSERT INTO badge_optional_requirements VALUES(3734,284,22,'Make a “Friend Book.” Get a binder and fill it with binder paper (You can also use a notebook). On the first page number every other line from 1-10. On each of the other pages write something on the top such as address, phone number, favorite color, favorite animal, favorite ice cream, etc. Then find 10 friends to participate. On the first page each person chooses a number and writes their name on that line. Then on each consecutive page they write their answers to the question at the top on their numbered line. When the book is complete you will have compiled information about all of your friends’ favorite things.');
INSERT INTO badge_optional_requirements VALUES(3735,284,23,'Look for examples of friendship behaviors in magazines or make pictures of them. Use the pictures to create a collage. Include slogans or mottos about friendships in your collage.');
INSERT INTO badge_optional_requirements VALUES(3736,284,24,'Think about how a movie or TV shows dealt with friendship. What did someone in the show do that made him or her a good friend or a bad friend? Write a short paragraph about it.');
INSERT INTO badge_optional_requirements VALUES(3737,284,25,'Ask family members to tell you about a time when a friendship of theirs changed or ended because their friend moved, became part of a different group, went to a new school, or some other reason. How did they feel? How did they deal with it?');
INSERT INTO badge_optional_requirements VALUES(3738,284,26,'Ask your family members to describe a special friendship they currently have. What makes the friendship special and what is their advice to you regarding friendship?');
INSERT INTO badge_optional_requirements VALUES(3739,284,27,'Plan the following activity with a group of friends: Everyone writes their name on a sheet of paper, and then passes it to the right. This person writes one thing they like about the person listed. Then, continue passing the papers around until each person gets their own back, full of nice things about them.');
INSERT INTO badge_optional_requirements VALUES(3740,284,28,'Make awards for your friends with categories such as “best listener,” “funniest sense of humor,” “most helpful,” etc. Find a way to present the awards; perhaps exchange with a group of friends at a sleep over, or other get together.');
INSERT INTO badge_optional_requirements VALUES(3741,284,29,'Host a Bingo game with your troop using the following words represented by pictures. You can modify an existing Bingo set or make your own. This particular example is set so each person has all of the pictures below on their card: Dependable (planets and stars are dependable) Compliments (butterfly – tickles like a compliment) FREE SPACE (ice cream cone – free treat) Disagree lovingly (hearts – learn how to disagree without hurting feelings) Trustworthy (soccer ball – trusting your teammate to pass the ball or score) Faithful (frog – both start with “F”) Honest (rocket ship) Forgive (balloon – offense floats away, never to return) Solve Problems (monkey – he swings by and helps) Play (guitar – you can play a guitar) Listen (cow – stays in one place for some time grazing “listening”) Understand (goldfish – with a great big smile, he understands) Caring (flowers – always say you care) Cheer (party hat and confetti – represent cheer) Respect (skateboard – different choices should be respected) Share (piece of cake – represents sharing) DO NOT write the words on the cards so as to be able to see how many everyone can remember when the game is over (when we did this with our troop almost every single one was remembered!). As you call out the picture name and then follow it with the friendship word, describe how that picture represents the word and ask everyone to give an example of how to be that way or what to say to your friend. For example: You start out announcing, “balloon”. As everyone is finding their balloon, you tell them that it represents forgiveness, and how we should take whatever our friend did or said that hurt our feelings or made us mad and put them in the balloon, forgiving and forgetting that offense. At the end of the game you would ask, “What does the balloon represent?”');
INSERT INTO badge_optional_requirements VALUES(3742,286,3,'Visit a farm that grows your fruit.  If possible, pick some of your own.');
INSERT INTO badge_optional_requirements VALUES(3743,286,4,'Plant your fruit either by seed or seedling and watch it grow.');
INSERT INTO badge_optional_requirements VALUES(3744,286,5,'Eat your fruit prepared in four different ways such as:  raw, baked, sautéed, frozen, or grilled,');
INSERT INTO badge_optional_requirements VALUES(3745,286,6,'Volunteer at a community orchard or seed bank.');
INSERT INTO badge_optional_requirements VALUES(3746,286,7,'Preserve your fruit using at least one method such as drying, freezing or canning.');
INSERT INTO badge_optional_requirements VALUES(3747,286,8,'Find out what careers involve your fruit – examples might include: Farmer, Produce Manager, Fruit Stand Owner, or Chef. What education is needed for this job? What type of pay could you expect? What type of hours might you need to work? Where might you need to live?');
INSERT INTO badge_optional_requirements VALUES(3748,286,9,'Prepare your fruit and serve it three different ways, one for breakfast, one for lunch, and one for dinner.');
INSERT INTO badge_optional_requirements VALUES(3749,286,10,'Create garnishes using your fruit.');
INSERT INTO badge_optional_requirements VALUES(3750,286,11,'Find out how your fruit is harvested.');
INSERT INTO badge_optional_requirements VALUES(3751,286,12,'Find out if other countries and cultures enjoy your fruit.  Prepare a recipe from another country featuring your fruit.');
INSERT INTO badge_optional_requirements VALUES(3752,286,13,'Find out how your fruit is stored transported to grocery stores');
INSERT INTO badge_optional_requirements VALUES(3753,286,14,'Use a your fruit in a dessert such as a tart or cobbler.');
INSERT INTO badge_optional_requirements VALUES(3754,286,15,'Learn how to juice your fruit and try the fresh juice.');
INSERT INTO badge_optional_requirements VALUES(3755,287,3,'Play a game of water “basketball” or water volleyball with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(3756,287,4,'Take part in a water-relay-race with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(3757,287,5,'Take part in a rubber-duck race where each person propels their duck across the pool by blowing or pushing waves at the duck (no physical contact with the duck by the swimmer).  If you don’t want to race ducks, then choose some other inflatable/floating toy.');
INSERT INTO badge_optional_requirements VALUES(3758,287,6,'Improve your rescue skills by practicing your rope-throwing: tie a soft weight (a sock full of sand) to the end of a rope and attempt to throw it into the hole of an inflatable ring floating on the pool.');
INSERT INTO badge_optional_requirements VALUES(3759,287,7,'Take part in a Water Olympics. As a club or family, design six different activities that you can put together to make a series of events such as a relay race, followed by a rope throwing activity, followed by tossing small plastic balls into a floating net etc.');
INSERT INTO badge_optional_requirements VALUES(3760,287,8,'With your family, friends, or group learn about Synchronized Swimming. Make up a simple synchronized swim routine and practice it with your family or club.');
INSERT INTO badge_optional_requirements VALUES(3761,287,9,'Learn how to swim down to pick up items from the bottom of the pool. Remember NEVER to dive into shallow water as serious injury can result.');
INSERT INTO badge_optional_requirements VALUES(3762,287,10,'Learn some fun tricks at the pool, such as standing on your hands in the pool, trying to keep your balance whilst sitting on a floating noodle, etc – see what fun and safe tricks you can come up with.  Remember to check with your parent or lifeguard to make sure they are safe.');
INSERT INTO badge_optional_requirements VALUES(3763,287,11,'Compete in a splash contest. See who can make the biggest waves by doing a “cannon ball” jump off the diving board or from the side. See who can make the smallest splash by jumping in as straight as possible.');
INSERT INTO badge_optional_requirements VALUES(3764,287,12,'Play a game of Marco Polo with your family, friends, or group (all players must stay in the shallow end if any non- swimmers are playing). If you’re not familiar with the game, these are the rules: One person closes their eyes or is blindfolded. Their goal is to locate and tag one of the other players, while the other players move around and try to avoid being tagged. Whenever the blindfolded player calls, “Marco,” all the other players must respond, “Polo.” When someone is tagged, they become the “blind” player.');
INSERT INTO badge_optional_requirements VALUES(3765,287,13,'Weight is defined as the force on an object due to gravity. Buoyancy is defined as a force exerted by fluid that opposes an object’s weight. Experiment with the forces of weight and buoyancy in the following ways: Try to carry a person around the pool who is too heavy for you to lift on land.  Can you do it? Try to push an empty, sealed milk jug or large soda bottle to the floor of the pool.  How easy is that? Try to explain why you were or were not able to do each.  What did you learn about weight versus buoyancy?');
INSERT INTO badge_optional_requirements VALUES(3766,288,3,'What is density? What is buoyancy? How does fresh water differ from salt water? Perform the following experiment: Water Density and Floating Egg Experiment');
INSERT INTO badge_optional_requirements VALUES(3767,288,4,'Perform the following experiment: Density Tower');
INSERT INTO badge_optional_requirements VALUES(3768,288,5,'Perform the following experiment: Potato Chip Science');
INSERT INTO badge_optional_requirements VALUES(3769,288,6,'Study Plants. What do they need to grow? How do they get the nutrients they need? Perform the following experiment: Dissect a Bean Seed');
INSERT INTO badge_optional_requirements VALUES(3770,288,7,'Perform the following experiment: Grow a Lima Bean in a Bag');
INSERT INTO badge_optional_requirements VALUES(3771,288,8,'Perform the following experiment: Science Experiments with Plants for Kids');
INSERT INTO badge_optional_requirements VALUES(3772,288,9,'What is the solar system? What is out there besides the planets? Perform the following experiment: Peppercorn Experiment');
INSERT INTO badge_optional_requirements VALUES(3773,288,10,'Perform the following experiment: Oreo Cookie Moon Phases');
INSERT INTO badge_optional_requirements VALUES(3774,288,11,'Create a model of the solar system in the medium of your choice (Styrofoam, food, clay, etc).');
INSERT INTO badge_optional_requirements VALUES(3775,288,12,'What gases make up the sun? How are the stars classified? How can we use the energy from the sun? Perform one of the following experiments: Build a Solar Cooker');
INSERT INTO badge_optional_requirements VALUES(3776,288,13,'Perform the following experiment: Hot Dog Cooker/Solar Oven');
INSERT INTO badge_optional_requirements VALUES(3777,288,14,'Perform the following experiment: Solar and Lunar Eclipse');
INSERT INTO badge_optional_requirements VALUES(3778,288,15,'Perform the following experiment: Space Crafts for Kids');
INSERT INTO badge_optional_requirements VALUES(3779,288,16,'Perform the following experiment: Constellation Activity');
INSERT INTO badge_optional_requirements VALUES(3780,288,17,'Learn the science of flight. Explain lift, thrust and drag. Research Bernoulli’s principle and be able to explain it.');
INSERT INTO badge_optional_requirements VALUES(3781,288,18,'Perform the following experiment: Flight Lesson Plans');
INSERT INTO badge_optional_requirements VALUES(3782,288,19,'Have a paper airplane contest. Whose design seemed to fly the best and why do you think that is?');
INSERT INTO badge_optional_requirements VALUES(3783,288,20,'Design and build foam gliders from plates.');
INSERT INTO badge_optional_requirements VALUES(3784,289,3,'Participate in your troop fundraiser. Help with the selling and/or making of the items for sale; make signs to advertise your fund-raiser;  and/or help to distribute the orders/deliveries.');
INSERT INTO badge_optional_requirements VALUES(3785,289,4,'Set a goal – make a plan to reach your goal. Will you use the money from your fundraising for a trip, for a service project, for group supplies? Can you earn prizes if you reach your goal? If you reach your goal, what will you earn?');
INSERT INTO badge_optional_requirements VALUES(3786,289,5,'Figure out five new ways or places to sell your fundraising product.');
INSERT INTO badge_optional_requirements VALUES(3787,289,6,'Always use good manners including being polite and always saying “please” and “thank you.” Decide how you and your friends can practice good manners. You might even write thank you notes to your customers.');
INSERT INTO badge_optional_requirements VALUES(3788,289,7,'If you are going to sell something, you need to know how to make change. Find out how much your fundraiser costs. Ask your leader or another adult to help you learn about counting money. Practice buying and selling and making change.');
INSERT INTO badge_optional_requirements VALUES(3789,289,8,'Think of new fund-raising ideas you can use as a group, so that you have a variety of ways you can raise money.');
INSERT INTO badge_optional_requirements VALUES(3790,289,9,'There are many jobs connected with buying and selling of a product. Find out about some of these jobs by taking a trip around the neighborhood. Visit a grocery store to see how products are displayed. Visit a store and ask a salesperson to explain their job.');
INSERT INTO badge_optional_requirements VALUES(3791,289,10,'Practice what you would say to a customer. What would you say about the product? Don’t forget to start off with a greeting.');
INSERT INTO badge_optional_requirements VALUES(3792,289,11,'Know your product. Be able to tell your customers the differences in your products. Know your costs. If you have a variety of flavors or options – What is your favorite variety and why? What are the differences in your varieties?');
INSERT INTO badge_optional_requirements VALUES(3793,289,12,'Make a poster to display at your booth, work place or other place where a lot of people will see it. Remember to get permission to hang your poster. Create a design that is colorful and includes important information about your sale.');
INSERT INTO badge_optional_requirements VALUES(3794,289,13,'Know what your group is and what your group stands for if someone asks. What does your group value? What does your group do? Why would someone want to support your group by purchasing your product?');
INSERT INTO badge_optional_requirements VALUES(3795,290,3,'Find out how many colors fuse beads come in.  Does it vary by company?');
INSERT INTO badge_optional_requirements VALUES(3796,290,4,'What is the size differences between mini, midi and maxi beads.  What are each usually used for?');
INSERT INTO badge_optional_requirements VALUES(3797,290,5,'Create your own fuse bead pattern');
INSERT INTO badge_optional_requirements VALUES(3798,290,6,'Learn how to make a fuse bead pattern from a photo or drawing.');
INSERT INTO badge_optional_requirements VALUES(3799,290,7,'Make a piece of fuse bead artwork similar to a painting such as those by Patricia Padilla del Rio from Mexico.');
INSERT INTO badge_optional_requirements VALUES(3800,290,8,'Make a 3D fuse bead sculpture');
INSERT INTO badge_optional_requirements VALUES(3801,290,9,'Make a 3D fuse bead box.');
INSERT INTO badge_optional_requirements VALUES(3802,290,10,'Participate in a community service project that involves fuse bead such as making projects to sell and donating the money to charity or helping with a children’s center at a local festival or charity event and teaching kids how to use fuse beads.');
INSERT INTO badge_optional_requirements VALUES(3803,290,11,'With a parent’s permission, find at least 6 good “maker spaces” to sell fuse bead projects online.');
INSERT INTO badge_optional_requirements VALUES(3804,290,12,'Learn about a famous fuse bead artist such as Steve Moore who specializes in celebrity portraits.');
INSERT INTO badge_optional_requirements VALUES(3805,290,13,'Do a price comparison on fuse beads.  Where is the best place to purchase them?  What quantity is the cheapest for how much you get?  What brand is the cheapest?  Is the cheapest brand the same quality as pricier brands?');
INSERT INTO badge_optional_requirements VALUES(3806,290,14,'What other shapes do the peg boards come in other than square?');
INSERT INTO badge_optional_requirements VALUES(3807,290,15,'Make a personalized creation out of fuse beads to give to someone you care about.');
INSERT INTO badge_optional_requirements VALUES(3808,291,3,'Research the history of your favorite game. Write a paragraph (Levels 3-5 write a short essay) about what you learned. If you’ve done this at a previous level, choose a different game to research.');
INSERT INTO badge_optional_requirements VALUES(3809,291,4,'How have games changed since the birth of America? Learn to play three games that early American children played. Teach them to a group of younger children.');
INSERT INTO badge_optional_requirements VALUES(3810,291,5,'Put together a booklet of games you’ve learned how to play. Be sure to include early American games as well as games from different cultures. Make copies of the booklet to give to your family, friends, or group. Consider providing copies of your booklet to child care centers and elementary school teachers as well.');
INSERT INTO badge_optional_requirements VALUES(3811,291,6,'What are house rules? When should they be followed? Does your family have any house rules? If so, what are they, and why were they established?');
INSERT INTO badge_optional_requirements VALUES(3812,291,7,'How can games be recycled if they’re missing pieces? What can you do if the spinner or pawns or playing cards are missing? Can you substitute other items? Can you borrow pieces from other games? Can you make things to replace what was lost? Be creative in your problem solving. Make a booklet or poster of your ideas and show it to your troop.');
INSERT INTO badge_optional_requirements VALUES(3813,291,8,'Many popular card games (i.e.: Go Fish, Crazy Eights, Old Maid) were originally played using a standard deck of playing cards. Learn to play three.');
INSERT INTO badge_optional_requirements VALUES(3814,291,9,'Many popular games now have internet-based or computerized versions. Choose one multiplayer game to play with real live people. Then, with your parent’s permission, play the same game online or on the computer. Which way is more fun? Now choose an individual game (such as Solitaire) to play with real cards. Then play it on the computer. Which way do you most enjoy this game? Why?');
INSERT INTO badge_optional_requirements VALUES(3815,291,10,'Pick a successful game-making company to research (i.e.: Hasbro, Parker Brothers, Milton Bradley, etc.). Learn when the company was founded and where. Who started the company? What are some of its top- selling games? How much is the company worth today? Research careers within this company. What education is necessary for these positions? What is the average pay? Is this a field you might consider pursuing? Why or why not?');
INSERT INTO badge_optional_requirements VALUES(3816,291,11,'Organize a service project involving games. You may collect games to donate to a children’s hospital or nursing home, or arrange to play games with shut-ins. Your service project should take at least three hours (four hours for Level 1, five hours for Level 2, six hours for Level 3, seven hours for Level 4, eight hours for Level 5).');
INSERT INTO badge_optional_requirements VALUES(3817,291,12,'Play someone else’s favorite game with them. Learn how to play it if you’ve never played before.');
INSERT INTO badge_optional_requirements VALUES(3818,291,13,'Learn to play a new board game you’ve never played before.');
INSERT INTO badge_optional_requirements VALUES(3819,291,14,'Learn to play a new card game you’ve never played before.');
INSERT INTO badge_optional_requirements VALUES(3820,291,15,'Learn to play a new group game you’ve never played before.');
INSERT INTO badge_optional_requirements VALUES(3821,291,16,'Learn to play an age appropriate computer game with a parent’s supervision.');
INSERT INTO badge_optional_requirements VALUES(3822,291,17,'Learn the history of a popular board or card game, such as Monopoly, Sorry, Go Fish, etc. What country did it originate in? How have the rules evolved over the years? Who created it?');
INSERT INTO badge_optional_requirements VALUES(3823,294,3,'Take a field trip to a gem and mineral show.');
INSERT INTO badge_optional_requirements VALUES(3824,294,4,'A lapidary is an artist who forms stone such as engraving gemstones or creating cameos. Visit a lapidary display and speak to the artist if possible.');
INSERT INTO badge_optional_requirements VALUES(3825,294,5,'Mine for your own precious stones, or search for them at places like Agate Beach, California. Many tourist mines, or caverns have panning available to visitors.');
INSERT INTO badge_optional_requirements VALUES(3826,294,6,'Make a piece of jewelry or other art project using precious or semi precious stones.');
INSERT INTO badge_optional_requirements VALUES(3827,294,7,'Find out what a geode is and look at several different varieties. Why do some geodes glow in the dark?');
INSERT INTO badge_optional_requirements VALUES(3828,294,8,'Learn about “phenomenal” gemstones such as star gemstones, cat’s eyes, rainbows, and shimmering lights. Why are these effects so rare?');
INSERT INTO badge_optional_requirements VALUES(3829,294,9,'Find out about at least three of the largest gemstones ever found. Where were they found? What type were they? How much did they weigh? When were they found?');
INSERT INTO badge_optional_requirements VALUES(3830,294,10,'Learn about at least three famous gemstones that are famous for something other than size. Examples might include the Andamooka Opal, the DeLong Star Ruby, or the Star of Bombay.');
INSERT INTO badge_optional_requirements VALUES(3831,294,11,'Learn about different careers that involve gemstones. What type of education would you need? Would you have to relocate?');
INSERT INTO badge_optional_requirements VALUES(3832,294,12,'Gemstones can have different meanings. Pick six gemstones and learn their meanings. Why do you think those meanings were chosen for those particular gemstones?');
INSERT INTO badge_optional_requirements VALUES(3833,294,13,'Each month has its own birthstone. Learn the birthstone for each month and be able to identify it.');
INSERT INTO badge_optional_requirements VALUES(3834,296,3,'What does your faith say about generosity? Find five passages that talk about generosity.');
INSERT INTO badge_optional_requirements VALUES(3835,296,4,'Learn the history of St. Nicholas and his generosity.');
INSERT INTO badge_optional_requirements VALUES(3836,296,5,'Make a list of careers that require a generous spirit.');
INSERT INTO badge_optional_requirements VALUES(3837,296,6,'Go through your kitchen with a parent and take out any canned or sealed/packaged goods that you have not eaten in the last 6 months and donate them to the local food bank.');
INSERT INTO badge_optional_requirements VALUES(3838,296,7,'Go through your room and collect any toys you have not played with in the last year and donate them to a homeless shelter, charity thrift store, or family who can use them.');
INSERT INTO badge_optional_requirements VALUES(3839,296,8,'Learn to be generous with your time. Help someone with a chore or project, or invite someone lonely to come visit with you.');
INSERT INTO badge_optional_requirements VALUES(3840,296,9,'Pick a charity and learn what specific benefits they give back to the community. How do they directly affect the people they serve? What percent of the money they raise goes to salaries or operating expenses rather than benefits for the people they serve.');
INSERT INTO badge_optional_requirements VALUES(3841,296,10,'Find out when a foster child is having a birthday and what they want. Work with others to try to make their birthday wishes come true.');
INSERT INTO badge_optional_requirements VALUES(3842,296,11,'For your birthday this year, have guests bring something to support a local charity rather than presents for you. For example, they could bring canned goods for the local food bank, used horse tack to donate to the local horse rescue, or dog food for your local animal shelter.');
INSERT INTO badge_optional_requirements VALUES(3843,297,3,'Learn about three genetic diseases. What are the symptoms? Are they dominant or recessive? Are there treatments or cures? What challenges does a person with this disease face in life?');
INSERT INTO badge_optional_requirements VALUES(3844,297,4,'Find out what the Human Genome Project (HGP) is and how it is affecting the science of genetics.');
INSERT INTO badge_optional_requirements VALUES(3845,297,5,'Stem cell research is a controversial genetic subject. Learn about the process and make a list of pros and cons for continuing this type of research. What conclusions do you come to? Why?');
INSERT INTO badge_optional_requirements VALUES(3846,297,6,'Learn about genetically modified organisms (GMOs). What are the advantages and disadvantages of this type of genetic manipulation?');
INSERT INTO badge_optional_requirements VALUES(3847,297,7,'Participate in a service project that relates to genetics. You may wish to participate in a fundraiser to support research for a genetic disease, or create a game or booklet to teach genetics to younger kids.');
INSERT INTO badge_optional_requirements VALUES(3848,297,8,'Learn about careers within the field of genetics. Choose one and find out what education you would need, salary you could expect, where you might have to live, etc.');
INSERT INTO badge_optional_requirements VALUES(3849,297,9,'Read a book or magazine about genetics.');
INSERT INTO badge_optional_requirements VALUES(3850,297,10,'Play a game that teaches about genetics.');
INSERT INTO badge_optional_requirements VALUES(3851,297,11,'Contact someone who works in the field of genetics and ask them at least five questions. If possible, shadow them for a day. Third Party Resources: Neok12: Genetics for Kids Exploring Nature: Punnett’s Square Activity Science Spot: Genetics with a Smile Activity');
INSERT INTO badge_optional_requirements VALUES(3852,298,3,'Draw a picture of what gentleness means to you.');
INSERT INTO badge_optional_requirements VALUES(3853,298,4,'Write an essay about what gentleness means to you.');
INSERT INTO badge_optional_requirements VALUES(3854,298,5,'Write a story or skit where gentleness plays an important role.');
INSERT INTO badge_optional_requirements VALUES(3855,298,6,'Read a biography about someone known for their gentleness.');
INSERT INTO badge_optional_requirements VALUES(3856,298,7,'What does your book of worship say about gentleness? Memorize verses about faithfulness. Preschool-Level 2: Memorize three verses. Levels 3-4: Memorize five verses. Level 5: Memorize seven verses.');
INSERT INTO badge_optional_requirements VALUES(3857,298,8,'Memorize or write a poem about gentleness.');
INSERT INTO badge_optional_requirements VALUES(3858,298,9,'Find and memorize at least three famous quotes about gentleness.');
INSERT INTO badge_optional_requirements VALUES(3859,298,10,'Divide a piece of paper into two sides. On one side, list words that describe being gentle, such as kind, humble, or quiet. On the other side, make a list of words that describe what being gentle is not, such as loud, obnoxious, or impatient. Discuss your list with someone else and see if they have ideas to add to it.');
INSERT INTO badge_optional_requirements VALUES(3860,298,11,'Many animals are mistreated every day. Make a poster encouraging people to be gentle to animals. Put it up somewhere in your community.');
INSERT INTO badge_optional_requirements VALUES(3861,298,12,'Visit a petting zoo, senior citizen’s home, or day care and show how you need to be physically gentle around animals, older people and small children. Discuss why gentleness is so important in these cases.');
INSERT INTO badge_optional_requirements VALUES(3862,298,13,'Create a craft about gentleness. For example, you could create warm fuzzies. Take a pompom, put google eyes on it and cut out a heart to glue to the bottom for feet. Write a happy thought or quote on a strip of paper and attach to your warm fuzzy and give it to someone to make their day brighter. Discuss how warm fuzzies are good things to make and spread around while “cold pricklies” would be the opposite. Instead of soft and gentle words and actions, cold pricklies are harsh and hurtful words and actions.');
INSERT INTO badge_optional_requirements VALUES(3863,298,14,'Show how harsh words and actions leave lasting damage even after you say “I am sorry.” For example, take a large red paper heart and have kids say mean things to it. Every time they do, tear the heart. When they say “I am sorry” tape the tear back together. After 5 or times. Show the patched together heart to the kids and explain that while saying “I am sorry” helps, it can never really undo the damage of the mean words or actions. The more people are mean to someone , the harder it is to keep repairing the heart until finally it is so ragged that it can no longer be repaired.');
INSERT INTO badge_optional_requirements VALUES(3864,299,3,'Learn the history of geocaching.');
INSERT INTO badge_optional_requirements VALUES(3865,299,4,'Create your own cache box and hide it.  Record the waypoints or coordinates for it so it can be found later. Either register your cache online for others (if a parent is willing to monitor it for at least 3 months), or see if a friend can find it using the coordinates you saved on your G.P.S. Be able to explain why caches are never buried.');
INSERT INTO badge_optional_requirements VALUES(3866,299,5,'What is a travel bug and how to you use one?');
INSERT INTO badge_optional_requirements VALUES(3867,299,6,'Learn about difficulty and terrain ratings.');
INSERT INTO badge_optional_requirements VALUES(3868,299,7,'Show you know how to use a map and compass and explain why this is important for geocaching. Explain the similarities and differences between GPS navigation and standard map reading skills and describe the benefits of each.');
INSERT INTO badge_optional_requirements VALUES(3869,299,8,'Research different types of G.P.S. units.  What are the cost differences?');
INSERT INTO badge_optional_requirements VALUES(3870,299,9,'Research careers that use GPS in their job. Examples include pilot, forester, police, military, ecologist, wildlife managers and park rangers. Interview one of these people or find out how they use the GPS.');
INSERT INTO badge_optional_requirements VALUES(3871,299,10,'Plan a geohunt for a group of friends or family. Choose a theme, set up a course with at least four waypoints, and teach the players how to use a GPS unit, and play the game.');
INSERT INTO badge_optional_requirements VALUES(3872,299,11,'Find a geocache that is not in your city.');
INSERT INTO badge_optional_requirements VALUES(3873,300,3,'Earn the Rocks and Minerals badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(3874,300,4,'Make craft or art project using rocks. For example, you might make “pet rocks” using rocks, paint, and glue-on eyes, or you might make a piece of jewelry using gemstones.');
INSERT INTO badge_optional_requirements VALUES(3875,300,5,'List the top five Earth resources used to generate electricity. What are the pros and cons of each.');
INSERT INTO badge_optional_requirements VALUES(3876,300,6,'Learn the different parts of a volcano. Draw a picture, make a poster, or even a 3D diagram of what you learned.');
INSERT INTO badge_optional_requirements VALUES(3877,300,7,'Grow a crystal garden.');
INSERT INTO badge_optional_requirements VALUES(3878,300,8,'Earn the Paleontology badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(3879,300,9,'Take a field trip to a mine, oil or gas field, gravel pit, stone quarry, or other location related to geology.');
INSERT INTO badge_optional_requirements VALUES(3880,300,10,'Learn how to read a geologic map.  What types of rocks are represented?  How can you tell?  Be able to explain the difference between horizontal, folded, and faulted rocks.');
INSERT INTO badge_optional_requirements VALUES(3881,300,11,'Learn about careers related to geology.  Examples might include a geologist, a miner, civil engineer or an oil worker.  What education is necessary?  What salary can you expect?  Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(3882,300,12,'Visit a cavern and explain the difference between stalactites and stalagmites.  Be able to explain how they are formed.');
INSERT INTO badge_optional_requirements VALUES(3883,300,13,'Create a science project that shows how sediments are carried with moving water and how they settle from suspension in water.');
INSERT INTO badge_optional_requirements VALUES(3884,300,14,'Be able to identify examples in a stream of a cut bank, fill bank, point bar, medial channel bar, and delta. What is the sediment size found in each feature?');
INSERT INTO badge_optional_requirements VALUES(3885,300,15,'What are the three components that must be present for the occurrence of oil and gas underground?');
INSERT INTO badge_optional_requirements VALUES(3886,300,16,'Learn about one or more geologic tools used to explore the earth. Examples might include: Electric well logs Stratigraphic correlation Offshore platform Geologic map Subsurface structure map Subsurface isopach map Core samples Cutting samples');
INSERT INTO badge_optional_requirements VALUES(3887,300,17,'Define a mineral and understand how they are identified according to color, hardness, streak, cleavage, luster, and crystal form.');
INSERT INTO badge_optional_requirements VALUES(3888,300,18,'Understand how fossils are formed and what information they give regarding the life, climate, and environment of the past.');
INSERT INTO badge_optional_requirements VALUES(3889,300,19,'Visit a museum, exhibit, or show with displays on rocks or fossils.');
INSERT INTO badge_optional_requirements VALUES(3890,302,3,'Make someone a gift made of paper.');
INSERT INTO badge_optional_requirements VALUES(3891,302,4,'Learn about organizations that exist through gifts given to them. What are these organizations called? What is your favorite organization?');
INSERT INTO badge_optional_requirements VALUES(3892,302,5,'Give someone a gift made of photographs.');
INSERT INTO badge_optional_requirements VALUES(3893,302,6,'Donate at least four hours of your time to an organization. How would this be considered gift giving?');
INSERT INTO badge_optional_requirements VALUES(3894,302,7,'Bake something and give it as a gift. It could be a plate of cookies, a birthday cake or homemade candy.');
INSERT INTO badge_optional_requirements VALUES(3895,302,8,'Save up some money or use some money you already have saved and buy a gift for someone you care about.');
INSERT INTO badge_optional_requirements VALUES(3896,302,9,'Make someone a gift made of fabric.');
INSERT INTO badge_optional_requirements VALUES(3897,302,10,'Give someone the gift of a plant or pet, something living that they would have to care for.');
INSERT INTO badge_optional_requirements VALUES(3898,302,11,'Make someone a gift made of ceramics.');
INSERT INTO badge_optional_requirements VALUES(3899,302,12,'Donate some money to a local organization you support, such as your church, an animal shelter or a homeless shelter.');
INSERT INTO badge_optional_requirements VALUES(3900,302,13,'Give a gift you made from upcycling or recycling items you already had.');
INSERT INTO badge_optional_requirements VALUES(3901,302,14,'Give the gift of time, whether this be doing an activity with someone you care about even if it isn’t your favorite or washing someone’s car for them without excepting anything in return.');
INSERT INTO badge_optional_requirements VALUES(3902,307,3,'Learn what a pantheon is and identify the pantheon to which your deity belongs.');
INSERT INTO badge_optional_requirements VALUES(3903,307,4,'Watch a movie that features your deity.');
INSERT INTO badge_optional_requirements VALUES(3904,307,5,'Write your own myth or story featuring your chosen god or goddess.');
INSERT INTO badge_optional_requirements VALUES(3905,307,6,'Learn about the cultural practices and rituals associated with worshiping the chosen deity.');
INSERT INTO badge_optional_requirements VALUES(3906,307,7,'Compare and contrast the chosen deity with similar figures in other mythologies.');
INSERT INTO badge_optional_requirements VALUES(3907,307,8,'Explore the influence of the chosen deity on modern culture, including movies, books, and games.');
INSERT INTO badge_optional_requirements VALUES(3908,307,9,'Create a collage using images and symbols associated with your deity.');
INSERT INTO badge_optional_requirements VALUES(3909,307,10,'Learn about festivals or holidays honoring the chosen deity.');
INSERT INTO badge_optional_requirements VALUES(3910,307,11,'Explore the genealogy or create a family tree of the chosen deity within the pantheon.');
INSERT INTO badge_optional_requirements VALUES(3911,307,12,'Analyze the moral lessons or values conveyed through myths involving the chosen deity.');
INSERT INTO badge_optional_requirements VALUES(3912,307,13,'Create a symbolic “artifact” out of clay that might have been used in the worship of your deity such as a sacred animal, weapon or object.');
INSERT INTO badge_optional_requirements VALUES(3913,307,14,'Research the afterlife beliefs associated with the chosen deity’s mythology.');
INSERT INTO badge_optional_requirements VALUES(3914,307,15,'Discuss how the chosen deity is similar to or different from characters in your favorite fairy tales or cartoons.');
INSERT INTO badge_optional_requirements VALUES(3915,307,16,'If applicable, investigate the role of the chosen deity in creation myths.');
INSERT INTO badge_optional_requirements VALUES(3916,307,17,'Learn about temples or sacred sites dedicated to the chosen deity.');
INSERT INTO badge_optional_requirements VALUES(3917,307,18,'Identify historical figures or leaders associated with the worship of the chosen deity.');
INSERT INTO badge_optional_requirements VALUES(3918,307,19,'Prepare a simple recipe for a food or drink traditionally offered to the deity.');
INSERT INTO badge_optional_requirements VALUES(3919,307,20,'Investigate the impact of colonization or cultural exchange on the worship of the chosen deity.');
INSERT INTO badge_optional_requirements VALUES(3920,307,21,'Learn about religious sects or movements centered around the worship of the chosen deity.');
INSERT INTO badge_optional_requirements VALUES(3921,308,3,'Learn what a sluice box is and how one is used.');
INSERT INTO badge_optional_requirements VALUES(3922,308,4,'Learn what a gold rocker is and how to use one.');
INSERT INTO badge_optional_requirements VALUES(3923,308,5,'Read a book about the Gold Rush.');
INSERT INTO badge_optional_requirements VALUES(3924,308,6,'Watch a movie about the Gold Rush.');
INSERT INTO badge_optional_requirements VALUES(3925,308,7,'Learn how to tell the difference between real gold and fool’s gold. What is fool’s gold made of?');
INSERT INTO badge_optional_requirements VALUES(3926,308,8,'Visit a Gold Rush exhibit or Gold Rush Days festival.');
INSERT INTO badge_optional_requirements VALUES(3927,308,9,'Create a booklet or poster about what you have learned about the Gold Rush.');
INSERT INTO badge_optional_requirements VALUES(3928,308,10,'Learn some miner’s folk songs.');
INSERT INTO badge_optional_requirements VALUES(3929,308,11,'Find out what type of animals miners used and for what purposes.');
INSERT INTO badge_optional_requirements VALUES(3930,308,12,'Create a Gold Rush craft such as making pretend gold nuggets by spray painting small rocks with metallic gold paint.');
INSERT INTO badge_optional_requirements VALUES(3931,308,13,'Learn a poem about the Gold Rush');
INSERT INTO badge_optional_requirements VALUES(3932,308,14,'Discuss why different people may have given up everything and headed west for the Gold Rush. Examples might include veteran miners, merchants, families, single women, or single men. What were the advantages and disadvantages each faced?');
INSERT INTO badge_optional_requirements VALUES(3933,308,15,'Cook a recipe that a miner during the Gold Rush may have eaten. Third Party Resources: History Channel: Gold Rush of 1849  American Mining Rights Association: How to Pan for Gold');
INSERT INTO badge_optional_requirements VALUES(3934,309,3,'Visit a beautician or hair stylist and ask him or her about hair care and styles. Decide which style you think would look best on you.');
INSERT INTO badge_optional_requirements VALUES(3935,309,4,'Demonstrate good posture for sitting, walking, lifting, bending, reading, and carrying packages.');
INSERT INTO badge_optional_requirements VALUES(3936,309,5,'Discuss proper care for your feet. What would be the proper footwear for going to the beach? Hiking? Going for a long walk? Going to church?');
INSERT INTO badge_optional_requirements VALUES(3937,309,6,'The way we present our outside should match who we are on the inside. What message does clean, unwrinkled clothing send? What about modest or immodest clothing?  Ill-fitting clothing? Unprofessional clothing in a working environment? What affect can clothing have on our confidence?');
INSERT INTO badge_optional_requirements VALUES(3938,309,7,'Discuss how good grooming affects your appearance and attitude. How does this affect other impressions of you?');
INSERT INTO badge_optional_requirements VALUES(3939,309,8,'Put on a fashion show to demonstrate good grooming. Make sure that hair is styled well, nails are trimmed and neat, and clothing is appropriate, clean, and neat.');
INSERT INTO badge_optional_requirements VALUES(3940,309,9,'Discuss how sleep contributes to the way you feel and look. How much sleep should you be getting each night?');
INSERT INTO badge_optional_requirements VALUES(3941,309,10,'Make a Good Grooming chart with items you think should be checked daily, weekly, and monthly. Items may include haircuts, nails, clothing fit and style, etc.');
INSERT INTO badge_optional_requirements VALUES(3942,309,11,'Discuss what kinds of foods you should be eating to stay healthy and what happens when you don’t eat enough of them. Make a dietary plan that meets your health needs and follow it for one month.');
INSERT INTO badge_optional_requirements VALUES(3943,309,12,'Learn how to properly tweeze your eyebrows.');
INSERT INTO badge_optional_requirements VALUES(3944,309,13,'Learn the difference between waxing, shaving, threading, or laser hair removal when it comes to getting rid of unwanted body hair. Which method would you prefer?');
INSERT INTO badge_optional_requirements VALUES(3945,310,3,'Watch at least three different movies and discuss which characters were “good” and which were “bad.” How could you tell? Were the “bad” characters recognizable throughout the whole movie or did they appear to be “good” at some time. What does that tell you about how people act? Can someone do a “good” act for a “bad” reason?');
INSERT INTO badge_optional_requirements VALUES(3946,310,4,'Draw a picture of what goodness means to you.');
INSERT INTO badge_optional_requirements VALUES(3947,310,5,'Write an essay about what goodness means to you.');
INSERT INTO badge_optional_requirements VALUES(3948,310,6,'Write a story where goodness plays an important role.');
INSERT INTO badge_optional_requirements VALUES(3949,310,7,'Read a biography about someone known for their goodness.');
INSERT INTO badge_optional_requirements VALUES(3950,310,8,'Many parents threaten to wash their children’s mouth out with soap if they use foul language. This is because bad language is considered “dirty”. At the same time, good language is considered “clean.” Why is using clean language important? To help you remember to use only good language, make some homemade soap and put it in your bathroom. Every time you use it to wash your hands, remind yourself to use only clean words in both your thoughts and speech.');
INSERT INTO badge_optional_requirements VALUES(3951,310,9,'Write the word GOODNESS vertically on a piece of paper. Now think of one good trait that you would like to have that starts with each letter in the word. For example you could put “Giving” and you might put “Optimistic.”');
INSERT INTO badge_optional_requirements VALUES(3952,310,10,'Memorize or write a poem about goodness.');
INSERT INTO badge_optional_requirements VALUES(3953,310,11,'Find and memorize at least 3 famous quotes about goodness.');
INSERT INTO badge_optional_requirements VALUES(3954,310,12,'What does your book of faith say about goodness? Memorize verses about goodness. Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(3955,310,13,'Choose an advertisement that you feel is not sending good messages to the public. How would you change it so that the ad was still effective, but had a good message?');
INSERT INTO badge_optional_requirements VALUES(3956,311,3,'What are grains used for other than bread?  What drinks are made from grain?  What fuel?  What type of grains are used?');
INSERT INTO badge_optional_requirements VALUES(3957,311,4,'Make a craft out of grain foods.  Examples might include pasta necklaces, or grain mosaics.');
INSERT INTO badge_optional_requirements VALUES(3958,311,5,'Create an advertisement to encourage kids to eat a healthy amount of grain in their diets.  This can be anything from a simply flyer to a video ad.');
INSERT INTO badge_optional_requirements VALUES(3959,311,6,'Learn the differences between the following flour types and what each might be used for: All purpose flour Bread flour Self-Rising flour Whole Wheat flour Cake flour Gluten flour Semolina Durum Flour Farina');
INSERT INTO badge_optional_requirements VALUES(3960,311,7,'Research a career that involves grain.  Examples might include grain growers, seed growers, dock workers, feedmill workers, grain inspectors, brewers, fertilizer dealers, bakery workers, truckers, farm equipment dealers or mechanics, etc.');
INSERT INTO badge_optional_requirements VALUES(3961,311,8,'Put together a recipe book of grain recipes and share it with family and friends, or sell it as part of a fundraiser.');
INSERT INTO badge_optional_requirements VALUES(3962,311,9,'Participate in a community service project that involves grain.  Examples might include helping collect food for a food bank, baking cookies for your local shut ins or fire department, or having a bake sale to raise money for charity.');
INSERT INTO badge_optional_requirements VALUES(3963,311,10,'What is the difference between whole grains and enriched grains?  What benefits do each have for your nutrition?');
INSERT INTO badge_optional_requirements VALUES(3964,311,11,'Track what you eat for one week.  Which ones are made from grains?  How many grain servings did you have each day?  Which ones were from whole grains?  Which from enriched grains?  You should be eating 5-6 servings of healthy grains each day.  Are you?');
INSERT INTO badge_optional_requirements VALUES(3965,311,12,'Go through your house and make a list of everything you can find that contains grain.');
INSERT INTO badge_optional_requirements VALUES(3966,311,13,'Talk to your school food service manager about which foods on the school’s breakfast and lunch menu contain whole grains.  Find out how meals are planned to include enough whole grains.');
INSERT INTO badge_optional_requirements VALUES(3967,311,14,'Find at least three different groups or associations that support the grain industry.  Which part of the industry do each support?  What role do they play in helping the grain industry?');
INSERT INTO badge_optional_requirements VALUES(3968,311,15,'Create a collage out of product packages and pictures of whole grain foods.');
INSERT INTO badge_optional_requirements VALUES(3969,311,16,'Make a chart about the steps needed to grow a grain from seed, harvest it, process it and get it to market.');
INSERT INTO badge_optional_requirements VALUES(3970,311,17,'Find out how much grain the U.S. exports every year. Which state grows the most? Where does it go?');
INSERT INTO badge_optional_requirements VALUES(3971,312,3,'Choose a children’s book or story with very simple sentences and enhance the story by rewriting it using vivid descriptive adjectives and adverbs.');
INSERT INTO badge_optional_requirements VALUES(3972,312,4,'Write the longest run-on sentence you can. (Get creative and silly!) Then place a / mark between each section that should have actually started a new sentence.');
INSERT INTO badge_optional_requirements VALUES(3973,312,5,'Play a grammar related game.');
INSERT INTO badge_optional_requirements VALUES(3974,312,6,'Learn a song about grammar.');
INSERT INTO badge_optional_requirements VALUES(3975,312,7,'Create Bingo cards with various grammar terms. Call out definitions or examples, and players mark the corresponding terms.');
INSERT INTO badge_optional_requirements VALUES(3976,312,8,'Design crossword puzzles or word searches with grammar-related clues and terms.');
INSERT INTO badge_optional_requirements VALUES(3977,312,9,'Play Mad Libs. Fill in the blanks of a story with different parts of speech, creating hilarious and sometimes nonsensical results.');
INSERT INTO badge_optional_requirements VALUES(3978,312,10,'Design an escape room with grammar-related puzzles and challenges to solve and see if your friends can solve it.');
INSERT INTO badge_optional_requirements VALUES(3979,312,11,'Set up a Jeopardy-style game with categories related to different grammar topics.');
INSERT INTO badge_optional_requirements VALUES(3980,312,12,'Play a game where you take turns choosing a noun in the house. Then the other players must identify a adjective, verb, adverb, pronoun, and preposition that describes it. For example, if someone chooses a stapler on the desk, an adjective might be “black” or “heavy”; a verb describing its action might be “sitting” or “resting”; an adverb might be “quietly” or “neatly”; the pronoun would be “it” and a preposition would be “on”.');
INSERT INTO badge_optional_requirements VALUES(3981,312,13,'Write a sentence using emojis and challenge others to decode the grammar elements represented.');
INSERT INTO badge_optional_requirements VALUES(3982,312,14,'Record a short podcast or video discussing grammar topics or common language misconceptions.');
INSERT INTO badge_optional_requirements VALUES(3983,312,15,'Place various words in a “Sorting Hat” (a hat or container), draw words out and sort them into different parts of speech.');
INSERT INTO badge_optional_requirements VALUES(3984,312,16,'Create story cubes with different parts of speech. Roll the cubes and use the elements rolled to form a creative sentence.');
INSERT INTO badge_optional_requirements VALUES(3985,312,17,'Take turns choosing an object and then brainstorm as many adjectives as you can to describe it. What is your record for the number of adjectives you can come up with? What was the object you described?');
INSERT INTO badge_optional_requirements VALUES(3986,312,18,'Get several takeout menus. Then read through the menus and correct all the grammar errors you see.');
INSERT INTO badge_optional_requirements VALUES(3987,312,19,'Go on a grammar scavenger hunt. While running errands in town, read every sign or product description you can and find any spelling or grammar errors. Make a list of what you find and the person who finds the most wins.');
INSERT INTO badge_optional_requirements VALUES(3988,314,3,'Attend a nature-inspired musical performance or create your own composition inspired by the elements.');
INSERT INTO badge_optional_requirements VALUES(3989,314,4,'Create a piece of art, whether visual or literary, that captures the essence of each element.');
INSERT INTO badge_optional_requirements VALUES(3990,314,5,'Write a short story that weaves the magical or mystical aspects of the four elements into a captivating narrative.');
INSERT INTO badge_optional_requirements VALUES(3991,314,6,'Research symbols that have been used for the four element over time.  Create symbols of your own that represent each of the four elements. Explain the significance of each symbol.');
INSERT INTO badge_optional_requirements VALUES(3992,314,7,'Write a poem or song that evokes the spirit of Earth, Water, Air, and Fire.');
INSERT INTO badge_optional_requirements VALUES(3993,314,8,'Learn about ancient mythology that revolves around the four elements.');
INSERT INTO badge_optional_requirements VALUES(3994,314,9,'Learn about pagan religions and their focus on the four elements.');
INSERT INTO badge_optional_requirements VALUES(3995,314,10,'Engage in a local conservation project related to preserving the balance of Earth, Water, Air, or Fire.');
INSERT INTO badge_optional_requirements VALUES(3996,314,11,'Earn the Natural Disasters Specific badge for disaster caused by one of the four elements.  For example you could earn the Earthquakes Badge (earth), the Tornado Badge (wind), the Floods Badge (water) or the Wildfires Badge (fire).');
INSERT INTO badge_optional_requirements VALUES(3997,314,12,'Learn about how the changing seasons impact the manifestations of the four elements.');
INSERT INTO badge_optional_requirements VALUES(3998,314,13,'Create a multimedia presentation that highlights the beauty and significance of the four elements.');
INSERT INTO badge_optional_requirements VALUES(3999,314,14,'Discuss how the four elements are integrated into various disciplines, such as art, science, philosophy, and spirituality.  Be able to provide examples of each.');
INSERT INTO badge_optional_requirements VALUES(4000,314,15,'Earn a badge specific to one of the four elements such as the Water badge, the Fire Safety Badge, the Geology badge or the Kites badge.');
INSERT INTO badge_optional_requirements VALUES(4001,314,16,'Earn the Weather badge and discuss how the weather effects the four elements.');
INSERT INTO badge_optional_requirements VALUES(4002,314,17,'Create a scavenger hunt that incorporates finding items representing Earth, Water, Air, and Fire in your local environment.');
INSERT INTO badge_optional_requirements VALUES(4003,314,18,'Learn about the astrology and its beliefs about the elements.');
INSERT INTO badge_optional_requirements VALUES(4004,314,19,'Investigate how symbols representing Earth, Water, Air, and Fire are used in various cultural contexts, such as flags, religious symbols, or art.');
INSERT INTO badge_optional_requirements VALUES(4005,314,20,'Create crafts using natural materials that represent the four elements. Examples include rock painting, watercolor art, wind chimes, and fire-themed candles.');
INSERT INTO badge_optional_requirements VALUES(4006,314,21,'Design a board game centered around the concepts of Earth, Water, Air, and Fire. Include challenges and tasks related to each element.');
INSERT INTO badge_optional_requirements VALUES(4007,314,22,'Explore ways to make your living space more energy-efficient, considering the principles of Earth-friendly construction, water conservation, air quality improvement, and fire safety.]');
INSERT INTO badge_optional_requirements VALUES(4008,314,23,'Conduct simple physics experiments showcasing the principles of gravity (Earth), buoyancy (Water), air pressure (Air), and combustion (Fire).');
INSERT INTO badge_optional_requirements VALUES(4009,314,24,'Develop an emergency response plan for natural disasters or incidents related to Earthquakes, Floods, Hurricanes (Air), and Fires.');
INSERT INTO badge_optional_requirements VALUES(4010,314,25,'Capture photographs representing the beauty and significance of the elements.');
INSERT INTO badge_optional_requirements VALUES(4011,314,26,'Volunteer for a community service project that addresses environmental issues related to the elements, such as cleaning up a local riverbank or planting trees.');
INSERT INTO badge_optional_requirements VALUES(4012,315,3,'Learn the history of greeting cards.  Visit a collection, view a collection of photos, or peruse a book of antique greeting cards.  Be able to describe several things that have changed over the years.');
INSERT INTO badge_optional_requirements VALUES(4013,315,4,'Make ‘recycled’ cards using either cut-up pieces of other cards, calendars, advertisements, etc, or your own homemade paper made from used paper.  You may use store-bought blank cards for your base.');
INSERT INTO badge_optional_requirements VALUES(4014,315,5,'Practice thriftiness.  Figure out how much you might save making your own blank cards and your own envelopes.  Make 3 cards using only scraps from other projects (except for the blank card that is your base).');
INSERT INTO badge_optional_requirements VALUES(4015,315,6,'Find someone who is depressed, sick, far from home, or lonely who doesn’t get many cards and send them a card.');
INSERT INTO badge_optional_requirements VALUES(4016,315,7,'Learn about the major greeting card companies in this country.  Find out how to get a job with one of them, or find out about owning a greeting card shop.  What education and skills are needed?  How much money could a person make either designing cards or managing a greeting card store?');
INSERT INTO badge_optional_requirements VALUES(4017,315,8,'Create a set of at least five greeting cards for different occasions and package them as a gift or donation set.');
INSERT INTO badge_optional_requirements VALUES(4018,315,9,'Enter some of your homemade cards in your local fair or an art or craft contest or show.');
INSERT INTO badge_optional_requirements VALUES(4019,315,10,'Create a digital greeting card using a computer or tablet and send it through email or a digital platform.');
INSERT INTO badge_optional_requirements VALUES(4020,315,11,'Practice writing greetings or poems for five different types of cards.  If you are short on ideas of things to write inside, what are at least three sources you can refer to for help?');
INSERT INTO badge_optional_requirements VALUES(4021,315,12,'Create an envelope template and learn how to fold and glue it to fit your handmade card.');
INSERT INTO badge_optional_requirements VALUES(4022,315,13,'Host or attend a card-making party with friends or family.');
INSERT INTO badge_optional_requirements VALUES(4023,315,14,'Learn about calligraphy or decorative handwriting and try using it in your cards.');
INSERT INTO badge_optional_requirements VALUES(4024,315,15,'Make an interactive greeting card that includes a puzzle, pop-up, pull tab, or scratch-off element.');
INSERT INTO badge_optional_requirements VALUES(4025,315,16,'Study how greeting cards are mass-produced and sold. Visit a store and analyze how cards are displayed, categorized, and priced.');
INSERT INTO badge_optional_requirements VALUES(4026,315,17,'Design a card specifically for someone in a hard-to-find category (e.g., adoption day, moving to a new country, first day of homeschooling).');
INSERT INTO badge_optional_requirements VALUES(4027,315,18,'Learn the difference between a greeting card, a postcard, and a note card. Make one of each.');
INSERT INTO badge_optional_requirements VALUES(4028,315,19,'Design your own personal logo or signature to use on the back of every card you make.');
INSERT INTO badge_optional_requirements VALUES(4029,315,20,'Design a greeting card line with a theme (e.g., animal puns, inspirational quotes, seasonal art).');
INSERT INTO badge_optional_requirements VALUES(4030,317,3,'Read a book about how to care for a domestic guinea pig.');
INSERT INTO badge_optional_requirements VALUES(4031,317,4,'Draw a detailed picture of a guinea pig and label all parts.');
INSERT INTO badge_optional_requirements VALUES(4032,317,5,'Visit a pet store and browse the guinea pig section. How many different types of guinea pigs can you find? Talk to a worker about guinea pig care.');
INSERT INTO badge_optional_requirements VALUES(4033,317,6,'Most guinea pigs are known for being domestic, but learn about feral guinea pigs. What do they eat? Where can they be found? How would someone domesticate them?');
INSERT INTO badge_optional_requirements VALUES(4034,317,7,'Learn how to select the best guinea pig cage. Find three different types you think would be the best option and list pros and cons for each.  What factors influence your decision? Price, size, material?');
INSERT INTO badge_optional_requirements VALUES(4035,317,8,'Create a presentation about guinea pigs with pictures. When you finish, show your presentation to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4036,317,9,'Watch a documentary about guinea pigs. Take notes and discuss what you learn with a friend or family member.');
INSERT INTO badge_optional_requirements VALUES(4037,317,10,'Learn about and list five different guinea pig accessories or toys.');
INSERT INTO badge_optional_requirements VALUES(4038,317,11,'Learn what “popcorning” is in relation to a guinea pig.');
INSERT INTO badge_optional_requirements VALUES(4039,317,12,'Learn how to properly trim a guinea pigs nails (adult supervision required)');
INSERT INTO badge_optional_requirements VALUES(4040,317,13,'Research different cages and homes for your guinea pigs. Choose three different types and compare and contrast the pros and cons of each. nail trimming, teeth care, brushing, diet, bathing, being in a pair, a home for a guinea pig');
INSERT INTO badge_optional_requirements VALUES(4041,318,3,'Watch or participate in a gymnastics meet or performance.');
INSERT INTO badge_optional_requirements VALUES(4042,318,4,'Participate in a service project that involves gymnastics in some way.  You might participate in a charity gymnastic show, help raise money for scholarships to your local gym, perform at your county fair, etc.');
INSERT INTO badge_optional_requirements VALUES(4043,318,5,'Learn about different ways gymnastics can be used with other sports or arts.  For example, how could gymnastics be used in dance, cheerleading, skating, etc.');
INSERT INTO badge_optional_requirements VALUES(4044,318,6,'Read a biography about a famous gymnast.');
INSERT INTO badge_optional_requirements VALUES(4045,318,7,'Learn about the history of gymnastics.');
INSERT INTO badge_optional_requirements VALUES(4046,318,8,'Learn at least one trick on the trampoline (make sure to follow all safety rules and always have an adult spotter).');
INSERT INTO badge_optional_requirements VALUES(4047,318,9,'If you are earning the Artistic Gymnastics badge, learn about the different types of rhythmic gymnastics including ribbon, ball, hoop, rope, and the clubs.  If you re earning the Rhythmic Gymnastics badge, learn about the balance beam, uneven bars, vault, and tumbling.');
INSERT INTO badge_optional_requirements VALUES(4048,318,10,'Interview a gymnast and find out what they like and dislike about the sport.  How often do they practice?  What competitions do they participate in?');
INSERT INTO badge_optional_requirements VALUES(4049,318,11,'Find out what types of gymnastics are available in other countries.  What types of gymnastics are represented in the Olympics?');
INSERT INTO badge_optional_requirements VALUES(4050,318,12,'How is gymnastics different for girls than boys?  What events can boys compete in that the girls don’t?  What events do the girls compete in?  Why do you think there are differences?');
INSERT INTO badge_optional_requirements VALUES(4051,318,13,'Learn the most common injuries in gymnastics and how to prevent and treat them.');
INSERT INTO badge_optional_requirements VALUES(4052,318,14,'What careers are there that use gymnastics? Think about things like choreographers, professional cheerleaders, gymnastic instructor, etc.  What type of education might you need?  What type of pay could you expect?  What type of hours might you have to work? Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(4053,319,3,'Find a modern haiku literary journal, and read some haiku from it.');
INSERT INTO badge_optional_requirements VALUES(4054,319,4,'Learn what shasei means.  Why is this technique difficult to master in a Haiku?');
INSERT INTO badge_optional_requirements VALUES(4055,319,5,'Find at least three haiku-writing competitions. Consider entering one, or holding a haiku-writing competition with your family or troop.');
INSERT INTO badge_optional_requirements VALUES(4056,319,6,'Read a book on haiku, such as William J. Higginson’s The Haiku Handbook or Cor van den Heuvel’s The Haiku Anthology.');
INSERT INTO badge_optional_requirements VALUES(4057,319,7,'What is the importance of a seasonal reference in haiku? List at least twenty words with seasonal associations.');
INSERT INTO badge_optional_requirements VALUES(4058,319,8,'Create a piece of art to illustrate a haiku you read or wrote.');
INSERT INTO badge_optional_requirements VALUES(4059,319,9,'Read a biography of someone who wrote haiku.');
INSERT INTO badge_optional_requirements VALUES(4060,319,10,'Study the works of famous haiku poets like Matsuo Bashō, Yosa Buson, and Kobayashi Issa.');
INSERT INTO badge_optional_requirements VALUES(4061,319,11,'Discuss how emotions and moments are captured in haiku and write one expressing a personal emotion.');
INSERT INTO badge_optional_requirements VALUES(4062,319,12,'Explore how nature is depicted in haiku and write a haiku inspired by a natural setting.');
INSERT INTO badge_optional_requirements VALUES(4063,319,13,'Write a haiku for each of the four seasons.');
INSERT INTO badge_optional_requirements VALUES(4064,319,14,'Learn about the cultural significance of haiku in Japanese society.');
INSERT INTO badge_optional_requirements VALUES(4065,319,15,'Learn about the history of Haiku and when it originated.');
INSERT INTO badge_optional_requirements VALUES(4066,319,16,'Learn how, in haiku, you write about what causes your reactions to stimuli as opposed to writing about your reactions. Why is it important in haiku to write about what’s taken in by your five senses, as opposed to your interpretation of your five senses or your imagination?');
INSERT INTO badge_optional_requirements VALUES(4067,319,17,'Participate in a group activity to create a renku.  Understand how a renku differs from Haiku.');
INSERT INTO badge_optional_requirements VALUES(4068,319,18,'Attend or organize a haiku writing workshop.');
INSERT INTO badge_optional_requirements VALUES(4069,319,19,'Is there a local haiku writing group in your area? Find out.');
INSERT INTO badge_optional_requirements VALUES(4070,319,20,'Learn about the difference between Japanese and English haiku.');
INSERT INTO badge_optional_requirements VALUES(4071,319,21,'Earn the poetry or poetry memorization badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4072,319,22,'Memorize at least three haiku and their authors.');
INSERT INTO badge_optional_requirements VALUES(4073,319,23,'Translate a haiku from Japanese into English and discuss the challenges of translation.');
INSERT INTO badge_optional_requirements VALUES(4074,319,24,'Discuss how Haiku inspires music.  Listen to at least three musical compositions inspired by Haiku. With your troop or family, host a haiku recitation night.');
INSERT INTO badge_optional_requirements VALUES(4075,321,3,'Save up some of your own money and donate at least $5 to your non-profit.');
INSERT INTO badge_optional_requirements VALUES(4076,321,4,'How can your local salon get involved? See if your non-profit has any programs or other way they work with salons. You can also talk with local salons to find out what they do with long cut hair.');
INSERT INTO badge_optional_requirements VALUES(4077,321,5,'Host a fundraiser to raise money for your non-profit. Please check with your non-profit to see if they have any specific guidelines.');
INSERT INTO badge_optional_requirements VALUES(4078,321,6,'Try on different wigs with some friends.  Discuss how the difference styles make you feel.  How important is hair to your own self confidence? Discuss why  you think providing hair pieces to those who need them is so important.');
INSERT INTO badge_optional_requirements VALUES(4079,321,7,'Learn about the history of your non-profit.  Who founded it and why?  How long have they been around?');
INSERT INTO badge_optional_requirements VALUES(4080,321,8,'Learn about the most common types of hair loss your non-profit battles.');
INSERT INTO badge_optional_requirements VALUES(4081,321,9,'Earn the Hair Styling badge at your current level and focus on styles that a person can wear after donating their hair.');
INSERT INTO badge_optional_requirements VALUES(4082,321,10,'Earn the Hair Care badge  at your current level.  Be able to explain how this relates to donating hair.');
INSERT INTO badge_optional_requirements VALUES(4083,321,11,'Learn how hair pieces are made.');
INSERT INTO badge_optional_requirements VALUES(4084,322,3,'Research how hairbrushes and combs are made.  How many different types of comb are there? What are the bristles of a hairbrush made from?');
INSERT INTO badge_optional_requirements VALUES(4085,322,4,'Learn how to make your own hair ornaments, such as scrunchies or crocheted bun covers and make one.');
INSERT INTO badge_optional_requirements VALUES(4086,322,5,'Learn about careers in the hair industry, such as hair care product manufacturers (think hairspray makers, or shampoo/conditioner producers), or hairdressers/barbers.  If possible, shadow someone for a day who works in the hair industry.');
INSERT INTO badge_optional_requirements VALUES(4087,322,6,'With your parents’ permission learn how to use a curling iron or a straightener.');
INSERT INTO badge_optional_requirements VALUES(4088,322,7,'Have a fashion show with your family, friends or group and model different hairstyles.');
INSERT INTO badge_optional_requirements VALUES(4089,322,8,'Earn the Good Grooming badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4090,322,9,'Look at pictures of hairstyles from days gone by and try one of them.  Do you like it? Would you want to wear it all the time?');
INSERT INTO badge_optional_requirements VALUES(4091,322,10,'Read a book, watch a video, or go online (with your parent’s permission) to find out how hair ornaments are made.');
INSERT INTO badge_optional_requirements VALUES(4092,322,11,'Research ways in which you can improvise with other objects to stand in for something you don’t have, such as using crochet hooks, knitting needles, or pencils to substitute for sticks.  DO NOT use rubber/elastic bands to substitute for regular hair-wraps; they will hurt when you try to take them out.');
INSERT INTO badge_optional_requirements VALUES(4093,322,12,'Every day for one week try a new hairstyle (Levels 3-5 need to do this for two weeks in order to complete this requirement).  Which one do you like best?  Be creative.');
INSERT INTO badge_optional_requirements VALUES(4094,322,13,'Learn about hair dyes and how they are made.');
INSERT INTO badge_optional_requirements VALUES(4095,322,14,'Find pictures of different hairstyles and make a collage, poster, or scrapbook page of them.  Be sure to include why you like or dislike each one.  Show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4096,322,15,'Learn about ways to do your hair that require the use of objects that you would not normally think of putting on your head, such as beading, or wrapping a strand of hair with embroidery floss.');
INSERT INTO badge_optional_requirements VALUES(4097,322,16,'Learn how to braid your hair and demonstrate at least one different braid, such as a French braid, cowgirl braid, herringbone braid, rope, etc.');
INSERT INTO badge_optional_requirements VALUES(4098,322,17,'Earn the Hair Styling Badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4099,322,18,'Learn about different types of buns and demonstrate at least one, such as a regular bun or a braided bun.  Find out if there are any special tools/ornaments that can help you get a bun you like.');
INSERT INTO badge_optional_requirements VALUES(4100,322,19,'Earn the Hair Care badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4101,322,20,'Learn how to create a chignon and try wearing one for a day.  Do you like it?');
INSERT INTO badge_optional_requirements VALUES(4102,322,21,'Learn about the history and culture around certain hair styles, such as Afros, Mohawks, and cornrows.');
INSERT INTO badge_optional_requirements VALUES(4103,325,3,'Listen to Hank the Cowdog songs.  Which is your favorite? Preschool: Listen one song. Levels 1-2: Listen three songs. Levels 3-4: Listen five. Level 5: Listen seven.');
INSERT INTO badge_optional_requirements VALUES(4104,325,4,'Listen to one of the earliest Hank stories that were written for a newspaper.');
INSERT INTO badge_optional_requirements VALUES(4105,325,5,'Listen to an audio of a Hank book. Which character’s voice do you like best? Try imitating the characters’ voices. Which one can you do best?');
INSERT INTO badge_optional_requirements VALUES(4106,325,6,'Make a list of your favorite Hank quotations, and share at least one of them with your family, friends, and group. Preschool: List one quote. Levels 1-2: List three quotes. Levels 3-4: List five. Level 5: List eight.');
INSERT INTO badge_optional_requirements VALUES(4107,325,7,'Many times Hank and Drover mix up their figures of speech – “Dogs who live in glass houses mustn’t call kettles black,” for example.  Make a list of at least five of these mix-ups and then work out which are the correct sayings.');
INSERT INTO badge_optional_requirements VALUES(4108,325,8,'Read all the Hank books in order.  Which is your favorite?');
INSERT INTO badge_optional_requirements VALUES(4109,325,9,'Act out a Hank song while someone else sings it.  Perform your act for your family, friends, and group');
INSERT INTO badge_optional_requirements VALUES(4110,325,10,'Write a review of a Hank book you have read and show it to your family, friends, and group');
INSERT INTO badge_optional_requirements VALUES(4111,325,11,'Hank the Cowdog products have gone beyond books and audios now.  Look online (with your parent’s permission) and make a list of the other things relating to Hank that can be found.');
INSERT INTO badge_optional_requirements VALUES(4112,325,12,'Read one of the first Hank books and then read one of the most recently published ones and compare them.  How does the plot change as the series continues?');
INSERT INTO badge_optional_requirements VALUES(4113,325,13,'Discuss what lessons can be learned from the Hank the Cowdog books. Why are they worth reading?');
INSERT INTO badge_optional_requirements VALUES(4114,325,14,'Go to an event where John Erickson is one of the speakers.');
INSERT INTO badge_optional_requirements VALUES(4115,325,15,'Visit a ranch similar to the one depicted in books.');
INSERT INTO badge_optional_requirements VALUES(4116,325,16,'Participate in a community service project that revolves around the Hank the Cowdog books such as, donating a set of Hank the Cowdog books to your local library or other charitable organization or sponsoring a storytime at your local library where you read Hank the Cowdog books to younger children.');
INSERT INTO badge_optional_requirements VALUES(4117,325,17,'Earn the Cowboy/Cowgirl badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4118,326,3,'What is Quidditch? Learn about the history of the game and some famous Quidditch teams in the Wizarding world. What are the different positions? The different objects used? Name some of the positions that characters from the book play, such as Harry playing seeker for the Gryffindor team.');
INSERT INTO badge_optional_requirements VALUES(4119,326,4,'Hogwarts is not the only Wizarding school in the world. How many other Wizarding schools are there and what countries are they located in? If given the option, which school would you attend and why?');
INSERT INTO badge_optional_requirements VALUES(4120,326,5,'A major theme in Harry Potter is having courage. How does Harry display courage and bravery on multiple occasions? List examples from the books or movies. If you would like, earn the Courage badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4121,326,6,'If possible, visit the Wizarding World of Harry Potter in Orlando or Hollywood. If it’s not possible, research the theme park online and learn about its history. Which rides would you want to go on? Which foods would you want to eat?');
INSERT INTO badge_optional_requirements VALUES(4122,326,7,'The series has some unique food and drinks. Find a recipe online from the series and recreate it at home. Examples include pumpkin juice, treacle tart, Hogwarts steak and kidney pie, cauldron cakes, etc.');
INSERT INTO badge_optional_requirements VALUES(4123,326,8,'There are several magical creatures featured throughout the series, including house elves, goblins, hippogriffs, mermaids, werewolves, ghosts, unicorns, etc. Pick two magical creatures and learn about them and how they relate to Harry Potter’s world. What occupations do they typically have? Where are they most commonly found? Of the two creatures you picked, who does Harry Potter encounter and how do they help or hinder his journey? For example, if you picked house elves, you can talk about how Dobby both helped and hindered Harry at different points in the series.');
INSERT INTO badge_optional_requirements VALUES(4124,326,9,'Research the different classes available at Hogwarts. Name as many as you can think of. If you could take classes there, which ones would you take? Who were some of your favorite teachers from the series? If you could create your own class, what would it be?');
INSERT INTO badge_optional_requirements VALUES(4125,326,10,'As students get older, they must take exams before they can graduate. Learn about the O.W.L.S. and the N.E.W.T.S. What subjects do these exams cover and what must students do to pass each one?');
INSERT INTO badge_optional_requirements VALUES(4126,326,11,'There are many occupations throughout the Wizarding World. Name as many as you can think of, such as Auror, Ministry of Magic worker, dragon trainer, Hogwarts teacher, etc. Pick your top three occupations and learn about what a wizard or witch must do to qualify for that job or occupation. What sort of post-Hogwarts education would you need?');
INSERT INTO badge_optional_requirements VALUES(4127,326,12,'Research wands and how they are made. What are the different wand cores you can have? What type of wood can a wand be made out of? Design your own wand, and what type of core and wood it would be made from. With a parent’s permission, you can take the Pottermore quiz for what wand you might have.');
INSERT INTO badge_optional_requirements VALUES(4128,326,13,'Learn about the many different locations visited in the Harry Potter series. Pick one and explain how it is relevant to the story and how it affected the characters. Learn about it’s history and which characters, if any, lived there. Examples include: Godric’s Hollow, Shell Cottage, the Burrow, Hogsmeade, Ministry of Magic, etc.');
INSERT INTO badge_optional_requirements VALUES(4129,326,14,'Potions are explored throughout the series, some good and some bad. Name at least ten potions, what they do, and some of the ingredients needed for each one. If you could create your own potion, what it do and what ingredients would it need? Examples include: Polyjuice Potion, Love Potion, Wolfsbane Potion, etc.');
INSERT INTO badge_optional_requirements VALUES(4130,326,15,'Who is the cast of the Harry Potter movies? Pick ten actors or actresses and learn about them. Who is your favorite and why?');
INSERT INTO badge_optional_requirements VALUES(4131,326,16,'What sort of shops and restaurants would you find in Diagon Alley? If possible, find a virtual tour of Diagon Alley online and explore it. Name several of the shops that Hogwarts students need to visit in order to prepare for the school year.');
INSERT INTO badge_optional_requirements VALUES(4132,326,17,'There are many different modes of transportation in the Wizarding world, such as broomstick, floo powder, apparition, portkey, etc. Learn about each one. Which way would you use to travel if you could?');
INSERT INTO badge_optional_requirements VALUES(4133,326,18,'Make your own Harry Potter costume, such as a Hogwarts uniform or invisibility cloak.');
INSERT INTO badge_optional_requirements VALUES(4134,326,19,'Create a craft related to the series, such as a Christmas ornament, t-shirt, magnet, etc.');
INSERT INTO badge_optional_requirements VALUES(4135,326,20,'Participate in a charity event related to the series, such as a book drive.');
INSERT INTO badge_optional_requirements VALUES(4136,326,21,'Learn about the Patronus Charm. What Patronus would you like to have? With a parent’s permission, you can take the quiz on Pottermore to find out what your Patronus might be.');
INSERT INTO badge_optional_requirements VALUES(4137,327,3,'Learn about the hats worn for different jobs, such as a chef’s toque, a cowboy’s Stetson, a policeman’s helmet or a builder’s hard hat. What makes these hats right for their specific jobs?');
INSERT INTO badge_optional_requirements VALUES(4138,327,4,'Learn about hats worn in the past, such as a jester’s hat, a Phrygian cap, a hennin hat, tricorne or bicorne hats, or a mob cap. Does anyone still wear this type of hat?');
INSERT INTO badge_optional_requirements VALUES(4139,327,5,'Make a hat for yourself, a younger child or a doll.');
INSERT INTO badge_optional_requirements VALUES(4140,327,6,'Learn about military headgear, such as bearskins, pith helmets or garrison caps. When and why would each type be worn, and by whom?');
INSERT INTO badge_optional_requirements VALUES(4141,327,7,'Decorate a plain or homemade hat.');
INSERT INTO badge_optional_requirements VALUES(4142,327,8,'Read a nonfiction book about hats.');
INSERT INTO badge_optional_requirements VALUES(4143,327,9,'Look at pictures of headdresses worn in the past. Would you have liked to wear any of them?  What is the difference between a headdress and a hat?');
INSERT INTO badge_optional_requirements VALUES(4144,327,10,'Read a biography of a person famous for the hats they wore, such as Queen Elizabeth II, Queen Elizabeth the Queen Mother, Kate Middleton, or Clementine Churchill.');
INSERT INTO badge_optional_requirements VALUES(4145,327,11,'Learn about hats worn in other countries, such as the Mexican sombrero or Moroccan fez. Which do you like the best?');
INSERT INTO badge_optional_requirements VALUES(4146,327,12,'Find a store that has a hat section and look round it. How many different styles of hat can you find? What is the price range?');
INSERT INTO badge_optional_requirements VALUES(4147,327,13,'Learn about a famous hat designer, such as Bill Cunningham, Philip Treacy, Freddie Fox or Simone Mirman. Who have they designed hats for?');
INSERT INTO badge_optional_requirements VALUES(4148,327,14,'At what sort of events are hats commonly worn today? Look at pictures or watch a video clip of at least one of these events, such as a royal wedding, Kentucky Derby, Ascot or a royal garden party, and focus on the hats being worn. Which styles of hat did you see the most?');
INSERT INTO badge_optional_requirements VALUES(4149,327,15,'What are fascinators? What is the difference between fascinators and hatinators?  Look at pictures of fascinators and hatinators; which do you like best?');
INSERT INTO badge_optional_requirements VALUES(4150,327,16,'Learn how to store hats properly and safely, so they don’t get damaged, and how to clean a hat properly.');
INSERT INTO badge_optional_requirements VALUES(4151,327,17,'Learn proper hat etiquette for men and women in various cultures and in various times and places. Should you wear a hat indoors? What about in church? What does it mean to “tip your hat”?');
INSERT INTO badge_optional_requirements VALUES(4152,327,18,'Make a fascinator or hatinator.');
INSERT INTO badge_optional_requirements VALUES(4153,327,19,'Make an origami hat.');
INSERT INTO badge_optional_requirements VALUES(4154,327,20,'Learn about hat pins and view a collection of them.');
INSERT INTO badge_optional_requirements VALUES(4155,327,21,'Visit a hat exhibit.');
INSERT INTO badge_optional_requirements VALUES(4156,329,3,'Help plan a healthy menu for your family for one week. You may not use any processed or prepackaged foods. Try to stick with fresh fruits and vegetables, whole grains, dairy, and lean protein. Boxed macaroni and cheese, frozen corn dogs, potato chips, etc. are not allowed. Don’t forget to plan for snacks.  Items like cheese sticks, yogurt, carrots and celery, or fresh fruit are great to have on hand.');
INSERT INTO badge_optional_requirements VALUES(4157,329,4,'The harder an activity, the higher your heart rate and the more calories your body is burning. To find your heart rate, count the number of beats in 6 seconds and multiply by 10. Calculate your heart rate (bpm = beats per minute) for the activities listed below: Standing Stretching Walking Strength training Jogging Jumping jacks Sprinting Sitting If you have problems getting your heart rate up, try “interval” training. This simply means that you do easier activities in between the harder ones while still keeping your body moving. For example, walk for 2 minutes, jog for 1 minute, walk, jog, walk, jog, etc.');
INSERT INTO badge_optional_requirements VALUES(4158,329,5,'The harder your body works, the more calories you burn.  Following is a list of exercises and the approximate calories they burn per minute. Sitting = 1.1 calories per minute Standing = 1.4 calories per minute Stretching = 3 calories per minute Walking = 4 calories per minute Strengthening = 5.3 calories per minute Jogging = 7 calories per minute Jumping Jacks = 10 calories per minute Sprinting = 15 calories per minute Look at the list of foods below and figure out how many minutes you would have to exercise using each of the above methods to burn off the calories you just ate. Divide the number of calories by the calories burned per minute for each exercise. For example a 32 oz soda has 400 calories. If you choose to walk off the calories you would divide 400 by 4 giving you 100 minutes (1 hour and 40 minutes) of walking in order to burn off the calories you just consumed. 3.5 oz Chips = 560 calories 3.5 oz Pretzels = 385 calories 32 oz Soda = 400 calories 32 oz Diet Soda = 0 calories 1 Tbsp Mayonnaise = 94 calories Super Size Fries = 450 calories Small Fries = 210 calories');
INSERT INTO badge_optional_requirements VALUES(4159,329,6,'Put together a list of ways you can make healthy choices when eating out. Then get menus for your favorite 3 restaurants and make a list of what you could order that would be a healthier choice than your normal meal. Ideas might include: Order salad dressing on the side and ask for fat free or light. Drink water, iced tea, or milk instead of soda. Skip the super size and choose a small order. Choose grilled or baked foods instead of deep fried. Eliminate mayonnaise and cheese.');
INSERT INTO badge_optional_requirements VALUES(4160,329,7,'Choose a health or fitness goal for yourself. Maybe you want to stop drinking soda, or limit dessert to just the weekends.  Maybe you want to add 10 push ups a day or be able to bench press 50 pounds. Whatever it is, write it down and post it somewhere where you will see it every day. Set a time frame to complete your goal.  When your goal is reached, this requirement is complete, but you are encouraged to continue adding new goals. This week you may try drinking 6 glasses of water daily.  Next week you could go jogging once a week. Goal setting should be a healthy part of your everyday life. Follow the tips listed below to create a good goal: Be positive – A goal is something you want to add to you life, not subtract. If you are trying to change a bad habit such as biting your nails, your goal should be something like, “I will chew sugarless gum instead of biting my nails.” Be specific – Saying you want to “eat better” is too general.  Instead, try saying, “I will eat one piece of fruit everyday.” Make sure it is attainable – Goals should be achievable in a reasonable amount of time.  If you make them too difficult you will get discouraged.');
INSERT INTO badge_optional_requirements VALUES(4161,329,8,'Get others involved with your goal to be healthy and fit.  Ask your mom to walk with you, your friends to try to eat more fruit with you, or your doctor to give you advice. Having others to rely on helps everyone achieve their goals. Get at least 3 other people to get involved in some way.');
INSERT INTO badge_optional_requirements VALUES(4162,329,9,'With a parent’s permission, watch an episode of a television show or a movie (no cartoons and no news). Then fill in the following information for at least one character: Name Name of TV show Time and date of show Key characters Which character is the most fit? What types of exercise to they do, or do you think they do? What types of food do you they eat, or do you think they eat? Does this character’s activity and food behavior mesh with his or her appearance? In other words, do they look fit even though their character is a couch potato on the show? Does this character watch a lot of TV? Does the actor or actress who plays this character exercise? Is this character a good role model for you?');
INSERT INTO badge_optional_requirements VALUES(4163,329,10,'Go to the store and compare the labels on different food items. What are carbs, saturated fats, sugars, calories, etc? Learn about what each item that is listed on a food label is.');
INSERT INTO badge_optional_requirements VALUES(4164,329,11,'Create an exercise routine and stick to it for one week.');
INSERT INTO badge_optional_requirements VALUES(4165,330,3,'Learn what foods are good for your heart. Preschool: Identify three foods. Level 1: Identify five foods. Levels 2-3: Identify ten foods. Levels 4-5: Identify fifteen foods. In contrast, try to name categories of food that are bad for your heart.');
INSERT INTO badge_optional_requirements VALUES(4166,330,4,'Level 3 and Up Only: Become CPR certified.');
INSERT INTO badge_optional_requirements VALUES(4167,330,5,'Know what a heart attack is, the signs of it in both men and women, and what to do if you witness someone having a heart attack.');
INSERT INTO badge_optional_requirements VALUES(4168,330,6,'Describe the individual components of blood including red blood cells, white blood cells, plasma, and platelets. What is the role of each component?');
INSERT INTO badge_optional_requirements VALUES(4169,330,7,'How much blood does an average heart pump in a minute? How many times does it beat in a minute How big is your heart?');
INSERT INTO badge_optional_requirements VALUES(4170,330,8,'Your heart is a unique muscle in your body. What makes it unique? Can you make your knee bend? Can you make your heart stop beating?');
INSERT INTO badge_optional_requirements VALUES(4171,330,9,'Learn about different heart problems. Are there any heart issues in your family? If so, understand what their issue is, any diet or activity adjustments, and how this will impact their lives.');
INSERT INTO badge_optional_requirements VALUES(4172,330,10,'Learn to make a heart healthy meal and share it with someone who would benefit from that diet.');
INSERT INTO badge_optional_requirements VALUES(4173,330,11,'Take a field trip to a doctor’s office, hospital, nursing home, or other health facility.');
INSERT INTO badge_optional_requirements VALUES(4174,330,12,'Participate in a community service project that involves the health of the human heart. Perhaps a heart health walk.');
INSERT INTO badge_optional_requirements VALUES(4175,330,13,'Accompany an eligible person to donate blood and talk to people donating about why they donate.');
INSERT INTO badge_optional_requirements VALUES(4176,330,14,'At your next doctor office visit, ask if you could listen to your heart and/or look at a model of your heart.');
INSERT INTO badge_optional_requirements VALUES(4177,330,15,'Understand different heart issues, such as Coronary Artery Disease.');
INSERT INTO badge_optional_requirements VALUES(4178,330,16,'Understand what a pacemaker (or ICD) device is, what an electrocardiogram (ECG or EKG) is and what it tells you, what is the difference between an electrocardiogram and an echocardiogram?');
INSERT INTO badge_optional_requirements VALUES(4179,330,17,'What is a stress test and what will that tell you?');
INSERT INTO badge_optional_requirements VALUES(4180,330,18,'What is the difference between arteries and veins? What are capillaries?');
INSERT INTO badge_optional_requirements VALUES(4181,330,19,'Understand blood pressure. What is a good blood pressure? What indicates a low blood pressure? What happens if your blood pressure is too high? What happens if your blood pressure is too low?');
INSERT INTO badge_optional_requirements VALUES(4182,330,20,'Visit a museum or health center with a heart health display.');
INSERT INTO badge_optional_requirements VALUES(4183,330,21,'Earn the Health and Fitness badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4184,330,22,'Explain some things you can do to support a loved one who may have to have surgery on their heart. How can you show compassion as they recover?');
INSERT INTO badge_optional_requirements VALUES(4185,330,23,'Does your religion refer to a different kind of heart related to your character? Explore this representation as it relates to your hand on your heart during the pledge, various spiritual references related to your heart.');
INSERT INTO badge_optional_requirements VALUES(4186,331,3,'Research a significant heat wave event in history.  How long did it last?  What temperatures did it reach? How large of an area was effected?  How many people died?  How did people at that time stay cool?');
INSERT INTO badge_optional_requirements VALUES(4187,331,4,'Investigate the highest recorded temperatures and heat waves in your local area.  Create a chart or timeline showing these records.');
INSERT INTO badge_optional_requirements VALUES(4188,331,5,'Assemble a heat wave preparedness kit including items such as water, a fan, cooling packs, and sunscreen.');
INSERT INTO badge_optional_requirements VALUES(4189,331,6,'Define the urban heat island effect.  Conduct an experiment to measure temperature differences between urban and rural areas.');
INSERT INTO badge_optional_requirements VALUES(4190,331,7,'Develop a family or community heat wave safety plan.  Include steps for staying safe indoors and outdoors during extreme heat.');
INSERT INTO badge_optional_requirements VALUES(4191,331,8,'Examine how heat waves affect energy consumption and power grids.  Create an energy-saving plan for your home during heat waves.');
INSERT INTO badge_optional_requirements VALUES(4192,331,9,'Learn about different weather instruments used to measure temperature and humidity.  Build a simple thermometer, hygrometer or other weather device and use it to record local weather data.');
INSERT INTO badge_optional_requirements VALUES(4193,331,10,'Learn about at least 5 heat wave myths and explain why they are incorrect.');
INSERT INTO badge_optional_requirements VALUES(4194,331,11,'Explore the relationship between heat waves and air quality.  Create an infographic showing how heat waves can worsen air pollution.');
INSERT INTO badge_optional_requirements VALUES(4195,331,12,'Compare and contrast heat wave occurrences in different parts of the world.  Choose one region and research how they cope with extreme heat.');
INSERT INTO badge_optional_requirements VALUES(4196,331,13,'Learn about the role of emergency services during heat waves.');
INSERT INTO badge_optional_requirements VALUES(4197,331,14,'Learn what a cooling center is and why they are needed during a heat wave.');
INSERT INTO badge_optional_requirements VALUES(4198,331,15,'Learn which foods can naturally cool the body.  Create a meal or snack using these foods.');
INSERT INTO badge_optional_requirements VALUES(4199,331,16,'Investigate architectural and urban design strategies that mitigate heat waves.  Design a model or drawing of a heat-resilient building or community space.');
INSERT INTO badge_optional_requirements VALUES(4200,331,17,'Research the effects of prolonged heat waves on mental health.  Discuss strategies to maintain mental well-being during extreme heat.');
INSERT INTO badge_optional_requirements VALUES(4201,331,18,'Study the impact of heat waves on local ecosystems and wildlife.');
INSERT INTO badge_optional_requirements VALUES(4202,331,19,'Create a piece of art (e.g., drawing, painting, sculpture) that represents the effects of heat waves.');
INSERT INTO badge_optional_requirements VALUES(4203,331,20,'Earn the Weather badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(4204,332,3,'Just like symbols, colors used in heraldry had different meanings. Learn what colors were commonly used in the design of coats of arms and what they symbolized.');
INSERT INTO badge_optional_requirements VALUES(4205,332,4,'Many symbols were used on the shield in a coat of arms. Learn the names of at least three symbols.');
INSERT INTO badge_optional_requirements VALUES(4206,332,5,'Some shields are divided into different parts using stylized lines. Learn the names of 4 types of lines and what they represent.');
INSERT INTO badge_optional_requirements VALUES(4207,332,6,'Many countries are represented by a crest or coat of arms. Learn about the United States Coat of Arms. What symbols are used to represent our country and what do they mean? Learn about at least one other country’s coat of arms and its symbols.');
INSERT INTO badge_optional_requirements VALUES(4208,332,7,'Be able to accurately blazon the United States Coat of Arms.');
INSERT INTO badge_optional_requirements VALUES(4209,332,8,'Earn the Genealogy badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(4210,332,9,'Families in countries such as Scotland or Ireland used special fabric designs called a Tartan to represent them. Learn about tartans and find out about one famous person who wore one.');
INSERT INTO badge_optional_requirements VALUES(4211,332,10,'Learn about what coat of arms were put on (clothing, shields, etc.) How were they displayed to the world? What was the process? Why was it so important to display your family’s crest?');
INSERT INTO badge_optional_requirements VALUES(4212,332,11,'Make your own cardboard shield and paint your family’s crest on it.');
INSERT INTO badge_optional_requirements VALUES(4213,332,12,'How did families decide what went into their coat of arms or how it was designed? Was it based on their status? Profession? Where they lived?');
INSERT INTO badge_optional_requirements VALUES(4214,332,13,'Learn about Medieval knights coat of arms and what they represented. Design your own Medieval-style coat of arms.');
INSERT INTO badge_optional_requirements VALUES(4215,332,14,'Know the difference between a coat of arms, a family crest, and heraldic badges.');
INSERT INTO badge_optional_requirements VALUES(4216,333,3,'Comparison shop for the equipment used in making teas. Compare prices, versatility, and quality of at least three brands of the same item.');
INSERT INTO badge_optional_requirements VALUES(4217,333,4,'Comparison shop for herbs. Choose which herbs you will price and compare them in bags, in bulk, organically grown and commercially grown. What would be the disadvantages of buying teas in bulk?');
INSERT INTO badge_optional_requirements VALUES(4218,333,5,'Investigate the growing, harvesting, processing, and distribution methods of herbs used in teas. What does it mean when an herb is wild-grown? Organically grown? Fair traded?');
INSERT INTO badge_optional_requirements VALUES(4219,333,6,'Tour an herb farm and/or processing facility. At least two aspects of the operation need to be observed.');
INSERT INTO badge_optional_requirements VALUES(4220,333,7,'Some people like sweeteners in their teas. Find out how much of several different sweeteners it takes to sweeten a cup of tea. Make a cup or two of tea, divide it into 2-ounce servings and sweeten it with several different sweeteners. Remember to use the correct fraction of the sweetener amount that is called for when using it for a full cup of tea. Which do you like best? Which sweeteners are ‘better for you’ and why?');
INSERT INTO badge_optional_requirements VALUES(4221,333,8,'Make a map of either the world or one country. Show where at least 6 different herbs are grown.');
INSERT INTO badge_optional_requirements VALUES(4222,333,9,'Make a color poster (use photographs or color some line drawings) of ten herbs. Include a minimum of two of the following types of information: Common name Scientific name Medicinal uses Places it’s grown Type of climate the herb prefers');
INSERT INTO badge_optional_requirements VALUES(4223,333,10,'Learn how to blend teas or teas & juices to make refreshing punches. You may make your own new recipe or try at least three recipes someone else has developed. Share your favorite recipe with other people.');
INSERT INTO badge_optional_requirements VALUES(4224,333,11,'Hold a tea party for at least two friends. Serve at least two different herb teas.');
INSERT INTO badge_optional_requirements VALUES(4225,333,12,'Make your own mug or tea cup in a ceramics class or studio or purchase a tea set and paint it so the pieces are coordinated.');
INSERT INTO badge_optional_requirements VALUES(4226,333,13,'Learn about the other ways to use herbal infusions other than drinking them. Find at least one tea that is applied to the skin. Find at least two recipes that use herb teas in baking or other products.');
INSERT INTO badge_optional_requirements VALUES(4227,334,3,'Make an herbal beauty product, such as a hair rinse or facial scrub.');
INSERT INTO badge_optional_requirements VALUES(4228,334,4,'Make a craft using herbs.');
INSERT INTO badge_optional_requirements VALUES(4229,334,5,'Read a book or magazine about herbs.');
INSERT INTO badge_optional_requirements VALUES(4230,334,6,'Learn how to substitute fresh herbs for dry herbs in a recipe. A general guideline when using fresh herbs in a recipe is to use three times as much as you would use dried. You’ll usually be more successful in substituting fresh herbs for dried herbs, rather than the other way around.');
INSERT INTO badge_optional_requirements VALUES(4231,334,7,'Learn about the role herbs have played in religion. For example, myrrh and frankincense in Christianity, holy basil or Tulsi in Hinduism, or white sage and cedar for the  Cherokee.');
INSERT INTO badge_optional_requirements VALUES(4232,334,8,'Learn about how herbs can be used as a natural pest control.');
INSERT INTO badge_optional_requirements VALUES(4233,334,9,'Attend an herb festival.');
INSERT INTO badge_optional_requirements VALUES(4234,334,10,'Learn about different herbs found around the world.  Try at least 3 that are not usually found in the in your country.');
INSERT INTO badge_optional_requirements VALUES(4235,334,11,'Learn about the role herbs have played throughout history.');
INSERT INTO badge_optional_requirements VALUES(4236,334,12,'Help make a recipe that uses at least 2 herbs.');
INSERT INTO badge_optional_requirements VALUES(4237,334,13,'Plant an herb garden. A few fun examples might be: A  pizza garden including herbs such as basil, garlic, oregano and parsley. A fragrant garden including herbs such as lavender, thyme, rosemary, mints or curry to make potpourri. A drink garden including herbs such as lemon balm for lemonade, chamomile for tea, or mints for tea.');
INSERT INTO badge_optional_requirements VALUES(4238,334,14,'Learn to dry herbs to make your own potpourri.');
INSERT INTO badge_optional_requirements VALUES(4239,334,15,'Create your own herb blend for use in cooking, such as an Italian herb mix.');
INSERT INTO badge_optional_requirements VALUES(4240,334,16,'Create a comforting and fragrant mix for your bath.');
INSERT INTO badge_optional_requirements VALUES(4241,335,3,'Participate in a service project that affects hiking. Examples might include picking up trash along trails, clearing trails, making signs for trail directions and rules, tree planting, etc.');
INSERT INTO badge_optional_requirements VALUES(4242,335,4,'Take an Alphabet Hike. Find something that starts with the letter A such as an ant, then B for butterfly, etc.');
INSERT INTO badge_optional_requirements VALUES(4243,335,5,'Take a Color Hike. Look around and see how many different colors you can find. Blue sky, dark green leaves, pink flowers, etc.');
INSERT INTO badge_optional_requirements VALUES(4244,335,6,'Take a Sound Hike. How many sounds can you hear? Birds chirping, sticks crunching, frogs croaking, etc.');
INSERT INTO badge_optional_requirements VALUES(4245,335,7,'Have a Habitat Hunt while you hike. How many animal habitats can you spot? Can you find a nest? An anthill? A dead log?');
INSERT INTO badge_optional_requirements VALUES(4246,335,8,'Learn tracking skills for your area to find out what animals have passed over or around your trails. For example in the foothills of California, you might learn to tell the difference between deer tracks and pig tracks and learn to recognize where wild pigs have wallowed or rubbed up against trees. Raccoon tracks and various bird tracks can also be frequently seen. Find out what animals are in your area and how to track them.');
INSERT INTO badge_optional_requirements VALUES(4247,335,9,'Learn how to leave trail signs. Divide your group in two (make sure to always have 2 adults in each group). Have the first group leave trail signs and see if the second group can follow the instructions. Make sure to clean up all trail signs when you are done.');
INSERT INTO badge_optional_requirements VALUES(4248,335,10,'Take a hike around your neighborhood for at least a half an hour. Observe the things around you. How many things do you see that you never noticed before?');
INSERT INTO badge_optional_requirements VALUES(4249,335,11,'Create a presentation about one of your hikes to show to a group of your choice. Show how you prepared for your hike, who went with you, what you saw, what the weather was like, etc.');
INSERT INTO badge_optional_requirements VALUES(4250,335,12,'Learn about careers that might be associated with hiking. Examples might include naturalist, botanist, biologist, wild life artist, photographer, a forestry worker, etc.');
INSERT INTO badge_optional_requirements VALUES(4251,335,13,'Make three different recipes for trail mixes or trail lunches.');
INSERT INTO badge_optional_requirements VALUES(4252,335,14,'Earn the First Aid badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4253,336,3,'Visit a Hindenburg exhibit either online or in person. Please get your parent’s permission before going online.');
INSERT INTO badge_optional_requirements VALUES(4254,336,4,'Draw and/or color a picture of the Hindenburg and share it with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4255,336,5,'Make a model of the Hindenburg. Share it with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4256,336,6,'Write an essay about one of the survivors of the Hindenburg and share it with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4257,336,7,'Watch a documentary on the Hindenburg and share what you learned with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4258,336,8,'Create a design for an airship that you would like to travel on. What kind of amenities would it have? How much would it cost to build? How much did it cost to build the Hindenburg? How much would it cost today?');
INSERT INTO badge_optional_requirements VALUES(4259,336,9,'Find out what kind of careers are available to work on an airship or airplane. Examples might include captain, flight attendant, mechanic, etc. What kind of education do you need for these jobs? What kind of pay can you expect? What hours would you have to work?');
INSERT INTO badge_optional_requirements VALUES(4260,336,10,'Pretend you are a reporter in 1937. Write a newspaper article about the Hindenburg crash and share it with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4261,336,11,'Find out what was served in the dining room of the Hindenburg and make one dish from that menu.');
INSERT INTO badge_optional_requirements VALUES(4262,336,12,'How much would it cost to travel from Frankfurt, Germany to Newark, NJ today? How much did it cost in 1937 on the Hindenburg?');
INSERT INTO badge_optional_requirements VALUES(4263,336,13,'Learn about the different decks of the Hindenburg and what you would find in each if you were a passenger.');
INSERT INTO badge_optional_requirements VALUES(4264,336,14,'With a parent’s approval, watch a video news clip of the actual Hindenburg crash on the internet. Write a short essay about what it might have been like to have been watching the crash from the ground. Use description of what you might have seen and how you might have felt. Show your essay to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4265,337,3,'Throw, or attend, a party specifically themed to your era.  Dress up in an era appropriate costume, eat era appropriate food, and play era appropriate music.');
INSERT INTO badge_optional_requirements VALUES(4266,337,4,'Listen to music from your chosen era. How does it differ from what people listen to today?');
INSERT INTO badge_optional_requirements VALUES(4267,337,5,'Learn about the food of your chosen era. What did people eat? How much did groceries cost compared to today? Where did food come from?');
INSERT INTO badge_optional_requirements VALUES(4268,337,6,'What was the art like in this era? Learn about at least one famous artist from your era.');
INSERT INTO badge_optional_requirements VALUES(4269,337,7,'Learn about the money of this era. What did the money of this era look like? What was the value based on? How much did things cost compared to today?');
INSERT INTO badge_optional_requirements VALUES(4270,337,8,'Learn about the trade of this era. What was imported/exported the most during this time? What were the most valuable commodities?');
INSERT INTO badge_optional_requirements VALUES(4271,337,9,'Learn about hairstyles of your chosen era. How did men and women wear their hair? Were there different styles for different classes of people?');
INSERT INTO badge_optional_requirements VALUES(4272,337,10,'How did people spend their free time? What did they do for entertainment? What toys did they have? Learn a game that was played during this era.');
INSERT INTO badge_optional_requirements VALUES(4273,337,11,'What kinds of jobs were available to men and women during this era?');
INSERT INTO badge_optional_requirements VALUES(4274,337,12,'What was transportation like in this era? How did people and products get from one place to the next?');
INSERT INTO badge_optional_requirements VALUES(4275,337,13,'Learn a dance appropriate to this era.');
INSERT INTO badge_optional_requirements VALUES(4276,337,14,'Watch a film or documentary that is based on your selected time period.');
INSERT INTO badge_optional_requirements VALUES(4277,337,15,'Read a book about your era.');
INSERT INTO badge_optional_requirements VALUES(4278,338,3,'Create a poster or diorama depicting the event that can teach someone something about it.');
INSERT INTO badge_optional_requirements VALUES(4279,338,4,'Visit a museum or exhibit about the event.');
INSERT INTO badge_optional_requirements VALUES(4280,338,5,'Watch a documentary about the event.');
INSERT INTO badge_optional_requirements VALUES(4281,338,6,'Find out if there have been any technological advances because of the event.  If so, what?  How will these advances help prevent future disastrous events or improve future beneficial events?');
INSERT INTO badge_optional_requirements VALUES(4282,338,7,'Read a biography of someone who lived through the event.');
INSERT INTO badge_optional_requirements VALUES(4283,338,8,'Learn a song inspired by the event.');
INSERT INTO badge_optional_requirements VALUES(4284,338,9,'Participate in a play or skit about the event.');
INSERT INTO badge_optional_requirements VALUES(4285,338,10,'Make a list of 10 pieces of trivia associated with the event that most people don’t know.');
INSERT INTO badge_optional_requirements VALUES(4286,338,11,'Learn about an animal affected by the event.');
INSERT INTO badge_optional_requirements VALUES(4287,338,12,'Find out if there are any holidays or events that commemorate your event.  If so, participate if possible.');
INSERT INTO badge_optional_requirements VALUES(4288,338,13,'Create a craft that represents the event in some way.');
INSERT INTO badge_optional_requirements VALUES(4289,338,14,'Participate in a community service project that supports either the repercussions of the event itself, or similar cause.');
INSERT INTO badge_optional_requirements VALUES(4290,339,3,'Create a timeline of 10 key events in regard to your historical site.');
INSERT INTO badge_optional_requirements VALUES(4291,339,4,'Watch a documentary about your historic site.');
INSERT INTO badge_optional_requirements VALUES(4292,339,5,'Make a craft of your historic site.');
INSERT INTO badge_optional_requirements VALUES(4293,339,6,'Design a poster or brochure or write a brief report about your historic site.');
INSERT INTO badge_optional_requirements VALUES(4294,339,7,'Read a book or magazine about your historical site.');
INSERT INTO badge_optional_requirements VALUES(4295,339,8,'If you were to visit the historical location in person, are there areas that are not open to the public?  What are they?  Why are they restricted?  Does the landmark have an entrance fee to visit it?  If so, how much? Do they have coupons or discounted days for students or scouts?');
INSERT INTO badge_optional_requirements VALUES(4296,339,9,'Draw a picture or take a picture of you and the historic site.');
INSERT INTO badge_optional_requirements VALUES(4297,339,10,'Explain how and why you should show respect when visiting a historic site.');
INSERT INTO badge_optional_requirements VALUES(4298,339,11,'Learn about a legend or myth in regard to your historic site.');
INSERT INTO badge_optional_requirements VALUES(4299,339,12,'What type of architecture was used when the historic site was built?');
INSERT INTO badge_optional_requirements VALUES(4300,339,13,'Locate and label your historic site on a map, showing its relation to surrounding regions.');
INSERT INTO badge_optional_requirements VALUES(4301,339,14,'Interview a local resident or historian to gain insights into personal stories and local anecdotes regarding your historical site.');
INSERT INTO badge_optional_requirements VALUES(4302,339,15,'Learn about how historic sites are preserved and maintained. Where does the money come from for upkeep?');
INSERT INTO badge_optional_requirements VALUES(4303,339,16,'Identify one or more key historical figures associated with your historic site and explain their impact on society.');
INSERT INTO badge_optional_requirements VALUES(4304,339,17,'Choose a specific time period in your historic site’s history and write a fictional journal entry as if you were living during that era.');
INSERT INTO badge_optional_requirements VALUES(4305,339,18,'Make a 3D model of your historic site.');
INSERT INTO badge_optional_requirements VALUES(4306,339,19,'Create a historical reenactment event or participate in one, showcasing a pivotal moment from your historic site’s past.');
INSERT INTO badge_optional_requirements VALUES(4307,339,20,'Write a reflective essay or hold a discussion on the lasting impact of your historic site on the region and the world.');
INSERT INTO badge_optional_requirements VALUES(4308,339,21,'Write a fictional story that weaves together historical facts and imaginative elements set at your historic site.');
INSERT INTO badge_optional_requirements VALUES(4309,339,22,'Find out if there are any current issues facing your historical site, such as environmental threats or urban development. Propose potential solutions.');
INSERT INTO badge_optional_requirements VALUES(4310,339,23,'Create a trivia quiz about your historical site and include a minimum of 10 questions.');
INSERT INTO badge_optional_requirements VALUES(4311,339,24,'Volunteer at your historical site if allowed. Help with tours, educational programs, or preservation work.');
INSERT INTO badge_optional_requirements VALUES(4312,339,25,'Participate in or organize a debate on the importance of preserving historical sites versus modern development.');
INSERT INTO badge_optional_requirements VALUES(4313,340,3,'Participate in a parade, play, concert, party or other celebration honoring an event or famous person from your country. You must learn at least one new fact from this event.');
INSERT INTO badge_optional_requirements VALUES(4314,340,4,'Learn or compose a song, ballad, or poem about a famous person or event in your country’s history. Perform/recite it for an audience or attend an event that includes the performance of the same work.');
INSERT INTO badge_optional_requirements VALUES(4315,340,5,'Visit a museum which features objects from your country’s history. This requirement can be repeated if each museum takes at least a half hour to go through it.  A tour through an online museum is also acceptable.');
INSERT INTO badge_optional_requirements VALUES(4316,340,6,'Learn to play a game that teaches or reinforces the history of your country or learn to play a traditional children’s game from your country, preferably one that has historical interest attached. Level 3 and Up: Can you find any information about how the games have changed over the years? Teach one of them to younger children.');
INSERT INTO badge_optional_requirements VALUES(4317,340,7,'Visit your country and visit at least one historical site while you are there.');
INSERT INTO badge_optional_requirements VALUES(4318,340,8,'Find out about the monetary system of your country. How has money changed in your country over the course of it’s history? Level 3 and Up: List the five most important agricultural products and the five most important industrial products for your country. Find out how the lists have changed through the years and how those changes have affected the country’s history and vice versa. Make sure you know from which parts of the country each product comes.');
INSERT INTO badge_optional_requirements VALUES(4319,340,9,'If you cannot visit your country in person, make a list of the ten sites you think are most important for a visitor to see and explain your rationale for each one. Level 3 and Up: Make a list of the twenty sites you think are important and explain your rationale for each one.');
INSERT INTO badge_optional_requirements VALUES(4320,340,10,'Create a timeline for your country showing each change in governmental form, name, or constitution. If your country has less than five such changes, write out at least a full paragraph about one of those changes..');
INSERT INTO badge_optional_requirements VALUES(4321,340,11,'Visit a part of your country that you haven’t seen before and pay attention to the history of the area. Tours of famous people’s houses, cemeteries, government buildings and monuments all count. If the history of an area is your emphasis for the day, this requirement can also be repeated up to four times.');
INSERT INTO badge_optional_requirements VALUES(4322,340,12,'Learn where the most important natural features or resources are—how have they affected the country’s history? Which parts of the country are more industrial or more rural?');
INSERT INTO badge_optional_requirements VALUES(4323,340,13,'Learn where the most important natural features or resources are—how have they affected the country’s history? Which parts of the country are more industrial or more rural? Badges with their own specific requirements: Canadian History');
INSERT INTO badge_optional_requirements VALUES(4324,341,3,'In ancient times people used herbs and plants to help cure ailments. Choose three herbs or other plants and learn what they were used to heal.');
INSERT INTO badge_optional_requirements VALUES(4325,341,4,'Sometimes women giving birth are helped by midwives as well as doctors. Learn what a midwife is. If possible, talk to a midwife and ask how she became interested in the midwifery field.');
INSERT INTO badge_optional_requirements VALUES(4326,341,5,'Learn about the history of the American Red Cross. Who pioneered it, and when?');
INSERT INTO badge_optional_requirements VALUES(4327,341,6,'Earn the Nursing History badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4328,341,7,'Understand how health care business has changed over the centuries. Research careers in the healthcare business, such as a doctor, midwife, chiropractor, physical therapist, pediatrician, surgeon, nurse, pharmacist, or pharmaceutical technician, etc. What kind of training/education is required? What are working hours typically like and what hourly pay-rate/salary can you expect? If possible, shadow someone for a day who works in the medical field for a living.');
INSERT INTO badge_optional_requirements VALUES(4329,341,8,'Write an essay about how the practice of medicine has changed over the centuries.');
INSERT INTO badge_optional_requirements VALUES(4330,341,9,'Ambulances are used to transport people to hospitals who are too severely injured or ill to bring themselves. Earn the Emergency Services badge at your level for ambulances or medi-flight.');
INSERT INTO badge_optional_requirements VALUES(4331,341,10,'Research different college options for those specializing in the medical field. How much do they cost, how long would it take to get your degree, what sort of facilities do they have, etc.?');
INSERT INTO badge_optional_requirements VALUES(4332,341,11,'Learn about the invention of anesthesia and how it affected medical history. Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(4333,341,12,'Healthy people do not become sick as often or as severely as unhealthy ones. Part of being healthy is good nutrition. Earn the Nutrition badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4334,341,13,'Many times in history large percentages of the population of a country have been wiped out by diseases such as cholera, typhoid, Black Death/bubonic plague, influenza, smallpox, etc., which were usually brought on by insanitary conditions. Research these disease epidemics. Preschool-Level 1: Learn about one epidemic. Level 2: Learn about two. Levels 3-5: Learn about three. How did each spread?');
INSERT INTO badge_optional_requirements VALUES(4335,341,14,'Diets have changed much over the centuries and the foods we eat today effect the body differently than foods eaten in the past. Research the effects that foods such as coffee, soft drinks/sodas, sugar, etc., can have on your health and body. Why should you be careful of how much of some of these foods you consume?');
INSERT INTO badge_optional_requirements VALUES(4336,341,15,'Choose a piece of medical equipment and learn the history behind, how it was invented and how it has changed the medical community.');
INSERT INTO badge_optional_requirements VALUES(4337,341,16,'Research the history of vaccines. What type of ingredients are used in vaccines, how do they work, and what are their effects on the body? Some people choose not to vaccinate themselves or their children. Learn why this is so. Do you agree or disagree? How have vaccines changed the world we live in today?');
INSERT INTO badge_optional_requirements VALUES(4338,341,17,'Learn about the history of the pharmaceutical industry. Learn about side effects of at least 3 popular drugs. Do you feel the benefits of the drug justify the side effects? How were these illnesses treated in the past? What were the side effects of previous treatments?');
INSERT INTO badge_optional_requirements VALUES(4339,343,3,'Try three different types of exercise, such as yoga, running, swimming, or dancing.');
INSERT INTO badge_optional_requirements VALUES(4340,343,4,'Keep a food journal for one week, noting balanced meals and portion sizes.');
INSERT INTO badge_optional_requirements VALUES(4341,343,5,'Establish a consistent sleep schedule, create a calming bedtime routine, and maintain a comfortable sleep environment to ensure 7-9 hours of restful sleep each night.  Discuss how sleep effects your physical, mental and emotional health.  Follow your schedule for at least 2 weeks.');
INSERT INTO badge_optional_requirements VALUES(4342,343,6,'Practice meditation and mindfulness techniques to reduce stress, enhance focus, and cultivate awareness of your thoughts and emotions.');
INSERT INTO badge_optional_requirements VALUES(4343,343,7,'Create a safe and fun obstacle course in your backyard or local park to boost cardiovascular fitness, coordination, and motor skills.');
INSERT INTO badge_optional_requirements VALUES(4344,343,8,'Take a hike out in nature.  Discuss the health benefits out getting outdoors for physical activity.');
INSERT INTO badge_optional_requirements VALUES(4345,343,9,'Attend classes or practice Tai Chi/Qigong for a month.  How do these holistic movement practices effect physical and mental well-being? Mental Wellness:');
INSERT INTO badge_optional_requirements VALUES(4346,343,10,'Engage in a brain-stimulating activity, such as solving puzzles, for 30 minutes a day for one week.');
INSERT INTO badge_optional_requirements VALUES(4347,343,11,'Practice mindfulness meditation for at least 10 minutes daily for two weeks.');
INSERT INTO badge_optional_requirements VALUES(4348,343,12,'Practice progressive muscle relaxation or a similar relaxation technique to reduce stress.');
INSERT INTO badge_optional_requirements VALUES(4349,343,13,'Disconnect from technology for a whole weekend and immerse yourself in analog, non technological, activities.');
INSERT INTO badge_optional_requirements VALUES(4350,343,14,'Do mind puzzles such as cross word puzzles, suduko, etc. to keep your brain active.');
INSERT INTO badge_optional_requirements VALUES(4351,343,15,'Learn a new skill.  This can be anything from knitting to computer coding.  Discuss how learning new skills helps your mental well being.');
INSERT INTO badge_optional_requirements VALUES(4352,343,16,'Use your creativity to invent stories, draw, or play make-believe games to nurture your imaginative thinking. Emotional Wellness:');
INSERT INTO badge_optional_requirements VALUES(4353,343,17,'Identify and name five different emotions you experience regularly.  Discuss proper ways of expressing those emotions');
INSERT INTO badge_optional_requirements VALUES(4354,343,18,'Create a “comfort kit” with items that bring you joy and comfort.');
INSERT INTO badge_optional_requirements VALUES(4355,343,19,'Volunteer for a cause that resonates with you, contributing positively to your community.');
INSERT INTO badge_optional_requirements VALUES(4356,343,20,'Use a journal to help express your emotions in a healthy way.  By putting your thoughts and emotions into words, you gain clarity about what you’re experiencing and why you might be feeling a certain way.');
INSERT INTO badge_optional_requirements VALUES(4357,343,21,'Cultivate self-compassion by replacing negative self-talk with positive affirmations and self-encouragement, fostering a healthier self-esteem.');
INSERT INTO badge_optional_requirements VALUES(4358,343,22,'Play a game of Emotional Charades where children act out different emotions, allowing them to explore and identify various feelings in a fun and safe environment. Spiritual Wellness:');
INSERT INTO badge_optional_requirements VALUES(4359,343,23,'Spend time in nature, appreciating the beauty and tranquility around you.');
INSERT INTO badge_optional_requirements VALUES(4360,343,24,'Create a daily ritual that aligns with your beliefs, such as meditation, prayer, or reflection.');
INSERT INTO badge_optional_requirements VALUES(4361,343,25,'Write a personal mission statement that outlines your values and aspirations.');
INSERT INTO badge_optional_requirements VALUES(4362,343,26,'Engage in an act of kindness without expecting anything in return.');
INSERT INTO badge_optional_requirements VALUES(4363,343,27,'Keep a gratitude journal for 30 days, noting three things you’re thankful for each day. Social Wellness:');
INSERT INTO badge_optional_requirements VALUES(4364,343,28,'Practice active listening with a friend or family member for a meaningful conversation.');
INSERT INTO badge_optional_requirements VALUES(4365,343,29,'Strengthen relationships by spending quality time with friends and family individually.');
INSERT INTO badge_optional_requirements VALUES(4366,343,30,'Initiate a conversation with someone new and learn about their interests and experiences.');
INSERT INTO badge_optional_requirements VALUES(4367,343,31,'Organize a social event or gathering that promotes positivity and connection.');
INSERT INTO badge_optional_requirements VALUES(4368,343,32,'Practice empathy by volunteering or assisting someone in need.');
INSERT INTO badge_optional_requirements VALUES(4369,343,33,'Apologize and make amends if there’s an unresolved conflict with someone.');
INSERT INTO badge_optional_requirements VALUES(4370,343,34,'Engage in activities that require teamwork, such as sports, building structures with blocks or playing cooperative board games, to promote collaboration and communication. Holistic Lifestyle:');
INSERT INTO badge_optional_requirements VALUES(4371,343,35,'Attend a wellness workshop, seminar, or class to expand your knowledge.');
INSERT INTO badge_optional_requirements VALUES(4372,343,36,'Attend a series of yoga classes or workshops to explore the physical and mental benefits of yoga and how it contributes to holistic health.');
INSERT INTO badge_optional_requirements VALUES(4373,343,37,'Identify and research five common medicinal herbs in your region, including their uses and benefits.');
INSERT INTO badge_optional_requirements VALUES(4374,343,38,'Learn about Reiki and energy healing.  How is it supposed to promote balance?');
INSERT INTO badge_optional_requirements VALUES(4375,343,39,'Research and create a simple energy map of the body’s energy centers (chakras), highlighting their significance in holistic healing.');
INSERT INTO badge_optional_requirements VALUES(4376,343,40,'Explore the principles of Traditional Chinese Medicine, including acupuncture and herbal medicine, through readings and discussions.');
INSERT INTO badge_optional_requirements VALUES(4377,343,41,'Research the basics of Ayurveda, identifying your dosha (mind-body type) and how it informs holistic health choices.');
INSERT INTO badge_optional_requirements VALUES(4378,343,42,'Cultivate a small herb garden with at least five medicinal herbs, learning their properties and applications.');
INSERT INTO badge_optional_requirements VALUES(4379,343,43,'Study the properties of five different healing crystals and create a personalized crystal grid.');
INSERT INTO badge_optional_requirements VALUES(4380,343,44,'Learn about a traditional Native American healing ceremony and the holistic approach to health within Indigenous cultures.');
INSERT INTO badge_optional_requirements VALUES(4381,343,45,'Embrace a plant-based diet for two weeks, focusing on nutrient-dense foods.');
INSERT INTO badge_optional_requirements VALUES(4382,343,46,'Attend a holistic wellness fair.');
INSERT INTO badge_optional_requirements VALUES(4383,344,3,'Research at least three different heating and cooling systems.  Which would you choose for your home and why?  What permits are required?');
INSERT INTO badge_optional_requirements VALUES(4384,344,4,'How will water be furnished?  What precautions should always be taken about the water supply and how should it be tested?  What permits are required?');
INSERT INTO badge_optional_requirements VALUES(4385,344,5,'Explain the difference between a septic tank and sewer system and how each works.  What rules apply to each when building a new home?  What permits are required?');
INSERT INTO badge_optional_requirements VALUES(4386,344,6,'How will your house get its electricity?  City power?  Solar?  Generator?  Discuss the pros and cons of each and choose one for your house.  What permits are required?');
INSERT INTO badge_optional_requirements VALUES(4387,344,7,'Learn about the care, maintenance, and durability of at least three different flooring such as tile, carpet, wood, laminate, or linoleum.  Which flooring would you choose for each room in your home and why?');
INSERT INTO badge_optional_requirements VALUES(4388,344,8,'Learn about different wall paints and the pros and cons of each.  Know the difference between flat, eggshell, and glossy.  Which are easy to clean or paint over and which are not?');
INSERT INTO badge_optional_requirements VALUES(4389,344,9,'Choose at least two rooms in your home and decide how much and what type of lighting should be used.  Look through different light fixtures either in a catalog, online or at a store and choose fixtures for these two rooms.');
INSERT INTO badge_optional_requirements VALUES(4390,344,10,'Describe the appliances needed in a new home.  What is the difference between electric appliances and gas appliances?  Research at least 3 different types of stove/oven, refrigerators, dish washers, and washer/dryers.  Choose one of each that you would put in your new home and explain why you made this choice.  Taking a field trip to an appliance store is a great way to fulfill this requirement.');
INSERT INTO badge_optional_requirements VALUES(4391,344,11,'Find out what the fire regulations are for new homes in your area.  These might include brush clearance from the home, turn arounds, fire retardant carpets, etc.');
INSERT INTO badge_optional_requirements VALUES(4392,344,12,'Discuss different types of architectural styles and look at pictures of each or take an architectural tour around your town.  Which do you like best?  Which are more cost effective?');
INSERT INTO badge_optional_requirements VALUES(4393,344,13,'Visit several different model homes and discuss what you like and don’t like about each.  Pay attention to the room layout, traffic flow, décor, flooring, walls, appliances and lighting.');
INSERT INTO badge_optional_requirements VALUES(4394,344,14,'Learn about at least three different roof options such as tile, shingle, or metal.  What are the pros and cons of each?');
INSERT INTO badge_optional_requirements VALUES(4395,344,15,'Discuss what home hazards must be considered when building a home in your area such as earthquakes, tornadoes, or hurricanes, and pest issues such as termites, squirrels, woodpeckers or packrats.  What precautions should be built into your home to address these hazards?');
INSERT INTO badge_optional_requirements VALUES(4396,344,16,'Learn about the different types of wall construction and insulation.  What is the difference between 2”x 4” construction and 2”x 6”?  What are the advantages of wood studs and metal studs?  What are the difference insulation ratings and what types are available?');
INSERT INTO badge_optional_requirements VALUES(4397,344,17,'Measure the hallways, doorways, and windows in your current house.  What is the average for each.  Discuss how these measurements affect what furniture and appliances can be used in a house.');
INSERT INTO badge_optional_requirements VALUES(4398,344,18,'Learn about careers in home construction such as construction workers, architects, soil engineers, surveyors, etc.  Choose one to learn more about.  What salary might you expect?  What education would you need?  What hours might you have to work?');
INSERT INTO badge_optional_requirements VALUES(4399,344,19,'Participate in a community service project that involves home construction such as volunteering for Habitat for Humanity or raising money for them or other organizations such as Fisher House or the Ronald McDonald houses.');
INSERT INTO badge_optional_requirements VALUES(4400,344,20,'Recommended for Levels 4-5 only: Help to build part of a house, either the actual construction or some of the finish work, under the supervision of an experienced adult and while following all safety rules.');
INSERT INTO badge_optional_requirements VALUES(4401,344,21,'Make a 3D model of a home.');
INSERT INTO badge_optional_requirements VALUES(4402,345,3,'Learn to identify different types of lamps or light fixtures such as table lamps, torchiers, wall sconces, vanity strips, etc. Preschool – Level 1: Identify 5. Level 2: Identify 6. Level 3: Identify seven. Level 4: Identify 8. Level 5: Identify nine. Which ones tend to be less expensive? What types of light bulbs go with which types of lamps? About how many watts are recommended for different types of tasks?');
INSERT INTO badge_optional_requirements VALUES(4403,345,4,'After choosing a color scheme for a real or imaginary redo of a living, dining, bath or bedroom, find three samples of wallpaper or fabric that go together. They can have similar or different patterns on them, but need to look good together both in color and in pattern. Go through this exercise at least three times until you feel comfortable doing it.');
INSERT INTO badge_optional_requirements VALUES(4404,345,5,'Learn to identify the furniture of at least three historic styles (mostly intended for royalty and the elite) and three contemporary (after 1800 B.C.E.) styles (intended for the common man). Know when the style appeared and in which country it was developed.');
INSERT INTO badge_optional_requirements VALUES(4405,345,6,'Walk around your house, a friend’s house, any building or even your neighborhood until you can identify five of the following: Etched, stained, or frosted glass Glass blocks Awning bay window Venetian blinds Shutters Curtains Draperies Cornice Shades Valance');
INSERT INTO badge_optional_requirements VALUES(4406,345,7,'Earn the Table Setting badge at your level. While earning this badge, set a table and when it is all finished, choose one thing on the table that you pretend you don’t have any more and figure out what you would use in its place. Do this twice—but it can be with the same table setting. In other words, set a table with alternate napkins or alternate centerpieces, or glassware. Take into consideration when you set the table, the types of chairs, lighting, and wall color in the room.');
INSERT INTO badge_optional_requirements VALUES(4407,345,8,'Read a book on a home decorating topic and try out a idea you find. Suggestions include: Storage Refinishing furniture Uses for leftover remodeling materials Home accessories Collecting and decorating with art or found materials or hobbies.');
INSERT INTO badge_optional_requirements VALUES(4408,345,9,'Discuss the health and environmental advantages and disadvantages of incandescent, halogen, and fluorescent light bulbs. What are the price ranges? Which ones last longer? Which ones are full-spectrum? Compare the effects of artificial light versus natural light from a window. Is there a room where you can almost totally rely on getting light through windows? When should you place awnings and shades on the outside of your house?');
INSERT INTO badge_optional_requirements VALUES(4409,345,10,'Ask an adult to pick out five pieces of home furnishing with very different textures (a sleek contemporary mirror, a piece of hand-thrown pottery, a huge throw of long, fake fur, lacey curtains, etc.). Then list at least five adjectives that can be used to describe each piece, plus explain how the piece makes you feel when you look at it. It is fun to do this with other people and then compare notes.');
INSERT INTO badge_optional_requirements VALUES(4410,345,11,'Write a report on a famous designer such as Sybil Colefax, Syrie Maugham, Elsie de Wolfe, or Cecil Hayes.');
INSERT INTO badge_optional_requirements VALUES(4411,345,12,'Walls, floors, and ceilings are the background against which we place our furniture and accessories. They can give a house unity. Investigate 3 wall surfaces and their advantages: Ceramic tile Natural stone Fabric Mirrors Paint Stucco Wallpaper Wood. Investigate 3 types of flooring and their advantages: laminate, resilient (vinyl), wood, linoleum, various stone floors—concrete, bricks, terrazzo, granite, marble, slate, etc.');
INSERT INTO badge_optional_requirements VALUES(4412,345,13,'List some reasons why a person would choose any three of the following to be applied to her ceilings: Added beams Stenciling Murals Acoustic tiles Extended wall coverings Fabric tenting Different color paint.');
INSERT INTO badge_optional_requirements VALUES(4413,345,14,'Since cabinets are the most expensive part of a kitchen remodeling, discuss with an adult some ideas of how to get new cabinets less expensively. Look through a cabinet catalog to see the various types of cabinetry available both in design and function.');
INSERT INTO badge_optional_requirements VALUES(4414,346,3,'Learn candle fire safety.');
INSERT INTO badge_optional_requirements VALUES(4415,346,4,'Learn cooking fire safety.');
INSERT INTO badge_optional_requirements VALUES(4416,346,5,'Learn grilling and BBQ safety.');
INSERT INTO badge_optional_requirements VALUES(4417,346,6,'Learn about Class A, B, C, D and K fire extinguishers and what each is used for. Know how to properly use and maintain your fire extinguisher.   Know when it is appropriate to use a fire extinguisher and when you should leave and call the fire department.');
INSERT INTO badge_optional_requirements VALUES(4418,346,7,'Learn about fireplace and wood stove safety.');
INSERT INTO badge_optional_requirements VALUES(4419,346,8,'Learn about hazardous materials around your house that can cause fires and how to properly use and dispose of them.  Items might include: Automotive fluids Barbecue products Batteries Health and beauty products Home maintenance products Household cleaners Laundry products Lawn and garden products Medicines and medical supplies Paints and thinners');
INSERT INTO badge_optional_requirements VALUES(4420,346,9,'Learn about holiday fire safety, such as how to properly care for Christmas trees and lights.');
INSERT INTO badge_optional_requirements VALUES(4421,346,10,'Find out what you local burn laws are for burning trash or other debris.  What permits are needed?  What times of year are you allowed to burn and where?');
INSERT INTO badge_optional_requirements VALUES(4422,346,11,'Learn how to make your home more fire resistant.');
INSERT INTO badge_optional_requirements VALUES(4423,347,3,'Demonstrate how to insulate pipes against freezing and how to thaw them if they do freeze.');
INSERT INTO badge_optional_requirements VALUES(4424,347,4,'Locate an upright stud in a plaster wall by sounding or using a stud finder.  Explain why knowing where the studs are located is critical to many home projects.');
INSERT INTO badge_optional_requirements VALUES(4425,347,5,'Put up a shelf using brackets attached to the wall.   If the brackets are not attached to a stud, make sure to use proper hardware to avoid ripping the sheet rock.');
INSERT INTO badge_optional_requirements VALUES(4426,347,6,'Measure for and install a rod in a clothes closet or properly install a row of hooks for clothes or other articles.');
INSERT INTO badge_optional_requirements VALUES(4427,347,7,'Demonstrate how to repair, keep clean and care for window or door screens.');
INSERT INTO badge_optional_requirements VALUES(4428,347,8,'Demonstrate how to operate and care for at least two electrical household appliances, such as a washing machine, vacuum cleaner, toaster, iron, blender, etc.');
INSERT INTO badge_optional_requirements VALUES(4429,347,9,'Demonstrate how to unclog a toilet, sink, and tub.');
INSERT INTO badge_optional_requirements VALUES(4430,347,10,'(Suggested for Level 3 and above only) Learn to re-wire a lamp or replace a plug on a lamp or appliance cord.');
INSERT INTO badge_optional_requirements VALUES(4431,347,11,'Repair, refinish, or upholster a piece of furniture.');
INSERT INTO badge_optional_requirements VALUES(4432,347,12,'Build a sawhorse, stool, or work bench to be used around your home.');
INSERT INTO badge_optional_requirements VALUES(4433,347,13,'Properly install a curtain rod and hang the curtains.');
INSERT INTO badge_optional_requirements VALUES(4434,347,14,'(Suggested for Level 2 and above only)  Mow, trim, or fertilize a lawn.');
INSERT INTO badge_optional_requirements VALUES(4435,347,15,'(Suggested for Level 2 and above only) Properly trim a hedge.');
INSERT INTO badge_optional_requirements VALUES(4436,347,16,'Maintain or recondition a yard tool and show that you know how to clean up and properly store this equipment.');
INSERT INTO badge_optional_requirements VALUES(4437,347,17,'Weather strip a window or door.');
INSERT INTO badge_optional_requirements VALUES(4438,347,18,'Caulk cracks or joints open to the weather.');
INSERT INTO badge_optional_requirements VALUES(4439,347,19,'Repair a break in a concrete or asphalt surface.');
INSERT INTO badge_optional_requirements VALUES(4440,347,20,'Solder a broken wire or metal object.');
INSERT INTO badge_optional_requirements VALUES(4441,347,21,'(Suggested for Level 3 and above only) Learn to safely use an electric tool such as a screw gun or nail gun.');
INSERT INTO badge_optional_requirements VALUES(4442,347,22,'Install or build equipment for storing tools.');
INSERT INTO badge_optional_requirements VALUES(4443,347,23,'Repair a sagging door or gate.');
INSERT INTO badge_optional_requirements VALUES(4444,347,24,'Repair a loose step or railing.');
INSERT INTO badge_optional_requirements VALUES(4445,347,25,'Repair, paint, or stain a fence.');
INSERT INTO badge_optional_requirements VALUES(4446,347,26,'Locate a main electrical switch box and know how to replace a fuse or reset a circuit breaker.');
INSERT INTO badge_optional_requirements VALUES(4447,347,27,'Repair a leaky water faucet.');
INSERT INTO badge_optional_requirements VALUES(4448,347,28,'Repair a flush toilet.');
INSERT INTO badge_optional_requirements VALUES(4449,347,29,'Paint a wall or ceiling.');
INSERT INTO badge_optional_requirements VALUES(4450,347,30,'Repair or replace damaged flooring such as tile, wood, or linoleum.');
INSERT INTO badge_optional_requirements VALUES(4451,347,31,'Help with a project that involves properly laying brick or concrete.');
INSERT INTO badge_optional_requirements VALUES(4452,347,32,'Learn how to properly hang wallpaper or wall décor.');
INSERT INTO badge_optional_requirements VALUES(4453,347,33,'Interview a handyman/woman who fixes household items for a living.  What kind of hours do they work?  How much do they have to travel?  What types of things do they fix?  Are they required to have a license?  If so, what education is necessary?  What insurance must they carry?');
INSERT INTO badge_optional_requirements VALUES(4454,347,34,'Participate in a community service project that puts your home maintenance knowledge to use.  Examples might include making small repairs at a homeless shelter or women’s refuge, or helping out an elderly neighbor.');
INSERT INTO badge_optional_requirements VALUES(4455,348,3,'Meal planning is an important aspect of home-making to ensure that family members receive nutritionally balanced, interesting and varied meals.  Learn what makes a meal nutritionally balanced. Preschool: Plan a nutritionally balanced meal. Levels 1-2: Plan a day’s worth of nutritionally-balanced meals. Levels 3-4: Plan a week’s worth of nutritionally-balanced meals. Level 5: Plan a month’s worth of nutritionally balanced meals.');
INSERT INTO badge_optional_requirements VALUES(4456,348,4,'Earn the Cleaning badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4457,348,5,'Keeping the home attractively decorated is important.  There are different styles and ways to do this. Look at pictures of different styles of décor. Which do you like best and why?');
INSERT INTO badge_optional_requirements VALUES(4458,348,6,'Earn the Laundry badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4459,348,7,'Good financial management is critical to a successful home-maker.  What expenses are there in a typical family budget?  Talk to a home-maker about ways they have found to enable them to be able to stay at home rather than go out to work.  Are there things that they choose to do without so that they can stay at home?');
INSERT INTO badge_optional_requirements VALUES(4460,348,8,'Earn the Clothing Repair badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4461,348,9,'There are often broken items to be repaired.  Different items need different types of repairs.  Torn books can be mended with tape; broken wooden items can be mended with white-glue; toys can sometimes be mended with string, etc.  Learn how to mend something. Preschool: With help, mend something using sticky-tape. Level 1: In addition, mend something using white glue. Level 2: In addition, mend something using string. Level 3: In addition, mend something using a screwdriver. Level 4: In addition, mend something using a glue-gun. Level 5: In addition, mend something using super-glue.');
INSERT INTO badge_optional_requirements VALUES(4462,348,10,'Earn the Child Care or Babies badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4463,348,11,'Earn the Cooking or Baking badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4464,348,12,'Many home-makers also grow a garden to produce flowers.  Earn the Flower Gardening or Flower Arranging badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4465,348,13,'Some home-makers grow a vegetable garden to add fresh produce to their food supplies.  Earn the Gardening badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4466,348,14,'Home-makers often care for sick people.  Earn the Home Nurse badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4467,348,15,'What does your book of faith say about home-makers/home-making?  Preschool: Memorize one verses. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(4468,348,16,'Many home-makers have a vehicle that will require regular care and maintenance.  Earn the Automotive Maintenance badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4469,349,3,'Learn how to relieve boredom for a sick person.  Discuss with your family, friends, group, or your “patient’s” caregiver some things you can do to relieve boredom.  The complete at least two of your proposed ideas, such as putting together a craft bag and using its contents, playing with toy soldiers on a quilt top, doing a puppet show, playing games, doing puzzles, or sitting and talking.');
INSERT INTO badge_optional_requirements VALUES(4470,349,4,'With a parent’s permission, watch at least one age-appropriate movie about a chronically ill or handicapped person, such as “The Awakening”, “Wit”, “Lorenzo’s Oil”, “Joni”, “Ice Castles”, etc. Books may be read instead of watching movies if you prefer.');
INSERT INTO badge_optional_requirements VALUES(4471,349,5,'Figure out how to entice a sick person to eat more or healthier food.  Does your “patient” have enough variety in the textures and colors of their food?  How about new tastes or seasonings and proper temperatures?  Would music or pleasant conversation enhancer their dining experience?  How about teddy bear shaped sandwiches, or a fancy dessert with protein powder added?  Prepare a meal or a snack for your “patient.”');
INSERT INTO badge_optional_requirements VALUES(4472,349,6,'Go to a medical supply store and learn to identify at least ten things such as walkers, different types of canes, beside commodes, reaches, braces, and handrails.  Be sure you know the function of each piece of equipment.');
INSERT INTO badge_optional_requirements VALUES(4473,349,7,'Give an adult caregiver a break.  Do chores or favors for them so they don’t get as tired as they normally would.  Do at least ten helpful activities to help your caregiver.');
INSERT INTO badge_optional_requirements VALUES(4474,349,8,'(Level 3 and Up Only) Accompany a sick or physically challenged person to his doctor visit or therapy session.  Write out any instructions given by the health care provider.  Compare notes with the sick person and discuss changes in care.');
INSERT INTO badge_optional_requirements VALUES(4475,349,9,'Earn the Kindness badge at your level and write out a reason why kindness is important during the time someone is ill.');
INSERT INTO badge_optional_requirements VALUES(4476,349,10,'Do research on the health condition of a friend or relative.  For each condition, check out at least three sources.  If there is more than one approach to treating the condition, find out why one is chosen over the other(s).  Be able to explain to someone else what the condition is and what the treatment accomplishes.');
INSERT INTO badge_optional_requirements VALUES(4477,349,11,'Go to a drug or medical supply store to learn about medical equipment and/or medications for people who can be cared for at home.  Research a group of aids or medications and find out how much they cost. For example, research the pros and cons of the two main types of wheelchairs, their seat pads and bags.  Or study the difference between acetaminophen and aspirin.  What is the difference between two-wheeled walkers and four wheeled?  What is the difference in cost?  Try out different reaches and see which ones you like best, etc.');
INSERT INTO badge_optional_requirements VALUES(4478,349,12,'Be the chief caregiver for someone for at least two hours.  Be aware of any safety concerns before you start and if you are standing in for someone else, be sure you know all the contact information before the caregiver leaves you in charge.  You may NOT administer any medications unless an adult is there to supervise.');
INSERT INTO badge_optional_requirements VALUES(4479,350,3,'Find out what things had to be done ahead of time in order to renovate the house you are working on. Did someone have to get a loan or other help to pay for the project? Did you have to get a building permit? How many stores did you have to go to in order to find the right paint, flooring, paneling, etc.?');
INSERT INTO badge_optional_requirements VALUES(4480,350,4,'What tools were required for the project (flooring, painting, new cabinets, etc.) you worked on? What were the steps from start to finish? What did someone have to do to clean up afterwards? With an experienced adult’s supervision, learn to use at least one of the tools used in your home renovation.');
INSERT INTO badge_optional_requirements VALUES(4481,350,5,'Take at least two photos before and two photos after the renovation you are working on. If you don’t have a camera available, you can also draw sketches.');
INSERT INTO badge_optional_requirements VALUES(4482,350,6,'Did any friends or relatives help with your home renovation? Make at least two thank you cards or letters to people who helped, or you can make the helpers a thank you present, such as cookies.');
INSERT INTO badge_optional_requirements VALUES(4483,350,7,'Learn a new skill related to your house renovation, such as washing paint brushes, painting walls, hammering a nail, or accurately measuring wallpaper.');
INSERT INTO badge_optional_requirements VALUES(4484,350,8,'Learn about inspections. Why might the city/state/government require inspections? If possible, interview an inspector to learn more about their career.');
INSERT INTO badge_optional_requirements VALUES(4485,350,9,'Either write a letter describing your house renovation project or write an essay detailing how to do your project and what lessons you learned from doing the project.');
INSERT INTO badge_optional_requirements VALUES(4486,350,10,'Earn the Home Decorating badge.');
INSERT INTO badge_optional_requirements VALUES(4487,350,11,'Learn the names of all the tools for the project(s) you worked. How does one take proper care of these tools including cleaning them? Be able to describe the steps involved in your project and the clean-up required. With an experienced adult’s supervision, learn to use at least two of the tools used in your home renovation.');
INSERT INTO badge_optional_requirements VALUES(4488,350,12,'Help another family or an organization such as a Rescue Mission or Habitat for Humanity with a house renovation.');
INSERT INTO badge_optional_requirements VALUES(4489,350,13,'Write a photo-essay, create a presentation, or keep a journal about the troubles and rewards connected with a house renovation.');
INSERT INTO badge_optional_requirements VALUES(4490,350,14,'Help prepare a party or open house to celebrate the completion of a renovation.');
INSERT INTO badge_optional_requirements VALUES(4491,351,3,'Role play at least 3 different safety scenarios and know the proper safety rules for each.  Examples might include how to check if a room is adequately child proofed for small children; what to do in case of a fire; how to properly use a knife or matches (or to stay away from them if you are too young); how to properly answer the front door when you don’t know who is on the other side; quickly cleaning up wet spills so others won’t slip; etc.');
INSERT INTO badge_optional_requirements VALUES(4492,351,4,'Learn electrical appliance safety, including for their cords/batteries.');
INSERT INTO badge_optional_requirements VALUES(4493,351,5,'Take a field trip to the fire or police department and have them talk to you about home safety.');
INSERT INTO badge_optional_requirements VALUES(4494,351,6,'Design and practice an evacuation plan for your home. Make sure to designate a meeting spot outside your home. Check all smoke detectors in your house for fresh batteries.');
INSERT INTO badge_optional_requirements VALUES(4495,351,7,'Earn the Home Fire Safety badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(4496,351,8,'Learn about careers that involve home safety.  Examples might include police and fire fighters, architects, landscapers, electricians, pool installers, etc.  What salary could you expect with one of these jobs?  What hours might you have to work?  What education would you need?');
INSERT INTO badge_optional_requirements VALUES(4497,351,9,'Learn proper gun safety for a house.');
INSERT INTO badge_optional_requirements VALUES(4498,351,10,'Learn proper pool safety.');
INSERT INTO badge_optional_requirements VALUES(4499,351,11,'Participate in a community service project that promotes home safety.');
INSERT INTO badge_optional_requirements VALUES(4500,352,3,'Find a spa in your area.  Learn about what they offer and how much they charge.  Plan an imaginary trip there, choosing the treatments you’d like to try and the total cost.');
INSERT INTO badge_optional_requirements VALUES(4501,352,4,'What are mineral hot springs?  Create a map of hot springs including at least 10 locations.  What health benefits are they thought to provide?');
INSERT INTO badge_optional_requirements VALUES(4502,352,5,'Learn what exfoliate means and why it is helpful.');
INSERT INTO badge_optional_requirements VALUES(4503,352,6,'Plan your own spa day at home.  Compare the cost to a spa trip.  Remember to set the mood with music and lighting.');
INSERT INTO badge_optional_requirements VALUES(4504,352,7,'What is a sugar scrub?  What are the health benefits?  What are the common base ingredients? Create your own.');
INSERT INTO badge_optional_requirements VALUES(4505,352,8,'What is a salt scrub?  What are the health benefits?  What are the common base ingredients?  Make your own.');
INSERT INTO badge_optional_requirements VALUES(4506,352,9,'What is a facial mask?  What are the health benefits? What are the common base ingredients? Make your own.');
INSERT INTO badge_optional_requirements VALUES(4507,352,10,'What is a foot scrub?  What are the health benefits? What are the common base ingredients? Make your own.');
INSERT INTO badge_optional_requirements VALUES(4508,352,11,'What herbs are used in a bath soak?  Learn the benefits of 3 different herbs. Levels 3-5: Learn 5.  Create an herbal bath soak.');
INSERT INTO badge_optional_requirements VALUES(4509,352,12,'Research the ingredients in commercial spa products.  Are some harmful?  What natural ingredients could you substitute?');
INSERT INTO badge_optional_requirements VALUES(4510,352,13,'Plan a spa party for your friends or for younger kids in your group.');
INSERT INTO badge_optional_requirements VALUES(4511,352,14,'Give away some of your homemade products as gifts.');
INSERT INTO badge_optional_requirements VALUES(4512,352,15,'Plan a spa day for a women’s shelter, homeless shelter or nursing home.  You could enlist the help of local beauty schools or spas as a Make a Difference award project.');
INSERT INTO badge_optional_requirements VALUES(4513,352,16,'Research careers in the spa industry.  What type of training and education is involved?');
INSERT INTO badge_optional_requirements VALUES(4514,354,3,'Find and list a style of architecture that is common to your hometown.  Preschool-Level 1: Identify one style. Levels 2-3: Identify two styles. Levels 4-5: Identify three styles.');
INSERT INTO badge_optional_requirements VALUES(4515,354,4,'Find and list types of plant/tree/flower that is common in your hometown. Preschool-Level 1: Identify two plants. Levels 2-3: Identify four plants. Levels 4-5: Identify six plants.');
INSERT INTO badge_optional_requirements VALUES(4516,354,5,'Find out what major land/water features are nearby, such as bodies of water, mountains, deserts, rivers, etc.');
INSERT INTO badge_optional_requirements VALUES(4517,354,6,'Learn about the history of your hometown and visit at least one historical site.');
INSERT INTO badge_optional_requirements VALUES(4518,354,7,'Learn about a famous person that came from your hometown.');
INSERT INTO badge_optional_requirements VALUES(4519,354,8,'Find out what museums are in your hometown and visit at least one..');
INSERT INTO badge_optional_requirements VALUES(4520,354,9,'Find out what type of food is common in your hometown.  Try at least one new local food.');
INSERT INTO badge_optional_requirements VALUES(4521,354,10,'Look at a map of your destination. How is the city laid out? Are the streets in a logical grid, or do they wind all over the place?  Are there different sections of the city such as downtown, suburbs, commercial districts, manufacturing, etc.?');
INSERT INTO badge_optional_requirements VALUES(4522,354,11,'Find what type of music originated in this region and listen to at least 3 songs.');
INSERT INTO badge_optional_requirements VALUES(4523,354,12,'Find out about an artist or artistic style that originated in or around your hometown.');
INSERT INTO badge_optional_requirements VALUES(4524,354,13,'Have a picnic at a local park.  Try to find one that you’ve never visited before.');
INSERT INTO badge_optional_requirements VALUES(4525,354,14,'Take a hike on local trails.  Try to find some within your abilities that you’ve never explored before.');
INSERT INTO badge_optional_requirements VALUES(4526,354,15,'Create a scrapbook of pictures and mementos of your travels.');
INSERT INTO badge_optional_requirements VALUES(4527,355,3,'Put together a skit or theater piece about truth and honesty.  Perform it for a group of your choice.');
INSERT INTO badge_optional_requirements VALUES(4528,355,4,'Create a comic about honesty.');
INSERT INTO badge_optional_requirements VALUES(4529,355,5,'Read a poem about honesty and discuss what you think it means.  Try writing your own.');
INSERT INTO badge_optional_requirements VALUES(4530,355,6,'Create a “recipe” for honesty.  What ingredients would you need? Truth? Courage?  In what quantities?  How should they be mixed?');
INSERT INTO badge_optional_requirements VALUES(4531,355,7,'Create a booklet on the care an feeding of honesty.  What type of things do you have to do on a daily basis to maintain honesty in your life?');
INSERT INTO badge_optional_requirements VALUES(4532,355,8,'What does your book of faith say about honesty and truth? Memorize verses about honesty and truth. Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(4533,355,9,'Organize a story time at your local library or daycare center to tell stories with themes of honesty to young children.');
INSERT INTO badge_optional_requirements VALUES(4534,355,10,'Interview someone who shows the character trait “honesty” on a regular basis.  What does honesty mean to them?  Come up with at least 10 questions to ask about honesty in their lives.');
INSERT INTO badge_optional_requirements VALUES(4535,355,11,'When watching TV, pay close attention to the commercials you see.  How much truth is there in what the companies claim about their product?  What important details might they be leaving out?  Discuss with your parents or group the topic “truth in advertising.”');
INSERT INTO badge_optional_requirements VALUES(4536,355,12,'Discuss different scenarios with your parents or group where honesty is difficult, but still necessary.  Examples may include: You forgot to study for a test, but you sit next to the best student in class and it would be very easy to copy their paper. A clerk at a store gives you too much change. Mom told you not to touch the brownies on the counter, but no one is in the kitchen but you. You have a huge report due in a week and you haven’t done any work on it yet.  Your friend tells you about a website where you can simply download a report that is already written and ready to turn in.');
INSERT INTO badge_optional_requirements VALUES(4537,355,13,'Read a story about honesty such as Pinocchio, The Tale of Peter Rabbit, or The Boy Who Cried Wolf.');
INSERT INTO badge_optional_requirements VALUES(4538,355,14,'Research whistle-blowers or people who go public about an unfair, unsafe, or unethical practice in the workplace or other place.');
INSERT INTO badge_optional_requirements VALUES(4539,355,15,'Find out how your school handles dishonesty. Are there student guidelines about cheating, stealing, lying, plagiarism, and other issues? Survey your class to find out how honest students are.');
INSERT INTO badge_optional_requirements VALUES(4540,355,16,'Learn about the relationship of honesty and health.');
INSERT INTO badge_optional_requirements VALUES(4541,355,17,'Research cultures past and present to learn their views of honesty.');
INSERT INTO badge_optional_requirements VALUES(4542,355,18,'Remind members of your community to be honest. With permission, decorate public areas with signs telling about the value of honesty. Follow all local/state/federal laws.');
INSERT INTO badge_optional_requirements VALUES(4543,355,19,'Create a classroom honor code. Write it down and hang it up in the classroom, so that everyone can see it all year long.');
INSERT INTO badge_optional_requirements VALUES(4544,355,20,'Play a game about honesty and discuss what you learn about truth.  Below are a couple of examples: Whopper:  Take turns making 4 statements about yourself.  3 should be true and one should be false. Opponents must try to guess which statement is the “whopper” or lie.  Receive one point every time you guess someone’s “whopper” correctly and score one point for each person who does NOT guess yours. I Never:  Every person needs the same number of toothpicks (or pretzels or any other counter) as the number of people playing.  Take turns going around the circle and making a statement about something you have never done.  The object is to come up with something that everyone else in the group has done, but you have not.  For example you might say, “I have never eaten peas.” or “I have never ridden a roller coaster.”  As you go around the circle, every time someone makes a statement of what they have not done, but you have done it, you give them a toothpick.  The person with the most toothpicks at the end of the game wins.  In this game of reverse peer pressure, the winner is actually the  person who has done the least things in comparison to everyone else. To Tell the Truth:  Send 3 people out of the room.  These three must choose a true statement about one of them (it must be false for the other two) such as “I got lost at Disneyland when I was 5.”  They come back in the room and each make the statement, “My name is _______, and I got lost in Disneyland when I was 5.” The rest of the group takes turns asking them questions for 5 minutes.  At the end of that time they group take turns stating who they think told the truth.  If the majority of the group guesses correctly, the group wins, if the majority guesses incorrectly, the players win.');
INSERT INTO badge_optional_requirements VALUES(4545,356,3,'Visit a local shop or farmers market where you can purchase honey. Compare it to store bought honey. What are some differences you notice?');
INSERT INTO badge_optional_requirements VALUES(4546,356,4,'Tour a honey-making facility or farm.');
INSERT INTO badge_optional_requirements VALUES(4547,356,5,'Participate in the process and collecting and making honey.');
INSERT INTO badge_optional_requirements VALUES(4548,356,6,'Bake a snack or dessert where honey is a main ingredient.');
INSERT INTO badge_optional_requirements VALUES(4549,356,7,'What is the difference between pure honey and raw honey?');
INSERT INTO badge_optional_requirements VALUES(4550,356,8,'Compare the price of different types and grades of honey. Why is one more expensive than another?');
INSERT INTO badge_optional_requirements VALUES(4551,356,9,'Participate in a community service project involving honey, such as a fundraiser or bake sale.');
INSERT INTO badge_optional_requirements VALUES(4552,356,10,'Donate jars of honey to a local shelter, hospital, or someone in need.');
INSERT INTO badge_optional_requirements VALUES(4553,356,11,'Learn about careers involving honey. What type of training would you need? What kind of environment could you expect to work in?');
INSERT INTO badge_optional_requirements VALUES(4554,356,12,'Have a honey taste test between your family, friends, or group. Taste an assortment of different types of honey and try to guess which type is which.');
INSERT INTO badge_optional_requirements VALUES(4555,357,3,'What does your book of faith say about honor?');
INSERT INTO badge_optional_requirements VALUES(4556,357,4,'Attend a ceremony in your community that honors a person or group of people (such as veterans).');
INSERT INTO badge_optional_requirements VALUES(4557,357,5,'Visit at least two monuments that honor a person or what a group of people accomplished.');
INSERT INTO badge_optional_requirements VALUES(4558,357,6,'Earn the Grandparents badge or U.S. Presidents badge at your level. Be sure to include a requirement that emphasizes honor.');
INSERT INTO badge_optional_requirements VALUES(4559,357,7,'Earn the Our Flag badge or the Patriotism badge at your level. Be sure to include a requirement that emphasizes honor.');
INSERT INTO badge_optional_requirements VALUES(4560,357,8,'List what you think are the most important ways to honor God in your life.');
INSERT INTO badge_optional_requirements VALUES(4561,357,9,'Make and give a gift or card as a way of honoring someone you haven’t honored in over a year, or someone you’ve never met.');
INSERT INTO badge_optional_requirements VALUES(4562,357,10,'Make a donation to a charity in someone else’s name to honor the other person.');
INSERT INTO badge_optional_requirements VALUES(4563,357,11,'Discuss how to deal with someone who is in a position of authority (and should therefore be honored) who acts in an un-honorable way sometimes.');
INSERT INTO badge_optional_requirements VALUES(4564,357,12,'Discuss whether you should honor someone for a talent he/she has or for the way they use the talent.');
INSERT INTO badge_optional_requirements VALUES(4565,357,13,'Donate your time to a celebration/ceremony that honors other people. If possible, be involved in the planning or setting up of the celebration.');
INSERT INTO badge_optional_requirements VALUES(4566,357,14,'Attend a parade that honors veterans or other people who deserve honor.');
INSERT INTO badge_optional_requirements VALUES(4567,357,15,'Visit with wounded or retired veterans or public safety officers or help with with regular maintenance at a veteran’s retirement facility.');
INSERT INTO badge_optional_requirements VALUES(4568,357,16,'Visit with the elderly at a nursing home or retirement facility.');
INSERT INTO badge_optional_requirements VALUES(4569,357,17,'Help educate other people about something/someone that does not always receive the honor it/he should, such as wearing a Constitution Day pin or handing out booklets about heroes. Keep spreading the word about this until at least five people have responded to your information.');
INSERT INTO badge_optional_requirements VALUES(4570,357,18,'Discuss and role play the non-verbal ways people show honor and lack of honor. Learn a minimum of ten ways that show honor without words, such as saluting, bowing, rifle salutes, etc.');
INSERT INTO badge_optional_requirements VALUES(4571,357,19,'Why is going “above and beyond the call of duty” a way to honor someone? Who are the people you might honor in this way? Give examples of ways different people might go “above & beyond” such as a student, a teacher, a grandparent, a parent, a soldier, etc.');
INSERT INTO badge_optional_requirements VALUES(4572,358,3,'Volunteer at a horse sanctuary or hold a fundraiser for one.');
INSERT INTO badge_optional_requirements VALUES(4573,358,4,'Learn about careers that involve with horses.');
INSERT INTO badge_optional_requirements VALUES(4574,358,5,'Learn the difference between a miniature horse, pony, horse, and draft horse.  Look at pictures of each or see them in person if possible.');
INSERT INTO badge_optional_requirements VALUES(4575,358,6,'Learn to identify at least 5 different breeds of horses. Know what each type of horse is generally used for.');
INSERT INTO badge_optional_requirements VALUES(4576,358,7,'Read a fictional book about horses.');
INSERT INTO badge_optional_requirements VALUES(4577,358,8,'Read a non-fiction book about horse care.');
INSERT INTO badge_optional_requirements VALUES(4578,358,9,'Visit a tack shop or look through a tack catalog. Learn what items are necessary to keep your horse healthy and comfortable.  Level 3 and Up: Make a list of the prices and calculate what the necessary equipment and supplies would cost.');
INSERT INTO badge_optional_requirements VALUES(4579,358,10,'Watch a farrier trim or shoe a horse. Find out how often trimming or shoeing needs to be done, and how much it costs each time.  Is a draft horse the same cost as a miniature horse? Level 3 and Up: What adjustments are necessary according to the horse’s conformation, the season of the year, and the riding conditions?');
INSERT INTO badge_optional_requirements VALUES(4580,358,11,'Learn the parts of the saddle and bridle. What is the difference between English and Western tack? Find out how each part contributes to the comfort of both the horse and rider.  Learn how to care for tack and assist with the bridling or saddling of the horse if possible.');
INSERT INTO badge_optional_requirements VALUES(4581,358,12,'Learn about a famous horse, such as Roy Roger’s Trigger or Secretariat.');
INSERT INTO badge_optional_requirements VALUES(4582,358,13,'Learn how to properly groom a horse, including picking the hooves,  and what each tool is used for.');
INSERT INTO badge_optional_requirements VALUES(4583,358,14,'Learn about wild horses and what is being done to protect them.  Visit a wild horse sanctuary if possible or research one online with the permission of a parent.');
INSERT INTO badge_optional_requirements VALUES(4584,358,15,'Learn about horse riding therapy for physically or mentally disabled people.');
INSERT INTO badge_optional_requirements VALUES(4585,358,16,'Learn about how horses are measured and what “hands high” means.   What are the height requirements for a miniature horse, a pony, a horse and a draft horse?');
INSERT INTO badge_optional_requirements VALUES(4586,358,17,'Put together a comparison chart of three different stables.  Include the following information: Boarding or leasing prices Stall or paddock accommodations Number of horses Feeding schedules and type of feed Number and types of riding arenas and trails Amount of pasture Type of bedding Method of manure disposal Quality and amount of water available Hours open to visitors Whether or not dogs are allowed If blanketing is included in the boarding cost');
INSERT INTO badge_optional_requirements VALUES(4587,358,18,'Learn about rare or unusual horse colors and markings, such as silver bay, brindle, or badger face.');
INSERT INTO badge_optional_requirements VALUES(4588,358,19,'Learn to recognize the four main patterns for pintos: tobiano, overo, sabino, and splashed white.');
INSERT INTO badge_optional_requirements VALUES(4589,358,20,'Learn to recognize the main patterns for breeds like the Appaloosa, Knabstrupper, or Nortiker, such as leopard, blanket, and snowflake.');
INSERT INTO badge_optional_requirements VALUES(4590,358,21,'Learn about extinct equine species, such as the eohippus.');
INSERT INTO badge_optional_requirements VALUES(4591,358,22,'Earn the Horse Riding badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4592,358,23,'Earn the Horse Lover badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4593,358,24,'Earn the Horse Training badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4594,358,25,'Earn the Horse Racing badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4595,359,3,'Learn about various types of equine competition such as flat racing, polo, show jumping, dressage, reining, vaulting, steeplechase, etc.');
INSERT INTO badge_optional_requirements VALUES(4596,359,4,'Attend a horse event such as a hunt, show, or competition.  If you cannot attend one in person, watch one on TV or on the internet with permission from a parent. ­­­');
INSERT INTO badge_optional_requirements VALUES(4597,359,5,'Have a riding lesson.');
INSERT INTO badge_optional_requirements VALUES(4598,359,6,'Create a horse craft of some kind.');
INSERT INTO badge_optional_requirements VALUES(4599,359,7,'Make an accessory for a model horse such as a head collar/halter, saddle, or blanket');
INSERT INTO badge_optional_requirements VALUES(4600,359,8,'Read an autobiography or biography about someone who worked with horses such as Monty Roberts, Princess Anne, Paul Nicholls, Henry Cecil, etc.');
INSERT INTO badge_optional_requirements VALUES(4601,359,9,'With a parent’s permission, watch two fictional horse films such as Black Beauty, Spirit: Stallion of the Cimarron, or National Velvet.');
INSERT INTO badge_optional_requirements VALUES(4602,359,10,'Read a fictional book about horses that is set in a different country to your own. For example Black Beauty is set in England, Flicka in America, Silver Brumby in Australia.');
INSERT INTO badge_optional_requirements VALUES(4603,359,11,'Find out about three of the following types of workhorse: Police Canal Agriculture Cow pony Circus Mining Pony express Coaching/cabbing/hackney');
INSERT INTO badge_optional_requirements VALUES(4604,359,12,'Read a book or watch a film  about a true famous horse such as Seabiscuit, Secretariat, Shergar, or Black Jack.');
INSERT INTO badge_optional_requirements VALUES(4605,359,13,'Research how horses have been used in war and battles through the centuries.');
INSERT INTO badge_optional_requirements VALUES(4606,359,14,'Shadow someone at a stable for a day.');
INSERT INTO badge_optional_requirements VALUES(4607,360,3,'Learn about famous racehorses. Preschool-Level 1: Learn two. Level 2: Learn three. Level 3: Learn four. Levels 4-5: Learn five.');
INSERT INTO badge_optional_requirements VALUES(4608,360,4,'Learn the requirements to be a jockey. How do they differ between ‘flat’ racing and steeplechasing?');
INSERT INTO badge_optional_requirements VALUES(4609,360,5,'Earn the Horse Riding badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4610,360,6,'Learn the basics of what goes into the training of a horse for a race.');
INSERT INTO badge_optional_requirements VALUES(4611,360,7,'Attend a horse race.');
INSERT INTO badge_optional_requirements VALUES(4612,360,8,'Learn which illnesses and injuries racehorses are most susceptible to. What can be done to treat and prevent them?');
INSERT INTO badge_optional_requirements VALUES(4613,360,9,'Know who the winners of this year’s major races are, such as the Kentucky Derby and the Breeder’s Cup.');
INSERT INTO badge_optional_requirements VALUES(4614,360,10,'Learn the history of the one of the main breeds used for racing, such as the Thoroughbred, Arabian, or Quarter Horse.');
INSERT INTO badge_optional_requirements VALUES(4615,360,11,'Follow the family tree of a racehorse back. Preschool-Level 1: Follow back one generation. Level 2: Follow back two. Level 3: Follow back three. Levels 4-5: Follow back four.');
INSERT INTO badge_optional_requirements VALUES(4616,360,12,'Learn at least three racetrack terms and sayings as well as their meanings.');
INSERT INTO badge_optional_requirements VALUES(4617,360,13,'Learn how “handicapping” works.');
INSERT INTO badge_optional_requirements VALUES(4618,360,14,'Learn about three different breeds that are used for racing around the world. Why do these breeds excel at racing?');
INSERT INTO badge_optional_requirements VALUES(4619,360,15,'Learn the time record for a race of your choice. What horse set it and when?');
INSERT INTO badge_optional_requirements VALUES(4620,360,16,'Learn the names of three races. Where are these held? Who was the most recent winner?');
INSERT INTO badge_optional_requirements VALUES(4621,360,17,'Earn the Horses badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4622,360,18,'Learn about the horses that aren’t successful. What is an Off the Track Thoroughbred (OTTB)? What struggles might these horses face when being retrained? What happens to the ones who aren’t bought/rescued?');
INSERT INTO badge_optional_requirements VALUES(4623,360,19,'Learn about racing tack. What are the weigh limits? Why do some people use horse blinders? Are special horseshoes needed?');
INSERT INTO badge_optional_requirements VALUES(4624,360,20,'Tour a horseracing stable, such as one in Kentucky.');
INSERT INTO badge_optional_requirements VALUES(4625,362,3,'Read a book about training horses.');
INSERT INTO badge_optional_requirements VALUES(4626,362,4,'Name 4 styles/disciplines of training. Explain similarities and differences.');
INSERT INTO badge_optional_requirements VALUES(4627,362,5,'Make a list of tools or supplies you might need for training.');
INSERT INTO badge_optional_requirements VALUES(4628,362,6,'Know what food/supplements are needed for horses when in training.');
INSERT INTO badge_optional_requirements VALUES(4629,362,7,'What activities can be done in a round pen, square pen, arenas, open space?');
INSERT INTO badge_optional_requirements VALUES(4630,362,8,'Interview a professional trainer. What schooling did that have to do? How did they learn what to do and when?');
INSERT INTO badge_optional_requirements VALUES(4631,362,9,'Take at least three lessons from a professional trainer on “how to” subject of your choice.');
INSERT INTO badge_optional_requirements VALUES(4632,362,10,'Teach a horse something new while under appropriate supervision.');
INSERT INTO badge_optional_requirements VALUES(4633,362,11,'Draw your ideal training facility. What do you want and why?');
INSERT INTO badge_optional_requirements VALUES(4634,362,12,'How old should a horse be when they begin training? Why?');
INSERT INTO badge_optional_requirements VALUES(4635,362,13,'How much time should be spent training a 1 year old horse, 2 year old horse, or a 3 year old horse (daily, weekly, monthly)?');
INSERT INTO badge_optional_requirements VALUES(4636,362,14,'If you have a horse that has no training, make a list of 10 or more items you would want your horse to know/be able to do. Which order would you training your horse in and why?');
INSERT INTO badge_optional_requirements VALUES(4637,362,15,'Look back in history. Can you find three examples of how horses were trained?');
INSERT INTO badge_optional_requirements VALUES(4638,362,16,'What careers are there related to horse training? What school is required or often used?');
INSERT INTO badge_optional_requirements VALUES(4639,362,17,'Are trainers the only people who should know about body language? Who else should understand body language? How can it help what they do?');
INSERT INTO badge_optional_requirements VALUES(4640,362,18,'Participate in an equine clinic.');
INSERT INTO badge_optional_requirements VALUES(4641,363,3,'Learn about jobs that involve hostess/host skills.  Think about everything from waitressing to a hotel concierge.');
INSERT INTO badge_optional_requirements VALUES(4642,363,4,'A good hostess/host makes their guests feel as comfortable as possible.  You should introduce people who don’t know each other and make sure that you mention one or two things they have in common so that they have something they can talk about.  There is nothing worse than being in a room where you don’t know anyone and can’t think of how to start a conversation.  Invite at least two friends over who do not know each other. Make sure you introduce them and tell them what they have in common. Make sure you plan your activities for the day to include things that both friends like to do and that you do not favor one friend over the other.');
INSERT INTO badge_optional_requirements VALUES(4643,363,5,'Help your parent clean your house before guests are expected to arrive.');
INSERT INTO badge_optional_requirements VALUES(4644,363,6,'Part of a hostess’s/host’s job is to make sure her guests are entertained.  Invite one or more friends over and make sure to have plans for several activities.  Think about what your friends might enjoy as well as how much time each activity might take.  Always plan extra activities in case you finish early, or someone is not interested one or more of them.');
INSERT INTO badge_optional_requirements VALUES(4645,363,7,'A hostess/host should do everything she can to enhance her guest’s experience and make them feel good.  How a room is decorated goes a long way to improving your guest’s experience.   Have you ever gone to a party and got excited the second you went through the door simply because of the decorations?   If you are having a birthday party, people expect a festive atmosphere with balloons and decorations.  If you are having a formal dinner, guests expect nice table cloths and a center piece.  Decorate a room, or set a table, for a specific type of get together.  Think about what type of reaction you want to see from your guests.');
INSERT INTO badge_optional_requirements VALUES(4646,363,8,'Earn the Etiquette badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4647,363,9,'Participate in a service project that involves hostessing such as serving meals at a rescue mission.');
INSERT INTO badge_optional_requirements VALUES(4648,364,3,'Read a book about hot air balloons.');
INSERT INTO badge_optional_requirements VALUES(4649,364,4,'Attend a hot air balloon festival or event.');
INSERT INTO badge_optional_requirements VALUES(4650,364,5,'Ride in a hot air balloon.');
INSERT INTO badge_optional_requirements VALUES(4651,364,6,'Find out about at least 5 different major hot air balloon festivals.  Where are they held?  When? How many balloonists usually participate?');
INSERT INTO badge_optional_requirements VALUES(4652,364,7,'Find out what the term “Glodeo” means.  Where did it originate?');
INSERT INTO badge_optional_requirements VALUES(4653,364,8,'Complete a science project involving warm air rising.');
INSERT INTO badge_optional_requirements VALUES(4654,364,9,'Find out what types of safety equipment must be on board a hot air balloon.');
INSERT INTO badge_optional_requirements VALUES(4655,364,10,'Watch a documentary about hot air balloons.');
INSERT INTO badge_optional_requirements VALUES(4656,364,11,'Research a career that has something to with hot air balloons.  For example a balloon pilot, balloon designer, event coordinator, etc.  What does their job entail?  How much might you expect to earn? Where might you need to live?');
INSERT INTO badge_optional_requirements VALUES(4657,364,12,'With permission from a parent, surf the internet to see how many unusual shaped hot air balloons you can find.  Which is your favorite?  Why?');
INSERT INTO badge_optional_requirements VALUES(4658,364,13,'Know what the following instrumentation is used for that is commonly found on a hot air balloon: Altimeter Variometer GPS Air Temperature Gauge Envelope Temperature Gauge Ambient Temperature Gauge');
INSERT INTO badge_optional_requirements VALUES(4659,364,14,'Find out how hot air balloons are stored and maintained.  How often should they be inspected? What is looked for?');
INSERT INTO badge_optional_requirements VALUES(4660,365,3,'What can you do with left over homemade hot chocolate? How long will it keep?');
