INSERT INTO badge_optional_requirements VALUES(4663,365,6,'Have a hot chocolate party with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4664,365,7,'What are extracts? How can these add flavors to your hot chocolate? Try two flavors.');
