INSERT INTO badge_optional_requirements VALUES(4673,365,18,'What are the price differences by making your own hot chocolate verses buying the instant powder?');
INSERT INTO badge_optional_requirements VALUES(4674,368,3,'Participate in a community service project that involves hula hoops.  You might hold a hula hoop marathon to raise money for a charity, hold a hula hoop collection to gather hoops for local schools, etc.');
