INSERT INTO badge_optional_requirements VALUES(4676,368,5,'Participate in a hula hooping contest, or challenge yourself to hula hoop for 5 minutes without stopping.');
INSERT INTO badge_optional_requirements VALUES(4677,368,6,'While hula hooping, practice walking, jumping, turning in circles, dancing, squating, standing on one leg, etc.');
INSERT INTO badge_optional_requirements VALUES(4678,368,7,'Learn about how hula hooping can help you become a healthier person.  What can hula hooping do for your heart, lungs, and muscles?');
INSERT INTO badge_optional_requirements VALUES(4679,368,8,'Teach a friend or younger person how to hula hoop.');
INSERT INTO badge_optional_requirements VALUES(4680,368,9,'Watch a hula hoop competition or performance.');
INSERT INTO badge_optional_requirements VALUES(4681,368,10,'Learn about hula hoop dancing and create your own dance routine using a hula hoop.');
INSERT INTO badge_optional_requirements VALUES(4682,368,11,'Learn about how hoops are used in rhythmic gymnastics and watch at least one routine.');
INSERT INTO badge_optional_requirements VALUES(4683,369,3,'Learn what germs and bacteria are and how they affect the body.  Explain the importance of proper hand washing to maintaining the health of your body.  Preschool-Level 2: Demonstrate proper hand washing technique.  In addition, Levels 3-5: Design an activity to help teach younger children how to properly wash their hands.');
INSERT INTO badge_optional_requirements VALUES(4684,369,4,'Earn the First Aid badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4685,369,5,'Create a craft that shows your knowledge of the human body.  Examples might include a jointed paper skeleton, a paper bag vest with all organs located in the right position, a model of the brain, etc.');
