INSERT INTO badge_optional_requirements VALUES(4689,369,9,'Describe what hormones are and what they do.');
INSERT INTO badge_optional_requirements VALUES(4690,369,10,'Explain how vaccinations work and give three examples of diseases that are prevented through the use of vaccinations.');
INSERT INTO badge_optional_requirements VALUES(4691,369,11,'Take a field trip to a doctor’s office, hospital, nursing home, or other health facility.');
