INSERT INTO badge_optional_requirements VALUES(4693,369,13,'Learn about bacteria living in your body and how they contribute to health.');
INSERT INTO badge_optional_requirements VALUES(4694,369,14,'Learn about and describe the differences between cartilage and bones. What parts of your body are made of cartilage?');
INSERT INTO badge_optional_requirements VALUES(4695,370,3,'Learn about various gun types.  Compare and contrast at least three different guns.');
INSERT INTO badge_optional_requirements VALUES(4696,370,4,'Learn about various bow types.  Compare and contrast at least three different bows and arrows.');
INSERT INTO badge_optional_requirements VALUES(4697,370,5,'Take a field trip to a gun shop or shooting range.');
INSERT INTO badge_optional_requirements VALUES(4698,370,6,'Learn how to imitate an animal call to attract the animal you are hunting.');
INSERT INTO badge_optional_requirements VALUES(4699,370,7,'Learn about animal conservation and sustainable hunting.');
INSERT INTO badge_optional_requirements VALUES(4700,370,8,'Learn about the history of hunting and the weapons that have been used over time.');
INSERT INTO badge_optional_requirements VALUES(4701,370,9,'Build a blind or learn to set one up properly in an appropriate location.');
INSERT INTO badge_optional_requirements VALUES(4702,370,10,'Visit a butcher shop and find out how much it would cost to butcher your animal.  What type of meat cuts can you expect?');
INSERT INTO badge_optional_requirements VALUES(4703,370,11,'Learn about careers that have something to do with hunting.  Examples might include taxidermy, working for department of fish and game, or the forestry department, or even being a butcher.');
INSERT INTO badge_optional_requirements VALUES(4704,370,12,'Participate in a community service project that has something to do with hunting.  Examples might include building animal habitats, education others through posters or pamphlets, etc.');
INSERT INTO badge_optional_requirements VALUES(4705,370,13,'Take a field trip to a taxidermy shop and learn how animals are preserved and mounted.');
INSERT INTO badge_optional_requirements VALUES(4706,370,14,'Learn about the role that dogs play in hunting.  What breeds are used and why?  Visit a hunting dog training, or show, or view one online with a parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(4707,370,15,'Learn about camouflage.  How can proper camouflage help you succeed in hunting?  What type of camouflage is available?  Clothing?  Blinds?  Tree Stands?');
INSERT INTO badge_optional_requirements VALUES(4708,370,16,'Earn the Firearms badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4709,370,17,'Earn the Animal Tracking badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4710,371,3,'When you cough or sneeze, do it into your elbow instead of your hand. If you cough into your hand and then shake hands with someone or touch a door knob, you can spread your germs to other people.');
INSERT INTO badge_optional_requirements VALUES(4711,371,4,'Find out what kind of skin you have. If you have dry skin, take a bath every 1-2 days and wash all parts of your body. If you have normal skin or if you have been playing outside or in hot weather, make sure you take a bath every day.');
INSERT INTO badge_optional_requirements VALUES(4712,371,5,'Learn when you should wash your hands and the proper way to do it. Germs from coughing or rubbing your eyes, nose and mouth can be spread to other people by your hands. Hand washing helps decrease the number of germs that can be spread.');
INSERT INTO badge_optional_requirements VALUES(4713,371,6,'Create a chart for your bathroom that includes things like brushing your teeth, taking a bath, clipping your nails and washing your hair. Keep track of how often you do these things for 2 weeks.');
INSERT INTO badge_optional_requirements VALUES(4714,371,7,'What is bacteria? How does it affect your health? How can you avoid bacterial infections? What is a virus? How does it affect your health? How can you avoid viral infections? What is a fungus? How do they affect your health? How can you avoid fungal infections?');
INSERT INTO badge_optional_requirements VALUES(4715,371,8,'Research careers in the hygiene industry. Examples might include becoming a dental hygienist, public health official, chemist, or a salesperson for a company like Johnson and Johnson.');
INSERT INTO badge_optional_requirements VALUES(4716,371,9,'Find out how to care for your nails on your hands and feet. What are the dangers in getting a manicure or pedicure?');
INSERT INTO badge_optional_requirements VALUES(4717,371,10,'Participate in a community service project that promotes good hygiene such as putting together personal hygiene kits to donate to organizations such as your local homeless shelter, foster care agency, or other program. Your kits might include items such as a hair brush, tooth brush, tooth paste, nail clippers, soap, shampoo, deodorant, etc.');
INSERT INTO badge_optional_requirements VALUES(4718,372,3,'Like everything else, modern technology is changing the way we view ice cream.  Learn about modern methods of ice cream making such as Dippin’Dots, Nitrofreeze, or freeze dried ice cream.');
INSERT INTO badge_optional_requirements VALUES(4719,372,4,'Make some homemade ice cream using a different method then you used for Preschool requirement 1 (coffee can rolling or ice cream in a bag, a hand crank ice cream machine, or an electric machine).  Which method did you prefer?  Why?');
INSERT INTO badge_optional_requirements VALUES(4720,372,5,'Tour an ice cream shop and learn about all the different treats they make with ice cream.');
INSERT INTO badge_optional_requirements VALUES(4721,372,6,'Make a list of all the ice cream flavors you can find.  This includes flavors found at various grocery stores, ice cream parlors, or even online.  Discuss which flavors you think would be the most popular and which probably don’t sell as well.  Can you find a list of flavors that have been discontinued?  Make up a list of at least 3 new flavors that you think would make good ice cream.');
INSERT INTO badge_optional_requirements VALUES(4722,372,7,'Tour an ice cream factory.');
INSERT INTO badge_optional_requirements VALUES(4723,372,8,'Learn about alternatives to dairy ice cream for people who have allergies such as coconut milk, rice milk, soy milk, etc.  Try at least one of these alternatives.  Do they taste as good as dairy ice cream?');
INSERT INTO badge_optional_requirements VALUES(4724,372,9,'Make a list of at least 10 desserts that use ice cream as a base such as sundaes, fried ice cream, or ice cream cake.  Make at least one of these desserts.');
INSERT INTO badge_optional_requirements VALUES(4725,372,10,'Learn how people made ice cream before there were in home freezers.  Where did they get the ice?  How was it stored?  Where did they get the cream?');
INSERT INTO badge_optional_requirements VALUES(4726,372,11,'Learn about careers in the ice cream industry.  Who invents, tastes, tests, and markets new ice cream flavors or desserts?  What type of education do they need?  How much might they be paid?  Where might you have to live and work?');
INSERT INTO badge_optional_requirements VALUES(4727,372,12,'Participate in a community service project that involves ice cream.  This could be anything from hosting a community ice cream social to coordinating with a local ice cream shop to donate a percentage of their profits to a local charity.');
INSERT INTO badge_optional_requirements VALUES(4728,373,3,'Create a model of an iceberg showing both the visible and underwater parts.');
INSERT INTO badge_optional_requirements VALUES(4729,373,4,'Learn how icebergs form and break off from glaciers.');
INSERT INTO badge_optional_requirements VALUES(4730,373,5,'Learn the difference between dynamic and thermodynamic growth of sea ice.');
INSERT INTO badge_optional_requirements VALUES(4731,373,6,'Learn the history of iceberg monitoring and control.');
INSERT INTO badge_optional_requirements VALUES(4732,373,7,'Learn the origin of the expression “tip of the iceberg” and what it refers to.');
INSERT INTO badge_optional_requirements VALUES(4733,373,8,'Make a chart of different iceberg shapes (like tabular, dome, or pinnacle).');
INSERT INTO badge_optional_requirements VALUES(4734,373,9,'Learn how icebergs can pose hazards to ships. Read about the Titanic and how it sank after hitting an iceberg.');
INSERT INTO badge_optional_requirements VALUES(4735,373,10,'Look at famous pieces of art that contain icebergs. Why do you think so many artists felt drawn to depicting icebergs in their work?');
INSERT INTO badge_optional_requirements VALUES(4736,373,11,'Explore the role sea ice plays in polar ecosystems.');
INSERT INTO badge_optional_requirements VALUES(4737,373,12,'Discover which animals rely on sea ice for survival (such as polar bears or seals).');
INSERT INTO badge_optional_requirements VALUES(4738,373,13,'Learn the difference in size and shape between icebergs that calve in Greenland vs. Antarctica.');
INSERT INTO badge_optional_requirements VALUES(4739,373,14,'Learn how ice acts as an insulator in the ocean.');
INSERT INTO badge_optional_requirements VALUES(4740,373,15,'Watch time-lapse footage of sea ice forming or icebergs breaking apart.');
INSERT INTO badge_optional_requirements VALUES(4741,373,16,'Study the seasonal patterns of sea ice in the Arctic and Antarctic.');
INSERT INTO badge_optional_requirements VALUES(4742,373,17,'Observe how climate change is affecting sea ice and iceberg formation.');
INSERT INTO badge_optional_requirements VALUES(4743,373,18,'Learn about ice climbing. Why is it so dangerous? Why do you think people do it despite the known dangers?');
INSERT INTO badge_optional_requirements VALUES(4744,373,19,'Compare the density of saltwater and freshwater using simple tools such as a graduated cylinder and a scale.');
INSERT INTO badge_optional_requirements VALUES(4745,373,20,'Explore how salt water affects the freezing point of water. Do a simple experiment with salt and fresh water to compare. Conduct an experiment to see how fast ice melts in saltwater vs. freshwater. How does this affect sea ice and icebergs?');
INSERT INTO badge_optional_requirements VALUES(4746,373,21,'Interview or research a scientist who studies polar environments.');
INSERT INTO badge_optional_requirements VALUES(4747,373,22,'Write a short story or poem from the perspective of an iceberg.');
INSERT INTO badge_optional_requirements VALUES(4748,373,23,'Explore how ocean currents move icebergs long distances.');
INSERT INTO badge_optional_requirements VALUES(4749,373,24,'Learn what the International Ice Patrol is and what it does.');
INSERT INTO badge_optional_requirements VALUES(4750,373,25,'Make a graph showing sea ice coverage over the last several decades.');
INSERT INTO badge_optional_requirements VALUES(4751,373,26,'Build a 3D model or diorama of a polar environment including sea ice and icebergs.');
INSERT INTO badge_optional_requirements VALUES(4752,373,27,'Draw a map showing places where icebergs are typically found, and where they typically originate.');
INSERT INTO badge_optional_requirements VALUES(4753,373,28,'Research how melting ice impacts global sea levels.');
INSERT INTO badge_optional_requirements VALUES(4754,373,29,'Use a magnifying glass or microscope to examine ice crystals and describe what you see.');
INSERT INTO badge_optional_requirements VALUES(4755,373,30,'Participate in a citizen science project that tracks polar changes (like NASA’s GLOBE Observer).');
INSERT INTO badge_optional_requirements VALUES(4756,376,3,'Learn to identify different materials needed for forts. Preschool – Level 1: Identify 5. Level 2: Identify 6. Level 3: Identify seven. Level 4: Identify 8. Level 5: Identify nine. Which are the most available?  What may differ in other cultures.');
INSERT INTO badge_optional_requirements VALUES(4757,376,4,'Build a fort using a kit.  This can be a rod and ball, cardboard house, pop up tent, fan fort, etc.  What benefits does it have?  What problems does it have?');
INSERT INTO badge_optional_requirements VALUES(4758,376,5,'Create a fort that takes up an entire room.');
INSERT INTO badge_optional_requirements VALUES(4759,376,6,'Try an activity in your fort: video gamessleep outswatch TVpretend adventureprank peopleeat a snackplay board games/card gamespretend adventureDo a non-messy craftHave a snack');
INSERT INTO badge_optional_requirements VALUES(4760,376,7,'Earn the Cleaning badge at this level.  Why is cleaning important to fort building?');
INSERT INTO badge_optional_requirements VALUES(4761,376,8,'Read a book on homes and shelters around the world.  What can you learn from them?');
INSERT INTO badge_optional_requirements VALUES(4762,376,9,'Use fort building items to create something functional in your fort.  A place to hold a tablet, create a shadow puppet wall, a door, or a place for a fan or just a few ideas.');
INSERT INTO badge_optional_requirements VALUES(4763,376,10,'Ask an adult to pick out three fort building items. One large, one small and one medium. You must use these objects, and only these objects to build a fort you can fit in.');
INSERT INTO badge_optional_requirements VALUES(4764,376,11,'Write a descriptive letter to an adult in your life about what you used to build your fort');
INSERT INTO badge_optional_requirements VALUES(4765,376,12,'Investigate careers that you might pursue if you were really good with fort building.  Ideas might include careers such as construction, architecture, or logistics.');
INSERT INTO badge_optional_requirements VALUES(4766,376,13,'Learn about the physics behind fort building.  Why does the weight of materials and the angle at which they are placed make a difference?  If you bump a couch cushion used for a wall and it falls over, what caused that?  How can draping a blanket over the cushion help keep it in place and why?');
INSERT INTO badge_optional_requirements VALUES(4767,376,14,'Take time to journal about your fort.  If you were the grown up and your child was playing in the fort, what do you think you’d want them to know?');
INSERT INTO badge_optional_requirements VALUES(4768,376,15,'Create a drawing of a fort have made and identify areas that need improvement.  These may be visual or structural. Determine the best materials to fix your fort and attempt to do so.');
INSERT INTO badge_optional_requirements VALUES(4769,376,16,'Measure your fort.  Find out the surface area of your floor space, the perimeter, and the roof height.');
INSERT INTO badge_optional_requirements VALUES(4770,376,17,'Make a themed fort.  For example you might choose Star Wars.  Create a fort that looks like a space ship and use Star Wars themed sheets, towels, etc.');
INSERT INTO badge_optional_requirements VALUES(4771,377,3,'Visit a zoo, pet shop, or other place where you can see your category of animal being fed and cared for. Level 2: Also interview the caretakers and find out what they like/dislike about their job. Level 3: Do Level 2 of this requirement and also find out what type of education or special training is necessary to work in this position. Level 4 & Level 5: Do requirement 11.');
INSERT INTO badge_optional_requirements VALUES(4772,377,4,'Make something to attract, protect, or observe your category of animal.');
INSERT INTO badge_optional_requirements VALUES(4773,377,5,'Make a chart, poster, booklet, or other exhibit to teach others what you have learned while earning this badge.');
INSERT INTO badge_optional_requirements VALUES(4774,377,6,'Make a list of animals from your category that might make good pets.  What special equipment would you need to take care of them?  What types of foods do they eat?  Is this a pet that you would like to have?  Why or why not?');
INSERT INTO badge_optional_requirements VALUES(4775,377,7,'Design and carry out a service project that will benefit your animal group.  This may be planting trees or flowers for birds or insects, raising money for organizations that protect endangered species, gathering a volunteer crew to help out at a local animal shelter, etc.');
INSERT INTO badge_optional_requirements VALUES(4776,377,8,'Research any state and federal laws that protect your animal category.  What animals in your category are on the endangered species list?  What specific protection do they receive?  How would the extinction of this animal affect mankind?  (If you researched this group at an earlier level, make sure all your data is up to date.)');
INSERT INTO badge_optional_requirements VALUES(4777,377,9,'What local or national organizations are there that study or protect animals in your category?  What do they do?  Make a poster showing how you can help to protect an animal from your category. Level 4 & Level 5: Volunteer at least 4 hours to working with one of these organizations.');
INSERT INTO badge_optional_requirements VALUES(4778,377,10,'If your animal category is present naturally in your local community, find out which animals are beneficial to humans, which are nuisances, and which are harmful.  Explain how people interact with each of these animals.');
INSERT INTO badge_optional_requirements VALUES(4779,377,11,'Level 4 & Level 5 Only: Shadow an animal caretaker for a day at a zoo, pet shop, or other place where you can see your category of animal being fed and cared for.  What careers are there in working with these types of animals?  What education or special training would you need?');
INSERT INTO badge_optional_requirements VALUES(4780,378,3,'Visit somewhere where you can see or interact with your specific insect.');
INSERT INTO badge_optional_requirements VALUES(4781,378,4,'If you insect is a local one, go outside and hunt for them.');
INSERT INTO badge_optional_requirements VALUES(4782,378,5,'Take a photograph of your insect.');
INSERT INTO badge_optional_requirements VALUES(4783,378,6,'Find out if you can eat them.  Where do people actually eat these insect?  How are they prepared?  If possible, and with a parent’s permission, eat one properly prepared.');
INSERT INTO badge_optional_requirements VALUES(4784,378,7,'What is the largest species of your insect, what is the smallest?');
INSERT INTO badge_optional_requirements VALUES(4785,378,8,'Make a booklet or poster about what you have learned to share with others.');
INSERT INTO badge_optional_requirements VALUES(4786,378,9,'Are there any world records regarding your insect (largest, strongest, fastest, smallest, etc.)?');
INSERT INTO badge_optional_requirements VALUES(4787,378,10,'If your insect is endangered, what is being done to protect it?  How can you help?');
INSERT INTO badge_optional_requirements VALUES(4788,378,11,'Participate in a community service project revolving around your insect.');
INSERT INTO badge_optional_requirements VALUES(4789,378,12,'Create a collage of at least 15 pictures of your insect.');
INSERT INTO badge_optional_requirements VALUES(4790,378,13,'If your insect is considered a pest, what is the safest, most environmentally safe way of controlling it?');
INSERT INTO badge_optional_requirements VALUES(4791,378,14,'If your insect is a beneficial one, plant some plants in your yard that will attract your insect.');
INSERT INTO badge_optional_requirements VALUES(4792,378,15,'Interview someone who studies or works with your insect.');
INSERT INTO badge_optional_requirements VALUES(4793,378,16,'Make a craft or piece of artwork that has to do with your insect.');
INSERT INTO badge_optional_requirements VALUES(4794,379,3,'Some bands have given themselves names that seem rather peculiar. Make a list of bands in your style of music and see if there are any themes that suggest themselves to you, such as food or places.');
INSERT INTO badge_optional_requirements VALUES(4795,379,4,'Write an essay about your type of music. What makes it so special to you?');
INSERT INTO badge_optional_requirements VALUES(4796,379,5,'Pick your favorite band/music group that performs your style of music and learn about their history and how they got started. Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(4797,379,6,'Attend a performance of your type of music. How many of the pieces of music played had you heard before?');
INSERT INTO badge_optional_requirements VALUES(4798,379,7,'Make a poster, scrapbook page, collage, etc, that shows what you like about your favorite band or the type of music it plays. Show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4799,379,8,'If your chosen variety of music is not a dance form choose one of your favorite pieces and try to create a dance to go along with it. If your chosen style of music is a dance form (polka, swing, etc.), learn to dance that way.');
INSERT INTO badge_optional_requirements VALUES(4800,379,9,'Learn about careers in the music business, such as music teachers, musicians, composers, etc. If possible shadow someone who works in the music industry for a day.');
INSERT INTO badge_optional_requirements VALUES(4801,379,10,'Choose a piece of music in your selected variety of music and learn the history behind it. If you cannot find any history behind your chosen piece learn who wrote it and why.');
INSERT INTO badge_optional_requirements VALUES(4802,379,11,'Make a list of song titles or pieces of music in your particular genre. Group them either by what key they are in (for classical music particularly most are labelled with what key they are in, W. A. Mozart’s Clarinet Concerto in A Major, for example) or by who wrote the music for them. Make a graph showing which composer wrote the most pieces or which were the most frequently used keys.');
INSERT INTO badge_optional_requirements VALUES(4803,379,12,'With a parent’s permission, watch a music video or a selection of video clips of pieces of music in your style.');
INSERT INTO badge_optional_requirements VALUES(4804,379,13,'Learn to play a piece of music in your style on a musical instrument.');
INSERT INTO badge_optional_requirements VALUES(4805,379,14,'On a map find 5 places that are connected in some way with your type of music, such as the birthplaces of famous musicians, sites of concerts, countries where your style of music developed, etc. Show them to at least two other people.');
INSERT INTO badge_optional_requirements VALUES(4806,379,15,'Visit the birthplace or home of a famous person in your style of music. With a parent’s permission, a virtual tour can also be taken.');
INSERT INTO badge_optional_requirements VALUES(4807,379,16,'Do you know anyone who plays your type of music for dances or talent shows, etc? Talk to them and ask how they got started and what attracted them to that particular style of music.');
INSERT INTO badge_optional_requirements VALUES(4808,380,3,'Earn the Internet Safety badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4809,380,4,'Build your own website and/or blog.');
INSERT INTO badge_optional_requirements VALUES(4810,380,5,'Learn basic coding. You may learn it for website building, which will vary depending on what type of website program you are using. For instance, in 2020, WordPress was using PHP, HTML, CSS, and JavaScript. Why do some coding languages go out of fashion, such as JOSS or DOS?');
INSERT INTO badge_optional_requirements VALUES(4811,380,6,'Learn advanced search techniques for photos. How can you instruct a search engine to only show images of a certain size or color, or that can be used for personal versus commercial use. What does “commercial use” mean? Why is it not okay to pretend that someone else’s art, photos, or other media are your own creations?');
INSERT INTO badge_optional_requirements VALUES(4812,380,7,'With a parent’s approval, find three free, age-appropriate games to play on the internet.');
INSERT INTO badge_optional_requirements VALUES(4813,380,8,'Learn how to use a map program. How can you find directions to a location you would like to visit? Can you adjust for whether you are driving or taking a bus or biking? Can you see where there might be traffic?');
INSERT INTO badge_optional_requirements VALUES(4814,380,9,'Learn what the following terms mean: Copyright Trademark Open source Commercial use Royalty/Royalty-free');
INSERT INTO badge_optional_requirements VALUES(4815,380,10,'What is a “live cam”? View three live cams around the world, for instance, at a zoo or aquarium. What is the purpose of a live cam?');
INSERT INTO badge_optional_requirements VALUES(4816,380,11,'Pretend you have to take your family on a vacation. Budget a trip using the internet to find flights, hotels, rental cars, activities, maps, etc. that you will need for your vacation. Make sure you stay within your budget. Print out the information and put together a dream travel report with your findings.');
INSERT INTO badge_optional_requirements VALUES(4817,380,12,'Learn how the internet works. Make a presentation to show to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4818,380,13,'Learn the history of the internet. Make a timeline with at least 10 events on it to show to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4819,380,14,'Find out what the difference is between websites that end with: .com,  .net .org .gov .uk, .au.  What do these mean?');
INSERT INTO badge_optional_requirements VALUES(4820,380,15,'Learn how to find reputable, scholarly articles online, either for a research project or for your own education. Are there specific websites for scholarly articles? Are there special commands that you can use with your browser to show more specific results?');
INSERT INTO badge_optional_requirements VALUES(4821,381,3,'Learn how to tell if a website is safe or not. How can you tell if a website has cryptographic protocols, such as Secure Sockets Layer (SSL) or Transport Layer Security (TLS)?');
INSERT INTO badge_optional_requirements VALUES(4822,381,4,'What is spam and what is a safe way to proceed when you encounter it?');
INSERT INTO badge_optional_requirements VALUES(4823,381,5,'Talk with you parents and decide on an appropriate time limit for internet use each day.');
INSERT INTO badge_optional_requirements VALUES(4824,381,6,'Earn the Internet badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4825,381,7,'Many teens and children have access to the internet right at their fingertips with the use of smartphones. Discuss with a parent or guardian safety guidelines for smartphone internet use.');
INSERT INTO badge_optional_requirements VALUES(4826,381,8,'Learn how to recognize a potential scam. What are some common online scams people fall for? How can you protect yourself?');
INSERT INTO badge_optional_requirements VALUES(4827,381,9,'How can you make sure your personal information is protected when you enter it online? What is the importance of passwords, pin numbers, usernames, etc?');
INSERT INTO badge_optional_requirements VALUES(4828,381,10,'Levels 4-5 Only: Learn the risks of online dating and what safety precautions you should take before considering it.');
INSERT INTO badge_optional_requirements VALUES(4829,381,11,'Learn proper internet forum safety. What are the advantages and disadvantages of forums?');
INSERT INTO badge_optional_requirements VALUES(4830,381,12,'Learn proper safety for buying and selling products online, either through an online store or an auction house. What protections does a specific site ensure for the buyer and/or seller, if any at all?');
INSERT INTO badge_optional_requirements VALUES(4831,381,13,'What is “doxing”? Compare and contrast this to cyberbullying. Why is doxing dangerous? How can you prevent it?');
INSERT INTO badge_optional_requirements VALUES(4832,381,14,'Create a presentation about internet safety and show it to a group that you believe would benefit from it.');
INSERT INTO badge_optional_requirements VALUES(4833,381,15,'What is an antivirus program and what does it do? Find out how to access your antivirus program on your computer. How can you make sure that it is up-to-date?. Find out what other components you have protecting your computer such as a firewall, ad-blocker, or anti-spyware program. Know what these components are and how they work.');
INSERT INTO badge_optional_requirements VALUES(4834,381,16,'Learn how to use cameras safely on the internet. How do you safely use a video conferencing program? What about the cameras built into your devices?');
INSERT INTO badge_optional_requirements VALUES(4835,381,17,'How can you minimize the tracings you leave behind online? How can you protect or destroy data?');
INSERT INTO badge_optional_requirements VALUES(4836,381,18,'How can you ensure that your wifi is secure? Why is it unwise to check your bank account while using public wifi?');
INSERT INTO badge_optional_requirements VALUES(4837,382,3,'Watch an age-appropriate documentary or a movie about an inventor or invention.');
INSERT INTO badge_optional_requirements VALUES(4838,382,4,'Create a list of pithy quotations from different inventors, such as “Genius is one percent inspiration and ninety-nine percent perspiration.” by Thomas Edison. Preschool: Memorize one quotes. Levels 1-2: Memorize three quotes. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(4839,382,5,'Draw a picture of your favorite invention.  Be sure to include all its parts.  Explain what it does and why it is your favorite.');
INSERT INTO badge_optional_requirements VALUES(4840,382,6,'Find pictures of different inventions and make a collage.  Show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4841,382,7,'Earn the Diligence badge. Explain why diligence is necessary for inventors.');
INSERT INTO badge_optional_requirements VALUES(4842,382,8,'Read a biography of a famous inventor, and be able to state a significant fact about them.');
INSERT INTO badge_optional_requirements VALUES(4843,382,9,'Create your own wacky invention, such as a monkey-powered banana peeler.  You may draw a picture of it or create it/a model of it in any medium you wish, such as toothpicks and marshmallows, Legos, etc.');
INSERT INTO badge_optional_requirements VALUES(4844,382,10,'Write a report on an inventor and share it with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4845,382,11,'Learn how different inventors planned their days.  Tell your family, friends, or group what you learned.  Would you like to have a day planned the way any of them planned theirs? Why or why not?');
INSERT INTO badge_optional_requirements VALUES(4846,382,12,'Make a scrapbook page about your favorite inventor and his inventions.  Show it to your family, friends, or group.  Include pictures, quotations, facts, etc.');
INSERT INTO badge_optional_requirements VALUES(4847,383,3,'Dry some herbs and use them in cooking, potpourri, or dried floral arrangements.');
INSERT INTO badge_optional_requirements VALUES(4848,383,4,'Earn the Flower Arranging badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4849,383,5,'Learn some traditional table or parlor games such as chess or charades.');
INSERT INTO badge_optional_requirements VALUES(4850,383,6,'Learn to curtsy and make formal introductions. Learn how to set a formal table and practice being a servant for your family for one meal.');
INSERT INTO badge_optional_requirements VALUES(4851,383,7,'Learn to line dance and participate in a line dance at a party or other function.');
INSERT INTO badge_optional_requirements VALUES(4852,383,8,'Make a bonnet or hat from Jane Austen’s time period.');
INSERT INTO badge_optional_requirements VALUES(4853,383,9,'Earn the Stitchery badge at your level.');
INSERT INTO badge_optional_requirements VALUES(4854,383,10,'Care for some chickens for at least one day. This needs to include gathering eggs. What protection from predators do these chickens have compared with chickens in Austen’s day?');
INSERT INTO badge_optional_requirements VALUES(4855,383,11,'Learn to play some traditional garden games such as croquet, lawn bowling or horseshoes.');
INSERT INTO badge_optional_requirements VALUES(4856,383,12,'Locate some songs mentioned in an Austen book or played in one of the movies.  Learn to sing or play one of them.');
INSERT INTO badge_optional_requirements VALUES(4857,383,13,'Cook (and eat) two traditional English foods such as lemon curd, crumpets, plum pudding, eels, pot pies, and roast venison or wild fowl.');
INSERT INTO badge_optional_requirements VALUES(4858,383,14,'Ride in a stagecoach or similar horse-drawn vehicle.');
INSERT INTO badge_optional_requirements VALUES(4859,383,15,'Read Browning sonnets aloud to family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4860,383,16,'Earn the Calligraphy badge.');
INSERT INTO badge_optional_requirements VALUES(4861,383,17,'Design and print out your own calling cards.');
INSERT INTO badge_optional_requirements VALUES(4862,383,18,'Earn the Sports (Specific) badge in Fencing.');
INSERT INTO badge_optional_requirements VALUES(4863,383,19,'Draw someone’s silhouette and pose while someone draws yours.');
INSERT INTO badge_optional_requirements VALUES(4864,383,20,'Spend an hour polishing silverware.');
INSERT INTO badge_optional_requirements VALUES(4865,383,21,'Harvest some reeds, vines, or tulles and weave them into a basket or other useable article.');
INSERT INTO badge_optional_requirements VALUES(4866,383,22,'Write a compare/contrast paper on Austen’s books.');
INSERT INTO badge_optional_requirements VALUES(4867,383,23,'Design and sew a period costume for a Jane Austen character.');
INSERT INTO badge_optional_requirements VALUES(4868,383,24,'If you have previously ridden horses and you have permission from the adult in charge, try riding a horse side-saddle.');
INSERT INTO badge_optional_requirements VALUES(4869,383,25,'Attend a day-long conference, or minimum of two meetings of a society or book club featuring Jane Austen or her books.');
INSERT INTO badge_optional_requirements VALUES(4870,383,26,'Host a party, meeting, or badge day to help younger girls earn this badge.');
INSERT INTO badge_optional_requirements VALUES(4871,383,27,'What were traditional occupations for women in Jane Austen’s day?  Many women sewed, knitted, embroidered, painted, crocheted etc.  A well accomplished young lady was expected to shine in many areas: music, art, hand-work.  Choose one of the skills and make an item.');
INSERT INTO badge_optional_requirements VALUES(4872,383,28,'Learn about daily life in Regency England.  What was the Regency?  What important events happened during that period?  What was life like for the Upper, Middle and Lower classes?');
INSERT INTO badge_optional_requirements VALUES(4873,383,29,'Read one of Jane Austen’s novels and then watch two different movies based upon that book.  Which one did you like best?  Why?  Do you feel movie-makers take too much license with the story or were they accurate to the text?  Did the omissions/alterations improve or detract from the story?');
INSERT INTO badge_optional_requirements VALUES(4874,383,30,'Learn about one of the towns or cities that Jane Austen mentions in her books such as London, Bath, and Portsmouth.  What was the town/city like during her lifetime?');
INSERT INTO badge_optional_requirements VALUES(4875,383,31,'Learn about fashions during Jane Austen’s time period.  Do you like the styles?  Why or why not?');
INSERT INTO badge_optional_requirements VALUES(4876,383,32,'Learn about the art of Jane Austen’s period.  Which British artists were active at this time?');
INSERT INTO badge_optional_requirements VALUES(4877,383,33,'Read a book by another author from the same time period.');
INSERT INTO badge_optional_requirements VALUES(4878,384,3,'Make up some recipes for Jelly Bellies.');
INSERT INTO badge_optional_requirements VALUES(4879,384,4,'Learn why Ronald Reagan is so famous for Jelly Bellies. How did his presidency impact Jelly Belly?');
INSERT INTO badge_optional_requirements VALUES(4880,384,5,'Sort a bag of Jelly Bellies into flavors. Make a chart showing how many of each type you have. Choose the best type of chart to show that information (pie, bar, line, etc.).');
INSERT INTO badge_optional_requirements VALUES(4881,384,6,'Taste test Jelly Bellies. Which are the most like the real-life counterpart? Do a blind taste test. Can you tell what flavor the beans are?');
INSERT INTO badge_optional_requirements VALUES(4882,384,7,'Taste test the Jelly Bean chocolate dips and compare to the non-dipped flavors. Which do you like better? Why?');
INSERT INTO badge_optional_requirements VALUES(4883,384,8,'Write to Jelly Belly and suggest a new flavor.');
INSERT INTO badge_optional_requirements VALUES(4884,384,9,'Use Jelly Bellies to create Jelly Belly art—temporary or permanent.');
INSERT INTO badge_optional_requirements VALUES(4885,384,10,'Compare the cost of Jelly Bellies between two stores. Which has the best price?');
INSERT INTO badge_optional_requirements VALUES(4886,384,11,'Play the Beanboozled game with the specialty surprise flavors like rotten eggs, toothpaste, and grass.');
INSERT INTO badge_optional_requirements VALUES(4887,384,12,'Design a poster advertising Jelly Bellies.');
INSERT INTO badge_optional_requirements VALUES(4888,384,13,'Learn about specialty flavors, such as certain flavors created for a holiday or that can only be purchased at certain locations.');
INSERT INTO badge_optional_requirements VALUES(4889,384,14,'Learn the history of the Jelly Belly Candy Company. What other names did the company formerly go by?');
INSERT INTO badge_optional_requirements VALUES(4890,384,15,'What other candies and products does the Jelly Belly company make?');
INSERT INTO badge_optional_requirements VALUES(4891,384,16,'Compare Jelly Bellies against similar jelly bean companies. Which company was your favorite?');
INSERT INTO badge_optional_requirements VALUES(4892,385,3,'Make a piece of jewelry using a beading technique.');
INSERT INTO badge_optional_requirements VALUES(4893,385,4,'Visit a jewelry store and examine the different jewelry styles presented.');
INSERT INTO badge_optional_requirements VALUES(4894,385,5,'Visit a craft store and examine the different jewelry supplies and tools for sale.');
INSERT INTO badge_optional_requirements VALUES(4895,385,6,'Make a ring.');
INSERT INTO badge_optional_requirements VALUES(4896,385,7,'Make a bracelet.');
INSERT INTO badge_optional_requirements VALUES(4897,385,8,'Make an anklet.');
INSERT INTO badge_optional_requirements VALUES(4898,385,9,'Make a pair of earrings.');
INSERT INTO badge_optional_requirements VALUES(4899,385,10,'Make a belt.');
INSERT INTO badge_optional_requirements VALUES(4900,385,11,'Make a piece of jewelry using semi-precious stones.');
INSERT INTO badge_optional_requirements VALUES(4901,385,12,'Make a piece of jewelry using leather.');
INSERT INTO badge_optional_requirements VALUES(4902,385,13,'Learn to identify at least 3 different types of chain such as trace, belcher, rope, anchor, herringbone, curb or bead.');
INSERT INTO badge_optional_requirements VALUES(4903,385,14,'Participate in a service project that involves jewelry making such as making give away pins with an inspirational message or selling your creations to raise money for charity.');
INSERT INTO badge_optional_requirements VALUES(4904,385,15,'Learn about different careers that involve jewelry making such as a jeweler, instructor, store owner, etc.');
INSERT INTO badge_optional_requirements VALUES(4905,385,16,'Learn to make your own chain.');
INSERT INTO badge_optional_requirements VALUES(4906,385,17,'Learn at least 3 wire twisting patterns used in jewelry.');
INSERT INTO badge_optional_requirements VALUES(4907,385,18,'Learn to lengthen or shorten a piece of jewelry without damaging it.');
INSERT INTO badge_optional_requirements VALUES(4908,385,19,'Learn to make a piece of jewelry by tying knots in string such as friendship bracelets.');
INSERT INTO badge_optional_requirements VALUES(4909,385,20,'Learn how to create a piece of jewelry that also has a useful application. For instance, you might make a band for a watch, create a necklace with a compass on it, or a paracord belt.');
INSERT INTO badge_optional_requirements VALUES(4910,385,21,'Make a piece of jewelry using a metal or wire technique.');
INSERT INTO badge_optional_requirements VALUES(4911,386,3,'Read a book, watch a video, or go online (with your parent’s permission) to find out how jigsaw puzzles are made. What sorts of materials can jigsaw puzzles be made of?');
INSERT INTO badge_optional_requirements VALUES(4912,386,4,'Host a jigsaw puzzles party for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4913,386,5,'Find out what products are available to glue your puzzles together when they are done.  Learn the process involved and when you have finished your jigsaw puzzle, glue it together and hang it on a wall for everyone to see.');
INSERT INTO badge_optional_requirements VALUES(4914,386,6,'Make a timeline of the history of jigsaw puzzles and show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(4915,386,7,'Learn about unusual jigsaw puzzles, such as two-sided, shaped, monochromatic, or holographic ones. Find one and put it together!');
INSERT INTO badge_optional_requirements VALUES(4916,386,8,'Learn about careers having to do with jigsaw puzzles, such as a designer, or a manufacturer. If possible, shadow someone for a day who works with jigsaw puzzles for a living.');
INSERT INTO badge_optional_requirements VALUES(4917,386,9,'Make your own jigsaw puzzle.');
INSERT INTO badge_optional_requirements VALUES(4918,386,10,'Collect jigsaw puzzles to donate to soldiers, hospitals, senior centers, or other places where they might be used or participate in another community service project that involves jigsaw puzzles.');
INSERT INTO badge_optional_requirements VALUES(4919,386,11,'Put together a 3D jigsaw puzzle.');
INSERT INTO badge_optional_requirements VALUES(4920,386,12,'Learn about the different brands of jigsaw puzzles. Which ones create the most durable puzzles? Which ones specialize in unusual puzzles? Are there limited edition puzzles?');
INSERT INTO badge_optional_requirements VALUES(4921,386,13,'Some puzzles can’t be built in a day. Learn how to protect your jigsaw puzzle from harm while you are building it.');
INSERT INTO badge_optional_requirements VALUES(4922,386,14,'What are the world’s smallest and largest commercially sold puzzles?');
INSERT INTO badge_optional_requirements VALUES(4923,387,3,'Write down at least ten journaling prompts of your own to help you think of things to write about. Examples might include: If you could have any super power, what would it be and why? What was you favorite part of today? What are you doing to make yourself a better person?');
INSERT INTO badge_optional_requirements VALUES(4924,387,4,'Learn about the mental and physical health benefits of journaling.');
INSERT INTO badge_optional_requirements VALUES(4925,387,5,'What is Journal Therapy and when is it used?');
INSERT INTO badge_optional_requirements VALUES(4926,387,6,'Visit a bookstore or gift store that sells journals. How many different designs can you find? How many have lined pages? How many have blank? Which ones come with prompts or ideas for writing? Which have a specific purpose?');
INSERT INTO badge_optional_requirements VALUES(4927,387,7,'Make a list of at least ten different types of journals you could keep. Examples might include a personal journal, a travel journal, or a goals journal.');
INSERT INTO badge_optional_requirements VALUES(4928,387,8,'Participate in a community service project that involves journaling in some way. Examples might include teaching younger kids how to make a journal, holding a journal writing workshop, having community members write in a community journal about what the military’s service means to them and sending it to soldiers overseas (make sure to review all entries before sending!).');
INSERT INTO badge_optional_requirements VALUES(4929,387,9,'Design a cover for a journal.');
INSERT INTO badge_optional_requirements VALUES(4930,387,10,'Research careers involving journaling, such as journalism or becoming a journalist. What kind of education would you need? What type of salary might you be paid?');
INSERT INTO badge_optional_requirements VALUES(4931,387,11,'Watch a documentary that is based on a journal and compare the two. What are the differences and similarities you notice?');
INSERT INTO badge_optional_requirements VALUES(4932,387,12,'Historically, why are journals important? What can they tell us about the past? What is the oldest known journal?');
INSERT INTO badge_optional_requirements VALUES(4933,388,3,'Listen to joyful music.  Learn a hymn/psalm/song of joy and share it with friends, family or group.');
INSERT INTO badge_optional_requirements VALUES(4934,388,4,'Have you ever noticed how just the memory of a joyful moment can lift your spirits?  Think about ways you can create some new memories to hold on to.  Recall your most joyous memories and talk about them with your friends or family.  Come up with a list of at least 10 different things that would give joy to yourself and others and do two of them.');
INSERT INTO badge_optional_requirements VALUES(4935,388,5,'Families today can become so busy that they forget to spend time just having fun with one and other. Write down a list of joyful things you can do with your family in only 15 minutes that will bring all of you joy. Try to do at least one of them each day for one week.  For an extra challenge, take a chore that you don’t usually enjoy. Put on some joyful music and do the chore in a joyful attitude.');
INSERT INTO badge_optional_requirements VALUES(4936,388,6,'What does your book of worship/faith say about being joyful? Memorize verses about joy. Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(4937,388,7,'Host a Night of Laughter. Laughter is often from pure joy in the enjoyment of uplifting activities. Following are a few ideas, but feel free to come up with your own. Have family members take turns recalling their favorite joyous or humorous memories.  Tell jokes that are really funny – not poking fun at people.  Hold a serious contest: On “go” everyone must hold a straight face; if you smile or laugh you are out and may do whatever is necessary to make the others laugh so long as you do not actually touch them (no tickling allowed).  Have a barn dance or a 1970’s disco night complete with costumes and listen to uplifting, joyful music.');
INSERT INTO badge_optional_requirements VALUES(4938,388,8,'Using the Victorian Language of Flowers, make a bouquet that symbolizes what joy means to you.  You can find the meanings assigned to the flowers at various websites (with a parent’s permission) or in books and you may cut pictures from magazines or webpages to create a collage “bouquet”.  Make sure you include the name and meaning of each flower that you choose.  If you wish you may make a bouquet out of real or artificial flowers.');
INSERT INTO badge_optional_requirements VALUES(4939,388,9,'Find and memorize quotes about joy. Preschool: Memorize one quote. Levels 1-2: Memorize three quotes. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(4940,388,10,'Make a list of what brings you joy that are not dependent on another person’s actions.');
INSERT INTO badge_optional_requirements VALUES(4941,388,11,'Prepare a list of questions and interview three people that you would consider “joyful”. Discuss with your parent or leader what these people have in common.');
INSERT INTO badge_optional_requirements VALUES(4942,388,12,'Make a decoration to display in your home that reminds you to find joy.');
INSERT INTO badge_optional_requirements VALUES(4943,390,3,'Participate in a jump rope competition.');
INSERT INTO badge_optional_requirements VALUES(4944,390,4,'Learn at least 3 songs or chants that people jump rope to.');
INSERT INTO badge_optional_requirements VALUES(4945,390,5,'Learn about jump rope competitions and watch one.');
INSERT INTO badge_optional_requirements VALUES(4946,390,6,'Join a jump rope team.');
INSERT INTO badge_optional_requirements VALUES(4947,390,7,'Try out at least 3 different types of jump ropes such as beaded, vinyl, leather, or cloth.');
INSERT INTO badge_optional_requirements VALUES(4948,390,8,'Learn to jump a rope being turned by two other people. Learn how to “jump in”.');
INSERT INTO badge_optional_requirements VALUES(4949,390,9,'Learn how to do double dutch.');
INSERT INTO badge_optional_requirements VALUES(4950,390,10,'Find out how jumping rope impacts your health.  What can it do for your heart, lungs and muscles?');
INSERT INTO badge_optional_requirements VALUES(4951,390,11,'Learn a new jump rope trick that you did not previously know. This requirement can be repeated up to three times.');
INSERT INTO badge_optional_requirements VALUES(4952,392,3,'Learn about the different styles of kayaks for different activities.  How do the designs and composition differ from activity to activity? recreational kayaks sea kayaks  racing kayaks  whitewater kayaks fishing kayaks surf kayaks');
INSERT INTO badge_optional_requirements VALUES(4953,392,4,'Learn about how kayaks can differ in structure.  What are the pros and cons of each? Rigid or hard shell kayaks Inflatable kayaks Foldable Kayaks');
INSERT INTO badge_optional_requirements VALUES(4954,392,5,'Learn about the different things kayaks can be made of: Rotomolded polyethylene Blow-molded plastic Fiberglass composite ABS plastic PVC (polyvinyl chloride)');
INSERT INTO badge_optional_requirements VALUES(4955,392,6,'Learn how to keep your kayak from capsizing including learning proper bracing techniques.');
INSERT INTO badge_optional_requirements VALUES(4956,392,7,'Demonstrate how to safely raft up with other kayaks and how to separate from a raft quickly in case of emergency.');
INSERT INTO badge_optional_requirements VALUES(4957,392,8,'Learn how to properly navigate through different water conditions, including wind, waves, and currents.');
INSERT INTO badge_optional_requirements VALUES(4958,392,9,'Learn about the history of kayaking. Where did kayaks originate, and who used them?');
INSERT INTO badge_optional_requirements VALUES(4959,392,10,'Demonstrate how to safely execute an assisted rescue and a self-rescue.');
INSERT INTO badge_optional_requirements VALUES(4960,392,11,'Demonstrate how to properly adjust the foot pedals and seat for comfort and proper paddling technique in a paddle kayak.');
INSERT INTO badge_optional_requirements VALUES(4961,392,12,'Show knowledge of different types of paddles and their uses.  How does weight, length and design affect how easy it is to control a kayak.  Why would you want different types of paddles for different activities?');
INSERT INTO badge_optional_requirements VALUES(4962,392,13,'Volunteer to help clean up a lake, river, or beach to help protect waterways for kayakers and wildlife.');
INSERT INTO badge_optional_requirements VALUES(4963,392,14,'Demonstrate how to properly load a kayak for a multi-day trip, including gear placement and weight distribution.');
INSERT INTO badge_optional_requirements VALUES(4964,392,15,'Research famous kayak expeditions or athletes. What made their journey special or record-breaking?');
INSERT INTO badge_optional_requirements VALUES(4965,392,16,'Show knowledge of different types of PFDs and their uses, including inflatable and non-inflatable PFDs.');
INSERT INTO badge_optional_requirements VALUES(4966,392,17,'Show knowledge of different types of kayaking equipment such as spray skirts, dry bags, and bilge pumps.  Look through a kayak catalog or website and see what type of items are available that you may never have thought of.');
INSERT INTO badge_optional_requirements VALUES(4967,392,18,'Visit a kayak store. What types of kayaks do they carry? What accessories do they have? How might a store in a different part of the country differ depending on the type of water activites they are near?');
INSERT INTO badge_optional_requirements VALUES(4968,392,19,'Demonstrate how to properly use a whistle and signal mirror for communication and rescue.');
INSERT INTO badge_optional_requirements VALUES(4969,392,20,'Demonstrate how to properly use a spray skirt and how to perform a wet exit with a spray skirt.');
INSERT INTO badge_optional_requirements VALUES(4970,392,21,'Demonstrate how to properly use a bilge pump and how to pump out a kayak.');
INSERT INTO badge_optional_requirements VALUES(4971,392,22,'Learn about the proper clothing and footwear to wear while kayaking.');
INSERT INTO badge_optional_requirements VALUES(4972,393,1,'Learn why the letters and symbols are placed the way they are on a keyboard.');
INSERT INTO badge_optional_requirements VALUES(4973,393,2,'Learn how keyboards or typewriters are made.');
INSERT INTO badge_optional_requirements VALUES(4974,393,3,'Learn the history of typing.  When did this become a popular way of writing? How did it change the world of writing?');
INSERT INTO badge_optional_requirements VALUES(4975,393,4,'Make a timeline of at least 10 events in the history of typing.');
INSERT INTO badge_optional_requirements VALUES(4976,393,5,'Learn about different careers that use typing. What additional educational requirements are needed to work in these fields?  What type of pay can you expect to receive?');
INSERT INTO badge_optional_requirements VALUES(4977,393,6,'Learn the history of the different kinds of machines used to type. How have these machines changed typing through the years?');
INSERT INTO badge_optional_requirements VALUES(4978,393,7,'With a parent’s permission, go online and find 3 different typing games to play.');
INSERT INTO badge_optional_requirements VALUES(4979,393,8,'Set a new typing goal like increasing how many letters you can type per minute and meet that goal.');
INSERT INTO badge_optional_requirements VALUES(4980,393,9,'Find a place where you can go see different kinds of old typewriters, either in person or online. Pick 3 or more kinds and be able to tell the differences between them.');
INSERT INTO badge_optional_requirements VALUES(4981,393,10,'Write 2-3 of your reports for school using a typewriter or a computer program. Did typing become easier or harder with each report typed?  Did you make more or less mistakes?');
INSERT INTO badge_optional_requirements VALUES(4982,393,11,'Learn who Frank Gilbreth was and how his motion studies influenced typing.');
INSERT INTO badge_optional_requirements VALUES(4983,393,12,'Learn what ASCII art is and create a piece of artwork using this technique.');
INSERT INTO badge_optional_requirements VALUES(4984,394,3,'Read a book about kindness. What does this story say about kindness? What can you learn from the main character? Write a short essay about what this story meant to you and how it portrays kindness.');
INSERT INTO badge_optional_requirements VALUES(4985,394,4,'Make some Random Acts of Kindness (RAK) tokens. These can be made of wooden discs or squares of cardboard and then decorated with the initials RAK. Keep a few with you and hand them to people when you catch them performing a random act of kindness. For example, if you are standing in line at the store and someone allows you to go in front of them because you have fewer items, thank them and give them a token to recognize their act of kindness. Then ask them to pass the token on to someone else who does a kind act.');
INSERT INTO badge_optional_requirements VALUES(4986,394,5,'Kindness is a trait that you should show not only to humans, but also to animal and nature. Discuss the Leave No Trace rule of camping and outdoor activities. How does this relate to being kind? How can you be kind to animals? If you have a pet, find a way to show it extra kindness. Play with it more often, make sure that it is fed on time and an appropriate amount of food, etc.');
INSERT INTO badge_optional_requirements VALUES(4987,394,6,'Perform at least 20 random acts of kindness. These acts are usually unplanned, which means you need to keep your eyes out for opportunities to show kindness, wherever and whenever they appear. Examples might include: Leave a small gift at the door of a family suffering severe illness, like cancer. Write a note to a teacher, thanking him or her for a lesson. Let the impatient person behind you go ahead of you in line. Buy a movie ticket for the person behind you in line.');
INSERT INTO badge_optional_requirements VALUES(4988,394,7,'Search through magazines to find examples of people performing acts of kindness. Create a collage with what you find.');
INSERT INTO badge_optional_requirements VALUES(4989,394,8,'What does your book of faith say about kindness? Memorize verses about kindness. Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(4990,394,9,'Learn or compose a song about kindness. Sing or play it for someone.');
INSERT INTO badge_optional_requirements VALUES(4991,394,10,'Put away a shopping cart for someone who has just finished loading their groceries or put away some that have been left in inappropriate spots in the parking lot. How is this an act of kindness for both the business and the shoppers?');
INSERT INTO badge_optional_requirements VALUES(4992,394,11,'Have you ever noticed how the tone of your voice can make even kind words seem mean? Practice using both kind words and a kind tone when you speak. Think before you say something about how it may make someone else feel.');
INSERT INTO badge_optional_requirements VALUES(4993,394,12,'Make a list of 10 kind things to say about each member of your family. Then give them the lists.');
INSERT INTO badge_optional_requirements VALUES(4994,394,13,'Draw a picture of what kindness means to you.');
INSERT INTO badge_optional_requirements VALUES(4995,394,14,'Write an essay about what kindness means to you.');
INSERT INTO badge_optional_requirements VALUES(4996,394,15,'Write a story where kindness plays an important role.');
INSERT INTO badge_optional_requirements VALUES(4997,394,16,'Read a biography about someone known for their kindness.');
INSERT INTO badge_optional_requirements VALUES(4998,394,17,'Many animals are mistreated every day. Make a poster encouraging people to be kind to animals. Put it up somewhere in your community with permission.');
INSERT INTO badge_optional_requirements VALUES(4999,394,18,'Write the word KINDNESS vertically on a piece of paper. Now think of one kind act that you could do that starts with each letter in the word. For example  you could put “Kiss my mom” and you might put “invite someone to join in a game.”');
INSERT INTO badge_optional_requirements VALUES(5000,394,19,'Memorize or write a poem about kindness.');
INSERT INTO badge_optional_requirements VALUES(5001,394,20,'Find and memorize famous quotations about kindness. Preschool: Memorize one quote. Levels 1-2: Memorize three quotes. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(5002,394,21,'Create a booklet or poster by answering and illustrating the following prompts: a. My friends like it when ______________ b. I show others I care when ______________ c. Friends can be counted on to ______________ d. I am kind when I ______________ e. Caring shows when I ______________ f. The best way to show my family that I care is when I ______ g. The most important kindness I’ve received is ______________ h. Kindness means ______________');
INSERT INTO badge_optional_requirements VALUES(5003,394,22,'Using the Victorian Language of flowers make a bouquet that symbolizes what kindness means to you. You can find the meanings assigned to the flowers at various websites or in books and you may cut pictures from magazines or web pages to create a collage bouquet.  Make sure you include the name and meaning of each flower that you choose. You may make a scrapbook page using pictures of flowers or make a bouquet using real or artificial flowers.');
INSERT INTO badge_optional_requirements VALUES(5004,394,23,'Make a skit or movie where kindness plays an important role in the plot.');
INSERT INTO badge_optional_requirements VALUES(5005,394,24,'Make and give out “Warm Fuzzies” to your friends and family. A how-to is listed below. How to Make Warm Fuzzies You will need: Pompoms Googly eyes Colored paper or craft foam Glue White paper Instructions: 1. Glue two google eyes onto your pompom. 2. Cut a small heart out of paper or craft foam to use for feet. Glue your pompom on top of your heart, and you will have a basic Warm Fuzzy. 3. Cut your white paper into small strips about 1 inch wide and 4 inches long. Leaving the first inch of your paper blank, write kind phrases on the slips such as: Have a Great Day! I love you. God loves you. You are special. I’m glad you’re my friend. 4. Now glue your Warm Fuzzy onto the blank part of the slip of paper so that you do not cover up your phrase. 5. Give the Warm Fuzzies to your friends and family whenever you think they may need a little kindness. If you are really feeling creative, add hair bows, sun glasses, small pompom noses and other details to your Warm Fuzzies to make them more unique.');
INSERT INTO badge_optional_requirements VALUES(5006,395,3,'Research whether there is a rock group in your community.   Join them if you like or if there is no group in your area, create one.');
INSERT INTO badge_optional_requirements VALUES(5007,395,4,'Give thought to what kind of rocks work the best for painting. Discuss the characteristics of a good painting rock.');
INSERT INTO badge_optional_requirements VALUES(5008,395,5,'Go on a rock hunt for rocks to paint. Of you are unable to locate good ones, consider floral stones from the craft store.');
INSERT INTO badge_optional_requirements VALUES(5009,395,6,'Paint and place at least 10 rocks.');
INSERT INTO badge_optional_requirements VALUES(5010,395,7,'Go on rock hunt for painted rocks hidden by others.');
INSERT INTO badge_optional_requirements VALUES(5011,395,8,'Host a rock painting party with your family, friends, and group.');
INSERT INTO badge_optional_requirements VALUES(5012,395,9,'Mark a map with places around the world that participate in rock hiding.');
INSERT INTO badge_optional_requirements VALUES(5013,395,10,'Earn the Kindness badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5014,395,11,'Research the best kind of paint to use on your rocks. You want your design to hold up in inclement weather.');
INSERT INTO badge_optional_requirements VALUES(5015,395,12,'Brainstorm at least 20 short inspirational sayings or quotes you can paint on a rock to brighten someone’s day.');
INSERT INTO badge_optional_requirements VALUES(5016,396,3,'Define the term “aerodynamics.”  Be sure to study the concepts of lift vs. gravity and drag vs. thrust.  In terms of aerodynamics, how is a kite more like an airplane than a bubble or a balloon?');
INSERT INTO badge_optional_requirements VALUES(5017,396,4,'Be able to identify the following parts of a kite: Tether Sail Spar Bridle Tail Spine Frame Flying Line Cover');
INSERT INTO badge_optional_requirements VALUES(5018,396,5,'Be able to identify the following types of kites: Flat kite Box kite Delta kite Soft kite Sled kite Diamond kite');
INSERT INTO badge_optional_requirements VALUES(5019,396,6,'Identify one type of stunt kite and one type of high altitude kite.  In both types, be able to label the three defining characteristics of a kite: a body designed to obtain lift from the wind, a tether to prevent the kite from blowing away, and a bridle with at least two strings to control the kite as it flies in the air.');
INSERT INTO badge_optional_requirements VALUES(5020,396,7,'Learn the ancient history of the kite, including the first written record of kite use in China around the year 200 B.C. during the Han Dynasty. How did General Han Hsin use the kite?  When were kites introduced into Japan and how were they initially used? How did their kites differ from Chinese kite designs? What other ancient cultures used kites and how were they used?');
INSERT INTO badge_optional_requirements VALUES(5021,396,8,'Make a homemade diamond kite.');
INSERT INTO badge_optional_requirements VALUES(5022,396,9,'Make a homemade box kite.');
INSERT INTO badge_optional_requirements VALUES(5023,396,10,'Make a homemade tetrahedral kite.');
INSERT INTO badge_optional_requirements VALUES(5024,396,11,'Take a field trip to a kite store or kite exhibit.');
INSERT INTO badge_optional_requirements VALUES(5025,396,12,'Try flying a kite of your own.');
INSERT INTO badge_optional_requirements VALUES(5026,396,13,'How has the use of kites changed since the popularization of the airplane?');
INSERT INTO badge_optional_requirements VALUES(5027,397,3,'Read, or have read to you, a book about knights, whether fictional or non-fictional.');
INSERT INTO badge_optional_requirements VALUES(5028,397,4,'Learn the steps a person had to go through to become a knight.');
INSERT INTO badge_optional_requirements VALUES(5029,397,5,'Compare and contrast knights with soldiers from other eras throughout history and up to modern times. How does their dress, weapons, etc. change through history? Make a list, diagram with pictures, or discuss orally, depending on your level.');
INSERT INTO badge_optional_requirements VALUES(5030,397,6,'Write your own short story about a quest a knight could go. Read it to a parent or friend. As an additional optional requirement, act it out as a skit or play with your family, friends, and group.');
INSERT INTO badge_optional_requirements VALUES(5031,397,7,'Research where knights lived. What were their living conditions like? How did that compare to how other people of that time period lived? How does it compare with how we live today?');
INSERT INTO badge_optional_requirements VALUES(5032,397,8,'Read or watch a movie about the legendary King Arthur and his Knights of the Round Table. Discuss it with your family, friends, and group.');
INSERT INTO badge_optional_requirements VALUES(5033,397,9,'Watch an age-appropriate movie or documentary based on knights.');
INSERT INTO badge_optional_requirements VALUES(5034,397,10,'Read or watch a movie about the legendary Robin Hood and King Richard the Lion Heart. Discuss with your family, friends, and group.');
INSERT INTO badge_optional_requirements VALUES(5035,397,11,'Knights learned how to joust as part of their training to become a knight. Hold a pretend jousting competition for fun. You can use pool noodles, sticks, etc.');
INSERT INTO badge_optional_requirements VALUES(5036,397,12,'Visit a museum that has a display dedicated to knights.');
INSERT INTO badge_optional_requirements VALUES(5037,397,13,'Visit one of the Medieval Times theaters.');
INSERT INTO badge_optional_requirements VALUES(5038,397,14,'Design and create your own medieval banner with colors and symbols of your choice.');
INSERT INTO badge_optional_requirements VALUES(5039,397,15,'Visit a Renaissance fair.');
INSERT INTO badge_optional_requirements VALUES(5040,397,16,'Pick a famous knight, real or fictional, and write a short essay on them. What are they most known for?');
INSERT INTO badge_optional_requirements VALUES(5041,397,17,'Learn about the Crusades or the Templars and write a brief essay on them.');
INSERT INTO badge_optional_requirements VALUES(5042,397,18,'Learn about the Codes of Chivalry and memorize a few of the lines to say aloud to your family, friends, and group.');
INSERT INTO badge_optional_requirements VALUES(5043,398,3,'Make a collage or scrapbook page of pictures of different knitted items.');
INSERT INTO badge_optional_requirements VALUES(5044,398,4,'Learn about different types of yarn that can be used for knitting eg; woolen, acrylic, bamboo, cotton, silk, etc.  Learn about the different weights of yarn eg; chunky, sport weight, worsted, double-knitting.   How are they different?   Find out which size needles you would use with these yarns.  Visit a yarn shop to feel and see these for yourself.  Which do you like best? Preschool: Learn about one type of yarn. Levels 1-2:Learn about three types of yarn. Levels 3-4: Learn about five types of yarn. Level 5: Learn about eight types of yarn.');
INSERT INTO badge_optional_requirements VALUES(5045,398,5,'Make a scarf for a teddy bear/doll by casting on 10 stitches and knitting in garter stitch until it is long enough for the toy.  Cast off the stitches and sew in the ends with a tapestry needle.');
INSERT INTO badge_optional_requirements VALUES(5046,398,6,'Find out about different ways to knit: these include knitting machines, French knitting/spool knitting looms and pole knitting.   How are they similar and how are they different?');
INSERT INTO badge_optional_requirements VALUES(5047,398,7,'Learn about the history of knitting and make a timeline of the key developments.  Find out what sorts of items were knitted in the past.');
INSERT INTO badge_optional_requirements VALUES(5048,398,8,'Visit the craft section of a bookstore, library or craft store and look at the knitting books.  Check the junior books section also as there are knitting books written for young people too.  Which books did you like best?  Do you feel the instructions in the books are easy to follow?');
INSERT INTO badge_optional_requirements VALUES(5049,398,9,'Learn how to knit with two colors of yarn: make a square in alternating rows of color.  Knit 36 garter stitch squares and join them together with overcast stitch or blanket stitch into a blanket for a baby.  Be creative: use a combination of plain colored squares and striped ones in your blanket.  Try different color combinations.');
INSERT INTO badge_optional_requirements VALUES(5050,398,10,'Learn two different styles of “rib” knitting ie; Fisherman’s rib, and learn how to cast of/bind-off rib-wise. Ribbing is often used for scarves because it looks good from both sides.   Choose one pattern of ribbing, cast on 50 stitches and make a simple scarf for yourself or a friend or relative.  You may add tassels to the ends of the scarf if you wish.');
INSERT INTO badge_optional_requirements VALUES(5051,398,11,'Learn to make eyelet holes in a row of knitting.  Make a simple item which has eyelet holes, such as an egg cosy or a bag with drawstring.');
INSERT INTO badge_optional_requirements VALUES(5052,398,12,'Make a book of sample squares of different knitting stitch patterns. Learn five new knitting stitch patterns and make a sample square of each pattern.  Examples of stitch patterns would be moss stitch, double moss stitch, broken garter stitch, and more. Attach each square to a piece of card and label each pattern.');
INSERT INTO badge_optional_requirements VALUES(5053,398,13,'Learn how knitting has developed over the years from a cottage industry to a major industrial clothing source. Investigate the history of knitting machines and give a report to your family, friends, and group on your findings.  What careers are available in the knitting industry?  What salary can you expect?  If possible, shadow someone who works in the knitting industry for a day.');
INSERT INTO badge_optional_requirements VALUES(5054,398,14,'Knit an item of clothing for yourself, such as a cardigan, vest, sweater, shawl.');
INSERT INTO badge_optional_requirements VALUES(5055,398,15,'Knit an item for your home, such as cushion, ice cream coozie, dish-cloth.');
INSERT INTO badge_optional_requirements VALUES(5056,398,16,'Earn the Advanced Knitting badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5057,399,3,'Learn at least one type of stopper knot and explain when it should be used.');
INSERT INTO badge_optional_requirements VALUES(5058,399,4,'Learn at least one type of hitch knot and explain when it should be used.');
INSERT INTO badge_optional_requirements VALUES(5059,399,5,'Learn at least one type of loop knot and explain when it should be used.');
INSERT INTO badge_optional_requirements VALUES(5060,399,6,'Learn at least one type of slip knot and explain when it should be used.');
INSERT INTO badge_optional_requirements VALUES(5061,399,7,'Learn at least one type of bend knot and explain when it should be used.');
INSERT INTO badge_optional_requirements VALUES(5062,399,8,'Know what each of the following terms mean: Bight Bitter End Loop Elbow Standing End Standing Part Turn Working End Working Part');
INSERT INTO badge_optional_requirements VALUES(5063,399,9,'Implement your knowledge of knots in everyday life in at least six things like, tying a boat up to a dock, tying a tarp down, tying up two ropes of different sizes, tying bait to a fishing line, etc.');
INSERT INTO badge_optional_requirements VALUES(5064,399,10,'Teach someone else a knot that you’ve learned from this badge.');
INSERT INTO badge_optional_requirements VALUES(5065,400,3,'Learn about the the three different types of string used in Korean Knot tying:  dongdahoegwangdahoegyeokdap or gyeolja How does the shape of the string effect the knot tied.');
INSERT INTO badge_optional_requirements VALUES(5066,400,4,'Learn about Hanbok, the traditional Korean clothing.  What role does Korean knots play in traditional Korean fashion.');
INSERT INTO badge_optional_requirements VALUES(5067,400,5,'What is the most usual type of material used to make Korean knots?  Why is this material used?');
INSERT INTO badge_optional_requirements VALUES(5068,400,6,'Name the 3 essential parts that make up a norigae.  Draw a diagram.');
INSERT INTO badge_optional_requirements VALUES(5069,400,7,'Use Korean knots as part of a community service project.  Examples may include making craft items for sale and donating the money, or teaching a class on Korean knot tying at your local library.');
INSERT INTO badge_optional_requirements VALUES(5070,400,8,'View an exhibit of Korean Knots either in person or online.');
INSERT INTO badge_optional_requirements VALUES(5071,400,9,'Learn about a career that involves Korean knot tying such as a fashion designer or historian.');
INSERT INTO badge_optional_requirements VALUES(5072,400,10,'There are more than 30 basic types of Korean knots as well as many variations of the basic types.  Make a picture chart of at least 20 different Korean knots.');
INSERT INTO badge_optional_requirements VALUES(5073,400,11,'Make a bracelet using Korean knots.');
INSERT INTO badge_optional_requirements VALUES(5074,400,12,'Make a necklace using Korean knots.');
INSERT INTO badge_optional_requirements VALUES(5075,400,13,'Make a zipper or cell phone charm using Korean knots.');
INSERT INTO badge_optional_requirements VALUES(5076,400,14,'Make a pair of earrings using Korean knots.');
INSERT INTO badge_optional_requirements VALUES(5077,401,3,'Find out the basic tools needed to make lace.');
INSERT INTO badge_optional_requirements VALUES(5078,401,4,'Learn the three basic types of pillows and how to choose your pillow based on the type of lace you are making.');
INSERT INTO badge_optional_requirements VALUES(5079,401,5,'Learn the types of spindles and how to choose which type to use based on the lace you are making.');
INSERT INTO badge_optional_requirements VALUES(5080,401,6,'Learn about the differences in pin sizes and how this affects your finished lace.');
INSERT INTO badge_optional_requirements VALUES(5081,401,7,'Learn about threads and why you should use certain fiber contents for best results.');
INSERT INTO badge_optional_requirements VALUES(5082,401,8,'Learn about patterns and be able to recognize at least five designs.');
INSERT INTO badge_optional_requirements VALUES(5083,401,9,'Learn the best way to prepare your paper pattern for lace-making. Why you should laminate your paper pattern?');
INSERT INTO badge_optional_requirements VALUES(5084,401,10,'Learn the two different movements to making lace.');
INSERT INTO badge_optional_requirements VALUES(5085,401,11,'Make a piece of lace and enter it in a fair or contest.');
INSERT INTO badge_optional_requirements VALUES(5086,401,12,'Participate in a service project that involves lace such as teaching others how to make lace or designing an exhibit for others to learn about lace.');
INSERT INTO badge_optional_requirements VALUES(5087,401,13,'Watch lace-making demonstrations.');
INSERT INTO badge_optional_requirements VALUES(5088,401,14,'Tour a lace factory.');
INSERT INTO badge_optional_requirements VALUES(5089,401,15,'Attend a meeting of a lace guild.');
INSERT INTO badge_optional_requirements VALUES(5090,401,16,'Create a piece of art using lace.');
INSERT INTO badge_optional_requirements VALUES(5091,401,17,'Try your hand at designing a lace pattern.');
INSERT INTO badge_optional_requirements VALUES(5092,402,3,'Invite a speaker to talk to your group about surveying.');
INSERT INTO badge_optional_requirements VALUES(5093,402,4,'Find out who were the first people that we have records of using triangulation? What did they use it for?');
INSERT INTO badge_optional_requirements VALUES(5094,402,5,'Look at some ancient and modern surveying equipment and compare how they are similar and how they are different.');
INSERT INTO badge_optional_requirements VALUES(5095,402,6,'What is metes and bounds? Why are metes and bounds descriptions no longer used?');
INSERT INTO badge_optional_requirements VALUES(5096,402,7,'Find simple ways on the internet (with a parent’s permission) or in a book to make a clinometer. Make one.');
INSERT INTO badge_optional_requirements VALUES(5097,402,8,'Look at some aerial photos from the internet (with a parent’s permission). How can you tell what time of day and what time of year the aerial photos were taken?');
INSERT INTO badge_optional_requirements VALUES(5098,402,9,'Look at some maps from our history. How do they compare to maps made today?');
INSERT INTO badge_optional_requirements VALUES(5099,402,10,'If possible compare a map from our history and a recent map of the same location. What has changed about the location (for example, what buildings and trees are still there or are no longer there)?');
INSERT INTO badge_optional_requirements VALUES(5100,402,11,'What small shapes are used to create all property shapes when surveying/map making?');
INSERT INTO badge_optional_requirements VALUES(5101,402,12,'What two measurements are needed to locate a point?');
INSERT INTO badge_optional_requirements VALUES(5102,402,13,'Find out which of our presidents worked as a surveyor? Where did he survey?');
INSERT INTO badge_optional_requirements VALUES(5103,402,14,'Learn about careers in surveying.');
INSERT INTO badge_optional_requirements VALUES(5104,403,3,'What is landscape cloth and why is it used? What are bio-degradable alternatives?');
INSERT INTO badge_optional_requirements VALUES(5105,403,4,'Learn to make compost and use it on your garden or lawn.');
INSERT INTO badge_optional_requirements VALUES(5106,403,5,'What are some invasive plants in your area that could be used in landscaping? What does that mean and why can they be a problem?');
INSERT INTO badge_optional_requirements VALUES(5107,403,6,'How should you care for perennials and annuals at the end of the season?');
INSERT INTO badge_optional_requirements VALUES(5108,403,7,'What are some animals that can harm landscaping and how can you protect trees and shrubs?');
INSERT INTO badge_optional_requirements VALUES(5109,403,8,'Visit a perennial garden or botanical garden. What are your favorite plants and why?');
INSERT INTO badge_optional_requirements VALUES(5110,403,9,'With a parent’s permission, learn how to mow your lawn.');
INSERT INTO badge_optional_requirements VALUES(5111,403,10,'Help an older person with their garden.');
INSERT INTO badge_optional_requirements VALUES(5112,403,11,'Learn how to prune trees. What time of year should this be done?');
INSERT INTO badge_optional_requirements VALUES(5113,403,12,'What does it mean to deadhead a plant? Why do gardeners do this?');
INSERT INTO badge_optional_requirements VALUES(5114,403,13,'Name three edible plants that can be used in landscaping.');
INSERT INTO badge_optional_requirements VALUES(5115,403,14,'What is permaculture? Learn three basic ideas for this concept.');
INSERT INTO badge_optional_requirements VALUES(5116,403,15,'Learn about various borders for perennial beds (wood, brick, stone, etc.)');
INSERT INTO badge_optional_requirements VALUES(5117,403,16,'What are some drought tolerant plants in your area? Why would you use them?');
INSERT INTO badge_optional_requirements VALUES(5118,403,17,'Learn how to divide perennials. When and how is it done? What are some plants that can be divided?');
INSERT INTO badge_optional_requirements VALUES(5119,403,18,'What are some animals and insects that benefit from flowering plants.');
INSERT INTO badge_optional_requirements VALUES(5120,403,19,'Find three perennial plants that are beautiful for their foliage, not necessarily their flowers.');
INSERT INTO badge_optional_requirements VALUES(5121,403,20,'Learn to plant bulbs. When should they be planted where you live?');
INSERT INTO badge_optional_requirements VALUES(5122,403,21,'Design landscaping for a house on paper and price it. Think about when things bloom and what color they bloom, also sun/shade requirements and the zone you live in.');
INSERT INTO badge_optional_requirements VALUES(5123,405,3,'Compare prices between buying a latch hook project kit vs. buying all of the materials separately.  Which is the best value for your money?');
INSERT INTO badge_optional_requirements VALUES(5124,405,4,'Find 3 things that you could make your latch hook project into.  Choose one and make it.');
INSERT INTO badge_optional_requirements VALUES(5125,405,5,'Demonstrate how to latch hook to someone else.');
INSERT INTO badge_optional_requirements VALUES(5126,405,6,'Visit a museum that has examples of rug hooked rugs.');
INSERT INTO badge_optional_requirements VALUES(5127,405,7,'Create a latch hook gift to give to someone or make latch hook craft projects to sell to raise money for a charity.');
INSERT INTO badge_optional_requirements VALUES(5128,405,8,'Look up pictures of latch hook on the internet or in books.  Find at least 15 different latch hook projects or patterns.  How do they differ in complexity?');
INSERT INTO badge_optional_requirements VALUES(5129,405,9,'Learn how to create a 3D feel to your latch hook project.');
INSERT INTO badge_optional_requirements VALUES(5130,405,10,'Research the different types of hoops and frames that are used for different sized latch hook project.  What are the differences between floor stands and table stands?');
INSERT INTO badge_optional_requirements VALUES(5131,405,11,'Make your own latch hook frame or stand.');
INSERT INTO badge_optional_requirements VALUES(5132,406,3,'Learn to make your own frothed milk using a mason jar. Pour milk into the Mason jar to about halfway, leaving space for it to double in volume. Secure the lid and shake vigorously for 20–30 seconds. Remove the lid and heat the milk froth in the microwave for 30–45 seconds.');
INSERT INTO badge_optional_requirements VALUES(5133,406,4,'Learn how to create a simple snowflake using syrup');
INSERT INTO badge_optional_requirements VALUES(5134,406,5,'Learn how to pour a heart.');
INSERT INTO badge_optional_requirements VALUES(5135,406,6,'Learn how to pour a swan.');
INSERT INTO badge_optional_requirements VALUES(5136,406,7,'Learn about coffee printers. How do they work? Why are some baristas upset at automating latte art?');
INSERT INTO badge_optional_requirements VALUES(5137,406,8,'Learn about a famous latte artist. What styles do they do? Where do they live? How old are they? How did they get started in latte art?');
INSERT INTO badge_optional_requirements VALUES(5138,406,9,'Find out how espresso is made.');
INSERT INTO badge_optional_requirements VALUES(5139,406,10,'Learn how to make at least 3 different espresso drinks that use milk foam and can have latte art on top.');
INSERT INTO badge_optional_requirements VALUES(5140,406,11,'Learn to pour a rosetta');
INSERT INTO badge_optional_requirements VALUES(5141,406,12,'Learn to pour a tulip.');
INSERT INTO badge_optional_requirements VALUES(5142,406,13,'Learn about different types of milk that can be used in latte art. What are the pros and cons of each?');
INSERT INTO badge_optional_requirements VALUES(5143,406,14,'Research different espresso makers and milk frothers for home use.  What are the price points?  What are the pros and cons of each machine?');
INSERT INTO badge_optional_requirements VALUES(5144,406,15,'Find out what the following latte art tools are and how they are used: stencils latte pens writing bottles powder shaker pitcher coffee spoons');
INSERT INTO badge_optional_requirements VALUES(5145,406,16,'Learn how to make a flower using syrup');
INSERT INTO badge_optional_requirements VALUES(5146,406,17,'Draw a latte picture using syrup');
INSERT INTO badge_optional_requirements VALUES(5147,406,18,'Learn how to make some 3D latte art using foam.');
INSERT INTO badge_optional_requirements VALUES(5148,406,19,'Find out what cold foam is and how it is used.');
INSERT INTO badge_optional_requirements VALUES(5149,406,20,'Learn about automatic milk foaming and dispensing systems.  What the advantages and disadvantages to automated verses foaming by hand?');
INSERT INTO badge_optional_requirements VALUES(5150,406,21,'What is the crema?  How does it effect latte art?');
INSERT INTO badge_optional_requirements VALUES(5151,406,22,'Learn about latte art competitions and view art produced by the winners.');
INSERT INTO badge_optional_requirements VALUES(5152,406,22,'Find out what a barista is.  If possible, meet one and watch them create some latte art.');
INSERT INTO badge_optional_requirements VALUES(5153,406,23,'Visit a coffee shop that creates latte art.  What types do they create? How long did it take the barista to learn the techniques?');
INSERT INTO badge_optional_requirements VALUES(5154,407,3,'Talk to an older person about how they used to clean their laundry. How is it different from today? How is it the same?');
INSERT INTO badge_optional_requirements VALUES(5155,407,4,'Learn about laundromat etiquette and be able to explain how being polite can help you and others around you. If possible, visit a laundromat.');
INSERT INTO badge_optional_requirements VALUES(5156,407,5,'What was a washerwoman? Find out what the life of a washerwoman was like. Would you like to have been a washerwoman?');
INSERT INTO badge_optional_requirements VALUES(5157,407,6,'Learn about how people in other countries do their laundry. For instance, in some countries the clothes are pounded on rocks to remove the dirt; in others the women take their laundry down to the hot springs and wash their clothes there.');
INSERT INTO badge_optional_requirements VALUES(5158,407,7,'Learn about how doing laundry has changed over the years. What was a washboard? What was soap often made out of? How did the invention of the washing machine and dryer impact the way in which laundry was done?');
INSERT INTO badge_optional_requirements VALUES(5159,407,8,'Find someone who does their laundry differently from the way in which you do yours, such as hanging it on the clothesline to dry instead of putting it in the clothes dryer. If possible, spend some time helping them to do their laundry. Ask why they decided to do it this way.');
INSERT INTO badge_optional_requirements VALUES(5160,407,9,'How are washing machines and tumble dryers made? Read a book, watch a video or go online (with your parent’s permission) and find out.');
INSERT INTO badge_optional_requirements VALUES(5161,407,10,'Make a list of all the things you can use to do your laundry, such as stain removal products, laundry bags for delicate items or clothes with hooks-and-eyes that might snag on other items, washing soap, laundry baskets for carrying clothes, etc.');
INSERT INTO badge_optional_requirements VALUES(5162,407,11,'Learn about different methods of drying clothes, such as drip-drying, flat drying, hanging to dry, and tumble-drying. Why must certain fabrics be dried in special ways?');
INSERT INTO badge_optional_requirements VALUES(5163,407,12,'What is the difference between soap and detergent? How is each made? Read a book, watch a video or go online (with your parent’s permission) and find out. How does soap help to clean clothes?');
INSERT INTO badge_optional_requirements VALUES(5164,408,3,'Visit one of the Laura Ingalls Wilder homes.');
INSERT INTO badge_optional_requirements VALUES(5165,408,4,'Cook and eat at least three things mentioned in one or more of the Little House books, such as pumpkin pie, fried fish, whole-wheat bread, pancakes, apple pie, etc.');
INSERT INTO badge_optional_requirements VALUES(5166,408,5,'Pa played the fiddle for dances at cornhuskings, barn-raisings, and other social get-togethers that combined work with fun and company.  Find recordings of at least three fiddle tunes that would have been popular at that time, such as Bile ‘Em Cabbage Down, Sally Goodin, Cotton-eyed Joe, or Old Joe Clark and listen to them. Which do you like best?');
INSERT INTO badge_optional_requirements VALUES(5167,408,6,'Learn about Laura’s family.  Read at least one of the books about any of the men or women in her family line: Charles (Laura’s Pa), Charlotte (Laura’s grandmother), Caroline (Laura’s Ma), or Rose (Laura’s daughter).');
INSERT INTO badge_optional_requirements VALUES(5168,408,7,'Square dancing would have been foremost at the dances for which Pa played his fiddle.  Learn to square dance. Square dance calls have changed over the years. Find a recording of calls from at least 50 years ago.  How many can you recognize?');
INSERT INTO badge_optional_requirements VALUES(5169,408,8,'Railroads were being built all across America during Laura’s life.  Find out about how railroads linked the West with the East, and how they were built.  What were the tarriers?');
INSERT INTO badge_optional_requirements VALUES(5170,408,9,'Read all nine of the Little House books in order. Which is your favorite?');
INSERT INTO badge_optional_requirements VALUES(5171,408,10,'Learn about the one-room schoolhouses, such as Laura and her sisters would have attended.  Look as pictures or actual copies of the types of schoolbooks and materials that were in use at that time, such as the McGuffey Readers, slates and slate pencils, etc. How do they compare to the materials you have used in school?');
INSERT INTO badge_optional_requirements VALUES(5172,408,11,'The Ingalls family traveled across America in a covered wagon.  Look at pictures of covered wagons and find out what a wagon train was.  Draw a picture of a covered wagon.  Where did the wagon trains start and how far did they go?  Why were wagon trains popular?');
INSERT INTO badge_optional_requirements VALUES(5173,408,12,'Learn about the different sorts of animals which Pa would have hunted for meat or skins, such as muskrat, mink, deer, bear, antelope, etc.  Are these animals still wild in America today?  Can you still hunt them?');
INSERT INTO badge_optional_requirements VALUES(5174,408,13,'Make something mentioned in one of the Little House books, such as paper dolls, a rag doll, or a sled.');
INSERT INTO badge_optional_requirements VALUES(5175,408,14,'Read a biography of Laura Ingalls Wilder.  How does it differ from her own books?');
INSERT INTO badge_optional_requirements VALUES(5176,408,15,'At home or at Sunday School Laura and her sisters learned Bible verses and recited them to Ma or to their Sunday School teacher. Memorize some of your favorite verses. Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(5177,408,16,'Singing was a popular way of relaxing for Laura and her family. In the evenings Pa would play his fiddle, and when Laura grew up she and Almanzo went to a singing school.  Find at least five different songs that are mentioned in the Little House books and learn to sing at least one of them.  Examples might include: Buy a Broom, Wait for the Wagon, Buffalo Gals, Rock Me to Sleep, There is a Happy Land, or Pop Goes the Weasel.');
INSERT INTO badge_optional_requirements VALUES(5178,408,17,'Sewing was an important skill for Ma and for other prairie women.  Learn to sew a simple running stitch and anchor your thread with a double stitch at both ends.  Sew something simple by hand, such as a handkerchief, and give it to someone.');
INSERT INTO badge_optional_requirements VALUES(5179,408,18,'Earn the Little House on the Prairie badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5180,409,3,'Learn about the history of leather working.');
INSERT INTO badge_optional_requirements VALUES(5181,409,4,'Visit a museum, exhibit, or private collection of leather items throughout history.  How was leather used for household items, musical instruments, or articles of clothing?');
INSERT INTO badge_optional_requirements VALUES(5182,409,5,'Level 2 and Above Only: With an adult’s supervision, carve a piece of leather for a wallet, belt, purse, book cover, bookmark, or other item.');
INSERT INTO badge_optional_requirements VALUES(5183,409,6,'Learn how to clean, preserve, and polish articles made of leather.');
INSERT INTO badge_optional_requirements VALUES(5184,409,7,'Make two different useful articles by braiding leather.');
INSERT INTO badge_optional_requirements VALUES(5185,409,8,'Learn about careers in leather working.  What type of education do you need?  What type of pay could you expect?  Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(5186,409,9,'Participate in a community service project that involves leather working. Examples might include teaching younger kids how to stamp leather, making leather crafts to give away or sell for charity, etc.');
INSERT INTO badge_optional_requirements VALUES(5187,409,10,'Visit a leather goods store.  What type of items do they sell?  How many types of leather can you find?  What is your favorite item and why?  What do these items sell for?  Why do you think they are so expensive?');
INSERT INTO badge_optional_requirements VALUES(5188,410,3,'Play a game that teaches and re-enforces the Leave No Trace Principles.');
INSERT INTO badge_optional_requirements VALUES(5189,410,4,'Levels 3-5 Only: Teach the Leave No Trace principles to a group of younger children.');
INSERT INTO badge_optional_requirements VALUES(5190,410,5,'Peg out a 1 yard x 1 yard (3 ft x 3 ft) square in a patch of nature. Focus on all the wildlife that is located inside the square. Discuss how walking on this square, leaving trash on it, etc. would damage what is in it.');
INSERT INTO badge_optional_requirements VALUES(5191,410,6,'Understand that Leave No Trace also includes cleaning up after others. Participate in a trash clean up of your favorite hiking trail or park.');
INSERT INTO badge_optional_requirements VALUES(5192,410,7,'Participate in a Leave No Trace-related service project that reduces or rehabilitates recreational impacts. Discuss with your family, friends, or group which recreational impacts were involved with the project.');
INSERT INTO badge_optional_requirements VALUES(5193,410,8,'Go on a Leave No Trace scavenger hunt and try to find examples of violations of the Leave No Trace principles. Be able to explain which principle is being violated and why some violations cannot be fixed except over time.');
INSERT INTO badge_optional_requirements VALUES(5194,410,9,'When respecting wildlife, show that you understand the following guidelines and be able to explain to an adult why each is important. Don’t feed the wildlife. Stay a respectful distance away. If an animal is changing its behavior you are too close. Store food and trash securely. Control pets at all times. Avoid wildlife during sensitive times including mating, nesting, raising young or winter.');
INSERT INTO badge_optional_requirements VALUES(5195,410,10,'Create posters, flyers, or booklets to teach others the Leave No Trace principles and place them in useful locations (such as park bulletin boards or at park information centers) with permission.');
INSERT INTO badge_optional_requirements VALUES(5196,410,11,'Think of one of your favorite outdoor places and what it means to you. What if your favorite place was ruined? In order to have outdoor ethics, people have to have that connection to nature. Write an essay about the importance of connecting with nature and of respecting your favorite outdoor place in particular.');
INSERT INTO badge_optional_requirements VALUES(5197,410,12,'Earn the Backyard Camping badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5198,410,13,'Earn the Camping badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5199,410,14,'Earn the Hiking badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5200,411,3,'Visit a place connected with your chosen legend.');
INSERT INTO badge_optional_requirements VALUES(5201,411,4,'Earn a badge at your level that relates to your chosen legend. For instance, for either Robin Hood or William Tell, you could earn the Archery badge.');
INSERT INTO badge_optional_requirements VALUES(5202,411,5,'Watch an age-appropriate film of/about your chosen legend, or a person in it.');
INSERT INTO badge_optional_requirements VALUES(5203,411,6,'Read a nonfiction book about your chosen legend.');
INSERT INTO badge_optional_requirements VALUES(5204,411,7,'Earn the Mythology or Mythological Creatures badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5205,411,8,'Read an age-appropriate fiction book about characters from your chosen legend.');
INSERT INTO badge_optional_requirements VALUES(5206,411,9,'Create a costume or art project that represents your chosen legend.');
INSERT INTO badge_optional_requirements VALUES(5207,411,10,'Learn a skill from your chosen legend.');
INSERT INTO badge_optional_requirements VALUES(5208,411,11,'Make a timeline of at least 10 events in the development of your chosen legend.');
INSERT INTO badge_optional_requirements VALUES(5209,411,12,'What is an “urban legend”? Read at least three urban legends. How do they compare to your legend?');
INSERT INTO badge_optional_requirements VALUES(5210,411,13,'Write your own legend.');
INSERT INTO badge_optional_requirements VALUES(5211,411,14,'Earn the Historic Era badge for the era in which your legend takes place.');
INSERT INTO badge_optional_requirements VALUES(5212,411,15,'Learn how your chosen legend has developed over time.');
INSERT INTO badge_optional_requirements VALUES(5213,411,16,'Watch an age-appropriate documentary about your chosen legend.');
INSERT INTO badge_optional_requirements VALUES(5214,411,17,'Read a poem about your chosen legend.');
INSERT INTO badge_optional_requirements VALUES(5215,411,18,'Write an acrostic of your chosen legend.');
INSERT INTO badge_optional_requirements VALUES(5216,411,19,'Be able to name at least five of the characters in your chosen legend. What part did each of them play in your chosen legend?');
INSERT INTO badge_optional_requirements VALUES(5217,412,3,'Visit LEGOLAND or a Lego exhibit.');
INSERT INTO badge_optional_requirements VALUES(5218,412,4,'Find out what careers there are with Lego.  What type of education might you need for one of these jobs?  What type of salary could you expect?  Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(5219,412,5,'Create something that uses Lego gears and axles. Understand how the gears fit together to make things move. What is the purpose of the axle?');
INSERT INTO badge_optional_requirements VALUES(5220,412,6,'Create something that uses a Lego pulley.');
INSERT INTO badge_optional_requirements VALUES(5221,412,7,'Use Legos to help you learn about a subject in school. For example Preschoolers and Level 1 might make a Lego car and learn about speed based on the angle of a ramp, or you may use  them to learn how to add, subtract, or count by 10’s. Level 2 might make a Lego car and learn about speed based on the angle of a ramp, and use them to learn how to multiply, divide, or deal with fractions.  Levels 3-5 might make a Lego model of DNA or a model of a famous building.');
INSERT INTO badge_optional_requirements VALUES(5222,412,8,'Subscribe to the Lego magazine (or borrow one) and read through it.');
INSERT INTO badge_optional_requirements VALUES(5223,412,9,'Participate in a Lego Contest or Competition such as a Lego Education Competition, or a First Lego League Competition.');
INSERT INTO badge_optional_requirements VALUES(5224,412,10,'Participate in a Lego club.');
INSERT INTO badge_optional_requirements VALUES(5225,412,11,'Find out where at least 10 Lego stores are located and find them on a map. Where is the store closest to you?  How many countries have Lego stores?  How much money did Lego make last year?');
INSERT INTO badge_optional_requirements VALUES(5226,412,12,'Find out what a Lego Ambassador is. What activities do they do? How do you become one?');
INSERT INTO badge_optional_requirements VALUES(5227,412,13,'Create something using Lego motors or robotics.');
INSERT INTO badge_optional_requirements VALUES(5228,412,14,'Create a Lego minifigure movie.');
INSERT INTO badge_optional_requirements VALUES(5229,412,15,'Find out what jobs are available with Lego.');
INSERT INTO badge_optional_requirements VALUES(5230,412,16,'Hold a Lego drive to collect Legos to donate to your local school, or come up with another Lego oriented service project.');
INSERT INTO badge_optional_requirements VALUES(5231,412,17,'With a parent’s permission, play a Lego videogame. How does it compare to the real-life bricks?');
INSERT INTO badge_optional_requirements VALUES(5232,412,18,'With a parent’s permission, watch a Lego movie. How does it compare to the real-life bricks? How much money did this movie make in the box office?');
INSERT INTO badge_optional_requirements VALUES(5233,413,3,'Level 2 and Up: With an adult’s help, carve your own rubber stamp.');
INSERT INTO badge_optional_requirements VALUES(5234,413,4,'Learn the history of letterboxing.');
INSERT INTO badge_optional_requirements VALUES(5235,413,5,'Create your own letterbox and hide it. Either register your letterbox online for others (if a parent is willing to monitor it for at least 3 months), or see if a friend can find it using the clues.');
INSERT INTO badge_optional_requirements VALUES(5236,413,6,'Learn how to read a G.P.S. system and follow it to find specific coordinates.');
INSERT INTO badge_optional_requirements VALUES(5237,413,7,'In letterboxing terms , what is a hitch hiker,cootie, muggle and SPOR?');
INSERT INTO badge_optional_requirements VALUES(5238,413,8,'Find the 10 closest letterboxes to your house (or a particular point of interest if you are away from home).');
INSERT INTO badge_optional_requirements VALUES(5239,413,9,'Teach younger children about letterboxing.');
INSERT INTO badge_optional_requirements VALUES(5240,413,10,'Discuss first aid and prevention for the types of injuries or illnesses that could occur while participating in letterboxing activities, including cuts, scrapes, snakebite, insect stings, tick bites, exposure to poisonous plants, heat and cold reactions (sunburn, heatstroke, heat exhaustion, hypothermia), and dehydration.');
INSERT INTO badge_optional_requirements VALUES(5241,413,11,'Introduce a friend to letterboxing and take them out letterboxing.');
INSERT INTO badge_optional_requirements VALUES(5242,413,12,'Learn about different ways of stamping. Try stamp pads and stamp markers. Practice stamping some different types of stamps.');
INSERT INTO badge_optional_requirements VALUES(5243,413,13,'Choose or create your own signature stamp for your letterboxing adventures.');
INSERT INTO badge_optional_requirements VALUES(5244,414,3,'Earn the Communications badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5245,414,4,'Read a selection of letters written by a historical figure such as Thomas Jefferson or John Adams. What do you find most interesting in them?');
INSERT INTO badge_optional_requirements VALUES(5246,414,5,'Earn the Calligraphy badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5247,414,6,'Why is good spelling important in letter writing? Earn the Spelling badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5248,414,7,'Earn the Writing badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5249,414,8,'Read a book of fiction about writing letters. What important lesson does it teach about writing thank you letters?');
INSERT INTO badge_optional_requirements VALUES(5250,414,9,'Learn about the different materials used for writing in days gone by, such as papyrus scrolls, quill pens, fountain pens or clay tablets. How did the invention of the ballpoint pen affect the way we write letters today? Tell your family, friends, and group what you learned.');
INSERT INTO badge_optional_requirements VALUES(5251,414,10,'Typing is a very useful skill, and is used by thousands of people every day. Learn how to type at a reasonable degree of speed and accuracy for your age. Level 3 and Up: learn to touch type.');
INSERT INTO badge_optional_requirements VALUES(5252,414,11,'Learn about different styles of handwriting, such as Spencerian penmanship, copperplate writing, or Italic handwriting. Copy a quotation, bible verse, or adage written in one of these styles of handwriting. Is it harder than it looks?');
INSERT INTO badge_optional_requirements VALUES(5253,414,12,'When the typewriter was invented, no one wanted it. Research the history of the typewriter and learn why this was so. What was done to make it more marketable?  What was the result?');
INSERT INTO badge_optional_requirements VALUES(5254,414,13,'Read a book, watch a video, or go online (with your parent’s permission) to find out how paper is made. If possible, make a sheet of handmade paper.');
INSERT INTO badge_optional_requirements VALUES(5255,414,14,'Find out how ink is made. Learn how to make your own ink from berry juice, water and soot, etc.');
INSERT INTO badge_optional_requirements VALUES(5256,414,15,'Write a letter to someone of special significance, such as someone who is sick or a soldier. How do you think your letter might cheer them?');
INSERT INTO badge_optional_requirements VALUES(5257,414,16,'Before more modern inventions such as the internet, the telegraph, the telephone, etc., the main form of communication between people living at a distance was written letters. Learn about the different ways letters traveled in the old days, and how long a letter could take to arrive across the country, such as from San Francisco to New York, or across the ocean, such as from the United States to England.');
INSERT INTO badge_optional_requirements VALUES(5258,415,3,'How does your library get new books? Who funds the library? Do they ever do fundraisers or book sales? Are there organizations that support libraries?');
INSERT INTO badge_optional_requirements VALUES(5259,415,4,'Take a library tour. Learn the history of your library.');
INSERT INTO badge_optional_requirements VALUES(5260,415,5,'Go through books you have at home that you no longer read and donate them to a local library.');
INSERT INTO badge_optional_requirements VALUES(5261,415,6,'Volunteer at your local library.');
INSERT INTO badge_optional_requirements VALUES(5262,415,7,'Help put on a story hour for your local library.');
INSERT INTO badge_optional_requirements VALUES(5263,415,8,'Check out at least 3 non-fiction books on a subject that interests you.');
INSERT INTO badge_optional_requirements VALUES(5264,415,9,'Use the library to find information on something you are studying for school.');
INSERT INTO badge_optional_requirements VALUES(5265,415,10,'What is censorship? Discuss the pros and cons of censorship within a library setting with a parent or other adult. When is censorship appropriate? When is it not?');
INSERT INTO badge_optional_requirements VALUES(5266,415,11,'Why are libraries important? How can a library help its community? What is “social infrastructure” and why is a library often considered one?');
INSERT INTO badge_optional_requirements VALUES(5267,415,12,'Join a reading program or club.');
INSERT INTO badge_optional_requirements VALUES(5268,415,12,'Learn the history of libraries and create a timeline with at least 10 events.');
INSERT INTO badge_optional_requirements VALUES(5269,415,13,'Learn about at least five libraries around the world, such as the Trinity College Library in Dublin or the British Library in London.');
INSERT INTO badge_optional_requirements VALUES(5270,415,14,'Learn about the world’s largest library. How many books does it have? How large is the building? What special programs or events does it have?');
INSERT INTO badge_optional_requirements VALUES(5271,415,15,'Learn about organizations and charities who are fighting to bring books and libraries to impoverished communities. How can you help?');
INSERT INTO badge_optional_requirements VALUES(5272,415,16,'Learn about previous ways books have been organized in libraries. For instance, what is a card catalog and why is it no longer mainstream? How did it work?');
INSERT INTO badge_optional_requirements VALUES(5273,415,17,'Learn about careers in a library or other literature-focused areas, such as a conservator or author. What type of education do you need?  What type of pay could you expect?  Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(5274,416,3,'Learn about how light and shadow is used in artwork.   Use light and shadow in either a drawing or a painting.');
INSERT INTO badge_optional_requirements VALUES(5275,416,4,'What happens to the shadows of different objects when you tilt the light source or change its brightness? What happens to the shadow if the light source is dim?');
INSERT INTO badge_optional_requirements VALUES(5276,416,5,'Create an educational presentation about light and shadow and show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(5277,416,6,'Explore reflections and shadows using various reflective materials, like old CD’s or mirrors.');
INSERT INTO badge_optional_requirements VALUES(5278,416,7,'How is light reflected? Distorted?');
INSERT INTO badge_optional_requirements VALUES(5279,416,8,'With a parent’s permission, watch an educational video about lights and shadows');
INSERT INTO badge_optional_requirements VALUES(5280,416,9,'How does light travel?  How fast does it travel?');
INSERT INTO badge_optional_requirements VALUES(5281,416,10,'How do lights and shadows play into Groundhog Day on Feb. 2?  Learn the History of Groundhog day.');
INSERT INTO badge_optional_requirements VALUES(5282,416,11,'Trace your shadow (stand in a lighted area/outside, near a large piece of paper ~ trace what you see).');
INSERT INTO badge_optional_requirements VALUES(5283,416,12,'Understand the difference between natural light and artificial light.  How does things like the weather or time of day affect natural light?  How can things like different types of light bulbs, or dimmer switches affect artificial light?  How does the type of light affect shadows?');
INSERT INTO badge_optional_requirements VALUES(5284,416,13,'Read a book about shadows.');
INSERT INTO badge_optional_requirements VALUES(5285,416,14,'Make a personal shadow clock.');
INSERT INTO badge_optional_requirements VALUES(5286,416,15,'Learn about a career that has something to do with light or shadows.  Careers like artists, photographers, home designers, scientists, etc.  How do they use light in their career? What type of money do they make?  What type of hours do they work?');
INSERT INTO badge_optional_requirements VALUES(5287,416,16,'Participate in a community service project that has something to do with light or shadow.  Examples might be to host a free photo booth for a community event, or hold a light bulb recycling event.');
INSERT INTO badge_optional_requirements VALUES(5288,416,17,'Learn how a sundial works and find out what the largest sundial in the world is.  Try making your own sundial.');
INSERT INTO badge_optional_requirements VALUES(5289,416,18,'Learn how the color of light can change what colors shadows are.');
INSERT INTO badge_optional_requirements VALUES(5290,417,3,'Make your own lip balm. This requirement does not count towards optional requirements 4 or 5.');
INSERT INTO badge_optional_requirements VALUES(5291,417,4,'Make a lip balm using natural dyes (beet juice, grape juice, etc.).');
INSERT INTO badge_optional_requirements VALUES(5292,417,5,'Make your own lip with essential oils.');
INSERT INTO badge_optional_requirements VALUES(5293,417,6,'Learn what was the first flavoring of lip balm and what brand made it.');
INSERT INTO badge_optional_requirements VALUES(5294,417,7,'Make a list of at least 15 different lip balm companies.');
INSERT INTO badge_optional_requirements VALUES(5295,417,8,'Learn about a career in the lip balm industry.');
INSERT INTO badge_optional_requirements VALUES(5296,417,9,'Learn about lip balms in other countries.  What flavors do they prefer?  Do they make it differently?');
INSERT INTO badge_optional_requirements VALUES(5297,417,10,'Create a craft using lip balm such as decorating one with patterned tape or gems.');
INSERT INTO badge_optional_requirements VALUES(5298,417,11,'Design your own lip balm.  What color and flavor would it be?  What health properties would it have?  What would the container look like?');
INSERT INTO badge_optional_requirements VALUES(5299,417,12,'Participate in a community service project that involves lip balm such as donating toiletry bags to a local women’s shelter.');
INSERT INTO badge_optional_requirements VALUES(5300,417,13,'Conduct a survey of at least 20 people.  What is their favorite brand of lip balm?  What is their favorite flavor?  What do they look for in a lip balm?  How often do they use it?  Share your findings with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(5301,417,14,'Conduct a price comparison of at least 10 different lip balms.');
INSERT INTO badge_optional_requirements VALUES(5302,418,3,'What are some uses for liquid nitrogen? Preschool: List one use. Levels 1-2: List three uses. Levels 3-4: List five. Level 5: List eight.');
INSERT INTO badge_optional_requirements VALUES(5303,418,4,'If you have an accident while handling liquid nitrogen, what are some common first aid treatments you should know?');
INSERT INTO badge_optional_requirements VALUES(5304,418,5,'With adult supervision, conduct a science experiment utilizing liquid nitrogen.');
INSERT INTO badge_optional_requirements VALUES(5305,418,6,'Watch a demonstration of how liquid nitrogen is used.');
INSERT INTO badge_optional_requirements VALUES(5306,418,7,'Learn about common careers where liquid nitrogen might be used. Learn about the type of education you might need for these careers.');
INSERT INTO badge_optional_requirements VALUES(5307,418,8,'Learn about what happens to liquid nitrogen when the temperature changes. What happens to the molecules of nitrogen that make it change from one state of matter to another?');
INSERT INTO badge_optional_requirements VALUES(5308,418,9,'Learn the history of how liquid nitrogen has been used in the past.');
INSERT INTO badge_optional_requirements VALUES(5309,418,10,'Learn about the chemical nature of nitrogen. Where can it be found on the periodic table? What is its symbol? It’s atomic number? What does the atomic number mean?');
INSERT INTO badge_optional_requirements VALUES(5310,419,3,'Make a poster to show off one of the characters’ heroic traits.');
INSERT INTO badge_optional_requirements VALUES(5311,419,4,'Do a craft inspired by the character. For example: create an Eiffel Tower sculpture for Madeline, a cipher book for Enola Holmes, or Howl’s Moving Castle out of clay.');
INSERT INTO badge_optional_requirements VALUES(5312,419,5,'Plan an event inspired by a character. For example, a Fancy Nancy tea party, a Little Women Maypole dance,  a sword fight from The Song of the Lioness, or an archery contest inspired by Katniss Everdeen.');
INSERT INTO badge_optional_requirements VALUES(5313,419,6,'Write a short about a character in one of the books you read.');
INSERT INTO badge_optional_requirements VALUES(5314,419,7,'Earn the Courage badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5315,419,8,'Put together a book club to read and discuss a book with a literary heroine.');
INSERT INTO badge_optional_requirements VALUES(5316,419,9,'Write a poem about your heroine.');
INSERT INTO badge_optional_requirements VALUES(5317,419,10,'Do something that your heroine did in her book. For example Anne from Anne of Green Gables learned to make preserves. Nancy Drew decoded codes.  Jo from Little Women wrote stories and did dramatic plays. If you are feeling particularly adventurous, you could even learn to weld like Jazz in Artemis.');
INSERT INTO badge_optional_requirements VALUES(5318,419,11,'Write your own story with a heroine as the main character.');
INSERT INTO badge_optional_requirements VALUES(5319,420,3,'Learn to identify bird songs. Preschool: Memorize one bird song. Levels 1-2: Memorize three bird songs. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(5320,420,4,'Walk outside and look around you for 10 minutes and write down all the sounds you hear. Now close your eyes. Do you hear more sounds than you did with your eyes open? Write down the new sounds you heard.');
INSERT INTO badge_optional_requirements VALUES(5321,420,5,'Sit in your home and look around you for 10 minutes and write down all the sounds you hear. Now close your eyes. Do you hear more sounds than you did with your eyes open? Write down the new sounds you heard.');
INSERT INTO badge_optional_requirements VALUES(5322,420,6,'Learn 12 basic phrases in a foreign language with the use of a learning program that uses an audio aid as a companion to a book. Is it easier for you to learn the language when you hear it, as opposed to read it?');
INSERT INTO badge_optional_requirements VALUES(5323,420,7,'Attend a classical music concert/opera/musical theater performance where the skill of good, attentive listening is required.');
INSERT INTO badge_optional_requirements VALUES(5324,420,8,'Attend a stage play or literary reading. Afterwards write down the key points as you remember them. Then read the play or the literary work. How much did you absorb through listening?');
INSERT INTO badge_optional_requirements VALUES(5325,420,9,'Watch your favorite film all the way through. At the most emotional parts, such as high drama, comic moments, tense action scenes, mute the sound. What sort of music is being used in these sections? How does the music affect your emotions?');
INSERT INTO badge_optional_requirements VALUES(5326,420,10,'Listen to a news program on the radio or a podcast. How much of what is said is filling the air time and how much is conveying information? Compare it with a news program on television. Which is easier for you to follow? Which has more filler material the radio or the television? How much do you feel is fact and how much is opinion?');
INSERT INTO badge_optional_requirements VALUES(5327,420,11,'Watch a television program with the sound muted, but the closed captioning on. What have you noticed? Is it easier/harder for you to follow along?');
INSERT INTO badge_optional_requirements VALUES(5328,420,12,'With a parent’s permission, watch an age-appropriate comedic show. Then re-watch the show with the sound switched off. Did the action make you laugh (physical comedy), the language usage (wit/pun/etc), or the taped laughter on the sound track? How funny was it without the sound?');
INSERT INTO badge_optional_requirements VALUES(5329,420,13,'Research careers that require good listening skills, such as air traffic-controllers, emergency dispatch secretary, interpreter, or court reporter. What training is required? What sort of salary can one expect in these positions? If possible shadow a person in one of these positions for a week.');
INSERT INTO badge_optional_requirements VALUES(5330,420,14,'Advertisers know that people retain the information they are presented with first and last. The information in the middle is usually lost fairly soon after hearing. Watch or listen to advertisements for 6 different pharmaceutical products. What information is included at the beginning and ending sections? What is in the middle section? What is the dispersal of positive and negative information? How do you feel this information is structured to sell the product?');
INSERT INTO badge_optional_requirements VALUES(5331,420,15,'Listen to the beat/tempo of various types of music, such classical waltz, jazz, marching band, ballad, etc. Write down how the beat makes you feel. Investigate how the beat of music affects the body physiologically.');
INSERT INTO badge_optional_requirements VALUES(5332,421,3,'Visit the Laura Ingalls Wilder home in Mansfield, Missouri.');
INSERT INTO badge_optional_requirements VALUES(5333,421,4,'Visit at least one historical site where Laura’s books took place.');
INSERT INTO badge_optional_requirements VALUES(5334,421,5,'Learn how to sew a sunbonnet or other piece of pioneer clothing.');
INSERT INTO badge_optional_requirements VALUES(5335,421,6,'Create a timeline of world events that took place during Laura Ingalls Wilder’s lifetime.');
INSERT INTO badge_optional_requirements VALUES(5336,421,7,'Learn to make a corn husk doll or other pioneer toy.');
INSERT INTO badge_optional_requirements VALUES(5337,421,8,'Learn to cook a pioneer meal or try at least 3 recipes that from the 1870’s-1890’s.');
INSERT INTO badge_optional_requirements VALUES(5338,421,9,'Learn to churn your own butter.  Put heavy cream in a baby food jar with a clean, glass marble.  Put on the lid and shake until you have butter.  Pour off the whey and salt to taste if you desire.');
INSERT INTO badge_optional_requirements VALUES(5339,421,10,'Learn to make your own soap.');
INSERT INTO badge_optional_requirements VALUES(5340,421,11,'Learn to make your own candles.');
INSERT INTO badge_optional_requirements VALUES(5341,421,12,'With parent permission, watch at least 10 episodes of the Little House on the Prairie television program.  How does the program differ from the book, On the Banks of Plum Creek, that it is based on?');
INSERT INTO badge_optional_requirements VALUES(5342,421,13,'Learn at least three songs from the Little House on the Prairie books.');
INSERT INTO badge_optional_requirements VALUES(5343,421,14,'Learn about at least three wild animals that the Ingalls encountered.  Learn what their food is, who their predators are, distinguishing characteristics, sounds they make, and be able to identify their tracks.');
INSERT INTO badge_optional_requirements VALUES(5344,421,15,'Wear a pioneer/ late 1800’s outfit to a party, play, or reading festival that includes activities about the Little House books.');
INSERT INTO badge_optional_requirements VALUES(5345,421,16,'Learn to play part of a song (or a whole song) on the fiddle.');
INSERT INTO badge_optional_requirements VALUES(5346,421,17,'Do a craft that Laura or her family did such as making red striped wrapping paper or cutting designs on the edges of shelf paper.');
INSERT INTO badge_optional_requirements VALUES(5347,421,18,'Make a miniature log cabin or sod house or spend a day helping someone build a regular-size one.');
INSERT INTO badge_optional_requirements VALUES(5348,421,19,'Find out about the different types of apparatus for smoking meat.  Smoke some meat and eat some of it.');
INSERT INTO badge_optional_requirements VALUES(5349,422,3,'Create a timeline of world events that took place during Little Women’s time frame, or during Louisa May Alcott’s lifetime.');
INSERT INTO badge_optional_requirements VALUES(5350,422,5,'Watch one of the films produced of the book.  Describe how it differs from the book.');
INSERT INTO badge_optional_requirements VALUES(5351,422,6,'Create a craft mentioned in one of the books, or that girls would have done during that time frame.');
INSERT INTO badge_optional_requirements VALUES(5352,422,7,'Visit Orchard House, Concord, Massachusetts, either in person or virtually (with a parent’s permission).');
INSERT INTO badge_optional_requirements VALUES(5353,422,8,'Attend a Louisa May Alcott’s historical celebration or learn about what these celebrations consist of if you cannot attend one.');
INSERT INTO badge_optional_requirements VALUES(5354,422,9,'Learn about the clothing of the era. Why was it important for Jo to have her gloves for the dance? Why was the expected clothing expensive? View pieces of clothing from this era either through pictures or through an exhibit.');
INSERT INTO badge_optional_requirements VALUES(5355,422,10,'Recreate a scene from the book.  You can act it out, draw a picture of it, create a diorama, etc.');
INSERT INTO badge_optional_requirements VALUES(5356,422,11,'Cook/prepare three recipes mentioned in the books or that would have been served in that time period in that part of the country');
INSERT INTO badge_optional_requirements VALUES(5357,422,12,'Learn to play a game the Little Women would have played.');
INSERT INTO badge_optional_requirements VALUES(5358,423,3,'Visit your local farmers market and talk to a vendor about what they grow.');
INSERT INTO badge_optional_requirements VALUES(5359,423,4,'Visit a local farm stand. Are they open year round? What do they specialize in selling?');
INSERT INTO badge_optional_requirements VALUES(5360,423,5,'Visit a local/non-chain store. Check out your local downtown. What types of businesses are there?');
INSERT INTO badge_optional_requirements VALUES(5361,423,6,'Eat a locally-sourced meal.');
INSERT INTO badge_optional_requirements VALUES(5362,423,7,'Make (or buy) a unique or traditional food from your area.');
INSERT INTO badge_optional_requirements VALUES(5363,423,8,'Go to a local craft fair and talk to a vendor about what they make. How did they get started?');
INSERT INTO badge_optional_requirements VALUES(5364,423,9,'Learn about Slow Food, Farm to School, or similar programs/movements.');
INSERT INTO badge_optional_requirements VALUES(5365,423,10,'Learn about a local artist and see their work.');
INSERT INTO badge_optional_requirements VALUES(5366,423,11,'Listen to a local musician.');
INSERT INTO badge_optional_requirements VALUES(5367,423,12,'Take part in a community garden project.');
INSERT INTO badge_optional_requirements VALUES(5368,423,13,'Learn about local currency.');
INSERT INTO badge_optional_requirements VALUES(5369,423,14,'Hear a local author speak or read one of their books.');
INSERT INTO badge_optional_requirements VALUES(5370,423,15,'Read a book about food sourcing.');
INSERT INTO badge_optional_requirements VALUES(5371,423,16,'Make a list of local/non-commercial entertainment ideas for your area. What local grassroots events or festivals does your area have?');
INSERT INTO badge_optional_requirements VALUES(5372,423,17,'What are the benefits of buying from a local person or business instead of a chain store? What are some of the challenges local businesses face?');
INSERT INTO badge_optional_requirements VALUES(5373,423,18,'Think of some local business opportunities. What could you add to your community?');
INSERT INTO badge_optional_requirements VALUES(5374,424,3,'Make a timeline of Louis L’Amour’s life. Be sure to include when each of his books was written and published. You must have at least 10 items on your timeline.');
INSERT INTO badge_optional_requirements VALUES(5375,424,4,'Listen to an audiobook or dramatization of one of Louis L’Amour’s books. How does it compare to the actual book? Did listening really make it come alive?');
INSERT INTO badge_optional_requirements VALUES(5376,424,5,'Write a book report one of the books you read.');
INSERT INTO badge_optional_requirements VALUES(5377,424,6,'Choose a time period from one of Louis L’Amour’s books, and learn about it. Things to learn about could include: fashions of that particular time period, technological advances or discoveries made, or world events.');
INSERT INTO badge_optional_requirements VALUES(5378,424,7,'Louis L’Amour wrote an entire series of books about a family named Sackett. The series covered most of America’s history, starting with Barnabas Sackett coming from England to America during the reign of Elizabeth I. Read at least one of the books in the Sackett series.');
INSERT INTO badge_optional_requirements VALUES(5379,424,8,'Read at least five of Louis L’Amour’s books.');
INSERT INTO badge_optional_requirements VALUES(5380,424,9,'Watch a movie adaption of a Louis L’Amour book and read the book it was based off. Did the screenwriters do a good job or adapting the book?');
INSERT INTO badge_optional_requirements VALUES(5381,424,10,'During the times in which Louis L’Amour wrote about, men and women needed to know how to fire a gun in order to protect themselves from danger, such as wild animals. Learn about the history of development of firearms in America.');
INSERT INTO badge_optional_requirements VALUES(5382,424,11,'Look at a map of the westward expansion of America. What was a pioneer? What was a covered wagon?');
INSERT INTO badge_optional_requirements VALUES(5383,424,12,'Choose a state west of the Mississippi and research which Native American tribes lived there. Pick a tribe and learn more about it.');
INSERT INTO badge_optional_requirements VALUES(5384,424,13,'Earn the Cowboy/Cowgirl badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5385,424,14,'Learn about careers that could potentially relate to Louis L’Amour’s work, such as a screenwriter, film director, librarian, rancher, cowboy/girl, or Texas Ranger. What type of education do they need?  What type of pay could they expect?  Where might they have to live? If possible, shadow someone for a day in one of these areas.');
INSERT INTO badge_optional_requirements VALUES(5386,424,15,'Not all of Louis L’Amour’s books were westerns. Some of his books concerned places such as the Solomon Islands. Read at least one of his non-western books and locate the place on a map.');
INSERT INTO badge_optional_requirements VALUES(5387,424,16,'Louis L’Amour also wrote several books about a Texas Ranger named Chick Bowdrie. Find and read at least one book starring him.');
INSERT INTO badge_optional_requirements VALUES(5388,424,17,'Earn the Firearms (Specific) badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5389,425,3,'Write an essay about what love means to you.');
INSERT INTO badge_optional_requirements VALUES(5390,425,4,'How do you show love to your family? Find at least 3 ways to show each member of your family how much you love them this week.');
INSERT INTO badge_optional_requirements VALUES(5391,425,5,'How can you show love to pets/animals? Do something nice for your pet to show it how much you love it. Give it extra petting or grooming; take it for an extra walk; make sure to keep cages or bedding clean. If you are old enough, volunteer some time to help out your local animal shelter in some way.');
INSERT INTO badge_optional_requirements VALUES(5392,425,6,'How can you show love to your friends? How often do you tell your friends how much you appreciate them? Write a friend a letter telling them all the reasons you are glad they are your friend.');
INSERT INTO badge_optional_requirements VALUES(5393,425,7,'Discuss how you can show your love of your country. How does showing respect for American symbols such as the flag or the eagle show your love of country? Do something nice for the veterans in your community to express your appreciation for the sacrifices they made for our country.');
INSERT INTO badge_optional_requirements VALUES(5394,425,8,'Search through magazines for examples of how people show love. Make a collage and share it with your friends or family.');
INSERT INTO badge_optional_requirements VALUES(5395,425,9,'Learn a song or poem about love.');
INSERT INTO badge_optional_requirements VALUES(5396,425,10,'What does your book of faith say about love? Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(5397,425,11,'Read a biography about someone known for showing their love.');
INSERT INTO badge_optional_requirements VALUES(5398,425,12,'Memorize a poem about love.');
INSERT INTO badge_optional_requirements VALUES(5399,425,13,'Discuss how different people show love for God. How many ways do you show God you love Him each day. Through prayer? Being kind to others? Attending your house of worship? Say a prayer to God tell Him how much you love Him and why.');
INSERT INTO badge_optional_requirements VALUES(5400,427,3,'Take a series of photographs, or create a series of sketches, showing the moon phases over the course of 4 weeks and create a poster or other visual display. In your visual display, label each image include the date and time it was taken. Include labels about which phase each photograph is representing. Show your display at school or at a club meeting. Be able to explain the changes you observed.');
INSERT INTO badge_optional_requirements VALUES(5401,427,4,'Read an age/reading level appropriate book about the moon and the history of its exploration by humans. Explain why you think this book will or will not be read 100 years from now.');
INSERT INTO badge_optional_requirements VALUES(5402,427,5,'Visit a Planetarium or Observatory to learn more about the moon and planets in our solar system.');
INSERT INTO badge_optional_requirements VALUES(5403,427,6,'Sketch the face of the moon and indicate at least five seas and five craters. Label these landmarks. Sketch the phase and the daily position of the Moon at the same time and place, for a week. Include landmarks on the horizon such as hills, trees, and buildings to help show the position. Explain the changes you observe.');
INSERT INTO badge_optional_requirements VALUES(5404,427,7,'Learn about careers that involve the moon. What education do you need for this career? What is the pay and work schedule you can expect? If possible, shadow someone with this job for a day: Level 3, 4, and 5 only.');
INSERT INTO badge_optional_requirements VALUES(5405,427,8,'Witness a lunar eclipse. Record and share your observations.');
INSERT INTO badge_optional_requirements VALUES(5406,427,9,'Learn the names, mission and length of extravehicular activity of the twelve men who have stood on the moon.');
INSERT INTO badge_optional_requirements VALUES(5407,427,10,'Read a biography about a lunar astronaut and complete an age appropriate book report in the style of your choice. Explain why you think this book will or will not be read 100 years from now.');
INSERT INTO badge_optional_requirements VALUES(5408,427,11,'Create a travel brochure for the Moon – include how your traveler will get there, what they should bring and what they can expect to see once they get there. Your traveler should also send a postcard – its not everyday you go to the moon.');
INSERT INTO badge_optional_requirements VALUES(5409,427,12,'Write a poem or song about the moon. Use your imagination!  Or learn one that is already written.');
INSERT INTO badge_optional_requirements VALUES(5410,427,13,'Learn all about the ocean tides and how they are connected to the moon. Observe in person or on video both a low and a high tide.');
INSERT INTO badge_optional_requirements VALUES(5411,427,14,'Write a letter to an astronaut. Be certain to ask questions and ask for a reply!');
INSERT INTO badge_optional_requirements VALUES(5412,428,3,'Put on a magic show with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(5413,428,4,'Have a magician/illusionist come to your class or meeting or take a field trip to a magic show.');
INSERT INTO badge_optional_requirements VALUES(5414,428,5,'Watch a magic show on television or online (with a parent’s permission).');
INSERT INTO badge_optional_requirements VALUES(5415,428,6,'Learn about a famous magic trick such the levitating woman or person being sawed in half.  Who was the first person to invent the trick?  How long has it been around?  What variations on the trick have been performed?  If possible, learn how the trick is done.');
INSERT INTO badge_optional_requirements VALUES(5416,428,7,'Learn about a career in magic.  This could be anything from a magician, to a costume or set designer, magic trick creator, etc.  What type of education would you need for this job?  What type of salary might you expect?  Where might you have to live or travel?');
INSERT INTO badge_optional_requirements VALUES(5417,428,8,'Participate in community service project that involves magic tricks such as putting on a magic show for a local homeless shelter or school.');
INSERT INTO badge_optional_requirements VALUES(5418,428,9,'What’s the cups and balls trick? Watch a video on it and be able to perform it for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(5419,428,10,'Visit a museum or exhibit about magic tricks.');
INSERT INTO badge_optional_requirements VALUES(5420,429,3,'The earliest use for magnets was to create a compass.  Learn how a compass works and the difference between magnetic north and true north.');
INSERT INTO badge_optional_requirements VALUES(5421,429,4,'Compare the strength of two different magnets.  Take a paper clip and bend one side out slightly to make a small hook.  Then one by one, hang more paperclips off the first one.  How many paperclips can it hold before they fall?  Which magnet was the strongest?  Were they the same?');
INSERT INTO badge_optional_requirements VALUES(5422,429,5,'Find out what things a magnet will attract.  Place a rubber band, a penny, a paper clip, some aluminum foil, a nail and a piece of string on the counter.  Which ones will the magnet pick up?  Why?');
INSERT INTO badge_optional_requirements VALUES(5423,429,6,'Find out what ferromagnetism, paramagnetism, and diamagnetism are.');
INSERT INTO badge_optional_requirements VALUES(5424,429,7,'Learn about the discovery of lodestone. What does the word lodestone mean? How did this discovery lead to the invention of the compass?');
INSERT INTO badge_optional_requirements VALUES(5425,429,8,'Learn about how iron atoms are arranged in a weak magnet, a strong magnet and demagnetized material.  Draw a diagram to demonstrate what you have learned.');
INSERT INTO badge_optional_requirements VALUES(5426,429,9,'Draw a diagram of a magnetic field around a bar magnet.');
INSERT INTO badge_optional_requirements VALUES(5427,429,10,'Scientists believe that many animals navigate using magnetic fields, such as birds, whales, and butterflies.   Make a list of as many animals as you can that are believed to use magnetic fields to navigate.');
INSERT INTO badge_optional_requirements VALUES(5428,429,11,'What role do magnets play in producing electricity?  Read about generators and write a short report or diagram on how they work.');
INSERT INTO badge_optional_requirements VALUES(5429,429,12,'Junk yard cranes use giant electromagnets to pick up old car bodies.  If you pulled this electromagnet apart, what would you expect to find inside?  As a crane operator, how would you pick up a car body and let it down again?  Would this crane work if you used a giant permanent magnet in place of the electromagnet?  Why?');
INSERT INTO badge_optional_requirements VALUES(5430,429,13,'Find out who William Gilbert was. What was his revolutionary idea regarding magnetism?');
INSERT INTO badge_optional_requirements VALUES(5431,429,14,'Conduct a “Rice Round Up”.  To do this, open a manila folder and cut it in half along the fold.  Using one half of the folder, place an index card lengthwise in the center of the folder and draw circles at each end using a D battery as a template.  Tape a flat ruler along the two short ends of the folder with at least 4” sticking out past one end. Place your folder off the edge of a table and use books piled on the rulers to keep it in place and create a platform.  Put 10 grains of rice in one circle and an open staple in the other.  Pass a magnet underneath your platform to herd your rice from one circle to the other using the staple.');
INSERT INTO badge_optional_requirements VALUES(5432,429,15,'Find a magnet experiment either online or in a book that you would like to try and test it out.  Explain to someone younger than you what you have done and what the results mean.');
INSERT INTO badge_optional_requirements VALUES(5433,429,16,'Find the magnetic variation (declination) for your area.  Using an isogonic map of the world, find other areas with the same variation.');
INSERT INTO badge_optional_requirements VALUES(5434,429,17,'Research a career that uses magnetism such as physicist, geophysicist, surveyor, electrical engineer, or ceramic engineer.  What education and experience will you need?  What is the typical salary and hours worked per week? If possible, shadow someone for a day in one of these careers.');
INSERT INTO badge_optional_requirements VALUES(5435,429,18,'Research the history of the telegraph.  What role did magnetism play in its invention?  What modern day inventions came from the ideas presented in the telegraph?');
INSERT INTO badge_optional_requirements VALUES(5436,429,19,'Research and explain how magnets are used are used in modern day roller coasters.');
INSERT INTO badge_optional_requirements VALUES(5437,429,20,'What is an MRI machine and how does it diagnose illnesses?');
INSERT INTO badge_optional_requirements VALUES(5438,429,21,'Research “magnetic therapy.”  The possible health benefits of magnetism have been under debate for years.  Read articles from both sides and present you case either for or against this type of therapy.');
INSERT INTO badge_optional_requirements VALUES(5439,430,3,'Learn what naked mail is and send someone a piece.');
INSERT INTO badge_optional_requirements VALUES(5440,430,4,'Learn about the International Union of Mail Artists.');
INSERT INTO badge_optional_requirements VALUES(5441,430,5,'Design a postcard to send someone.');
INSERT INTO badge_optional_requirements VALUES(5442,430,6,'Collage a piece of mail art to send.');
INSERT INTO badge_optional_requirements VALUES(5443,430,7,'Paint a piece of mail art.');
INSERT INTO badge_optional_requirements VALUES(5444,430,8,'Send mail art to someone who is sick, a soldier who is deployed, an elderly person, or the like.');
INSERT INTO badge_optional_requirements VALUES(5445,430,9,'Unused U.S. stamps are always valid. Get some older stamps of different denominations and practice using multiple stamps to add up to the correct postage.');
INSERT INTO badge_optional_requirements VALUES(5446,430,10,'Make a piece of mail art using only one color.');
INSERT INTO badge_optional_requirements VALUES(5447,430,11,'Watch a documentary or read a book about mail art.');
INSERT INTO badge_optional_requirements VALUES(5448,430,12,'Learn calligraphy and use it to address a piece of mail art.');
INSERT INTO badge_optional_requirements VALUES(5449,430,13,'Cut out letters from magazines or newspapers and use it to write an address or message in a piece of mail art.');
INSERT INTO badge_optional_requirements VALUES(5450,430,14,'Earn the Pen Pals badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5451,430,15,'Earn the Letter Writing badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5452,430,16,'Artistamps or faux postage are fake stamps made by artists. They are not to be used in place of real postage, but are fun to make. Design your own artistamp.');
INSERT INTO badge_optional_requirements VALUES(5453,430,17,'Make a piece of mail art from recycled materials. For example, cut a piece of cardboard from a cereal box and send it as a postcard.');
INSERT INTO badge_optional_requirements VALUES(5454,430,18,'Learn about non-traditional materials you can mail. For instance, can you mail a coconut?');
INSERT INTO badge_optional_requirements VALUES(5455,431,3,'Make one main dish that includes pasta.');
INSERT INTO badge_optional_requirements VALUES(5456,431,4,'Make one main dish that includes any whole grain such as rice or barley.');
INSERT INTO badge_optional_requirements VALUES(5457,431,5,'Taste at least six different cheeses.  Make a main dish that uses at least two different cheeses.');
INSERT INTO badge_optional_requirements VALUES(5458,431,6,'Make a vegan main dish and serve it as part of a vegan meal.  Make sure your main dish has complete protein.');
INSERT INTO badge_optional_requirements VALUES(5459,431,7,'Learn to roast meat.  Understand the following and use one of them: marinade, brining, gravy, or stuffing.');
INSERT INTO badge_optional_requirements VALUES(5460,431,8,'Try out at least two of the following used as part of a main dish: Dumplings Pie crust Gnocchi Mashed potatoes Stewed vegetables Sautéed vegetables Stir-fried vegetables');
INSERT INTO badge_optional_requirements VALUES(5461,431,9,'Learn different ways to garnish a main dish.  Use one of them while serving your family a main dish. Preschool: Learn one garnish. Levels 1-2: Learn three garnishes. Levels 3-4: Learn five. Level 5: Learn eight.');
INSERT INTO badge_optional_requirements VALUES(5462,431,10,'Make a main dish to take to a sick person or create or for use at some community event.');
INSERT INTO badge_optional_requirements VALUES(5463,431,11,'Learn to use a new kitchen tool making a main dish.');
INSERT INTO badge_optional_requirements VALUES(5464,431,12,'Learn to use a larger electric appliance while making a main dish (food processor, pressure cooker, blender, electric skillet, rice cooker, etc.).');
INSERT INTO badge_optional_requirements VALUES(5465,431,13,'Learn the advantages and disadvantages of different types of cookware such as skillets, casserole dishes, stoneware, silicone, glass and metal dishes.   Cook main dishes in two different types of cookware.');
INSERT INTO badge_optional_requirements VALUES(5466,431,14,'Learn how to make at least three different main dishes from around the world.');
INSERT INTO badge_optional_requirements VALUES(5467,431,15,'Earn the Food Presentation badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5468,432,4,'Explore the issues of too much sun blocking and low vitamin D levels. How much sunlight does a person need each day? Why should you get some sunshine near midday as well as earlier or later in the day? Identify ten health problems associated with low levels of vitamin D.');
INSERT INTO badge_optional_requirements VALUES(5469,432,5,'Learn about the types of ingredients in makeup that you should avoid. Why do you want to avoid these ingredients?');
INSERT INTO badge_optional_requirements VALUES(5470,432,6,'Make a list of poor health conditions credited to, worsened or spread by cosmetics. What can you do to remedy or prevent each condition on your list?');
INSERT INTO badge_optional_requirements VALUES(5471,432,7,'Learn about the history of makeup around the world. Choose one society that interests you, such as Ancient Eygpt, and learn what their makeup was originally made of.');
INSERT INTO badge_optional_requirements VALUES(5472,432,8,'Apply makeup to a person to make the person look like they are younger or older than they are.');
INSERT INTO badge_optional_requirements VALUES(5473,432,9,'Help the makeup artists working with a community theater.');
INSERT INTO badge_optional_requirements VALUES(5474,432,10,'Learn how to properly find the correct color of cosmetics for your skin tone. What is a neutral look?');
INSERT INTO badge_optional_requirements VALUES(5475,432,11,'Find photos in magazines of people who made themselves look worse with their make-up. What did they do wrong?');
INSERT INTO badge_optional_requirements VALUES(5476,432,12,'Learn about what colors and levels of makeup is appropriate for different situations. Everyday? A formal event? A party? Work?');
INSERT INTO badge_optional_requirements VALUES(5477,432,13,'Can you find any cosmetics that contain enough beneficial ingredients that they might possibly double as nutritional supplements?');
INSERT INTO badge_optional_requirements VALUES(5478,432,14,'Learn about theater makeup. Compare theater makeup with everyday makeup. What are the price differences? What are the strains that theater makeup has to endure?');
INSERT INTO badge_optional_requirements VALUES(5479,432,15,'Get a “makeover” by a cosmetic specialist.');
INSERT INTO badge_optional_requirements VALUES(5480,432,16,'Visit a store that sells a wide variety of makeup. Count the various tints and shades. Do different brands focus on different makeup types? What type of makeup has the most variety? Lipstick? Blush? Eye shadow? Foundation?');
INSERT INTO badge_optional_requirements VALUES(5481,432,17,'Put on a makeup fashion show with your friends.');
INSERT INTO badge_optional_requirements VALUES(5482,433,3,'Visit a zoo, pet shop, or other place where you can see your category of animal being fed and cared for. Level 2: Also interview the caretakers and find out what they like/dislike about their job. Level 3: Do Level 2 of this requirement and also find out what type of education or special training is necessary to work in this position. Level 4 & Level 5: Do requirement 11.');
INSERT INTO badge_optional_requirements VALUES(5483,433,4,'Make something to attract, protect, or observe your category of animal.');
INSERT INTO badge_optional_requirements VALUES(5484,433,5,'Make a chart, poster, booklet, or other exhibit to teach others what you have learned while earning this badge.');
INSERT INTO badge_optional_requirements VALUES(5485,433,6,'Make a list of animals from your category that might make good pets.  What special equipment would you need to take care of them?  What types of foods do they eat?  Is this a pet that you would like to have?  Why or why not?');
INSERT INTO badge_optional_requirements VALUES(5486,433,7,'Design and carry out a service project that will benefit your animal group.  This may be planting trees or flowers for birds or insects, raising money for organizations that protect endangered species, gathering a volunteer crew to help out at a local animal shelter, etc.');
INSERT INTO badge_optional_requirements VALUES(5487,433,8,'Research any state and federal laws that protect your animal category.  What animals in your category are on the endangered species list?  What specific protection do they receive?  How would the extinction of this animal affect mankind?  (If you researched this group at an earlier level, make sure all your data is up to date.)');
INSERT INTO badge_optional_requirements VALUES(5488,433,9,'What local or national organizations are there that study or protect animals in your category?  What do they do?  Make a poster showing how you can help to protect an animal from your category. Level 4 & Level 5: Volunteer at least 4 hours to working with one of these organizations.');
INSERT INTO badge_optional_requirements VALUES(5489,433,10,'If your animal category is present naturally in your local community, find out which animals are beneficial to humans, which are nuisances, and which are harmful.  Explain how people interact with each of these animals.');
INSERT INTO badge_optional_requirements VALUES(5490,433,11,'Level 4 & Level 5 Only: Shadow an animal caretaker for a day at a zoo, pet shop, or other place where you can see your category of animal being fed and cared for.  What careers are there in working with these types of animals?  What education or special training would you need?');
INSERT INTO badge_optional_requirements VALUES(5491,434,3,'What makes manga eyes unique? Learn to draw at least 4 different styles of manga eyes.');
INSERT INTO badge_optional_requirements VALUES(5492,434,4,'What is “Chibi” and how does it differ from other manga styles.');
INSERT INTO badge_optional_requirements VALUES(5493,434,4,'Write a book review for the Manga you read.  How does it compare to traditional books?  Did you enjoy it?  Why or why not?');
INSERT INTO badge_optional_requirements VALUES(5494,434,5,'What is the difference between Anime and Manga.  Why are they frequently used together? Watch an age appropriate Anime.');
INSERT INTO badge_optional_requirements VALUES(5495,434,5,'Earn the Japanese Culture badge');
INSERT INTO badge_optional_requirements VALUES(5496,434,6,'Learn what an anthropomorphic (anthro) character is and draw one.');
INSERT INTO badge_optional_requirements VALUES(5497,434,7,'Earn the Pokemon badge');
INSERT INTO badge_optional_requirements VALUES(5498,434,8,'Make a list of 10 age appropriate manga books for your age.');
INSERT INTO badge_optional_requirements VALUES(5499,434,9,'Illustrate a story in manga style');
INSERT INTO badge_optional_requirements VALUES(5500,434,10,'Research manga magazines.  Which are the most popular?  How long have they been in print?');
INSERT INTO badge_optional_requirements VALUES(5501,434,11,'What does “heads high” mean in manga art? How does this contribute to the manga style. Draw your own manga character following the traditional heads high rule of manga art.');
INSERT INTO badge_optional_requirements VALUES(5502,434,12,'Learn about food related manga and read a manga that features food as a main part of its plot.');
INSERT INTO badge_optional_requirements VALUES(5503,434,13,'Learn about a career in manga or anime.  What types of jobs are available other than just artists?');
INSERT INTO badge_optional_requirements VALUES(5504,434,14,'Learn to identify 6 iconic manga characters such as Pikachu from Pokemon.');
INSERT INTO badge_optional_requirements VALUES(5505,434,15,'What is “manpu” and how is it used in manga?');
INSERT INTO badge_optional_requirements VALUES(5506,435,3,'Identify and research three significant examples of your chosen structure worldwide.  Compare and contrast their architectural and engineering features.');
INSERT INTO badge_optional_requirements VALUES(5507,435,4,'Learn about careers involved in building a structure of this type.  What type of education is needed? What type of salary can you expect?  What hours can you expect to work?');
INSERT INTO badge_optional_requirements VALUES(5508,435,5,'Design a future version of this type of structure.');
INSERT INTO badge_optional_requirements VALUES(5509,435,6,'Create a photo story for the construction of a specific structure.  This can be over the life of the project, or a story of a day, such as from sunrise to sunset on the job site.');
INSERT INTO badge_optional_requirements VALUES(5510,435,7,'Create a photo collage of similar structures around the world.');
INSERT INTO badge_optional_requirements VALUES(5511,435,8,'Make a 3D model of this structure.');
INSERT INTO badge_optional_requirements VALUES(5512,435,9,'Investigate the engineering principles employed in the construction of the structure.  Describe how technological advancements have influenced its engineering.');
INSERT INTO badge_optional_requirements VALUES(5513,435,10,'Learn about environmental impact reports and the planning process. What has to happen before construction can even begin?');
INSERT INTO badge_optional_requirements VALUES(5514,435,11,'Interview a project manager or architect who deals with these types of structures.');
INSERT INTO badge_optional_requirements VALUES(5515,435,12,'Look at different phases of the plans for the project.');
INSERT INTO badge_optional_requirements VALUES(5516,435,13,'Research one of the materials used in your structure.  These might include steel, concrete, glass, etc.  Where did the material come from?  How is it processed?  How is it transported?  Why does it make a good building material for this type of structure?');
INSERT INTO badge_optional_requirements VALUES(5517,435,14,'Explore the various architectural styles relevant to your chosen structure. Identify specific design elements that define these styles.');
INSERT INTO badge_optional_requirements VALUES(5518,435,15,'Identify safety features incorporated into this type of structure.  Explain how these features ensure the well-being of occupants and visitors.  How has safety improved in how these structures are made and used over the years?');
INSERT INTO badge_optional_requirements VALUES(5519,435,16,'Research the maintenance practices and preservation efforts for this type of structure.');
INSERT INTO badge_optional_requirements VALUES(5520,435,17,'Conduct surveys or interviews to gauge public opinion about the recent construction of  one of your chosen structures.  Analyze the impact of public perception on the structure’s reputation.');
INSERT INTO badge_optional_requirements VALUES(5521,435,18,'Explore the economic impact of constructing and maintaining the structure.  Investigate its role in job creation and economic development.');
INSERT INTO badge_optional_requirements VALUES(5522,435,19,'Produce a documentary or podcast episode about your chosen structure.');
INSERT INTO badge_optional_requirements VALUES(5523,437,3,'Plan and then create a piece of art that incorporates marbles.  This can be simple like painting individual marbles, or more complicated like creating a small sculpture that includes marbles.');
INSERT INTO badge_optional_requirements VALUES(5524,437,4,'Learn this vocabulary: – Shooter/taw – Mib – Mibster');
INSERT INTO badge_optional_requirements VALUES(5525,437,5,'Learn and practice different ways to shoot a marble: – Bombsies/bombies – Bowling – Fulking/knuckle down/knuckling down – Histing');
INSERT INTO badge_optional_requirements VALUES(5526,437,6,'Play two other versions of marbles such as Nucks from Australia, Kelereng from Indonesia, or Dool from Uganda.');
INSERT INTO badge_optional_requirements VALUES(5527,437,7,'Start a marble collection.');
INSERT INTO badge_optional_requirements VALUES(5528,437,8,'Know the difference between playing keepsies and friendlies.');
INSERT INTO badge_optional_requirements VALUES(5529,437,9,'Make your own marbles out of clay or other material.');
INSERT INTO badge_optional_requirements VALUES(5530,437,10,'Teach a game of marbles and how to shoot them to someone who is not already familiar with them.');
INSERT INTO badge_optional_requirements VALUES(5531,437,11,'Learn about marble collecting as a hobby. What are some things to consider when taking up marble collecting? Where can you find collector’s marbles? How should you store them?');
INSERT INTO badge_optional_requirements VALUES(5532,437,12,'Learn about the value of rare marbles. About how much could you sell a rare marble for?');
INSERT INTO badge_optional_requirements VALUES(5533,437,13,'Participate in a community service project involving marbles.');
INSERT INTO badge_optional_requirements VALUES(5534,437,14,'Research different careers that have to do with marbles. What type of education do you need?  What type of pay could you expect?  Where might you have to live? If possible, shadow someone for a day in one of these careers.');
INSERT INTO badge_optional_requirements VALUES(5535,437,15,'Make up your own game using marbles.  If you need to use other materials to play, ensure they are easily-available to almost anyone.  Teach your game to others and play it with them.');
INSERT INTO badge_optional_requirements VALUES(5536,437,16,'Create a marble run and see how far you can make a marble travel.');
INSERT INTO badge_optional_requirements VALUES(5537,437,17,'Participate in a marble tournament or competition and share your experience.');
INSERT INTO badge_optional_requirements VALUES(5538,438,3,'Earn a state badge for another state that hosts Frontier Girls. (Preferably the same state you swapped with!)');
INSERT INTO badge_optional_requirements VALUES(5539,438,4,'Get together with another Frontier Girls troop or Pioneer to do a fun activity or service project.');
INSERT INTO badge_optional_requirements VALUES(5540,438,5,'Meet the Founder, Kerry Cordy, or interview her by phone or email.');
INSERT INTO badge_optional_requirements VALUES(5541,438,6,'Collaborate on a project with a Frontier Girl sister who lives far away.');
INSERT INTO badge_optional_requirements VALUES(5542,438,7,'Make flyers or posters to advertise your troop and try to recruit new members to Frontier Girls.');
INSERT INTO badge_optional_requirements VALUES(5543,438,8,'Make a recipe that is popular in another state and share it with friends.');
INSERT INTO badge_optional_requirements VALUES(5544,438,9,'Make a craft that represents another state.');
INSERT INTO badge_optional_requirements VALUES(5545,438,10,'Host or participate in a March 4th Day celebration.  Have each person (or troop) learn about a different part of our country.  Then have each person/troop bring a dish of food from their region, make a swap from their region, bring a craft or item to talk about, etc.');
INSERT INTO badge_optional_requirements VALUES(5546,438,11,'Learn a song from a different region or state.');
INSERT INTO badge_optional_requirements VALUES(5547,438,12,'Wear your uniform to school.');
INSERT INTO badge_optional_requirements VALUES(5548,438,13,'Make a presentation about Frontier Girls to your church, class, friends or family.');
INSERT INTO badge_optional_requirements VALUES(5549,439,3,'Learn about ancient forms of shipbuilding, such as the balsa-wood rafts from Peru or the reed boats from Mesopotamia.');
INSERT INTO badge_optional_requirements VALUES(5550,439,4,'Earn the Rain Gutter Regatta badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5551,439,5,'Find at least three songs about ships or three sea shanties and learn to sing them.');
INSERT INTO badge_optional_requirements VALUES(5552,439,6,'Not all boats are successful in reaching their destination.  Many are wrecked en route and sink.  Research a famous shipwreck, such as the H. M. S. Titanic, or the Lusitania.');
INSERT INTO badge_optional_requirements VALUES(5553,439,7,'Find out how lighthouses help ships to avoid dangerous reefs, shoals, sandbars, rocks, etc.  Learn about a famous lighthouse, such as the Pharos lighthouse at Alexandria, or the Eddystone Lighthouse in England.');
INSERT INTO badge_optional_requirements VALUES(5554,439,8,'Read about famous lifeboat rescues such as Grace Darling and how she helped the crew of the Forfarshire to safety.  What was the result of her action?   Where was the world’s first official lifeboat service?');
INSERT INTO badge_optional_requirements VALUES(5555,439,9,'Research careers in the ships business, such as designer, mechanic, engineer, pilot, navigator, steward, etc. What type of education do you need?  What type of pay could you expect?  Where might you have to live? If possible, shadow someone for a day in one of these careers.');
INSERT INTO badge_optional_requirements VALUES(5556,439,10,'Research areas of the world that are famous for many shipwrecks/ships lost at sea.  Where are they and what makes them so dangerous for ships?  Examples could be the Goodwin Sands or the Bermuda Triangle.');
INSERT INTO badge_optional_requirements VALUES(5557,439,11,'Watch an age-appropriate documentary or movie about ships.');
INSERT INTO badge_optional_requirements VALUES(5558,439,12,'Find out about navigation on the open sea.  How do ships navigate today versus 200 years ago (or more)?  Which do you think worked better?');
INSERT INTO badge_optional_requirements VALUES(5559,439,13,'Learn about different businesses that use ships, both in the past and the present.');
INSERT INTO badge_optional_requirements VALUES(5560,439,14,'Plan a pretend cruise on a cruise ship.  Look at flyers for different cruise lines and decide which one you would choose.  Find and look at an itinerary for a cruise on the line you have chosen. What do you like about it?  How much does it cost?  How long is it?  What documents (passports, visas etc) do you need?  Do you need special vaccinations?');
INSERT INTO badge_optional_requirements VALUES(5561,439,15,'Learn about smaller boats, such as coracles and rowboats.  If possible, learn how to row a boat.');
INSERT INTO badge_optional_requirements VALUES(5562,439,16,'Learn about the history of the U. S. Navy.  Look at a chart of the ranks of personnel on a ship in the U. S. Navy.  Find the respective places of an ensign, a captain, an admiral, and a commodore.');
INSERT INTO badge_optional_requirements VALUES(5563,439,17,'Research famous sea battles, such as the Battle of the Coral Sea, the Battle of the Atlantic, or the Battle of Gravelines.');
INSERT INTO badge_optional_requirements VALUES(5564,439,18,'Learn about a famous ship from the past, such as Sir Francis Drake’s The Golden Hind, or the ocean liner the Queen Mary. Tell your family, friends, or group what you learned. If you choose to learn about the Queen Mary find out about the fiasco surrounding the naming of the ship.');
INSERT INTO badge_optional_requirements VALUES(5565,439,19,'Learn about the Coast Guard and what sort of equipment they use to rescue people from the sea.  What other responsibilities do they have besides rescuing people from wrecked craft?');
INSERT INTO badge_optional_requirements VALUES(5566,439,20,'Learn about marine craft such as submarines and submersibles.  How do they submerge?  Learn why the German U-boats were such a problem during WWI and WWII.');
INSERT INTO badge_optional_requirements VALUES(5567,439,21,'Find places in your own book of faith that relate to ships.  Examples from the Bible might include the Ark, Solomon’s navy, or the navy that Ahaziah and Jehoshaphat tried to build.');
INSERT INTO badge_optional_requirements VALUES(5568,439,22,'Find out about the Sutton Hoo burial ship in England.  Why do archeologists think it was buried, what do they know about it, and what do they think it was for? Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(5569,439,23,'Read a book, watch a video, or go online (with your parent’s permission) to find out how ships and boats are constructed.  What is the Plimsoll line?  Why is it important?');
INSERT INTO badge_optional_requirements VALUES(5570,439,24,'Learn what scurvy is and why it was such a problem on long sea voyages.  How did Captain Cook prevent scurvy on the ship the H. M. S. Endeavour?  What other disease conditions did sailors have to deal with in the past?  How have they been overcome?');
INSERT INTO badge_optional_requirements VALUES(5571,439,25,'Learn how boats and ships can harm wildlife. What can be done to protect sealife, birds, and more from ships?');
INSERT INTO badge_optional_requirements VALUES(5572,439,26,'Earn the Sailing badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5573,440,3,'Visit a zoo, pet shop, or other place where you can see your category of animal being fed and cared for. Level 2: Also interview the caretakers and find out what they like/dislike about their job. Level 3: Do Level 2 of this requirement and also find out what type of education or special training is necessary to work in this position. Level 4 & Level 5: Do requirement 11.');
INSERT INTO badge_optional_requirements VALUES(5574,440,4,'Make something to attract, protect, or observe your category of animal.');
INSERT INTO badge_optional_requirements VALUES(5575,440,5,'Make a chart, poster, booklet, or other exhibit to teach others what you have learned while earning this badge.');
INSERT INTO badge_optional_requirements VALUES(5576,440,6,'Make a list of animals from your category that might make good pets.  What special equipment would you need to take care of them?  What types of foods do they eat?  Is this a pet that you would like to have?  Why or why not?');
INSERT INTO badge_optional_requirements VALUES(5577,440,7,'Design and carry out a service project that will benefit your animal group.  This may be planting trees or flowers for birds or insects, raising money for organizations that protect endangered species, gathering a volunteer crew to help out at a local animal shelter, etc.');
INSERT INTO badge_optional_requirements VALUES(5578,440,8,'Research any state and federal laws that protect your animal category.  What animals in your category are on the endangered species list?  What specific protection do they receive?  How would the extinction of this animal affect mankind?  (If you researched this group at an earlier level, make sure all your data is up to date.)');
INSERT INTO badge_optional_requirements VALUES(5579,440,9,'What local or national organizations are there that study or protect animals in your category?  What do they do?  Make a poster showing how you can help to protect an animal from your category. Level 4 & Level 5: Volunteer at least 4 hours to working with one of these organizations.');
INSERT INTO badge_optional_requirements VALUES(5580,440,10,'If your animal category is present naturally in your local community, find out which animals are beneficial to humans, which are nuisances, and which are harmful.  Explain how people interact with each of these animals.');
INSERT INTO badge_optional_requirements VALUES(5581,440,11,'Level 4 & Level 5 Only: Shadow an animal caretaker for a day at a zoo, pet shop, or other place where you can see your category of animal being fed and cared for.  What careers are there in working with these types of animals?  What education or special training would you need?');
INSERT INTO badge_optional_requirements VALUES(5582,441,3,'Listen to and learn the Marine Corp Hymn.');
INSERT INTO badge_optional_requirements VALUES(5583,441,4,'Be able to identify at least 5 different Marine vehicles and explain their purpose.');
INSERT INTO badge_optional_requirements VALUES(5584,441,5,'Tour a Marine base and find out what jobs they do there.');
INSERT INTO badge_optional_requirements VALUES(5585,441,6,'Learn how to read a 24 hour clock as well as use the military phonetic alphabet. Practice translating time from a 12 hour clock to 24 hour and back again. Translate license plates using the phonetic alphabet.');
INSERT INTO badge_optional_requirements VALUES(5586,441,7,'Tour a Marine museum, memorial, or monument.');
INSERT INTO badge_optional_requirements VALUES(5587,441,8,'Interview a member of the Marines. What is their role? What has their experience been like? What is the best and worst part of their job? Where have they traveled');
INSERT INTO badge_optional_requirements VALUES(5588,441,9,'Make a map of the 10 Marine bases nearest you. Which is the closest? What is their mission? What groups are stationed there?');
INSERT INTO badge_optional_requirements VALUES(5589,441,10,'Participate in a community service project for the Marines. For example you could send cards or care packages to Marine members overseas; do yard work or babysitting for a Marine family with a member serving away from home; serve dinner at your local VFW post and listen to stories from veteran Marine men and women; volunteer at your local veteran cemetery such as placing flags or wreaths on the graves for memorial day; etc.');
INSERT INTO badge_optional_requirements VALUES(5590,441,11,'Learn about the Marine uniform. What is the significance of the different parts of the uniform?');
INSERT INTO badge_optional_requirements VALUES(5591,441,12,'Learn the ranking system for members of the Marines, from enlisted to officers.');
INSERT INTO badge_optional_requirements VALUES(5592,442,4,'Try different flavors of marshmallows. How many different flavors can you find at the grocery store? What are they flavored with?');
INSERT INTO badge_optional_requirements VALUES(5593,442,5,'With adult supervision, make homemade marshmallows and compare them to store bought. Which taste better? Can you make them healthier?');
INSERT INTO badge_optional_requirements VALUES(5594,442,6,'Make a craft using marshmallows, such as marshmallow snowmen or robots.');
INSERT INTO badge_optional_requirements VALUES(5595,442,7,'Create a marshmallow shooter or catapult. How can you improve it?');
INSERT INTO badge_optional_requirements VALUES(5596,442,8,'Use marshmallows in your schoolwork. For example, make molecule models out of marshmallows or use mini’s to spell words for your spelling homework.');
INSERT INTO badge_optional_requirements VALUES(5597,442,9,'Earn the S’mores badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5598,442,10,'Find out the history behind marshmallows. Who made the first marshmallows? What were they used for before they were just a sweet treat?');
INSERT INTO badge_optional_requirements VALUES(5599,442,11,'With adult supervision, roast marshmallows over a campfire. Compare these to uncooked marshmallows. Which do you like best? Survey your friends and family members. Do they like their marshmallows burned, golden brown, or uncooked? Plot your results.');
INSERT INTO badge_optional_requirements VALUES(5600,442,12,'Try marshmallow creme. You could make a fluff-a-nutter sandwich (peanut butter and marshmallow creme).');
INSERT INTO badge_optional_requirements VALUES(5601,442,13,'Take a tour of a factory where marshmallows are made in person or virtually (with a parent’s permission).');
INSERT INTO badge_optional_requirements VALUES(5602,442,14,'Use marshmallows in a community service project. For example, use them in a recipe to give away as gifts, or to sell for a fundraiser. A fun idea is taking a mason jar and putting in hot cocoa mix, mini marshmallows, and a cute stirring stick. Follow all local/state/federal laws.');
INSERT INTO badge_optional_requirements VALUES(5603,443,3,'Watch one of the films based off of the books. Describe how it differs from the book.');
INSERT INTO badge_optional_requirements VALUES(5604,443,4,'Recreate a scene from the book. You can act it out, draw a picture of it, create a diorama, etc.');
INSERT INTO badge_optional_requirements VALUES(5605,443,5,'Cook/prepare a food mentioned in Mary Poppins in the Kitchen. Levels 3-5: Create a whole meal.');
INSERT INTO badge_optional_requirements VALUES(5606,443,6,'Make your own kite and fly it.');
INSERT INTO badge_optional_requirements VALUES(5607,443,7,'Earn the Tea Time badge for your level.');
INSERT INTO badge_optional_requirements VALUES(5608,443,8,'Make your own Mary Poppins craft, such as a Mary Poppins style hat or paper dolls of one or more of the characters from the books or movies.');
INSERT INTO badge_optional_requirements VALUES(5609,443,9,'Throw a Mary Poppins movie watching or book party.');
INSERT INTO badge_optional_requirements VALUES(5610,443,10,'Try your hand at song writing by creating a song about turning a everyday chore into a fun game.');
INSERT INTO badge_optional_requirements VALUES(5611,443,11,'Find out if Mary Poppins was based on a real person in P. L. Travers’ life.  If so, who was the person and what were the similarities?');
INSERT INTO badge_optional_requirements VALUES(5612,443,12,'Who was your favorite character in the books or movies? Why? What was a trait that that character had that you could develop that would improve your life? Practice that trait for a week.');
INSERT INTO badge_optional_requirements VALUES(5613,444,3,'Learn about the different oils and lotions people use during a massage.  How do oils and lotions help with massage?  What are the names of some petroleum products you might want to avoid in a lotion or a cream?');
INSERT INTO badge_optional_requirements VALUES(5614,444,4,'What is an essential oil?  What are the benefits of essential oils?  Are there any cautions related to their use?  Know the names and common applications of at least 5 essential oils.');
INSERT INTO badge_optional_requirements VALUES(5615,444,3,'Learn and, if able, perform a massage for someone who is ill or has a special need that can be addressed by massage.');
INSERT INTO badge_optional_requirements VALUES(5616,444,4,'Learn about various specialized massages such as infant massage, rolfing, or myofascial release. Know the distinctive characteristics of at least three such therapies.');
INSERT INTO badge_optional_requirements VALUES(5617,444,5,'Investigate healing therapies that can compliment massage such as aromatherapy, topical vitamins,  and heat. Which ones require extra training?  Which ones are more frequently used by a masseuse?');
INSERT INTO badge_optional_requirements VALUES(5618,444,6,'What is the origin and insertion of a muscle?');
INSERT INTO badge_optional_requirements VALUES(5619,444,7,'What are some ingredients added to lotions or creams that may relieve pain?');
INSERT INTO badge_optional_requirements VALUES(5620,444,8,'Look at different styles of massage tables at a spa or in a store or catalog.  Learn a little about how they operate.  What is the range of prices and what are the advantages of the different styles?');
INSERT INTO badge_optional_requirements VALUES(5621,444,9,'Learn about other things people use during a massage to help people relax such as music, lighting, and temperature. Why is it important to relax during a message?');
INSERT INTO badge_optional_requirements VALUES(5622,444,10,'What is trigger point therapy?');
INSERT INTO badge_optional_requirements VALUES(5623,444,11,'Find out what kinds of schooling is available for learning massage.  How much do the schools cost?  How long do the schools last & how many hours of practice do you need?  How do you get certified in your state?');
INSERT INTO badge_optional_requirements VALUES(5624,444,12,'Investigate the price of supplies and rental space for massage.  What does a masseuse need to know about accounting and taxes?');
INSERT INTO badge_optional_requirements VALUES(5625,444,13,'Tour a masseuse treatment space and interview a masseuse.');
INSERT INTO badge_optional_requirements VALUES(5626,444,14,'Read or watch a video on massage to expand your knowledge.');
INSERT INTO badge_optional_requirements VALUES(5627,446,3,'Learn three different ways to make May baskets.');
INSERT INTO badge_optional_requirements VALUES(5628,446,4,'Interview senior citizens about their memories of May baskets.');
INSERT INTO badge_optional_requirements VALUES(5629,446,5,'Create paper flowers to put in May baskets.');
INSERT INTO badge_optional_requirements VALUES(5630,446,6,'Make homemade treats to put in May baskets.');
INSERT INTO badge_optional_requirements VALUES(5631,446,7,'Learn which spring flowers are typically the first to bloom in your area.');
INSERT INTO badge_optional_requirements VALUES(5632,446,8,'Do something special with your family, friends, or group to celebrate spring.');
INSERT INTO badge_optional_requirements VALUES(5633,446,9,'Earn the Seasons badge for spring at your level.');
INSERT INTO badge_optional_requirements VALUES(5634,446,10,'Pick a bouquet of spring flowers.');
INSERT INTO badge_optional_requirements VALUES(5635,446,11,'What are some other historical or traditional ways to celebrate spring?');
INSERT INTO badge_optional_requirements VALUES(5636,446,12,'Make handmade cards to put in May baskets.');
INSERT INTO badge_optional_requirements VALUES(5637,448,3,'Visit a local farm or ranch that raises meat animals and observe the husbandry practices and care provided to the animals.');
INSERT INTO badge_optional_requirements VALUES(5638,448,4,'Try meat from an animal you don’t usually eat everyday such as rabbit, alligator or frog legs.');
INSERT INTO badge_optional_requirements VALUES(5639,448,4,'Learn about the different breeds of meat animals and their characteristics, such as size, temperament, and meat quality.  For example what breed of cow produces the best beef and why?  How do meat cows differ from dairy cows?');
INSERT INTO badge_optional_requirements VALUES(5640,448,5,'Explore the environmental considerations and sustainability practices associated with raising meat animals.');
INSERT INTO badge_optional_requirements VALUES(5641,448,6,'Participate in a hands-on activity related to meat animal care, such as feeding, grooming, or observing animal behavior.');
INSERT INTO badge_optional_requirements VALUES(5642,448,7,'Visit a local slaughterhouse, butcher shop or meat processing facility to learn about the processing steps involved in transforming a meat animal into consumable meat.');
INSERT INTO badge_optional_requirements VALUES(5643,448,8,'Research the different feeding practices and diets provided to meat animals for optimal growth and health.');
INSERT INTO badge_optional_requirements VALUES(5644,448,9,'Create a diagram of thedifferent cuts of meat obtained from various parts of a meat animal.  What is each cut usually used for when cooking?');
INSERT INTO badge_optional_requirements VALUES(5645,448,10,'Participate in a cooking or grilling activity, preparing and cooking meat from different meat animals.');
INSERT INTO badge_optional_requirements VALUES(5646,448,11,'Discuss the importance of proper meat handling, storage, and cooking techniques to ensure food safety and prevent foodborne illnesses.');
INSERT INTO badge_optional_requirements VALUES(5647,448,12,'Learn about the cultural significance of meat animals in different regions or cuisines, including traditional recipes and celebrations.');
INSERT INTO badge_optional_requirements VALUES(5648,448,13,'Research and present on the different production systems for meat animals, such as conventional farming, organic farming, or free-range systems.');
INSERT INTO badge_optional_requirements VALUES(5649,448,14,'Discuss the concept of animal breeding and the selection criteria used to improve meat animal genetics and characteristics.');
INSERT INTO badge_optional_requirements VALUES(5650,448,15,'Understand the principles of meat quality evaluation, including factors such as tenderness, flavor, and marbling.');
INSERT INTO badge_optional_requirements VALUES(5651,448,16,'Understand the challenges and opportunities in the meat industry, including market demand, technology advancements, and sustainability initiatives.');
INSERT INTO badge_optional_requirements VALUES(5652,448,17,'Raise a meat animal for sale through 4H, FFA or another organization.');
INSERT INTO badge_optional_requirements VALUES(5653,448,18,'Explore the concept of alternative protein sources and their potential impact on meat consumption and animal agriculture.');
INSERT INTO badge_optional_requirements VALUES(5654,448,19,'Learn about the economic significance of meat animals in local and global food systems, including the livelihoods of farmers and the meat industry’s contribution to the economy.');
INSERT INTO badge_optional_requirements VALUES(5655,448,20,'Roleplay a small “farm” using toy animals wiht your friends or troop. Take on roles such as farmers, veterinarians, butcher or chefs. What would each person do in relation to the animals.');
INSERT INTO badge_optional_requirements VALUES(5656,448,21,'Learn to read food packaging labels on meat.  Talk about the information provided on labels, including where the meat comes from and any certifications related to animal welfare as well as cooking suggestions or freeze/use by dates.');
INSERT INTO badge_optional_requirements VALUES(5657,449,3,'Look at an item from the animal kingdom under the microscope (anything from amoeba to a piece of a feather).');
INSERT INTO badge_optional_requirements VALUES(5658,449,4,'Look at an item from the plant kingdom under the microscope (tiny alga to a large leaf).');
INSERT INTO badge_optional_requirements VALUES(5659,449,5,'Look at an item from neither the plant or animal kingdoms under the microscope (such as salt or sugar).');
INSERT INTO badge_optional_requirements VALUES(5660,449,6,'Make a drawing of something you see under a microscope. It must be magnified at least 30 times.');
INSERT INTO badge_optional_requirements VALUES(5661,449,7,'Visit a laboratory where people use a microscope for work.');
INSERT INTO badge_optional_requirements VALUES(5662,449,8,'Learn about a famous scientist who used a microscope in their work. What did they use a microscope for? When did they live? Where were they from?');
INSERT INTO badge_optional_requirements VALUES(5663,449,9,'Learn how to take care of a microscope, how to clean slides and cover slips. Find out how much different microscopes cost, from an amateur one to a professional one.');
INSERT INTO badge_optional_requirements VALUES(5664,449,10,'Interview someone who uses a microscope at work. Find out how important the microscope is to his/her work.');
INSERT INTO badge_optional_requirements VALUES(5665,449,11,'Help a younger child earn this badge.');
INSERT INTO badge_optional_requirements VALUES(5666,449,12,'Help a medical clinic or school buy a new microscope.');
INSERT INTO badge_optional_requirements VALUES(5667,451,3,'Read an age-appropriate book on military families. Write a book report about what you’ve read.');
INSERT INTO badge_optional_requirements VALUES(5668,451,4,'Research how military families celebrate homecomings.');
INSERT INTO badge_optional_requirements VALUES(5669,451,5,'Learn about care packages and what families send to their service member while deployed. Create a care package and send to a friend or family member!');
INSERT INTO badge_optional_requirements VALUES(5670,451,6,'What does it mean to be a dual military family? How are their challenges different from a family with only one parent in the military?');
INSERT INTO badge_optional_requirements VALUES(5671,451,7,'Create a count down device that military families may use while their service member is deployed. Use it for your own countdown for a birthday or a special trip!');
INSERT INTO badge_optional_requirements VALUES(5672,451,8,'Make a craft to send to a military service member without family to send him or her stuff while deployed.');
INSERT INTO badge_optional_requirements VALUES(5673,451,9,'Participate in a community service project that has something to do with military families.');
INSERT INTO badge_optional_requirements VALUES(5674,451,10,'Find out about 3 organizations that help military families.');
INSERT INTO badge_optional_requirements VALUES(5675,451,11,'Collect teddy bears or other item that could be used as a comfort friend for kids who are waiting for their mom or dad to return home. Donate the items to an organization.');
INSERT INTO badge_optional_requirements VALUES(5676,451,12,'Write a poem about military families. Share your poem with others.');
INSERT INTO badge_optional_requirements VALUES(5677,451,13,'If you’re part of a military family, share your own experiences with others');
INSERT INTO badge_optional_requirements VALUES(5678,451,14,'Learn about how long deployment lasts. Create a list of things you could do to stay busy during a deployment.');
INSERT INTO badge_optional_requirements VALUES(5679,451,15,'Learn about how military families celebrate birthdays and holiday’s. Plan and execute a party the way military families would, such as celebrating Thanksgiving and Christmas together and have a Christ-giving.');
INSERT INTO badge_optional_requirements VALUES(5680,451,16,'Learn about how military children communicate with their military family member. How can you incorporate this type of communication for your own family?');
INSERT INTO badge_optional_requirements VALUES(5681,451,17,'How are military families similar to families whose mothers or fathers are not in the military?');
INSERT INTO badge_optional_requirements VALUES(5682,452,3,'Learn about how puzzles such as crosswords are created.  If possible, shadow someone for a day who creates puzzles for a newspaper, etc.  Make a puzzle of your own.');
INSERT INTO badge_optional_requirements VALUES(5683,452,4,'Learn about crossword puzzles, learn to do them and complete one appropriate to your age and ability.  Levels 3 & Up: Create your own crossword puzzle.');
INSERT INTO badge_optional_requirements VALUES(5684,452,5,'Learn about frame game puzzles, learn to do them and complete one appropriate to your age and ability.  Levels 3 & Up: Create your own frame game puzzle.');
INSERT INTO badge_optional_requirements VALUES(5685,452,6,'Learn about hourglass puzzles, learn to do them and complete one appropriate to your age and ability.  Levels 3 & Up: Create your own hourglass puzzle.');
INSERT INTO badge_optional_requirements VALUES(5686,452,7,'Learn about kakuro puzzles, learn to do them and complete one appropriate to your age and ability. Levels 3 & Up: Create your own kakuro puzzle.');
INSERT INTO badge_optional_requirements VALUES(5687,452,8,'Learn about sudoku puzzles, learn to do them and complete one appropriate to your age and ability. Levels 3 & Up: Create your own sudoku puzzle.');
INSERT INTO badge_optional_requirements VALUES(5688,452,9,'Learn how doing mind puzzles can help to stimulate your brain or can help it to relax.');
INSERT INTO badge_optional_requirements VALUES(5689,452,10,'Teach someone else how to do your favorite type of mind puzzles.');
INSERT INTO badge_optional_requirements VALUES(5690,452,11,'Learn how to complete a Rubik’s cube or other similar 3D puzzle.');
INSERT INTO badge_optional_requirements VALUES(5691,453,3,'With a parent’s permission, install at least one modification to the game.');
INSERT INTO badge_optional_requirements VALUES(5692,453,4,'Construct a full set of diamond tools.');
INSERT INTO badge_optional_requirements VALUES(5693,453,5,'Research the version history of Minecraft on their special wiki and play the classic version to examine how much they have changed the game.');
INSERT INTO badge_optional_requirements VALUES(5694,453,6,'Defeat the Enderdragon.');
INSERT INTO badge_optional_requirements VALUES(5695,453,7,'Defeat the Wither.');
INSERT INTO badge_optional_requirements VALUES(5696,453,8,'Find at least one dungeon, temple, or fortress.');
INSERT INTO badge_optional_requirements VALUES(5697,453,9,'Research redstone and how to use it in building traps, machines, doors, etc.');
INSERT INTO badge_optional_requirements VALUES(5698,453,10,'Find an NPC village and trade with one of the villagers.');
INSERT INTO badge_optional_requirements VALUES(5699,453,11,'Build a farm and successfully farm wheat, sugar cane, carrots, potatoes, melons, and pumpkins');
INSERT INTO badge_optional_requirements VALUES(5700,453,12,'Research brewing and potions, and brew at least three different types of potions.');
INSERT INTO badge_optional_requirements VALUES(5701,453,13,'Go to all of the different dimensions.');
INSERT INTO badge_optional_requirements VALUES(5702,453,14,'Create every color of dyed wool.');
INSERT INTO badge_optional_requirements VALUES(5703,453,15,'Kill 20 creepers without allowing them to explode.');
INSERT INTO badge_optional_requirements VALUES(5704,453,16,'Create an enchanting table and place bookshelves around to allow you to enchant at least three tools/ pieces of armor past level 10.');
INSERT INTO badge_optional_requirements VALUES(5705,453,17,'Craft one cake.');
INSERT INTO badge_optional_requirements VALUES(5706,453,18,'Play on a multiplayer server.');
INSERT INTO badge_optional_requirements VALUES(5707,453,19,'Visit each of the different biomes.');
INSERT INTO badge_optional_requirements VALUES(5708,453,20,'Craft a full set of iron tools.');
INSERT INTO badge_optional_requirements VALUES(5709,453,21,'Kill one ghast.');
INSERT INTO badge_optional_requirements VALUES(5710,453,22,'Play a version of Minecraft on a different gaming system.');
INSERT INTO badge_optional_requirements VALUES(5711,455,3,'Participate in a miniature golf tournament.');
INSERT INTO badge_optional_requirements VALUES(5712,455,4,'Play miniature golf on a black light course.');
INSERT INTO badge_optional_requirements VALUES(5713,455,5,'On paper or computer, design your own course.');
INSERT INTO badge_optional_requirements VALUES(5714,455,6,'On paper or computer, design your own golf club.');
INSERT INTO badge_optional_requirements VALUES(5715,455,7,'Create a simple indoor course in your home or meeting area and play a round of mini golf on it.');
INSERT INTO badge_optional_requirements VALUES(5716,455,8,'Create a simple outdoor course in your yard or a local park and play a round of mini golf on it.');
INSERT INTO badge_optional_requirements VALUES(5717,455,9,'Understand mini golf terminology. Par Eagle Birdie Bogey Hole-In-One The Green Spin Teeing Off');
INSERT INTO badge_optional_requirements VALUES(5718,455,10,'Play a mini golf video game or app.');
INSERT INTO badge_optional_requirements VALUES(5719,455,11,'Participate in a community service project that involves miniature golf.  You may choose to host a tournament and give the money to a charity, or possibly make portable miniature gold holes that can be donated to local senior centers or schools.');
INSERT INTO badge_optional_requirements VALUES(5720,455,12,'Learn about miniature golf organizations. Which ones are available to your location? Do any of them have membership fees? Age requirements?');
INSERT INTO badge_optional_requirements VALUES(5721,456,3,'The way we present our outside should match who we are on the inside.  Different messages can be given depending on the clothing we choose to wear. Why are certain clothing choices immodest? Why these items of clothing considered inappropriate in most, if not all, situations? What might they say about a person? What clothing choices are modest but flattering for common situations, such as everyday, work, or a formal event?');
INSERT INTO badge_optional_requirements VALUES(5722,456,4,'Have you ever wanted to be the center of attention?  Have you noticed that in order to get that attention you may behave in ways that are overly dramatic?  For one week, think about your behavior when you are trying to get attention.  Do you whine?  Do you get very loud?  Do you brag? Joke during inappropriate times or about inappropriate subjects? How does this type of behavior make you feel when you see it in others?  What is a better way to express yourself?  Practice noticing if you are trying to steal the attention away from someone else.  If your sister is getting a lot of attention because of something wonderful that she accomplished, don’t try to take the attention for yourself, but instead, praise your sister and enjoy her moment with her.');
INSERT INTO badge_optional_requirements VALUES(5723,456,5,'Create a collage that expresses modesty.');
INSERT INTO badge_optional_requirements VALUES(5724,456,6,'Write a paragraph about what modesty means.');
INSERT INTO badge_optional_requirements VALUES(5725,456,7,'Create a short skit about modesty and perform it for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(5726,456,8,'For one week, keep a list of immodest behavior demonstrated in the books your read and the movies and TV shows that you watch.  At the end of the week, review your list.  Could the author or director have still told the story if they had their characters behave in a more modest manner?  If not, was the story still worth telling?  Think about what you read and watch and whether or not you need to make changes in your own behavior.');
INSERT INTO badge_optional_requirements VALUES(5727,456,9,'Find and memorize quotes about modesty. Preschool: Memorize one quote. Levels 1-2: Memorize three quotes. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(5728,456,10,'Drugs and alcohol diminish the brain’s capacity for rational judgment and modest behavior.  Find at least 3 organizations committed to the elimination of underage drinking and drugs in your community. If possible, volunteer service to one of these organizations with parental permission.');
INSERT INTO badge_optional_requirements VALUES(5729,456,11,'Create a recipe for cooking up modesty.  What type of ingredients would you need?  Self control?  Modest clothing? Unselfishness?   What quantities would you need of each and how should they be mixed together?  Create recipe cards for your modesty recipe and give them to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(5730,456,12,'Write a short story about modesty.');
INSERT INTO badge_optional_requirements VALUES(5731,456,13,'Using the Victorian Language of flowers make a bouquet that symbolizes what modesty means to you.  You can find the meanings assigned to the flowers at various websites or in books and you may cut pictures from magazines or webpages to create a collage “bouquet”.  Make sure you include the name and meaning of each flower that you choose.  You may make a scrapbook page using pictures of flowers or make a bouquet using real or artificial flowers.');
INSERT INTO badge_optional_requirements VALUES(5732,456,14,'Interview 3 people of 3 different age groups and find out their views on modesty.  Come up with at least 10 interview questions to cover topics such as dress, language, television, etc.  Compare the answers you received to your own views and discuss them with a parent.');
INSERT INTO badge_optional_requirements VALUES(5733,456,15,'Look at our culture in America today and identify 6 areas in which modesty is frequently lacking.  What can you do in your own community to promote modest behavior?  Create a poster or flyer that promotes modesty and post it somewhere in your community with permission.');
INSERT INTO badge_optional_requirements VALUES(5734,456,16,'What does your book of worship say about modesty? Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(5735,456,17,'Take an article of immodest clothing and use it in an outfit in a modest but flattering way using layering or other techniques.');
INSERT INTO badge_optional_requirements VALUES(5736,456,18,'Write the word MODESTY on a piece of paper and then think of one faithful act that you could do that starts with each letter in the word. For example for “M”, you could put “Make other people feel appreciated” and for “O” you might put “Observe humility”.');
INSERT INTO badge_optional_requirements VALUES(5737,456,19,'Organize a “Modesty Fashion Show”. You can use your own clothing or find local businesses in town which carry stylish, but modest, clothing and ask them to participate.  Put on your show for a group of your choice.  A fun spin on this idea is to put on a fashion show that specializes in modest prom dresses. This could potentially be expanded into a fundraiser with a bit of creativity.');
INSERT INTO badge_optional_requirements VALUES(5738,456,20,'Make a piece of artwork that shows what modesty means to you.');
INSERT INTO badge_optional_requirements VALUES(5739,457,3,'Learn about crypto currency.  How does it differ from regular money?');
INSERT INTO badge_optional_requirements VALUES(5740,457,4,'Learn the differences between a loan and a line of credit.  What are the pros and cons of borrowing money?');
INSERT INTO badge_optional_requirements VALUES(5741,457,5,'Learn who is featured on each coin and monetary bill.');
INSERT INTO badge_optional_requirements VALUES(5742,457,6,'Determine if you are “spender” or a “saver”. If you are a spender, what can you do to help you save? Identify something you need or want and make a plan to save for it.');
INSERT INTO badge_optional_requirements VALUES(5743,457,7,'Earn the “budgeting” badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5744,457,8,'Learn one of the Jack Hartman money songs  (see resources)');
INSERT INTO badge_optional_requirements VALUES(5745,457,9,'Learn the difference between “needs” and “wants”. Make a list of things you want vs things you need.');
INSERT INTO badge_optional_requirements VALUES(5746,457,10,'Watch a video about how coins are minted or how dollars are printed.');
INSERT INTO badge_optional_requirements VALUES(5747,457,11,'Understand the concept of interest. Levels 3 and above should understand how to calculate compound interest.');
INSERT INTO badge_optional_requirements VALUES(5748,457,12,'Learn what investing is and how your money can make you even more money.  What are the risks of various investments?');
INSERT INTO badge_optional_requirements VALUES(5749,457,13,'Learn about loans and credit cards.  How can borrowing money cost you even more money?');
INSERT INTO badge_optional_requirements VALUES(5750,457,14,'Help someone count and roll coins to cash in at a bank.');
INSERT INTO badge_optional_requirements VALUES(5751,457,15,'Participate in a community service project involving money such as ringing bells for Salvation Army.');
INSERT INTO badge_optional_requirements VALUES(5752,457,16,'Earn the Banking badge at your level. Resources provided by  Cindy Lillemo.  Not all sources have been checked yet.  Please use at your own risk. Currency Coloring Pages: https://www.uscurrency.gov/sites/default/files/downloadable-materials/files/en/play-money-coloring-sheets-en.pdf Printable Play Money: https://www.uscurrency.gov/sites/default/files/downloadable-materials/files/en/printable-play-money-en.pdf Jack Hartman Jack Hartman Money Song Jack Hartman Show Me the Money www.juniorachievement.org www.jausa.ja.org/programs/index Junior Achievement Home Resources: https://sites.google.com/ja.org/ja-ed-resources/home Junior Achievement Saving Tips:  (https://drive.google.com/file/d/1KI4utocsRCSgWAZ5z3fO8ZoJvf_fyvX-/view?usp=drivesdk) www.education.com/games/money-math Currency Security Features: https://www.uscurrency.gov/sites/default/files/downloadable-materials/files/en/know-your-money-en.pdf How are coins made?: https://www.govmint.com/coin-authority/post/how-are-coins-made#:~:text=Initially%2C%20coins%20were%20made%20with%20a%20hammer%20and,hydraulic%20presses%20are%20used%20for%20minting%20today%E2%80%99s%20coinage. YouTube US Quarter Minting Process: https://www.youtube.com/watch?v=HRpRz2P4l2g Field Trip to the Money Factory: https://www.youtube.com/watch?v=-IBHbe-t-X4 How to write a check: www.thebalance.com/how-to-write-a-check Federal Regulation D: https://www.thebalance.com/what-is-regulation-d-5074854 What is a register: https://www.thebalance.com/use-check-registers-315289 8 Printable Checkbook Registers: https://www.examples.com/business/printable-checkbook-register-examples-pdf.html How to balance your account: https://www.thebalance.com/balance-checking-accounts-step-by-step-guide-315357#:~:text=Five%20Steps%20to%20Balance%20Your%20Checking%20Account%201,Numbers.%20…%205%20Fix%20Mistakes%20and%20Problems.%20 Bank vs. credit union: https://keydifferences.com/difference-between-credit-union-and-bank.html#:~:text=The%20significant%20differences%20between%20credit%20union%20and%20bank,operate%20in%20making%20profits.%20…%20More%20items…%20 Identity Theft: https://www.usa.gov/identity-theft');
INSERT INTO badge_optional_requirements VALUES(5753,458,3,'Send a message back and forth with a friend using a basic number cipher (a=1, b=2, c=3….).');
INSERT INTO badge_optional_requirements VALUES(5754,458,4,'Read a rescue story where Morse code was used.');
INSERT INTO badge_optional_requirements VALUES(5755,458,5,'Send a message back and forth with a friend using Morse code.');
INSERT INTO badge_optional_requirements VALUES(5756,458,6,'Learn numbers 1-10 in Morse code.');
INSERT INTO badge_optional_requirements VALUES(5757,458,7,'Listen to a simple recording in Morse code and try to translate.');
INSERT INTO badge_optional_requirements VALUES(5758,458,8,'What is a telegraph? When and how was the telegraph used? What replaced it?');
INSERT INTO badge_optional_requirements VALUES(5759,458,9,'Build your own telegraph using a 9 volt battery.');
INSERT INTO badge_optional_requirements VALUES(5760,458,10,'Where is Morse code used today?');
INSERT INTO badge_optional_requirements VALUES(5761,458,11,'Is Morse code the same in other parts of the world? Where else is it used?');
INSERT INTO badge_optional_requirements VALUES(5762,458,12,'Learn to do Morse code using flags.');
INSERT INTO badge_optional_requirements VALUES(5763,459,3,'Make a paper mosaic.');
INSERT INTO badge_optional_requirements VALUES(5764,459,4,'Make a mosaic out of dyed eggs shells.');
INSERT INTO badge_optional_requirements VALUES(5765,459,5,'Make a mosaic out of tiles.');
INSERT INTO badge_optional_requirements VALUES(5766,459,6,'Make a mosaic out of food items such as beans or dried pasta.');
INSERT INTO badge_optional_requirements VALUES(5767,459,7,'Make a mosaic out of stickers.');
INSERT INTO badge_optional_requirements VALUES(5768,459,8,'Make a mosaic out of glass (This requirement should be done under direct supervision of an adult).');
INSERT INTO badge_optional_requirements VALUES(5769,459,9,'Participate in a community service project that involves a mosaic.  Examples might include creating a mosaic mural or table top in a public area or making mosaic notecards to sell at a craft fair to make money for a charity.');
INSERT INTO badge_optional_requirements VALUES(5770,459,10,'Learn about a career that has to do with mosaics.  Examples might include a museum curator or an artist. What type of education do you need?  What type of pay could you expect?  Where might you have to live? If possible, shadow someone for a day in one of these careers.');
INSERT INTO badge_optional_requirements VALUES(5771,459,11,'Visit an art exhibit that includes mosaics.');
INSERT INTO badge_optional_requirements VALUES(5772,459,12,'Visit an artist that creates mosaics.');
INSERT INTO badge_optional_requirements VALUES(5773,460,3,'Write a play based on a movie. If you are doing a specific movie, the play must be about that movie.');
INSERT INTO badge_optional_requirements VALUES(5774,460,4,'Participate in a community service project involving movies.  Ideas might include collecting DVD’s to donate to our soldiers overseas, holding a community movie night at your school or church, etc.');
INSERT INTO badge_optional_requirements VALUES(5775,460,5,'Learn about product licensing.  What kind of products are licensed to use the name and images from your movie?  Toys?  Clothing?  Housewares?');
INSERT INTO badge_optional_requirements VALUES(5776,460,6,'Make a short movie using a video camera.');
INSERT INTO badge_optional_requirements VALUES(5777,460,7,'Read the book (if there is one) that the movie you watched or are learning about. Write a short essay about the differences and similarities.');
INSERT INTO badge_optional_requirements VALUES(5778,460,8,'Find out the following facts about the movie you are learning about:  When was it made? Who directed and produced it?  What other movies has this director and producer made?  Who starred in it? What else have they starred in?  How much money did it gross? Where is it available and in what forms?');
INSERT INTO badge_optional_requirements VALUES(5779,460,9,'Learn a dance, make a recipe, or learn a skill based on something you saw in your movie.');
INSERT INTO badge_optional_requirements VALUES(5780,460,10,'Make a list of movie genres (such as Romance, Western, etc.). Watch a movie from a genre you don’t typically watch. If you are working on a specific movie, determine which genre your movie is from and choose to watch a movie from another genre.');
INSERT INTO badge_optional_requirements VALUES(5781,460,11,'Determine who your favorite actor or actress is in your movie and 1) make a list of movies they’ve been in and 2) do a biographical sketch.');
INSERT INTO badge_optional_requirements VALUES(5782,460,12,'Research careers related to the movie-making industries other than actor/actress.');
INSERT INTO badge_optional_requirements VALUES(5783,460,13,'Define these movie-related terms: Set Director Wardrobe Choreography Cinematography Producer Animation CGI Claymation Grip Make a list of 10 more movie-related terms and define them.');
INSERT INTO badge_optional_requirements VALUES(5784,460,14,'Make a list of quotes from your movie. Choose one to artistically decorate.');
INSERT INTO badge_optional_requirements VALUES(5785,460,15,'Make a list of the various awards related to movies. Find a televised showing of one of these award events either on television or YouTube (with a parent’s permission) and watch it.');
INSERT INTO badge_optional_requirements VALUES(5786,460,16,'Watch an original movie and its remake. What are the differences and similarities? Write a short essay. If you are working on a specific movie, make sure you watch its original and its remake.');
INSERT INTO badge_optional_requirements VALUES(5787,462,3,'Visit or write a report about the museum.');
INSERT INTO badge_optional_requirements VALUES(5788,462,4,'Volunteer or work at your museum.');
INSERT INTO badge_optional_requirements VALUES(5789,462,5,'Explain why you should show respect when visiting a museum.');
INSERT INTO badge_optional_requirements VALUES(5790,462,6,'Make up a puzzle or game using facts about something you would find in the museum.');
INSERT INTO badge_optional_requirements VALUES(5791,462,7,'Draw a picture or take a picture of you at the museum.');
INSERT INTO badge_optional_requirements VALUES(5792,462,8,'Make a scrapbook with facts, pictures and photos of the museum.');
INSERT INTO badge_optional_requirements VALUES(5793,462,9,'Learn about careers that might involve the making or upkeep of the museum.');
INSERT INTO badge_optional_requirements VALUES(5794,462,10,'What type of architecture was used when the museum was built?');
INSERT INTO badge_optional_requirements VALUES(5795,462,11,'If you plan to visit your museum, locate your travel destination on a map. How far is it from your home? How will you travel there? How long will it take? Make a plan for keeping yourself busy during travel so that you do not get bored. Level 3 and Up: Know the costs involved in traveling to this destination.');
INSERT INTO badge_optional_requirements VALUES(5796,462,12,'Learn about a legend or myth that has to do with your museum.');
INSERT INTO badge_optional_requirements VALUES(5797,462,13,'Learn about what makes your museum special. Does it have outdoor exhibits as well as indoor exhibits? Is it known for a certain exhibit most? Why is the museum important to the community it is built in?');
INSERT INTO badge_optional_requirements VALUES(5798,462,14,'Watch a documentary or read a book about your museum.');
INSERT INTO badge_optional_requirements VALUES(5799,464,3,'Learn all the words to a song of at least five verses and five choruses. If you want, sing them to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(5800,464,4,'Attend a musical performance, such as a concert, recital or choir performance, and learn one of the songs from it. Tell your family, friends, or group about it. What did you like or not like?');
INSERT INTO badge_optional_requirements VALUES(5801,464,5,'Create four different playlists with your favorite music. Maybe they are sorted to mood, an activity, or a genre of music.');
INSERT INTO badge_optional_requirements VALUES(5802,464,6,'Perform a song or play an instrument in a local musical show/program.');
INSERT INTO badge_optional_requirements VALUES(5803,464,7,'Learn the history of a certain instrument, such as the violin, piano, etc. Talk to someone who plays your instrument. Why did they choose it? Listen to a piece of music where your instrument either plays solo (such as Mozart’s Piano Concerto 21) or plays a vital role.');
INSERT INTO badge_optional_requirements VALUES(5804,464,8,'Earn the Singing badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5805,464,9,'Look at a diagram of an orchestra and find where the different instrument families are located. If you play an instrument, where would you sit in an orchestra?');
INSERT INTO badge_optional_requirements VALUES(5806,464,10,'Learn about an instrument from another land such as the bagpipes from Scotland or the castanets from Spain.  Listen to a piece of music that includes your chosen instrument.');
INSERT INTO badge_optional_requirements VALUES(5807,464,11,'Learn about careers in the music business, such as a composer, a dancer, a music teacher, a conductor, an instrument maker, a singer or a musician.  How much pay could you expect, what hours would you keep, etc?  If possible, shadow someone for a day who works for a living in the music business.');
INSERT INTO badge_optional_requirements VALUES(5808,464,12,'Listen to examples of at least three different types of dance music, such as foxtrot, cha-cha, polka, waltz, or swing.  Which did you like best?');
INSERT INTO badge_optional_requirements VALUES(5809,464,13,'Earn Vocal Music by Genre or Instrumental Music by Genre at your level.');
INSERT INTO badge_optional_requirements VALUES(5810,464,14,'Watch a musical such as The Sound of Music or Hello Dolly! with your family, friends, or group and learn at least one song from it.  How has Hollywood had an impact on music over the last century?');
INSERT INTO badge_optional_requirements VALUES(5811,464,15,'Be able to recognize or “pick out” the sounds of at least 3 different instruments, such as piano, fiddle, drums, etc. when listening to a piece of music.');
INSERT INTO badge_optional_requirements VALUES(5812,464,16,'Make a list of at least 12 composers and put them in chronological order.  Learn about one of them, and listen to at least 2 pieces of their music.Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(5813,464,17,'Earn the Musical Instrument (Specific) badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5814,465,3,'Create a collage or poster of at least 20 different musical instruments.');
INSERT INTO badge_optional_requirements VALUES(5815,465,4,'Earn the Music History badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5816,465,5,'Visit a musical instrument store and find out what instruments are the most popular. What is their cost range? Where might you be able to get lessons?');
INSERT INTO badge_optional_requirements VALUES(5817,465,6,'Discuss the use of lyrics in a song. How do lyrics make you feel?');
INSERT INTO badge_optional_requirements VALUES(5818,465,7,'Attend or watch a video of a concert of any musical style. This requirement may be repeated with different genres of music.');
INSERT INTO badge_optional_requirements VALUES(5819,465,8,'Visit a museum or exhibit of music or musical instruments.');
INSERT INTO badge_optional_requirements VALUES(5820,465,9,'Make a musical instrument of your own.');
INSERT INTO badge_optional_requirements VALUES(5821,465,10,'Learn to sing a song from at least three different musical styles or eras.');
INSERT INTO badge_optional_requirements VALUES(5822,465,11,'Participate in a community service project that involves music. Examples might include Christmas caroling at a nursing home, playing an instrument in a free concert, singing in your church choir, or teaching younger kids some new songs or how to play an instrument');
INSERT INTO badge_optional_requirements VALUES(5823,465,12,'Learn about careers involving music appreciation. Examples might include auditorium mangers, event coordinators, music producers, professional musicians, etc. What education and training might you need? What salary could you expect? What hours might you have to work? Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(5824,465,13,'Watch a musical either on film or on stage.');
INSERT INTO badge_optional_requirements VALUES(5825,465,14,'Attend an opera or watch one on video (with parental permission).');
INSERT INTO badge_optional_requirements VALUES(5826,465,15,'Watch a silent movie. What role did the music play? Discuss how music can be an important part of storytelling.');
INSERT INTO badge_optional_requirements VALUES(5827,466,3,'Identify and name at least five famous music box makers and their contributions to the field.');
INSERT INTO badge_optional_requirements VALUES(5828,466,4,'Visit a museum or exhibition featuring music boxes.');
INSERT INTO badge_optional_requirements VALUES(5829,466,5,'Create a music box using a kit or parts, and demonstrate how it works.');
INSERT INTO badge_optional_requirements VALUES(5830,466,6,'Design your own music box.  What would it be made of?  What would it look like?  What mechanism would it use?  What song would it play?');
INSERT INTO badge_optional_requirements VALUES(5831,466,6,'Visit a music box shop and interview the owner or staff about their knowledge of music boxes.  Where did they gain that knowledge?');
INSERT INTO badge_optional_requirements VALUES(5832,466,7,'Demonstrate the ability to repair a music box, including replacing broken parts and cleaning the mechanism.');
INSERT INTO badge_optional_requirements VALUES(5833,466,8,'Write a fictional story featuring a music box as a central element of the plot.');
INSERT INTO badge_optional_requirements VALUES(5834,466,9,'Demonstrate an understanding of the care and maintenance required for music boxes, including proper storage and cleaning techniques.');
INSERT INTO badge_optional_requirements VALUES(5835,466,10,'Create a quiz or trivia game about music boxes, including their history and unique features.');
INSERT INTO badge_optional_requirements VALUES(5836,466,11,'Research the different styles of music boxes, including those with figurines and those with different shapes and sizes. Identify different products that use music boxes such as jewelry boxes, toys, or sculptures.');
INSERT INTO badge_optional_requirements VALUES(5837,466,12,'Research and present on the different materials used to make music boxes throughout history.');
INSERT INTO badge_optional_requirements VALUES(5838,466,13,'Create a timeline of significant events in the history of music boxes.');
INSERT INTO badge_optional_requirements VALUES(5839,466,14,'Research the role of music boxes in popular culture, such as in movies, books, and TV shows.  Level 3 and above, discuss why music boxes are frequently used in horror films.  What is it about their sound that makes them popular in this genre?');
INSERT INTO badge_optional_requirements VALUES(5840,466,15,'Research different types of music box collectors and their motivations.');
INSERT INTO badge_optional_requirements VALUES(5841,466,16,'Create a display or exhibit featuring your personal collection of music boxes.');
INSERT INTO badge_optional_requirements VALUES(5842,466,17,'Write a research paper on a specific topic related to music boxes, such as the history of a particular maker or the use of music boxes in a specific culture.');
INSERT INTO badge_optional_requirements VALUES(5843,466,18,'Identify and name at least five famous songs that have been adapted for music boxes.  What songs seem to be the most popular on music boxes?');
INSERT INTO badge_optional_requirements VALUES(5844,466,19,'Attend a workshop or class on making music boxes, and create your own unique design.');
INSERT INTO badge_optional_requirements VALUES(5845,466,20,'Learn about the music boxes built into some of the famous Faberge Eggs.');
INSERT INTO badge_optional_requirements VALUES(5846,466,21,'Create a collage or scrapbook featuring images of different types of music boxes and their history.');
INSERT INTO badge_optional_requirements VALUES(5847,466,22,'Identify and name at least five famous music box museums around the world.');
INSERT INTO badge_optional_requirements VALUES(5848,467,3,'Read a biography of one of the members of your chosen band. Would you choose to be this person if you could?');
INSERT INTO badge_optional_requirements VALUES(5849,467,4,'Learn about any awards your chosen band has won, such as the CMA awards or the Grammys. When, and for which song?');
INSERT INTO badge_optional_requirements VALUES(5850,467,5,'Know what each member of your chosen band contributes to the whole, such as singing or playing instruments. For any band member who plays an instrument, know which instruments they play.');
INSERT INTO badge_optional_requirements VALUES(5851,467,6,'Meet a member of your chosen band.');
INSERT INTO badge_optional_requirements VALUES(5852,467,7,'Being polite at a concert is very important, and shows respect for both the performers and the rest of the audience. Learn audience etiquette.');
INSERT INTO badge_optional_requirements VALUES(5853,467,8,'With your parent’s permission, go online to find out what sort of memorabilia is available for your chosen band.');
INSERT INTO badge_optional_requirements VALUES(5854,467,9,'Learn fun facts about your chosen band. Preschool: Learn one fun fact. Levels 1-2: Learn three fun facts. Levels 3-4: Learn five. Level 5: Learn eight.');
INSERT INTO badge_optional_requirements VALUES(5855,467,10,'Meet someone who works behind the scenes for your chosen band. What is their job? How do they help make the band run smoothly?');
INSERT INTO badge_optional_requirements VALUES(5856,467,11,'Earn either the Instrumental Music by Genre or Vocal Music by Genre badge for your band’s genre at your level.');
INSERT INTO badge_optional_requirements VALUES(5857,467,12,'Attend one of your band’s concerts.');
INSERT INTO badge_optional_requirements VALUES(5858,467,13,'Does your band have a grant foundation? Find out what kinds of groups/projects your band supports, how they select grant recipients, how they raise money for the grants.');
INSERT INTO badge_optional_requirements VALUES(5859,467,14,'Write an essay about what you like about your favorite band and the kind of music they play.');
INSERT INTO badge_optional_requirements VALUES(5860,467,15,'Earn the Musical Instrument (Specific) badge for an instrument that is used in your chosen band’s music.');
INSERT INTO badge_optional_requirements VALUES(5861,467,16,'Do any of your band members have charities? Learn about any. If possible, do a service project to help one of them.');
INSERT INTO badge_optional_requirements VALUES(5862,467,17,'Learn what goes into creating a band and what career can be made out of being a band member.');
INSERT INTO badge_optional_requirements VALUES(5863,467,18,'Learn the names of any former band members and be able to recognize them in a photograph.');
INSERT INTO badge_optional_requirements VALUES(5864,467,19,'Earn the Singing badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5865,468,3,'Pick two musical periods (preferably consecutive ones) and learn about the differences between them. Were there different instruments that were invented during those periods? Was there a certain composer that greatly influenced the change in styles?');
INSERT INTO badge_optional_requirements VALUES(5866,468,4,'What kind of careers are available if you wanted to go into music history? What kind of education must you acquire? How much does the average individual get paid in one of those jobs?');
INSERT INTO badge_optional_requirements VALUES(5867,468,5,'What is the difference between folk songs and classical music? How have folk songs influenced composers? Are there any specific composers that took folk songs and made them their own?');
INSERT INTO badge_optional_requirements VALUES(5868,468,6,'Earn the Music, Music Appreciation, or Musical Instrument (Specific) badge at your level. Each one counts as a separate requirement.');
INSERT INTO badge_optional_requirements VALUES(5869,468,7,'Learn about the modern period. What makes songs by impressionist, blues, jazz, and rock and roll composers different from each other?');
INSERT INTO badge_optional_requirements VALUES(5870,468,8,'How has music been used politically? Are there countries in which songs have been banned for too skeptical or broad an outlook?');
INSERT INTO badge_optional_requirements VALUES(5871,468,9,'What countries are most famous for their music? Why? Level 3 and Up: Find out where most classical composers, verses modern composers are from.');
INSERT INTO badge_optional_requirements VALUES(5872,468,10,'Create a game of some sort to help others learn the composers and their eras. Can be a crossword puzzle, board game, a puzzle, word find, etc.');
INSERT INTO badge_optional_requirements VALUES(5873,468,11,'Create a timeline of musical styles. Include at least 15 different musical styles such as: Classical Jazz Dixieland Jazz Pop Rock Country Folk HipHop A cappella Beat boxing Blues Cadence Celtic Cinematic Opera Hymns Big Band New Age Patriotic Polka Praise Songs Ragtime Salsa Reggae Gospel Tribal Chants');
INSERT INTO badge_optional_requirements VALUES(5874,468,12,'Make a collage of composers or instruments through-out history.');
INSERT INTO badge_optional_requirements VALUES(5875,468,13,'What does your book of faith say about music? How has music been used in your religion through-out the years?  Has it changed at all?');
INSERT INTO badge_optional_requirements VALUES(5876,468,14,'Research the history of travel music, folk songs, or Gregorian chants.  How did they come into existence?');
INSERT INTO badge_optional_requirements VALUES(5877,468,15,'Research pre-baroque era music. Can you find any recordings of Renaissance music?  Does anyone still perform that type of music?');
INSERT INTO badge_optional_requirements VALUES(5878,468,16,'Research the history of one particular music genre. How has it progressed over the years? Where there any spin-offs of it? Try and find a recording of an early performance and then a later one.');
INSERT INTO badge_optional_requirements VALUES(5879,468,17,'Research cultural responses to different genres of music. Why were they rejected or accepted?');
INSERT INTO badge_optional_requirements VALUES(5880,468,18,'Learn the musical history of a country or specific region. How has their music evolved over time? What genre of music was most popular/traditional in the beginning? What about now?');
INSERT INTO badge_optional_requirements VALUES(5881,470,3,'Cemeteries and graveyards can be rich sources of information about the community. Visit the cemetery or graveyard in your community and look at the gravestones. Pay attention to when the person was born and when they died, and work out how old they were when they died. Do certain years seem to have more deaths in them than others? Which families have the most members buried there?');
INSERT INTO badge_optional_requirements VALUES(5882,470,4,'Look at street names in your community. Are any of them named after people? Choose three people who have streets in your community named after them, and find out about them.');
INSERT INTO badge_optional_requirements VALUES(5883,470,5,'Talk to someone who has lived in your community for at least 25 years.  What sort of happenings have they seen?  What do they think was the most important event?  Which affected them most?');
INSERT INTO badge_optional_requirements VALUES(5884,470,6,'Drive through your community and make a list of all the businesses you see.  Go back fifty years, or as far back as you can, and find out which businesses were in your town then.  Are any of them still in business? Which business in your community has been there the longest?');
INSERT INTO badge_optional_requirements VALUES(5885,470,7,'Look at a picture of your community when it was much younger. How big is it compared to its present size?  Can you recognize any of the places shown in the picture?');
INSERT INTO badge_optional_requirements VALUES(5886,470,8,'Participate in a service project to help your community in some way.  For instance, you could organize a food drive to help your local food bank, or clean up a city park.');
INSERT INTO badge_optional_requirements VALUES(5887,470,9,'The “downtown” part of town is usually the oldest part.  Visit the downtown part of your town.  How different is it from the newer parts of town?');
INSERT INTO badge_optional_requirements VALUES(5888,470,10,'Many older parts of towns have brick streets.  Read a book, watch a video, or go online (with your parent’s permission) to find out how brick streets are made.');
INSERT INTO badge_optional_requirements VALUES(5889,470,11,'Visit a museum that showcases items from your town or community’s history.  Which is your favorite part?');
INSERT INTO badge_optional_requirements VALUES(5890,470,12,'Visit a different community from the one you live in. What similarities are there? How is it different?');
INSERT INTO badge_optional_requirements VALUES(5891,470,13,'Learn about a career of leadership in your community (mayor, city council member, etc.). What is required of such a person? What salary can they expect? What is involved in obtaining such a position?');
INSERT INTO badge_optional_requirements VALUES(5892,470,14,'Visit at least two local restaurants and taste at least one dish from each. What makes the local restaurants in your community special?');
INSERT INTO badge_optional_requirements VALUES(5893,470,15,'Visit your town’s farmer’s market. What local produce and products can you buy?');
INSERT INTO badge_optional_requirements VALUES(5894,471,4,'Identity the differences between a Unicorn, Pegasus, Earth Pony, and Alicorn.');
INSERT INTO badge_optional_requirements VALUES(5895,471,5,'Read the My Little Pony books. Preschool: Read one book. Levels 1-2: Read three books. Levels 3-4: Read five. Level 5: Read eight.');
INSERT INTO badge_optional_requirements VALUES(5896,471,6,'Make a friendship card using the My Little Pony characters.');
INSERT INTO badge_optional_requirements VALUES(5897,471,7,'Earn a Character badge attached to the Elements of Harmony.');
INSERT INTO badge_optional_requirements VALUES(5898,471,8,'Learn about Spike. What animal is he? How did Twilight get him? What does he eat? How does he help Twilight?');
INSERT INTO badge_optional_requirements VALUES(5899,471,9,'Make your own My Little Pony friendship game. Play it with a friend or family member.');
INSERT INTO badge_optional_requirements VALUES(5900,471,10,'Have a My Little Pony friendship party. Make snacks, decorations, or games themed to the show.');
INSERT INTO badge_optional_requirements VALUES(5901,471,11,'Watch a My Little Pony Equestria Girls movie. What lessons did you learn?');
INSERT INTO badge_optional_requirements VALUES(5902,471,12,'Who are the Cutie Mark Crusaders? What are they trying to do? Who are the bullies? Why do you think getting a cutie mark is important to ponies?');
INSERT INTO badge_optional_requirements VALUES(5903,471,13,'The six main ponies each have a pet. What kind of animals are they and what are their names? Discuss which one you would want as a pet.');
INSERT INTO badge_optional_requirements VALUES(5904,471,14,'Play one of the My Little Pony video games.');
INSERT INTO badge_optional_requirements VALUES(5905,471,15,'Who are Princess Celestia and Princess Luna? What are their jobs? How did Princess Luna change to Nightmare Moon? How did she change back into Princess Luna?');
INSERT INTO badge_optional_requirements VALUES(5906,471,16,'Learn what a Cutie Mark is and make your own original cutie mark. What is the meaning behind your cutie mark? How does it relate to yourself?');
INSERT INTO badge_optional_requirements VALUES(5907,471,17,'Write a report on each villain in My Little Pony. Write on how they are different, their reason for being evil, what their powers are, and what they look like. Also, note whether they were changed to good, imprisoned or destroyed.');
INSERT INTO badge_optional_requirements VALUES(5908,471,18,'Learn about which ponies they kept from the original generations and brought into Friendship is Magic. Which characters did they not keep? Why do you think they kept the ones they did and didn’t keep others?');
INSERT INTO badge_optional_requirements VALUES(5909,471,19,'Make your own original pony with clay. Give it a name, a cutie mark and a personality.');
INSERT INTO badge_optional_requirements VALUES(5910,471,20,'Write a brief description of Spike’s ancestors. What did they act like? Where did they live? How was their appearance different than Spike? Why is this?');
INSERT INTO badge_optional_requirements VALUES(5911,471,21,'Make a replica of the current Equestria map, including the names of villages, rivers and mountains.');
INSERT INTO badge_optional_requirements VALUES(5912,471,23,'Watch My Little Pony: The Movie. How did it compare to the original show? How did the animation differ?');
INSERT INTO badge_optional_requirements VALUES(5913,471,23,'Although My Little Pony: Friendship is Magic has ended, this does not mean that the franchise is no longer alive. Learn about any new show(s) and movie(s) that are either out or in development.');
INSERT INTO badge_optional_requirements VALUES(5914,472,3,'Know how many community service projects your troop is supposed to participate in each year and why.  Participate in each service project your troop chooses to do.');
INSERT INTO badge_optional_requirements VALUES(5915,472,4,'Play “Bet Ya Didn’t Know”.  Each member of the troop starts a sentence with the words, bet ya didn’t know, and then completes the sentence with something about themselves that they don’t think anyone else in the group knows about them.  For example, Bet ya didn’t know that I love guacamole, but hate avocados; bet ya didn’t know I used to live in Florida; bet ya didn’t know that I collect model horses, etc.');
INSERT INTO badge_optional_requirements VALUES(5916,472,5,'Create a troop scrapbook.');
INSERT INTO badge_optional_requirements VALUES(5917,472,6,'Write a troop song or chant.');
INSERT INTO badge_optional_requirements VALUES(5918,472,7,'Come up with a unique troop greeting.');
INSERT INTO badge_optional_requirements VALUES(5919,472,8,'Help to plan or decorate for a troop ceremony.');
INSERT INTO badge_optional_requirements VALUES(5920,472,9,'Know who founded Frontier Girls and when.  Know the year your troop was founded and by whom.');
INSERT INTO badge_optional_requirements VALUES(5921,472,10,'Create a troop quilt with one square representing each girl in the troop.');
INSERT INTO badge_optional_requirements VALUES(5922,472,11,'Create a troop banner or flag for parades and events.');
INSERT INTO badge_optional_requirements VALUES(5923,472,12,'Participate in a troop campout.');
INSERT INTO badge_optional_requirements VALUES(5924,472,13,'Memorize the Frontier Girls Creed.');
INSERT INTO badge_optional_requirements VALUES(5925,472,14,'Make a list of every place in  your community that your troop could go to have fun, do new activities, take field trips, or do community service.');
INSERT INTO badge_optional_requirements VALUES(5926,472,15,'Make an exhibit that tells people about your troop.');
INSERT INTO badge_optional_requirements VALUES(5927,472,16,'Earn the Teamwork badge.');
INSERT INTO badge_optional_requirements VALUES(5928,472,17,'Help the leaders in your troop by either leading some songs, games, or activities for the other members of your troop. (Eagles and Owls only)');
INSERT INTO badge_optional_requirements VALUES(5929,473,3,'Give a presentation about the creature or make a display about your creature. Show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(5930,473,4,'Does your creature have a scientific name? What you you think it would be? Would it be a reptile, amphibian, mammal, bird, fish or insect? Is it an inverbrate? Vertebrate?');
INSERT INTO badge_optional_requirements VALUES(5931,473,5,'Your mythological creature may be the result of a misunderstanding. For instance, narwhal horns were often said to be unicorn horns. Is there a record of how your mythological creature may have come to be? If not, how or why do you think people created this creature?');
INSERT INTO badge_optional_requirements VALUES(5932,473,6,'Earn the Fantasy badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5933,473,7,'Earn the Mythology badge at your level.');
INSERT INTO badge_optional_requirements VALUES(5934,473,8,'Participate in a community service project that involves mythological creatures in some way such as volunteering to help at a Renaissance or Celtic faire.');
INSERT INTO badge_optional_requirements VALUES(5935,473,9,'Create a model, draw a picture, or make a craft of your creature. Show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(5936,473,10,'Does your creature, or a similar creature, appear in other cultures? How do they compare?');
INSERT INTO badge_optional_requirements VALUES(5937,474,3,'Learn about the history of the Parthenon.  Where is it located?  How old is it?  How was it designed?  Look at pictures of the Parthenon and understand its importance in early Greek culture.');
INSERT INTO badge_optional_requirements VALUES(5938,474,4,'Create a meal that represents a specific mythology.  For example if you are learning about Greek mythology, you might have hummus and pita bread, olives, or grapes.');
INSERT INTO badge_optional_requirements VALUES(5939,474,5,'Play a game that helps you learn about mythology.');
INSERT INTO badge_optional_requirements VALUES(5940,474,6,'Create a display of some type to show what you have learned about mythology.  This could be a poster, 3D diorama, booklet, etc.');
INSERT INTO badge_optional_requirements VALUES(5941,474,7,'Participate in a skit or play about a specific myth.');
INSERT INTO badge_optional_requirements VALUES(5942,474,8,'Create a craft that represents a specific mythology.');
INSERT INTO badge_optional_requirements VALUES(5943,474,9,'Create a board game with a mythology theme.  Make sure to include a variety of characters and facts within your game.');
INSERT INTO badge_optional_requirements VALUES(5944,474,10,'Many words and sayings we use today have their roots in mythology.  Learn what it means to have an “Achilles Heel”, to make a “Herculean Effort”, to take on a “Sisyphean task”, to have something “Tantalize” you, or to see a “Titanic” object.');
INSERT INTO badge_optional_requirements VALUES(5945,474,11,'Visit a museum or art gallery that has displays inspired by mythology.');
INSERT INTO badge_optional_requirements VALUES(5946,474,12,'Create a panel mural depicting one of your favorite myths.');
INSERT INTO badge_optional_requirements VALUES(5947,474,13,'Mythology is still referenced today, especially in advertising.   Make a list of as many myth references as you can find in your day to day life (TV or magazine commercials, words, sayings, etc.). Discuss why you think these myths were used?  What message do they still convey today?  For example, why would a magazine choose to call itself Daedalus?  Why would you use the image of Hermes (Mercury) for a delivery service?  Create an advertising flyer for the product of your choice using a mythology reference.');
INSERT INTO badge_optional_requirements VALUES(5948,474,14,'Choose a character from mythology and create a family tree for them.');
INSERT INTO badge_optional_requirements VALUES(5949,474,15,'Read at least three mythology inspired poems.');
INSERT INTO badge_optional_requirements VALUES(5950,474,16,'Conduct mock interviews with the gods.  Have one person play the god (or goddess) and have another person interview them.  What type of questions would you have for a god or goddess?  How do you think  they would respond?');
INSERT INTO badge_optional_requirements VALUES(5951,474,17,'Read a book or watch a movie that has a modern retelling of a myth or focuses on mythological characters, such as Rick Riordan’s Percy Jackson series. How does it compare to the original tale?');
INSERT INTO badge_optional_requirements VALUES(5952,475,3,'Read or listen to a story about how the world was created according to the mythology.');
INSERT INTO badge_optional_requirements VALUES(5953,475,4,'Learn about a sacred place or landmark related to the mythology (e.g., Mount Olympus, Yggdrasil, or the River Styx).');
INSERT INTO badge_optional_requirements VALUES(5954,475,5,'Write a short mythological story using characters or creatures from the mythology.');
INSERT INTO badge_optional_requirements VALUES(5955,475,6,'Discuss the attributes (e.g., wisdom, strength) of two gods or goddesses and what they represent.');
INSERT INTO badge_optional_requirements VALUES(5956,475,7,'Draw or create an artistic representation of a god, creature, or mythological event.');
INSERT INTO badge_optional_requirements VALUES(5957,475,8,'Research two legendary objects or artifacts from the mythology (e.g., Thor’s hammer, the Holy Grail).');
INSERT INTO badge_optional_requirements VALUES(5958,475,9,'Compare a myth from your chosen culture with one from another culture (e.g., compare Greek Zeus and Roman Jupiter).');
INSERT INTO badge_optional_requirements VALUES(5959,475,10,'Identify ways in which this mythology has influenced modern culture (e.g., names of planets, movies, books).');
INSERT INTO badge_optional_requirements VALUES(5960,475,11,'Learn about one ancient festival or ritual related to your chosen mythology.');
INSERT INTO badge_optional_requirements VALUES(5961,475,12,'Create a simple timeline showing major events in the mythology (e.g., wars, births of gods).');
INSERT INTO badge_optional_requirements VALUES(5962,475,13,'Create a small diorama or model of a famous mythological scene or location.');
INSERT INTO badge_optional_requirements VALUES(5963,475,14,'Design your own mythical creature inspired by the chosen culture’s mythology.');
INSERT INTO badge_optional_requirements VALUES(5964,475,15,'Learn how the mythology connects to or influenced the culture’s ancient religion.');
INSERT INTO badge_optional_requirements VALUES(5965,475,16,'Role-play as a character from a myth in a fun, short skit.');
INSERT INTO badge_optional_requirements VALUES(5966,475,17,'Learn how the chosen mythology explains natural phenomena (e.g., why the sun rises or where storms come from).');
INSERT INTO badge_optional_requirements VALUES(5967,475,18,'Explore a map of an ancient world related to the mythology (e.g., Odysseus’ journey, the Nine Realms in Norse myths).');
INSERT INTO badge_optional_requirements VALUES(5968,475,19,'Look at various pieces of art, sculpture, or architecture inspired by your mythology.');
INSERT INTO badge_optional_requirements VALUES(5969,476,3,'Check out several books from your library about nail art.  Study the various techniques.');
INSERT INTO badge_optional_requirements VALUES(5970,476,4,'With a parent’s permission, search for blogs and videos that teach various nail art techniques.  Find at least five and, if able, attempt at least one.');
INSERT INTO badge_optional_requirements VALUES(5971,476,5,'Learn about and describe some of the tools used in nail art such as brushes, pens, stencils, stamps, decals, glitter, gems, etc.');
INSERT INTO badge_optional_requirements VALUES(5972,476,6,'Nail art brushes can be purchased inexpensively at a beauty supply store or online.  Consider purchasing some brushes and trying some of the techniques you have learned on friends and family.  If friends and family do not wish to have their nails done, you can also purchase a manikin hand or fake fingers to practice on for not much money.');
INSERT INTO badge_optional_requirements VALUES(5973,476,7,'Learn about and/or experiment with magnetic nail art.');
INSERT INTO badge_optional_requirements VALUES(5974,476,8,'Arrange a visit to a nail salon and ask the nail technicians about the training and education they needed to get their job.  If possible, watch them perform some of their tasks on the job.  Note their attention to cleanliness.  Why is cleanliness so important at a nail salon?');
INSERT INTO badge_optional_requirements VALUES(5975,476,9,'Learn about nail fungus and how to prevent and treat it.');
INSERT INTO badge_optional_requirements VALUES(5976,476,10,'Provide service to the community by offering to share your new skills with the elderly, home bound, or possibly a women’s shelter.  Avoid using any sharp tools or objects on others, unless you are a trained nail technician.  Stick to just polish for now.');
INSERT INTO badge_optional_requirements VALUES(5977,476,11,'Share what you have learned with your family, friends, or group and do their nails with permission.');
INSERT INTO badge_optional_requirements VALUES(5978,476,12,'Some polishes contain formaldehyde, dibutyl phthalate (DBP), and toluene. Research these chemicals and their possible side effects.  Identify at least three brands of polish that do not use these chemicals and compare their prices to brands that do use them. Discuss possible pros and cons of using nail polishes without these chemicals.');
INSERT INTO badge_optional_requirements VALUES(5979,477,3,'Learn the Bishop’s Hat fold.');
INSERT INTO badge_optional_requirements VALUES(5980,477,4,'Learn the Pyramid fold.');
INSERT INTO badge_optional_requirements VALUES(5981,477,5,'Learn the Crown fold.');
INSERT INTO badge_optional_requirements VALUES(5982,477,6,'Learn the Fan fold (standing or flat).');
INSERT INTO badge_optional_requirements VALUES(5983,477,7,'Learn the Rose fold (rolled style).');
INSERT INTO badge_optional_requirements VALUES(5984,477,8,'Fold a napkin into an animal shape such as a swan or bunny.');
INSERT INTO badge_optional_requirements VALUES(5985,477,9,'Fold a napkin into a flower other than a rose.');
INSERT INTO badge_optional_requirements VALUES(5986,477,10,'Try a themed holiday napkin fold (e.g., tree for Christmas, heart for Valentine’s).');
INSERT INTO badge_optional_requirements VALUES(5987,477,11,'Fold a napkin to resemble silverware pockets in at least two different styles.');
INSERT INTO badge_optional_requirements VALUES(5988,477,12,'Design your own original napkin fold and name it.');
INSERT INTO badge_optional_requirements VALUES(5989,477,13,'Use a napkin ring in three creative ways to enhance your fold.');
INSERT INTO badge_optional_requirements VALUES(5990,477,14,'Set a formal table for four using folded napkins.');
INSERT INTO badge_optional_requirements VALUES(5991,477,15,'Learn at least five etiquette rules about napkin use at the table.');
INSERT INTO badge_optional_requirements VALUES(5992,477,16,'Discover how different cultures use napkins—folded, rolled, or otherwise.');
INSERT INTO badge_optional_requirements VALUES(5993,477,17,'Create a napkin-folding tutorial (video, photo series, or written instructions).');
INSERT INTO badge_optional_requirements VALUES(5994,477,18,'Create a napkin folding display or photo gallery of at least ten different folds.');
INSERT INTO badge_optional_requirements VALUES(5995,477,19,'Incorporate a menu card, place card, or favor into your napkin design.');
INSERT INTO badge_optional_requirements VALUES(5996,477,20,'Watch a professional napkin folding demonstration (live or online) and attempt to recreate one fold you saw.');
INSERT INTO badge_optional_requirements VALUES(5997,478,3,'Visit a national monument or landmark in person, or online with permission from a parent.');
INSERT INTO badge_optional_requirements VALUES(5998,478,4,'Earn a Junior Ranger badge for any national monument.');
INSERT INTO badge_optional_requirements VALUES(5999,478,5,'Find at least 5 books or movies that feature a national landmark.');
INSERT INTO badge_optional_requirements VALUES(6000,478,6,'Watch a documentary about a national landmark.');
INSERT INTO badge_optional_requirements VALUES(6001,478,7,'Design a poster or brochure, or write a brief report about one of our national landmarks.');
INSERT INTO badge_optional_requirements VALUES(6002,478,8,'Which of our national landmarks are in danger of being damaged or destroyed?  Why?  What is being done to save them?');
INSERT INTO badge_optional_requirements VALUES(6003,478,9,'Participate in a service project that benefits one of our national landmarks or educated people about it.');
INSERT INTO badge_optional_requirements VALUES(6004,478,10,'Read a book or magazine about your national landmark.');
INSERT INTO badge_optional_requirements VALUES(6005,478,11,'Pick a national landmark and plan a dream trip to visit it.  What would you want to see and do while you are there?  How would you get there?  Where would you stay?  How much would it cost? (younger girls can plan in general terms while older girls should do some actual travel research.)');
INSERT INTO badge_optional_requirements VALUES(6006,478,12,'If you were to visit the national landmark in person, are there areas that are not open to the public?  What are they?  Why are they restricted?  Does the landmark have an entrance fee to visit it?  If so, how much?');
INSERT INTO badge_optional_requirements VALUES(6007,479,3,'Visit or write a report about the monument or memorial.');
INSERT INTO badge_optional_requirements VALUES(6008,479,4,'Do a service project while visiting the memorial or monument. You could leave flowers or teach younger kids why the memorial is important.');
INSERT INTO badge_optional_requirements VALUES(6009,479,5,'Explain why you should show respect when visiting a memorial or monument.');
INSERT INTO badge_optional_requirements VALUES(6010,479,6,'Make up a puzzle or game using facts about the monument or memorial.');
INSERT INTO badge_optional_requirements VALUES(6011,479,7,'Draw a picture or take a picture of you and the memorial or monument.');
INSERT INTO badge_optional_requirements VALUES(6012,479,8,'Make a scrapbook with facts, pictures and photos of the memorial or monument.');
INSERT INTO badge_optional_requirements VALUES(6013,479,9,'Learn about careers that might involve with the making or upkeep of the monument or memorial.');
INSERT INTO badge_optional_requirements VALUES(6014,479,10,'What type of architecture was used when the monument was built?');
INSERT INTO badge_optional_requirements VALUES(6015,479,11,'If you plan to visit your monument, locate your travel destination on a map. How far is it from your home? How will you travel there? How long will it take? Make a plan for keeping yourself busy during travel so that you do not get bored. Level 3 and Up: Know the costs involved in traveling to this destination.');
INSERT INTO badge_optional_requirements VALUES(6016,479,12,'Learn about a legend or myth in regards to your national monument.');
INSERT INTO badge_optional_requirements VALUES(6017,479,13,'Learn an interesting fact (or more) about your national monument.  For example, the Lincoln Monument was designed by a deaf man and Lincoln’s hands rest in the position of the American Sign Language alphabet letters of A and L.');
INSERT INTO badge_optional_requirements VALUES(6018,479,14,'Earn a Junior Ranger badge at your level for your monument if offered.');
INSERT INTO badge_optional_requirements VALUES(6019,479,15,'Make a craft of your monument.');
INSERT INTO badge_optional_requirements VALUES(6020,479,16,'Watch a documentary or read a book about your monument.');
INSERT INTO badge_optional_requirements VALUES(6021,480,3,'Visit a Native American Art  Museum or exhibit.');
INSERT INTO badge_optional_requirements VALUES(6022,480,4,'Create a piece of art in the style of the region you are studying. This requirement may be repeated up to three times.');
INSERT INTO badge_optional_requirements VALUES(6023,480,5,'Make a drawing of art styles and patterns used in Native American art.');
INSERT INTO badge_optional_requirements VALUES(6024,480,6,'Name one famous Native American artist (living or deceased) and what form of art they make.  If you cannot see samples in person, find pictures online (with a parent’s permission) or in books.');
INSERT INTO badge_optional_requirements VALUES(6025,480,7,'Discuss which Native American art form is your favorite and why.');
INSERT INTO badge_optional_requirements VALUES(6026,480,8,'Participate in a service project that involves Native American art.  You might volunteer to help with a local exhibit, make your own crafts in the Native American styles to sell and make money for a charity, or teach younger children how to make art pieces of their own.');
INSERT INTO badge_optional_requirements VALUES(6027,480,9,'Learn about the patterns and symbols involved in Native American art.  What do they mean? How can we be respectful of the symbolism and history in Native American art?');
INSERT INTO badge_optional_requirements VALUES(6028,480,10,'Learn the differences between the style and materials used for a specific art form in your tribe/region as compared to the Native American art forms in a different tribe/region.  For example, what materials were used for weaving or baskets?  How do the designs differ?');
INSERT INTO badge_optional_requirements VALUES(6029,480,11,'Visit a public Native American event, such as a community powwow. If there is a local artist, talk to them about their tribe’s artwork. Has the artwork been adapted to modern day materials or interests? What does the artist find fascinating about this particular style of artwork?');
INSERT INTO badge_optional_requirements VALUES(6030,481,3,'Learn how the natural disaster you are studying interacts with other natural disasters, either as a cause, or an effect. For example, an earthquake can cause a tsunami, or a thunderstorm might cause a wildfire. Why?');
INSERT INTO badge_optional_requirements VALUES(6031,481,4,'How are your disasters named? Are they named after locations or use a naming system? Do they earn colloquial nicknames?');
INSERT INTO badge_optional_requirements VALUES(6032,481,5,'Learn at least five vocabulary words related to the natural disaster you are studying that you did not know before starting this badge.');
INSERT INTO badge_optional_requirements VALUES(6033,481,6,'Create a booklet to teach younger kids how to stay safe during the natural disaster you are studying.');
INSERT INTO badge_optional_requirements VALUES(6034,481,7,'Create a science experiment that demonstrates the natural disaster you are studying.');
INSERT INTO badge_optional_requirements VALUES(6035,481,8,'Participate in a community service project that relates to the natural disaster you are studying. This might be make community service pamphlets or posters, or even raising money or collecting supplies for a relief effort.');
INSERT INTO badge_optional_requirements VALUES(6036,481,9,'Learn about at least three different organizations or government agencies that provide assistance and relief after a natural disaster. These may be world-wide organizations, or federal/state/local organizations.');
INSERT INTO badge_optional_requirements VALUES(6037,481,10,'Find out how the natural disaster you are studying can be predicted and an early warning system set in place.');
INSERT INTO badge_optional_requirements VALUES(6038,481,11,'Write an essay about the impact of the natural disaster you are studying on a community.');
INSERT INTO badge_optional_requirements VALUES(6039,481,12,'Learn about careers that relate to the natural disaster you have chosen. These might be careers regarding studying the disaster, providing relief for the disaster, or creating technology to predict the disaster. What education would you need for your chosen career? What type of pay might you expect? Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(6040,481,13,'How can your natural disaster be prevented and/or its effects minimized?');
INSERT INTO badge_optional_requirements VALUES(6041,482,3,'Learn the history of food dye (both natural and artificial) in the USA.');
INSERT INTO badge_optional_requirements VALUES(6042,482,4,'Research how two of the ingredients in your natural dye benefit your health.');
INSERT INTO badge_optional_requirements VALUES(6043,482,5,'What happens when you add other ingredients like sugar, salt, etc?');
INSERT INTO badge_optional_requirements VALUES(6044,482,6,'What are the primary colors? Can you make them with natural colors?');
INSERT INTO badge_optional_requirements VALUES(6045,482,7,'Preschool-Level 1 Only: Name three different things that have food coloring in them.');
INSERT INTO badge_optional_requirements VALUES(6046,482,8,'Find two things that you are surprised have food coloring in them.');
INSERT INTO badge_optional_requirements VALUES(6047,482,9,'What is carmine? Research and find one product that contains it.');
INSERT INTO badge_optional_requirements VALUES(6048,482,10,'Create a presentation comparing the advantages/disadvantages of natural versus artificial food colorings.');
INSERT INTO badge_optional_requirements VALUES(6049,482,11,'Can you mix colors to make secondary colors and tertiary colors?');
INSERT INTO badge_optional_requirements VALUES(6050,482,12,'What happens when you add an acid base such as vinegar or baking soda to natural food colorings?');
INSERT INTO badge_optional_requirements VALUES(6051,482,13,'Research careers involving natural food colorings. What type of facility might you work in and what type of education might you need?');
INSERT INTO badge_optional_requirements VALUES(6052,482,14,'Make a snack that is colored with your natural dye and share it with someone.');
INSERT INTO badge_optional_requirements VALUES(6053,482,16,'Participate in a community service project involving natural food dye, such as coloring clothing to donate or sell in a fundraiser.');
INSERT INTO badge_optional_requirements VALUES(6054,482,17,'Does the amount of natural dye you use affect the taste of the food? Conduct an experiment using different amounts of natural dye on three types of the same food and compare the taste.');
INSERT INTO badge_optional_requirements VALUES(6055,482,18,'Dye eggs using natural food dye.');
INSERT INTO badge_optional_requirements VALUES(6056,482,19,'How does the preparation of ingredients affect the intensity of color? Share your findings with someone.');
INSERT INTO badge_optional_requirements VALUES(6057,483,2,'Visit a natural wonder (a waterfall, canyon, coral reef, etc.). What is the history of this particular site?  Has it changed much in the last two hundred years?  Was it ever privately owned?  Has it been abused? Has it been used for something other than a tourist attraction? This requirement can be repeated for each site visited.');
INSERT INTO badge_optional_requirements VALUES(6058,483,3,'Visit a visitor’s center at a natural wonder. Ask a tour guide or other employee about their favorite fact or story about the natural wonder. This requirement can be repeated for each site visited.');
INSERT INTO badge_optional_requirements VALUES(6059,483,4,'Attend an authority-led tour, session, or class about a natural wonder. Don’t forget to thank your guide or teacher when it is over!');
INSERT INTO badge_optional_requirements VALUES(6060,483,5,'Do a photo shoot of a natural wonder or make a collage of photos you have gathered.');
INSERT INTO badge_optional_requirements VALUES(6061,483,6,'Write a journal entry or a letter describing a visit you made to a natural wonder.');
INSERT INTO badge_optional_requirements VALUES(6062,483,7,'Create a presentation on a natural wonder. Present it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6063,483,8,'Create a piece of art inspired by a natural wonder.');
INSERT INTO badge_optional_requirements VALUES(6064,483,9,'Hike or walk around a natural wonder.');
INSERT INTO badge_optional_requirements VALUES(6065,483,10,'Write a short story that involves a natural wonder. Be sure to complete the necessary research to insure that this story is accurate in every way possible.');
INSERT INTO badge_optional_requirements VALUES(6066,484,3,'Listen to and learn the Navy song  “Anchor’s Away.”');
INSERT INTO badge_optional_requirements VALUES(6067,484,4,'Be able to identify at least 3 different Navy ships and 3 different Navy air craft, and explain their purpose.');
INSERT INTO badge_optional_requirements VALUES(6068,484,5,'Tour a Navy base and find out what jobs they do there.');
INSERT INTO badge_optional_requirements VALUES(6069,484,6,'Learn how to read a 24 hour clock as well as use the military phonetic alphabet. Practice translating time from a 12 hour clock to 24 hour and back again. Translate license plates using the phonetic alphabet.');
INSERT INTO badge_optional_requirements VALUES(6070,484,7,'Tour a Navy museum, memorial, or monument.');
INSERT INTO badge_optional_requirements VALUES(6071,484,8,'Interview a member of the Navy. What is their role? What has their experience been like? What is the best and worst part of their job? Where have they traveled? If they lived on a ship, what was it like?');
INSERT INTO badge_optional_requirements VALUES(6072,484,9,'Make a map of the 10 Navy bases nearest you. Which is the closest? What is their mission? What groups are stationed there?');
INSERT INTO badge_optional_requirements VALUES(6073,484,10,'Participate in a community service project for the Navy. For example you could send cards or care packages to Navy members overseas; do yard work or babysitting for a Navy family with a member serving away from home; serve dinner at your local VFW post and listen to stories from veteran Navy men and women; volunteer at your local veteran cemetery such as placing flags or wreaths on the graves for memorial day; etc.');
INSERT INTO badge_optional_requirements VALUES(6074,484,11,'Learn the ranking system for members of the Navy, from enlisted to officers.');
INSERT INTO badge_optional_requirements VALUES(6075,484,12,'Tour a Navy ship or submarine.');
INSERT INTO badge_optional_requirements VALUES(6076,486,3,'Know what motor neurons and sensory neurons are. Understand what a reflex is.');
INSERT INTO badge_optional_requirements VALUES(6077,486,4,'Label parts of the brain.');
INSERT INTO badge_optional_requirements VALUES(6078,486,5,'Know the difference between the peripheral nervous system and the central nervous system.');
INSERT INTO badge_optional_requirements VALUES(6079,486,6,'Research three neurotransmitters (e.g., dopamine, serotonin, acetylcholine) and explain their roles.');
INSERT INTO badge_optional_requirements VALUES(6080,486,7,'Explain how drugs affect the brain. Make a commitment to never take recreational drugs.');
INSERT INTO badge_optional_requirements VALUES(6081,486,8,'Explain what neural adaptation is.');
INSERT INTO badge_optional_requirements VALUES(6082,486,9,'List at least five disorders that affect the brain and nervous system. Learn what is believed to be the cause and how they are treated. Examples include ALS (also called motor neuron disease) and schizophrenia.');
INSERT INTO badge_optional_requirements VALUES(6083,486,10,'Participate in a community service project to benefit a disease that affects the brain and nervous system, like fundraising for Alzheimer’s disease research or volunteering at a memory care ward of a nursing home.');
INSERT INTO badge_optional_requirements VALUES(6084,486,11,'Learn about MRI, fMRI, and EEG. Compare how each technique helps study the brain.');
INSERT INTO badge_optional_requirements VALUES(6085,486,12,'Observe a neuron under a microscope.');
INSERT INTO badge_optional_requirements VALUES(6086,486,13,'Explain how local and general anesthetics work.');
INSERT INTO badge_optional_requirements VALUES(6087,486,14,'List at least five things you can do to prevent brain damage, such as always wearing a helmet when riding a bike and saying no to drugs.');
INSERT INTO badge_optional_requirements VALUES(6088,486,15,'Define brain plasticity. Give an example of how the brain can change in response to experience.');
INSERT INTO badge_optional_requirements VALUES(6089,486,16,'Describe the “fight or flight” response and how the amygdala and sympathetic nervous system are involved.');
INSERT INTO badge_optional_requirements VALUES(6090,486,17,'Investigate two cognitive processes (e.g., memory and learning) and how the brain handles them.');
INSERT INTO badge_optional_requirements VALUES(6091,486,18,'Explain how the brain interprets signals from the five senses.');
INSERT INTO badge_optional_requirements VALUES(6092,486,19,'Explain three ways neuroscience has impacted daily life (e.g., sleep patterns, emotional regulation, or learning).');
INSERT INTO badge_optional_requirements VALUES(6093,486,20,'Compare short-term and long-term memory. Perform an experiment to test your memory.');
INSERT INTO badge_optional_requirements VALUES(6094,486,21,'Learn how sleep affects brain function and why it is important for cognitive health.');
INSERT INTO badge_optional_requirements VALUES(6095,486,22,'Learn about the causes and effects of traumatic brain injuries (TBI).');
INSERT INTO badge_optional_requirements VALUES(6096,486,23,'Explore the basics of how brain-computer interfaces work and their potential uses.');
INSERT INTO badge_optional_requirements VALUES(6097,486,24,'Research careers in neuroscience (e.g., neurologist, neuroscientist, neuropsychologist).  What education do you need?  What hours and working conditions can you expect?  What is the average salary?');
INSERT INTO badge_optional_requirements VALUES(6098,486,25,'Learn how addiction affects brain pathways and decision-making.');
INSERT INTO badge_optional_requirements VALUES(6099,486,26,'Research how excessive use of social media effects the brain.');
INSERT INTO badge_optional_requirements VALUES(6100,487,3,'Make a homemade NERF gun.');
INSERT INTO badge_optional_requirements VALUES(6101,487,4,'Make at least three homemade targets.  Get creative and decorate the targets as well.');
INSERT INTO badge_optional_requirements VALUES(6102,487,5,'Set up a large active NERF obstacle course/ shooting range with the targets ( think police active range test). If you can, take turns going through it with friends.');
INSERT INTO badge_optional_requirements VALUES(6103,487,6,'Set up a NERF “war” party!  Invite another club, or a group of friends. Before beginning, make sure that all participates and observers know and agree to all safety rules. Tip: Have a permanent marker or other identifying material on hand. Have everyone mark any NERF materials/supplies they bring to prevent confusion.');
INSERT INTO badge_optional_requirements VALUES(6104,487,7,'What groups and events are there for NERF guns? If you can, participate in one.');
INSERT INTO badge_optional_requirements VALUES(6105,487,8,'Practice the “weaver stance”  with a NERF hand-gun style gun. The “weaver stance” is the firing technique that police and military follow when firing an actual handgun.');
INSERT INTO badge_optional_requirements VALUES(6106,487,9,'Observe the different types of bullets used by the various types of NERF guns.  Experiment and observe which types of guns shoot the farthest.');
INSERT INTO badge_optional_requirements VALUES(6107,487,10,'What types of NERF tactical wear are available?  How can wearing a tactical vest or jacket improve your game?  What is the price range for tactical wear?');
INSERT INTO badge_optional_requirements VALUES(6108,488,3,'Look at old newspapers stored in the newspaper office or public library.  Find out what was happening in the world or in your community on the day you were born.  Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(6109,488,4,'Research careers in the newspaper business, such as a printer, layout person, writer, correspondent, ad writer and seller, editor, photo person, etc. What type of education do you need?  What type of pay could you expect?  Where might you have to live? If possible, shadow someone for a day in one of these careers.');
INSERT INTO badge_optional_requirements VALUES(6110,488,5,'Learn how newspapers are modernizing in this world of technology. How has the use of the internet affected newspapers?');
INSERT INTO badge_optional_requirements VALUES(6111,488,6,'Find copies of at least three newspapers from different places and compare them.  Do they all have the same sections?');
INSERT INTO badge_optional_requirements VALUES(6112,488,7,'Create your own mock newspaper for your family, friends, or group.  Include reports about what each person has been doing, or about real local events, what the weather has been like, whether or not your favorite sports team won their latest match/tournament, etc.');
INSERT INTO badge_optional_requirements VALUES(6113,488,8,'Find out about how newspapers used to be made and look at pictures of some of the old equipment used, such as a mimeograph or an old-fashioned typewriter (not an electric one).  How did the invention of movable type affect the newspaper business?');
INSERT INTO badge_optional_requirements VALUES(6114,488,9,'Learn about the different programs used for creating layouts for a newspaper. Look at examples of each. Which one do you like best?');
INSERT INTO badge_optional_requirements VALUES(6115,488,10,'Learn about different journalism awards for categories such as Headline Writing, News Photo, Feature Photo, or Column Writing.  Find out who has won each one for the past five years. Who has been the Journalist of the Year for the past five years?');
INSERT INTO badge_optional_requirements VALUES(6116,488,11,'Research how newspapers are recycled. Find the nearest recycling center for newspapers and donate some to it. You can also find your own ecological way to recycle newspapers, such as ripping them up and using them as mulch for a garden, using them to cover your workspace when painting, or using them to keep the area around a pet’s cage clean.');
INSERT INTO badge_optional_requirements VALUES(6117,489,3,'Examine Norse warships and weapons.  Wha did they use?  How werethey made?');
INSERT INTO badge_optional_requirements VALUES(6118,489,4,'Compare and contrast at least two modern movies or TV shows that are based onNorse myths with the original story. How do they compare? What similarities and differences do you note? For one, create a Venn diagram; for the other write (or video) a film review.');
INSERT INTO badge_optional_requirements VALUES(6119,489,5,'Read a traditional Norse book (ex. Prose Edda)');
INSERT INTO badge_optional_requirements VALUES(6120,489,6,'Learn a traditional Norse game');
INSERT INTO badge_optional_requirements VALUES(6121,489,7,'Make a traditional Norse craft');
INSERT INTO badge_optional_requirements VALUES(6122,489,8,'Cook a traditional Norse recipe');
INSERT INTO badge_optional_requirements VALUES(6123,489,9,'Research at least 10 historic Norse landmarks around the world. Make sure you find them on a map. Pick one and create a travel brochure for it.');
INSERT INTO badge_optional_requirements VALUES(6124,489,10,'Explore the Elder Futhark, the original runic alphabet. Create a table showing the runes, what they were called and what they represented. Explain the history of runes – what were they used for? Are they still used?');
INSERT INTO badge_optional_requirements VALUES(6125,489,11,'Read one example of Norse Eddaic poetry and one of Norse Skaldic poetry. What is the difference between the two?');
INSERT INTO badge_optional_requirements VALUES(6126,489,12,'Write a persuasive letter to a friend or family member telling them why you feel Norse  mythology is better than other forms. Give at least three reasons.');
INSERT INTO badge_optional_requirements VALUES(6127,489,13,'Design a book cover for a Norse myth.');
INSERT INTO badge_optional_requirements VALUES(6128,489,14,'Create a storyboard depicting a traditional Norse myth or an event from history. This may be hand drawn or done digitally. Create at least 6 panels, and include a short caption for each.');
INSERT INTO badge_optional_requirements VALUES(6129,489,15,'Write a biography of a famous Norse warrior or explorer.');
INSERT INTO badge_optional_requirements VALUES(6130,489,16,'Write a how-to manual for something from Norse history, such as how to make a sword, ship, build a longhouse etc… Include diagrams. These can be hand drawn or images you find online.');
INSERT INTO badge_optional_requirements VALUES(6131,489,17,'Write a newspaper story recounting an important event in Norse history');
INSERT INTO badge_optional_requirements VALUES(6132,490,3,'Look at pictures of how nurses’ uniforms have changed over the years.  Which one would you have liked to wear?  How are nurses’ uniforms from other countries different?  Are there special uniforms that nurses have to wear for different jobs, such as helping in the operating theater?');
INSERT INTO badge_optional_requirements VALUES(6133,490,4,'Make a timeline of important events in the history of nursing.  You must have at least 10 items on your timeline.');
INSERT INTO badge_optional_requirements VALUES(6134,490,5,'Research careers in nursing, such as a nurse in a hospital, on a battlefield, or in a nursing home.  What injuries/ailments would you be likely to deal with?  What education would you need? If possible, shadow someone for a day who works in the nursing field.');
INSERT INTO badge_optional_requirements VALUES(6135,490,6,'With your parents’ permission, watch an age-appropriate documentary or a movie about nursing.');
INSERT INTO badge_optional_requirements VALUES(6136,490,7,'Earn the Home Nurse badge at your level.');
INSERT INTO badge_optional_requirements VALUES(6137,490,8,'Research different nursing schools around the country. Where would you get the best education for your money?');
INSERT INTO badge_optional_requirements VALUES(6138,490,9,'Earn the Hygiene badge at your level.  Be able to explain why hygiene is so important when dealing with wounds. How did the discovery of germs affect nursing?');
INSERT INTO badge_optional_requirements VALUES(6139,490,10,'Make a list of the tools and instruments that a nurse would use in their everyday work, such as syringes, bandages, thermometers, blood pressure cuffs, gauze, cotton wool, etc. What are each of these tools used for?');
INSERT INTO badge_optional_requirements VALUES(6140,490,11,'Earn the First Aid badge at your level.');
INSERT INTO badge_optional_requirements VALUES(6141,492,3,'Practice reading nutrition labels. Find five packaged foods. Arrange the items from most to least by protein content per serving. Then do the same thing for fat, carbohydrate, sugars, and calcium. Which one was the most nutritious? The least?');
INSERT INTO badge_optional_requirements VALUES(6142,492,4,'Talk to another family member (a parent is usually best) about ways to include more fruits, vegetables, and fiber in your family’s diet. Make a list of five dishes your family likes to eat and how to make them more nutritious.');
INSERT INTO badge_optional_requirements VALUES(6143,492,5,'Collect pictures of foods, cut them out and sort them. Make the pictures into two collages of two separate kinds of food, such as a vegetable collage, a meat and high-protein foods collage, a grains/bread collage, etc.');
INSERT INTO badge_optional_requirements VALUES(6144,492,6,'Write or learn a song, rap, dance, or poem about the functions of protein, fat, and carbohydrates in a person’s body. You can also choose to present your knowledge in a different way. Present your knowledge to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6145,492,7,'Keep track of the water you drink for a week. Do not count sodas, fruit juice, or milk. Only count water or herb teas. How close do you come to the recommended amount of water a day?');
INSERT INTO badge_optional_requirements VALUES(6146,492,8,'What are the building blocks of protein called? What are the building blocks of fat called? What is the difference between sugars, starches, and indigestible fiber?');
INSERT INTO badge_optional_requirements VALUES(6147,492,9,'Learn the definitions of vitamins, minerals, and phytonutrients (also called phytochemicals). List 8 of the vitamins, minerals, and phytonutrients found in fruits and vegetables. Find out the benefits of four of the nutrients on your list.');
INSERT INTO badge_optional_requirements VALUES(6148,492,10,'Make up a game, song or skit that teaches about nutrition. Play or perform it. You can also do a demonstration on nutrition for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6149,492,11,'Read about sweeteners. What are some of the problems with artificial sweeteners? What are some problems with refined sugar and corn syrup? Can you find a sweetener that has either health benefits or contains nutritional value other than just calories/energy?');
INSERT INTO badge_optional_requirements VALUES(6150,492,12,'Why are some amino acids and fatty acids called essential? Find out how many grams of protein and fat you are supposed to eat a day. What are simple and complex carbohydrates?');
INSERT INTO badge_optional_requirements VALUES(6151,492,13,'By using nutrition charts and nutrition labels, keep track of what you eat for five days. Track your grams of fat, protein, and carbohydrate and amount of either calcium or iron that you consume. There are online resources or apps that can help you track your food intake that can be used with a parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(6152,492,14,'Find out what fat soluble and water soluble means. Memorize the fat soluble vitamins. Learn the names of two phytochemicals, what foods they’re in and why they are important.');
INSERT INTO badge_optional_requirements VALUES(6153,492,15,'Learn about food preservation. What are nutritious ways to preserve food? What are unhealthy ways to preserve food?');
INSERT INTO badge_optional_requirements VALUES(6154,492,16,'Help fix a breakfast, a lunch, and a dinner that are more nutritious than what your family usually has. Or help fix the same three meals for a family that needs meals brought to them.');
INSERT INTO badge_optional_requirements VALUES(6155,492,17,'Learn the names of 3 deficiency diseases and which nutrient deficiency causes them.');
INSERT INTO badge_optional_requirements VALUES(6156,492,18,'Learn about chlorine, fluorine, pesticides or industrial chemicals that if often in our water supply. What are the advantages/disadvantages of these chemicals and minerals in our water?');
INSERT INTO badge_optional_requirements VALUES(6157,492,19,'Learn about organic, heritage, wild-caught, and genetically modified organisms (GMO’s) produce and seafood. What are the advantages/disadvantages of each?');
INSERT INTO badge_optional_requirements VALUES(6158,492,20,'Find out which foods are the most common triggers for food intolerances and what the common symptoms of food intolerance are. Find out which foods can be substituted for those which trigger reactions so that a nutritionally complete diet can be maintained.');
INSERT INTO badge_optional_requirements VALUES(6159,492,21,'Learn about artificial versus natural food coloring. What are the advantages/disadvantages of each?');
INSERT INTO badge_optional_requirements VALUES(6160,492,22,'Learn about the effects of poor nutrition around the world, including countries/communities that suffer from starvation or obesity. What can be done to help these communities? What organizations are out there promoting healthy nutrition?');
INSERT INTO badge_optional_requirements VALUES(6161,492,23,'Human nutrition is different than other animals’. Learn about a type of animal and compare their natural diet to ours. Is it okay to feed “people food” to animals?');
INSERT INTO badge_optional_requirements VALUES(6162,492,24,'Learn about pork, chicken, lamb, beef, etc. What cuts are the most nutritious? The least? Does your animal’s diet and living condition affect their meat and other products, such as milk or eggs?');
INSERT INTO badge_optional_requirements VALUES(6163,493,3,'Make something using nuts and give it as a gift to someone else.  Examples might be cookies with walnuts donated to your local fire fighters  or police officers;  homemade almond butter to give to shut ins;  a craft project given to a nursing home.');
INSERT INTO badge_optional_requirements VALUES(6164,493,4,'Choose two types of nuts and find out where it grows best, where it came from originally, what farmers need to do to help this kind of tree, and how to tell when it is time to harvest the nuts.');
INSERT INTO badge_optional_requirements VALUES(6165,493,5,'Choose two types of nuts and find out what kind of pests affect the nuts, what beneficial insects like this nuts, and how easy they are to grow organically.');
INSERT INTO badge_optional_requirements VALUES(6166,493,6,'Host a nut-themed party and use nuts for the decor, food and the games.');
INSERT INTO badge_optional_requirements VALUES(6167,493,7,'Study the economics of nut tree farms.  What are the start-up costs and hoped-for income?  Do the farmers need to hire a lot of help?  What expenses are there besides the trees and water?');
INSERT INTO badge_optional_requirements VALUES(6168,493,8,'Learn about the hand tools and machinery that nut tree farmers use.  What safety precautions do they take around their machines?');
INSERT INTO badge_optional_requirements VALUES(6169,493,9,'Learn about the nutrition of two types of nuts.  Find out how much fat, protein, and vitamins they have. Are there any other health claims made about your chosen nuts?  What studies support those claims?');
INSERT INTO badge_optional_requirements VALUES(6170,493,10,'With appropriate help if needed, make recipes that use nuts.  Use at least two kinds of nuts. Preschool: Make one recipe. Levels 1-2: Make three recipes. Levels 3-4: Make five. Level 5: Make eight.');
INSERT INTO badge_optional_requirements VALUES(6171,493,11,'Learn the history of the processing and use of nuts in general. Then learn how two types of nuts are processed specially.');
INSERT INTO badge_optional_requirements VALUES(6172,493,12,'Learn about some of the more unconventional ways to eat nuts, such as nut milk, nut butter, and nut meal. What types of people would be most likely to use products like these regularly?');
INSERT INTO badge_optional_requirements VALUES(6173,493,13,'Make a craft out of nuts or nut shells.');
INSERT INTO badge_optional_requirements VALUES(6174,493,14,'Learn what to do if someone who is allergic to nuts has a reaction.');
INSERT INTO badge_optional_requirements VALUES(6175,494,3,'Host an indoor obstacle course for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6176,494,4,'Participate in an obstacle course designed by someone else.');
INSERT INTO badge_optional_requirements VALUES(6177,494,5,'Help a younger club member or sibling through a difficult obstacle course.');
INSERT INTO badge_optional_requirements VALUES(6178,494,6,'Host an outdoor obstacle course for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6179,494,7,'Try an obstacle course with water or mud involved.');
INSERT INTO badge_optional_requirements VALUES(6180,494,8,'Earn the Hula Hoop badge at your level.');
INSERT INTO badge_optional_requirements VALUES(6181,494,9,'Try an obstacle course with more than 20 tasks to do.');
INSERT INTO badge_optional_requirements VALUES(6182,494,10,'Draw a map of an obstacle course you would like to try.');
INSERT INTO badge_optional_requirements VALUES(6183,494,11,'Participate in a team obstacle course and see which team makes it through fastest. How did they work better as a team to complete it?');
INSERT INTO badge_optional_requirements VALUES(6184,494,12,'Earn the Fitness Games badge at your level.');
INSERT INTO badge_optional_requirements VALUES(6185,494,13,'Make a chart of the different obstacles you have gone through and what muscles they used.');
INSERT INTO badge_optional_requirements VALUES(6186,494,14,'Use sticky notes to make an obstacle course that teaches something. You could write clues on where to go next, or that quizzes you on math facts, or has new vocabulary words.');
INSERT INTO badge_optional_requirements VALUES(6187,495,3,'Learn about the history of your chosen career/occupation. When is the first record of it?');
INSERT INTO badge_optional_requirements VALUES(6188,495,4,'Shadow someone in your chosen occupation for a day. Ask them questions, observe how they work, and write down what you learn.');
INSERT INTO badge_optional_requirements VALUES(6189,495,5,'Read the biography of someone in your chosen occupation.');
INSERT INTO badge_optional_requirements VALUES(6190,495,6,'Interview someone in your chosen career. Come up with at least ten questions to ask them beforehand.');
INSERT INTO badge_optional_requirements VALUES(6191,495,7,'Learn a new skill that could used in the field you are learning about. (i.e. menu planning for food service, write a newspaper article for journalism, learn to make photo copies for an office career, etc.)');
INSERT INTO badge_optional_requirements VALUES(6192,495,8,'Watch an age-appropriate video or documentary about your chosen occupation.');
INSERT INTO badge_optional_requirements VALUES(6193,495,9,'Write a short story where the main character is someone in your chosen career field. Read it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6194,495,10,'Role play or make a skit based on your occupation. Perform it for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6195,495,11,'Attend a local career fair and talk to several different employers. If there is only one in your chosen career field, try to find a couple more that are in similar fields.');
INSERT INTO badge_optional_requirements VALUES(6196,495,12,'Make a task list of things you need to accomplish in order to enter your chosen career. How will you make these things happen?');
INSERT INTO badge_optional_requirements VALUES(6197,495,13,'Learn about your chosen career in other countries. How is it different? How is similar? What are the education requirements like? What about income? Preschool-Level 1: Learn about one country. Level 2 and Up: Learn about at least three different countries.');
INSERT INTO badge_optional_requirements VALUES(6198,495,14,'List the top 10 places where you could find someone working in your chosen occupation. Would you need to move to one of them to work in that occupation? Also, list the top 10 schools people attend to pursue that occupation.');
INSERT INTO badge_optional_requirements VALUES(6199,495,15,'Earn a badge that relates to your chosen occupation. Make sure to explain how it relates and why you chose that badge.');
INSERT INTO badge_optional_requirements VALUES(6200,496,3,'Find and try an experiment with saltwater (ocean water).');
INSERT INTO badge_optional_requirements VALUES(6201,496,4,'Spend at least one day at the ocean or beach and do at least two activities. Some ideas include swimming, flying kites, or building sandcastles.');
INSERT INTO badge_optional_requirements VALUES(6202,496,5,'Learn about seaweed. What is seaweed? Can you eat it? Is there anything interesting that can be done with seaweed? Where does it grow? What does it provide to sealife?');
INSERT INTO badge_optional_requirements VALUES(6203,496,6,'Find and try an experiment with sand.');
INSERT INTO badge_optional_requirements VALUES(6204,496,7,'Visit an aquarium or a museum with an ocean theme or exhibit.');
INSERT INTO badge_optional_requirements VALUES(6205,496,8,'Read a story about the ocean (fiction or non fiction).');
INSERT INTO badge_optional_requirements VALUES(6206,496,9,'Make a craft using items from the ocean.');
INSERT INTO badge_optional_requirements VALUES(6207,496,10,'Sample some seafood. What did you like and dislike?');
INSERT INTO badge_optional_requirements VALUES(6208,496,11,'Earn an ocean-related badge at your level, such as Marine Life or Swimming.');
INSERT INTO badge_optional_requirements VALUES(6209,496,12,'Learn about the different boats that sail on the ocean, either during modern times or in the past.');
INSERT INTO badge_optional_requirements VALUES(6210,496,13,'Make two crafts using items from the ocean. Give one to someone as a present.');
INSERT INTO badge_optional_requirements VALUES(6211,496,14,'Make three dishes using seafood. Serve them to your friends or family.');
INSERT INTO badge_optional_requirements VALUES(6212,496,15,'Learn about careers that involve the ocean.  What type of education do you need?  What type of pay could you expect?  Where might you have to live? If possible, shadow someone for a day in one of these careers.');
INSERT INTO badge_optional_requirements VALUES(6213,496,16,'Learn about one trade or business associated with the ocean. Some examples include fishing, tourism, or transportation.');
INSERT INTO badge_optional_requirements VALUES(6214,496,17,'Compare the trade and commerce of coastal versus inland cities or communities. Write or present a report.');
INSERT INTO badge_optional_requirements VALUES(6215,496,18,'Volunteer for an ocean or beach cleanup, environmental, or community service project that involves the ocean.');
INSERT INTO badge_optional_requirements VALUES(6216,496,19,'Research an endangered ocean animal.');
INSERT INTO badge_optional_requirements VALUES(6217,496,21,'Scrapbook or journal your trip to the ocean.');
INSERT INTO badge_optional_requirements VALUES(6218,496,22,'Learn about tides. What creates them? How do they affect people and sealife?');
INSERT INTO badge_optional_requirements VALUES(6219,497,3,'Participate in a beach cleanup');
INSERT INTO badge_optional_requirements VALUES(6220,497,4,'Learn about a marine food chain.  What happens if one part of that food chain is no longer available?');
INSERT INTO badge_optional_requirements VALUES(6221,497,5,'Identify at least 5 types of ocean pollution and their sources.');
INSERT INTO badge_optional_requirements VALUES(6222,497,6,'Make a list of ways you could reduce your use of plastic');
INSERT INTO badge_optional_requirements VALUES(6223,497,7,'Learn about the way oil drilling affects the ocean');
INSERT INTO badge_optional_requirements VALUES(6224,497,8,'Save your plastic waste and turn it into a trash sculpture');
INSERT INTO badge_optional_requirements VALUES(6225,497,9,'Do an oil spill cleanup experiment');
INSERT INTO badge_optional_requirements VALUES(6226,497,10,'Learn about the careers in ocean conservation');
INSERT INTO badge_optional_requirements VALUES(6227,497,11,'Learn about marine biomes');
INSERT INTO badge_optional_requirements VALUES(6228,497,12,'Identify at least 10 different ocean animals and their habitats.');
INSERT INTO badge_optional_requirements VALUES(6229,497,13,'Learn about marine protected areas and their importance.  Identify at least 3 marine protected areas and their rules.');
INSERT INTO badge_optional_requirements VALUES(6230,497,14,'Learn about ocean currents and how they impact marine ecosystems.  How do current carry pollutants to other areas in the ocean?');
INSERT INTO badge_optional_requirements VALUES(6231,497,15,'Learn about the impact of overfishing on marine ecosystems.');
INSERT INTO badge_optional_requirements VALUES(6232,497,16,'Identify at least 3 sustainable fishing practices.');
INSERT INTO badge_optional_requirements VALUES(6233,497,17,'Participate in at least one citizen science project focused on ocean conservation.  Many researcher need the help of everyday citizens to collect data.');
INSERT INTO badge_optional_requirements VALUES(6234,497,18,'Learn about the impact of plastic on marine ecosystems.');
INSERT INTO badge_optional_requirements VALUES(6235,497,19,'Learn about the importance of mangroves, coral reefs, and seagrass beds in ocean ecosystems.');
INSERT INTO badge_optional_requirements VALUES(6236,497,20,'Learn about ocean exploration and the tools used to study the ocean.');
INSERT INTO badge_optional_requirements VALUES(6237,497,21,'Identify at least 3 international organizations focused on ocean conservation.');
INSERT INTO badge_optional_requirements VALUES(6238,498,3,'Help clean an office. This includes daily tasks like plant-watering, trash-dumping and vacuuming as well as quarterly or semi-yearly tasks such as window-washing or carpet-cleaning.');
INSERT INTO badge_optional_requirements VALUES(6239,498,4,'Learn how to package things that need to be mailed. Be sure you know how to properly label both envelopes and packages. Learn how to use scales and postage meters. What are options for cushioning the contents of a box? Which ones can be recycled? What are some of the pros and cons for using different delivery services?');
INSERT INTO badge_optional_requirements VALUES(6240,498,5,'Complete at least 3 helpful tasks such as putting out water or other beverages for a meeting, taking coats at a door, helping make shopping lists, replenishing paper in machines, taking notes during a conversation, picking up after projects, etc.');
INSERT INTO badge_optional_requirements VALUES(6241,498,6,'Improve your keyboarding skills. Increase your Words Per Minute (WPM) by at least five. Practice touch typing. Use your keyboarding skills to help with an office project.');
INSERT INTO badge_optional_requirements VALUES(6242,498,7,'Improve your computer skills. Learn how to do a new format such as a table, graph, list, etc. Be sure you know how to cut & paste and do an internet search. Make sure you know proper email etiquette and safety. Learn some new desktop or graphic design skills.');
INSERT INTO badge_optional_requirements VALUES(6243,498,8,'Be in charge of teaching a new office worker at least one task. Show the new person around the office so they know where to put their personal belongings and make sure they have met all their co-workers and knows their proper titles. Be sure to compliment them and answer any questions they have.');
INSERT INTO badge_optional_requirements VALUES(6244,498,9,'What is petty cash? What is it used for? What method does your office use for tracking financial transactions? Does your office use a safe to store its cash overnight? What other security measure does it use?');
INSERT INTO badge_optional_requirements VALUES(6245,498,10,'Take an accounting course.');
INSERT INTO badge_optional_requirements VALUES(6246,498,11,'Compose a public service announcement, a memo, and a short business letter. They do not have to actually be used. Have someone critique them.');
INSERT INTO badge_optional_requirements VALUES(6247,498,12,'Learn how your office usually schedules appointments. How do they record them? How much time do they allow for different types of appointments? Do different people in the office conduct different types of appointments?');
INSERT INTO badge_optional_requirements VALUES(6248,498,13,'What is the usual attire for people at your office? Do they wear different styles of clothing on different days? Why do some offices use uniforms? Is there something your office manager would like you to change about your hair or clothing?');
INSERT INTO badge_optional_requirements VALUES(6249,498,14,'What do you like most about the layout and decor of your office? What would you change if you could? Help decorate for a season such as Christmas or for a party.');
INSERT INTO badge_optional_requirements VALUES(6250,498,15,'If your office is willing to discuss finances, learn how much they pay for rent, utilities, wages, insurance, etc. What do they do to save money? Have they ever had a professional energy audit?');
INSERT INTO badge_optional_requirements VALUES(6251,498,16,'Participate in light manufacturing and packaging tasks. Why are your products packaged the way they are? Is the labeling clear? Are there economy sizes of your products? What influences the decision to add or delete items from your office’s inventory?');
INSERT INTO badge_optional_requirements VALUES(6252,498,17,'Learn to take transcription and dictate clearly into a machine. Ask someone to show you how old-fashioned shorthand works. Why do people dictate into a recorder?');
INSERT INTO badge_optional_requirements VALUES(6253,498,18,'Bake cookies or prepare a fruit tray as a treat for your fellow office workers or help organize or serve or clean up after an office potluck or party.');
INSERT INTO badge_optional_requirements VALUES(6254,498,19,'Are there any safety issues at your office? What is OSHA? Is there something that happens at your office where it would be beneficial to know first aid? If so, take a first aid course. Where does your office display their maps of escape routes? Where do they post emergency phone numbers? Where are the fire extinguishers?');
INSERT INTO badge_optional_requirements VALUES(6255,498,20,'Learn how to properly use a fax machine.');
INSERT INTO badge_optional_requirements VALUES(6256,499,3,'Learn what a topographic map is and how to read one.');
INSERT INTO badge_optional_requirements VALUES(6257,499,4,'Preschool-Level 1 Only: Participate in a string course. This is a course marked with a continuous string line. These courses are often used with very young children to give them familiarity with the forest.');
INSERT INTO badge_optional_requirements VALUES(6258,499,5,'Preschool-Level 1 Only: Play a game of directional Simon Says. Stand facing North and have “Simon” shout either “North,” “South,” “East,” or “West.” You must then turn and face the correct direction. Can you do it without a compass?');
INSERT INTO badge_optional_requirements VALUES(6259,499,6,'Describe the features of an orienteering compass.');
INSERT INTO badge_optional_requirements VALUES(6260,499,7,'Be able to read a topographic map and identify at least 5 terrain features both on the map and in the field.');
INSERT INTO badge_optional_requirements VALUES(6261,499,8,'Learn how to read the international control symbols sheet.');
INSERT INTO badge_optional_requirements VALUES(6262,499,9,'Be able to identify at least 10 control symbols and tell their meaning.');
INSERT INTO badge_optional_requirements VALUES(6263,499,10,'Take part in an orienteering event, or create your own.');
INSERT INTO badge_optional_requirements VALUES(6264,499,11,'Find out what organizations have competitive orienteering in your area.');
INSERT INTO badge_optional_requirements VALUES(6265,499,12,'Explain what declination means and why it is important when orienteering.');
INSERT INTO badge_optional_requirements VALUES(6266,499,13,'Show how to measure distances using an orienteering compass.');
INSERT INTO badge_optional_requirements VALUES(6267,499,14,'Explain the following terms and tell when you would use them: Control marker Attack point Collecting (or catching) feature Aiming off Point feature Contouring Handrail Fine orienteering Safety bearing');
INSERT INTO badge_optional_requirements VALUES(6268,499,15,'Understand pace counting and why it is important in orienteering.');
INSERT INTO badge_optional_requirements VALUES(6269,499,16,'Know the difference between a cross country orienteering event and a scored event.');
INSERT INTO badge_optional_requirements VALUES(6270,499,17,'Explain the following terms and tell when you would use them: Dog leg Star event Thumbing Reentrant Line event Knoll');
INSERT INTO badge_optional_requirements VALUES(6271,499,18,'Participate in a cross country orienteering course.');
INSERT INTO badge_optional_requirements VALUES(6272,499,19,'Participate in a scored orienteering course.');
INSERT INTO badge_optional_requirements VALUES(6273,500,3,'Create a meal of foods eaten in the country hosting the Olympics.');
INSERT INTO badge_optional_requirements VALUES(6274,500,4,'Learn fun unknown facts about the Olympics. For example, in 1904 an American won the gold medal for the marathon. His time was remarkable. It was later found out that he drove in a car for the majority of the race. He was later also disqualified. Preschool: Learn one fact. Levels 1-2: Learn three factss. Levels 3-4: Learn five. Level 5: Learn eight.');
INSERT INTO badge_optional_requirements VALUES(6275,500,5,'Make a chart and track the medals your country has won. Preschool: Track two events. Levels 1-2: Track three events. Levels 3-4: Track five. Level 5: Track eight.');
INSERT INTO badge_optional_requirements VALUES(6276,500,6,'Find out the Olympic torch route and create a map to share with your family, friends, or group. Level 3: Find at least 2 news stories regarding the torch relay. Level 4: Find at least 5 stories. Level 5: Find at least 8 stories.');
INSERT INTO badge_optional_requirements VALUES(6277,500,7,'Hold your own mini Olympics.');
INSERT INTO badge_optional_requirements VALUES(6278,500,8,'Take a virtual tour of the host country by searching travel websites.');
INSERT INTO badge_optional_requirements VALUES(6279,500,9,'At most modern day Olympic Games there have been a variety of demonstration sports held as part of the Games, but not as official events eligible for medals. Some of the events have later gone on to become official Olympic sports, such as baseball and synchronized swimming. Find out which sports are being demonstrated and decide if you would include them as Olympic sports. If there are no demonstration sports this year, learn about two demonstration sports from history. How are they played? Did they ever become official Olympic sports?');
INSERT INTO badge_optional_requirements VALUES(6280,500,10,'Learn about the advantages/disadvantages some countries have. For instance, population size or country interests may affect how many eligible athletes a country has.');
INSERT INTO badge_optional_requirements VALUES(6281,500,11,'Learn about the records for three of your favorite sports.');
INSERT INTO badge_optional_requirements VALUES(6282,500,12,'Learn about an Olympic athlete. Where are they from? How old are they? What do they compete in? How much do they practice a day?');
INSERT INTO badge_optional_requirements VALUES(6283,500,13,'With parental permission, watch an age-appropriate documentary or movie about the Olympics.');
INSERT INTO badge_optional_requirements VALUES(6284,501,3,'On the same day, purchase a fruit or vegetable in both organic and non-organic. Place both on your counter. Which rots first? Why?');
INSERT INTO badge_optional_requirements VALUES(6285,501,4,'Make some organic vanilla ice cream. Compare the taste and texture to store bought vanilla ice cream. Look at the label of the store bought ice cream and compare it to what you put into your own ice cream. Which do you think is better for you? Why?');
INSERT INTO badge_optional_requirements VALUES(6286,501,5,'Take a field trip to an organic farm. If you cannot do this in person visit one virtually with the permission of a parent.');
INSERT INTO badge_optional_requirements VALUES(6287,501,6,'Plant a plant and care for it using organic methods.');
INSERT INTO badge_optional_requirements VALUES(6288,501,7,'Learn three organic methods of pest control.');
INSERT INTO badge_optional_requirements VALUES(6289,501,8,'Find a recipe for something organic that is non-edible, such as shampoo, hair dye, or window cleaner. Make some and try it out. Does it work better than the conventional store bought variety?');
INSERT INTO badge_optional_requirements VALUES(6290,501,9,'Make a compost heap. How does compost help to grow things in an organic way?');
INSERT INTO badge_optional_requirements VALUES(6291,501,10,'What is the history of organic foods?');
INSERT INTO badge_optional_requirements VALUES(6292,501,11,'Find out how something is certified organic? What requirements are there? Who certifies the product?');
INSERT INTO badge_optional_requirements VALUES(6293,501,12,'Choose three items and compare the labels of both the organic version and the non-organic version of the product. For example, you may choose to compare the label of an organic ice cream with a non-organic ice-cream, or an organic shampoo with a non-organic shampoo. After reading the ingredients for each, which do you think you would rather use? Why? Test out each product and discuss which you like better and why.');
INSERT INTO badge_optional_requirements VALUES(6294,501,13,'Visit a local farmer’s market. If you have a garden of your own, try selling some of your extras at the market.');
INSERT INTO badge_optional_requirements VALUES(6295,501,14,'Visit an organic food store. Price compare at least 10 items with similar items found at a regular grocery store. Organic foods generally cost more. Growing organic foods is more time and labor intensive and farmers do not receive the same subsidies that non-organic farmers receive. What other reasons might there be for organic foods to be more expensive than non-organic?');
INSERT INTO badge_optional_requirements VALUES(6296,501,15,'Conduct a poll of family and friends. Ask them the following questions: Do you know what a GMO (genetically modified organism) is? Have you consumed any GMO foods in the past week? If so, how many times? How do you identify them? Do you think the government should require genetically modified foods to be labeled as such? Discuss your findings.');
INSERT INTO badge_optional_requirements VALUES(6297,501,16,'Read three articles that addresses the ethical issues of GMO and organic products. Share your findings with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6298,501,17,'With a parent’s permission, learn the arguments of two leading companies, one who promotes organic, and another that promotes GMO’s. How are they similar/dissimilar? Are their arguments fact-based? Do you agree/disagree with either one of them?');
INSERT INTO badge_optional_requirements VALUES(6299,501,18,'Investigate proposed legislation about organic farming. You may also investigate legislation in other countries.');
INSERT INTO badge_optional_requirements VALUES(6300,501,19,'Create a menu using only fresh organic products. Shop for your ingredients, and cook the menu you planned.');
INSERT INTO badge_optional_requirements VALUES(6301,501,20,'Participate in a community service project that involves organic foods, products, or information. You might volunteer in a community garden, donate organic foods to the local food bank, or create posters to educate others about the benefits of organics.');
INSERT INTO badge_optional_requirements VALUES(6302,501,21,'What is the environmental impact of choosing organic products over those conventionally grown?');
INSERT INTO badge_optional_requirements VALUES(6303,502,3,'Fold an origami animal.');
INSERT INTO badge_optional_requirements VALUES(6304,502,4,'Fold an origami flower.');
INSERT INTO badge_optional_requirements VALUES(6305,502,5,'Fold some paper money into an origami shape.');
INSERT INTO badge_optional_requirements VALUES(6306,502,6,'Fold an 0rigami box.');
INSERT INTO badge_optional_requirements VALUES(6307,502,7,'Fold an 0rigami star.');
INSERT INTO badge_optional_requirements VALUES(6308,502,8,'Fold an 0rigami Christmas ornament.');
INSERT INTO badge_optional_requirements VALUES(6309,502,9,'Fold an origami jumping frog and have a frog jumping competition with friends.');
INSERT INTO badge_optional_requirements VALUES(6310,502,10,'Read a book about 0rigami.');
INSERT INTO badge_optional_requirements VALUES(6311,502,11,'Fold a paper airplane and have flying contests with friends.  You might compete for distance, time in the air, or creativity such as loop de loops.');
INSERT INTO badge_optional_requirements VALUES(6312,502,12,'Visit an origami exhibit.');
INSERT INTO badge_optional_requirements VALUES(6313,502,13,'Watch a video or documentary on origami.');
INSERT INTO badge_optional_requirements VALUES(6314,502,14,'Teach some origami folds to younger children.');
INSERT INTO badge_optional_requirements VALUES(6315,503,3,'Create a poster or booklet showing why you think the flag is important to our country.');
INSERT INTO badge_optional_requirements VALUES(6316,503,4,'Find a poem about our flag and recite it for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6317,503,5,'Write a poem about our flag.');
INSERT INTO badge_optional_requirements VALUES(6318,503,6,'Learn what responsibilities the various people have during a flag ceremony: The flag bearer, the color guard, the caller, and the audience. If able, participate in a formal flag ceremony.');
INSERT INTO badge_optional_requirements VALUES(6319,503,7,'Create your own special flag ceremony that expresses the importance of the symbolism of the flag.  Make sure you follow proper flag etiquette at all times. You may choose to read a poem, sing a special song, display special artwork, etc.');
INSERT INTO badge_optional_requirements VALUES(6320,503,8,'Create a booklet of patriotic songs and poems that could be used for flag ceremonies. Share some withyour family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6321,503,9,'Arrange to perform a formal flag ceremony for a community function. Make sure you structure your ceremony to reflect whether the flag will be posted in a stand for the occasion (such as a banquet or ceremony) or return with the color guard (such as the opening of a parade). How many friends will you need for your ceremony? Is there an opportunity for you to do a dress rehearsal at the location before the actual ceremony?');
INSERT INTO badge_optional_requirements VALUES(6322,503,10,'Our flag holds a special symbolism for those who serve in our military. When is Veterans’ Day? What was it originally and what is significant about its date? When is Memorial Day? What is the difference between the two days? Find a way to express your gratitude to at least 3 veterans. You may thank them in person, make cards, send care packages to soldiers overseas, etc.');
INSERT INTO badge_optional_requirements VALUES(6323,503,11,'The flag is a symbol of American freedom. Over the course of our history, many women have contributed to various war efforts. What types of roles did they play? Find out who Sybil Ludington and Dicey Langston were and what role they played in the American Revolution. How could they serve as a role model today?');
INSERT INTO badge_optional_requirements VALUES(6324,503,12,'When a flag has become too worn or faded it should be retired with honor, burned, and the ashes disposed of in a respectful manner. Learn how to properly retire a flag. If able, participate in a flag retirement ceremony.');
INSERT INTO badge_optional_requirements VALUES(6325,503,13,'Make a poster of the original 13 colonies. Include the date each colony became a state.');
INSERT INTO badge_optional_requirements VALUES(6326,503,14,'Find out where the original “Star Spangled Banner” that flew over Fort McHenry now hangs.  How big is it?');
INSERT INTO badge_optional_requirements VALUES(6327,503,15,'Who was Betsy Ross? Find out when and where she lived and why she is important to our country’s history. Find a copy of the painting “Betsy Ross Makes a Five Pointed Star”. What is happening in the picture? Why do you think the men look concerned? Learn how to make a 5 pointed star.');
INSERT INTO badge_optional_requirements VALUES(6328,503,16,'Pass out flags for people to wave at a 4th of July parade or some other patriotic event. You may help an organization do this or buy some flags on your own to give away, a minimum of a dozen if you buy them.');
INSERT INTO badge_optional_requirements VALUES(6329,503,17,'Research events in history that are famous for the usage of a flag, such as the battles at Iwo Jima & Fort McHenry.');
INSERT INTO badge_optional_requirements VALUES(6330,503,18,'Learn the history of the Pledge of Allegiance. When was it written and by whom? How and why has it changed? If you could rewrite the Pledge of Allegiance what changes would you make and why?');
INSERT INTO badge_optional_requirements VALUES(6331,504,3,'Demonstrate your ability to maintain a cooking fire in windy or wet weather.');
INSERT INTO badge_optional_requirements VALUES(6332,504,4,'Earn the Fire Building badge.');
INSERT INTO badge_optional_requirements VALUES(6333,504,5,'Prepare an easy-to-pack, lightweight, high-energy dinner for hot weather or emergency use that requires no cooking or refrigeration.');
INSERT INTO badge_optional_requirements VALUES(6334,504,6,'Make at least three different trail mixes to take on camping trips or hikes.');
INSERT INTO badge_optional_requirements VALUES(6335,504,7,'Earn the Pocket Knife Safety badge and use your pocket knife to help prepare an outdoor meal.');
INSERT INTO badge_optional_requirements VALUES(6336,504,8,'Visit a camping store or look through a catalog to earn about different outdoor cooking tools such as: Pie iron Dutch oven Roasting stick or fork Broiler basket Griddle Hot dog Cooker Campfire popcorn popper Tea kettle');
INSERT INTO badge_optional_requirements VALUES(6337,504,9,'Learn to make and use a box oven.');
INSERT INTO badge_optional_requirements VALUES(6338,504,10,'Learn to make and use a solar cooker.');
INSERT INTO badge_optional_requirements VALUES(6339,504,11,'Learn to make and use a tin can stove.');
INSERT INTO badge_optional_requirements VALUES(6340,504,12,'Learn how to use the sun to dry out foods for making things like dried fruit.');
INSERT INTO badge_optional_requirements VALUES(6341,504,13,'Learn how to cook with a Dutch oven.');
INSERT INTO badge_optional_requirements VALUES(6342,504,14,'Go to a Dutch oven or BBQ cook-off. Recipes: Biscuit on a Stick – Wrap biscuit dough around a stick or marshmallow skewer and roast over the fire.  Don’t layer the dough too thick, or you will burn it on the outside and the inside will still be raw.  For a special treat roll the finished biscuits in butter and cinnamon with sugar.  You can make “garlic bread” by rolling the biscuit in butter and sprinkling it with garlic powder or garlic salt. Pudding Catch –Put instant pudding and milk into Ziploc bags, following the directions on the box for quantity.  Double bag to ensure your pudding does not leak.  Then play catch with a friend for about 5 minutes to set the pudding.  When it is all mixed, cut a corner off the bag, squeeze it out and eat! S’mores – Top a graham cracker square with ½ of a chocolate bar. Roast a marshmallow over the fire, and place it on top of the chocolate.  Put another graham cracker square on top to create a sandwich.  If you don’t have a wood fire, or roasting sticks, you can grill your s’more by placing a marshmallow and chocolate between two graham cracker halves and then wrapping it loosely in foil.  Do not wrap it too tight as you want the air to circulate.  Place it on a medium/hot grill for 4-5 minutes or until the marshmallow has melted. Banana Boats – On a large sheet of foil place a banana that has been slit lengthwise.  Inside, place marshmallows, and chocolate chips.  Wrap securely with the foil, leaving room for air circulation and place on the grill or medium coals for 10- 15 minutes or until the chocolate and marshmallows have melted. Sizzling Apples – Roast an apple over the fire until the skin splits and the flesh sizzles.  Have an adult help carefully peel away the skin and then roll the apple in cinnamon and sugar. Chili in a Bag – You will need an individual sized bag of Frito Corn Chips for each person. Heat your chili in a pot over the fire or on the stove. Spoon chili directly into the bags of corn chips and serve.  Be careful not to get your chili too hot or you will not be able to hold onto your bags. Foil Packets – In a large sheet of foil, combine the meat of your choice (precooked), chopped vegetables, seasoning, and a pat of butter.  Wrap your packet securely, but make sure to leave room for air to circulate. Place your packet on the grill or over medium coals until heated through, about 25-45 minutes..  This recipe works great with the kids since each person gets to put in only the items they like.  Many clubs have each kids bring their own meat and then one vegetable to share. Taco Packet – On a large sheet of foil, place 1 flour tortilla. Top it with a little meat, cheese and salsa. Bring up the foil on the sides and double fold the top and ends, leaving room for air to circulate.  Place it on the grill or over medium coals until heated through.  Check after 15 minutes.  Open and top with lettuce, sour cream, or other toppings. Dogs and Beans Packet – On a large sheet of foil place ½ cup of baked beans and one sliced hot dog.  Top with BBQ sauce if you like.  Wrap your packet securely, leaving room for air circulation and place on the grill or medium coals until heated through for about 15-30 minutes.  Open and top with cheese if you wish, or serve with tortilla chips. Hobo Soup – Have each kid bring one can of soup to the campout.  It doesn’t matter what kind.  Cook all the soup together in a large pot and serve.  This recipe never turns out the same twice, but always somehow turns up tasting quite good. Pigs in a Blanket – Place a hot dog on a long stick or marshmallow skewer.  Wrap it securely with biscuit dough and roast over the fire until the dough is cooked through. French Toast – Spray the inside of a pie iron with non-stick cooking spray.  Dip a piece of toast in a mixture of egg, milk, a little cinnamon, and sugar.  Place it in the pie iron and roast over the fire until done. Pie Iron Sandwich – Butter two slices of bread and place buttered side down on each side of the pie iron.  Fill with your favorite sandwich meat, cheese, and veggies such as sliced onions or peppers. Close and cook over the fire. Ice Cream in a Bag — Place 2 tablespoons sugar, 1 cup half and half, and ½  teaspoon vanilla extract in  a pint size Ziploc bag (double bagging will help prevent any salt from accidentally getting into your ice cream).  In a gallon size bag place ½ cup rock salt and enough ice cubes to fill the bag half full.  Place the small Ziploc bag with your ice cream mixture inside the larger bag an seal. Shake the bag, or play catch with a friend until your ice cream hardens (about 5-10 minutes depending on the weather).  Each bag makes one serving. Third Party Resources: Outdoor Cook: Cook Anything Outdoors!');
INSERT INTO badge_optional_requirements VALUES(6343,505,3,'Go backyard camping.');
INSERT INTO badge_optional_requirements VALUES(6344,505,4,'Go on a nature hike off pavement');
INSERT INTO badge_optional_requirements VALUES(6345,505,5,'Participate in a nature service project');
INSERT INTO badge_optional_requirements VALUES(6346,505,6,'Explore using a compass to find your way');
INSERT INTO badge_optional_requirements VALUES(6347,505,7,'Find a nature-hidden geocache');
INSERT INTO badge_optional_requirements VALUES(6348,505,8,'Have a person-powered watercraft experience (canoe, kayak, paddle boat…)');
INSERT INTO badge_optional_requirements VALUES(6349,505,9,'Swim in natural water such as a lake or the ocean.');
INSERT INTO badge_optional_requirements VALUES(6350,505,10,'Explore a beach');
INSERT INTO badge_optional_requirements VALUES(6351,505,11,'Explore a creek or pond');
INSERT INTO badge_optional_requirements VALUES(6352,505,12,'Observe a wild animal at a safe distance. Go home and learn about its habitat, feeding habits, and characteristics.');
INSERT INTO badge_optional_requirements VALUES(6353,505,13,'Cook a meal and eat outside.');
INSERT INTO badge_optional_requirements VALUES(6354,505,14,'Go on a campout in “the wild” (state park or campground or similar)');
INSERT INTO badge_optional_requirements VALUES(6355,505,15,'Go bird watching');
INSERT INTO badge_optional_requirements VALUES(6356,505,16,'Go backpacking.');
INSERT INTO badge_optional_requirements VALUES(6357,505,17,'Go rock climbing or bouldering.');
INSERT INTO badge_optional_requirements VALUES(6358,505,18,'Go star gazing.  If at all possible get away from all city lights.');
INSERT INTO badge_optional_requirements VALUES(6359,505,19,'Explore a forest.');
INSERT INTO badge_optional_requirements VALUES(6360,505,20,'Go fishing in a creek, pond, lake or ocean.');
INSERT INTO badge_optional_requirements VALUES(6361,505,21,'Explore a field or meadow and have a picnic.');
INSERT INTO badge_optional_requirements VALUES(6362,505,22,'Go snowshoeing or cross country skiing to explore the snow.');
INSERT INTO badge_optional_requirements VALUES(6363,505,23,'Explore the outdoors by taking nature photography.  Build an album of your photos.');
INSERT INTO badge_optional_requirements VALUES(6364,505,24,'Go tree climbing.');
INSERT INTO badge_optional_requirements VALUES(6365,505,25,'Go whale watching.');
INSERT INTO badge_optional_requirements VALUES(6366,505,26,'Explore a cave or cavern.');
INSERT INTO badge_optional_requirements VALUES(6367,505,27,'Ride an outdoor zipline.');
INSERT INTO badge_optional_requirements VALUES(6368,505,28,'Go trailriding on a horse.');
INSERT INTO badge_optional_requirements VALUES(6369,505,29,'Go river rafting.');
INSERT INTO badge_optional_requirements VALUES(6370,505,30,'Watch a sunrise or sunset, or both!');
INSERT INTO badge_optional_requirements VALUES(6371,505,31,'Explore the air in a hot air balloon ride.');
INSERT INTO badge_optional_requirements VALUES(6372,506,3,'Learn how to properly pack and store food when participating in outdoor activities, including how to prevent wild animals such as raccoons and bears from eating your food.');
INSERT INTO badge_optional_requirements VALUES(6373,506,4,'Earn the Fire Building badge at your level.');
INSERT INTO badge_optional_requirements VALUES(6374,506,5,'Earn the First Aid badge at your level.');
INSERT INTO badge_optional_requirements VALUES(6375,506,6,'Earn the Pocket Knife Safety badge at your level.');
INSERT INTO badge_optional_requirements VALUES(6376,506,7,'Earn the Water Safety badge at your level.');
INSERT INTO badge_optional_requirements VALUES(6377,506,8,'Explore careers that have to do with outdoor safety such as rescue workers, meteorologists, forestry workers, outdoor equipment retailer or manufacturer, etc.');
INSERT INTO badge_optional_requirements VALUES(6378,506,9,'Take a field trip to a camping store, and explore equipment that can help you keep safe while participating in outdoor activities.');
INSERT INTO badge_optional_requirements VALUES(6379,506,10,'Learn wildlife safety, including what to if forced into an interaction with a dangerous or deadly animal.');
INSERT INTO badge_optional_requirements VALUES(6380,506,11,'Learn proper hiking safety rules.');
INSERT INTO badge_optional_requirements VALUES(6381,506,12,'Learn to identify the plants in your area that are poisonous, or can cause rashes or injury.  Examples might include poison oak, nettles,  poison ivy, poison sumac, cactus, or oleanders.');
INSERT INTO badge_optional_requirements VALUES(6382,506,13,'Be able to explain proper clothing and attire for a variety of outdoor activities such as beach days, hiking, camping, or boating.  How should the weather affect your choices in attire?  Know the characteristics of different fabrics such as cotton, wool and polyester.  Which keep you cool? Dry? Warm?');
INSERT INTO badge_optional_requirements VALUES(6383,506,14,'Learn about different alarm methods that campgrounds and parks use in case of emergency. Know what to do in case of severe storm, flood, tornado, or wildfire while outdoors.');
INSERT INTO badge_optional_requirements VALUES(6384,506,15,'Participate in an outdoor activity and learn all safety rules that apply to it.  Examples might be hiking, camping, kayaking, rock climbing, zip-lining, etc.  This requirement may be repeated.');
INSERT INTO badge_optional_requirements VALUES(6385,507,3,'Learn about various careers that involve painting, such as a painter, art teacher, museum curator, and talk to someone in that field about what they like about painting and why they chose that career.');
INSERT INTO badge_optional_requirements VALUES(6386,507,4,'Go to a local art fair that shows paintings or an art gallery. Find 3 paintings and write about what you like about them.');
INSERT INTO badge_optional_requirements VALUES(6387,507,5,'Take a painting class.');
INSERT INTO badge_optional_requirements VALUES(6388,507,6,'Use paint to decorate a craft you have made, such as a painting a clay sculpture or a wood frame.');
INSERT INTO badge_optional_requirements VALUES(6389,507,7,'Read a biography about a famous painter.');
INSERT INTO badge_optional_requirements VALUES(6390,507,8,'Watch a documentary about a famous painting or painter.');
INSERT INTO badge_optional_requirements VALUES(6391,507,9,'Research one of the genres/styles of paintings, such as Abstract or Impressionism and create one of your own. This requirement may be repeated several times as further optional requirements.');
INSERT INTO badge_optional_requirements VALUES(6392,507,10,'Write an essay on the history of your favorite art movement. This could include ones such as impressionism, cubism, surrealism, etc.');
INSERT INTO badge_optional_requirements VALUES(6393,507,11,'Learn about digital painting. How can artists create digital paintings that look like they have been painted traditionally?');
INSERT INTO badge_optional_requirements VALUES(6394,508,3,'Visit a dinosaur or prehistoric life exhibit.');
INSERT INTO badge_optional_requirements VALUES(6395,508,4,'Learn about at least three different tools used in paleontology.');
INSERT INTO badge_optional_requirements VALUES(6396,508,5,'Make your own impression fossil.');
INSERT INTO badge_optional_requirements VALUES(6397,508,6,'Find out how organisms turn into fossils. Look at examples of each process.');
INSERT INTO badge_optional_requirements VALUES(6398,508,7,'Learn about trackways (fossilized footprints). Discuss how these fossils may give us information about: Speed and length of stride of the animal Whether they walked on 2 or 4 legs The bone structure of the foot The existence of herds or stampedes How the tail was carried (did it drag on the ground, or was it held up high?)');
INSERT INTO badge_optional_requirements VALUES(6399,508,8,'Find out what a coprolite is. What is the largest coprolite that has been discovered? What animal do they think it came from?');
INSERT INTO badge_optional_requirements VALUES(6400,508,9,'Make a plaster cast fossil.');
INSERT INTO badge_optional_requirements VALUES(6401,508,10,'Participate in a community service project that involves paleontology. Examples might include teaching younger kids how to make fossils or volunteering at a local dig.');
INSERT INTO badge_optional_requirements VALUES(6402,508,11,'Learn about the history of a petrified forest.');
INSERT INTO badge_optional_requirements VALUES(6403,508,12,'Learn about how scientists determine the age of fossils.');
INSERT INTO badge_optional_requirements VALUES(6404,508,13,'Write an essay about why paleontology is important to science and society.');
INSERT INTO badge_optional_requirements VALUES(6405,508,14,'Create a set of trading cards or flash cards that can help kids learn about prehistoric life.');
INSERT INTO badge_optional_requirements VALUES(6406,508,15,'Go on a fossil hunt in your community. Look at buildings, sidewalks, and other places where plants or animals may have left their mark. Use a magnifying glass to hunt for signs of tiny shells or imprints.');
INSERT INTO badge_optional_requirements VALUES(6407,508,16,'Explore fossils and geologic layers with a park ranger at a national or state park.');
INSERT INTO badge_optional_requirements VALUES(6408,508,17,'Use a cookie extraction to learn about the difficulties of extracting fossils. You will need: 1 hard chocolate chip cookie 1 soft chocolate chip cookie 1 hard raisin cookie 1 soft raisin cookie 24 toothpicks 2 paper towels A timer Instructions: Set a timer for 3 minutes. Place the hard chocolate chip cookie on a paper towel. Using only 6 toothpicks, try to take all of the chocolate chips out of the hard chocolate chip cookie without damaging the chocolate chips and place them on the second paper towel. As your toothpicks break or wear down, trade them for a new one, but do not use more than 6 total. Stop at the end of 3 minutes and see what you have. Do the same for each of the other cookies. Discuss the difficulty of the different cookies. Which were easier to extract intact, the chocolate chips or the raisins? Which cookie was easier to deal with, the hard or the soft? Discuss how this exercise compares to actual fossil extraction.');
INSERT INTO badge_optional_requirements VALUES(6409,509,3,'Use pancake batter to create fun shapes or designs on the griddle.');
INSERT INTO badge_optional_requirements VALUES(6410,509,4,'Create at least 3 different (sweet or savory) versions of pancakes by adding ingredients to a basic recipe.');
INSERT INTO badge_optional_requirements VALUES(6411,509,5,'Create a cookbook for your family, friends, and troop of all the pancake recipes you’ve created and tried.');
INSERT INTO badge_optional_requirements VALUES(6412,509,6,'Read a book about Pancakes. (examples: Pancakes, Pancakes! By Eric Carle; Pancakes for Breakfast By Tommie DePaola; Curious George Makes a Pancake By Margret & H. E. Rey)');
INSERT INTO badge_optional_requirements VALUES(6413,509,7,'Learn what a crepe is and how it differs from a pancake. How are they similar? How are they different?');
INSERT INTO badge_optional_requirements VALUES(6414,509,8,'Make a list of 10 sweet things you can put on a pancake and a list of 10 savory things you can put on a pancake.');
INSERT INTO badge_optional_requirements VALUES(6415,509,9,'Make a pancake batter with gluten-free flour. How does it taste? How well does it cook?');
INSERT INTO badge_optional_requirements VALUES(6416,509,10,'Explore options for making vegan pancakes. Make a list of substitute options that can be used in traditional recipes to make them vegan. Find and try at least one vegan recipe.');
INSERT INTO badge_optional_requirements VALUES(6417,509,11,'Research a famous dessert (for example; Black Forest Cake, Tiramisu, Banana Cream Pie, Pineapple Upside-down Cake, etc). Design a pancake that duplicates the dessert. Make your pancake recipe for your family, friends, or troop.');
INSERT INTO badge_optional_requirements VALUES(6418,509,12,'Participate in a community service project that has something to do with pancakes, such as host/help at a charity pancake breakfast, or donate pancake box mixes to your local food pantry.');
INSERT INTO badge_optional_requirements VALUES(6419,509,13,'Make pancakes over a campfire or charcoal grill. How does a pancake cooked over open flame differ in taste and texture to a pancake cooked on a stove top or pancake griddle?');
INSERT INTO badge_optional_requirements VALUES(6420,509,14,'Practice flipping pancakes with a spatula.  Have a pancake flipping contest with your family or troop.');
INSERT INTO badge_optional_requirements VALUES(6421,509,15,'Conduct an experiment by making two batches of pancakes, one with and one without baking powder, and compare the results.');
INSERT INTO badge_optional_requirements VALUES(6422,509,16,'Learn about savory pancake recipes, such as potato pancakes or scallion pancakes.  Make some to serve with a meal.');
INSERT INTO badge_optional_requirements VALUES(6423,509,17,'Read a story or book about pancakes.');
INSERT INTO badge_optional_requirements VALUES(6424,509,18,'Experiment with different types of flour (e.g., all-purpose, whole wheat, almond) to see how they affect the pancakes.');
INSERT INTO badge_optional_requirements VALUES(6425,509,19,'Taste test pancakes from different restaurants or cafes.');
INSERT INTO badge_optional_requirements VALUES(6426,509,20,'Conduct a survey to find out which restaurant has the best pancakes is town.  Tally the results and go test out the winner.  Create a certificate to give them along wiht your results.');
INSERT INTO badge_optional_requirements VALUES(6427,509,21,'Learn about different cooking techniques for pancakes (e.g., griddle, skillet, oven-baked).  Try cooking pancakes using at least two different methods and compare the results.');
INSERT INTO badge_optional_requirements VALUES(6428,509,22,'Invent your own pancake recipe with a unique twist.\');
INSERT INTO badge_optional_requirements VALUES(6429,509,23,'Host a pancake breakfast for your family or friends.');
INSERT INTO badge_optional_requirements VALUES(6430,509,24,'Earn the Maple Syrup badge for your age level.');
INSERT INTO badge_optional_requirements VALUES(6431,509,25,'Learn about the science behind pancake batter—what makes them rise, fluff up, or stay thin?');
INSERT INTO badge_optional_requirements VALUES(6432,511,3,'Make three types of pop-up pictures for dioramas or greeting cards using folded paper techniques.');
INSERT INTO badge_optional_requirements VALUES(6433,511,4,'Make a piece of origami.');
INSERT INTO badge_optional_requirements VALUES(6434,511,5,'Make a 3D paper sculpture.');
INSERT INTO badge_optional_requirements VALUES(6435,511,6,'Make a paper garland.');
INSERT INTO badge_optional_requirements VALUES(6436,511,7,'Make a piece of kirigami.');
INSERT INTO badge_optional_requirements VALUES(6437,511,8,'Decoupage a frame, box, or other item.');
INSERT INTO badge_optional_requirements VALUES(6438,511,9,'Create something using paper mache.');
INSERT INTO badge_optional_requirements VALUES(6439,511,10,'Create a collage.');
INSERT INTO badge_optional_requirements VALUES(6440,511,11,'Learn about quilling and make something using this technique.');
INSERT INTO badge_optional_requirements VALUES(6441,511,12,'Weave some paper to create a basket, mat, or other object.');
INSERT INTO badge_optional_requirements VALUES(6442,511,13,'Learn to emboss on paper or use crayons to make a rubbing.');
INSERT INTO badge_optional_requirements VALUES(6443,511,14,'Create something using paper punches and punch-outs.');
INSERT INTO badge_optional_requirements VALUES(6444,511,15,'Enter some of your paper crafts in a fair or competition.');
INSERT INTO badge_optional_requirements VALUES(6445,511,16,'Use some of your creations to brighten someone’s day or help a charity in some way.');
INSERT INTO badge_optional_requirements VALUES(6446,511,17,'Find out about a career that uses paper crafting techniques. What type of education do you need for this job? How much money can you expect to make? What hours might you expect to work?');
INSERT INTO badge_optional_requirements VALUES(6447,512,3,'Earn the Doll Badge at your current level');
INSERT INTO badge_optional_requirements VALUES(6448,512,4,'Make a piece of origami like a table or something for your paper dolls to use.');
INSERT INTO badge_optional_requirements VALUES(6449,512,5,'Earn the Fashion History badge at your current level');
INSERT INTO badge_optional_requirements VALUES(6450,512,6,'Put on a paper doll show for family or troop.');
INSERT INTO badge_optional_requirements VALUES(6451,512,7,'What kind of animal paper dolls is there? Make one.');
INSERT INTO badge_optional_requirements VALUES(6452,512,8,'Create at least 3 different backdrop scenes for your paper dolls');
INSERT INTO badge_optional_requirements VALUES(6453,512,9,'Make a magnetic paper doll.  You can use printable magnets and use them on a small cookie tin for travel play.');
INSERT INTO badge_optional_requirements VALUES(6454,512,10,'Participate in a community service project that uses paper dolls in some way.  Examples might include making paper dolls and donating them to a classroom, making travel magnet paper dolls to donate to homeless shelters, etc.');
INSERT INTO badge_optional_requirements VALUES(6455,512,11,'Learn about a career that involves paper dolls such as a publisher, artist, exhibit designer, or museum curator.');
INSERT INTO badge_optional_requirements VALUES(6456,512,12,'Make at least 3 different paper dolls with three different ways of attaching clothing. Examples might include paper tabs, magnets, velcro, repositional tape, etc.');
INSERT INTO badge_optional_requirements VALUES(6457,512,13,'Learn about fashion in another part of the world by making and playing with a paper doll with clothing from that region.');
INSERT INTO badge_optional_requirements VALUES(6458,512,14,'Learn about fashion from another era by making and playing with a paper doll with clothing from that era.');
INSERT INTO badge_optional_requirements VALUES(6459,512,15,'Learn about ways paper dolls are used in education.  How many different paper doll pages or books can you find that are used to educate people on something such as culture, history, feelings, or weather?');
INSERT INTO badge_optional_requirements VALUES(6460,512,16,'Make a paper doll chain where you fold paper in an accordian fashion, cut out a doll and unfold it so you have a chain of paper dolls all holding hands.');
INSERT INTO badge_optional_requirements VALUES(6461,512,17,'Talk to someone that used paper dolls as a main toy growing up. Really listen to their story and how much they cared for them.');
INSERT INTO badge_optional_requirements VALUES(6462,513,1,'What is the Grand Marshall? How are they chosen, and what are their duties?');
INSERT INTO badge_optional_requirements VALUES(6463,513,2,'Participate in a parade for the benefit of a charity.');
INSERT INTO badge_optional_requirements VALUES(6464,513,3,'Make a parade banner for your group.');
INSERT INTO badge_optional_requirements VALUES(6465,513,4,'Learn some songs that you can sing while being in a parade.');
INSERT INTO badge_optional_requirements VALUES(6466,513,5,'Volunteer to be on a parade committee.');
INSERT INTO badge_optional_requirements VALUES(6467,513,6,'Design and build a themed pull behind float for a parade.');
INSERT INTO badge_optional_requirements VALUES(6468,513,7,'Find out the history and traditions of an annual parade, such as the Macy’s Thanksgiving, Tournament of Roses, Mardi Gras, 500-Mile, Ticker Tape, St. Patrick’s Day, etc.');
INSERT INTO badge_optional_requirements VALUES(6469,513,8,'Find an example of a parade in your book of worship. Hint: Look for “procession” and other synonyms.');
INSERT INTO badge_optional_requirements VALUES(6470,513,9,'What are the differences between a military, political, hometown, holiday parades, and religious processions?');
INSERT INTO badge_optional_requirements VALUES(6471,513,10,'What is special about the parade in the opening ceremony of the Olympics?');
INSERT INTO badge_optional_requirements VALUES(6472,513,11,'Participate in a tall flag team, dance team, baton team, or other performance group during a parade.');
INSERT INTO badge_optional_requirements VALUES(6473,513,12,'Find out what happens to professional floats once the parade is over.   What becomes of them?');
INSERT INTO badge_optional_requirements VALUES(6474,513,13,'Learn about careers in the parade industry.  Examples might be float designers, costume designers, announcers, balloonists, etc.  What education and training do you need?  What salary could you expect?  Where might you need to live?');
INSERT INTO badge_optional_requirements VALUES(6475,513,14,'Organize and host a neighborhood parade.  This might be a bike parade, a pet parade, or even a costume parade.');
INSERT INTO badge_optional_requirements VALUES(6476,513,15,'Design posters or flyers to help promote a local parade.');
INSERT INTO badge_optional_requirements VALUES(6477,513,16,'Participate as part of the color guard for the opening flag ceremony of a parade.');
INSERT INTO badge_optional_requirements VALUES(6478,513,17,'Learn about famous parades in at least 3 other countries.  What type of parades are they? What are they celebrating?  What traditions do they have?');
INSERT INTO badge_optional_requirements VALUES(6479,514,3,'Make a recipe that reflects your parshah. This could be a cake decorated to a scene in your parshah, or a food mentioned, or something made from an ingredient mentioned. Be creative!');
INSERT INTO badge_optional_requirements VALUES(6480,514,4,'Write a dvar Torah (discussion of the parshah and its relevance to our lives) on your parshah and share it with your family.');
INSERT INTO badge_optional_requirements VALUES(6481,514,5,'Find a dvar Torah on your parshah written by someone else and read it.');
INSERT INTO badge_optional_requirements VALUES(6482,514,6,'Learn about the positive and negative commandments. If there are any commandments in your parshah, find them and know if they are positive or negative.');
INSERT INTO badge_optional_requirements VALUES(6483,514,7,'Do an art project based on your parshah.');
INSERT INTO badge_optional_requirements VALUES(6484,514,8,'Create a craft based on your parshah.');
INSERT INTO badge_optional_requirements VALUES(6485,514,9,'Make a timeline of events in your parshah. It should include at lease ten items.');
INSERT INTO badge_optional_requirements VALUES(6486,514,10,'Memorize a verse from your parshah.  Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(6487,514,11,'Create a comic book that depicts your parshah.');
INSERT INTO badge_optional_requirements VALUES(6488,514,12,'Read the haftarah for your parshah. Discuss how the haftarah relates to the parshah.');
INSERT INTO badge_optional_requirements VALUES(6489,514,13,'Earn the Torah Study Badge at your level.');
INSERT INTO badge_optional_requirements VALUES(6490,514,14,'Find out what week this year your parshah is read during services. If possible, attend services when it is read.');
INSERT INTO badge_optional_requirements VALUES(6491,514,15,'Earn the Foreign Language badge for Hebrew at your level.');
INSERT INTO badge_optional_requirements VALUES(6492,515,3,'Make a patchwork piece using hexagons as the basic shape, eg; a basket lining, place mat, cushion cover, quilt top for a doll’s bed etc.');
INSERT INTO badge_optional_requirements VALUES(6493,515,4,'Make a patchwork piece using squares as the basic shape eg; a cushion cover, Dorothy bag, pencil case.');
INSERT INTO badge_optional_requirements VALUES(6494,515,5,'Make a patchwork piece using rectangles as the basic shape eg; log cabin quilt, cushion cover, wall hanging.');
INSERT INTO badge_optional_requirements VALUES(6495,515,6,'Learn what Somerset patchwork is.  Make a piece of Somerset patchwork.');
INSERT INTO badge_optional_requirements VALUES(6496,515,7,'Make a patchwork item using diamonds or long diamonds eg; bag, or Star of Bethlehem pattern.');
INSERT INTO badge_optional_requirements VALUES(6497,515,8,'Make a patchwork item using mixed shapes eg; a cushion cover, a bag or a wall hanging.');
INSERT INTO badge_optional_requirements VALUES(6498,515,9,'Make a piece of clothing out of patchwork eg; a waistcoat.');
INSERT INTO badge_optional_requirements VALUES(6499,515,10,'Learn about patchwork made by famous people eg; Jane Austen’s patchwork quilt.');
INSERT INTO badge_optional_requirements VALUES(6500,515,11,'Make a piece of patchwork using non-geometric shapes eg; clamshell shape');
INSERT INTO badge_optional_requirements VALUES(6501,515,12,'Learn about and make a piece of Cathedral Window patchwork.  Why is it called Cathedral Window?');
INSERT INTO badge_optional_requirements VALUES(6502,515,13,'Learn about and make a piece of Suffolk Puff patchwork.');
INSERT INTO badge_optional_requirements VALUES(6503,515,14,'Learn about and make a piece of Crazy Patchwork.');
INSERT INTO badge_optional_requirements VALUES(6504,515,15,'Which embroidery stitches are commonly used with patchwork?  Learn how to work these stitches and use them to embellish one of your pieces of patchwork.');
INSERT INTO badge_optional_requirements VALUES(6505,515,16,'Learn how appliqué can be added to patchwork and appliqué a design onto a piece of fabric.');
INSERT INTO badge_optional_requirements VALUES(6506,515,17,'Read a book about patchwork.  What was the most interesting thing you learned?  Which designs do you like the most?  Which do you like the least?  Why?');
INSERT INTO badge_optional_requirements VALUES(6507,515,18,'Watch a video about patchwork.');
INSERT INTO badge_optional_requirements VALUES(6508,515,19,'What other tools, besides the basic ones, might you want to have if you do patchwork professionally?  Level 3 and Up: if possible shadow someone for a day who works patchwork professionally.');
INSERT INTO badge_optional_requirements VALUES(6509,515,20,'Earn the Quilting Badge at your level.');
INSERT INTO badge_optional_requirements VALUES(6510,515,21,'Learn the difference between English patchwork and American patchwork.  What is the basic difference between the two techniques?  Make a piece of patchwork using each technique.  Which do you prefer?');
INSERT INTO badge_optional_requirements VALUES(6511,515,22,'Learn about Amish patchwork.  What makes their designs distinctive?  What types of fabrics, colours and shapes do they use? Helpful resources: Learn Patchwork by Lynette-Merlin Syme, Collins 1986, ISBN: 0-00-412005-1');
INSERT INTO badge_optional_requirements VALUES(6512,516,3,'Create a poster to track how often you and others in your family or group are patience. For example you could make a Patience tree and each time someone has been patient, you can write their name on a leaf with what they were patience about (e.g. waiting their turn politely) and stick it to the tree. You could also make a Patience caterpillar adding a new circle to its body with each act of patience until it wraps around the room.');
INSERT INTO badge_optional_requirements VALUES(6513,516,4,'Place yourself in a situation where patience is needed for a specific amount of time. For example, put a piece of your favorite cake on the counter and then set a timer for 15 minutes. You may not eat the cake until the timer goes off. During this time, you are not allowed to complain (not even jokingly). If you do, you have to start over. Find ways to stay calm, happy, and polite to others while you wait.');
INSERT INTO badge_optional_requirements VALUES(6514,516,5,'Create a piece of artwork about what patience means to you.');
INSERT INTO badge_optional_requirements VALUES(6515,516,6,'Write an essay about what patience means to you.');
INSERT INTO badge_optional_requirements VALUES(6516,516,7,'Write a story or skit where patience plays an important role.');
INSERT INTO badge_optional_requirements VALUES(6517,516,8,'Read a biography about someone known for their patience such as Anne Sullivan.');
INSERT INTO badge_optional_requirements VALUES(6518,516,9,'What does your book of worship say about patience?  Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(6519,516,10,'Memorize or write a poem about patience.');
INSERT INTO badge_optional_requirements VALUES(6520,516,11,'Find and memorize quotes about patience. Preschool: Memorize one quote. Levels 1-2: Memorize three quotes. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(6521,516,12,'Role play at least 3 instances where patience may be necessary.');
INSERT INTO badge_optional_requirements VALUES(6522,516,13,'Write the word PATIENCE on a piece of paper and then think of one patient act that you could do that starts with each letter in the word. For example for P you could put “pass time constructively while waiting”.');
INSERT INTO badge_optional_requirements VALUES(6523,516,14,'Using the Victorian Language of flowers make a bouquet that symbolizes what patience means to you. You can find the meanings assigned to the flowers at various websites or in books and you may cut pictures from magazines or web pages to create a collage bouquet. Make sure you include the name and meaning of each flower that you choose. You may make a scrapbook page using pictures of flowers or make a bouquet using real or artificial flowers.');
INSERT INTO badge_optional_requirements VALUES(6524,517,3,'Learn to identify landmarks of the United States such as the Statue of Liberty, the Golden Gate Bridge, or Mount Rushmore. Preschool: Identify four landmarks. Levels 1-2: Identify eight landmarks. Levels 3-4: Identify twelve. Level 5: Identify fifteen.');
INSERT INTO badge_optional_requirements VALUES(6525,517,4,'What does our nation’s motto, “In God We Trust” mean to you? When did this motto come into being?');
INSERT INTO badge_optional_requirements VALUES(6526,517,5,'What are the four main branches of military service? What do they specialize in?');
INSERT INTO badge_optional_requirements VALUES(6527,517,6,'Write a poem or create a piece of art about what your country means to you..');
INSERT INTO badge_optional_requirements VALUES(6528,517,7,'Create a list of patriotic songs and/or poems that can be used on holidays such as Independence Day, Veterans Day, Memorial Day, or Flag Day.');
INSERT INTO badge_optional_requirements VALUES(6529,517,8,'Choose your favorite American patriot and create a simple booklet to tell their story. Share your booklet with other kids in your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6530,517,9,'Wander through your town and make a list of how many symbols of patriotism you see. What was the most common? What was the most unusual?');
INSERT INTO badge_optional_requirements VALUES(6531,517,10,'Write a brief essay about why you think the events of September 11, 2001 caused a surge in American patriotism. How do you think we can maintain that patriotic awareness even today?');
INSERT INTO badge_optional_requirements VALUES(6532,517,11,'Interview a veteran and ask them what patriotism means to them. Ask them how they think you might display a patriotic heart in your own life.');
INSERT INTO badge_optional_requirements VALUES(6533,517,12,'Use your camera to take picture of signs of patriotism in your community. These may be actual symbols such as the American Flag or a yellow ribbon, or people doing things like saying the Pledge of Allegiance, voting, making speeches, city council meetings, etc. Make a montage of your pictures to share with your family, friends, and group. If able, present your montage to your city council.');
INSERT INTO badge_optional_requirements VALUES(6534,517,13,'Who were spouses of our founding fathers and what kind of women were they? How did they contribute to the formation of our country? How can we use them as examples today?');
INSERT INTO badge_optional_requirements VALUES(6535,517,14,'Read the complete Declaration of Independence and rewrite it in your own words.');
INSERT INTO badge_optional_requirements VALUES(6536,517,15,'Choose 3 patriotic songs and research their history. Make sure you find ALL the verses. Teach at least one to your family, friends, or group. Examples can include Yankee Doodle, Battle Hymn of the Republic, America the Beautiful, God Bless America, etc.');
INSERT INTO badge_optional_requirements VALUES(6537,517,16,'Organize others to participate in a local event celebrating Memorial Day, Independence Day, Veterans Day, or Flag Day. This could be a parade, or simply a performance of some kind at your local Veterans Hall or City Council.');
INSERT INTO badge_optional_requirements VALUES(6538,517,17,'Write a poem or create a piece of art about what your country means to you.');
INSERT INTO badge_optional_requirements VALUES(6539,517,18,'Find out about at least 3 national monuments in your state and tell your family, friends, or group about them. How are national monuments chosen and who cares for them? If you do not have 3 monuments in your own state, the remainder can be chosen from other states.');
INSERT INTO badge_optional_requirements VALUES(6540,517,19,'During times of war, each branch of military service has special warfare units. Find out the main duties of at least one unit from each branch of the military.');
INSERT INTO badge_optional_requirements VALUES(6541,517,20,'Learn about our national holidays. The U.S. Government thought these days important enough to ask the entire country to stop what they are doing and think about what the day stands for. Explain to your parent or leader why you think each holiday is important and what it means to you.');
INSERT INTO badge_optional_requirements VALUES(6542,517,21,'Earn the Our Flag badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(6543,518,3,'Make a pattern for a costume accessory such as fairy wings, a cape, or a bag.');
INSERT INTO badge_optional_requirements VALUES(6544,518,4,'Make a list of at least 5 different types of paper or material you could use for pattern making. Examples might include freezer paper or wrapping paper.  What are the pros and cons of using each type of paper or material on your list?  How sturdy are they?  What do they cost?  How easy are they to draw on and cut?');
INSERT INTO badge_optional_requirements VALUES(6545,518,5,'Earn the Fashion Design badge');
INSERT INTO badge_optional_requirements VALUES(6546,518,6,'Create a pattern by disassembling a ready made piece of clothing.  Carefully pull apart all stitching and lay the individual pieces out on paper.  Trace to create a pattern.  If you are earning the sewing badge, fashion design, or advanced sewing, try using your pattern to recreate the piece of clothing in a new way.');
INSERT INTO badge_optional_requirements VALUES(6547,518,7,'Read a book about pattern making.');
INSERT INTO badge_optional_requirements VALUES(6548,518,8,'Learn to identify the following pattern making tools and know what they are used for: Pattern notcher Awl Tracing wheel Cloth tape measure Cloth weight Draping pins Transparent ruler Transparent French Curve Dress form');
INSERT INTO badge_optional_requirements VALUES(6549,518,9,'Research the difference between adjustable and set size dress forms.  What are the pros and cons of each?');
INSERT INTO badge_optional_requirements VALUES(6550,518,10,'Create a pattern for a home decor item.  Examples might include a bed skirt, pillow case, slip cover, quilt, or valance.');
INSERT INTO badge_optional_requirements VALUES(6551,518,11,'Create a pattern for a craft such as a pillow, tote bag, beanbag, Christmas ornament, or stuffed animal.');
INSERT INTO badge_optional_requirements VALUES(6552,518,12,'Learn about “ready to wear” clothing and the industrial method of pattern making used to create it.  The industrial method does not create patterns on personal sizes, but according to the physical conformation of the target of end-consumers they refer to.');
INSERT INTO badge_optional_requirements VALUES(6553,518,13,'Create a pattern for beachwear.');
INSERT INTO badge_optional_requirements VALUES(6554,518,14,'Create a pattern for a pair of slippers.');
INSERT INTO badge_optional_requirements VALUES(6555,518,15,'Learn about pattern grading and how to adjust the same pattern for smaller or larger sizes.');
INSERT INTO badge_optional_requirements VALUES(6556,518,16,'Learn how to add darts or pleats to your pattern.');
INSERT INTO badge_optional_requirements VALUES(6557,519,3,'Religion can cause some of the biggest arguments in the world. Countless wars have been fought over religious beliefs, yet most religions actually have a lot in common. Nearly every religion around the world has a version of the golden rule they expect their followers to live by. Choose three major religions that are different than your own and find out what beliefs you have in common. Understanding and respecting others opinions and beliefs, even if you disagree with them, is an important part of living a peaceful life.');
INSERT INTO badge_optional_requirements VALUES(6558,519,4,'Write a poem or essay about peace and what it means to you.');
INSERT INTO badge_optional_requirements VALUES(6559,519,5,'Create a piece of artwork that expresses your view of peace.');
INSERT INTO badge_optional_requirements VALUES(6560,519,6,'Read a book about peace.');
INSERT INTO badge_optional_requirements VALUES(6561,519,7,'Memorize verses about peace. Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(6562,519,8,'Visit another place of worship and have lunch with someone of their religion. Find out what you have in common.');
INSERT INTO badge_optional_requirements VALUES(6563,519,9,'Conflicts often arise when people become so absorbed with what they believe to be correct that they cannot listen to other opinions. Choose a controversial subject that is currently occurring and see if you can discover what each side have in common. Are they as different as they think they are? Do they have the same goals, even if their methods are different? How might these two differing opinions be brought to peace?');
INSERT INTO badge_optional_requirements VALUES(6564,519,10,'Learn about three famous peacemakers such as Mahatma Gandhi, Martin Luther King, Jr, Mother Teresa, Nelson Mandela, or Yitzhak Rabin. What did they do that made them famous for peace? What were their beliefs? What can you learn from them?');
INSERT INTO badge_optional_requirements VALUES(6565,519,11,'What is the Nobel Peace Prize? What is its history? Who are some of the people who have won the award and for what?');
INSERT INTO badge_optional_requirements VALUES(6566,519,12,'Read a poem or book about peacefulness.');
INSERT INTO badge_optional_requirements VALUES(6567,519,13,'Write the word PEACEFULNESS on a piece of paper and then think of one peaceful act that you could do that starts with each letter in the word. For example for P you could put, “Promote understanding between people and encourage friendships”.');
INSERT INTO badge_optional_requirements VALUES(6568,519,14,'Using the Victorian Language of flowers make a bouquet that symbolizes what peace means to you. You can find the meanings assigned to the flowers at various websites or in books and you may cut pictures from magazines or web pages to create a collage bouquet. Make sure you include the name and meaning of each flower that you choose. You may make a scrapbook page using pictures of flowers or make a bouquet using real or artificial flowers.');
INSERT INTO badge_optional_requirements VALUES(6569,519,15,'Find and memorize quotes about peace. Preschool: Memorize one quote. Levels 1-2: Memorize three quotes. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(6570,520,3,'Lean the history of peanut butter.  When was it invented? Who invented it? Where?  Why?');
INSERT INTO badge_optional_requirements VALUES(6571,520,4,'What is the difference between popular commercial peanut butters and all natural peanut butters?  Compare nutrition information.  Which one is healthier?');
INSERT INTO badge_optional_requirements VALUES(6572,520,5,'Learn about a major manufacturer of peanut butter, Jif, Skippy, Peter Pan, etc.  How many kinds do they make?  Where is their base of operations?  How much peanut butter do they make each year?  If you live near one of their plants, see if it is possible to get a tour.');
INSERT INTO badge_optional_requirements VALUES(6573,520,6,'Perform a blind taste test, comparing at least 4 different brands, and/or crunchy vs. smooth. Which do you prefer?');
INSERT INTO badge_optional_requirements VALUES(6574,520,7,'Peanut allergies are a very common, often dangerous, food allergy.  What alternatives are there on the market?  Try one (or more!).');
INSERT INTO badge_optional_requirements VALUES(6575,520,8,'Make your own peanut butter – or alternative.  Compare the taste and texture to store bought.  Which do you prefer?');
INSERT INTO badge_optional_requirements VALUES(6576,520,9,'Learn about the work of Dr. George Washington Carver.  How is he connected to the peanut?');
INSERT INTO badge_optional_requirements VALUES(6577,520,10,'Learn about 5 other uses, past or present, for peanuts besides peanut butter.  What other uses are there for peanut butter?');
INSERT INTO badge_optional_requirements VALUES(6578,520,11,'When is National Peanut Butter Day?  Celebrate with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6579,520,12,'Make a dessert using peanut butter.');
INSERT INTO badge_optional_requirements VALUES(6580,520,13,'Make a savory dish using peanut butter.');
INSERT INTO badge_optional_requirements VALUES(6581,520,14,'Make dog treats using peanut butter and give them to your local shelter.');
INSERT INTO badge_optional_requirements VALUES(6582,520,15,'Make bird feeders using peanut butter and hang them outside.');
INSERT INTO badge_optional_requirements VALUES(6583,520,16,'Learn about and sample at least two different kinds of flavored/blended peanut butter available on the market (e.g. chocolate peanut butter, peanut butter with cinnamon and raisins, white chocolate peanut butter).');
INSERT INTO badge_optional_requirements VALUES(6584,521,3,'Harvest pears from a tree: Preschool 10 pears, Level 1 – ½ bushel, Level 2 –  1 bushel, Level 3 –  2 bushels, Level s 4 & 5 -Assist in harvesting from a whole tree');
INSERT INTO badge_optional_requirements VALUES(6585,521,4,'Why is it important to pick bad fruit, and not allow fruit that has fallen to remain under the tree? What good does it do to maintain cleanliness around your pear trees?');
INSERT INTO badge_optional_requirements VALUES(6586,521,5,'What are some issues that could ruin a pear harvest for a year? What could destroy an entire tree? (molds, blight, hail, etc…)');
INSERT INTO badge_optional_requirements VALUES(6587,521,6,'Seeds are distributed by plants in different ways. A pear tree distributes its seed through fruit. Why would a plant produce fruit around its seeds?');
INSERT INTO badge_optional_requirements VALUES(6588,521,7,'Make a pear craft such as pear prints, pear candle holders, or similar.');
INSERT INTO badge_optional_requirements VALUES(6589,521,8,'Participate in a community service project that has something to do with pears. Examples might include donate pears or pear recipe items to a shelter, shut ins, food bank, etc., or holding an pear bake sale or craft sale to donate money to a local charity.');
INSERT INTO badge_optional_requirements VALUES(6590,521,9,'Find out what careers involve pears – examples might include: Farmer, Produce Manager, Fruit Stand Owner, or Chef. What education is needed for this job? What type of pay could you expect? What type of hours might you need to work? Where might you need to live?');
INSERT INTO badge_optional_requirements VALUES(6591,521,10,'Visit your county fair and see what pear items were entered. How is the judging conducted? Enter an pear recipe or project yourself if you can.');
INSERT INTO badge_optional_requirements VALUES(6592,521,11,'Can you find ancient myths involving pears? What were their importance?');
INSERT INTO badge_optional_requirements VALUES(6593,521,12,'Teach younger children something about pear.');
INSERT INTO badge_optional_requirements VALUES(6594,521,13,'Dehydrate pear. Try different recipes such as dipping the pear in maple syrup first, or in cinnamon and sugar. Or make fruit leather with pear');
INSERT INTO badge_optional_requirements VALUES(6595,521,14,'Make a hot pear recipe such as poached pears, pear muffins, pear butter, or pear tart.');
INSERT INTO badge_optional_requirements VALUES(6596,521,15,'Make a cold pear recipe such as pear sauce, fruit salad, or pears with peanut butter.');
INSERT INTO badge_optional_requirements VALUES(6597,521,16,'Make a savory pear recipe-Bacon wrapped pear, ricotta stuffed pear salad, etc..');
INSERT INTO badge_optional_requirements VALUES(6598,521,17,'Find out how to keep a pear from turning brown. Why does it work? What makes the pear turn brown in the first place?');
INSERT INTO badge_optional_requirements VALUES(6599,521,18,'Find out about pear world records, such as the heaviest pear.');
INSERT INTO badge_optional_requirements VALUES(6600,522,3,'Write your pen pal and tell them about yourself and your various interests.');
INSERT INTO badge_optional_requirements VALUES(6601,522,4,'Send your pen pal a handmade gift.');
INSERT INTO badge_optional_requirements VALUES(6602,522,5,'Visit the post office to learn where your letter goes after you put it in your mail box.');
INSERT INTO badge_optional_requirements VALUES(6603,522,6,'If you have a foreign pen pal, write about an American holiday or other American cultural norm.');
INSERT INTO badge_optional_requirements VALUES(6604,522,7,'Send your pen pal a birthday card, on their birthday.');
INSERT INTO badge_optional_requirements VALUES(6605,522,8,'Write your pen pal at least once a month for 4 months.');
INSERT INTO badge_optional_requirements VALUES(6606,522,9,'Send your pen pal a postcard from your city and state.');
INSERT INTO badge_optional_requirements VALUES(6607,522,10,'Ask your pen pal at least 5 questions, you wish to know about them, their city, state, country, family, school, etc.');
INSERT INTO badge_optional_requirements VALUES(6608,522,11,'Make and send a mini scrapbook album about you to your pen pal.');
INSERT INTO badge_optional_requirements VALUES(6609,522,12,'If you interact with your pen pal online, how does the email service or app that you use work? How can you communicate with your pen pal nearly instantaneously despite the distance?');
INSERT INTO badge_optional_requirements VALUES(6610,523,3,'Do something nice for your coach, director, teacher or team members. Provide snacks for an intermission, make a special card of appreciation, spend a significant amount of time helping to clean up after a performance, etc.');
INSERT INTO badge_optional_requirements VALUES(6611,523,4,'Learn about the history of your art. You may read a biography, watch a documentary, or listen to a live presentation about someone who made a lasting contribution to your art.');
INSERT INTO badge_optional_requirements VALUES(6612,523,5,'Help produce a performance in some way. For instance, you can be an usher, help with a fundraiser, distribute advertising, prepare costumes, make reminder phone calls, or change props between acts of a play.');
INSERT INTO badge_optional_requirements VALUES(6613,523,6,'Take a tour of a theater, opera house, auditorium, or large studio to see how facilities can make a difference to a performer. What are acoustics? What types of equipment, props, or tools are used in your art? Check out how one of them works—one that you haven’t used before (this can be learning to play a song on a new musical instrument). What is the role of lighting, curtains, and decorations? If you are repeating this badge at a higher level, you must tour a different facility than you previously visited.');
INSERT INTO badge_optional_requirements VALUES(6614,523,7,'Attend, in person or virtually (with a parent’s permission), a performance of your art (or a similar one) done by a professional or a person of some renown in your art.');
INSERT INTO badge_optional_requirements VALUES(6615,523,8,'Help with planning a performance away from home. Help with whatever you can, such as packing, making checklists, making reservations, lining people up before the performance, keeping in touch with other drivers by phone, ordering and distributing meals, etc.');
INSERT INTO badge_optional_requirements VALUES(6616,523,9,'Attend a class or workshop about your art.');
INSERT INTO badge_optional_requirements VALUES(6617,523,10,'Create something new in your art—compose a new song, choreograph a dance, write and help perform a puppet show, etc.');
INSERT INTO badge_optional_requirements VALUES(6618,523,11,'Put on a complete workshop for younger kids. If they are in your group, you can help them meet the majority of this badge’s requirements for their level.');
INSERT INTO badge_optional_requirements VALUES(6619,525,3,'Choose 10 animals and explain why each would or would not make a good pet.');
INSERT INTO badge_optional_requirements VALUES(6620,525,4,'Create a scrapbook about your pet, or if you don’t have one, about a pet you would like to have. There should be descriptions on each page to tell about the pictures. Include things like the day your pet joined your family and how you felt, funny things your pet does, your pet sleeping or playing, etc.');
INSERT INTO badge_optional_requirements VALUES(6621,525,5,'Visit at least one animal shelter in your area and find out what type of animals they take in and how they care for them. Level 2 and Up: Find out why most of the animals are there and what can be done to help prevent further abandonment or abuse.');
INSERT INTO badge_optional_requirements VALUES(6622,525,6,'Write a short essay about why you love your pet. If you do not have a pet yet, tell what pet you would choose and why.');
INSERT INTO badge_optional_requirements VALUES(6623,525,7,'Research at least 6 pets and then identify 3 that would make a good pet for you. Consider their daily care, the cost of keeping it, temperament, how well it would fit in with your family and home, and how long it generally lives.');
INSERT INTO badge_optional_requirements VALUES(6624,525,8,'Create a care chart for your pet in case you ever need a pet-sitter. Your chart should contain the following information: Name and description of your pet. Feeding schedule: What type of food, how much, and how often. Exercise: How much and what type is preferred. Training: Commands or discipline. Grooming: How often and what type. Medical History and Care: Veterinarian contact info. Cleaning: Bathing, cages, stalls, etc. Location of essential items: Food, grooming tools, leash, etc.');
INSERT INTO badge_optional_requirements VALUES(6625,525,9,'Read at least 2 books about your kind of pet. Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(6626,525,10,'Compare and contrast different foods for your pet. Collect ads for at least 6 different types of food for your pet. What information do they give you about the nutritional needs of your pet and which does the best job of meeting those needs? Compare cost verses nutrition and find the best value for your pet.');
INSERT INTO badge_optional_requirements VALUES(6627,525,11,'There are many homeless animals that need the love and support of a family. Design a campaign to find homes for these animals and share it with your local animal shelter.');
INSERT INTO badge_optional_requirements VALUES(6628,525,12,'Find out how to care for a female pet before and after she has her young. What do the newborns need if natural food is not available and at what age can they be weaned? What kind of bed or nest is needed? How can you housebreak the young if they are going to be allowed inside? Find out how to prevent your pet from having unwanted young.');
INSERT INTO badge_optional_requirements VALUES(6629,525,13,'Volunteer at a local animal rescue center for a minimum of 6 hours. Make sure you take any training required by the organization before you start.');
INSERT INTO badge_optional_requirements VALUES(6630,525,14,'What is the best way to transport your animal? What type of animal containment devices are available for your pet? Compare and contrast at least 2 different types of devices and decide which would be best suited for your pet.');
INSERT INTO badge_optional_requirements VALUES(6631,525,15,'Pets can also pass on certain diseases to humans. Find out about what illnesses your specific pet may be able to pass on. Examples may include tick-borne Lyme disease, rabies, or tularemia. What can you do to prevent your pet from getting and passing on these diseases? Create a flyer that will help educate people about a pet disease or help prevent a common pet disease.');
INSERT INTO badge_optional_requirements VALUES(6632,525,16,'Volunteer to provide exercise, grooming, or transportation to the vet for the pet of a home-bound person. Provide this service at least once a week for one month.');
INSERT INTO badge_optional_requirements VALUES(6633,525,17,'Research animal assisted therapy. What is it? What is its history? What type of animals work best for different types of therapy and what are the benefits to people?');
INSERT INTO badge_optional_requirements VALUES(6634,525,18,'Interview the owner or an employee of a pet store. What type of training did they need in order to perform their job safely and correctly? How long have they worked there? What do they love/dislike about their job? What changes have they seen in pet products over time?');
INSERT INTO badge_optional_requirements VALUES(6635,525,19,'Create a presentation about the care, feeding, and housing of your pet. Show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6636,525,20,'Attend a training class, or watch a video (with parental permission) on the proper way to train your pet. Teach your pet at least 3 commands, tricks, or special abilities.');
INSERT INTO badge_optional_requirements VALUES(6637,525,21,'Write an essay on what responsible pet ownership means to you.');
INSERT INTO badge_optional_requirements VALUES(6638,525,22,'Learn the anatomy of your kind of animal. Include muscles, bones, and internal organs.');
INSERT INTO badge_optional_requirements VALUES(6639,525,23,'Compare three books on training or care of your pet. Which one do you like best? Are they all equally accurate and easy to understand?');
INSERT INTO badge_optional_requirements VALUES(6640,525,24,'Make something for your pet such as a leather collar, a bed to sleep on, a knit sweater, a toy, new maze or cage extension.');
INSERT INTO badge_optional_requirements VALUES(6641,525,25,'Go to a show or fair that features your kind of pet.');
INSERT INTO badge_optional_requirements VALUES(6642,526,3,'Learn about how rabies can cause phobias. Which phobias does it usually cause and why?');
INSERT INTO badge_optional_requirements VALUES(6643,526,4,'Learn about various methods of treating a phobia.');
INSERT INTO badge_optional_requirements VALUES(6644,526,5,'Are phobias considered a mental illness?  If so, what category of mental illness do they fall into?');
INSERT INTO badge_optional_requirements VALUES(6645,526,6,'Research how phobias are named. Are they aptly named, or rather ironic? How does Hippopotomonstro-sesquippedaliophobia work for what it means?');
INSERT INTO badge_optional_requirements VALUES(6646,526,7,'Are all phobias “classic” or “old” or are there new phobias that have developed in recent times? For more help on this, try researching “nomophobia.”');
INSERT INTO badge_optional_requirements VALUES(6647,526,8,'Make a list of 20 specific phobias, and divide them into categories, such as animal, situational, natural environment, etc.');
INSERT INTO badge_optional_requirements VALUES(6648,526,9,'Make phobia bingo cards and try to name as many as possible. Play with your family or troop.');
INSERT INTO badge_optional_requirements VALUES(6649,526,10,'As you go about your daily life, try to recall the correct phobia names of things you see around you.');
INSERT INTO badge_optional_requirements VALUES(6650,526,11,'Discuss the impact that phobias can have on a person’s life.');
INSERT INTO badge_optional_requirements VALUES(6651,526,12,'Understand the role of genetics and environment in the development of phobias.');
INSERT INTO badge_optional_requirements VALUES(6652,526,13,'Discuss the potential benefits and drawbacks of medication for treating phobias.');
INSERT INTO badge_optional_requirements VALUES(6653,526,14,'Identify triggers for phobias and develop strategies to cope with them.');
INSERT INTO badge_optional_requirements VALUES(6654,526,15,'Create a personal plan for managing a specific phobia.');
INSERT INTO badge_optional_requirements VALUES(6655,526,16,'Read a book or watch a movie about phobias and discuss it with a parent or group.');
INSERT INTO badge_optional_requirements VALUES(6656,526,17,'Explain how phobias can affect relationships and social interactions.');
INSERT INTO badge_optional_requirements VALUES(6657,526,18,'Discuss how societal attitudes towards mental health impact people with phobias.');
INSERT INTO badge_optional_requirements VALUES(6658,526,19,'Attend a workshop or seminar on phobias and share what you learned with others.');
INSERT INTO badge_optional_requirements VALUES(6659,526,20,'Write a story about someone with a phobia.');
INSERT INTO badge_optional_requirements VALUES(6660,526,21,'Play Phobia Charades. Instructions: Divide into two teams. Place pieces of paper with various phobias in a hat. One team chooses a phobia and has one minute to act out the phobia without speaking. The other team tries to guess the phobia. If the other team guesses the phobia correctly, they get a point. Play continues until all of the phobias have been used. The team with the most points at the end of the game wins.');
INSERT INTO badge_optional_requirements VALUES(6661,526,22,'Understand the concept of desensitization and its role in managing phobias.');
INSERT INTO badge_optional_requirements VALUES(6662,526,23,'Practice relaxation techniques such as deep breathing and meditation to manage phobias.');
INSERT INTO badge_optional_requirements VALUES(6663,526,24,'Learn how to use positive self-talk to combat phobias.');
INSERT INTO badge_optional_requirements VALUES(6664,527,3,'Describe how to hold a camera and how to position it and yourself for different types of pictures such as close-ups, landscapes and portraits.');
INSERT INTO badge_optional_requirements VALUES(6665,527,4,'Choose a photo you took that you are not satisfied with and describe how it could be improved upon. Retake the picture with your proposed improvements.');
INSERT INTO badge_optional_requirements VALUES(6666,527,5,'How do you take a self-portrait? Try to take several under different conditions (including lighting, using a timer vs. holding it in front of you, night vs. day etc.).');
INSERT INTO badge_optional_requirements VALUES(6667,527,6,'Find out the history of the camera. Make a poster or other presentation showing the changes made to the camera over the years. Who invented the camera? When did color photos emerge?');
INSERT INTO badge_optional_requirements VALUES(6668,527,7,'Visit a museum or art gallery and view a photography exhibit. Choose your favorite and learn about the artist and their work.');
INSERT INTO badge_optional_requirements VALUES(6669,527,8,'Explain how a camera works. Make a poster to show the steps in which the camera can capture an image.');
INSERT INTO badge_optional_requirements VALUES(6670,527,9,'Take one of each of the following types of pictures. Display these pictures for your family, friends, or group: Landscape Portrait Group photo Action shot Candid photo');
INSERT INTO badge_optional_requirements VALUES(6671,527,10,'Explain the differences between indoor and outdoor photography. Make a poster to compare the two.');
INSERT INTO badge_optional_requirements VALUES(6672,527,11,'Take several portraits of someone or something special to you. Describe what makes a good portrait. Take some close-up and others further away. Frame one and give it as a gift.');
INSERT INTO badge_optional_requirements VALUES(6673,527,12,'Read a book on photography and practice the suggestions given. What did you learn about photography? Be able to explain what you learned either verbally, or through a written paragraph. Include the photos you took that reflect the things you learned.');
INSERT INTO badge_optional_requirements VALUES(6674,527,13,'Describe what a still-life picture is. Take a mystery picture by choosing objects that belong to a special person and have other people guess who it is.');
INSERT INTO badge_optional_requirements VALUES(6675,527,14,'Take some action shots in a series. Make a display or presentation to give as a gift. Paste them next to each other and write a small story related to it.');
INSERT INTO badge_optional_requirements VALUES(6676,527,15,'Describe a candid photograph. Take several of them. What is the difference between a candid photograph and other photographs? Get permission to take candid shots of someone who is celebrating a special occasion (happy or sad) and their family. Make a small scrapbook with these pictures and present it to the family.');
INSERT INTO badge_optional_requirements VALUES(6677,527,16,'Make a puzzle. Choose a picture with a lot of things in it to make the puzzle more fun. Paste the picture, face up, onto a thin piece of cardboard slightly larger than the picture. Place the picture under a few books for several hours or overnight so it will dry flat. Trim the cardboard to picture size. On the cardboard side draw lines to look like puzzle pieces. Cut out carefully.');
INSERT INTO badge_optional_requirements VALUES(6678,527,17,'Choose a famous photographer. Write a report or other presentation on that person.');
INSERT INTO badge_optional_requirements VALUES(6679,527,18,'Enter a public photography competition.');
INSERT INTO badge_optional_requirements VALUES(6680,527,19,'Shadow someone in the photography business for a day. Write down what you learned and share that with your family, friends, or group. Prepare yourself with questions to ask and bring a notebook to take notes. Oh, and don’t forget your camera!');
INSERT INTO badge_optional_requirements VALUES(6681,527,20,'Learn about advanced composition techniques, such as the Rule of Thirds, and try at least three new techniques.');
INSERT INTO badge_optional_requirements VALUES(6682,528,3,'Visit a hands-on physics museum or exhibit.');
INSERT INTO badge_optional_requirements VALUES(6683,528,4,'Visit an amusement park and discuss how physics affect the rides.  Identify areas of acceleration, gravity, velocity, speed, and friction.');
INSERT INTO badge_optional_requirements VALUES(6684,528,5,'Play an interactive physics video game.');
INSERT INTO badge_optional_requirements VALUES(6685,528,6,'Create a timeline of physics discoveries.  Include at least 15 items.');
INSERT INTO badge_optional_requirements VALUES(6686,528,7,'Learn about a famous physicist such as Neils Bohr, Albert Einstein, Galilei Galileo, Stephen Hawking, Isaac Newton, or Lord Kelvin.');
INSERT INTO badge_optional_requirements VALUES(6687,528,8,'Read a book or magazine about physics.');
INSERT INTO badge_optional_requirements VALUES(6688,528,9,'Design a roller coaster or other amusement park ride.  How would physics play a part in the way it works?  Identify areas of gravity, friction, speed, acceleration, velocity, potential energy, kinetic energy, etc.');
INSERT INTO badge_optional_requirements VALUES(6689,528,10,'Participate in a community service project that has to do with physics. For example you might create a game to teach physics concepts to younger kids and donate it to your local school, volunteer at or host a local bike rodeo, host a community paper airplane contest, etc.');
INSERT INTO badge_optional_requirements VALUES(6690,528,11,'Have an egg drop competition with your friends.  Using materials found around the house, create a way to protect an egg dropped from a distance of at least 10 feet.  Whose egg survived?  Why?');
INSERT INTO badge_optional_requirements VALUES(6691,528,12,'Learn about careers that involve physics.  Examples might include a physicist, an engineer, a roller coaster designer, or an architect.  Choose one and find out what type of education you would need, what salary you could expect, where you might need to live, etc.');
INSERT INTO badge_optional_requirements VALUES(6692,528,13,'Watch an age-appropriate documentary about physics or an invention that heavily involves physics, such as spacecraft.');
INSERT INTO badge_optional_requirements VALUES(6693,529,3,'Bake a fruit pie.');
INSERT INTO badge_optional_requirements VALUES(6694,529,4,'Try making a pies with at least two different kinds of crusts (cookie crust, graham cracker crust, pastry crust, etc)');
INSERT INTO badge_optional_requirements VALUES(6695,529,5,'Take a field trip to a bakery where they make pies.');
INSERT INTO badge_optional_requirements VALUES(6696,529,6,'Bake a savory or meat pie.');
INSERT INTO badge_optional_requirements VALUES(6697,529,7,'Participate in a community service project that has something to do with pies. For example, hold a bake sale and donate the money to charity. Give a pie as a gift to the fire department as a thank you. Donate pies to the local homeless shelter.');
INSERT INTO badge_optional_requirements VALUES(6698,529,8,'Learn about careers that involve pies. For example, pastry chefs, bakers, etc. What kind of education would you need for a career like this? What are the types of hours and average salary?');
INSERT INTO badge_optional_requirements VALUES(6699,529,9,'Learn the following pastry terms: cut-in, shielding, flute, one-crust pie vs. two-crust pie, tart and turnover.');
INSERT INTO badge_optional_requirements VALUES(6700,529,10,'Learn a song about pies.');
INSERT INTO badge_optional_requirements VALUES(6701,529,11,'What are some popular or traditional holiday pies? Bake one for an upcoming holiday.');
INSERT INTO badge_optional_requirements VALUES(6702,529,12,'Celebrate national PI day. Memorize the first ten digits of the number pi.');
INSERT INTO badge_optional_requirements VALUES(6703,529,13,'Make three pastry pie crusts from scratch using three different types of oil (lard, butter, vegetable oil, Crisco, coconut oil, etc.) How do the different oils affect the crust? Does the temperature of the oil affect the quality of the crust? Which was your favorite crust?');
INSERT INTO badge_optional_requirements VALUES(6704,529,14,'Make a custard or cream pie');
INSERT INTO badge_optional_requirements VALUES(6705,529,15,'Make a breakfast pie.');
INSERT INTO badge_optional_requirements VALUES(6706,529,16,'Make a pumpkin, sweet potato, or rutabaga pie.');
INSERT INTO badge_optional_requirements VALUES(6707,529,17,'Make a meringue pie. Pie Council http://www.piecouncil.org/Events/NationalPieDay/HistoryOfPies');
INSERT INTO badge_optional_requirements VALUES(6708,530,3,'Learn about the history of Pinewood Derby and tell your family, friends, or group about it.');
INSERT INTO badge_optional_requirements VALUES(6709,530,4,'Research the different types of legal weights (such as bullet weights vs. flat weights) and which ones work best for what shapes of cars.  Also, research the different placements of weights on cars (such as front vs. back or top vs. bottom) and find out which work best for speed and aerodynamics.');
INSERT INTO badge_optional_requirements VALUES(6710,530,5,'Assist the leader in setting up equipment, checking cars in, and/or passing out awards afterwards.');
INSERT INTO badge_optional_requirements VALUES(6711,530,6,'Help a younger child with their car.');
INSERT INTO badge_optional_requirements VALUES(6712,530,7,'Make a small booklet containing drawings of at least 8 different car designs and show it to your family, friends, or group.  Which do you think are the best for racing?  Why?');
INSERT INTO badge_optional_requirements VALUES(6713,530,8,'Talk to others at the race about their cars and ask them why they chose their particular design, how they created the car, if they have ever raced before, and if so, if they ever won anything, etc. ­­');
INSERT INTO badge_optional_requirements VALUES(6714,530,9,'Make a scrapbook page or collage of photos taken at the race.  Be sure to include photos of the cars, the racetrack and the awards ceremony.');
INSERT INTO badge_optional_requirements VALUES(6715,530,10,'Learn how pinewood derby tracks are designed and built.  Is there more than one design? Try designing your own track.');
INSERT INTO badge_optional_requirements VALUES(6716,530,11,'Discuss the ethics involved in purchasing a ready-made car or having an adult build yours for you.  Why would this be considered cheating?  What is the point of the race?  What is it trying to teach youth?');
INSERT INTO badge_optional_requirements VALUES(6717,530,12,'Many communities have pinewood derby tracks open to the public.  Find out if there is one near you and if so visit it to watch or participate in a race.');
INSERT INTO badge_optional_requirements VALUES(6718,530,13,'Visit a craft/hobby shop that sells supplies for pinewood derby cars.  Look through the selections of paints, decals, tools, weights, and accessories.  Set and reasonable budget for a car and plan a list of supplies that will fill your needs and still stay in budget.');
INSERT INTO badge_optional_requirements VALUES(6719,530,14,'Research specialty tools available specifically marketed for making pinewood derby cars.');
INSERT INTO badge_optional_requirements VALUES(6720,531,3,'Visit at least one historical site where pioneer history is reenacted and /or taught.');
INSERT INTO badge_optional_requirements VALUES(6721,531,4,'Learn how to sew a sunbonnet or other piece of pioneer clothing.');
INSERT INTO badge_optional_requirements VALUES(6722,531,5,'Learn to make a corn husk doll or other pioneer toy.');
INSERT INTO badge_optional_requirements VALUES(6723,531,6,'Learn to cook a pioneer meal or try at least 3 recipes from pioneer days');
INSERT INTO badge_optional_requirements VALUES(6724,531,7,'Learn to churn your own butter.  Put heavy cream in a baby food jar with a clean, glass marble.  Put on the lid and shake until you have butter.  Pour off the whey and salt to taste if you desire.');
INSERT INTO badge_optional_requirements VALUES(6725,531,8,'Learn to make your own soap.');
INSERT INTO badge_optional_requirements VALUES(6726,531,9,'Learn to make your own candles.');
INSERT INTO badge_optional_requirements VALUES(6727,531,10,'Wear a pioneer/ late 1800’s outfit to a party, play, or reading festival that includes pioneer activities.');
INSERT INTO badge_optional_requirements VALUES(6728,531,11,'Learn to play part of a song (or a whole song) on the fiddle, dulcimer or another pioneer era instrument.');
INSERT INTO badge_optional_requirements VALUES(6729,531,12,'Do a pioneer craft such as making red striped wrapping paper or cutting designs on the edges of shelf paper.');
INSERT INTO badge_optional_requirements VALUES(6730,531,13,'Make a miniature log cabin or sod house or spend a day helping someone build a regular-size one.');
INSERT INTO badge_optional_requirements VALUES(6731,531,14,'Find out about the different types of apparatus for smoking meat.  Smoke some meat and eat some of it.');
INSERT INTO badge_optional_requirements VALUES(6732,531,15,'On a map, trace and label one of the routes the pioneers used to settle the west.');
INSERT INTO badge_optional_requirements VALUES(6733,531,16,'Create a timeline of westward expansion. Your timeline must include at least 10 items.');
INSERT INTO badge_optional_requirements VALUES(6734,531,17,'Play a game based on westward expansion (for example, The Oregon Trail computer game).');
INSERT INTO badge_optional_requirements VALUES(6735,531,18,'Learn about the hardships pioneers faced. What diseases and dangers did they face?');
INSERT INTO badge_optional_requirements VALUES(6736,531,19,'Read the journal or diary of a pioneer.');
INSERT INTO badge_optional_requirements VALUES(6737,531,20,'Learn why pioneers traveled west. Why did many choose to take wagons than a ship?');
INSERT INTO badge_optional_requirements VALUES(6738,531,21,'Watch an age-appropriate documentary about pioneers.');
INSERT INTO badge_optional_requirements VALUES(6739,531,22,'What jobs did each member of the family do as a pioneer?');
INSERT INTO badge_optional_requirements VALUES(6740,531,23,'Learn about the concept of Manifest Destiny. How did this drive pioneers west?');
INSERT INTO badge_optional_requirements VALUES(6741,531,24,'Learn what role the American government during pioneer times.');
INSERT INTO badge_optional_requirements VALUES(6742,531,25,'Learn about the role of animals during pioneer times, both domesticated and wild.');
INSERT INTO badge_optional_requirements VALUES(6743,531,26,'Create a presentation about pioneers and show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6744,531,27,'If you were a pioneer, what would you pack for your journey, and what would you leave behind?');
INSERT INTO badge_optional_requirements VALUES(6745,533,3,'Read a book about pirates.');
INSERT INTO badge_optional_requirements VALUES(6746,533,4,'Watch an age-appropriate pirate movie. Is it very realistic?  Why or why not?');
INSERT INTO badge_optional_requirements VALUES(6747,533,5,'Build a model pirate ship, or build a play pirate ship out of a large box.  Include at least 6 items that would be found on a real pirate ship.');
INSERT INTO badge_optional_requirements VALUES(6748,533,6,'Learn to talk like a pirate.  Find out what the following words and expressions mean (and where they came from if you can!) How many more can you find? Ahoy Avast Dead men tell no tales He’s gone to Davy Jones’s Locker Me hearties Shiver me timbers Aye Ye Walk the plank Deadlights Landlubber Scallywag Doubloons Grog Jolly Roger');
INSERT INTO badge_optional_requirements VALUES(6749,533,7,'Dress like a pirate and host a pirate party.');
INSERT INTO badge_optional_requirements VALUES(6750,533,8,'Create a pirate craft.');
INSERT INTO badge_optional_requirements VALUES(6751,533,9,'Learn a sea shanty.');
INSERT INTO badge_optional_requirements VALUES(6752,533,10,'Learn about what type of clothing pirates wore, what their life was like, and how they were punished.');
INSERT INTO badge_optional_requirements VALUES(6753,533,11,'Learn about modern international anti-piracy laws and organizations.');
INSERT INTO badge_optional_requirements VALUES(6754,533,12,'Learn the history of pirate flags such as the Jolly Roger and what the various colors and symbols stood for.  Design a pirate flag of your own.');
INSERT INTO badge_optional_requirements VALUES(6755,533,13,'Watch an age-appropriate documentary about pirates.');
INSERT INTO badge_optional_requirements VALUES(6756,533,14,'Learn about one of the famous islands often visited by pirates, such as Tortuga.');
INSERT INTO badge_optional_requirements VALUES(6757,533,15,'Learn about the dangers pirates faced, including disease.');
INSERT INTO badge_optional_requirements VALUES(6758,533,16,'Learn how pirates navigated the oceans. Understand basic navigation using a compass and create a simple map of your surroundings.');
INSERT INTO badge_optional_requirements VALUES(6759,533,17,'Learn about Articles of Agreement and how pirates divided their plunder.  Create your own articles of agreement if you were captain.  What rules would you have?');
INSERT INTO badge_optional_requirements VALUES(6760,533,18,'Master the art of tying five essential maritime knots used by pirates.');
INSERT INTO badge_optional_requirements VALUES(6761,533,19,'Learn the names and functions of various parts of a ship.');
INSERT INTO badge_optional_requirements VALUES(6762,533,20,'Identify and explain the significance of three constellations used for navigation.');
INSERT INTO badge_optional_requirements VALUES(6763,533,21,'Write a short poem capturing the spirit of pirate life.');
INSERT INTO badge_optional_requirements VALUES(6764,533,22,'Learn and demonstrate basic fencing or swordplay techniques.');
INSERT INTO badge_optional_requirements VALUES(6765,534,3,'Make a dessert pizza.');
INSERT INTO badge_optional_requirements VALUES(6766,534,4,'Make a breakfast pizza.');
INSERT INTO badge_optional_requirements VALUES(6767,534,5,'Make a list of at least 6 different cheeses you could use on pizza and try them.');
INSERT INTO badge_optional_requirements VALUES(6768,534,6,'Grow or visit a pizza garden.');
INSERT INTO badge_optional_requirements VALUES(6769,534,7,'Tour a pizza parlor.');
INSERT INTO badge_optional_requirements VALUES(6770,534,8,'Learn about different sauces used on pizzas, like red sauce, white sauce, garlic sauce, pesto sauce, etc. Try at least 3.');
INSERT INTO badge_optional_requirements VALUES(6771,534,9,'Learn about different ways to cook pizza, including BBQ, brick oven, commercial pizza oven, home oven, microwave, etc. What are the pros and cons of each?');
INSERT INTO badge_optional_requirements VALUES(6772,534,10,'Learn about the new trend toward “gourmet” pizzas. What new and interesting combinations can you find on current menus. Create your own “gourmet” pizza recipe.');
INSERT INTO badge_optional_requirements VALUES(6773,534,11,'Learn about the different types of pizza crusts used, like deep dish, thin crust, calzones, whole wheat, gluten free, etc.');
INSERT INTO badge_optional_requirements VALUES(6774,534,12,'Create a pizza for at least one type of dietary restriction, such as lactose intolerance.');
INSERT INTO badge_optional_requirements VALUES(6775,535,3,'Earn the Astronomy badge at your level.');
INSERT INTO badge_optional_requirements VALUES(6776,535,4,'Watch a documentary or a movie about the planets. Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(6777,535,5,'Learn about the technology that enables us to learn more about the planets, such as the Hubble telescope or the Mars Mission Rover. Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(6778,535,6,'Write an essay about the planets and share it with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(6779,535,7,'Research careers relating to the planets. Examples include an astronaut, a designer or manufacturer of spacecraft, or an astronomer. If possible, shadow someone for a day who works in a job that relates to planets.');
INSERT INTO badge_optional_requirements VALUES(6780,535,8,'Make a scrapbook page, collage, or poster that shows what you learned in earning this badge.');
INSERT INTO badge_optional_requirements VALUES(6781,535,9,'Learn about the history of NASA. What does NASA stand for? What is their official job? Who created NASA?');
INSERT INTO badge_optional_requirements VALUES(6782,535,10,'Visit a planetarium. Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(6783,535,11,'Learn about other planetary objects, such as dwarf planets or astroids. Be able to name at least three dwarf planets. Also, learn about the moons that orbit certain planets, such as Jupiter and Saturn. Be able to name at least four moons, and know which planet each one orbits. Which planet has the most moons?');
INSERT INTO badge_optional_requirements VALUES(6784,535,12,'Research famous celestial occurrences in history, such as planetary conjunctions or appearances of Halley’s Comet.');
INSERT INTO badge_optional_requirements VALUES(6785,535,13,'Read a book about the planets. Which planet did you find most interesting to read about?');
INSERT INTO badge_optional_requirements VALUES(6786,535,14,'How do scientists believe planets were created? Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(6787,536,3,'Find out what Mummers’ Plays were, when they were played, who acted in them, and what they were about.');
INSERT INTO badge_optional_requirements VALUES(6788,536,4,'Find out about 2 types of theatre buildings, such as open air theatre.');
INSERT INTO badge_optional_requirements VALUES(6789,536,5,'Find a play that has been turned into a TV drama/film and watch it, then discuss it with a parent or adult. Read the play in book form. Which did you like best?');
INSERT INTO badge_optional_requirements VALUES(6790,536,6,'Read a book about the development of the theatre from Greek to modern times.');
INSERT INTO badge_optional_requirements VALUES(6791,536,7,'Learn about the different types of plays, such as comedies, tragedies, and farces.');
INSERT INTO badge_optional_requirements VALUES(6792,536,8,'Have some friends over and see what sort of a play you can come up with by taking turns to each add just one line at a time.');
INSERT INTO badge_optional_requirements VALUES(6793,536,9,'Learn about careers in the playwriting business. How much do they pay? What sort of education do you need? If possible, shadow someone for a day who works in the playwriting business.');
INSERT INTO badge_optional_requirements VALUES(6794,536,10,'If you know a foreign language very well, try to write a play of at least 4 lines per character in that language. Or try writing a play of at least 4 lines each in another dialect, such as Cockney, Cornish, Yorkshire, etc.');
INSERT INTO badge_optional_requirements VALUES(6795,536,11,'At certain times in history, the theatre and plays have been banned. Read a book about one of these periods. Tell your family, friends, or group about what you learned.');
INSERT INTO badge_optional_requirements VALUES(6796,536,12,'Know the meaning of the following terms: Act Audience Backdrop Backstage Balcony Costume Curtain Enter Exit Flies Floodlights Footlights Place Pit Production Stage Scene Wings');
INSERT INTO badge_optional_requirements VALUES(6797,537,3,'Draw or Color a picture of your chosen plant. Make sure you use the correct colors.');
INSERT INTO badge_optional_requirements VALUES(6798,537,4,'Read a nonfiction book about your chosen plant.');
INSERT INTO badge_optional_requirements VALUES(6799,537,5,'Learn how to grow your chosen plant. Does it grow from a bulb, a seed or a cutting? If possible, grow one of your chosen plants.');
INSERT INTO badge_optional_requirements VALUES(6800,537,6,'Attend a show or exhibition that includes your chosen plant. How many varieties did you see? Were there any that were new to you?');
INSERT INTO badge_optional_requirements VALUES(6801,537,7,'Find a poem or song about your chosen plant and read it. Did you like it? Level 2 & 3, find two poems or songs; Level 4 & 5, find three poems or songs.');
INSERT INTO badge_optional_requirements VALUES(6802,537,8,'Grow some of your chosen plants and enter them in a show or contest.');
INSERT INTO badge_optional_requirements VALUES(6803,537,9,'Find examples of your chosen plant in artwork such as paintings, architectural detail or textile design. Which do you like best?');
INSERT INTO badge_optional_requirements VALUES(6804,537,10,'Write a poem about your chosen plant.');
INSERT INTO badge_optional_requirements VALUES(6805,537,11,'Flowers and plants are often chosen as symbols of nations or other geographical divisions; for instance, the bluebonnet is known for being the state flower of Texas, while the maple leaf is the symbol of Canada and the golden wattle is the national symbol of Australia. Is your chosen plant a national, state or local symbol anywhere in the world?');
INSERT INTO badge_optional_requirements VALUES(6806,537,12,'Find literary excerpts about your chosen plant, such as the garden scene in Alice in Wonderland where Alice talks to the Tiger-Lily and the Daisies, the rose garden in The Secret Garden, or Shakespeare’s A Midsummer Night’s Dream.');
INSERT INTO badge_optional_requirements VALUES(6807,537,13,'Do a craft project about your chosen plant, such as a painting, drawing, embroidery project, etc.');
INSERT INTO badge_optional_requirements VALUES(6808,537,14,'Insects are very important to many plants as they pollinate them and thus help to produce seeds.  Earn the Insect Specific badge for a pollinator insect at your level.');
INSERT INTO badge_optional_requirements VALUES(6809,537,15,'The Victorians created a whole language using flowers and plants to mean different things. Learn about the Victorian Language of Flowers; what does your chosen plant represent?');
INSERT INTO badge_optional_requirements VALUES(6810,537,16,'Are there any world records for your chosen plant, such as tallest, fastest-growing, most planted in one garden, etc.?');
INSERT INTO badge_optional_requirements VALUES(6811,537,17,'If your plant is edible, make a recipe or garnish that includes it.');
INSERT INTO badge_optional_requirements VALUES(6812,537,18,'If your plant is poisonous, what are the symptoms?  Is there a cure?  What first aid should be administered if eaten?  Is this plant poisonous to animals as well?');
INSERT INTO badge_optional_requirements VALUES(6813,537,19,'Does your plant self pollinate or cross pollinate?  How?  Does it do so by wind or does it require the help of an insect?');
INSERT INTO badge_optional_requirements VALUES(6814,538,3,'Understand the labeling and certification systems related to plant-based products, such as organic or non-GMO.');
INSERT INTO badge_optional_requirements VALUES(6815,538,4,'Explore the various cooking and preparation methods used for plant-based foods, including steaming, roasting, or blending.  Cook a plant based food using at least 3 different methods.');
INSERT INTO badge_optional_requirements VALUES(6816,538,5,'Learn about the different categories of plant-based foods; fruits, vegetables, legumes, grains, nuts, seeds, herbs and spices.  How do they differ?  Why is it important to eat a selection from all categories and not just one?');
INSERT INTO badge_optional_requirements VALUES(6817,538,6,'Identify and name at least five different plant-based protein sources, such as different legumes, tofu, or quinoa.  Cook a recipe with one or more and choose one plant based protein you can eat raw and try some.');
INSERT INTO badge_optional_requirements VALUES(6818,538,7,'Learn about the cultural significance of plant-based foods in different cuisines and traditions around the world.  Make at least one traditional recipe using plant based foods.');
INSERT INTO badge_optional_requirements VALUES(6819,538,8,'Volunteer at a community garden or urban farm, assisting with planting, harvesting, or maintaining plant-based food sources.');
INSERT INTO badge_optional_requirements VALUES(6820,538,9,'Visit a local vegan or vegetarian restaurant to explore the diverse range of plant-based dishes and culinary creativity.');
INSERT INTO badge_optional_requirements VALUES(6821,538,10,'Learn about plant based meat substitutes such as the Impossible Burger.  What are they made of?  Try one.  How does it compare in both flavor and nutrion to its meat counterpart?');
INSERT INTO badge_optional_requirements VALUES(6822,538,11,'Experiment with plant-based alternatives to traditional animal-based products, such as dairy-free milk or egg replacers.');
INSERT INTO badge_optional_requirements VALUES(6823,538,12,'Understand the concept of whole foods and the benefits of incorporating minimally processed plant-based foods into your meals.');
INSERT INTO badge_optional_requirements VALUES(6824,538,13,'Learn about plant-based meal planning and how to create balanced and nutritious meals without animal products.');
INSERT INTO badge_optional_requirements VALUES(6825,538,14,'Explore the use of herbs, spices, and seasonings to enhance the flavors of plant-based dishes and create exciting culinary experiences.');
INSERT INTO badge_optional_requirements VALUES(6826,538,15,'Research and discuss the challenges and misconceptions surrounding plant-based diets, and how to address them.');
INSERT INTO badge_optional_requirements VALUES(6827,538,16,'Research the nutritional considerations for plant-based diets, including potential nutrient deficiencies and strategies for ensuring a well-balanced diet.');
INSERT INTO badge_optional_requirements VALUES(6828,538,17,'Research the nutritional benefits of plant-based foods, including their fiber, vitamins, minerals, and phytonutrient content.');
INSERT INTO badge_optional_requirements VALUES(6829,538,18,'Explore the health benefits of incorporating plant-based foods into your diet, such as reducing the risk of chronic diseases.');
INSERT INTO badge_optional_requirements VALUES(6830,539,3,'Bring your favorite stuffed toys to show your friends or group and tell why they are special to you.');
INSERT INTO badge_optional_requirements VALUES(6831,539,4,'Earn the Collecting badge for your level using your plush toys.');
INSERT INTO badge_optional_requirements VALUES(6832,539,5,'Host a stuffed animal tea party and invite your friends and their favorite stuffed toys.');
INSERT INTO badge_optional_requirements VALUES(6833,539,6,'With an adult’s help/permission, look online for 3 charities that accept gently used stuffed toys and find out what they do with them.  Collect stuffed toys and donate them to one of the charities you researched.');
INSERT INTO badge_optional_requirements VALUES(6834,539,7,'Help organize a stuffed toy drive for charity.');
INSERT INTO badge_optional_requirements VALUES(6835,539,8,'Discuss with an adult or write a paragraph on why you think stuffed toys are important.');
INSERT INTO badge_optional_requirements VALUES(6836,539,9,'Discuss with an adult or write a paragraph comparing stuffed toys to baby dolls. What are the differences and similarities of what we can learn from them?');
INSERT INTO badge_optional_requirements VALUES(6837,539,10,'What hypo-allergenic materials can plush toys be made out of? Are there organic materials?');
INSERT INTO badge_optional_requirements VALUES(6838,539,11,'Visit an exhibit of plush toys.');
INSERT INTO badge_optional_requirements VALUES(6839,539,12,'Make a simple plush toy yourself.');
INSERT INTO badge_optional_requirements VALUES(6840,539,13,'Learn about careers or volunteer options involving plush toys. What sort of job/position could you have? What would your hours and pay be like? Where would you volunteer?');
INSERT INTO badge_optional_requirements VALUES(6841,539,14,'Give a plush toy as a gift.');
INSERT INTO badge_optional_requirements VALUES(6842,539,15,'Learn about special or expensive brands of plush toys and what is significant of them.');
INSERT INTO badge_optional_requirements VALUES(6843,539,16,'Learn about someone who was involved with plush toys, such as President Teddy Roosevelt. Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(6844,540,3,'Learn the history of pocket knives.');
INSERT INTO badge_optional_requirements VALUES(6845,540,4,'Practice learning the following cuts using a plastic knife and a bar of soap: •        Push Cut –With your thumb on the back of the blade, angle the blade away from you.  Push and shave off small pieces of wood. •        Score Line – This cut gives you a clear line that you can use to cut back to. •        Stop Cut – Used when scoring a line or cutting back to the line you scored.');
INSERT INTO badge_optional_requirements VALUES(6846,540,5,'Properly use a pocket knife to open a sealed box.');
INSERT INTO badge_optional_requirements VALUES(6847,540,6,'Properly use a pocket knife to cut rope.');
INSERT INTO badge_optional_requirements VALUES(6848,540,7,'Learn a push cut and safely use your pocket knife to whittle a point on a stick to toast a marshmallow or hotdog.');
INSERT INTO badge_optional_requirements VALUES(6849,540,8,'Take a field trip to a store that sells pocket knives and have someone teach you about them.');
INSERT INTO badge_optional_requirements VALUES(6850,540,9,'Visit someone with a collection of different pocket knives or a pocket knife exhibition.');
INSERT INTO badge_optional_requirements VALUES(6851,540,10,'Know what to do if someone is injured using a pocket knife, whether this is a minor or major cut. Whether you should fetch an adult or treat it yourself should depend on your age, the situation, and your experience.');
INSERT INTO badge_optional_requirements VALUES(6852,540,11,'Draw a design onto the wood (or soap).  Use your pocket knife to carve or whittle out the design. Keep it simple; complicated drawings are difficult to carve! Balsa wood or Ivory soap works well for beginners.');
INSERT INTO badge_optional_requirements VALUES(6853,540,12,'Use a pocket knife to help prepare a meal or snack.');
INSERT INTO badge_optional_requirements VALUES(6854,542,4,'Read a biography of a poet.');
INSERT INTO badge_optional_requirements VALUES(6855,542,5,'Read aloud at least fifteen minutes of poetry as part of a story time at a library, shelter, or non-profit daycare or nursery. Choose your poems carefully ahead of time so that the vocabulary is not too advanced. Did you have to explain the poetry to the children?');
INSERT INTO badge_optional_requirements VALUES(6856,542,6,'Illustrate a poem using any kind of art you want.');
INSERT INTO badge_optional_requirements VALUES(6857,542,7,'Visit the library and explore the poetry section. Read, or have someone read to you, some of the poems you found.');
INSERT INTO badge_optional_requirements VALUES(6858,542,8,'Make three lists of at least 5 words that rhyme.  For example you could find 5 words that rhyme with cat, 5 with coat, and 5 with dog. Level 2 and Up: Learn about rhymed poetry. What are the rhyme schemes AA and ABAB? Find examples of each.');
INSERT INTO badge_optional_requirements VALUES(6859,542,9,'What are ABC poetry, acrostics, and tongue twisters? Find an example of each.');
INSERT INTO badge_optional_requirements VALUES(6860,542,10,'Find out what shaped, concrete, or picture (three names for the same thing) poetry is and read two examples. Take a poem you like or write your own and then put it into a shape form.');
INSERT INTO badge_optional_requirements VALUES(6861,542,11,'Poems are most often grouped by meter, verse form, and stanza form. Learn what these terms mean. Find two poems that have differing meter, two with differing verse, and two with differing stanzas.');
INSERT INTO badge_optional_requirements VALUES(6862,542,12,'Set a poem to music.');
INSERT INTO badge_optional_requirements VALUES(6863,542,13,'Attend a talent show or public reading time that includes recitation of poetry.');
INSERT INTO badge_optional_requirements VALUES(6864,542,14,'Find two books of illustrated poems. How do the illustrations enhance the poetry? Do you like one of the books better than the other? Are there any illustrations that don’t fit the poems the way you think they should? What does the book cover say about the training of the artist?');
INSERT INTO badge_optional_requirements VALUES(6865,542,15,'Compare a poem about an historical event with actual accounts of the event. Did the poet change anything in order to make the poem more interesting? Which did you like better, the poem or the regular account?');
INSERT INTO badge_optional_requirements VALUES(6866,542,16,'Find an example of a poem that inspired a famous piece of art or music or that was referred to in a piece of classical literature. Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(6867,542,17,'Help put on a literary party that features poetry as a fundraiser or in an effort to help other members earn their Poetry badge.');
INSERT INTO badge_optional_requirements VALUES(6868,542,18,'Find out what the following terms mean and find an example of each in poetry: Personification Onomatopoeia Repetition Metaphor Hyperbole Alliteration Simile Imagery');
INSERT INTO badge_optional_requirements VALUES(6869,542,19,'Help with some service project involving poetry. This can be composing rhymes for greeting cards for soldiers or ill persons, putting beautifully lettered poems on walls at a school or banquet, including poetry on invitations or newsletters you make for a non-profit organization.');
INSERT INTO badge_optional_requirements VALUES(6870,542,20,'Learn about a poet who has used their poetry as a way to express their beliefs. A famous example would be Maya Angelou’s I Know Why the Caged Bird Sings.');
INSERT INTO badge_optional_requirements VALUES(6871,544,3,'Look at pictures of 5 different types of poisonous plants. What are some differences and similarities you notice? List several differences and several similarities.');
INSERT INTO badge_optional_requirements VALUES(6872,544,4,'Learn about poison gardens, such as the Alnwick Garden or the garden at Blarney Castle.');
INSERT INTO badge_optional_requirements VALUES(6873,544,5,'Learn about the types of flowers that grow on poisonous plants. Research at least four different types.');
INSERT INTO badge_optional_requirements VALUES(6874,544,6,'Make a booklet about poisonous plants. Include at least ten different types, with facts and pictures about each.');
INSERT INTO badge_optional_requirements VALUES(6875,544,7,'Make a poster about poisonous plants to hang up somewhere locally (with permission) for people to be more aware.');
INSERT INTO badge_optional_requirements VALUES(6876,544,8,'Why are some plants poisonous to humans but okay for animals to eat? And vice versa? Research why this could be.');
INSERT INTO badge_optional_requirements VALUES(6877,544,9,'Interview someone who has been effected by a poisonous plant. What did they experience? How did they cure it?');
INSERT INTO badge_optional_requirements VALUES(6878,544,10,'Study a career that involves poisonous plants, such as a botanist. What type of salary could you expect to receive? What kind of education would you need?');
INSERT INTO badge_optional_requirements VALUES(6879,544,11,'Participate in a community service project involving plants, such as making posters to place around local parks that warn about poisonous plants or cleaning up poisonous plants from an area where lots of children play.');
INSERT INTO badge_optional_requirements VALUES(6880,544,12,'How do indigenous cultures use poisonous plants? Study a specific culture that uses poisonous plants in their medicine or for other purposes.');
INSERT INTO badge_optional_requirements VALUES(6881,545,3,'Who have been the villains of the Pokemon series? What are their goals? How does it contrast to the protagonists?');
INSERT INTO badge_optional_requirements VALUES(6882,545,4,'Make a timeline of ten important events in Pokemon history, such as when the television series first aired or when the first game was released.');
INSERT INTO badge_optional_requirements VALUES(6883,545,5,'Write about the different generations of Pokemon. How are they alike? Different? How has it changed over the years?');
INSERT INTO badge_optional_requirements VALUES(6884,545,6,'With a parent’s permission, watch episodes of the Pokemon television series. Preschool: Watch three episodes. Level 1: Watch five. Level 2: Watch seven. Level 3: Watch nine. Level 4: Watch eleven. Level 5: Watch thirteen.');
INSERT INTO badge_optional_requirements VALUES(6885,545,7,'Watch one of the Pokemon movies.');
INSERT INTO badge_optional_requirements VALUES(6886,545,8,'Pikachu is an important and popular Pokemon. Why do you think that is? What makes him different than other Pokemon? Who is his trainer? How did he come to be with his trainer?');
INSERT INTO badge_optional_requirements VALUES(6887,545,9,'Who are the Elite Four? How can you battle them? What makes them different in each game?');
INSERT INTO badge_optional_requirements VALUES(6888,545,10,'Pokemon is also a trading card game. Learn the rules of the game and play with a friend.');
INSERT INTO badge_optional_requirements VALUES(6889,545,11,'Reach level 5 of Pokemon Go. Find a gym and try to battle it.');
INSERT INTO badge_optional_requirements VALUES(6890,545,12,'Play one of the spinoff games (Mystery Dungeon, Ranger, Battles, etc). What makes them different than one of the main series generational games?');
INSERT INTO badge_optional_requirements VALUES(6891,545,13,'Learn the evolutions of at least ten different Pokemon. How do its attacks and abilities change as it evolves?');
INSERT INTO badge_optional_requirements VALUES(6892,545,14,'Visit a Pokemon booth at a convention or other event.');
INSERT INTO badge_optional_requirements VALUES(6893,545,15,'Learn about specialty moves and evolutions, such as Z-Move or Mega-Evolutions.');
INSERT INTO badge_optional_requirements VALUES(6894,546,3,'Design your dream pollinator garden. Remember, gardens don’t have to be large. Even a few potted plants on your patio can help our pollinators. Be sure to include native flowers and plants to your area that will provide the best sources of nutrition for pollinators. If resources allow, create the garden you design.');
INSERT INTO badge_optional_requirements VALUES(6895,546,4,'Contact your local extension office, native plant society, or Master Gardeners and find out about volunteer opportunities to help pollinators in your area.  If possible volunteer to help in some way.');
INSERT INTO badge_optional_requirements VALUES(6896,546,5,'Create a poster that celebrates pollinators native to your area. Be sure to include information about the creatures you highlight, the products or foods that require pollinators, or the ways we can help pollinator populations.');
INSERT INTO badge_optional_requirements VALUES(6897,546,6,'Write a letter to your school, library, local park, or other community space asking them to leave a portion of their lawn unmowed and wild to help benefit bees and other pollinating insects.');
INSERT INTO badge_optional_requirements VALUES(6898,546,7,'Interview a local beekeeper, entomologist, or Master Gardener, or invite them to speak to your group. Request that they discuss information about pollinator populations in your area, the challenges they face, as well as ways you can help locally.');
INSERT INTO badge_optional_requirements VALUES(6899,546,8,'Go on a bug hunt. Using a bug net, catch, observe, and release insects in your backyard. What did you find? How many of them are pollinators?');
INSERT INTO badge_optional_requirements VALUES(6900,546,9,'Host a Pollinator’s Party celebrating pollinators and the work they do. Serve foods that showcase the fruits, vegetables, and other treats that would not be possible without them. Use the party to bring awareness to the importance of pollinators in your area and have your guests take the pledge to do all they can to help.');
INSERT INTO badge_optional_requirements VALUES(6901,546,10,'Make a list of 10 items or foods you use each day and a creature that pollinates it.');
INSERT INTO badge_optional_requirements VALUES(6902,546,11,'What are 5 reasons for pollinator’s declining numbers?');
INSERT INTO badge_optional_requirements VALUES(6903,546,12,'Explain the role of bees in pollination and their importance to food production.  Identify at least three different species of bees found in your area.');
INSERT INTO badge_optional_requirements VALUES(6904,546,13,'Explain the difference between honeybees and native bees and their respective roles in pollination.');
INSERT INTO badge_optional_requirements VALUES(6905,546,14,'Demonstrate how to identify male and female bees and explain their different roles in pollination.');
INSERT INTO badge_optional_requirements VALUES(6906,546,15,'Discuss the impact of habitat loss on pollinator populations and the importance of preserving natural habitats.');
INSERT INTO badge_optional_requirements VALUES(6907,546,16,'Discuss the impact of pesticides on bee and other pollinator populations and the importance of pollinator-friendly farming practices.  Name at least one pesticide which affects bees.');
INSERT INTO badge_optional_requirements VALUES(6908,546,17,'Explain the role of butterflies and moths in pollination and their importance in maintaining plant diversity.  Identify at least three different species of butterflies or moths found in your area.');
INSERT INTO badge_optional_requirements VALUES(6909,546,18,'Visit a local botanical garden or arboretum and observe pollinators in action.');
INSERT INTO badge_optional_requirements VALUES(6910,546,19,'Explain how flowers have adapted to attract pollinators and describe at least three different types of flower adaptations.');
INSERT INTO badge_optional_requirements VALUES(6911,546,20,'Identify at least 10 different types of flowers that are important for pollinators in your area.');
INSERT INTO badge_optional_requirements VALUES(6912,546,21,'Explain the role of hummingbirds in pollination and their importance to the ecosystem.  Identify at least two different species of hummingbirds found in your area.');
INSERT INTO badge_optional_requirements VALUES(6913,546,22,'Research and present on a pollinator conservation project in your area.');
INSERT INTO badge_optional_requirements VALUES(6914,546,23,'Discuss the role of bats in pollination and their importance to the ecosystem.  Identify at least one species of bat found in your area.');
INSERT INTO badge_optional_requirements VALUES(6915,546,24,'Participate in a citizen science project that involves monitoring pollinator populations. Resources submitted by Christina Hunt.  These sites are not part of Curiosity Untamed.  Use at your own risk.https://kidsgardening.org/wild-for-pollinators-program/https://pollinatorlive.pwnet.org/webcasts/index.phphttps://www.abfnet.org/https://www.pollinator.org/guides');
INSERT INTO badge_optional_requirements VALUES(6916,547,3,'Try using paint, ink, or powders to embellish your clay.');
INSERT INTO badge_optional_requirements VALUES(6917,547,4,'Make a piece of jewelry.');
INSERT INTO badge_optional_requirements VALUES(6918,547,5,'Make a miniature for a dollhouse, diorama, or similar.');
INSERT INTO badge_optional_requirements VALUES(6919,547,6,'Make a gift for someone from polymer clay.');
INSERT INTO badge_optional_requirements VALUES(6920,547,7,'Make something to adorn a something for your home.');
INSERT INTO badge_optional_requirements VALUES(6921,547,8,'Try to mix colors of clay to make a new color.');
INSERT INTO badge_optional_requirements VALUES(6922,547,9,'Make a Christmas ornament or similar.');
INSERT INTO badge_optional_requirements VALUES(6923,547,10,'Learn to make clay “canes.”');
INSERT INTO badge_optional_requirements VALUES(6924,547,11,'Try to make a set of identical pieces, like you would for earrings or buttons.');
INSERT INTO badge_optional_requirements VALUES(6925,547,12,'Try using stamps or a similar tool to add texture to the clay.');
INSERT INTO badge_optional_requirements VALUES(6926,547,13,'Make a sculpture that required a “skeleton” of toothpicks or similar.');
INSERT INTO badge_optional_requirements VALUES(6927,547,14,'Make a set of beads.');
INSERT INTO badge_optional_requirements VALUES(6928,547,15,'Make an animal, mythical creature, or something similar.');
INSERT INTO badge_optional_requirements VALUES(6929,548,3,'Make a food item using popcorn and give it as a gift to someone else.  Examples might be: a tin of caramel corn, popcorn balls or popcorn cake. Donate to your local fire fighters, police officers, shut ins or nursing home residents.');
INSERT INTO badge_optional_requirements VALUES(6930,548,4,'Host a Popcorn Party and use popcorn for the decor, food and the games.');
INSERT INTO badge_optional_requirements VALUES(6931,548,5,'With appropriate help if needed, prepare at least two recipes that use popcorn.');
INSERT INTO badge_optional_requirements VALUES(6932,548,6,'Learn the history of popcorn, including the processing and use of popcorn in general. When and where were the oldest ears of popcorn found? Are there any myths or legends regarding popcorn? Make a timeline with 10 events.');
INSERT INTO badge_optional_requirements VALUES(6933,548,7,'Try to grow some corn. How many days until you see roots? Leaves? Ears? Find out when your popcorn will be ready to pick and how to prepare it for popping.');
INSERT INTO badge_optional_requirements VALUES(6934,548,8,'Make a craft out of popcorn or other parts of the corn plant. Examples: a seed mosaic, bird feeder, popcorn garland for a Christmas tree, corn husk doll.');
INSERT INTO badge_optional_requirements VALUES(6935,548,9,'Find a healthy alternative to replace a sweet or savory popcorn recipe. Make them both and conduct a blind taste test with a few friends or family members.');
INSERT INTO badge_optional_requirements VALUES(6936,548,10,'Tour a popcorn farm or processing plant in person or virtually (with a parent’s permission). Find out how to grow, harvest, store, process, package and ship it. Which states grow the most corn?');
INSERT INTO badge_optional_requirements VALUES(6937,548,11,'Read a book on popcorn.');
INSERT INTO badge_optional_requirements VALUES(6938,548,12,'Find out how to make stale popcorn crispy again. Why does it work? Try it.');
INSERT INTO badge_optional_requirements VALUES(6939,548,13,'Make up a game using popcorn and then try it out with your family, friends, or group. Make modifications if necessary to make the game work.');
INSERT INTO badge_optional_requirements VALUES(6940,548,14,'List three companies that sell popcorn. What is gourmet popcorn? List some of the popcorn products they sell. Which one would you like best?');
INSERT INTO badge_optional_requirements VALUES(6941,548,15,'Find out what kind of pests affect popcorn, what beneficial insects like this grain and how easy it is to grow organically.');
INSERT INTO badge_optional_requirements VALUES(6942,548,16,'Study the economics of popcorn farms.  What are the start-up costs and hoped-for income?  Do the farmers need to hire a lot of help?  What expenses are there?');
INSERT INTO badge_optional_requirements VALUES(6943,548,17,'Name and the describe the different varieties of popcorn. What are the different flavor characteristics? What varieties create a mushroom shape when popped? Which ones a butterfly shape? Describe how to color popcorn using food dye.');
INSERT INTO badge_optional_requirements VALUES(6944,548,18,'Learn some fun popcorn facts. How much popcorn does the average American eat annually? What is the ideal popcorn popping temperature? Where is the ideal place to store popcorn? How heavy was the world’s largest popcorn ball?When is National Popcorn Poppin’ month?');
INSERT INTO badge_optional_requirements VALUES(6945,548,19,'Try out four different unusual topping recipes, such as Tapatío hot sauce mixed with butter.');
INSERT INTO badge_optional_requirements VALUES(6946,549,3,'Make a postcard set as a gift for someone.');
INSERT INTO badge_optional_requirements VALUES(6947,549,4,'Participate in the Flat Stanley project and ask everyone who receives your Flat Stanley to send you a postcard.');
INSERT INTO badge_optional_requirements VALUES(6948,549,5,'Look through a postcard collection that belongs to someone else.');
INSERT INTO badge_optional_requirements VALUES(6949,549,6,'Look through pictures of old fashioned postcards.');
INSERT INTO badge_optional_requirements VALUES(6950,549,7,'Find examples of humorous postcards, wildlife postcards, nature postcards, city/town postcards, etc.  How many categories can you find? Which is your favorite?');
INSERT INTO badge_optional_requirements VALUES(6951,549,8,'Send a postcard of where you live to someone far away. It might be even your favorite hero!');
INSERT INTO badge_optional_requirements VALUES(6952,549,9,'Make postcards sets and sell them to raise money for a local charity.');
INSERT INTO badge_optional_requirements VALUES(6953,549,10,'Help design a postcard marketing campaign for a local business or charity.');
INSERT INTO badge_optional_requirements VALUES(6954,549,11,'Find out about deltiology, the official name for postcard collecting.  What types of postcards do people collect?  Where can you buy, sell and trade postcards?');
INSERT INTO badge_optional_requirements VALUES(6955,549,12,'Make your own postcard and send it to a friend or family member.');
INSERT INTO badge_optional_requirements VALUES(6956,549,13,'Send a postcard to your family or friends while you are traveling. You can even mail one to yourself!');
INSERT INTO badge_optional_requirements VALUES(6957,550,3,'Read an account of how prayer changed the course of someone’s life or the course of history.');
INSERT INTO badge_optional_requirements VALUES(6958,550,4,'Learn about prayer in other religions. How does it reflect your own?');
INSERT INTO badge_optional_requirements VALUES(6959,550,5,'Read some well-known “standard” prayers.  Memorize one.');
INSERT INTO badge_optional_requirements VALUES(6960,550,6,'Look up prayer in the dictionary.  How does the definition differ from what you were expecting it to say? Share your discovery with someone.');
INSERT INTO badge_optional_requirements VALUES(6961,550,7,'Keep a journal of prayer requests (answers are optional). Keep it for at least one month.');
INSERT INTO badge_optional_requirements VALUES(6962,550,8,'Read a devotional or theological book on prayer recommended by your pastor, rabbi, elder, priest, etc.');
INSERT INTO badge_optional_requirements VALUES(6963,550,9,'Why do some people use incense, icons, prayer beads, or prayer wheels when they pray?  What is the function of each?');
INSERT INTO badge_optional_requirements VALUES(6964,550,10,'Read a collection of prayers.');
INSERT INTO badge_optional_requirements VALUES(6965,550,11,'Illustrate a famous or well-known prayer.');
INSERT INTO badge_optional_requirements VALUES(6966,550,12,'Learn a new-to-you song that is a prayer set to music.');
INSERT INTO badge_optional_requirements VALUES(6967,550,13,'Read a well-known book of prayers. What did you think?');
INSERT INTO badge_optional_requirements VALUES(6968,550,14,'What are some common motions or body positions for prayer?  What are their purposes?');
INSERT INTO badge_optional_requirements VALUES(6969,550,15,'Research prayer’s effect on the ill.');
INSERT INTO badge_optional_requirements VALUES(6970,550,16,'Research and learn about 5 famous prayers.');
INSERT INTO badge_optional_requirements VALUES(6971,550,17,'Write the word PRAYER down the side of your page.  Now think of a word that begins with P that has to do with Prayer such as Penitent.  Next think of a work starting with R…and work your way through the entire word.');
INSERT INTO badge_optional_requirements VALUES(6972,550,18,'Make a list of all the ways God has blessed you.  Then pray and thank God for each one.');
INSERT INTO badge_optional_requirements VALUES(6973,550,19,'What does your book of faith say about prayer?  Discuss with an adult one verse for preschoolers, three for levels 1 & 2, five for level 3 & 4, and eight for level 5.');
INSERT INTO badge_optional_requirements VALUES(6974,550,20,'Learn and discuss with an adult, 1 quotation about prayer for preschoolers, three for levels 1 & 2, five for level 3 & 4, and eight for level 5.');
INSERT INTO badge_optional_requirements VALUES(6975,550,21,'Interview a religious leader and learn their perspective on prayer.');
INSERT INTO badge_optional_requirements VALUES(6976,550,22,'Make a Prayer Hand craft where each finger stands for an essential aspect of prayer:  confession, petition, intercession, thanksgiving and praise.');
INSERT INTO badge_optional_requirements VALUES(6977,550,23,'Practice prayer in a natural setting, such as a park or forest, and reflect on the connection between God and nature.');
INSERT INTO badge_optional_requirements VALUES(6978,550,24,'Research prayer practices throughout history, focusing on different time periods and civilizations.');
INSERT INTO badge_optional_requirements VALUES(6979,550,25,'Differentiate between types of prayer, such as intercessory, meditative, thanksgiving, and contemplative prayer.');
INSERT INTO badge_optional_requirements VALUES(6980,550,26,'Attend a group prayer session or prayer circle, and reflect on the communal aspects of prayer.');
INSERT INTO badge_optional_requirements VALUES(6981,550,27,'Examine how prayer is depicted in art throughout history and in different cultures.');
INSERT INTO badge_optional_requirements VALUES(6982,550,28,'Learn about the use of music in prayer rituals across various cultures and traditions.');
INSERT INTO badge_optional_requirements VALUES(6983,550,29,'Visit a museum or exhibition showcasing prayer-related artifacts and objects.');
INSERT INTO badge_optional_requirements VALUES(6984,550,30,'Write an essay reflecting on how prayer has contributed to your personal growth and understanding of spirituality.');
INSERT INTO badge_optional_requirements VALUES(6985,551,3,'Earn the Kindness badge for your level and discuss how it relates to princesses.');
INSERT INTO badge_optional_requirements VALUES(6986,551,4,'Determine on a map where the princess stories you read about were originally written.  If the stories took place in a real location, find those on the map as well.');
INSERT INTO badge_optional_requirements VALUES(6987,551,5,'Learn about a princess from a country you have not studied before.');
INSERT INTO badge_optional_requirements VALUES(6988,551,6,'Learn about the qualities a princess must have, such as brave, caring, and intelligent. Which qualities do you have? Which qualities do you need to work on?');
INSERT INTO badge_optional_requirements VALUES(6989,551,7,'Watch both a Disney Princess movie (animated or not) as well as a non-Disney princess movie.  Which did you like better and why?');
INSERT INTO badge_optional_requirements VALUES(6990,551,8,'Watch or read a biography about a real princess (such as Princess Anastasia, Princess Diana, Princess Kate, etc.).');
INSERT INTO badge_optional_requirements VALUES(6991,551,9,'Make a princess themed craft.');
INSERT INTO badge_optional_requirements VALUES(6992,551,10,'Write your own princess story.');
INSERT INTO badge_optional_requirements VALUES(6993,551,11,'Act out a scene from your favorite princess story and perform it in front of friends or family.');
INSERT INTO badge_optional_requirements VALUES(6994,551,12,'Participate in a community service project that revolves around princesses such as teaching younger kids how to make a princess craft or holding a princess collection drive for princess books, toys, and movies to donate.');
INSERT INTO badge_optional_requirements VALUES(6995,551,13,'Make a timeline of at least 15 real princesses and where they lived.');
INSERT INTO badge_optional_requirements VALUES(6996,551,14,'Learn about the Prince Charming from each of your princess stories. Why is he important to the story? What is the same about each of them, and what is different? Is there a difference between Disney Princes and non-Disney Princes? Make a chart showing what you found.');
INSERT INTO badge_optional_requirements VALUES(6997,551,15,'Learn about a real prince (either present day or in history).');
INSERT INTO badge_optional_requirements VALUES(6998,551,16,'Earn the Etiquette badge and discuss how it relates to princesses.');
INSERT INTO badge_optional_requirements VALUES(6999,551,17,'Learn about the responsibilities of princesses, both in the present and the past.');
INSERT INTO badge_optional_requirements VALUES(7000,553,3,'Give a speech of an age-appropriate length to your family, friends, or group about all the things you enjoy about Curiosity Untamed.');
INSERT INTO badge_optional_requirements VALUES(7001,553,4,'Learn a poem and recite it to your family, friends, or group. Preschool-Level 1: Recite a poem with 1-3 verses. Level 2: Recite a poem with 4-5 verses. Level 3: 6-8 verses. Levels 4-5: 10-12 verses.');
INSERT INTO badge_optional_requirements VALUES(7002,553,5,'Learn about the life of a famous public speaker.  Find out how they became a good public speaker and what sort of speeches they gave. If you are repeating this requirement at a higher level you must learn about a different public speaker.');
INSERT INTO badge_optional_requirements VALUES(7003,553,6,'Make a booklet/collection of poems/mnemonics that pass on knowledge from one generation to another such as, “30 days have September, April, June and November; all the rest have 31 excepting February alone and that has 28 days clear and 29 in each leap-year.”   This sort of poetry is part of what is known as the oral tradition of passing on knowledge.');
INSERT INTO badge_optional_requirements VALUES(7004,553,7,'Give a how-to speech, teaching your audience how to do something.');
INSERT INTO badge_optional_requirements VALUES(7005,553,8,'Give a speech on your hobby.  Include information and facts about the hobby itself as well as reasons you enjoy it.');
INSERT INTO badge_optional_requirements VALUES(7006,553,9,'Research the history of public speaking.  Find out about the different areas where people spoke in public.');
INSERT INTO badge_optional_requirements VALUES(7007,553,10,'Make a booklet of your favorite famous speeches.');
INSERT INTO badge_optional_requirements VALUES(7008,553,11,'Give a speech about current events.  This could be current world political events, current local news events, or current events in the environmental, social or arts areas of life.  Choose a subject that you feel will be interesting to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(7009,553,12,'Give a declamation speech. A good speaker is usually familiar with well-known speeches made by famous people in government, arts or industry.  Learn a famous speech by a well-known person and deliver it as you would expect the original person to have done so.  Some examples are Winston Churchill’s “We Will Fight Them on the Beaches” speech; Martin Luther King Jr’s “I Have a Dream” speech, etc.');
INSERT INTO badge_optional_requirements VALUES(7010,553,13,'Give an interpretation speech. Learn a well-known speech from a Shakespeare play and perform it to your family, friends, or group. You may interpret this speech to make it as dramatic as you choose.');
INSERT INTO badge_optional_requirements VALUES(7011,553,14,'Give a speech to a local organization or city council about something that is important to you.');
INSERT INTO badge_optional_requirements VALUES(7012,553,15,'Learn about careers that have a high degree of public speaking.  If possible shadow someone who does public speaking.');
INSERT INTO badge_optional_requirements VALUES(7013,553,16,'Research the history of ballads.  These folk-lore poems transmitted history orally from one generation to another.  Learn a ballad and its history and recite it to your family, friends, or group, giving them some historical background.');
INSERT INTO badge_optional_requirements VALUES(7014,554,3,'Learn about the history of public transport.  What was the first kind?  Which is your favorite?  Which is the most unusual?');
INSERT INTO badge_optional_requirements VALUES(7015,554,4,'Choose one method of public transport and study its history.  What made it popular at its peak?  Is it still as popular?  What caused its decline? You may repeat this requirement for different methods of public transport.');
INSERT INTO badge_optional_requirements VALUES(7016,554,5,'Learn about the history of coaching inns and stage coaches.  What led to their decline?');
INSERT INTO badge_optional_requirements VALUES(7017,554,6,'What health and safety regulations are in effect on public transport systems?  What age do you have to be to work in public transport?  What training and qualifications do you need?  What salary can you expect to earn?  Levels 3-5, if possible, shadow a public transport worker.');
INSERT INTO badge_optional_requirements VALUES(7018,554,7,'Find out how to get a Passport.  Which agency do you go through to obtain one?  How much does it cost?  How long is it valid?');
INSERT INTO badge_optional_requirements VALUES(7019,554,8,'Find out about travel visas.  When would you need one?  How long are they valid?  How much do they cost?');
INSERT INTO badge_optional_requirements VALUES(7020,554,9,'Earn the Road Trip Badge at your level.');
INSERT INTO badge_optional_requirements VALUES(7021,554,10,'Plan an international trip.  Work out the costs involved.  What documentation would you need?');
INSERT INTO badge_optional_requirements VALUES(7022,554,11,'Learn about travel insurance.  When would you need to purchase this?  How much does it cost?  How long is it good for?  What does it cover?');
INSERT INTO badge_optional_requirements VALUES(7023,554,12,'Make a model or picture of an aspect of public transport.');
INSERT INTO badge_optional_requirements VALUES(7024,554,13,'Do a community service project related to public transport.');
INSERT INTO badge_optional_requirements VALUES(7025,554,14,'Read a book about public transport.');
INSERT INTO badge_optional_requirements VALUES(7026,554,15,'Learn what to do when public transport becomes disrupted due to a power-outage, worker strike, or natural disaster.');
INSERT INTO badge_optional_requirements VALUES(7027,554,16,'Earn the Travel Destination Badge at your level.');
INSERT INTO badge_optional_requirements VALUES(7028,554,17,'How do public transport systems affect the ecosystem?  Are there ways in which travel has been made more environmentally friendly?  What can be done to protect the environment but still preserve efficient travel?');
INSERT INTO badge_optional_requirements VALUES(7029,554,19,'Study a specific country’s unusual forms of public transport.  For example, the rickshaw in China, camels in Africa, etc.');
INSERT INTO badge_optional_requirements VALUES(7030,554,20,'Study into the history of hotels/motels.  Which was the first national chain?  What made it successful?  How do hotels/motels rely on public transport to generate their business?');
INSERT INTO badge_optional_requirements VALUES(7031,555,1,'Find out how much it costs to enter the pumpkin patch.  Is the park a pay one price to enter admission or is it free admission that uses tickets to pay per ride?  Are discounts available for groups? Season passes? Coupons or promotions?  What are the opening and closing dates for the season?');
INSERT INTO badge_optional_requirements VALUES(7032,555,2,'Understand prices for  the various sizes and variety options for the pumpkins available for purchase.');
INSERT INTO badge_optional_requirements VALUES(7033,555,3,'Visit or ride many of the features available at the pumpkin patch.');
INSERT INTO badge_optional_requirements VALUES(7034,555,4,'Play a carnival game, pan for crystals or gem stones, participate in a show, or do another non-ride, non-pumpkin picking activity.');
INSERT INTO badge_optional_requirements VALUES(7035,555,5,'Try a specialty food or drink item of the pumpkin patch.  If none are available, eat a pumpkin-themed food item at another point in time.');
INSERT INTO badge_optional_requirements VALUES(7036,555,6,'How should you choose a pumpkin at the patch? How will you know it’s ripe? What qualities should you look for or avoid? How will you get your pumpkin from the field and out of the park?  Which pumpkin varieties should you choose for your purpose? (Display, carving, baking, etc)');
INSERT INTO badge_optional_requirements VALUES(7037,555,7,'Take a behind the scene tour of of your pumpkin patch.');
INSERT INTO badge_optional_requirements VALUES(7038,555,8,'Using a smart phone, smart watch, or pedometer to track your steps around the patch for the day.  Determine how far you walked, over how much time, how many steps equal a mile, convert miles to kilometers, and calculate your average miles per hour.');
INSERT INTO badge_optional_requirements VALUES(7039,555,9,'Learn the history of your pumpkin patch. Who owns or runs it, (family, corporation, church, community group)? When did it open? Has it expanded over time?');
INSERT INTO badge_optional_requirements VALUES(7040,555,10,'Design a feature for your pumpkin patch, such as a pumpkin painting center, rides, petting zoo, etc.  Be able to explain why this feature fits the atmosphere of the pumpkin patch, what ages can participate, and how you would supervise people in the feature to keep them safe.  Draw a picture or make a 3D model of your feature, and decide where it could go on a map (available or sketched) of the pumpkin patch.');
INSERT INTO badge_optional_requirements VALUES(7041,555,11,'Watch a documentary, a movie, or read a book with a  pumpkin patch theme.');
INSERT INTO badge_optional_requirements VALUES(7042,555,12,'Learn the history of Jack-o-lanterns and associated traditions.');
INSERT INTO badge_optional_requirements VALUES(7043,555,13,'Decorate a pumpkin (real or artificial), like a jack-o-lantern or alternate design.  This can include choosing a design and helping scoop out and carve a pumpkin (with adult assistance if appropriate), painting a pumpkin, attaching extra things such as felt, plastic jewels, googly eyes, or animal ears, etc.  Help clean up the area when you’re done. Show your pumpkin to someone else.');
INSERT INTO badge_optional_requirements VALUES(7044,555,14,'Participate in a service project that involves your pumpkin patch in some way.  This could be supporting a charity affiliated with it, volunteering to help take a group of younger kids or disabled kids to the pumpkin patch, raising money to buy tickets to the pumpkin patch for a local community group.  Help kids, seniors, etc carve or decorate pumpkins.');
INSERT INTO badge_optional_requirements VALUES(7045,555,15,'Complete an associated badge, such as Pumpkin, Farm Equipment,  or Farmer.');
INSERT INTO badge_optional_requirements VALUES(7046,556,4,'Visit a pumpkin patch and pick pumpkins.');
INSERT INTO badge_optional_requirements VALUES(7047,556,5,'With parental supervision, carve at least two pumpkins with different designs. What are the safety rules when carving? You can use a traditional face or carve a specific shape, object, or scene. Be creative!');
INSERT INTO badge_optional_requirements VALUES(7048,556,6,'Do a community service project involving pumpkins. Examples include making pumpkin bread and delivering it to the homeless, having a bake sale, etc.');
INSERT INTO badge_optional_requirements VALUES(7049,556,7,'Make a pumpkin craft.');
INSERT INTO badge_optional_requirements VALUES(7050,556,8,'Learn songs about pumpkins.');
INSERT INTO badge_optional_requirements VALUES(7051,556,9,'Take seeds from the pumpkin and make pumpkins seeds to eat.');
INSERT INTO badge_optional_requirements VALUES(7052,556,10,'Learn about at least three pumpkin myths.');
INSERT INTO badge_optional_requirements VALUES(7053,556,11,'Learn about careers that involve pumpkins, such as farmers, artists who carve pumpkins, florists or designers who use pumpkins in their designs. What type of pay could you expect?  Where might you have to live? If possible, shadow someone for a day in one of these careers.');
INSERT INTO badge_optional_requirements VALUES(7054,556,12,'Research different kinds of pumpkins and how to tell them apart. What sort of shapes and colors of gourds are still considered pumpkins?');
INSERT INTO badge_optional_requirements VALUES(7055,556,13,'Learn about the pumpkin’s significance in specific holidays such as Halloween. Why do people carve pumpkins?');
INSERT INTO badge_optional_requirements VALUES(7056,557,3,'Craft a pumpkin spice-scented candle, potpourr or other craft item.');
INSERT INTO badge_optional_requirements VALUES(7057,557,4,'Create a timeline of key moments in the popularity of pumpkin spice.');
INSERT INTO badge_optional_requirements VALUES(7058,557,5,'Try a pumpkin spice latte or tea.');
INSERT INTO badge_optional_requirements VALUES(7059,557,6,'Participate in a community service project with a pumpkin spice theme such as organizing a pumpkin spice-themed charity bake sale and donate the proceeds; host a pumpkin spice-themed event at a local senior center or community center; or volunteer at a local food bank and donate pumpkin spice-flavored goods');
INSERT INTO badge_optional_requirements VALUES(7060,557,7,'Bake a batch of pumpkin spice cookies, muffins, or bread from a traditional recipe.');
INSERT INTO badge_optional_requirements VALUES(7061,557,8,'Create a unique pumpkin spice recipe and share it with your friends or family.');
INSERT INTO badge_optional_requirements VALUES(7062,557,9,'Host a pumpkin spice tasting party with a variety of treats.');
INSERT INTO badge_optional_requirements VALUES(7063,557,10,'Develop a pumpkin spice-themed board game or puzzle.');
INSERT INTO badge_optional_requirements VALUES(7064,557,11,'Learn about the chemical compounds that make up pumpkin spice.');
INSERT INTO badge_optional_requirements VALUES(7065,557,12,'Visit a local pumpkin patch or farm to learn about pumpkin cultivation.');
INSERT INTO badge_optional_requirements VALUES(7066,557,13,'Organize a pumpkin spice-themed scavenger hunt.');
INSERT INTO badge_optional_requirements VALUES(7067,557,14,'Learn about the health benefits of pumpkin spice ingredients.');
INSERT INTO badge_optional_requirements VALUES(7068,557,15,'Create a collage of pumpkin spice packaging, advertisements, etc.');
INSERT INTO badge_optional_requirements VALUES(7069,558,3,'Learn about the history of puppets. What are some of the early puppet forms that we know about?');
INSERT INTO badge_optional_requirements VALUES(7070,558,4,'Watch a puppet show, preferably live or a video recording of a puppet show.');
INSERT INTO badge_optional_requirements VALUES(7071,558,5,'Watch a television show that uses puppets, such as the Muppets or Sesame Street. Try to see how the puppets work. Notice how they interact with each other and other actors in the show.');
INSERT INTO badge_optional_requirements VALUES(7072,558,6,'Spend some time with or watch a documentary about a professional puppeteer. Make note of his/her techniques and the details of the puppets he/she uses.');
INSERT INTO badge_optional_requirements VALUES(7073,558,7,'Put on a puppet show for your family, friends, or group. Be sure to spend some time creating your story and the personality of each puppet.');
INSERT INTO badge_optional_requirements VALUES(7074,558,8,'Explore the use of sound effects for a puppet show. Make the sounds with your voice, explore props, or make a recording to use.');
INSERT INTO badge_optional_requirements VALUES(7075,558,9,'Learn about some different ways of hiding or showing the puppeteers during a performance. You should understand the terms light curtain, blacklight puppetry, and white light theatre. Why might each option be chosen?');
INSERT INTO badge_optional_requirements VALUES(7076,558,10,'Use puppets to teach younger children a skill or lesson.');
INSERT INTO badge_optional_requirements VALUES(7077,558,11,'Do a service project involving puppets. Some examples would include doing a puppet show for a library story time or being part of the church puppet team for Vacation Bible School or Sunday School.');
INSERT INTO badge_optional_requirements VALUES(7078,558,12,'Research a career as a puppeteer. What training would you need? Does college or apprenticeship make sense? What skills besides puppet operation would help you?');
INSERT INTO badge_optional_requirements VALUES(7079,558,13,'How can you use puppets in careers/adulthood besides being a professional puppeteer? Share your list with an adult. Can they suggest a few more ways?');
INSERT INTO badge_optional_requirements VALUES(7080,558,14,'Research a famous puppeteer. Share what you have learned about their life with someone else.');
INSERT INTO badge_optional_requirements VALUES(7081,558,15,'Learn how puppets are used in another culture.');
INSERT INTO badge_optional_requirements VALUES(7082,558,16,'Make a timeline of puppet history. You must have at least 10 items on your timeline.');
INSERT INTO badge_optional_requirements VALUES(7083,559,3,'Make your own purse from felt, fabric, crochet, etc.');
INSERT INTO badge_optional_requirements VALUES(7084,559,4,'Decorate a plain purse or a homemade purse with markers, paints, sequins, charms, feathers, or any other craft supply.');
INSERT INTO badge_optional_requirements VALUES(7085,559,5,'Visit the purse department of a store and look at all the different purses for sale. What sizes/colors/styles are available? Consider what you would be carrying in your purse when thinking about size.');
INSERT INTO badge_optional_requirements VALUES(7086,559,6,'Give a small purse filled with items to someone who needs it.');
INSERT INTO badge_optional_requirements VALUES(7087,559,7,'Participate in a community service project that involves purses. Examples might include holding a purse drive to donate purses to a women’s shelter, making purses to sell to raise money for a charity, etc.');
INSERT INTO badge_optional_requirements VALUES(7088,559,8,'Pick a past decade and make a poster discussing what purses looked like during that time period. Attach pictures or drawings to your poster and write a short description explaining purse history from that time.');
INSERT INTO badge_optional_requirements VALUES(7089,559,9,'Make a small bag or purse for your doll.');
INSERT INTO badge_optional_requirements VALUES(7090,559,10,'Learn about a career in purse design. Where would you work, and what kind of salary could you expect? What sort of experience/schooling is required?');
INSERT INTO badge_optional_requirements VALUES(7091,559,11,'Bring your favorite purse to a meeting for show and tell. Why is this purse special?');
INSERT INTO badge_optional_requirements VALUES(7092,559,12,'Learn about expensive brands of purses. How much would a high quality brand cost and on average how long might it last?');
INSERT INTO badge_optional_requirements VALUES(7093,559,13,'Learn the importance of keeping your purse with you at all times while in public and learn some safety tips to follow to avoid your purse getting stolen.');
INSERT INTO badge_optional_requirements VALUES(7094,560,3,'Create a timeline of the construction of famous pyramids around the world.');
INSERT INTO badge_optional_requirements VALUES(7095,560,4,'Watch a documentary or read a book about the Great Pyramid of Giza.');
INSERT INTO badge_optional_requirements VALUES(7096,560,5,'Learn about the gods and symbols associated with pyramids in ancient Egypt and create a related piece of art.');
INSERT INTO badge_optional_requirements VALUES(7097,560,6,'Calculate dimensions and slope angle of the Great Pyramid of Giza and recreate it to scale as a model.');
INSERT INTO badge_optional_requirements VALUES(7098,560,7,'Create a blueprint of a pyramid with measurements and labels for its dimensions.  Include at least three chambers:  a lower chamber, a queen’s chamber and a king’s chamber as well as passegeways to get to each.');
INSERT INTO badge_optional_requirements VALUES(7099,560,8,'Build a pulley system or ramp to explore how ancient people might have lifted heavy stones.');
INSERT INTO badge_optional_requirements VALUES(7100,560,9,'Make a cross-section drawing of a famous pyramid, showing inner chambers and passageways.');
INSERT INTO badge_optional_requirements VALUES(7101,560,10,'Explore hieroglyphics by making your own cartouche (nameplate) and placing it on a mini pyramid.');
INSERT INTO badge_optional_requirements VALUES(7102,560,11,'Create a replica of a sarcophagus or treasure found in a pyramid using craft materials.');
INSERT INTO badge_optional_requirements VALUES(7103,560,12,'Learn about the alignment of pyramids with stars or cardinal directions.  Bonus:  Earn your Cardinal Directions Badge.');
INSERT INTO badge_optional_requirements VALUES(7104,560,13,'Learn the difference between a tetrahedron and a pyramid.  Create a simple paper example of each.');
INSERT INTO badge_optional_requirements VALUES(7105,560,14,'Learn about myths or legends about pyramids.');
INSERT INTO badge_optional_requirements VALUES(7106,560,15,'Design your own pyramid with unique features and explain its purpose.');
INSERT INTO badge_optional_requirements VALUES(7107,560,16,'Create a travel brochure for tourists visiting famous pyramids today.');
INSERT INTO badge_optional_requirements VALUES(7108,560,17,'Explore the relationship between the base area and the height of a pyramid by calculating its volume using a mathematical formula.');
INSERT INTO badge_optional_requirements VALUES(7109,560,18,'Research and compare the burial practices associated with pyramids in different cultures.');
INSERT INTO badge_optional_requirements VALUES(7110,560,19,'Take a virtual tour of an ancient pyramid.');
INSERT INTO badge_optional_requirements VALUES(7111,560,20,'Research the theories on how ancient pyramids were built.');
INSERT INTO badge_optional_requirements VALUES(7112,560,21,'Invent a board game or scavenger hunt based on exploring pyramids and uncovering treasures.');
INSERT INTO badge_optional_requirements VALUES(7113,560,22,'Name and identify at least 6 modern pyramids and what they are used for.  Locate them them on a map.');
INSERT INTO badge_optional_requirements VALUES(7114,561,3,'Watch a video about pyrographing.');
INSERT INTO badge_optional_requirements VALUES(7115,561,4,'Read a book about pyrographing.  Which tips were most helpful?  Which designs did you like the best?  Which did you like the least?  Why?');
INSERT INTO badge_optional_requirements VALUES(7116,561,5,'Make a pyrograph piece as a picture.');
INSERT INTO badge_optional_requirements VALUES(7117,561,6,'Make a pyrograph piece as the top of a box/chest.');
INSERT INTO badge_optional_requirements VALUES(7118,561,7,'Make a pyrograph piece for outdoor use.  What kinds of finishes can you use to protect your artwork from the elements?');
INSERT INTO badge_optional_requirements VALUES(7119,561,8,'Find some unusual pieces of wood suitable for pyrographing?  Where did you find them? What can you make these unusual pieces into?');
INSERT INTO badge_optional_requirements VALUES(7120,561,9,'Level 3 and Up: shadow someone for a day who works pyrography professionally.');
INSERT INTO badge_optional_requirements VALUES(7121,561,10,'Earn the Woodworking Badge at your level.');
INSERT INTO badge_optional_requirements VALUES(7122,561,11,'Use pyrographing as part of a Community Service Project.');
INSERT INTO badge_optional_requirements VALUES(7123,561,10,'Learn about a contemporary pyrographing artist and view their work either in person, on the Internet or through books.');
INSERT INTO badge_optional_requirements VALUES(7124,561,11,'Find out the cost of the tools and equipment necessary for pyrographing.  What extra tools/items might be optional extras?  How much do these cost?');
INSERT INTO badge_optional_requirements VALUES(7125,561,12,'Make a pyrographed toy, such as a set of wooden blocks for a child.');
INSERT INTO badge_optional_requirements VALUES(7126,561,13,'What other materials can be used for pyrographing besides wood?  Look at some examples of other media used for pyrography.');
INSERT INTO badge_optional_requirements VALUES(7127,561,14,'Make a piece of pyrography on a medium other than wood.');
INSERT INTO badge_optional_requirements VALUES(7128,561,15,'Pyrograph a design on a pencil.  Level 3 and up: pyrograph at least 3 pencils.');
INSERT INTO badge_optional_requirements VALUES(7129,561,16,'Pyrograph an outdoor game, such as a yard Yahtzee set.');
INSERT INTO badge_optional_requirements VALUES(7130,561,17,'Pyrograph an indoor game, such as a set of popsicle stick cards.');
INSERT INTO badge_optional_requirements VALUES(7131,561,18,'Pyrograph something for your pet, such as a set of drinking and eating bowls for a dog or cat.');
INSERT INTO badge_optional_requirements VALUES(7132,561,19,'Pyrograph something for your kitchen, such as a set of wooden spoons.');
INSERT INTO badge_optional_requirements VALUES(7133,561,20,'Learn about famous historical pyrography artists such as Robert Ball Hughes and J William Fosdick.  If you did Eagle 2* learn about different artists. Helpful resources: Pyrography for Beginners: A Complete Step by Step Guide to Getting Started with the Art of Pyrography, by Michael Richard');
INSERT INTO badge_optional_requirements VALUES(7134,562,3,'Participate in a community service project that involves quilting.  Ideas might include quilting dog beds for the local animal shelter, quilting blankets for the local homeless shelter, or baby blankets for a hospital.');
INSERT INTO badge_optional_requirements VALUES(7135,562,4,'Make a sampler quilt.  Using a different pattern for each square.');
INSERT INTO badge_optional_requirements VALUES(7136,562,5,'Make a friendship quilt with each friend decorating one square.  This is a great club project with each child decorating one square.');
INSERT INTO badge_optional_requirements VALUES(7137,562,6,'Read a “how to” book about quilting for your ability level.');
INSERT INTO badge_optional_requirements VALUES(7138,562,7,'Be able to identify 6 different quilt patterns by name.');
INSERT INTO badge_optional_requirements VALUES(7139,562,8,'What careers are there that involve quilting?  Research one and find out what the average wage is, hours worked, and where you might have to live.');
INSERT INTO badge_optional_requirements VALUES(7140,562,9,'Explain what type of fabric is used in quilting and why?');
INSERT INTO badge_optional_requirements VALUES(7141,562,10,'Earn the Sewing badge at your level.');
INSERT INTO badge_optional_requirements VALUES(7142,562,11,'Make a doll quilt.');
INSERT INTO badge_optional_requirements VALUES(7143,562,12,'Make a quilted article of clothing.');
INSERT INTO badge_optional_requirements VALUES(7144,562,13,'Make a quilted pillow.');
INSERT INTO badge_optional_requirements VALUES(7145,562,14,'Get some practice fabric and familiarize yourself with your sewing machine.  Be sure you can sew a ¼ inch from the edge of your fabric and work on sewing in straight lines.  Continue until you are confident enough to attempt an actual quilt pattern.');
INSERT INTO badge_optional_requirements VALUES(7146,562,15,'Earn the Advanced Quilting badge at your level.');
INSERT INTO badge_optional_requirements VALUES(7147,564,3,'Learn about the life cycle of rabbits. How long do they live?  How many babies do they normally have?');
INSERT INTO badge_optional_requirements VALUES(7148,564,4,'Describe at least three difference rabbit diseases, their symptoms, and their treatment.');
INSERT INTO badge_optional_requirements VALUES(7149,564,5,'Be able to identify three different species of rabbit.');
INSERT INTO badge_optional_requirements VALUES(7150,564,6,'Rabbits are raised for meat as well as for pets.  Eat a recipe that includes rabbit.');
INSERT INTO badge_optional_requirements VALUES(7151,564,7,'Learn about careers that involve rabbits.');
INSERT INTO badge_optional_requirements VALUES(7152,564,8,'Visit your state or county fair and tour the rabbit section.  Take part in it if possible.');
INSERT INTO badge_optional_requirements VALUES(7153,564,9,'Attend a rabbit show.');
INSERT INTO badge_optional_requirements VALUES(7154,564,10,'Rabbits are used for meat, fur, wool, or even just as a pet. Learn about at least one type of rabbit that is used for each of these different purposes.');
INSERT INTO badge_optional_requirements VALUES(7155,564,11,'Visit someone who raises rabbits and learn about how they care for them.  Discuss daily care, sanitation, management, and feed.');
INSERT INTO badge_optional_requirements VALUES(7156,564,12,'Learn about the differences between wild rabbits and tame rabbits.');
INSERT INTO badge_optional_requirements VALUES(7157,564,13,'Learn how to properly groom a rabbit.  Know how to trim their nails, clean their scent glands, and check their ears and fur.');
INSERT INTO badge_optional_requirements VALUES(7158,564,14,'Participate in a service project that deals with rabbits.');
INSERT INTO badge_optional_requirements VALUES(7159,564,15,'Build a rabbit feeder, carrying case, tattooing box, or other equipment for your rabbit.');
INSERT INTO badge_optional_requirements VALUES(7160,564,16,'Stretch and dry a rabbit pelt.');
INSERT INTO badge_optional_requirements VALUES(7161,564,17,'Conduct a demonstration about rabbits, or create a small booklet, to share with a group of younger children.');
INSERT INTO badge_optional_requirements VALUES(7162,564,18,'Learn how to register a rabbit with the American Rabbit Breeders Association (ARBA).');
INSERT INTO badge_optional_requirements VALUES(7163,564,19,'Levels 3-5 Only: Butcher a rabbit humanely for a purpose, such as meat.');
INSERT INTO badge_optional_requirements VALUES(7164,564,20,'Read a fiction book about rabbits.');
INSERT INTO badge_optional_requirements VALUES(7165,564,21,'Read a nonfiction book about rabbits.');
INSERT INTO badge_optional_requirements VALUES(7166,564,22,'Create a craft that involves rabbits.');
INSERT INTO badge_optional_requirements VALUES(7167,565,3,'Ride on a historic train, a modern train, or an Amtrak train.');
INSERT INTO badge_optional_requirements VALUES(7168,565,4,'Ride on an alternative train, such as a monorail at Disneyland or in Las Vegas, the MetroRail in Arizona, the elevated train in Chicago, the subway in New York, or BART system of San Francisco.');
INSERT INTO badge_optional_requirements VALUES(7169,565,5,'Visit a railroad museum.');
INSERT INTO badge_optional_requirements VALUES(7170,565,6,'Write a report on railroads.');
INSERT INTO badge_optional_requirements VALUES(7171,565,7,'Study the economic advantages the railroad brought to America.');
INSERT INTO badge_optional_requirements VALUES(7172,565,8,'Know the names of at least three major railroad companies in America and where their major routes are.');
INSERT INTO badge_optional_requirements VALUES(7173,565,9,'Learn about railroad signals and related traffic laws, such as right of way.');
INSERT INTO badge_optional_requirements VALUES(7174,565,10,'Tour a train station.');
INSERT INTO badge_optional_requirements VALUES(7175,565,11,'Learn about the safety inspections of trains.');
INSERT INTO badge_optional_requirements VALUES(7176,565,12,'Find out what kind of jobs there are in the railroad industry today. Levels 3-5: Learn about outdated jobs that are now performed by technology.');
INSERT INTO badge_optional_requirements VALUES(7177,565,13,'Participate in a service project related to trains/railroads.  You may choose to volunteer at a railroad museum, raise funds to restore an old train for display, or educate others about trains.');
INSERT INTO badge_optional_requirements VALUES(7178,565,14,'Learn how modern inventions changed traveling by rail. What amenities were added to passenger trains to improve the ride?  How have the engines and traffic control of the railways changed thanks to modern inventions?');
INSERT INTO badge_optional_requirements VALUES(7179,565,15,'Watch a television show, movie, or documentary, or read a book where trains play an important role.');
INSERT INTO badge_optional_requirements VALUES(7180,565,16,'Learn the difference between steam engines, diesel engines, and electrical engines');
INSERT INTO badge_optional_requirements VALUES(7181,565,17,'Learn about train tracks, how they are made, and their dimensions. Levels 3 – 5: Know the difference between standard rail and narrow gauge rail.');
INSERT INTO badge_optional_requirements VALUES(7182,565,18,'Learn what a turntable and turnout is.');
INSERT INTO badge_optional_requirements VALUES(7183,565,19,'Learn about the Federal Railroad Administration (FRA), the American Railway Engineering and Maintenance-of-Way Association (AREMA), and Association of American Railroads (AAR). What do each of these associations do?');
INSERT INTO badge_optional_requirements VALUES(7184,566,3,'Go to the craft store and look at all the different supplies available.');
INSERT INTO badge_optional_requirements VALUES(7185,566,4,'Make three beginner bracelets, using one of these methods: Basic Starburst Ladder Waterfall Fishtail Inverted fishtail Origami Beaded ladder French braid');
INSERT INTO badge_optional_requirements VALUES(7186,566,5,'Make two intermediate bracelets, using one of these methods: Triple link chain Triple fishtail Zippy chain Back and forth Zipper Dragon scale Butterfly garland Heart Diamond with ring Lion’s mane Spectrum Vortex');
INSERT INTO badge_optional_requirements VALUES(7187,566,6,'Make an advanced bracelet, using one of these methods: Snake belly Zig zag Rock candy Feather Totum pole Hexafish Sparkle Extravaganza Life saver Cruise wave Double starburst Triple starburst Lacey zee Eclipse');
INSERT INTO badge_optional_requirements VALUES(7188,566,7,'Make a charm for your Rainbow Loom bracelet.');
INSERT INTO badge_optional_requirements VALUES(7189,566,8,'Make a 3D charm for your Rainbow Loom bracelet.');
INSERT INTO badge_optional_requirements VALUES(7190,566,9,'Make an accessory, such as a ring, phone case, purse, earrings, or glasses chain.');
INSERT INTO badge_optional_requirements VALUES(7191,566,10,'Make a bracelet as a gift.');
INSERT INTO badge_optional_requirements VALUES(7192,566,11,'Donate bracelets to a children’s hospital or participate in another community service event with Rainbow Looms.');
INSERT INTO badge_optional_requirements VALUES(7193,566,12,'Host a Rainbow Loom party.');
INSERT INTO badge_optional_requirements VALUES(7194,566,13,'Learn three new techniques you did not previously know.');
INSERT INTO badge_optional_requirements VALUES(7195,566,14,'Invent a new bracelet.');
INSERT INTO badge_optional_requirements VALUES(7196,566,15,'Teach a friend or group how to Rainbow Loom.');
INSERT INTO badge_optional_requirements VALUES(7197,566,16,'Neatly organize your loom supplies.');
INSERT INTO badge_optional_requirements VALUES(7198,567,3,'Research the significance of sanding the boat and different areas for variations of speed and accuracy.');
INSERT INTO badge_optional_requirements VALUES(7199,567,4,'Discuss the importance of sportsmanship during a race.');
INSERT INTO badge_optional_requirements VALUES(7200,567,5,'Draw a sketch of how you want to decorate your boat and follow accordingly.');
INSERT INTO badge_optional_requirements VALUES(7201,567,6,'Compare a regatta boat to an actual boat. Discuss what materials and layouts would be best used for speed and accuracy during the race.');
INSERT INTO badge_optional_requirements VALUES(7202,567,7,'Research the different wind variations and best places to blow for speed and accuracy.');
INSERT INTO badge_optional_requirements VALUES(7203,567,8,'Help a younger child build their boat for a race.');
INSERT INTO badge_optional_requirements VALUES(7204,567,9,'Help keep score and pass out awards at the end of the race.');
INSERT INTO badge_optional_requirements VALUES(7205,567,10,'Create a booklet explaining how a rain gutter regatta works and share it with other youth organizations.');
INSERT INTO badge_optional_requirements VALUES(7206,568,3,'Read 6 poems, or 2 books written in a poem format.');
INSERT INTO badge_optional_requirements VALUES(7207,568,4,'Subscribe to at least one magazine or check one out from your local library.  Read at least 3 issues of the same magazine.');
INSERT INTO badge_optional_requirements VALUES(7208,568,5,'Read 2 age-appropriate books that are nonfiction.');
INSERT INTO badge_optional_requirements VALUES(7209,568,6,'Read 2 age-appropriate books that are fiction.');
INSERT INTO badge_optional_requirements VALUES(7210,568,7,'Read 2 age-appropriate biographies.');
INSERT INTO badge_optional_requirements VALUES(7211,568,8,'Read at least 3 award winning books such as Newbery Medal, Phoenix Award, Hugo Award, Parent’s Choice Award, etc.');
INSERT INTO badge_optional_requirements VALUES(7212,568,9,'Find out about careers in the book industry.  You might interview an author, a poet, an illustrator, editor, or someone who publishes books.  Draw a diagram of how a book gets from the idea stage to the printed page.');
INSERT INTO badge_optional_requirements VALUES(7213,568,10,'Read about the world around you from any two sources—books, magazines, newspapers, the Internet (with your parent’s permission), field manuals, etc. Topics may include sports, environmental problems, politics, social issues, current events, nature, religion, etc.  Discuss what you found with your parent or leader.');
INSERT INTO badge_optional_requirements VALUES(7214,568,11,'Get a local newspaper and be able to identify what types of articles are found in each section.  Read at least one article from each section.');
INSERT INTO badge_optional_requirements VALUES(7215,568,12,'Volunteer to read for others. You may read to the sick, the elderly, your siblings, story time at the local library, a day care, etc.');
INSERT INTO badge_optional_requirements VALUES(7216,568,13,'Pick a subject you are interested in and research it on the Internet (with parent’s permission and guidance).  Find at least 3 sites that discuss your subject in writing and not videos.  How do you know if these sites are reputable and can be believed?');
INSERT INTO badge_optional_requirements VALUES(7217,568,14,'Write 3 books reviews on books you have read that you think your peers may enjoy.');
INSERT INTO badge_optional_requirements VALUES(7218,568,15,'Collect books and magazines appropriate for a specific age group and donate them to a library, nursing home, youth shelter, day-care center, or Veterans’ hospital.');
INSERT INTO badge_optional_requirements VALUES(7219,568,16,'Get at least 3 different newspapers from the same day such as your local paper, The Wallstreet Journal, and USA today.  Compare which article topics you find in all the newspapers and which are exclusive.  Do the papers have the same sections or do they differ?');
INSERT INTO badge_optional_requirements VALUES(7220,568,17,'Volunteer in your local library.');
INSERT INTO badge_optional_requirements VALUES(7221,568,18,'Use your dictionary to learn the meaning of one new word a day for 2 weeks.  Keep a log of the words and teach them to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(7222,568,19,'Choose two stories with different points of view (first- and third-person narrations) and compare and contrast their narrative styles.  Which do you prefer and why?');
INSERT INTO badge_optional_requirements VALUES(7223,568,20,'Create a visual representation (drawing, paintng, collage, etc.) of a key scene from a chosen story or drama.');
INSERT INTO badge_optional_requirements VALUES(7224,568,21,'Participate in a book club or literary discussion group.');
INSERT INTO badge_optional_requirements VALUES(7225,568,22,'Create a storyboard for a scene from a story, drama, or poem, highlighting key elements.');
INSERT INTO badge_optional_requirements VALUES(7226,569,3,'Build a composter and either use it yourself or give it to a friend.');
INSERT INTO badge_optional_requirements VALUES(7227,569,4,'Help publicize a home toxic waste collection day in your community, such as for collecting old paints, garden chemicals, oil, etc.');
INSERT INTO badge_optional_requirements VALUES(7228,569,5,'Learn which items in your house can be returned when you are done with them (examples include computer parts, batteries, tires etc.). Identify one item from this list you were planning to throw out and with an adult, bring it somewhere to be recycled.');
INSERT INTO badge_optional_requirements VALUES(7229,569,6,'Find out all of the items that your county will accept for recycling. Examine what you recycle at home or at the home of your grandparents or another relative and expand your efforts to include all of these items. Don’t forget about items that can be donated (e.g. clothing, dishes, etc.), repaired (e.g. resoling shoes), and reused (excess packaging, etc.). Find a way to help your family, relative or grandparent to recycle, reduce, repair, and reuse all these possible items.');
INSERT INTO badge_optional_requirements VALUES(7230,569,7,'Interview someone who works in the recycling industry. What do these companies do with the collected items? Find out what kind of training and education are necessary for a career in the recycling business.');
INSERT INTO badge_optional_requirements VALUES(7231,569,8,'Explain and show new uses for old plastic containers, old jars and cans, different kinds of paper, greeting cards, bags and cardboard boxes. Make a craft using items you would normally throw away.');
INSERT INTO badge_optional_requirements VALUES(7232,569,9,'Make your own reusable shopping bag. Plastic shopping bags are a big garbage problem — it takes 1,000 years for a bag to break down! Choose some heavy fabric and sew it into simple rectangular bags with handles. Or, buy some canvas bags at a craft or environmentally friendly gift shop. Then use fabric pens to draw pictures on them. Take the bags out with you every time you shop.');
INSERT INTO badge_optional_requirements VALUES(7233,569,10,'Search out all recycling centers in your community and/or county. Make a list of the recycling centers and their locations along with a list of the items which are recycled at each location. Make this list available to local businesses, schools, real estate agents, etc. in your community');
INSERT INTO badge_optional_requirements VALUES(7234,569,11,'Find a person or company that has made a business or hobby out of repurposing used articles.  What inspired them?  Where do they get their used articles?  What are the benefits and products of this hobby or business?');
INSERT INTO badge_optional_requirements VALUES(7235,569,12,'Help make a list of at least ten clothing or other items your family wants or needs.  Help your parent(s) shop for the items at yard sales or thrift shops.');
INSERT INTO badge_optional_requirements VALUES(7236,569,13,'Visit the home of someone who composts in his own yard, or a business that produces compost commercially (selling the final product).');
INSERT INTO badge_optional_requirements VALUES(7237,569,14,'With help from an adult, collect old clothes, furniture, or books and donate them.');
INSERT INTO badge_optional_requirements VALUES(7238,569,15,'Using old paper products, make your own recycled paper.');
INSERT INTO badge_optional_requirements VALUES(7239,569,16,'Write a short booklet on the “recycling process” in your community. What happens to a tin can or bottle?');
INSERT INTO badge_optional_requirements VALUES(7240,569,17,'Understand the meaning of recycling, and describe why recycling has become more important in recent years.');
INSERT INTO badge_optional_requirements VALUES(7241,569,18,'Make a list of items in your home or at the store that could be sold with less packaging.');
INSERT INTO badge_optional_requirements VALUES(7242,569,19,'Bring your own non-disposable mug and eating utensils to use at camp or bring a garbage-free lunch to school or work regularly.');
INSERT INTO badge_optional_requirements VALUES(7243,569,20,'Visit or learn about a company or industry that is involved in recycling or collecting recyclable materials.');
INSERT INTO badge_optional_requirements VALUES(7244,569,21,'Make a poster describing what is recyclable.');
INSERT INTO badge_optional_requirements VALUES(7245,569,22,'A great way to learn about “reuse” and “recycle” is to go on a trip to your local thrift store, recycling center, or church. Gather old clothing, toys, shoes, or other items in reusable condition, and make a family trip down to the donation center to can see how your trash is someone else’s treasure. Teach others how items can be reused for different purposes–for example old towels, blankets, and comforters can often be donated to local animal shelters for bedding. These real-life examples will teach others that many items they would normally throw away can actually have a second life.');
INSERT INTO badge_optional_requirements VALUES(7246,569,23,'Make a list of all the things that you didn’t need to buy during one week because you reused items you already had. Explain how reusing items reduces the amount of energy needed to make new things.');
INSERT INTO badge_optional_requirements VALUES(7247,569,24,'Make a project from old lumber or Christmas trees.');
INSERT INTO badge_optional_requirements VALUES(7248,569,25,'Show or tell your family, friends, or club about three products that are made with recycled materials.');
INSERT INTO badge_optional_requirements VALUES(7249,569,26,'Make a list of products that display the recycling symbol.');
INSERT INTO badge_optional_requirements VALUES(7250,569,27,'Learn about efforts to make reused fuel, such as using old frying oil as fuel. What are the advantages/disadvantages of this?');
INSERT INTO badge_optional_requirements VALUES(7251,570,3,'Interview 3 people of 3 different age groups and find out their views on relationships.  What do they consider essential elements in each type of relationship (family, friends, dating partner, spouse, co-workers, etc.)?');
INSERT INTO badge_optional_requirements VALUES(7252,570,4,'Make a piece of artwork that shows what relationship means to you.');
INSERT INTO badge_optional_requirements VALUES(7253,570,5,'Create a short skit about relationships and perform it for your family or friends.');
INSERT INTO badge_optional_requirements VALUES(7254,570,6,'Level 2 and Up: Come up with at least 10 interview questions to cover topics such as dating, marriage, courtship etc.  and interview at least 10 people roughly your own age.   Compare the answers you received to your own views and discuss them with a parent.');
INSERT INTO badge_optional_requirements VALUES(7255,570,7,'Look at our culture in America today and identify 6 areas in which relationships are frequently lacking.');
INSERT INTO badge_optional_requirements VALUES(7256,570,8,'Learn about the affects of relationships on mental health. Why is it important to surround yourself with supportive, positive people?');
INSERT INTO badge_optional_requirements VALUES(7257,570,9,'Level 2 and Up: Talk with your parents and ask them what your family’s views on dating are.  Why do they have these views?  How will these views affect you both now and in the future?');
INSERT INTO badge_optional_requirements VALUES(7258,570,10,'Earn a character badge for a trait you consider important for a good relationship with others. Examples might include Patience, Respect, or Honesty.  Explain how this character trait can make a healthier relationship.');
INSERT INTO badge_optional_requirements VALUES(7259,570,11,'Role play different relationship situations.  Show the difference between a healthy relationship and an unhealthy one.');
INSERT INTO badge_optional_requirements VALUES(7260,570,12,'Level 2 and Up: Learn about domestic abuse and violence. Know what local resources are available for victims and how to contact them.  Why do some people stay in a relationship even if it is abusive? How can this affect children?');
INSERT INTO badge_optional_requirements VALUES(7261,571,3,'Learn about what “scale” means.  What scale is your RC vehicle compared to real vehicles?');
INSERT INTO badge_optional_requirements VALUES(7262,571,4,'Design a paint job for your RC vehicle.');
INSERT INTO badge_optional_requirements VALUES(7263,571,5,'Watch an RC competition of your chosen vehicle or even better, participate in one.');
INSERT INTO badge_optional_requirements VALUES(7264,571,6,'Understand the difference between a brushed and brushless motor.');
INSERT INTO badge_optional_requirements VALUES(7265,571,7,'Learn the basics of how the engine works in your RC vehicle and how to make general repairs if things get broken.');
INSERT INTO badge_optional_requirements VALUES(7266,571,8,'Be able to identify at least 3 body/hull types.');
INSERT INTO badge_optional_requirements VALUES(7267,571,9,'Participate in a community service project that involves RC vehicles in some way.  You may wish to raise money for a local club or association, help maintain club or community facilities that allow RC vehicles, volunteer to help facilitate a competition, etc.');
INSERT INTO badge_optional_requirements VALUES(7268,571,10,'Compare ready to run models vs build your own kits.  What are the cost differences?  What are the quality differences?  What are the pros and cons of each.');
INSERT INTO badge_optional_requirements VALUES(7269,571,11,'Learn about what tools you should have on hand if you plan to get into RC hobbies.  What are the most common tools you will need to repair and maintain your vehicle?');
INSERT INTO badge_optional_requirements VALUES(7270,571,12,'Learn the aerodynamics of the designs for racing an RC vehicle.  Explain how the design can effect the speed and what design elements are most important when competing.');
INSERT INTO badge_optional_requirements VALUES(7271,571,13,'Compare various brands and options for your RC vehicle.  What are the cost/quality differences?  Can they be purchased at a local hobby store, or must they be purchased online?');
INSERT INTO badge_optional_requirements VALUES(7272,571,14,'Learn the rules for a competition involving your RC vehicle.  How do they start?  Are there “lanes”?  What errors can add a lap or disqualify you?  Are there engine rules?  How and when are you allowed to pass another vehicle?');
INSERT INTO badge_optional_requirements VALUES(7273,571,15,'Learn about how your RC vehicle is made. What are the pros/cons of the different types of body/hull material?');
INSERT INTO badge_optional_requirements VALUES(7274,571,16,'Learn about how your RC vehicle is used beyond recreation, such as firefighting drones.');
INSERT INTO badge_optional_requirements VALUES(7275,571,17,'Research different types of batteries or power systems used in RC vehicles. Compare charging time and run time.');
INSERT INTO badge_optional_requirements VALUES(7276,571,18,'Learn the difference between gas powered vs electric vs nitro RC motors.  What are the pros and cons of each?');
INSERT INTO badge_optional_requirements VALUES(7277,571,19,'Research careers related to remote control or robotics such as drone operators, engineers, or animatronics designers.');
INSERT INTO badge_optional_requirements VALUES(7278,571,20,'Design your own RC vehicle concept. Draw it and explain what makes it unique or better than others.');
INSERT INTO badge_optional_requirements VALUES(7279,572,3,'Learn about methane gas and how it is produced from cow manure and landfills.  What is it used for?');
INSERT INTO badge_optional_requirements VALUES(7280,572,4,'Learn what biodiesel is and what it is used for.');
INSERT INTO badge_optional_requirements VALUES(7281,572,5,'Learn about the new algae fuel being developed at Arizona State University Lab of Algae Research and Biotechnology.');
INSERT INTO badge_optional_requirements VALUES(7282,572,6,'Build a model vehicle that uses alternative energy to move.');
INSERT INTO badge_optional_requirements VALUES(7283,572,7,'List five ways to accomplish tasks using renewable energy.');
INSERT INTO badge_optional_requirements VALUES(7284,572,8,'Use a kinetic energy  scooter or other riding toy, and study how it uses renewable energy to work.');
INSERT INTO badge_optional_requirements VALUES(7285,572,9,'Explain what regenerative braking systems are and how they might be used in the future.');
INSERT INTO badge_optional_requirements VALUES(7286,572,10,'Make a solar clock or other small solar device.');
INSERT INTO badge_optional_requirements VALUES(7287,572,11,'Learn how a water wheel powered sawmills in the old days.  Show how that could be utilized today.');
INSERT INTO badge_optional_requirements VALUES(7288,572,12,'Learn about ways to heat or cool using renewable energy.');
INSERT INTO badge_optional_requirements VALUES(7289,572,13,'Take a field trip to somewhere where renewable energy is produced.  This might be a wind farm, a dam, a solar rooftop or field, a renewable energy laboratory, etc.');
INSERT INTO badge_optional_requirements VALUES(7290,572,14,'Create a science experiment that deals with renewable energy.');
INSERT INTO badge_optional_requirements VALUES(7291,572,15,'Create a presentation about renewable energy, why it is important, and different types of renewable energy. Present it to your family, friends, group, or your community.');
INSERT INTO badge_optional_requirements VALUES(7292,573,3,'Visit a zoo, pet shop, or other place where you can see your category of animal being fed and cared for. Level 2: Also interview the caretakers and find out what they like/dislike about their job. Level 3: Do Level 2 of this requirement and also find out what type of education or special training is necessary to work in this position. Level 4 & Level 5: Do requirement 11.');
INSERT INTO badge_optional_requirements VALUES(7293,573,4,'Make something to attract, protect, or observe your category of animal.');
INSERT INTO badge_optional_requirements VALUES(7294,573,5,'Make a chart, poster, booklet, or other exhibit to teach others what you have learned while earning this badge.');
INSERT INTO badge_optional_requirements VALUES(7295,573,6,'Make a list of animals from your category that might make good pets.  What special equipment would you need to take care of them?  What types of foods do they eat?  Is this a pet that you would like to have?  Why or why not?');
INSERT INTO badge_optional_requirements VALUES(7296,573,7,'Design and carry out a service project that will benefit your animal group.  This may be planting trees or flowers for birds or insects, raising money for organizations that protect endangered species, gathering a volunteer crew to help out at a local animal shelter, etc.');
INSERT INTO badge_optional_requirements VALUES(7297,573,8,'Research any state and federal laws that protect your animal category.  What animals in your category are on the endangered species list?  What specific protection do they receive?  How would the extinction of this animal affect mankind?  (If you researched this group at an earlier level, make sure all your data is up to date.)');
INSERT INTO badge_optional_requirements VALUES(7298,573,9,'What local or national organizations are there that study or protect animals in your category?  What do they do?  Make a poster showing how you can help to protect an animal from your category. Level 4 & Level 5: Volunteer at least 4 hours to working with one of these organizations.');
INSERT INTO badge_optional_requirements VALUES(7299,573,10,'If your animal category is present naturally in your local community, find out which animals are beneficial to humans, which are nuisances, and which are harmful.  Explain how people interact with each of these animals.');
INSERT INTO badge_optional_requirements VALUES(7300,573,11,'Level 4 & Level 5 Only: Shadow an animal caretaker for a day at a zoo, pet shop, or other place where you can see your category of animal being fed and cared for.  What careers are there in working with these types of animals?  What education or special training would you need?');
INSERT INTO badge_optional_requirements VALUES(7301,574,3,'How long do you spend in the shower each morning?  Why is taking short showers important?  Time yourself for the next week and see how quickly you can shower (and still get completely clean!).');
INSERT INTO badge_optional_requirements VALUES(7302,574,4,'Make sure you turn the lights off when you leave a room and open the blinds to let in more natural light. Try playing the following game with your family: whenever someone leaves a light on they must put a quarter in a jar.  At the end of the week, use the money for a family treat or donate it to a worthy charity.');
INSERT INTO badge_optional_requirements VALUES(7303,574,5,'Where does your family keep the thermostat?  Try to keep it set to at least 80 degrees for the air conditioner and 68 degrees for the heater to help save on your family’s energy costs. Does your gas and electric company have any special deals your family can take advantage of?  How renewable alternative energy like solar power help reduce costs as well as help the environment?');
INSERT INTO badge_optional_requirements VALUES(7304,574,6,'Create an odds and ends box for when you do crafts.  Instead of throwing away scraps of paper, craft foam, or fabric, put them in your box.  Then when you only need a small piece you can look in the box rather than cut up a brand new piece of paper or other material.');
INSERT INTO badge_optional_requirements VALUES(7305,574,7,'Learn to make the most of leftovers.  What are some different techniques to make use of leftovers, or prevent them?');
INSERT INTO badge_optional_requirements VALUES(7306,574,8,'Find at least three items you own that you no longer use and either give them away or sell them and donate the money to a worthy charity.');
INSERT INTO badge_optional_requirements VALUES(7307,574,9,'What items can you recycle in your community?  Most recycling businesses take cans and plastic bottles, but many also take newspapers, cardboard, and other items.  Design a poster to promote recycling and place it on a bulletin board in your community.');
INSERT INTO badge_optional_requirements VALUES(7308,574,10,'Organize an aluminum can drive and donate the money to a worthy charity or a stuffed animal drive to give to a local hospital, police department, or other agency.  You could also hold a suitcase drive to donate to the local foster children’s agency as these kids usually carry what few belongings they have in trash bags.');
INSERT INTO badge_optional_requirements VALUES(7309,574,11,'Read a book about how to be thrifty or resourceful such as The Tightwad Gazette by Amy Dacyczyn.');
INSERT INTO badge_optional_requirements VALUES(7310,574,12,'Learn about a famous person who is known for their resourcefulness. Examples might include George Washington Carver, Louisa May Alcott, Thomas Edison, and Mother Teresa.');
INSERT INTO badge_optional_requirements VALUES(7311,574,13,'Find and memorize quotes about resourcefulness. Preschool: Memorize one quote. Levels 1-2: Memorize three quotes. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(7312,574,14,'Earn the Recycling badge or Upcycling badge at your level.');
INSERT INTO badge_optional_requirements VALUES(7313,574,15,'Plan a route through a city using public transportation, maps, and alternative routes.');
INSERT INTO badge_optional_requirements VALUES(7314,574,16,'Live a “zero-waste” lifestyle for a week, minimizing the use of disposable items.');
INSERT INTO badge_optional_requirements VALUES(7315,574,17,'Organize and lead a scavenger hunt with a focus on resourcefulness and problem-solving.  (Check out the Resourcefulness Scavenger Hunt on our blog.)');
INSERT INTO badge_optional_requirements VALUES(7316,574,18,'Grow a small garden using recycled containers and compost.');
INSERT INTO badge_optional_requirements VALUES(7317,574,19,'Develop and execute a community service project that involves repurposing materials for a positive impact.');
INSERT INTO badge_optional_requirements VALUES(7318,574,20,'Plan a weekend camping trip on a tight budget, emphasizing resourcefulness in equipment and supplies.');
INSERT INTO badge_optional_requirements VALUES(7319,574,21,'Design and create a unique piece of clothing or accessory using recycled textiles.');
INSERT INTO badge_optional_requirements VALUES(7320,574,22,'Build a small-scale renewable energy project (e.g., solar oven, wind turbine).');
INSERT INTO badge_optional_requirements VALUES(7321,575,3,'Write the word ‘RESPECT’ down the side of a piece of paper. Then write a word or sentence describing respect next to each letter. For instance, ‘R’ could be “Recognizing authority”, ‘E’ could be “Elders know best”, etc.');
INSERT INTO badge_optional_requirements VALUES(7322,575,4,'Memorize verses about respect. Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(7323,575,5,'Make a “Respect Bouquet” using the Victorian Language of Flowers. Find pictures of flowers that represent respect and use them to make a scrapbook page or a poster or create a collage of pictures that show respect.  Explain what each picture represents.');
INSERT INTO badge_optional_requirements VALUES(7324,575,6,'Find and memorize quotes about respect. Preschool: Memorize one quote. Levels 1-2: Memorize three quotes. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(7325,575,7,'Draw a picture of what respect means to you.');
INSERT INTO badge_optional_requirements VALUES(7326,575,8,'Learn a song about respect.');
INSERT INTO badge_optional_requirements VALUES(7327,575,9,'Read a poem about respect and discuss it with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(7328,575,10,'Read a biography of someone known for their respectfulness.');
INSERT INTO badge_optional_requirements VALUES(7329,575,11,'Write your own poem about respectfulness.');
INSERT INTO badge_optional_requirements VALUES(7330,575,12,'Write a skit about respect and perform it for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(7331,575,13,'When you watch television make a list of how many times respect or lack of respect is portrayed.');
INSERT INTO badge_optional_requirements VALUES(7332,575,14,'Watch a television interview with national leader/senator, etc., and observe whether the interviewer treats the interviewee with respect and vise versa.');
INSERT INTO badge_optional_requirements VALUES(7333,575,15,'How is respect similar to obedience?  If one doesn’t respect the authority figures, is one likely to respect the laws that those figures represent?');
INSERT INTO badge_optional_requirements VALUES(7334,575,16,'Make a list of people you think are respectful and be able to explain why.');
INSERT INTO badge_optional_requirements VALUES(7335,575,17,'Earn the Etiquette badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(7336,575,18,'How can we be respectful to the environment? Explore at least 10 ways that we can be respectful towards nature and our community.');
INSERT INTO badge_optional_requirements VALUES(7337,575,19,'Make a list of at least 5 synonyms for respect.');
INSERT INTO badge_optional_requirements VALUES(7338,576,3,'Make a poster of what being responsible means to you.');
INSERT INTO badge_optional_requirements VALUES(7339,576,4,'What are the different responsibilities of the people in your family? Make a chart showing each member of your family and what they are responsible for.');
INSERT INTO badge_optional_requirements VALUES(7340,576,5,'Role play responsible vs. irresponsible behaviors in a variety of circumstances.');
INSERT INTO badge_optional_requirements VALUES(7341,576,6,'What are the different responsibilities of people at school or in the community? Where do you fit in? What would happen if people did not meet their responsibilities?');
INSERT INTO badge_optional_requirements VALUES(7342,576,7,'Memorize verses about responsibility. Preschool: Memorize one verse. Levels 1-2: Memorize three verses. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(7343,576,8,'Make a chart of your responsibilities in the following areas: your family, friends, school, community, church or place of worship, your country, the world, the environment.');
INSERT INTO badge_optional_requirements VALUES(7344,576,9,'Read a short biographical sketch, listen to a story, or watch a good video about an historical or contemporary person of widely admired character.');
INSERT INTO badge_optional_requirements VALUES(7345,576,10,'Set 6 goals of things you would like to get done. Use the “will, what, when” format. I will clean my room (what) in 45 minutes (when). Be very specific with your goals and see how well you stick to them. Other examples may include things like, “I will do my chores for 1 whole week without being asked and without complaint.” or “I will finish my homework by 5:00pm every night this week.”');
INSERT INTO badge_optional_requirements VALUES(7346,576,11,'Find a role model in your family or community that your feel shows the true meaning of responsibility and interview them. Ask them questions like: How does being responsible help a person in life? How did it help you? Who had the most influence on your character? How did they influence you? How did you help yourself develop a good sense of responsibility? What advice would you give to young people today who want to develop responsibility? Find out why they think responsibility is important and what they do in their own life to make sure they are as responsible as possible.');
INSERT INTO badge_optional_requirements VALUES(7347,576,12,'Find newspaper or magazine articles about individuals who set and pursued a goals');
INSERT INTO badge_optional_requirements VALUES(7348,576,13,'Find and memorize quotes about responsibility. Preschool: Memorize one quote. Levels 1-2: Memorize three quotes. Levels 3-4: Memorize five. Level 5: Memorize eight.');
INSERT INTO badge_optional_requirements VALUES(7349,576,14,'How is procrastination the opposite of responsibility? Many people suffer from procrastination. What are at least 5 ways to fight procrastination?');
INSERT INTO badge_optional_requirements VALUES(7350,577,3,'Watch a documentary about the history of fast food or a well-known restaurant.');
INSERT INTO badge_optional_requirements VALUES(7351,577,4,'Watch a television show of someone who visits different restaurants and critiques their food. Write a review stating what you liked and disliked about the show.');
INSERT INTO badge_optional_requirements VALUES(7352,577,5,'With permission, take a tour of a restaurant.');
INSERT INTO badge_optional_requirements VALUES(7353,577,6,'Research from where and how most restaurants get their food.');
INSERT INTO badge_optional_requirements VALUES(7354,577,7,'What are the pros and cons of owning a food truck versus owning a restaurant? Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(7355,577,8,'Eat food from five different restaurants and tell someone which one you liked best and why.');
INSERT INTO badge_optional_requirements VALUES(7356,577,9,'Learn about food safety laws. What is required of restaurants for them to remain open?');
INSERT INTO badge_optional_requirements VALUES(7357,577,10,'Pick a restaurant and try the healthy options on their menu. How does it compare to their less healthy options?');
INSERT INTO badge_optional_requirements VALUES(7358,577,11,'Try to cook one of the dishes a restaurant serves. Do you like your version better or worse?');
INSERT INTO badge_optional_requirements VALUES(7359,577,12,'Learn the differences between dine-in, take-out, deliver, etc. What are some of the advantages and disadvantages of each?');
INSERT INTO badge_optional_requirements VALUES(7360,577,13,'Interview someone who works at your restaurant. Ask them what they like and dislike about working there, what they would do differently, etc.');
INSERT INTO badge_optional_requirements VALUES(7361,577,14,'Learn about the different roles that a person can take part of in a restaurant, including the traditional French names.');
INSERT INTO badge_optional_requirements VALUES(7362,577,15,'Read a biography or otherwise learn about a famous chef who helped revolutionize the restaurant world, such as Jacques Pépin.');
INSERT INTO badge_optional_requirements VALUES(7363,577,16,'Learn about food blogging. How is this helpful or harmful to restaurants? Is it okay to ask a restaurant for free food in exchange for a review? Why or why not?');
INSERT INTO badge_optional_requirements VALUES(7364,577,17,'Learn about a famous restaurant, such as Thomas Keller’s The French Laundry.');
INSERT INTO badge_optional_requirements VALUES(7365,577,18,'Learn about careers in the restaurant industry.  What type of education do you need?  What type of pay could you expect?  Where might you have to live? If possible, shadow someone for a day in one of these careers.');
INSERT INTO badge_optional_requirements VALUES(7366,577,19,'How does a restaurant kitchen differ from a home kitchen? What equipment is different? Safety rules? Expectations?');
INSERT INTO badge_optional_requirements VALUES(7367,578,3,'Watch a documentary or read about the history of restaurants.');
INSERT INTO badge_optional_requirements VALUES(7368,578,4,'Learn about your restaurant’s competitors. Which one do you like better? What are the pros and cons of having restaurant competitors?');
INSERT INTO badge_optional_requirements VALUES(7369,578,5,'With permission, take a tour of your chosen restaurant or one that works similarly.');
INSERT INTO badge_optional_requirements VALUES(7370,578,6,'Learn where your restaurant gets their food and why it is important to know what food you are putting in your body.');
INSERT INTO badge_optional_requirements VALUES(7371,578,7,'Create a presentation about your chosen restaurant and show it to your family, friends, or family.');
INSERT INTO badge_optional_requirements VALUES(7372,578,8,'Eat food from four other restaurants that serve similar types of food. Which one did you like best and why? Was their food better or worse than your restaurant’s food?');
INSERT INTO badge_optional_requirements VALUES(7373,578,9,'Interview someone who works at your restaurant. Ask them what they like and dislike about working there, what they would do differently if they were in charge, etc.');
INSERT INTO badge_optional_requirements VALUES(7374,578,10,'Learn about what things your chosen restaurant does for their community. If they do nothing, what could they do?');
INSERT INTO badge_optional_requirements VALUES(7375,578,11,'Earn the Restaurants (General) badge at your level.');
INSERT INTO badge_optional_requirements VALUES(7376,579,3,'Learn the history rice cookers. Which country takes credit for making them first? Do you need them to cook rice?  What are their advantages and disadvantages?');
INSERT INTO badge_optional_requirements VALUES(7377,579,4,'Read a story book about rice. (some examples: Everybody Cooks Rice, My Grandma Feeds Me Sticky Rice, A Grain of Rice, etc.)');
INSERT INTO badge_optional_requirements VALUES(7378,579,5,'Identify and try at least 10 different types of rice. How are they cooked differently? What type of dishes are usually made with each rice type?');
INSERT INTO badge_optional_requirements VALUES(7379,579,6,'Understand how rice is grown and harvested. Watch a video or read a book about farming for rice.');
INSERT INTO badge_optional_requirements VALUES(7380,579,7,'Visit a grocery store and note how many different types of rice are available.  If possible visit more than one and compare the selections.');
INSERT INTO badge_optional_requirements VALUES(7381,579,8,'Celebrate National Rice Month (September) and participate in a celebration of Fried Rice Day (September 20th).');
INSERT INTO badge_optional_requirements VALUES(7382,579,9,'Make a craft out of rice such as rice mosaics or dyed rice patterns.');
INSERT INTO badge_optional_requirements VALUES(7383,579,10,'Host a “rice potluck” (a.k.a. rice party) with sweet and savory options.');
INSERT INTO badge_optional_requirements VALUES(7384,579,11,'Learn the history of the rice ball and when it was most popular. Make a rice ball recipe from at least three different countries such as onigiri from Japan,  jumeok-bap from Korea, or arancini or suppli from Italy.  How are the flavors and preparations different?');
INSERT INTO badge_optional_requirements VALUES(7385,579,12,'Learn a song or poem about rice, Or make your own.');
INSERT INTO badge_optional_requirements VALUES(7386,579,13,'Participate in a community service project that has something to do with rice, such as host a charity breakfast, or donate rice to your local food pantry.');
INSERT INTO badge_optional_requirements VALUES(7387,579,14,'Make a dish from a culture where rice is a staple food, like sushi from Japan or biryani from India.');
INSERT INTO badge_optional_requirements VALUES(7388,579,15,'Learn about companies that make Instant Rice.  Is instant rice good for you?');
INSERT INTO badge_optional_requirements VALUES(7389,579,16,'Learn about rice in mythology.  What role does it play in myths and beliefs.');
INSERT INTO badge_optional_requirements VALUES(7390,579,17,'Learn about traditional rice breakfasts around the world and try at least 3.');
INSERT INTO badge_optional_requirements VALUES(7391,579,18,'Try 4 different rice foods such as rice noodles, rice bread, rice cookies, or rice candy.');
INSERT INTO badge_optional_requirements VALUES(7392,579,19,'Learn how rice paddies are created and why they’re used in cultivation.');
INSERT INTO badge_optional_requirements VALUES(7393,579,20,'Research rice’s role in world religions and cultural celebrations.');
INSERT INTO badge_optional_requirements VALUES(7394,579,21,'Find out about rice-based beverages like sake or horchata.  Try one.');
INSERT INTO badge_optional_requirements VALUES(7395,579,22,'Try making rice flour and use it to prepare a recipe like rice noodles or pancakes.');
INSERT INTO badge_optional_requirements VALUES(7396,579,23,'Experiment with making sticky rice and learn what makes it different from other types of rice.');
INSERT INTO badge_optional_requirements VALUES(7397,579,24,'Study how rice plays a role in addressing global food security.');
INSERT INTO badge_optional_requirements VALUES(7398,581,3,'Explain the most likely hazards you may encounter while working with robots and what you should do to anticipate, prevent, and respond to these hazards. Describe the appropriate safety gear and clothing that should be used when working with robotics. Discuss first aid and prevention for the types of injuries that could occur while participating in robotics activities and competitions, including cuts, eye injuries, and burns (chemical or heat).');
INSERT INTO badge_optional_requirements VALUES(7399,581,4,'Discuss the similarities and differences between remote control vehicles, tele-robots, and autonomous robots.');
INSERT INTO badge_optional_requirements VALUES(7400,581,5,'Discuss three different methods robots can use to move themselves other than wheels or tracks. Describe when it would be appropriate to use each method.');
INSERT INTO badge_optional_requirements VALUES(7401,581,6,'Learn about careers in robotics.  What type of education do you need?  What type of pay could you expect?  Where might you have to live? If possible, shadow someone for a day in one of these careers.');
INSERT INTO badge_optional_requirements VALUES(7402,581,7,'Read, or have read to you, a book on robotics.');
INSERT INTO badge_optional_requirements VALUES(7403,581,8,'Research the best colleges or universities to study robotics. What makes their programs more advanced than others?');
INSERT INTO badge_optional_requirements VALUES(7404,581,9,'Watch a cartoon or movie where one of the main characters is a robot. How does it compare to what you’ve learned so far about robotics?');
INSERT INTO badge_optional_requirements VALUES(7405,581,10,'Learn about robotics and space exploration. How are robots changing how we interact with space?');
INSERT INTO badge_optional_requirements VALUES(7406,581,11,'Research where scientists foresee robotics advancing in the future. Do you think their expectations are realistic? What interests you the most?');
INSERT INTO badge_optional_requirements VALUES(7407,581,12,'Learn about robotics in a career or industry that is not outright robotics, such as movie making, amusement parks, or medicine.');
INSERT INTO badge_optional_requirements VALUES(7408,581,13,'Build a programmable robot, and learn the names and functions of the parts you use.');
INSERT INTO badge_optional_requirements VALUES(7409,581,14,'Experiment with programming a robot to perform a simple task that includes movement and sensors.');
INSERT INTO badge_optional_requirements VALUES(7410,581,15,'Visit a location where robots are in use, and learn about what they do, and how that affects humans and the area itself.');
INSERT INTO badge_optional_requirements VALUES(7411,581,16,'Learn about three youth robotics competitions, including the type of competition, time commitment, age of participants, and how many teams are involved.');
INSERT INTO badge_optional_requirements VALUES(7412,581,17,'Attend a robotics competition and take notes about what you see and learn, as well as how teams are organized and managed while there.');
INSERT INTO badge_optional_requirements VALUES(7413,582,3,'What careers are available for rock climbers? What kind of education, if any, do you need? How much does the average rock climber make in a year?');
INSERT INTO badge_optional_requirements VALUES(7414,582,4,'Learn about the 5 different harnesses. What are they used for. Are there harnesses used specially for beginners or children as opposed to more advanced or intermediate climbers?');
INSERT INTO badge_optional_requirements VALUES(7415,582,5,'Watch a movie or documentary or read a book on a famous mountain climber or a climbing expedition. What mountain did they climb? What are they famous for? Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(7416,582,6,'Create a game or activity that will help others learn about the different equipment used in climbing.');
INSERT INTO badge_optional_requirements VALUES(7417,582,7,'Go rock climbing on an indoor wall and then on actual rocks outdoors. What is the difference between the two? Was one particularly easier than the other? Share you findings with others.');
INSERT INTO badge_optional_requirements VALUES(7418,582,8,'What are the hardest mountains in the world to climb? What makes them so hard? Height, weather, or maybe vertical slopes?');
INSERT INTO badge_optional_requirements VALUES(7419,582,9,'Are there any cultures around the world that encourage climbing more than others? Why? How about the ratio of men to women climbers? Why do you think that normally men are more encouraged than women to climb?');
INSERT INTO badge_optional_requirements VALUES(7420,582,10,'Explain how the difficulty of climbs are classified, and apply classifications to the rock faces or walls where you will demonstrate your climbing skills.');
INSERT INTO badge_optional_requirements VALUES(7421,582,11,'Learn the differences between top-rope climbing, lead climbing, and bouldering.');
INSERT INTO badge_optional_requirements VALUES(7422,582,12,'Using a carabiner and a rappel device, secure your climbing harness to a rappel rope.   Tie in to a belay rope set up to protect rappellers and rappel down three different rock faces or three rappel routes on a climbing wall. Use verbal signals to communicate with a belayer, and demonstrate good rappelling technique.');
INSERT INTO badge_optional_requirements VALUES(7423,583,3,'Discover when the first manned and unmanned mission into space took place.');
INSERT INTO badge_optional_requirements VALUES(7424,583,4,'What is the furthest place in space we have received pictures from? If possible, look at a few of the photographs.');
INSERT INTO badge_optional_requirements VALUES(7425,583,5,'Be able to describe the main components of a rocket.');
INSERT INTO badge_optional_requirements VALUES(7426,583,6,'Learn about and discuss the procedure for launching a NASA rocket into space.');
INSERT INTO badge_optional_requirements VALUES(7427,583,7,'Learn about the major events in space exploration. What places in space have human beings visited? What places have robots visited?');
INSERT INTO badge_optional_requirements VALUES(7428,583,8,'Learn about the laws in your area regarding rocket launching. Where and when are you allowed to launch a rocket?');
INSERT INTO badge_optional_requirements VALUES(7429,583,9,'Build a rocket and launch it in a lawful location. Level 4 and above must build a second rocket to fulfill this requirement. All underage members must have adult supervision.');
INSERT INTO badge_optional_requirements VALUES(7430,583,10,'Learn about the different types of fuel for both hobby and commercial/government rocks.');
INSERT INTO badge_optional_requirements VALUES(7431,583,11,'Learn about the basics of aerodynamics. How do aerodynamics affect rockets?');
INSERT INTO badge_optional_requirements VALUES(7432,583,12,'What is NASA? Describe NASA’s mission and how long it has been in operation.');
INSERT INTO badge_optional_requirements VALUES(7433,583,13,'Learn about at least two rocket accidents in history. What was the damage inflicted on property and human life?');
INSERT INTO badge_optional_requirements VALUES(7434,583,14,'Learn about animals that have participated in the history of space exploration.');
INSERT INTO badge_optional_requirements VALUES(7435,583,15,'Learn about the first man to the moon.');
INSERT INTO badge_optional_requirements VALUES(7436,583,16,'Participate in a community service project involving rockets.');
INSERT INTO badge_optional_requirements VALUES(7437,583,17,'Learn about different careers involving rockets. Where would you be expected to live, what would your pay be, and what would your hours be? If possible, shadow someone with a job involving rockets.');
INSERT INTO badge_optional_requirements VALUES(7438,584,3,'Make a craft using rocks.');
INSERT INTO badge_optional_requirements VALUES(7439,584,4,'Learn about what erosion is and how it effects the land. Find at least 3 examples of erosion in your neighborhood.');
INSERT INTO badge_optional_requirements VALUES(7440,584,5,'Look around your neighborhood and see how many things you can find that are made out of rock such as sidewalks, or buildings.  Levels 3- 5: Know what type of rock was used and why.');
INSERT INTO badge_optional_requirements VALUES(7441,584,6,'Participate in a community service project that involves rocks or minerals. Examples might include volunteering to help at rock and mineral show or helping with an erosion control project.');
INSERT INTO badge_optional_requirements VALUES(7442,584,7,'Make a list of precious and semi-precious stones used for adornment. Be able to recognize and name at least 10 and find out where they come from.');
INSERT INTO badge_optional_requirements VALUES(7443,584,8,'Take a field trip to a place of geologic interest. Write a short essay or draw a picture about what you learned.');
INSERT INTO badge_optional_requirements VALUES(7444,584,9,'Make an edible craft to represent your study of rocks. Examples might include rock candy, dirt cupcakes, candy jewelry, chocolate rocks, etc.');
INSERT INTO badge_optional_requirements VALUES(7445,584,10,'Visit a lapidary (artist who works with gemstones) and find out about their craft.');
INSERT INTO badge_optional_requirements VALUES(7446,584,11,'Attend a rock and mineral show or exhibit.');
INSERT INTO badge_optional_requirements VALUES(7447,584,12,'Dirt and sand are simply broken down pieces of rock. Create an art project using soil, clay, or sand. Examples might be a colored sand jar, pottery, chalk drawings, etc.');
INSERT INTO badge_optional_requirements VALUES(7448,584,13,'Start a rock collection. Find a box or object to store your rocks in. Collect rocks from at least 5 different locations away from your home.');
INSERT INTO badge_optional_requirements VALUES(7449,584,14,'Learn about stalactites and stalagmites. What are they made of? What causes them? View pictures online (with parent permission) or in a book, and if possible, visit an actual cavern to see them in person.');
INSERT INTO badge_optional_requirements VALUES(7450,584,15,'Learn about careers that involve rocks such as a geologist, soil engineer, mineralogist, geochronologist, miner, geochemist, stratigrapher, lapidarist, etc.');
INSERT INTO badge_optional_requirements VALUES(7451,584,16,'Choose one piece of geological equipment to learn more about. Explain how the item is used, why it is important, and find out how much one would cost to purchase. Examples might include microscopes, cameras, safety glasses, geologist hammer, rock polisher, etc.');
INSERT INTO badge_optional_requirements VALUES(7452,584,17,'Learn about at least 5 famous rocks around the world. Examples might include the Hope Diamond, Uluru, Rock of Gibraltar, or Mount Rushmore.');
INSERT INTO badge_optional_requirements VALUES(7453,585,3,'Earn the Cowboy/girl badge at your level.');
INSERT INTO badge_optional_requirements VALUES(7454,585,4,'Create a presentation about rodeos. Be sure to include important dates, names of famous rodeo riders, etc. Present to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(7455,585,5,'Attend a rodeo or watch one on television (with your parent’s permission). Which event did you most enjoy watching? Which did you least enjoy?');
INSERT INTO badge_optional_requirements VALUES(7456,585,6,'Learn about careers in the rodeo business, such as a cowboy or a veterinarian. What kind of training/education is required? What are working hours typically like and what hourly pay-rate/salary can you expect? If possible, shadow someone for a day who works in the rodeo business.');
INSERT INTO badge_optional_requirements VALUES(7457,585,7,'Find at least three songs about cowboys/cowgirls or rodeos and learn one of them.');
INSERT INTO badge_optional_requirements VALUES(7458,585,8,'Learn about bullfighting. How is it different from a rodeo? What is the difference between a matador and a toreador?');
INSERT INTO badge_optional_requirements VALUES(7459,585,9,'Find out what spurs are, what they are used for, and how they are used responsibly. Look at pictures of different styles of spurs, such as the Prince of Wales style.');
INSERT INTO badge_optional_requirements VALUES(7460,585,10,'Learn about the role of the rodeo clown. Explain why this job is so important.');
INSERT INTO badge_optional_requirements VALUES(7461,585,11,'Learn about the Little Britches Rodeo. Children of what ages can compete in it? What is “mutton busting”? Tell your family, friends, or group what you learn. If possible, attend a children’s rodeo.');
INSERT INTO badge_optional_requirements VALUES(7462,585,12,'Longhorn cattle are the breed usually used in rodeos. Learn about this breed and where it came from. Tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(7463,585,13,'Learn how to tie a noose/slipknot and how to lasso something stationary, such as a fence post. Do not attempt to lasso anything alive that could potentially hurt you or it.');
INSERT INTO badge_optional_requirements VALUES(7464,585,14,'Make a collage, poster, or scrapbook page showing what you have learned while earning this badge. Show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(7465,585,15,'Learn about the safety equipment and clothing that are used at rodeos. How have safety standards changed during the history of rodeos?');
INSERT INTO badge_optional_requirements VALUES(7466,585,16,'Learn about a famous rodeo horse or bull, such as bulls Tornado or Blueberry Wine or cutting horses Bet Yur Blue Boons or Smart Little Lena. What made these animals so notable?');
INSERT INTO badge_optional_requirements VALUES(7467,586,3,'Ride a roller coaster.');
INSERT INTO badge_optional_requirements VALUES(7468,586,4,'Learn the History of roller coasters (Preschool and Level 1 only)');
INSERT INTO badge_optional_requirements VALUES(7469,586,5,'Make a time line of at least 10 events in roller coaster history. Level 3 and above must make a timeline of at least 15 events.');
INSERT INTO badge_optional_requirements VALUES(7470,586,6,'Watch a documentary or video about famous roller coasters or how roller coasters work.');
INSERT INTO badge_optional_requirements VALUES(7471,586,7,'(Preschool – Otters only) Read a story that has a roller coaster in it.');
INSERT INTO badge_optional_requirements VALUES(7472,586,8,'Play the game “Roller Coaster Tycoon”');
INSERT INTO badge_optional_requirements VALUES(7473,586,9,'Find out what role magnets play in the operation of newer roller coaster.');
INSERT INTO badge_optional_requirements VALUES(7474,586,10,'(Preschool – Level 2 only) Find out what effect a roller coaster has on your body. Why do you feel like your stomach is rising when you fall? What is a G Force? What is inertia?');
INSERT INTO badge_optional_requirements VALUES(7475,586,11,'What is the difference between a chain lift and catapult/launch lift? What type of braking system do most roller coasters have?');
INSERT INTO badge_optional_requirements VALUES(7476,586,12,'Read a book about roller coasters.');
INSERT INTO badge_optional_requirements VALUES(7477,586,13,'Interview a roller coaster designer or theme park manager');
INSERT INTO badge_optional_requirements VALUES(7478,586,14,'(Preschool – Level 3 only) Explain the role that potential energy and kinetic energy play in the operation of a roller coaster? What is Newton’s First Law of Motion, and how does it relate to roller coasters?');
INSERT INTO badge_optional_requirements VALUES(7479,586,15,'Find out what jobs are available that work with roller coasters. Examples might be a roller coaster designer, theme park worker, maintenance worker, film maker, etc. What education would you need for one of these jobs? What pay could you expect? What hours might you expect to work?');
INSERT INTO badge_optional_requirements VALUES(7480,587,3,'Listen to a few songs about Route 66 and learn the history behind one.');
INSERT INTO badge_optional_requirements VALUES(7481,587,4,'Visit a historic site along Route 66.');
INSERT INTO badge_optional_requirements VALUES(7482,587,5,'Learn about Harvey Houses.');
INSERT INTO badge_optional_requirements VALUES(7483,587,6,'Watch a movie or TV show related to Route 66.');
INSERT INTO badge_optional_requirements VALUES(7484,587,7,'Drive (ride) along a section of the Mother Road.');
INSERT INTO badge_optional_requirements VALUES(7485,587,8,'Find out how much of Route 66 is still travel-able.');
INSERT INTO badge_optional_requirements VALUES(7486,587,9,'Read a book about Route 66.');
INSERT INTO badge_optional_requirements VALUES(7487,587,10,'Find as many Route 66 associations and foundations as you can. What are their goals?');
INSERT INTO badge_optional_requirements VALUES(7488,587,11,'Make a list of at least 10 fun places to visit along Route 66.  Find them on a map.');
INSERT INTO badge_optional_requirements VALUES(7489,587,12,'Plan a pretend or real trip along Route. 66. Where would you stop along the way? How long would you have to drive? Where might you eat or sleep during your trip?');
INSERT INTO badge_optional_requirements VALUES(7490,587,13,'Learn about Route 66 in popular media/culture. How is it presented? Are these realistic portrayals?');
INSERT INTO badge_optional_requirements VALUES(7491,588,3,'Learn about a competitive Rubik’s cube solver, such as Feliks Zemdegs or Mats Valk.');
INSERT INTO badge_optional_requirements VALUES(7492,588,4,'Be able to solve a 3x3x3 in under 5 minutes.');
INSERT INTO badge_optional_requirements VALUES(7493,588,5,'Learn how to solve 2 cubes other than the 3x3x3, such as 4x4x4, 5x5x5, or 2x2x2.');
INSERT INTO badge_optional_requirements VALUES(7494,588,6,'Read about the history of Rubik’s cubes.');
INSERT INTO badge_optional_requirements VALUES(7495,588,7,'Watch a Rubik’s cube competition in person or online (with a parent’s permission).');
INSERT INTO badge_optional_requirements VALUES(7496,588,8,'Learn a speed solve method.');
INSERT INTO badge_optional_requirements VALUES(7497,588,9,'Participate in a Rubik’s cube club or competition.');
INSERT INTO badge_optional_requirements VALUES(7498,588,10,'Teach a friend or sibling how to solve a Rubik’s cube.');
INSERT INTO badge_optional_requirements VALUES(7499,588,11,'Challenge a friend or sibling to a Rubik’s cube competition.');
INSERT INTO badge_optional_requirements VALUES(7500,588,12,'Learn how a Rubik’s cube is made.');
INSERT INTO badge_optional_requirements VALUES(7501,589,3,'Why is weather so important to sailors? Learn what to do if you are caught in dangerous weather and how to avoid it in the first place.');
INSERT INTO badge_optional_requirements VALUES(7502,589,4,'Learn about the history of sailing and how sailboats have evolved.');
INSERT INTO badge_optional_requirements VALUES(7503,589,5,'Learn about someone who has sailed around the globe alone.');
INSERT INTO badge_optional_requirements VALUES(7504,589,6,'What are the most common injuries to sailors? Know the basic first aid to treat them.');
INSERT INTO badge_optional_requirements VALUES(7505,589,7,'Where is competitive sailing most popular? Learn about a popular sailboat competition in one of these countries. Can you compete in a sailing competition locally?');
INSERT INTO badge_optional_requirements VALUES(7506,589,8,'Learn 5 good sailing drills and practice them.');
INSERT INTO badge_optional_requirements VALUES(7507,589,9,'What are the points of sail? Be able to identify which point you are facing while sailing.');
INSERT INTO badge_optional_requirements VALUES(7508,589,10,'Learn about modern careers in which sailing is involved. What education is needed, and what are the pay and work schedules like?');
INSERT INTO badge_optional_requirements VALUES(7509,589,11,'Learn about different types of sailing rigs, such as: Ship Schooner Brig Ketch Cutter Yawl Bark Junk');
INSERT INTO badge_optional_requirements VALUES(7510,589,12,'Learn how to create at least five knots that are handy for sailing.');
INSERT INTO badge_optional_requirements VALUES(7511,589,13,'Learn how to prevent a sailboat from capsizing and, if it does capsize, what to do.');
INSERT INTO badge_optional_requirements VALUES(7512,589,14,'If you could own the sailboat of your dreams, what would it be? What would it look like? How much might it cost?');
INSERT INTO badge_optional_requirements VALUES(7513,590,3,'Celebrate the saints day of your chosen saint. Some ways could be participating in a mass, volunteering, or donating to their cause');
INSERT INTO badge_optional_requirements VALUES(7514,590,4,'Perform in a play about your saint’s life.');
INSERT INTO badge_optional_requirements VALUES(7515,590,5,'Complete a craft about your saint');
INSERT INTO badge_optional_requirements VALUES(7516,590,6,'Is there a place where people celebrate your saint regularly? Find it on a map. Why do you think that they celebrate your saint?');
INSERT INTO badge_optional_requirements VALUES(7517,590,7,'Find some of your saint’s shrines or churches on a map. If you can, visit the shrine or church.');
INSERT INTO badge_optional_requirements VALUES(7518,590,8,'Many pictures of saints have symbolism in them. Learn the meaning behind some of the symbols in the pictures.');
INSERT INTO badge_optional_requirements VALUES(7519,590,9,'Learn a song about your saint');
INSERT INTO badge_optional_requirements VALUES(7520,590,10,'Learn a prayer or Bible passage featuring your saint.');
INSERT INTO badge_optional_requirements VALUES(7521,590,11,'Create a poster or piece of art that shows what you know about your chosen saint.');
INSERT INTO badge_optional_requirements VALUES(7522,590,12,'Discuss how this saint can be a role model for young children today. What can you learn from this saint as far as how to make yourself a better person?');
INSERT INTO badge_optional_requirements VALUES(7523,590,13,'Watch an age-appropriate documentary on your chosen saint.');
INSERT INTO badge_optional_requirements VALUES(7524,590,14,'If you could interview your chosen saint, what would you ask? Make a list of 10 questions you would ask if you were given the opportunity. Discuss what you think their answers might be.');
INSERT INTO badge_optional_requirements VALUES(7525,590,15,'Follow in the footsteps of your chosen saint by doing something they may have done. If they were a painter, what style did they paint in? Try painting in that style. If they were famous for their speeches, try writing a speech about something important to you, etc.');
INSERT INTO badge_optional_requirements VALUES(7526,590,16,'Write a poem about the saint you chose. The poem should feature qualities that make the person unique, facts relating to the person’s life, and other details.');
INSERT INTO badge_optional_requirements VALUES(7527,590,17,'Participate in a community service project that reflects your chosen saint. For example, if they were known for helping children, find a way to help the children in your community.');
INSERT INTO badge_optional_requirements VALUES(7528,592,3,'Discuss the nutritional value of salads. Is there anything you can do to increase the healthfulness of standard salads? What is the nutritional difference of dark vs. light green leaves? What is the nutritional difference between cruciferous vegetables and those from other families?');
INSERT INTO badge_optional_requirements VALUES(7529,592,4,'Make a side salad such as a potato salad, pasta salad, rice salad, couscous salad, etc.');
INSERT INTO badge_optional_requirements VALUES(7530,592,5,'Think of all the pros and cons you can regarding making individual salads versus salads in a large bowl. Which ones are easiest to garnish? Compare the price of salad bowls with serving utensils and individual salad plates.');
INSERT INTO badge_optional_requirements VALUES(7531,592,6,'Develop your talent at making gelatin salads. Make at least 2 of the following: Vegetable salad with gelatin Fruit salad with gelatin Layered gelatin salad Molded gelatin salad and turn it out onto a plate or serving dish');
INSERT INTO badge_optional_requirements VALUES(7532,592,7,'Practice making garnishes for your salads. Learn at least one you have never made before. Make garnishes from fruits or vegetables in at least three basic shapes and in at least three different colors.');
INSERT INTO badge_optional_requirements VALUES(7533,592,8,'Learn how to make your own salad dressings. Levels 3-5: Make at least one oil-and-vinegar style dressing and at least one containing egg yolk.');
INSERT INTO badge_optional_requirements VALUES(7534,592,9,'Be able to identify by sight and taste 5 different kinds of greens such as kale, chard, tat soi, mache,  and endive.');
INSERT INTO badge_optional_requirements VALUES(7535,592,10,'Learn to identify by sight and taste 5 different foods that add a sour taste to a salad such as grapefruit, pickled cucumbers, okra or beets.');
INSERT INTO badge_optional_requirements VALUES(7536,592,11,'Visit a restaurant that has a salad bar. What would you do to give the bar more eye appeal? Could you enhance the nutritional value of the offerings? Does the restaurant do a good job keeping everything fresh and clean? If you think you have a valid criticism or a wonderful suggestion for the restaurant, write the manager a letter.');
INSERT INTO badge_optional_requirements VALUES(7537,592,12,'Make at least one salad for a shut-in or a large one for a fund-raising event.');
INSERT INTO badge_optional_requirements VALUES(7538,592,13,'Choose ten fruits or vegetables and rank them according to content of vitamin A, fiber, vitamin C, and antioxidants (look for the ORAC value). Share your four tables with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(7539,593,3,'Visit Salem, Massachusetts and visit sites relating to the Witch Trials. If you cannot visit in person, use the internet to take a virtual field trip with parental permission.');
INSERT INTO badge_optional_requirements VALUES(7540,593,4,'Learn about other witch trials/witch hunts in history and other countries.');
INSERT INTO badge_optional_requirements VALUES(7541,593,5,'Read a book or watch a movie about the Salem Witch Trials.');
INSERT INTO badge_optional_requirements VALUES(7542,593,6,'Create a map of the Trials. Include the homes of accusers and accused, where trials took place, and where prisoners were kept.');
INSERT INTO badge_optional_requirements VALUES(7543,593,7,'Look at real life court sketches. Make one of what you think the trials looked like.');
INSERT INTO badge_optional_requirements VALUES(7544,593,8,'Learn who the Puritans were.');
INSERT INTO badge_optional_requirements VALUES(7545,593,9,'Make a map of the American colonies during the Salem Witch Trials.');
INSERT INTO badge_optional_requirements VALUES(7546,593,10,'Write a report on how you think you would react if you were accused of witchcraft. Would you confess to avoid punishment or stand your ground and tell the truth? Compare the consequences of both options.');
INSERT INTO badge_optional_requirements VALUES(7547,593,11,'Create a newspaper article about the Salem Witch Trials. If you are earning this badge with your group, you can combine your articles into one newspaper!');
INSERT INTO badge_optional_requirements VALUES(7548,594,3,'Learn about other cultures’ methods of making “sandwiches” such as tacos, empanadas, pasties, burritos, calzones, pitas, sushi rolls, etc. Try one that is new to you.');
INSERT INTO badge_optional_requirements VALUES(7549,594,4,'Learn to cook sandwiches that are cooked after being put together such as grilled cheese sandwiches and calzones.');
INSERT INTO badge_optional_requirements VALUES(7550,594,5,'Learn to make sandwiches with hot fillings such as pulled pork, hamburgers, and hot roast beef.');
INSERT INTO badge_optional_requirements VALUES(7551,594,6,'Help make, sell, or serve sandwiches for a non-profit organization.');
INSERT INTO badge_optional_requirements VALUES(7552,594,7,'Learn to make gluten-free and dairy-free sandwiches. These can be on crackers or rice cakes if gluten-free bread is hard to obtain.');
INSERT INTO badge_optional_requirements VALUES(7553,594,8,'Learn how to best store and keep cold or hot all the raw ingredients for sandwich-making.');
INSERT INTO badge_optional_requirements VALUES(7554,594,9,'Learn about your options for packing and transporting sandwiches for trips. What can you do so they don’t get soggy, misshapen, or spoiled?');
INSERT INTO badge_optional_requirements VALUES(7555,594,10,'Learn about fancy little open-face sandwiches on crackers. What part of the world is famous for them? Learn 5 different way to garnish these sandwiches.');
INSERT INTO badge_optional_requirements VALUES(7556,594,11,'Learn about the risks people take with their health when they eat too many sandwiches from fast food restaurants. Watch a documentary on the fast food industry in regards to sandwiches.');
INSERT INTO badge_optional_requirements VALUES(7557,594,12,'Learn how to make at least three variations of hamburgers by stirring ingredients into the meat or by adding interesting additions on top of the burger.');
INSERT INTO badge_optional_requirements VALUES(7558,594,13,'Learn how to make veggie burgers from scratch.');
INSERT INTO badge_optional_requirements VALUES(7559,595,3,'Participate in a holiday-themed scavenger hunt.');
INSERT INTO badge_optional_requirements VALUES(7560,595,4,'Participate in a photography scavenger hunt and create an album of your finds.');
INSERT INTO badge_optional_requirements VALUES(7561,595,5,'Visit your local library and complete a library-themed scavenger hunt.');
INSERT INTO badge_optional_requirements VALUES(7562,595,6,'Participate in a geography-themed scavenger hunt.  Tell others one new fact that you learned.');
INSERT INTO badge_optional_requirements VALUES(7563,595,7,'Participate in a numbers- or math-themed scavenger hunt.');
INSERT INTO badge_optional_requirements VALUES(7564,595,8,'Create and organize a random acts of kindness scavenger hunt.');
INSERT INTO badge_optional_requirements VALUES(7565,595,9,'Create and organize a gratitude scavenger hunt.');
INSERT INTO badge_optional_requirements VALUES(7566,595,10,'Create and organize a five senses-themed scavenger hunt.');
INSERT INTO badge_optional_requirements VALUES(7567,595,11,'Make a book or journal full of scavenger hunt lists that you have completed or would like to complete in the future.');
INSERT INTO badge_optional_requirements VALUES(7568,595,12,'Sketch a scavenger hunt list, no words allowed.');
INSERT INTO badge_optional_requirements VALUES(7569,595,13,'Learn about the world’s largest in-person scavenger hunt and the world’s largest media scavenger hunt.');
INSERT INTO badge_optional_requirements VALUES(7570,595,14,'Go on a hike and complete a nature-themed scavenger hunt that you find on-line or one that someone created for you.');
INSERT INTO badge_optional_requirements VALUES(7571,595,15,'With a parent’s permission, research online scavenger hunts available for various travel locations.');
INSERT INTO badge_optional_requirements VALUES(7572,596,3,'What is the history of your school? Is it a part of a school district?');
INSERT INTO badge_optional_requirements VALUES(7573,596,4,'Know where your school’s cafeteria, gym, library, bathrooms, offices are located so you can find them and help guests or new students find them.');
INSERT INTO badge_optional_requirements VALUES(7574,596,5,'Help keep your classroom or playground clean. Make posters or flyers  to discourage littering.');
INSERT INTO badge_optional_requirements VALUES(7575,596,6,'Participate in a service project to help your school, such as having a book drive to get books for the library, organizing a fundraiser to buy new sports equipment, planting trees, picking up trash, raking leaves,  etc');
INSERT INTO badge_optional_requirements VALUES(7576,596,7,'Think of at least 5 things that make your school special to you.');
INSERT INTO badge_optional_requirements VALUES(7577,596,8,'Participate in a special ceremony or performance at your school.');
INSERT INTO badge_optional_requirements VALUES(7578,596,9,'With permission from the necessary people, invite someone to your school. Show them around, introduce them to your teacher.');
INSERT INTO badge_optional_requirements VALUES(7579,596,10,'Do something to promote school spirit, like help with Spirit Days, wear a school shirt to a public event, march with the band in a parade, etc.');
INSERT INTO badge_optional_requirements VALUES(7580,596,11,'Interview a staff member to find out why they like working at your school.');
INSERT INTO badge_optional_requirements VALUES(7581,596,12,'Know what special awards your school has received.');
INSERT INTO badge_optional_requirements VALUES(7582,597,3,'Draw your own mystery machine van. What would your van have on it? What colors would you use? Would it have any special features for detective work?');
INSERT INTO badge_optional_requirements VALUES(7583,597,4,'Create your own group of detectives and solve a mystery. This could be a group of friends or family that come together to do an escape room, city wide scavenger hunt, old historical mystery in your city, etc. Get creative. Check with the local library or any museums dedicated to your area.');
INSERT INTO badge_optional_requirements VALUES(7584,597,5,'Make a Scooby Doo craft. Share this craft by gifting it to someone you know or a neighborhood child who likes the stories.');
INSERT INTO badge_optional_requirements VALUES(7585,597,6,'Have a Mystery Inc party. Make mystery treats but make sure to list allergens in case your friends or family have any. Make the party members guess what the treat is supposed to represent from the books or shows. Hold a Scooby doo character voice contest. Who sounds the most like Fred, Daphne, or Velma?');
INSERT INTO badge_optional_requirements VALUES(7586,597,7,'Dress as your favorite character from the Scooby doo timeline. This can be from a book and or one of the shows or movies.');
INSERT INTO badge_optional_requirements VALUES(7587,597,8,'Play a Scooby Doo game. This can be one you find online, have on your gaming console, or you make at home.');
INSERT INTO badge_optional_requirements VALUES(7588,597,9,'Pick a Scooby Doo story from another part of the world and study that area. What nationality of people live here? What is the weather like in this area? What type of foods do they eat in this area? Did Shaggy and Scooby eat anything authentic to the people of that region in the show or book?');
INSERT INTO badge_optional_requirements VALUES(7589,597,10,'Create and carry out a Scooby Doo hunt with your friends. Place an object somewhere close to home, and leave clues for the others playing to search and find the item.');
INSERT INTO badge_optional_requirements VALUES(7590,597,11,'Learn about real detectives. What is it like doing actual detective work in real life? What career fields would use these types of skills and how would you obtain this type of work. Do you need to do any special schooling to achieve becoming a detective?');
INSERT INTO badge_optional_requirements VALUES(7591,597,12,'How far back does the Scooby doo enjoyment go in your family? Ask someone in your family or neighborhood who is older than you if they know the character and how far back, they remember enjoying it. Do they have a favorite episode or book from the series?');
INSERT INTO badge_optional_requirements VALUES(7592,597,13,'Read five Scooby Doo books in one week. Pick one of the five books and write out your favorite parts from the story. Where were the Mystery Inc. when they were investigating? Did you suspect the wrong person to be the villain? How did they catch the bad guy?');
INSERT INTO badge_optional_requirements VALUES(7593,597,14,'Create a resume and cover letter to join the Mystery Inc gang. Don''t forget to mention why you would be a good addition to the team. What makes you Mystery Inc material?');
INSERT INTO badge_optional_requirements VALUES(7594,597,15,'Watch two different versions of Scooby-Doo (e.g., original series and a newer version) and describe how they are the same or different.');
INSERT INTO badge_optional_requirements VALUES(7595,597,16,'Learn and sing the Scooby-Doo theme song.');
INSERT INTO badge_optional_requirements VALUES(7596,597,17,'Watch a Scooby-Doo movie that features a real celebrity or crossover (like Batman or WWE) and describe what made it special.');
INSERT INTO badge_optional_requirements VALUES(7597,597,18,'Learn what animation is and how Scooby-Doo cartoons are made.');
INSERT INTO badge_optional_requirements VALUES(7598,597,19,'Learn what a red herring is in a mystery and find examples in Scooby-Doo episodes.');
INSERT INTO badge_optional_requirements VALUES(7599,597,20,'Create a new ghost or villain character and draw or describe what makes them spooky.');
INSERT INTO badge_optional_requirements VALUES(7600,597,21,'Learn what a catchphrase is and list famous Scooby-Doo phrases like ''Jinkies!'' or ''Zoinks!''');
INSERT INTO badge_optional_requirements VALUES(7601,598,3,'Play at least 10 games of Scrabble, either with another person or online/against a computer (with your parent’s permission).');
INSERT INTO badge_optional_requirements VALUES(7602,598,4,'Read about a famous Scrabble champion, such as Brian Cappelletto or Mike Baron.');
INSERT INTO badge_optional_requirements VALUES(7603,598,5,'Learn about Scrabble tournaments.  If possible, compete in one.');
INSERT INTO badge_optional_requirements VALUES(7604,598,6,'Research different legal game variations or house-rules, such as that about replacing blanks already on the board with the corresponding letter tile so as to be able to use the blank in the same turn (no points are gained for the letter replacing the blank).');
INSERT INTO badge_optional_requirements VALUES(7605,598,7,'Explain how playing Scrabble can help improve your grades in spelling and math.');
INSERT INTO badge_optional_requirements VALUES(7606,598,8,'Teach a younger person, such as a younger sibling, friend, or fellow member, how to play Scrabble, or play a game with someone in a nursing home or other place where you can share your knowledge with your community.');
INSERT INTO badge_optional_requirements VALUES(7607,598,9,'Find out what sort of Scrabble helps are available, such as Scrabble dictionaries, wordbooks, or crossword puzzle books.');
INSERT INTO badge_optional_requirements VALUES(7608,598,10,'Learn about any other Scrabble games, such as Junior Scrabble. Find one and play it.');
INSERT INTO badge_optional_requirements VALUES(7609,598,11,'Make a craft using Scrabble pieces.');
INSERT INTO badge_optional_requirements VALUES(7610,599,3,'Learn about the following adhesives and the benefits and drawbacks of each. Try at least 2. Glue Glue Sticks Double Sided Tape Glue Dots Double Sided foam');
INSERT INTO badge_optional_requirements VALUES(7611,599,4,'Create a scrapbook to give to someone as a gift.');
INSERT INTO badge_optional_requirements VALUES(7612,599,5,'Visit a scrapbook store or browse one online with a parent. Find out about at least three different products you have never seen before.');
INSERT INTO badge_optional_requirements VALUES(7613,599,6,'Learn to safely use a paper cutter to cut a straight line. Use a paper cutter to make at least three frames for your photos.');
INSERT INTO badge_optional_requirements VALUES(7614,599,7,'Take a scrapbook class.');
INSERT INTO badge_optional_requirements VALUES(7615,599,8,'Create a scrapbook layout for your family, group, school, sports team, or church.');
INSERT INTO badge_optional_requirements VALUES(7616,599,9,'Learn about different types of embellishments. Be able to identify the following: Eyelets Die-cut Stickers Buttons Transfers Punches');
INSERT INTO badge_optional_requirements VALUES(7617,599,10,'Create an ABC album, where every page’s theme starts with a letter of the alphabet.');
INSERT INTO badge_optional_requirements VALUES(7618,599,11,'Use a graphic or scrapbook program to create a digital scrapbook layout on your computer.');
INSERT INTO badge_optional_requirements VALUES(7619,599,12,'Host or attend a crop. When a group of scrapbookers get together to work on their scrapbooks, it is called a crop. If you are the host, make sure that you plan well and have plenty of trash cans, scrap buckets, etc. Most crops require that each scrapbooker bring their own supplies and tools, but it is always nice to share as well.');
INSERT INTO badge_optional_requirements VALUES(7620,600,3,'Learn about various careers that involve sculpting, such as a sculptor, art teacher, museum curator, and talk to someone in that field about what they like about sculpting and why they chose that career.  What type of hours and pay could you expect for this type of career?');
INSERT INTO badge_optional_requirements VALUES(7621,600,4,'Go to a local art fair that shows sculptures or an art gallery. Find 3 sculptures and write or discuss about what you like or don’t like about them.');
INSERT INTO badge_optional_requirements VALUES(7622,600,5,'Take a sculpting class.');
INSERT INTO badge_optional_requirements VALUES(7623,600,6,'Learn about kinetic sculptures. Find at least 5 to see in action in person or online.');
INSERT INTO badge_optional_requirements VALUES(7624,600,7,'Read a biography about a famous sculptor.');
INSERT INTO badge_optional_requirements VALUES(7625,600,8,'Watch a documentary about a famous sculpture or sculptor.');
INSERT INTO badge_optional_requirements VALUES(7626,600,9,'Research one of the following genres/types of sculptures and create one of your own (this requirement may be repeated several times as further optional requirements). Clay Plasticine Wire Mixed media Blown glass Carving in wood Carving in stone Soft sculpture Figurine Miniatures Religious sculptures Busts Cameos Ice sculpture Sand sculpture Other');
INSERT INTO badge_optional_requirements VALUES(7627,600,10,'Make a simple pinch pot and then carve or print designs into the sides.');
INSERT INTO badge_optional_requirements VALUES(7628,600,11,'Make a carved sculpture from soap or soft wood. Be sure to follow proper safety techniques.');
INSERT INTO badge_optional_requirements VALUES(7629,600,12,'Watch or read about a sculpture competition such as an ice carving, sand castle, or other. Discuss the techniques and tools used.');
INSERT INTO badge_optional_requirements VALUES(7630,600,13,'With permission, search your house for tools that you could use to work with clay. Look for items that will carve, make an impression, and build up.');
INSERT INTO badge_optional_requirements VALUES(7631,600,14,'Use a framework as the base for a sculpture in clay or another medium. What is the purpose of framing underneath?');
INSERT INTO badge_optional_requirements VALUES(7632,600,15,'Learn what an armature is.  Create an armature out of tin foil or wire and then sculpt around it.');
INSERT INTO badge_optional_requirements VALUES(7633,600,16,'Learn about a famous sculpture.  Who made it and why?  What techniques were used?  Why is it famous?');
INSERT INTO badge_optional_requirements VALUES(7634,600,17,'Learn the following sculpture vocabulary words and their meanings: additive armature assemblage carving casting concave construction convex environmental in-the-round kinetic lost-wax casting mass modeling negative space positive space relief subtractive volume');
INSERT INTO badge_optional_requirements VALUES(7635,600,18,'Do a community service project involving public art or sculpture maintenance—such as cleaning outdoor art, creating signage, or designing a sculpture trail.');
INSERT INTO badge_optional_requirements VALUES(7636,600,19,'Learn the difference between freestanding (in-the-round) and relief sculpture. Make an example of each.');
INSERT INTO badge_optional_requirements VALUES(7637,600,20,'Learn about famous sculpture locations such as Mount Rushmore, Easter Island, or the Statue of Liberty');
INSERT INTO badge_optional_requirements VALUES(7638,600,21,'Design a sculpture that communicates an emotion or message. Explain what it means and how you expressed it through shape or material');
INSERT INTO badge_optional_requirements VALUES(7639,600,22,'Learn about safety and tools used in sculpting. Identify which tools are used for wood, stone, or metal sculpture');
INSERT INTO badge_optional_requirements VALUES(7640,600,23,'Learn about sculptures made from metal.  Some are single pieces of metal that have been moulded to form different shapes.  Some are made from many smaller pieces of metal.  Look at examples or pictures of metal sculptures.  Make your own from aluminium foil.');
INSERT INTO badge_optional_requirements VALUES(7641,600,24,'Learn about Kinetic Lego sculptures.  Visit an exhibition of Kinetic Lego sculptures or with permission watch a video of some online.  Make your own kinetic Lego sculpture.');
INSERT INTO badge_optional_requirements VALUES(7642,600,25,'Learn about simple kinetic sculptures that you can make at home from household materials and make one.');
INSERT INTO badge_optional_requirements VALUES(7643,600,26,'Learn about famous sculptures in your State.   Look at a minimum of 6 different sculptures either in person or online.   What materials are they made from?  Which sculpture do you like the best?  Why?  Find out who made your favourite sculpture and when it was made.');
INSERT INTO badge_optional_requirements VALUES(7644,600,27,'Make a sculpture out of Lego.');
INSERT INTO badge_optional_requirements VALUES(7645,601,3,'Collect seashells on a beach and identify what creature they are from.');
INSERT INTO badge_optional_requirements VALUES(7646,601,4,'Find out what sea creature has the largest shell and which has the smallest.');
INSERT INTO badge_optional_requirements VALUES(7647,601,5,'Learn about hermit crabs and other animals who use discarded shells.');
INSERT INTO badge_optional_requirements VALUES(7648,601,6,'Be able to identify different kinds of seashells. Preschool: Recognize one type of seashell. Levels 1-2: Recognize three seashells. Levels 3-4: Recognize five. Level 5: Recognize eight.');
INSERT INTO badge_optional_requirements VALUES(7649,601,7,'Learn how to package seashells for a trip without damaging them.');
INSERT INTO badge_optional_requirements VALUES(7650,601,8,'Visit a seashell exhibit.');
INSERT INTO badge_optional_requirements VALUES(7651,601,9,'Learn about the history of seashell collecting.');
INSERT INTO badge_optional_requirements VALUES(7652,601,10,'Do a craft involving seashells.');
INSERT INTO badge_optional_requirements VALUES(7653,601,11,'Learn about a career that involves seashells.  What type of education is needed?  How much money might you earn?  Where might you need to live?  Examples might include a marine biologist, a jewelry maker specializing in shell jewelry, or a natural museum curator.');
INSERT INTO badge_optional_requirements VALUES(7654,601,12,'Participate in a community service project involving shells, such as a beach cleanup, teaching younger kids about shells, making seashell crafts to sell and donate to a charity, etc.');
INSERT INTO badge_optional_requirements VALUES(7655,602,3,'Earn the Marine Life badge at your level.');
INSERT INTO badge_optional_requirements VALUES(7656,602,4,'Watch an animal show at SeaWorld.  Learn about how the animals are raised and cared for.');
INSERT INTO badge_optional_requirements VALUES(7657,602,5,'Ride a ride at SeaWorld Park and discuss the safety standards.');
INSERT INTO badge_optional_requirements VALUES(7658,602,6,'Learn what it takes to become a SeaWorld animal trainer.  Are there opportunities for youth to act as an intern or participate in classes that give them direct access to any of the animals?');
INSERT INTO badge_optional_requirements VALUES(7659,602,7,'Pick your favorite animal featured at the park and read a book about them.');
INSERT INTO badge_optional_requirements VALUES(7660,602,8,'Learn about SeaWorld’s conservation activities. Make a conservation poster.');
INSERT INTO badge_optional_requirements VALUES(7661,602,9,'Visit an exhibit where you can touch an animal and describe what it feels like to someone.');
INSERT INTO badge_optional_requirements VALUES(7662,602,10,'Make a piece of artwork about your favorite animal featured at SeaWorld.');
INSERT INTO badge_optional_requirements VALUES(7663,602,11,'Compare marine mammals and fish. What are the different characteristics of each? Learn about one exhibit of each at SeaWorld.');
INSERT INTO badge_optional_requirements VALUES(7664,602,12,'Pick two animals featured at SeaWorld and make a skit or mini-book about them.');
INSERT INTO badge_optional_requirements VALUES(7665,602,13,'Write a short story from the perspective of one of the animals featured at the park.');
INSERT INTO badge_optional_requirements VALUES(7666,602,14,'Design a habitat for an animal at SeaWorld. How would it differ from the habitat at the park?');
INSERT INTO badge_optional_requirements VALUES(7667,602,15,'Make a food chain using at least 3 animals featured at SeaWorld.');
INSERT INTO badge_optional_requirements VALUES(7668,602,16,'Use the SeaWorld map to give directions to at three different exhibits or rides.');
INSERT INTO badge_optional_requirements VALUES(7669,602,17,'Discuss the controversy all zoos and aquariums face regarding keeping animals in captivity.  Read at least one article for and one against this practice. What are your thoughts?');
INSERT INTO badge_optional_requirements VALUES(7670,603,3,'Create a piece of artwork or a craft that represents your season. Examples might include: Winter: Make scented pine cones. Collect pine cones, wash them with soap and water, bake them in the oven at 200 degrees for one hour. Place the cooled pine cones in a resealable plastic bag and sprinkle a few drops of essential oil (cinnamon, apple, orange, nutmeg) and shake the bag. Place the pine cones in a bowl or basket. Spring: Place the flowers between sheets of wax paper and place between two heavy books. Make bookmarks, note cards, pictures, etc. for a friend with your flowers. Summer: Make a picture frame by gluing seashells to a plastic frame. Fall: Collect fall leaves and either press them or do leaf rubbings.');
INSERT INTO badge_optional_requirements VALUES(7671,603,4,'Take a seasonal hike. Pay attention to what plants are blooming, or have lost their leaves. How does the season affect what you see?');
INSERT INTO badge_optional_requirements VALUES(7672,603,5,'Watch a documentary about your season.');
INSERT INTO badge_optional_requirements VALUES(7673,603,6,'Find out what holidays occur during your season.');
INSERT INTO badge_optional_requirements VALUES(7674,603,7,'Participate in a seasonal form of entertainment such as ice skating in the winter, leaf throwing in the fall, swimming in the summer or picking wildflowers in the spring.');
INSERT INTO badge_optional_requirements VALUES(7675,603,8,'Participate in a seasonal community service project such as tree planting or leaf raking.');
INSERT INTO badge_optional_requirements VALUES(7676,603,9,'Find out what sports are played during your season.');
INSERT INTO badge_optional_requirements VALUES(7677,603,10,'Find out what fruits and vegetables are available in your season. Where do the fruits and vegetables come from that are not currently in season in your area, but are still available at the grocery store?');
INSERT INTO badge_optional_requirements VALUES(7678,603,11,'Find out about your season in other parts of the world. For example, when it is summer in the U.S. it is winter in Australia. What is the season like there and how does it differ from the season at home?');
INSERT INTO badge_optional_requirements VALUES(7679,603,12,'Learn what constellations can be seen during your season and where they appear in the sky.');
INSERT INTO badge_optional_requirements VALUES(7680,603,13,'Learn how your local animals behave during your season. Do they hibernate, forage for food, mate, breed, migrate, go through metamorphosis, etc.?');
INSERT INTO badge_optional_requirements VALUES(7681,603,14,'Grow or care for a plant typically planted in the season you chose. Some examples include: Winter: Care for Chrysanthemums or a Christmas Cactus, or for the indoor bulb you planted in the fall (see below). Describe what you need to do to care for the plant and keep it healthy during the season. Spring: Examine how roots and shoots grow. Gather a glass jar, paper towel, bean seeds, water, and a spoon. Fold the paper towel in half, roll in into a tube, and put it into the jar. Slip bean seeds into the side of the jar in between the glass and the paper towel. Wet the paper towel by spooning water onto the paper until it is really wet. Place the jar in a sunny location. Journal what happens to the bean seeds. Another option is to plant spring flowers in your family’s garden. This requirement is fulfilled if you earn the Flower Gardening Merit Badge Summer: Plant some vegetables or herbs (from small plants or seeds). This requirement is fulfilled if you earn the Gardening Merit Badge. Fall: Plant some bulbs in indoor pots. These bulbs will not bloom until winter. Compare growing bulbs in indoor pots to planting bulbs outdoors in the fall to bloom in the spring.');
INSERT INTO badge_optional_requirements VALUES(7682,603,15,'Earn a Merit Badge focusing on the season you chose as a theme. Some examples include: Astronomy, Collecting, Gardening, Cooking, Flower Gardening, Holidays (Specific).');
INSERT INTO badge_optional_requirements VALUES(7683,603,16,'Make something typically eaten during the season you chose. Serve it to your family, friends, or group. Why is this dish/recipe/meal typically eaten during this season? Levels 1-2: make one dish. Level 3: make two dishes. Levels 4-5: make an entire meal');
INSERT INTO badge_optional_requirements VALUES(7684,603,17,'Research stories from ancient times that tried to explain the change in seasons. Make up a myth of your own explaining why the seasons change, and focus on creating a story explaining  what happens during the season you chose. Share your story');
INSERT INTO badge_optional_requirements VALUES(7685,603,18,'Discuss with your family what projects are done to take care of your home during the season you chose. Do at least two of these projects during that season. Some ideas include: Winter: Make a plan to protect pipes from freezing or help shop for items to keep on hand in case of a winter storm. Spring: Help with a spring cleanup project (inside or outside the house) or plant flowers or vegetables. Summer: Help care for a garden and harvest any fruits/vegetables or help take care of the lawn or family pool. Fall: Help care for the yard (raking leaves, planting bulbs, clearing up dead plants from the summer, etc.) or help your family winterize the house (covering air conditioning or heating units, putting summer furniture away, etc.).');
INSERT INTO badge_optional_requirements VALUES(7686,605,3,'Have you ever heard the expression, “Sticks and stones can break my bones, but words will never hurt me?” The truth is, words can hurt; sometimes even more than physical pain. Learning to control what you say and how you say it is just as important as controlling your actions. Get two jars and label one “Kept Control” and the other “Lost Control.” Place a bowl of marbles (or paper clips, jelly beans, or any other small item) next to the two jars. For the next week, pay attention to what you say. Every time you get angry or irritated and you keep control of your tongue, place a marble in the Kept Control jar. Every time you lose control and say an unkind word, or use a disrespectful tone, place a marble in the Lost Control jar. At the end of the week, discuss with a parent or guardian your results. How difficult was it to keep control of what you said? Did things slip out before you could stop them? Did you hurt anyone on accident when they took something you said the wrong way because of your tone? What did you learn from this about keeping control of your words?');
INSERT INTO badge_optional_requirements VALUES(7687,605,4,'Bullying has become a huge problem in many schools and communities and especially online. Bullying can be classified as any ongoing physical or verbal mistreatment. Bullies show no self control. Look for examples of bullying in your books and TV shows.  Have you ever bullied someone?  Discuss with a parent or other adult what to do if you are ever bullied by someone else or see someone else being bullied.');
INSERT INTO badge_optional_requirements VALUES(7688,605,5,'Write an essay about self control, why it is important, and how you plan to implement it in your life.');
INSERT INTO badge_optional_requirements VALUES(7689,605,6,'Do silly exercises to strengthen your self-control like not scratching, not blinking, or sitting extremely still for a long period of time. How difficult was it? Is it easier if you set a time limit and know that you have a deadline?');
INSERT INTO badge_optional_requirements VALUES(7690,605,7,'Have you ever noticed that many people do things they know are wrong simply because others around them are doing it? Self control is much easier when the friends you choose to associate with are those that will hold you accountable to proper behavior. Think about the friends that you have. Do they challenge you to be the best you can be and love you unconditionally? Or do they encourage you to behave in a way that you know is wrong, but you are afraid of their disapproval? Self control means standing up for yourself and for what you know is right, even if it means that your friends might not like it. The next time your friends want you to do or say something that you know you shouldn’t, stand firm and refuse. Think long and hard about the type of friends that they are and decide if they are truly worth having.');
INSERT INTO badge_optional_requirements VALUES(7691,605,8,'Anger can serve as a signal that something is wrong, and the best way to control anger is to find what caused you to feel angry in the first place and resolve it. If you continue to justify your anger, or blame it on others, you will not be able to overcome it. When you are angry, practice taking time to count to ten and take a deep breath before you say or do anything. Do not slam things or throw them, and think before you speak. Remember how insults and mean actions affect you and make sure that you avoid causing others the same pain. In many cases, the problem that caused your anger may have something to do with your own actions. Be honest with yourself about your role in the problem and find ways to change how you behave in the future. If you are at fault, ask forgiveness of those you have offended. If others are at fault, try to understand where they are coming from and be tolerant of their position. Every time something makes you angry, take the time to calm down enough to take control of your response before you speak or act.');
INSERT INTO badge_optional_requirements VALUES(7692,605,9,'Many things in life are not inherently bad, but can become so if done to excess. For example, we all need food to survive, but overeating can lead to obesity. Over sleeping, over working, and over spending are all examples of good things gone bad by losing self control. Brainstorm a list of problems that might result from a lack of self-control: How do they affect personal appearance, physical-mental-emotional health, school success, life success, friendships, job performance, talents, participation in family-clubs-community-faith, marriage, or parenting? Look at your own life and find a place where too much of a good thing has started to cause problems for you. Maybe you love to snack on cookies and potato chips in the afternoon and it is starting to affect your health; maybe you like to stay up late every night and you are not getting enough sleep, or maybe you love to buy things and you find that you are always broke. Now make a plan to get your excess under control. If snacking is your problem, make sure there are plenty of healthy snacks in the kitchen prepared and ready to eat. Make a conscious decision to control yourself and not reach for the cookies, but grab some carrot sticks instead. If spending is your problem, have your parents help you set up a savings account. Whenever you receive money, make a commitment to putting ½ of it into savings, leaving you free to spend the other half as you wish without guilt.');
INSERT INTO badge_optional_requirements VALUES(7693,605,10,'Procrastination is something that everyone fights from time to time. Whether it is chores, homework, or some other task that you do not wish to do, putting it off will only provide more stress later on. Having the self control to do unwanted tasks quickly will actually make your life easier and more enjoyable. For the next week, make an effort to complete all necessary tasks as quickly as possible. Take note of how much free time you end up with and how much more relaxing it is without undone chores hanging over your head.');
INSERT INTO badge_optional_requirements VALUES(7694,605,11,'Write or tell a chain story about a make-believe prince or princess who has no self-discipline.');
INSERT INTO badge_optional_requirements VALUES(7695,605,12,'Interview people with careers that require self control such as doctors, scientists, and engineers. How does self control help their work?');
INSERT INTO badge_optional_requirements VALUES(7696,606,3,'Take a professional self-defense class.');
INSERT INTO badge_optional_requirements VALUES(7697,606,4,'How do the police investigate abductions? If possible, visit a police station or have a police officer come speak to your troop. Level 3 and Up: also learn what role private investigators can play. What kind of training and education would you need to become either a police officer who investigates abductions, or a private investigator?');
INSERT INTO badge_optional_requirements VALUES(7698,606,5,'Preschool-Level 2:  Complete a coloring or activity sheet about safety.');
INSERT INTO badge_optional_requirements VALUES(7699,606,6,'In some countries, criminals will abduct vacationers and hold them for ransom, and terrorists will hold people hostage. Learn which countries are most dangerous in this regard. If you are going to a foreign country, learn how to ask for help in that country’s dominant language. Otherwise, learn how to ask for help in another common language in your area. Level 3 and Up: How would you contact your embassy from a foreign country?');
INSERT INTO badge_optional_requirements VALUES(7700,606,7,'Preschool-Level 2: Sometimes, kidnappers will pretend that they’ve been sent by your parents or guardians to come get you, when really that isn’t true. Come up with a family code word for your parents to tell any grown-ups who they send to pick you up. If someone can’t give you the code word, don’t go with them. Make sure you choose something unique, and something that wouldn’t be easy to guess, like “dancing pink flamingos” or “grape tacos.”');
INSERT INTO badge_optional_requirements VALUES(7701,606,8,'If someone gets kidnapped, it’s very important that they stay calm so they can think well enough to plan an escape or way to get help. Learn some ways to calm down quickly. Try counting down from 100, reciting the alphabet backwards, breathing deeply, listing all the colors you see in a room, imagining a flower blooming, or tensing all the muscles in your body and then progressively relaxing them from your tiptoes to your face.');
INSERT INTO badge_optional_requirements VALUES(7702,606,9,'Learn how to escape if your hands were bound with duct tape or with plastic zip ties. If your hands are being bound with zip ties, what should you do to make sure the kidnappers bind your hands as loosely as possible?');
INSERT INTO badge_optional_requirements VALUES(7703,606,10,'Learn at least one method to escape from the trunk of a car. Level 4 and Up: Learn two methods. If you can’t escape, learn how to pull out the tail light’s wires – that increases the chances of the police pulling the car over. What are other ways of attracting attention when trapped in a trunk?');
INSERT INTO badge_optional_requirements VALUES(7704,606,11,'What is stalking? Who should someone tell if they are being stalked? When should they make a police report? Why is it important not to respond directly to a stalker?');
INSERT INTO badge_optional_requirements VALUES(7705,606,12,'If you cannot escape from your home during a home invasion, how should you prepare for the intruders’ entry? Why should you turn off your home’s power—or at least shut off the lights—during a home invasion?');
INSERT INTO badge_optional_requirements VALUES(7706,606,13,'How are missing people found? What non-profit organizations help to search for them? Do a service project for a group that helps find missing people, or volunteer or fund-raise to help search for a missing person.');
INSERT INTO badge_optional_requirements VALUES(7707,606,14,'Learn the rules of safety in parking garages and lots. It’s especially important to be cautious in them—they’re often sparsely populated, they tend to be poorly lit, and people in them are often distracted, making them a prime target for predators.');
INSERT INTO badge_optional_requirements VALUES(7708,606,15,'Preschool – Level 2: Learn about good and bad secrets. How can you know whether a secret is okay to keep? If you have a secret that’s making you feel worried or uncomfortable, who are some adults you can trust to talk to about it?');
INSERT INTO badge_optional_requirements VALUES(7709,606,16,'Learn the rules of personal safety online. Why is it important to be safe on the internet? What are cyberbullying and doxxing?');
INSERT INTO badge_optional_requirements VALUES(7710,606,17,'Learn about the myths and facts of human trafficking. Some people think that human trafficking only happens far away in other countries, or only happens when people are kidnapped to different countries, or that no one you know could ever be a human trafficking victim. All of that is false. Learn what the warnings signs are that someone could be a human trafficking victim, and learn what the warning signs are for someone trying to lure you into human trafficking.');
INSERT INTO badge_optional_requirements VALUES(7711,606,18,'Learn about self-defense products, such as pepper spray and stun guns. Some products are made especially for women, such as pepper spray disguised to look like a container of lipstick. Where can they be bought, and how much do they cost? Also learn what kind of personal safety apps are available, such as SafeTrek.');
INSERT INTO badge_optional_requirements VALUES(7712,606,19,'Read an age-appropriate book or watch an age-appropriate documentary about safety.');
INSERT INTO badge_optional_requirements VALUES(7713,607,3,'Invite a senior citizen to help your group earn a badge by sharing their knowledge or special skill.');
INSERT INTO badge_optional_requirements VALUES(7714,607,4,'Find out if your community has an Adopt-A-Grandparent program.  If they do, adopt a grandparent.  If they don’t, contact a local nursing home or senior center to see if they would be interested in starting such a program.');
INSERT INTO badge_optional_requirements VALUES(7715,607,5,'Find out what local agencies and organizations are available in your area to assist seniors.  Put together a simple flyer or booklet with the  resources you find and give them to your local senior center. Ideas might include senior transportation, meals on wheels, landscapers, house cleaners, places that offer senior discounts, senior clubs or activities, etc.');
INSERT INTO badge_optional_requirements VALUES(7716,607,6,'Participate in a community service project that serves seniors.');
INSERT INTO badge_optional_requirements VALUES(7717,607,7,'Visit a nursing home and participate in an activity such as games, a sing-a-long, or crafts.');
INSERT INTO badge_optional_requirements VALUES(7718,607,8,'Visit a nursing home and perform for the residents.  This might be a selection of songs, dances, tall flag routines, or even a play.');
INSERT INTO badge_optional_requirements VALUES(7719,607,9,'How are senior citizens portrayed in the media?  Find both positive and negative examples. Discuss the accuracy of how they are portrayed.');
INSERT INTO badge_optional_requirements VALUES(7720,607,10,'Make crafts such as warm fuzzies or a wall banner to give to a nursing home or senior center.');
INSERT INTO badge_optional_requirements VALUES(7721,607,11,'Learn about someone 65 or older who is still in the work force in some way.  Have they always been in this career or did they change careers at some point?  If so, why?  Find out what this person considers a successful and happy life.');
INSERT INTO badge_optional_requirements VALUES(7722,607,12,'Learn about a person who made a significant contribution to our world in their senior years.  This might  be a great artist, a U.S. President, or a philanthropist.  Discuss why you think they were able to make such a difference at such an advanced age.');
INSERT INTO badge_optional_requirements VALUES(7723,607,13,'Earn the Grandparents badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(7724,607,14,'Read a book or watch a movie where the main character(s) are senior citizens.');
INSERT INTO badge_optional_requirements VALUES(7725,607,15,'Learn about careers involving senior citizens.  Examples might include a doctor, nursing home assistant, senior center manager, assisted living manager, etc.  What type of education would you need? What type of salary could you expect?');
INSERT INTO badge_optional_requirements VALUES(7726,609,3,'Learn to sew on a button. Level 2 and Up: Learn to sew on a snap, a hook and eye closure, and a zipper.  If you did this requirement at a lower level, choose a new requirement.');
INSERT INTO badge_optional_requirements VALUES(7727,609,4,'Learn at least 3 different embroidery stitches and use them to embellish something.  If you’re repeating this badge at a higher level, you must learn 3 new stitches.');
INSERT INTO badge_optional_requirements VALUES(7728,609,5,'Sew something for you to wear.');
INSERT INTO badge_optional_requirements VALUES(7729,609,6,'Levels 1-2: Use a sewing machine to make a small pillow, bean bag, sachet, stuffed toy, tote bag, draw-string bag, vest, apron, etc.');
INSERT INTO badge_optional_requirements VALUES(7730,609,7,'Learn how to measure for and make a window valance or curtain.');
INSERT INTO badge_optional_requirements VALUES(7731,609,8,'Sew something you can use for home decor such as a decorative pillow for your bed, chair covers, or a bed skirt.');
INSERT INTO badge_optional_requirements VALUES(7732,609,9,'Learn how to sew from a pattern. Choose a pattern and make something for yourself to wear.');
INSERT INTO badge_optional_requirements VALUES(7733,609,10,'With adult supervision, learn how to use an iron. Discuss what are appropriate temperatures for certain fabrics. Press five simple things such as a handkerchief, a tea towel, a pillowcase, etc. Why is learning to iron important in sewing?');
INSERT INTO badge_optional_requirements VALUES(7734,609,11,'Sew something using recycled material. You might choose to make a purse out of an old pair of jeans, or a skirt out of discarded neckties. Be creative!');
INSERT INTO badge_optional_requirements VALUES(7735,609,12,'Using pattern stitches available on your sewing machine and colored thread, embellish something you own.');
INSERT INTO badge_optional_requirements VALUES(7736,609,13,'Help sew useful items such as lap robes, quilts, winter garments, etc. for a charity. If you can’t sew well enough to actually make your chosen project, spend a couple hours serving drinks to the workers or pressing seams & threading needles at a charitable sewing bee or something similar.');
INSERT INTO badge_optional_requirements VALUES(7737,609,14,'Learn to adjust or combine patterns. Take a collar, sleeve or skirt from one pattern and put it together with another pattern or use a pattern that needs to be enlarged or taken in to fit the person for whom you are sewing. Be sure to get experienced help if needed, rather than make a mistake that wastes fabric.');
INSERT INTO badge_optional_requirements VALUES(7738,609,15,'Learn to embellish or change the design of a garment while still following the basic pattern such as adding trims not suggested by the pattern, changing fabric, or adding a lace or voile overlay.');
INSERT INTO badge_optional_requirements VALUES(7739,609,16,'Identify and learn to use frog closures, blanket binding, lace Velcro, and hardware for purses and belts.');
INSERT INTO badge_optional_requirements VALUES(7740,609,17,'Learn to identify various types of fabric by design, weave, or fiber content.');
INSERT INTO badge_optional_requirements VALUES(7741,611,3,'Find out what international versions of Shark Tank are still airing as well as any spin offs that were made.');
INSERT INTO badge_optional_requirements VALUES(7742,611,4,'Find out the statistics on how many “deals” actually go through the way you see them on TV. What percentage fail completely off air? How many get a deal, but maybe not the exact one that was aired?');
INSERT INTO badge_optional_requirements VALUES(7743,611,5,'Understand “The Shark Tank Effect” and why it occurs. What is meant by the term “Gold Digger” in regards to show contestants?');
INSERT INTO badge_optional_requirements VALUES(7744,611,6,'In order to appear on Shark Tank, you can’t be afraid of public speaking. Create something or choose something from around your house and pretend you just invented it. Then “pitch” it to a panel of Shark judges made up of family and friends. Did they think it was a good idea? Did they suggest improvements or changes? Did they offer you a deal?');
INSERT INTO badge_optional_requirements VALUES(7745,611,7,'Design a new product or business that you think the world needs. Then write up a brief business plan. How you would advertise and market it? How much would you sell it for? How would you make it? Would you need a factory?');
INSERT INTO badge_optional_requirements VALUES(7746,611,8,'One part of a successful product is packaging. Create a new package for something you have around the house. For example a cereal box. How would you redesign the front and back to make it more appealing?');
INSERT INTO badge_optional_requirements VALUES(7747,611,9,'Find out who some of the guest Sharks have been and watch one of their episodes if possible. Why do you think they were chosen to be a guest?');
INSERT INTO badge_optional_requirements VALUES(7748,611,10,'Research at least 5 different products that got deals on Shark Tank and find out how they are doing today.');
INSERT INTO badge_optional_requirements VALUES(7749,611,11,'Find out how many awards Shark Tank has been nominated for and how many they have won.');
INSERT INTO badge_optional_requirements VALUES(7750,611,12,'Role play an episode of Shark Tank with some family or friends. Have each person design a product and create a “pitch” including a display and logo for your item. Then take turns being the contestant and the judges. Give each person a set amount of pretend money to spend on investing in products and businesses that they can split any way they wish. Whoever ends up with the most money invested in their product got the best “deal”.');
INSERT INTO badge_optional_requirements VALUES(7751,611,13,'Find out what the most successful Shark Tank product or business has been. Who did they make a deal with and for what?');
INSERT INTO badge_optional_requirements VALUES(7752,611,14,'Find out what the application process for the show is and read up on tips and suggestions for those who try out.');
INSERT INTO badge_optional_requirements VALUES(7753,611,15,'Watch an episode of Shark Tank with a “kid-preneur” making a pitch.');
INSERT INTO badge_optional_requirements VALUES(7754,611,16,'Watch at least 6 episodes of Shark Tank. Map each investor’s investing style based on what they invest in. How many total dollars has each invested in total? What types of businesses does each investor like to buy? What types do they opt of and for what reasons?');
INSERT INTO badge_optional_requirements VALUES(7755,612,3,'Research the history of art as a tool for advocacy and awareness.');
INSERT INTO badge_optional_requirements VALUES(7756,612,4,'Understand the significance of seashells as symbols in the project.  Discuss how finding a painted seashell would make you feel.');
INSERT INTO badge_optional_requirements VALUES(7757,612,5,'Learn about the importance of proper shell selection for painting.  How can you ethically source shells without damage to the environment?');
INSERT INTO badge_optional_requirements VALUES(7758,612,6,'Learn about what type of paints work best on painted shells and how to seal them.');
INSERT INTO badge_optional_requirements VALUES(7759,612,7,'Learn about environmentally-friendly paints and coatings to use on your shells.');
INSERT INTO badge_optional_requirements VALUES(7760,612,8,'Find a painted shell and post it to the Shells for Stacey Facebook group (with a parent’s permission)');
INSERT INTO badge_optional_requirements VALUES(7761,612,9,'Learn proper safety measures when handling painting materials and sealer.');
INSERT INTO badge_optional_requirements VALUES(7762,612,10,'Come up with 3 creative ways to draw attention to the shells once hidden.');
INSERT INTO badge_optional_requirements VALUES(7763,612,11,'Organize a community service project where people can paint shells and hide them.');
INSERT INTO badge_optional_requirements VALUES(7764,612,12,'Study examples of other awareness-raising art projects.');
INSERT INTO badge_optional_requirements VALUES(7765,612,13,'Learn about current research on treatments and therapies for Alzheimer’s.');
INSERT INTO badge_optional_requirements VALUES(7766,612,14,'Identify the symptoms and progression of Alzheimer’s disease.');
INSERT INTO badge_optional_requirements VALUES(7767,612,15,'Hold a treasure hunt where you hide painted seashells and provide a map for others to find them.');
INSERT INTO badge_optional_requirements VALUES(7768,612,16,'Engage in a public speaking opportunity to promote the Shells for Stacey project.');
INSERT INTO badge_optional_requirements VALUES(7769,612,17,'Create a video PSA about the Shells for Stacey project.');
INSERT INTO badge_optional_requirements VALUES(7770,612,18,'Create an informational flyers or pamphlets to educate people on the Shells for Stacey project and how to partcipate.');
INSERT INTO badge_optional_requirements VALUES(7771,614,3,'Watch another of Shirley Temple’s movies.');
INSERT INTO badge_optional_requirements VALUES(7772,614,4,'Read a biography of Shirley Temple or her own autobiography.');
INSERT INTO badge_optional_requirements VALUES(7773,614,5,'Learn about Shirley’s signature hairstyle. Why was it significant?');
INSERT INTO badge_optional_requirements VALUES(7774,614,6,'Learn about her political campaign in 1967.');
INSERT INTO badge_optional_requirements VALUES(7775,614,7,'Learn about her work as an ambassador to Ghana and Czechoslovakia.');
INSERT INTO badge_optional_requirements VALUES(7776,614,8,'Learn about her work in politics serving President Carter.');
INSERT INTO badge_optional_requirements VALUES(7777,614,9,'Earn the Performance, Singing, or Dance badge, using some of Shirley’s songs or dances.');
INSERT INTO badge_optional_requirements VALUES(7778,614,10,'Learn about her battle with breast cancer, and why her public announcement about it was so important.');
INSERT INTO badge_optional_requirements VALUES(7779,614,11,'Learn about the awards and honors she received during her many careers. Study one in depth.');
INSERT INTO badge_optional_requirements VALUES(7780,615,3,'Take a field trip to a cobbler shoppe either in person or online(with a parent’s permission) to learn how shoes are made and repaired.  Discuss why cobblers are now difficult to find and why most people do not bother to have their shoes repaired anymore.');
INSERT INTO badge_optional_requirements VALUES(7781,615,4,'Take a field trip to a shoe store.  Discuss the different styles available and the price differences between them.');
INSERT INTO badge_optional_requirements VALUES(7782,615,5,'Research a career that has to do with shoes such as a cobbler, shoe designer, shoe salesman, etc.  What type of education or training is necessary for this job?  What type of hours would you usually work?  Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(7783,615,6,'Design your own pair of shoes.');
INSERT INTO badge_optional_requirements VALUES(7784,615,7,'Make a pair of shoes or slippers you can wear.');
INSERT INTO badge_optional_requirements VALUES(7785,615,8,'Participate in a community service project that involves shoes such a shoe drive or a walk-a-thon.');
INSERT INTO badge_optional_requirements VALUES(7786,615,9,'Try on at least 10 different styles of shoes.  Which are the most comfortable?  Which are the least?  Are some hard to walk in?');
INSERT INTO badge_optional_requirements VALUES(7787,615,10,'Learn how to properly measure someone’s shoe size.');
INSERT INTO badge_optional_requirements VALUES(7788,615,11,'Learn why people in certain places of the world or in certain occupations wear special shoes (e.g. a cowboy wearing boots) and how their shoes help them. Choose at least three different examples to research and create a poster showing your findings.');
INSERT INTO badge_optional_requirements VALUES(7789,615,12,'Learn about the different materials used to make shoes today, and create a poster illustrating your findings. Choose at least five different kinds of shoes to research.');
INSERT INTO badge_optional_requirements VALUES(7790,615,13,'Learn about customs concerning shoes in different countries around the world. In what ways are these customs similar to and different from the accepted practices in the United States?');
INSERT INTO badge_optional_requirements VALUES(7791,615,14,'Learn about shoes that have special qualities such as the ability to light up or Heelys wheel shoes. Who first came up with the design, and how are they made? What kinds of things can you do with these shoes?');
INSERT INTO badge_optional_requirements VALUES(7792,616,3,'Help plan and put on a fundraiser for a short flags team.');
INSERT INTO badge_optional_requirements VALUES(7793,616,4,'Be part of a short flag team for at least three months and participate in a parade or performance.');
INSERT INTO badge_optional_requirements VALUES(7794,616,5,'Learn what some good warm-ups and stretches might be before a practice.  Is there a time of day they might be more important?');
INSERT INTO badge_optional_requirements VALUES(7795,616,6,'What are the modesty and practicality issues a team should consider when choosing their performance outfits?  What about price and durability?');
INSERT INTO badge_optional_requirements VALUES(7796,616,7,'If you do not have a band to play for you, do some research equipment for playing the music for your team.  Compare the costs as well as the performance and mobility of various listening devices.');
INSERT INTO badge_optional_requirements VALUES(7797,616,8,'Choreograph a routine for a short flag team.');
INSERT INTO badge_optional_requirements VALUES(7798,616,9,'Teach a new trick, technique, or part of a workshop to younger kids.');
INSERT INTO badge_optional_requirements VALUES(7799,616,10,'Help sew some flags or performance outfits for a short flag team.');
INSERT INTO badge_optional_requirements VALUES(7800,616,11,'What material are the flag poles made of?  Why?  What is the price range?  What fabric is used in making the flags?  Why?');
INSERT INTO badge_optional_requirements VALUES(7801,617,3,'Which other country’s sign language system is most like America’s? Learn the history behind why American Sign Language patterned itself after this nation’s. In your research, be sure to learn who Thomas Hopkins Gallaudet, Alice Cogswell, and Laurent Clerc were and what role they played in ASL’s history.');
INSERT INTO badge_optional_requirements VALUES(7802,617,4,'Learn the difference between deaf and Deaf. What does hard-of-hearing mean? Can a person be both hard-of-hearing and Deaf at the same time?');
INSERT INTO badge_optional_requirements VALUES(7803,617,5,'Learn to sign a popular joke from Deaf culture. How is it different than jokes that are popular among hearing people?');
INSERT INTO badge_optional_requirements VALUES(7804,617,6,'Watch a video of someone signing a story while an interpreter voices the story. Watch it again without the volume. Can you follow the story by watching the signs?');
INSERT INTO badge_optional_requirements VALUES(7805,617,7,'Learn to sign two simple, repetitive single-verse songs, such as “Oh, How I Love Jesus,” or “Happy Birthday,” or learn one simple, non-repetitive single verse song, such as “Jesus Loves Me,” or “Twinkle, Twinkle, Little Star.” Be sure you are using the real ASL signs and not the popular hand motions for these songs.');
INSERT INTO badge_optional_requirements VALUES(7806,617,8,'Learn about name signs. Why is it not appropriate to assign your own name sign? Why is it significant when a Deaf person “gives” you a name sign? Does a person’s name sign stay the same for life, or might it change? Why?');
INSERT INTO badge_optional_requirements VALUES(7807,617,9,'Sign language is not universal. Learn how to fingerspell your name using other countries’ manual alphabet systems. Preschool-Level 1: Learn your name in 1 other alphabet system. Levels 2-3: Learn 2 systems. Levels 4-5: Learn 3 systems.');
INSERT INTO badge_optional_requirements VALUES(7808,617,10,'What are classifiers in sign language? Learn how to properly use 5 of them. Try to find and watch an example of an ASL “classifier story.”  One good example of classifier stories is “The Ball.”');
INSERT INTO badge_optional_requirements VALUES(7809,617,11,'Learn to sign either an alphabet story or a number story. What is special about these types of stories? Perform your story for your family, friends, or group, and be sure you can explain what your story means.');
INSERT INTO badge_optional_requirements VALUES(7810,617,12,'Collect 3 poems from Deaf culture. Look for performances of these works if possible.');
INSERT INTO badge_optional_requirements VALUES(7811,617,13,'Learn the suspected link between sign language and the Lincoln Memorial monument in Washington DC. Do you think this is true based off of the monument’s history?');
INSERT INTO badge_optional_requirements VALUES(7812,617,14,'Research Gallaudet University, and include in your research where it is, when it was founded, and what is unique about this school. If possible, arrange to visit the campus or obtain an informational brochure from the university.');
INSERT INTO badge_optional_requirements VALUES(7813,617,15,'Learn the Pledge of Allegiance and the Star Spangled Banner in ASL. Think about what each line means when choosing the signs. (Remember, ASL interpreting is not about signing word-for-word, but conveying the appropriate ideas with signs, so there is more than one proper way to interpret these pieces.) Many different beautiful interpretations can be found online. Be sure the interpretations you choose support your understanding of what these works mean. Perform these for your group during a formal flag ceremony.');
INSERT INTO badge_optional_requirements VALUES(7814,617,16,'Learn about five deaf people who changed the world. Who are/were they? What are they know for? Where are they from?');
INSERT INTO badge_optional_requirements VALUES(7815,617,17,'See if there is an upcoming sign language theater performance in your area. Arrange to attend the show. Several colleges and universities have ASL or Deaf Clubs that perform annual variety shows.');
INSERT INTO badge_optional_requirements VALUES(7816,617,18,'Deaf athletes have shaped the look of sports over history. Research some of their contributions including umpire/referee hand signals and football huddles.');
INSERT INTO badge_optional_requirements VALUES(7817,617,19,'Contact a local Deaf Community club and ask permission to attend one of their meetings. Arrange for a signing friend or interpreter to come with you if you are unsure of your ability to communicate.');
INSERT INTO badge_optional_requirements VALUES(7818,617,20,'Many people consider musical works performed in sign language a beautiful form of art. Learn to sign a hymn or popular song with at least 3 verses. Perform this interpretation for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(7819,618,3,'Find 3 different types of levers in your home or community (e.g., seesaw, crowbar) and explain how they work.');
INSERT INTO badge_optional_requirements VALUES(7820,618,4,'Build a simple pulley system to lift a small object, such as a toy or book.');
INSERT INTO badge_optional_requirements VALUES(7821,618,5,'Use an inclined plane to roll or slide an object and explain how it makes the task easier.');
INSERT INTO badge_optional_requirements VALUES(7822,618,6,'Use a wedge (like a doorstop, crowbar or axe) and demonstrate how it can split or hold objects apart.');
INSERT INTO badge_optional_requirements VALUES(7823,618,7,'Create one of the six basic simple machines using household materials and test its effectiveness.');
INSERT INTO badge_optional_requirements VALUES(7824,618,8,'Explain how simple machines help transfer force and reduce the amount of effort needed to do work.');
INSERT INTO badge_optional_requirements VALUES(7825,618,9,'Explain the relationship between the length of a lever and the amount of force needed to lift an object.');
INSERT INTO badge_optional_requirements VALUES(7826,618,10,'Explain the relationship between the height and length of an inclined plane and the amount of force needed to move an object.');
INSERT INTO badge_optional_requirements VALUES(7827,618,11,'Explain the relationship between the number of pulleys used in a pulley system and the amount of force needed to lift an object.');
INSERT INTO badge_optional_requirements VALUES(7828,618,12,'Create a Rube Goldberg machine that uses at least three simple machines to complete a task.');
INSERT INTO badge_optional_requirements VALUES(7829,618,13,'Go on a scavenger hunt to find as many examples of all six types of simple machines in everyday life that you can.  Play in teams and see who can find the most.');
INSERT INTO badge_optional_requirements VALUES(7830,618,14,'Identify the simple machines involved in at least 3 common tools like scissors, a stapler, or a wrench.');
INSERT INTO badge_optional_requirements VALUES(7831,618,15,'Research the history of the wheel and its impact on human society.');
INSERT INTO badge_optional_requirements VALUES(7832,618,16,'Explore different surfaces (e.g., sandpaper, smooth wood) on an inclined plane. Document how surface texture affects movement.');
INSERT INTO badge_optional_requirements VALUES(7833,618,17,'Construct a simple lever using a ruler and a small object like a toy. Experiment by placing the fulcrum in different positions and observe how it affects the effort needed to lift the object.');
INSERT INTO badge_optional_requirements VALUES(7834,618,18,'Use a screw (or a simple threaded bolt) to lift an object or hold materials together. Explain why screws are more effective than nails for certain jobs.');
INSERT INTO badge_optional_requirements VALUES(7835,618,19,'Explain why a gear is complex machine and not a simple machine.');
INSERT INTO badge_optional_requirements VALUES(7836,619,3,'Learn a song from another country.');
INSERT INTO badge_optional_requirements VALUES(7837,619,4,'Learn the history behind an American folk song.');
INSERT INTO badge_optional_requirements VALUES(7838,619,5,'Perform a song for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(7839,619,6,'Write your own song and sing it for a family member, friend, or your group.');
INSERT INTO badge_optional_requirements VALUES(7840,619,7,'Discuss good musical manners when attending different types of concerts, and when listening to music at home.');
INSERT INTO badge_optional_requirements VALUES(7841,619,8,'Research the background of a song you learned and tell some interesting facts to your family, friends, and group.');
INSERT INTO badge_optional_requirements VALUES(7842,619,9,'Music and singing have always been used in the worship of God.  Choose your favorite spiritual song and find out about its history.  Who was the author?  Why did they write it?  What does the song say to you?');
INSERT INTO badge_optional_requirements VALUES(7843,619,10,'Plan to attend a concert and learn at least 3 of the songs to be sung before you go.  After the concert, write a short review for your friends.');
INSERT INTO badge_optional_requirements VALUES(7844,619,11,'Listen to a piece of opera, and attend one if possible.   How does opera differ from what you are used to listening to?  Learn a short piece from an opera.');
INSERT INTO badge_optional_requirements VALUES(7845,619,12,'Find out how folk songs originate and some of their general characteristics.  Learn 6 folk songs from at least 3 countries.');
INSERT INTO badge_optional_requirements VALUES(7846,619,13,'Research the Underground Railroad and how songs were used by slaves to convey covert information.  Learn at least 3 of these songs, and their meanings.');
INSERT INTO badge_optional_requirements VALUES(7847,619,14,'Arrange a karaoke party for your friends or group.');
INSERT INTO badge_optional_requirements VALUES(7848,619,15,'Teach at least 3 songs to a group of young children.');
INSERT INTO badge_optional_requirements VALUES(7849,619,16,'Computers are now a part of the world of music.  Visit a music store and find out what software is available to song writers.   Write your own song and if possible, use a computer program to help notate the music.');
INSERT INTO badge_optional_requirements VALUES(7850,619,17,'Learn about the minnesingers in Germany, the troubadours in southern France, or the early minstrels in England.  Learn a song or two of the kind that they might have sung.');
INSERT INTO badge_optional_requirements VALUES(7851,619,18,'Choose a songwriter and read their biography. Write a short report on their life, and learn at least 3 of their songs.');
INSERT INTO badge_optional_requirements VALUES(7852,620,3,'Why do people snore?');
INSERT INTO badge_optional_requirements VALUES(7853,620,4,'What causes sleepwalking?');
INSERT INTO badge_optional_requirements VALUES(7854,620,5,'What are the benefits or disadvantages of napping?');
INSERT INTO badge_optional_requirements VALUES(7855,620,6,'Is it bad to eat right before sleeping?');
INSERT INTO badge_optional_requirements VALUES(7856,620,7,'Have a sleepover!');
INSERT INTO badge_optional_requirements VALUES(7857,620,8,'Learn how to properly make a bed.');
INSERT INTO badge_optional_requirements VALUES(7858,620,9,'Learn about the different time zones and how they affect sleep.');
INSERT INTO badge_optional_requirements VALUES(7859,620,10,'What are some environmental changes that you can make to help you sleep?');
INSERT INTO badge_optional_requirements VALUES(7860,620,11,'How does sleep affect your immune system?');
INSERT INTO badge_optional_requirements VALUES(7861,620,12,'Learn how long naps should be. How do you feel if you take a fifteen minute nap? Twenty? Thirty? An hour?');
INSERT INTO badge_optional_requirements VALUES(7862,620,13,'Learn about circadian rhythm.');
INSERT INTO badge_optional_requirements VALUES(7863,620,14,'Learn about the difference between morning people and night owls.');
INSERT INTO badge_optional_requirements VALUES(7864,620,15,'Learn about how other cultures sleep such as the tradition of taking a siesta.');
INSERT INTO badge_optional_requirements VALUES(7865,620,16,'Learn about different bed styles throughout history and in different areas of the world.');
INSERT INTO badge_optional_requirements VALUES(7866,620,17,'Participate in a community service project that has something to do with sleep such as a stuffed animal drive for children in a hospital.');
INSERT INTO badge_optional_requirements VALUES(7867,620,18,'Learn about a career that has something to do with sleep such as a doctor or mattress manufacturer.  What kind of education would you need?  How much would you be paid? What type of hours might you expect?');
INSERT INTO badge_optional_requirements VALUES(7868,620,19,'Take a field trip to a sleep center');
INSERT INTO badge_optional_requirements VALUES(7869,620,20,'Take a field trip to a mattress store and learn about different types of mattresses.');
INSERT INTO badge_optional_requirements VALUES(7870,620,21,'Learn the history of pillows and mattresses.');
INSERT INTO badge_optional_requirements VALUES(7871,621,3,'Watch a YouTube video (with a parent’s permission) about making slime.');
INSERT INTO badge_optional_requirements VALUES(7872,621,4,'Earn the Fun with Science badge at your level.');
INSERT INTO badge_optional_requirements VALUES(7873,621,5,'Earn the Chemistry badge and understand the chemistry behind slime.');
INSERT INTO badge_optional_requirements VALUES(7874,621,6,'Write an original slime recipe.');
INSERT INTO badge_optional_requirements VALUES(7875,621,7,'Host a slime party.');
INSERT INTO badge_optional_requirements VALUES(7876,621,8,'Make a list of items you can add-in to a basic slime recipe.');
INSERT INTO badge_optional_requirements VALUES(7877,621,9,'Experiment with different kinds of glues in slime recipes.');
INSERT INTO badge_optional_requirements VALUES(7878,621,10,'Make glow-in-the-dark slime.');
INSERT INTO badge_optional_requirements VALUES(7879,621,11,'Make your own slime video.');
INSERT INTO badge_optional_requirements VALUES(7880,621,12,'Try using essential oils to make scented slime.');
INSERT INTO badge_optional_requirements VALUES(7881,621,13,'Make a slideshow or poster about slime to share and teach others about slime.');
INSERT INTO badge_optional_requirements VALUES(7882,621,14,'What are some careers that involve slime or the science behind it?');
INSERT INTO badge_optional_requirements VALUES(7883,621,15,'Look up slime conventions. Are there any near you?  Who hosts them?');
INSERT INTO badge_optional_requirements VALUES(7884,621,16,'Go to a slime convention.');
INSERT INTO badge_optional_requirements VALUES(7885,621,17,'Host a slime workshop.');
INSERT INTO badge_optional_requirements VALUES(7886,622,3,'Know your local and state laws for owning and using slingshots.');
INSERT INTO badge_optional_requirements VALUES(7887,622,4,'Look at a catalog or website (with parent’s permission) that sells slingshots. Find out what different equipment is available and the price differences of each.');
INSERT INTO badge_optional_requirements VALUES(7888,622,5,'Discuss examples of slingshots being used in the Bible or other literature.');
INSERT INTO badge_optional_requirements VALUES(7889,622,6,'Draw a picture illustrating the trajectory of something shot from a slingshot. Does it travel in a straight line or a curved line? What does this tell you about where to aim?');
INSERT INTO badge_optional_requirements VALUES(7890,622,7,'Find out what canting is and how it might make slingshot shooting more accurate.');
INSERT INTO badge_optional_requirements VALUES(7891,622,8,'Have a slingshot competition with your family, friends, or group. Make sure an adult is present.');
INSERT INTO badge_optional_requirements VALUES(7892,622,9,'Find examples of slingshots being used in movies or television. What are some famous examples?');
INSERT INTO badge_optional_requirements VALUES(7893,622,10,'Design and draw your own slingshot.');
INSERT INTO badge_optional_requirements VALUES(7894,622,11,'Learn about different slingshot associations and organizations that exist. Are there any near you?');
INSERT INTO badge_optional_requirements VALUES(7895,623,3,'Make a list of at least ten health benefits of sleep.');
INSERT INTO badge_optional_requirements VALUES(7896,623,4,'Make a list of at least ten ways to fight insomnia and/or get quality sleep.');
INSERT INTO badge_optional_requirements VALUES(7897,623,5,'Be in charge of the invitations and RSVP’s for a slumber party with three or more guests.  Make sure the invitations convey all the necessary information and the theme of the party (if you have one).');
INSERT INTO badge_optional_requirements VALUES(7898,623,6,'Plan and execute two crafts for your slumber party.');
INSERT INTO badge_optional_requirements VALUES(7899,623,7,'Be in charge of games for a slumber party. Levels 4-5: Lead at least two games.  If you are giving prizes, brainstorm ways to make sure everyone gets a prize.');
INSERT INTO badge_optional_requirements VALUES(7900,623,8,'Be in charge of breakfast the morning after a slumber party.');
INSERT INTO badge_optional_requirements VALUES(7901,623,9,'Be in charge of music for a slumber party.  Teach everyone a song or make a recording of your singing.');
INSERT INTO badge_optional_requirements VALUES(7902,623,10,'Be in charge of party favors for a slumber party.');
INSERT INTO badge_optional_requirements VALUES(7903,623,11,'Be in charge of the food during a slumber party.  Make a list of ways you can reduce the sugar, preservatives, and artificial colors & flavors in party food.  Remember some people have trouble sleeping after eating too much junk food. Be aware of any food allergies/sensitives and plan accordingly!');
INSERT INTO badge_optional_requirements VALUES(7904,623,12,'If you are planning on watching a movie during your slumber party, be in charge of getting permission from parents for the movies on your list and tally the votes from the kids to see what movie to watch.');
INSERT INTO badge_optional_requirements VALUES(7905,623,13,'Be in charge of cleaning and decorations for a slumber party.');
INSERT INTO badge_optional_requirements VALUES(7906,623,14,'Be in charge of cleaning up after a slumber party.');
INSERT INTO badge_optional_requirements VALUES(7907,623,15,'Send supplies for a slumber party to a women’s/children’s refuge or donate some bedding to an orphanage.');
INSERT INTO badge_optional_requirements VALUES(7908,623,16,'Learn five methods of coping with homesickness at a slumber party.');
INSERT INTO badge_optional_requirements VALUES(7909,624,3,'Create at least 3 different versions of s’mores by trying different cookies (chocolate chip, Oreos, etc), different candy bars (Reese’s Peanut Butter Cups, KitKat, etc) or other foods that melt such as caramel or white chocolate. Which do you like better, one of your creations or the original s’mores recipe?');
INSERT INTO badge_optional_requirements VALUES(7910,624,4,'Make s’more kabobs by skewering a marshmallow on a stick, dipping it in melted chocolate, and rolling it into graham cracker crumbs and other crumbled toppings.');
INSERT INTO badge_optional_requirements VALUES(7911,624,5,'Research a country and a dessert it is famous for (for example, Germany’s Black Forest Cake, Italy’s Tiramisu, etc). Design a s’more that duplicates the dessert. Make your s’more recipe for your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(7912,624,6,'Make a recipe that tastes like s’mores, such as a s’mores dip or party mix.');
INSERT INTO badge_optional_requirements VALUES(7913,624,7,'Sometimes you may not be able to cook over an open fire. Think of other ways you could cook your s’mores such as using a microwave or in tin foil on a BBQ.  Try one and compare to campfire s’mores. Which do you like better and why?');
INSERT INTO badge_optional_requirements VALUES(7914,624,8,'Create a cookbook for your family, friends, and groups of all the s’mores recipes you’ve tried.');
INSERT INTO badge_optional_requirements VALUES(7915,624,9,'Create and make at least 3 “gourmet” s’mores that add special ingredients to a basic s’more, such as peanut butter and banana S’mores.');
INSERT INTO badge_optional_requirements VALUES(7916,624,10,'Go on a s’more scavenger hunt. Visit a grocery store and see how many s’more flavored items you can find (possibilities include things like cereal, granola bars, ice cream and much more). Which use real chocolate and marshmallows and which use things like chocolate flavoring or marshmallow cream? What other products make use of people’s love of s’mores, such as t-shirts?  How many different items can you find?');
INSERT INTO badge_optional_requirements VALUES(7917,624,11,'Participate in a community service project that involves s’mores in some way. You might hold a bake sale of s’more items to raise money for charity, or host a s’mores night for families at your church.');
INSERT INTO badge_optional_requirements VALUES(7918,624,12,'Discuss what careers might involve s’mores and learn more about one. Ideas might include a pastry chef or baker, an artist who might draw s’mores for clipart or other commercial uses, a Christmas ornament designer, etc.');
INSERT INTO badge_optional_requirements VALUES(7919,624,13,'Host a s’mores celebration for National S’Mores Day (or a day of your choice) with marshmallow-themed games.');
INSERT INTO badge_optional_requirements VALUES(7920,624,14,'Make s’mores with different kinds of chocolate, such as dark chocolate, white chocolate, milk chocolate, etc. You can even use a chocolate bar with filling, such as caramel filling or peanut butter filling. Use as many different kinds of chocolate as you can. Which type of s’more is your favorite? Do they melt differently depending on whether they have a filling or not?');
INSERT INTO badge_optional_requirements VALUES(7921,625,3,'Why do small animals burrow down into the snow? If you are able, find a deep snow bank and dig a small hole to the base. You will need two thermometers. Place one thermometer in the hole and the other on top of the snow bank. Leave them there overnight and compare the temperatures in the morning. The colder it is outside, the bigger the difference in the temperature should be. This activity works best when the temperature drops below 10 degrees Fahrenheit.');
INSERT INTO badge_optional_requirements VALUES(7922,625,4,'Learn who Wilson “Snowflake” Bentley was. Why is he important?');
INSERT INTO badge_optional_requirements VALUES(7923,625,5,'Learn about avalanches. What causes them? If you live where it is cold enough, create your own avalanche. Cut a large cardboard box in half corner to corner to create your “mountain.” Set the box on the ground, point up, and wet it down. Let it freeze and then wet it again to get a smoother layer of ice. Leave the box outdoors until it is blanketed with snow. Now give the box a small bump and see if the snow slides off. How big of a bump is necessary for the snow to fall?');
INSERT INTO badge_optional_requirements VALUES(7924,625,6,'Make at least ten snowballs or help build a snowman or snow fort.');
INSERT INTO badge_optional_requirements VALUES(7925,625,7,'Spend at least an hour sledding, skiing, snowshoeing or tobogganing. If you can’t do one of these activities, watch three events of the Winter Olympics that involve snow (minimum 15 minutes each).');
INSERT INTO badge_optional_requirements VALUES(7926,625,8,'Learn a song or poem about snow and share it with someone.');
INSERT INTO badge_optional_requirements VALUES(7927,625,9,'Learn to make paper snowflakes with folded paper. Create at least two different designs.');
INSERT INTO badge_optional_requirements VALUES(7928,625,10,'Use a camera or sketch what you see out your window when it starts snowing.');
INSERT INTO badge_optional_requirements VALUES(7929,625,11,'Help make a dessert that tries to copy the appearance of snow with coconut or icing.');
INSERT INTO badge_optional_requirements VALUES(7930,625,12,'Decorate a garment or home furnishing item with snowmen or snowflakes. You may use fabric paint, embroidery, appliqués, or crochet, etc.');
INSERT INTO badge_optional_requirements VALUES(7931,625,13,'Volunteer your time to help family and neighbors de-ice the sidewalks near your home to make them safer.');
INSERT INTO badge_optional_requirements VALUES(7932,625,14,'Find out the names of places (and locate on a map) that have snow records in your state, country, and continent including: The most snow in one day The most snow in a year The latest spring day it snowed or the earliest fall day');
INSERT INTO badge_optional_requirements VALUES(7933,625,15,'Earn the Sports (Specific) badge for a winter sport involving snow such as skiing.');
INSERT INTO badge_optional_requirements VALUES(7934,625,16,'Have a snow party with your family, friends, or group that include snow-related crafts/games and food.');
INSERT INTO badge_optional_requirements VALUES(7935,625,17,'Learn the safety tips for winter travel. Learn how to get weather advisories for land, air, and sea travel during the winter. Put together or update an emergency kit for your family’s car.');
INSERT INTO badge_optional_requirements VALUES(7936,625,18,'Sew, knit, or crochet at least two caps, sweaters, afghans, etc. for people in need of warm items.');
INSERT INTO badge_optional_requirements VALUES(7937,625,19,'Make a list of pros and cons about living in an area that has snow every winter. Each list should have at least five items on it. Is there an economical difference in monthly expenses?');
INSERT INTO badge_optional_requirements VALUES(7938,626,3,'Make a glycerin soap.');
INSERT INTO badge_optional_requirements VALUES(7939,626,4,'Make a blender soap.');
INSERT INTO badge_optional_requirements VALUES(7940,626,5,'Learn about what different cultures have used in place of traditional soap for cleaning.');
INSERT INTO badge_optional_requirements VALUES(7941,626,6,'Do a service project that has to do with making soap such as making soap to give to a homeless shelter or battered women’s house.');
INSERT INTO badge_optional_requirements VALUES(7942,626,7,'Learn about careers in soap making.  Examples might include making and selling your own soaps as a small business or working for a large corporation such as Proctor and Gamble who make a wide variety of soaps.');
INSERT INTO badge_optional_requirements VALUES(7943,626,8,'What companies produce the most soap?  How are their soaps developed?');
INSERT INTO badge_optional_requirements VALUES(7944,626,9,'Soap making has become a cottage industry with “gourmet” soaps sold online.  With the permission of a parent find out how many different types of homemade soap you can find.');
INSERT INTO badge_optional_requirements VALUES(7945,626,10,'Make some soap to sell as a fundraiser.');
INSERT INTO badge_optional_requirements VALUES(7946,626,11,'Make a vegan soap.');
INSERT INTO badge_optional_requirements VALUES(7947,626,12,'Make a soap that will help with a health condition such as acne, dry skin, or bug repellent.');
INSERT INTO badge_optional_requirements VALUES(7948,626,13,'Make laundry soap.');
INSERT INTO badge_optional_requirements VALUES(7949,626,14,'Find out what ingredients can be added to your soap for health benefits such as oatmeal.');
INSERT INTO badge_optional_requirements VALUES(7950,626,15,'Make a layered soap. Third Party Resources: Soap Recipes 101: Soap Making Basics Teach Soap: Easy Soap and Scrub Recipes');
INSERT INTO badge_optional_requirements VALUES(7951,627,3,'Make solar prints using construction paper and leaves.');
INSERT INTO badge_optional_requirements VALUES(7952,627,4,'Experiment with solar beads. Try using novelty glasses and a variety of sunglasses.  Solar beads can be found at craft stores.');
INSERT INTO badge_optional_requirements VALUES(7953,627,5,'During an eclipse observe crescent/eclipse shaped shadows by making finger windows or pinholes with your hands');
INSERT INTO badge_optional_requirements VALUES(7954,627,6,'Learn how animals tend to behave before, during, and after an eclipse.');
INSERT INTO badge_optional_requirements VALUES(7955,627,7,'Experiment with the sun’s power using a magnifying glass to pop a balloon. Beware of starting a fire!  Use fire safety rules.');
INSERT INTO badge_optional_requirements VALUES(7956,627,8,'Research the significance of solar eclipses in history.  Research the importance of the eclipse in the early 1900’s.  Research Sir Arthur Stanley Eddington’s 1919 solar eclipse experiment and discuss how it confirmed Einstein’s theory of general relativity.');
INSERT INTO badge_optional_requirements VALUES(7957,627,9,'Earn the Astronomy badge at your level.');
INSERT INTO badge_optional_requirements VALUES(7958,627,10,'Using a map of the United States, plot the path of the eclipse.');
INSERT INTO badge_optional_requirements VALUES(7959,627,11,'Watch a solar eclipse (using safety precautions).  Record what percentage the sun is covered where you are.  How long did the eclipse last?  How long did it take to reach maximum coverage?');
INSERT INTO badge_optional_requirements VALUES(7960,627,12,'Do a craft related to the eclipse.');
INSERT INTO badge_optional_requirements VALUES(7961,627,13,'If you travel to view an eclipse, earn a related badge, such as Travel Destinations or Budgeting.');
INSERT INTO badge_optional_requirements VALUES(7962,627,14,'Read about eclipse legends from different cultures.');
INSERT INTO badge_optional_requirements VALUES(7963,627,15,'During an eclipse many people want to be in the area of totality (where the eclipse is total).  Research the costs associated with traveling to a totality city  Prices usually skyrocket when many people visit a certain area. How/why is this not price gouging? How do the laws of supply and demand apply in these areas?');
INSERT INTO badge_optional_requirements VALUES(7964,627,16,'Participate in a citizen science project during an eclipse to help organizations like NASA learn more about space and how it effects the earth.');
INSERT INTO badge_optional_requirements VALUES(7965,628,3,'Learn what these words mean for songwriting: Verse Chorus Bridge');
INSERT INTO badge_optional_requirements VALUES(7966,628,4,'Take the song Mary had a Little Lamb, and change one of the verses in the song. Show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(7967,628,5,'Choose a poem you like, and put it to a tune.');
INSERT INTO badge_optional_requirements VALUES(7968,628,6,'When writing songs, you will be rhyming a lot of words. Preschool-Level 1: Make a list of at least 5 words that rhyme. Level 2: Make a list of 7 words. Level 3: Make a list of 10 words. Level 4: Make a list of 15 words. Level 5: Make a list of 20.');
INSERT INTO badge_optional_requirements VALUES(7969,628,7,'A jingle is a short song used in advertising. Write a short jingle about some you like, such as one of your favorite foods.');
INSERT INTO badge_optional_requirements VALUES(7970,628,8,'Do some research on a songwriter you like. Can find why they started writing songs?');
INSERT INTO badge_optional_requirements VALUES(7971,628,9,'Think of something you like, and see if you can find a song about it. Learn about the person who wrote it.');
INSERT INTO badge_optional_requirements VALUES(7972,628,10,'What is your favorite type of music? Learn more about it and write a short paragraph about what you learned. Level 3 and Up: Learn about a singer who sings that type of music.');
INSERT INTO badge_optional_requirements VALUES(7973,628,11,'Learn about at least two singers who write their own songs.');
INSERT INTO badge_optional_requirements VALUES(7974,628,12,'Look up what copy-writing means and how it applies to anything you have written.');
INSERT INTO badge_optional_requirements VALUES(7975,628,13,'Learn about careers in songwriting. Find out about how to sell a song.');
INSERT INTO badge_optional_requirements VALUES(7976,628,14,'Go and see someone perform their own songs that they wrote. After, if you can, ask them what inspired them to start writing.');
INSERT INTO badge_optional_requirements VALUES(7977,629,3,'Make five garnishes used in/on soups.  Use a garnish on a soup you made.');
INSERT INTO badge_optional_requirements VALUES(7978,629,4,'Learn about thickeners used in soups.  Use two of the following in soups you make: Pureed Starchy or mucilaginous vegetables Starches Flours Grains Egg yolk Gelatin if it is a cold soup.');
INSERT INTO badge_optional_requirements VALUES(7979,629,5,'Discuss the health benefits of various soups.');
INSERT INTO badge_optional_requirements VALUES(7980,629,6,'Try some unique ways to cut vegetables for your soups.  Learn to use safely one new-to-you kitchen tool or piece of equipment while making a soup.');
INSERT INTO badge_optional_requirements VALUES(7981,629,7,'Try soups containing three different beans.');
INSERT INTO badge_optional_requirements VALUES(7982,629,8,'Try a meat or seafood soup that contains a cut of meat or type of protein food that you have never had before.');
INSERT INTO badge_optional_requirements VALUES(7983,629,9,'Help make a large quantity (for 20+ persons) of soup for a camp out, banquet, holiday meal, etc.');
INSERT INTO badge_optional_requirements VALUES(7984,629,10,'Choose five vegetables used in soups and rank them for fiber content and content of one vitamin and one mineral (you will end up with three separate lists/charts/tables with the same five vegetables).');
INSERT INTO badge_optional_requirements VALUES(7985,629,11,'Make three types of soup, each from a different country.');
INSERT INTO badge_optional_requirements VALUES(7986,629,12,'Learn to identify five types of pasta by shape.  Taste three different pastas made from three different flours (spelt, corn, rice, etc.) or make some pasta from scratch and use it in your soup.  Try a soup with a new-to-you grain in it.');
INSERT INTO badge_optional_requirements VALUES(7987,629,13,'Volunteer at a soup kitchen or participate in some other community service that involves soup.');
INSERT INTO badge_optional_requirements VALUES(7988,630,3,'Research a career in rocketry.  What education would you need?  What salary could you expect?  Where might you need to live?');
INSERT INTO badge_optional_requirements VALUES(7989,630,4,'Draw a sketch of how you want to decorate your rocket and follow accordingly.');
INSERT INTO badge_optional_requirements VALUES(7990,630,5,'Make a small booklet containing drawings of at least 8 different rocket designs and show it to your family, friends, or group.  Which do you think are the best for racing?  Why?');
INSERT INTO badge_optional_requirements VALUES(7991,630,6,'Talk to others at the race about their rockets and ask them why they chose their particular design, how they created the rocket, if they have ever raced before, and if so, if they ever won anything, etc.');
INSERT INTO badge_optional_requirements VALUES(7992,630,7,'Make a scrapbook page or collage of photos taken at the race.  Be sure to include photos of the rockets, the track and the awards ceremony.');
INSERT INTO badge_optional_requirements VALUES(7993,630,8,'Help build a Space Derby race course.');
INSERT INTO badge_optional_requirements VALUES(7994,630,9,'Research space ships/rockets in the US and present to your family, friends, or group.  Include date of first space ship launch and name.  Level 2 and Up: What shuttle exploded during liftoff, when was this, and what was the career of the specially chosen astronaut?');
INSERT INTO badge_optional_requirements VALUES(7995,630,10,'Discuss why your rocket needs to be balanced and symmetrical.');
INSERT INTO badge_optional_requirements VALUES(7996,630,11,'Assist the leader in setting up equipment, checking rockets in, and/or passing out awards.');
INSERT INTO badge_optional_requirements VALUES(7997,630,12,'Help a younger child with their rocket.');
INSERT INTO badge_optional_requirements VALUES(7998,631,3,'Create a rocket ship craft.');
INSERT INTO badge_optional_requirements VALUES(7999,631,4,'Dive deeper into the study of celestial bodies and phenomena. Discuss topics such as black holes, dark matter, and the origins of the universe.');
INSERT INTO badge_optional_requirements VALUES(8000,631,5,'Investigate the international cooperation involved in space missions. Discuss the role of different countries and their contributions to space exploration.');
INSERT INTO badge_optional_requirements VALUES(8001,631,6,'Earn the Occupation/Career badge for your current level for a space exploration career such as an astronaut or physicist .');
INSERT INTO badge_optional_requirements VALUES(8002,631,7,'Earn the Aerospace badge for your current level.');
INSERT INTO badge_optional_requirements VALUES(8003,631,8,'Design an inhabited base located within our solar system, on a location such as one of the asteroids, a planet, or a moon around a planet. Make a model or drawing of your base. Consider the following needs: energy, construction, life-support, purpose and function.');
INSERT INTO badge_optional_requirements VALUES(8004,631,9,'Engage in philosophical discussions about the nature of space, time, and our place in the universe. Explore concepts like the Big Bang theory, multiverse theory, and the philosophical implications of space exploration. Reflect on the philosophical questions raised by space exploration and the search for extraterrestrial life.');
INSERT INTO badge_optional_requirements VALUES(8005,631,10,'Study the impact of space weather phenomena, such as solar flares and geomagnetic storms, on Earth and space missions. Discuss how space weather affects satellite communications, power grids, and astronaut safety.');
INSERT INTO badge_optional_requirements VALUES(8006,631,11,'Learn about the role of robotics in space exploration. Discuss the use of robots and rovers in missions to other planets');
INSERT INTO badge_optional_requirements VALUES(8007,631,12,'Create a  piece of space-themed artwork using various mediums such as painting, drawing, clay or digital art.');
INSERT INTO badge_optional_requirements VALUES(8008,631,13,'Explore sustainability in space exploration, and space pollution and its impact on our planet. Discuss how astronauts recycle resources and the challenges of waste management in space, as well as importance of responsible space exploration and the measures taken to mitigate space debris.');
INSERT INTO badge_optional_requirements VALUES(8009,631,14,'Read and analyze science fiction literature related to space exploration. Explore themes of human exploration, extraterrestrial life, and the impact of space travel on society.');
INSERT INTO badge_optional_requirements VALUES(8010,631,15,'Explore the commercial aspects of space exploration. Discuss the rise of private space companies and their contributions to the industry.');
INSERT INTO badge_optional_requirements VALUES(8011,631,16,'Investigate the concept of space travel and the principles behind rocket propulsion.');
INSERT INTO badge_optional_requirements VALUES(8012,631,17,'Conduct a model rocket launch and discuss the forces at play during the launch and flight.');
INSERT INTO badge_optional_requirements VALUES(8013,631,18,'Watch a video or documentary about a significant space mission.');
INSERT INTO badge_optional_requirements VALUES(8014,631,19,'Learn about a famous space artist such as Chesley Bonestell, Robert McCall, Don Davis, Michael Whelan, Lucy West-Binnall, Kim Poor, or David A. Hardy and their works.');
INSERT INTO badge_optional_requirements VALUES(8015,631,20,'Learn how to use a telescope or binoculars for stargazing.');
INSERT INTO badge_optional_requirements VALUES(8016,631,21,'Learn how astronauts prepare for space.  Create a series of physical challenges to simulate astronaut training.');
INSERT INTO badge_optional_requirements VALUES(8017,631,22,'Learn about the health consequences of space travel.    What are the physical effects of microgravity on the human body?');
INSERT INTO badge_optional_requirements VALUES(8018,631,23,'Learn about at least 3 inventions that are a direct result of space exploration that are used in everyday life like the memory foam found in mattresses, insoles, etc .');
INSERT INTO badge_optional_requirements VALUES(8019,631,24,'Prepare a space-themed meal using freeze-dried or dehydrated ingredients.  Discuss the challenges of eating in space.');
INSERT INTO badge_optional_requirements VALUES(8020,631,25,'Alien Life Search: – Study micro-organisms on Earth and discuss the possibility of life on other planets. – Create a “wanted poster” for an imaginary alien species.');
INSERT INTO badge_optional_requirements VALUES(8021,632,3,'Participate in a community service project that supports your area of study.');
INSERT INTO badge_optional_requirements VALUES(8022,632,4,'Learn about the importance of words. Why is it important to use a positive, empowering vocabulary, rather than using outdated terms? What current terminology is promoted for your area of study?');
INSERT INTO badge_optional_requirements VALUES(8023,632,5,'Learn about the role of education and your area of study. How are schools providing necessary accommodations? What struggles might your area of study face? Levels 4-5: Learn about which laws protect your area of study in regards to education.');
INSERT INTO badge_optional_requirements VALUES(8024,632,6,'Find out what government programs are available for your area of study, if any.');
INSERT INTO badge_optional_requirements VALUES(8025,632,7,'Learn about common accommodations often required for your area of study. Reflect on your own city/town. Would someone with your disability be able to lead a confident life in your city? What further progress could be made to make your town more inclusive?');
INSERT INTO badge_optional_requirements VALUES(8026,632,8,'Read a book written by someone from your area of study.');
INSERT INTO badge_optional_requirements VALUES(8027,632,9,'Find at least one organization/community specific to your area of study. Are they non-profit? What is their mission? Where do their funds go? How do they promote inclusiveness in regards to this disability?');
INSERT INTO badge_optional_requirements VALUES(8028,632,10,'What is the Americans with Disabilities Act (ADA)? Why is it created? When did it become law? When was the last time it was revised?');
INSERT INTO badge_optional_requirements VALUES(8029,632,11,'If you are a part of a troop or club earning this badge, what accommodations would you need to include for someone from this area of study in your club/troop/group?');
INSERT INTO badge_optional_requirements VALUES(8030,632,12,'What is it like at work for your area of study? What accommodations might they need? What advantages/disadvantages might they face? Levels 4-5: Learn about which laws protect your area of study in regards to work.');
INSERT INTO badge_optional_requirements VALUES(8031,632,13,'How does technology affect your area of study? What opportunities does technology provide?');
INSERT INTO badge_optional_requirements VALUES(8032,632,14,'Many people with disabilities have service animals. What animals/breeds of animals are typically used for service animals? What training does a service animal require? How do you interact with a service animal? How does a person qualify for a service animal? What is the difference between a service animal and an emotional support animal? How do fake service animals affect real, trained service animals and those who need them? Levels 4-5: Learn about which laws involve service animals.');
INSERT INTO badge_optional_requirements VALUES(8033,632,15,'Learn about careers involving your area of study.  What type of education do you need?  What type of pay could you expect?  Where might you have to live? If possible, shadow someone for a day in one of these careers.');
INSERT INTO badge_optional_requirements VALUES(8034,632,16,'What is the history of your area of study? What struggles and victories has your area of study faced?');
INSERT INTO badge_optional_requirements VALUES(8035,632,17,'Interview someone with the disability you are studying or their caregiver. What is their daily life like?');
INSERT INTO badge_optional_requirements VALUES(8036,633,3,'Find a spelling handbook and learn two spelling rules you didn’t know before.');
INSERT INTO badge_optional_requirements VALUES(8037,633,4,'Play a minimum of two rounds of a spelling game such as Scrabble, Big Boggle, Hangman, Crossword Cubes, etc.  This can be repeated for a second requirement.');
INSERT INTO badge_optional_requirements VALUES(8038,633,5,'Memorize the meaning of ten prefixes or suffixes.');
INSERT INTO badge_optional_requirements VALUES(8039,633,6,'While you are driving around town, look for a word that has been spelled incorrectly.  This could be a simple mistake or someone could have done it on purpose to catch your attention or to make a “play on words” (find out what that means).');
INSERT INTO badge_optional_requirements VALUES(8040,633,7,'Learn the different parts of an entry in the dictionary, what they mean, and who might use them. Learn the definition of the word “etiology.” If you don’t have a dictionary handy, how else can you check the spelling of a word?');
INSERT INTO badge_optional_requirements VALUES(8041,633,8,'Create a piece of art that has correctly spelled words in it.  This can be a poster, a collage, or a calligraphy piece.');
INSERT INTO badge_optional_requirements VALUES(8042,633,9,'Watch the National Spelling Bee on TV or participate in a spelling bee.');
INSERT INTO badge_optional_requirements VALUES(8043,633,10,'Help host a spelling-themed party.');
INSERT INTO badge_optional_requirements VALUES(8044,633,11,'Learn a riddle or joke based on a misspelled word or a word that can be spelled two ways.  Tell it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(8045,633,12,'Learn a song or compose a song that helps a person learn to spell at least one word.');
INSERT INTO badge_optional_requirements VALUES(8046,633,13,'Help someone learn to spell five words using a creative method such as jumping rope, bouncing a ball, using blocks or finger painting.');
INSERT INTO badge_optional_requirements VALUES(8047,633,14,'Proofread someone’s paper and help them look for spelling errors.');
INSERT INTO badge_optional_requirements VALUES(8048,634,3,'Read a book about a famous spy.');
INSERT INTO badge_optional_requirements VALUES(8049,634,4,'Study how spies were used in one major conflict such as the American Revolution, Civil War, World War II, or the Cold War. Learn about at least one male and one female spy from that conflict.');
INSERT INTO badge_optional_requirements VALUES(8050,634,5,'Watch a spy movie.');
INSERT INTO badge_optional_requirements VALUES(8051,634,6,'Learn about gadgets used by spies, past and present. With the permission of a parent, search the internet to discover what types of real spy gadgets are available for sale. Create your own imaginative spy gadget and explain how it works.');
INSERT INTO badge_optional_requirements VALUES(8052,634,7,'Learn about at least 3 different careers related to “spying” and the education needed to enter that field.');
INSERT INTO badge_optional_requirements VALUES(8053,634,8,'Create a simple disguise using items you already own. Practice changing your appearance without a costume.');
INSERT INTO badge_optional_requirements VALUES(8054,634,9,'Create a spy kit using household objects (e.g., magnifying glass, flashlight, notepad, disguise).');
INSERT INTO badge_optional_requirements VALUES(8055,634,10,'Research how women used “invisible” roles (nurses, couriers, servants, etc.) to spy without being noticed.');
INSERT INTO badge_optional_requirements VALUES(8056,634,11,'Listen to an unfamiliar conversation (in person or in a safe, public space) and try to summarize what it was about. Discuss the ethics of eavesdropping afterward.');
INSERT INTO badge_optional_requirements VALUES(8057,634,12,'Learn to dust for fingerprints');
INSERT INTO badge_optional_requirements VALUES(8058,634,13,'Learn to make and write with invisible ink.');
INSERT INTO badge_optional_requirements VALUES(8059,634,14,'Learn how animals (like pigeons or dogs) have been used for spying or secret communication.');
INSERT INTO badge_optional_requirements VALUES(8060,634,15,'Create a timeline of major spy-related events or operations in history.');
INSERT INTO badge_optional_requirements VALUES(8061,634,16,'Design your own fictional spy character with a code name, backstory, mission, and tools.');
INSERT INTO badge_optional_requirements VALUES(8062,634,17,'Learn about spy satellites and drones are used to gather information in modern times.');
INSERT INTO badge_optional_requirements VALUES(8063,634,18,'Practice your observation skills by studying a room for one minute, then writing down everything you remember. Repeat to improve.');
INSERT INTO badge_optional_requirements VALUES(8064,634,19,'Learn to follow a set of clues to solve a mystery. Try a beginner logic puzzle, escape room game, or scavenger hunt.');
INSERT INTO badge_optional_requirements VALUES(8065,634,20,'Learn at least 10 words or jargon terms that relate to spies such as: Brush Pass – A quick, casual exchange of items (like documents or flash drives) between agents in public without drawing attention. Cut-out – An intermediary who passes messages between spies so they don’t know each other’s identities. Safe House – A secure location where spies can hide, meet, or conduct operations without being detected. Asset – A person (not necessarily a trained spy) who provides valuable information to an intelligence agency. Burn Notice – An official notice that an agent is compromised and can no longer be trusted or used. Tradecraft – The techniques and methods used in espionage, such as disguises, surveillance, and encryption. Black Bag Job – A secret, unauthorized break-in to gather information or plant surveillance devices. Legend – A completely fabricated background or identity created for a spy to support their cover story. The Farm – Nickname for the CIA’s training facility in Virginia (Camp Peary), where operatives are trained. Blown – A term used when a spy’s identity or mission has been exposed. Alias – A false name used to hide a spy’s real identity. Cipher – A secret code used to hide the meaning of a message. Encryption – The process of converting information into a code to prevent unauthorized access. Operative – A person working as a secret agent or spy. Surveillance – The act of secretly watching someone or something to gather information. Dead drop – A hidden location where items or messages are left to be picked up later by someone else. Intel – Short for “intelligence,” meaning important information, especially gathered secretly. Mole – A spy who secretly works within an organization to gather and report information. Cover – A disguise or fake identity used by a spy to hide their true role. Reconnaissance – The act of exploring or observing an area to gather information, often before taking action. Espionage – The practice of spying or using spies to gather secret information, especially about governments or enemies.');
INSERT INTO badge_optional_requirements VALUES(8066,635,3,'Learn about different types of fibers that can be spun.  Include at least 3 animal fibers and 3 plant fibers.');
INSERT INTO badge_optional_requirements VALUES(8067,635,4,'Learn how to properly clean your raw material prior to spinning.');
INSERT INTO badge_optional_requirements VALUES(8068,635,5,'Learn to identify each of the following spinning accessories and explain what it is used for: Niddy Noddy Swift or Skeinwinder Diz Lazy Kate Ball Winder');
INSERT INTO badge_optional_requirements VALUES(8069,635,6,'Attend a spinning demonstration with at least two different types of spinning.');
INSERT INTO badge_optional_requirements VALUES(8070,635,7,'Find out what a Spinning Guild does.  Where is the one closest to you?  How often do they meet?  If possible, attend a meeting.');
INSERT INTO badge_optional_requirements VALUES(8071,635,8,'Participate in a community service project that involves spinning.  You might spin yarn to knit baby hats to donate, or work on a project with a Spinning Guild.');
INSERT INTO badge_optional_requirements VALUES(8072,635,9,'Read a book about spinning.  This can be a work of fiction such as The Goat in the Rug, or a how-to book or magazine.');
INSERT INTO badge_optional_requirements VALUES(8073,635,10,'Watch a video or documentary about spinning.');
INSERT INTO badge_optional_requirements VALUES(8074,635,11,'Learn how to dye the materials you plan to spin.');
INSERT INTO badge_optional_requirements VALUES(8075,635,12,'Teach someone else how to card fibers or spin thread.');
INSERT INTO badge_optional_requirements VALUES(8076,635,13,'Make your own drop spindle.');
INSERT INTO badge_optional_requirements VALUES(8077,635,14,'Explain at least 5 of the following terms (10 Level 3 and Level 4, and all 13 Level 5) Bobbin Bench Crimp Draft Hank Noils Plying Skeining Slub Treadle Whorl Worsted Z or S twist Useful Websites TheWoolery https://www.woolery.com/store/pc/Examples-of-Spinning-Wheels-d13.htm');
INSERT INTO badge_optional_requirements VALUES(8078,636,3,'(Preschool only) Be able to identify and name three pieces of equipment for your sport.');
INSERT INTO badge_optional_requirements VALUES(8079,636,4,'(Preschool and Level 1 only) Participate in a short friendly game of your chosen sport (Playing with child-sized versions of the sport’s equipment is acceptable.).');
INSERT INTO badge_optional_requirements VALUES(8080,636,5,'What traditions are connected to your sport? Are there any superstitions or celebratory actions?');
INSERT INTO badge_optional_requirements VALUES(8081,636,6,'Know the safety rules for your sport. Level 1 and Up must also learn the first aid necessary to treat the most common injuries.');
INSERT INTO badge_optional_requirements VALUES(8082,636,7,'If your sport is a team sport, list 3 characteristics that make a good team member. If your sport is an individual sport, list 3 things that help keep you motivated and focused.');
INSERT INTO badge_optional_requirements VALUES(8083,636,8,'Make a poster about what good sportsmanship means to you. Level 3 and up must write an essay on what good sportsmanship means to you.');
INSERT INTO badge_optional_requirements VALUES(8084,636,9,'(Preschool-Level 3 only) Take part in some form of competition of your sport.');
INSERT INTO badge_optional_requirements VALUES(8085,636,10,'Learn the vocabulary for your sport. Know the names of different types of movement, scoring, field or court components, etc. Level 4 and up must compile a list of at least 20 terms to share with your group or a friend who may be interested in the sport.');
INSERT INTO badge_optional_requirements VALUES(8086,636,11,'Spend at least 2 (Level 4 and up must spend 4 hours) hours showing younger children how to play your sport.');
INSERT INTO badge_optional_requirements VALUES(8087,636,12,'Watch a professional competition of your sport either in person or on TV.');
INSERT INTO badge_optional_requirements VALUES(8088,636,13,'Help plan and run a competition in your sport');
INSERT INTO badge_optional_requirements VALUES(8089,636,14,'Officiate as a referee, umpire, timekeeper, scorekeeper, etc. for a competitive event in your sport.');
INSERT INTO badge_optional_requirements VALUES(8090,636,15,'Create a booklet for younger kids explaining how to play your sport.');
INSERT INTO badge_optional_requirements VALUES(8091,636,16,'(Preschool-Level 3 only) Find out about at least one professional female athlete in your sport. Who is she? Where is she from? What makes her an outstanding athlete? Write a brief article of your findings to share with your family, friends, or your group.');
INSERT INTO badge_optional_requirements VALUES(8092,636,17,'Learn the history of your sport. Where and when did it originate? What has changed about the game since then? Level 4 and up must write an essay comparing and contrasting the sport when it was first developed and the sport as it is today.');
INSERT INTO badge_optional_requirements VALUES(8093,636,18,'Research careers in your chosen sport. What education is required? What pay can be expected for these careers?');
INSERT INTO badge_optional_requirements VALUES(8094,636,19,'Research organizations in your area that promote this sport. Put together an information sheet for people who wish to participate in this sport in your area. Include the contact information for local organizations, parks, courts, etc. that can be used to play this sport, as well as stores that sell equipment for your sport, etc.');
INSERT INTO badge_optional_requirements VALUES(8095,636,20,'Are there scholarships available for your sport? If so, to which universities? Find out what they are looking for in their athletes and what agreements are made upon accepting a scholarship.');
INSERT INTO badge_optional_requirements VALUES(8096,636,21,'Complete an entire season as a team member in your sport (minimum 8 games/matches).');
INSERT INTO badge_optional_requirements VALUES(8097,636,22,'Spend four hours fundraising for your sport. Spend four hours cheering for friends who are competing in your sport.');
INSERT INTO badge_optional_requirements VALUES(8098,636,23,'Read or watch movies of historical accounts/figures in your sport. Be sure to get permission from a parent on any movies as many of them are not appropriate for all ages. Below is a list of possible sports. This list is NOT all inclusive: Basketball Football Skeet Shooting Wrestling Pool Playing Synchronized Swimming Cheer Leading Volleyball Badminton Baseball Boxing Tennis Hockey Water Skiing Down Hill Skiing Cross Country Skiing Water Polo Bowling Racket ball Darts Foosball Decathlon Speed Skating Handball Rowing Table Tennis Triathlon Weight Lifting Horseshoes Bocce Ball Soccer Rugby Aquatics Fencing Modern Pentathlon Lacrosse Rugby Golf Surfing Squash Netball Frisbee golf Track and field Paddle ball Shot put Hang gliding Softball Soccer Kickball T-ball Wiffleball Snowboarding Wake boarding Curling Dodge ball Racquetball Handball Pickle ball Speed ball Cross country Sind surfing Kite boarding Polo Tetherball');
INSERT INTO badge_optional_requirements VALUES(8099,637,3,'Learn something about your team’s playing ground that makes it unique from all others in its category (i.e., Chase Field, home of the Arizona Diamondbacks is the only ballpark in the U.S. which has a pool.)');
INSERT INTO badge_optional_requirements VALUES(8100,637,4,'Has your team’s stadium/arena always had the same name? Find out the history behind your stadium/arena’ name and previous names');
INSERT INTO badge_optional_requirements VALUES(8101,637,5,'Meet a player for your team.');
INSERT INTO badge_optional_requirements VALUES(8102,637,6,'Know your way around your team’s stadium or arena. Be able to locate your seats on a seating chart as well as find them in real life.');
INSERT INTO badge_optional_requirements VALUES(8103,637,7,'Meet a member of your team’s professional staff: the president of the team, a coach, someone who works in the broadcasting or public relations department, a team lawyer, etc. Learn about their job.');
INSERT INTO badge_optional_requirements VALUES(8104,637,8,'Meet one of the cheerleaders, game hosts or mascot.');
INSERT INTO badge_optional_requirements VALUES(8105,637,9,'Does your team have a grant foundation? Find out what kinds of groups/projects your team supports, how they select grant recipients, how they raise money for the grants.');
INSERT INTO badge_optional_requirements VALUES(8106,637,10,'Do any of the players on your team have their own charities? Learn about them.');
INSERT INTO badge_optional_requirements VALUES(8107,637,11,'Do a service project to help promote something your team supports.');
INSERT INTO badge_optional_requirements VALUES(8108,637,12,'Participate in a service project with your team.');
INSERT INTO badge_optional_requirements VALUES(8109,637,13,'Come up with an idea to add to the team/home game experience. Submit your idea to the team’s president.');
INSERT INTO badge_optional_requirements VALUES(8110,637,14,'Attend a home game.');
INSERT INTO badge_optional_requirements VALUES(8111,637,15,'Draw a picture of your stadium or arena or create a model.');
INSERT INTO badge_optional_requirements VALUES(8112,637,16,'Attend a fan event for your team.');
INSERT INTO badge_optional_requirements VALUES(8113,637,17,'Learn your team’s song, if they have one.');
INSERT INTO badge_optional_requirements VALUES(8114,637,18,'Collect memorabilia from your team.');
INSERT INTO badge_optional_requirements VALUES(8115,637,19,'Earn the Sports badge for your team’s sport.');
INSERT INTO badge_optional_requirements VALUES(8116,637,20,'Write a letter to the president of the club, thanking him/her for the great job they are doing.');
INSERT INTO badge_optional_requirements VALUES(8117,637,21,'Learn the meaning behind hand gestures (clean ones), and cheers/chants that are used for your team.');
INSERT INTO badge_optional_requirements VALUES(8118,637,22,'Learn appropriate stadium/arena etiquette. Demonstrate at a game that you can be a good fan.');
INSERT INTO badge_optional_requirements VALUES(8119,638,3,'Find at least three current news stories that show good sportsmanship and share them with your club, family, or friends.  Discuss how their behavior reflects a good sport.');
INSERT INTO badge_optional_requirements VALUES(8120,638,4,'Role play ways to deal with someone who is a sore lose or poor winner.  Discuss ways you can politely show someone that their winning attitude hurts others, or that their losing attitude takes the joy away from everyone involved, both winners and losers.  Discuss the saying, “It’s not about whether you win or lose, but how you play the game.”  What does this mean and how should it affect your enjoyment of a competition?');
INSERT INTO badge_optional_requirements VALUES(8121,638,5,'Participate in a community service project that involves being a good sport.  You might walk in a walk-a-thon to raise money for charity and show that it doesn’t matter how much you raise because every dollar counts, or you might host a game day for younger children demonstrating how to be a good sport regardless of the outcome of each game.');
INSERT INTO badge_optional_requirements VALUES(8122,638,6,'Play a game where you have to take turns being a leader.  Discuss how to make sure that everyone gets a turn in a fair manner.  How will you decide who goes first?  Can everyone agree to this method?  How should you express your disagreement?  What happens if you are outvoted?');
INSERT INTO badge_optional_requirements VALUES(8123,638,7,'Read a book that displays good sportsmanship in its characters.  Discuss the book with your club, friends, or family.');
INSERT INTO badge_optional_requirements VALUES(8124,638,8,'Watch a movie that displays good sportsmanship in its characters.  Discuss the movie with your club, friends, or family.');
INSERT INTO badge_optional_requirements VALUES(8125,638,9,'Learn about careers where demonstrating and teaching good sportsmanship is necessary.  Examples might be a teacher, coach, professional athlete, or youth counselor.  Research one of these careers.  What type of salary could you expect?  What hours might you have to work?  Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(8126,638,10,'Role play good sportsmanship when you are an observer rather than a player.  Cheer on your teammates with positive statements and avoid trash-talking the other team.  Acknowledge and applaud good plays, even when someone on the other team makes them.  When officials make a call, accept it gracefully even if it goes against you. Remember that referees may not be right every time — but they’re people who are doing their best, just as you are.  Whether you win or lose, congratulate your opponents on a game well played.');
INSERT INTO badge_optional_requirements VALUES(8127,639,3,'Discuss how you can better understand people, places, institutions, history, and geography as a result of collecting stamps.');
INSERT INTO badge_optional_requirements VALUES(8128,639,4,'Briefly describe some aspects of the history, growth, and development of the United States postal system. How is it different from postal systems in other countries?');
INSERT INTO badge_optional_requirements VALUES(8129,639,5,'Monitor your mail for a period of 30 days.  Put together a collection of items from stamps, to cancellation marks, metered mail, and other postal marks.');
INSERT INTO badge_optional_requirements VALUES(8130,639,6,'Demonstrate the use of ONE standard catalog for several different stamp issues. Explain why catalog value can vary from the corresponding purchase price.');
INSERT INTO badge_optional_requirements VALUES(8131,639,7,'Demonstrate the use of at least THREE of the following stamp collector’s tools: Stamp tongs Water and tray Magnifiers Hinges Perforation gauge Envelopes and sleeves Watermark fluid');
INSERT INTO badge_optional_requirements VALUES(8132,639,8,'Collect and display a collection of 25 stamps on one topic such as birds, flowers, historical figures, etc.  (If you did requirement #8 at Level 3, you must choose a new topic.)');
INSERT INTO badge_optional_requirements VALUES(8133,639,9,'Collect and display a collection of 25 stamps from around the world by mounting them on a map.');
INSERT INTO badge_optional_requirements VALUES(8134,639,10,'Demonstrate that you can handle stamps with tweezers.');
INSERT INTO badge_optional_requirements VALUES(8135,639,11,'What is the difference between hinged and plastic mounts?  What are the advantages and disadvantages of each.');
INSERT INTO badge_optional_requirements VALUES(8136,639,12,'Make a display of your collection for your club and answer any questions your club mates may have.');
INSERT INTO badge_optional_requirements VALUES(8137,639,13,'Explain the meaning of the term condition as used to describe a stamp. Show examples that illustrate the different factors that affect a stamp’s value.');
INSERT INTO badge_optional_requirements VALUES(8138,639,14,'Visit a post office, stamp club, or stamp show with an experienced collector. Explain what you saw and/or did.');
INSERT INTO badge_optional_requirements VALUES(8139,639,15,'Design your own stamp, cancellation, or cachet.');
INSERT INTO badge_optional_requirements VALUES(8140,639,16,'Write a review of an interesting article from a stamp newspaper, magazine, or book.');
INSERT INTO badge_optional_requirements VALUES(8141,639,17,'Pick your favorite stamp and find out the history behind it.  Why was this subject or person chosen?  When?');
INSERT INTO badge_optional_requirements VALUES(8142,639,18,'Discuss at least THREE ways you can help to preserve stamps, covers, and albums in first-class condition.');
INSERT INTO badge_optional_requirements VALUES(8143,639,19,'Describe the steps taken to produce a stamp. Include the methods of printing, types of paper, perforation styles, and how they are gummed.');
INSERT INTO badge_optional_requirements VALUES(8144,639,20,'Define topical stamp collecting. What are some other types of stamp collections?');
INSERT INTO badge_optional_requirements VALUES(8145,639,21,'Prepare a two- to three-page display involving stamps. Using ingenuity, as well as clippings, drawings, etc., tell a story about the stamps. How do they relate to history, geography, or a favorite topic of yours?');
INSERT INTO badge_optional_requirements VALUES(8146,639,22,'Visit your local post office and find out which stamp designs they currently have.  If possible, purchase one of each for your collection.');
INSERT INTO badge_optional_requirements VALUES(8147,640,3,'Learn about special effect makeup artists.  Which of the Star Wars movies use traditional special effects and which use modern computer generated visual effects?');
INSERT INTO badge_optional_requirements VALUES(8148,640,4,'Learn how at least 3 special effects or visual effects were created in the movies.');
INSERT INTO badge_optional_requirements VALUES(8149,640,5,'Be able to identify at least 10 Star Wars characters, where they are from and what mode of transportation they use.');
INSERT INTO badge_optional_requirements VALUES(8150,640,6,'Find a website about Star Wars and find 5 facts about a planet in the movies.');
INSERT INTO badge_optional_requirements VALUES(8151,640,7,'Make a movie poster for Star Wars.');
INSERT INTO badge_optional_requirements VALUES(8152,640,8,'Play a Star Wars video game.');
INSERT INTO badge_optional_requirements VALUES(8153,640,9,'Costumes play a big role in Star Wars, and all the costumes were specially designed for Star Wars. Who designed the costumes for Star Wars? Read Dressing a Galaxy: The Costumes of Star Wars or another book on Stars Wars costuming, or visit a museum with some of the Star Wars costumes on display. Design a costume that might be worn in one of the movies.');
INSERT INTO badge_optional_requirements VALUES(8154,640,10,'Find out the box office revenues for each of the Star Wars movies. Which movie had the highest revenue? Which movies were made more money overseas than in the U.S.?');
INSERT INTO badge_optional_requirements VALUES(8155,640,11,'Find out what types of licensed materials have been offered relating to the Star Wars movies, such as toys, t-shirts, books, etc.');
INSERT INTO badge_optional_requirements VALUES(8156,640,12,'Find out who wrote the musical scores for the films and listen to at least 3 of the overtures.');
INSERT INTO badge_optional_requirements VALUES(8157,640,13,'Find out what a leitmotif is and explain how they were used in the movies.');
INSERT INTO badge_optional_requirements VALUES(8158,640,14,'Explain what the Star Wars Expanded Universe is. Why do you think they created it?');
INSERT INTO badge_optional_requirements VALUES(8159,640,15,'Read one or more of the original Star Wars books.');
INSERT INTO badge_optional_requirements VALUES(8160,640,16,'Create your own Star Wars character, complete with planet and transportation, and do one of the following: Write a short story incorporating your character into a Star Wars scene. Make a display or poster of your character and how they would fit into the Star Wars story.');
INSERT INTO badge_optional_requirements VALUES(8161,642,3,'Do a service project while visiting your park. You could pick up litter, clear trails, clean facilities, or help with a ranger program.');
INSERT INTO badge_optional_requirements VALUES(8162,642,4,'List five park rules or regulations and explain why each one is important.');
INSERT INTO badge_optional_requirements VALUES(8163,642,5,'Earn the Leave No Trace badge and understand why following these guidelines is important to this park.');
INSERT INTO badge_optional_requirements VALUES(8164,642,6,'Make up a puzzle or game using facts about your chosen park. Play it with someone.');
INSERT INTO badge_optional_requirements VALUES(8165,642,7,'Make a scrapbook about your visit to this state park.');
INSERT INTO badge_optional_requirements VALUES(8166,642,8,'Write a report or make a brochure or poster about the interesting natural features of this park (for example: mountains, rivers, geysers, or rock formations).');
INSERT INTO badge_optional_requirements VALUES(8167,642,9,'Learn about a legend or myth that features this state park. Retell your story to someone or to a group.');
INSERT INTO badge_optional_requirements VALUES(8168,642,10,'What is the history of state parks?  Why are they important to your state?  Why are they important to both humanity and nature?');
INSERT INTO badge_optional_requirements VALUES(8169,642,11,'Watch a documentary or travelogue about this park and plan a trip (real or imaginary) to visit the places you liked most in the video.');
INSERT INTO badge_optional_requirements VALUES(8170,642,12,'Earn a Junior Ranger badge at your chosen park.');
INSERT INTO badge_optional_requirements VALUES(8171,642,13,'Research the history of your park and give a presentation about it.');
INSERT INTO badge_optional_requirements VALUES(8172,642,14,'Earn the Natural Wonders Badge (specific wonder) for a natural wonder occurring in your park.');
INSERT INTO badge_optional_requirements VALUES(8173,642,15,'Take a hike or go camping at your state park. How was this different from where you usually hike or camp in other places?');
INSERT INTO badge_optional_requirements VALUES(8174,642,16,'Make a chart comparing and contrasting the natural features, animals, climate, weather, etc. of this state park and your hometown.');
INSERT INTO badge_optional_requirements VALUES(8175,642,17,'Learn about what it takes to volunteer at your chosen park. What would a volunteer do? What sorts of things would you have to know?');
INSERT INTO badge_optional_requirements VALUES(8176,642,18,'Learn about the park’s namesake (if it has one) and their historical significance.');
INSERT INTO badge_optional_requirements VALUES(8177,642,19,'Read a biography of a famous person connected with your chosen park.');
INSERT INTO badge_optional_requirements VALUES(8178,642,20,'Identify 5 plant species that ar native to the park and 5 animal species that either live in or migrate through it.');
INSERT INTO badge_optional_requirements VALUES(8179,642,21,'Find out what types of weather are common in the park throughout the year.  What is the best time of year to visit?');
INSERT INTO badge_optional_requirements VALUES(8180,642,22,'What dangers should you be aware of in your park?  (Cliffs?  Falling rocks?  Wildfire? Flooding? Dangerous animals? etc….)');
INSERT INTO badge_optional_requirements VALUES(8181,642,23,'Design a travel brochure or digital flyer encouraging others to visit your park.');
INSERT INTO badge_optional_requirements VALUES(8182,642,24,'Write a thank-you letter or email to the park rangers or staff, even if you’ve never met them.');
INSERT INTO badge_optional_requirements VALUES(8183,642,25,'Research how to support the park remotely—through donations, advocacy, or spreading awareness—and take one action to help.');
INSERT INTO badge_optional_requirements VALUES(8184,642,26,'Learn about one endangered or threatened species that lives in the park and what is being done to protect it.');
INSERT INTO badge_optional_requirements VALUES(8185,643,3,'Earn a Character Trait badge related to one of the character traits taught in Steven Universe (courage, friendship, peace, teamwork, etc.)');
INSERT INTO badge_optional_requirements VALUES(8186,643,4,'Make a piece of artwork inspired by Steven Universe.');
INSERT INTO badge_optional_requirements VALUES(8187,643,5,'The Crystal Gems decided to protect planet Earth and fight against Homeworld. Why do you think the gems choose Earth? Did they make the right choice?');
INSERT INTO badge_optional_requirements VALUES(8188,643,6,'Homeworld thinks some gems, like pearls, aren’t able to do the things other gems can do. They think pearls should only be servants. Why do you think they think that? The Crystal Gems disagree. What do you think happened to make the Crystal Gems decide Homeworld was wrong about pearls? How do you think being treated like she should be a servant made Pearl feel? Butterflies and Eagles: Learn about the real life caste system in India, and about the lives of “untouchable” people.');
INSERT INTO badge_optional_requirements VALUES(8189,643,7,'If you learned to sing a Steven Universe song for your Level 1 requirement, learn to play it on an instrument. If you learned to play it, also learn how to sing it.');
INSERT INTO badge_optional_requirements VALUES(8190,643,8,'Make a Steven Universe character costume and dress up in it.');
INSERT INTO badge_optional_requirements VALUES(8191,643,9,'Steven has a pet lion. Learn about real lions—how are they similar to and different from Steven’s lion? What do they eat? How much exercise do they need? Where do they live? In real life, would a lion make a good pet?');
INSERT INTO badge_optional_requirements VALUES(8192,643,10,'Connie’s fighting skills are based on a real life Indian martial art, Kalaripayattu. Learn about the history of Kalaripayattu—when was it invented? Where is it practised? Are there any places in your city to take lessons?');
INSERT INTO badge_optional_requirements VALUES(8193,643,11,'Pearl’s style of fighting is based on ballet. Try to learn a couple of ballet steps—there are videos online that show you how.');
INSERT INTO badge_optional_requirements VALUES(8194,643,12,'Make a picture of yourself as a Crystal Gem. You can draw a picture, or there are even programs online to design yourself as a gem.');
INSERT INTO badge_optional_requirements VALUES(8195,643,13,'Many cultures have attributed all sorts of legends and meanings to gemstones. Learn some of the meaning attached to some of the gems you see in the show.');
INSERT INTO badge_optional_requirements VALUES(8196,643,14,'What is your birthstone on a modern birthstone chart? What about on an alternative birthstone chart, like the Italian or Hebrew birthstone chart?');
INSERT INTO badge_optional_requirements VALUES(8197,643,15,'In order to fuse, gems have to do a dance together. Make up your own dance. If possible, make one up with someone else and dance it together.');
INSERT INTO badge_optional_requirements VALUES(8198,644,3,'Learn to identify at least three different types of background fabric for hand stitching. (If you are re-earning this badge at a new level and have already done this requirement, you may not repeat it.)');
INSERT INTO badge_optional_requirements VALUES(8199,644,4,'(Preschool – Level 1 only) Learn to tell the difference between embroidery floss, crewel yarns, and sewing thread.');
INSERT INTO badge_optional_requirements VALUES(8200,644,5,'Learn to identify embroidery hoops, various embroidery needles, thimbles, and how to transfer a pattern onto a fabric. Practice putting fabric into an embroidery hoop. (If you are re-earning this badge at a new level and have already done this requirement, you may not repeat it.)');
INSERT INTO badge_optional_requirements VALUES(8201,644,6,'Go to a museum, county fair, or other exhibit with at least twenty different examples of stitchery. See if you can identify each type of stitching.');
INSERT INTO badge_optional_requirements VALUES(8202,644,7,'Learn about thread counts, mesh sizes, and the different types of fabric used for your type of stitching. (If you are re-earning this badge at a new level and have already done this requirement, you may not repeat it.)');
INSERT INTO badge_optional_requirements VALUES(8203,644,8,'(Level 2 – Level 5) Learn what silk, wool, cotton, linen, rayon, and polyester are. Learn to tell the difference between embroidery floss, crewel yarns, sewing thread, and crochet thread. (Level 3 and up) Learn what hemp, bamboo, and acrylic are. Find examples of each to examine. Learn to tell the difference between rayon and cotton embroidery floss, crewel yarns, sewing & crochet thread, knitting yarns, and silk ribbons intended for embroidery');
INSERT INTO badge_optional_requirements VALUES(8204,644,9,'Using some of your own embroidery project(s), make a larger work. For example, use some cross stitch for an apron pocket or some needlepoint to make a pillow. Whatever you use, it can also count for requirement #1 or #2.');
INSERT INTO badge_optional_requirements VALUES(8205,644,10,'Take a ready-made item (bath or bedroom linen, garment, etc.) and change it with the addition of embroidery. Show it to your club.');
INSERT INTO badge_optional_requirements VALUES(8206,644,11,'Enter a finished piece of your embroidery in your county fair, or another competition, or donate it to a shelter or some other charity.');
INSERT INTO badge_optional_requirements VALUES(8207,644,12,'Find at least two different books that show a lot of photographs of historical embroidery work. Do a book review for your club.');
INSERT INTO badge_optional_requirements VALUES(8208,644,13,'Design your own embroidery project. You can do it totally freehand or you can write out the directions for a counted project. Execute the project and show it to your club.');
INSERT INTO badge_optional_requirements VALUES(8209,644,14,'Try your hand at machine embroidery. Do at least two projects. What do you like or not like about machine embroidery? How long does it take to learn? How much more money does it take to buy a machine over using just needles and thread?');
INSERT INTO badge_optional_requirements VALUES(8210,644,15,'Shadow for at least four hours a person who does hand or machine-embroidery for a living. Or you can spend the time with someone who presents seminars or writes books of embroidery projects. You need to observe more than one aspect of the person’s job.');
INSERT INTO badge_optional_requirements VALUES(8211,645,3,'Host a screening night for your stop-motion animation movies.');
INSERT INTO badge_optional_requirements VALUES(8212,645,4,'Research stop motion apps.  What free apps are available?  What do the reviews say about them?  Is there a paid version with more options?');
INSERT INTO badge_optional_requirements VALUES(8213,645,5,'Build characters & sets for a stop-motion animation movie.');
INSERT INTO badge_optional_requirements VALUES(8214,645,6,'Make a “Lego” stop-motion animation movie.');
INSERT INTO badge_optional_requirements VALUES(8215,645,7,'Make a “Clay-mation” stop-motion animation movie.');
INSERT INTO badge_optional_requirements VALUES(8216,645,8,'Learn how to publish your stop-motion animation movie on-line.');
INSERT INTO badge_optional_requirements VALUES(8217,645,9,'Learn about “Go-Motion” & make a stop-motion animation movie using the technique.');
INSERT INTO badge_optional_requirements VALUES(8218,645,10,'Learn about a stop motion artist such as Tim Burton or Ray Harryhausen');
INSERT INTO badge_optional_requirements VALUES(8219,645,11,'Create a public service video using stop motion techniques');
INSERT INTO badge_optional_requirements VALUES(8220,645,12,'Research the best type of equipment to use for quality stop motion video.  What type of backdrops do you need?  What type of lighting?  What is the best type of camera or camera setting to use?');
INSERT INTO badge_optional_requirements VALUES(8221,646,3,'Stand in a neutral position and express the setting of your chosen story through fluid arm movements.');
INSERT INTO badge_optional_requirements VALUES(8222,646,4,'Execute a traveling step sequence that represents a journey or adventure.');
INSERT INTO badge_optional_requirements VALUES(8223,646,5,'Incorporate interpretative dance moves to convey a conversation between two characters without using words.');
INSERT INTO badge_optional_requirements VALUES(8224,646,6,'Incorporate frozen poses into your movements, creating dynamic and visually striking moments in your storytelling.');
INSERT INTO badge_optional_requirements VALUES(8225,646,7,'Express a range of emotions through dance, portraying different scenes or moods within the narrative.');
INSERT INTO badge_optional_requirements VALUES(8226,646,8,'Create a dynamic dance sequence that builds up to a climax, mirroring the tension and excitement in a story.');
INSERT INTO badge_optional_requirements VALUES(8227,646,9,'Integrate spins and turns to signify plot twists or significant events in the narrative.');
INSERT INTO badge_optional_requirements VALUES(8228,646,10,'Use slow and fast movements to convey the passage of time within your story.');
INSERT INTO badge_optional_requirements VALUES(8229,646,11,'Partner with one or more people to create a story movement routine together.  Will everyone portray a character or will some people portray nature, the weather or various props?');
INSERT INTO badge_optional_requirements VALUES(8230,646,12,'Use props such as scarves or ribbons to help act out your story and provide movement.');
INSERT INTO badge_optional_requirements VALUES(8231,646,13,'Try using shadows to convey your story.  Hang a large white sheet up and use a bright light to cast your shadow.  How do your movements tell the story using shadow.  Experiment with moving closer to the sheet and farther away.  How does the size of your shadow affect the story telling?');
INSERT INTO badge_optional_requirements VALUES(8232,646,14,'End your performance with a dramatic and expressive final pose that summarizes the essence of the entire story.');
INSERT INTO badge_optional_requirements VALUES(8233,646,15,'Discuss how story movement can improve physical fitness and flexibility.');
INSERT INTO badge_optional_requirements VALUES(8234,646,16,'Learn appropriate stretching techniques to keep your body limber and avoid injury when doing story movements.');
INSERT INTO badge_optional_requirements VALUES(8235,646,17,'Showcase your ability to maintain balance and control by including one-legged poses or movements in your story telling.');
INSERT INTO badge_optional_requirements VALUES(8236,646,18,'Earn the Storytelling badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(8237,646,19,'Discuss the differences between theater, dance, readers theater, story telling and story movements.');
INSERT INTO badge_optional_requirements VALUES(8238,646,20,'Use movements to tell your story that require quick changes in direction, showcasing agility and nimbleness.');
INSERT INTO badge_optional_requirements VALUES(8239,646,21,'Demonstrate skillful handling and manipulation of invisible objects, showcasing clarity and precision in your movements.');
INSERT INTO badge_optional_requirements VALUES(8240,646,22,'Create movements as though interacting with an invisible barrier, emphasizing the use of imaginary obstacles in storytelling.');
INSERT INTO badge_optional_requirements VALUES(8241,646,23,'Use movement to portray different sensory experiences (sight, sound, touch, etc.) in a creative and expressive manner.');
INSERT INTO badge_optional_requirements VALUES(8242,647,4,'Watch at least 1 episode from the 1980’s Strawberry Shortcake show. What differences do you notice between the older and newer versions?');
INSERT INTO badge_optional_requirements VALUES(8243,647,5,'Watch the Strawberry Shortcake: The Sweet Dreams movie. What did you learn?');
INSERT INTO badge_optional_requirements VALUES(8244,647,6,'Design your own new character, draw them, give them a name and at least 4 traits. Who will this character get along with? Give 4 other details of this character.');
INSERT INTO badge_optional_requirements VALUES(8245,647,7,'Earn a Character Trait badge attached to the lessons learned in an episode of Strawberry Shortcake (Laughter, Friendliness, Joy, Sharing, Kindness, Helpfulness, Loyalty, Generosity, Honesty, etc).');
INSERT INTO badge_optional_requirements VALUES(8246,647,8,'Learn about two pets in Strawberry Shortcake, such as Pupcake or Custard. What kind of animal are they? Who do they belong to?');
INSERT INTO badge_optional_requirements VALUES(8247,647,9,'Make your own Strawberry Shortcake friendship game. Play it with a friend or family member.');
INSERT INTO badge_optional_requirements VALUES(8248,647,10,'Have a Strawberry Shortcake friendship party. Make snacks, decorations, or games themed to the show.');
INSERT INTO badge_optional_requirements VALUES(8249,647,11,'Learn about the different “districts” in Strawberryland, such as Cakewalk, Orange Blossom Acres or Huckleberry Briar. Draw a map of Strawberryland as you imagine it. Which district is your favorite and why?');
INSERT INTO badge_optional_requirements VALUES(8250,647,12,'Write a poem about Strawberry Shortcake. It should include at least 10 lines.');
INSERT INTO badge_optional_requirements VALUES(8251,647,13,'With the help of an adult, make Strawberry shortcake (the dessert). How did it taste?');
INSERT INTO badge_optional_requirements VALUES(8252,647,14,'Write your own comic line complete with pictures of how you would have a Strawberry Shortcake episode go.');
INSERT INTO badge_optional_requirements VALUES(8253,648,3,'Identify at least three well known street artists and describe their work.');
INSERT INTO badge_optional_requirements VALUES(8254,648,4,'Learn about the different forms of street art, such as murals, stencils, wheatpasting, and yarn bombing.');
INSERT INTO badge_optional_requirements VALUES(8255,648,5,'Design your own street art style mural on a piece of paper or cardboard.');
INSERT INTO badge_optional_requirements VALUES(8256,648,6,'Participate in painting a mural in a public space.');
INSERT INTO badge_optional_requirements VALUES(8257,648,7,'Create a chalk mural.');
INSERT INTO badge_optional_requirements VALUES(8258,648,8,'Learn about a famous street artist, such as Banksy.');
INSERT INTO badge_optional_requirements VALUES(8259,648,9,'Sometimes people living under oppressive regimes express their political views through guerilla street art. Find age-appropriate examples of this. If you lived somewhere where you couldn’t express your political views freely, what kind of art might you make?');
INSERT INTO badge_optional_requirements VALUES(8260,648,10,'Learn about a collective of street artists. What does it mean to be in an artists’ collective?');
INSERT INTO badge_optional_requirements VALUES(8261,648,11,'Interview a street artist about what they do. How do they design their art? What is the process that brings a piece from an idea into being?');
INSERT INTO badge_optional_requirements VALUES(8262,648,12,'Learn about the connections between street art and other forms of independent art, such as zine-making. Earn the Zines badge at your level.');
INSERT INTO badge_optional_requirements VALUES(8263,648,13,'How can street art share positive messages that promote well-being? Create a piece of street art—perhaps a chalk mural—with a positive message.');
INSERT INTO badge_optional_requirements VALUES(8264,648,14,'Learn about the beautification movement. How can public art create safer, happier communities?');
INSERT INTO badge_optional_requirements VALUES(8265,648,15,'Go on a photo scavenger hunt, finding as many examples as you can of street art in your neighborhood or town.');
INSERT INTO badge_optional_requirements VALUES(8266,648,16,'Create a collage made of your favourite pictures of street art from around the world.');
INSERT INTO badge_optional_requirements VALUES(8267,648,17,'Choose a piece of street art you especially like or that is meaningful to you. Explain to your family or troop leader what it is that you like about it, and what makes it special to you.');
INSERT INTO badge_optional_requirements VALUES(8268,648,18,'Learn about different materials and tools used in street art (e.g., spray paint, brushes, chalk, adhesives).');
INSERT INTO badge_optional_requirements VALUES(8269,648,19,'Practice creating stencil art using a medium such as plastic or cardboard.');
INSERT INTO badge_optional_requirements VALUES(8270,648,20,'Try wheatpasting by making a poster and applying it to a surface (make sure you have permission).');
INSERT INTO badge_optional_requirements VALUES(8271,648,21,'Explore the use of digital technology in street art, such as projection mapping and augmented reality.');
INSERT INTO badge_optional_requirements VALUES(8272,648,22,'Research how street art can revitalize communities and attract tourism.');
INSERT INTO badge_optional_requirements VALUES(8273,648,23,'Learn about street art festivals and events that promote legal work.');
INSERT INTO badge_optional_requirements VALUES(8274,648,24,'Write a proposal for a public art project and present it to a local organization.');
INSERT INTO badge_optional_requirements VALUES(8275,648,25,'Develop a unique artist signature or symbol to represent yourself.');
INSERT INTO badge_optional_requirements VALUES(8276,648,26,'Make a street art-inspired piece using recycled materials.');
INSERT INTO badge_optional_requirements VALUES(8277,649,3,'Attend a yoga class and learn different yoga stretching techniques.');
INSERT INTO badge_optional_requirements VALUES(8278,649,4,'Take a class such as Pilates or a dance class that includes stretching.');
INSERT INTO badge_optional_requirements VALUES(8279,649,5,'Learn how breathing properly can increase the effectiveness of stretching.  Practice deep breathing while stretching to increase relaxation.');
INSERT INTO badge_optional_requirements VALUES(8280,649,6,'Learn about physical therapy and how stretching is used to heal injuries.  Interview a phyisical therapist if possible.');
INSERT INTO badge_optional_requirements VALUES(8281,649,7,'Research the importance of stretching for athletes.  Choose a specific athletic sport.  What type of stetches do these athletes usually do?');
INSERT INTO badge_optional_requirements VALUES(8282,649,8,'Choose a specific muscle group such as your hamstrings.  Learn different techniques for stretching this muscle.  Then stretch that muscle daily for two weeks.  At the end of two weeks assess how flexible you were when you started verses how flexible you are now.');
INSERT INTO badge_optional_requirements VALUES(8283,649,9,'Find out what proprioceptive neuromuscular facilitation is.  How and why is this stretching technique used?');
INSERT INTO badge_optional_requirements VALUES(8284,649,10,'Research the best times to stretch, such as in the morning or before bedtime.  Why does it matter when you stretch?');
INSERT INTO badge_optional_requirements VALUES(8285,649,11,'Investigate and explain the physiological changes that occur in the body during stretching, including the role of connective tissues, blood flow, and nerve impulses.');
INSERT INTO badge_optional_requirements VALUES(8286,649,12,'Design a fun and interactive stretching game.');
INSERT INTO badge_optional_requirements VALUES(8287,649,13,'Laern about a career that involves stretching such as dance instructor, athlete or physical therapist.  How do they use stretching in their career? What education, experience or talent do they need to get their job?  What kind of hours and pay can be expected for this career?');
INSERT INTO badge_optional_requirements VALUES(8288,649,14,'Particpate in a community service project that involves stretching in some way.  You might help lead a summer yoga class for for a Day Camp or participate in a walk-a-thon where you should stretch before beginning.');
INSERT INTO badge_optional_requirements VALUES(8289,650,3,'Create at least five Mario fangames. This is in addition to Eagle #2.');
INSERT INTO badge_optional_requirements VALUES(8290,650,4,'Create at least five Mario-themed microgames/levels and share it with your friends! (using WarioWare D.I.Y., Mario vs Donkey Kong 2: March of the Minis, Mario vs Donkey Kong: Minis March Again, Mario vs Donkey Kong: Mini-Land Mayhem!, Mario and Donkey Kong: Minis on the Move) Level 3: 10 microgames/levels Level 4: 15 microgames/levels Level 5: 20 microgames/levels');
INSERT INTO badge_optional_requirements VALUES(8291,650,5,'Play a 3D Mario game (Super Mario 64, Super Mario Sunshine, Super Mario Galaxy, etc).');
INSERT INTO badge_optional_requirements VALUES(8292,650,6,'Watch an episode of any Mario cartoon (Super Mario Bros Super Show, Super Mario World (cartoon), etc)');
INSERT INTO badge_optional_requirements VALUES(8293,650,7,'Play a Mario board game (Super Mario Chess, Super Mario Checkers, etc)');
INSERT INTO badge_optional_requirements VALUES(8294,650,8,'Learn about game ratings.  What are they?  What does each mean?');
INSERT INTO badge_optional_requirements VALUES(8295,650,9,'With parental permission, check out www.mariowiki.com.');
INSERT INTO badge_optional_requirements VALUES(8296,650,10,'Make your own Super Mario power-up and explain why how you decided to create it.');
INSERT INTO badge_optional_requirements VALUES(8297,650,11,'Throw a Super Mario party.');
INSERT INTO badge_optional_requirements VALUES(8298,650,12,'Give a Super Mario toy to a charity.');
INSERT INTO badge_optional_requirements VALUES(8299,650,13,'Create an ABC brag book with a Super Mario theme.');
INSERT INTO badge_optional_requirements VALUES(8300,650,14,'Dress up as a Super Mario character.');
INSERT INTO badge_optional_requirements VALUES(8301,650,15,'Write a review on a Super Mario game you have played and share it with your friends. Other Resources: Console Classix – www.consoleclassix.com – play retrogames on your PC.  This includes NES, SNES, GameBoy, GameBoy Color, GameBoy Advanced, and Nintendo 64. The Mushroom Kingdom – www.mushroomkingdom.net');
INSERT INTO badge_optional_requirements VALUES(8302,651,3,'Show that you know when your SWAPS are due and when you are going to be mailing and/or giving your SWAPS.  Make sure that everything is ready and turned in on time.');
INSERT INTO badge_optional_requirements VALUES(8303,651,4,'Make or choose a display for your SWAPS.  You might make a banner, sash, or scarf, or decide to pin them on a special tote bag, backpack, jacket, or hat.');
INSERT INTO badge_optional_requirements VALUES(8304,651,5,'Make a SWAPS out of recycled materials and without spending any money.');
INSERT INTO badge_optional_requirements VALUES(8305,651,6,'With the permission of a parent, search the internet for SWAPS ideas.');
INSERT INTO badge_optional_requirements VALUES(8306,651,7,'Learn the history of SWAPS.');
INSERT INTO badge_optional_requirements VALUES(8307,651,8,'Make a SWAPS using craft foam.');
INSERT INTO badge_optional_requirements VALUES(8308,651,9,'Make a SWAPS using beads.');
INSERT INTO badge_optional_requirements VALUES(8309,651,10,'Make a SWAPS using computer technology.  Examples might include using print outs of your state flag and laminating them or using decoupage to seal them to other objects.');
INSERT INTO badge_optional_requirements VALUES(8310,651,11,'Once you receive your new swap item talk about it within your family, friends, or group. How does it make you feel?');
INSERT INTO badge_optional_requirements VALUES(8311,651,12,'As you build your collection of SWAPS, discuss which is your favorite and why.');
INSERT INTO badge_optional_requirements VALUES(8312,651,13,'Create a booklet of creative SWAPS designs.');
INSERT INTO badge_optional_requirements VALUES(8313,651,14,'Design your own SWAPS around the theme of your choice.');
INSERT INTO badge_optional_requirements VALUES(8314,652,3,'Make a decorated sheet cake for an event, such as a party or reunion.');
INSERT INTO badge_optional_requirements VALUES(8315,652,4,'Make a recipe based on another recipe.');
INSERT INTO badge_optional_requirements VALUES(8316,652,5,'Bake cookies or brownies.');
INSERT INTO badge_optional_requirements VALUES(8317,652,6,'Put candy coating on cupcakes instead of icing.');
INSERT INTO badge_optional_requirements VALUES(8318,652,7,'Have a party where you bring your own baked goods and decorate them with different styles.');
INSERT INTO badge_optional_requirements VALUES(8319,652,8,'Try to make brownie-cookies. There is a recipe on www.allrecipes.com');
INSERT INTO badge_optional_requirements VALUES(8320,652,9,'Watch a television show about baking (at least 2-3 episodes). If any of the recipes appeal to you, attempt to make them.');
INSERT INTO badge_optional_requirements VALUES(8321,652,10,'Make the same type of dessert using different recipes and compare them. Which one do you like best.');
INSERT INTO badge_optional_requirements VALUES(8322,652,11,'Make homemade candy or chocolate.');
INSERT INTO badge_optional_requirements VALUES(8323,652,12,'Decorate a cake or cupcakes to look like an animal or flower.');
INSERT INTO badge_optional_requirements VALUES(8324,652,13,'Compare baking from when the settlers came to America and now.');
INSERT INTO badge_optional_requirements VALUES(8325,652,14,'Make a seasonal dessert and decorate it with a seasonal decoration. For example, in October you could bake a pumpkin pie and put a jack-o-lantern face on it.');
INSERT INTO badge_optional_requirements VALUES(8326,652,15,'Look at baking books and make a recipe you have never made before.');
INSERT INTO badge_optional_requirements VALUES(8327,652,16,'Make cupcakes and design them to look like farm animals.');
INSERT INTO badge_optional_requirements VALUES(8328,652,17,'Prepare a dessert that is made by refrigerating and one that is made by baking. Which do you like best? Which is easier to make?');
INSERT INTO badge_optional_requirements VALUES(8329,652,18,'Make a cheesecake. Compare it with a traditional cake.');
INSERT INTO badge_optional_requirements VALUES(8330,653,3,'How do animals and insects move through the water? Watch how they use their legs, fins, tails and bodies to propel through the water. Try to imitate the animal actions in a game or while playing with your friends.');
INSERT INTO badge_optional_requirements VALUES(8331,653,4,'If you are swimming at a beach, make sure you know what the ocean conditions are. Some beaches post colored flags, others may have a chalkboard or other method of communicating dangerous conditions. Know what rip currents and undertows are. If you are ever caught in an ocean current, swim parallel to shore (alongside the shore) rather than to the shore until the water stops pulling you, then swim back to shore. If you can’t get back to the beach, tread water and wave for a lifeguard’s help. You probably won’t see any sharks where you are swimming, but you might run into some jellyfish or Portuguese man-of-wars. If you get stung, tell an adult immediately. If you know you swim in an area with jellyfish, keep vinegar on hand to treat any jellyfish stings. Serious stings should always be seen by a doctor. Swim underwater to retrieve something from a depth of at least 4 feet. Level 2 5 ft, Level 3 6ft, Level 4 8ft, and Level 5 9ft.');
INSERT INTO badge_optional_requirements VALUES(8332,653,5,'Learn to snorkel. Learn how to choose a mask that fits your face and how to keep it from fogging. Learn to breathe with a snorkel and how to clear both your mask and snorkel');
INSERT INTO badge_optional_requirements VALUES(8333,653,6,'Demonstrate the safe way to get in and out of a canoe or rowboat.');
INSERT INTO badge_optional_requirements VALUES(8334,653,7,'Demonstrate survival floating for 3 minutes. Level 3 and up demonstrate for 5 minutes.');
INSERT INTO badge_optional_requirements VALUES(8335,653,8,'Demonstrate the HELP and huddle positions while wearing a properly fitted PFD. What is the purpose of these positions? Explain why swimming or survival floating will hasten the onset of hypothermia in cold water.');
INSERT INTO badge_optional_requirements VALUES(8336,653,9,'Play water games with younger children that will help teach them water safety or basic swimming skills.');
INSERT INTO badge_optional_requirements VALUES(8337,653,10,'Demonstrate how to recover yourself if you fall into the water fully clothed. Stay near the boat, dock, or edge of pool and remain afloat for five minutes.');
INSERT INTO badge_optional_requirements VALUES(8338,653,11,'Demonstrate survival skills by jumping into deep water wearing clothes (shoes, socks, bathing suit, long pants, and long-sleeved shirt). Show that you can remove your shoes and socks. Then remove and inflate your pants, and show that you can float using the pants for support. Swim for 5 minutes using your pants for support and demonstrate how to re-inflate your pants while using them for support (Preschool – Level 3 only)');
INSERT INTO badge_optional_requirements VALUES(8339,653,12,'In deep water, do a head first dive from a dock or pool deck, and from a low diving board.');
INSERT INTO badge_optional_requirements VALUES(8340,653,13,'Take a certified water rescue course through the Red Cross or similar organization.');
INSERT INTO badge_optional_requirements VALUES(8341,653,14,'Discuss how swimming is used for both fitness and therapy. What are the health benefits verses those of other exercises? Write a swimming exercise plan that promotes aerobic fitness, strength and muscle tone, body flexibility, and weight control for someone your age. What resources are there in your community that could be used for your program?');
INSERT INTO badge_optional_requirements VALUES(8342,653,15,'Research a specific swimming activity. Ideas may include competitive swimming, scuba diving, snorkeling, free diving, synchronized swimming, or distance swimming.');
INSERT INTO badge_optional_requirements VALUES(8343,653,16,'Learn a synchronized swimming routine.');
INSERT INTO badge_optional_requirements VALUES(8344,654,3,'Make a list of all the things you can think of that a person could use for a centerpiece besides just flowers. Earn the Flower Arranging Badge or make a centerpiece with flowers. Make a centerpiece without flowers as well.');
INSERT INTO badge_optional_requirements VALUES(8345,654,4,'Discuss the advantages and disadvantages of the following: paper, plastic, natural fiber, and synthetic fiber table linens. Learn 3 new ways to fold table napkins. Discuss the advantages and disadvantages of round and rectangular tables.');
INSERT INTO badge_optional_requirements VALUES(8346,654,5,'Do a nice table setting for someone who has too many physical or economic challenges to be able to do it for herself.');
INSERT INTO badge_optional_requirements VALUES(8347,654,6,'Do the table setting for a themed party that helps other kids earn a badge, such as a doll party or a literary party.');
INSERT INTO badge_optional_requirements VALUES(8348,654,7,'Earn the Food Presentation Badge, the Chef Badge, the Garnishing Badge or the Home Decorating Badge and discuss how table setting effects each.');
INSERT INTO badge_optional_requirements VALUES(8349,654,8,'Discuss when it might be appropriate to use menus, place cards, or napkin rings. Learn how to make some simple but pretty menus, place cards, and napkin rings. Practice putting settings of flatware inside napkins for a buffet.');
INSERT INTO badge_optional_requirements VALUES(8350,654,9,'Learn the difference between tapers, votives, and other candles. Why should a person not use scented candles on a dinner table? What safety measures should a person take when using lighted candles? Create a center piece for your table using candles.');
INSERT INTO badge_optional_requirements VALUES(8351,654,10,'Help design and set tables for a charitable event.');
INSERT INTO badge_optional_requirements VALUES(8352,654,11,'Make sure you know the definitions of hostess and hospitality. For what occupations might a person need to know how to set an inviting table? How much do these occupations pay? Either briefly visit two different people working these occupations or shadow one person for half a day.');
INSERT INTO badge_optional_requirements VALUES(8353,654,12,'Practice writing descriptions of table settings. Write a description of a more formal setting as if you were reporting for a newspaper. Write another description of an informal table setting as if you were reporting for a small newsletter or as if you were writing to a relative.');
INSERT INTO badge_optional_requirements VALUES(8354,655,3,'Find out what your book of worship says about leadership and memorize at least one verse. Level 2: Memorize at least 3 verses. Level 3 and 4: Memorize at least 5 verses. Level 5: Memorize at least 6 verses.');
INSERT INTO badge_optional_requirements VALUES(8355,655,4,'Draw a picture about what leadership means to you.');
INSERT INTO badge_optional_requirements VALUES(8356,655,5,'Learn a song about leadership.');
INSERT INTO badge_optional_requirements VALUES(8357,655,6,'Play Follow the Leader, Simon Says,  or a similar game where one person leads.  Make sure to take turns being the leader.');
INSERT INTO badge_optional_requirements VALUES(8358,655,7,'Choose 3 quotes about leadership and tell why they are important to you. Level 3: Choose 5 quotes. Level 4 and 5: Choose 8 quotes.');
INSERT INTO badge_optional_requirements VALUES(8359,655,8,'Read a biography about a famous leader.  What made this person an effective leader?  Make a list of character traits that a good leader should have.');
INSERT INTO badge_optional_requirements VALUES(8360,655,9,'Interview someone who holds a leadership position to find out how they lead. Questions may include: a)        How do you set goals and delegate jobs to your team? b)        How do you keep your team motivated and focused on the set goals? c)        How do you communicate with your team and keep them informed? d)        How do you hold your team accountable to the tasks assigned to them? e)        How do you recognize successful work? f)        How do you manage conflicts between team members?');
INSERT INTO badge_optional_requirements VALUES(8361,655,10,'Research jobs that require leadership skills. Choose one, and find out what education and experience you would need, what type of pay you could expect, and what type of hours you may be required to work.');
INSERT INTO badge_optional_requirements VALUES(8362,655,11,'Lead a group of younger children in songs, games, crafts, or other activities.');
INSERT INTO badge_optional_requirements VALUES(8363,655,12,'Work for at least 3 different leaders. Who was the best leader and who was the worst?  Why?  Make a list of the characteristics of each leader.  What character traits do you want to develop and which do you want to avoid? (Level 3 & Up Only)');
INSERT INTO badge_optional_requirements VALUES(8364,655,13,'Shadow someone in a leadership position for a day.  How do they make sure that work and goals get accomplished?  How do they motivate their team?  How do they resolve any conflicts that arise?  Make a list of good character traits that they show as a leader. (Level 2 & Up Only) Websites:  These websites are not associated with our program and we cannot guarantee their content. Please do not surf the internet without your parent’s permission. Leadership Games http://www.scribd.com/collections/2282147/Leadership-Lesson-Plans');
INSERT INTO badge_optional_requirements VALUES(8365,656,3,'Help plan and put on a fundraiser for a tall flags troop.');
INSERT INTO badge_optional_requirements VALUES(8366,656,4,'Be part of a tall flag team for at least three months and participate in a parade or performance.');
INSERT INTO badge_optional_requirements VALUES(8367,656,5,'Learn what some good warm-ups and stretches might be before a practice.  Is there a time of day they might be more important?');
INSERT INTO badge_optional_requirements VALUES(8368,656,6,'What are the modesty and practicality issues a team should consider when choosing their performance outfits?  What about price and durability?');
INSERT INTO badge_optional_requirements VALUES(8369,656,7,'If you do not have a band to play for you, do some research equipment for playing the music for your team. Compare the costs as well as the performance and mobility of various listening devices.');
INSERT INTO badge_optional_requirements VALUES(8370,656,8,'Choreograph a routine for a tall flag team.');
INSERT INTO badge_optional_requirements VALUES(8371,656,9,'Teach a new trick, technique or part of a workshop to younger kids.');
INSERT INTO badge_optional_requirements VALUES(8372,656,10,'Help sew some flags or performance outfits for a tall flag team.');
INSERT INTO badge_optional_requirements VALUES(8373,656,11,'What material are the tall flag poles made of?  Why?  What is the price range?  What fabric is used in making the flags?  Why?');
INSERT INTO badge_optional_requirements VALUES(8374,656,12,'Help sew some flags or performance outfits for a tall flag team.');
INSERT INTO badge_optional_requirements VALUES(8375,657,3,'What is cambric tea? Long ago, who drank it and why? Make some.');
INSERT INTO badge_optional_requirements VALUES(8376,657,4,'What is high tea? What is low tea? Learn about the importance of tea in China, Japan, India or another country with tea traditions.');
INSERT INTO badge_optional_requirements VALUES(8377,657,5,'Attend a local tea event.');
INSERT INTO badge_optional_requirements VALUES(8378,657,6,'Learn about tea’s significance in the American Revolution.');
INSERT INTO badge_optional_requirements VALUES(8379,657,7,'Check out old fashioned tea sets at a museum.');
INSERT INTO badge_optional_requirements VALUES(8380,657,8,'Identify the items in a formal tea service. Learn to set the table properly for tea.');
INSERT INTO badge_optional_requirements VALUES(8381,657,9,'Play 2 traditional tea party games.');
INSERT INTO badge_optional_requirements VALUES(8382,657,10,'How should tea be stored? How long does it last?');
INSERT INTO badge_optional_requirements VALUES(8383,657,11,'Harvest your own tea.');
INSERT INTO badge_optional_requirements VALUES(8384,657,12,'Make your own chai or spice tea.');
INSERT INTO badge_optional_requirements VALUES(8385,657,13,'Have tea with an older person or neighbor.');
INSERT INTO badge_optional_requirements VALUES(8386,657,14,'Learn about the difference between black, white, green, and oolong tea. What plant to they come from and where is it grown?');
INSERT INTO badge_optional_requirements VALUES(8387,657,15,'Make iced tea.');
INSERT INTO badge_optional_requirements VALUES(8388,657,16,'Make sun tea.');
INSERT INTO badge_optional_requirements VALUES(8389,657,17,'Sew your own tea bags.');
INSERT INTO badge_optional_requirements VALUES(8390,657,18,'Find a local person or business that makes their own teas. Visit their store and/or talk with them about their teas.');
INSERT INTO badge_optional_requirements VALUES(8391,660,3,'Build something with a team of friends such as a marble run, Lego creation, or fort. Make sure that everyone gets to be equally involved. Observe how decisions are made.');
INSERT INTO badge_optional_requirements VALUES(8392,660,4,'Be a part of some sort of team. This could be a sports team, dance team, band, etc. What is good sportsmanship? How should your team behave if they beat another team in a competition? How should you behave if you lose? How should you treat others on your team?');
INSERT INTO badge_optional_requirements VALUES(8393,660,5,'Play the “Iceberg” game. Spread a sheet out on the floor to represent an iceberg and have a group of around 10 kids stand on it. Then fold the sheet in half (the iceberg is melting) and do it again. Fold it in half again and still try to fit everyone on. Using teamwork, discuss how to keep everyone on the sheet without touching the ground as the space continues to shrink. You will have to work together. How long can you continue before someone falls off?');
INSERT INTO badge_optional_requirements VALUES(8394,660,6,'Patrols must work as a team both at club meetings as well as at camp outs and other functions. Each patrol should have a leader, but that person leads a team. Whether you are the leader or patrol member, show your knowledge of teamwork by helping your patrol to work cooperatively. Do what is asked of you quickly and efficiently and help your other patrol members complete their tasks as well. If you are the patrol leader, make sure you take the needs and desires of your team into account when making your decisions.');
INSERT INTO badge_optional_requirements VALUES(8395,660,7,'Play Wobblyballoons. Place a marble in a balloon and blow it up. Have your team stand in a circle and throw the balloon into the air. The object is not to let the balloon touch the ground until each member of the team has touched it. Each member can only touch the balloon once however. Discuss strategies that may make this easier. For example, try having the smaller kids go first and stand closer to the center of the circle while taller kids stand farther out.');
INSERT INTO badge_optional_requirements VALUES(8396,660,8,'Participate as a team to perform a fundraiser. Who will be responsible for what? Does someone need to bring tables? Do you need people to bake or make things? Who will be responsible for the money and making the deposit? Make sure your team works together so that everyone shares the work and one person is not over-burdened.');
INSERT INTO badge_optional_requirements VALUES(8397,660,9,'Participate as a team to perform a service project. Make sure your team works together so that everyone shares the work and one person is not over-burdened. Discuss how to divide up the work. If you are fixing up the landscaping where you meet, who will weed? Who will trim the bushes? Who will collect the trash and dispose of it? Will you take turns at each job or keep your assignment? How can you make it the most enjoyable for everyone?');
INSERT INTO badge_optional_requirements VALUES(8398,660,10,'Play “The Line Forms Here.” Have your team line up according to whatever the leader shouts such as “Birthday”, “Height”, or “Shoe Size.” How quickly can you organize yourselves? Time yourself and observe how everyone communicates to organize each line. Did everyone try to take charge or did you all work together?');
INSERT INTO badge_optional_requirements VALUES(8399,660,11,'Play “Knots.” Have everyone stand in a circle, reach in and grab two different people’s hands. Now have everyone work together to untangle themselves by going over or under linked hands so that you are standing in circle again. No one may let go of a hand until the knot is untied. Depending on whose hands grabbed whose and how large your group is, you may find yourselves untied into two or more separate circles (occasionally they will interconnect if your group is large). Some people may be facing forward, and some may be facing backward, but it is always possible to untie if your team works well together.');
INSERT INTO badge_optional_requirements VALUES(8400,660,12,'Play “Balloon Panic” Blow up two to three balloons per person. Each person has a balloon, with the rest in a nearby pile. Everyone begins bouncing their balloons in the air. Every five seconds, another balloon is added. See how long the group can keep the balloons bouncing before receiving six penalties. A penalty is announced loudly by the leader when a balloon hits the floor, or once on the floor, if is not got back into play within five seconds. The leader keeps a cumulative score by shouting out “one”, “two”, etc. When the leader gets to “six”, time is stopped. After some discussion, the group tries to better its record with another attempt.');
INSERT INTO badge_optional_requirements VALUES(8401,662,3,'Create a poster about the 10 commandments');
INSERT INTO badge_optional_requirements VALUES(8402,662,4,'Do a craft that involves the 10 commandments. Examples might include: Make puppets to role play situations that discuss the 10 commandments Make 10 commandment tablets: You will need: 2 pieces of cardboard or heavy cardstock for each person, black and white poster paint, and paint brushes. Cut each piece of cardboard into the shape of a stone tablet. Mix the black an white paint into various shades of gray and paint your tablets. When dry, print 5 commandments on each one, or glue on a pre-printed list of commandments for smaller children. Purchase a craft kit from Oriental Trading at www.orientaltrading.com such as their 10 commandments necklace, kids craft, or sticker scene.');
INSERT INTO badge_optional_requirements VALUES(8403,662,5,'Learn a song about the 10 commandments. An example can be found here: The Ten Commandment Song  Garden of Praise http://gardenofpraise.com/tencom.htm');
INSERT INTO badge_optional_requirements VALUES(8404,662,6,'Create a skit, or role play situations, regarding the 10 commandments.');
INSERT INTO badge_optional_requirements VALUES(8405,662,7,'Help teach the 10 commandments to younger children (Butterflies and up only).');
INSERT INTO badge_optional_requirements VALUES(8406,662,8,'Write an essay about what the 10 commandments means to you.');
INSERT INTO badge_optional_requirements VALUES(8407,662,9,'Discuss how rules and laws are important. Come up with 10 commandments for your club. Ideas might include: Thou shalt always wear your uniform to meetings. Thou shalt be on time. Thou shalt listen to and obey your leaders. Thou shalt not horse around or rough-house.etc.');
INSERT INTO badge_optional_requirements VALUES(8408,662,10,'Participate in a service project that addresses one of the 10 commandments. Examples might include: Hold a yard sale and donate the proceeds to a local charity that helps the homeless. Donate any left over items to a charitable thrift store. (You shall not covet your neighborâ€™s house; you shall not covet your neighbor’s wife, or male or female slave, or ox, or donkey, or anything that belongs to your neighbor.) Conduct a teddy bear/stuffed animal drive and donate new or gently used stuffed animals to your local police department to hand out to kids whose parent has been arrested. (Thou shalt not kill. Thou shalt not steal). Help with a project at your local church such as weeding, or helping to paint or decorate a room. (Do no have any other gods before me) Make coupon books to give to your parents with a list of extra chores you will do around the house for them. (Honor thy father and mother)');
INSERT INTO badge_optional_requirements VALUES(8409,662,11,'Play a game to help you learn the 10 commandments. Two examples are shown below: 10 Commandments Bowling You will need: 10 plastic bowling pins or empty water bottles, 1 ball, 2 sets of cards with each set having one card of each of the 10 Commandments To Play: Divide the group into two teams. Each team takes turns bowling and trying to knock down the pins (small children can get closer to the pins than the older children). Count how many pins they know down. They then take the commandment card that goes with that number. For example, if they knock down 6 pins, they would take and read the card with the 6th commandment. The team to get all 10 of their cards first wins. The game gets harder as it progresses since you have to knock down a specific number of pins to get the card. 10 Commandments Dice Game You will need: 2 dice (giant foam or cardboard dice are more fun!) 2 sets of 10 commandment cards To Play: Divide the group into two teams. Teams take turns rolling the dice. Add the two numbers together. The team must then recite that number commandment. For example, if they roll a 3 and a 4, they must recite the 7th commandment. If they roll an 11 or 12, they can choose which commandment to recite. If recited correctly, they get to take that commandment card. The first team to get all 10 cards wins.');
INSERT INTO badge_optional_requirements VALUES(8410,662,12,'Print each of the 10 commandments on a piece of paper. Then arrange the papers from the commandment that you think is the most important down to the one you feel is the least important. Discuss with an adult why you arranged them the way you did. (Preschool and Level 1 only)');
INSERT INTO badge_optional_requirements VALUES(8411,663,3,'Be able to explain the difference between batik, stick-tied, and tied dyed designs.  Make something using at least one of these techniques.  This requirement may be repeated for each design type.');
INSERT INTO badge_optional_requirements VALUES(8412,663,4,'Create a design to use with silk screening, stencil, or block prints.  Print some material using one of these methods.  This requirement may be repeated for each design type.');
INSERT INTO badge_optional_requirements VALUES(8413,663,5,'Understand how to prepare and use natural and commercial dyes.  Use one of these methods to dye a piece of cloth.');
INSERT INTO badge_optional_requirements VALUES(8414,663,6,'Take a field trip to a wholesale fabric house or textile mill and find out how fabrics are printed and distributed to retailers.');
INSERT INTO badge_optional_requirements VALUES(8415,663,7,'Make something using your knowledge of textile design.');
INSERT INTO badge_optional_requirements VALUES(8416,663,8,'Visit a fabric store and make a collage of samples from your fabric designs.');
INSERT INTO badge_optional_requirements VALUES(8417,663,9,'Earn the weaving badge.');
INSERT INTO badge_optional_requirements VALUES(8418,663,10,'Create an abstract design and show how it can be repeated to create an over-all pattern.   You can use rubber stamps, computer programs, block prints, etc. to create your design.');
INSERT INTO badge_optional_requirements VALUES(8419,663,11,'.  Discuss how the texture of different fabrics affects the look of a design.   Choose a simple textile design technique such as block printing and test the same design on at least three different types of fabric.');
INSERT INTO badge_optional_requirements VALUES(8420,663,12,'Create a textile design for each of the following:  a dress; curtains; upholstery; bedding.');
INSERT INTO badge_optional_requirements VALUES(8421,663,13,'Learn about two modern textile designers and make a collage of pictures of their work.');
INSERT INTO badge_optional_requirements VALUES(8422,663,14,'Learn about careers in the textile design industry.  What type of education do you need?  What type of pay can you expect?  What hours can you expect to work?');
INSERT INTO badge_optional_requirements VALUES(8423,663,15,'Interview a textile designer or tour their studio.  You can do an online tour with the permission of your parents.');
INSERT INTO badge_optional_requirements VALUES(8424,663,16,'Earn the weaving badge.');
INSERT INTO badge_optional_requirements VALUES(8425,664,3,'Draw a picture of what thankfulness means to you.');
INSERT INTO badge_optional_requirements VALUES(8426,664,4,'Write an essay about what thankfulness means to you.');
INSERT INTO badge_optional_requirements VALUES(8427,664,5,'Write a story or skit where thankfulness plays an important role.');
INSERT INTO badge_optional_requirements VALUES(8428,664,6,'Read a biography about someone known for their thankfulness.');
INSERT INTO badge_optional_requirements VALUES(8429,664,7,'What does your book of worship say about thankfulness? Memorize at least 1 verse about thankfulness if you are a Preschooler, 3 if you are in Level 1 or 2, 5 if you are in Level 3 or 4, and 7 if you are in Level 5.');
INSERT INTO badge_optional_requirements VALUES(8430,664,8,'Memorize or write a poem about thankfulness.');
INSERT INTO badge_optional_requirements VALUES(8431,664,9,'Find and memorize at least 3 famous quotes about thankfulness.');
INSERT INTO badge_optional_requirements VALUES(8432,664,10,'Write the word THANKFULNESS on a piece of paper and then think of one way to show you are thankful that starts with each letter in the word. For example you could put “Thank a veteran for his/her service in some way” and you might put “Have a tea party to honor a senior in your life.”');
INSERT INTO badge_optional_requirements VALUES(8433,664,11,'Perform a service to show someone or a group that you are thankful for what they do. For example, you could make cookies for the local fire department, spend time playing games with grandparents or other older people, or bring cards to the local VFW/American Legion for the next holiday.');
INSERT INTO badge_optional_requirements VALUES(8434,664,12,'Learn about the first Thanksgiving in the United States and why we celebrate it today.');
INSERT INTO badge_optional_requirements VALUES(8435,664,13,'Create a “Thanksgiving Tree” with your club or family. Construction paper in fall colors Cardboard Scissors Markers Glue stick How to make thanksgiving tree: Cut thanksgiving leaf shapes or hand prints out of colored construction paper. Draw a tree trunk and branches on a piece of cardboard. Ask your friends and family to name things for which they are thankful and write them on each leaf. Glue the leaves. You can pin the thanksgiving tree to a bulletin board, or butcher paper, and hang it up.');
INSERT INTO badge_optional_requirements VALUES(8436,665,3,'Explain the role that tie dye played in the U.S. during the 1920’s and 1930’s when times were tough. Try a tie dye craft from this era.');
INSERT INTO badge_optional_requirements VALUES(8437,665,4,'Learn how to remove dye stains.');
INSERT INTO badge_optional_requirements VALUES(8438,665,5,'Tie dye a household article such as curtains or a dish towel');
INSERT INTO badge_optional_requirements VALUES(8439,665,6,'Learn how to make at least two of the tie dye patterns or techniques below Swirl Sunburst Heart Peace Symbol Cross Circles/Bulls-eye Stripes Gradation');
INSERT INTO badge_optional_requirements VALUES(8440,665,7,'Learn what the Bandhani (also known as Bandhni and Bandhej) technique is. Where do they still practice this type of tie dye?');
INSERT INTO badge_optional_requirements VALUES(8441,665,8,'Tie dye a personal accessory such as a scarf, lunch bag, or hat.');
INSERT INTO badge_optional_requirements VALUES(8442,665,9,'Visit a store specializes in tie dye. How many different techniques are used?  What types of dyes are for sale?');
INSERT INTO badge_optional_requirements VALUES(8443,665,10,'Participate in a service project that involves tie dye. Examples might include hosting a tie dye clinic for kids in your community, making tie dyed articles to donate to a homeless shelter or rescue mission, or making tie dye articles to raise money for a charity.');
INSERT INTO badge_optional_requirements VALUES(8444,665,11,'Research careers that involve tie dye. Examples might include an artist, camp counselor, retail store owner or manager, hair stylist (yes, they do tie dyed hair!), research and development for a dye company, etc. What education and training is needed? What salary could you expect? What hours might you need to work? Where might you need to live?');
INSERT INTO badge_optional_requirements VALUES(8445,665,12,'Make your own natural dyes from items such as blackberries, marigolds, onion, or red cabbage. What is the best way to set a natural dye?');
INSERT INTO badge_optional_requirements VALUES(8446,665,13,'Make a tie dyed edible treat using food dye and share it with your family or club.');
INSERT INTO badge_optional_requirements VALUES(8447,665,14,'Learn about a famous tie dye artist such as Tye Dye Mary. Third Party Resources: Fave Crafts: 50 Tie Dye Craft Projects and How To Tie Dye');
INSERT INTO badge_optional_requirements VALUES(8448,666,3,'Write or learn a song or poem or draw a picture about time capsules.');
INSERT INTO badge_optional_requirements VALUES(8449,666,4,'Write a song,essay or poem about what your life is like that can be included in a time capsule of your life today.');
INSERT INTO badge_optional_requirements VALUES(8450,666,5,'Coordinate collecting items and hiding a time capsule for a local organization.  Ensure it is recorded properly so it can be opened at the selected time.');
INSERT INTO badge_optional_requirements VALUES(8451,666,6,'Begin a birthday time capsule where you add an item each year on your birthday.');
INSERT INTO badge_optional_requirements VALUES(8452,666,7,'Discuss  what would be a good time period to wait before opening a time capsule. Are there reasons to have a very long time period for some whereas a capsule with a different purpose may have a shorter time period?');
INSERT INTO badge_optional_requirements VALUES(8453,666,8,'Write a report or give a presentation discussing how letters and newspapers are like time capsules.  If possible, read letters or newspapers that are at least 25 years old.');
INSERT INTO badge_optional_requirements VALUES(8454,666,9,'Make a time capsule that includes items from each of the nine areas of discovery.');
INSERT INTO badge_optional_requirements VALUES(8455,666,10,'Discuss and make a list of possible reasons why a time capsule may be created. These could include family, community, sports team, birthday, holiday, new buildings, and special events.  Why would time capsules be important for each of these topics?  What type of things might be included.');
INSERT INTO badge_optional_requirements VALUES(8456,666,11,'Research safety considerations when creating and burying a time capsule.  What material should a time capsule be made from. What items may deteriorate in a time capsule? Do you have to buy a ready-made time capsule container or are there other kinds of containers that make good time capsules? Do you have to be aware of possible electric lines/telephone cables etc before burying a time capsule?');
INSERT INTO badge_optional_requirements VALUES(8457,666,12,'Earn the archeology badge at your level.');
INSERT INTO badge_optional_requirements VALUES(8458,666,13,'Learn how a seed bank is like a time capsule. What is the purpose of a seed bank?  Do you have one in your community?');
INSERT INTO badge_optional_requirements VALUES(8459,666,14,'Earn the Museum (Specific) Badge at your level. How are museums like time capsules? What can museums do to prevent their artifacts from deteriorating?');
INSERT INTO badge_optional_requirements VALUES(8460,666,15,'Learn about time capsules that have been sent into space. Which space missions include time capsules from earth?  What was in them?');
INSERT INTO badge_optional_requirements VALUES(8461,666,16,'Make a time capsule from the past. You could collect items that have been passed down through your family and keep them safe for future generations, or you could find articles in junk/antique shops.  Discuss why you chose the items you did and why they might be important to someone in the future.');
INSERT INTO badge_optional_requirements VALUES(8462,666,17,'Make a mini-time capsule for your doll/toy. Include items you think your toy would put in a time capsule.');
INSERT INTO badge_optional_requirements VALUES(8463,666,18,'Find an old cookbook and try some new-to-you old recipes or create a generational cookbook including recipes from your parents and grandparents. How can this be like a time capsule?');
INSERT INTO badge_optional_requirements VALUES(8464,666,19,'Do other cultures make time capsules and how do they differ from those made by your culture?');
INSERT INTO badge_optional_requirements VALUES(8465,666,20,'Popular culture items are often included in time capsules and these items can include fads, catch phrases or slang. Discuss how these things might be interesting but could be misunderstood by those who later open the capsule.');
INSERT INTO badge_optional_requirements VALUES(8466,666,21,'Compare and contrast time capsules to geocaching.');
INSERT INTO badge_optional_requirements VALUES(8467,666,22,'Can you put nature items in a time capsule or will these items promote decay? How else could you include information about nature without compromising the preservation of the capsule.');
INSERT INTO badge_optional_requirements VALUES(8468,666,23,'Find and discuss with an adult 1 (PK), 3 (Level 1), 5 (Level 2 & 3), 7 (Level 4 & 5) verses from your book of faith that discuss passing down your heritage.');
INSERT INTO badge_optional_requirements VALUES(8469,666,24,'Interview 5 people to find out what they would put into a time capsule to communicate what people should know about them. The following website links are for informational purposes only and are not a part of the Curiosity Untamed website.  Visit them at your own risk. Websites: https://www.history.com/news/8-famous-time-capsules https://www.si.edu/mci/english/learn_more/taking_care/timecaps.html https://www.loc.gov/preservation/resources/educational/timecapsule/index.html');
INSERT INTO badge_optional_requirements VALUES(8470,668,3,'Visit a Titanic exhibit either online or in person. Please get your parent’s permission before going online.');
INSERT INTO badge_optional_requirements VALUES(8471,668,4,'Draw and/or color a picture of the Titanic and share it with your parent or leader.');
INSERT INTO badge_optional_requirements VALUES(8472,668,5,'Make a model of the Titanic either with a Lego kit or a model kit. Share it with your club.');
INSERT INTO badge_optional_requirements VALUES(8473,668,6,'Write an essay about one of the survivors of the Titanic and share it with your parent or leader.');
INSERT INTO badge_optional_requirements VALUES(8474,668,7,'Watch a documentary on the Titanic and share what you learned with your club or parent.');
INSERT INTO badge_optional_requirements VALUES(8475,668,8,'Create a design for a ship that you would like to travel on. What kind of amenities would it have? How much would it cost to build? How much did it cost to build the Titanic in 1912? How much would it cost today?');
INSERT INTO badge_optional_requirements VALUES(8476,668,9,'Find out what kind of careers are available to work on a ship. Examples might include Captain, Steward, Chef or Activities Director. What kind of education do you need for these jobs? What kind of pay can you expect? What hours would you have to work?');
INSERT INTO badge_optional_requirements VALUES(8477,668,10,'Pretend you are a reporter in 1912. Write a newspaper article about the sinking of the Titanic and share it with your club.');
INSERT INTO badge_optional_requirements VALUES(8478,668,11,'Learn Morse Code. Share with your club the message sent by the Titanic the night it sank and show them how to do it in Morse Code.');
INSERT INTO badge_optional_requirements VALUES(8479,668,12,'Find out the main reason the people who went down with the Titanic died. What are the symptoms of this condition and how can it be treated?');
INSERT INTO badge_optional_requirements VALUES(8480,668,13,'Compare luxury ships of today with the Titanic. How do their amenities compare?');
INSERT INTO badge_optional_requirements VALUES(8481,668,14,'Play a game about the Titanic. If you are going to play a game online, please ask your parents before doing so.');
INSERT INTO badge_optional_requirements VALUES(8482,668,15,'Find out what was on the menu in the dining room of the Titanic and make one dish from that menu.');
INSERT INTO badge_optional_requirements VALUES(8483,668,16,'Find out what the difference was between steerage and first class accommodations. Why were there such vast differences? Would it be the same today?');
INSERT INTO badge_optional_requirements VALUES(8484,668,17,'How much would it cost to travel from Southampton, England to New York, New York today? How much did it cost in 1912 on the Titanic? www.titanic-facts.com www.wartgames.com/themes/titanic.html http://www.encyclopedia-titanica.org/ Websites: These websites are not associated with our program and we cannot guarantee their content. Please do not surf the internet without your parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(8485,670,3,'Use towel art for a community service.  For example: Get donated towels and fold to give to an abused woman and children’s shelter or go to a nursing home and fold for residents there.');
INSERT INTO badge_optional_requirements VALUES(8486,670,4,'Learn how to make a towel sculpture permanent such as by dipping in concrete, using wire to frame the sculpture or sewing the folds in place.');
INSERT INTO badge_optional_requirements VALUES(8487,670,5,'Watch a video demonstrating different folds.');
INSERT INTO badge_optional_requirements VALUES(8488,670,7,'Earn the origami badge at your level. Compare and contrast working with paper verses towels.');
INSERT INTO badge_optional_requirements VALUES(8489,670,8,'Read a book on folding towels.');
INSERT INTO badge_optional_requirements VALUES(8490,670,9,'Compare and contrast towel art to napkin folding.');
INSERT INTO badge_optional_requirements VALUES(8491,670,10,'Create an original fold.');
INSERT INTO badge_optional_requirements VALUES(8492,670,11,'Enter some of your towel art in a fair or competition.');
INSERT INTO badge_optional_requirements VALUES(8493,670,12,'Host a towel folding contest. Create a set of rules, structure the event, and host it.');
INSERT INTO badge_optional_requirements VALUES(8494,670,13,'Compare towel folding to similar crafts, such as diaper cakes.');
INSERT INTO badge_optional_requirements VALUES(8495,671,3,'Play with a toy from another era.');
INSERT INTO badge_optional_requirements VALUES(8496,671,4,'Invent a toy of your own.  Draw what it would look like and write up how it should be played with.');
INSERT INTO badge_optional_requirements VALUES(8497,671,5,'Learn about a career being a toy designer or inventor.  What jobs are available?  What education is needed?');
INSERT INTO badge_optional_requirements VALUES(8498,671,6,'Find out how a toy of your choice is made.');
INSERT INTO badge_optional_requirements VALUES(8499,671,7,'Visit a toy museum either in person or online.');
INSERT INTO badge_optional_requirements VALUES(8500,671,8,'Discuss how toys can help strengthen certain skills.  For example roller skates help you with physical coordination and strength.  Board games teach problem solving, healthy competition and teamwork. Make a list of at least 15 toys and explain how playing with them can benefit you.');
INSERT INTO badge_optional_requirements VALUES(8501,671,9,'Learn about the patent process.  Why is obtaining a patent an important part of inventing.  Why is obtaining a patent for a toy so difficult?');
INSERT INTO badge_optional_requirements VALUES(8502,671,10,'Toys reflect culture.  Learn about toys from different parts of the world over time.');
INSERT INTO badge_optional_requirements VALUES(8503,671,11,'Learn about how the same toy has changed over time.  Compare two of the same type of toy that were made at least 20 years apart (the longer the better).  Examples might include dolls, toy trains, or board games.  How do they differ in design and how they look?  How do they differ in how they are made?');
INSERT INTO badge_optional_requirements VALUES(8504,671,12,'Make a physical timeline of toys you own.  Choose at least 10 toys and find out when they were first invented and played with.  Put your toys in order from oldest to newest.');
INSERT INTO badge_optional_requirements VALUES(8505,671,13,'Learn about the toy collectibles industry.  Why do some toys increase in value and some don’t?  Find out what “mint condition” means.  Be able to identify at least 5 collectible toys.');
INSERT INTO badge_optional_requirements VALUES(8506,671,14,'Many stories and movies have been written or produced about toys.  Read at least one book about a toy such as the Velveteen Rabbit or Winnie the Pooh and watch at least one movie about a toy such as Toy Story or Paddington.');
INSERT INTO badge_optional_requirements VALUES(8507,675,3,'Visit a transportation museum such as a train museum or airplane museum.');
INSERT INTO badge_optional_requirements VALUES(8508,675,4,'Learn and sing a song about transportation, like “Barges”,  “Leaving on a Jet Plane”, “The Wheels on the Bus” or “Row, Row, Row Your Boat.” Perform it for family or friends.');
INSERT INTO badge_optional_requirements VALUES(8509,675,5,'Take a short trip on a form of public transportation, such as a bus, train, or ferry.');
INSERT INTO badge_optional_requirements VALUES(8510,675,6,'Participate in a guided tour or field trip to a transportation-related facility, such as a railway station or airport.');
INSERT INTO badge_optional_requirements VALUES(8511,675,7,'Create a map showing major transportation routes for at least 3 of the following: roads, railways, shipping lanes, air routes, used for moving people and products.');
INSERT INTO badge_optional_requirements VALUES(8512,675,8,'Research eco-friendly transportation options (e.g., electric cars, bicycles, public transit). Discuss the benefits and challenges of each.');
INSERT INTO badge_optional_requirements VALUES(8513,675,9,'Research safety measures and regulations for one mode of transportation.');
INSERT INTO badge_optional_requirements VALUES(8514,675,10,'Learn about the infrastructure required for one or more modes of transportation (e.g., roads for cars, tracks for trains, airports for planes, ports for ships).  How is it decided where to build?  How does the infrastructure contribute to the efficiency of the transportation method?');
INSERT INTO badge_optional_requirements VALUES(8515,675,11,'Interview a professional working in the transportation industry (e.g., pilot, truck driver, ship captain). Ask about their job and the challenges they face.  What type of education did they need?  What type of hours do they work?  How much travel do they have to do?');
INSERT INTO badge_optional_requirements VALUES(8516,675,12,'Create a piece of art (drawing, painting, model) representing a mode of transportation. Explain your artistic choices.');
INSERT INTO badge_optional_requirements VALUES(8517,675,13,'Learn about the environmental impact of different modes of transportation.');
INSERT INTO badge_optional_requirements VALUES(8518,675,14,'Play a game that focuses on transporation such as Scotland Yard, Ticket to Ride or Freight Cars.');
INSERT INTO badge_optional_requirements VALUES(8519,675,15,'Design your own transportation-related game.');
INSERT INTO badge_optional_requirements VALUES(8520,675,16,'Build a model or design a prototype of a transportation vehicle of the future.');
INSERT INTO badge_optional_requirements VALUES(8521,675,17,'Conduct a survey or interview to gather opinions and suggestions from community members on improving local transportation infrastructure.  Then submit your findings to your city council.');
INSERT INTO badge_optional_requirements VALUES(8522,675,18,'Learn about new innovative transportation technologies and what type of vehicles will be made in the near future.');
INSERT INTO badge_optional_requirements VALUES(8523,675,19,'Learn what a freight forwarder is and the role they play in the transporation industry.  How to get into this type of career?');
INSERT INTO badge_optional_requirements VALUES(8524,675,20,'Learn what logistics are.  Follow a product from source to destination.  Where is it aquired? How is it stored and transported to its final destination?  Were the logistics based on speed or cost?');
INSERT INTO badge_optional_requirements VALUES(8525,675,21,'Research how emergency services (e.g., ambulances, fire trucks, rescue boats) use transportation to respond to emergencies.  What supplies do they transport in addition to emergency responders?  Discuss what special equipment emergency vehicles have that other forms of transporation do not.');
INSERT INTO badge_optional_requirements VALUES(8526,675,22,'Plan and execute a community service project related to transportation such as helping to promote biking or sustainable transportation modes, creating a safe routes to school map for kid biking or walking to school, or making safety signs such as “SLOW – Children at Play” and posting them.');
INSERT INTO badge_optional_requirements VALUES(8527,676,3,'Tour a dump/landfill.  If you have never been to a dump, they differ greatly so go to more than one if you can.  What are the different sections they offer? What is the public allowed to salvage and what is off limits?');
INSERT INTO badge_optional_requirements VALUES(8528,676,4,'Learn about the various jobs and careers involved in trash collection.  What education/training do you need?');
INSERT INTO badge_optional_requirements VALUES(8529,676,5,'Find out how much trash “escapes” the average truck to become litter on the road?');
INSERT INTO badge_optional_requirements VALUES(8530,676,6,'Learn about how trash trucks operate.  What makes them different from other trucks?  Understand the various components of a trash collection truck, including the compactor, hopper, and hydraulic systems.');
INSERT INTO badge_optional_requirements VALUES(8531,676,7,'Identify different types of trash collection vehicles used around the world, such as rear loaders, front loaders, and side loaders.');
INSERT INTO badge_optional_requirements VALUES(8532,676,8,'Learn about the environmental impact of landfill vs incineration?');
INSERT INTO badge_optional_requirements VALUES(8533,676,9,'Learn what type of diseases can spread, and how, if trash is not disposed of properly.');
INSERT INTO badge_optional_requirements VALUES(8534,676,10,'Learn about the different types of waste containers, such as bins, dumpsters, or roll-off containers, used for efficient trash collection.');
INSERT INTO badge_optional_requirements VALUES(8535,676,11,'Participate in a trash clean up service project.');
INSERT INTO badge_optional_requirements VALUES(8536,676,12,'Learn about waste management regulations and guidelines specific to your region or country, including proper disposal methods and recycling requirements.');
INSERT INTO badge_optional_requirements VALUES(8537,676,13,'Explore innovative trash collection technologies, such as automated sorting systems or sensor-based waste bins.  How can technology make trash collection more efficient and effective?');
INSERT INTO badge_optional_requirements VALUES(8538,676,14,'Interview a trash collector.  Find out what they like and dislike about their job.  What does their day look like?');
INSERT INTO badge_optional_requirements VALUES(8539,676,15,'Find out what a waste to energy facility is.  How do they work?  How do they benefit society?');
INSERT INTO badge_optional_requirements VALUES(8540,676,16,'Learn the safety protocols and procedures for working around trash collection vehicles and handling potentially hazardous waste.');
INSERT INTO badge_optional_requirements VALUES(8541,676,17,'Explore waste collection practices in different countries or regions, learning about unique approaches and challenges faced.  How does their system compare to that of the United States?');
INSERT INTO badge_optional_requirements VALUES(8542,676,18,'Create educational materials, such as brochures or posters, to inform others about the importance of proper trash collection and disposal.');
INSERT INTO badge_optional_requirements VALUES(8543,676,19,'Advocate for improved waste collection infrastructure in your community, such as the placement of additional trash bins or the implementation of recycling programs.');
INSERT INTO badge_optional_requirements VALUES(8544,676,20,'Develop a waste management plan for your group’s meeting place, ensuring proper trash collection, recycling, and disposal practices.');
INSERT INTO badge_optional_requirements VALUES(8545,676,21,'Create a model or design of an innovative trash collection vehicle that addresses specific waste management challenges in your community.');
INSERT INTO badge_optional_requirements VALUES(8546,676,22,'Create a waste audit and evaluate the types and amounts of waste generated within your scouting group or community.');
INSERT INTO badge_optional_requirements VALUES(8547,676,23,'Explore the concept of waste reduction and resource recovery, investigating methods such as recycling, upcycling, and composting.');
INSERT INTO badge_optional_requirements VALUES(8548,676,24,'Visit a recycling or waste management facility to learn about the recycling process and the importance of waste segregation.');
INSERT INTO badge_optional_requirements VALUES(8549,676,25,'Design a futuristic trash vehicle.  How would it operate?  How would it make trash collecting more efficient?');
INSERT INTO badge_optional_requirements VALUES(8550,677,3,'(Preschool-Level 1) Demonstrate your knowledge of proper behavior on trains, buses, planes, or cars so that you are courteous to fellow travelers and leave no trace of litter or vandalism in restrooms, waiting rooms, etc.');
INSERT INTO badge_optional_requirements VALUES(8551,677,4,'Create a scrapbook of a trip.  Include journaling of your different activities, photos, and physical mementos such as plane tickets, or show programs.');
INSERT INTO badge_optional_requirements VALUES(8552,677,5,'(Preschool-Level 1 only) Cars, bikes, and trains are just a few of the different modes of transportation you can use to travel. How many more can you think of?  What about modes of transportation used in other countries such as elephants or rickshaws?');
INSERT INTO badge_optional_requirements VALUES(8553,677,6,'Practice ordering a meal in a restaurant and demonstrate polite behavior and table manners. (Level 3 and up) Learn how to calculate a 10%, 15%, and 20% tip and how to go about leaving one.');
INSERT INTO badge_optional_requirements VALUES(8554,677,7,'Earn the foreign language badge.');
INSERT INTO badge_optional_requirements VALUES(8555,677,8,'(Preschool-Level 2 Only) Show that you can use a telephone directory to find things like restaurants, movie theaters, and medical help.  Role play different phone conversations you may have on a trip.');
INSERT INTO badge_optional_requirements VALUES(8556,677,9,'Know the rules of taking pets on planes, trains, buses and boats.');
INSERT INTO badge_optional_requirements VALUES(8557,677,10,'(Preschool-Level 2) Plan a real or pretend trip for your family.  Where would you go?  How would you get there?  What would you do or see?  What would you do for food or lodging?');
INSERT INTO badge_optional_requirements VALUES(8558,677,11,'Read a book or travel magazine about another country.');
INSERT INTO badge_optional_requirements VALUES(8559,677,12,'(Preschool-Level 3) Understand the different rate structures for a specific mode of transportation such as a plane or train.  How does the passenger’s age effect the price?  What about advance purchase verses last minute purchases or the quality of your seating?');
INSERT INTO badge_optional_requirements VALUES(8560,677,13,'What careers are there in the travel industry?  Pick one to research.  What type of education is needed?  What salary can you expect?  How much travel would you be doing?');
INSERT INTO badge_optional_requirements VALUES(8561,677,14,'Know where to find, and how to use first aid and emergency equipment on planes, trains, buses and boats.');
INSERT INTO badge_optional_requirements VALUES(8562,677,15,'As a service project, put together a visitor’s guide to your town.  What type of things would a traveler need to know?  Make sure to include items such as family activities, cultural or historical sites, medical care, post offices, and lodging.  Copy and donate your booklets to realtors, the chamber of commerce, travel agents, and others you feel may be able to use them.');
INSERT INTO badge_optional_requirements VALUES(8563,677,16,'Learn about natural disasters that occur in different parts of the world.  Learn what to do in each type of emergency.');
INSERT INTO badge_optional_requirements VALUES(8564,677,17,'Demonstrate your knowledge of security issues on different modes of transportation.  What are you not allowed to bring on board?  What packing requirements are there?  What things are you not allowed to say, even if you are joking (about bombs, fire, terrorists, etc.)  What is the proper procedure for going through the security stations and x-ray stations?');
INSERT INTO badge_optional_requirements VALUES(8565,677,18,'Learn what documentation is needed to travel to other at least 5 different countries.  What is the difference between a passport and a visa?  How do you get them?');
INSERT INTO badge_optional_requirements VALUES(8566,679,3,'From pictures or actual leaves, identify at least 10 trees just by their leaves. You may wish to create a leaf rubbing of each leaf and make a poster of your tree types.');
INSERT INTO badge_optional_requirements VALUES(8567,679,4,'What are tree rings and what do they tell us? If you are a Level 3, 4, or 5, find out what the study of tree rings is called and who invented it.');
INSERT INTO badge_optional_requirements VALUES(8568,679,5,'How are trees used for décor? Find décor tips for using bonsai, birch, and evergreen trees.');
INSERT INTO badge_optional_requirements VALUES(8569,679,6,'What is photosynthesis and how does it work? Level 3, 4, and 5 should know the anatomy of the tree and the role each part of the leaf plays in photosynthesis.');
INSERT INTO badge_optional_requirements VALUES(8570,679,7,'What are the top three oldest types of trees in the world? Where are they found? Learn about the history or folklore of these trees.');
INSERT INTO badge_optional_requirements VALUES(8571,679,8,'Create a tree craft. You might make a card, painting, woodworking project, etc.');
INSERT INTO badge_optional_requirements VALUES(8572,679,9,'Create a game to help other kids learn about the photosynthetic process.');
INSERT INTO badge_optional_requirements VALUES(8573,679,10,'Learn about tree breeding. What is grafting and how does it work to one’s advantage? What is a seed orchard?');
INSERT INTO badge_optional_requirements VALUES(8574,679,11,'How are trees used for medicinal purposes? What tree’s bark is used in chemotherapy? What kind of bark was the first aspirin? How about the Melaleuca tree? What is it used in?');
INSERT INTO badge_optional_requirements VALUES(8575,679,12,'Using folklore from any type of tree write a story centered on it.');
INSERT INTO badge_optional_requirements VALUES(8576,679,13,'What kind of animals depend on trees for their survival? Where do they live?');
INSERT INTO badge_optional_requirements VALUES(8577,679,14,'Learn at least 3 ways that people in ancient times used trees.');
INSERT INTO badge_optional_requirements VALUES(8578,679,15,'Find out what the tallest trees in the world are. Where do they grow? Either visit one, or look at pictures online or in a book (with permission from your parent). How old are some of these trees?');
INSERT INTO badge_optional_requirements VALUES(8579,679,16,'Take a hike and note how many different trees you can find. How many can you identify?');
INSERT INTO badge_optional_requirements VALUES(8580,679,17,'What careers are there that involve trees? Examples might include a forest ranger, orchard manager, or botanist. What education and training do you need? What salary could you expect? What type of hours might you have to work? Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(8581,679,18,'Help with a tree planting service project.');
INSERT INTO badge_optional_requirements VALUES(8582,679,19,'Draw the life cycle of a particular tree including how it changes seasonally.');
INSERT INTO badge_optional_requirements VALUES(8583,681,3,'Be able to explain the difference between a friendly and unfriendly amendment, and between a moderated and unmoderated caucus.');
INSERT INTO badge_optional_requirements VALUES(8584,681,4,'Learn about the World Health Organization, a special agency of the U.N. What does it do?');
INSERT INTO badge_optional_requirements VALUES(8585,681,5,'What does the Security-General of the United Nations do? Who is the current U.N. Security-General?');
INSERT INTO badge_optional_requirements VALUES(8586,681,6,'What other events or organizations led up to the creation of the United Nations? What was the League of Nations?');
INSERT INTO badge_optional_requirements VALUES(8587,681,7,'Many schools, especially high schools and colleges, have Model United Nations teams. They simulate real U.N. committees and roleplay as U.N. delegates. Represent a country in a Model U.N. conference.');
INSERT INTO badge_optional_requirements VALUES(8588,681,8,'The United Nations started with only fifty member states. It now has one-hundred and ninety-three. Find a list of them. Were there any countries that you were surprised are members of the U.N.? List at least three countries who are not members of the U.N. Who are they?');
INSERT INTO badge_optional_requirements VALUES(8589,681,9,'Learn what it means for a country to have “veto power.” There are five countries with permanent places on the Security Council, and they wield veto power. Which countries are they? Level 4 – 5: Do you agree that they are the most appropriate countries to hold veto power? Some people don’t feel any countries should hold veto power – what do you think?');
INSERT INTO badge_optional_requirements VALUES(8590,681,10,'Learn about U.N. peacekeeping missions and peacekeeping forces. Which countries contribute the most troops to peacekeeping forces? What factors do you think cause these countries to contribute the most peacekeepers?');
INSERT INTO badge_optional_requirements VALUES(8591,681,11,'Learn about UNICEF, the United Nations International Children’s Emergency Fund. What kind of work do they do?');
INSERT INTO badge_optional_requirements VALUES(8592,682,3,'Learn about commemorative stamps and how the subjects for the stamps are selected.  If possible, make a collection of these stamps, or view a collection belonging to someone else.');
INSERT INTO badge_optional_requirements VALUES(8593,682,4,'Look through your town and find examples of where public property as been abused or misused. What can be done to help prevent this abuse?');
INSERT INTO badge_optional_requirements VALUES(8594,682,5,'Take a tour of a government building, office, or department.');
INSERT INTO badge_optional_requirements VALUES(8595,682,6,'Volunteer to help with a service project that benefits your country.  This may be supporting our soldiers in some way, planting trees in a national forest, or even helping with a coastal clean up.');
INSERT INTO badge_optional_requirements VALUES(8596,682,7,'Read the Bill of Rights.  How does this affect your daily life?');
INSERT INTO badge_optional_requirements VALUES(8597,682,8,'Learn about the history of town meetings, secret ballots, and elected leaders.');
INSERT INTO badge_optional_requirements VALUES(8598,682,9,'Know what religious groups are most common in America.  How do these groups help better our country?');
INSERT INTO badge_optional_requirements VALUES(8599,682,10,'Make a list of taxes that YOU pay.  What taxes will you pay as an adult?  What is the tax money used for?  Be able to list at least three services you use that are paid for by either Federal or State taxes.');
INSERT INTO badge_optional_requirements VALUES(8600,682,11,'Research a large government project.  This may be a new government building, reforestation, or even agricultural experiments.');
INSERT INTO badge_optional_requirements VALUES(8601,682,12,'Assist in a citizen education class.');
INSERT INTO badge_optional_requirements VALUES(8602,682,13,'Take a survey of at least 25 people outside your family to find out how many were born outside the U.S. or whose parents were born outside the U.S.   How many speak another language?');
INSERT INTO badge_optional_requirements VALUES(8603,683,3,'Create upcycled gifts to give to a friend or family member for their birthday or another holiday.');
INSERT INTO badge_optional_requirements VALUES(8604,683,4,'Upcycle an old t-shirt into something new!');
INSERT INTO badge_optional_requirements VALUES(8605,683,5,'Upcycle parts of old board games that are missing pieces or broken! (Scrabble pieces can become jewelry, boards can become shelves or journals…  and so much more!)');
INSERT INTO badge_optional_requirements VALUES(8606,683,6,'Create a pretty and practical storage solution by upcycling old items (mismatched or chipped dishes, food containers, and much more can become beautiful new items!)');
INSERT INTO badge_optional_requirements VALUES(8607,683,7,'Are there items that your class or troop throw away or recycle that can be turned into something new?  Create an example, and share with your teacher or troop leader!');
INSERT INTO badge_optional_requirements VALUES(8608,683,8,'Make a list of 6 simple items you need around the house such as storage trays for the bathroom drawer, a new nightstand, a lamp, a bookcase, a desk organizer, or a totebag.  Figure out how much money you would spend if you bought those items new.  Now find upcycle project ideas to create each of the items on your list.  How much money could you save on each item by upcycling instead of buying new?  Choose one of the projects you found and make it.');
INSERT INTO badge_optional_requirements VALUES(8609,683,9,'Learn about a specific upcycle artist such as the steampunk sculptures of Sue Beatrice, or the tea cup floor designed by Yusuke Seki.  How did they get into upcycling?  What is the inspiration for their designs?  Where do they get their materials?');
INSERT INTO badge_optional_requirements VALUES(8610,683,10,'Participate in a community service project that involves upcycling.  Try volunteering at a community yard sale, teaching a class on upcycling for younger kids, or creating posters to educate people on the benefits of upcycling .');
INSERT INTO badge_optional_requirements VALUES(8611,683,11,'Create a dress or accessory by upcycling something you would normally throw away.');
INSERT INTO badge_optional_requirements VALUES(8612,683,12,'Visit an upcycle art gallery or view a wide variety of upcycled art online.  Who is your favorite artist? What materials do they use and how have them been transformed?');
INSERT INTO badge_optional_requirements VALUES(8613,683,13,'Learn about how shipping containers are upcycled into everything from homes to swimming pools.');
INSERT INTO badge_optional_requirements VALUES(8614,684,3,'Overgrown and abandoned areas can have poisonous plants. Learn to identify the poisonous plants in your area so you can avoid them while exploring.');
INSERT INTO badge_optional_requirements VALUES(8615,684,4,'Watch some videos or a documentary on urban exploration. What are they doing to be safe?  Did they do something that goes against the basic rules you’ve learned?');
INSERT INTO badge_optional_requirements VALUES(8616,684,5,'Pick 5 different things you saw either while exploring yourself or in a video you watched of someone else exploring. Make up a story about the location based on the items you chose.');
INSERT INTO badge_optional_requirements VALUES(8617,684,6,'Look at pictures of abandoned buildings. What building materials seem to hold up the best over time?');
INSERT INTO badge_optional_requirements VALUES(8618,684,7,'Discuss how you should handle personal waste while exploring. Even if there are already items of garbage at the site, should you litter?');
INSERT INTO badge_optional_requirements VALUES(8619,684,8,'Review important factors to consider when looking for a place to explore');
INSERT INTO badge_optional_requirements VALUES(8620,684,9,'Exploring is tough business! Make a nutritious trail mix that’d be good to take along on our exploration adventure!');
INSERT INTO badge_optional_requirements VALUES(8621,684,10,'How are we going to deal with changing weather should we experience it?');
INSERT INTO badge_optional_requirements VALUES(8622,684,11,'Earn the First Aid badge at your level');
INSERT INTO badge_optional_requirements VALUES(8623,684,12,'Participate in a community service project to help protect or restore your abandoned area');
INSERT INTO badge_optional_requirements VALUES(8624,685,3,'Learn at least 3 famous quotes about the U.S. Constitution.');
INSERT INTO badge_optional_requirements VALUES(8625,685,4,'Find out who wrote the constitution and when.  How did they do it?  What process did it have to go through before it was accepted?');
INSERT INTO badge_optional_requirements VALUES(8626,685,5,'Hold a special celebration for U.S. Constitution Day on September 17th.');
INSERT INTO badge_optional_requirements VALUES(8627,685,6,'Design a poster or craft project showing how you have benefited from the freedoms embodied in the U.S. Constitution.');
INSERT INTO badge_optional_requirements VALUES(8628,685,7,'Create a timeline from the founding of the constitution to the present of every change or addition that has been made.');
INSERT INTO badge_optional_requirements VALUES(8629,685,8,'If you could add an amendment to the constitution, what would it be?  How would you word it to make sure that others do not interpret your amendment differently than you intended it?  Why do you think this amendment is important enough to make into law for all Americans?');
INSERT INTO badge_optional_requirements VALUES(8630,685,9,'Create a poster or booklet to teach others about the constitution.');
INSERT INTO badge_optional_requirements VALUES(8631,685,10,'Participate in a community service project that has something to do with the constitution.');
INSERT INTO badge_optional_requirements VALUES(8632,685,11,'Research a career that has something to do with the constitution.  Examples might include politicians, judges, lawyers, lobbyists, law enforcement, or even journalists.  How does knowledge of the constitution effect their job?');
INSERT INTO badge_optional_requirements VALUES(8633,685,12,'Take a field trip to learn more about the constitution. You might go to Washington D.C., your state capital, an exhibit about the constitution, etc.');
INSERT INTO badge_optional_requirements VALUES(8634,685,13,'Rewrite the Bill of Rights in your own words.  What do each of these amendments mean to you? How do you interpret them?');
INSERT INTO badge_optional_requirements VALUES(8635,685,14,'Learn how a bill becomes a law.');
INSERT INTO badge_optional_requirements VALUES(8636,685,15,'Know what the Bill of Rights is and what rights it guarantees the American people.');
INSERT INTO badge_optional_requirements VALUES(8637,685,16,'Know the original 13 colonies and create a map that shows them.');
INSERT INTO badge_optional_requirements VALUES(8638,685,17,'Listen to school house Rock “Preamble”, put into your own words what the”preamble” means');
INSERT INTO badge_optional_requirements VALUES(8639,686,3,'Earn the state badge your state and for at least one other..');
INSERT INTO badge_optional_requirements VALUES(8640,686,4,'What is GPS and how does it work?  Find the satellite coordinates for your home.');
INSERT INTO badge_optional_requirements VALUES(8641,686,5,'Recite all 50 states. (There are songs on youtube to help with this).');
INSERT INTO badge_optional_requirements VALUES(8642,686,6,'U.S. Military Bases are also considered U.S. Territory. Find at least 6 on a map.');
INSERT INTO badge_optional_requirements VALUES(8643,686,7,'Read a book that is set in a specific state and/or city. Look the location up on a map. Examples: Sam the Minuteman (set in Boston, MA), Many of the American Girl books have a specific locations as well.');
INSERT INTO badge_optional_requirements VALUES(8644,686,8,'Read an age-appropriate magazine article that is located in a certain state in the U.S. Find the location on the map. Good sources are Your Big Backyard, Ranger Rick, Click Magazine, Muse, Ask, National Geographic for Kids etc.');
INSERT INTO badge_optional_requirements VALUES(8645,686,9,'Earn the Map Reading Badge.');
INSERT INTO badge_optional_requirements VALUES(8646,686,10,'Find the location of our National Parks on a map.   Preschool find 3, Level 1 find 5, Level 2 find 10, Level 3 find 15, Level 4 find 20 and Level 5 find 25.');
INSERT INTO badge_optional_requirements VALUES(8647,686,11,'Identify the following on a map of the U.S.: –Mississippi River –Erie Canal –The Great Lakes, and if you are a higher level, be able to identify which lake is which –Rio Grande –Appalachian Mountains –Rocky Mountains –Great Plains –East Coast –West Coast');
INSERT INTO badge_optional_requirements VALUES(8648,686,12,'Find each of the 6 major mountain ranges in the U.S. on a map.');
INSERT INTO badge_optional_requirements VALUES(8649,686,13,'There are 7 major rivers in the U.S. Identify them on a map.');
INSERT INTO badge_optional_requirements VALUES(8650,686,14,'Know which states are considered to be in each of the following categories: –Pacific Northwest –Southwest –Midwest –Southern –Northeast');
INSERT INTO badge_optional_requirements VALUES(8651,686,15,'Look on a map to find the borders of the various time zones.  Which states are included in which zone?  What zone are you in?  If it was 5:00pm your time, what time would be in California?  What time would it be in New York?');
INSERT INTO badge_optional_requirements VALUES(8652,686,16,'Know which states were the 13 original colonies. Find them on a map of the U.S.   Label them on a paper map.');
INSERT INTO badge_optional_requirements VALUES(8653,686,17,'Put together an age appropriate puzzle of the U.S.');
INSERT INTO badge_optional_requirements VALUES(8654,686,18,'Color blank map of the U.S.   Preschool: Write the 2 letter abbreviation on your state. Level 1: Write the 2 letter abbreviation on all states. Level 2: Write the full name on each state. You may use numbers to mark the smaller states and write the state name in the margin next to a corresponding number. Level 3 – Level 5: Do Level 2 requirement, but write capital AND state.');
INSERT INTO badge_optional_requirements VALUES(8655,687,3,'Make a list of all of the government jobs you can think of. With an adult, look up city, county and state government offices in the phone book to get an idea of different jobs that run our government. Examples would include a postman, animal control, building and planning, waste management, police, or fire fighters.');
INSERT INTO badge_optional_requirements VALUES(8656,687,4,'Go to a place where government workers do their jobs and watch them in action. This can be anything from a courtroom to an office to a fire station.   Why do you think these jobs are done by the government and not private individuals?');
INSERT INTO badge_optional_requirements VALUES(8657,687,5,'Interview a government official to find out what citizens can do to make his job easier. Level 2:  What training or education do you need to do this job? Level 3: What kind of pay can you expect? What hours can you expect to work? Level 4 and Level 5:  Find out more about his/her responsibilities. With which current events does he or she interact the most?');
INSERT INTO badge_optional_requirements VALUES(8658,687,6,'Obtain photos of three (Preschool), five (Level 1), six (Level 2), seven (Level 3), eight (Level 4), nine (Level 5) government officials at the top or near the top of their departments. Learn their names, positions, and responsibilities.');
INSERT INTO badge_optional_requirements VALUES(8659,687,7,'Obtain a blank map of at least your state and some neighboring states. Find pencils or markers in three or four different shades of a color. Starting with a dark color for your town or city, mark the jurisdictions (Learn what that word means) in successively lighter shades until the largest jurisdiction of which you are a part is either very pale or you can leave it white. An example would be to mark your town in navy, your county/district/borough in royal blue, your state in light blue, and the neighboring states in very pale blue. Level 2: Make sure all the major cities on your map are labeled. Level 3: Also mark at least five of the most important natural features of your state such as rivers. Level 4 and Level 5:  Make a list or diagram of the four levels of government for where you live. Add other jurisdictions such as neighborhood councils, school districts and US district courts to show how they all fit together and who has authority over whom.');
INSERT INTO badge_optional_requirements VALUES(8660,687,8,'Pray for your elected or appointed officials every day for two weeks OR send two of them a card or letter of appreciation.');
INSERT INTO badge_optional_requirements VALUES(8661,687,9,'What other forms of government are used around the world? How do they differ from the U.S.government?');
INSERT INTO badge_optional_requirements VALUES(8662,687,10,'Choose an important event in history (an example would be the invention of the automobile) and list ways that event influenced government and ways that government influenced either the event itself or the consequences of that event (think of all the laws related to traffic).');
INSERT INTO badge_optional_requirements VALUES(8663,687,11,'What is the difference between being elected and being appointed? Give three examples of each. Which government workers apply for their jobs and have to pass various tests rather than being appointed or elected? Level 4: Go over a ballot with a voting adult. Discuss the pros and cons of the different measures and candidates. There must be at least five items on the ballot. Level 5: Go over a ballot. Discuss the pros and cons of the different measures and candidates. There must be at least five items on the ballot.');
INSERT INTO badge_optional_requirements VALUES(8664,687,12,'The military is part of which branch of government? Study the chain of command of one branch of the military. Name five famous military personnel who later went into other government jobs. Level 3 – Level 5 in addition: Learn the history of the Pentagon.');
INSERT INTO badge_optional_requirements VALUES(8665,687,13,'What branch of government are commissions, bureaus, and agencies usually under? Why are they in existence? Can you find one that you think does a really important job? Is there one you can find that looks to be unnecessary? With what size budgets do they work? What is the largest one you can find and which is the smallest?');
INSERT INTO badge_optional_requirements VALUES(8666,687,14,'Tour your state capitol or Washington DC for a day. You must visit at least three different offices or historic government buildings.');
INSERT INTO badge_optional_requirements VALUES(8667,687,15,'Level 2 and above: Read a book or watch a movie that explains how laws are made by a legislature. Level 3 – Level 5 also: Find out how propositions can get put on ballots instead of coming from a legislature. What percentage of voters needs to petition your state before a measure is put on a ballot?');
INSERT INTO badge_optional_requirements VALUES(8668,687,16,'Level 3 – Level 5 only:  Volunteer for at least two hours at a government office such as a police department or with a group that augments government work such as a docent in a state park or with a clean-up crew in your town.');
INSERT INTO badge_optional_requirements VALUES(8669,687,17,'Earn the Presidents badge at your level.');
INSERT INTO badge_optional_requirements VALUES(8670,688,3,'Visit a famous historical site and learn about it.');
INSERT INTO badge_optional_requirements VALUES(8671,688,4,'Make a timeline of major wars that America has participated in and understand why we were involved. Preschool list 5, Levels 1 and 2 list 10, Level 3 and Up list 15.');
INSERT INTO badge_optional_requirements VALUES(8672,688,5,'Watch a movie about part of American History.');
INSERT INTO badge_optional_requirements VALUES(8673,688,6,'Read a book about part of American History.');
INSERT INTO badge_optional_requirements VALUES(8674,688,7,'Learn at least traditional patriotic songs and the history behind them. Preschool learn two, Levels 1 and 2 learn four, Level 3 and Up learn six. Examples might include: National Anthem, God Bless America, She’s a Grand Old Flag, This Land is Your Land, America the Beautiful, Yankee Doodle Dandy, Star Spangled Banner, Dixie, Stars and Stripes Forever, God Bless the USA, When Johnny Comes Marching Home Again, etc.');
INSERT INTO badge_optional_requirements VALUES(8675,688,8,'Visit a museum or exhibit about American History.');
INSERT INTO badge_optional_requirements VALUES(8676,688,9,'Learn about the history of American immigrants and Ellis Island. Dolphins and up: Research at least one particular group of immigrants such as Irish, Italian, Mexican, or French. Why did they come and where did they settle?');
INSERT INTO badge_optional_requirements VALUES(8677,688,10,'Learn about the pilgrims and the role that American Indians played in their survival.');
INSERT INTO badge_optional_requirements VALUES(8678,688,11,'Learn about the various Indian tribes in America and how the Indian reservations came about.');
INSERT INTO badge_optional_requirements VALUES(8679,688,12,'Learn about important American inventors and what they invented. Preschool learn about two, Levels 1 and 2 learn about four, Level 3 and Up learn about six. Examples might include: Benjamin Franklin, Alexander Graham Bell, Samuel Colt, the Wright Brothers, Henry Ford, Eli Whitney, Charles Goodyear, Robert Fulton, Willis Carrier, Samuel F.B. Morse, etc.');
INSERT INTO badge_optional_requirements VALUES(8680,688,13,'Find out when Black History month is and learn about at least three black Americans who had an impact on American history.');
INSERT INTO badge_optional_requirements VALUES(8681,688,14,'What is meant by having the “Pioneer Spirit?” Learn about the pioneers and the western expansion of the U.S.');
INSERT INTO badge_optional_requirements VALUES(8682,688,15,'Learn about the Pony Express and draw a map of its route. Know the requirements for being a rider and what they carried with them.');
INSERT INTO badge_optional_requirements VALUES(8683,688,16,'Learn about the history of the railroad in America. View a map of the transcontinental rail lines.');
INSERT INTO badge_optional_requirements VALUES(8684,688,17,'Find famous quotations from historical Americans. Learn who said them and in what context. Preschool learn about five, Levels 1 and 2 learn about ten, Level 3 and Up learn about fifteen.');
INSERT INTO badge_optional_requirements VALUES(8685,688,18,'Pick popular songs from various time periods and discuss how they reflect their times both in lyrics and musical style. Preschool – Level 2 pick five. Level 3 and Up pick eight.');
INSERT INTO badge_optional_requirements VALUES(8686,688,19,'Rewrite the Declaration of Independence using your own words.');
INSERT INTO badge_optional_requirements VALUES(8687,688,20,'Learn about the Gold Rush and its effect on western expansion.');
INSERT INTO badge_optional_requirements VALUES(8688,688,21,'Pick three U.S. Presidents and learn at least five facts about each.');
INSERT INTO badge_optional_requirements VALUES(8689,688,22,'Explain the National Register of Historic Places and how a property is added to the list. Then make a map of historic sites in your area and identify which ones are on the National Register. Are there any local sites that you feel should be listed that are not?');
INSERT INTO badge_optional_requirements VALUES(8690,688,23,'Learn about a career related to U.S. history. What type of education would you need? What type of pay could you expect? What type of hours might you work? Where might you live?');
INSERT INTO badge_optional_requirements VALUES(8691,688,24,'Study the lives and accomplishments of three historical figures, one from politics, one from business,  and one from another area of life, and compare their roles in and contributions to America’s heritage.');
INSERT INTO badge_optional_requirements VALUES(8692,688,25,'Interview three military veterans about their experiences and what they see as their role in history.');
INSERT INTO badge_optional_requirements VALUES(8693,688,26,'Study a local event of historical importance to our country (visiting the site if possible) and discuss its effects on our nation.');
INSERT INTO badge_optional_requirements VALUES(8694,688,27,'Listen to, or read, at least three famous American speeches. Why do you think these speeches are still remembered and quoted many years later?');
INSERT INTO badge_optional_requirements VALUES(8695,688,28,'Learn about the Great Depression, Black Tuesday and the New Deal.');
INSERT INTO badge_optional_requirements VALUES(8696,688,29,'Learn about the history of slavery in America and how slaves helped to build our country. Websites: These websites are not associated with our program and we cannot guarantee their content. Please do not surf the internet without your parent’s permission. Great site for all types of US history Great resource for history games & quizzes Fun website with trivia facts about US Presidents');
INSERT INTO badge_optional_requirements VALUES(8697,689,3,'Write a report about a president.  This can be repeated.');
INSERT INTO badge_optional_requirements VALUES(8698,689,4,'Attend a parade, political rally, celebration, or any gathering where you get to see a president or  former president.');
INSERT INTO badge_optional_requirements VALUES(8699,689,5,'Be able to identify by portrait seven of the presidents you learned for #1.  This requirement can be repeated.');
INSERT INTO badge_optional_requirements VALUES(8700,689,6,'Visit the birthplace, monument, home, or presidential library of a president.  This requirement can be repeated.');
INSERT INTO badge_optional_requirements VALUES(8701,689,7,'Tour the White House.');
INSERT INTO badge_optional_requirements VALUES(8702,689,8,'Memorize the names of the wives of the presidents you learned for #1.  Research what the life of a First Lady is like.');
INSERT INTO badge_optional_requirements VALUES(8703,689,9,'Write to the president to encourage him or thank him for something he did.');
INSERT INTO badge_optional_requirements VALUES(8704,689,10,'Research music that has been written for presidential functions.  See if you can find at least three pieces and listen to a recording of them or play them on an instrument so you can see what they sound like.');
INSERT INTO badge_optional_requirements VALUES(8705,689,11,'Memorize the dates of five presidents'' administrations in order.');
INSERT INTO badge_optional_requirements VALUES(8706,689,12,'Read three different inaugural addresses.  Which ones do you like the best and why?');
INSERT INTO badge_optional_requirements VALUES(8707,689,13,'Learn about the presidential seal and the symbolism behind it.');
INSERT INTO badge_optional_requirements VALUES(8708,691,3,'Visit a farm that grows vegetables and sells them.');
INSERT INTO badge_optional_requirements VALUES(8709,691,4,'Learn about the botanical families that different vegetables are in.  Find out about at least 2 families and locate all the common members you can find at the grocery store.');
INSERT INTO badge_optional_requirements VALUES(8710,691,5,'Eat one vegetable in four different ways such as:  raw, boiled, steamed, baked, sautéed, cooked after being frozen, grilled, creamed, or broiled.');
INSERT INTO badge_optional_requirements VALUES(8711,691,6,'Volunteer at a community vegetable garden or seed bank.');
INSERT INTO badge_optional_requirements VALUES(8712,691,7,'Preserve at least three vegetables using at least one method such as drying, freezing or canning.');
INSERT INTO badge_optional_requirements VALUES(8713,691,8,'Grow at least three vegetables in your garden and prepare them in at least two ways each.');
INSERT INTO badge_optional_requirements VALUES(8714,691,9,'Choose a vegetable and serve it three different ways, one for breakfast, one for lunch, and one for dinner.');
INSERT INTO badge_optional_requirements VALUES(8715,691,10,'Create garnishes using two different vegetables.');
INSERT INTO badge_optional_requirements VALUES(8716,691,11,'Make a craft using vegetables, such as a Mr. Potato Head out of a real potato.');
INSERT INTO badge_optional_requirements VALUES(8717,691,12,'Visit an ethnic market and find out about some of their unusual vegetables.  Learn where they originated and which ethnic groups use them a lot in their cooking.  Find a recipe for each (you don’t have to prepare the recipe, just make sure you taste the vegetable).');
INSERT INTO badge_optional_requirements VALUES(8718,691,13,'Use two vegetables in a dish that combines vegetables and a bread product (think pot pie, pizza, quiche, etc.).');
INSERT INTO badge_optional_requirements VALUES(8719,691,14,'Use a vegetable in a dessert such as pumpkin pie or carrot cake.');
INSERT INTO badge_optional_requirements VALUES(8720,691,15,'Use at least two vegetables while making food for a needy family.');
INSERT INTO badge_optional_requirements VALUES(8721,691,16,'Take a vegetable and use it in a ‘one-pot’ meal such as a stew.');
INSERT INTO badge_optional_requirements VALUES(8722,691,16,'Make a vegetable soup.');
INSERT INTO badge_optional_requirements VALUES(8723,691,17,'Make a vegetable salad using at least 7 vegetables.');
INSERT INTO badge_optional_requirements VALUES(8724,691,18,'Make a Coleslaw using at least 4 vegetables.');
INSERT INTO badge_optional_requirements VALUES(8725,691,19,'Make a salad that combines fruit and vegetables.');
INSERT INTO badge_optional_requirements VALUES(8726,691,20,'Make a piece of art work about vegetables.  This can be a picture, sculpture, etc');
INSERT INTO badge_optional_requirements VALUES(8727,692,3,'Visit a farm or garden that grows your vegetable. If possible, pick some of your own.');
INSERT INTO badge_optional_requirements VALUES(8728,692,4,'Plant your vegetable either by seed or seedling. Study how long your vegetable takes to grow and what care it needs. Create a planting and watering schedule.');
INSERT INTO badge_optional_requirements VALUES(8729,692,5,'Eat your  vegetable prepared in four different ways such as:  raw, baked, sautéed, frozen, or grilled,');
INSERT INTO badge_optional_requirements VALUES(8730,692,6,'Volunteer at a community garden or seed bank.');
INSERT INTO badge_optional_requirements VALUES(8731,692,7,'Preserve your vegetable using at least one method such as drying, pickling, freezing or canning.');
INSERT INTO badge_optional_requirements VALUES(8732,692,8,'Find out what careers involve your vegetable  – examples might include: Farmer, Produce Manager, Vegetable Stand Owner, or Chef. What education is needed for this job? What type of pay could you expect? What type of hours might you need to work? Where might you need to live?');
INSERT INTO badge_optional_requirements VALUES(8733,692,9,'Prepare your vegetable and serve it three different ways, one for breakfast, one for lunch, and one for dinner.');
INSERT INTO badge_optional_requirements VALUES(8734,692,10,'Create garnishes using your  vegetable .');
INSERT INTO badge_optional_requirements VALUES(8735,692,11,'Learn how your vegetable is harvested—by hand or machine—and what happens between the farm and your grocery store.');
INSERT INTO badge_optional_requirements VALUES(8736,692,12,'Find out if other countries and cultures enjoy your vegetable . Prepare a recipe from another country featuring your vegetable .');
INSERT INTO badge_optional_requirements VALUES(8737,692,13,'Find out how your  vegetable is stored and transported to grocery stores');
INSERT INTO badge_optional_requirements VALUES(8738,692,15,'Learn how to juice your vegetable and try the fresh juice.');
INSERT INTO badge_optional_requirements VALUES(8739,692,16,'Find out where your vegetable grows and in what type of climate. What is the growing season?');
INSERT INTO badge_optional_requirements VALUES(8740,692,17,'Research one pest or disease that affects your vegetable and learn how farmers or gardeners deal with it.');
INSERT INTO badge_optional_requirements VALUES(8741,692,18,'Study how your vegetable contributes to sustainable farming or crop rotation.');
INSERT INTO badge_optional_requirements VALUES(8742,692,19,'Learn how your vegetable is processed for sale—washed, peeled, packaged, or canned—and what that process looks like.');
INSERT INTO badge_optional_requirements VALUES(8743,692,20,'Find out what pollinators help your vegetable grow and draw a diagram of the relationship between plant and pollinator.');
INSERT INTO badge_optional_requirements VALUES(8744,694,3,'Attend a Veteran’s Day service/ceremony');
INSERT INTO badge_optional_requirements VALUES(8745,694,4,'Earn a war badge ( WWI, WWII, Korea, Vietnam, etc.)');
INSERT INTO badge_optional_requirements VALUES(8746,694,5,'Do a community service project for VFW, American Legion, or similar veterans organization.');
INSERT INTO badge_optional_requirements VALUES(8747,694,6,'Help pass out poppies (does not count for #5).');
INSERT INTO badge_optional_requirements VALUES(8748,694,7,'Write an essay about veterans and why they have earned our respect.');
INSERT INTO badge_optional_requirements VALUES(8749,694,8,'Put together a scrapbook, shadow box, etc. to honor a vet.');
INSERT INTO badge_optional_requirements VALUES(8750,694,9,'Visit a veteran’s cemetery and help beautify by removing trash, planting flowers, posting flags, etc. (make sure to get permission from the cemetery management first.)');
INSERT INTO badge_optional_requirements VALUES(8751,694,10,'Earn a Military Services Branch badge.');
INSERT INTO badge_optional_requirements VALUES(8752,694,11,'Visit a veteran’s memorial or monument.');
INSERT INTO badge_optional_requirements VALUES(8753,694,12,'Earn the Honor badge.');
INSERT INTO badge_optional_requirements VALUES(8754,695,3,'Learn at least 5 veterinary terms and be able to explain what they mean to someone else.');
INSERT INTO badge_optional_requirements VALUES(8755,695,4,'Learn about jobs in the veterinary field, such as a veterinarian or a veterinary instructor. What are the hours, how much are the salaries/pay-rates, where would you have to live, etc.? Level 3 and up only: If possible, shadow a veterinarian for a day.');
INSERT INTO badge_optional_requirements VALUES(8756,695,5,'Earn one or more of the following badges at your current age level:  Pets or any pet specific animal animal badge such as the Cat badge or Dog badge; Farm Animals or any specific farm animal badge such as Goats or Pigs; Animals Around the World badge or any specific animal badge such as Elephants or Tigers.');
INSERT INTO badge_optional_requirements VALUES(8757,695,6,'Look at a map of your state or country. Which areas are most suitable for raising livestock? Are there any areas which are better for raising one sort of animal more than another? What would a vet in your part of the country have to deal with most?');
INSERT INTO badge_optional_requirements VALUES(8758,695,7,'Choose an animal and learn what diseases it is most prone to. How can you prevent these diseases? What would a veterinarian do to treat them?');
INSERT INTO badge_optional_requirements VALUES(8759,695,8,'Research different college options for those specializing in the veterinary field. How much do they cost, how long would it take to get your degree, what sort of facilities do they have, etc.?');
INSERT INTO badge_optional_requirements VALUES(8760,695,9,'At one time veterinarians did not exist as we know them today, so farmers had to treat their animals themselves. Learn about old-fashioned techniques and cures for various illnesses and diseases. If you are a Preschooler, learn about one disease and old methods of curing it; if you are at Level 1 or Level 2, learn about three diseases and methods of curing them; if you are at Level 3 or above, learn about five diseases and the methods of curing them.');
INSERT INTO badge_optional_requirements VALUES(8761,695,10,'Before tractors were invented many farmers used horses to do the jobs which tractors now do, such as pulling plows and wagons. This meant that a farmer had to take very good care of his horses or he would get nothing done on his farm. Earn the Horses badge at your level.');
INSERT INTO badge_optional_requirements VALUES(8762,695,11,'Learn how a veterinarian might help an animal give birth. What sort of equipment do they use?');
INSERT INTO badge_optional_requirements VALUES(8763,695,12,'How is the job of a veterinarian who works in a zoo or wildlife preserve different from a veterinarian who works with farm animals? Read a book, watch a video, or go online (with your parent’s permission) to find out.');
INSERT INTO badge_optional_requirements VALUES(8764,695,13,'Participate in a community service project that benefits veterinarians and/or animal health.');
INSERT INTO badge_optional_requirements VALUES(8765,695,14,'Shadow someone who works in a veterinarian office for a day.');
INSERT INTO badge_optional_requirements VALUES(8766,695,15,'Learn a song about veterinarians such as “Veterinarian” Songs about Professions by StoryBots/Netflix Jr.');
INSERT INTO badge_optional_requirements VALUES(8767,695,16,'Role play working as a veterinarian using stuffed animals with your friends.');
INSERT INTO badge_optional_requirements VALUES(8768,696,3,'With your parent’s permission, watch a documentary on the Vietnam War.');
INSERT INTO badge_optional_requirements VALUES(8769,696,4,'With your parent’s permission, listen to a selection of popular music of the period.');
INSERT INTO badge_optional_requirements VALUES(8770,696,5,'Read an age appropriate book about the Vietnam War.');
INSERT INTO badge_optional_requirements VALUES(8771,696,6,'Find out what Vietnamese people eat and make a Vietnamese meal.');
INSERT INTO badge_optional_requirements VALUES(8772,696,7,'Draw flags of the countries involved.');
INSERT INTO badge_optional_requirements VALUES(8773,696,8,'Learn about the Tet Offensive. What is the Tet holiday?');
INSERT INTO badge_optional_requirements VALUES(8774,696,9,'What are other names for the Vietnam War?');
INSERT INTO badge_optional_requirements VALUES(8775,696,10,'Find out what was happening here in the United States during the time of the Vietnam War. How did this affect the way returning soldiers were treated?');
INSERT INTO badge_optional_requirements VALUES(8776,696,11,'What is meant by the Cold War? What did this have to do with our sending soldiers to fight in Vietnam?');
INSERT INTO badge_optional_requirements VALUES(8777,696,12,'What was the Gulf of Tonkin incident? How did this change our involvement?');
INSERT INTO badge_optional_requirements VALUES(8778,696,13,'What is the Congressional Medal of Honor? When was it instituted? How many men earned the medal during the Vietnam War? Read a short biography of one of them.');
INSERT INTO badge_optional_requirements VALUES(8779,696,14,'Many times in learning about a war, we ourselves choose sides and decide who are the “good guys” and who are the “bad guys.”  If you are feeling this way, put yourself in someone else’s shoes. Research the “other” side and write a short essay about their reasons for the war. Learn about what life was like during and after the war from their point of view.');
INSERT INTO badge_optional_requirements VALUES(8780,696,15,'Visit a Vietnam War Memorial.');
INSERT INTO badge_optional_requirements VALUES(8781,696,16,'Learn about the Fall of Saigon and the Vietnamese refugees.');
INSERT INTO badge_optional_requirements VALUES(8782,696,17,'Create a timeline of the major events of the Vietnam War. (Level 2 10 items, Level 3 20, Level 4 and 5 25)');
INSERT INTO badge_optional_requirements VALUES(8783,696,18,'Learn about the draft and when in US history it has been used. Is it in effect today? What is Selective Service? Who needs to sign up?');
INSERT INTO badge_optional_requirements VALUES(8784,696,19,'Interview relatives, friends, or neighbors who are old enough to remember the War. Gather the memories of at least 3 different people. They can be veterans, women, men, people who remained on the home front, or even those who were just children. Create a booklet out of what you collected.');
INSERT INTO badge_optional_requirements VALUES(8785,696,20,'Participate in a community service project that benefits veterans of the Vietnam War. You might serve dinner at a local VFW post, entertain at a veteran’s hospital, or participate in a Veterans Day Parade.');
INSERT INTO badge_optional_requirements VALUES(8786,697,3,'Learn about Viking mythology: Preschool and Level 1: Be able to name at least 2 Viking gods. Level 2 and up: Be able to name at least 3 Viking gods and tell a little bit about each one. Level 4 and 5: Name at least 5 elements of Viking mythology and explain how it compares and contrasts with your faith.');
INSERT INTO badge_optional_requirements VALUES(8787,697,4,'Learn about Viking weapons, armor, and battle tactics.');
INSERT INTO badge_optional_requirements VALUES(8788,697,5,'Learn about runes. Write your name or a message using runes.');
INSERT INTO badge_optional_requirements VALUES(8789,697,6,'Prepare and/or eat a traditional Scandinavian dish such as Swedish meatballs or lefse.');
INSERT INTO badge_optional_requirements VALUES(8790,697,7,'Read a book about Vikings.');
INSERT INTO badge_optional_requirements VALUES(8791,697,8,'Build a model of a Viking boat incorporating at least 4 features that made Viking boats unique.');
INSERT INTO badge_optional_requirements VALUES(8792,697,9,'Create a Viking craft.');
INSERT INTO badge_optional_requirements VALUES(8793,697,10,'Learn about what kind of clothing Vikings wore, what their life was like, and what caused them to explore other countries.');
INSERT INTO badge_optional_requirements VALUES(8794,697,11,'Attend a Viking festival or other Scandinavian cultural event.');
INSERT INTO badge_optional_requirements VALUES(8795,697,12,'Play a Viking game.');
INSERT INTO badge_optional_requirements VALUES(8796,697,13,'Visit a Viking exhibit.');
INSERT INTO badge_optional_requirements VALUES(8797,697,14,'Watch a documentary about Vikings.');
INSERT INTO badge_optional_requirements VALUES(8798,699,3,'Try writing your own song in the style you have chosen.');
INSERT INTO badge_optional_requirements VALUES(8799,699,4,'Write an essay about your type of music. What makes it so special to you?');
INSERT INTO badge_optional_requirements VALUES(8800,699,5,'Pick your favorite band/music group that performs your style of music and learn about their history and how they got started. Tell your family or Club what you learned.');
INSERT INTO badge_optional_requirements VALUES(8801,699,6,'Attend a performance of your type of music. Do you know any of the songs played?');
INSERT INTO badge_optional_requirements VALUES(8802,699,7,'Make a poster, scrapbook page, collage, etc, that shows what you like about your favorite band or the type of music it plays. Show it to your family or Club.');
INSERT INTO badge_optional_requirements VALUES(8803,699,8,'Choose one of your favorite songs in your chosen variety of music and try to create a dance to go along with it.');
INSERT INTO badge_optional_requirements VALUES(8804,699,9,'Learn about careers in the music business, such as music or voice teachers, musicians, singers, songwriters, etc.');
INSERT INTO badge_optional_requirements VALUES(8805,699,10,'Pick a song or piece of music in your selected variety of music and learn the history behind it. If you cannot find any history behind your chosen song, learn who wrote it and why.');
INSERT INTO badge_optional_requirements VALUES(8806,699,11,'Make a list of song titles in your particular genre. Put them together so that they rhyme to create a poem. OR, do the same thing but only use titles from one singer or band.');
INSERT INTO badge_optional_requirements VALUES(8807,699,12,'Watch a music video or a selection of video clips of songs in your style of music. (Music video clips can be found on YouTube get your parent’s permission before going online.)');
INSERT INTO badge_optional_requirements VALUES(8808,699,13,'Learn to play a piece of music in your style on a musical instrument.');
INSERT INTO badge_optional_requirements VALUES(8809,699,14,'Look at a map and find at least five places that are connected in some way with your type of music, such as the birthplaces of famous singers/musicians, sites of concerts, etc.');
INSERT INTO badge_optional_requirements VALUES(8810,699,15,'Visit the birthplace or home of a famous person in your style of music. (An online tour is also acceptable.)');
INSERT INTO badge_optional_requirements VALUES(8811,699,16,'Find out if you know anyone who plays your type of music for dances, etc. Talk to them and ask how they got started and what attracted them to that particular style of music.');
INSERT INTO badge_optional_requirements VALUES(8812,699,17,'Some bands have given themselves names that seem rather peculiar. Make a list of bands in your style of music and see if there are any themes that suggest themselves to you, such as food or places.');
INSERT INTO badge_optional_requirements VALUES(8813,699,18,'Learn about any official music awards for your type of music. For instance, country music has the Country Music Awards, presented in Nashville.');
INSERT INTO badge_optional_requirements VALUES(8814,700,3,'Find out how your community honors volunteers.  If you can’t find any ways in your community, learn how some national organizations honor volunteers.');
INSERT INTO badge_optional_requirements VALUES(8815,700,4,'Find an organization that relies heavily on free volunteer labor.  Learn the % of hours or work done by volunteers versus paid staff.  How much money does each % represent?  How much money does the volunteering save?');
INSERT INTO badge_optional_requirements VALUES(8816,700,5,'Learn the history of an all-volunteer (90%+) organization.  Why is it all-volunteer?');
INSERT INTO badge_optional_requirements VALUES(8817,700,6,'Learn about people who spend all their time volunteering (35+ hours per week) with no pay.  How do they get money to eat and live?');
INSERT INTO badge_optional_requirements VALUES(8818,700,7,'Find out about financial accountability for non-profit organizations.  What is the difference between non-profit and all-volunteer?  What is the job of a fundraiser?  How does a fundraiser learn about wills and trusts?');
INSERT INTO badge_optional_requirements VALUES(8819,700,8,'What is a military draft?  What is an all-volunteer army?  When has our country had which kind of military and why?');
INSERT INTO badge_optional_requirements VALUES(8820,700,9,'Earn 3 (Preschool), 5 (Level 1), 7 (Level 2 and Level 3), 9 (Level 4 and Level 5) servant’s hearts.');
INSERT INTO badge_optional_requirements VALUES(8821,700,10,'Earn the Make-a-Difference award at your level.');
INSERT INTO badge_optional_requirements VALUES(8822,700,11,'Spend 5 (Level 2 and Level 3) 10 (Level 4 and Level 5) hours volunteering while being in charge of the project at hand.  This doesn’t have to be your idea.  You just need to be in charge. (Level 3 and up only) (The hours you spend doing this requirement must be separate from previous requirements.)');
INSERT INTO badge_optional_requirements VALUES(8823,700,12,'. Be responsible for all the set-up and clean-up for two service projects.');
INSERT INTO badge_optional_requirements VALUES(8824,700,13,'.  Learn about some famous volunteers. Read a biography or watch a movie about a volunteer (this can be done a second time by Level 4 and Level 5, but you must choose a different movie/biography).');
INSERT INTO badge_optional_requirements VALUES(8825,700,14,'.  Do a service project that is out of your comfort zone.  Discuss what this means with your leader first and make sure your project will count.  Report back to your leader when you are done.');
INSERT INTO badge_optional_requirements VALUES(8826,700,15,'Write thank-you notes to 2 (Preschool), 3 (Level 1), 6 (Level 2 and Level 3), 8 (Level 4 and Level 5) people who have volunteered to help with a project.  It does not have to be your project.  Sometimes it is very helpful for leaders to have assistance in expressing thanks to their helpers.');
INSERT INTO badge_optional_requirements VALUES(8827,700,16,'Learn two verses from the Bible, your own book of faith, or other quotes about the importance of servant hood.');
INSERT INTO badge_optional_requirements VALUES(8828,704,3,'Create a model of a watershed and show how the water flows and where it collects.');
INSERT INTO badge_optional_requirements VALUES(8829,704,4,'Visit a nearby river or stream, noting its flow, depth, and any visible signs of pollution.  Where does the water come from?  Where does it go?');
INSERT INTO badge_optional_requirements VALUES(8830,704,5,'Explore a local lake, documenting its characteristics and potential threats to its health.');
INSERT INTO badge_optional_requirements VALUES(8831,704,6,'Identify at least five plant and five animal species that rely on the watershed for survival.');
INSERT INTO badge_optional_requirements VALUES(8832,704,7,'Explain the processes of erosion and sedimentation within a watershed.');
INSERT INTO badge_optional_requirements VALUES(8833,704,8,'Understand the difference between point source and non-point source pollution. Provide examples specific to your local watershed.');
INSERT INTO badge_optional_requirements VALUES(8834,704,9,'Evaluate the impact of human activities on the watershed, both positive and negative.');
INSERT INTO badge_optional_requirements VALUES(8835,704,10,'Visit a wetland within the watershed and describe its role in maintaining water quality.');
INSERT INTO badge_optional_requirements VALUES(8836,704,11,'Conduct basic water quality tests on water found in your local watershed such as pH and turbidity.  Discuss how the results affect the plants and animals in the area.');
INSERT INTO badge_optional_requirements VALUES(8837,704,12,'Propose and discuss at least three strategies to prevent both point and non-point source pollution in your local watershed.');
INSERT INTO badge_optional_requirements VALUES(8838,704,13,'Make a map of your local watershed.');
INSERT INTO badge_optional_requirements VALUES(8839,704,14,'Investigate how the watershed has changed over the past century, including human-induced alterations.');
INSERT INTO badge_optional_requirements VALUES(8840,704,15,'Develop or participate in a community outreach initiative to raise awareness about watershed conservation.');
INSERT INTO badge_optional_requirements VALUES(8841,704,16,'Find out what local organizations are actively involved in watershed conservation.  How do they help?  How can you get involved?');
INSERT INTO badge_optional_requirements VALUES(8842,704,17,'Take a field trip to a relevant watershed management facility or organization.');
INSERT INTO badge_optional_requirements VALUES(8843,704,18,'Create anartistic representation of your local watershed, highlighting its beauty and importance.');
INSERT INTO badge_optional_requirements VALUES(8844,704,19,'Participate in a citizen science project related to watershed monitoring or conservation.');
INSERT INTO badge_optional_requirements VALUES(8845,704,20,'Visit a local lake.  How does it get its water?  What are potential threats to its health?');
INSERT INTO badge_optional_requirements VALUES(8846,704,21,'Trace the path of water from its origin in the watershed to where it enters a bay in the ocean.  What pollution can affect the water along the way?');
INSERT INTO badge_optional_requirements VALUES(8847,705,3,'Read a book about watercolor techniques.');
INSERT INTO badge_optional_requirements VALUES(8848,705,4,'Look at a watercolor book, pick 3 favorite paintings, describe the paintings to someone, include topics such as light, perspective, and color.');
INSERT INTO badge_optional_requirements VALUES(8849,705,5,'Go to an art museum or visit an online art museum that has watercolor artworks on display.');
INSERT INTO badge_optional_requirements VALUES(8850,705,6,'Read about the life of a famous watercolors artist.');
INSERT INTO badge_optional_requirements VALUES(8851,705,7,'Create a piece of watercolor artwork and give it to someone.');
INSERT INTO badge_optional_requirements VALUES(8852,705,8,'Attend an art class on watercolors.');
INSERT INTO badge_optional_requirements VALUES(8853,705,9,'Enter your artwork in an art contest or fair.');
INSERT INTO badge_optional_requirements VALUES(8854,705,10,'Create a color wheel using watercolor paints.   Divide the wheel into a minimum of 12 segments.');
INSERT INTO badge_optional_requirements VALUES(8855,705,11,'Paint a watercolor picture of one of the following: a)  Animals b)  Flowers:  Draw directly from the growing plant or make your own arrangement of cut flowers. c)  The human figure d)  Still life:  Arrange groups of familiar objects –books,  a vase, toys, and so forth. e.)  Landscape f.)  Cityscape');
INSERT INTO badge_optional_requirements VALUES(8856,706,3,'Know your local and state laws for owning and using your weapon.');
INSERT INTO badge_optional_requirements VALUES(8857,706,4,'Look at a catalog or website (with parent’s permission) that sells your weapon. Can you still buy them?');
INSERT INTO badge_optional_requirements VALUES(8858,706,5,'Discover a famous battle when your weapon was used. What happened?');
INSERT INTO badge_optional_requirements VALUES(8859,706,6,'If you are studying a projectile weapon, draw a picture illustrating the trajectory of something shot from your weapon. Does it travel in a straight line or a curved line? What does this tell you about where to aim?');
INSERT INTO badge_optional_requirements VALUES(8860,706,7,'Find examples of your weapon being used in movies or television. What are some famous examples?');
INSERT INTO badge_optional_requirements VALUES(8861,706,8,'Design and draw your own version of your weapon. How would you improve it or change it?');
INSERT INTO badge_optional_requirements VALUES(8862,706,9,'What type of ammunition does your weapon use?  Is it still available today?  If so, what are the rules for purchasing it?');
INSERT INTO badge_optional_requirements VALUES(8863,706,10,'Build a model or replica of your weapon.');
INSERT INTO badge_optional_requirements VALUES(8864,706,11,'Create an artwork of your weapon. This could be drawing, sculpture, etc.');
INSERT INTO badge_optional_requirements VALUES(8865,706,12,'Do a community service project about your weapon. Examples may include helping a museum that has your weapon.');
INSERT INTO badge_optional_requirements VALUES(8866,706,13,'Some live action role playing events may use your weapon.  Find out what events are near you and if possible, visit one in person.');
INSERT INTO badge_optional_requirements VALUES(8867,706,14,'Listen to a song that mentions your weapon.');
INSERT INTO badge_optional_requirements VALUES(8868,706,15,'Read a story that includes your weapon.');
INSERT INTO badge_optional_requirements VALUES(8869,706,16,'If your weapon is a blade, learn the proper way to keep it sharp.');
INSERT INTO badge_optional_requirements VALUES(8870,706,17,'Find out how your weapon is made');
INSERT INTO badge_optional_requirements VALUES(8871,706,18,'Learn about a famous weapon designer who made weapons such as the one you are studying.  Why were their weapons preferred over other manufacturers of similar weapons?');
INSERT INTO badge_optional_requirements VALUES(8872,706,19,'Learn how to properly clean or maintain your weapon.');
INSERT INTO badge_optional_requirements VALUES(8873,707,3,'Be able to identify each of the following cloud types:  cumulus, stratus, cirrus, and nimbus.  Divide a piece of blue paper into four sections.  Glue cotton balls to each section to represent the different types of clouds and what they look like.');
INSERT INTO badge_optional_requirements VALUES(8874,707,4,'Compare at least 4 different photos of single type of weather event such as lightning, tornadoes, or hurricanes.  If possible, try to compare photography taken from the ground versus aerial photography of the same type of event.');
INSERT INTO badge_optional_requirements VALUES(8875,707,5,'Make a rain gauge and use it to check the amount of rainfall you get for one week.');
INSERT INTO badge_optional_requirements VALUES(8876,707,6,'Learn about the water cycle.  Be able to explain how water evaporates, condenses and falls back to earth as rain or snow.');
INSERT INTO badge_optional_requirements VALUES(8877,707,7,'Visit a meteorologist and learn how they predict the weather.');
INSERT INTO badge_optional_requirements VALUES(8878,707,8,'Find out how a rainbow is made.  Learn the colors in a rainbow and the order in which they appear.');
INSERT INTO badge_optional_requirements VALUES(8879,707,9,'Earn one of the following badges:  snow, tornadoes, hurricanes, rain, wind, weather forecasting, drought.');
INSERT INTO badge_optional_requirements VALUES(8880,707,10,'Learn the difference between rain, snow, sleet, and hail.');
INSERT INTO badge_optional_requirements VALUES(8881,707,11,'Learn what the six stages of a hurricane are:  Tropical Wave, Tropical Disturbance, Tropical Cyclone, Tropical Depression, Tropical Storm, and Hurricane.  Know how fast the winds are at each stage of the Saffir-Simpson hurricane scale and how much damage you can expect.');
INSERT INTO badge_optional_requirements VALUES(8882,707,12,'Learn how weather is predicted.  What models are used?  Which computer programs?');
INSERT INTO badge_optional_requirements VALUES(8883,707,13,'Learn about why we experience seasons, and how where you live on earth affects what type of weather you experience.  Why is it hotter at the equator and colder at the poles?  Why is it winter in Australia when it is summer in the USA?');
INSERT INTO badge_optional_requirements VALUES(8884,707,14,'Watch a documentary on weather.');
INSERT INTO badge_optional_requirements VALUES(8885,707,15,'Learn what a “front” is.  What is the difference between a warm front and a cold front?  What is an occluded front?  A stationary front?  A trough?  Learn to identify how to read each type of front on a weather map.');
INSERT INTO badge_optional_requirements VALUES(8886,707,16,'Learn about careers in weather such as meteorologists, TV weather woman, storm chasers, etc.');
INSERT INTO badge_optional_requirements VALUES(8887,707,17,'Waht is NOAA?  What is its function?  How does it affect your life?');
INSERT INTO badge_optional_requirements VALUES(8888,707,18,'Learn about the Beaufort scale to measure wind speed.  Who developed it, when and for what purpose?  How is it used today?');
INSERT INTO badge_optional_requirements VALUES(8889,707,19,'Read a book about weather such as Magic School Bus:  Electric Storm');
INSERT INTO badge_optional_requirements VALUES(8890,707,20,'Learn about weather manipulati8on.  When were the first patents granted for weather manipulation technology?  How is it done?  What are its effects?  Does your home state actively use weather manipulation technology?');
INSERT INTO badge_optional_requirements VALUES(8891,707,21,'Make a barometer and check the air pressure for at least 3 days. You will need: •        small coffee can •        large balloon •        thin wooden skewer •        index card •        large rubber band (big enough to fit around the can) •        tape First, cut the end off the balloon and stretch the balloon over the top of the coffee can.  Use the rubber band to hold the balloon tightly in place.  Make sure it is air tight as any leakage will affect the reliability of your barometer. Next, place the skewer across the balloon so that the blunt end is in the center of the balloon and the sharp end sticks out over the edge of the can. Tape the skewer to the balloon so that it will not fall off. Draw horizontal lines across the index card every 1/8”.  Then tape the index card to the can behind the skewer. The skewer will act as a pointer on the card. Carefully record the location of the skewer on the index card with a pencil After 15 minutes, record the new location of the skewer on the index card. Continue checking and recording the location as often as you want. High pressure will make the balloon cave in and the straw go up.  High pressure usually means clear weather.   Low pressure will make the balloon puff up and the straw go down. Low pressure usually means cloudy or rainy weather. Websites:  These websites are not associated with our program and we cannot guarantee their content.  Please do not surf the internet without your parent’s permission. Weather Wiz Kids – Great site for all things weather related. http://www.weatherwizkids.com/ Great Weather Hands On Experiments http://eo.ucar.edu/webweather/activities.html');
INSERT INTO badge_optional_requirements VALUES(8892,708,3,'Name 3 materials that you can use for weaving.(4 for Level 1, 5 for Level 2, 6 for Level 3, 7 for Level 4, 8 for Level 5)');
INSERT INTO badge_optional_requirements VALUES(8893,708,4,'Visit a museum or gallery that has examples of weaving.  There are many examples of weaving Navajo blankets and also pioneer clothes and  rugs.');
INSERT INTO badge_optional_requirements VALUES(8894,708,5,'Create a woven gift to give to someone.');
INSERT INTO badge_optional_requirements VALUES(8895,708,6,'Weave outdoors using natural materials.');
INSERT INTO badge_optional_requirements VALUES(8896,708,7,'Weave a friendship bracelet.');
INSERT INTO badge_optional_requirements VALUES(8897,708,8,'Complete a finger-weaving projects, i.e.  Jumprope, cord, necklace.');
INSERT INTO badge_optional_requirements VALUES(8898,708,9,'Complete a larger weaving project like a rug or wall hanging.');
INSERT INTO badge_optional_requirements VALUES(8899,708,10,'Learn about famous weaving done by the Navajos or other modern weavers.');
INSERT INTO badge_optional_requirements VALUES(8900,708,11,'Make a collection of pictures of patterns and types of weaving for your use.');
INSERT INTO badge_optional_requirements VALUES(8901,708,12,'Find examples of weaving and arrange an exhibit of woven articles to show to family or friends.  Compare machine-woven and hand-woven pieces.');
INSERT INTO badge_optional_requirements VALUES(8902,708,13,'Make some natural dyes and use them to dye materials for your weaving.');
INSERT INTO badge_optional_requirements VALUES(8903,708,14,'Learn about commercial modern day looms.  How do they differ from old fashioned looms?  How do they work?  How fast can they go?  What is the quality difference between old and new looms?');
INSERT INTO badge_optional_requirements VALUES(8904,708,15,'Learn about the weaving industry.  What type of education would you need for a job in this industry?  What type of pay could you expect?  Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(8905,708,16,'Learn about Francis Cabot Lowell and the role he played in weaving history.  Learn about the town named after him as well as the “mill girls”.');
INSERT INTO badge_optional_requirements VALUES(8906,708,17,'Learn about at least three of the following loom types:  back strap, warp weighted, draw, hand, flying shuttle, haute-lisse, power, pit, circular, Dobby, free standing, or simple frame.');
INSERT INTO badge_optional_requirements VALUES(8907,709,3,'Look at pictures of wedding dresses. Which is your favorite? How have wedding fashions changed through time? When did white wedding dresses become “traditional”?  Level 3 and up: What does the color white symbolize?');
INSERT INTO badge_optional_requirements VALUES(8908,709,4,'Learn about at least 5 different wedding traditions in the world.');
INSERT INTO badge_optional_requirements VALUES(8909,709,5,'Plan your dream wedding.');
INSERT INTO badge_optional_requirements VALUES(8910,709,6,'Participate in a wedding as a member of the wedding party, i.e.: flower girl, bridesmaid, etc.');
INSERT INTO badge_optional_requirements VALUES(8911,709,7,'Usually when two people get married, the woman “takes on” the man’s surname (i.e.: when Maggie Blunt marries James Smith, she becomes Mrs. James Smith formally, and Mrs. Maggie Smith informally). Learn why this is so. What is a “Lucy Stoner”?');
INSERT INTO badge_optional_requirements VALUES(8912,709,8,'Learn why the bride usually wears a veil. When are the different veil lengths appropriate?');
INSERT INTO badge_optional_requirements VALUES(8913,709,9,'Look at pictures of different wedding and engagement rings. What are some famous rings?');
INSERT INTO badge_optional_requirements VALUES(8914,709,10,'Help do something to make a wedding wonderful for the bride and groom, such as helping to set tables or decorate the building.');
INSERT INTO badge_optional_requirements VALUES(8915,709,11,'Find out what is meant by a destination wedding. If you had a destination wedding, where would you go?');
INSERT INTO badge_optional_requirements VALUES(8916,709,12,'Attend a wedding.');
INSERT INTO badge_optional_requirements VALUES(8917,709,13,'Listen to some famous pieces of music that were written for weddings or have been used for weddings, such as the Bridal Chorus from Lohengrin by Richard Wagner; the Wedding March from A Midsummer Night’s Dream by Felix Mendelssohn; the Arrival of the Queen of Sheba from Solomon by George Frederick Handel; or the Trumpet Voluntary.');
INSERT INTO badge_optional_requirements VALUES(8918,709,14,'Learn about at least 1 (Preschool and Level 1), 2 (Levels 2-3), 3 (Levels 4-5) famous weddings, such as Prince Charles and Lady Diana, Prince Rainier of Monaco and Grace Kelly, Consuelo Vanderbilt and the 9th Duke of Marlborough, David Beckham and Victoria Adams, or Henry VIII and Catherine of Aragon.');
INSERT INTO badge_optional_requirements VALUES(8919,709,15,'Learn about royal weddings. Where are they usually held? If possible, watch a royal wedding.');
INSERT INTO badge_optional_requirements VALUES(8920,709,16,'Look at pictures of wedding cakes. Which do you like best? What traditions are there associated with the wedding cake? (For instance, in Britain the wedding cake is always a fruitcake.) What is a “groom’s cake”?');
INSERT INTO badge_optional_requirements VALUES(8921,709,17,'Learn about the Victorian Language of Flowers. What are some of the most popular flowers for weddings? What are their meanings?');
INSERT INTO badge_optional_requirements VALUES(8922,710,3,'Take a field trip to visit a welder at his/her shop.');
INSERT INTO badge_optional_requirements VALUES(8923,710,4,'(Level 2 and up) With the help of an experienced adult, weld two pieces of metal together.');
INSERT INTO badge_optional_requirements VALUES(8924,710,5,'Visit an art exhibit of welded sculptures.');
INSERT INTO badge_optional_requirements VALUES(8925,710,6,'Know the colors of at least three basic metals.   carbon steel – gray, cast iron – dark gray, stainless steel – silvery and has a shine, brass – yellow,  copper – reddish brown,  aluminum – light gray,  magnesium – dark gray,  pot metal/white metal – light gray to white,  lead – nonmagnetic medium to dark gray.');
INSERT INTO badge_optional_requirements VALUES(8926,710,7,'Understand the difference between ferrous and non-ferrous metals.  What are two ferrous metals? Make a pile of small metal objects and use a magnet to discover which are ferrous and which are not.');
INSERT INTO badge_optional_requirements VALUES(8927,710,8,'Learn what brazing is and when it is used.');
INSERT INTO badge_optional_requirements VALUES(8928,710,9,'Learn the history of welding.');
INSERT INTO badge_optional_requirements VALUES(8929,710,10,'Understand the difference between ferrous and non-ferrous metals.  What are two ferrous metals? Make a pile of small metal objects and use a magnet to discover which are ferrous and which are not.');
INSERT INTO badge_optional_requirements VALUES(8930,710,11,'Read a book on welding.');
INSERT INTO badge_optional_requirements VALUES(8931,710,12,'Watch a documentary on welding.');
INSERT INTO badge_optional_requirements VALUES(8932,710,13,'Examine the weight of different metals by holding cut pieces in your hand or putting them on a scale.  What type of metal is the heaviest?  Which is the lightest?  Why is it important to identify the materials you are welding?  What can go wrong you misidentify the type of metal or material?');
INSERT INTO badge_optional_requirements VALUES(8933,710,14,'Learn about different careers that involve welding. Websites:  These websites are not associated with our program and we cannot guarantee their content.  Please do not surf the internet without your parent’s permission. Lesson Plan on Welding Safety http://metals.about.com/gi/dynamic/offsite.htm?site=http://www.calaged. org/ResourceFiles/Curriculum/advcluster/2351.txt Huge source of welding links http://www.khake.com/page89.html Welding terms: http://www.keenovens.com/articles/welding-terms.htm');
INSERT INTO badge_optional_requirements VALUES(8934,711,3,'Research how long can you survive without water.  Without food?');
INSERT INTO badge_optional_requirements VALUES(8935,711,4,'Put together a personal survival kit. Explain how each item is used and why it was included.');
INSERT INTO badge_optional_requirements VALUES(8936,711,5,'Read, or watch a documentary, about a real life “survivor”.  How did they survive?  Did they make any mistakes?  What would you have done differently?  How might their circumstances have been different if they were stranded in a different environment?');
INSERT INTO badge_optional_requirements VALUES(8937,711,6,'Describe the steps you would take to survive in the following conditions: * Cold and snowy * Wet (marsh, bog, or forest) * Hot and dry (desert) * Windy (mountains,prairie or plains) * Water (ocean, lake, or river)');
INSERT INTO badge_optional_requirements VALUES(8938,711,7,'Build a natural shelter.  Whenever possible, use techniques that have little negative impact on the environment.');
INSERT INTO badge_optional_requirements VALUES(8939,711,8,'Spend the night in the shelter you built.');
INSERT INTO badge_optional_requirements VALUES(8940,711,9,'Demonstrate three ways to treat water found in the outdoors to prepare it for drinking.');
INSERT INTO badge_optional_requirements VALUES(8941,711,10,'Earn the pocketknife safety badge and the pocketknife badge.');
INSERT INTO badge_optional_requirements VALUES(8942,711,11,'Make a list of edible wild plants in your area and be able to identify them.  Explain why you should never eat anything you cannot positively identify.  What are the dangers of eating wild animals or fish?  How can these dangers be eliminated?');
INSERT INTO badge_optional_requirements VALUES(8943,711,12,'Show how to build a field Travis to carry heavy items such as firewood or an injured person.');
INSERT INTO badge_optional_requirements VALUES(8944,711,13,'Learn how to fish with basic or improvised materials that you have in your survival kit.');
INSERT INTO badge_optional_requirements VALUES(8945,711,14,'Learn how to make and lay animal snares and how to properly clean and cook an animal.');
INSERT INTO badge_optional_requirements VALUES(8946,712,3,'Find or make a flower press and learn how to use it. Press some flowers and use them to make greetings cards or a picture. You can make a press from cardboard and heavy books or bricks.');
INSERT INTO badge_optional_requirements VALUES(8947,712,4,'Learn about a career that studies wildflowers. Examples might include the forestry department, a florist, or a botanist. What type of salary would you earn? What kind of education would you need to enter that field?');
INSERT INTO badge_optional_requirements VALUES(8948,712,5,'Earn the Flower Arranging badge at your level.');
INSERT INTO badge_optional_requirements VALUES(8949,712,6,'Create a book of pressed flowers and include all the information on each flower that you can, such as number of pistils and stamens, Latin and family names, color variety, height, number of leaves and petals, etc. Show it to your family or club.');
INSERT INTO badge_optional_requirements VALUES(8950,712,7,'Take some photos of your favorite wildflowers and make a collage, poster, or scrapbook page out of them.');
INSERT INTO badge_optional_requirements VALUES(8951,712,8,'Write an essay on the different types of flowers that grow in your area and why you like them.');
INSERT INTO badge_optional_requirements VALUES(8952,712,9,'Choose a wildflower from your area and draw it. Show it to your family, friends, or group');
INSERT INTO badge_optional_requirements VALUES(8953,712,10,'Find out how Native Americans and/or early settlers, used wildflower plants as medicine or to dye cloth. Do any of them grow in your area? (WARNING: You must never eat any flowers you find growing wild unless you have parental permission.)');
INSERT INTO badge_optional_requirements VALUES(8954,712,11,'Find a coloring book of wildflowers and color at least 12 pictures in it. Make sure you get the right colors for each flower. (Preschool and Level 1 need only color five pictures in order to fulfill this requirement.)');
INSERT INTO badge_optional_requirements VALUES(8955,712,12,'Plant some wildflower seed in a window-box or an empty patch of your yard. Tend the patch, making sure it is watered adequately and has enough sun.');
INSERT INTO badge_optional_requirements VALUES(8956,712,13,'Learn about how wildflowers are pollinated. What roles do bees, hummingbirds, and butterflies play in the life cycle of a wildflower? What would happen if these animals disappeared?');
INSERT INTO badge_optional_requirements VALUES(8957,712,14,'Take a hike and record the wildflowers you see as drawings in a field journal.');
INSERT INTO badge_optional_requirements VALUES(8958,712,15,'Learn about the benefits and importance of native plants to the local ecology (food, habitat, soil erosion, etc.).');
INSERT INTO badge_optional_requirements VALUES(8959,712,16,'Participate in a community service project that involves wildflowers.');
INSERT INTO badge_optional_requirements VALUES(8960,712,17,'Learn about legends or folk stories about wildflowers. Create your own legend, story or poem about a wildflower and tell it to your club or family.');
INSERT INTO badge_optional_requirements VALUES(8961,712,18,'Go on a wildflower scavenger hunt. Find the following: A flower that grows in the sun. A flower that grows in the shade. A plant growing in or near water. A plant growing in dry sand. A native plant with a single flower on each stem. A native plant with multiple flowers on each stem.');
INSERT INTO badge_optional_requirements VALUES(8962,712,19,'Learn about adaptations that allow wildflowers to survive in their natural habitat.');
INSERT INTO badge_optional_requirements VALUES(8963,712,20,'Contact your local Highway Department, Parks and Wildlife or Natural Resources Department. Find out what organizations are working to protect wildflowers in your area. Contact one of these organizations and request any free literature available. The Lady Bird Johnson Wildflower Center can be contacted for information on an organization in your area.');
INSERT INTO badge_optional_requirements VALUES(8964,712,21,'Create a flower arrangement using wildflowers you find outside. Display it in your home or garden. Third Party Resources: US Forest Service: Just For Kids US Forest Service: Nature Watch Lady Bird Johnson Wildflower Center: Native Plants of North America');
INSERT INTO badge_optional_requirements VALUES(8965,713,3,'Watch one of Will Rogers movies.');
INSERT INTO badge_optional_requirements VALUES(8966,713,4,'Watch a biography of Will, such as the one his son portrayed him in, or read a book about him.');
INSERT INTO badge_optional_requirements VALUES(8967,713,5,'Learn about Will Rogers horses. Who was his favorite?');
INSERT INTO badge_optional_requirements VALUES(8968,713,6,'Learn about the political campaign Will was involved in.');
INSERT INTO badge_optional_requirements VALUES(8969,713,7,'Find out when Will was born and how and when he died.');
INSERT INTO badge_optional_requirements VALUES(8970,713,8,'Visit the Will Rogers State Park (Los Angeles, California). Tour the house. Watch the movie about his life in the Visitor’s Center.  Learn about the restoration of the house.');
INSERT INTO badge_optional_requirements VALUES(8971,713,9,'Try rope tricks similar to the ones Will used');
INSERT INTO badge_optional_requirements VALUES(8972,713,10,'Earn the Cowgirls or Cowboys badge. Official Will Rogers Website http://www.cmgww.com/historic/rogers/media/index.html');
INSERT INTO badge_optional_requirements VALUES(8973,714,3,'Talk about the accommodations people with Williams Syndrome generally need when attending school. Learn what an IEP is and how it can be used for those with special needs.');
INSERT INTO badge_optional_requirements VALUES(8974,714,4,'Spend a day with someone with Williams Syndrome.');
INSERT INTO badge_optional_requirements VALUES(8975,714,5,'Find out about a program or group that works with people with Williams Syndrome. Tell what the program or group does, and find out how people can help them.');
INSERT INTO badge_optional_requirements VALUES(8976,714,6,'Volunteer to help a family with a loved one with Williams Syndrome.');
INSERT INTO badge_optional_requirements VALUES(8977,714,7,'Participate in a service project that will benefit a Williams Syndrome organization.');
INSERT INTO badge_optional_requirements VALUES(8978,714,8,'Create a poster, or other art project, to promote Williams Syndrome awareness.');
INSERT INTO badge_optional_requirements VALUES(8979,714,9,'List the similarities between you and someone with Williams Syndrome. Tell why it is important to focus on what the similarities are, and not just the differences.');
INSERT INTO badge_optional_requirements VALUES(8980,714,10,'Do a musical activity with someone with Williams Syndrome.');
INSERT INTO badge_optional_requirements VALUES(8981,714,11,'Earn the Kindness badge. Tell why it is important to be kind and loving to all people, even when they are different.');
INSERT INTO badge_optional_requirements VALUES(8982,714,12,'Earn the Anti-bullying badge. Tell why it is important to stand up for those with special needs.');
INSERT INTO badge_optional_requirements VALUES(8983,714,13,'Talk with your principal and find out what programs your school offers for those with Williams Syndrome.');
INSERT INTO badge_optional_requirements VALUES(8984,714,14,'Create an informational display about Williams Syndrome. Display it in a public place, such as a library or school.');
INSERT INTO badge_optional_requirements VALUES(8985,714,15,'Volunteer with a Williams Syndrome organization.');
INSERT INTO badge_optional_requirements VALUES(8986,714,16,'Organize or help with a fundraiser for a Williams Syndrome organization.');
INSERT INTO badge_optional_requirements VALUES(8987,714,17,'Find out about a camp for those with Williams Syndrome. Where is it located? What kinds of activities do they offer?');
INSERT INTO badge_optional_requirements VALUES(8988,714,18,'Read a blog about Williams Syndrome.');
INSERT INTO badge_optional_requirements VALUES(8989,714,19,'Tell about the challenges and joys a family of a person with Williams Syndrome experiences.');
INSERT INTO badge_optional_requirements VALUES(8990,714,20,'Watch a documentary or movie that focuses on Williams Syndrome.');
INSERT INTO badge_optional_requirements VALUES(8991,716,3,'Using simple materials make a Wizard of Oz costume.');
INSERT INTO badge_optional_requirements VALUES(8992,716,4,'With your troop or family act out a scene from The Wizard of Oz.');
INSERT INTO badge_optional_requirements VALUES(8993,716,5,'Make a list of things you appreciate about home. Level 1 – 6, Level 2 – 9,  Level 3 – 12, Level 4 – 15, Level 5- 18.');
INSERT INTO badge_optional_requirements VALUES(8994,716,6,'Practice bravery, having heart, and using your brains in your daily activities. Spend one day focusing on each quality — Write about each day’s experience in your journal or share them with your troop or family.');
INSERT INTO badge_optional_requirements VALUES(8995,716,7,'Create a Wizard of Oz collection that contains at least 5 items. Share it with your troop or family.');
INSERT INTO badge_optional_requirements VALUES(8996,716,8,'Decorate a wearable item celebrating the Wizard of Oz such as a t-shirt or hat. Wear it.');
INSERT INTO badge_optional_requirements VALUES(8997,716,9,'Learn some interesting things about L. Frank Baum. Level 1 learn 6, Level 2 learn 9, Level 3 learn 12, Level 4 learn 15, Level 5 learn 18. What was his motivation to write the books? Where did he grow up, what does “L” stand for etc.');
INSERT INTO badge_optional_requirements VALUES(8998,716,10,'Visit the Wizard of Oz museum or exhibit');
INSERT INTO badge_optional_requirements VALUES(8999,716,11,'Create an art project such as a collage or painting of  something from the book or movie.');
INSERT INTO badge_optional_requirements VALUES(9000,716,12,'Learn about actress Judy Garland (Dorothy). Did she star in other films? What was her first movie? How old was she when she starred in Oz? Did she enjoy staring in Oz? What memories can you find that she shared?');
INSERT INTO badge_optional_requirements VALUES(9001,716,13,'Play a musical piece or sing a song from The Wizard of Oz soundtrack in front of an audience.');
INSERT INTO badge_optional_requirements VALUES(9002,716,14,'Learn about tornadoes. Would they actually pick up a house? What are the safety precautions for tornadoes? Does your area have tornadoes? If yes, what is your emergency plan?');
INSERT INTO badge_optional_requirements VALUES(9003,716,15,'Watch the Wizard of Oz play. If the cast is available after the show talk to at least 2 major characters and 3 minor characters. Ask at least 1 major and 1 minor about their experience in the play.');
INSERT INTO badge_optional_requirements VALUES(9004,716,16,'Butterfly’s and up, watch the play or listen to the soundtrack of the play Wicked.');
INSERT INTO badge_optional_requirements VALUES(9005,716,17,'Perfect a witches cackle. Perform it for your troop or family.');
INSERT INTO badge_optional_requirements VALUES(9006,716,18,'The original movie was produced 75+ years ago. Learn about the special effects from the movie and how they were achieved. How have special effects changed?');
INSERT INTO badge_optional_requirements VALUES(9007,716,19,'Talk to an adult about the difference between the book and the movie.');
INSERT INTO badge_optional_requirements VALUES(9008,716,20,'Watch or read other adaptations of the story. Compare the differences. Level 1 choose 1 adaption, Level 2 choose 2, Level 3 choose 3, Level 4 choose 4, Level 5 choose 5. Some are not age appropriate have an adult preview them before watching.');
INSERT INTO badge_optional_requirements VALUES(9009,716,21,'Read the entire Wizard of Oz series.');
INSERT INTO badge_optional_requirements VALUES(9010,718,3,'Find three songs, poems or ballads about women who changed or made history, such as Victoria the Wise by Alfred Austin, Betsy Ross by Nancy Byrd Tucker, or Lady of the Air, (about Amelia Earhart) by John Carter and Mary Kay Beall, and learn one of them. OR, listen to a song that describes how women helped to make a difference in a usually male-dominated area, as with Arthur Askey’s song The Thingamabob which tells how women worked in armament production in wartime Britain.');
INSERT INTO badge_optional_requirements VALUES(9011,718,4,'Read a biography of a famous woman from the past, such as Cleopatra, Golda Meir, or Queen Victoria, and be able to list at least two significant facts about her.');
INSERT INTO badge_optional_requirements VALUES(9012,718,5,'Look through the Bible or your own book of faith and find three well-known women in it. (Examples from the Bible might include Mary, Esther, Ruth, etc.) Read their stories and discuss how you can learn from their lives.');
INSERT INTO badge_optional_requirements VALUES(9013,718,6,'Watch a documentary or a movie about a famous woman. Tell your family or Club what made her famous.');
INSERT INTO badge_optional_requirements VALUES(9014,718,7,'Find a woman inventor and learn about her. What was her life like? Why did she invent what she did? If you could invest something what would it be? Draw a picture of it or make a prototype if possible.');
INSERT INTO badge_optional_requirements VALUES(9015,718,8,'Learn about a well-known movie actress, such as Grace Kelly or Nancy Reagan. Make a list of your chosen actress’s films and watch one.');
INSERT INTO badge_optional_requirements VALUES(9016,718,9,'Many famous women in the past were famous only because of whom they were related to, rather than what they did, such as Marie Antoinette, or all of Henry VIII’s wives. Choose one such woman and learn about her life. Next, make a list of current women that are famous only because of who they are related to in some way.');
INSERT INTO badge_optional_requirements VALUES(9017,718,10,'Learn about a celebrated authoress, such as Charlotte Bronte, Jane Austen, or Harriet Beecher Stowe. Read at least one of her books. What do you like about it?');
INSERT INTO badge_optional_requirements VALUES(9018,718,11,'Choose one of the women mentioned in requirement 1 and write an essay about her.');
INSERT INTO badge_optional_requirements VALUES(9019,718,12,'Write a poem about one of the women you learned about for requirement 1.');
INSERT INTO badge_optional_requirements VALUES(9020,718,13,'Find a picture of a famous woman and look at it. Do you think the painter captured the true appearance of the woman? Does the woman look anything like what you imagined her to look? Share the picture with your family or Club.');
INSERT INTO badge_optional_requirements VALUES(9021,718,14,'Some women become famous for what they have done for others, rather than for themselves. Find such a person (Edith Cavell or Mother Teresa, for example), and learn about her. How can you imitate her good attributes in your own life? Choose a community service to participate in the reflects what you learned.');
INSERT INTO badge_optional_requirements VALUES(9022,718,15,'Make a piece of artwork, such as a collage, poster, or a scrapbook page, that expresses what you know about one of the women you learned about for requirement 1. Show it to your family or Club.');
INSERT INTO badge_optional_requirements VALUES(9023,718,16,'Some women have not been very nice people and are famous for all the wrong reasons. Pick one of these women, such as Jezebel, Athaliah, or Mary I (Bloody Mary), and learn about her life. Why do you think she acted the way she did? Discuss how can you learn from her mistakes.');
INSERT INTO badge_optional_requirements VALUES(9024,718,17,'Women have been professional singers throughout history. Pick a female singer from at least 50 years ago and learn what her life was like. Examples might include: Jenny Lind, Vera Lynn, or Elisa Felix Rachel. Listen to at least 3 of her songs.');
INSERT INTO badge_optional_requirements VALUES(9025,721,4,'Practice measuring pieces of wood and drawing lines needed on them. Know the abbreviations for inches and feet. Know how many inches are in a foot and how many feet are in a yard. Why is it important to hold lumber still while it is being cut? What are some ways you can hold the wood still?');
INSERT INTO badge_optional_requirements VALUES(9026,721,5,'Choose two woodworking projects from a book or magazine & make a list of all the wood and nails a person would need to make that project. Go to a hardware or lumber store and figure out how much your projects would cost. Do you think it is cheaper to make your own items from wood or to buy them?');
INSERT INTO badge_optional_requirements VALUES(9027,721,6,'Make or buy another item of unfinished wood. Varnish or paint it after sanding it.');
INSERT INTO badge_optional_requirements VALUES(9028,721,7,'Tour a furniture factory, a lumber mill, or a carpenter’s shop. What safety practices do the workers follow? Did you see anyone do something that looked unsafe to you?');
INSERT INTO badge_optional_requirements VALUES(9029,721,8,'Learn what a 1 x 6 or a 2 x 4 are. What are their actual precise measurements? Practice putting two pieces of wood together in a C-clamp and put a piece of wood in a bench vise. Find out what the most common sizes of plywood are. What is doweling and how do people keep track of the sizes of dowels? Level 3 and up make a wood project that uses a piece of doweling. Level 4 and up practice following a grid drawing (from a book) for a curved piece of wood. Do this twice, once with a grid drawn on the wood itself and once making a template out of hardboard or cardboard.');
INSERT INTO badge_optional_requirements VALUES(9030,721,9,'Go to a craft fair, county fair or art shop where finished wood projects are sold. Ask the craftsmen how long it took to do the various projects. What kinds of finishes are put on wooden bowls? What kinds of finishes are used on outdoor furniture? What is wood turning? Watch someone whittle or carve with a chisel (this can be done via a movie). Level 3 and up must whittle or carve something yourself rather than watching someone else do it. Level 4 and up must whittle or carve two small items or one large one.');
INSERT INTO badge_optional_requirements VALUES(9031,721,10,'Make a wood project. Use at least two of the following techniques to decorate it: sanding, painting, varnishing, wood burning, stenciling, decoupage, nailing nails in a pattern, using naturally different colors of wood to make a pattern (such as in a chessboard).');
INSERT INTO badge_optional_requirements VALUES(9032,721,11,'Visit a tree farm or earn the Trees badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(9033,721,12,'Visit a museum or craft shop that has a lot of wooden art pieces or artifacts. Make a wood project with balsa wood, redwood burl, or a tropical wood that is not from an endangered species. This project needs to show off the natural wood if it is made of burl or a tropical wood.');
INSERT INTO badge_optional_requirements VALUES(9034,721,13,'Find out how much various woodworkers make in wages and what kind of benefits they might get. Watch a house being framed—at least three visits of at least ten minutes each. OR shadow a carpenter in a shop for a day.');
INSERT INTO badge_optional_requirements VALUES(9035,721,14,'Help repair or construct wooden toys or furniture for a disabled individual or charity. Or donate one of your projects to a benefit craft sale or auction.');
INSERT INTO badge_optional_requirements VALUES(9036,721,15,'Study the history of woodworking and house building. Get information from at least two sources.');
INSERT INTO badge_optional_requirements VALUES(9037,721,16,'Work as an aid in a class using wood for projects. This can be crafts or carpentry-oriented.');
INSERT INTO badge_optional_requirements VALUES(9038,722,3,'Find and learn a song that helps you learn about words.');
INSERT INTO badge_optional_requirements VALUES(9039,722,4,'Good spelling is very important. Earn the Spelling badge at your level.');
INSERT INTO badge_optional_requirements VALUES(9040,722,5,'Learn what puns (plays on words) are. Learn 1 (Preschool), 3 (Level 1), 5 (Level 2), 10 (Level 3), 15 (Level 4), 20 (Level 5) words that can have different meanings and could be used for puns.');
INSERT INTO badge_optional_requirements VALUES(9041,722,6,'Play a word game such as SCRABBLE, Railroad/End-to-End, UpWords, Perquackey, etc.');
INSERT INTO badge_optional_requirements VALUES(9042,722,7,'Learn to do word puzzles such as crosswords. Complete a crossword appropriate for your age and reading level.');
INSERT INTO badge_optional_requirements VALUES(9043,722,8,'Read a book written at least 50 years ago and pay attention to the language used in it. How many words are new to you? Make a list of at least 10 words that you have never seen before and look up each one.');
INSERT INTO badge_optional_requirements VALUES(9044,722,9,'Earn the SCRABBLE badge at your level.');
INSERT INTO badge_optional_requirements VALUES(9045,722,10,'Learn about Latin and Greek roots. Choose one (Preschool and Level 1), three (Level 2), five (Level 3 & 4), seven (Level 5) roots and make a list of all the words you can find that have sprung from that root.');
INSERT INTO badge_optional_requirements VALUES(9046,722,11,'Learn what slang is, and where and when it is OK to use it. Learn where at least 5 different slang terms originally came from. Do you feel these words are acceptable? Note: slang here is not intended to mean profanity.');
INSERT INTO badge_optional_requirements VALUES(9047,722,12,'Cockneys are people who are born and live within a certain part of London, England. Find out which part of London they come from. Their language consists of a great deal of rhyme, called Cockney rhyming slang. Find out about Cockney Rhyming Slang and learn a few of their terms.');
INSERT INTO badge_optional_requirements VALUES(9048,722,13,'Each profession has its own vocabulary/jargon. Choose a profession, such as a musician, a seamstress, or a mechanic, and learn at least 5 jargon words that they would use on a regular basis.');
INSERT INTO badge_optional_requirements VALUES(9049,722,14,'Good punctuation is also very important. The way we punctuate our sentences can dramatically affect what they mean. Learn about the significance of good punctuation along with good word usage. Then choose three sentences to punctuate differently to change the meaning. Why is proper punctuation so vital to the way we use our words in writing?');
INSERT INTO badge_optional_requirements VALUES(9050,722,15,'Learn about archaic spelling and usage of words in the English language. Read a passage from the King James Bible or another book that uses archaic pronouns and learn what the archaic words in the portion mean. Can some words have different meanings based on their context?');
INSERT INTO badge_optional_requirements VALUES(9051,722,16,'Learn about career opportunities that involve words, such as an editor. What must your understanding of the English language be to have such a job? What salary could you expect, and what would your job be like?');
INSERT INTO badge_optional_requirements VALUES(9052,724,3,'Celebrate World Dance Day on April 21 by watching a dance performance, hosting a dance party, or learning a new dance. Find your own creative ways to celebrate this day.');
INSERT INTO badge_optional_requirements VALUES(9053,724,4,'Without music, there is no rhythm to dance to. Listen to music from around the world and move your body to the rhythm. How does each piece of music make you feel? How does your body want to move?');
INSERT INTO badge_optional_requirements VALUES(9054,724,5,'Find pictures of different dance costumes from around the world and make a collage.');
INSERT INTO badge_optional_requirements VALUES(9055,724,6,'Create a piece of artwork inspired by a dance from another country. It can include dancers, musical instruments, or even just patterns inspired by floor patterns or figures such as in ballroom dancing.');
INSERT INTO badge_optional_requirements VALUES(9056,724,7,'Participate in a performance that features a dance from another country.');
INSERT INTO badge_optional_requirements VALUES(9057,724,8,'Host a dance party where you play music from other countries. If you learned your dances well enough from requirement #1, try teaching them to your guests.');
INSERT INTO badge_optional_requirements VALUES(9058,724,9,'Create a timeline of dances from around the world. What is the most ancient dance you can find? What about the most recent? (Preschool-Level 2 only)');
INSERT INTO badge_optional_requirements VALUES(9059,724,10,'Learn about a famous choreographer. What type of dances do/did they design? What dance or performance made them famous?');
INSERT INTO badge_optional_requirements VALUES(9060,724,11,'Research careers that require dance. These may include dancers, choreographers, artistic director, or dance notator.');
INSERT INTO badge_optional_requirements VALUES(9061,724,12,'Choreograph your own dance to a piece of instrumental music.');
INSERT INTO badge_optional_requirements VALUES(9062,726,3,'Read a book, at your reading level, that takes place in another country.');
INSERT INTO badge_optional_requirements VALUES(9063,726,4,'Learn the capital city of the country we live in and find it on a map (Preschool); the capital cities of at least 5 countries (Level 1); at least 10 countries (Level 2); at least 15 countries (Level 3); at least 20 countries (Level 4); at least 25 countries (Level 5).');
INSERT INTO badge_optional_requirements VALUES(9064,726,5,'Look at two (Preschool), three (Level 1), four (Level 2), five (Level 3), six (Level 4), seven (Level 5) different types of maps of the world.   Examples may include a climate, topography, population, political, road, shaded relief, photographic, or physiographic map. Be able to identify what type of map you are looking at and what each map shows.');
INSERT INTO badge_optional_requirements VALUES(9065,726,6,'Learn to identify the northern, southern, eastern, and western hemispheres, the equator, prime meridian, and latitude and longitude lines.');
INSERT INTO badge_optional_requirements VALUES(9066,726,7,'Pick one country (Preschool), two (Level 1), three (Level 2), four (Level 3), five (Level 4), six (Level 5) countries and learn what their climate is, their largest river, tallest mountain, and any landmarks that they are famous for.');
INSERT INTO badge_optional_requirements VALUES(9067,726,8,'Create a travel brochure for the country of your choice. Make sure to include items of interest to travelers such as climate, landmarks, recreational activities, money, etc.');
INSERT INTO badge_optional_requirements VALUES(9068,726,9,'Create a map of the world with outlines of each country. On each country, write the capital city and any national landmarks. Cover the information with small flaps to create a “quiz board”. Use your map to play geography games or quiz your club.');
INSERT INTO badge_optional_requirements VALUES(9069,726,10,'Research careers in which a knowledge of world geography is needed. Examples may include import, export, transportation, international investment, missionary, etc. What education is needed for this career? What pay and work schedules can you expect?');
INSERT INTO badge_optional_requirements VALUES(9070,727,1,'What characterizes your area (rivers, mountains, forests, deserts, volcanoes, cities, etc)? What defines its boundaries? Learn about at least 5 major geographic features of your area (10 for Level 3 and 4, 15 for Level 5) and find them on a map. How do these geographic circumstances affect and continue to shape the region?');
INSERT INTO badge_optional_requirements VALUES(9071,727,2,'What is one of the most visited tourist attractions in your area?  How and why is this attraction a reflection of the area?  Is it a Geographic attraction (like the Four Corners), Historic (like the Liberty Bell), Artistic (the Bean, Disney Land), Commercial (Blue Bell Factory, The Stock Exchange), Scientific (NASA), etc?  When did it become an attraction, how many people visit it annually, how much does it cost to visit?');
INSERT INTO badge_optional_requirements VALUES(9072,727,3,'Learn about a specific historic or unusual building, monument or other geographic feature within your chosen area. This may be repeated for different places studied.');
INSERT INTO badge_optional_requirements VALUES(9073,727,4,'What is the currency of your chosen area? Look at examples/pictures of the notes/coins that are used. What is the currency’s exchange rate to the US Dollar? What is an average yearly income for the area? How does this compare with the average income for the United States?');
INSERT INTO badge_optional_requirements VALUES(9074,727,5,'Learn a dance from your chosen area.');
INSERT INTO badge_optional_requirements VALUES(9075,727,6,'What is education like in this area? Are children primarily educated at home or at school? Do all children receive academic education? What age do most children finish their education? What percentage complete school or go on to complete college?');
INSERT INTO badge_optional_requirements VALUES(9076,727,7,'Listen to music from your chosen area.  What style(s) are dominant? What influences have affected the music of the area? Do you like the music or not? Why? How does it compare with the music from your own area?');
INSERT INTO badge_optional_requirements VALUES(9077,727,8,'Throw, or attend, a party specifically themed to your area.  Dress up in costume, eat food, and play music from your chosen area.');
INSERT INTO badge_optional_requirements VALUES(9078,727,9,'What styles of visual art are dominant in your chosen area?  Painting? Sculpture? Beadwork? Learn about at least one famous artist from your area.');
INSERT INTO badge_optional_requirements VALUES(9079,727,10,'What means of transport are used in your chosen area?  How do people and products get from one place to another? How has transport changed during the history of this area?');
INSERT INTO badge_optional_requirements VALUES(9080,727,11,'Read a biography of a famous person from this area. How did they affect the area? How did the area affect them?');
INSERT INTO badge_optional_requirements VALUES(9081,727,12,'Visit a museum where you can learn about and see exhibits and artifacts from your chosen area.');
INSERT INTO badge_optional_requirements VALUES(9082,727,13,'Earn the Museum Specific Badge for a museum about your specific area.');
INSERT INTO badge_optional_requirements VALUES(9083,727,14,'Read a non-fiction book about your chosen area.');
INSERT INTO badge_optional_requirements VALUES(9084,727,15,'Read a fiction book about your chosen area.');
INSERT INTO badge_optional_requirements VALUES(9085,729,3,'Research video games that deal with war and violence. Why do you think these games are popular? Do you think these games make people think that violence is the solution to every conflict? Discuss violence in video games with your parents. Then design your own game with heroes or heroines that solve conflict in a nonviolent way.');
INSERT INTO badge_optional_requirements VALUES(9086,729,4,'Collect political cartoons and discuss them with your club or parent. Do you agree with the point of view of the cartoon? Is it done in a tasteful manner or in a way that invites further conflict? Design a cartoon of your own advocating world peace. See if you can get it printed in a local school or community paper.');
INSERT INTO badge_optional_requirements VALUES(9087,729,5,'Write a story or play about world peace.');
INSERT INTO badge_optional_requirements VALUES(9088,729,6,'Learn at least 4 (5 for Level 1, 6 for Level 2, 7 for Level 3, 8 for Level 4, 9 for Level 5) famous quotes about peace. Who said each and why?');
INSERT INTO badge_optional_requirements VALUES(9089,729,7,'Find out what the Nobel Peace Prize is and learn about at least 3 of the winners.');
INSERT INTO badge_optional_requirements VALUES(9090,729,8,'Research careers that influence world peace such as politicians, teachers, diplomats, entertainers, and people in the medical field. Choose one and find out what education is required, what salary you can expect, and what hours and travel may be required.');
INSERT INTO badge_optional_requirements VALUES(9091,729,9,'Find out what others think about world peace. Design a survey with at least 10 questions to ask people about how to obtain world peace or about specific world peace issues. Have at least 15 people fill out your survey and then share your results with your family or club.');
INSERT INTO badge_optional_requirements VALUES(9092,729,10,'Learn 3 songs about world peace and teach them to your club, friends, or family.');
INSERT INTO badge_optional_requirements VALUES(9093,729,11,'Visit an organization that is working toward world peace in some form. Volunteer at least 4 hours to help them in any way you can.');
INSERT INTO badge_optional_requirements VALUES(9094,729,12,'Host a Peace contest through your school or club. Form a committee to select judges and prizes for the best posters, essays poems, songs, etc.');
INSERT INTO badge_optional_requirements VALUES(9095,729,13,'Celebrate International Peace Day on September 21 by throwing a Peace Party with your club or family.');
INSERT INTO badge_optional_requirements VALUES(9096,729,14,'Write a letter to the president of the United States, or to your congressman/woman asking specific questions about world peace issues. If you have ideas for them, feel free to share them as well. Include a return address so that they can write you back. (Preschool – Level 3 only)');
INSERT INTO badge_optional_requirements VALUES(9097,729,15,'Say a prayer for peace every night for a week.');
INSERT INTO badge_optional_requirements VALUES(9098,729,16,'Find out what the World Peace bell is and where it is located.');
INSERT INTO badge_optional_requirements VALUES(9099,730,3,'What are monotheistic, polytheistic and nontheistic religions?  Find and example of each.');
INSERT INTO badge_optional_requirements VALUES(9100,730,4,'Create a Venn diagram to compare and contrast two world religions.  Where do the beliefs of these religions overlap?');
INSERT INTO badge_optional_requirements VALUES(9101,730,5,'Find out how many people in the world follow each of the following world religions and where they are mostly located: Christianity, Islam, Judaism, Hinduism, Sikhism, Buddhism, Taoism, Shintoism and Baha’i.');
INSERT INTO badge_optional_requirements VALUES(9102,730,6,'Christianity has become a broad term for a variety of different denominations and doctrines.  What does the word “Christian” mean?  Learn about at least 6 different Christian religions such as Catholics, Methodists or Baptists.  While the core beliefs of each of these religions is “Christian” how do their beliefs differ?');
INSERT INTO badge_optional_requirements VALUES(9103,730,7,'Choose 6 different world religions and find out where and when, and how each of them originated. Where are they still practiced today?');
INSERT INTO badge_optional_requirements VALUES(9104,730,8,'Learn about a major holiday from another religion.  Why is it celebrated?  How is it usually observed?  What traditional activities, decorations, etc. are used?');
INSERT INTO badge_optional_requirements VALUES(9105,730,9,'Learn about the first amendment of the constitution and what it says about religion.  Why is it important that our government does not establish a national religion?');
INSERT INTO badge_optional_requirements VALUES(9106,730,10,'Visit a church, temple or place of worship of another religion.');
INSERT INTO badge_optional_requirements VALUES(9107,730,11,'Create world-religion trivia game to play.  It can be similar to “Jeopardy!”, “Trivial Pursuit” or a game style of your choice.');
INSERT INTO badge_optional_requirements VALUES(9108,730,12,'Find out how the Golden Rule is stated in at least 6 different world religions.');
INSERT INTO badge_optional_requirements VALUES(9109,730,13,'Attend a religious festival such as Baisakhi or Day of the Dead.');
INSERT INTO badge_optional_requirements VALUES(9110,730,14,'Learn the following vocabulary words: Deity Reincarnation Nirvana Karma Atheist Monotheistic Polytheistic Nontheistic Sacred Divine Prophecy/Prophetic Doctrine Denomination Orthodox Canon');
INSERT INTO badge_optional_requirements VALUES(9111,730,15,'Create a craft symbolizing a world religion.');
INSERT INTO badge_optional_requirements VALUES(9112,731,3,'Inch-worms are the larvae of moths. Find out what the common characteristics of an inch-worm are. How do they differ from an earthworm? Level 3 and up add: What kinds of worms produce silk and how?');
INSERT INTO badge_optional_requirements VALUES(9113,731,4,'Find out what worms are best for fishing. Go on a fishing trip using fish for bait.');
INSERT INTO badge_optional_requirements VALUES(9114,731,5,'Observe worms by making your own “wormery”. You will need: • Wide-mouth glass jar • Garden soil • Peat • Sand • Water • Earthworms • Dead leaves • Paper bag Place a layer of soil, a layer of peat, and a layer of sand into your jar. Water the soil well. Put your worms on top of the soil, but don’t bury them. They will dig down into the soil on their own. Cover the worms with some dead leaves and put a paper bag over the top of the jar. The will keep out the light, but still let in oxygen.Place your jar in a cool place out of any direct sunlight.Check your worm farm every day and make sure the soil is damp, but not soaked. Watch your worms at work. After a few days, make sure to set your worms free in a good, damp location outside.');
INSERT INTO badge_optional_requirements VALUES(9115,731,6,'What is compost, and why is worm compost especially good for gardening?');
INSERT INTO badge_optional_requirements VALUES(9116,731,7,'Read a book about worms. Suggestions listed. Preschool and Level 1: “The Very Hungary Caterpillar” by Eric Carle Level 2: “Diary of a Worm” by Doreen Cronin Level 3 and up: Or watch a documentary');
INSERT INTO badge_optional_requirements VALUES(9117,731,8,'Some cultures around the world eat worms. Find out where some worms are eaten, what types they eat, and how they are prepared.');
INSERT INTO badge_optional_requirements VALUES(9118,731,9,'Visit a worm farm in person, or online with permission from your parents.');
INSERT INTO badge_optional_requirements VALUES(9119,731,10,'Participate in a service project that has something to do with worms. You might help dig worms for a community kids fishing or help in a community garden. Websites: These websites are not associated with our program and we cannot guarantee their content. Please do not surf the internet without your parent’s permission. Discover Kids – All About Worms http://yucky.discovery.com/flash/worm/pg000102.html All About Worms http://www.allaboutworms.com/types-of-worms Worm Activities http://www.calrecycle.ca.gov/Education/curriculum/worms/98Activities.pdf Worm Crafts http://www.kidactivities.net/post/Worms-for-Fun!.aspx Adventures of Herman the Worm http://urbanext.illinois.edu/worms/');
INSERT INTO badge_optional_requirements VALUES(9120,732,3,'Write a story. (Level 2) Write a story of at least 500 words. (Level 3 and Up) write a story of at least 1500 words.');
INSERT INTO badge_optional_requirements VALUES(9121,732,4,'Write a book report. (Level 3 and Up) write 2');
INSERT INTO badge_optional_requirements VALUES(9122,732,5,'Write a poem. Level 2 must do 2 and Level 3 and Up must do 5');
INSERT INTO badge_optional_requirements VALUES(9123,732,6,'Enter a writing contest.');
INSERT INTO badge_optional_requirements VALUES(9124,732,7,'Write a personal narrative about something that happened to you. (Level 2 and Up) must use words that capture the five senses, sight, smell, sound, taste, and feeling.');
INSERT INTO badge_optional_requirements VALUES(9125,732,8,'Write a persuasive paragraph.');
INSERT INTO badge_optional_requirements VALUES(9126,732,9,'Write a radio commercial for the product of your choice. It should be short, catchy, and informative. Try to write a jingle to go with it.');
INSERT INTO badge_optional_requirements VALUES(9127,732,10,'Write your own twist to a classic fairy tale.');
INSERT INTO badge_optional_requirements VALUES(9128,732,11,'Write a “How To” article to explain to someone how to do something. It might be a recipe, game instructions, how to put up a tent, or anything else you can think of. Have friends or family members follow your directions and check to see if you missed something important.');
INSERT INTO badge_optional_requirements VALUES(9129,732,12,'Write a newspaper article about something going on in your community or something your club has done. Don’t forget important things like “who,” “what,” “where,” “why” and “how.”');
INSERT INTO badge_optional_requirements VALUES(9130,732,13,'Earn the badge writing badge.');
INSERT INTO badge_optional_requirements VALUES(9131,732,14,'Write a letter to a political representative about an issue you are concerned about.');
INSERT INTO badge_optional_requirements VALUES(9132,732,15,'Learn about Martin Luther King and write your own “I Have a Dream” speech.');
INSERT INTO badge_optional_requirements VALUES(9133,732,16,'Write your own urban legend.');
INSERT INTO badge_optional_requirements VALUES(9134,732,17,'Read the Declaration of Independence and reword it using today’s language style.');
INSERT INTO badge_optional_requirements VALUES(9135,732,18,'Write a short play.');
INSERT INTO badge_optional_requirements VALUES(9136,732,19,'Create a newsletter for your club. Include articles on upcoming events, things you have done, interviews with kids and leaders, etc.');
INSERT INTO badge_optional_requirements VALUES(9137,732,20,'Find out how a writer’s manuscript in turned into a published book.');
INSERT INTO badge_optional_requirements VALUES(9138,732,21,'Research careers in writing and interview someone who writes for a living. This may be a newspaper columnist, magazine editor, author, or even someone who write training manuals or advertising copy.');
INSERT INTO badge_optional_requirements VALUES(9139,732,22,'Write a personal letter such as a thank you letter, a letter of appreciation to our soldiers overseas, or a letter to a pen-pal. Level 2 and Up must write 3.');
INSERT INTO badge_optional_requirements VALUES(9140,733,3,'Learn about Isolationism and why that was important to the United States. What were the 3 strikes that led to the United States to entering the war. Learn how many American soldiers, sailors, and marines fought in WWI.');
INSERT INTO badge_optional_requirements VALUES(9141,733,4,'Political cartoons were used to influence public opinion and support for the War.  Create a political cartoon for WWI that might have been used to gather support for the war.  Learn about Yellow Journalism.');
INSERT INTO badge_optional_requirements VALUES(9142,733,5,'Learn about the war efforts at home and their impact. Know what roles women and African Americans had in the states during WWI. What else were women fighting for during this time?');
INSERT INTO badge_optional_requirements VALUES(9143,733,6,'Learn and understand the poem “In Flanders Field”.');
INSERT INTO badge_optional_requirements VALUES(9144,733,7,'Learn and understand the song “Over There” By George M. Cohan.');
INSERT INTO badge_optional_requirements VALUES(9145,733,8,'Learn about the Spanish Flu epidemic of 1918 and where the first reported cases in the United States. Know how this had an effect on America during the war.');
INSERT INTO badge_optional_requirements VALUES(9146,733,9,'Learn about the League of Nations and what its goal was.');
INSERT INTO badge_optional_requirements VALUES(9147,733,10,'Find out about the role of radio in WWI.');
INSERT INTO badge_optional_requirements VALUES(9148,733,11,'Watch a movie or documentary about WWI.');
INSERT INTO badge_optional_requirements VALUES(9149,733,13,'Learn about the Treaty of Versailles and about how the world leaders met then came to an agreement on punishment against Germany. Why did America think the punishments were too harsh? What were the main components of the treaty?');
INSERT INTO badge_optional_requirements VALUES(9150,733,14,'Know how the poppy became  the symbol of WWI.');
INSERT INTO badge_optional_requirements VALUES(9151,733,15,'Posters were used to influence public opinion and support for the War.  Create a poster for World War I that might have been used to gather support for the war.');
INSERT INTO badge_optional_requirements VALUES(9152,733,16,'Write a poem about WWI or someone who lived through it.');
INSERT INTO badge_optional_requirements VALUES(9153,733,17,'Learn to identify at least 5 different aircraft or ships used in WWI and what the role of each was.');
INSERT INTO badge_optional_requirements VALUES(9154,733,18,'Learn about the role of women in WWI.');
INSERT INTO badge_optional_requirements VALUES(9155,733,19,'Learn about the Tuskegee Airman and the role that black Americans played in the war.');
INSERT INTO badge_optional_requirements VALUES(9156,733,20,'Many times in learning about a war, we ourselves choose sides and decide who are the “good guys” and who are the “bad guys”.  If you are feeling this way, put yourself in someone else’s shoes.  Research the “other” side and write a short essay about their reasons for the war.  Learn about what life was like during and after the war from their point of view.');
INSERT INTO badge_optional_requirements VALUES(9157,733,21,'Learn about the Zimmerman Telegram and the role it played in WWI.');
INSERT INTO badge_optional_requirements VALUES(9158,733,22,'During World War I, Herbert Hoover led a volunteer food rationing program in America, while in England even the King and Queen had to present their food ration cards.  Choose a food to ration in your household and set up a program to try out for a few weeks such as Meatless Mondays or Wheatless Wednesdays.');
INSERT INTO badge_optional_requirements VALUES(9159,733,23,'Learn about treaties and alliances.  What is the difference between the two? How did that play into the start of the war?');
INSERT INTO badge_optional_requirements VALUES(9160,734,3,'Learn about the role that codes and cryptography played in WWII.  Find out about Enigma and the Navajo Code Talkers.  Make up a code of your own and share it with friends or family.');
INSERT INTO badge_optional_requirements VALUES(9161,734,4,'Posters were used to influence public opinion and support for the War.  Create a poster for World War II that might have been used to gather support for the war.   Another option is to record a 30 second public service message (remember, TV was not widely available, but radio was very popular.)');
INSERT INTO badge_optional_requirements VALUES(9162,734,5,'Disney released a series of cartoons not only supporting the war, but many were actually used as training videos for the military.  Watch at least 5 of these cartoons.  They can be rented from places like Netflix and Blockbuster Online as well as viewed on Youtube on the internet (search Disney WWII).');
INSERT INTO badge_optional_requirements VALUES(9163,734,6,'Write a poem about WWII or someone who lived through it.');
INSERT INTO badge_optional_requirements VALUES(9164,734,7,'Learn about the bombing of Pearl Harbor.  Locate Pearl Harbor on a map and trace the route of the Japanese airplanes.  On what date this occur?');
INSERT INTO badge_optional_requirements VALUES(9165,734,8,'Learn to identify at least 5 different aircraft or ships used in WWII and what the role of each was.');
INSERT INTO badge_optional_requirements VALUES(9166,734,9,'Learn about the role of women in WWII.  Where did the term Rosie the Riveter come from?');
INSERT INTO badge_optional_requirements VALUES(9167,734,10,'Find out about the role of music in WWII.  Learn at least 3 songs written during WWII.');
INSERT INTO badge_optional_requirements VALUES(9168,734,11,'Watch a movie or documentary about WWII.');
INSERT INTO badge_optional_requirements VALUES(9169,734,12,'Interview relatives, friends, or neighbors who are old enough to remember the War.  Gather the memories of at least 3 different people.  They can be veterans, women, men, people who remained on the home front, or even those who were just children.   Create a booklet out of what you collected.');
INSERT INTO badge_optional_requirements VALUES(9170,734,13,'Learn about the bombing of Hiroshima and how it affected the outcome of the war.  (Level 3 and Up) President Truman had to make the decision that propelled the nation and the world into the nuclear arms race and set up conditions for the ‘Cold War.’  Debate the development and use of the atomic bomb. Was it the best decision? What would likely have happened if the bombings had not been carried out on Hiroshima and Nagasaki? Consider alternate scenarios.');
INSERT INTO badge_optional_requirements VALUES(9171,734,14,'Learn about the Tuskegee Airman and the role that black Americans played in the war.');
INSERT INTO badge_optional_requirements VALUES(9172,735,3,'Participate in a yoga class.');
INSERT INTO badge_optional_requirements VALUES(9173,735,4,'The five yamas are the ethical guideline for how a yogi behaves.  Be able to explain each yama and how it should affect your life.');
INSERT INTO badge_optional_requirements VALUES(9174,735,5,'According to yoga philosophy, the Kleshas are the cause of all suffering.  What are the five main Kleshas and how can they affect your life?');
INSERT INTO badge_optional_requirements VALUES(9175,735,6,'What is the law of Karma?  According to this law, how does Karma affect your life?');
INSERT INTO badge_optional_requirements VALUES(9176,735,7,'What are the Koshas?');
INSERT INTO badge_optional_requirements VALUES(9177,735,8,'Read a book about yoga.');
INSERT INTO badge_optional_requirements VALUES(9178,735,9,'Watch a documentary about yoga.');
INSERT INTO badge_optional_requirements VALUES(9179,736,3,'Get some friends together and have a yo-yo competition.');
INSERT INTO badge_optional_requirements VALUES(9180,736,4,'Visit http://www.yoyomuseum.com with a parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(9181,736,5,'Learn about the Smothers Brothers.');
INSERT INTO badge_optional_requirements VALUES(9182,736,6,'Teach someone younger than you how yo-yo.');
INSERT INTO badge_optional_requirements VALUES(9183,736,7,'Compare different yo-yos. Is one easier to use than the others?');
INSERT INTO badge_optional_requirements VALUES(9184,736,8,'Learn ten different yo-yo shapes (body styles).');
INSERT INTO badge_optional_requirements VALUES(9185,736,9,'Find out how yo-yos are made.');
INSERT INTO badge_optional_requirements VALUES(9186,736,10,'Learn about the world yo-yo contest. Which countries are in first, second, and third place?');
INSERT INTO badge_optional_requirements VALUES(9187,736,11,'What are some of the world yo-yo records?');
INSERT INTO badge_optional_requirements VALUES(9188,736,12,'Write a report on the history of yo-yos.');
INSERT INTO badge_optional_requirements VALUES(9189,738,3,'Learn about how many straws are thrown away every year. Get a reusable straw .');
INSERT INTO badge_optional_requirements VALUES(9190,738,4,'Watch a video or documentary on what happens to trash .');
INSERT INTO badge_optional_requirements VALUES(9191,738,5,'Find at least 10 places where plastic bags are not allowed to be used . Read at least 3 of the laws as written.  Do you think they are good laws?  How do you think they could be improved?');
INSERT INTO badge_optional_requirements VALUES(9192,738,6,'Find at least 3 items that you don’t use and donate them to a thrift store or someone else who could use them.');
INSERT INTO badge_optional_requirements VALUES(9193,738,7,'Purchase a used item. Make a list of benefits of buying used items instead of buying new.');
INSERT INTO badge_optional_requirements VALUES(9194,738,8,'Learn about reusable gift wrap. Make cloth bags or use furoshiki for a gift.');
INSERT INTO badge_optional_requirements VALUES(9195,738,9,'Read a book about zero waste.');
INSERT INTO badge_optional_requirements VALUES(9196,738,10,'Learn to reduce waste in food packaging and the benefits of buying in bulk.');
INSERT INTO badge_optional_requirements VALUES(9197,738,11,'Learn to compost food scraps.');
INSERT INTO badge_optional_requirements VALUES(9198,738,12,'Learn to reduce junk mail and catalogs.  Reduce your junk mail or catalogs.');
INSERT INTO badge_optional_requirements VALUES(9199,738,13,'Participate in a 30 day zero waste challenge.');
INSERT INTO badge_optional_requirements VALUES(9200,738,14,'Learn about at least 3 companies that produce zero landfill waste.');
INSERT INTO badge_optional_requirements VALUES(9201,739,3,'Explore different genres of zines (art, science, DIY, literary, fanzines, etc.) and create a list of your favorites.');
INSERT INTO badge_optional_requirements VALUES(9202,739,4,'Research and create a timeline highlighting key milestones in the history of zine-making.');
INSERT INTO badge_optional_requirements VALUES(9203,739,5,'Start a notebook or sketchbook specifically for zines. Jot down ideas for topics you might like to write about, and drawings or designs you might like to include.');
INSERT INTO badge_optional_requirements VALUES(9204,739,6,'Some people create zines with multiple contributors, sometimes called a Compilation Zine. Together with your troop or family, make a group zine.');
INSERT INTO badge_optional_requirements VALUES(9205,739,7,'Make a collage to include in your zine.');
INSERT INTO badge_optional_requirements VALUES(9206,739,8,'Learn to make a virtual zine on a computer.');
INSERT INTO badge_optional_requirements VALUES(9207,739,9,'List at least ten themes you could make a zine about.');
INSERT INTO badge_optional_requirements VALUES(9208,739,10,'Learn about Oulipo and how these writing techniques can make zines more unique.');
INSERT INTO badge_optional_requirements VALUES(9209,739,11,'Complete a community service project involving zines, such as selling them to raise money for charity, distributing zines on an important issue, or teaching a class how to make zines.');
INSERT INTO badge_optional_requirements VALUES(9210,739,12,'Learn different ways of binding zines, like folding paper, stitching papers together, or gluing or stapling pages together.');
INSERT INTO badge_optional_requirements VALUES(9211,739,13,'Edit a zine made by someone else.');
INSERT INTO badge_optional_requirements VALUES(9212,739,14,'Contribute to a zine someone else is making.');
INSERT INTO badge_optional_requirements VALUES(9213,739,15,'Draw a sketch to include in your zine.');
INSERT INTO badge_optional_requirements VALUES(9214,739,16,'Trading zines is a popular practice within the zine community. Host a trading event with your friends to share zines you’ve made or collected.');
INSERT INTO badge_optional_requirements VALUES(9215,739,17,'Collect at least ten zines on topics that interest you.');
INSERT INTO badge_optional_requirements VALUES(9216,739,18,'Write a poem to include in your zine.');
INSERT INTO badge_optional_requirements VALUES(9217,739,19,'Draw a short comic strip to include in your zine.');
INSERT INTO badge_optional_requirements VALUES(9218,739,20,'Read a guide to making zines. A short one appropriate for all ages is available here: https://www.readbrightly.com/how-to-make-zine/. More in-depth options can also be found for older readers.');
INSERT INTO badge_optional_requirements VALUES(9219,739,21,'Earn the bookbinding badge at your level.');
INSERT INTO badge_optional_requirements VALUES(9220,739,22,'Create a zine using the Cut-Up technique by cutting and rearranging old text to create something new.');
INSERT INTO badge_optional_requirements VALUES(9221,739,23,'Learn about what a Risograph is and how it works');
INSERT INTO badge_optional_requirements VALUES(9222,739,24,'Learn what Ephermera is and what types can be included in zine.');
INSERT INTO badge_optional_requirements VALUES(9223,739,25,'Explore how zines can be used as an educational tool. Create a zine that explains a topic of interest to you.');
INSERT INTO badge_optional_requirements VALUES(9224,739,26,'Learn about the preservation of zines. Discuss the challenges and ways to ensure zines are archived for future generations.');
INSERT INTO badge_optional_requirements VALUES(9225,739,27,'Investigate how technology has influenced zine culture. Create a list of online platforms for sharing zines.');
INSERT INTO badge_optional_requirements VALUES(9226,739,28,'Attend a zine festival or event, documenting your experience and favorite discoveries.');
INSERT INTO badge_optional_requirements VALUES(9227,739,29,'Explore different ways zines are distributed, from trading to online platforms.');
INSERT INTO badge_optional_requirements VALUES(9228,739,30,'Look online at some zines for sale. How much do people charge for zines?');
INSERT INTO badge_optional_requirements VALUES(9229,739,31,'Learn about different ways to print and self publish your zine.  For example you can hand draw, write and bind a simple zine or you can computer print your zine and have it spiral bound at a local office store.  You can create a digital zine people can read online or print themeselves.  If you plan to print many copies of your zine, what is the most cost effective way to do so?  What is involved?');
INSERT INTO badge_optional_requirements VALUES(9230,740,3,'Find out what the steepest zipline in the world is.  Which zipline is the longest?');
INSERT INTO badge_optional_requirements VALUES(9231,740,4,'Find out at least 3 other names for ziplining.');
INSERT INTO badge_optional_requirements VALUES(9232,740,5,'Make a map of recreational zipline courses around the world.  Include at least 5 courses for Preschool, and Level 1, and 10 for Level 2, Level 3 and Level 4, and 15 for Level 5.  Look at pictures of these courses and understand the terrain you would see if you were able to ride them.');
INSERT INTO badge_optional_requirements VALUES(9233,740,6,'Look through catalogs or online to find different types of backyard ziplines.  What are the safety concerns someone should consider before installing a backyard zipline?');
INSERT INTO badge_optional_requirements VALUES(9234,740,7,'Find out what careers there are in ziplining.  Examples might include engineers of backyard or professional ziplines, zipline guides, maintenance personnel, zipline inspector, etc.  What type of education is required?  What type of salary could you expect?  Where might you have to live and work?');
INSERT INTO badge_optional_requirements VALUES(9235,740,8,'Diagram a basic zipline system and identify all the different parts involved.');
INSERT INTO badge_optional_requirements VALUES(9236,740,9,'Design a fantasy zipline course.  Where would it be?  What would you see?  How far and how fast would you go?');
INSERT INTO badge_optional_requirements VALUES(9237,740,10,'Interview someone who works with ziplines or have them come visit your club.');
INSERT INTO badge_optional_requirements VALUES(9238,741,3,'What is an endangered species? Why should zoos protect them? Name at least three endangered species zoos are currently trying to save.');
INSERT INTO badge_optional_requirements VALUES(9239,741,4,'How do zoos educate others about animals and protecting their habitat? Â Create a flyer or brochure to educate others about your favorite animal at the zoo.');
INSERT INTO badge_optional_requirements VALUES(9240,741,5,'Visit a petting zoo.');
INSERT INTO badge_optional_requirements VALUES(9241,741,6,'Learn safari style zoos where the animals are all kept in a large open habitat where they interact with each other much as they would in the wild. Visit one if possible.');
INSERT INTO badge_optional_requirements VALUES(9242,741,7,'Find out how zoos get their animals.');
INSERT INTO badge_optional_requirements VALUES(9243,741,8,'What is meant by adopting a zoo animal? Would you consider doing it? Why or why not?');
INSERT INTO badge_optional_requirements VALUES(9244,741,9,'Create a plan for your own zoo either on paper, or using a computer program such as Zoo Tycoon. What animals would you keep? Where would they each be located? What amenities would you have for your visitors (make sure to have enough bathrooms and drinking fountains!)? What type of shows or exhibits might you have?');
INSERT INTO badge_optional_requirements VALUES(9245,741,10,'Learn about different careers that involve zoos such as animal trainer, veterinarian, zoo management, etc. What education is needed for these jobs? How much might you be paid? What hours might you have to work?');
INSERT INTO badge_optional_requirements VALUES(9246,741,11,'Tour behind the scenes of a zoo and learn how the zoo is run.');
INSERT INTO badge_optional_requirements VALUES(9247,741,12,'Make a list of all the zoos within 150 miles of your home. Include petting zoos and wild life rescue facilities that allow public viewing of the animals.');
INSERT INTO badge_optional_requirements VALUES(9248,743,3,'Tell a story that you made up.');
INSERT INTO badge_optional_requirements VALUES(9249,743,4,'Tell a story with puppets, props, illustrations, or costumes.');
INSERT INTO badge_optional_requirements VALUES(9250,743,5,'Record your story to send to a relative or friend.');
INSERT INTO badge_optional_requirements VALUES(9251,743,6,'Draw pictures or make a movie to tell your story');
INSERT INTO badge_optional_requirements VALUES(9252,743,7,'Add sound effects or compose music to go with your story.');
INSERT INTO badge_optional_requirements VALUES(9253,743,8,'Find a story in real life told from two viewpoints. You may ask you parent to tell a story from their childhood and then ask a relative to give his or her version, or find a traditional story told by different characters. Why can the same story sound so different from another source?');
INSERT INTO badge_optional_requirements VALUES(9254,743,9,'Tell a story that has a moral. How can you emphasize a moral when telling a story?');
INSERT INTO badge_optional_requirements VALUES(9255,743,10,'Tell a chapter story so that people have to wait for the next installment.');
INSERT INTO badge_optional_requirements VALUES(9256,743,11,'Tell the same story separately to more than one age group. Did you have to change it for the different groups?');
INSERT INTO badge_optional_requirements VALUES(9257,743,12,'Do a story time for a little kids'' club/classroom/library.');
INSERT INTO badge_optional_requirements VALUES(9258,743,13,'What is something significant you learned from (1) hearing a story and (2) telling a story? Share this with your club or leader or write out what you learned');
INSERT INTO badge_optional_requirements VALUES(9259,744,3,'Learn to play a new video game that is approved by your parent, guardian, or teacher.');
INSERT INTO badge_optional_requirements VALUES(9260,744,4,'With your parents, create a plan to buy a video game that is right for your age group. Compare the price for this game at three different stores. Decide which store has the best deal. In your decision, be sure to consider things like coupons, used games, and travel costs.');
INSERT INTO badge_optional_requirements VALUES(9261,744,5,'Play a video game with a family member for at least 30 minutes. Why is it important to choose a video game that is age and content appropriate for everyone?');
INSERT INTO badge_optional_requirements VALUES(9262,744,6,'Research the possible career of a professional video gamer. Are there any professional video game competitions?');
INSERT INTO badge_optional_requirements VALUES(9263,744,7,'With an adult''s supervision, teach an older person (like a grandparent) how to play a video game.');
INSERT INTO badge_optional_requirements VALUES(9264,744,8,'Invent your own video game. What is the concept of the game? Draw three different scenes from the game.');
INSERT INTO badge_optional_requirements VALUES(9265,744,9,'What safety issues are involved with gaming? Create a list of Internet safety rules for yourself that you follow while gaming.');
INSERT INTO badge_optional_requirements VALUES(9266,744,10,'Learn about some of the benefits of playing video games such as improved problem-solving skills, enhanced creativity, or better hand-eye coordination.');
INSERT INTO badge_optional_requirements VALUES(9267,744,11,'Explore an educational video game that teaches you something new, like a language, history, or science.');
INSERT INTO badge_optional_requirements VALUES(9268,744,12,'Create a timeline for video game advancements. Include at least 15 different events.');
INSERT INTO badge_optional_requirements VALUES(9269,744,13,'Learn about video game apps created for smart phones and tablets. How do these differ from traditional video games?');
INSERT INTO badge_optional_requirements VALUES(9270,744,14,'Play at least one online video game on the internet (with a parent''s permission!) What type of games are available for free on the internet for your age group? Can you find any educational online games?');
INSERT INTO badge_optional_requirements VALUES(9271,744,15,'Learn about a career that involves video games. You might look into game designers, programmers, marketers, etc. What type of education would you need for this job? What type of salary might you expect? Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(9272,744,16,'Participate in community service project that involves video games. For example, you might run a video game drive and donate the games to the Salvation Army or other organization to sell. Older kids might choose to teach younger kids how to use video games to help with their schoolwork.');
INSERT INTO badge_optional_requirements VALUES(9273,745,3,'Learn the history of waffles and waffle irons. Which country takes credit for making them first? When did waffles arrive in America? Who is thought to have brought them to America?');
INSERT INTO badge_optional_requirements VALUES(9274,745,4,'Learn the different types of waffles and the difference between them including but not limited to: Standard, Belgian, Brussels, Liege, Hong Kong Bubble, Stroopwafel and Waffle on a stick. Which type is your favorite?');
INSERT INTO badge_optional_requirements VALUES(9275,745,5,'What are waffles made of? How is a waffle different from a pancake? Try making waffles and pancakes to compare both the batter, and the cooking and eating experience.');
INSERT INTO badge_optional_requirements VALUES(9276,745,6,'Draw or paint a picture of a waffle.');
INSERT INTO badge_optional_requirements VALUES(9277,745,7,'Read a story about waffles and discuss the elements of the story.');
INSERT INTO badge_optional_requirements VALUES(9278,745,8,'Research famous waffle restaurants or stands around the world and present your findings.');
INSERT INTO badge_optional_requirements VALUES(9279,745,9,'Write a creative story involving waffles.');
INSERT INTO badge_optional_requirements VALUES(9280,745,10,'Waffle irons can be used for making things other than waffles, such as cornbread, hash browns and brownies. Try making something other than waffles using a waffle iron.');
INSERT INTO badge_optional_requirements VALUES(9281,745,11,'Try other waffle inspired foods such as waffle fries, waffle chips, "chicken and waffles," waffle cones, "wonut" (a waffle donut), or "wookie" ( a waffle cookie.) Or, try making your own waffle creation (perhaps a waffle sandwich, waffle tacos or a waffle hotdog.)');
INSERT INTO badge_optional_requirements VALUES(9282,745,12,'Learn a song or poem about waffles.');
INSERT INTO badge_optional_requirements VALUES(9283,745,13,'Participate in a community service project that has something to do with waffles, such as host a charity waffle breakfast, or donate waffles/waffle box mixes to your local food pantry.');
INSERT INTO badge_optional_requirements VALUES(9284,745,14,'Watch a video of how waffle cones or waffle fries are made.');
INSERT INTO badge_optional_requirements VALUES(9285,745,15,'Learn about companies that make waffles (Kellogg''s Eggo, Aunt Jemima, Krusteaz, Waffle House, Daelmans, Stroopies, etc.)');
INSERT INTO badge_optional_requirements VALUES(9286,745,16,'Play a fun game using waffles. It can be a board game, a food game, or your own creation.');
INSERT INTO badge_optional_requirements VALUES(9287,746,3,'Understand what AP classes are an how they earn you college credit as well as what CLEP tests are how they also earn college credits.  Understand what types of scores and tests are needed for credit at the college you are considering attending.');
INSERT INTO badge_optional_requirements VALUES(9288,746,4,'Colleges look at your extracurricular activities to see if you are well rounded individual.  Participate in at least three extracurricular activities.');
INSERT INTO badge_optional_requirements VALUES(9289,746,5,'Create or update a resume.  Have someone experienced in hiring review your resume for content and grammar.');
INSERT INTO badge_optional_requirements VALUES(9290,746,6,'Complete at least three scholarship applications.');
INSERT INTO badge_optional_requirements VALUES(9291,746,7,'Research what the ACT and SAT tests are and which colleges require them.  Take the PSAT or PreACT to see where your strengths and weaknesses are and develop a plan to improve before you take the actual ACT or SAT.');
INSERT INTO badge_optional_requirements VALUES(9292,746,8,'Visit at least two colleges.  If you are unable to visit them in person use the virtual tours that colleges offer on their websites. Attend open houses and college fairs.');
INSERT INTO badge_optional_requirements VALUES(9293,746,9,'Research your desired college and write down all admissions requirements to create your own checklist and timeline.');
INSERT INTO badge_optional_requirements VALUES(9294,746,10,'Research and write down the timeline of when college admissions applications should be turned in for each college you are interested in.');
INSERT INTO badge_optional_requirements VALUES(9295,746,11,'Research what occupations are available for the degree you are seeking.  Search for people who work in occupations you are interested in and write pros and cons of the occupation.  Shadow someone for a day in an occupation you think you would enjoy.  If possible get an internship.');
INSERT INTO badge_optional_requirements VALUES(9296,746,12,'Entrance to college is based partly on your grade point average.  Maintain a 3.0 GPA or better in all classes for a full semester.');
INSERT INTO badge_optional_requirements VALUES(9297,746,13,'Take an aptitude, personality and skills test to determine your strengths for different occupations.');
INSERT INTO badge_optional_requirements VALUES(9298,746,14,'Attend a job fair and talk with people about job options in your community.');
INSERT INTO badge_optional_requirements VALUES(9299,747,3,'Create a craft that could be used as a decoration for the holiday you chose.');
INSERT INTO badge_optional_requirements VALUES(9300,747,4,'Find a traditional song about the holiday you chose. Learn about the song''s history, including why and when it was composed, and be able to perform or recite the lyrics.');
INSERT INTO badge_optional_requirements VALUES(9301,747,5,'Find a game that commemorates the holiday you chose. Play this game with your family, friends, or group. The game can be one played in your country, or in another country you chose in requirement 2.');
INSERT INTO badge_optional_requirements VALUES(9302,747,6,'Find out what is typically worn (a costume) in another country (such as one chosen in requirement #2). Tell your family, friends, or group about the costume (why is is worn, what the parts of the costume signify, etc.).');
INSERT INTO badge_optional_requirements VALUES(9303,747,7,'Find out what organizations do special things for the homeless, elderly, indigent, veterans, or military during the holiday you chose. Volunteer your time individually or as a group for one of these organizations. Preschool-Level 1: Volunteer at least 1 hour. Level 2: At least 2 hours. Level 3: At least 3 hours. Level 4: At least 4 hours. Level 5: At least 5 hours.');
INSERT INTO badge_optional_requirements VALUES(9304,747,8,'Holidays are supposed to be a time to spend with family. Plan an activity to do with your family (examples include: scavenger hunt, a game or a skit).');
INSERT INTO badge_optional_requirements VALUES(9305,747,9,'Create a greeting card for the holiday you chose, and give it to a friend or family member. Include a personal message that demonstrates your understanding of the holiday''s significance.');
INSERT INTO badge_optional_requirements VALUES(9306,747,10,'Research the holiday''s traditions in at least three different countries, and create a comparison chart/poster highlighting the similarities and differences.');
INSERT INTO badge_optional_requirements VALUES(9307,747,11,'Compile a playlist of songs associated with the holiday you chose and share it with your family or group.');
INSERT INTO badge_optional_requirements VALUES(9308,747,12,'Write a short essay about what the holiday means to you personally and how you celebrate it.');
INSERT INTO badge_optional_requirements VALUES(9309,747,13,'Create a timeline of the holiday''s history, highlighting key events and changes over the years.');
INSERT INTO badge_optional_requirements VALUES(9310,747,14,'Identify and explain five symbols or icons associated with the holiday.  Why do these icon represent this holiday?');
INSERT INTO badge_optional_requirements VALUES(9311,747,15,'Research and participate in at least one traditional ritual or custom associated with the holiday.');
INSERT INTO badge_optional_requirements VALUES(9312,747,16,'Learn about a historical figure associated with the holiday and present your findings.');
INSERT INTO badge_optional_requirements VALUES(9313,747,17,'Attend a celebration or service at a church or a festival that commemorates the holiday you chose.');
INSERT INTO badge_optional_requirements VALUES(9314,747,18,'Read or listen to a traditional story or legend associated with the holiday and summarize it.');
INSERT INTO badge_optional_requirements VALUES(9315,747,19,'Explore artworks and literature inspired by the holiday.');
INSERT INTO badge_optional_requirements VALUES(9316,747,20,'Interview a family member or friend about their holiday traditions and share your findings.');
INSERT INTO badge_optional_requirements VALUES(9317,747,21,'Watch a movie or documentary about the holiday and discuss its portrayal.');
INSERT INTO badge_optional_requirements VALUES(9318,747,22,'Write a poem that captures the essence of the holiday.');
INSERT INTO badge_optional_requirements VALUES(9319,748,3,'Dress up like your favorite superhero and perform a skit or short movie in which you are using the character''s powers.');
INSERT INTO badge_optional_requirements VALUES(9320,748,4,'Create a piece of art with your superhero''s logo.');
INSERT INTO badge_optional_requirements VALUES(9321,748,5,'Create your own superhero. Include his/her name, costume, origin story, special powers/gadgets, alter ego and at least one villain.');
INSERT INTO badge_optional_requirements VALUES(9322,748,6,'Play a video game or board game that involves your superhero.');
INSERT INTO badge_optional_requirements VALUES(9323,748,7,'Read a comic book or watch a movie that involves your superhero.');
INSERT INTO badge_optional_requirements VALUES(9324,748,8,'Visit a science center or museum that has a superhero exhibit.');
INSERT INTO badge_optional_requirements VALUES(9325,748,9,'Learn about the creator(s) of your superhero. When was the character first introduced?');
INSERT INTO badge_optional_requirements VALUES(9326,748,10,'Does your character have a sidekick or does he/she work alone? Learn about your character''s sidekick(s). Do they have any special powers? What is their relationship with your superhero? If your character does not have a sidekick, create one. Draw a picture of their sidekick or the one you created.');
INSERT INTO badge_optional_requirements VALUES(9327,748,11,'Learn about where your character lives or about his secret base (e.g. Asgard, the Batcave, etc.). What makes their home/base unique? Create a map of the layout.');
INSERT INTO badge_optional_requirements VALUES(9328,748,12,'Learn about your character''s love interest and the impact their relationship has on them being a superhero. (e.g. Jane, M.J., Lois Lane, etc.) How did they meet their love interest? Do they have any special powers?');
INSERT INTO badge_optional_requirements VALUES(9329,748,13,'Write your own comic about your superhero. Include existing characters within the story or create your own.');
INSERT INTO badge_optional_requirements VALUES(9330,748,14,'What merchandise/fan apparel is available on the market for your character?');
INSERT INTO badge_optional_requirements VALUES(9331,748,15,'Does your character belong to a team? What team? Who are the members? If your character does not belong to a team, create one.');
INSERT INTO badge_optional_requirements VALUES(9332,748,16,'Does your superhero have any famous catchphrases? What are they?');
INSERT INTO badge_optional_requirements VALUES(9333,748,17,'How has your superhero been portrayed in media (TV shows, movies, video games)? Which portrayal is most faithful to the comics?');
INSERT INTO badge_optional_requirements VALUES(9334,748,18,'What can you learn about good vs. evil or right vs. wrong from your superhero? What character traits make your superhero heroic? Earn a character badge of your choice in honor of your chosen superhero and seek to demonstrate that trait in your life.');
INSERT INTO badge_optional_requirements VALUES(9335,749,1,'Learn about corn anatomy and life cycle.');
INSERT INTO badge_optional_requirements VALUES(9336,749,2,'Complete an existing paper maze that is reasonably challenging for your skill level.');
INSERT INTO badge_optional_requirements VALUES(9337,749,3,'Watch a movie or read a book that contains a corn maze.');
INSERT INTO badge_optional_requirements VALUES(9338,749,4,'Learn about maze designs, especially the theme designs created by different Corn Maze locations.  Do mazes change each year?  Why or why not?');
INSERT INTO badge_optional_requirements VALUES(9339,749,5,'Design a floor plan for a corn maze.');
INSERT INTO badge_optional_requirements VALUES(9340,749,6,'Create a maze for someone to solve.');
INSERT INTO badge_optional_requirements VALUES(9341,749,7,'Research the history of mazes and labyrinths. How long have they existed? What were they originally used for?');
INSERT INTO badge_optional_requirements VALUES(9342,749,8,'Eat a food that contains corn at a corn maze or festival.');
INSERT INTO badge_optional_requirements VALUES(9343,749,9,'Earn an associated badge, such as Farm Equipment, Farmer, Grain, Vegetable (Corn).');
INSERT INTO badge_optional_requirements VALUES(9344,749,10,'Create a piece of artwork inspired by corn mazes, using various mediums like painting, drawing, or digital design.');
INSERT INTO badge_optional_requirements VALUES(9345,749,11,'Write a reflective essay or create a video sharing your personal insights and experiences from navigating corn mazes.');
INSERT INTO badge_optional_requirements VALUES(9346,750,3,'Create a poster or piece of art that shows what you know about your chosen animal.');
INSERT INTO badge_optional_requirements VALUES(9347,750,4,'Watch a documentary about your chosen animal.');
INSERT INTO badge_optional_requirements VALUES(9348,750,5,'Write a poem about your chosen animal.');
INSERT INTO badge_optional_requirements VALUES(9349,750,6,'Participate in a community service project that helps animals.');
INSERT INTO badge_optional_requirements VALUES(9350,750,7,'Learn about careers that are related to your chosen animal''s story.');
INSERT INTO badge_optional_requirements VALUES(9351,750,8,'Interview a local veterinarian, animal trainer, or wildlife expert about the type of animal your famous animal is.');
INSERT INTO badge_optional_requirements VALUES(9352,750,9,'Create a presentation about your famous animal and share it with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(9353,750,10,'Write a short story or play from the perspective of your chosen famous animal.');
INSERT INTO badge_optional_requirements VALUES(9354,750,11,'Visit a zoo, aquarium, wildlife sanctuary, or a location related to your famous animal.');
INSERT INTO badge_optional_requirements VALUES(9355,750,12,'Choose a cause or charity that supports the type of animal your chosen famous animal is.  Support that charity. For example: Smokey the Bear was a famous bear who helped prevent forest fires so you could support your local fire department.  Seabiscuit was a famous race horse so you could support an equine rescue.');
INSERT INTO badge_optional_requirements VALUES(9356,750,13,'Create a coloring or activity book to help teach about why your animal is famous.');
INSERT INTO badge_optional_requirements VALUES(9357,751,3,'Create a meme of a family member that you think they would enjoy.');
INSERT INTO badge_optional_requirements VALUES(9358,751,4,'Use some popular meme backgrounds (angry baby, grumpy cat, etc.) and create your own captions.');
INSERT INTO badge_optional_requirements VALUES(9359,751,5,'Hold a meme contest and vote on the funniest meme.');
INSERT INTO badge_optional_requirements VALUES(9360,751,6,'Learn what fair use is and how it applies to memes.');
INSERT INTO badge_optional_requirements VALUES(9361,751,7,'Learn about the ethical implications of sharing memes. What should you consider before sharing a meme?');
INSERT INTO badge_optional_requirements VALUES(9362,751,8,'Learn about what ''going viral'' means.  What qualities make a meme likely to go viral?');
INSERT INTO badge_optional_requirements VALUES(9363,751,9,'Learn about how memes are used in advertising and marketing. Create a meme that could be used to promote a product or cause.');
INSERT INTO badge_optional_requirements VALUES(9364,751,10,'Compare and contrast memes from different cultures or countries.  How do humor and references differ?');
INSERT INTO badge_optional_requirements VALUES(9365,751,11,'Choose a meme from at least 3 years ago that highlighted specific problems (political, social, religious) and research the effects that it had on the conversation.');
INSERT INTO badge_optional_requirements VALUES(9366,751,12,'Create a timeline for memes.  Start with the first internet memes of the 1990''s and explain how they evolved with technology.');
INSERT INTO badge_optional_requirements VALUES(9367,751,13,'Learn about "bad" memes that missed the mark.  These are often used in political satire or advertisement.');
INSERT INTO badge_optional_requirements VALUES(9368,751,14,'Watch a meme compilation video from a trusted Youtuber or other video site.  Do you also find them funny?');
INSERT INTO badge_optional_requirements VALUES(9369,751,15,'Learn about the career of a graphic designer or a marketer. How has meme culture informed these jobs?');
INSERT INTO badge_optional_requirements VALUES(9370,751,16,'Create a meme page or account on a social media platform (with parental permission) and share your original memes.');
INSERT INTO badge_optional_requirements VALUES(9371,68,1,'Batman knows a butler named Alfred Pennyworth. Find out something new about Alfred.');
INSERT INTO badge_optional_requirements VALUES(9372,68,2,'Batman has many enemies. Find out why one of them chose to live a life of crime.');
INSERT INTO badge_optional_requirements VALUES(9373,68,3,'Watch a Batman movie or TV show. Discuss with an adult what lesson you learned.');
INSERT INTO badge_optional_requirements VALUES(9374,68,4,'Donate a Batman toy to charity.');
INSERT INTO badge_optional_requirements VALUES(9375,68,5,'Research the history of Batman. Who drew the first Batman? When was the first Batman comic published? When did the first Batman TV show aired? When was the first Batman movie released? What licensed toys and games are now available?');
INSERT INTO badge_optional_requirements VALUES(9376,68,6,'Go online and explore the DC Comics website with your parents’ permission.');
INSERT INTO badge_optional_requirements VALUES(9377,68,7,'Read three Batman books. (Level 5 – read three Batman books and a book about Batman, such as one listed in the footnotes).');
INSERT INTO badge_optional_requirements VALUES(9378,68,8,'Read a biography about one of Batman’s writers, illustrators, actors, or voice actors.');
INSERT INTO badge_optional_requirements VALUES(9379,68,9,'Design or create the superhero costume you would wear if you were Batman’s new sidekick.');
INSERT INTO badge_optional_requirements VALUES(9380,68,10,'Sometimes even Batman needs help from his friends. Celebrate a superhero party with help from your friends.');
INSERT INTO badge_optional_requirements VALUES(9381,68,11,'Make and play a Batman theme game.');
INSERT INTO badge_optional_requirements VALUES(9382,68,12,'Make your own “Bat Signal” with a flashlight and black construction paper.');
INSERT INTO badge_optional_requirements VALUES(9383,68,13,'Make your own “Batmobile”.');
INSERT INTO badge_optional_requirements VALUES(9384,68,14,'Draw your own Batman comic strip.');
INSERT INTO badge_optional_requirements VALUES(9385,68,15,'Write your own Batman adventure.');
INSERT INTO badge_optional_requirements VALUES(9386,68,16,'Batman is very observant. Play an observation game, such as “I Spy” or “Memory”.');
INSERT INTO badge_optional_requirements VALUES(9387,68,17,'Batman works hard to stay fit and healthy. Practice a sport or fitness activity to improve your skills.');
INSERT INTO badge_optional_requirements VALUES(9388,68,18,'Batman is a good detective. Read a real life or fictional mystery.');
INSERT INTO badge_optional_requirements VALUES(9389,68,19,'Batman knows about forensic science. Do a science experiment or investigation about chemical analysis, fingerprints, footprints, tire tracks, DNA, accident reconstruction, handwriting analysis, or other type of physical evidence. Third Party Resources: The Essential Batman Encyclopedia by Robert Greenberger Batman Unauthorized: vigilantes, Jokers, and Heroes in Gotham City The Batman Companion by Michael Eury Billion Dollar Batman by Bruce Scivally Batman and Psychology by Travis Langley God on the Streets of Gotham by Paul Asay Soul of the Dark Knight by Alex M. Wainer Batman: A visual history by Matthew Manning');
INSERT INTO badge_optional_requirements VALUES(9390,198,1,'Find out what foods are typical of diner fare. What are blue plate specials?');
INSERT INTO badge_optional_requirements VALUES(9391,198,2,'Design your own diner menu.');
INSERT INTO badge_optional_requirements VALUES(9392,198,3,'Look at pictures of typical diner décor. How and why did the materials used change over the years? Design your own diner on paper, or make a 3-D model.');
INSERT INTO badge_optional_requirements VALUES(9393,198,4,'How is a diner different from a drive-in? What are carhops and what was their original name?');
INSERT INTO badge_optional_requirements VALUES(9394,198,5,'Watch a documentary about diners or an episode of Diners, Drive-is and Dives.');
INSERT INTO badge_optional_requirements VALUES(9395,198,6,'Learn diner lingo and terminology.  For example, “Walk A Cow Through The Garden” means a burger with lettuce, tomato and onion.  Learn at least 10 Diner phrases.');
INSERT INTO badge_optional_requirements VALUES(9396,198,7,'Create your own diner night with your family, friends or troop! Pick a theme for your diner, use the menu from Requirement #4. Play music, take orders, use the lingo you learned in Requirement #9. Make it as simple or elaborate as you’d like!');
INSERT INTO badge_optional_requirements VALUES(9397,198,8,'Make a map of diners in your state. Visit some if you can.');
INSERT INTO badge_optional_requirements VALUES(9398,198,9,'Research the market for diner collectibles and memorabilia.');
INSERT INTO badge_optional_requirements VALUES(9399,198,10,'With your parent’s permission, go online to see a diner museum. Or visit one in person!');
INSERT INTO badge_optional_requirements VALUES(9400,198,11,'If possible, job shadow at a diner (owner, cook, waitstaff, etc.).');
INSERT INTO badge_optional_requirements VALUES(9401,198,12,'Compare and contrast the characteristics of diners in different regions of the U.S. (e.g., East Coast vs. Midwest).');
INSERT INTO badge_optional_requirements VALUES(9402,198,13,'Identify and describe three different architectural styles of diners.');
INSERT INTO badge_optional_requirements VALUES(9403,198,14,'Identify 3 diners that are known for specific iconic dishes and why.');
INSERT INTO badge_optional_requirements VALUES(9404,198,15,'Research how diners have been depicted in movies and TV shows. Name at least three examples.');
INSERT INTO badge_optional_requirements VALUES(9405,198,16,'Research and explain the economic impact of diners on small towns and local communities.');
INSERT INTO badge_optional_requirements VALUES(9406,198,17,'Research three diner chains (e.g., Denny’s, IHOP) and compare them to independent diners.');
INSERT INTO badge_optional_requirements VALUES(9407,198,18,'Research how diners have influenced American culture and cuisine.');
INSERT INTO badge_optional_requirements VALUES(9408,198,19,'Compile a collection of diner recipes, either from your own research or by talking to diner chefs.');
INSERT INTO badge_optional_requirements VALUES(9409,217,1,'What are movies are based off of Dr. Seuss’ books? Watch at least two of them.');
INSERT INTO badge_optional_requirements VALUES(9410,217,2,'Create a craft based on one of the books you read. For example, The Cat in the Hat’s hat, Red Fish and Blue Fish made out of your handprint, etc.');
INSERT INTO badge_optional_requirements VALUES(9411,217,3,'Try some green eggs and ham! Use food coloring to dye eggs green and serve them with ham.');
INSERT INTO badge_optional_requirements VALUES(9412,217,4,'Complete a service project based on Dr. Seuss. For instance, you could donate or volunteer to read Dr. Seuss books to a local children’s hospital, library, school or homeless shelter.');
INSERT INTO badge_optional_requirements VALUES(9413,217,5,'Write a rhyming poem in a style similar to Dr. Seuss’ writing style.');
INSERT INTO badge_optional_requirements VALUES(9414,217,6,'Conduct a Dr. Seuss experiment! For example, make Oobleck from the book Bartholomew and the Oobleck. Mix 1.5 to 2 cups of corn starch with 1 cup of water. Add some food coloring to create a non-Newtonian fluid that is fun to play with!');
INSERT INTO badge_optional_requirements VALUES(9415,217,7,'Some of Dr. Seuss’ books include a political or social message. Read a Dr. Seuss book such as The Butter Battle Book, The Sneetches or Yertle the Turtle and write a short paragraph on what you think the message of the book is.');
INSERT INTO badge_optional_requirements VALUES(9416,217,8,'Research a career in children’s fiction. How do you go about getting a book published? What is the writing process like? What is the typical salary of a children’s writer?');
INSERT INTO badge_optional_requirements VALUES(9417,217,9,'Learn more about Dr. Seuss’ life. Why did he chose the pen name Dr. Seuss? How did he become interested in children’s fiction? Why were his books so famous? Did he have any children of his own?');
INSERT INTO badge_optional_requirements VALUES(9418,217,10,'Illustrate and write your own short story with characters, settings, and situations similar to the ones in a Dr. Seuss story.');
INSERT INTO badge_optional_requirements VALUES(9419,261,1,'Learn how to make your own fidget.');
INSERT INTO badge_optional_requirements VALUES(9420,261,2,'Earn a badge about a sensory processing disorder (such as Autism Awareness) or a Diseases and Genetic Disorders badge about an attention deficit disorder or anxiety.');
INSERT INTO badge_optional_requirements VALUES(9421,261,3,'Many doctors believe there is a connection between stress and fidgeting – Research other ways of relieving stress such as yoga and breathing exercises');
INSERT INTO badge_optional_requirements VALUES(9422,261,4,'Do a community service project such as creating fidget blankets for alzheimer’s patients, creating posters about eliminating distractions or showcasing the benefits of fidgets, or create a fidget box for a classroom or meeting space. Make sure to include plenty of different options for all types of fidgeting!');
INSERT INTO badge_optional_requirements VALUES(9423,261,5,'Be a scientist! Using a fidget spinner investigate the length of time you can keep spinning. Find the average spin.');
INSERT INTO badge_optional_requirements VALUES(9424,261,6,'Try to challenge yourself with a fidget spinner challenge!');
INSERT INTO badge_optional_requirements VALUES(9425,261,7,'Don’t just make your own fidget, but become a designer. What elements should be present in a fidget What works best for you?');
INSERT INTO badge_optional_requirements VALUES(9426,261,8,'Fidgets are an important tool for many people. Why do people use fidgets? Name some of the benefits of using fidgets');
INSERT INTO badge_optional_requirements VALUES(9427,261,9,'Many schools and groups are banning fidgets. Explore and explain why fidgets can be called a distraction.');
INSERT INTO badge_optional_requirements VALUES(9428,261,10,'Create a contract or rules for when to use fidgets in your classroom or home.');
INSERT INTO badge_optional_requirements VALUES(9429,261,11,'Choose one type of fidget and learn how it was created, who invented it and the research behind it.');
INSERT INTO badge_optional_requirements VALUES(9430,271,1,'Sometimes situations change because of a more pressing need or an important opportunity. With this, we need to examine priorities, change the plans, and communicate with those involved. Role play with a parent or other adult the decision-making process involved in adjusting plans. Discuss the competing priorities.  When do you need to honor commitments despite a better sounding opportunity and when do you need to take the opportunity? If a plan gets blocked, how will you handle it? What constitutes an emergency and what needs to be done then? Who needs to know about changes?');
INSERT INTO badge_optional_requirements VALUES(9431,271,2,'Discuss careers that involve a lot of flexibility and some that need less.');
INSERT INTO badge_optional_requirements VALUES(9432,271,3,'Write a story or skit where flexibility plays an important role.');
INSERT INTO badge_optional_requirements VALUES(9433,271,4,'Read a biography about someone known for their flexibility.');
INSERT INTO badge_optional_requirements VALUES(9434,271,5,'What does your book of faith say about flexibility? Memorize at least three verses about flexibility if you are preschool or Level 1, five if you are a Level 3 or 4, and seven if you are a Level 5.');
INSERT INTO badge_optional_requirements VALUES(9435,271,6,'Find and memorize at least three famous quotes about flexibility.');
INSERT INTO badge_optional_requirements VALUES(9436,271,7,'Divide a piece of paper into two sides. On one side, list words that describe healthy responses when plans change. On the other side, make a list of words that describe unhealthy and unhelpful responses. Discuss your list with someone else and see if they have ideas to add to it.');
INSERT INTO badge_optional_requirements VALUES(9437,271,8,'Arrange to have someone else plan a surprise flexibility challenge for you. Have them surprise you with a change in plans. Do your best to react appropriately.');
INSERT INTO badge_optional_requirements VALUES(9438,271,9,'Create a piece of art that shows flexibility.');
INSERT INTO badge_optional_requirements VALUES(9439,271,10,'With some friends, tell a chain story. Each person tells a part of the story. Be sure to be patient with the ideas of others.  As the story circles around back to you, remember to stay flexible as it may have changed quite a bit from where you intended it to go when it was last your turn.');
INSERT INTO badge_optional_requirements VALUES(9440,271,11,'Write an acrostic poem for FLEXIBILITY.');
INSERT INTO badge_optional_requirements VALUES(9441,271,12,'Write a poem or essay about the need for flexibility.');
INSERT INTO badge_optional_requirements VALUES(9442,271,13,'Using the Victorian Language of Flowers make a bouquet that symbolizes what flexibility means to you. You can find the meanings assigned to the flowers at various websites or in books and you may cut pictures from magazines or web pages to create a collage bouquet. Make sure you include the name and meaning of each flower that you choose. You may make a scrapbook page using pictures of flowers or make a bouquet using real or artificial flowers.');
INSERT INTO badge_optional_requirements VALUES(9443,271,14,'With parent or leader approval, you may count a situation where you demonstrated great flexibility. Write or discuss with an adult what you learned in the situation.');
INSERT INTO badge_optional_requirements VALUES(9444,303,1,'Wrap a present using fabric. How would you fasten the fabric so the gift doesn’t fall out?');
INSERT INTO badge_optional_requirements VALUES(9445,303,2,'Look at different ways you could wrap or decorate a large or bulky item.');
INSERT INTO badge_optional_requirements VALUES(9446,303,3,'Some stores and online retailers offer gift wrapping. How much does this usually cost? Can you specify what sort of wrapping you would like? Are the wrapping options as attractive as those you could purchase separately?');
INSERT INTO badge_optional_requirements VALUES(9447,303,4,'With your parent’s permission, go online and look at different ways of wrapping presents. (YouTube has some good videos on how to wrap presents.)');
INSERT INTO badge_optional_requirements VALUES(9448,303,5,'Learn how to make your own gift bags and pillow boxes. Make at least two of each.');
INSERT INTO badge_optional_requirements VALUES(9449,303,6,'Find a large roll of paper and make your own wrapping paper. You could draw pictures on it, do stenciling, use fun stickers, do rubber stamping on it, etc. Use your homemade wrapping paper to wrap a present.');
INSERT INTO badge_optional_requirements VALUES(9450,303,7,'Explore ways to recycle items such as toilet roll tubes, egg cartons, tissue boxes, etc., into gift wrapping supplies. Try at least two ways.');
INSERT INTO badge_optional_requirements VALUES(9451,303,8,'Learn how you would wrap the following: Gift cardsPackaged toysMoneyJewelryCosmeticsWine bottles or any other glass bottlesStuffed toysFragile or breakable objects (i.e.: glass, china, ceramics, etc.)');
INSERT INTO badge_optional_requirements VALUES(9452,303,9,'Learn how to correctly tie a ribbon around a present and how to tie a bow. Level 2 and up, learn how to curl the ends of a piece of ribbon. Level 3 and up, learn how to make a larger, more intricate separate bow.');
INSERT INTO badge_optional_requirements VALUES(9453,303,10,'Explore ways to use part of the gift as wrapping, such as using a new kitchen towel to wrap a bottle of olive oil, wrapping a gift for a man in a new shirt, or placing several small gifts inside a mixing bowl or a basket, for instance. Try at least two ideas.');
INSERT INTO badge_optional_requirements VALUES(9454,303,11,'Learn how to gift wrap a plant.');
INSERT INTO badge_optional_requirements VALUES(9455,303,12,'Learn how to make an origami gift box.');
INSERT INTO badge_optional_requirements VALUES(9456,303,13,'Learn how to package a gift of food, such as cookies.');
INSERT INTO badge_optional_requirements VALUES(9457,303,14,'Research fun ways to wrap presents for an event, such as a baby shower. For example, if you were giving a new mom a set of baby clothes, a teddy bear and a baby bath, you could lay the baby clothes around the edges of the baby bath and place the teddy in the middle.');
INSERT INTO badge_optional_requirements VALUES(9458,303,15,'Learn how to wrap a round or spherical present. Preschool and Level 1 should learn how to place items neatly and attractively in a gift bag with tissue paper; Level 2 and above should also learn how to wrap up a round or spherical object in paper.');
INSERT INTO badge_optional_requirements VALUES(9459,303,16,'Make a list of ways to reuse gift wrap and do at least two of them.');
INSERT INTO badge_optional_requirements VALUES(9460,303,17,'Learn how to wrap a present if you don’t have enough wrapping paper.');
INSERT INTO badge_optional_requirements VALUES(9461,306,1,'Research a company that is a leader in different types of skincare. Discuss the different types of products they offer, cost, and how well the products work.');
INSERT INTO badge_optional_requirements VALUES(9462,306,2,'Go to a salon and have an up-do done.');
INSERT INTO badge_optional_requirements VALUES(9463,306,3,'Have someone who specializes in proper skincare come speak to your troop about skin care, the products their company offers, which products should be used for your age level, and learn how to properly use these items.');
INSERT INTO badge_optional_requirements VALUES(9464,306,4,'Enjoy a spa day where you and your friends can get pampered. Use products such as lotion, a face mask, lip scrub, etc.');
INSERT INTO badge_optional_requirements VALUES(9465,306,5,'Learn what ingredients are in the products that you use. Research what some of these ingredients are made from, what they are used for, and how it benefits the product you are using.');
INSERT INTO badge_optional_requirements VALUES(9466,306,6,'Shadow a skin care, hair care, or beauty consultant. Ask them questions about their career, why they chose this field, and see what their typical day is like.');
INSERT INTO badge_optional_requirements VALUES(9467,306,7,'Research a leading skin care company. When was it founded? Who founded it? Does this company give back to the community?');
INSERT INTO badge_optional_requirements VALUES(9468,306,8,'Identify five products that would work, for your age level, to help protect your skin throughout the year.');
INSERT INTO badge_optional_requirements VALUES(9469,306,9,'Identify other businesses or companies, in your area, that offer the same services as the one you have worked with. What makes these companies similar? What makes these companies different?');
INSERT INTO badge_optional_requirements VALUES(9470,306,10,'Collect items for your local homeless shelter, women in crisis, or other center in which people can benefit from receiving skin care/hair care products');
INSERT INTO badge_optional_requirements VALUES(9471,306,11,'Set-up haircuts/updos for a local center which could benefit from receiving pampering services.');
INSERT INTO badge_optional_requirements VALUES(9472,306,12,'Names some items you can use every day to protect yourself from the natural environments, to keep your skin healthy. Name some items you should only use on occasion to help protect your skin.');
INSERT INTO badge_optional_requirements VALUES(9473,306,13,'What is corrective make-up? In what circumstances would someone use corrective make-up? What products are there for these occasions?');
INSERT INTO badge_optional_requirements VALUES(9474,306,14,'Name situations on why someone would want to alter their appearance using make-up.');
INSERT INTO badge_optional_requirements VALUES(9475,306,15,'How is make-up used in theater, movies and TV?');
INSERT INTO badge_optional_requirements VALUES(9476,306,16,'Learn what colors of accent make-up work well with different skin tones.');
INSERT INTO badge_optional_requirements VALUES(9477,306,17,'Research different careers in the skin care, makeup or beauty industry. What type of education or training would you need?');
INSERT INTO badge_optional_requirements VALUES(9478,316,1,'Learn what the your book of faith says about death and/or life after death.');
INSERT INTO badge_optional_requirements VALUES(9479,316,2,'Talk about your favorite memory or thoughts about the person or event you are grieving over.');
INSERT INTO badge_optional_requirements VALUES(9480,316,3,'Learn about the grieving process or steps of grief.  How do different types of people deal with grief?');
INSERT INTO badge_optional_requirements VALUES(9481,316,4,'Read a book designed to help deal with grief.');
INSERT INTO badge_optional_requirements VALUES(9482,316,5,'Think about and pick something you will do to honor your loved one or event you are grieving over.  This might be a craft or art project designed to display in your home to remember them, lighting a candle on special days, wearing a piece of jewelry to remember them, etc.');
INSERT INTO badge_optional_requirements VALUES(9483,316,6,'Keep an item that belonged to your loved one or a picture of them. (Make sure you have permission to keep the object)');
INSERT INTO badge_optional_requirements VALUES(9484,316,7,'Write a note or letter to your loved one telling them things you want them to know.');
INSERT INTO badge_optional_requirements VALUES(9485,316,8,'Perform an act of kindness to other family members or friends who are also grieving.');
INSERT INTO badge_optional_requirements VALUES(9486,316,9,'What jobs support or help people who are grieving? What jobs are involved in funerals, burials, or cremations? Disclaimer: Some Frontier Girls/Quest Clubs Web pages may provide links to other Internet sites for the convenience of users. Frontier Girls/Quest Clubs is not responsible for the availability or content of these external sites, nor does Frontier Girls/Quest Clubs endorse, warrant, or guarantee the products, services, or information described or offered at these other Internet sites. Use these sites at your own risk.');
INSERT INTO badge_optional_requirements VALUES(9487,320,1,'Learn how to put hair into a ponytail and how to braid. You can demonstrate these on a doll, another person, or your own hair. How can braiding your hair or putting it in a ponytail help to keep it healthy?');
INSERT INTO badge_optional_requirements VALUES(9488,320,2,'Grow your hair long and donate it to an organization that makes wigs for people who need them. You must have healthy hair or they will not take it.');
INSERT INTO badge_optional_requirements VALUES(9489,320,3,'Find out what causes dreadlocks. What are the health issues that can be associated with this type of hairstyle? How can one properly care for dreadlocks?');
INSERT INTO badge_optional_requirements VALUES(9490,320,4,'Find out about typical hair health problems such as dry hair, frizzy hair, split ends, and oily hair. What types of products are available to help with these issues? Find out what type of hair you have and what products you should be using to keep it as healthy as possible.');
INSERT INTO badge_optional_requirements VALUES(9491,320,5,'Visit a hair salon and talk to a stylist about hair health.');
INSERT INTO badge_optional_requirements VALUES(9492,320,6,'What type of hair do you have? Did you know that there are specific names for types of hair? For instance, two types of curly hair is 3A and 3B. Why can it be handy to know what type of hair you have?');
INSERT INTO badge_optional_requirements VALUES(9493,320,7,'Learn what to do naturally for various hair problems such as lice, split ends, dandruff, and chemically-damaged hair.');
INSERT INTO badge_optional_requirements VALUES(9494,320,8,'Learn about the common ingredients of various hair products. What are some that can be bad for you? Why do some people use hair products that are unscented? Why do some people use hair products that have organic ingredients?');
INSERT INTO badge_optional_requirements VALUES(9495,320,9,'Find recipes for making one’s own shampoo and conditioner and make some.');
INSERT INTO badge_optional_requirements VALUES(9496,320,10,'Help an elderly or disabled person with a shampoo or other hair care.');
INSERT INTO badge_optional_requirements VALUES(9497,320,11,'Look at hair under a microscope at two different magnifications. What are the parts of a hair? Find a diagram of hair growing from skin and label all the parts of the epidermis near the base of the hair.');
INSERT INTO badge_optional_requirements VALUES(9498,320,12,'Research various careers in the hair care industry, such as hair stylist, barber, hair product manufacturer.  Butterflies and Eagles, if possible, shadow a professional for a day.');
INSERT INTO badge_optional_requirements VALUES(9499,320,13,'Which foods are helpful to maintain healthy hair?  Make a list of the 15 best foods for healthy hair.  How many of these foods do you eat regularly?  Do you need to change your eating habits to include more of these hair-healthy foods?');
INSERT INTO badge_optional_requirements VALUES(9500,320,14,'Investigate different types of hairbrushes and combs.  Which types are best suited for your type of hair?');
INSERT INTO badge_optional_requirements VALUES(9501,328,1,'Learn how headphones work.');
INSERT INTO badge_optional_requirements VALUES(9502,328,2,'Learn about the different types available (traditional, ear buds, in-clothing, etc).  Try at least 2.');
INSERT INTO badge_optional_requirements VALUES(9503,328,3,'Take an online hearing test to check your hearing. Why is it important to use headphones at a proper volume level?');
INSERT INTO badge_optional_requirements VALUES(9504,328,4,'Research different jobs that use headphones.');
INSERT INTO badge_optional_requirements VALUES(9505,328,5,'Many athletes use headphones during their warm-ups to “psych up” for their events.  Create your own playlist to motivate you before or during exercise or a game or sporting event.  Find at least 1o songs.');
INSERT INTO badge_optional_requirements VALUES(9506,328,6,'Study how the ear works.');
INSERT INTO badge_optional_requirements VALUES(9507,328,7,'Make a model of the ear.');
INSERT INTO badge_optional_requirements VALUES(9508,328,8,'Define noise reduction and noise pollution.  Learn about any noise ordinances in your area.  Learn about noise reduction headphones.');
INSERT INTO badge_optional_requirements VALUES(9509,328,9,'As a service project, create posters educating people about noise pollution or the danger of listening to music at too high a volume. Present your posters to your family, friends, or group. If able, with permission, hang them up in a public place.');
INSERT INTO badge_optional_requirements VALUES(9510,450,1,'Using the word processing function, like Word or Google Docs, learn how to create: Title Header Paragraph Page numbers Table of Contents Shape');
INSERT INTO badge_optional_requirements VALUES(9511,450,2,'Make a list of your favorite fonts on your word processing function.');
INSERT INTO badge_optional_requirements VALUES(9512,450,3,'Create a brochure for something (a product, place, or program) using the word processing or presentation functions.');
INSERT INTO badge_optional_requirements VALUES(9513,450,4,'Create a simple budget using the spreadsheet function using at least one math  formula.');
INSERT INTO badge_optional_requirements VALUES(9514,450,5,'Create a spreadsheet of your friends names, their favorite colors and their age.  Learn to sort the information by each category. Learn how to add all of their ages together using a formula.');
INSERT INTO badge_optional_requirements VALUES(9515,450,6,'Send and receive an email with an attachment using the email function.');
INSERT INTO badge_optional_requirements VALUES(9516,450,7,'Set up a recurring event using the calendar function.');
INSERT INTO badge_optional_requirements VALUES(9517,450,8,'Look up the version history of your program.  Which version do you have?  What changes have occurred over time?');
INSERT INTO badge_optional_requirements VALUES(9518,450,9,'Learn how to include sounds, animations, and videos to a presentation.');
INSERT INTO badge_optional_requirements VALUES(9519,450,10,'Learn about the other components of your office software.  Create something using either using one of the additional components.');
INSERT INTO badge_optional_requirements VALUES(9520,450,11,'Learn how to edit your projects online or offline, and how to have them automatically save and/or backup.');
INSERT INTO badge_optional_requirements VALUES(9521,485,1,'Make a list of 10 famous places where neon lights are found, such as Broadway, Los Angeles, Times Square, Memphis, and Las Vegas and view pictures of at least one sign from each location..');
INSERT INTO badge_optional_requirements VALUES(9522,485,2,'Learn about careers that involve neon lights, such as a designer, manufacturer, or electrician. How much education is needed?  What are the pay-rates/salaries?  Where would you have to live? Butterflies and Eagles only: if possible, shadow someone for a day who works with neon lights for a living.');
INSERT INTO badge_optional_requirements VALUES(9523,485,3,'Take a trip round your town and see how many places you can find where neon lights are used. Ideas could include gas stations, theaters/cinemas, restaurants/fast-food places, stores, etc.  Create a photo montage of the signs.');
INSERT INTO badge_optional_requirements VALUES(9524,485,4,'Read a biography of the inventor of neon lights, Georges Claude .');
INSERT INTO badge_optional_requirements VALUES(9525,485,5,'Design your own neon sign.  How would the tubes for each color connect?');
INSERT INTO badge_optional_requirements VALUES(9526,485,6,'What is the difference between neon lights, LED lights and florescent lights?');
INSERT INTO badge_optional_requirements VALUES(9527,485,7,'Earn the Electricity badge at your level.');
INSERT INTO badge_optional_requirements VALUES(9528,485,8,'Find at least three pictures of famous establishments where neon lights are used. Which one do you like best?');
INSERT INTO badge_optional_requirements VALUES(9529,485,9,'Find at least three songs in which neon lights are mentioned and learn at least one of them. Examples might include Downtown, by Petula Clark, Neon Moon, by Brooks and Dunn,or The Sound of Silence, by Simon and Garfunkel.');
INSERT INTO badge_optional_requirements VALUES(9530,485,10,'Visit an exhibition of neon lights.');
INSERT INTO badge_optional_requirements VALUES(9531,485,11,'Learn about a famous neon lights artist, such as Dan Flavin, Victor Millonzi or Brigitte Kowanz.');
INSERT INTO badge_optional_requirements VALUES(9532,485,12,'Research how neon lights are used in plasma screen TVs.');
INSERT INTO badge_optional_requirements VALUES(9533,485,13,'Look in stores or catalogs, or go online (with your parent’s permission) to see what sort of different household objects incorporating neon lights are available (i.e.: clocks, lamps, room décor, etc.). Which is your favorite?');
INSERT INTO badge_optional_requirements VALUES(9534,485,14,'Learn how to safely dispose of dead or broken neon lights.');
INSERT INTO badge_optional_requirements VALUES(9535,510,1,'Many people say that pancetta tastes like bacon.  Taste test some pancetta alongside some bacon.  Compare and contrast their flavors.');
INSERT INTO badge_optional_requirements VALUES(9536,510,2,'Unlike other meats it is safe to eat pancetta raw as long as it has been cured and stored properly.  Taste test both raw and cooked pancetta.  Compare and contrast their flavors and textures.');
INSERT INTO badge_optional_requirements VALUES(9537,510,3,'Make at least three recipes using pancetta.');
INSERT INTO badge_optional_requirements VALUES(9538,510,4,'Watch a video on how pancetta is made.');
INSERT INTO badge_optional_requirements VALUES(9539,510,5,'Where did pancetta originate?  Find this country on a map.  How is it typically served there today?');
INSERT INTO badge_optional_requirements VALUES(9540,510,6,'Earn the cooking badge at your level.');
INSERT INTO badge_optional_requirements VALUES(9541,510,7,'Understand the difference between pancetta, bacon, prosciutto and speck.');
INSERT INTO badge_optional_requirements VALUES(9542,510,8,'Learn about the following six varieties of pancetta and how each is used. Pancetta Steccata (flat pancetta)Pancetta Arrotolata (rolled pancetta)Pancetta Tesa (bacon)Pancetta with Black PepperLean and DerinedLegatura pancetta');
INSERT INTO badge_optional_requirements VALUES(9543,510,9,'Research different ways that pancetta is photographed for use in magazines, on website, or in advertising.  Which way of cutting pancetta do you like best for photography?');
INSERT INTO badge_optional_requirements VALUES(9544,510,10,'Explore how pancetta is used as a garnish.  What types of dishes are usually garnished with pancetta?');
INSERT INTO badge_optional_requirements VALUES(9545,510,11,'Learn at least 6 flavors that pair well with pancetta when cooking.');
INSERT INTO badge_optional_requirements VALUES(9546,510,12,'Create a charcuterie board that features pancetta.');
INSERT INTO badge_optional_requirements VALUES(9547,543,1,'Read a biography of someone known for memorizing poetry, for instance, Sir Winston Churchill (who won a prize for memorizing and reciting 1,200 lines of Thomas Babington Macaulay’s Lays of Ancient Rome when at school) or Laura Ingalls Wilder.');
INSERT INTO badge_optional_requirements VALUES(9548,543,2,'Learn about a career that could involve memorizing poetry, such as an actor, college professor or orator.');
INSERT INTO badge_optional_requirements VALUES(9549,543,3,'Find at least three literary excerpts that include poetry memorization, such as in Laura Ingalls Wilder’s Little Town on the Prairie.');
INSERT INTO badge_optional_requirements VALUES(9550,543,4,'Talk to an older person, such as a grandparent, and ask them if they learned any poetry in school. Ask them to recite a poem to you.');
INSERT INTO badge_optional_requirements VALUES(9551,543,5,'Take part in a poetry recital.');
INSERT INTO badge_optional_requirements VALUES(9552,543,6,'Read a biography of the author of the poem you memorized for requirement 1*.');
INSERT INTO badge_optional_requirements VALUES(9553,543,7,'Memorize a poem to go along with a subject you are studying in school. For instance, if you are studying botany, find and memorize a poem about flowers, trees or plants; if you are learning about a specific era in history, find a poem from that era and memorize it; etc.');
INSERT INTO badge_optional_requirements VALUES(9554,543,8,'For centuries, history was passed down orally as many people were illiterate. This was often put into rhyme and sung or recited to make it easier to remember. One particular form of poetry that was very popular is the ballad form. Find an example of a ballad and learn it. What is it about?');
INSERT INTO badge_optional_requirements VALUES(9555,543,9,'Find three short (1-2 verses) poems, one funny, one emotionally moving and one other of your choice, and learn them. Which did you find easiest to memorize?');
INSERT INTO badge_optional_requirements VALUES(9556,543,10,'Choose a poem to memorize and find three (Preschool – Level 2), (five for Levels 3-5) different methods to help you learn it. Which did you find was most effective and helpful for you?');
INSERT INTO badge_optional_requirements VALUES(9557,543,11,'Research what are the most commonly memorized poems and read at least five of them.');
INSERT INTO badge_optional_requirements VALUES(9558,543,12,'Read a selection of poetry from different eras and authors, and make a list of any new words you find. Look up these words in a dictionary.');
INSERT INTO badge_optional_requirements VALUES(9559,543,13,'Attend a poetry recital. Which was your favourite? Did you know any of the poems recited?');
INSERT INTO badge_optional_requirements VALUES(9560,543,14,'Not all poems should be read or recited at the same speed or in the same way. Learn how to make your chosen poem “come alive” to make it real to your audience.');
INSERT INTO badge_optional_requirements VALUES(9561,591,1,'Learn about at least three different honey bees and name their characteristics.  What is the most common type of honey bee?');
INSERT INTO badge_optional_requirements VALUES(9562,591,2,'Learn the scientific same for the honey bee and what it means.');
INSERT INTO badge_optional_requirements VALUES(9563,591,3,'Participate in, or organize, a fundraiser to help save the honey beeds.  Examples may include a bake sale featuring honey as an ingredient (check local laws first) or selling bee themed craft items.  Donate the money raised to to a honey bee research organization.');
INSERT INTO badge_optional_requirements VALUES(9564,591,4,'Read, or have read to you, a book about pollination.');
INSERT INTO badge_optional_requirements VALUES(9565,591,5,'Learn about at least three parasites that use honey bees as a source of survivial.  How do they harm the bees?');
INSERT INTO badge_optional_requirements VALUES(9566,591,6,'Learn about pesticides.  What are they?  How are they meant to help crops? How do they harm the honey bees?');
INSERT INTO badge_optional_requirements VALUES(9567,591,7,'Make a list of at least 15 things we would not have if the honey bees went extinct such as cherries, blueberries, or pumpkins?');
INSERT INTO badge_optional_requirements VALUES(9568,591,8,'Taste a fruit or vegetable grown with pesticides and one that has been grown organically.  How do they differ in look, taste and smell?');
INSERT INTO badge_optional_requirements VALUES(9569,591,9,'Visit an apiary.');
INSERT INTO badge_optional_requirements VALUES(9570,591,10,'Earn your Beekeeping badge.');
INSERT INTO badge_optional_requirements VALUES(9571,591,11,'Shadow a beekeeper for a day.  What does he/she have to say about the plight of the bees?  Make a list of everything you learned about bees.');
INSERT INTO badge_optional_requirements VALUES(9572,591,12,'Make a list of at least 10 flowers that honey bees are attracted to.  Plant at least one and encourage others to do the same.');
INSERT INTO badge_optional_requirements VALUES(9573,591,13,'Write a persuasive essay to restrict or ban pesticides that are harmful to honey bees.  Older levels may also wish to start a petition to this effect and see how many people they can get to sign it.');
INSERT INTO badge_optional_requirements VALUES(9574,591,14,'Find out which government agencies are in charge of protecting the honey bees at the local, state, and federal levels.  What are they doing to help protect the bees.');
INSERT INTO badge_optional_requirements VALUES(9575,591,15,'Compare and contrast three different non-profit organizations claiming to help save the bees.  What approach do each of them have?  Which would you support and why?');
INSERT INTO badge_optional_requirements VALUES(9576,608,1,'Draw a poster to help you remember the Seven Teachings.');
INSERT INTO badge_optional_requirements VALUES(9577,608,2,'Create an art project to remind you of the Seven Teachings. (Can be repeated).');
INSERT INTO badge_optional_requirements VALUES(9578,608,3,'Make a craft to help you to remember the Seven Teachings. (Can be repeated).');
INSERT INTO badge_optional_requirements VALUES(9579,608,4,'Play a game about one or more of the Seven Teachings. (Can be repeated).');
INSERT INTO badge_optional_requirements VALUES(9580,608,5,'Read or write a story about one or more of the Seven Teachings.');
INSERT INTO badge_optional_requirements VALUES(9581,608,6,'Read or write a biography about someone who is a good example of one of the Seven Teachings.');
INSERT INTO badge_optional_requirements VALUES(9582,608,7,'Write a song or poem about one or more of the Seven Teachings.');
INSERT INTO badge_optional_requirements VALUES(9583,608,8,'Perform a skit or role play situations about one or more of the Seven Teachings.');
INSERT INTO badge_optional_requirements VALUES(9584,608,9,'Help teach younger children about the Seven Teachings.');
INSERT INTO badge_optional_requirements VALUES(9585,608,10,'Participate in a service project that addresses one of the Seven Teachings. (Can be repeated).');
INSERT INTO badge_optional_requirements VALUES(9586,608,11,'Earn one of these badges: Courage, Honesty, Love, or Respect. (Can be repeated).');
INSERT INTO badge_optional_requirements VALUES(9587,608,12,'Earn the Native American badge for the Anishinaabe people.');
INSERT INTO badge_optional_requirements VALUES(9588,613,1,'Discuss why people hoard certain items during a crisis and how this selfish behavior hurts your community as a whole.  Donate any excess items you may have to local churches or charities to distribute to those in need.');
INSERT INTO badge_optional_requirements VALUES(9589,613,2,'Understand what “essential businesses” are.  Make a list of those business you consider essential and see how it compares against those listed by your state.  Why do “essential workers” still need to report for work when everyone else is told to stay home?');
INSERT INTO badge_optional_requirements VALUES(9590,613,3,'Find a way to serve your community while still obeying the rules of Shelter in Place.  Brighten the day of a shut in by giving them a call or video chatting with them, especially those who live alone.  Help sew face masks for facilities who are requesting them.  Order take out or delivery from local restaurants who are still serving to help them stay in business.  Foster a homeless pet.  If you are over the age of 16, give blood.  Donate to local charities.');
INSERT INTO badge_optional_requirements VALUES(9591,613,4,'Learn a song to ensure that when you wash your hands you do so for at least 20 seconds.');
INSERT INTO badge_optional_requirements VALUES(9592,613,5,'Plan two weeks worth of meals based on what you currently have in your cupboards and freezer.  Can you last two weeks without a trip to the grocery store?  If not, make a shopping list of non perishable items that you can shop for to lengthen the time between your shopping trips to ensure you can stay home for at least two weeks at a time.');
INSERT INTO badge_optional_requirements VALUES(9593,613,6,'Play a round of “Chopped” based off the Food Network show.  Randomly take 4 items from your pantry or freezer and create a tasty meal from them.');
INSERT INTO badge_optional_requirements VALUES(9594,613,7,'Make a list of activities to keep younger children occupied indoors or put together activity boxes to help kids entertain themselves.  For example one box might include art supplies, another might be full of legos, and yet another might contain dress up items to create skits with.');
INSERT INTO badge_optional_requirements VALUES(9595,613,8,'Find creative ways to exercise indoors and put together a 30 minute workout.');
INSERT INTO badge_optional_requirements VALUES(9596,613,9,'Most kids already have regular chores to do, but find at least three new chores you can do to help make life in your house more enjoyable for all.  Make an extra effort to keep things neat and clean.  Make a chart and mark off each day you keep your room clean and personal items picked up.  How long can you keep it up?');
INSERT INTO badge_optional_requirements VALUES(9597,613,10,'Earn the Emergency Preparedness badge at your current age level.');
INSERT INTO badge_optional_requirements VALUES(9598,613,11,'Earn the Hygiene badge at your current level');
INSERT INTO badge_optional_requirements VALUES(9599,613,12,'Discuss ways to do essential shopping or to get “To Go” food safely and to minimize risk of contamination.');
INSERT INTO badge_optional_requirements VALUES(9600,613,13,'Come up with 3 safe and sanitary alternatives to toilet paper and discuss their proper disposal.');
INSERT INTO badge_optional_requirements VALUES(9601,613,14,'Make a list of non-perishable food items you should always keep on hand in case of an emergency.');
INSERT INTO badge_optional_requirements VALUES(9602,613,15,'Find 3 or more reliable sources of news and information (no social media allowed).  Find at least one online source, one televised source and one radio source.');
INSERT INTO badge_optional_requirements VALUES(9603,613,16,'Learn 3 different ways to maintain health and well being while sheltering in place.');
INSERT INTO badge_optional_requirements VALUES(9604,613,17,'What type of events might be interrupted by a shelter in place order? (birthday, graduation, wedding, prom, etc.)  Think of alternative ways to celebrate these events without breaking the rules of sheltering in place.');
INSERT INTO badge_optional_requirements VALUES(9605,613,18,'Make a timeline of different pandemics in history.');
INSERT INTO badge_optional_requirements VALUES(9606,613,19,'What does it mean to “flatten the curve”?  Why is it important in a pandemic?');
INSERT INTO badge_optional_requirements VALUES(9607,613,20,'Learn about how germs travel and why good hygiene is especially important during a pandemic. Disclaimer: Links below are to external sites.  Frontier Girls/Quest Clubs is not responsible for the availability or content of these external sites, nor does Frontier Girls/Quest Clubs endorse, warrant, or guarantee the products, services, or information described or offered at these other Internet sites.  Use these sites at your own risk. “Baby Shark Hand Wash Challenge”   This is a Youtube video so there will be ads. Great article on talking to kids about the COVID 19 without scaring them. https://www.theguardian.com/us-news/2020/mar/24/coronavirus-kids-how-to-talk-to-children-death-virus-expert-guide');
INSERT INTO badge_optional_requirements VALUES(9608,641,1,'Draw pictures of the state flags you learned about for requirement 1*, and make a small booklet of the drawings. Show it to your family or Club.');
INSERT INTO badge_optional_requirements VALUES(9609,641,2,'Read a book, watch a video, or go online (with your parent’s permission) to find out how flags are made.');
INSERT INTO badge_optional_requirements VALUES(9610,641,3,'Learn the correct way to fold one of the state flags you chose for requirement 1*. Demonstrate folding it for your family or Club .');
INSERT INTO badge_optional_requirements VALUES(9611,641,4,'Look at a book of state flags and make a list of the colors for each flag; and then make a graph of how many times each color is used.  Which is the most popular color?');
INSERT INTO badge_optional_requirements VALUES(9612,641,5,'Pick one state flag and learn what each color on it symbolizes. Tell your family or Club what you learn.');
INSERT INTO badge_optional_requirements VALUES(9613,641,6,'Learn the rules in the United States Federal Flag Code for how state flags are to be flown. The Texas flag is a special case; why is this?');
INSERT INTO badge_optional_requirements VALUES(9614,641,7,'Find out which states have had more than one flag in their history. Choose one state and learn how many flags have flown over it. Look at pictures of each of these flags.  For instance, Texas has had the flags of France, Spain, Mexico, the Republic of Texas, the Confederacy, and the United States of America fly over it.');
INSERT INTO badge_optional_requirements VALUES(9615,641,8,'Learn about heraldry.  Know the heraldic names for each of the following colors: black, blue, red, green, purple, yellow/gold, and white/silver.  Does your family have any coats of arms in its history?  What do they represent?  Design your own coat-of-arms.  Show it to your family or Club.');
INSERT INTO badge_optional_requirements VALUES(9616,641,9,'Choose your favorite state flag and color a picture of it. Make sure you use the right colors for each part.');
INSERT INTO badge_optional_requirements VALUES(9617,641,10,'Find out what the rules are for correctly retiring a state flag when it has become to ragged/worn out to fly any more. If possible, conduct a state flag retirement ceremony with your Club.');
INSERT INTO badge_optional_requirements VALUES(9618,658,1,'Teach something with virtually no talking, just demonstrating.');
INSERT INTO badge_optional_requirements VALUES(9619,658,2,'Teach something with oral descriptions and virtually no demonstrating. Explain why this can be difficult for some learners and why effective communication is important.');
INSERT INTO badge_optional_requirements VALUES(9620,658,3,'Discuss occupations that involve a lot of teaching, but are not called teachers. Level 3 – Level 5 need to either observe one of the occupations for two hours or research the training needed for these jobs.');
INSERT INTO badge_optional_requirements VALUES(9621,658,4,'Practice writing sequential instructions so that someone can teach themselves to do something even if the teacher isn’t available. Your instructions need to have a minimum of 5 steps.');
INSERT INTO badge_optional_requirements VALUES(9622,658,5,'Teach someone how to do a chore. This requirement must be done on at least two days: the first day for the instruction and the second day for checking to see that your student is still doing it correctly.');
INSERT INTO badge_optional_requirements VALUES(9623,658,6,'Teach a group of people a song new to them.');
INSERT INTO badge_optional_requirements VALUES(9624,658,7,'Teach someone a craft. You need to oversee the craft from start to finish. If you start the craft one day, but don’t finish it, you will need to check the finished project.');
INSERT INTO badge_optional_requirements VALUES(9625,658,8,'Teach someone everything they need to know to develop a new hobby. This can be a craft, but not the same person & craft as #9 (same person with a different craft or same craft with a different person is OK).');
INSERT INTO badge_optional_requirements VALUES(9626,658,9,'Teach a new game to a friend, family member, or group.');
INSERT INTO badge_optional_requirements VALUES(9627,658,10,'Earn a character badge that would be beneficial to a teacher. Examples might include patience, kindness, respectfulness, or listening. Explain why a teacher might need this character trait. For example when teaching others it’s important to be patient and kind. Students may have questions and need more information. You may have to go back and explain and demonstrate again. When you teach you learn more about the subject yourself!');
INSERT INTO badge_optional_requirements VALUES(9628,658,11,'Participate in a service project where you have to teach something. You might volunteer to help coach a younger soccer team, volunteer to help with Sunday School or Vacation Bible school, or teach younger kids how to do a craft while at a child activity center at a local festival.');
INSERT INTO badge_optional_requirements VALUES(9629,658,12,'Teach a moral lesson by reading or telling a story or commenting on a shared experience (Preschool, Level 1, and Level 2 need to do this twice, Level 3, Level 4, and Level 5 need to do this 3 times)');
INSERT INTO badge_optional_requirements VALUES(9630,658,13,'Teach something to someone younger than yourself and to someone older than yourself. It does not have to be the same thing. Level 3 and up need to do these twice.');
INSERT INTO badge_optional_requirements VALUES(9631,658,14,'Preschool and Level 1: Teach mom or dad how to use their imagination and play with toys on the floor with you.');
INSERT INTO badge_optional_requirements VALUES(9632,658,15,'Read a biography about one of the great teachers in history.');
INSERT INTO badge_optional_requirements VALUES(9633,658,16,'What does your book of worship say about teachers and teaching? Memorize at least 1 verse about teaching if you are at Preschool, Level 1 or Level 2, 2 if you are at Level 3, Level 4, or Level 5.');
INSERT INTO badge_optional_requirements VALUES(9634,658,17,'Write about your experience in teaching others. What was easy for you? What was difficult?');
INSERT INTO badge_optional_requirements VALUES(9635,658,18,'Find and memorize at least 3 famous quotes about teaching.');
INSERT INTO badge_optional_requirements VALUES(9636,659,1,'Create a fundraiser through the Teal Pumpkin Project.');
INSERT INTO badge_optional_requirements VALUES(9637,659,2,'Add your house to the Teal Pumpkin map at: https://www.foodallergy.org/our-initiatives/awareness-campaigns/living-teal/teal-pumpkin-project');
INSERT INTO badge_optional_requirements VALUES(9638,659,3,'Create a list of at least 10 inexpensive non-candy treats you could hand out at Halloween.');
INSERT INTO badge_optional_requirements VALUES(9639,659,4,'Learn about how food allergies are diagnosed.');
INSERT INTO badge_optional_requirements VALUES(9640,659,5,'Paint a pumpkin teal.');
INSERT INTO badge_optional_requirements VALUES(9641,659,6,'Create a teal inspired Halloween stop.  Ideas might include streamers, lights, a scarecrow dressed in teal, etc.');
INSERT INTO badge_optional_requirements VALUES(9642,659,7,'Create a teal pumpkin craft.');
INSERT INTO badge_optional_requirements VALUES(9643,661,1,'Learn about a famous real bear like Smokey or Knut.');
INSERT INTO badge_optional_requirements VALUES(9644,661,2,'Read about collecting bears or visit a bear collection that includes historical or themed bears, or some other connection, more than just random toy bears.');
INSERT INTO badge_optional_requirements VALUES(9645,661,3,'Look in catalogs, toy stores, or online for bear furniture and accessories (with your parent’s permission). Make or find something to be a new accessory or furniture for your teddy bear.');
INSERT INTO badge_optional_requirements VALUES(9646,661,4,'Make a teddy bear. You may use a kit, pattern, or go to a bear “workshop”.');
INSERT INTO badge_optional_requirements VALUES(9647,661,5,'Give a teddy bear to a bear service project like bears for police officers, foster children, children’s hospitals, Operation Christmas Child, gifts for deployed military, mission projects, etc.');
INSERT INTO badge_optional_requirements VALUES(9648,661,6,'Read a story about a bear like Winnie the Pooh, Corduroy, Paddington, etc.');
INSERT INTO badge_optional_requirements VALUES(9649,661,7,'Make a list of all of the story bears you find from books, TV, and movies.');
INSERT INTO badge_optional_requirements VALUES(9650,661,8,'Learn about a career that is involved in the creation of teddy bears – factory worker (making and dressing), store worker at a bear “workshop”, store managers, bear designer, product safety specialist, packers and shippers, customer service, purchasing, marketing, etc. Check out the Vermont Teddy Bear Factory or Build a Bear for more ideas.');
INSERT INTO badge_optional_requirements VALUES(9651,661,9,'Tour a teddy bear factory in person or online with your parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(9652,661,10,'Listen to a teddy bear song and make a piece of art inspired by the song. A couple of song options are – “Teddy Bear Picnic” or “Teddy Bear, Teddy Bear, Turn Around”.');
INSERT INTO badge_optional_requirements VALUES(9653,661,11,'Host a teddy bear picnic or tea party or other bear themed party for your friends.');
INSERT INTO badge_optional_requirements VALUES(9654,661,12,'Learn about different types of teddy bears – jointed, stuffed, knitted, crochet, novelty, etc.');
INSERT INTO badge_optional_requirements VALUES(9655,661,13,'Find a bear that needs cleaning, fixing, or a new outfit. Then help the bear. You may need adult help or to do a little research on the best cleaning or repair methods to preserve the bear.');
INSERT INTO badge_optional_requirements VALUES(9656,661,14,'Research the challenges that teddy bears can be to children with asthma. What can be done to make teddy bears sage for people with asthma or other health conditions? You might enjoy the radio program “The Cinnamon Bear”. It is a Christmas themed serial in 25 episodes from 1937. You can find it here http://cinnamonbear.org/index.html http://vimeo.com/35260982  An 8 minute tour and interview of Vermont Teddy Bear Factory http://www.howjoyful.com/2010/05/howjoyful-bear-tutorial-and-pattern/ Tutorial and pattern for a challenging but adorable teddy bear. Thanks to HowJooyful.com for sharing. http://www.eldrbarry.net/im/meg/simpbear.pdf Pattern and directions for a simpler bear.');
INSERT INTO badge_optional_requirements VALUES(9657,669,1,'Who was Moses? Learn about his life and the events that led up to his receiving the Torah.');
INSERT INTO badge_optional_requirements VALUES(9658,669,2,'Make a time line of the events in the Torah.');
INSERT INTO badge_optional_requirements VALUES(9659,669,3,'Earn the Hebrew Language badge at your level');
INSERT INTO badge_optional_requirements VALUES(9660,669,4,'Earn the Ten Commandments badge at your level.');
INSERT INTO badge_optional_requirements VALUES(9661,669,5,'Learn about the some of the people in the Torah (Adam, Eve, Noah, Abraham, Isaac, Jacob, Sarah, Rebecca, Rachel, Leah, Joseph, Judah, Tamar, Miriam, Aaron, Zipporah, Jethro, Pinchas, Eliezer, the five daughters of Zelophehad)Â  Preschool and Level 1 should learn about at least three, Level 2, 3, 4 & 5 should learn about at least five.');
INSERT INTO badge_optional_requirements VALUES(9662,669,6,'Write a d’var Torah (discussion of the parsha and its relevance to our lives) for at least one parsha you read.');
INSERT INTO badge_optional_requirements VALUES(9663,669,7,'Who was Rashi? Learn about his life and read some of his commentaries on your parshiyot. You may also learn Rashi script.');
INSERT INTO badge_optional_requirements VALUES(9664,669,8,'Read the haftarah for at least one of your parshiyot. Discuss how the haftarah relates to the parsha');
INSERT INTO badge_optional_requirements VALUES(9665,669,9,'What is halacha? Find specific mitzvos (commandments) in the parshiyot you are reading. Which mitzvos are between man and G-d (bein adam l’makom) and which are between man and man (bein adam l’chaveiro)');
INSERT INTO badge_optional_requirements VALUES(9666,669,10,'Visit a sofer (scribe) to see how a Torah scroll is written. You may also attend a hachnossos sefer Torah (dedication of a new Torah scroll) if there is one in your area.');
INSERT INTO badge_optional_requirements VALUES(9667,702,1,'Learn about slip-n-slides. Why are these considered water games? What are they made of? Is it better to buy one or make your own? What kind of things can you do with one? Try a slip-n-slide.');
INSERT INTO badge_optional_requirements VALUES(9668,702,2,'What sort of things can you do with water balloons? Learn to fill, tie and save your water balloon. Play a water balloon game with someone, like egg toss (with balloons), water balloon fight, a balancing game, etc.');
INSERT INTO badge_optional_requirements VALUES(9669,702,3,'Earn the Swimming badge at your level.');
INSERT INTO badge_optional_requirements VALUES(9670,702,4,'Learn about water games and sports around the world.  What sort of things do they use? What are the rules?');
INSERT INTO badge_optional_requirements VALUES(9671,702,5,'Learn about water games throughout history. What sort of people played them? Where did they play? Are any of the games still played?');
INSERT INTO badge_optional_requirements VALUES(9672,702,6,'Make a list of all the places you could play a water game (pool, lake, ocean, etc). How would you have to change a game to play it in say, the ocean, rather than a pool? Are their games you couldn’t play?');
INSERT INTO badge_optional_requirements VALUES(9673,702,7,'Participate in a community service project that involves water games or sports in some way.  You might collect pool toys for a local children’s group or have a game day at the public pool to raise money.');
INSERT INTO badge_optional_requirements VALUES(9674,702,8,'Think of things you could use to play water games if you did not have a place like those listed in #9.  How could you use sprinklers, hoses, squirt guns, or water balloons?  Play at least two games involving two different items listed above.');
INSERT INTO badge_optional_requirements VALUES(9675,702,9,'With your parents permission, have a pool games party!  Invite your family, friends, or even your troop over to play games like those you learned in #1.  If you do not have a pool or other body of water, try things in like in #11.');
INSERT INTO badge_optional_requirements VALUES(9676,702,10,'Make your own water toy, like a pool noodle sword or paper plate floating target to shoot with water guns.  Try it out.   Did it last well?  Did it work the way you wanted?  Is there a comparable toy on the market?  If so, which one do you like better?');
INSERT INTO badge_optional_requirements VALUES(9677,702,11,'Learn about pool care (or, if you have a pond/something similar, how you care for it).  What type of chemicals do you add?  If you don’t want to use chemicals, what are your other options?  How do you clean a pool?  What sort of tools do you need?  Help someone take care of their pool for a day, or talk to someone who works at a pool store about the chemicals they sell, how they test the pool water, etc.');
INSERT INTO badge_optional_requirements VALUES(9678,702,12,'Learn about proper health care when you are playing outside.  Why is it important to wear sunscreen, and what does SPF stand for?  What about hydration?  Are there temperatures you should not be swimming in?  Know what to do about bruises, cuts, sunburn, heat rash, bee stings and other insect injuries, heat exhaustion, and hypothermia. Helpful Resources 11 Water Games & Summer Activities Water Games – Ultimate Camp Resource Water Safety');
INSERT INTO badge_optional_requirements VALUES(9679,719,1,'Learn the Scientific Method and explain why it is important in scientific research and experimentation.');
INSERT INTO badge_optional_requirements VALUES(9680,719,2,'With adult supervision, perform one experiment reflecting the work of each of the women studied.');
INSERT INTO badge_optional_requirements VALUES(9681,719,3,'With adult supervision, design your own science experiment. Make sure to use the Scientific Method.');
INSERT INTO badge_optional_requirements VALUES(9682,719,4,'Enter a project in your school science fair.');
INSERT INTO badge_optional_requirements VALUES(9683,719,5,'Have a club science fair or exhibition.');
INSERT INTO badge_optional_requirements VALUES(9684,719,6,'Learn about the challenges and difficulties faced by women scientists throughout history. Are there still problems today?');
INSERT INTO badge_optional_requirements VALUES(9685,719,7,'Visit a science museum, in your area or online with your parent’s permission, which features the work of a female scientist.');
INSERT INTO badge_optional_requirements VALUES(9686,719,8,'Research current opportunities for women in the sciences. What salary could you expect? Is there a difference for men and women in the same field?');
INSERT INTO badge_optional_requirements VALUES(9687,719,9,'Learn what training and education are required for scientists. Research colleges and universities in your area and learn about the science degrees offered.');
INSERT INTO badge_optional_requirements VALUES(9688,719,10,'What is STEM? What fields does it include? Learn about the history of STEM education in America.');
INSERT INTO badge_optional_requirements VALUES(9689,719,11,'Level 3 & up plan a STEM focused club meeting or activity for younger kids.');
INSERT INTO badge_optional_requirements VALUES(9690,719,12,'Create a booklet or poster with photographs or drawings showing the work of one of your choices from requirement 2*. Include descriptions or short paragraphs with each photo explaining what they represent. Show your booklet/poster to your club or family.');
INSERT INTO badge_optional_requirements VALUES(9691,720,1,'Read the 19th Amendment to our Constitution. Find out when it was first introduced to congress and when it finally became part of our United States Constitution');
INSERT INTO badge_optional_requirements VALUES(9692,720,2,'Make a map of the United States and find out when each state ratified the 19th Amendment.  Write the date on top of each state.');
INSERT INTO badge_optional_requirements VALUES(9693,720,3,'Choose a present day women’s rights issue and prepare a campaign to support this issue.  You might make signs, advertisements, a video, or even write an article.');
INSERT INTO badge_optional_requirements VALUES(9694,720,4,'Earn the Biographies badge for a famous Women’s Suffragist.');
INSERT INTO badge_optional_requirements VALUES(9695,720,5,'Find out what the Declaration of Sentiments was.  How does it compare to the Declaration of Independence?');
INSERT INTO badge_optional_requirements VALUES(9696,720,6,'Create a map of the world and and write the year each country passed women’s suffrage');
INSERT INTO badge_optional_requirements VALUES(9697,720,7,'Learn about the play Failure is Impossible.  Act it out with friends as a play or readers theater.  The script can be found here: https://www.archives.gov/education/lessons/woman-suffrage/script.html');
INSERT INTO badge_optional_requirements VALUES(9698,720,8,'Research the various suffrage banners used in different locations over time.  Then create a banner of your own.');
INSERT INTO badge_optional_requirements VALUES(9699,720,9,'Research women in American politics today.  How many congressional seats are held by women?  Which states are they from?');
INSERT INTO badge_optional_requirements VALUES(9700,720,10,'Learn about Affirmative action.  Discuss the pros and cons of this method of ending or correcting discrimination.');
INSERT INTO badge_optional_requirements VALUES(9701,720,11,'Learn a song either sung by suffragists or about them.');
INSERT INTO badge_optional_requirements VALUES(9702,720,12,'Watch a movie about women’s suffrage.');
INSERT INTO badge_optional_requirements VALUES(9703,723,1,'Make a booklet of crayon rubbings you have done of coins from different countries.');
INSERT INTO badge_optional_requirements VALUES(9704,723,2,'Learn the history of money. What does it mean to “barter” something?');
INSERT INTO badge_optional_requirements VALUES(9705,723,3,'Look at pictures of coins from many years ago, such as coins from Ancient Rome. How do they look different from today’s coins?');
INSERT INTO badge_optional_requirements VALUES(9706,723,4,'Make a timeline of the money used in the United States. What were bits, half-eagles, and double eagles? How much was each worth? You must have at least 10 items on your timeline.');
INSERT INTO badge_optional_requirements VALUES(9707,723,5,'Learn about the history of the Federal Reserve. What does it mean to devalue the currency? What is the Gold Standard?');
INSERT INTO badge_optional_requirements VALUES(9708,723,6,'Make a list of the people whose faces are on our money (i.e.: Abraham Lincoln, Alexander Hamilton, Franklin D. Roosevelt, Benjamin Franklin, George Washington, etc.). Choose one and read a biography of that person. Be able to list at least two significant facts about your chosen person. (If you earn this badge again at a different level you must read about a new person.)');
INSERT INTO badge_optional_requirements VALUES(9709,723,7,'Learn about the job of Secretary of the Treasury. Who were some famous Treasury Secretaries? What was each of them famous for?');
INSERT INTO badge_optional_requirements VALUES(9710,723,8,'What sort of money was used in the Bible? Look through the Bible or your own book of faith, and find and memorize 1 (Preschool), 3 (Level 1 and 2), 5 (Level 3 and 4) 7 (Level 5) verses about money.');
INSERT INTO badge_optional_requirements VALUES(9711,723,9,'Research how banks work. What is interest and how does it work? What does the “exchange rate” between different currencies mean?');
INSERT INTO badge_optional_requirements VALUES(9712,723,10,'Learn about careers in the money sector, such as a bank teller, stockbroker, cashier, or a foreign exchange converter, etc. Levels 3 and up only: if possible, shadow someone for a day who works with money for a living.');
INSERT INTO badge_optional_requirements VALUES(9713,723,11,'Learn about the history of Wall Street.  How are stocks and shares bought and sold?');
INSERT INTO badge_optional_requirements VALUES(9714,725,1,'Make a small booklet of drawings of your favorite flags. Show it to your family or Club.');
INSERT INTO badge_optional_requirements VALUES(9715,725,2,'Read a book, watch a video, or go online (with your parent’s permission) to find out how flags are made.');
INSERT INTO badge_optional_requirements VALUES(9716,725,3,'Learn the correct way to fold one of the flags you chose for requirement 1*. Demonstrate folding it for your family or Club.');
INSERT INTO badge_optional_requirements VALUES(9717,725,4,'Look at a book of flags and choose 20 of your favorites. Make a list of the colors for each flag, and then make a graph of how many times each color is used.  Which is the most popular color?');
INSERT INTO badge_optional_requirements VALUES(9718,725,5,'How have flags changed over the centuries? I.e.: from war-standards to national emblems, etc. Tell your family or Club what you learned.');
INSERT INTO badge_optional_requirements VALUES(9719,725,6,'Find and learn the rules for how to treat another nation’s flag.  How is it similar to the United States Federal Flag Code? How is it different?');
INSERT INTO badge_optional_requirements VALUES(9720,725,7,'Pick a country and learn how many flags have flown over it.');
INSERT INTO badge_optional_requirements VALUES(9721,725,8,'Learn about heraldry.  Know the heraldic names for each of the following colors: black, blue, red, green, purple, yellow/gold, and white/silver. Design your own coat-of-arms. Show it to your family or Club .');
INSERT INTO badge_optional_requirements VALUES(9722,725,9,'Learn how to display flags from more than one nation at a time. How would you fly the United Nations flag?  How would you fly the flag of the European Union?');
INSERT INTO badge_optional_requirements VALUES(9723,725,10,'Visit a flag store that carries flags from around the world.  How many different country’s flags do they carry?  Which are the most popular?  Why?');
INSERT INTO badge_optional_requirements VALUES(9724,725,11,'Make a flag out of fabric that represents your Club or patrol.');
INSERT INTO badge_optional_requirements VALUES(9725,728,1,'Learn about any legends or myths that surround the landmarks found in  requirement #1.');
INSERT INTO badge_optional_requirements VALUES(9726,728,2,'Find three world landmarks that have major replicas located around the world.  Where are each of the replicas in relation to the main landmark?  Why were they created?');
INSERT INTO badge_optional_requirements VALUES(9727,728,3,'Create a world map showing the location of world landmarks.  Preschool include 5, Level 1 -10, Level 2 -12, Level 3 -15, Level 4 -20, Level 5 -25.  A few examples include: Statue of Liberty Eiffel Tower Stonehenge Taj Mahal Big Ben Golden Gate Bridge Empire State Building Mount Rushmore Colosseum Great Wall of China London Bridge Tower of London Cambodia’s Angkor Wat Macchu Picchu Pyramids Grand Canyon Uluru Sydney Opera House');
INSERT INTO badge_optional_requirements VALUES(9728,728,4,'Make a list of world landmarks that have been featured in fictional television shows or movies you have seen, or books you have read.  Which to seems to be featured most often?  Why do you think this is?');
INSERT INTO badge_optional_requirements VALUES(9729,728,5,'Learn about at least 3 world landmarks that are in danger of being damaged or destroyed.  What is being done to save them?');
INSERT INTO badge_optional_requirements VALUES(9730,728,6,'Make a craft of one of the landmarks or draw one.');
INSERT INTO badge_optional_requirements VALUES(9731,728,7,'Put together a puzzle depicting a world landmark.');
INSERT INTO badge_optional_requirements VALUES(9732,728,8,'Write a report on one of the world’s landmarks.');
INSERT INTO badge_optional_requirements VALUES(9733,728,9,'Watch a documentary on the history of one of the world landmarks.');
INSERT INTO badge_optional_requirements VALUES(9734,728,10,'What is the difference between world landmark and a World Heritage site?  How many World Heritage sites are there? Websites:  These websites are not associated with our program and we cannot guarantee their content.  Please do not surf the internet without your parent’s permission. http://www.mrnussbaum.com/wlandmarks.htm');
INSERT INTO badge_optional_requirements VALUES(9735,737,1,'Make a booklet or brochure about yurts.');
INSERT INTO badge_optional_requirements VALUES(9736,737,2,'Stay overnight in a yurt.');
INSERT INTO badge_optional_requirements VALUES(9737,737,3,'With permission from a parent, view a YouTube video, documentary, or other educational video that explains what it’s like to live in or construct a yurt.');
INSERT INTO badge_optional_requirements VALUES(9738,737,4,'Find out how much a basic yurt would cost. Butterflies and up: explore the cost of add-ons, such as nicer windows, French doors, or a deck.');
INSERT INTO badge_optional_requirements VALUES(9739,737,5,'Read a book about yurts.');
INSERT INTO badge_optional_requirements VALUES(9740,737,6,'Learn the history of yurts. Where did they originate? What is the first record of them?');
INSERT INTO badge_optional_requirements VALUES(9741,737,7,'Do an art project relating to yurts, such as a painting or drawing.');
INSERT INTO badge_optional_requirements VALUES(9742,737,8,'Create a model yurt.');
INSERT INTO badge_optional_requirements VALUES(9743,737,9,'Teach your family or club what you have learned about yurts.');
INSERT INTO badge_optional_requirements VALUES(9744,737,10,'Interview someone who lives or has lived in a yurt about their experience.');
INSERT INTO badge_optional_requirements VALUES(9745,737,11,'Some campgrounds or bed and breakfasts have yurts available for overnight guests. View pictures and costs of both and compare the differences in price and amenities.');
INSERT INTO badge_optional_requirements VALUES(9746,737,12,'Discuss whether or not you would want to live in a yurt. Why?');
INSERT INTO badge_optional_requirements VALUES(9747,737,13,'Plan a yurt vacation. What would it cost? How far would you travel? What amenities are available? What activities would you participate in on your stay? How long would you stay? Who would you go with? If possible, take your trip. Helpful Resources Yurt.com Wikipedia – Yurt');
INSERT INTO badge_optional_requirements VALUES(9748,5,1,'Do at least one of the projects below, or a similar project: Make an “About Me Cube.”  Wrap a square box in plain or decorated paper.  On each side, glue on a piece of paper with the following: This is me (current photo of you and your name) This is me when I was a baby (photo if possible, or drawing if no photo available) My family (photo or drawing if no photo available) I am  ____  years old. My eyes are ____. I am  ____  inches tall. I weigh  ___  pounds. My favorites: Color ________, food ________, book _________. This is my ____________(free choice of topic for this side, such as your pet or a picture of your home). Share your cube with new friends. Create an “About Me” bag and share it with your family and friends.  Place several things in a bag that represent you. Things to include might be a family photo, your favorite stuffed animal, art supplies if you like to draw, a book if you like to read, etc. Trace yourself onto butcher paper. Decorate it to look like you, and write things about yourself around the edges.');
INSERT INTO badge_optional_requirements VALUES(9749,5,2,'Create a scrapbook of your life.');
INSERT INTO badge_optional_requirements VALUES(9750,5,3,'Create a craft project using tracings of your hands or feet. Make sure to write your name and the date on the project. Examples might include a paper wreath made of cutouts of your hand, a plaster cast of a footprint or hand print, or a flower made of cutouts of your hand.');
INSERT INTO badge_optional_requirements VALUES(9751,5,4,'What do you want to be when you grow up?  Write a paragraph and illustrate what your future job might be and why you are interested in it.');
INSERT INTO badge_optional_requirements VALUES(9752,5,5,'Learn about the uniqueness of fingerprints. Compare fingerprints with your friends and look for patterns. Use fingerprints to create designs on wrapping paper or cards.');
INSERT INTO badge_optional_requirements VALUES(9753,5,6,'Find out about your family’s heritage. Where did your ancestors originally come from? Find the countries on a map.');
INSERT INTO badge_optional_requirements VALUES(9754,5,7,'Share a celebration that is unique to your heritage or religion with some friends who may not be familiar with it.');
INSERT INTO badge_optional_requirements VALUES(9755,5,8,'Write an acrostic poem. For each letter of your name, come up with something about yourself that starts with that letter');
INSERT INTO badge_optional_requirements VALUES(9756,5,9,'Participate in a service project that has special meaning to you.');
INSERT INTO badge_optional_requirements VALUES(9757,5,10,'Create a recipe book of your favorite recipes. It should include no less than 5 recipes. Make one of them.');
INSERT INTO badge_optional_requirements VALUES(9758,5,11,'Make a photo collage of some of your favorite memories. Third Party Resources: Behind the Name: http://www.behindthename.com/ Poetry4Kids.com’s How to Write an Acrostic Poem (for Kids): http://www.poetry4kids.com/lessons/how-to-write-an-acrostic-poem/ Disclaimer: Our web pages may provide recommendations and/or links to other digital and/or non-digital resources for the convenience of users. Curiosity Untamed LLC is not responsible for the availability or content of these external sources, nor does Curiosity Untamed LLC endorse, warrant, or guarantee the products, services, or information described or offered at these other digital and/or non-digital resources. Use these resources at your own risk and with a parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(9759,7,1,'Write down three areas of your life where you want to be more accountable and create a plan for improvement');
INSERT INTO badge_optional_requirements VALUES(9760,7,2,'Set a personal or academic goal and share it with someone else. Ask them to check in with you weekly for one month and help hold you accountable to reach your goal.');
INSERT INTO badge_optional_requirements VALUES(9761,7,3,'Keep a accountability journal for a week. Write down what you said you’d do each day and whether you did it');
INSERT INTO badge_optional_requirements VALUES(9762,7,4,'Complete a multi-step project or assignment and reflect on what helped you stay on task');
INSERT INTO badge_optional_requirements VALUES(9763,7,5,'Choose a responsibility at home or in your group (like feeding a pet or taking out trash) and take charge of it for two weeks.  Hold yourself accountable and make sure it gets does well and on time.');
INSERT INTO badge_optional_requirements VALUES(9764,7,6,'Interview someone in a leadership role and ask how they stay accountable to their responsibilities');
INSERT INTO badge_optional_requirements VALUES(9765,7,7,'Shadow or interview a person with a job that requires a high level of accountability (such as firefighter, pilot, EMT, accountant, or teacher).  Discuss how they stay accountable to their responsibilities.');
INSERT INTO badge_optional_requirements VALUES(9766,7,8,'Volunteer to be in charge of a task at a meeting, event, or project. Follow through and reflect on what went well');
INSERT INTO badge_optional_requirements VALUES(9767,7,9,'Role-play scenarios where someone forgets a responsibility (like feeding a pet, missing a deadline, or not cleaning up), then discuss or act out the consequences.');
INSERT INTO badge_optional_requirements VALUES(9768,7,10,'Ask someone to be your “accountability partner” for a habit you want to build or break');
INSERT INTO badge_optional_requirements VALUES(9769,7,11,'Create a skit or short comic about someone learning to take responsibility for their actions');
INSERT INTO badge_optional_requirements VALUES(9770,7,12,'Study a historical figure known for being accountable or facing the consequences of failing to be (cannot be combined with Level 4 requirement 2)');
INSERT INTO badge_optional_requirements VALUES(9771,7,13,'Do a community service project where you are responsible for organizing at least one part');
INSERT INTO badge_optional_requirements VALUES(9772,7,14,'Participate in a team activity or sport and discuss how team members rely on each other');
INSERT INTO badge_optional_requirements VALUES(9773,7,15,'Research apps and activities that gamify accountability. Create a game of your own to help you stay accountable.');
INSERT INTO badge_optional_requirements VALUES(9774,7,16,'Set a screen-time or social media limit for yourself and stick to it for one week');
INSERT INTO badge_optional_requirements VALUES(9775,7,17,'Learn a song about responsibility or accountability.');
INSERT INTO badge_optional_requirements VALUES(9776,7,18,'Study the role of accountability in the legal system or civic leadership');
INSERT INTO badge_optional_requirements VALUES(9777,7,19,'Track a bad habit (procrastination, blaming others, etc.) and work on replacing it with a positive one');
INSERT INTO badge_optional_requirements VALUES(9778,7,20,'Participate in a group challenge where everyone tracks and supports each other’s goals');
INSERT INTO badge_optional_requirements VALUES(9779,7,21,'Write a letter of apology or explanation for a time you didn’t follow through and describe how you’ll make it right');
INSERT INTO badge_optional_requirements VALUES(9780,7,22,'Read a book or watch a movie where a character learns accountability. Discuss what you learned');
INSERT INTO badge_optional_requirements VALUES(9781,7,23,'Learn about the difference between making an excuse and taking responsibility. Role-play examples of each');
INSERT INTO badge_optional_requirements VALUES(9782,7,24,'Create a poster or video encouraging others to take responsibility for their words and actions');
INSERT INTO badge_optional_requirements VALUES(9783,7,25,'Create and manage a personal budget for one week, tracking every expense and reflecting on spending choices');
INSERT INTO badge_optional_requirements VALUES(9784,7,26,'Practice time management by setting timers for tasks and completing them before the timer ends for three consecutive days');
INSERT INTO badge_optional_requirements VALUES(9785,7,27,'Commit to a “no reminders” challenge where you are responsible for remembering and completing your tasks without being told');
INSERT INTO badge_optional_requirements VALUES(9786,69,1,'What is the largest battery in the world? What is its power used for?');
INSERT INTO badge_optional_requirements VALUES(9787,69,2,'Make your own voltaic pile battery using coins or a battery out of a potato or lemon. Use a voltmeter or mulitmeter to test how well it works.');
INSERT INTO badge_optional_requirements VALUES(9788,69,3,'Create and label a diagram showing the inside of a battery and how it produces electricity through chemical reactions.');
INSERT INTO badge_optional_requirements VALUES(9789,69,4,'Learn how to dispose of and recycle different types of batteries safely. Start a battery recycling bin at home or in your community');
INSERT INTO badge_optional_requirements VALUES(9790,69,5,'Create a chart tracking all the battery-powered devices you use in one day. Record the device, battery type, and how long it’s used.');
INSERT INTO badge_optional_requirements VALUES(9791,69,6,'Design a mini game or obstacle course using battery-powered toys or devices and explain how the batteries make them move');
INSERT INTO badge_optional_requirements VALUES(9792,69,7,'Explain how battery-powered objects are different from plug-in or wind-up ones.');
INSERT INTO badge_optional_requirements VALUES(9793,69,8,'Research the environmental impact of battery production and disposal. What are scientists doing to make batteries more sustainable?');
INSERT INTO badge_optional_requirements VALUES(9794,69,9,'Study how electric cars use battery systems and how they compare to gasoline engines. Create a comparison chart and include items such as cost, weight, environmental concerns (production, disposal, and emissions), repairs, etc.');
INSERT INTO badge_optional_requirements VALUES(9795,69,10,'Create a timeline showing how battery technology has evolved—from the voltaic pile to modern phone, solar, and vehicle batteries');
INSERT INTO badge_optional_requirements VALUES(9796,69,11,'Test how temperature affects battery performance by using batteries in warm and cold environments. Record your results');
INSERT INTO badge_optional_requirements VALUES(9797,69,12,'Find out how solar energy can be stored in batteries and build a solar-powered gadget or experiment kit');
INSERT INTO badge_optional_requirements VALUES(9798,69,13,'Identify different sizes and types of household batteries (AA, AAA, 9V, button cell, etc.) and learn what each is used for.  Why are some round and flat, some rectangular and some cylindrical?');
INSERT INTO badge_optional_requirements VALUES(9799,69,14,'Explore how rechargeable batteries work and how they can help reduce waste. Use one in a device and track how many times you recharge it over a set period of time.');
INSERT INTO badge_optional_requirements VALUES(9800,69,15,'Organize or participate in a community service project related to battery safety, recycling, or energy conservation');
INSERT INTO badge_optional_requirements VALUES(9801,69,16,'Build a battery tester or learn to use a multimeter or voltmeter to measure voltage on different types of batteries');
INSERT INTO badge_optional_requirements VALUES(9802,69,17,'Use a simple battery-powered robot kit or motor project to learn about energy transfer and movement');
INSERT INTO badge_optional_requirements VALUES(9803,69,18,'Visit a battery store have them show you all the different types of batteries and what each is usually used for.');
INSERT INTO badge_optional_requirements VALUES(9804,69,19,'Compare energy storage alternatives to batteries, such as capacitors or fuel cells. How are they similar or different?');
INSERT INTO badge_optional_requirements VALUES(9805,69,20,'Investigate how batteries are used in medical devices like hearing aids, pacemakers, or insulin pumps. Create a report on one device and how battery power is essential to its function.');
INSERT INTO badge_optional_requirements VALUES(9806,69,21,'Design a battery-powered invention to solve a real-world problem (e.g., a portable fan for pets, a mini light for a backpack). Sketch your idea and explain how it would work.');
INSERT INTO badge_optional_requirements VALUES(9807,75,1,'Tell Bible stories to a child, peer, or an adult. Preschool: tell 2, stories; Level 1: tell 3 stories; Level 2: tell 5 stories; Level 3: tell 7 stories; Level 4: tell 9 stories; and Level 5 tell 11 stories.');
INSERT INTO badge_optional_requirements VALUES(9808,75,2,'Be able to identify three Bible characters from the Old Testament and three characters from the New Testament. Write a short summary on each.');
INSERT INTO badge_optional_requirements VALUES(9809,75,3,'Prepare for the National Bible Bee and participate in your local contest. While preparing, be able to answer more than half the questions correctly.');
INSERT INTO badge_optional_requirements VALUES(9810,75,4,'Earn the Bible Memory badge.');
INSERT INTO badge_optional_requirements VALUES(9811,75,5,'Participate in a Bible drill. This can be done at home with just one competitor or in a group. A Bible drill consists of a leader calling out the name of a Bible reference and the contestants seeing who can find the verse first, stand up, and read the verse.');
INSERT INTO badge_optional_requirements VALUES(9812,75,6,'Do a personal Bible study for a month.');
INSERT INTO badge_optional_requirements VALUES(9813,75,7,'Learn about Bible translators and printers. Choose a biography of a famous translator or printer to read—John Wycliffe, William Carey, Martin Luther, William Tyndale, Johann Gutenberg, etc.');
INSERT INTO badge_optional_requirements VALUES(9814,75,8,'Learn the definition of epistles, parables, and chronicles. Be able to relate at least two parables in your own words. Be able to give examples of books of the Bible that are epistles, history and poetry.');
INSERT INTO badge_optional_requirements VALUES(9815,75,9,'Learn of the extent to which people will go to obtain a copy of the Bible. Read God’s Smuggler or Mary Jones and her Bible.');
INSERT INTO badge_optional_requirements VALUES(9816,75,10,'Outline the books of the Bible. Give a minimum of one full sentence for each book.');
INSERT INTO badge_optional_requirements VALUES(9817,75,11,'Do a visual or oral presentation for your family or troop about the things you learned earning this badge or how they impacted you.');
INSERT INTO badge_optional_requirements VALUES(9818,75,12,'Learn a church’s catechism or statement of faith and be able to cite the Bible verses that support each point in it.');
INSERT INTO badge_optional_requirements VALUES(9819,81,1,'Create a piece of art inspired by glowing creatures (use paint, digital tools, or glow-in-the-dark materials)');
INSERT INTO badge_optional_requirements VALUES(9820,81,2,'Learn the difference between bioluminescence, fluorescence, and phosphorescence. Give one example of each');
INSERT INTO badge_optional_requirements VALUES(9821,81,3,'Visit a museum, aquarium, or science center exhibit that includes bioluminescent organisms');
INSERT INTO badge_optional_requirements VALUES(9822,81,4,'Compare the brightness, color, and pattern of different bioluminescent species');
INSERT INTO badge_optional_requirements VALUES(9823,81,5,'Do a safe at-home experiment to help you learn about bioluniescence.');
INSERT INTO badge_optional_requirements VALUES(9824,81,6,'Research how deep-sea exploration vehicles detect and photograph bioluminescent life');
INSERT INTO badge_optional_requirements VALUES(9825,81,7,'Make a model or poster of a bioluminescent food chain');
INSERT INTO badge_optional_requirements VALUES(9826,81,8,'Read a science book or watch a documentary about life in the deep ocean');
INSERT INTO badge_optional_requirements VALUES(9827,81,9,'Interview or shadow someone who studies marine biology or bioluminescent organisms');
INSERT INTO badge_optional_requirements VALUES(9828,81,10,'Participate in or create a nighttime scavenger hunt using glow-in-the-dark clues to simulate glowing signals in nature');
INSERT INTO badge_optional_requirements VALUES(9829,81,11,'Make a glow jar or sensory bottle to simulate the calming effect of glowing organisms');
INSERT INTO badge_optional_requirements VALUES(9830,81,12,'Use Google Earth or a world map to locate natural bioluminescent areas such as Mosquito Bay (Puerto Rico) or the Maldives');
INSERT INTO badge_optional_requirements VALUES(9831,81,13,'Write a short story or comic about a glowing animal who uses bioluminescence in an adventure');
INSERT INTO badge_optional_requirements VALUES(9832,81,14,'Learn about how scientists are using bioluminescence in medical or environmental research');
INSERT INTO badge_optional_requirements VALUES(9833,81,15,'Explore how glowing bacteria are used in science and biotechnology');
INSERT INTO badge_optional_requirements VALUES(9834,81,16,'Study the cultural significance or myths surrounding glowing creatures in different parts of the world');
INSERT INTO badge_optional_requirements VALUES(9835,81,17,'Simulate communication through light by creating a blinking flashlight code and using it to send simple messages.');
INSERT INTO badge_optional_requirements VALUES(9836,81,18,'Create a public display or online post educating others about bioluminescence and its importance in ecosystems');
INSERT INTO badge_optional_requirements VALUES(9837,87,1,'Draw a diagram of your body part.');
INSERT INTO badge_optional_requirements VALUES(9838,87,2,'Watch a video about your body part.');
INSERT INTO badge_optional_requirements VALUES(9839,87,3,'Find 10 interesting facts about your body part.');
INSERT INTO badge_optional_requirements VALUES(9840,87,4,'Make a 3D craft to represent your body part.');
INSERT INTO badge_optional_requirements VALUES(9841,87,5,'Learn about an artist famous for drawing, painting or sculpting your body part such as Trisha Thompson Adams.');
INSERT INTO badge_optional_requirements VALUES(9842,87,6,'Create a drawing or painting that includes your body part in a way that makes it beautiful or interesting.');
INSERT INTO badge_optional_requirements VALUES(9843,87,7,'Participate in a community service project that involves your body part. For example, you may collect used eyeglasses for donation if you are studying eyes.');
INSERT INTO badge_optional_requirements VALUES(9844,87,8,'Different body parts are made of different cells. What type of cells are found in your body part? What is the purpose of each type of cell? If possible, look at these cells under a microscope or look at images of them.');
INSERT INTO badge_optional_requirements VALUES(9845,87,9,'What kind of muscles and/or tissues are found in your body part? What functions does the muscle/tissue have for your body part? Look at the muscles under a microscope if possible');
INSERT INTO badge_optional_requirements VALUES(9846,87,10,'Learn about the body part in one animal from each of the following categories. How does theirs compare to humans? Can they do things with theirs that we can’t?● Mammal● Bird● Insect● Fish● Reptile● Amphibian');
INSERT INTO badge_optional_requirements VALUES(9847,87,11,'Dissect your specific body part. For example if you were studying eyes, you can order cow eyeballs to dissect. (This requirement must be done under direct supervision of an adult and is only for levels 3 and up.)');
INSERT INTO badge_optional_requirements VALUES(9848,87,12,'Read a book about your body part.');
INSERT INTO badge_optional_requirements VALUES(9849,87,13,'Learn at least 10 vocabulary words associated with your body part.');
INSERT INTO badge_optional_requirements VALUES(9850,87,14,'Play a game that teaches about your body part.');
INSERT INTO badge_optional_requirements VALUES(9851,89,1,'Explain the criteria considered in choosing an appropriate book for your book club.');
INSERT INTO badge_optional_requirements VALUES(9852,89,2,'Host a book club meeting.  What is the role of of the host?  How does it differ than a participant?');
INSERT INTO badge_optional_requirements VALUES(9853,89,3,'Create a list of at least 10 questions or conversation starters from your book that you would like your club to discuss.');
INSERT INTO badge_optional_requirements VALUES(9854,89,4,'Make a timeline of book club history. Include at least ten events.');
INSERT INTO badge_optional_requirements VALUES(9855,89,5,'Research with a parents permission how book clubs started.');
INSERT INTO badge_optional_requirements VALUES(9856,89,6,'Levels 3 and Up Only: Learn about Celebrity Book Clubs, where celebrities choose books to discuss with their audience. Make a list of celebrities that host book clubs and the type of books they choose.  If you are under 18, make sure to check with a parent before reading any books recommended by celebrities as not all are appropriate for minors.');
INSERT INTO badge_optional_requirements VALUES(9857,89,7,'Have everyone dress up as a character from a book you are reading with your club to attend a meeting.');
INSERT INTO badge_optional_requirements VALUES(9858,89,8,'Make a serve a recipe to your club based on food in the book you are reading for your book club.');
INSERT INTO badge_optional_requirements VALUES(9859,89,9,'Read 3 different types of books: fictional, non fictional, historical fiction, fantasy, biography etc. and discuss them with friends, family or your book club.');
INSERT INTO badge_optional_requirements VALUES(9860,89,10,'Earn the Literary Heroines badge at your level.');
INSERT INTO badge_optional_requirements VALUES(9861,89,11,'Earn the Books (Specific) badge at your level about one of the books you have read for book club.');
INSERT INTO badge_optional_requirements VALUES(9862,89,12,'Invite a local author or literature expert to speak at a book club meeting.');
INSERT INTO badge_optional_requirements VALUES(9863,89,13,'Plan a book-related event for your book club.');
INSERT INTO badge_optional_requirements VALUES(9864,89,14,'Identify common challenges faced by book clubs and ways to manage them.');
INSERT INTO badge_optional_requirements VALUES(9865,89,15,'Maintain a journal documenting your book club experiences such as which books you enjoyed and why verses those you did not.');
INSERT INTO badge_optional_requirements VALUES(9866,89,16,'Plan and execute a community service project related to promoting literacy.');
INSERT INTO badge_optional_requirements VALUES(9867,89,17,'Choose and read a book written by an author from a different cultural background.');
INSERT INTO badge_optional_requirements VALUES(9868,89,18,'Organize a literary trivia night for your book club.');
INSERT INTO badge_optional_requirements VALUES(9869,89,19,'Create promotional materials to recruit new members for a book club.');
INSERT INTO badge_optional_requirements VALUES(9870,89,20,'Explore how technology has impacted book clubs.');
INSERT INTO badge_optional_requirements VALUES(9871,89,21,'Attend a literary event or book fair with members of your club.');
INSERT INTO badge_optional_requirements VALUES(9872,94,1,'What careers are involved with bowling?');
INSERT INTO badge_optional_requirements VALUES(9873,94,2,'Visit a bowling alley, take a tour, speak with someone involved with bowling.');
INSERT INTO badge_optional_requirements VALUES(9874,94,3,'Watch  a  televised  professional bowling tournament.');
INSERT INTO badge_optional_requirements VALUES(9875,94,4,'How did bowling start? Learn the history of bowling and how it has evolved.');
INSERT INTO badge_optional_requirements VALUES(9876,94,5,'What types of bowling  tournaments  bowlers can  participate in?  How do you get involved in one?');
INSERT INTO badge_optional_requirements VALUES(9877,94,6,'Learn about how to properly choose a bowling ball.  Learn about weight, number of holes, hole size, etc.');
INSERT INTO badge_optional_requirements VALUES(9878,94,7,'Play 3 complete games of bowling.  (They do not all need  to be on the same day) Does you score get better or worse each time you play?');
INSERT INTO badge_optional_requirements VALUES(9879,94,8,'Score a complete game using a score sheet (or show mathematically how computer generated comes up with the score)');
INSERT INTO badge_optional_requirements VALUES(9880,94,9,'Learn the proper forms of holding and delivery of a bowling ball.');
INSERT INTO badge_optional_requirements VALUES(9881,94,10,'How many holes does a traditional bowling ball have?  How many of your fingers do you use?  What is the most amount of holes a bowling ball can have?');
INSERT INTO badge_optional_requirements VALUES(9882,94,11,'Learn about what type of shoes you can wear when you’re bowling?  Why do you need special shoes?');
INSERT INTO badge_optional_requirements VALUES(9883,94,12,'Take a bowling lesson.');
INSERT INTO badge_optional_requirements VALUES(9884,94,13,'Attend a bowling game. (Just watching)');
INSERT INTO badge_optional_requirements VALUES(9885,94,14,'Hold a bowling pin.  What do they feel like?  How heavy are they?');
INSERT INTO badge_optional_requirements VALUES(9886,94,15,'Learn how a ball return works.');
INSERT INTO badge_optional_requirements VALUES(9887,94,16,'How many bowlers can be on an official bowling team?');
INSERT INTO badge_optional_requirements VALUES(9888,94,17,'Find out what bowling balls are made of and how they are made.');
INSERT INTO badge_optional_requirements VALUES(9889,94,18,'Find out what bowling pins are made of and how they are made.');
INSERT INTO badge_optional_requirements VALUES(9890,115,1,'Learn five vocabulary words such as corrugated, fluting, tensile, biodegradable, and die-cut');
INSERT INTO badge_optional_requirements VALUES(9891,115,2,'Create a cardboard sculpture or piece of art');
INSERT INTO badge_optional_requirements VALUES(9892,115,3,'Make a cardboard game—like a marble maze, ring toss, or board game');
INSERT INTO badge_optional_requirements VALUES(9893,115,4,'Test how strong different shapes are when made from cardboard (cube, cylinder, triangle, etc.)');
INSERT INTO badge_optional_requirements VALUES(9894,115,5,'Design a cardboard chair or structure that can hold your weight (with adult help if needed)');
INSERT INTO badge_optional_requirements VALUES(9895,115,6,'Compare cardboard to other packaging materials (plastic, foam, wood). What are the pros and cons of each?');
INSERT INTO badge_optional_requirements VALUES(9896,115,7,'Try using cardboard in a STEM challenge (e.g., build a bridge or catapult)');
INSERT INTO badge_optional_requirements VALUES(9897,115,8,'Decorate a cardboard box to reuse as storage or a gift container');
INSERT INTO badge_optional_requirements VALUES(9898,115,9,'Recycle cardboard and track how much your family uses in a week');
INSERT INTO badge_optional_requirements VALUES(9899,115,10,'Make a timeline showing how cardboard use has changed over the last 100 years');
INSERT INTO badge_optional_requirements VALUES(9900,115,11,'Build a miniature cardboard city or building with windows, doors, and signs');
INSERT INTO badge_optional_requirements VALUES(9901,115,12,'Study the environmental impact of cardboard production and recycling');
INSERT INTO badge_optional_requirements VALUES(9902,115,13,'Investigate how cardboard biodegrades. Set up an experiment comparing it to plastic or paper over time.');
INSERT INTO badge_optional_requirements VALUES(9903,115,14,'Volunteer at a food bank or organization that uses cardboard boxes for packaging donations');
INSERT INTO badge_optional_requirements VALUES(9904,115,15,'Create a how-to guide or video showing how to make something useful or fun from cardboard');
INSERT INTO badge_optional_requirements VALUES(9905,115,16,'Interview or shadow someone who works in packaging, shipping, or recycling. Ask how they use cardboard in their job.');
INSERT INTO badge_optional_requirements VALUES(9906,115,17,'Research careers that use cardboard in creative ways (e.g., packaging designer, engineer, artist)');
INSERT INTO badge_optional_requirements VALUES(9907,115,18,'Organize or participate in a cardboard-themed event (build-off, sculpture contest, recycled art show, etc.)');
INSERT INTO badge_optional_requirements VALUES(9908,127,1,'Learn five vocabulary words related to characters or storytelling, such as protagonist, backstory, setting, franchise, and adaptation');
INSERT INTO badge_optional_requirements VALUES(9909,127,2,'Make a timeline showing how your character has changed or developed over time');
INSERT INTO badge_optional_requirements VALUES(9910,127,3,'Interview someone who also likes your character and ask why they connect with them');
INSERT INTO badge_optional_requirements VALUES(9911,127,4,'Create a piece of fan art, costume, or craft inspired by your character (follow copyright rules—don’t sell it!)');
INSERT INTO badge_optional_requirements VALUES(9912,127,5,'Write a story, comic, or skit where your character goes on a new adventure');
INSERT INTO badge_optional_requirements VALUES(9913,127,6,'Compare two versions of your character—book vs. movie, animated vs. live-action, or real-life portrayal vs. historical account');
INSERT INTO badge_optional_requirements VALUES(9914,127,7,'Research the author, illustrator, performer, or historical figure behind your character and learn how they contributed to making them well known');
INSERT INTO badge_optional_requirements VALUES(9915,127,8,'Learn how licensing works for characters that appear in merchandise or media. What does it take to license a character, and why does it matter?');
INSERT INTO badge_optional_requirements VALUES(9916,127,9,'Create your own original character inspired by the one you studied—give them a name, personality, and backstory');
INSERT INTO badge_optional_requirements VALUES(9917,127,10,'Watch a documentary or behind-the-scenes video about how your character’s story was created or performed');
INSERT INTO badge_optional_requirements VALUES(9918,127,11,'Do a community service project inspired by your character’s traits or values—such as kindness, courage, or creativity');
INSERT INTO badge_optional_requirements VALUES(9919,127,12,'Participate in or help organize a character-themed event like a storytime, dress-up day, or book club');
INSERT INTO badge_optional_requirements VALUES(9920,127,13,'Research whether your character is based on an earlier version or story (e.g., a modern character adapted from a myth, folktale, or public domain book)');
INSERT INTO badge_optional_requirements VALUES(9921,127,14,'Learn how characters are used in theme parks, video games, or immersive events to create audience experiences');
INSERT INTO badge_optional_requirements VALUES(9922,127,15,'Make a music playlist that reflects your character’s mood, journey, or story arc, and explain your choices');
INSERT INTO badge_optional_requirements VALUES(9923,127,16,'Act out a scene, monologue, or create a short skit about your character—either from their story or one you imagined');
INSERT INTO badge_optional_requirements VALUES(9924,127,17,'Write a thank-you letter to the creator or performer of your character, or write a letter as the character to a friend');
INSERT INTO badge_optional_requirements VALUES(9925,127,18,'Explore how your character reflects a certain time period, culture, social issue, or moral value');
INSERT INTO badge_optional_requirements VALUES(9926,130,1,'Find pictures of as many of the characters out of Dickens’ books as you can. Make a collage out of these pictures and show it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(9927,130,2,'Dickens lived during Queen Victoria’s reign. Look up pictures of Victorian clothing and draw a picture of what Dickens may have worn in his day.');
INSERT INTO badge_optional_requirements VALUES(9928,130,3,'Find somebody who likes to read Dickens and talk to them. Have they read any of the same books as you? Who was their favorite character? Sometimes people will dress up as characters from a Dickens book. Have they ever done this?');
INSERT INTO badge_optional_requirements VALUES(9929,130,4,'Most people did not have sewing machines in Dickens’ day so hand-stitching was a very useful skill. Learn how to do a simple running/straight stitch and make something simple, such as a handkerchief with lace edging.');
INSERT INTO badge_optional_requirements VALUES(9930,130,5,'Find a game that was played in Dickens’ time, such as croquet or hopscotch, and learn to play it.');
INSERT INTO badge_optional_requirements VALUES(9931,130,6,'What did children in Dickens’ day do for fun? Make a list of things such as dolls and dollhouses, hoops, kites, etc, and share it with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(9932,130,7,'Rich people had servants to help them with different things. Practice curtsying and serve dinner to your family for one meal. Make a list of all the servants that would be found in an upper-class home. Find out what the life of a servant was like and tell your family, friends, or group what you learned.');
INSERT INTO badge_optional_requirements VALUES(9933,130,8,'Make a list of quotations from Dickens’ books that you like and share them with at least two people.');
INSERT INTO badge_optional_requirements VALUES(9934,130,9,'Read one of Dickens’ original books and then read a condensed version of it. Did you like it as much as the unabridged version? Did they do a good job of condensing it?');
INSERT INTO badge_optional_requirements VALUES(9935,130,10,'Volunteer to read one Dickens’ books to someone else. This can be for residents at a nursing home, or you can read it onto a tape for someone who is visually impaired or not able to read.');
INSERT INTO badge_optional_requirements VALUES(9936,130,11,'Which of Dickens books have been turned into films? Find one and watch it. Then read the book. Did they do a good job of making it into a film? Which did you like best, the book or the film? Why?');
INSERT INTO badge_optional_requirements VALUES(9937,130,12,'Choose an occupation mentioned in a Dickens book, such as a chimney-sweep or a milliner, and learn about it. Would you have liked to have this job? Why or why not? Are any of these jobs still common today?');
INSERT INTO badge_optional_requirements VALUES(9938,130,13,'Dickens liked to give his characters names that expressed who they really were. Make a list of at least 10 peoples names from Dickens and see if you can figure out why he called them by that particular name, (i.e. Mr. Bumble was a large, and rather ineffectual character).');
INSERT INTO badge_optional_requirements VALUES(9939,130,14,'Find pictures of different hairstyles from Victorian times. Which would you like to wear? See if you can recreate one of the hairstyles either on yourself or on someone else, or have them create it on you.');
INSERT INTO badge_optional_requirements VALUES(9940,130,15,'Write a report on your favorite character, OR pretend to interview them. What sort of questions could you ask them?');
INSERT INTO badge_optional_requirements VALUES(9941,130,16,'Make a list of at least 15 new words you find Dickens using and look them up. Keep a log of the words and their meanings and teach them to your troop.');
INSERT INTO badge_optional_requirements VALUES(9942,130,17,'Not all of Dickens’ work was complete fiction. For instance, A Tale of Two Cities is what is sometimes called historical fiction, and he also wrote an English history book for children (A Child’s History of England). Read one of these. If you choose to read A Tale of Two Cities write a summary of the historic aspects of the book.');
INSERT INTO badge_optional_requirements VALUES(9943,130,18,'With some adult help, make an outfit for yourself or a younger girl like the ones worn in Dickens’ day.');
INSERT INTO badge_optional_requirements VALUES(9944,130,19,'Find a map of England and see how many places you can find that are mentioned in Dickens’ books (for example, Chatham, London, Broadstairs, etc.)');
INSERT INTO badge_optional_requirements VALUES(9945,130,20,'Many shows or movies in popular culture today draw on Dickens themes or stories. Find a show or movie that has done this, and compare it to Dickens original work. An example could be a show’s Christmas special using the “Ghosts of Christmas” theme from A Christmas Carol.');
INSERT INTO badge_optional_requirements VALUES(9946,130,21,'Dress up as a character from one of Dickens books. Show your costume to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(9947,168,1,'Create your own competitive card game.');
INSERT INTO badge_optional_requirements VALUES(9948,168,2,'Research the history of one popular competitive card game and find out where and when it started.');
INSERT INTO badge_optional_requirements VALUES(9949,168,3,'Learn what a “deck building” card game is.  Either create your own deck, or look through someone else’s deck.  Discuss why each card was chosen to include in the deck.');
INSERT INTO badge_optional_requirements VALUES(9950,168,4,'Watch a tournament or championship match for a competitive card game (online or in person). Discuss the strategies used.');
INSERT INTO badge_optional_requirements VALUES(9951,168,5,'Track your wins and losses while playing a game over a period of time. What patterns do you notice? What skills could improve your game?');
INSERT INTO badge_optional_requirements VALUES(9952,168,6,'Interview someone who plays a card game competitively. Ask what they like about it and how they prepare for matches.');
INSERT INTO badge_optional_requirements VALUES(9953,168,7,'Find a local league or tournament and compete.');
INSERT INTO badge_optional_requirements VALUES(9954,168,8,'Learn how to shuffle and deal cards correctly for different types of games.');
INSERT INTO badge_optional_requirements VALUES(9955,168,9,'Study the math or probability behind one card game. How likely is it to draw certain cards or win a round?');
INSERT INTO badge_optional_requirements VALUES(9956,168,10,'Set up and run a mini tournament with friends or family using a card game of your choice.');
INSERT INTO badge_optional_requirements VALUES(9957,168,11,'Explore ethical behavior in competitive play. What actions are considered cheating, and why are rules important?');
INSERT INTO badge_optional_requirements VALUES(9958,168,12,'Create a themed storage box or card binder to organize your deck or playing cards.');
INSERT INTO badge_optional_requirements VALUES(9959,168,13,'Compare two competitive card games. What makes one more skill-based and another more luck-based?');
INSERT INTO badge_optional_requirements VALUES(9960,168,14,'Play a game that involves bluffing or reading other players (such as Poker or Exploding Kittens). Talk about how social strategy plays a role.');
INSERT INTO badge_optional_requirements VALUES(9961,168,15,'Participate in a community service project that teaches younger children how to play a beginner card game.');
INSERT INTO badge_optional_requirements VALUES(9962,168,16,'Learn how to protect or “sleeve” collectible cards and why card condition matters in competitions.');
INSERT INTO badge_optional_requirements VALUES(9963,168,17,'Learn about the art and graphic design behind card design.  What makes a good layout? How do color, symbols or font choice affect readablity, etc.  Learn about collectible artist cards for decks such as Pokemon. Design a card of your own.');
INSERT INTO badge_optional_requirements VALUES(9964,168,18,'Create a fair-play poster or guide for a card game night to help others understand rules, behavior, and fairness.');
INSERT INTO badge_optional_requirements VALUES(9965,168,19,'Explore how digital versions of competitive card games (like Hearthstone or MTG Arena) differ from their physical counterparts.');
INSERT INTO badge_optional_requirements VALUES(9966,168,20,'Research careers or jobs related to card games—such as game designers, tournament organizers, or streamers.');
INSERT INTO badge_optional_requirements VALUES(9967,171,1,'Play a new age-appropriate computer game. Compare it to something you have played before. What do you think?');
INSERT INTO badge_optional_requirements VALUES(9968,171,2,'Preschool-Level 2 Only: With the help of an adult, learn to use an Internet browser.');
INSERT INTO badge_optional_requirements VALUES(9969,171,3,'Use a computer to create an invitation or thank you note.');
INSERT INTO badge_optional_requirements VALUES(9970,171,4,'Practice improving your typing speed, either through lessons or through a virtual program.');
INSERT INTO badge_optional_requirements VALUES(9971,171,5,'Keep a log for one week of how many times your life has been effected by computers. At the end of the week, share your results with your friends, family, or group.');
INSERT INTO badge_optional_requirements VALUES(9972,171,6,'Research the many different internet browsers available. Which do you prefer? What are some differences you notice in each?');
INSERT INTO badge_optional_requirements VALUES(9973,171,7,'Pick two computer software programs and write a review about them. What do you like about them? What improvements would you make? If possible, find a review online of each of these programs and compare them to the review that you wrote.');
INSERT INTO badge_optional_requirements VALUES(9974,171,8,'With your parent’s permission, access the internet and using a search engine, find three sites on a subject you are interested in.');
INSERT INTO badge_optional_requirements VALUES(9975,171,9,'Learn how to sit or stand at a computer correctly. How can you avoid future injury or pain? What specialized desks, chairs, etc. are out there? What are the risks to your health at spending too much time at a computer, especially while slouching or in poor lighting?');
INSERT INTO badge_optional_requirements VALUES(9976,171,10,'Is it permissible to accept a free copy of a computer game or program from a friend? Why or why not? What is a “license” and what can be the consequences of misusing it? Learn about “pirated” music or movies and why it is illegal to view or download them.');
INSERT INTO badge_optional_requirements VALUES(9977,171,11,'How has computer technology improved everyday appliances like ovens, washer and dryers, televisions, and telephones?');
INSERT INTO badge_optional_requirements VALUES(9978,171,12,'Create a brochure of kid friendly websites. Have a sections for things like games, homework helpers, and contests.');
INSERT INTO badge_optional_requirements VALUES(9979,171,13,'Describe the major parts of a computer system. Draw a diagram and label these major parts.');
INSERT INTO badge_optional_requirements VALUES(9980,171,14,'What is a computer program? How is it developed? Give three examples of programming languages and what types of programming they are used for. Describe a source program and an object program.');
INSERT INTO badge_optional_requirements VALUES(9981,171,15,'What may be the future of the computer? Research what people predict computers will be like in the future. Will they look different? Run differently? Make your own predictions of what computers may become and design a futuristic computer.');
INSERT INTO badge_optional_requirements VALUES(9982,171,16,'Visit a business or industry that uses computers. Study what the computer accomplishes and be prepared to discuss what you observed.');
INSERT INTO badge_optional_requirements VALUES(9983,171,17,'How has the computer allowed people to work from home? Find at least one person who works remotely using a computer and interview them. Are they self-employed, or do they work for a larger company? What are the advantages/disadvantages of working at home? What special hardware and software do they use, if any?');
INSERT INTO badge_optional_requirements VALUES(9984,171,18,'What careers are there in the computer field? Find three careers and research the type of education you would need for that field, as well as what type of training you would need on the computer.');
INSERT INTO badge_optional_requirements VALUES(9985,171,19,'What happens to old or broken computers? How does one dispose of a computer properly? What pieces can be recycled, and which ones go to a landfill?');
INSERT INTO badge_optional_requirements VALUES(9986,171,20,'Build your own computer, specialized for your own needs and interests, whether that be school or gaming.');
INSERT INTO badge_optional_requirements VALUES(9987,171,21,'Earn the Internet badge at your level.');
INSERT INTO badge_optional_requirements VALUES(9988,171,22,'Earn the Internet Safety badge at your level.');
INSERT INTO badge_optional_requirements VALUES(9989,179,1,'Learn about different glues.  Why is it important to use the proper glue when constructing costume pieces?  Know what each of the following glues are used for:  hot glue, spray adhesive, pressure sensitive adhesive, epoxy, glue sticks, white craft glue, and fabric adhesive.');
INSERT INTO badge_optional_requirements VALUES(9990,179,2,'Learn about the following different types of paint and when each should be used:  acrylic, body paint, lacquer, gloss, matte, textured spray paint, metallic spray paint, stain, and primer.');
INSERT INTO badge_optional_requirements VALUES(9991,179,3,'Learn about what the following materials are and how they are used in costume construction:  Warbla (thermoplastic modeling material), EVA foam, paper mache.  Use one of these materials to make a costume prop.');
INSERT INTO badge_optional_requirements VALUES(9992,179,4,'Learn how to properly dye a garment.  Understand how different dyes work with different types of fabric.  Dye at least one garment.');
INSERT INTO badge_optional_requirements VALUES(9993,179,5,'Learn what Cos-play is and construct a cos-play costume for one of your favorite characters.');
INSERT INTO badge_optional_requirements VALUES(9994,179,6,'Learn about historical reenactments and construct a costume you could wear to an event such as a Renaissance Fair.');
INSERT INTO badge_optional_requirements VALUES(9995,179,7,'Learn about what Larping and Role Playing are and construct a costume that would fit in with a typical story line.');
INSERT INTO badge_optional_requirements VALUES(9996,179,8,'Construct a hat or headpiece.');
INSERT INTO badge_optional_requirements VALUES(9997,179,9,'Construct a pair of shoes for a costume.');
INSERT INTO badge_optional_requirements VALUES(9998,179,10,'Construct a costume for an in-animate object such as a box of crayons or a bunch of grapes.');
INSERT INTO badge_optional_requirements VALUES(9999,179,11,'Learn about careers in costume construction.  What type of education must you have?  What type of pay can you expect?  Where might you have to live?');
INSERT INTO badge_optional_requirements VALUES(10000,179,12,'Participate in a community service project that involves costume construction. Examples might include helping to create costumes for a local school play, making costumes for kids in a homeless shelter for Halloween, or making a costume for a mascot for a reading or safety program.');
INSERT INTO badge_optional_requirements VALUES(10001,181,1,'Preschool – Level 2 Only: Take a large paper shopping bag, cut holes for a head in the bottom and in two sides for arms.  Decorate the bag to make a costume. What can you make out of this basic item besides a robot?');
INSERT INTO badge_optional_requirements VALUES(10002,181,2,'Find a rectangular piece of cloth and practice draping and tying it different ways to make a south Pacific sarong, a Greek toga, or a historic Egyptian costume, a cape, shawl, or veil. What accessories could you use with these pieces to make them look more authentic?');
INSERT INTO badge_optional_requirements VALUES(10003,181,3,'Preschool – Level 2 Only: Find a rectangular piece of fabric you are allowed to cut. Make a lengthwise slit in the center of the fabric to use for a neck hole of a poncho. What types of fabric would be best for this project? What things could go with this outfit to complete it?');
INSERT INTO badge_optional_requirements VALUES(10004,181,4,'How important is it to keep costumes clean? How are they usually stored? If you are helping actors get dressed quickly between acts, how would you keep track of who wears what?');
INSERT INTO badge_optional_requirements VALUES(10005,181,5,'Tour a costume shop, the storage or costume sections of a theater company, or a museum with costumes.');
INSERT INTO badge_optional_requirements VALUES(10006,181,6,'Look through a book about costumes and costume designs. What details do you see in the costumes that make the character look more authentic?');
INSERT INTO badge_optional_requirements VALUES(10007,181,7,'Design a costume for a character of your choice.');
INSERT INTO badge_optional_requirements VALUES(10008,181,8,'Make a mask using stiff paper, lightweight cardboard, paper mache, or other materials.');
INSERT INTO badge_optional_requirements VALUES(10009,181,9,'Learn how to make a skirt with a casing for elastic out of a rectangular piece of cloth. Describe or draw two different tops to go with such a skirt that would give different looks.');
INSERT INTO badge_optional_requirements VALUES(10010,181,10,'Learn how to take two rectangles of fabric, stitch them part way up to make two tubes and then stitch them together (at the unstitched end for the crotch) into baggy trousers. These will also need a casing for elastic at the waist. Who might wear baggy trousers besides pirates?');
INSERT INTO badge_optional_requirements VALUES(10011,181,11,'Learn how to make a half-circle of fabric into a cape or cloak.');
INSERT INTO badge_optional_requirements VALUES(10012,181,12,'Learn about the costume design process for a movie or play. Who comes up with the costumes? How are they made?');
INSERT INTO badge_optional_requirements VALUES(10013,181,13,'Help design and make costumes for a local play or production.');
INSERT INTO badge_optional_requirements VALUES(10014,181,14,'Interview a costume designer, whether it is in person, by phone or online. Come up with at least ten questions to ask them.');
INSERT INTO badge_optional_requirements VALUES(10015,181,15,'If you have a collection of costumes, donate a minimum of two costumes to a children’s shelter or school drama department.');
INSERT INTO badge_optional_requirements VALUES(10016,181,16,'Discuss with an adult how a person could make a basic T-shaped garment into a Roman tunic (to put under a toga), a Native American leather top, a kimono, a wizard’s or monk’s tunic, or an African bubu or danshiki.');
INSERT INTO badge_optional_requirements VALUES(10017,181,17,'Help someone get dressed for their part in a play or help repair costumes for a drama group.');
INSERT INTO badge_optional_requirements VALUES(10018,181,18,'Using your own designs or a sewing pattern plus accessories you design, make a complete outfit including hat and shoes (You may embellish a purse, hat or shoes that are ready-made). This can be repeated, preferably with a costume from another country or century.');
INSERT INTO badge_optional_requirements VALUES(10019,181,19,'Take a basic rectangular base garment/ a plain cloak/other plain garment and learn how to attach various decorations to change the way it looks. You do not need to glue or sew the decorations on, you may just lay them out. Use one basic garment varied at least three ways. Learn how gems and fabric trims are attached. Learn how to make fringes or pom-poms.');
INSERT INTO badge_optional_requirements VALUES(10020,187,1,'Play a age-appropriate board game (such as Clue) that involves collecting clues or evidence.');
INSERT INTO badge_optional_requirements VALUES(10021,187,2,'Visit a person from local law enforcement or forensics lab or invite them to visit your club. What does his/her job involve? Write a short report about what you learned from them.');
INSERT INTO badge_optional_requirements VALUES(10022,187,3,'What types of careers are available to those interested in law enforcement and forensic science? What education is required for these careers? What does the job require?');
INSERT INTO badge_optional_requirements VALUES(10023,187,4,'With a parent’s permission, play an age-appropriate video game (e.g. Nancy Drew, Sherlock Holmes, CSI) that involves collecting clues and evidence, evaluating data, and solving the mystery or crime.');
INSERT INTO badge_optional_requirements VALUES(10024,187,5,'What types of shows, movies, and games use crime scene investigation (forensic science)? List and discuss as many examples as you can think of. How has popular culture affected real life law enforcement and court cases? What is different from real life and popular culture?');
INSERT INTO badge_optional_requirements VALUES(10025,187,6,'Read an age-appropriate book involving crime scene investigation or forensic science (e.g. Hardy Boys, Nancy Drew, Sherlock Holmes, etc.).');
INSERT INTO badge_optional_requirements VALUES(10026,187,7,'Explain how Sir Arthur Conan Doyle’s character Sherlock Holmes had an effect on forensic science. Also explain how the character of Sherlock was influenced by real scientists and cases.');
INSERT INTO badge_optional_requirements VALUES(10027,187,8,'Participate in a service project that benefits local law enforcement or forensic science.');
INSERT INTO badge_optional_requirements VALUES(10028,187,9,'Watch an age-appropriate movie or television show that involves crime scene investigation and forensic science.');
INSERT INTO badge_optional_requirements VALUES(10029,187,10,'Research important pieces of equipment used in a forensics lab and create a brief presentation with photographs or drawings for your family. Be sure to include what they are used for.');
INSERT INTO badge_optional_requirements VALUES(10030,187,11,'Learn about at least two famous forensics scientists and their careers. Make a poster describing what they did and why they are remembered.');
INSERT INTO badge_optional_requirements VALUES(10031,187,12,'Learn about the use of forensics in court and why it is so important. What might be presented to the judge during a trial?');
INSERT INTO badge_optional_requirements VALUES(10032,196,1,'Create a story to film and write lines for each character. Consider the props you might need for your movie.');
INSERT INTO badge_optional_requirements VALUES(10033,196,2,'Research professional movie making and make a list of filming techniques you can implement in your own filming.');
INSERT INTO badge_optional_requirements VALUES(10034,196,3,'Learn about etiquette involving filming in public places. What are the laws regarding filming in public places in your area (if there are any)? What type of legal photo releases are necessary if you film people?');
INSERT INTO badge_optional_requirements VALUES(10035,196,4,'Learn about the use of soundtrack and effects in movie editing. How do these things influence the mood of the scene? Consider different kinds of music to create a sad, scary, happy, intense, or sweet scene. Consider effects such as color, lighting, transitions, etc. and how they affect the scene.');
INSERT INTO badge_optional_requirements VALUES(10036,196,5,'Create a film that is at least 10 minutes in length. You can use your story from optional requirement 3. Film a sporting event, a celebration (wedding, party, holiday, etc.), one-on-one interview with guests, or anything you wish to film. Use different lighting and angles in your film.');
INSERT INTO badge_optional_requirements VALUES(10037,196,6,'Learn about lighting and how you can manipulate it in your film. What kinds of lamps are available on the market? Create a chart comparing the availability, pricing, and features of your findings.');
INSERT INTO badge_optional_requirements VALUES(10038,196,7,'Preschool and Level 1 Only: Watch someone else’s digital movie .');
INSERT INTO badge_optional_requirements VALUES(10039,196,8,'Take a class on digital movie making or connect with a local expert to learn from. Write a brief report discussing some things you learned from your class/instructor or share what you have learned with others.');
INSERT INTO badge_optional_requirements VALUES(10040,196,9,'Participate in a community service project involving digital movie making. For instance, you could volunteer to create a film for an event or make a film with your friends promoting an important cause or idea.');
INSERT INTO badge_optional_requirements VALUES(10041,196,10,'Learn about careers in professional movie making. What kinds of jobs are available? What would your pay be, and what schooling is required?');
INSERT INTO badge_optional_requirements VALUES(10042,196,11,'Watch a professional movie and discuss the different components of the filming with your family. How often did the camera angle change within a two minute span? How did the shot selections influence the scene?');
INSERT INTO badge_optional_requirements VALUES(10043,196,12,'Learn about ways professional filming is manipulated to show action shots (such as mounting the camera on a track to film a horse running). How are these devices used and why are they helpful? Create a chart showing how these scenes are filmed.');
INSERT INTO badge_optional_requirements VALUES(10044,196,13,'Visit a film set or television production studio to see how films are produced.');
INSERT INTO badge_optional_requirements VALUES(10045,211,1,'Complete Level 4 requirements 1 & 2');
INSERT INTO badge_optional_requirements VALUES(10046,211,2,'Teach someone how to do a skill from this badge or teach some knowledge about this badge to someone.  You can teach kids, your spouse, seniors, anyone, just as long as you are sharing your new found knowledge.  If for some reason you cannot teach what you have learned to someone else, you may choose and additional 2 optional requirements instead. Optional Requirements');
INSERT INTO badge_optional_requirements VALUES(10047,211,3,'Visit a Disney World water park');
INSERT INTO badge_optional_requirements VALUES(10048,211,4,'Level 4 and 5 only – Visit a Disney spa');
INSERT INTO badge_optional_requirements VALUES(10049,211,5,'Eat a meal at a Disney restaurant outside the parks.');
INSERT INTO badge_optional_requirements VALUES(10050,211,6,'Examine the theme of a Disney hotel.  Do you like the theme?  What would you add to make the theme even more apparant at the hotel?');
INSERT INTO badge_optional_requirements VALUES(10051,211,7,'Participate in an activity outside the parks – animation class at Art of Animation, Chip & Dale’s Campfire Singalong at Fort Wilderness Campground, animal watching at the Animal Kingdom Lodge safari, or any of the other numerous activities available.');
INSERT INTO badge_optional_requirements VALUES(10052,211,8,'Disneybound to match a hotel theme.');
INSERT INTO badge_optional_requirements VALUES(10053,211,9,'What is Disney Springs?  Look it up on a map and discuss what is available there.');
INSERT INTO badge_optional_requirements VALUES(10054,211,10,'Learn about the R50 renewable diesel that powers Disney buses.');
INSERT INTO badge_optional_requirements VALUES(10055,211,11,'Look at the architecture of a bus stop at a Disney World hotel or park.  Does it match the park/hotel theming? For Butterflies and above, how would you improve the theming of the bus stop?');
INSERT INTO badge_optional_requirements VALUES(10056,211,12,'Find one piece of merchandise that you like that is not related to the parks.  Either purchase it or take a picture of it.');
INSERT INTO badge_optional_requirements VALUES(10057,211,13,'Look at a map of Disney property and find the locations of non-Disney companies.  What do those companies do on Disney property?');
INSERT INTO badge_optional_requirements VALUES(10058,211,14,'Eat a Disney snack that you can’t get in the parks (zebra domes at Animal Kingdom Lodge, resort specific cupcakes, Disney Springs exclusive snacks, etc.)');
INSERT INTO badge_optional_requirements VALUES(10059,211,15,'Take pictures of the different Disney character buses (Preschool/Level 1 need to take at least 3, Level 2 – 5, Level 3 – 7, Level 4 and Level 5 – 10).  Which one is your favorite?');
INSERT INTO badge_optional_requirements VALUES(10060,211,16,'Research the history of the monorail system at Disney World.');
INSERT INTO badge_optional_requirements VALUES(10061,211,17,'Learn about the Disney Vacation Club and how members stay at deluxe resorts.');
INSERT INTO badge_optional_requirements VALUES(10062,211,18,'Watch a video or read about the Treehouse Villas, Fort Wilderness cabins, or other unique lodging.');
INSERT INTO badge_optional_requirements VALUES(10063,211,19,'Find out what sports or recreation activities are offered outside the parks (e.g., boating, fishing, golfing, horseback riding).');
INSERT INTO badge_optional_requirements VALUES(10064,211,20,'Explore the Disney BoardWalk area and learn what you can do there.');
INSERT INTO badge_optional_requirements VALUES(10065,211,21,'Study the environmental efforts Disney takes outside the parks, such as solar fields or recycling at resorts.');
INSERT INTO badge_optional_requirements VALUES(10066,211,22,'Learn how mobile ordering or dining reservations work outside the parks.');
INSERT INTO badge_optional_requirements VALUES(10067,211,23,'Discover nighttime entertainment options outside the parks like fireworks viewing from resorts or live shows at Disney Springs.');
INSERT INTO badge_optional_requirements VALUES(10068,211,24,'Explore the pet-friendly options at Disney World, including dog-friendly resorts and the Best Friends Pet Care facility.');
INSERT INTO badge_optional_requirements VALUES(10069,211,25,'Research how Disney manages guest flow using MagicBands or phone apps in resort areas.');
INSERT INTO badge_optional_requirements VALUES(10070,211,26,'Learn what transportation options are available for guests traveling between the airport and Disney property.');
INSERT INTO badge_optional_requirements VALUES(10071,211,27,'Create a brochure or travel guide showcasing the best ways to enjoy Walt Disney World without entering the theme parks.');
INSERT INTO badge_optional_requirements VALUES(10072,224,1,'Learn how to use a duck call.');
INSERT INTO badge_optional_requirements VALUES(10073,224,2,'Help to build a duck  box or other appropriate habitat for a local species of duck.');
INSERT INTO badge_optional_requirements VALUES(10074,224,3,'Listen to at least five different duck calls, either in person or online with a parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(10075,224,4,'Find at least three recipes that use duck. Make one, if possible.');
INSERT INTO badge_optional_requirements VALUES(10076,224,5,'Find at least three recipes that use duck eggs. Make one, if possible.');
INSERT INTO badge_optional_requirements VALUES(10077,224,6,'Volunteer to help clean up or restore local wetlands.');
INSERT INTO badge_optional_requirements VALUES(10078,224,7,'Find out what a “brooder” is, and how to build one. Find out what to feed the newly hatched ducklings.');
INSERT INTO badge_optional_requirements VALUES(10079,224,8,'Watch a documentary about ducks.');
INSERT INTO badge_optional_requirements VALUES(10080,224,9,'Learn about three different diseases that affect ducks and what to do if they appear.');
INSERT INTO badge_optional_requirements VALUES(10081,224,10,'Find out what predators attack ducks and how to protect ducks from them.');
INSERT INTO badge_optional_requirements VALUES(10082,227,1,'Build a terrarium');
INSERT INTO badge_optional_requirements VALUES(10083,227,2,'Build a diorama of a biome and explain it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(10084,227,3,'Research careers in ecology such as ecologists, environmental consultants, science writers, environmental lawyers. Find out the education, training, and experience required for this profession.');
INSERT INTO badge_optional_requirements VALUES(10085,227,4,'Conduct an experiment illustrating the greenhouse effect. Keep a journal of your data and observations.');
INSERT INTO badge_optional_requirements VALUES(10086,227,5,'Give examples of: a producer, a consumer, and a decomposer in the food chain of an ecosystem as well as one way humans have changed the balance of nature and how you can help protect the balance of nature.');
INSERT INTO badge_optional_requirements VALUES(10087,227,6,'How can you show appreciation and respect for wildlife? Tell things that some people have done that show a lack of respect for wildlife. Name ways you will show respect for and protect wildlife.');
INSERT INTO badge_optional_requirements VALUES(10088,227,7,'Visit a wildlife sanctuary, nature center, or fish hatchery.');
INSERT INTO badge_optional_requirements VALUES(10089,227,8,'Participate in an environmental service project that helps maintain habitat for wildlife, such as cleaning up an area, a riverbank restoration or planting trees.');
INSERT INTO badge_optional_requirements VALUES(10090,227,9,'Draw a diagram to show the different layers of plant life in a particular area. Try to figure out why these occur.');
INSERT INTO badge_optional_requirements VALUES(10091,227,10,'Visit a natural area near where you live such as a park or campground. Mark off an area 20 paces wide and examine the ecology inside your area. What plants do you see? What animals? How do they relate to each other? What type of soil do you have? Is there shade or sunlight? Discuss your findings with a parent or club leader.');
INSERT INTO badge_optional_requirements VALUES(10092,227,11,'Learn what ecological succession is and how it occurs.');
INSERT INTO badge_optional_requirements VALUES(10093,227,12,'Visit an area where you can see migrating animals or fish returning to spawn. Learn about their journey and changing numbers.');
INSERT INTO badge_optional_requirements VALUES(10094,227,13,'Identify five different types of soil in your area and explain their properties.  Discuss how soil type affects what grows there.');
INSERT INTO badge_optional_requirements VALUES(10095,227,14,'Calculate your ecological footprint and propose ways to reduce it.');
INSERT INTO badge_optional_requirements VALUES(10096,227,15,'Research and explain the concept of invasive species and their impact on native ecosystems.');
INSERT INTO badge_optional_requirements VALUES(10097,227,16,'Measure and record the pH and temperature of water in a nearby stream, river, or pond.  Discuss how this affects the plants and animals who live there.');
INSERT INTO badge_optional_requirements VALUES(10098,227,17,'Study the concept of symbiosis and provide examples of mutualism, commensalism, and parasitism.');
INSERT INTO badge_optional_requirements VALUES(10099,227,18,'Explore the concept of biomimicry and identify human innovations inspired by nature.');
INSERT INTO badge_optional_requirements VALUES(10100,227,19,'Research the role of keystone species in maintaining ecosystem stability.');
INSERT INTO badge_optional_requirements VALUES(10101,227,20,'Participate in a citizen science project, such as monitoring wildlife populations or tracking migratory birds.');
INSERT INTO badge_optional_requirements VALUES(10102,228,1,'Create a piece of art using mold-able chocolate or a recipe like the following to create your own edible dough and create something from it. You will need: 3/4 cup (from a 7- to 7 1/2-oz jar) marshmallow cream (such as marshmallow fluff or creme) 1 1/2 cups confectioners’ sugar, plus more for dusting Food coloring Instructions: Scrape marshmallow cream into a medium bowl. Stir in as much of the 1 1/2 cups confectioners’ sugar as possible, kneading in remaining sugar until a smooth, stiff dough forms. Divide into as many portions as you wish to have different colors. Keep each portion tightly wrapped in plastic wrap until ready for use. Take one portion at a time and add 1- 2 drops of food color at a time. Knead, adding extra color if necessary, until you reach the desired color. Wrap tightly until ready to use. Start creating! Smaller, thinner creations will dry faster and more evenly. To get different pieces to stick together, lightly dampen where they are to connect. Let dry overnight.');
INSERT INTO badge_optional_requirements VALUES(10103,228,2,'Create a piece of edible art for dessert (decorate cupcakes, cookies, cakes, etc.)');
INSERT INTO badge_optional_requirements VALUES(10104,228,3,'Participate in a community service project that involves edible art in some way.  Examples might include holding a bake sale of edible art to raise money for your favorite charity, visiting a  day care and making and helping the staff make an edible art lunch for the kids, making edible art and donating it to your local fire station to enjoy, etc. Please follow all federal/state/local laws.');
INSERT INTO badge_optional_requirements VALUES(10105,228,4,'Create an edible bouquet.');
INSERT INTO badge_optional_requirements VALUES(10106,228,5,'Create a sandwich that is also edible art. You can use cookie cutters to get creative!');
INSERT INTO badge_optional_requirements VALUES(10107,228,6,'Use bread dough to create a piece of edible art (Braid, shape, layer, etc.).');
INSERT INTO badge_optional_requirements VALUES(10108,228,7,'Make a piece of jewelry that is edible.');
INSERT INTO badge_optional_requirements VALUES(10109,228,8,'Create a piece of edible art that is also a salad.');
INSERT INTO badge_optional_requirements VALUES(10110,228,9,'Learn a technique for decorating with frosting');
INSERT INTO badge_optional_requirements VALUES(10111,228,10,'Learn an edible painting technique such as Shiny Corn Syrup Paint: You will need: 1 qt clear corn syrup Food coloring Pancakes, graham crackers or cookies to paint on. Instructions: Pour corn syrup into a small to medium-sized container. Add one drop of food coloring to the corn syrup. Mix the ingredients together using toothpicks or a metal Use a toothpick or clean paint brush to use your paint on pancakes, graham crackers or cookies. You can also use this paint on paper, but it will be sticky.');
INSERT INTO badge_optional_requirements VALUES(10112,228,11,'Earn the Garnishing badge at your level.');
INSERT INTO badge_optional_requirements VALUES(10113,228,12,'Earn the Cake Decorating badge at your level.');
INSERT INTO badge_optional_requirements VALUES(10114,228,13,'Make a gingerbread house.');
INSERT INTO badge_optional_requirements VALUES(10115,228,14,'Make a candy mosaic out of items like jelly beans.');
INSERT INTO badge_optional_requirements VALUES(10116,228,15,'Create an edible wreath.');
INSERT INTO badge_optional_requirements VALUES(10117,228,16,'Create an edible center piece or piece of art for a party or event.');
INSERT INTO badge_optional_requirements VALUES(10118,228,17,'Help teach younger kids how to create a piece of edible art.');
INSERT INTO badge_optional_requirements VALUES(10119,236,1,'Through games, songs, stories, crafts, skits, etc. show that you can keep a small group of children occupied in a confined indoor area as well as an open outdoor area.');
INSERT INTO badge_optional_requirements VALUES(10120,236,2,'Demonstrate at least one method of purifying water.');
INSERT INTO badge_optional_requirements VALUES(10121,236,3,'Earn the Fire Safety badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(10122,236,4,'Earn the First Aid badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(10123,236,5,'Learn to use a compass effectively. Know how to locate the North Star at night and use it as a compass if necessary. Learn to read a street map and be able to give and follow directions.');
INSERT INTO badge_optional_requirements VALUES(10124,236,6,'Writing materials or cell phones may not always be available in an emergency. Show that you are able to carry an important message accurately in your head.');
INSERT INTO badge_optional_requirements VALUES(10125,236,7,'Put together an emergency kit for a 3 – 4 day evacuation of your home. Make sure you include food, first aid supplies, lighting, etc. Keep this kit somewhere in your home and update it once a year (replacing packaged food if necessary).');
INSERT INTO badge_optional_requirements VALUES(10126,236,8,'Show three ways of attracting and communicating with rescue planes/aircraft.');
INSERT INTO badge_optional_requirements VALUES(10127,236,9,'Show how you could safely save a person from the following: Touching a live household electric wire. A room filled with carbon monoxide Clothes on fire Drowning, using non-swimming rescues (including accidents on ice)');
INSERT INTO badge_optional_requirements VALUES(10128,236,10,'Earn the Home Fire Safety badge at your current level.');
INSERT INTO badge_optional_requirements VALUES(10129,236,11,'Make a display or give a presentation for your family or troop on what you have learned about preparing for emergencies.');
INSERT INTO badge_optional_requirements VALUES(10130,236,12,'Take a self defense class');
INSERT INTO badge_optional_requirements VALUES(10131,236,13,'Levels 2-5 Only: Learn how to properly use and maintain a fire extinguisher.');
INSERT INTO badge_optional_requirements VALUES(10132,236,14,'Create a plan to keep your pets safe in case of an emergency. If you have to evacuate, how would you transport them and where would they go? Make an evacuation kit of necessary pet supplies to keep ready in case of an emergency.');
INSERT INTO badge_optional_requirements VALUES(10133,236,15,'Levels 4 – 5 Only: Make a list of all important documents and valuables you own such as bank information, drivers license, credit cards information, computers, cameras, etc. Create a photo inventory of your valuables and make a copy of all important documents. Store these backups in an off-site location such as a safety deposit box or family member’s home.');
INSERT INTO badge_optional_requirements VALUES(10134,236,16,'Help your community respond to or recover from an emergency such as forest fires, floods, tornadoes, hurricanes or earthquake. Participate in some sort of relief effort whether it is gathering food, water, or clothing, for evacuated families, or planting trees to help regrow damaged forests.');
INSERT INTO badge_optional_requirements VALUES(10135,236,17,'Make a reminder tag/bulletin board to check smoke alarms, list emergency numbers, etc');
INSERT INTO badge_optional_requirements VALUES(10136,236,18,'Make a list of emergency items to keep in your car.');
INSERT INTO badge_optional_requirements VALUES(10137,236,19,'Describe the emergency plan for your Troop meeting.');
INSERT INTO badge_optional_requirements VALUES(10138,236,20,'Learn how to perform CPR.');
INSERT INTO badge_optional_requirements VALUES(10139,236,21,'Explain how you should react when the power goes out.  How can you safely keep cool in the summer and warm in the winter?  What alternative sources of heat, light and power can you use safely?  What are the proper safety precautions for candles?  Why are they dangerous if not used safely?');
INSERT INTO badge_optional_requirements VALUES(10140,236,22,'Know who First Responders are and how to respond to them in emergency situations.  Sometimes first responders in uniform or safety gear can look intimidating to young children.  Learn which type of first responders would respond to emergencies in your area and what kind of safety equipment they might use.  (Fire fighters wearing air masks; Police in body armour, carrying firearms etc).');
INSERT INTO badge_optional_requirements VALUES(10141,244,1,'Understand what the optic chiasma is and draw a diagram of it.');
INSERT INTO badge_optional_requirements VALUES(10142,244,2,'As our eyes register incoming light; electrical pulses transport the information to the brain, which processes it and informs us of what we see.  Learn how the brain takes the information from each eye and combines it with this simple exercise.  Roll up a piece of paper and hold it to your left eye.  Keeping both eyes open place your right hand with the palm facing you next to the tube with your pinky finger touching the tube.  Does it look like there is a hole in your hand?  Find out why.');
INSERT INTO badge_optional_requirements VALUES(10143,244,3,'Visit an optometrist or ophthalmologist and interview them about their job.  What type of education did they need?  What does a typical day look like?  What do they like about their job?');
INSERT INTO badge_optional_requirements VALUES(10144,244,4,'Learn about the different types of equipment an optometrist uses and what each one does.');
INSERT INTO badge_optional_requirements VALUES(10145,244,5,'Learn about Enchroma glasses and how they help the colorblind distinguish color.');
INSERT INTO badge_optional_requirements VALUES(10146,244,6,'Learn about light wavelengths');
INSERT INTO badge_optional_requirements VALUES(10147,244,7,'Find out what an autostereogram is and try to see one.  How do they work?');
INSERT INTO badge_optional_requirements VALUES(10148,244,8,'Learn how glasses and contact lens work.');
INSERT INTO badge_optional_requirements VALUES(10149,244,9,'Visit an optometrist and try on various glasses.  Find out what styles suit what shaped faces and why.');
INSERT INTO badge_optional_requirements VALUES(10150,244,10,'What is persistence of vision and after effects?');
INSERT INTO badge_optional_requirements VALUES(10151,244,11,'Learn how animation tricks our brain into seeing motion.  Create a simple flipbook to demonstrate.');
INSERT INTO badge_optional_requirements VALUES(10152,244,12,'Learn about optical illusions. How do these “trick” our eyes and make us think we see something that is not real? Look at at least 10 different types of optical illusions.');
INSERT INTO badge_optional_requirements VALUES(10153,244,13,'Learn the difference between optometry and ophthalmology.');
INSERT INTO badge_optional_requirements VALUES(10154,247,1,'Learn story of the Tooth Fairy. Make a tooth pouch for yourself or a younger child.');
INSERT INTO badge_optional_requirements VALUES(10155,247,2,'Make a miniature fairy house using natural items such as rocks and twigs. Pine cones can become mini trees, flowers make beautiful decor,  acorn caps make wonderful bowls, etc.');
INSERT INTO badge_optional_requirements VALUES(10156,247,3,'Write your own fairy story or play.');
INSERT INTO badge_optional_requirements VALUES(10157,247,4,'Make a fairy costume, fairy wings, a wand, or a flower wreath for your hair.');
INSERT INTO badge_optional_requirements VALUES(10158,247,5,'Make a fairy themed craft (the costume requirement above cannot be counted for this requirement).');
INSERT INTO badge_optional_requirements VALUES(10159,247,6,'Participate in a community service project that involves fairies. Examples might be to organize a fairy day at your local library and read fairy stories to young children; make and sell fairy crafts or baked items to raise money for a local charity; host a community fairy party; or put together educational flyers regarding fairies to donate to schools or your local library.');
INSERT INTO badge_optional_requirements VALUES(10160,247,7,'Read some poetry about flower fairies and then design your own flower fairy who might be hiding in your backyard, blending into flowers you see.');
INSERT INTO badge_optional_requirements VALUES(10161,247,8,'Learn what the following fairy related words/terms mean: Changling Fae (Fey) Solstice Equinox Sidhe Gaelic Celtic Breaca Sith Fairy Ring (or Circle) Pagan Highlands Banshee.');
INSERT INTO badge_optional_requirements VALUES(10162,247,9,'Read a book of fairy stories or fairy poems that is age appropriate to your level.');
INSERT INTO badge_optional_requirements VALUES(10163,247,10,'With a parent’s permission, watch a fairy movie. What lessons can be learned from this movie?');
INSERT INTO badge_optional_requirements VALUES(10164,247,11,'Bake a fairy-themed dessert and share it with your friends or family.');
INSERT INTO badge_optional_requirements VALUES(10165,247,12,'Earn the Fairy Garden badge.');
INSERT INTO badge_optional_requirements VALUES(10166,247,13,'Learn about some of the items that are traditionally involved with fairies, such as horseshoes, iron, milk, and honey. What items do fairies like? Dislike?');
INSERT INTO badge_optional_requirements VALUES(10167,254,1,'In your backyard, raise either a small crop of vegetables, or a farm animal. If you choose vegetables, they must be started from seed and cared for until they can be harvested. If you choose an animal, you must care for that animal for a minimum of three months. Know where and how you can sell what you raised (You do not have to actually sell your vegetables or animal if you choose not to.)');
INSERT INTO badge_optional_requirements VALUES(10168,254,2,'Find out what animals are raised in your community and what their purpose is; food, clothing, bedding, etc.');
INSERT INTO badge_optional_requirements VALUES(10169,254,3,'Know how to act safely around various farm animals.');
INSERT INTO badge_optional_requirements VALUES(10170,254,4,'Preschool and Level 1 Only: Know what walls, fences, and gates are for and why they should be left as you found them.');
INSERT INTO badge_optional_requirements VALUES(10171,254,5,'Know the location of your state or country fair and attend.');
INSERT INTO badge_optional_requirements VALUES(10172,254,6,'Know what crop rotation is, and why and how the soil is replenished for the crops in your area.');
INSERT INTO badge_optional_requirements VALUES(10173,254,7,'Do some kind of service to help improve farming for your own family, a neighbor, or your community.');
INSERT INTO badge_optional_requirements VALUES(10174,254,8,'Make a poster or booklet showing different types of farming such as dairy, aquaculture, horses, beef, poultry, emus, alpacas, and produce.');
INSERT INTO badge_optional_requirements VALUES(10175,254,9,'Know the farm journals and magazines that are published or widely read in your community.');
INSERT INTO badge_optional_requirements VALUES(10176,254,10,'Be able to recognize the various machines used in planting, cultivating, and harvesting the crops in your area.');
INSERT INTO badge_optional_requirements VALUES(10177,254,11,'Know the cloud formations, temperatures, and wind directions that bring rain, snow, or frosts in your area.');
INSERT INTO badge_optional_requirements VALUES(10178,254,12,'Pick a crop or stock animal and find out what major diseases, parasites, and other threats you must protect against and how.');
INSERT INTO badge_optional_requirements VALUES(10179,254,13,'Create a simple booklet to teach young children about farms.');
INSERT INTO badge_optional_requirements VALUES(10180,254,14,'Find out what careers there are in the farming area of your choice.  What education and experience is needed?  What is the average pay scale and hours worked per week?');
INSERT INTO badge_optional_requirements VALUES(10181,254,15,'Shadow someone who works on a farm for a day.');
INSERT INTO badge_optional_requirements VALUES(10182,254,16,'Explain how farming affects everyone in our country and how the building over of prime agricultural land may affect our future.');
INSERT INTO badge_optional_requirements VALUES(10183,254,17,'Pick a crop or stock animal and learn about the technology used in planting, tending, harvesting, and packaging your item.');
INSERT INTO badge_optional_requirements VALUES(10184,254,18,'Learn about the laws regarding importing and exporting fruits and vegetables both nationally and internationally. If possible, visit a freight forwarder who specializes in agricultural products.');
INSERT INTO badge_optional_requirements VALUES(10185,254,19,'Learn which agricultural products are the United States largest import and export.  Where to we export agricultural products to?  Where do we import them from?');
INSERT INTO badge_optional_requirements VALUES(10186,254,20,'Learn the labeling laws required for the agricultural product of your choice.  How must you adapt your labels if you’re exporting your product to another country?');
INSERT INTO badge_optional_requirements VALUES(10187,254,21,'Learn about heritage varieties of plants. What are these? How can these varieties remain “heritage”?');
INSERT INTO badge_optional_requirements VALUES(10188,254,22,'Learn about the pros and cons of pesticides for crops.');
INSERT INTO badge_optional_requirements VALUES(10189,276,1,'Watch a documentary on food preservation.');
INSERT INTO badge_optional_requirements VALUES(10190,276,2,'Visit a food processing plant to watch food being processed or watch a video about how food is processed and preserved.');
INSERT INTO badge_optional_requirements VALUES(10191,276,3,'Create a visual chart showing different preservation methods (freezing, drying, canning, pickling, etc.) and what types of food each is best for.');
INSERT INTO badge_optional_requirements VALUES(10192,276,4,'Research careers related to food preservation such as food scientists, quality control inspectors, or emergency supply manufacturers.');
INSERT INTO badge_optional_requirements VALUES(10193,276,5,'Visit your county fair and check out the preserved foods competitions. Why do you think one item scored higher than others? What types of things are the judges looking for?');
INSERT INTO badge_optional_requirements VALUES(10194,276,6,'Visit a farm, homestead, or historic site where food preservation is demonstrated.');
INSERT INTO badge_optional_requirements VALUES(10195,276,7,'Learn about food preservation in a different culture and how it has shaped that culture’s diet or cuisine.');
INSERT INTO badge_optional_requirements VALUES(10196,276,8,'Know recommended packaging materials for freezing food. Know how to properly wrap meat, and how to label food for the freezer. Create and maintain a freezer inventory for at least two weeks.');
INSERT INTO badge_optional_requirements VALUES(10197,276,9,'Know the steps in preparing a home canned item, show how to test a seal and prepare canned foods for storage. What is the difference between hot water bath canning and pressure canning? When should each be used? Create a safety checklist for canning at home and explain what could go wrong if steps aren’t followed.');
INSERT INTO badge_optional_requirements VALUES(10198,276,10,'Choose three foods and eat them each prepared in three ways — fresh and after two different types of preservation. Which ways are your favorites?');
INSERT INTO badge_optional_requirements VALUES(10199,276,11,'What are the things that make food spoil? (Examples include heat, light, oxygen, microbes, pests, etc.)  What kinds of diseases can be caught from spoiled food? What happens to nutrients when food spoils? How about taste and appearance? How can you tell if preserved foods have spoiled? What is botulism and how can you prevent it?');
INSERT INTO badge_optional_requirements VALUES(10200,276,12,'What is blanching and why is it used in food preservation? How do acids such as lemon juice help with food preservation?');
INSERT INTO badge_optional_requirements VALUES(10201,276,13,'Learn about historical foods that were preserved for long journeys, such as ship’s biscuits or jerky.  Make some.');
INSERT INTO badge_optional_requirements VALUES(10202,276,14,'Make jam, jelly or other preserved items to give as gifts. Make decorative labels and decorate the lid.');
INSERT INTO badge_optional_requirements VALUES(10203,276,15,'Use preserved ingredients to cook a meal (e.g., canned tomatoes, frozen peas, or dried beans).');
INSERT INTO badge_optional_requirements VALUES(10204,276,16,'Explore the role of food preservatives in packaged foods. What common chemicals are used, and why?');
INSERT INTO badge_optional_requirements VALUES(10205,276,17,'Learn about using herbs, oils, or vinegar as preservatives and try making an herb-infused oil or flavored vinegar.');
INSERT INTO badge_optional_requirements VALUES(10206,276,18,'Design packaging for a preserved food product and write a label that includes the preservation method, ingredients, and storage instructions.');
INSERT INTO badge_optional_requirements VALUES(10207,277,1,'Compare the nutritional value of a boxed ready made food with its homemade counter part. Prepare each and decide which you like better based on nutritional value, taste, and convenience.');
INSERT INTO badge_optional_requirements VALUES(10208,277,2,'With the help of your local butcher, learn how to select meat for various methods of cooking. Which cuts are the least expensive? Which are the most? Why? Learn the name and be able to recognize one cut of meat for each of the following cooking methods: fry, broil, bake, grill.');
INSERT INTO badge_optional_requirements VALUES(10209,277,3,'Find out what kinds of fish are available in your area. Where do they come from and what do they cost? What is the difference between farm raised fish and wild fish?');
INSERT INTO badge_optional_requirements VALUES(10210,277,4,'What are the advantages and disadvantages to preserving foods in the following ways? Canning, freezing, drying, dehydrating, salting, bottling, and vacuum sealing. Demonstrate at least one method.');
INSERT INTO badge_optional_requirements VALUES(10211,277,5,'Help to run a canned food drive for your local food bank.');
INSERT INTO badge_optional_requirements VALUES(10212,277,6,'Visit a local farm or ranch.');
INSERT INTO badge_optional_requirements VALUES(10213,277,7,'What careers are there in the food industry? What education do you need for various jobs? If possible, shadow someone for a day that works in the food industry.');
INSERT INTO badge_optional_requirements VALUES(10214,277,8,'Try one or more vegetables in each of the following ways: fresh, canned, and frozen. Which did you like best? Why? Levels 2-5: Compare cost and nutritional values as well as ease of preparation.');
INSERT INTO badge_optional_requirements VALUES(10215,277,9,'Create a booklet of at least five (Level 2 and above use at least ten) different descriptive labels from various food products. What information should you look for on a label to help you make wise buying decisions? What good things do you see on each label, what things should you avoid?');
INSERT INTO badge_optional_requirements VALUES(10216,277,10,'Create a poster of a food pyramid with examples of each type of food.');
INSERT INTO badge_optional_requirements VALUES(10217,277,11,'Create a display of foods now readily available due to the world market such as bananas, pineapples, coconuts, salmon, tuna, etc.');
INSERT INTO badge_optional_requirements VALUES(10218,277,12,'Select ten fruits or vegetables and make a calendar showing which months it is best to buy. If you buy them in the off season, where are they coming from?');
INSERT INTO badge_optional_requirements VALUES(10219,277,13,'What is botulism and how can you prevent it when preserving foods?');
INSERT INTO badge_optional_requirements VALUES(10220,277,14,'Learn how at least two foods can be stored in your climate in storage pits, basements, cellars, garages, or backyards.');
INSERT INTO badge_optional_requirements VALUES(10221,277,15,'Participate in a community service project involving food, such as a bake sale, donating food to a shelter, etc.');
INSERT INTO badge_optional_requirements VALUES(10222,277,16,'Learn about five different foods from a foreign country that you do not have in your country. Find out how they are made/grown, what dishes they are most used in, etc.');
INSERT INTO badge_optional_requirements VALUES(10223,277,17,'Earn the Food Around the World badge at your level.');
INSERT INTO badge_optional_requirements VALUES(10224,277,18,'Earn the Food Presentation badge at your level.');
INSERT INTO badge_optional_requirements VALUES(10225,277,19,'Earn the Food Preservation badge at your level.');
INSERT INTO badge_optional_requirements VALUES(10226,277,20,'Earn the Food Safety badge at your level.');
INSERT INTO badge_optional_requirements VALUES(10227,285,1,'Learn about at least five different species of frogs. What are their distinctive features?');
INSERT INTO badge_optional_requirements VALUES(10228,285,2,'Visit a local pond, marsh, or wetland. Observe the habitat and identify signs of frog presence.');
INSERT INTO badge_optional_requirements VALUES(10229,285,3,'Research what frogs eat at different stages of their life. Observe or simulate a frog feeding.');
INSERT INTO badge_optional_requirements VALUES(10230,285,4,'Learn about common predators and threats to frogs. How do frogs defend themselves?');
INSERT INTO badge_optional_requirements VALUES(10231,285,5,'Study how frogs use camouflage and other adaptations to survive in their environment.');
INSERT INTO badge_optional_requirements VALUES(10232,285,6,'Participate in or design a project aimed at conserving frog populations in your local area.');
INSERT INTO badge_optional_requirements VALUES(10233,285,7,'Understand the importance of clean water for frogs. Test a local water source for quality.');
INSERT INTO badge_optional_requirements VALUES(10234,285,8,'Research how frogs are depicted in different cultures and folklore. Share a story or legend.');
INSERT INTO badge_optional_requirements VALUES(10235,285,9,'Create a piece of art (drawing, painting, sculpture, craft project) that features a frog.');
INSERT INTO badge_optional_requirements VALUES(10236,285,10,'Read a scientific article or watch a documentary about frogs.');
INSERT INTO badge_optional_requirements VALUES(10237,285,11,'Participate in or observe a frog dissection to learn more about their internal anatomy. There are several (Note: This requirement is optional and should only be done under proper supervision and with ethical considerations in mind.  Online digital dissections can also be used.)');
INSERT INTO badge_optional_requirements VALUES(10238,285,12,'Practice mimicking frog calls. Perform them for your troop or group.');
INSERT INTO badge_optional_requirements VALUES(10239,285,13,'If possible, care for a pet frog or visit an aquarium/zoo to learn about frog care requirements.');
INSERT INTO badge_optional_requirements VALUES(10240,285,14,'Find out what herpetology is and careers that are in this field. Interview a professional in the field if possible.');
INSERT INTO badge_optional_requirements VALUES(10241,285,15,'Design and build a small frog-friendly habitat in your backyard or community garden.');
INSERT INTO badge_optional_requirements VALUES(10242,285,16,'Study frog migration patterns. What triggers their movement, and how do they navigate?');
INSERT INTO badge_optional_requirements VALUES(10243,285,17,'Learn and sing simple songs or rhymes about frogs, like “Five Little Speckled Frogs.”');
INSERT INTO badge_optional_requirements VALUES(10244,285,18,'Learn to fold a jumping origami frog.');
INSERT INTO badge_optional_requirements VALUES(10245,285,19,'Investigate the role of frogs in their ecosystems. How do they contribute to biodiversity and what happens when they are removed from the ecosystem?');
INSERT INTO badge_optional_requirements VALUES(10246,285,20,'Make a frog themed snack.');
INSERT INTO badge_optional_requirements VALUES(10247,292,1,'Plan and carry out a design for a window or potted garden.');
INSERT INTO badge_optional_requirements VALUES(10248,292,2,'Grow three different herbs and use them in at least one recipe.');
INSERT INTO badge_optional_requirements VALUES(10249,292,3,'Start a business or fundraiser using plants that you have grown. For example, you could grow basil in small pots and sell them. You could make tags with “Basil by Bella” or a similar name to advertise your business or event.');
INSERT INTO badge_optional_requirements VALUES(10250,292,4,'Learn the history of scarecrows and create one for your garden.');
INSERT INTO badge_optional_requirements VALUES(10251,292,5,'Learn about three different careers that involve growing fruits and vegetables. What education would you need for this career? What is the average pay and work schedule?');
INSERT INTO badge_optional_requirements VALUES(10252,292,6,'Read a book about gardening and look through a garden catalog. Using what you learned in the book and the catalog, create a budget for creating a dream garden. List the plants that you would plant, the tools you would need, etc. How much would your dream garden cost you?');
INSERT INTO badge_optional_requirements VALUES(10253,292,7,'Donate items from your garden to a community food bank or rescue mission.');
INSERT INTO badge_optional_requirements VALUES(10254,292,8,'Visit your local county extension agent’s office, a local university agricultural or horticultural department, or local produce farm. Report on or make a poster about what you learned.');
INSERT INTO badge_optional_requirements VALUES(10255,292,9,'Participate in a farmer’s market and sell some of your produce.');
INSERT INTO badge_optional_requirements VALUES(10256,292,10,'Build a compost bin and maintain it for 90 days.');
INSERT INTO badge_optional_requirements VALUES(10257,293,1,'Make a garnish for drinks.');
INSERT INTO badge_optional_requirements VALUES(10258,293,2,'Make a fruit garnish and be able to explain what type of dishes it would work well with.');
INSERT INTO badge_optional_requirements VALUES(10259,293,3,'Make a vegetable garnish and be able to explain what type of dishes it would work well with.');
INSERT INTO badge_optional_requirements VALUES(10260,293,4,'Make a sauce garnish using things like mayonnaise, chocolate sauce, or ketchup and be able to explain what type of dishes it would work well with.');
INSERT INTO badge_optional_requirements VALUES(10261,293,5,'Make creamed garnish using things like cream cheese, pate, mouse, etc. and be able to explain what type of dishes it would work well with.');
INSERT INTO badge_optional_requirements VALUES(10262,293,6,'Go to a nice restaurant and see how they garnish their dishes. Try eating some of the garnish that comes with the meal. Does it complement the flavor of the food?');
INSERT INTO badge_optional_requirements VALUES(10263,293,7,'Earn the Food Presentation badge at your level.');
INSERT INTO badge_optional_requirements VALUES(10264,293,8,'Earn the Edible Art badge at your level.');
INSERT INTO badge_optional_requirements VALUES(10265,293,9,'Learn about garnishes throughout history and from different countries.');
INSERT INTO badge_optional_requirements VALUES(10266,293,10,'Make bread garnish and be able to explain what type of dishes it would work well with');
INSERT INTO badge_optional_requirements VALUES(10267,293,11,'Make a cheese garnish and be able to explain what type of dishes it would work well with');
INSERT INTO badge_optional_requirements VALUES(10268,293,12,'Make a candied garnish and be able to explain what type of dishes it would work well with');
INSERT INTO badge_optional_requirements VALUES(10269,293,13,'Prepare a meal for family or friends and use some of the garnishing techniques you have learned.');
INSERT INTO badge_optional_requirements VALUES(10270,295,1,'Have one of your grandparents teach you how to prepare a favorite food from their childhood. If they are not available, have a parent teach you to prepare a favorite food from their childhood.');
INSERT INTO badge_optional_requirements VALUES(10271,295,2,'Learn about a popular game or sport that your parents or grandparents played when they were young. If possible, get some friends together and play the game.');
INSERT INTO badge_optional_requirements VALUES(10272,295,3,'Ask your parents and grandparents if they own any family heirlooms. Ask them to show them to you and explain the history behind them.');
INSERT INTO badge_optional_requirements VALUES(10273,295,4,'Visit a historic home in your area. Ask questions about how someone your age would have lived during the time the home was first lived in.');
INSERT INTO badge_optional_requirements VALUES(10274,295,5,'Go to the library and check out some family history ‘how to’ books suitable to your age level. Ask the librarian for help if necessary.');
INSERT INTO badge_optional_requirements VALUES(10275,295,6,'Learn a song or dance from a country your ancestors came from.');
INSERT INTO badge_optional_requirements VALUES(10276,295,7,'Visit a genealogical research facility. Call your public library or use an Internet search engine to find facilities near your home. Look up your family name and see if you can find ancestors you didn’t know about.');
INSERT INTO badge_optional_requirements VALUES(10277,295,8,'On a map of the world or your country, place a sticker on each city or area in which your ancestors lived.');
INSERT INTO badge_optional_requirements VALUES(10278,295,9,'Visit a cemetery. Take pictures of various headstones and create a collage of the different types, designs, sayings etc. that you find.');
INSERT INTO badge_optional_requirements VALUES(10279,295,10,'Write to a relative and ask them to tell you a story about themselves.');
INSERT INTO badge_optional_requirements VALUES(10280,295,11,'Make a family calendar of all the birthdays and wedding anniversaries for everyone in the family. Make copies and share them with your relatives.');
INSERT INTO badge_optional_requirements VALUES(10281,295,12,'Look at photograph albums with an older relative. Have them identify the people in the photos.   Many times the identities of the people are lost over the years and future generations will have no way of knowing who the people in the photos are.  If the identities are not marked on the photos, carefully write the name on the back with a soft lead pencil or archival quality pen.');
INSERT INTO badge_optional_requirements VALUES(10282,295,13,'Several hundred years ago people did not have surnames (last names). Learn about the history of surnames – where they came from and what they meant. What does your surname mean? Try inventing a new surname.');
INSERT INTO badge_optional_requirements VALUES(10283,295,14,'A census is an official government count or list of all individuals that lived in a certain location at a certain time. A census can contain information such as name, age, gender, race, address, employment, place of birth, parent’s place of birth, education, etc. Learn about census records. Prepare a mock census entry for your family.');
INSERT INTO badge_optional_requirements VALUES(10284,295,15,'Learn about heraldry. Design and create a personal or family Coat of Arms.');
INSERT INTO badge_optional_requirements VALUES(10285,295,16,'Ask older relatives to tell about themselves. Use a voice recorder to record what they have to say for future generations.');
INSERT INTO badge_optional_requirements VALUES(10286,295,17,'Learn about your ancestor’s native language. Get a dictionary for that language from the library and try to learn some words and phrases.');
INSERT INTO badge_optional_requirements VALUES(10287,295,18,'Physical traits can be passed down through generations. Pick a trait that you have: eye color, freckles, hair color, hitchhiker’s thumb, good singing voice, long fingers, etc. Map out several generations of your family on pedigree and family group records. Note on the chart which relatives also share your physical trait.');
INSERT INTO badge_optional_requirements VALUES(10288,295,19,'With the help of your parents, gather and look at original birth, marriage, and death documents you might have around your house. Keep them all together and store them in a safe place.');
INSERT INTO badge_optional_requirements VALUES(10289,301,1,'Create a travel brochure or visitor guide for a real or imaginary ghost town. Include history, what people can see, and safety tips.');
INSERT INTO badge_optional_requirements VALUES(10290,301,2,'Make a model or diorama of a ghost town with labeled buildings.');
INSERT INTO badge_optional_requirements VALUES(10291,301,3,'Create a fictional story or comic about a ghost town and what might have happened there.');
INSERT INTO badge_optional_requirements VALUES(10292,301,4,'Visit a ghost town in person or take a virtual tour online.');
INSERT INTO badge_optional_requirements VALUES(10293,301,5,'Watch a documentary or video about a famous ghost town and report on what you learned.');
INSERT INTO badge_optional_requirements VALUES(10294,301,6,'Research the environmental factors that can cause towns to be abandoned, such as drought, landslides, or pollution.');
INSERT INTO badge_optional_requirements VALUES(10295,301,7,'Learn how archaeologists or historians study abandoned towns to understand the past.');
INSERT INTO badge_optional_requirements VALUES(10296,301,8,'Compare two ghost towns from different parts of the world. How are they alike or different?');
INSERT INTO badge_optional_requirements VALUES(10297,301,9,'Write a journal entry or letter from the point of view of someone who once lived in a now-abandoned town.');
INSERT INTO badge_optional_requirements VALUES(10298,301,10,'Do a creative writing activity imagining what your hometown would be like if it became a ghost town 100 years from now.');
INSERT INTO badge_optional_requirements VALUES(10299,301,11,'Study how ghost towns can become habitats for wildlife. What animals or plants might take over abandoned spaces?');
INSERT INTO badge_optional_requirements VALUES(10300,301,12,'Study how ghost towns are used in pop culture (like in movies, video games, or books).');
INSERT INTO badge_optional_requirements VALUES(10301,301,13,'Participate in or help organize a community clean-up of an old or historic site in your area.');
INSERT INTO badge_optional_requirements VALUES(10302,301,14,'Research ghost towns that became tourist attractions. How are they preserved or rebuilt to attract visitors?');
INSERT INTO badge_optional_requirements VALUES(10303,301,15,'Make a map of a ghost town—real or imaginary—labeling roads, buildings, and landmarks.');
INSERT INTO badge_optional_requirements VALUES(10304,301,16,'Listen to or read ghost stories or legends tied to abandoned towns. Discuss how storytelling helps keep a place’s memory alive.');
INSERT INTO badge_optional_requirements VALUES(10305,301,17,'Learn about the dangers of exploring real ghost towns (unstable buildings, wildlife, toxins, etc.) and how to stay safe.');
INSERT INTO badge_optional_requirements VALUES(10306,301,18,'Study how modern technology (like drones or 3D scanning) is used to explore and preserve ghost towns today.');
INSERT INTO badge_optional_requirements VALUES(10307,301,19,'Draw or write about how you think your town might look if it became a ghost town.  What plants or animals might take over?  What would still be standing after 100 years and what would be gone?');
INSERT INTO badge_optional_requirements VALUES(10308,304,1,'Read the Gingerbread Man poem.');
INSERT INTO badge_optional_requirements VALUES(10309,304,2,'Read a story based on gingerbread. Examples include The Gingerbread Girl by Lisa Campbell Ernst, The Gingerbread Man by various authors, The Gingerbread Mouse by Katy Bratun.');
INSERT INTO badge_optional_requirements VALUES(10310,304,3,'Bake gingerbread men cookies. Decorate with candy and icing.');
INSERT INTO badge_optional_requirements VALUES(10311,304,4,'Read Hansel and Gretel. Who was the author of the story and from what country was it written?  Find the meaning of the names Lebkuchenhaus and Knuperhaeuschen.');
INSERT INTO badge_optional_requirements VALUES(10312,304,5,'Name at least five spices used in gingerbread recipes and name at least six types of candies used in gingerbread decorating.');
INSERT INTO badge_optional_requirements VALUES(10313,304,6,'Make a gingerbread man paper chain.');
INSERT INTO badge_optional_requirements VALUES(10314,304,7,'Describe ten buildings that can be constructed in a gingerbread village. Create designs for five different types of buildings and how you would construct them.');
INSERT INTO badge_optional_requirements VALUES(10315,304,8,'Name the city that is called The Gingerbread Capital of the World and find it on a map.');
INSERT INTO badge_optional_requirements VALUES(10316,304,9,'Find a recipe for making edible gingerbread house glue icing or caramel glue.');
INSERT INTO badge_optional_requirements VALUES(10317,304,10,'Learn about the history of gingerbread and gingerbread houses.');
INSERT INTO badge_optional_requirements VALUES(10318,304,11,'Name the writer of the Hansel and Gretel Opera. Watch a version of the opera by renting a movie or for free on Youtube only after receiving adult supervision.');
INSERT INTO badge_optional_requirements VALUES(10319,304,12,'Watch a gingerbread construction demo at a local craft store, online (with parent permission) or on video.');
INSERT INTO badge_optional_requirements VALUES(10320,304,13,'Participate in a gingerbread house competition. Competitions take place at local craft stores, museums and online throughout November and December each year, or hold one with your friends.');
INSERT INTO badge_optional_requirements VALUES(10321,304,14,'Find out the difference in gingerbread in countries such as England, France, Germany, Poland, and Russia. Include information on the different spices used.');
INSERT INTO badge_optional_requirements VALUES(10322,304,15,'Create a booklet to describe the steps for putting a gingerbread house together and how to use candy to decorate house, pathways, etc.');
INSERT INTO badge_optional_requirements VALUES(10323,304,16,'Create a Gingerbread Mix (recipe) in a Jar to give as a gift.');
INSERT INTO badge_optional_requirements VALUES(10324,304,17,'Take a tour of gingerbread houses that are set up for the holidays, such as at your local school or library.');
INSERT INTO badge_optional_requirements VALUES(10325,304,18,'Participate in a community service project involving this badge, such as baking gingerbread men cookies to give away at your local children’s hospital or holding a bake sale. Make sure to follow all local/state/federal laws.');
INSERT INTO badge_optional_requirements VALUES(10326,305,1,'View a display of glass jewelry.');
INSERT INTO badge_optional_requirements VALUES(10327,305,2,'Make a piece of jewelry using glass beads.');
INSERT INTO badge_optional_requirements VALUES(10328,305,3,'Learn about different careers in glass art. What type of education do you need? What type of pay can you expect? What hours might you work?');
INSERT INTO badge_optional_requirements VALUES(10329,305,4,'Design a table centerpiece using glass, such as a vase, mirror, or bowl.');
INSERT INTO badge_optional_requirements VALUES(10330,305,5,'Visit a glass blower, or glass factory.');
INSERT INTO badge_optional_requirements VALUES(10331,305,6,'Make a collage of pictures of different types of glass art.');
INSERT INTO badge_optional_requirements VALUES(10332,305,7,'Learn what stained glass is and how it is made.');
INSERT INTO badge_optional_requirements VALUES(10333,305,8,'Learn how glass is made and the colors that are produced.');
INSERT INTO badge_optional_requirements VALUES(10334,305,9,'Make a simulated stained glass art project.');
INSERT INTO badge_optional_requirements VALUES(10335,305,10,'Research societies or clubs that allow membership and participation in a community of glass artists. How much does becoming a member cost, what are the requirements of membership, and what resources are available to members?');
INSERT INTO badge_optional_requirements VALUES(10336,305,11,'Learn about the Chihuly Garden and Glass exhibit in Seattle, Washington. Who created it, and how long did the process take? What were the steps in creating it, and how has it affected the city of Seattle?');
INSERT INTO badge_optional_requirements VALUES(10337,305,12,'Make something out of glass. This requirement can be repeated up to 3 times, but does not count toward Level 4 requirement 2.');
INSERT INTO badge_optional_requirements VALUES(10338,305,13,'View an exhibit of glass animals.');
INSERT INTO badge_optional_requirements VALUES(10339,313,1,'Help meet a need for a grandparent. Housecleaning, cooking, accompanying on walks, raking yards, painting fences, etc., all count.');
INSERT INTO badge_optional_requirements VALUES(10340,313,2,'Ask how things were done “back then” when your grandparent was young. Then try something out that your family doesn’t do now—sprinkle the clothes you need to iron, fetch water in a pail, squeeze orange juice straight from oranges, or use a cloth diaper on a baby, etc.');
INSERT INTO badge_optional_requirements VALUES(10341,313,3,'Report by words or photos to a grandparent on something you’ve done so he or she will feel included.');
INSERT INTO badge_optional_requirements VALUES(10342,313,4,'Read a story about a grandparent. A picture book is fine for younger kids. A biography is best for older children.');
INSERT INTO badge_optional_requirements VALUES(10343,313,5,'Write your grandparent’s biography.');
INSERT INTO badge_optional_requirements VALUES(10344,313,6,'Have the biography (#8) bound into a book and give it to your grandparent.');
INSERT INTO badge_optional_requirements VALUES(10345,313,7,'Help make a scrapbook of your grandparent’s life, or illustrate by drawings or photos your grandparent’s biography from #8.');
INSERT INTO badge_optional_requirements VALUES(10346,313,8,'Do something to help your grandparent keep in touch with his or her peers or relatives. This requirement can be repeated.');
INSERT INTO badge_optional_requirements VALUES(10347,313,9,'Memorize a poem or verse about grandparents.');
INSERT INTO badge_optional_requirements VALUES(10348,313,10,'Write a poem or song about grandparents.');
INSERT INTO badge_optional_requirements VALUES(10349,313,11,'Do a photo shoot of or with your grandparent(s).');
INSERT INTO badge_optional_requirements VALUES(10350,313,12,'Make a list of your grandparent’s favorite things—type of sandwich, dessert, book, song, poem, movie, actor, season, color, flowers, birds, etc.');
INSERT INTO badge_optional_requirements VALUES(10351,313,13,'Use the information in #15 to improve a celebration, even if it’s just family night at the movies.');
INSERT INTO badge_optional_requirements VALUES(10352,313,14,'With your grandparent’s permission, record their message for future descendants of your family.');
INSERT INTO badge_optional_requirements VALUES(10353,323,1,'Grow your hair long and donate it to an organization that makes wigs for people who need them.');
INSERT INTO badge_optional_requirements VALUES(10354,323,2,'Try a totally new hair style to see if you like it. Get your parent’s permission first.');
INSERT INTO badge_optional_requirements VALUES(10355,323,3,'Discuss the colors of hair accessories that might look best on two very different people. Do you like ones that blend in with your hair or contrast with it? What kinds of accessories would a person use for everyday? What kinds do you use for special occasions?');
INSERT INTO badge_optional_requirements VALUES(10356,323,4,'Look through some books or watch for unique hairstyles on TV or in a movie. Did you see some that looked really good on the person? Were there some styles that made the person look sloppy or weird?');
INSERT INTO badge_optional_requirements VALUES(10357,323,5,'Collect pictures of three styles that you might like to try yourself or on a doll.');
INSERT INTO badge_optional_requirements VALUES(10358,323,6,'Make a hair design for a favorite character from a book. Either demonstrate it on a doll or draw a detailed picture of it.');
INSERT INTO badge_optional_requirements VALUES(10359,323,7,'Earn the Hair Care badge at your level.');
INSERT INTO badge_optional_requirements VALUES(10360,323,8,'Learn how to make a hair accessory. Make one for yourself and one for someone else. Levels 2-5 need to make three.');
INSERT INTO badge_optional_requirements VALUES(10361,323,9,'Go through some old magazines or catalogs to find some neat ways to use hats, scarves, and ribbons in your hair. What are hats usually made of? Learn to tell the difference between satin and grosgrain ribbon.');
INSERT INTO badge_optional_requirements VALUES(10362,323,10,'Help a younger person try a new hairstyle (with parental permission) or help them get their hair ready for some special occasion.');
INSERT INTO badge_optional_requirements VALUES(10363,323,11,'Look through books for the history of hair styles. Which ones do you like best? Worst?');
INSERT INTO badge_optional_requirements VALUES(10364,323,12,'Research cultural effects on hair styles. Why do some magistrates wear wigs? Why do some people wear hats to church? Are there groups of people who require certain people to cut their hair in different ways?');
INSERT INTO badge_optional_requirements VALUES(10365,323,13,'Take a tour of a salon. What type of education is necessary to become a hair stylist?');
INSERT INTO badge_optional_requirements VALUES(10366,323,14,'Help an elderly or disabled person with a shampoo, style or other hair care.');
INSERT INTO badge_optional_requirements VALUES(10367,323,15,'Collect pictures of five styles that you might like to try yourself or on a doll.');
INSERT INTO badge_optional_requirements VALUES(10368,323,16,'Find five different hair fasteners and learn how to use them. If you earned this badge already, you will need to find five new fasteners, or you can learn the names of five styles of hat: pillbox, beret, etc. If you run out of hair fasteners and hats to learn about, find five ways to use scarves in your hair.');
INSERT INTO badge_optional_requirements VALUES(10369,323,17,'Watch a barbering video or get instruction from a barber and then see if you can find someone on which to practice cutting hair (with parental permission). Just before the usually scheduled trip to the barber is an excellent time to do this, because if the person doesn’t like the cut, the barber can help ‘fix’ it.');
INSERT INTO badge_optional_requirements VALUES(10370,323,18,'Earn the Hairstyles badge at your level.');
INSERT INTO badge_optional_requirements VALUES(10371,324,1,'Read a book about how to care for a domestic hamster.');
INSERT INTO badge_optional_requirements VALUES(10372,324,2,'Draw a detailed picture of a hamster and label all parts.');
INSERT INTO badge_optional_requirements VALUES(10373,324,3,'Visit a pet store and browse the hamster section. How many different types of hamsters can you find? Talk to a worker about hamster care.');
INSERT INTO badge_optional_requirements VALUES(10374,324,4,'Most hamsters are known for being domestic, but learn about feral hamsters. What do they eat? Where can they be found? How would someone domesticate them?');
INSERT INTO badge_optional_requirements VALUES(10375,324,5,'Learn how to select the best hamster cage. Find three different types you think would be the best option and list pros and cons for each. What factors influence your decision? Price, size, material?');
INSERT INTO badge_optional_requirements VALUES(10376,324,6,'Create a presentation about hamsters and then how it to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(10377,324,7,'Watch a documentary about hamsters. Take notes and discuss what you learn with a friend or family member.');
INSERT INTO badge_optional_requirements VALUES(10378,324,8,'Learn about and list five different hamster accessories or toys.');
INSERT INTO badge_optional_requirements VALUES(10379,353,1,'Brainstorm at least ten things that make homeschooling special to you and share them with someone who is not your homeschooling teacher.');
INSERT INTO badge_optional_requirements VALUES(10380,353,2,'Design a T-shirt for homeschoolers or your homeschool.');
INSERT INTO badge_optional_requirements VALUES(10381,353,3,'Start a homeschool blog, journal or newsletter to keep track of special events, field trips and achievements.');
INSERT INTO badge_optional_requirements VALUES(10382,353,4,'Find out if there is a local homeschool association or group in your area. If so, join and take part in one of their activities.');
INSERT INTO badge_optional_requirements VALUES(10383,353,5,'Find out what extra curricular activities are available for you to participate in with your local school. Examples include sports, choir, band, plays, clubs, etc.');
INSERT INTO badge_optional_requirements VALUES(10384,353,6,'Plan a service project for homeschoolers to participate in and be a part of.');
INSERT INTO badge_optional_requirements VALUES(10385,353,7,'Plan a get-together for the homeschoolers in your area, such as a back to school cookout, a used curriculum sale, a project or science fair, or a swimming party.');
INSERT INTO badge_optional_requirements VALUES(10386,353,8,'Browse through homeschool catalogs or websites and list at least three educational items that interest you.');
INSERT INTO badge_optional_requirements VALUES(10387,353,9,'Keep a scrapbook of your homeschool year.');
INSERT INTO badge_optional_requirements VALUES(10388,353,10,'Learn about at least three famous homeschoolers.');
INSERT INTO badge_optional_requirements VALUES(10389,353,11,'Know your states laws regarding work permits for minors and drivers licenses and how to apply for these as a homeschooler.');
INSERT INTO badge_optional_requirements VALUES(10390,353,12,'Know what colleges and universities are looking for on transcripts and applications from homeschoolers.');
INSERT INTO badge_optional_requirements VALUES(10391,361,1,'What is tack?  Visit a tack store or look through a tack catalog and be able to identify a saddle, bridle, halter, stirrups, and saddle pad.   What is the main difference between Western tack and English tack?');
INSERT INTO badge_optional_requirements VALUES(10392,361,2,'Learn the history of horseback riding. What were horses originally used for? When were stirrups invented? Why do we traditionally lead and mount a horse from the left?');
INSERT INTO badge_optional_requirements VALUES(10393,361,3,'What is a gait?  Name and define the four gaits. Learn about gaited horses, such as the Icelandic pony and its tolt.');
INSERT INTO badge_optional_requirements VALUES(10394,361,4,'Learn about the different types of bits. What is the difference between curb and snaffle bits? Why do some bits have rollers? What is a hackmore? A double bridle? How can bits be harmful if used wrong?');
INSERT INTO badge_optional_requirements VALUES(10395,361,5,'Make a poster of a horse and label 15 parts of its anatomy. Why is knowing horse anatomy helpful when riding a horse?');
INSERT INTO badge_optional_requirements VALUES(10396,361,6,'Make a booklet showing the different types of tack used on a horse. Include at least 3 types of saddles, bridles, and bits.  You can cut pictures out of a catalog, or draw your own.  Explain the proper use for each piece of tack chosen.');
INSERT INTO badge_optional_requirements VALUES(10397,361,7,'Learn how to properly care for your tack. What does unsafe tack look like?');
INSERT INTO badge_optional_requirements VALUES(10398,361,8,'Pick a riding discipline. What is the history of it? What breeds typically compete in this discipline? What tack is needed? What does the rider wear? What are the advantages and disadvantages in regards to the horse’s health? This requirement can be repeated up to three times.');
INSERT INTO badge_optional_requirements VALUES(10399,361,9,'The breed of horse one rides can matter. Physically, why are some horse breeds naturally better at certain disciplines? For instance, why do we race Thoroughbreds but not Clydesdales? Why are reining horses typically shorter than show jumping horses?');
INSERT INTO badge_optional_requirements VALUES(10400,361,10,'Learn about the different riding accessories, such as polo wraps, split boots, martingales, and breast collars. Why are these used?');
INSERT INTO badge_optional_requirements VALUES(10401,361,11,'Learn about spurs and the different types of whips. What are the advantages and disadvantages of these? How are they used properly? When should you use a crop whip versus a dressage whip versus a lunge whip?');
INSERT INTO badge_optional_requirements VALUES(10402,361,12,'Learn the foundational riding skills, including cantering, leg yield, and riding a proper 20 meter circle.');
INSERT INTO badge_optional_requirements VALUES(10403,361,13,'Learn the basics of jumping. What is two-point position?');
INSERT INTO badge_optional_requirements VALUES(10404,361,14,'Attend a horse show or rodeo.  What classes would you qualify to compete in?  What do the judges look for?');
INSERT INTO badge_optional_requirements VALUES(10405,361,15,'Learn the proper ways to warm up and cool down a horse in the summer and winter.');
INSERT INTO badge_optional_requirements VALUES(10406,366,1,'Learn how to use the machine properly and safely under adult supervision.');
INSERT INTO badge_optional_requirements VALUES(10407,366,2,'Draw a picture of your chosen machine and label the most important parts.');
INSERT INTO badge_optional_requirements VALUES(10408,366,3,'Take apart a broken or donated household machine (with supervision) to see what’s inside');
INSERT INTO badge_optional_requirements VALUES(10409,366,4,'Interview or shadow someone who repairs household appliances');
INSERT INTO badge_optional_requirements VALUES(10410,366,5,'Study the energy usage of several brands/types/styles of your machine and find out which are the most efficient');
INSERT INTO badge_optional_requirements VALUES(10411,366,6,'Learn basic maintenance tasks for you household machine (e.g., cleaning a filter, checking hoses, refilling detergent)');
INSERT INTO badge_optional_requirements VALUES(10412,366,7,'Write or draw step-by-step instructions for using your household machine correctly');
INSERT INTO badge_optional_requirements VALUES(10413,366,8,'Visit a store or showroom to see different options for your machine and their features');
INSERT INTO badge_optional_requirements VALUES(10414,366,9,'Learn what powers your machine—does it use electricity, gas, water, or batteries? Find where the power goes in.');
INSERT INTO badge_optional_requirements VALUES(10415,366,10,'Study safety symbols and warnings commonly found on household machines');
INSERT INTO badge_optional_requirements VALUES(10416,366,11,'Help run your machine as part of your chores.  Depending on the machine you are studying this might be daily, weekly or even monthly.');
INSERT INTO badge_optional_requirements VALUES(10417,366,12,'Research how smart technology is used in in your machine.');
INSERT INTO badge_optional_requirements VALUES(10418,366,13,'Make a poster showing which machines help with different household chores');
INSERT INTO badge_optional_requirements VALUES(10419,366,14,'Watch a video or animation showing how motors or gears help machines function');
INSERT INTO badge_optional_requirements VALUES(10420,366,15,'Make a mini model or a drawing that shows how your machine works.');
INSERT INTO badge_optional_requirements VALUES(10421,366,16,'Study how a timer, thermostat, or cycle control works in your chosen machine and how it regulates the process.');
INSERT INTO badge_optional_requirements VALUES(10422,366,17,'Learn how to tell when your machine needs maintenance or repair (e.g., strange noises, leaks, error messages)');
INSERT INTO badge_optional_requirements VALUES(10423,366,18,'Do a community service project that involves using your household machine.');
INSERT INTO badge_optional_requirements VALUES(10424,367,1,'Learn five vocabulary words related to houseplants such as humidity, propagation, pruning, succulent, and drainage');
INSERT INTO badge_optional_requirements VALUES(10425,367,2,'Research 3–5 common houseplants and compare their care needs (light, watering, humidity, etc.)');
INSERT INTO badge_optional_requirements VALUES(10426,367,3,'Create a care chart or illustrated guide for a beginner showing how to take care of a specific houseplant');
INSERT INTO badge_optional_requirements VALUES(10427,367,4,'Try propagating a houseplant by taking a cutting, dividing roots, or placing a leaf in water');
INSERT INTO badge_optional_requirements VALUES(10428,367,5,'Visit a plant nursery or garden center and talk to a staff member about indoor plant care. Ask what kinds of houseplants are easy or difficult to grow.');
INSERT INTO badge_optional_requirements VALUES(10429,367,6,'Grow a plant from seed indoors and compare its growth to a pre-purchased houseplant');
INSERT INTO badge_optional_requirements VALUES(10430,367,7,'Repot a plant using appropriate potting mix and a container with good drainage');
INSERT INTO badge_optional_requirements VALUES(10431,367,8,'Make a decorative plant marker or design a fun container for your plant');
INSERT INTO badge_optional_requirements VALUES(10432,367,9,'Create a science experiment comparing how a plant grows with and without sunlight, or with more vs. less water');
INSERT INTO badge_optional_requirements VALUES(10433,367,10,'Research which houseplants are safe or toxic for pets and make a list for families with animals.');
INSERT INTO badge_optional_requirements VALUES(10434,367,11,'Study how houseplants help improve indoor air quality and mood. Share your findings with others');
INSERT INTO badge_optional_requirements VALUES(10435,367,12,'Design a plant care schedule for a week and follow it for at least one month.');
INSERT INTO badge_optional_requirements VALUES(10436,367,13,'Decorate your room or home space with plants. Try arranging them by color, light needs, or size');
INSERT INTO badge_optional_requirements VALUES(10437,367,14,'Create a mini indoor garden using small plants, herbs, or succulents');
INSERT INTO badge_optional_requirements VALUES(10438,367,15,'Research how houseplants are used in different cultures (e.g., feng shui, herbal use, spiritual symbolism)');
INSERT INTO badge_optional_requirements VALUES(10439,367,16,'Donate a houseplant to a senior center, library, or community space to help brighten the environment');
INSERT INTO badge_optional_requirements VALUES(10440,367,17,'Participate in a plant swap or community garden event where houseplants are shared');
INSERT INTO badge_optional_requirements VALUES(10441,367,18,'Try using a moisture meter or other tool to help monitor your plant’s needs. Report on how it helps.');
INSERT INTO badge_optional_requirements VALUES(10442,374,1,'Learn about the tools used in ice sculpting and the safety rules when using them.');
INSERT INTO badge_optional_requirements VALUES(10443,374,2,'Experiment with freezing small objects (like leaves, flowers, or toys) into clear blocks of ice and turning them into “frozen exhibits.”');
INSERT INTO badge_optional_requirements VALUES(10444,374,3,'Learn about the physical process that occurs when salt is added to ice.');
INSERT INTO badge_optional_requirements VALUES(10445,374,4,'Try building a mini ice wall using ice cubes and water or salt “glue.” How tall can you make it before it tips over or melts?');
INSERT INTO badge_optional_requirements VALUES(10446,374,5,'Research the role of ice sculpting in cultural celebrations such as ice festivals, weddings, or religious events in countries like China, Russia, or Japan');
INSERT INTO badge_optional_requirements VALUES(10447,374,6,'Create a gallery of your own frozen art and share photos or a video with friends or family');
INSERT INTO badge_optional_requirements VALUES(10448,374,7,'Study how lighting and color can be used to enhance ice sculptures at night. Experiment with shining lights through your frozen creations');
INSERT INTO badge_optional_requirements VALUES(10449,374,8,'Watch time-lapse videos of professional ice sculptures being created. What techniques or sequences do you notice?');
INSERT INTO badge_optional_requirements VALUES(10450,374,9,'Participate in or help organize a community event that includes ice sculptures, or share your frozen art in a local showcase or school project');
INSERT INTO badge_optional_requirements VALUES(10451,374,10,'Learn how ice sculptors use chainsaws, chisels, and templates to create detail in large ice blocks.  Draw or digitally design a blueprint of a large ice sculpture you would like to make. Label the parts and tools that would be needed to create it.');
INSERT INTO badge_optional_requirements VALUES(10452,374,11,'Explore how climate and temperature affect outdoor ice sculptures. Track the temperature and how long yours lasts outside');
INSERT INTO badge_optional_requirements VALUES(10453,374,12,'Study the science of freezing and melting by testing how fast different shapes or types of ice melt');
INSERT INTO badge_optional_requirements VALUES(10454,374,13,'Create a stop-motion video showing your ice sculpture melting, disappearing, or transforming over time.');
INSERT INTO badge_optional_requirements VALUES(10455,374,14,'Compare ice sculpting to other temporary or meltable art forms like snow art, chocolate sculpture, or sand carving. What are the pros and challenges of each?');
INSERT INTO badge_optional_requirements VALUES(10456,374,15,'Research how clear ice is made and why most homemade ice looks cloudy. Try a method to make your ice clearer');
INSERT INTO badge_optional_requirements VALUES(10457,374,16,'Find out how ice is stored, transported, and prepared for carving at professional events or competitions');
INSERT INTO badge_optional_requirements VALUES(10458,374,17,'Visit or virtually tour an ice hotel, festival, or competition and describe the sculptures or structures you saw');
INSERT INTO badge_optional_requirements VALUES(10459,374,18,'Study how other cultures use ice and snow in architecture or art. Compare igloos, snow lanterns, and snow sculptures to ice carvings');
INSERT INTO badge_optional_requirements VALUES(10460,375,1,'Do an Iditarod-related service project, such as a dog food donation event for a local shelter or a fundraiser to benefit the Iditarod.');
INSERT INTO badge_optional_requirements VALUES(10461,375,2,'What types of dogs are used in the race? Has it changed over the years? Share what you’ve learned with someone.');
INSERT INTO badge_optional_requirements VALUES(10462,375,3,'Read the rules of the race and create a presentation about what you’ve learned to your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(10463,375,4,'Learn about the sled, supplies, and clothes the mushers have.');
INSERT INTO badge_optional_requirements VALUES(10464,375,5,'Read the biography of an Iditarod musher.');
INSERT INTO badge_optional_requirements VALUES(10465,375,6,'Watch a portion of the Iditarod (in person or on the computer/TV with a parent’s permission).');
INSERT INTO badge_optional_requirements VALUES(10466,375,7,'Draw/Paint an Iditarod related picture (e.g., musher, dog sled, dogs) and share it with your family, friends, or group.');
INSERT INTO badge_optional_requirements VALUES(10467,375,8,'Take a field trip to Iditarod Headquarters, or do it virtually with a parent’s permission.');
INSERT INTO badge_optional_requirements VALUES(10468,375,9,'Learn what a “dropped dog” is and what the vets do for them.');
INSERT INTO badge_optional_requirements VALUES(10469,375,10,'What is involved in training sled dogs? During the summer? Winter?');
INSERT INTO badge_optional_requirements VALUES(10470,375,11,'Write letters to Iditarod mushers.');
INSERT INTO badge_optional_requirements VALUES(10471,375,12,'Learn Iditarod mushing  vocabulary.');
INSERT INTO badge_optional_requirements VALUES(10472,375,13,'Research mushers participating in this year’s Iditarod and follow their progress.');
INSERT INTO badge_optional_requirements VALUES(10473,375,14,'Understand what the “Widow’s Lamp” used in the races is and why it’s significant.');
INSERT INTO badge_optional_requirements VALUES(10474,389,1,'Find out how long can you keep juice before it loses its nutrients?');
INSERT INTO badge_optional_requirements VALUES(10475,389,2,'Explain why some veggie drinks can give some people a stomach ache.');
INSERT INTO badge_optional_requirements VALUES(10476,389,3,'How do you use the pulp? Find at least one recipe using juice pulp.');
INSERT INTO badge_optional_requirements VALUES(10477,389,4,'What is the difference between blending and juicing? Try making juice with a blender and comparing it with juice made from a juicer. What are the taste differences? What is the difference in nutrition?');
INSERT INTO badge_optional_requirements VALUES(10478,389,5,'Visit your local farmer’s market or organic produce section and be able to tell which produce items can be juiced and which cannot.');
INSERT INTO badge_optional_requirements VALUES(10479,389,6,'Select 2 fruits and 3 vegetables and find out the health benefits each.');
INSERT INTO badge_optional_requirements VALUES(10480,389,7,'Juice a new combination.');
INSERT INTO badge_optional_requirements VALUES(10481,389,8,'Learn about different” boosts” to add to your juice such as wheat grass or probiotics.');
INSERT INTO badge_optional_requirements VALUES(10482,389,9,'Earn the Nutrition badge at your level.');
INSERT INTO badge_optional_requirements VALUES(10483,389,10,'Talk to or read about someone whom juicing has made an impact on their life.');
INSERT INTO badge_optional_requirements VALUES(10484,389,11,'Talk to or read about someone who is using juicing to make a living.');
INSERT INTO badge_optional_requirements VALUES(10485,389,12,'Earn the Organic Foods badge at your level.');
INSERT INTO badge_optional_requirements VALUES(10486,389,13,'Participate in a community service project that has to do with juicing.  You might make pamphlets educating the public about the health benefits of juicing, volunteer at a farmer’s market and give samples of fresh juice, or teach younger kids about juicing.');
INSERT INTO badge_optional_requirements VALUES(10487,391,1,'Learn five vocabulary words related to the Junior Ranger program such as ranger, conservation, stewardship, monument, and interpretation');
INSERT INTO badge_optional_requirements VALUES(10488,391,2,'Research how many different agencies offer Junior Ranger programs (such as National Park Service, state parks, national forests, wildlife refuges, or museums)');
INSERT INTO badge_optional_requirements VALUES(10489,391,3,'Create a timeline showing how the Junior Ranger program expanded to include many different sites and themes');
INSERT INTO badge_optional_requirements VALUES(10490,391,4,'Interview a park ranger, volunteer, or docent about why they enjoy working with Junior Rangers');
INSERT INTO badge_optional_requirements VALUES(10491,391,5,'Compare Junior Ranger programs for different age groups. How do activities change for younger vs. older kids?');
INSERT INTO badge_optional_requirements VALUES(10492,391,6,'Design your own Junior Ranger booklet page, including instructions, drawings, and learning goals');
INSERT INTO badge_optional_requirements VALUES(10493,391,7,'Learn about special Junior Ranger programs such as Junior Paleontologist, Junior Angler, WebRangers, or themed series');
INSERT INTO badge_optional_requirements VALUES(10494,391,8,'Collect photos or drawings of Junior Ranger badges from around the country and sort them by theme (nature, history, animals, geology, etc.)');
INSERT INTO badge_optional_requirements VALUES(10495,391,9,'Learn what Junior Rangers promise or pledge. Write your own pledge about caring for parks and public lands');
INSERT INTO badge_optional_requirements VALUES(10496,391,10,'Research how Junior Ranger programs support conservation, education, and public service');
INSERT INTO badge_optional_requirements VALUES(10497,391,11,'Do a community service project inspired by the Junior Ranger mission, such as park clean-up, trail care, or teaching others about protecting nature');
INSERT INTO badge_optional_requirements VALUES(10498,391,12,'Learn what education or training is needed to become a park ranger');
INSERT INTO badge_optional_requirements VALUES(10499,391,13,'Compare the Junior Ranger program to other youth programs focused on nature or history. What makes it unique?');
INSERT INTO badge_optional_requirements VALUES(10500,391,14,'Explore the Junior Ranger program online and find digital activities, videos, or printable resources');
INSERT INTO badge_optional_requirements VALUES(10501,391,15,'Create a display, poster, or slideshow explaining the Junior Ranger program to others');
INSERT INTO badge_optional_requirements VALUES(10502,391,16,'Plan a “Junior Ranger Day” at home or with a group, including activities, learning stations, and a ceremony');
INSERT INTO badge_optional_requirements VALUES(10503,391,17,'Track all the Junior Ranger badges you have earned and make a map showing where they came from');
INSERT INTO badge_optional_requirements VALUES(10504,391,18,'Write a reflection about how being a Junior Ranger helps kids learn responsibility, respect, and curiosity');
INSERT INTO badge_optional_requirements VALUES(10505,404,1,'Attend a role-playing event, as either a spectator or a participant. This can be a reenactment, a renaissance fair, a convention, or any other venue.  Are there games and activities for children to play?  Is there a place set up to show how the characters live (a tent village, for example)?  Are there shops or booths where gear is sold for people interested in the hobby?  Do the participants’ costumes look highly realistic, or do they look made up for fun?');
INSERT INTO badge_optional_requirements VALUES(10506,404,2,'Learn about the jobs a person might have in your chosen hobby, such as a oldier, blacksmith, laundress, weaver, farmer, wizard, elf, etc. Which people might be wealthy, and which people would be poor?  What gear and equipment would expect each person to have? If your persona is a child, consider what “your” family is like.  What does “your” father do for a living?  Does “your” mother work too?  Do you live on a farm, or in a village?  Are you wealthy, or poor?  Do you need to change your description of how your persona lives?');
INSERT INTO badge_optional_requirements VALUES(10507,404,3,'With your parent’s permission/assistance, explore your hobby online. Are there many websites for your hobby?  Can you buy clothing? Uniforms? Weapons? Armor? Toys? Tents? Gear for animals? Sewing patterns?');
INSERT INTO badge_optional_requirements VALUES(10508,404,4,'Put together a costume, and dress as your persona. This can include footwear, hairstyle and/or hat, and accessories.  Imagine you are that person.  Can you perform in character?');
INSERT INTO badge_optional_requirements VALUES(10509,404,5,'Plan a role-playing activity with your friends, family, or group. Put together costumes from clothing, props, and toys you have at home, and play the roles of your personas.  This can be anything from a tea party in long gowns to shopping at a Medieval market to battling orcs and goblins.  Stay in character.  If you are able to participate in an actual role-playing event, stay in character as much as possible during the event.');
INSERT INTO badge_optional_requirements VALUES(10510,404,6,'Many role-playing hobbies are military-oriented. Weapons come in all kinds. What weapons are used in your hobby?  Are they antiques or reproductions?  Are they actual weapons, or are they created to be safe for play-fighting?  Are there rules limiting what ages are allowed to participate with weapons?');
INSERT INTO badge_optional_requirements VALUES(10511,404,7,'Visit a living history event or village. These are often reenactors who are particularly careful to accurately portray the way people lived in another time.  Do the reenactors talk to you in character?');
INSERT INTO badge_optional_requirements VALUES(10512,404,8,'Some role-playing hobbies involve camping. Reenactors generally use canvas tents and wooden stools, but must find ways to hide all their modern gear. What could you use instead of a sleeping bag?  How will you hide a plastic cooler?   Better bring a tin cup for your Pepsi—you can’t let anyone see the can!  Plan a menu for a whole day with only a fire to cook on.');
INSERT INTO badge_optional_requirements VALUES(10513,404,9,'Levels 4 and 5 Only: Some role-playing is controversial—some parts of history were not pretty, and other parts are now judged from a modern perspective rather than a historic one. Even fantasy hobbies have been affected by controversy.  With your parents’ permission/assistance, learn about any controversy faced by your particular hobby.  Consider these controversies, and research if you need to.  Do you believe they are valid?');
INSERT INTO badge_optional_requirements VALUES(10514,404,10,'With your parents’ permission/assistance, go online and research national or international organizations for your hobby. Do these websites help you locate groups near you?  Can you find information about scheduled events?  Does your hobby hold very large events?  Can you find information on these sites about small local events?  Is there information that helps you learn to build a better character persona?  Is there information about safety and rules of conduct?');
INSERT INTO badge_optional_requirements VALUES(10515,404,11,'Learn about a role-playing group near you (“near” may be several hours away). How often do they meet?  Where do they meet?  Do they have specific times just to train or practice together?  Do they attend larger events as a group?');
INSERT INTO badge_optional_requirements VALUES(10516,404,12,'Learn about careers involving role-playing. This may be easiest by checking the employment postings at a popular locations that use living historians.  What kind of training or education is required?  What kinds of skills are needed to work professionally as a role-player?');
INSERT INTO badge_optional_requirements VALUES(10517,426,1,'Learn five vocabulary words related to love such as empathy, affirmation, appreciation, boundaries, and emotional intelligence');
INSERT INTO badge_optional_requirements VALUES(10518,426,2,'Take a love languages quiz (with permission) to discover your personal primary and secondary love languages');
INSERT INTO badge_optional_requirements VALUES(10519,426,3,'Interview or shadow someone in a helping profession (teacher, counselor, caregiver, etc.) and ask how they use different love languages to connect with others.');
INSERT INTO badge_optional_requirements VALUES(10520,426,4,'Create a chart showing examples of how each love language can be used with family, friends, or pets');
INSERT INTO badge_optional_requirements VALUES(10521,426,5,'Reflect on how misunderstandings in friendships or relationships might stem from different love languages. Write about a time this may have happened in your life or role-play possible scenarios with your group.');
INSERT INTO badge_optional_requirements VALUES(10522,426,6,'Make a mini-book or poster to teach younger kids about the five love languages');
INSERT INTO badge_optional_requirements VALUES(10523,426,7,'Do a community service project that includes showing kindness through multiple love languages (e.g., making cards, giving snacks, helping clean up, or visiting someone)');
INSERT INTO badge_optional_requirements VALUES(10524,426,8,'Interview your family or friends and ask how they feel most loved. Compare how their answers are alike or different from yours');
INSERT INTO badge_optional_requirements VALUES(10525,426,9,'Keep a one-week kindness journal and record how you used different love languages each day');
INSERT INTO badge_optional_requirements VALUES(10526,426,10,'Research how the five love languages are used in schools, therapy, or family counseling. Share what you learn in a short report or discussion.');
INSERT INTO badge_optional_requirements VALUES(10527,426,11,'Create a matching game, board game, or sorting activity to teach the five love languages');
INSERT INTO badge_optional_requirements VALUES(10528,426,12,'Design a badge, logo, or symbol for each love language');
INSERT INTO badge_optional_requirements VALUES(10529,426,13,'Learn how love languages might look different across cultures, generations, or personalities');
INSERT INTO badge_optional_requirements VALUES(10530,426,14,'Plan a “Love Language Challenge” for your family or club where you all try to use a different love language each day for a week');
INSERT INTO badge_optional_requirements VALUES(10531,426,15,'Explore how social media can affect the way people express or receive love languages. Are certain love languages harder or easier to express online?');
INSERT INTO badge_optional_requirements VALUES(10532,426,16,'Write a letter to someone who made you feel loved in the past and tell them why it meant so much');
INSERT INTO badge_optional_requirements VALUES(10533,426,17,'Role-play different situations where using the right love language could help someone feel included, supported, or encouraged');
INSERT INTO badge_optional_requirements VALUES(10534,426,18,'Create a story, comic, or skit that shows characters using different love languages');
INSERT INTO badge_optional_requirements VALUES(10535,436,1,'Do maple leaf rubbings with a crayon and a piece of paper Level 2 and Up: Teach someone else how to do leaf rubbings.');
INSERT INTO badge_optional_requirements VALUES(10536,436,2,'Make maple candy.');
INSERT INTO badge_optional_requirements VALUES(10537,436,3,'Taste different grades of pure maple syrup. Compare the flavor and color. Which was your favorite?');
INSERT INTO badge_optional_requirements VALUES(10538,436,4,'Participate in the process of collecting maple sap, and the cooking and bottling process.');
INSERT INTO badge_optional_requirements VALUES(10539,436,5,'Write a paper about the history of maple syrup.');
INSERT INTO badge_optional_requirements VALUES(10540,436,6,'Make a snack, dessert, or other dish that includes maple syrup as an ingredient.');
INSERT INTO badge_optional_requirements VALUES(10541,436,7,'Make a collage using different types of maple leaves.');
INSERT INTO badge_optional_requirements VALUES(10542,436,8,'Plant a maple tree.');
INSERT INTO badge_optional_requirements VALUES(10543,436,9,'Explain two different ways the sap can be cooked down.');
INSERT INTO badge_optional_requirements VALUES(10544,436,10,'Make a drawing showing the process of tapping a tree and cooking down the sap. Include all equipment needed to make the syrup. Show your family, friends, or group your drawing.');
INSERT INTO badge_optional_requirements VALUES(10545,436,11,'Create a presentation about the process of making maple syrup. Include an explanation of the window of opportunity to harvest sap, how much sap is needed to make one quart of finished product, and how long the entire process takes from start to finish. Show your family, friends, or group your presentation.');
INSERT INTO badge_optional_requirements VALUES(10546,436,12,'Explain the difference between pure maple syrup, imitation maple syrup, corn syrup, and maple flavoring.');
INSERT INTO badge_optional_requirements VALUES(10547,436,13,'Compare the price of different types and grades of syrup.');
INSERT INTO badge_optional_requirements VALUES(10548,445,1,'Plan a food budget for a week.  Take the grocery list to at least three different stores to compare prices and then do the purchasing from at least two locations. Figure out how much you saved on groceries over the most expensive store for each item. Figure out how much gas it took to go to the different stores. You will need your parent’s prior permission and try to plan your stops in between other errands to reduce fuel usage. If you made your stops while doing other errands in the same parking lot, do not add in any fuel cost for that stop.');
INSERT INTO badge_optional_requirements VALUES(10549,445,2,'Math and investing go hand in hand.  In simple interest, you earn interest payments from the principal only. In compound interest, you reinvest the interest payments and earn interest on interest. This is the equation for finding compound interest: A = P (1 + r / k) k * n Where A = amount in account at end of the period P = principal r = rate (usually, an annual rate) k = number of compounding times per year n = number of years Using this equation, if you are 15 years old and you want to retire at age 65 with a million dollars in the bank and you can invest your money to earn 10% compound interest per year, how much do you have to invest each year?  Divide this amount by 12 to find out how much you would have to invest each month.  Can you fit this into your family budget?');
INSERT INTO badge_optional_requirements VALUES(10550,445,3,'Play at least ten board games that use math. Make a chart to show which games help people practice which skills. Determine which game covers the most math. Which one is the most fun?');
INSERT INTO badge_optional_requirements VALUES(10551,445,4,'Find someone who buys most of her groceries at a discount store or through a food co-op. Ask her for one week’s worth of her grocery list and her cash register receipt or invoice. Go to a regular grocery store or a health food store and compare the cost for that week of food.');
INSERT INTO badge_optional_requirements VALUES(10552,445,5,'What does math have to do with home decorating? Most home decorators need to work within a budget. But in order to figure out what you’ll spend, you first have to know what you need. How will you know how many rolls of wallpaper to buy if you don’t calculate how much wall space you have to cover? Understanding some basic geometry can help you stick to your budget. Imagine you’re planning to buy new carpeting for your home. You’re going to put down carpeting in the living room, bedroom, and hallway, but not in the bathroom. You could try to guess at how much carpet you might need to cover these rooms, but you’re better off figuring out exactly what you need.   First, figure out the total area of  your floor plan.  Then subtract the area of the bathroom since you don’t plan to carpet that.  This will tell you the total number of square feet you will need to carpet.  What if the carpet only comes in rolls 10’ wide?  How many linear feet of carpet will you need?  If your ceilings are 10’ high, how much wall paper would you need for each room?');
INSERT INTO badge_optional_requirements VALUES(10553,445,6,'What is the value of the dollar?  Find out what the value of a dollar is compared 12 different world currencies such as the Japanese Yen, the EU Euro, the United Arab Emirates  Dirham, the Swiss Franc, or the Mexican New Peso.  Look up the currencies you have chosen on the internet and see if you can find pictures of what they look like.');
INSERT INTO badge_optional_requirements VALUES(10554,445,7,'Americans love their cars.  We drive to school, to work, and on trips.  Math can help us with our cars and in our driving in many different ways.  For example, we can save money by using math in choosing limited or unlimited mileage in car rentals, determining the best routes for trips, analyzing the cost trade off of driving various size cars, and deciding just how much you can afford to spend on a car. Figure out what the average gas mileage is for your family car.  The next time you fill up the car with a full tank write down the number on the odometer.  On the following trip to the gas station write down the new number on the odometer and fill up your tank.  Subtract the first odometer reading from the second to get how many miles you drove.  Then divide that number by the number of gallons it took to fill the car (this is the number of gallons you used since your last fill up) to get your gas mileage.   For example if the odometer read 78274 on your first fill up and 78578 on your second, you drove 304 miles.  If it took 16 gallons to fill your tank, you get 19 miles to the gallon.   Keep in mind that you will get less miles to the gallon if you did mostly city driving than you will if you did most of your driving on the highway.');
INSERT INTO badge_optional_requirements VALUES(10555,447,1,'Create a meal tradition of your own and explain what it celebrates');
INSERT INTO badge_optional_requirements VALUES(10556,447,2,'Interview a grandparent or elder about a meal they remember from their childhood');
INSERT INTO badge_optional_requirements VALUES(10557,447,3,'Learn about how some fictional meal traditions such as “second breakfast” from Lord of the Rings are based on real world traditions. Which countries eat Second Breakfast?');
INSERT INTO badge_optional_requirements VALUES(10558,447,4,'Make a centerpiece, napkin holders, placemats or other decor for a traditional meal.');
INSERT INTO badge_optional_requirements VALUES(10559,447,5,'Volunteer at a soup kitchen, community dinner, or food-related nonprofit');
INSERT INTO badge_optional_requirements VALUES(10560,447,6,'Learn how table manners differ around the world (e.g., slurping in Japan, eating with your hands in India)');
INSERT INTO badge_optional_requirements VALUES(10561,447,7,'Prepare a traditional holiday dish with your family and share the story behind it with someone.');
INSERT INTO badge_optional_requirements VALUES(10562,447,8,'Learn how certain religions or cultures include fasting or feasting as part of meal traditions');
INSERT INTO badge_optional_requirements VALUES(10563,447,9,'Explore how mealtimes differ—some cultures eat late, have multiple courses, or use communal dishes. Learn about how meals are traditionally eaten in at least 3 different countries.');
INSERT INTO badge_optional_requirements VALUES(10564,447,10,'Make a cookbook page with a recipe and memory tied to a meal tradition');
INSERT INTO badge_optional_requirements VALUES(10565,447,11,'Try a traditional meal from a culture you’ve never explored before and reflect on the experience.');
INSERT INTO badge_optional_requirements VALUES(10566,447,12,'Watch a documentary or cooking show about food traditions around the world');
INSERT INTO badge_optional_requirements VALUES(10567,447,13,'Set a table according to a specific cultural tradition or historical time period');
INSERT INTO badge_optional_requirements VALUES(10568,447,14,'Learn five vocabulary words related to food culture such as cuisine, custom, heritage, etiquette, and celebration');
INSERT INTO badge_optional_requirements VALUES(10569,447,15,'Visit a cultural or heritage festival and observe what types of meals are served');
INSERT INTO badge_optional_requirements VALUES(10570,447,16,'Create an illustrated “menu” of your family’s typical holiday or special-occasion meal');
INSERT INTO badge_optional_requirements VALUES(10571,447,17,'Explore how migration, trade, or colonization has influenced traditional meals around the world');
INSERT INTO badge_optional_requirements VALUES(10572,447,18,'Write or record a story about your favorite meal tradition and share it with someone');
INSERT INTO badge_optional_requirements VALUES(10573,461,1,'Mummify an apple.');
INSERT INTO badge_optional_requirements VALUES(10574,461,2,'Watch a documentary on mummies.');
INSERT INTO badge_optional_requirements VALUES(10575,461,3,'Watch a fictional (age appropriate) fictional movie featuring a mummy.');
INSERT INTO badge_optional_requirements VALUES(10576,461,4,'Visit a museum with a mummy exhibit');
INSERT INTO badge_optional_requirements VALUES(10577,461,5,'Create a piece of artwork inspired by a mummy');
INSERT INTO badge_optional_requirements VALUES(10578,461,6,'Create mummy inspired foods such as mummy cookies or mummy style pigs in blanket.');
INSERT INTO badge_optional_requirements VALUES(10579,461,7,'Read an age appropriate book about mummmies.');
INSERT INTO badge_optional_requirements VALUES(10580,461,8,'Learn about a famous mummy.  What have we learned from this mummy in regards to the culture and era they lived in?');
INSERT INTO badge_optional_requirements VALUES(10581,461,9,'Find out what a tomb raider is.  Learn about at least one real tomb raider.');
INSERT INTO badge_optional_requirements VALUES(10582,461,10,'Research careers that involve mummies such as working for a museum or as an arch archaeologist.');
INSERT INTO badge_optional_requirements VALUES(10583,461,11,'Create a timeline of major mummy discoveries throughout the years.');
INSERT INTO badge_optional_requirements VALUES(10584,461,12,'Learn about why Egyptians mummified animals.');
INSERT INTO badge_optional_requirements VALUES(10585,463,1,'Make a spore print or take photography of ascii / spores in a live fruiting body (don’t be afraid to pop the tops off those ascomycetes!');
INSERT INTO badge_optional_requirements VALUES(10586,463,2,'Attend a mushroom club/guild meeting or watch a presentation from one. (example: https://www.gamushroomclub.org)');
INSERT INTO badge_optional_requirements VALUES(10587,463,3,'Make collages of two different phyla of mushrooms.  Then compare and contrast the images.');
INSERT INTO badge_optional_requirements VALUES(10588,463,4,'Acquire a sample (from the wild or a culture bank) of a mushroom and see if you can cultivate it.');
INSERT INTO badge_optional_requirements VALUES(10589,463,5,'Learn about mycotoxins / secondary metabolites. What can be made from these compounds?');
INSERT INTO badge_optional_requirements VALUES(10590,463,6,'Write a business plan to commercialize a specific mushroom. How could you use them to best utilize what they provide? It’s okay to be creative! If your fungi are toxic, write up a Super Villain Plan for world domination if you like! If you’re an artist and your fungi make colors, dream up your own art installation. There are no rules or boundaries here');
INSERT INTO badge_optional_requirements VALUES(10591,463,7,'Watch a Mushroom documentary');
INSERT INTO badge_optional_requirements VALUES(10592,463,8,'Make two recipes with mushrooms, one cooked and one raw.');
INSERT INTO badge_optional_requirements VALUES(10593,463,9,'Learn about the medicinal uses of mushrooms');
INSERT INTO badge_optional_requirements VALUES(10594,463,10,'Draw or paint  a picture of a mushroom');
INSERT INTO badge_optional_requirements VALUES(10595,463,11,'Taste at least 5 different types of mushroom from the market.');
INSERT INTO badge_optional_requirements VALUES(10596,463,12,'Extract mushroom compounds at home. What colors do you see? Use the pigment to dye an item of your choice.');
INSERT INTO badge_optional_requirements VALUES(10597,463,13,'Research careers that involve mushrooms.');
INSERT INTO badge_optional_requirements VALUES(10598,463,14,'Go on a mushroom hike.  How many different mushrooms can you find?');
INSERT INTO badge_optional_requirements VALUES(10599,469,1,'Learn the history of your instrument and the names of three composers who have written music for it. Know the name of at least one composition by each of the three composers.');
INSERT INTO badge_optional_requirements VALUES(10600,469,2,'Attend a concert in which your instrument has a part.');
INSERT INTO badge_optional_requirements VALUES(10601,469,3,'Learn a song to play with at least one other person & perform it.');
INSERT INTO badge_optional_requirements VALUES(10602,469,4,'Draw the symbols of and be able to explain: Whole note Rest Half note Quarter note Eighth note Sixteenth note');
INSERT INTO badge_optional_requirements VALUES(10603,469,5,'Explain the following time signatures and be able to fill in measures using BOTH notes and rests: 4/4, ¾, 2/4, and 6/8.');
INSERT INTO badge_optional_requirements VALUES(10604,469,6,'Recognize by ear or sight and be able to play on your instrument a half and whole tone, thirds, fifths, and octaves.');
INSERT INTO badge_optional_requirements VALUES(10605,469,7,'Play your instrument in a recital/concert or for another group of your choosing.');
INSERT INTO badge_optional_requirements VALUES(10606,469,8,'Explore the differences between your instrument and other instruments. Learn to play an easy song on a new instrument. Learn how to care for it and the names of all the parts.');
INSERT INTO badge_optional_requirements VALUES(10607,469,9,'Give the meaning of these terms: Piano Forte Crescendo Diminuendo Ritard Accelerando Da Capo Allegro Andante Lento Give the symbol or abbreviation for all except the last three terms.');
INSERT INTO badge_optional_requirements VALUES(10608,469,10,'Play from memory a song you have learned in the last six months.');
INSERT INTO badge_optional_requirements VALUES(10609,469,11,'Play a song by sight. Explain all signs and terms in it.');
INSERT INTO badge_optional_requirements VALUES(10610,469,12,'Compose a song and play it for someone else.');
INSERT INTO badge_optional_requirements VALUES(10611,469,13,'What is an orchestra? Describe the four different sections of a symphony orchestra, naming three instruments from each. To what section does each of the following belong: Harp Bassoon Viola Celeste Tuba English horn Timpani Piccolo');
INSERT INTO badge_optional_requirements VALUES(10612,469,14,'Show with a baton how to lead a group playing songs written in ¾ and 4/4 time. Help a group perform in some way: choose the piece and obtain copies of the music, schedule practices, or arrange for a performance.');
INSERT INTO badge_optional_requirements VALUES(10613,469,15,'Play at least one song from each of four of the following categories: Folk song Pop song Patriotic song Holiday song Church song/hymn Classical piece written for your instrument Classical piece written for another instrument and transcribed for yours Skill-building exercise Silly song');
INSERT INTO badge_optional_requirements VALUES(10614,491,1,'Draw a picture of your favorites scene from the ballet.');
INSERT INTO badge_optional_requirements VALUES(10615,491,2,'See a live production of the Nutcracker Ballet.');
INSERT INTO badge_optional_requirements VALUES(10616,491,3,'Design your own nutcracker.');
INSERT INTO badge_optional_requirements VALUES(10617,491,4,'Make snowflake ballerinas from Waltz of the Snowflakes.');
INSERT INTO badge_optional_requirements VALUES(10618,491,5,'Look at a nutcracker collection, either in a book, online, or in a museum.');
INSERT INTO badge_optional_requirements VALUES(10619,491,6,'Start your own nutcracker collection.');
INSERT INTO badge_optional_requirements VALUES(10620,491,7,'Read the original story The Nutcracker and the Mouse King by E.T.A. Hoffman.');
INSERT INTO badge_optional_requirements VALUES(10621,491,8,'Share with your club for family your favorite part to the ballet and why.');
INSERT INTO badge_optional_requirements VALUES(10622,491,9,'Perform in a production of the Nutcracker Ballet.');
INSERT INTO badge_optional_requirements VALUES(10623,491,10,'Earn your Ballet Badge.');
INSERT INTO badge_optional_requirements VALUES(10624,491,11,'Design a costume based off a character in the ballet.');
INSERT INTO badge_optional_requirements VALUES(10625,491,12,'Listen to Tchaikovsky’s Nutcracker Suite.');
INSERT INTO badge_optional_requirements VALUES(10626,524,1,'Learn five vocabulary words related to perseverance such as grit, resilience, stamina, determination, and willpower');
INSERT INTO badge_optional_requirements VALUES(10627,524,2,'Set a personal goal that requires at least two weeks of work (the longer the better.) Write down your goal and the date you would like to complete it by.  Track your progress and stick with it until complete. Examples might be learning a specific piece of music on an instrument, memorizing a long poem, creating a daily exercise habit, etc.');
INSERT INTO badge_optional_requirements VALUES(10628,524,3,'Interview someone you know who has shown perseverance—such as a parent, coach, teacher, or veteran. Ask what kept them going during hard times');
INSERT INTO badge_optional_requirements VALUES(10629,524,4,'Complete a hands-on challenge that doesn’t usually work on the first try—such as card houses, spaghetti towers, or Rube Goldberg machines');
INSERT INTO badge_optional_requirements VALUES(10630,524,5,'Participate in a community clean-up or long-term service project that requires follow-through over time');
INSERT INTO badge_optional_requirements VALUES(10631,524,6,'Interview someone in a job that requires daily perseverance (like a farmer, firefighter, teacher, athlete, or caregiver) How does perseverance help their work?  For Level 3 and up shadow someone for a day who works for a living in an area that would require perseverance.');
INSERT INTO badge_optional_requirements VALUES(10632,524,7,'Make a visual art piece, short story, poem, or video showing what perseverance looks like.');
INSERT INTO badge_optional_requirements VALUES(10633,524,8,'Learn a new skill that takes practice—like juggling, a musical instrument, typing, jump rope, or calligraphy. Record your progress over one month.');
INSERT INTO badge_optional_requirements VALUES(10634,524,9,'Design a challenge for others that takes effort and persistence to complete (e.g., reading challenge, fitness challenge, cleanup calendar)');
INSERT INTO badge_optional_requirements VALUES(10635,524,10,'Create a “recipe” for perseverance.  What ingredients would you need, patience?  Endurance?  Stick-to-it-iveness?  In what quantities?  How should they be mixed?');
INSERT INTO badge_optional_requirements VALUES(10636,524,11,'Read or watch at least three different biographies/autobiographies about someone known for their perseverance. Write a comparison showing what they had in common.');
INSERT INTO badge_optional_requirements VALUES(10637,524,12,'Learn about how perseverance helps with brain growth. Study the science behind neuroplasticity and how practice strengthens your brain');
INSERT INTO badge_optional_requirements VALUES(10638,524,13,'Watch a sports documentary or behind-the-scenes film that shows how athletes, dancers, or musicians overcome obstacles to succeed');
INSERT INTO badge_optional_requirements VALUES(10639,524,14,'Teach younger children about perseverance by reading them a story, playing a game, or leading a short challenge');
INSERT INTO badge_optional_requirements VALUES(10640,524,15,'Create a list of encouraging phrases or mantras to say when you feel like giving up. Make it into a poster or screen saver');
INSERT INTO badge_optional_requirements VALUES(10641,524,16,'Keep a failure log for one week—write down mistakes or setbacks and what you learned from each one.  How will you use your failures to learn, adjust and succeed?');
INSERT INTO badge_optional_requirements VALUES(10642,524,17,'Identify a negative self-talk phrase you say when frustrated (like “I’m bad at this”) and write a positive replacement statement');
INSERT INTO badge_optional_requirements VALUES(10643,524,18,'Take part in a group project or activity that involves collaboration and sticking with a common goal even when it’s difficult');
INSERT INTO badge_optional_requirements VALUES(10644,524,19,'What does your book of faith say about perseverance? Find and discuss with an adult at least 1 verse about perseverance if you are in preschool, 3 verses if you are a Level 1 o 2, and 5 if you are a Level 3,4 or 5.');
INSERT INTO badge_optional_requirements VALUES(10645,524,20,'Find and discuss at least 5 famous quotations about perseverance.');
INSERT INTO badge_optional_requirements VALUES(10646,524,21,'Using the Victorian Language of flowers make a bouquet that symbolizes what perseverance means to you. You can find the meanings assigned to the flowers at various websites or in books and you may cut pictures from magazines or web-pages to create a collage “bouquet”. Make sure you include the name and meaning of each flower that you choose. You may make a scrapbook page using pictures of flowers or make a bouquet using real or artificial flowers.');
INSERT INTO badge_optional_requirements VALUES(10647,524,22,'Discuss characters in TV/movies/films who persevere. Are they portrayed as strong or weak characters? Is perseverance a characteristic that is valued by the media?  Find an example of a character who persevered and one who didn’t (who gave up).  Which kind of character do you find most represented in the media?');
INSERT INTO badge_optional_requirements VALUES(10648,532,1,'Create a flower.');
INSERT INTO badge_optional_requirements VALUES(10649,532,2,'Create an animal.');
INSERT INTO badge_optional_requirements VALUES(10650,532,3,'Create a piece of jewelry or hair accessory.');
INSERT INTO badge_optional_requirements VALUES(10651,532,4,'Add embellishments to a pipe cleaner creation such as felt, googly eyes, feathers, magnet, etc.');
INSERT INTO badge_optional_requirements VALUES(10652,532,5,'Create a structure out of pipe cleaners such as a bridge, building, etc.');
INSERT INTO badge_optional_requirements VALUES(10653,532,6,'Create favors for a themed party.');
INSERT INTO badge_optional_requirements VALUES(10654,532,7,'Give away one of your creations as a gift.');
INSERT INTO badge_optional_requirements VALUES(10655,532,8,'Level 2 and Up: Teach a younger child how to make something.');
INSERT INTO badge_optional_requirements VALUES(10656,532,9,'Find five alternate uses for pipe cleaners (game pieces, etc.).');
INSERT INTO badge_optional_requirements VALUES(10657,532,10,'Create a household decoration with pipe cleaners, such as a photo frame, table centerpiece, etc.');
INSERT INTO badge_optional_requirements VALUES(10658,532,11,'Participate in a service project that involves pipe cleaners crafts.');
INSERT INTO badge_optional_requirements VALUES(10659,552,1,'Learn about the seven senses of the body. How do these senses affect you psychologically?');
INSERT INTO badge_optional_requirements VALUES(10660,552,2,'Learn about mediation and try it. How does it make you feel? Try to remember to use mediation the next time you get upset.');
INSERT INTO badge_optional_requirements VALUES(10661,552,3,'While watching television or movies, look for characters who have some type of mental illness (i.e. depression, obsessive compulsive disorder, etc.) When you find one you are interested in, research it and find out if the TV or movie character acted correctly according to science.');
INSERT INTO badge_optional_requirements VALUES(10662,552,4,'Emotions are catchy. If you smile at someone, they will smile back at you. This is called Facial Feedback Hypothesis. Test this hypothesis, do an experiment and try it on friends and family.');
INSERT INTO badge_optional_requirements VALUES(10663,552,5,'Find 5 careers that are related to psychology. Learn about how much each one pays and what education is required.');
INSERT INTO badge_optional_requirements VALUES(10664,552,6,'Watch a superhero movie or cartoon. (Batman, Captain America, Spider-man, etc.) Does being a superhero make a person more lonely or sad? Why? Why do they act the way they do? What happened to make that person a superhero? How would it make you feel if you had super powers and could not tell anyone?');
INSERT INTO badge_optional_requirements VALUES(10665,552,7,'Explore what it means to be introverted or extroverted. Which type of person likes to go to parties and which one likes to spend time doing things by themselves? Learn about the psychology behind these behaviors, and determine which category you best fit in.');
INSERT INTO badge_optional_requirements VALUES(10666,552,8,'Study a diagram or drawing of the brain. Find out which parts of the brain control our emotions, memories, and how we act when we’re in danger.');
INSERT INTO badge_optional_requirements VALUES(10667,552,9,'Earn the Health and Fitness badge at your level. What does being active and healthy have to do with mental health and psychology?');
INSERT INTO badge_optional_requirements VALUES(10668,552,10,'Level 3 and Up: Learn about the concept of false memories. How can our memories change our perception of the world?');
INSERT INTO badge_optional_requirements VALUES(10669,552,11,'Learn about how the media (through magazines, television, movies, and even dolls) can influence how people feel about themselves. What does this do to people psychologically? How can we improve peoples’ self-esteem to keep them mentally healthy?');
INSERT INTO badge_optional_requirements VALUES(10670,552,12,'Organize or help with a community service project that has to do with psychology or promoting mental health.');
INSERT INTO badge_optional_requirements VALUES(10671,552,13,'Create a poster about a subject in psychology (e.g. stress, the seven senses, mediation, etc.) and share it with your family, friends, and group.');
INSERT INTO badge_optional_requirements VALUES(10672,552,14,'Mental illness is a subject that people are not comfortable with. However, mental illness affects 1 in 4 people sometime in their life. Why are people embarrassed to talk about it? Learn about why this is the case and discuss with your family or friends ways to make mental illness easier to discuss. How can a person ask for help if they are struggling? What resources are out there?');
INSERT INTO badge_optional_requirements VALUES(10673,563,1,'Learn five vocabulary words such as rhetoric, oratory, quotation, context, and persuasive');
INSERT INTO badge_optional_requirements VALUES(10674,563,2,'Create a poster or illustrated quote to hang on a wall or give as a gift');
INSERT INTO badge_optional_requirements VALUES(10675,563,3,'Research a speech that changed history. What was the result? Who was affected? What is the most common part of the speech to quote?');
INSERT INTO badge_optional_requirements VALUES(10676,563,4,'Choose three quotes and memorize them.  Know who said them and why.  Explain what they mean in your own words');
INSERT INTO badge_optional_requirements VALUES(10677,563,5,'Watch a video of a speech being given and describe how the speaker uses body language or voice to emphasize key points');
INSERT INTO badge_optional_requirements VALUES(10678,563,6,'Write a short speech or original quote that inspires or teaches something');
INSERT INTO badge_optional_requirements VALUES(10679,563,7,'Compare how a quote or speech has been used differently over time by various people or movements');
INSERT INTO badge_optional_requirements VALUES(10680,563,8,'Create a timeline of famous speeches from different time periods and cultures');
INSERT INTO badge_optional_requirements VALUES(10681,563,9,'Record yourself reciting a quote or speech and review your performance. What could you improve? Think about body languange, annunciation, volume, etc.');
INSERT INTO badge_optional_requirements VALUES(10682,563,10,'Make a collection of quotes around a theme, such as kindness, bravery, or freedom');
INSERT INTO badge_optional_requirements VALUES(10683,563,11,'Participate in a speech contest, public speaking event, or school presentation');
INSERT INTO badge_optional_requirements VALUES(10684,563,12,'Learn how quotes are often misattributed. Find an example and explain what the real origin was.');
INSERT INTO badge_optional_requirements VALUES(10685,563,13,'Create a matching game using famous quotes and the people who said them');
INSERT INTO badge_optional_requirements VALUES(10686,563,14,'Interview someone about a quote or speech that impacted them personally and why');
INSERT INTO badge_optional_requirements VALUES(10687,563,15,'Learn about speechwriting and write a speech for a specific purpose.  Your purpose might be to inform, to persuade, to entertain, or to commemorate/celebrate something.');
INSERT INTO badge_optional_requirements VALUES(10688,563,16,'Research the life of a famous orator such as Martin Luther King Jr., Winston Churchill, Malala Yousafzai, or Sojourner Truth');
INSERT INTO badge_optional_requirements VALUES(10689,563,17,'Study how translation affects famous speeches or quotes—compare the original to translated versions if possible');
INSERT INTO badge_optional_requirements VALUES(10690,563,18,'Do a community service project inspired by a quote or speech you admire (e.g., “Be the change you wish to see in the world”)');
INSERT INTO badge_optional_requirements VALUES(10691,580,1,'List ways to prepare ahead of time so you or the driver won’t be sleepy while driving. Come up with ways to stay awake if you start to feel drowsy. What are the best ways to cope with tiredness while driving? Why is it important to pull over and rest when you become too tired to drive?');
INSERT INTO badge_optional_requirements VALUES(10692,580,2,'Learn how to pack a car truck so luggage doesn’t shift too much and important items are easy to find.');
INSERT INTO badge_optional_requirements VALUES(10693,580,3,'Depending on the type of weather or season you will be driving in, you will need to pack the car differently. Learn how to pack a car for a winter trip through the mountains vs. a summer trip through the desert. What are some differences you notice in what you pack? What should you do if your car skids on a snowy or icy road, or if it dies in the desert?');
INSERT INTO badge_optional_requirements VALUES(10694,580,4,'Learn how to change a flat tire.');
INSERT INTO badge_optional_requirements VALUES(10695,580,5,'Compare gas prices from different gas stations. What is the difference between regular, plus and premium gas? Why might one gas station be much cheaper than another?');
INSERT INTO badge_optional_requirements VALUES(10696,580,6,'Wash and vacuum out your car before leaving on your trip.');
INSERT INTO badge_optional_requirements VALUES(10697,580,7,'If you are bringing a dog with you (or any other animal), what do you need to bring for him? Food, water, leash, etc. List any items you can think of. Also, figure out what rest stops are along the way so you can let your dog walk around and go to the bathroom if he needs to.');
INSERT INTO badge_optional_requirements VALUES(10698,580,8,'Discuss with an adult or other family member different ways you can stay safe on your trip. This could include safe driving, not walking around alone at the hotel or any rest area, not distracting the driver while he/she is driving, etc.');
INSERT INTO badge_optional_requirements VALUES(10699,580,9,'Look up the weather you will encounter on your way to your destination. Pack the appropriate clothing and shoes. Will you need sunscreen if it will be hot? Will you need a rain coat if there is a chance of rain?');
INSERT INTO badge_optional_requirements VALUES(10700,580,10,'Make a rough budget for your trip. What is your food budget? Gas? Accommodations? Activities? Use a gas calculator online to get an estimate of how much gas you will use.');
INSERT INTO badge_optional_requirements VALUES(10701,580,11,'Create an emergency kit for your car. This may include a flashlight, jumper cables, a tire jack and spare tire, a first aid kit, paper maps and compass, etc.');
INSERT INTO badge_optional_requirements VALUES(10702,604,1,'Visit a garden center or seed library and explore the different kinds of seeds available');
INSERT INTO badge_optional_requirements VALUES(10703,604,2,'Save seeds from a fruit or vegetable you ate and replant them.  Understand why some seeds are sterile and won’t grow.');
INSERT INTO badge_optional_requirements VALUES(10704,604,3,'Create a seed journal to record what you planted, when, and how it grew');
INSERT INTO badge_optional_requirements VALUES(10705,604,4,'Compare heirloom seeds, hybrid seeds, and GMO seeds. What are the differences?');
INSERT INTO badge_optional_requirements VALUES(10706,604,5,'Learn about the job of a seed scientist or agricultural specialist. Shadow or interview someone in this field.');
INSERT INTO badge_optional_requirements VALUES(10707,604,6,'Do a community service project such as donating seed packets to a community garden or helping plant seeds at a local school or nonprofit');
INSERT INTO badge_optional_requirements VALUES(10708,604,7,'Make seed art using real seeds to create a mosaic or design');
INSERT INTO badge_optional_requirements VALUES(10709,604,8,'Dissect and label different types of seeds using diagrams and/or actual specimens');
INSERT INTO badge_optional_requirements VALUES(10710,604,9,'Try sprouting seeds in a jar or bag (such as alfalfa or bean sprouts) and eat what you grow');
INSERT INTO badge_optional_requirements VALUES(10711,604,10,'Learn how different seeds are used for food, spices, oils, and even medicine');
INSERT INTO badge_optional_requirements VALUES(10712,604,11,'Do a science experiment comparing how different liquids (water, juice, soda) affect seed germination');
INSERT INTO badge_optional_requirements VALUES(10713,604,12,'Explore seed banks like the Svalbard Global Seed Vault. Why are they important for the future?');
INSERT INTO badge_optional_requirements VALUES(10714,604,13,'Research five vocabulary words related to seeds such as germination, cotyledon, dispersal, pollination, and dormancy');
INSERT INTO badge_optional_requirements VALUES(10715,604,14,'Learn how seeds are labeled and packaged commercially. Design your own seed packet with instructions and illustrations');
INSERT INTO badge_optional_requirements VALUES(10716,604,15,'Learn how seeds are used in cultural traditions (e.g., sunflower seeds for Native American snacks, sesame seeds in Asian cooking, etc.)');
INSERT INTO badge_optional_requirements VALUES(10717,604,16,'Visit a farm or botanical garden and look for seed pods in different stages');
INSERT INTO badge_optional_requirements VALUES(10718,604,17,'Watch a time-lapse video of a seed sprouting and describe what you see');
INSERT INTO badge_optional_requirements VALUES(10719,604,18,'Read a picture book, article, or chapter book that includes seeds or plants as a theme');
INSERT INTO badge_optional_requirements VALUES(10720,610,1,'Create a shadow silouette portrait of yourself or a friend.');
INSERT INTO badge_optional_requirements VALUES(10721,610,2,'Experiment with different light sources (sunlight, flashlight, lamp) to see how shadows change in size and direction');
INSERT INTO badge_optional_requirements VALUES(10722,610,3,'Create a photo series that tells a story using only shadows of objects or people.');
INSERT INTO badge_optional_requirements VALUES(10723,610,4,'Make a “cut shadow” sculpture—an object that casts a shadow image different from its physical shape');
INSERT INTO badge_optional_requirements VALUES(10724,610,5,'Try creating a shadow art piece using your own body or a friend’s body to form shapes or letters');
INSERT INTO badge_optional_requirements VALUES(10725,610,6,'Watch a shadow dance performance (such as those by groups like El Gamma Penumbra or Attraction). Describe how the performers use their bodies and light to tell a story.');
INSERT INTO badge_optional_requirements VALUES(10726,610,7,'Use chalk or paint to trace shadows cast by toys or people on the sidewalk or paper, then turn them into creative artwork');
INSERT INTO badge_optional_requirements VALUES(10727,610,8,'Make a “shadow screen” using a sheet or parchment paper and perform a story using puppets or objects behind it');
INSERT INTO badge_optional_requirements VALUES(10728,610,9,'Learn how shadow theater is used in storytelling and create a short skit of your own');
INSERT INTO badge_optional_requirements VALUES(10729,610,10,'Record a video of a shadow performance and edit it to add music or narration');
INSERT INTO badge_optional_requirements VALUES(10730,610,11,'Visit an art installation, exhibit, or watch an online performance that features shadow art or silhouette work');
INSERT INTO badge_optional_requirements VALUES(10731,610,12,'Create a shadow mural using cutouts and a projected light to form the design on a wall');
INSERT INTO badge_optional_requirements VALUES(10732,610,13,'Study how dancers or actors use shadow and silhouette to enhance live performances');
INSERT INTO badge_optional_requirements VALUES(10733,610,14,'Take a photo where the shadow is more important than the object casting it. Explain how this changes the image.');
INSERT INTO badge_optional_requirements VALUES(10734,610,15,'Learn about how shadows are used in animation or film to create drama or emotion');
INSERT INTO badge_optional_requirements VALUES(10735,610,16,'Build a rotating sculpture that creates changing shadows as it moves or the light shifts');
INSERT INTO badge_optional_requirements VALUES(10736,610,17,'Interview or research a professional shadow artist, puppeteer, dancer, or stage lighting designer');
INSERT INTO badge_optional_requirements VALUES(10737,610,18,'Explore the science behind shadows—how they are created, blocked, or diffused');
INSERT INTO badge_optional_requirements VALUES(10738,667,1,'Organize a “clock walk” around your home or neighborhood and take photos or draw different types of clocks you find (analog, digital, tower, etc.).');
INSERT INTO badge_optional_requirements VALUES(10739,667,2,'Build a timekeeping device of your choice such as a sundial, water clocks, candle clock, potato clock, etc. (This may not be the same device used for Level 2 requirement #2)');
INSERT INTO badge_optional_requirements VALUES(10740,667,3,'Visit a museum, science center, or website with historical timekeeping tools and write a short report on your favorite artifact.');
INSERT INTO badge_optional_requirements VALUES(10741,667,4,'Research a famous clock or timekeeping structure such as Big Ben, the Prague Astronomical Clock, or ancient Egyptian obelisks used for tracking shadows.');
INSERT INTO badge_optional_requirements VALUES(10742,667,5,'Explore how time zones work and what happens when people travel across them. Create a visual showing the world’s major time zones.  When and why were time zones invented?');
INSERT INTO badge_optional_requirements VALUES(10743,667,6,'Learn how calendars were developed and adjusted throughout history (e.g., Julian, Gregorian, lunar vs. solar).');
INSERT INTO badge_optional_requirements VALUES(10744,667,7,'Learn how farmers and ancient civilizations used the sun, stars, and seasons to track time and guide planting or harvesting.');
INSERT INTO badge_optional_requirements VALUES(10745,667,8,'Learn about Daylight Saving Time—why it was created and the debate about keeping or eliminating it.');
INSERT INTO badge_optional_requirements VALUES(10746,667,9,'Study how fashion influenced watch design.  How have watches changed over the years specifically to match certain fashions.');
INSERT INTO badge_optional_requirements VALUES(10747,667,10,'Study how art and decor influenced clocks over the years.  Compare clocks from many different eras.  What styles were popular and when?');
INSERT INTO badge_optional_requirements VALUES(10748,667,11,'Create a “day in the life” journal or poster showing how timekeeping affects your routine from morning to night.');
INSERT INTO badge_optional_requirements VALUES(10749,667,12,'Learn how sailors used timekeeping tools like marine chronometers to navigate across oceans. Create a drawing or model of one.');
INSERT INTO badge_optional_requirements VALUES(10750,667,13,'Use an online simulation or video to explore how atomic clocks work and why they’re important for GPS and internet synchronization.');
INSERT INTO badge_optional_requirements VALUES(10751,667,14,'Organize or participate in a service project that helps others manage time better—such as helping younger kids make morning routine charts or planners.');
INSERT INTO badge_optional_requirements VALUES(10752,667,15,'Compare analog and digital clocks. Which do you prefer and why? Learn the parts of each and how they function.');
INSERT INTO badge_optional_requirements VALUES(10753,667,16,'Do a timekeeping challenge—try to do a task (like walking a lap or brushing your teeth) and estimate one minute without looking at a clock.');
INSERT INTO badge_optional_requirements VALUES(10754,667,17,'Explore how timekeeping is important in sports, science, or music. Pick one and explain how timing impacts success.  How has the method of timekeeping changed over the years?');
INSERT INTO badge_optional_requirements VALUES(10755,667,18,'Watch a documentary or short video on the history of timekeeping and discuss what you found most surprising.');
INSERT INTO badge_optional_requirements VALUES(10756,672,1,'Design your own version of your trademarked toy (e.g. design your own cabbage patch kid, Lego set, Barbie, Bionicle, etc.). Draw a picture of your designs and explain to someone what makes your version special.');
INSERT INTO badge_optional_requirements VALUES(10757,672,2,'What other licensed apparel and accessories is on the market from your toy? (E.g. movies, t-shirts, backpacks, etc.) Make a list of at least ten items if possible.');
INSERT INTO badge_optional_requirements VALUES(10758,672,3,'Research the company that manufactures your toy. Who founded it? What other toys does this company make? Does this company pay for a license to use the name of a preexisting trademark (such as Lucas Films)?');
INSERT INTO badge_optional_requirements VALUES(10759,672,4,'Does your toy have a fan club? Research fan clubs and enthusiast events relating to your toy. (E.g. Breyerfest, Lego Club, Lego Americana Roadshow, Official Cabbage Patch Kids Collector’s Club, etc.) How does one become a member of such a club?  What are the benefits?');
INSERT INTO badge_optional_requirements VALUES(10760,672,5,'Does your toy have its own retail storefront? Where are the stores located? Are there any located in other countries? If there is one in your area, be sure to visit it! Create a simple map showing where at least retail three storefronts are located in the U.S. (if applicable).');
INSERT INTO badge_optional_requirements VALUES(10761,672,6,'Participate in a service project related to your toy. You could hold a toy drive for local homeless shelter, or donate toys to a daycare.');
INSERT INTO badge_optional_requirements VALUES(10762,672,7,'What characters/kinds of sets are available? For example, the Bionicles are made up of six characters fighting against evil. Who are these characters and what are the differences in their names, make up, abilities, etc.? Or, for example, what kinds of Lego sets can you purchase, such as Indiana Jones Legos, Lord of the Rings Legos, and City Legos? Or, perhaps your toy started with original characters, such as Barbie and Ken, and then broadened into many different dolls. Learn about the original characters/sets of your toy, and how they developed into many different varieties.');
INSERT INTO badge_optional_requirements VALUES(10763,672,8,'What materials is your toy made of? How does the material affect the way you play with them? (E.g. Barbie’s clothes are easily adjustable, and Legos are easily built into massive structures.) Learn about the manufacturing process of the toys (otherwise known as “life cycle analysis) and how the materials become the toys. With parental permission, watch a YouTube video showing this process for your toy, if it is available.*');
INSERT INTO badge_optional_requirements VALUES(10764,672,9,'Learn about the process of trademarking and how it works when trademarking a toy. What is the difference between trademarking a toy and patenting it? What is the difference in the two processes? What are the requirements of trademarking, and what are the requirements of patenting?');
INSERT INTO badge_optional_requirements VALUES(10765,672,10,'Give a trademarked toy (one of your choice) to someone as a gift.');
INSERT INTO badge_optional_requirements VALUES(10766,672,11,'Create your own accessories for your trademarked toy. For example, you could sew your Barbie homemade clothes, or you could create a secret fort for your Bionicles. Make at least two accessories and use them in gameplay with your friends!');
INSERT INTO badge_optional_requirements VALUES(10767,672,12,'Many toys have been customized for both boys and girls. Learn about the sister version of your trademarked toy, if applicable. For example, Lego has created sets particularly for girls and Cabbage Patch made a line of dolls for boys. What started the production of the sister version, and how popular have they become.');
INSERT INTO badge_optional_requirements VALUES(10768,672,13,'Is there anything about your toy that can be personalized when you purchase it? For example, Cabbage Patch Kids are formally adopted, and My Twin Dolls can be made to look like you. Research options of personalization for your toy, if applicable.');
INSERT INTO badge_optional_requirements VALUES(10769,672,14,'Is your trademarked toy collectible? If so, why? Is it highly valuable/expensive, limited in quantity, or discontinued? Research these possibilities and how they have changed over the years of your toy’s history. The following toys have specific requirements written just for them and submitted by our members. You may use the requirements above, the specialized requirements in the link provided or a combination of the two to earn your badge. Barbie Care Bears My Little Pony Friendship is Magic Strawberry Shortcake American Girl Doll Lego Breyer Model Horses Cabbage Patch Kids Disclaimer: Our web pages may provide recommendations and/or links to other digital and/or non-digital resources for the convenience of users. Curiosity Untamed LLC is not responsible for the availability or content of these external sources, nor does Curiosity Untamed LLC endorse, warrant, or guarantee the products, services, or information described or offered at these other digital and/or non-digital resources. Use these resources at your own risk and with a parent’s permission. Websites Development of Lego’s Bionicle toys: http://www.bzpower.com/ref.php?ID=489 Origin of many popular trademarked toys: https://secureyourtrademark.com/trademark-info/lego-and-other-famous-toy-trademarks-and-patents/ Legal info on trademarks and patents: http://info.legalzoom.com/put-trademark-patent-toy-23645.html The Cabbage Patch Kid Craze: http://wharble.com/Cabbage_Patch_Kids.htm Video of how Plastic dolls are made: https://www.youtube.com/watch?v=ZYIKkqzF_GE Video of how Legos are made: https://www.youtube.com/watch?v=VJbQ7zAlYo0');
INSERT INTO badge_optional_requirements VALUES(10770,673,1,'Participate in a service project that involves trampolining. Examples are helping raise money for your gym or to get other people interested in trampolining.');
INSERT INTO badge_optional_requirements VALUES(10771,673,2,'Read a book about trampolining.');
INSERT INTO badge_optional_requirements VALUES(10772,673,3,'Learn about the different types of trampolining- double mini and synchronized and individual. Take part in two of the disciplines.');
INSERT INTO badge_optional_requirements VALUES(10773,673,4,'Take part in a competition');
INSERT INTO badge_optional_requirements VALUES(10774,673,5,'What are the different levels of trampolining? How to you advance to each level? What competitions are available for each level?');
INSERT INTO badge_optional_requirements VALUES(10775,673,6,'Learn about the history of trampolining. How did it develop? How has it changed over the years? When was it recognized as a sport? When did it become an Olympic sport?');
INSERT INTO badge_optional_requirements VALUES(10776,673,7,'Trampolining is classed as gymnastics. Learn about the other types of gymnastics both artistic and rhythmic. How is gymnastics different for boys and girls? What events do only boys compete in? What events do only girls compete in?');
INSERT INTO badge_optional_requirements VALUES(10777,673,8,'Learn five conditioning exercises used in trampolining. Why is conditioning important?');
INSERT INTO badge_optional_requirements VALUES(10778,673,9,'Pick a trampolinist and learn about him/her. Write a report about him/her.');
INSERT INTO badge_optional_requirements VALUES(10779,673,10,'What careers are available in trampolining? Research the different jobs available. Which one would you pick?');
INSERT INTO badge_optional_requirements VALUES(10780,673,11,'Learn about the importance of good sportsmanship.  Earn the Sportsmanship badge.');
INSERT INTO badge_optional_requirements VALUES(10781,673,12,'Are there scholarships available for trampolining? Learn about what universities have them and find out what an athlete needs to do to get one.');
INSERT INTO badge_optional_requirements VALUES(10782,673,13,'Create a booklet for younger children explaining how to trampoline. Useful Website:en.wikipedia.org/wiki/Trampolining-terms (This website lists basic, intermediate and advanced skills plus other trampolining terms)');
INSERT INTO badge_optional_requirements VALUES(10783,674,1,'Learn five vocabulary words related to trade routes such as import, export, merchant, tariff, and barter');
INSERT INTO badge_optional_requirements VALUES(10784,674,2,'Create a physical or digital map tracing a famous trade route (e.g., the Silk Road, Amber Road, or Trans-Siberian Railway), labeling key cities, rest stops, and terrain features.');
INSERT INTO badge_optional_requirements VALUES(10785,674,3,'Use a world map or globe to follow the path of a common product (like chocolate, tea, bananas, or electronics) and learn how many places it passes through before reaching you');
INSERT INTO badge_optional_requirements VALUES(10786,674,4,'Interview or shadow someone who works in a job related to trade—such as shipping, logistics, delivery, or customs');
INSERT INTO badge_optional_requirements VALUES(10787,674,5,'Visit a port, railway yard, airport, or shipping facility to observe how goods move today');
INSERT INTO badge_optional_requirements VALUES(10788,674,6,'Do a community service project related to trade or goods distribution, such as collecting or delivering items for a food bank, school supply drive, or clothing donation');
INSERT INTO badge_optional_requirements VALUES(10789,674,7,'Read a book, article, or watch a video about trade and how it connects people and cultures');
INSERT INTO badge_optional_requirements VALUES(10790,674,8,'Create a board game, card game, or role-playing activity that involves trade routes and exchanging goods');
INSERT INTO badge_optional_requirements VALUES(10791,674,9,'Research how trade routes helped spread not only goods, but also ideas, languages, inventions, and diseases');
INSERT INTO badge_optional_requirements VALUES(10792,674,10,'Study the environmental impact of modern trade, including fuel use, shipping emissions, and packaging waste');
INSERT INTO badge_optional_requirements VALUES(10793,674,11,'Explore how natural disasters (like sandstorms, floods, or hurricanes) have disrupted trade routes throughout history and how people adapted.');
INSERT INTO badge_optional_requirements VALUES(10794,674,12,'Learn about the role of caravansaries, waystations, ports, and trading posts in supporting long-distance trade routes.');
INSERT INTO badge_optional_requirements VALUES(10795,674,13,'Research ancient road systems used for trade (such as the Roman roads or the Inca road network) and how they were constructed and maintained.');
INSERT INTO badge_optional_requirements VALUES(10796,674,14,'Investigate how borders, wars, and political alliances have shifted or blocked trade routes throughout history. Create a before-and-after map showing changes.');
INSERT INTO badge_optional_requirements VALUES(10797,674,15,'Explore how pirates, privateers, and smugglers affected trade routes in history');
INSERT INTO badge_optional_requirements VALUES(10798,674,16,'Learn how shipping containers revolutionized modern trade and global commerce.');
INSERT INTO badge_optional_requirements VALUES(10799,674,17,'Study the engineering challenges of building and maintaining trade routes through difficult terrain, such as mountain passes, desert crossings, or ocean straits.');
INSERT INTO badge_optional_requirements VALUES(10800,674,18,'Explore the connection between trade routes and the spread of religion, such as how Buddhism, Islam, or Christianity traveled via merchants and caravans.');
INSERT INTO badge_optional_requirements VALUES(10801,678,1,'Learn a minimum of five vocabulary words related to travel safety such as itinerary, identification, turbulence, emergency exit, and customs');
INSERT INTO badge_optional_requirements VALUES(10802,678,2,'Roleplay how to safely ask for help from a flight attendant, police officer, hotel staff, or other trusted adult while traveling');
INSERT INTO badge_optional_requirements VALUES(10803,678,3,'Pack a real or pretend travel safety kit with items like hand sanitizer, whistle, emergency contacts, bandages, a charger, and a flashlight.');
INSERT INTO badge_optional_requirements VALUES(10804,678,4,'Learn how to read and understand basic safety signs found in airports, train stations, and roadways.');
INSERT INTO badge_optional_requirements VALUES(10805,678,5,'Create a safety checklist for a family road trip or flight, including packing, emergency items, and safety steps.');
INSERT INTO badge_optional_requirements VALUES(10806,678,6,'Interview or shadow someone who works in travel safety, such as a flight attendant, TSA agent, bus driver, or ship captain.');
INSERT INTO badge_optional_requirements VALUES(10807,678,7,'Choose a place you’d like to visit and research the unique travel safety tips specific to that location, such as transportation, weather, cultural norms or known scams.');
INSERT INTO badge_optional_requirements VALUES(10808,678,8,'Create a plan for staying digitally safe while traveling—protect passwords, avoid public Wi-Fi risks, and use location sharing wisely.');
INSERT INTO badge_optional_requirements VALUES(10809,678,9,'Research common travel scams, such as fake vacaton rentals or overcharging taxis, in different parts of the world and make a “stay safe while traveling” tip sheet to avoid them.');
INSERT INTO badge_optional_requirements VALUES(10810,678,10,'Practice what to do in case of the following travel emergencies: flat tire or car breakdown flight delay or cancellation lost hotel reservation lost identification. Lost wallet or purse Lost phone Separation from your family or group');
INSERT INTO badge_optional_requirements VALUES(10811,678,11,'Learn about safe food and water practices when traveling to different countries or regions. How can you avoid food poisoning?');
INSERT INTO badge_optional_requirements VALUES(10812,678,12,'Study how different cultures handle travel safety, and safety expectations may change by country.  For example compare traveling by train in India with traveling by train in England.');
INSERT INTO badge_optional_requirements VALUES(10813,678,13,'Participate in or organize a community service project that promotes travel safety such as a helmet giveaway, car seat check, or safety poster campaign');
INSERT INTO badge_optional_requirements VALUES(10814,678,14,'Research how transportation agencies use technology (like GPS, radar, or air traffic control) to keep people safe in transit');
INSERT INTO badge_optional_requirements VALUES(10815,678,15,'Learn about safety when traveling with animals—how to prepare pets for flights or long car rides');
INSERT INTO badge_optional_requirements VALUES(10816,678,16,'Use a map to plan a safe walking route in a new city. Mark important landmarks, emergency services, and unsafe areas to avoid.');
INSERT INTO badge_optional_requirements VALUES(10817,678,17,'Learn about keeping your belongings secure while traveling—how to avoid pickpockets, keep valuables safe, and recognize travel scams');
INSERT INTO badge_optional_requirements VALUES(10818,678,18,'Design a safety-themed travel game (like a board game or card game) that teaches others what to do in common travel emergencies.');
INSERT INTO badge_optional_requirements VALUES(10819,680,1,'Decorate your shirt using glitter glue, iron-ons or beads.');
INSERT INTO badge_optional_requirements VALUES(10820,680,2,'With the help of a parent or leader, stitch a design on your shirt by hand or machine.');
INSERT INTO badge_optional_requirements VALUES(10821,680,3,'Donate a t-shirt that you have decorated to a children’s home or homeless shelter.');
INSERT INTO badge_optional_requirements VALUES(10822,680,4,'Give a  t-shirt that you have decorated as a gift.');
INSERT INTO badge_optional_requirements VALUES(10823,680,5,'Earn the tie-dye badge using a t-shirt for at least one of your projects.');
INSERT INTO badge_optional_requirements VALUES(10824,680,6,'Make a belt, hair clip,decorate shoelaces, or make some other accessory to match your t-shirt');
INSERT INTO badge_optional_requirements VALUES(10825,680,7,'Make a ball of yarn out of strips from old t-shirts and use it to knit or crochet something, like a belt or bag');
INSERT INTO badge_optional_requirements VALUES(10826,680,8,'Write a short page of instructions on the different ways to decorate t-shirts or teach at least three methods to other kids.');
INSERT INTO badge_optional_requirements VALUES(10827,680,9,'Look up t-shirt recycling websites online.  Choose 2 activities to try.');
INSERT INTO badge_optional_requirements VALUES(10828,680,10,'Learn about print on demand companies such as Cafe Press or Zazzle that allow you to upload your own design and have it printed on a t-shirt.  Compare pricing and selection from at least two different sources.');
INSERT INTO badge_optional_requirements VALUES(10829,680,11,'Learn about silk screening and visit a local t-shirt shop if possible.');
INSERT INTO badge_optional_requirements VALUES(10830,680,12,'Learn about the history of t-shirts.');
INSERT INTO badge_optional_requirements VALUES(10831,690,1,'Write a poem about your vacation- about the place you went to, the activities you did, or the people you were with.');
INSERT INTO badge_optional_requirements VALUES(10832,690,2,'Make an advertisement for the place where you will be vacationing.  You could make a brochure, a poster, or a TV commercial by taking a video of yourself.  The advertisement should include what is great about the vacation and why people would want to go there.');
INSERT INTO badge_optional_requirements VALUES(10833,690,3,'Take pictures on your vacation and then make a scrapbook or photo book of the trip.  Show at least two friends your book of pictures and tell them about your trip.');
INSERT INTO badge_optional_requirements VALUES(10834,690,4,'While you travel to your destination play a “find it” game with a family member.  For example, if you are on a long car ride, see how many different states’ license plates you can find.  If you’re taking a plane, see how many different color suitcases you see.  Or play “I spy,” while you’re waiting for your flight or in the car.');
INSERT INTO badge_optional_requirements VALUES(10835,690,5,'Find out how to make a reservation for a car rental, airline ticket and hotel.  What taxes and fees are added to the price you are quoted?');
INSERT INTO badge_optional_requirements VALUES(10836,690,6,'If you are visiting another country where a different language is spoken, learn how to speak some important phrases and sentences in the language such as “Thank you.” “Excuse me.” “Hi, how are you?” “My name is ____” “Do you speak English?” “Where is ___?” “I would like _____” or other phrases you find important on your vacation.');
INSERT INTO badge_optional_requirements VALUES(10837,690,7,'If you are visiting a place where they speak English find out what words they say differently or what local slang is used.  For example in some states you drink “soda” and in others you drink “pop.”');
INSERT INTO badge_optional_requirements VALUES(10838,690,8,'Be friendly on vacation!  Meet at least one new friend.  Find out their name, where they come from, and what they love about their vacation.  If you get to know them well ask for their address so you can become pen pals.');
INSERT INTO badge_optional_requirements VALUES(10839,690,9,'Try a new food or new restaurant you have never tried before on your vacation.  Is there some kind of food they have at your vacation destination that they don’t usually have where you live?  After you try the new food, write a review of how you liked it.');
INSERT INTO badge_optional_requirements VALUES(10840,690,10,'What are the risks of going through a 3rd party reservation company such as Expedia or Priceline verses booking directly with a hotel or airline?');
INSERT INTO badge_optional_requirements VALUES(10841,690,11,'Choose three of the following scenarios or create some of your own.  Plan a vacation that includes destination, time, budget, transportation, lodging, recreation, and meals. Newlywed couple on a honeymoon with a limited budget.Family of five wanting to visit a theme park with a moderate budget.Empty nest couple on their first cruise ship with unlimited budget.Single parent with children wanting to visit a historical site with a limited budget.Family of four with grandparents wanting to visit a natural wonder with a moderate budget.Professional couple without children wanting to vacation at a beach with an unlimited budget.Father and son wanting to visit a national sporting event with a limited budget.');
INSERT INTO badge_optional_requirements VALUES(10842,690,12,'Take a “virtual” vacation.  Choose a location you would like to visit and see how many virtual tours you can find for places in that city.  Is there drone footage of the region as a whole?  Interviews with chefs?  How many ways can you find to “visit” a location virtually? (Make sure to have a parent’s permission before visiting websites or watching videos.)');
INSERT INTO badge_optional_requirements VALUES(10843,690,13,'Put together a portable activity kit to keep kids busy in restaurants, on airplanes, in cars, etc.  Include items like coloring sheets, magnet boards, a deck of cards, a sketchbook and pencil, etc.');
INSERT INTO badge_optional_requirements VALUES(10844,693,1,'What foods are high in protein that can replace meat in a vegetarian’s diet?');
INSERT INTO badge_optional_requirements VALUES(10845,693,2,'Learn about animal cruelty and why it may convince a person to choose to live a meatless lifestyle. (Parents: this may a sensitive topic, so proceed with caution. Possibly preview before sharing info with your child, depending on age.)');
INSERT INTO badge_optional_requirements VALUES(10846,693,3,'Find a recipe that includes meat and come up with a way to make the dish vegetarian.');
INSERT INTO badge_optional_requirements VALUES(10847,693,4,'Browse cookbooks, magazines, or the internet and create a weekly menu of vegetarian dinners.');
INSERT INTO badge_optional_requirements VALUES(10848,693,5,'Find a list of famous vegetarians/vegans.');
INSERT INTO badge_optional_requirements VALUES(10849,693,6,'Prepare a vegetarian snack, making sure it has lots of good nutrients.');
INSERT INTO badge_optional_requirements VALUES(10850,693,7,'There are many books that feature vegetarian characters. Find one and read it. Fiction or non-fiction are fine.');
INSERT INTO badge_optional_requirements VALUES(10851,693,8,'Do you know any vegetarians? If you do, get in touch and ask them what it is like. How long have they been, and why did they choose to? Invite them over for a vegetarian meal, if you are able.');
INSERT INTO badge_optional_requirements VALUES(10852,693,9,'There are lots of meat alternatives out there. Pick up a product like Tofurkey slices, Morningstar Bacon, or Light Life Meatless Dogs and give them a try. (other brands include Quorn, Gardein, Beyond Meat, St. Yves, etc.)');
INSERT INTO badge_optional_requirements VALUES(10853,693,10,'Not all vegetarians are vegetarian by choice.  Some people have medical conditions that do not allow them to eat meat.  Find out about one of these conditions such as Phenylketonuria or Alpha-gal syndrome.');
INSERT INTO badge_optional_requirements VALUES(10854,698,1,'Learn who the original author is of your villain – who created him/her; did he/she appear in comics, television shows, or movies; when was he/she created? Share your findings with your family or troop. Watch at least one movie/TV show or read at least one comic about your character.');
INSERT INTO badge_optional_requirements VALUES(10855,698,2,'Research how your villain has changed from his/her earliest years to the present day. What changes have been made to the personality, costume, abilities, affiliations, and story of your character?');
INSERT INTO badge_optional_requirements VALUES(10856,698,3,'Dress up like your chosen villain and perform a skit or short movie in which you are using the character’s powers.');
INSERT INTO badge_optional_requirements VALUES(10857,698,4,'Create a piece of art with your villain’s logo.');
INSERT INTO badge_optional_requirements VALUES(10858,698,5,'Create your own villain. Include his/her name, costume, powers, and whatever else you would like. Draw a picture of your villain and/or create a short comic starring him/her.');
INSERT INTO badge_optional_requirements VALUES(10859,698,6,'If your villain has a theme song, learn the words to it and sing it. If you play an instrument you may learn to play it instead.');
INSERT INTO badge_optional_requirements VALUES(10860,698,7,'Learn about the heroes that fight your villain.  How did these characters become superheroes? Did they have a previous relationship with your villain before he/she turned evil? How does this affect your villain?');
INSERT INTO badge_optional_requirements VALUES(10861,698,8,'Does your character have a sidekick or does he/she work alone? Learn about your character’s sidekick(s). Do they have any special powers? What is their relationship with your villain? If your character does not have a sidekick, create one. Draw a picture of their sidekick or the one you created.');
INSERT INTO badge_optional_requirements VALUES(10862,698,9,'Learn about where your character lives or about his/her secret base. What makes his/her home/base unique? Create a map of the layout. What special features has your character added to make the place more useful?');
INSERT INTO badge_optional_requirements VALUES(10863,698,10,'Write your own comic about your villain. Include existing characters within the story or create your own.');
INSERT INTO badge_optional_requirements VALUES(10864,698,11,'What merchandise/fan apparel is available on the market for your villain? Make a list of at least 5 items you can purchase with your villain’s logo.');
INSERT INTO badge_optional_requirements VALUES(10865,698,12,'What toys are available for your villain?  Make a list of at least 5 toys that can be purchased involving your villain.');
INSERT INTO badge_optional_requirements VALUES(10866,698,13,'Learn about careers involving writing and publishing comics or making movies with villains. What kind of pay could you expect, and is any schooling/special training required?');
INSERT INTO badge_optional_requirements VALUES(10867,698,14,'Make up a game about your villain and play it with some friends or play a villain themed board game or video game in which your superhero makes an appearance.');
INSERT INTO badge_optional_requirements VALUES(10868,698,15,'What can you learn about good vs. evil or right vs. wrong from your villain? What character traits make your villain evil?');
INSERT INTO badge_optional_requirements VALUES(10869,701,1,'Play a water game.  For example, you could have a water race where children hold  2 containers with water in them and race to the finish line without spilling their water. The one with the most water wins.');
INSERT INTO badge_optional_requirements VALUES(10870,701,2,'Learn about erosion.  Simulate erosion by pouring water onto a “mountain” of dirt or sand.  What happens?  Why is erosion control important?  Find somewhere outdoors where there is evidence of erosion.  What is causing it?  What problems might  it cause?');
INSERT INTO badge_optional_requirements VALUES(10871,701,3,'Take a field trip that involves learning about water.  Examples might be to visit an aquarium, soil conservation group, flower garden, farm with either plants or animals, mill that makes juice (ex: cider or juice mill), a dam, etc.');
INSERT INTO badge_optional_requirements VALUES(10872,701,4,'Make your own water song or water game.');
INSERT INTO badge_optional_requirements VALUES(10873,701,5,'Find out how many items in your house contain water. With adult supervision, explore the kitchen, pantry, bathroom, laundry room, etc. and make a list of items that contain water. You will need for each person: A pen Paper A willingness to explore At home or in your meeting find food boxes, bags, juice or soda bottles Look for the ingredients label to see if water was used to make it If the label tells you, how much water was used to make that item?');
INSERT INTO badge_optional_requirements VALUES(10874,701,6,'Try the following experiment: Why freshwater (drinkable) is important to people, plants and animals? This will show that even though our planet is made up of about 70% water only 3% of it is freshwater (drinkable). You will need for each person: 2 clear drinking cups (must be clear!) Small bowl to put salt in (this is optional! If you want to go from child to child and fill their spoons, you can do that) 1 teaspoon for each child Table salt Table cloth (it might get messy from stirring) Clear water (warm water – this will help the salt dissolve faster) Place table cover on table Give or have each person get 2 containers (mark anywhere on the containers A and B or 1 and 2 so they don’t get confused later) Fill  cup A and B ½ full with water Have children take a sip from cup A and B so they know what it taste like Place small bowl with salt in it between children or fill their spoons with salt Add on teaspoon of salt to cup A and stir until salt disappears (this takes about 1 to 2 minutes) Have the children look at the cup A (salt added) and look at cup B (no salt). Do they look the same? Have them take a little sip of cup B (no salt added), then take a sip of cup A (salt added). Did they taste the same? You might not need an answer, just the look on their faces. Repeat step F and G 2 more times After doing step I have the children do step H Children might have to rinse their mouths after step H After children have rinsed their mouths talk about how they would feel if they didn’t have fresh/drinkable water to drink. Talk about what other things they couldn’t do if they didn’t have fresh/drinkable water. (ex: drinking, bathing, food growing, etc…)');
INSERT INTO badge_optional_requirements VALUES(10875,701,7,'Make a water snooper and go snooping: You will need : 1 large empty tin can (both ends cut out) 1 piece of clear cellophane cut to cover one end of can 1 sturdy rubber band Place cellophane over opening and secure with rubber band. Go to a creek, or small pond and use your “snooper” to see what you can see living in the water. Note: your water snooper will work as a magnifying glass when placed in contact with the water.');
INSERT INTO badge_optional_requirements VALUES(10876,701,8,'Have a visitor come and talk about how important water is or how clean water is important.');
INSERT INTO badge_optional_requirements VALUES(10877,701,9,'Make a list or talk about activities you can do with clean/fresh water. Now talk about how you would feel if you could not do those activities, or if it was limited by local communities.');
INSERT INTO badge_optional_requirements VALUES(10878,701,10,'Participate in a water service project.  Ideas might include: Do a cleanup of a local beach or public swimming area, a river, etc. Put up a poster at your local school, library, community builds, etc….. Have a water fair/carnival to celebrate how important water is.');
INSERT INTO badge_optional_requirements VALUES(10879,701,11,'Find out what industries have been created because of water use. (ex: hydro electricity, drink companies, etc…)');
INSERT INTO badge_optional_requirements VALUES(10880,701,12,'Find out if we use less plastic how that affects water and our world.');
INSERT INTO badge_optional_requirements VALUES(10881,701,13,'With permission from a parent, do a search online for good information about how to save water and keep water clean. Keep track of words that you used in your search and website you learned from. Have a pen and a piece of paper ready for use.  What search terms gave you the best results?  What did you learn?');
INSERT INTO badge_optional_requirements VALUES(10882,701,14,'Test and monitor local water. (http://www.worldwatermonitoringday.org)');
INSERT INTO badge_optional_requirements VALUES(10883,701,15,'Research at least 3 careers involving water. Find out salary, education requirements, equality ratio, quantity of jobs, and any other interesting “odd” information.');
INSERT INTO badge_optional_requirements VALUES(10884,701,16,'If you have a leaky faucet, place a cup under it. Figure out how many droplets went into the cup at the end of a minute.  Calculate how many that would be in an hour. Figure out how much water would be lost after 24 hours, 7 days, or you could even see how much would be lost in a year. If you do not have a leaky faucet, ask a parent to make the faucet drip slowly for one minute so you can do this. Here is one example of how much you could be losing. In 1 minute the faucet dripped 30 times, in 1 hour that 30 drops turned into 1,800 drops. Now figure out what this would equal in cups or gallons.');
INSERT INTO badge_optional_requirements VALUES(10885,701,17,'Make a wave bottle and help a younger child make one as well. Items needed: Recycled water bottle with cap. Vegetable oil (younger kids and children)/ used motor oil (older kids and adults) Water Food coloring (only needed with vegetable oil) Electrical tape Fill bottle halfway with water, add food coloring. Add vegetable oil. Seal with lid and wrap with electrical tape. What happens when it is agitated?');
INSERT INTO badge_optional_requirements VALUES(10886,701,18,'Discuss ideas on water conservation with others, make a personal goal or promise to make a specific change in your life to conserve water. Make a promise and practice this change for 1 month. Additional Resources- Don’t waste water — we need it http://dontwastewaterweneedit.weebly.com/ Crayola – water is everywhere http://www.crayola.com/free-coloring-pages/print/water-water-everywhere-coloring-page/ Super coloring pages – water http://www.supercoloring.com/pages/tag/water/ Free coloring pages fun – water http://freecoloringpagefun.com/nature/water EPA – water home page http://water.epa.gov/ Free coloring pages.com http://www.freeprintablecoloringpages.net/ Interactive water cycle http://www.epa.gov/safewater/kids/flash/flash_watercycle.html Water play cycle: http://www.homeschooling-ideas.com/water-experiments.html Virtual tour of a submarine. http://ussnautilus.org/virtualTour/index.shtml Additional ideas or experiments: Water cycle experiment made easy for kids: http://www.bukisa.com/articles/32887_water-cycle-experiment-easy-for-kids Most Amazing Deep Sea Creatures Part 1, 2 and 3 (children safe): http://www.youtube.com/watch?v=KpBSo80iNlE&feature=BFp&list=PLB792136F4BFBFC42 http://www.youtube.com/watch?v=IsO0j1Qoyns&feature=BFa&list=PLB792136F4BFBFC42&lf=BFp http://www.youtube.com/watch?v=x7fnumgWZgU&feature=BFa&list=PLB792136F4BFBFC42&lf=BFp Online interactive water cycle: http://www.epa.gov/safewater/kids/flash/flash_watercycle.html Make your own water cycle at a meeting or at home: http://thewaterproject.org/resources/the_water_cycle.asp Escaping water: http://www.sciencekids.co.nz/experiments/escapingwater.html Gravity Free Water: http://www.sciencekids.co.nz/experiments/gravityfreewater.html Saltwater Tester: http://pbskids.org/zoom/activities/sci/saltwatertester.html Water play cycle: http://www.homeschooling-ideas.com/water-experiments.html');
INSERT INTO badge_optional_requirements VALUES(10887,703,1,'Know what a person in distress in the water looks and acts like: it is practically impossible for a true drowning victim to shout for help, because he or she does not have a sufficient air supply to do so. Mention that if you see someone drowning on TV or in the movies, that person is not actually drowning, they are just acting.');
INSERT INTO badge_optional_requirements VALUES(10888,703,2,'Head back');
INSERT INTO badge_optional_requirements VALUES(10889,703,3,'Mouth open');
INSERT INTO badge_optional_requirements VALUES(10890,703,4,'Arms moving up and down, slapping the water');
INSERT INTO badge_optional_requirements VALUES(10891,703,5,'No sound');
INSERT INTO badge_optional_requirements VALUES(10892,703,6,'Demonstrate reaching water rescue techniques: reach with a float, an object or a garment.  Explain why you should use reaching techniques instead of swimming into the water to rescue someone.');
INSERT INTO badge_optional_requirements VALUES(10893,703,7,'Demonstrate throwing a rope with floatation ring to a person in the pool.  First practice being able to throw a rope weighted with a beanbag a distance of 10 feet (Level 1 and Level 2) and hitting a 2 ft square target. Level 3 and up should practice throwing the rope 20 feet and hitting the 2 ft square target.  Explain why you should use throwing techniques instead of swimming into the water to rescue someone if possible. Remember: don’t go: throw!');
INSERT INTO badge_optional_requirements VALUES(10894,703,8,'Understand what the HELP and Huddle positions are, when to use them and why.  Wearing a properly fitted PFD practice the HELP and Huddle positions in the pool. What is the purpose of these positions? Explain why swimming or survival floating will hasten the onset of hypothermia in cold water');
INSERT INTO badge_optional_requirements VALUES(10895,703,9,'Understand what Survival Floating is and demonstrate how to do it.  Understand what Mushroom Floating is and demonstrate how to do it.');
INSERT INTO badge_optional_requirements VALUES(10896,703,10,'Demonstrate how to recover yourself if you fall into the water fully clothed.  Stay near the boat, dock, or edge of pool and remain afloat for five minutes.');
INSERT INTO badge_optional_requirements VALUES(10897,703,11,'Play water games with younger children that will help teach them water safety skills.');
INSERT INTO badge_optional_requirements VALUES(10898,703,12,'Practice water safety rules at least twice at the pool.');
INSERT INTO badge_optional_requirements VALUES(10899,703,13,'Research the history of lifeboats and lifesaving.  Share what you learned with your friends or family.');
INSERT INTO badge_optional_requirements VALUES(10900,715,1,'Learn how to build a fire.  How does rain, wind and snow affect fire making ability?  Learn techniques for helping to get a fire going during wet and windy conditions.');
INSERT INTO badge_optional_requirements VALUES(10901,715,2,'Learn how to read a weather forecast for winter dangers like blizzards, wind chill warnings, and ice storms.  Understand basic cold weather vocabulary such as “wind chill”, “Black Ice”, “Flurries”, “Sleet”,  “Whiteout”');
INSERT INTO badge_optional_requirements VALUES(10902,715,3,'Interview someone who has experience in cold weather rescue, snow safety, or winter sports safety (e.g., ski patrol, SAR team, or ranger)');
INSERT INTO badge_optional_requirements VALUES(10903,715,4,'Help your parent do a winter safety inspection of your car.  Check tire pressure and tread.  Look for any cuts, punctures, bulges, scrapes, cracks or bumps in the tires.  Make sure you have a spare tire and that all lights and signals are working.  Keep the gas tank full as often as possible.');
INSERT INTO badge_optional_requirements VALUES(10904,715,5,'Try a cold-weather experiment: test different materials to see which insulate best against cold or wind');
INSERT INTO badge_optional_requirements VALUES(10905,715,6,'Learn about different types of snow and how their texture affects travel, insulation, and avalanche risk.');
INSERT INTO badge_optional_requirements VALUES(10906,715,7,'Learn how to recognize and treat early signs of frostbite and hypothermia');
INSERT INTO badge_optional_requirements VALUES(10907,715,8,'Plan a mock winter emergency scenario and explain what you would do in steps to survive and stay safe');
INSERT INTO badge_optional_requirements VALUES(10908,715,9,'Learn how to purify snow or ice into safe drinking water and why eating snow directly may not be the best choice.');
INSERT INTO badge_optional_requirements VALUES(10909,715,10,'Research avalanche zones and learn what safety tools and precautions are used in avalanche-prone areas');
INSERT INTO badge_optional_requirements VALUES(10910,715,11,'Learn how snow affects visibility and traction when driving.  Be able to explain the importance of chains, snow tires, 4WD, fog lights, excess space between vehicles, and slow speeds as they relate to safe driving in snow.');
INSERT INTO badge_optional_requirements VALUES(10911,715,12,'Learn how to walk safely in deep snow. Try walking in snow, walking with snowshoes, or simulate moving in thick snow at home.');
INSERT INTO badge_optional_requirements VALUES(10912,715,13,'Participate in or organize a community winter clothing drive or collect items for a shelter or emergency kit project');
INSERT INTO badge_optional_requirements VALUES(10913,715,14,'Be able to recognize the symptoms of hyperthermia and know how to treat it.');
INSERT INTO badge_optional_requirements VALUES(10914,715,15,'Learn what to do if you get lost in the snow. Practice how to stay put, signal for help, and protect yourself from the cold. Avoid perspiration and conserve your energy. Stay out of the wind and if you have company, cuddle up. Engage in light activity to increase circulation and warmth, but not so much that you sweat.');
INSERT INTO badge_optional_requirements VALUES(10915,715,16,'Research careers that require winter survival knowledge such as mountain guides, park rangers, wilderness EMTs, or polar researchers');
INSERT INTO badge_optional_requirements VALUES(10916,715,17,'Learn how to signal for help in a winter environment—using contrast, sound, light, or movement');
INSERT INTO badge_optional_requirements VALUES(10917,715,18,'Watch a documentary or film that includes real-life or dramatized winter survival and discuss what the characters did well and what mistakes they made');
INSERT INTO badge_optional_requirements VALUES(10918,717,1,'Where are wolves typically found? What type of habitat do they live in? Do some wolves prefer a colder climate while others prefer a warmer one?');
INSERT INTO badge_optional_requirements VALUES(10919,717,2,'Read about the first recorded taming of a wolf. Who tamed it? When and where did this take place? How did he tame the wolf?');
INSERT INTO badge_optional_requirements VALUES(10920,717,3,'Read a book about wolves, whether fictional or non-fictional. Make sure the book is at your appropriate age level.');
INSERT INTO badge_optional_requirements VALUES(10921,717,4,'Visit your local zoo to learn more about wolves. Read any information they have or ask one of the zoo attendants questions about their wolves.');
INSERT INTO badge_optional_requirements VALUES(10922,717,5,'What are some similarities between wolves and dogs? List at least five that you learn about.');
INSERT INTO badge_optional_requirements VALUES(10923,717,6,'Many times, wolves are portrayed as “savage.” Some of them are, but most are simply afraid of humans and stay away. How do you think wolves got such a bad notoriety?');
INSERT INTO badge_optional_requirements VALUES(10924,717,7,'Learn about the life cycle of a wolf, from birth until death. How long until they are full grown? What is a typically life span?');
INSERT INTO badge_optional_requirements VALUES(10925,717,8,'Write a story or play about a wolf. Read or perform it for your family or club. Helpful Resources Wolf.org Living With Wolves.com Wolves of the World Disclaimer: Some Frontier Girls/Quest Clubs Web pages may provide links to other Internet sites for the convenience of users. Frontier Girls/Quest Clubs is not responsible for the availability or content of these external sites, nor does Frontier Girls/Quest Clubs endorse, warrant, or guarantee the products, services, or information described or offered at these other Internet sites.  Use these sites at your own risk.');
